// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ COUNTER, 0x10				// Anzahl der Schleifendurchlaeufe

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
 * zu Unteraufgabe e):
 * Die Suchdauer ergibt immer den Wert 0x006F,
 * unabhaengig davon an welcher Position im Array der Maximalwert steht,
 * oder wie viele verschiedene Werte im Array enthalten sind.
 * Man koennte sich den IT-Befehl sparen und nur "movhi r9, r0" schreiben.
 * Es wird also entweder die MOV (T) oder die NOP (E) Operation ausgefuehrt.
 * Und wenn beide Operationen 1 Zyklus benoetigen erklaert dies das beobachtete Verhalten.
 */
 
main:	
	bl uart_init	// Initialisierung wird nur ein einziges Mal ausgefuehrt
	
	// Intervallmessung (Dauer in Zyklen) bei Leerlauf
	// (nimmt auch einige Zyklen in Anspruch und wuerde die Messung verfaelschen)
	bl pit3_init			// Timer initialisieren
	bl pit3_getval			// Startzeitpunkt messen
	mov r8, r0				// und diesen in R8 zwischenspeichern
	bl pit3_getval			// Endzeitpunkt messen
	sub r7, r8, r0			// und die Differenz (Dauer) in R7 speichern (brauchen wir spaeter noch)
	
loop_program:

	// Einlesen von 16 Bytes
	ldr r0, =str_eingabe // Zeiger auf String laden
	bl uart_putString // String ausgeben
	mov r4, #COUNTER	// Zaehler laden
	ldr r5, =bytearray
	
	// Eingabeschleife
loop_eingabe:
	ldr r0, =str_prompt	// Zeiger auf String laden
	bl uart_putString	// String ausgeben
	bl uart_getByte		// ein Byte lesen
	strb r0, [r5], #1	// im Array ablegen und Adresse in R5 um eins erhoehen
	bl uart_putByte		// das Byte ausgeben
	subs r4, r4, #1		// Zaehler dekrementieren
	bne loop_eingabe	// solange Zaehler noch nicht null
	
	// Maximumsbestimmung
	ldr r0, =str_startsuche	// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	mov r9, #0				// Maximum mit null initialisieren
	mov r4, #COUNTER
	
	// jetzt starten wir die eigentliche Intervallmessung
	bl pit3_init			// Timer initialisieren
	bl pit3_getval			// Startzeitpunkt messen
	mov r8, r0				// und diesen in R8 zwischenspeichern
	
loop_maximum:
	
	ldrb r0, [r5, #-1]!		// Byte aus dem Array holen, vorher Adresse in R5 dekrementieren (Predekrement)
	cmp r0, r9				// mit bisherigem Maximum vergleichen
	it hi					// wenn es groesser ist (unsigned)
	movhi r9, r0			// wird das bisherige Maximum ueberschrieben
	
	subs r4, r4, #1			// Zaehler dekrementieren
	bne loop_maximum		// solange Zaehler noch nicht null
	
	// Wir haben das Maximum bestimmt => Ende der Intervallmessung
	bl pit3_getval			// Endzeitpunkt der Maximumsberechnung messen
	sub r8, r8, r0			// noch nicht korrekte Dauer (in Takten) berechnen und in R8 sichern
	sub r8, r8, r7			// Dauer korrigieren mit Wert (= 0xB) aus Leerlaufmessung
	
	// Maximum zusaetzlich im Speicher ablegen
	ldr r0, =maximum		// Adresse des Speichers fuer Maximum laden
	strb r9, [r0]			// das Maximum im Speicher ablegen

	//Ausgabe des Ergebnisses der Maximumsberechnung
	ldr r0, =str_endsuche	// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	mov r0, r9				// Maximum nach R0 kopieren
	bl uart_putByte			// Maximum ausgeben
	
	// Ausgabe der Dauer zur Bestimmung der Maximumssuche
	ldr r0, =str_suchdauer	// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	mov r0, r8				// Dauer (in Zyklen) nach R0 kopieren um diese
	bl uart_putInt16		// auszugeben (Int16 sorgt fuer die Darstellung der vierstelligen Hexadezimalzahl)
	
	// Ruecksprung zu Beginn
	mov r1, #0				// Maximum zuruecksetzen
	ldr r0, =maximum		// Adresse des Speichers fuer Maximum laden
	strb r1, [r0]			// das Maximum im Speicher ablegen
	
	ldr r0, =str_markierung_ende	// Zeiger auf String laden
	bl uart_putString 				// String ausgeben
	b loop_program					// An Anfang springen
	

/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
	.rept COUNTER
	.byte 0x00
	.endr
maximum: .byte 0x0
str_prompt: .asciz "\n>0x"
str_eingabe: .asciz "Bitte 16 Bytes sukzessiv eingeben!"
str_startsuche: .asciz "\nDurchsuchen gestartet"
str_endsuche: .asciz "\nDurchsuchen beendet\nMaximum: 0x"
str_suchdauer: .asciz "\nSuchdauer: 0x"
str_markierung_ende: .asciz "\n# # # # # # # # # #\n\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ BASISADDR_BITBAND_ALIAS, 0x22000200	// Basisaddresse fuer Bit-Band-Alias der Bits des Words unter 0x20000010

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

loop_program:

	// Anwender bitten die Bit-Nummern einzugeben
	ldr r0, =str_eingabe	// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	
	// erste Bit-Nummer einlesen
	ldr r0, =str_prompt		// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	bl uart_getByte			// ein Byte lesen
	mov r4, r0		    	// und in R4 zwischenspeichern
	bl uart_putByte			// User-Eingabe als Rueckmeldung ausgeben
	and r4, r4, #0x001F		// Wert begrenzen (nur die unteren 5 Bits behalten) 
	
	// zweite Bit-Nummer einlesen
	ldr r0, =str_prompt		// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	bl uart_getByte			// ein Byte lesen
	mov r5, r0		    	// und in R5 zwischenspeichern
	bl uart_putByte			// User-Eingabe als Rueckmeldung ausgeben
	and r5, r5, #0x001F		// Wert begrenzen (nur die unteren 5 Bits behalten)
	
	// die Bit-Nummern ausgeben
	ldr r0, =str_eingabe_bit0
	bl uart_putString
	mov r0, r4				// erste Bit-Nummer nach R0 kopieren
	bl uart_putByte			// erste Bit-Nummer ausgeben
	
	ldr r0, =str_eingabe_bit1
	bl uart_putString
	mov r0, r5				// zweite Bit-Nummer nach R0 kopieren
	bl uart_putByte			// zweite Bit-Nummer ausgeben
	
	// Hinweis fuer Berechnungsart "ohne Bit-Banding"
	ldr r0, =str_ohne_bit_banding	// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	
	// Variable aus Speicher holen und ausgeben
	ldr r0, =str_wert_alt			// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	ldr r0, =word_ohne_bit_banding	// Adresse des Speichers fuer Variable laden
	ldr r6, [r0]					// Variable aus Speicher in R6 laden
	mov r0, r6						// Wert nach R0 schieben um
	bl uart_putInt32				// ihn auszugeben
	
	// In der 32-Bit-Variablen das Bit mit der ersten Bit-Nummer zuruecksetzen
	// => wir brauchen also LSL und BIC
	mov r0, #0x01			// Definition des Bits welches noch geshiftet werden muss
	lsl r1, r0, r4			// das Bit an die gewuenschte Position shiften
	bic r6, r6, r1 			// das Bit in der Variablen zuruecksetzen
	
	// In der 32-Bit-Variablen das Bit mit der ersten Bit-Nummer setzen
	// => wir brauchen also LSL und ORR
	mov r0, #0x01			// Definition des Bits welches noch geshiftet werden muss
	lsl r1, r0, r5			// das Bit an die gewuenschte Position shiften
	orr r6, r6, r1			// das Bit in der Variablen setzen (die manipulierte Variable ist noch in R6)
	
	// der neue Variablenwert muss wieder in den Speicher geschrieben werden
	ldr r0, =word_ohne_bit_banding	// Adresse des Speichers fuer Variable laden
	str r6, [r0]					// den Variablenwert im Speicher ablegen
	
	// Ausgabe des neuen Wertes
	ldr r0, =str_wert_neu	// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	mov r0, r6				// Wert nach R0 schieben um
	bl uart_putInt32		// ihn auszugeben
	
	// Hinweis fuer Berechnungsart "mit Bit-Banding"
	ldr r0, =str_mit_bit_banding	// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	
	// Variable aus Speicher holen und ausgeben
	ldr r0, =str_wert_alt			// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	ldr r0, =word_mit_bit_banding	// Adresse des Speichers fuer Variable laden
	ldr r6, [r0]					// Variable aus Speicher in R6 laden
	mov r0, r6						// Wert nach R0 schieben um
	bl uart_putInt32				// ihn auszugeben
	
	// hier nutzen wir das Bit-Banding um die Bits (zurueck) zu setzen.
	// Es geht um die Bits des Words unter Adresse 0x20000010
	// Die Basisadresse lautet 0x22000200 (= 0x22000000 + (0x20000010 – 0x20000000) × 32 + 0 × 4)
	// Die Bit-Nummer (unsigned) muss um zwei Bits nach links geshiftet (also mit 4 multipliziert) werden
	// und zur Basisadresse addiert werden um die gewuenschte Bit-Band-Alias-Adresse zu erhalten.
	
	/* komplizierte Art die Basisadresse zu berechnen
	// Zuerst berechnen wir die Basisadresse 0x22000200 und speichern sie in R7 zwischen
	mov r0, 0x22
	lsl r7, r0, #24
	add r7, r7, #0x200
	*/
	// einfacher: Absolute Addressen koennen als Konstanten definiert werden
	ldr r7, =BASISADDR_BITBAND_ALIAS // Basisadresse in R7 laden
	
	// Dann setzen wir das jeweilige Bit zurueck
	lsl r0, r4, #2					// Bit-Nummer mit 4 multiplizieren
	add r0, r7, r0					// Bit-Band-Alias-Adresse berechnen
	mov r1, #0x00					// Wert fuer Zuruecksetzen laden
	str r1, [r0]					// Bit/Word zuruecksetzen (im Speicher)
	
	// Dann setzen wir das andere Bit
	lsl r0, r5, #2					// Bit-Nummer mit 4 multiplizieren
	add r0, r7, r0					// Bit-Band-Alias-Adresse berechnen
	mov r1, #0x01					// Wert fuer Setzen laden
	str r1, [r0]					// Bit/Word setzen (im Speicher)
	
	// aktualisierte Variable aus Speicher holen und ausgeben
	ldr r0, =str_wert_neu			// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	ldr r0, =word_mit_bit_banding	// Adresse des Speichers fuer Variable laden
	ldr r6, [r0]					// Variable aus Speicher in R6 laden
	mov r0, r6						// Wert nach R0 schieben um
	bl uart_putInt32				// ihn auszugeben
	
	// Ruecksprung zu Beginn
	ldr r0, =str_markierung_ende	// Zeiger auf String laden
	bl uart_putString 				// String ausgeben
	mov r0, #0xA					// neue-Zeile-Zeichen in R0 schreiben 
	bl uart_putChar					// und als visuellen Trenner im Terminal schreiben
	b loop_program					// An Anfang springen

/*** Datenbereich (ab 0x20000000) ***/

.data
word_ohne_bit_banding: .word 0x0000FFFF // Adresse 0x20000000
wordarray_reserved1:
	.rept 0x03
	.word 0x00
	.endr
word_mit_bit_banding: .word 0x0000FFFF // Adresse 0x20000010
// weitere reservierte Bytes auf 0 setzen (hilft beim Debuggen)
wordarray_reserved2:
	.rept 0x03
	.word 0x00
	.endr
str_prompt: .asciz "\n>0x"
str_ohne_bit_banding: .asciz "\n[0x20000000: ohne Bit-Banding]"
str_mit_bit_banding: .asciz "\n[0x20000010: mit Bit-Banding]"
str_eingabe: .asciz "Bitte zwei Bit-Nummern (zwischen 0 und 31) eingeben!"
str_eingabe_bit0: .asciz "\nNummer des 0-Bits: 0x"
str_eingabe_bit1: .asciz "\nNummer des 1-Bits: 0x"
str_wert_alt: .asciz "\nalter Wert: 0x"
str_wert_neu: .asciz "\nneuer Wert: 0x"
str_markierung_ende: .asciz "\n# # # # # # # # # #\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ VECTOR_BYTESIZE, 0x04		// Anzahl der Bytes eines Vektors

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
 * Vergleich der Ausfuehrungszeiten:
 * - Routine 1 (ohne DSP-Befehle) benoetigt 54 Zyklen
 * - Routine 2 (mit DSP-Befehle) benoetigt nur 9 Zyklen
 */

main:	
	bl uart_init
	
	// Intervallmessung (Dauer in Zyklen) bei Leerlauf
	// (nimmt auch einige Zyklen in Anspruch und wuerde die Messung verfaelschen)
	bl pit3_init			// Timer initialisieren
	bl pit3_getval			// Startzeitpunkt messen
	mov r4, r0				// und diesen in R3 zwischenspeichern
	bl pit3_getval			// Endzeitpunkt messen
	sub r11, r4, r0			// Differenz (Leerlauf-Dauer) fuer spaeter in R11 speichern
	// wie in Versuch 1-1 betraegt die Leerlauf-Dauer 11 Zyklen
	
	// Willkommenstext ausgeben
	ldr r0, =str_welcome
	bl uart_putString
	
loop_program:
	ldr r0, =vector_1			// UP-Parameter 1: Vektoradresse
	mov r1, #VECTOR_BYTESIZE	// UP-Parameter 2: Anzahl der Vektorelemente
	bl user_readInByteVector	// Vektorelemente einlesen
	
	ldr r0, =vector_2			// UP-Parameter 1: Vektoradresse
	mov r1, #VECTOR_BYTESIZE	// UP-Parameter 2: Anzahl der Vektorelemente
	bl user_readInByteVector	// Vektorelemente einlesen
	
	// Vektor 1 ausgeben
	ldr r0, =str_ausgabe_v1		// Zeiger auf String laden
	bl uart_putString 			// String ausgeben
	ldr r1, =vector_1			// Zeiger auf Vektor-Startadresse holen
	ldr r0, [r1]				// Die 4 Bytes des Vektor in R0 laden
	bl uart_putInt32			// und ausgeben
	
	// Vektor 2 ausgeben
	ldr r0, =str_ausgabe_v2		// Zeiger auf String laden
	bl uart_putString 			// String ausgeben
	ldr r1, =vector_2			// Zeiger auf Vektor-Startadresse holen
	ldr r0, [r1]				// Die 4 Bytes des Vektor in R0 laden
	bl uart_putInt32			// und ausgeben
	
	// # # # # # # # # # # # # # # # # # # # # # #
	// Zuerst bestimmen wir min und max OHNE DSP
	// # # # # # # # # # # # # # # # # # # # # # #
	
	// Startadressen der Vektoren laden
	ldr r4, =vector_1
	ldr r5, =vector_2
	ldr r6, =vector_min
	ldr r7, =vector_max
	mov r8, #VECTOR_BYTESIZE
	
	bl pit3_init			// Timer initialisieren
	bl pit3_getval			// Startzeitpunkt messen
	mov r10, r0				// und diesen in R10 zwischenspeichern
	
loop_byte_vergleich:
	ldrb r0, [r4], #1	// Byte aus Vektor1 holen und Adresse in R4 um eins erhoehen
	ldrb r1, [r5], #1	// Byte aus Vektor2 holen und Adresse in R5 um eins erhoehen
	
	mov r2, r0			// Vermutung r0 ist min
	mov r3, r0			// Vermutung r0 ist max
	cmp r1, r0			// Bytes vergleichen
	ite hi
	movhi r3, r1		// max ueberschreiben falls r1 > r0
	movls r2, r1		// min ueberschreiben falls r1 <= r0
	
	strb r2, [r6], #1	// min in vector_min ablegen und Adresse in R6 um eins erhoehen
	strb r3, [r7], #1	// min in vector_min ablegen und Adresse in R6 um eins erhoehen
	
	subs r8, r8, #1			// Zaehler dekrementieren
	bne loop_byte_vergleich	// solange Zaehler noch nicht null
	
	// Routine beendet und Ergebnisse im Speicher gesichert
	bl pit3_getval			// Endzeitpunkt der Routine messen
	sub r10, r10, r0		// noch nicht korrekte Dauer (in Takten) berechnen
	sub r10, r10, r11		// Dauer korrigieren mit Wert aus Leerlaufmessung
	
	ldr r0, =str_header_ohne_dsp	// Zeiger auf String laden
	bl uart_putString 				// String ausgeben
	mov r0, r10						// Dauer als Parameter an UP uebergeben
	bl user_printMinAndMaxVector 	// Vektoren min und max ausgeben
	
	// # # # # # # # # # # # # # # # # # # # # # #
	// Nun bestimmen wir min und max MIT DSP
	// # # # # # # # # # # # # # # # # # # # # # #
		
	// Startadressen der Vektoren laden
	ldr r4, =vector_1
	ldr r5, =vector_2
	ldr r6, =vector_min
	ldr r7, =vector_max
	
	// Die Zeitmessung muss hier beginnen,
	// da sie bei der anderen Routine auch ungefaehr hier beginnt
	bl pit3_init	// Timer initialisieren
	bl pit3_getval	// Startzeitpunkt messen
	mov r10, r0		// und diesen in R10 zwischenspeichern
	
	ldr r0, [r4]	// Vektor1 (alle 4 Bytes) in R0 laden
	ldr r1, [r5]	// Vektor2 (alle 4 Bytes) in R1 laden
	
	// Die vorzeichenlosen min-Bytes und max-Bytes bestimmen
	// siehe Assembler-Reference 3.4.13 SEL (S.98), zweites Beispiel
	// The following instruction sequence sets each byte in R4 equal to
	// the unsigned minimum of the corresponding bytes of R1 and R2:
	usub8   r2, r0, r1
    sel     r2, r1, r0	// min-Bytes in R2 schreiben
    sel     r3, r0, r1	// max-Bytes in R3 schreiben
    str     r2, [r6]	// Den min-Vektor im Speicher aktualisieren
    str     r3, [r7]	// Den min-Vektor im Speicher aktualisieren
    
    // Routine beendet und Ergebnisse im Speicher gesichert
	bl pit3_getval			// Endzeitpunkt der Routine messen
	sub r10, r10, r0		// noch nicht korrekte Dauer (in Takten) berechnen
	sub r10, r10, r11		// Dauer korrigieren mit Wert aus Leerlaufmessung
    
    ldr r0, =str_header_mit_dsp		// Zeiger auf String laden
	bl uart_putString 				// String ausgeben
	mov r0, r10						// Dauer als Parameter an UP uebergeben
    bl user_printMinAndMaxVector	// Vektoren min und max ausgeben
    
    ldr r0, =str_markierung_ende	// Zeiger auf String laden
	bl uart_putString 				// String ausgeben
	b loop_program					// An Anfang springen


/**
 * Liest einen Vektor byte-weise vom Terminal ein und
 * schreibt diesen in den Speicher.
 * @parameter R0 - Adresse des ersten Vektor-Elements (in den geschrieben wird)
 * @parameter R1 - Anzahl der zu schreibenden Bytes
 */	
.thumb_func
user_readInByteVector:
	push {R4, R5, LR}			// Register sichern
	// Start UP
	mov r4, r0					// wir brauchen R0 und R1 fuer andere UP
	mov r5, r1					
	ldr r0, =str_eingabe_teil1	// Zeiger auf String laden
	bl uart_putString 			// String ausgeben
	mov r0, r5					// Byte-Anzahl ausgeben
	bl uart_putByteBase10
	ldr r0, =str_eingabe_teil2	// Zeiger auf String laden
	bl uart_putString 			// String ausgeben
	
	// Eingabeschleife
loop_vector_input:
	ldr r0, =str_prompt		// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	bl uart_getByte			// ein Byte lesen
	strb r0, [r4], #1		// im Array ablegen und Adresse in R4 um eins erhoehen
	bl uart_putByte			// das Byte ausgeben
	subs r5, r5, #1			// Zaehler dekrementieren
	bne loop_vector_input	// solange Zaehler noch nicht null
	// Ende UP
	pop {R4, R5, PC}		// Register wieder herstellen
	
/**
 * Gibt Min-, Max-Vektor und die Dauer fuer deren Bestimmung aus.
 * @parameter R0 - Dauer der Routine
 */
.thumb_func
user_printMinAndMaxVector:
	push {R4, LR}					// Register sichern
	// Start UP
	mov r4, r0						// wir brauchen die Dauer (Parameter) spaeter
	ldr r0, =str_ausgabe_min		// Min-Text laden
	bl uart_putString 				// und ausgeben
	ldr r1, =vector_min				// Zeiger auf Vektor-Startadresse holen
	ldr r0, [r1]					// Die 4 Bytes des Vektor in R0 laden
	bl uart_putInt32				// und ausgeben
	ldr r0, =str_ausgabe_max		// Max-Text laden (bzw. dessen Startadresse)
	bl uart_putString 				// und ausgeben
	ldr r1, =vector_max				// Zeiger auf Vektor-Startadresse holen
	ldr r0, [r1]					// Die 4 Bytes des Vektor in R0 laden
	bl uart_putInt32				// und ausgeben (in Hex)
	ldr r0, =str_ausgabe_dauer		// Zeiger auf String laden
	bl uart_putString 				// String ausgeben
	mov r0, r4						// Dauer in R0 laden
	bl uart_putByteBase10			// Dauer in dez ausgeben
	// Ende UP
	pop {R4,PC}						// Register wieder herstellen


/*** Datenbereich (ab 0x20000000) ***/
.data
vector_1:
	.rept VECTOR_BYTESIZE
	.byte 0x00
	.endr
vector_2:
	.rept VECTOR_BYTESIZE
	.byte 0x00
	.endr
vector_min:
	.rept VECTOR_BYTESIZE
	.byte 0x00
	.endr
vector_max:
	.rept VECTOR_BYTESIZE
	.byte 0x00
	.endr
str_prompt: .asciz "\n>0x"
str_welcome: .asciz "Versuch 1-3: DSP-Befehle (mit Vektoren)\n"
str_eingabe_teil1: .asciz "\nBitte "
str_eingabe_teil2: .asciz " Bytes eines Vektors sukzessiv eingeben (LSB zuerst)!"
str_ausgabe_v1: .asciz "\nv1: 0x"
str_ausgabe_v2: .asciz "\nv2: 0x"
str_ausgabe_min: .asciz "\n- min: 0x"
str_ausgabe_max: .asciz "\n- max: 0x"
str_ausgabe_dauer: .asciz "\n- Dauer in Zyklen (dez): "
str_header_ohne_dsp: .asciz "\nohne DSP - Befehle:"
str_header_mit_dsp: .asciz "\nmit DSP - Befehlen:"
str_markierung_ende: .asciz "\n# # # # # # # # # #\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ MATRIX_ELEMENT_COUNT, 0x10	// Anzahl der Matrixelemente (16)
.equ CHAR_LINE_FEED, 0x0A		// Zeichen LF ('\n')
.equ CHAR_SPACE, 0x20			// Zeichen Leerzeichen (' ')
.equ VALUE_A, 0xA4367C7B		// siehe Aufgabe 1d
.equ VALUE_B, 0x10A78933		// siehe Aufgabe 1d
.equ VALUE_C, 0xC5535F2C		// siehe Aufgabe 1d
.equ VALUE_D, 0x788E84B1		// siehe Aufgabe 1d

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
 * Zu 1a)
 * Matrixmultiplikation fuer ein Element: Multiplikation der jeweiligen Zeile von M mit der jeweiligen Spalte von N.
 * Also speichern wir Matrix M zeilenweise ab und Matrix N spaltenweise.
 *
 * Pro Element der Ergebnismatrix sind vier Multiplikationen (und Additionen) notwendig.
 * Mit Hilfe des DSPs sind nur zwei smlad-Operationen notwendig um ein Element zu berechnen.
 * Wir sparen uns also die Haelfte an Multiplikationsbefehlen.
 */
 
 /*
  * zu 1d)
  * Ausgabe:
  * UADD16:  B4DD_05AE 6989_DBA7 1CC4_012C
  * SADD16:  B4DD_05AE 6989_DBA7 1CC4_012C
  * UQADD16: B4DD_FFFF FFFF_DBA7 FFFF_FFFF
  * QADD16:  B4DD_05AE 8000_7FFF 1CC4_012C
  
    Allgemein kann bei einer Addition ein Overflow nur dann erfolgen wenn beide Operanden
    entweder positiv oder negativ sind.
  
    (bei UADD16 und SADD16 werden nur die niederwertigen 16 Bits des Ergebnisses beachtet,
     die anderen Bits werden abgeschnitten)
   
    Nur bei UQADD16 und QADD16 kann eine Saettigung auftreten.
    UQADD16:
    - hier werden alle Halbwoerter als unsigned interpretiert
    - A + B ergibt B4DD und 105AE, da 105AE zu gross ist, wird es auf FFFF begrenzt (Saettigung)
    - A + C ergibt 16989 und DBA7, da 16989 zu gross ist, wird es auf FFFF begrenzt (Saettigung)
    - A + D ergibt 11CC4 und 1012C, da beide zu gross sind, werden sie auf FFFF begrenzt (Saettigung)
    QADD16:
    - hier werden alle Halbwoerter als signed interpretiert
    - A + B = (A436 + 10A7) = (negative Zahl + positive Zahl) und (7C7B + 8933) = (pos. Zahl + neg. Zahl) => beides Mal kein Overflow
    - A + C = (A436 + C553) = (neg. Zahl + neg. Zahl) => Overflow und (7C7B + 5F2C) = (pos. Zahl + pos.Zahl) => Overflow, weshalb beide Halbwoerter gesaettigt sind
    - A + D = (A436 + 788E) = (neg. Zahl + pos. Zahl) und (7C7B + 84B1) = (pos. Zahl + neg. Zahl) => beides Mal kein Overflow
  */
  
 /*
  * zu 1e)
  * Ausgabe:
  * SSAT16: F000_0FFF 0FFF_F000
  * USAT16: 0000_1FFF 10A7_0000
  
    zum Vergleich A und B:
            A436_7C7B 10A7_8933
   	-(2^12)    = -4096 = 0xF000,
   	  2^12 - 1 =  4095 = 0x0FFF,
   	  2^13 - 1 =  8191 = 0x1FFF
   	  
    SSAT16 und USAT16 interpretieren beide die Halbwoerter aus A und B als signed.
    SSAT16 saettigt fuer 13 Bits im Bereich -4096 <= x <= 4095
    USAT16 saettigt fuer 13 Bits im Bereich     0 <= x <= 8191 
   	
   	SSAT16 Verhalten:
   	0xA436 < 0xF000 => Saettigung auf 0xF000
   	0x7C7B > 0x0FFF => Saettigung auf 0x0FFF
   	0x10A7 > 0x0FFF => Saettigung auf 0x0FFF
   	0x8933 < 0xF000 => Saettigung auf 0xF000
   	
   	USAT16 Verhalten:
    0xA436 (s) < 0x0000 (u)  => Saettigung auf 0x0000
    0x7C7B (s) > 0x1FFF (u)  => Saettigung auf 0x1FFF
    0x0000 (u) < 0x10A7 (s) < 0x1FFF (u) => keine Saettigung notwendig
   	0x8933 (s) < 0x0000 (u)  => Saettigung auf 0x0000
  */
  
main:	
	bl uart_init

	// Willkommenstext ausgeben
	ldr r0, =str_welcome
	bl uart_putString
	
	// Adressen der Matrizen laden
	ldr r4, =matrix_m
	ldr r5, =matrix_n
	ldr r6, =matrix_o
	
	// Zeile 1 der Ergebnismatrix befuellen
	// Argumente vorbereiten
	mov r0, r4				// Adresse der ersten Zeile der M-Matrix
	mov r1, r5				// Adresse des Elements n11 (N-Matrix)
	mov r2, r6				// Adresse der ersten Zeile der O-Matrix
	bl user_calcMatrixRow	// erste Zeile der O-Matrix berechnen und befuellen
	
	// Zeile 2 der Ergebnismatrix befuellen
	mov r2, r0 				// Adresse der zweiten Zeile der O-Matrix
	add r0, r4, #8			// Adresse der zweiten Zeile der M-Matrix
	mov r1, r5				// Adresse des Elements n11 (N-Matrix)
	bl user_calcMatrixRow	// zweite Zeile der O-Matrix berechnen und befuellen
	
	// Zeile 3 der Ergebnismatrix befuellen
	mov r2, r0 				// Adresse der dritten Zeile der O-Matrix
	add r0, r4, #16			// Adresse der dritten Zeile der M-Matrix
	mov r1, r5				// Adresse des Elements n11 (N-Matrix)
	bl user_calcMatrixRow	// dritte Zeile der O-Matrix berechnen und befuellen
	
	// Zeile 4 der Ergebnismatrix befuellen
	mov r2, r0 				// Adresse der vierten Zeile der O-Matrix
	add r0, r4, #24			// Adresse der vierten Zeile der M-Matrix
	mov r1, r5				// Adresse des Elements n11 (N-Matrix)
	bl user_calcMatrixRow	// vierte Zeile der O-Matrix berechnen und befuellen
	
	// Titelzeile der Ergebnismatrix ausgeben
	ldr r0, =str_ergebnismatrix_header
	bl uart_putString
	
	// Ergebnismatrix ausgeben
	mov r0, r6				// Adresse der ersten Zeile laden
	bl user_printMatrixRow	// erste Zeile ausgeben
	add r0, r6, #16			// Adresse der zweiten Zeile laden (4 Elemente * 4 Byte = Offset von 16)
	bl user_printMatrixRow	// zweite Zeile ausgeben
	add r0, r6, #32			// Adresse der dritten Zeile laden
	bl user_printMatrixRow	// dritte Zeile ausgeben
	add r0, r6, #48			// Adresse der vierten Zeile laden
	bl user_printMatrixRow	// vierte Zeile ausgeben
	
	// [Aufgabe 1b)]: Wir kopieren die Ergebnismatrix
	// Titelzeile der Kopie-Matrix ausgeben
	ldr r0, =str_copy_matrix_header
	bl uart_putString
	
	ldr r8, =matrix_o			// Adresse der Original-Matrix laden
	ldr r10, =matrix_o_copy		// Adresse der Kopie-Matrix laden
	
	ldm r8!, {r0-r7}	// die ersten acht Elemente von Matrix O laden (=kopieren) und die aktuelle Adresse in R8 zurueck schreiben
	stm r10!, {r0-r7}	// die kopierten acht Elemente in die Kopie-Matrix schreiben und die aktuelle Adresse in R8 zurueck schreiben
	ldm r8, {r0-r7}		// die naechsten acht Elemente von Matrix O laden (=kopieren)
	stm r10, {r0-r7}	// die kopierten acht Elemente in die Kopie-Matrix schreiben
	
	// [Aufgabe 1c)]: Wir berechnen die Summe der Element-Produkte
	// Anders gesagt, wird hier die Summe aus den Diagonalelementen der Matrix O benoetigt
	ldr r0, =matrix_o
	ldr r1, [r0], #20 	// o11 in r1 laden und r0 auf o22 zeigen lassen
	ldr r2, [r0], #20	// o22 in r2 laden und r0 auf o33 zeigen lassen
	add r1, r1, r2		// o11 und o22 addieren und in r1 sichern
	ldr r2, [r0], #20	// o33 in r2 laden und r0 auf o44 zeigen lassen
	add r1, r1, r2		// aufsummieren
	ldr r2, [r0]		// o44 in r2 laden
	add r1, r1, r2		// aufsummieren
	
	// Titelzeile der Produkt-Summe ausgeben
	ldr r0, =str_produkt_summe_header
	bl uart_putString
	// Summe ausgeben
	mov r0, r1
	bl uart_putInt32
	// Zeile mit LF beenden
	mov r0, #CHAR_LINE_FEED
	bl uart_putChar
	
	// [Aufgabe 1d)]: Saettigung testen
	ldr r4, =VALUE_A		// A in r4 schreiben
	ldr r5, =VALUE_B		// B in r5 schreiben
	ldr r6, =VALUE_C		// C in r6 schreiben
	ldr r7, =VALUE_D		// D in r7 schreiben
	
	// UADD16-Zeile ausgeben
	ldr r0, =str_prefix_uadd16
	bl uart_putString
	uadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	uadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	uadd16 r0, r4, r7
	bl uart_putInt32
	
	// SADD16-Zeile ausgeben
	ldr r0, =str_prefix_sadd16
	bl uart_putString
	sadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	sadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	sadd16 r0, r4, r7
	bl uart_putInt32
	
	// UQADD16-Zeile ausgeben
	ldr r0, =str_prefix_uqadd16
	bl uart_putString
	uqadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	uqadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	uqadd16 r0, r4, r7
	bl uart_putInt32
	
	// QADD16-Zeile ausgeben
	ldr r0, =str_prefix_qadd16
	bl uart_putString
	qadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	qadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #CHAR_SPACE
	bl uart_putChar
	qadd16 r0, r4, r7
	bl uart_putInt32
	// Leerzeile ausgeben
	mov r0, #CHAR_LINE_FEED
	bl uart_putChar
	
	// [Aufgabe 1e)]: 13-Bit-Saettigung
	// 3.7.3 SSAT16 and USAT16 sind die Befehle die wir brauchen
	
	// SSAT16-Zeile ausgeben
	ldr r0, =str_prefix_ssat16
	bl uart_putString
	ssat16 r0, #13, r4		// A auf 13 Bit saettigen
	bl uart_putInt32
	mov r0, #CHAR_SPACE		// Werte mit Leerzeichen trennen
	bl uart_putChar
	ssat16 r0, #13, r5		// B auf 13 Bit saettigen
	bl uart_putInt32
	
	// USAT16-Zeile ausgeben
	ldr r0, =str_prefix_usat16
	bl uart_putString
	usat16 r0, #13, r4		// A auf 13 Bit saettigen
	bl uart_putInt32
	mov r0, #CHAR_SPACE		// Werte mit Leerzeichen trennen
	bl uart_putChar
	usat16 r0, #13, r5		// B auf 13 Bit saettigen
	bl uart_putInt32
	
end:
	b end
	

/**
 * Berechnet eine Zeile der Ergebnismatrix O.
 * @parameter R0 - Adresse des ersten Zeilenelements von Matrix M
 * @parameter R1 - Adresse des Elements n11 von Matrix N
 * @parameter R2 - Adresse des ersten Zeilenelements von Matrix O
 * @return R0 - Adresse der naechsten Zeile von Matrix O
 */	
.thumb_func
user_calcMatrixRow:
	push {R4, R5, R6, LR}		// Register sichern
	// Start UP
	mov r4, r0					// wir brauchen R0 und R1 fuer andere UP
	mov r5, r1
	mov r6, r2
	
	// Die Kommentare sind exemplarisch fuer Zeile 1 der Matrix M und O
	mov r2, #0				// Akkumlator initialisieren
	ldr r0, [r4]			// Elemente m11 und m12 laden [name_zeile_splate]
	ldr r1, [r5], #4		// Elemente n11 und n21 laden [name_zeile_splate]
	smlad r2, r0, r1, r2	// r2 = r2 + m11 * n11 + m12 * n21
	ldr r0, [r4, #4]		// Elemente m13 und m14 laden
	ldr r1, [r5], #4		// Elemente n31 und n41 laden
	smlad r2, r0, r1, r2	// r2 = r2 + m13 * n31 + m14 * n41
	str r2, [r6], #4		// o11 in Speicher schreiben und Adresse erhoehen (auf o12)
	
	mov r2, #0				// Akkumlator initialisieren
	ldr r0, [r4]			// Elemente m11 und m12 laden
	ldr r1, [r5], #4		// Elemente n12 und n22 laden
	smlad r2, r0, r1, r2	// r2 = r2 + m11 * n12 + m12 * n22
	ldr r0, [r4, #4]		// Elemente m13 und m14 laden
	ldr r1, [r5], #4		// Elemente n32 und n42 laden
	smlad r2, r0, r1, r2	// r2 = r2 + m13 * n32 + m14 * n42
	str r2, [r6], #4		// o12 in Speicher schreiben und Adresse erhoehen (auf o13)
	
	mov r2, #0				// Akkumlator initialisieren
	ldr r0, [r4]			// Elemente m11 und m12 laden
	ldr r1, [r5], #4		// Elemente n13 und n23 laden
	smlad r2, r0, r1, r2	// r2 = r2 + m11 * n13 + m12 * n23
	ldr r0, [r4, #4]		// Elemente m13 und m14 laden
	ldr r1, [r5], #4		// Elemente n33 und n43 laden
	smlad r2, r0, r1, r2	// r2 = r2 + m13 * n33 + m14 * n43
	str r2, [r6], #4		// o13 in Speicher schreiben und Adresse erhoehen (auf o14)
	
	mov r2, #0				// Akkumlator initialisieren
	ldr r0, [r4]			// Elemente m11 und m12 laden
	ldr r1, [r5], #4		// Elemente n14 und n24 laden
	smlad r2, r0, r1, r2	// r2 = r2 + m11 * n14 + m12 * n24
	ldr r0, [r4, #4]		// Elemente m13 und m14 laden
	ldr r1, [r5]			// Elemente n34 und n44 laden
	smlad r2, r0, r1, r2	// r2 = r2 + m13 * n33 + m14 * n43
	str r2, [r6], #4		// o14 in Speicher schreiben und Adresse erhoehen (auf o21)
	
	mov r0, r6				// Adresse des naechsten Elements der Matrix O
	
	// Ende UP
	pop {R4, R5, R6, PC}						// Register wieder herstellen
	
/**
 * Gibt eine Zeile mit vier Int32-Elementen einer Matrix im Terminal aus.
 * @parameter R0 - Adresse des ersten Zeilenelements
 
 */	
.thumb_func
user_printMatrixRow:
	push {R4, LR}				// Register sichern
	// Start UP
	mov r4, r0					// Adresse der ersten Zeilenelements
	
	ldr r0, [r4], #4			// erstes Element in r0 laden und Adresse erhoehen
	bl uart_putInt32			// Element in hex ausgeben
	// Leerzeichen ausgeben (Trenner zwischen Elementen)
	mov r0, #CHAR_SPACE
	bl uart_putChar
	
	ldr r0, [r4], #4			// zweites Element in r0 laden und Adresse erhoehen
	bl uart_putInt32			// Element in hex ausgeben
	// Leerzeichen ausgeben (Trenner zwischen Elementen)
	mov r0, #CHAR_SPACE
	bl uart_putChar
	
	ldr r0, [r4], #4			// drittes Element in r0 laden und Adresse erhoehen
	bl uart_putInt32			// Element in hex ausgeben
	// Leerzeichen ausgeben (Trenner zwischen Elementen)
	mov r0, #CHAR_SPACE
	bl uart_putChar
	
	ldr r0, [r4]				// viertes Element in r0 laden
	bl uart_putInt32			// Element in hex ausgeben
	// Zeile mit LF beenden
	mov r0, #CHAR_LINE_FEED
	bl uart_putChar

	// Ende UP
	pop {R4, PC}				// Register wieder herstellen
			

/*** Datenbereich (ab 0x20000000) ***/
.data
matrix_m: .hword 0x5f8c,0x7f48,0x8245,0x6048,0xc799,0x9c5d,0xd49c,0x33d8,0x579b,0x8aef,0xf2c0,0xa3c2,0x41fd,0x50d4,0x25c6,0x4afa
matrix_n: .hword 0x7f41,0x0645,0x8c8f,0x9065,0x78e3,0xf7f3,0xd29f,0x2961,0x5a1e,0xdfed,0x4b9f,0x1092,0x61bf,0x21be,0x5ca1,0xc6d3
matrix_o:
	.rept MATRIX_ELEMENT_COUNT
	.word 0x0000
	.endr
matrix_o_copy:
	.rept MATRIX_ELEMENT_COUNT
	.word 0x0000
	.endr
str_welcome: .asciz "Versuch 2-1: DSP-Befehle 2 (Matrizenmultiplikation)\n"
str_ergebnismatrix_header: .asciz "Ergebnismatrix O:\n"
str_copy_matrix_header: .asciz "\nKopieren der Matrix O!\n"
str_produkt_summe_header: .asciz "\nProdukt -Summe: "
str_prefix_uadd16: .asciz "\nUADD16: "
str_prefix_sadd16: .asciz "\nSADD16: "
str_prefix_uqadd16: .asciz "\nUQADD16: "
str_prefix_qadd16: .asciz "\nQADD16: SSAT16 "
str_prefix_ssat16: .asciz "\nSSAT16: "
str_prefix_usat16: .asciz "\nUSAT16: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ DURATION_MEAS_CORR_OFFSET, 0x0B			// Correction offset used to calculate durations with PIT
.equ LOOP_COUNTER_START_VALUE,  0x7F2811		// Start value of the loop counter needed for a delay of about 1s

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
 * sub task a)
 * 25MHz frequency == 25,000,000 (0x17D7840) cycles per second == 40ns cycle duration
 * we can measure the duration needed to call delay and to return from it:
 * 		bl pit3_getval
 * 		bl delay
 * 		bl pit3_getval
 * (should be more accurate than using a stop watch)
 */
main:	
	bl uart_init
	
	mov r10, #1					// register used to determine run-stop-state (boolean)
	mov r11, #0					// register to buffer user input (char)
	bl user_printDateAndTime	// print date and time
	
loop_program:
	bl delay					// wait for about 1s
	
	cmp r10, #0					// if r10 == 0x0 then stop, else run
	beq label_check_input		// skip the incrementing of the time if r10 == 0
	
	// laod date and time variables
	ldr r0, =var_minute		// load address of minute variable
	ldr r4, [r0]			// load month value into R4
	ldr r0, =var_hour		// load address of hour variable
	ldr r5, [r0]			// load hour value into R5
	ldr r0, =var_day		// load address of day variable
	ldr r6, [r0]			// load day value into R6
	ldr r0, =var_month		// load address of month variable
	ldr r7, [r0]			// load month value into R7
	ldr r0, =var_year		// load address of year variable
	ldr r8, [r0]			// load year value into R8
	
	add r4, r4, #1			// increment the minutes variable
	// check if minutes reached the value 60
	// if yes: set minutes to 0 and increment the hours variable
	cmp r4, #59
	itt hi
	movhi r4, #0
	addhi r5, r5, #1
	
	// check if hours reached the value 24
	// if yes: set hours to 0 and increment the days variable
	cmp r5, #23
	itt hi
	movhi r5, #0
	addhi r6, r6, #1
	
	// check if days reached the value 31
	// if yes: set days to 1 and increment the months variable
	cmp r6, #30
	itt hi
	movhi r6, #1
	addhi r7, r7, #1
	
	// check if months reached the value 13
	// if yes: set days to 1 and increment the years variable
	cmp r7, #12
	itt hi
	movhi r7, #1
	addhi r8, r8, #1
	
	// store date and time variables
	ldr r0, =var_minute		// load address of minute variable
	str r4, [r0]			// update minute variable
	ldr r0, =var_hour		// load address of hour variable
	str r5, [r0]			// update hour variable
	ldr r0, =var_day		// load address of day variable
	str r6, [r0]			// update day variable
	ldr r0, =var_month		// load address of month variable
	str r7, [r0]			// update month variable
	ldr r0, =var_year		// load address of year variable
	str r8, [r0]			// update year variable

label_check_input:
	// check if a char is present and if it is present read it
	// it should be enough to check for user input only every second
	bl uart_charPresent
	cmp r0, #0
	it ne					// if r0 != 0
	blne uart_getChar 		// read char from terminal
	
	mov r11, r0				// store r0 in r11	
	cmp r11, #0x73 			// char == 's'?
	it eq					// if yes, then
	eoreq r10, r10, #0x01	// toogle the run-stop-mode boolean

	cmp r11, #0x74 			// char == 't'?
	it eq					// if yes, then
	bleq user_readAndUpdateTime // call sub routine
	
	cmp r11, #0x64 			// char == 'd'?
	it eq					// if yes, then
	bleq user_readAndUpdateDate // call sub routine
	
	bl user_printDateAndTime	// print date and time
	
	b loop_program			// go back to start

	
/**
 * Executes a delay of about 1 sec using busy waiting.
 * (Use PIT3 to determine the duration of "bl delay")
 */	
.thumb_func
delay:
	push {LR}							// save registers (duration: 1+N cycles (= 2 cycles))
	// Start of subroutine
	// 25MHz frequency == 25,000,000 (0x17D_7840) cycles per second == 40ns cycle duration
	// duration measurement
	// [duration_in_cycles (PIT3), repition counter]
	// 0x047868CB, 0x017D7840
	// 0x0180000A, 0x00800000
	// 0x016CB00B, 0x00799000
	// 0x016CB00E, 0x00799001 => increment counter by 1 to increment cycle count by 3
	// 0x017D783E, 0x007F2811
	
	// small check: 0x017D7840 / 3 = 0x007F2815
	
	// it's okay to have a delay that is a little bit shorter,
	// since the operations executed after delay will take some time (several cycles) 
	ldr r1, =LOOP_COUNTER_START_VALUE 	// load repition counter (duration: 2 cycles)
loop_delay:
	subs r1, r1, #1						// decrement counter (duration: 1 cycle)
	bne loop_delay						// repeat loop until we reach counter value 0 (duration: 1+P cycles (= 2 to 4 cycles))
	
	// End  of subroutine
	pop {PC}							// restore registers (duration: 1+N+P cycles (= 3 to 5 cycles))

/**
 * Prints date and time with a predefined format to the terminal.
 */	
.thumb_func
user_printDateAndTime:
	push {R4, R5, LR}							// save registers
	// Start of subroutine
	// we can assume all values to be unsigned
	// reason: dd, mm, jj, hh and mm are all less than 100 (decimal)
	
	mov r4, #0x0A			// needed to ensure that for each value 2 digits are printed
	
	ldr r0, =var_day		// load address of day variable
	ldr r5, [r0]			// load day value into R5
	
	// if the value of day is less than 10 (R2)
	// we have to print an extra 0
	mov r0, #0x30			// load ASCII-Code for 0
	cmp r4, r5				// check if day is less than 10
	it hi					// if day is less than 10,
	blhi uart_putChar		// print the char 0
	
	mov r0, r5				// load day value to r0
	bl uart_putByteBase10	// print day in decimal format
	mov r0, #0x2E			// load ASCII-Code for dot
	bl uart_putChar			// print the dot char
	
	ldr r0, =var_month		// load address of month variable
	ldr r5, [r0]			// load month value into R5
	
	// if the value of month is less than 10 (R2)
	// we have to print an extra 0
	mov r0, #0x30			// load ASCII-Code for 0
	cmp r4, r5				// check if month is less than 10
	it hi					// if month is less than 10,
	blhi uart_putChar		// print the char 0
	
	mov r0, r5				// load month value to r0
	bl uart_putByteBase10	// print month in decimal format
	mov r0, #0x2E			// load ASCII-Code for dot
	bl uart_putChar			// print the dot char
	
	// we assume the year to be between 2000 and 2099
	// so we print the first two digits of the year in decimal format
	mov r0, #20
	bl uart_putByteBase10
	
	ldr r0, =var_year		// load address of year variable
	ldr r5, [r0]			// load year value into R5
	
	// if the value of year is less than 10 (R2)
	// we have to print an extra 0
	mov r0, #0x30			// load ASCII-Code for 0
	cmp r4, r5				// check if year is less than 10
	it hi					// if year is less than 10,
	blhi uart_putChar		// print the char 0
	
	mov r0, r5				// load year value to r0
	bl uart_putByteBase10	// print year in decimal format
	mov r0, #0x20			// load ASCII-Code for SPACE
	bl uart_putChar			// print the space char
	
	ldr r0, =var_hour		// load address of hour variable
	ldr r5, [r0]			// load hour value into R5
	
	// if the value of hour is less than 10 (R2)
	// we have to print an extra 0
	mov r0, #0x30			// load ASCII-Code for 0
	cmp r4, r5				// check if hour is less than 10
	it hi					// if hour is less than 10,
	blhi uart_putChar		// print the char 0
	
	mov r0, r5				// load hour value to r0
	bl uart_putByteBase10	// print hour in decimal format
	mov r0, #0x3A			// load ASCII-Code for colon
	bl uart_putChar			// print the colon char
	
	ldr r0, =var_minute		// load address of minute variable
	ldr r5, [r0]			// load minute value into R5
	
	// if the value of minute is less than 10 (R2)
	// we have to print an extra 0
	mov r0, #0x30			// load ASCII-Code for 0
	cmp r4, r5				// check if minute is less than 10
	it hi					// if minute is less than 10,
	blhi uart_putChar		// print the char 0
	
	mov r0, r5				// load minute value to r0
	bl uart_putByteBase10	// print minute in decimal format
	
	ldr r0, =str_time_suffix	// load pointer to string
	bl uart_putString			// print string
	
	// End  of subroutine
	pop {R4, R5, PC}							// restore registers


/**
 * Reads hour and minutes from terminal and updates the regarding memory.
 */	
.thumb_func
user_readAndUpdateTime:
	push {R4, R5, LR}							// save registers
	// Start  of subroutine
	ldr r0, =str_hour_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read hour from terminal
	mov r4, r0					// store hour input in R4
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_minutes_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read minutes from terminal
	mov r5, r0					// store minutes input in R5
	bl uart_putByteBase10 		// and print the input as feedback
	
	// do not forget to start a new line
	mov r0, #0xA
	bl uart_putChar
	
	ldr r0, =var_hour		// load address of hour variable
	str r4, [r0]			// store hour value to memory
	
	ldr r0, =var_minute		// load address of minute variable
	str r5, [r0]			// store minute value to memory
	
	// End  of subroutine
	pop {R4, R5, PC}							// restore registers
	
	
/**
 * Reads day, month and year from terminal and updates the regarding memory.
 */	
.thumb_func
user_readAndUpdateDate:
	push {R4-R6, LR}							// save registers
	// Start  of subroutine
	ldr r0, =str_day_prompt		// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read day from terminal
	mov r4, r0					// store day input in R4
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_month_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read month from terminal
	mov r5, r0					// store month input in R5
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_year_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read year from terminal
	mov r6, r0					// store year input in R5
	bl uart_putByteBase10 		// and print the input as feedback
	
	// do not forget to start a new line
	mov r0, #0xA
	bl uart_putChar
	
	ldr r0, =var_day		// load address of day variable
	str r4, [r0]			// store day value to memory
	
	ldr r0, =var_month		// load address of month variable
	str r5, [r0]			// store month value to memory
	
	ldr r0, =var_year		// load address of year variable
	str r6, [r0]			// store year value to memory
	
	// End  of subroutine
	pop {R4-R6, PC}							// restore registers


/*** Datenbereich (ab 0x20000000) ***/
.data
var_year: .word 0x000E
var_month: .word 0x0001
var_day: .word 0x0001
var_hour: .word 0x0000
var_minute: .word 0x0000
str_time_suffix: .asciz " Uhr\n"
str_hour_prompt: .asciz "\nStunde eingeben (hh): "
str_minutes_prompt: .asciz "\nMinuten eingeben (mm): "
str_day_prompt: .asciz "\nTag eingeben (dd): "
str_month_prompt: .asciz "\nMonat eingeben (mm): "
str_year_prompt: .asciz "\nJahr eingeben (yy): "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ ADDR_SIM_SCGC6, 0x4004803C			// address of System Clock Gating Control Register 6
.equ ADDR_SCR_VTOR,  0xE000ED08			// address of Vector Table Offset Register
.equ OFFSET_VT_PIT1, 0x0154				// offset to the vector of PIT1
// 0xE000E280 - 0xE000E29C NVIC_ICPR0 - NVIC_ICPR7 RW 0x00000000 Interrupt Clear-Pending Registers
// 0xE000E100 - 0xE000E11C NVIC_ISER0 - NVIC_ISER7 RW 0x00000000 Interrupt Set-Enable Registers
.equ ADDR_NVIC_ICPR2, 0xE000E288		// address of ICPR2
.equ ADDR_NVIC_ISER2, 0xE000E108		// address of ISER2
.equ ADDR_PIT_MCR,    0x40037000		// address of PIT Module Control Register
.equ ADDR_PIT_LDVAL1, 0x40037110		// address of Timer Load Value Register of PIT1
.equ ADDR_PIT_TCTRL1, 0x40037118		// address of Timer Control Register of PIT1
.equ ADDR_PIT_TFLG1,  0x4003711C		// address of Timer Flag Register of PIT1
.equ LDVAL1_TRIGGER,  0x017D783F		// Timer start value of PIT1 needed for a period of 1 second
// addresses needed to use bit banding
.equ ADDR_BITBAND_MASK_BIT0,  0x22000000		// Address of bit band word used to set bit 0 of the byte at address 0x20000000
.equ ADDR_BITBAND_MASK_BIT1,  0x22000004		// Address of bit band word used to set bit 1 of the byte at address 0x20000000

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	// initialize uart and pit1
	bl uart_init
	
	// a) first we have to enable the PIT clock, so that we can initialize PIT1.
	// Thus we have to set bit 23 of SIM_SCGC6
	mov r0, #1
	lsl r0, r0, #23				// set only bit 23
	ldr r1, =ADDR_SIM_SCGC6		// load the address of SIM_SCGC6 into r1
	ldr r2, [r1]				// get the current value of SIM_SCGC6
	orr r2, r2, r0				// set bit 23 of r2
	str r2, [r1]				// update the register SIM_SCGC6
	
	// b) now we have to set the interrupt vector
	// first we need the base address of the VT (vector table)
	ldr r0, =ADDR_SCR_VTOR		// load the address of the Vector Table Offset Register
	ldr r1, [r0]				// get the base address of the vector table
	// r1 should have value 0x1FFF_FE00
	mov r0, #OFFSET_VT_PIT1		// load offset to PIT1 vector
	add r0, r0, r1				// get address of PIT1 vector
	ldr r1, =PIT1_IRQHandler	// get address of our ISR
	str r1, [r0]				// set pit1_handler as our new handler of the PIT1 interrupt
	
	// c) clear all pending interrupts regarding PIT1.
	// Thus set the bit NVIC_ICPR2[5]
	ldr r0, =ADDR_NVIC_ICPR2	// load address of NVIC_ICPR2
	mov r1, #0x20				// set bit 5
	str r1, [r0]				// clear the pending state of the PIT1 interrupt
	
	// d) enable PIT1 interrupt in NVIC
	// Thus set the bit NVIC_ISER2[5]
	ldr r0, =ADDR_NVIC_ISER2	// load address of NVIC_ISER2
	mov r1, #0x20				// set bit 5
	str r1, [r0]				// enable the PIT1 interrupt
	
	// e) enable clock for PIT timers with timers running in debug mode (in PIT_MCR)
	ldr r0, =ADDR_PIT_MCR		// load address of PIT_MCR
	mov r1, #0x00				// set bit 5
	str r1, [r0]				// enable clock for PIT
	
	// f) initialize Load Value Register for a period of 1 second
	// The 25 MHz clock frequency equates to a clock period of 40ns.
	// 1s / 40ns =  25,000,000 cycles (= 0x17D_7840)
	// LDVAL trigger = (period / clock period) - 1 = 0x17D_7840 - 1
	ldr r0, =ADDR_PIT_LDVAL1		// load address of PIT_LDVAL1
	ldr r1, =LDVAL1_TRIGGER			// load timer start value
	str r1, [r0]					// write timer start value of PIT1
	
	// first reset the bitmask (just in case)
	ldr r0, =var_bitmask			// load address of bit mask
	mov r1, #0						// load R1 with reset value
	str r1, [r0]					// reset bit mask to 0x0000_0000
	
	// g) enable timer 1 interrupts (set bit 1)
	ldr r0, =ADDR_BITBAND_MASK_BIT1	// load bit banding address in order to set bit 1 of the mask
	mov r1, #0x01
	str r1, [r0]					// set the bit (via bit banding)
	ldr r0, =var_bitmask			// load address of bit mask
	ldr r1, [r0]					// load value of bit mask into R1
	ldr r0, =ADDR_PIT_TCTRL1		// load address of PIT_TCTRL1
	str r1, [r0]					// write config to timer 1 control register
	
	// h) enable timer 1 (set bit 0)
	ldr r0, =ADDR_BITBAND_MASK_BIT0	// load bit banding address in order to set bit 0 of the mask
	mov r1, #0x01
	str r1, [r0]					// set the bit (via bit banding)
	ldr r0, =var_bitmask			// load address of bit mask
	ldr r1, [r0]					// load value of bit mask into R1
	ldr r0, =ADDR_PIT_TCTRL1		// load address of PIT_TCTRL1
	str r1, [r0]					// write config to timer 1 control register
	// finished initialisation
	
	mov r10, #1					// register used to determine run-stop-state (boolean)
	mov r11, #0					// register to buffer user input (char)
	bl user_printDateAndTime	// print date and time
	
loop_program:
	ldr r0, =flag_one_sec_passed
	ldr r1, [r0]				// load value of flag
	cmp r1, #0					// if the flag is not set
	beq loop_program			// go back and check the flag again
	
	// the flag is set, so we have to reset it and go
	mov r1, #0
	str r1, [r0]
	
	cmp r10, #0					// if r10 == 0x0 then stop, else run
	beq label_check_input		// skip the incrementing of the time if r10 == 0
	
	// laod date and time variables
	ldr r0, =var_minute		// load address of minute variable
	ldr r4, [r0]			// load month value into R4
	ldr r0, =var_hour		// load address of hour variable
	ldr r5, [r0]			// load hour value into R5
	ldr r0, =var_day		// load address of day variable
	ldr r6, [r0]			// load day value into R6
	ldr r0, =var_month		// load address of month variable
	ldr r7, [r0]			// load month value into R7
	ldr r0, =var_year		// load address of year variable
	ldr r8, [r0]			// load year value into R8
	
	add r4, r4, #1			// increment the minutes variable
	// check if minutes reached the value 60
	// if yes: set minutes to 0 and increment the hours variable
	cmp r4, #59
	itt hi
	movhi r4, #0
	addhi r5, r5, #1
	
	// check if hours reached the value 24
	// if yes: set hours to 0 and increment the days variable
	cmp r5, #23
	itt hi
	movhi r5, #0
	addhi r6, r6, #1
	
	// check if days reached the value 31
	// if yes: set days to 1 and increment the months variable
	cmp r6, #30
	itt hi
	movhi r6, #1
	addhi r7, r7, #1
	
	// check if months reached the value 13
	// if yes: set days to 1 and increment the years variable
	cmp r7, #12
	itt hi
	movhi r7, #1
	addhi r8, r8, #1
	
	// store date and time variables
	ldr r0, =var_minute		// load address of minute variable
	str r4, [r0]			// update minute variable
	ldr r0, =var_hour		// load address of hour variable
	str r5, [r0]			// update hour variable
	ldr r0, =var_day		// load address of day variable
	str r6, [r0]			// update day variable
	ldr r0, =var_month		// load address of month variable
	str r7, [r0]			// update month variable
	ldr r0, =var_year		// load address of year variable
	str r8, [r0]			// update year variable

label_check_input:
	// check if a char is present and if it is present read it
	// it should be enough to check for user input only every second
	bl uart_charPresent
	cmp r0, #0
	it ne					// if r0 != 0
	blne uart_getChar 		// read char from terminal
	
	mov r11, r0				// store r0 in r11	
	cmp r11, #0x73 			// char == 's'?
	it eq					// if yes, then
	eoreq r10, r10, #0x01	// toogle the run-stop-mode boolean

	cmp r11, #0x74 			// char == 't'?
	it eq					// if yes, then
	bleq user_readAndUpdateTime // call sub routine
	
	cmp r11, #0x64 			// char == 'd'?
	it eq					// if yes, then
	bleq user_readAndUpdateDate // call sub routine
	
	bl user_printDateAndTime	// print date and time
	
	b loop_program			// go back to start
	
	
/**
 * Executes a delay of about 1 sec using busy waiting.
 * (Use PIT3 to determine the duration of "bl delay")
 */
//.global PIT1_IRQHandler
.thumb_func
PIT1_IRQHandler:
	//push {LR}						// save registers
	// Start of subroutine
	
	// clear interrupt flag of PIT1
	ldr r0, =ADDR_PIT_TFLG1			// load address of PIT_TFLG1
	mov r1, #0x01
	str r1, [r0]					// clear the interrupt flag
		
	// now set the one second passed flag
	ldr r0, =flag_one_sec_passed	// load address of one sec passed flag
	mov r1, #0x01
	str r1, [r0]					// set the flag
	
	bx lr
	
	// End  of subroutine
	//pop {PC}						// restore registers
	

/**
 * Prints date and time with a predefined format to the terminal.
