/**
 * Reads day, month and year from terminal and updates the regarding memory.
 */	
.thumb_func
user_readAndUpdateDate:
	push {R4-R6, LR}							// save registers
	// Start  of subroutine
	ldr r0, =str_day_prompt		// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read day from terminal
	mov r4, r0					// store day input in R4
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_month_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read month from terminal
	mov r5, r0					// store month input in R5
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_year_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read year from terminal
	mov r6, r0					// store year input in R5
	bl uart_putByteBase10 		// and print the input as feedback
	
	// do not forget to start a new line
	mov r0, #0xA
	bl uart_putChar
	
	ldr r0, =var_day		// load address of day variable
	str r4, [r0]			// store day value to memory
	
	ldr r0, =var_month		// load address of month variable
	str r5, [r0]			// store month value to memory
	
	ldr r0, =var_year		// load address of year variable
	str r6, [r0]			// store year value to memory
	
	// End  of subroutine
	pop {R4-R6, PC}							// restore registers
	

/*** Datenbereich (ab 0x20000000) ***/
.data
var_bitmask: .word 0x0000				// variable used to set single bits 
flag_one_sec_passed: .word 0x0000		// flag to indicate to main that one second passed
var_year: .word 0x000E
var_month: .word 0x0001
var_day: .word 0x0001
var_hour: .word 0x0000
var_minute: .word 0x0000
str_time_suffix: .asciz " Uhr\n"
str_hour_prompt: .asciz "\nStunde eingeben (hh): "
str_minutes_prompt: .asciz "\nMinuten eingeben (mm): "
str_day_prompt: .asciz "\nTag eingeben (dd): "
str_month_prompt: .asciz "\nMonat eingeben (mm): "
str_year_prompt: .asciz "\nJahr eingeben (yy): "


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ SIM_SCGC6_CRC,  		0x429007C8	// Bit-Band-Alias address of bit 18 of SIM_SCGC6 (CRC clock gate)
.equ CRC_CTRL_WAS,   		0x42640164	// Bit-Band-Alias address of bit 25 of CRC_CTRL (WAS bit)
.equ CRC_CTRL,           	0x40032008	// Address of CRC_CTRL register
.equ INIT_MASK_CRC_CTRL, 	0x03000000	// Mask for "no transposition", "no complement", "32 bit protocol", "set seed"
.equ CRC_GPOLY,          	0x40032004	// Address of CRC_GPOLY register
.equ CRC32_POLYNOMIAL,     	0x04C11DB7	// Polynomial used for CRC generation
.equ CRC_CRC,          		0x40032000	// Address of CRC_CRC register
.equ CRC_GEN_SEED, 			0x12345678	// Seed used for CRC generation
.equ STR_LOOP_COUNT, 		0x12		// Counter used to iterate word-wise over the string

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// we will need the values 0 and 1
	mov r10, #0
	mov r11, #1
	
	// b) first we have to enable the CRC clock, so that we can initialize the CRC generator.
	// Thus we have to set bit 18 of SIM_SCGC6
	// and to initialize the CRC_CTRL register
	ldr r0, =SIM_SCGC6_CRC		// load the address of the bit-band-alias
	str r11, [r0]				// set bit 18 of SIM_SCGC6 to enable CRC clock
	
	ldr r0, =INIT_MASK_CRC_CTRL	// load initial value/config for CRC_CTRL
	ldr r1, =CRC_CTRL			// load the address of CRC_CTRL
	str r0, [r1]				// initialize CRC_CTRL (set init config)
	
	// c) set the polynomial
	ldr r0, =CRC32_POLYNOMIAL	// load value of polynomial
	ldr r1, =CRC_GPOLY			// load the address of CRC_GPOLY
	str r0, [r1]				// set polynomial to use
	
	// d) set the seed
	ldr r0, =CRC_GEN_SEED		// load value of the seed
	ldr r4, =CRC_CRC			// load the address of CRC_CRC
	str r0, [r4]				// set the seed to use
	
	// Clear CTRL[WAS] to start writing data values
	ldr r0, =CRC_CTRL_WAS		// load the address of the bit-band-alias
	str r10, [r0]				// reset bit 25 of CRC_CTRL in order to write data values
	
	// e) iterate through the string (word-wise)
	mov r5, #STR_LOOP_COUNT		// load loop counter
	ldr r6, =str_input			// load start address of the input string
loop_data_iteration:
	ldr r0, [r6], #4			// load sub string (4 chars) and increment address (point to next string part)
	str r0, [r4]				// set CRC data value (substring of length 4)
	subs r5, r5, #1				// decrement counter
	bne loop_data_iteration		// and keep iterating until we reach value 0
	
	// f) print the result
	// first print the input string
	ldr r0, =text_prefix_input
	bl uart_putString
	ldr r0, =str_input
	bl uart_putString
	
	// now print the CRC value
	ldr r0, =text_prefix_result
	bl uart_putString
	ldr r0, [r4]						// load the CRC value
	bl uart_putInt32					// print the CRC value
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
// The string contains 70 Bytes (including the termination char \0)
str_input: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
.space 2	// extend the "buffer" of str to 72 Bytes so that 18 words (18 * 4 Bytes) fit into the buffer
text_prefix_input: .asciz "Text: "
text_prefix_result: .asciz "\nCRC-Pruefwert: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
//.equ DURATION_MEAS_CORR_OFFSET,		0x0B		// Correction offset used to calculate durations with PIT
.equ INTERVAL_5MS_CORRECTED,  124988	// interval of 5ms expressed in cycles of PIT3 already corrected by value 0xB
.equ SIM_SCGC5_PORTA,		0x42900724	// Bit Band Alias for bit 9 (Port A module) of SIM_SCGC5
.equ SIM_SCGC5_PORTE,		0x42900734	// Bit Band Alias for bit 13 (Port E module) of SIM_SCGC5
.equ SIM_SCGC6_PIT,			0x429007DC	// Bit Band Alias for bit 23 (PIT) of SIM_SCGC6
.equ SCR_VTOR,				0xE000ED08	// address of Vector Table Offset Register
.equ OFFSET_VT_PIT1,		0x0154		// offset to the vector of PIT1
.equ OFFSET_VT_PORTE, 		0x01AC		// offset to the vector of port control module E

// 0xE000E280 - 0xE000E29C NVIC_ICPR0 - NVIC_ICPR7 RW 0x00000000 Interrupt Clear-Pending Registers
// 0xE000E100 - 0xE000E11C NVIC_ISER0 - NVIC_ISER7 RW 0x00000000 Interrupt Set-Enable Registers
.equ NVIC_ICPR2, 			0xE000E288		// address of ICPR2
.equ NVIC_ISER2, 			0xE000E108		// address of ISER2
.equ PIT_MCR, 				0x40037000		// address of PIT Module Control Register
.equ PIT_LDVAL1, 			0x40037110		// address of Timer Load Value Register of PIT1
.equ PIT_TCTRL1, 			0x40037118		// address of Timer Control Register of PIT1
.equ PIT_TFLG1, 			0x4003711C		// address of Timer Flag Register of PIT1
.equ PIT_LDVAL1_STARTVALUE,	0x017D783F		// Timer start value of PIT1 needed for a period of 1 second

.equ PORTA_PCR10, 			0x40049028		// address of PORTA_PCR10
.equ PORTA_PCR11, 			0x4004902C		// address of PORTA_PCR11
.equ PORTA_PCR19, 			0x4004904C		// address of PORTA_PCR19
.equ PORTA_PCR28, 			0x40049070		// address of PORTA_PCR28
.equ PORTA_PCR29, 			0x40049074		// address of PORTA_PCR29
.equ PORTE_PCR26, 			0x4004D068		// address of PORTE_PCR26
.equ PORTE_PCR26_ISF, 		0x429A0D60		// address of bit 24 of PORTE_PCR26

// INPUT: Since the switches pull the potential down to ground, we need an internal pullup resistor
// => Switch not pressed = HIGH, Switch pressed = LOW
// MUX = 001 (ALT1), IRQC = 1010 (Interrupt on falling edge)
.equ PCR_SW1_CONFIG, 		0x01000103		// Value of Pin Control Register to configure pin for switch SW1
.equ PCR_SW2_CONFIG, 		0x010A0103		// Value of Pin Control Register to configure pin for switch SW2

// OUTPUT: in order to switch on the LED we have to pull the pins down to ground
// We will use Push-Pull, since Open-Drain causes a floating state, that could switch on the LED unintentionally
.equ PCR_LED_CONFIG, 		0x01000100		// Value of Pin Control Register in order to switch on LEDs

// .equ GPIOA_PCOR,     0x400FF008		// address of GPIOA_PCOR (Port Clear Output Register)
// .equ GPIOA_PDIR,     0x400FF010		// address of GPIOA_PDIR (Port Data Input Register)
// .equ GPIOE_PDIR,     0x400FF110		// address of GPIOE_PDIR
.equ GPIOA_PSOR, 			0x400FF004		// address of GPIOA_PSOR (Port Set Output Register)
.equ GPIOA_PDDR, 			0x400FF014		// address of GPIOA_PDDR (Port Data Direction Register)
.equ GPIOE_PDDR, 			0x400FF114		// address of GPIOE_PDDR

.equ GPIOE_PDIR_BIT26, 		0x43FE2268		// address of GPIOE_PDIR Bit 26 bit band alias (0: pressed, 1: released)
.equ GPIOA_PDIR_BIT19, 		0x43FE024C		// address of GPIOA_PDIR Bit 19 bit band alias (0: pressed, 1: released)
.equ GPIOA_PSOR_BIT10, 		0x43FE00A8		// address of GPIOA_PSOR Bit 10 bit band alias
.equ GPIOA_PSOR_BIT11, 		0x43FE00AC		// address of GPIOA_PSOR Bit 11 bit band alias
.equ GPIOA_PSOR_BIT28, 		0x43FE00F0		// address of GPIOA_PSOR Bit 28 bit band alias
.equ GPIOA_PSOR_BIT29, 		0x43FE00F4		// address of GPIOA_PSOR Bit 29 bit band alias
.equ GPIOA_PCOR_BIT10, 		0x43FE0128		// address of GPIOA_PCOR Bit 10 bit band alias
.equ GPIOA_PCOR_BIT11,  	0x43FE012C		// address of GPIOA_PCOR Bit 11 bit band alias
.equ GPIOA_PCOR_BIT28, 		0x43FE0170		// address of GPIOA_PCOR Bit 28 bit band alias
.equ GPIOA_PCOR_BIT29, 		0x43FE0174		// address of GPIOA_PCOR Bit 29 bit band alias

.equ MOD_SW1_BIT, 			0x22000000		// address of bit band alias of data var_mod, bit 0
.equ MOD_SW2_BIT, 			0x22000004		// address of bit band alias of data var_mod, bit 1

.equ SW1_FLAG_COUNTDIR, 	0x22000080		// bit band alias of data var_switch_flags, bit 0 (count direction)
.equ SW1_FLAG_EDGEDETECT,	0x22000084		// bit band alias of data var_switch_flags, bit 1 (edge detected SW1)
.equ SW1_FLAG_DEBOUNCEOK,	0x22000088		// bit band alias of data var_switch_flags, bit 2 (debounce ok SW1)
.equ SW1_FLAG_BTNSTATE,		0x2200008C		// bit band alias of data var_switch_flags, bit 3 (button state SW1)
.equ SW2_FLAG_COUNTSTATE,	0x220000C0		// bit band alias of data var_switch_flags, bit 16 (count state SW2)
.equ SW2_FLAG_EDGEDETECT,	0x220000C4		// bit band alias of data var_switch_flags, bit 17 (edge detected SW2)
.equ SW2_FLAG_DEBOUNCEOK,	0x220000C8		// bit band alias of data var_switch_flags, bit 18 (debounce ok SW2)

.equ BUTTON_PRESSED_LVL,	0x0		// level/logic value of pressed button/switch
.equ BUTTON_RELEASED_LVL,	0x1		// level/logic value of released button/switch
.equ COUNT_DIR_UP,			0x0		// counter direction: upwards
.equ COUNT_DIR_DOWN,	    0x1		// counter direction: downwards
.equ COUNT_STATE_START,		0x0		// counter state: start/running
.equ COUNT_STATE_STOP,	    0x1		// counter direction: stopped

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	// initialize uart, pit3 and pit1
	bl uart_init
	bl pit3_init
	
	// first we have to enable the PIT clock and the clock of Port A and E,
	// so that we can initialize them.
	mov r0, #1
	ldr r1, =SIM_SCGC6_PIT 		// load the address of the bit band alias
	str r0, [r1]				// update the PIT bit of register SIM_SCGC6
	ldr r1, =SIM_SCGC5_PORTA	// load the address of the bit band alias
	str r0, [r1]				// update the Port A bit of register SIM_SCGC5
	ldr r1, =SIM_SCGC5_PORTE	// load the address of the bit band alias
	str r0, [r1]				// update the Port E bit of register SIM_SCGC5
	
	// now we have to set the interrupt vectors
	// first we need the base address of the VT (vector table)
	ldr r0, =SCR_VTOR				// load the address of the Vector Table Offset Register
	ldr r0, [r0]					// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	// SW2_IRQHandler
	ldr r2, =PIT1_IRQHandler		// get address of our ISR
	str r2, [r0, #OFFSET_VT_PIT1]	// set PIT1_IRQHandler as our new handler of the PIT1 interrupt
	
	ldr r2, =SW2_IRQHandler			// get address of our ISR
	str r2, [r0, #OFFSET_VT_PORTE]	// set SW2_IRQHandler as our new handler of the PortE interrupt
	
	ldr r0, =0x08000020		// set bit 5 and 27
	ldr r1, =NVIC_ICPR2 	// load address of NVIC_ICPR2
	ldr r2, =NVIC_ISER2		// load address of NVIC_ISER2
	str r0, [r1]			// clear the pending state of the PIT1 and PortE interrupts
	str r0, [r2]			// enable the PIT1 and PortE interrupts
	
	// configure the ports and pins
	// start with the directions
	ldr r0, =GPIOE_PDDR	// load address of GPIOE_PDDR
	ldr r1, [r0]				// get register value
	ldr r2, =0xFBFFFFFF			// laod mask to clear Bit 26
	and r1, r1, r2				// clear bit 26
	str r1, [r0]				// update register value
	
	ldr r0, =GPIOA_PDDR	// load address of GPIOA_PDDR
	ldr r1, [r0]				// get register value
	ldr r2, =0xFFF7FFFF			// laod mask to clear Bit 19
	and r1, r1, r2				// clear bit 19
	ldr r2, =0x30000C00			// laod mask to set Bits 10,11,28,29
	orr r1, r1, r2				// set bits
	str r1, [r0]				// update register value
	
	// turn off LEDs
	// use GPIOA_PSOR to turn off LEDs
	// use GPIOA_PCOR to turn on LEDs
	ldr r0, =GPIOA_PSOR			// load address of GPIOA_PSOR
	ldr r1, =0x30000C00			// laod mask to set Bits 10,11,28,29
	str r1, [r0]				// set to logic 1
	
	ldr r0, =PORTE_PCR26		// load address of PORTE_PCR26 (SW2)
	ldr r1, =PCR_SW2_CONFIG		// load config value for SW2
	str r1, [r0]				// write config for SW2
	
	ldr r0, =PORTA_PCR19		// load address of PORTA_PCR19 (SW1)
	ldr r1, =PCR_SW1_CONFIG		// load config value for SW1
	str r1, [r0]				// write config for SW1
	
	ldr r0, =PCR_LED_CONFIG		// load config value for LED pins
	ldr r1, =PORTA_PCR10		// load address of PORTA_PCR10
	str r0, [r1]				// write config
	ldr r1, =PORTA_PCR11		// load address of PORTA_PCR11
	str r0, [r1]				// write config
	ldr r1, =PORTA_PCR28		// load address of PORTA_PCR28
	str r0, [r1]				// write config
	ldr r1, =PORTA_PCR29		// load address of PORTA_PCR29
	str r0, [r1]				// write config
	
	// enable clock for PIT timers with timers running in debug mode (in PIT_MCR)
	ldr r0, =PIT_MCR			// load address of PIT_MCR
	mov r1, #0x00				// set wanted configuration value
	str r1, [r0]				// set configuration
	
	// initialize Load Value Register for a period of 1 second
	// The 25 MHz clock frequency equates to a clock period of 40ns.
	// 1s / 40ns =  25,000,000 cycles (= 0x17D_7840)
	// LDVAL trigger = (period / clock period) - 1 = 0x17D_7840 - 1
	ldr r0, =PIT_LDVAL1				// load address of PIT_LDVAL1
	ldr r1, =PIT_LDVAL1_STARTVALUE	// load timer start value
	str r1, [r0]					// write timer start value of PIT1
	
	// enable timer 1 interrupts and timer 1 (set bit 0 and 1)
	mov r1, #0x03 					// load value where bit 1 and 0 are set
	ldr r0, =PIT_TCTRL1				// load address of PIT_TCTRL1
	str r1, [r0]					// write config to timer 1 control register
	// finished initialisation
	
	ldr r4, =SW1_FLAG_BTNSTATE 		// load address of Button State Alias
	mov r1, #BUTTON_RELEASED_LVL	// load value representing a released button
	str r1, [r4]					// write button state
	
	ldr r5, =GPIOA_PDIR_BIT19 		// load bit band alias of SW1 data input register
	ldr r6, =SW1_FLAG_EDGEDETECT    // load bit band alias of SW1 edge detected flag
	ldr r7, =var_sw1_edge_pit_value // load address of SW1 edge pit value
	
loop_program:
	// on every falling edge of SW1 and SW2 we
	//   - remember the timer value of PIT3
	//   - set the edge detected flag
	
	// check if we have a falling edge of SW1
	bl pit3_getval	// get the current timer value
	mov r1, #1
	ldr r2, [r4]	// get last button state (SW1_FLAG_BTNSTATE)
	ldr r3, [r5]	// get current button state (GPIOA_PDIR_BIT19)
	str r3, [r4]	// save current button state (SW1_FLAG_BTNSTATE)
	
	// falling edge r2=1 and r3=0
	lsl r2, r2, #1	// shift one bit to the left
	orr r2, r2, r3
	
	cmp r2, #0x02	// is falling edge?
	itt eq
	streq r0, [r7]	// remember timer value of edge
	streq r1, [r6]	// set edge detected flag
	
	// get old press state of SW1
	ldr r0, =MOD_SW1_BIT
	ldr r8, [r0]
	// get new press state of SW1
	bl SW1_IsPressed
	// SW1 if(R8==0 && R0==1) then button has been pressed right now
	// => toggle count direction flag
	ldr r1, =SW1_FLAG_COUNTDIR
	ldr r2, [r1]
	lsl r8, r8, #1		// shift one bit to the left
	orr r8, r8, r0
	cmp r8, #0x01		// button pressed right now?
	itt eq
	eoreq r2, r2, #0x01 // toggle the bit/flag
	streq r2, [r1]		// update the flag
	
	// get old press state of SW2
	ldr r0, =MOD_SW2_BIT
	ldr r8, [r0]
	// get new press state of SW2
	bl SW2_IsPressed
	// SW2 if(R8==0 && R0==1) then button has been pressed right now
	// => toggle count state flag
	ldr r1, =SW2_FLAG_COUNTSTATE
	ldr r2, [r1]
	lsl r8, r8, #1		// shift one bit to the left
	orr r8, r8, r0
	cmp r8, #0x01		// button pressed right now?
	itt eq
	eoreq r2, r2, #0x01 // toggle the bit/flag
	streq r2, [r1]		// update the flag
	
	// check user input from console
	// if a char is present read it,
	// else skip user input check
	bl uart_charPresent
	cmp r0, #0
	beq after_user_input_check	// skip user input check

	bl uart_getChar 		// read char from terminal
	mov r10, r0				// store r0 in r10
	ldr r1, =SW2_FLAG_COUNTSTATE
	ldr r2, [r1]			// get current counter state
	cmp r10, #0x73 			// char == 's'?
	itt eq					// if yes
	eoreq r2, r2, #0x01 	// toggle the bit/flag
	streq r2, [r1]			// update the flag
	
	ldr r1, =SW1_FLAG_COUNTDIR
	cmp r10, #0x2B 			// char == '+'?
	itt eq
	moveq r2, #COUNT_DIR_UP	// set direction
	streq r2, [r1]			// update the flag
	
	cmp r10, #0x2D 			// char == '-'?
	itt eq
	moveq r2, #COUNT_DIR_DOWN // set direction
	streq r2, [r1]			  // update the flag
	
after_user_input_check:
	// check if one second has passed
	// only then update counter, leds and console output
	ldr r0, =flag_one_sec_passed
	ldr r1, [r0]				// load value of flag
	cmp r1, #0					// if the flag is not set
	beq loop_program			// go back to the main loop
	
	// the one second flag is set, so we have to reset it and go on
	mov r1, #0
	str r1, [r0]
	
	// update the counter if we are in state "start"
	ldr r0, =SW2_FLAG_COUNTSTATE
	ldr r1, [r0]
	cmp r1, #COUNT_STATE_STOP	// is state == "stop"?
	beq after_counter_update	// skip the update of the counter
	
	// either increment or decrement counter
	ldr r0, =SW1_FLAG_COUNTDIR
	ldr r1, [r0]
	ldr r0, =var_counter
	ldr r11, [r0]
	cmp r1, #COUNT_DIR_UP	// is direction == "up"?
	ite eq
	addeq r11, r11, #1
	subne r11, r11, #1
	// since it is a 8 bit counter we have to cut off the higher bits
	and r11, r11, #0x00FF
	str r11, [r0]
	
after_counter_update:
	// print the counter value and a new line char
	mov r0, r11
	bl uart_putByte
	mov r0, #0x0A	// load ASCII-Code for "new line"
	bl uart_putChar
	
	// E1 (Bit 0): PTA11, E2 (Bit 1): PTA28, E3: PTA 29, E4: PTA10
	// use GPIOA_PSOR to turn off LEDs
	// use GPIOA_PCOR to turn on LEDs
	mov r0, #1
	
	// handle LED E1 (Bit 0)
	and r1, r11, #0x01
	cmp r1, #0
	ite eq
	ldreq r2, =GPIOA_PSOR_BIT11	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT11	// load address to turn on LED
	str r0, [r2]
	
	// handle LED E2 (Bit 1)
	and r1, r11, #0x02
	cmp r1, #0
	ite eq
	ldreq r2, =GPIOA_PSOR_BIT28	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT28	// load address to turn on LED
	str r0, [r2]
	
	// handle LED E3 (Bit 2)
	and r1, r11, #0x04
	cmp r1, #0
	ite eq
	ldreq r2, =GPIOA_PSOR_BIT29	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT29	// load address to turn on LED
	str r0, [r2]
	
	// handle LED E4 (Bit 3)
	and r1, r11, #0x08
	cmp r1, #0
	ite eq
	ldreq r2, =GPIOA_PSOR_BIT10	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT10	// load address to turn on LED
	str r0, [r2]
	
	b loop_program			// go back to start
	
	
/**
 * Executes a delay of about 1 sec using busy waiting.
 * (Use PIT3 to determine the duration of "bl delay")
 */
//.global PIT1_IRQHandler
.thumb_func
PIT1_IRQHandler:
	mov r1, #0x01
	// clear interrupt flag of PIT1
	ldr r0, =PIT_TFLG1				// load address of PIT_TFLG1
	str r1, [r0]					// clear the interrupt flag
		
	// now set the one second passed flag
	ldr r0, =flag_one_sec_passed	// load address of one sec passed flag
	str r1, [r0]					// set the flag
	
	bx lr
	
/**
 * Registers a falling edge and updates the regarding flags
 */
.thumb_func
SW2_IRQHandler:
	push {LR}					// save registers
	
	// save timer value of current falling edge
	// and update edge detected flag
	bl pit3_getval
	mov r3, #1
	
	ldr r1, =var_sw2_edge_pit_value // load address of SW2 edge pit value
	ldr r2, =SW2_FLAG_EDGEDETECT    // load bit band alias of SW2 edge detected flag

	str r0, [r1]	// remember timer value of edge
	str r3, [r2]	// set edge detected flag
	
	// clear interrupt flag of PORTE
	ldr r0, =PORTE_PCR26_ISF	// load address of PCR26_ISF bit band aliias
	str r3, [r0]				// clear the interrupt flag
	
	pop {PC}					// restore registers
	

/**
 * Checks if button SW1 is pressed und updates data var_mod
 * return value R0: 0: released, 1: pressed
 */
.thumb_func
SW1_IsPressed:
	push {R4-R8, LR}						// save registers
	// Start of subroutine
	bl pit3_getval		// get timer value (needed to calculate interval)
	mov r4, r0			// and remember it
	ldr r0, =GPIOA_PDIR_BIT19 // load bit band alias of SW1 data input register
	ldr r5, [r0]						 // get current button level/state (0 = Pressed)	
	ldr r6, =SW1_FLAG_EDGEDETECT     // load bit band alias of SW1 edge detected flag
	ldr r7, =SW1_FLAG_DEBOUNCEOK	 // load bit band alias of SW1 debounce ok flag
	
	// on every rising edge of SW1 and SW2 we
	//   - reset the regarding debounce ok flag
	//   - reset the regarding edge detected flag
	// we have to do this in order to avoid unwanted recognitions of button presses. 
	
	mov r8, #0  // initialize return value of the subroutine (button released)
	
	cmp r5, #BUTTON_PRESSED_LVL // is button released (switch open)?
	ittt ne
	strne r8, [r6]			// reset edge detected flag
	strne r8, [r7]			// reset debounce ok flag
	bne endof_SW1_IsPressed // go to end
	
	ldr r2, [r6]			// get value of edge detected flag
	cmp r2, #0 				// is edge detected flag deasserted?
	itt eq					// if so
	streq r8, [r7]			// reset debounce ok flag
	beq endof_SW1_IsPressed // and go to the end
	
	// Button is pressed and edge detected flag is asserted/set
	ldr r2, [r7]			// get value of debounce ok flag
	// check special case: user keeps pushing button (does not release button)
	cmp r2, #0
	itt ne					// if the debounce ok flag is asserted/set
	movne r8, #1 			// we update the return value (button is pressed)
	bne endof_SW1_IsPressed // and go to the end
	
	// check if we have reached the 5ms interval
	// here the debounce ok flag is not set
	ldr r0, =var_sw1_edge_pit_value     // load address of SW1 edge pit value
	ldr r1, [r0]						// get pit value of falling edge
	sub r0, r1, r4 						// calculate the interval value
	ldr r2, =INTERVAL_5MS_CORRECTED		// load the wanted/needed interval value
	cmp r0, r2
	itt hs								// if we have reached the debounce interval
	movhs r8, #1 						// update the return value (button is pressed)
	strhs r8, [r7]						// and set the debounce ok flag

endof_SW1_IsPressed:
	ldr r0, =MOD_SW1_BIT 				// load address of the alias of the SW1 Bit of var_mod
	str r8, [r0]						// update SW1 Bit of var_mod
	mov r0, r8							// move return value to the correct register
	// End  of subroutine
	pop {R4-R8, PC}
	
/**
 * Checks if button SW2 is pressed und updates data var_mod
 * return value R0: 0: released, 1: pressed
 */
.thumb_func
SW2_IsPressed:
	push {R4-R8, LR}						// save registers
	// Start of subroutine
	bl pit3_getval		// get timer value
	mov r4, r0			// and remember it
	ldr r0, =GPIOE_PDIR_BIT26 // load bit band alias of SW2 data input register
	ldr r5, [r0]		// get current button level/state (0 = Pressed)	
	ldr r6, =SW2_FLAG_EDGEDETECT    // load bit band alias of SW2 edge detected flag
	ldr r7, =SW2_FLAG_DEBOUNCEOK	// load bit band alias of SW2 debounce ok flag
	
	mov r8, #0  // initialize return value of the subroutine (button released)
	
	cmp r5, #BUTTON_PRESSED_LVL // is button released (switch open)?
	ittt ne
	strne r8, [r6]			// reset edge detected flag
	strne r8, [r7]			// reset debounce ok flag
	bne endof_SW2_IsPressed // go to end
	
	ldr r2, [r6]			// get value of edge detected flag
	cmp r2, #0 				// is edge detected flag deasserted?
	itt eq					// if so
	streq r8, [r7]			// reset debounce ok flag
	beq endof_SW2_IsPressed // and go to the end
	
	// Button is pressed and edge detected flag is asserted/set
	ldr r2, [r7]			// get value of debounce ok flag
	// check special case: user keeps pushing button (does not release button)
	cmp r2, #0
	itt ne					// if the debounce ok flag is asserted/set
	movne r8, #1 			// we update the return value (button is pressed)
	bne endof_SW2_IsPressed // and go to the end
	
	// check if we have reached the 5ms interval
	ldr r0, =var_sw2_edge_pit_value     // load address of SW1 edge pit value
	ldr r1, [r0]						// get pit value of falling edge
	sub r0, r1, r4 						// calculate the interval value
	ldr r2, =INTERVAL_5MS_CORRECTED		// load the wanted interval value
	cmp r0, r2
	itt hs								// if we have reached the debounce interval
	movhs r8, #1 						// update the return value (button is pressed)
	strhs r8, [r7]						// and set the debounce ok flag

endof_SW2_IsPressed:
	ldr r0, =MOD_SW2_BIT 				// load address of the alias of the SW2 Bit of var_mod
	str r8, [r0]						// update SW2 Bit of var_mod
	mov r0, r8							// move return value to the correct register
	// End  of subroutine
	pop {R4-R8, PC}	


/*** Datenbereich (ab 0x20000000) ***/
.data
var_mod: .word 0x0  // 0x20000000
/*
 * SW1: Bit0=CountDirection, Bit1=EdgeDetected,  Bit2=5msPassed,    Bit3=ButtonState
 *      (0=up, 1=down),      (0=false, 1=true),  (0=false, 1=true), (0=Pressed, 1=Released)
 * SW2: Bit16=CountState,    Bit17=EdgeDetected, Bit18=5msPassed
 *      (0:start, 1:stop),   (0=false, 1=true),  (0=false, 1=true)
 */
var_switch_flags: .word 0x0 // 0x20000004
var_sw1_edge_pit_value: .word 0x0 // value of PIT3 of last falling edge of the button SW1
var_sw2_edge_pit_value: .word 0x0 // value of PIT3 of last falling edge of the button SW2
flag_one_sec_passed: .word 0x0 // flag to indicate to main that one second passed
var_counter: .word 0x0 // counter which gets incremented or decremented
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
 * Board Configuration:
 *  - 50MHz XTAL
 *  - OUTDIV1 (divide value for the core/system clock): Divide-by-2
 *  - OUTDIV2 (divide value for the bus clock):         Divide-by-2  (bus clock = 25MHz)
 *  - VREFH (G5) == VDDA (H5) == 3.3V (Volt, DC)
 *  - VREFL (G6) == VSSA (H6) == Ground (0 Volt, DC)
 */

// Declarations of constants
.equ SIM_SCGC3_ADC1,		0x4290066C	// Bit Band Alias for bit 27 (ADC1) of SIM_SCGC3
.equ SIM_SCGC5_PORTA,		0x42900724	// Bit Band Alias for bit 9 (Port A module) of SIM_SCGC5
.equ SIM_SCGC6_PIT,			0x429007DC	// Bit Band Alias for bit 23 (PIT) of SIM_SCGC6
.equ SCR_VTOR,				0xE000ED08	// address of Vector Table Offset Register
.equ OFFSET_VT_PIT1,		0x0154		// offset to the vector of PIT1

.equ NVIC_ICPR2, 			0xE000E288		// address of ICPR2
.equ NVIC_ISER2, 			0xE000E108		// address of ISER2
.equ PIT_MCR, 				0x40037000		// address of PIT Module Control Register
.equ PIT_LDVAL1, 			0x40037110		// address of Timer Load Value Register of PIT1
.equ PIT_TCTRL1, 			0x40037118		// address of Timer Control Register of PIT1
.equ PIT_TFLG1, 			0x4003711C		// address of Timer Flag Register of PIT1
.equ PIT_LDVAL1_STARTVALUE,	0x017D783F		// Timer start value of PIT1 needed for a period of 1 second

.equ PORTA_PCR10, 			0x40049028		// address of PORTA_PCR10 (LED E4)
.equ PORTA_PCR11, 			0x4004902C		// address of PORTA_PCR11 (LED E1)
.equ PORTA_PCR28, 			0x40049070		// address of PORTA_PCR28 (LED E2)
.equ PORTA_PCR29, 			0x40049074		// address of PORTA_PCR29 (LED E3)

// OUTPUT: in order to switch on the LED we have to pull the pins down to ground
// We will use Push-Pull, since Open-Drain causes a floating state, that could switch on the LED unintentionally
.equ PCR_LED_CONFIG, 		0x01000100		// Value of Pin Control Register in order to switch on LEDs
.equ GPIOA_PSOR, 			0x400FF004		// address of GPIOA_PSOR (Port Set Output Register)
.equ GPIOA_PDDR, 			0x400FF014		// address of GPIOA_PDDR (Port Data Direction Register)

// use GPIOA_PSOR to turn off LEDs
.equ GPIOA_PSOR_BIT10, 		0x43FE00A8		// address of GPIOA_PSOR Bit 10 (LED E4) bit band alias
.equ GPIOA_PSOR_BIT11, 		0x43FE00AC		// address of GPIOA_PSOR Bit 11 (LED E1) bit band alias
.equ GPIOA_PSOR_BIT28, 		0x43FE00F0		// address of GPIOA_PSOR Bit 28 (LED E2) bit band alias
.equ GPIOA_PSOR_BIT29, 		0x43FE00F4		// address of GPIOA_PSOR Bit 29 (LED E3) bit band alias
// use GPIOA_PCOR to turn on LEDs
.equ GPIOA_PCOR_BIT10, 		0x43FE0128		// address of GPIOA_PCOR Bit 10 (LED E4) bit band alias
.equ GPIOA_PCOR_BIT11,  	0x43FE012C		// address of GPIOA_PCOR Bit 11 (LED E1) bit band alias
.equ GPIOA_PCOR_BIT28, 		0x43FE0170		// address of GPIOA_PCOR Bit 28 (LED E2) bit band alias
.equ GPIOA_PCOR_BIT29, 		0x43FE0174		// address of GPIOA_PCOR Bit 29 (LED E3) bit band alias

.equ GPIOA_LED_BITMASK, 	0x30000C00		// bitmask used to GPIO direction and to set/reset LEDs

.equ ADC1_SC1A, 			0x400BB000		// address of ADC1_SC1A
.equ ADC1_CFG1, 			0x400BB008		// address of ADC1_CFG1
.equ ADC1_CFG2, 			0x400BB00C		// address of ADC1_CFG2
.equ ADC1_RA, 				0x400BB010		// address of ADC1_RA
.equ ADC1_SC2, 				0x400BB020		// address of ADC1_SC2
.equ ADC1_SC3, 				0x400BB024		// address of ADC1_SC3
//.equ ADC1_OFS, 				0x400BB028		// address of ADC1_OFS
.equ ADC1_PG, 				0x400BB02C		// address of ADC1_PG
.equ ADC1_MG, 				0x400BB030		// address of ADC1_MG
//.equ ADC1_CLPD, 			0x400BB034		// address of ADC1_CLPD
//.equ ADC1_CLPS, 			0x400BB038		// address of ADC1_CLPS
//.equ ADC1_CLP4, 			0x400BB03C		// address of ADC1_CLP4
//.equ ADC1_CLP3, 			0x400BB040		// address of ADC1_CLP3
//.equ ADC1_CLP2, 			0x400BB044		// address of ADC1_CLP2
//.equ ADC1_CLP1, 			0x400BB048		// address of ADC1_CLP1
.equ ADC1_CLP0, 			0x400BB04C		// address of ADC1_CLP0

//.equ ADC1_CLMD, 			0x400BB054		// address of ADC1_CLMD
//.equ ADC1_CLMS, 			0x400BB058		// address of ADC1_CLMS
//.equ ADC1_CLM4, 			0x400BB05C		// address of ADC1_CLM4
//.equ ADC1_CLM3, 			0x400BB060		// address of ADC1_CLM3
//.equ ADC1_CLM2, 			0x400BB064		// address of ADC1_CLM2
//.equ ADC1_CLM1, 			0x400BB068		// address of ADC1_CLM1
.equ ADC1_CLM0, 			0x400BB06C		// address of ADC1_CLM0

/*
ADC1_SC1A config value
- COCO (Bit 7): Don't care
- AIEN (Bit 6): 0 (Conversion complete interrupt is disabled.)
- DIFF (Bit 5): 0 (Single-ended conversions and input channels are selected.)
- ADCH (Bit 4-0): 10100 (When DIFF=0, AD20 is selected as input.)
*/
.equ ADC1_SC1A_VALUE,		0x14

/*
ADC1_CFG1 config value
- ADLPC (Bit 7): 0 (Normal power configuration.)
- ADIV (Bit 6-5): 11 (The divide ratio is 8 and the clock rate is (input clock)/8.)
- ADLSMP (Bit 4): 0 (Short sample time.)
- MODE (Bit 3-2): 11 (16-bit conversion)
- ADICLK (Bit 1-0): 00 (Bus clock)
*/
.equ ADC1_CFG1_VALUE,		0x6C

/*
ADC1_CFG2 config value
- MUXSEL (Bit 4): 0 (ADxxa channels are selected.)
- ADACKEN (Bit 3): 0 (Asynchronous clock output disabled)
- ADHSC (Bit 2): 0 (Normal conversion sequence selected.)
- ADLSTS (Bit 1-0): 00 (Default longest sample time)
*/
.equ ADC1_CFG2_VALUE,		0x00

/*
ADC1_SC2
- ADTRG (Bit 6): 0 (Software trigger selected.)
- ACFE (Bit 5): 0 (Compare function disabled.)
- ACFGT (Bit 4): 0 (we don't care)
- ACREN (Bit 3): 0 (we don't care)
- DMAEN (Bit 2): 0 (DMA is disabled.)
- REFSEL (Bit 1-0): 00 (Default voltage ref pin pair, that is, external pins VREFH and VREFL)
*/
.equ ADC1_SC2_VALUE,		0x00

/*
ADC1_SC3 normal operation config value
CAL (Bit 7): 0 (Calibration completed normally.)
CALF (Bit 6): Read-only bit
ADCO (Bit 3): 1 (Continuous conversions or sets of conversions)
AVGE (Bit 2): 1 (Hardware average function enabled.)
AVGS (Bit 1-0): 10 (16 samples averaged.)
*/
.equ ADC1_SC3_VALUE,		0x0E

/*
ADC1_SC3 calibration config value
CAL (Bit 7): 0 (Calibration completed normally.)
CALF (Bit 6): Read-only bit
ADCO (Bit 3): 0 (One conversion or one set of conversions)
AVGE (Bit 2): 1 (Hardware average function enabled.)
AVGS (Bit 1-0): 11 (32 samples averaged.)
*/
.equ ADC1_SC3_CALCFG_VALUE, 0x07

.equ ADC1_SC3_CAL, 			0x4376049C		// address of ADC1_SC3 Bit 7 (CAL) bit band
.equ ADC1_SC3_CALF, 		0x43760498		// address of ADC1_SC3 Bit 6 (CALF) bit band
//.equ ADC1_CFG1_BIT3, 		0x4376010C		// address of ADC1_CFG1 Bit 3 (MODE) bit band
//.equ ADC1_CFG1_BIT2, 		0x43760108		// address of ADC1_CFG1 Bit 2 (MODE) bit band
.equ ADC1_SC1A_COCO, 		0x4376001C		// address of ADC1_SC1A Bit 7 (COCO) bit band

.equ CHAR_SPACE, 			0x20			// ASCII Code of the space char
.equ RUN_MODE_STOP,			0x0				// Value of run mode "stop"

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	// execute calibration first
	bl adc1_calibrate
	// then execute initialization
	bl adc1_init
	bl uart_init
	bl leds_e1234_init
	bl pit1_init
	
	ldr r6, =var_run_mode
	ldr r7, =var_precision
	
	// enter main loop
main_loop_program:
	ldr r0, =flag_one_sec_passed
	ldr r1, [r0]				// load value of 1s flag
	cmp r1, #0					// if the flag is not set
	beq main_check_user_input	// skip printing
	
	// the flag is set, so we have to reset it and go on
	mov r2, #0
	str r2, [r0]
	
	ldr r0, [r6]				// load value run mode
	cmp r0, #RUN_MODE_STOP		// if run mode is "stop"
	beq main_check_user_input	// skip printing
	
	// first read the value of ADC1_RA	
	ldr r1, =ADC1_RA
	ldr r8, [r1]		// load value of ADC1_RA
	
	// determine the addresses of the regarding look-up-tables (LUPs)
	// initialize with the default precision of 16
	ldr r1, =lup_precision16_d
	ldr r2, =lup_precision16_a
	
	ldr r0, [r7]			// load value of var_precision
	cmp r0, #0 				// 8 bit precision?
	itt eq					// if yes, load the regarding LUPs
	ldreq r1, =lup_precision8_d
	ldreq r2, =lup_precision8_a
	
	cmp r0, #1 				// 10 bit precision?
	itt eq					// if yes, load the regarding LUPs
	ldreq r1, =lup_precision10_d
	ldreq r2, =lup_precision10_a
	
	cmp r0, #2 				// 12 bit precision?
	itt eq					// if yes, load the regarding LUPs
	ldreq r1, =lup_precision12_d
	ldreq r2, =lup_precision12_a
	
	// we start the level checks with level 0
	// we have to start with level 0 sind we have at most 16 level
	// and 4 LEDs which we use to represent the level in binary number format (0 - 15)
	mov r4, #0 				// R4 == level number

	// the digital value is saved in R8
main_find_level:
	ldrh r10, [r1], #2		// load upper digital limit value
	ldrh r11, [r2], #2		// load upper analog limit value
	cmp r10, r8				// if the current digital value is higher as the current upper limit
	itt lo					// then
	addlo r4, r4, #1		// move to the next level
	blo main_find_level		// and this level
	
	// now we should have:
	// - the regarding level
	// - the regarding upper digital and analog limit value
	// what we need:
	// - the lower analog limit value (which is 0 for level 0)
	
	mov r5, #0				// load initial lower analog limit value
	cmp r4, #0				// if the current level is 0
	beq main_print_result	// we already have the correct lower limit values and can print them
	
	// determine the correct lower limit value
	// get the upper limit value of the previous level
	ldrh r5, [r2, #-4] 		// get the correct lower analog limit value
	add r5, r5, #1			// we have to correct the value, in order to get the lower limit value
	
main_print_result:
	// print the digital value from ADC1_RA
	ldr r0, =text_result_prefix
	bl uart_putString
	mov r0, r8			// remember digital value in R8
	bl uart_putInt16	// print the value in hex
	
	mov r0, #CHAR_SPACE
	bl uart_putChar		// print space character
	
	// print the lower limit value
	mov r0, r5
	bl uart_putUIntBase10
	
	// print the separator hyphen
	ldr r0, =text_result_substr3
	bl uart_putString
	
	// print the upper limit value
	mov r0, r11
	bl uart_putUIntBase10
	
	ldr r0, =text_result_substr1
	bl uart_putString
	
	// print the level value
	mov r0, r4
	bl uart_putByteBase10
	
	// print the last substring, starting a new line
	ldr r0, =text_result_substr2
	bl uart_putString
	
	// now it's time to turn on/off the LEDs
	// use GPIOA_PSOR to turn off the LEDs
	// use GPIOA_PCOR to turn on the LEDs
	// E1: PTA11, E2: PTA28, E3: PTA 29, E4: PTA10
	mov r0, #1
	
	// handle LED E1 (Bit 0 of r4/level)
	ands r1, r4, #0x01
	ite eq						// EQ <-> Flag Z = 1
	ldreq r2, =GPIOA_PSOR_BIT11	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT11	// load address to turn on LED
	str r0, [r2]
	
	// handle LED E2 (Bit 1 of r4/level)
	ands r1, r4, #0x02
	ite eq						// EQ <-> Flag Z = 1
	ldreq r2, =GPIOA_PSOR_BIT28	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT28	// load address to turn on LED
	str r0, [r2]
	
	// handle LED E3 (Bit 2 of r4/level)
	ands r1, r4, #0x04
	ite eq
	ldreq r2, =GPIOA_PSOR_BIT29	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT29	// load address to turn on LED
	str r0, [r2]
	
	// handle LED E4 (Bit 3 of r4/level)
	ands r1, r4, #0x08
	ite eq
	ldreq r2, =GPIOA_PSOR_BIT10	// load address to turn off LED
	ldrne r2, =GPIOA_PCOR_BIT10	// load address to turn on LED
	str r0, [r2]

main_check_user_input:
	// check user input from console
	// if a char is present read it,
	// else skip user input check
	bl uart_charPresent
	cmp r0, #0
	beq main_loop_program	// nothing to do, thus go to start

	bl uart_getChar 		// read char from terminal
	cmp r0, #0x73 			// char == 's'?
	ittt eq					// if yes
	ldreq r1, [r6]			// load value of run mode (only one bit)
	eoreq r1, r1, #0x01 	// toggle the mode/flag
	streq r1, [r6]			// and update the mode/flag
	
	ldr r10, =ADC1_CFG1
	ldr r11, [r10]			// get current ADC1_CFG1 value (only bits 7-0 are used)
	bic r11, r11, #0x000C 	// clear bits 3-2
	
	// approach avoiding multiple branches:
	// always write a precision value to memory
	// but update the value only if user entered an accepted digit
	ldr r2, [r7]			// load current precision value
	mov r3, r2
	
	cmp r0, #0x30 			// char == '0'?
	itt eq
	moveq r1, #0x00			// mask for setting mode bits
	moveq r2, #0			// set new precision value (8 bit)

	cmp r0, #0x31 			// char == '1'?
	itt eq
	moveq r1, #0x08			// mask for setting mode bits
	moveq r2, #1			// set new precision value (10 bit)
	
	cmp r0, #0x32 			// char == '2'?
	itt eq
	moveq r1, #0x04			// mask for setting mode bits
	moveq r2, #2			// set new precision value (12 bit)

	cmp r0, #0x33 			// char == '3'?
	itt eq
	moveq r1, #0x0C			// mask for setting mode bits
	moveq r2, #3			// set new precision value (16 bit)

	// check if we have to update var_precision and ADC1_CFG1[MODE] (Bit 3-2)
	cmp r2, r3				// if the precision value has not changed,
	beq main_loop_program	// we can go to start
	
	// other wise we have to update var_precision and ADC1_CFG1[MODE]
	str r2, [r7]			// update var_precision
	orr r11, r11, r1		// update value for ADC1_CFG1
	ldr r3, =ADC1_CFG1
	str r11, [r3]			// update ADC1_CFG1
	mov r2, #0
	ldr r3, =ADC1_SC1A_COCO
	str r2, [r3]
	
	b main_loop_program
	
/**
 * Calibrates ADC1.
 * @return nothing
 */	
.thumb_func
adc1_calibrate:
	push {R4, R5, LR}	// save register
	
	// first we have to enable the ADC1 clock, so that we can initialize ADC1.
	mov r3, #1
	ldr r1, =SIM_SCGC3_ADC1 	// load the address of the bit band alias
	str r3, [r1]				// update the ADC1 bit of register SIM_SCGC3
	
	// now we have to execute the calibration according to chapter
	// "35.4.7 Calibration function" of the reference manual
	
	// reset-value of ADC1_SC1A = 0x0000_0000
	// reset-value of ADC1_CFG1 = 0x0000_0000
	mov r0, #ADC1_CFG1_VALUE	// load value to set ADC1_CFG1 to
	ldr r1, =ADC1_CFG1			// load the address of ADC1_CFG1
	str r0, [r1]				// update ADC1_CFG1 register
	
	// reset-value of ADC1_CFG2 = 0x0000_0000
	// mov r0, #ADC1_CFG2_VALUE	// load value to set ADC1_CFG2 to
	// ldr r1, =ADC1_CFG2			// load the address of ADC1_CFG2
	// str r0, [r1]				// update ADC1_CFG2 register
	
	// reset-value of ADC1_SC2 = 0x0000_0000
	
	// reset-value of ADC1_SC3 = 0x0000_0000
	// in case of calibration the manual recommends to use
	// SC3[AVGS]=11 for an average of 32
	mov r0, #ADC1_SC3_CALCFG_VALUE	// load value to set ADC1_SC3 to
	ldr r4, =ADC1_SC3				// load the address of ADC1_SC3
	str r0, [r4]					// update ADC1_SC3 register
	
	// now start the calibration
	ldr r2, =ADC1_SC3_CAL		// load bit band alias of SC3[CAL]
	str r3, [r2]				// start the calibration
	
	// and wait until SC1A[COCO] is set (calibration is finished)
	ldr r5, =ADC1_SC1A_COCO 	// load bit band alias of SC1A[COCO]
	
label_wait_cal_finish:	
	ldr r0, [r5]
	cmp r0, #0
	beq label_wait_cal_finish	// keep waiting
	
	// calibration is finished
	ldr r2, =ADC1_SC3_CALF
	ldr r0, [r2]
	cmp r0, #0
	beq label_adc1_calc_gain	// calibration completed normally
	
	// report that calibration failed and jump to sub routine end
	ldr r0, =text_cal_error
	bl uart_putString
	b endof_adc1_calibrate
	
label_adc1_calc_gain:
	// first update ADC1_PG
	mov r0, #0 				// init calculation variable
	// sum up  CLP0, CLP1, CLP2, CLP3, CLP4, and CLPS
	ldr r1, =ADC1_CLP0
	ldr r2, [r1], #-4		// load value of CLP0 and decrement address (r1 now points to CLP1) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLP1 and decrement address (r1 now points to CLP2) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLP2 and decrement address (r1 now points to CLP3) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLP3 and decrement address (r1 now points to CLP4) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLP4 and decrement address (r1 now points to CLPS) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLPS and decrement address (r1 now points to CLPD) 
	add r0, r0, r2
	lsr r0, r0, #1			// divide by 2
	orr r1, r0, #0x8000 	// set MSB of 16 bit variable
	// update ADC1_PG register
	ldr r2, =ADC1_PG
	strh r1, [r2]
	
	// now update ADC1_MG
	mov r0, #0 				// init calculation variable
	// sum up  CLM0, CLM1, CLM2, CLM3, CLM4, and CLMS
	ldr r1, =ADC1_CLM0
	ldr r2, [r1], #-4		// load value of CLM0 and decrement address (r1 now points to CLM1) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLM1 and decrement address (r1 now points to CLM2) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLM2 and decrement address (r1 now points to CLM3) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLM3 and decrement address (r1 now points to CLM4) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLM4 and decrement address (r1 now points to CLMS) 
	add r0, r0, r2
	ldr r2, [r1], #-4		// load value of CLMS and decrement address (r1 now points to CLMD) 
	add r0, r0, r2
	lsr r0, r0, #1			// divide by 2
	orr r1, r0, #0x8000 	// set MSB of 16 bit variable
	// update ADC1_MG register
	ldr r2, =ADC1_MG
	strh r1, [r2]
	
endof_adc1_calibrate:
	pop {R4, R5, PC}			// restore registers and return
	
	
/**
 * Initializes ADC1.
 * @return nothing
 */	
.thumb_func
adc1_init:	
	// first we have to enable the ADC1 clock, so that we can initialize ADC1.
	mov r3, #1
	ldr r1, =SIM_SCGC3_ADC1 	// load the address of the bit band alias
	str r3, [r1]				// update the ADC1 bit of register SIM_SCGC3
	
	// go on with point 2 of "35.5.1.1 Initialization sequence"
	mov r0, #ADC1_CFG1_VALUE	// load value to set ADC1_CFG1 to
	ldr r1, =ADC1_CFG1			// load the address of ADC1_CFG1
	str r0, [r1]				// update ADC1_CFG1 register
	
	mov r0, #ADC1_CFG2_VALUE	// load value to set ADC1_CFG2 to
	ldr r1, =ADC1_CFG2			// load the address of ADC1_CFG2
	str r0, [r1]				// update ADC1_CFG2 register
	
	mov r0, #ADC1_SC2_VALUE		// load value to set ADC1_SC2 to
	ldr r1, =ADC1_SC2			// load the address of ADC1_SC2
	str r0, [r1]				// update ADC1_CFG2 register
	
	// change to "16 samples averaged" (instead of 32)
	mov r0, #ADC1_SC3_VALUE		// load value to set ADC1_SC3 to
	ldr r1, =ADC1_SC3			// load the address of ADC1_SC3
	str r0, [r1]				// update ADC1_SC3 register
	
	// COCO is cleared when the respective SC1n register is written
	// or when the respective Rn register is read.
	mov r0, #ADC1_SC1A_VALUE	// load value to set ADC1_SC1A to
	ldr r1, =ADC1_SC1A			// load the address of ADC1_SC1A
	str r0, [r1]				// update ADC1_SC1A register
	
	bx lr					// jump back (return)
	
	

/**
 * Initializes PIT, so that an interrupt is triggered every milli second.
 * @return nothing
 */	
.thumb_func
pit1_init:	
	// first we have to enable the PIT clock, so that we can initialize PIT.
	mov r0, #1
	ldr r1, =SIM_SCGC6_PIT 		// load the address of the bit band alias
	str r0, [r1]				// update the PIT bit of register SIM_SCGC6
	
	// now we have to set the interrupt vector
	// first we need the base address of the VT (vector table)
	ldr r0, =SCR_VTOR		// load the address of the Vector Table Offset Register
	ldr r0, [r0]				// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	mov r1, #OFFSET_VT_PIT1		// load offset to PIT1 vector
	add r1, r1, r0				// get address of PIT1 vector
	ldr r2, =PIT1_IRQHandler	// get address of our ISR
	str r2, [r1]				// set PIT1_IRQHandler as our new handler of the PIT1 interrupt
	
	mov r1, #0x20				// set bit 5
	// clear all pending interrupts regarding PIT1.
	// Thus set the bit NVIC_ICPR2[5]
	ldr r0, =NVIC_ICPR2			// load address of NVIC_ICPR2
	str r1, [r0]				// clear the pending state of the PIT1 interrupt
	
	// enable PIT1 interrupt in NVIC
	// Thus set the bit NVIC_ISER2[5]
	ldr r0, =NVIC_ISER2			// load address of NVIC_ISER2
	str r1, [r0]				// enable the PIT1 interrupt
	
	// enable clock for PIT timers with timers running in debug mode (in PIT_MCR)
	ldr r0, =PIT_MCR			// load address of PIT_MCR
	mov r1, #0x00				// set bit 5
	str r1, [r0]				// enable clock for PIT
	
	// initialize Load Value Register for a period of 1 second
	// The 25 MHz clock frequency equates to a clock period of 40ns.
	// 1s / 40ns =  25,000,000 cycles (= 0x17D_7840)
	// LDVAL trigger = (period / clock period) - 1 = 0x17D_7840 - 1
	ldr r0, =PIT_LDVAL1				// load address of PIT_LDVAL1
	ldr r1, =PIT_LDVAL1_STARTVALUE	// load timer start value
	str r1, [r0]					// write timer start value of PIT1
	
	// enable timer 1 interrupts and timer 1 (set bit 0 and 1)
	mov r1, #0x03 					// load value where bit 1 and 0 are set
	ldr r0, =PIT_TCTRL1				// load address of PIT_TCTRL1
	str r1, [r0]					// write config to timer 1 control register

	bx lr					// jump back (return)
	
/**
 * Initializes GPIO pins in order to turn on and off the LEDs E1, E2, E3 and E4.
 * @return nothing
 */	
.thumb_func
leds_e1234_init:	
	// first we have to enable the clock of Port A, so that we can initialize the LED pins.
	mov r0, #1
	ldr r1, =SIM_SCGC5_PORTA	// load the address of the bit band alias
	str r0, [r1]				// update the Port A bit of register SIM_SCGC5
	
	ldr r2, =GPIOA_LED_BITMASK	// load mask to set Bits 10,11,28,29
	// configure the ports and pins
	ldr r0, =GPIOA_PDDR			// load address of GPIOA_PDDR
	ldr r1, [r0]				// get register value
	orr r1, r1, r2				// set bits (to configure pins as outputs)
	str r1, [r0]				// update register value
	
	// turn off LEDs
	// use GPIOA_PSOR to turn off LEDs
	// use GPIOA_PCOR to turn on LEDs
	ldr r0, =GPIOA_PSOR			// load address of GPIOA_PSOR
	str r2, [r0]				// set to logic 1
	
	ldr r0, =PCR_LED_CONFIG		// load config value for LED pins
	ldr r1, =PORTA_PCR10		// load address of PORTA_PCR10
	str r0, [r1]				// write config
	ldr r1, =PORTA_PCR11		// load address of PORTA_PCR11
	str r0, [r1]				// write config
	ldr r1, =PORTA_PCR28		// load address of PORTA_PCR28
	str r0, [r1]				// write config
	ldr r1, =PORTA_PCR29		// load address of PORTA_PCR29
	str r0, [r1]				// write config

	bx lr					// jump back (return)
	
	
/**
 * Executes a delay of about 1 sec using busy waiting.
 * (Use PIT3 to determine the duration of "bl delay")
 */
//.global PIT1_IRQHandler
.thumb_func
PIT1_IRQHandler:
	// clear interrupt flag of PIT1
	mov r0, #0x01
	ldr r1, =PIT_TFLG1				// load address of PIT_TFLG1
	str r0, [r1]					// clear the interrupt flag
		
	// now set the one second passed flag
	ldr r1, =flag_one_sec_passed	// load address of one sec passed flag
	str r0, [r1]					// set the flag
	
	bx lr

/**
 * Prints a given number (unsigned int) in decimal format.
 * @parameter R0 - value/number to be printed
 */
.thumb_func	
uart_putUIntBase10:
	// there are certainly more effective algorithms to do this,
	// but that does no matter here.
	push {R4, R5, LR}	// save register
	
	mov r4, #0 					// initialize digit count
	mov r5, r0
	mov r1, #10					// we need this value for the decimal format
	
	// we have to emulate the modulo-operator
	// also the conversion starts with the least significant digit
	// but because we push the ASCII code of the digits to the stack (LIFO)
	// and finally pop them, we ensure the correct order of the digits/chars

uart_putUIntBase10_digitloop:
	udiv r2, r5, r1		// divide r5 by 10 and store the result in R2
	mul r3, r2, r1		
	sub r0, r5, r3		// calculate the result of r5 modulo 10
	add r0, r0, #0x30	// convert the digit to it's regarding char (ASCII code)
	push {r0}			// remember the char
	add r4, r4, #1		// increment digit count
	mov r5, r2			// update the remaining number
	cmp r2, #0			// is the remaining number 0? We are done if it is so,
	bne uart_putUIntBase10_digitloop	// otherwise repeat the loop
	
uart_putUIntBase10_printloop:
	// now pop the chars and print them
	pop {r0}
	bl uart_putChar
	subs r4, r4, #1		// decrement digit/char count
	//cmp r4, #0		// check if we have printed all chars/digits
	bne uart_putUIntBase10_printloop
	
endof_uart_putUIntBase10:
	pop {R4, R5, PC} 	// restore registers and return
	
	
/*** Datenbereich (ab 0x20000000) ***/
.data
flag_one_sec_passed: .word 0x0 	// flag to indicate to main that one second passed
var_run_mode: .word 0x1 		// variable to indicate if we are in start/run mode (0x1) or in stop mode (0x0)
var_precision: .word 0x3		// precision in bit (0x0: 8 bit, 0x1: 10 bit, 0x2: 12 bit, 0x3: 16 bit)
// look-up-tables for digital (suffix d) level limits (only upper limits, starting with level 0)
lup_precision16_d: .hword 4095, 8191, 12287, 16383, 20479, 24575, 28671, 32767, 36863, 40959, 45055, 49151, 53247, 57343, 61439, 65535
lup_precision12_d: .hword 340, 682, 1023, 1364, 1706, 2047, 2388, 2730, 3071, 3412, 3754, 4095
lup_precision10_d: .hword 101, 204, 306, 409, 511, 613, 716, 818, 921, 1023
lup_precision8_d: .hword 31, 63, 95, 127, 159, 191, 223, 255
// look-up-tables for analog (suffix a) level limits (only upper limits in mV, starting with level 0)
lup_precision16_a: .hword 205, 412, 618, 824, 1030, 1237, 1443, 1649, 1855, 2062, 2268, 2474, 2680, 2887, 3093, 3300
lup_precision12_a: .hword 274, 549, 824, 1099, 1374, 1649, 1924, 2199, 2474, 2749, 3024, 3300
lup_precision10_a: .hword 329, 659, 989, 1319, 1649, 1979, 2309, 2639, 2969, 3300
lup_precision8_a: .hword 412, 824, 1237, 1649, 2062, 2474, 2887, 3300
text_cal_error: .asciz "Kalibrierung fehlgeschlagen!\n"
text_result_substr1: .asciz " mV (Stufe "
text_result_substr2: .asciz ")\n"
text_result_substr3: .asciz " - "
text_result_prefix: .asciz "0x"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ SIM_SCGC6_PIT,			0x429007DC	// Bit Band Alias for bit 23 (PIT) of SIM_SCGC6
.equ SCR_VTOR,				0xE000ED08	// address of Vector Table Offset Register
.equ OFFSET_VT_PIT1,		0x0154		// offset to the vector of PIT1

.equ NVIC_ICPR2, 			0xE000E288		// address of ICPR2
.equ NVIC_ISER2, 			0xE000E108		// address of ISER2
.equ PIT_MCR, 				0x40037000		// address of PIT Module Control Register
.equ PIT_LDVAL1, 			0x40037110		// address of Timer Load Value Register of PIT1
.equ PIT_TCTRL1, 			0x40037118		// address of Timer Control Register of PIT1
.equ PIT_TFLG1, 			0x4003711C		// address of Timer Flag Register of PIT1
.equ PIT_LDVAL1_STARTVALUE,	0x017D783F		// Timer start value of PIT1 needed for a period of 1 second

.equ SIM_SCGC5_PORTD,		0x42900730		// Bit Band Alias for bit 12 (Port D module) of SIM_SCGC5
.equ PORTD_PCR8, 			0x4004C020		// address of PORTD_PCR8 (I2C0_SCL)
.equ PORTD_PCR9, 			0x4004C024		// address of PORTD_PCR9 (I2C0_SDA)
.equ GPIOD_PDDR, 			0x400FF0D4		// address of GPIOD_PDDR (0: input, 1: output)
.equ GPIOD_PDOR, 			0x400FF0C0		// address of PortD Data Output Register 
.equ GPIOD_PDIR, 			0x400FF0D0		// address of PortD Data Input Register
.equ PD8_9, 				0x300			// Mask for PD8 and PD9
.equ PD8, 					0x100			// Mask for PD8
.equ ALT_GPIO, 				0x100			// Alternative 1: GPIO
/*
 * We need I2C0_SCL and I2C0_SDA, thus we need ALT2 and Open Drain enabled
 */
.equ ALT_I2C0, 				0x0220			// value of PORTD_PCR8 and 9
.equ SIM_SCGC4_I2C0, 		0x42900698		// Bit Band Alias for bit 6 (I2C0) of SIM_SCGC4

//.equ I2C0_A1, 			0x40066000		// address of I2C0_A1
.equ I2C0_F, 				0x40066001		// address of I2C0_F
.equ I2C0_C1, 				0x40066002		// address of I2C0_C1
.equ I2C0_S, 				0x40066003		// address of I2C0_S
.equ I2C0_D, 				0x40066004		// address of I2C0_D
//.equ I2C0_C2, 			0x40066005		// address of I2C0_C2
//.equ I2C0_FLT, 			0x40066006		// address of I2C0_FLT
//.equ I2C0_RA, 			0x40066007		// address of I2C0_RA
//.equ I2C0_SMB, 			0x40066008		// address of I2C0_SMB
//.equ I2C0_A2, 			0x40066009		// address of I2C0_A2
//.equ I2C0_SLTH, 			0x4006600A		// address of I2C0_SLTH
//.equ I2C0_SLTL, 			0x4006600B		// address of I2C0_SLTL

.equ I2C0_F_MASK, 			0x00			// value of I2C0_F (MULT: 00, ICR: 0)
.equ I2C0_C1_INIT_MASK, 	0x80			// value of I2C0_C1 (1000 0000)
//.equ I2C0_C1_IICEN, 		0x42CC005C		// bit band alias of I2C0_C1[IICEN]
//.equ I2C0_C1_IICIE, 		0x42CC0058		// bit band alias of I2C0_C1[IICIE]
.equ I2C0_C1_MST, 			0x42CC0054		// bit band alias of I2C0_C1[MST]
.equ I2C0_C1_TX, 			0x42CC0050		// bit band alias of I2C0_C1[TX]
.equ I2C0_C1_TXAK, 			0x42CC004C		// bit band alias of I2C0_C1[TXAK]
.equ I2C0_C1_RSTA, 			0x42CC0048		// bit band alias of I2C0_C1[RSTA]

//.equ I2C0_S_TCF, 			0x42CC007C		// bit band alias of I2C0_S[TCF]
//.equ I2C0_S_BUSY,			0x42CC0074		// bit band alias of I2C0_S[BUSY]
//.equ I2C0_S_ARBL, 		0x42CC0070		// bit band alias of I2C0_S[ARBL]
//.equ I2C0_S_IICIF, 		0x42CC0064		// bit band alias of I2C0_S[IICIF]
//.equ I2C0_S_RXAK, 		0x42CC0064		// bit band alias of I2C0_S[RXAK]

.equ ADDR_SENSOR_TX, 		0x90			// address used for TX (Write)
.equ ADDR_SENSOR_RX, 		0x91			// address used for RX (Read)

.equ POINTER_BYTE_TEMP, 	0x00			// DS75 pointer byte value for temperature
.equ POINTER_BYTE_CFG, 		0x01			// DS75 pointer byte value for configuration
.equ POINTER_BYTE_THYST, 	0x02			// DS75 pointer byte value for T_HYST
.equ POINTER_BYTE_TOS, 		0x03			// DS75 pointer byte value for T_OS
/*
 * 12-bit resolution, Fault-Tolerance: 1, O.S. is active low, Comparator mode, Shutdown = 0 (Active conversion)
 */
.equ DS75_CFGREG_MASK, 		0x60			// DS75 configuration mask

/* b): 
	 - according to the datasheet the SCL frequency of the DS75 is 400kHz (about 400kBaud)
	 - SDA hold time 		relates in DS75 to 	t_HD:DAT (min: 0 us, max: 0.9 us)
     - SCL start hold time 	relates in DS75 to 	t_HD:STA (min: 0.6 us)
     - SCL stop hold time	relates in DS75 to	t_SU:STO (min: 0.6 us)
     
     The frequency should not be the important quantity.
     Instead the listed time quantities should matter and though we can set I2C0_F to 0x00 (MULT: 00, ICR: 0)
     and the communication still succeds
         
     The following table uses a bus period of 40ns and a multiplier of 1 (mul=1<->MULT:00)
     SDA, SCL start and SCL stop are in microseconds
         
        Baud Rate | SDA   | SCL start | SCL stop | SDA Value | SCL start Val | SCL stop Val | ICR | SCL divider
		1.250.000	0,28	0,24	    0,44	   7		   6			   11			  0		20
		1.136.364	0,28	0,28	    0,48	   7		   7			   12			  1		22
		1.041.667	0,32	0,32	    0,52	   8		   8			   13			  2		24
		961.538		0,32	0,36	    0,56	   8		   9			   14			  3		26
		892.857		0,36	0,4		    0,6	       9		   10			   15			  4		28
		833.333		0,36	0,44	    0,64	   9		   11			   16			  5		30
		735.294		0,4		0,52	    0,72	   10		   13			   18			  6		34
		625.000		0,4		0,64	    0,84	   10		   16			   21			  7		40
		892.857		0,28	0,4		    0,6	       7		   10			   15			  8		28
		781.250		0,28	0,48	    0,68	   7		   12			   17			  9		32
		694.444		0,36	0,56	    0,76	   9		   14			   19			  10	36
		625.000		0,36	0,64	    0,84	   9		   16			   21			  11	40
		568.182		0,44	0,72	    0,92	   11		   18			   23			  12	44
		520.833		0,44	0,8	        1	       11		   20			   25			  13	48
		446.429		0,52	0,96	    1,16	   13		   24			   29			  14	56
		367.647		0,52	1,2		    1,4	       13		   30			   35			  15	68
		520.833		0,36	0,72	    1	       9		   18			   25			  16	48
		446.429		0,36	0,88	    1,16	   9		   22			   29			  17	56
		390.625		0,52	1,04	    1,32	   13		   26			   33			  18	64
		347.222		0,52	1,2		    1,48	   13		   30			   37			  19	72
		312.500		0,68	1,36	    1,64	   17		   34			   41			  20	80
		284.091		0,68	1,52	    1,8	       17		   38			   45			  21	88
		240.385		0,84	1,84	    2,12	   21		   46			   53			  22	104
		195.313		0,84	2,32	    2,6	       21		   58			   65			  23	128
         
        according to this tabel the combinations (mul=1 and ICR=7) or (mul=1 and ICR=11) should be suitable,
        but a test with the combination mul=1 and ICR=0 (thus I2C0_F=0x00) also succeded.
