/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init
	bl pit1_init
	bl I2CBus_Reset
	bl i2c_init
	bl ds75_configure				// configure the DS75 (12 bit, comparator, T_OS, T_HYST)
	
	// inform user about success or failure of configuration
	cmp r0, #0
	ite eq
	ldreq r0, =text_ds75_config_failure
	ldrne r0, =text_ds75_config_success
	bl uart_putString
		
	// read the temperature register (including sending the Pointer Byte)
	// so that we do not have send the Pointer Byte in the main loop
	ldr r0, =ds75_read_from_tempreg	// define routine to call multiple times (argument 1)
	mov r1, #1						// write Pointer Byte (argument 2)
	mov r2, #POINTER_BYTE_TEMP		// set Pointer Byte value (argument 3)
	bl exec_func_multiple_times		// try to read from the register multiple times
	// we assume the sub routine has been successful (so we do not check the return values)
	
main_loop_program:
	ldr r0, =flag_one_sec_passed
	ldr r1, [r0]				// load value of 1s flag
	cmp r1, #0					// if the flag is not set
	beq main_loop_program		// then there is nothing to do
	
	// the flag is set, so we have to reset it and go on
	mov r2, #0
	str r2, [r0]
	
	ldr r0, =ds75_read_from_tempreg	// define routine to call multiple times (argument 1)
	mov r1, #0						// no need to write Pointer Byte (argument 2)
	mov r2, #POINTER_BYTE_TEMP		// set Pointer Byte value (argument 3)
	bl exec_func_multiple_times		// try to read from the register multiple times
	cmp r0, #0				 		// failed to read?
	itt ne
	movne r4, r1					// remember read temperature
	bne main_print_temp				// success => print temperature
	
	// the reading failed => print error text
	ldr r0, =text_temp_read_error
	bl uart_putString
	b main_loop_program				// restart the main loop
	
main_print_temp:
	mov r0, r4						// set argument 1: temperature
	bl print_temperature			// call print sub routine
	b main_loop_program				// restart the main loop
	
/**
 * Executes a delay of about 1 sec using busy waiting.
 */
.thumb_func
PIT1_IRQHandler:
	// clear interrupt flag of PIT1
	mov r0, #0x01
	ldr r1, =PIT_TFLG1				// load address of PIT_TFLG1
	str r0, [r1]					// clear the interrupt flag
		
	// now set the one second passed flag
	ldr r1, =flag_one_sec_passed	// load address of one sec passed flag
	str r0, [r1]					// set the flag
	bx lr							// return
	
/**
 * Initializes PIT, so that an interrupt is triggered every milli second.
 * @return nothing
 */	
.thumb_func
pit1_init:	
	// first we have to enable the PIT clock, so that we can initialize PIT.
	mov r0, #1
	ldr r1, =SIM_SCGC6_PIT 		// load the address of the bit band alias
	str r0, [r1]				// update the PIT bit of register SIM_SCGC6
	
	// now we have to set the interrupt vector
	// first we need the base address of the VT (vector table)
	ldr r0, =SCR_VTOR		// load the address of the Vector Table Offset Register
	ldr r0, [r0]				// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	mov r1, #OFFSET_VT_PIT1		// load offset to PIT1 vector
	add r1, r1, r0				// get address of PIT1 vector
	ldr r2, =PIT1_IRQHandler	// get address of our ISR
	str r2, [r1]				// set PIT1_IRQHandler as our new handler of the PIT1 interrupt
	
	mov r1, #0x20				// set bit 5
	// clear all pending interrupts regarding PIT1.
	// Thus set the bit NVIC_ICPR2[5]
	ldr r0, =NVIC_ICPR2			// load address of NVIC_ICPR2
	str r1, [r0]				// clear the pending state of the PIT1 interrupt
	
	// enable PIT1 interrupt in NVIC
	// Thus set the bit NVIC_ISER2[5]
	ldr r0, =NVIC_ISER2			// load address of NVIC_ISER2
	str r1, [r0]				// enable the PIT1 interrupt
	
	// enable clock for PIT timers with timers running in debug mode (in PIT_MCR)
	ldr r0, =PIT_MCR			// load address of PIT_MCR
	mov r1, #0x00
	str r1, [r0]				// enable clock for PIT
	
	// initialize Load Value Register for a period of 1 second
	// The 25 MHz clock frequency equates to a clock period of 40ns.
	// 1s / 40ns =  25,000,000 cycles (= 0x17D_7840)
	// LDVAL trigger = (period / clock period) - 1 = 0x17D_7840 - 1
	ldr r0, =PIT_LDVAL1				// load address of PIT_LDVAL1
	ldr r1, =PIT_LDVAL1_STARTVALUE	// load timer start value
	str r1, [r0]					// write timer start value of PIT1
	
	// enable timer 1 interrupts and timer 1 (set bit 0 and 1)
	mov r1, #0x03 					// load value where bit 1 and 0 are set
	ldr r0, =PIT_TCTRL1				// load address of PIT_TCTRL1
	str r1, [r0]					// write config to timer 1 control register

	bx lr							// jump back (return)
	
/**
 * Executes busy waiting for the given time in micro seconds.
 * @parameter R0 - micro seconds to wait
 * @return nothing
 */	
.thumb_func
delay_in_us:
	// since pit3 runs with a frequence of 25MHz
	// 25 cycles are equivalent to 1 micro second
	// thus we have to caculate the loop counter
	// we have to stretch the loop iteration,
	// so that one iteration takes 5 cycles
	// so we need 1us for 5 iterations
	mov r2, #0x05
	mov r3, #0
	sub r0, r0, #1
	mul r1, r0, r2
	add r1, r1, #3

loop_delay_in_us:
	add r3, r3, #1
	add r3, r3, #1
	subs r1, r1, #1				// decrement counter (duration: 1 cycle)
	bne loop_delay_in_us		// repeat loop until we reach counter value 0
	
	bx lr						// jump back (return)
	
/**
 * Resets the I2C Bus.
 * @return nothing
 */	
.thumb_func
I2CBus_Reset:
	push {lr}
	
	ldr r0, =SIM_SCGC5_PORTD	// enable Port D clock
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR8			// configure port pins PD8 and PD9 as GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR 		// configure PD8 and PD9 as outputs
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]

	// we will repeat the loop at most 10 times
	mov r3, #10					// init loop counter
loop_I2CBus_Reset:
	ldr r0, =GPIOD_PDOR			// deactivate SCL
	ldr r2, [r0]
	bic r2, r2, #PD8 			// clear SCL bit
	str r2, [r0]
	// bl i2c_Delay				// wait for 2us
	mov r0, #2					// wait for 2us
	bl delay_in_us
	
	ldr r0, =GPIOD_PDOR 		// activate SCL and SDA
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	// bl i2c_Delay				// wait for 2us
	mov r0, #2					// wait for 2us
	bl delay_in_us
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9 			// check only bits 9 and 10
	cmp r2, #PD8_9 				// are bits 9 and 10 set?
	beq endof_I2CBus_Reset		// the bits are set => success
	
	subs r3, r3, #1				// decrement loop counter
	bne loop_I2CBus_Reset		// repeat loop as long we have not reached 0
	
	// we were not successful => output an error message
	ldr r0, =text_reset_error	// load pointer to error text
	bl uart_putString			// print error text
	
endof_I2CBus_Reset:
	pop {pc}

/**
 * Executes the passed function up to ten times.
 * Only functions that return 0 on failure, 1 on success in R0 can be handled by this function
 * @parameter R0 - function address
 * @parameter R1 - parameter 1 (optional)
 * @parameter R2 - parameter 2 (optional)
 * @parameter R3 - parameter 3 (optional)
 * @return in R0: 0 on failure, 1 on success (boolean)
 */	
.thumb_func
exec_func_multiple_times:
	push {R4-R8, LR}
	mov r4, r0					// save function address
	mov r5, r1					// save parameters
	mov r6, r2
	mov r7, r3
	
	mov r8, #10					// load loop counter
loop_func_multiple_times:
	mov r0, r5					// initialize arguments
	mov r1, r6
	mov r2, r7
	blx r4						// call function
	cmp r0, #0
	bne endof_func_multiple_times	// return successfully
	
	bl i2c_send_STOP			// just in case, try to send STOP
	
	subs r8, r8, #1				// decrement counter
	bne loop_func_multiple_times
	mov r0, #0					// return value "failure"
endof_func_multiple_times:
	pop {R4-R8, PC}
	
/**
 * Initializes the I2C Bus for communication with the DS75.
 */	
.thumb_func
i2c_init:	
	mov r3, #1
	
	ldr r0, =SIM_SCGC5_PORTD	// enable Port D clock
	str r3, [r0]
	ldr r0, =PORTD_PCR8			// configure port pins PD8 and PD9 as I2C0_SCL and I2C0_SDA
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_I2C0
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR 		// configure PD8 and PD9 as outputs
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	
	ldr r0, =SIM_SCGC4_I2C0		// enable I2C0 clock (otherwise we can not write to I2C0 registers)
	str r3, [r0]
	
	ldr r0, =I2C0_F 			// configure I2C baud rate
	mov r2, #I2C0_F_MASK
	strb r2, [r0]
	
	ldr r0, =I2C0_C1 			// enable I2C module (no interrupts)
	mov r2, #I2C0_C1_INIT_MASK
	strb r2, [r0]
	
	bx lr						// return
	
/**
 * Tries to configure the DS75 (wirte to config, T_HYST and T_OS register).
 * @return in R0: 0 on failure, 1 on success (boolean)
 */	
.thumb_func
ds75_configure:
	push {R4-R6, LR}
	mov r4, #0						// return value "failure"
	
	ldr r0, =ds75_write_to_cfgreg	// define routine to call multiple times (argument 1)
	mov r1, #DS75_CFGREG_MASK		// define value of the config register (argument 2)
	bl exec_func_multiple_times		// try to write to the register multiple times
	cmp r0, #0				 		// failed to write?
	beq endof_ds75_configure		// failure => return

	ldr r0, =ds75_read_from_cfgreg	// define routine to call multiple times (argument 1)
	mov r1, #0						// no need to write Pointer Byte (argument 2)
	bl exec_func_multiple_times		// try to read from the register multiple times
	cmp r0, #0				 		// failed to read?
	beq endof_ds75_configure		// failure => return
	
	mov r0, #DS75_CFGREG_MASK		// check if the config register of DS75 has the wanted content
	cmp r1, r0						// compare read value with expected value
	bne endof_ds75_configure		// if the values are not equal => failure
	
	// c) set T_HYST = T0 + 2°C and T_OS = T0 + 3°C
	// first we need the current ambient temperature T0
	ldr r0, =ds75_read_from_tempreg	// define routine to call multiple times (argument 1)
	mov r1, #1						// write Pointer Byte (argument 2)
	mov r2, #POINTER_BYTE_TEMP		// set Pointer Byte value (argument 3)
	bl exec_func_multiple_times		// try to read from the register multiple times
	cmp r0, #0				 		// failed to read?
	beq endof_ds75_configure		// failure => return
	
	add r5, r1, #0x0200 			// add 2°C to T0 and save result in R5 (=T_HYST)
	add r6, r1, #0x0300 			// add 3°C to T0 and save result in R6 (=T_OS)
	
	// now try to set T_HYST to T0+2°C
	ldr r0, =ds75_write_to_tempreg	// set routine to call multiple times (argument 1)
	mov r1, #POINTER_BYTE_THYST		// set Pointer Byte value (argument 2)
	mov r2, r5						// define value of T_HYST register (argument 3)
	bl exec_func_multiple_times		// try to wirte to the register multiple times
	
	// verify that the register contains the wanted value
	ldr r0, =ds75_read_from_tempreg	// define routine to call multiple times (argument 1)
	mov r1, #0						// no need to write Pointer Byte (argument 2)
	mov r2, #POINTER_BYTE_THYST		// set Pointer Byte value (argument 3)
	bl exec_func_multiple_times		// try to read from the register multiple times
	cmp r0, #0				 		// failed to read?
	beq endof_ds75_configure		// failure => return
	
	cmp r1, r5						// compare read value with expected value
	bne endof_ds75_configure		// if the values are not equal => failure
	
	// now try to set T_OS to T0+3°C
	ldr r0, =ds75_write_to_tempreg	// set routine to call multiple times (argument 1)
	mov r1, #POINTER_BYTE_TOS		// set Pointer Byte value (argument 2)
	mov r2, r6						// define value of T_OS register (argument 3)
	bl exec_func_multiple_times		// try to wirte to the register multiple times
	
	// verify that the register contains the wanted value
	ldr r0, =ds75_read_from_tempreg	// define routine to call multiple times (argument 1)
	mov r1, #0						// no need to write Pointer Byte (argument 2)
	mov r2, #POINTER_BYTE_TOS		// set Pointer Byte value (argument 3)
	bl exec_func_multiple_times		// try to read from the register multiple times
	cmp r0, #0				 		// failed to read?
	beq endof_ds75_configure		// failure => return
	
	cmp r1, r6						// compare read value with expected value
	bne endof_ds75_configure		// if the values are not equal => failure
	
	mov r4, #1						// return value "success"
endof_ds75_configure:
	mov r0, r4
	pop {R4-R6, PC}
	

	
/**
 * Prints a given number (unsigned int) in decimal format.
 * @parameter R0 - value/number to be printed
 */
.thumb_func	
uart_putUIntBase10:
	push {R4, R5, LR}	// save register
	
	mov r4, #0 					// initialize digit count
	mov r5, r0
	mov r1, #10					// we need this value for the decimal format
	
	// we have to emulate the modulo-operator
	// also the conversion starts with the least significant digit
	// but because we push the ASCII code of the digits to the stack (LIFO)
	// and finally pop them, we ensure the correct order of the digits/chars

uart_putUIntBase10_digitloop:
	udiv r2, r5, r1		// divide r5 by 10 and store the result in R2
	mul r3, r2, r1		
	sub r0, r5, r3		// calculate the result of r5 modulo 10
	add r0, r0, #0x30	// convert the digit to it's regarding char (ASCII code)
	push {r0}			// remember the char
	add r4, r4, #1		// increment digit count
	mov r5, r2			// update the remaining number
	cmp r2, #0			// is the remaining number 0? We are done if it is so,
	bne uart_putUIntBase10_digitloop	// otherwise repeat the loop
	
uart_putUIntBase10_printloop:
	// now pop the chars and print them
	pop {r0}
	bl uart_putChar
	subs r4, r4, #1		// decrement digit/char count
	bne uart_putUIntBase10_printloop
	
	pop {R4, R5, PC} 	// restore registers and return
	
/**
 * Prints the given temperature.
 * @parameter R0 - temperature, 16 bit, format 8.4(4)
 * @return nothing
 */	
.thumb_func
print_temperature:
	push {R4, R5, LR}		// save registers
	mov r4, r0				// save temperature
	
	ldr r0, =text_prefix	// print prefix "0x"
	bl uart_putString
	
	mov r0, r4				// print temperature in hex
	bl uart_putInt16
	
	ldr r0, =text_separator	// print separator string
	bl uart_putString
	
	// get number before period (unsigned byte)
	// the number is assumed to be positive
	mov r1, #0x00FF
	and r0, r1, r4, lsr #8
	bl uart_putByteBase10	// and print it
	
	mov r0, #0x2C			// print comma
	bl uart_putChar
	
	mov r1, #0x0F			// get number after period (fraction)
	and r2, r1, r4, lsr #4
	
	mov r5, r2
	cmp r2, #0x00					// do we have to print 0?
	beq print_temperature_put_frac
	
	cmp r2, #0x01						// do we have the value 2^4?
	bne print_temperature_calc_frac		// skip if we do not have to print the leading zero
	
	// we have to print 0625 since we have the value 2^4
	mov r0, 0x30	// ASCII code of digit '0'
	bl uart_putChar	// print digit 0
	ldr r5, =625
	b print_temperature_put_frac
	
print_temperature_calc_frac:
	// calculate the number
	mov r3, #1000	// divider needed to get rid of trailing zeros
	mov r5, #0		// initialize number
	
	// check bit 2^-1
	ands r1, r2, #0x08
	itt ne
	ldrne r0, =0x1388		// load 5000 in R0
	addne r5, r5, r0		// add 0.5 * 10000
	// check bit 2^-2
	ands r1, r2, #0x04
	ittt ne
	ldrne r0, =0x09C4		// load 2500 in R0
	addne r5, r5, r0		// add 0.25 * 10000
	movne r3, #100			// we have to print 2 digits => divider = 100
	// check bit 2^-3
	ands r1, r2, #0x02
	ittt ne
	ldrne r0, =0x04E2		// load 1250 in R0
	addne r5, r5, r0		// add 0.125 * 10000
	movne r3, #10			// we have to print 3 digits => divider = 10
	// check bit 2^-4
	ands r1, r2, #0x01
	ittt ne
	ldrne r0, =0x0271		// load 625 in R0
	addne r5, r5, r0		// add 0.0625 * 10000
	movne r3, #1			// we have to print 4 digits => divider = 1
	
	cmp r5, #1
	it ne
	udivne r5, r5, r3		// cut off trailing zeros
print_temperature_put_frac:
	mov r0, r5
	bl uart_putUIntBase10	// and print the number
	
	ldr r0, =text_suffix	// print suffix
	bl uart_putString
	
	pop {R4, R5, PC} 		// restore registers and return


/**
 * Waits until I2C0_S[IICIF] is set (but not forever) and clears the bit.
 * @return in R0: 0 on failure, 1 on success (boolean)
 */	
.thumb_func
wait_for_IICIF:
	ldr r0, =2000				// initialize loop count
	ldr r1, =I2C0_S				// load address of I2C0_S
	mov r3, #0x02				// save bit position of I2C0_S[IICIF]
loop_wait_for_IICIF:
	ldrb r2, [r1]				// check if I2C0_S[IICIF] is set
	ands r2, r2, r3
	ittt ne
	strbne r3, [r1]				// clear I2C0_S[IICIF]
	movne r0, #1				// return value "success"
	bne endof_wait_for_IICIF	// return
	
	subs r0, r0, #1				// decrement counter
	bne loop_wait_for_IICIF		// repeat loop until we reach counter value 0
endof_wait_for_IICIF:
	mov r3, #0x10				// save bit position of I2C0_S[ARBL]
	ldrb r2, [r1]				// check if I2C0_S[ARBL] is set
	ands r2, r2, r3
	itt ne
	strbne r3, [r1]				// clear I2C0_S[ARBL]
	movne r0, #0				// return value "failure"

	bx lr						// return
	
/**
 * Tries to send STOP and waits for 2 microseconds.
 * @return in R0: 0 on failure (I2C0_C1[MST] == 0), 1 on success (boolean)
 */	
.thumb_func
i2c_send_STOP:
	push {LR}		// save registers
	
	ldr r3, =I2C0_C1_MST
	ldrb r1, [r3]
	cmp r1, #1		// for STOP we need a transition of MST from 1 to 0
	itt ne
	movne r0, #0	// return value "failure"
	bne endof_i2c_send_STOP
	
	mov r1, #0
	strb r1, [r3]	// write 0 to I2C0_C1[MST]
	mov r0, #2		// wait for 2us
	bl delay_in_us
	mov r0, #1		// return value "success"
endof_i2c_send_STOP:
	pop {PC} 		// restore registers and return
	
/**
 * Tries to write the Address Byte (to DS75) inclusive START signal
 * @parameter R0 - Tranmission direction (0 = W/TX, 1 = R/RX)
 * @parameter R1 - Tranmission type (0 = Start, 1 = Repeat Start)
 * @return in R0: 0 on failure, 1 on success (boolean)
 */	
.thumb_func
ds75_write_address_byte:
	push {R4-R7, LR}		// save registers
	
	mov r4, #0				// return value "failure"
	
	mov r5, #ADDR_SENSOR_RX // determine address byte content
	cmp r0, #0
	it eq
	moveq r5, #ADDR_SENSOR_TX
	
	mov r3, #1				// in both transmission types, TX has to be set
	ldr r0, =I2C0_C1_TX		// set I2C0_C1[TX]		
	strb r3, [r0]
	
	cmp r1, #0				// execute "START" if R1 == 0
	itt eq
	ldreq r0, =I2C0_C1_MST	// set I2C0_C1[MST]	=> send START
	strbeq r3, [r0]
	beq wad_ds75_write_address_byte
	
	// execute "Repeat START" if R1 != 0			
	ldr r0, =I2C0_C1_RSTA	// set I2C0_C1[RSTA] => send START
	strb r3, [r0]

wad_ds75_write_address_byte:
	ldr r6, =I2C0_D
	ldr r7, =I2C0_S
	
	mov r1, #0x10			// check if ARBL is set
	ands r0, r7, r1
	itt ne
	strbne r1, [r7]			// clear ARBL and return (because we lost)
	bne endof_ds75_write_address_byte
	
	strb r5, [r6]			// write address byte to data register
	
	bl wait_for_IICIF		// we have to wait until IICIF is set
	cmp r0, #0				// is IICIF still not set => failure
	beq endof_ds75_write_address_byte
	
	// and now we expect ACK from DS75 (after Address Byte)
	// check if RXAK == 0 (Acknowledge signal was received)
	ldrb r1, [r7]
	ands r1, r1, 0x01		// if RXAK is set => failure
	bne endof_ds75_write_address_byte
	
	mov r4, #1				// return value "success"
endof_ds75_write_address_byte:
	mov r0, r4
	pop {R4-R7, PC} 		// restore registers and return
	
/**
 * Tries to write the Pointer Byte (to DS75) inclusive START signal
 * @parameter R0 - value of Pointer Byte
 * @return in R0: 0 on failure, 1 on success (boolean)
 */	
.thumb_func
ds75_write_pointer_byte:
	push {R4-R7, LR}		// save registers
	
	mov r4, #0				// return value "failure"
	mov r5, r0				// remember parameter
	
	mov r0, #0				// parameter "transmission direction TX"
	mov r1, #0 				// parameter "transmission type START"
	bl ds75_write_address_byte
	cmp r0, #0				// failure => return with failure
	beq endof_ds75_write_pointer_byte
	
	ldr r0, =I2C0_D			// write the Pointer Byte (to I2C0_D)
	strb r5, [r0]
	
	bl wait_for_IICIF
	cmp r0, #0				// is IICIF still not set => failure
	beq endof_ds75_write_pointer_byte
	
	ldr r0, =I2C0_S			// write the Pointer Byte (to I2C0_D)
	ldrb r1, [r0]			// ACK expected after Pointer Byte
	ands r1, r1, 0x01		// if RXAK is set => failure
	bne endof_ds75_write_pointer_byte

	mov r4, #1				// return value "success"
endof_ds75_write_pointer_byte:
	mov r0, r4				// set final return value
	pop {R4-R7, PC} 		// restore registers and return
	
/**
 * Tries to write to the configuration register of the DS75 (from START to STOP).
 * @parameter R0 - value to set the configuration register to
 * @return in R0: 0 on failure, 1 on success (boolean)
 */	
.thumb_func
ds75_write_to_cfgreg:
	push {R4-R5, LR}			// save registers
	
	mov r4, r0					// remember parameter/cfg reg value
	mov r5, #0					// return value "failure"
	
	mov r0, #POINTER_BYTE_CFG 	// write pointer byte value for configuration into data register
	bl ds75_write_pointer_byte
	cmp r0, #0					// failed to write pointer byte?
	beq endof_ds75_write_to_cfgreg
	
	// and now send configuration register value/mask
	ldr r1, =I2C0_D
	strb r4, [r1]
	
	bl wait_for_IICIF
	cmp r0, #0			// is IICIF still not set => failure
	beq endof_ds75_write_to_cfgreg
	
	// we already have transfered the last byte => no need to check RXAK
	bl i2c_send_STOP
	mov r5, r0			// last sub routine determines the overall return value

endof_ds75_write_to_cfgreg:
	mov r0, r5				// prepare return value
	pop {R4-R5, PC} 		// restore registers and return
	
/**
 * Tries to read from the configuration register of the DS75 (from START to STOP).
 * @parameter R0 - 0: do not send Pointer Byte, 1: send Pointer Byte
 * @return in R0: 0 on failure, 1 on success (boolean)
 * @return in R1: content of the configuration register
 */	
.thumb_func
ds75_read_from_cfgreg:
	push {R4-R6, LR}			// save registers
	
	mov r4, #0					// return value "failure"
	mov r5, r0					// save parameter
	
	cmp r5, #0					// evaluate parameter R0
	beq nopb_ds75_read_from_cfgreg	// do not send Pointer Byte
	
	// we have to send the Pointer Byte
	mov r0, #POINTER_BYTE_CFG 	// write pointer byte value for configuration into data register
	bl ds75_write_pointer_byte
	cmp r0, #0					// failed to write pointer byte?
	beq endof_ds75_read_from_cfgreg
	
nopb_ds75_read_from_cfgreg:
	mov r0, #1						// parameter "transmission direction" = RX
	mov r1, r5						// parameter "transmission type"
	bl ds75_write_address_byte
	cmp r0, #0						// failed to write address byte?
	beq endof_ds75_read_from_cfgreg
	
	ldr r5, =I2C0_D

	mov r3, #0				// switch to RX mode
	ldr r0, =I2C0_C1_TX		
	strb r3, [r0]
	
	// we only read one byte thus we have to set I2C0_C1[TXAK]
	mov r3, #1
	ldr r0, =I2C0_C1_TXAK	
	strb r3, [r0]
	
	ldrb r1, [r5]			// execute dummy read
	
	bl wait_for_IICIF
	cmp r0, #0				// is IICIF still not set => failure
	beq endof_ds75_read_from_cfgreg
	
	// send STOP and read the data register
	bl i2c_send_STOP
	mov r4, r0				// last called sub routine determines the overall return value
	ldrb r1, [r5]			// read data register
	
endof_ds75_read_from_cfgreg:
	mov r3, #0				// reset TXAK
	ldr r0, =I2C0_C1_TXAK	
	strb r3, [r0]
	mov r0, r4				// prepare return value
	pop {R4-R6, PC} 		// restore registers and return
	
/**
 * Tries to write to the T_OS or T_HYST register of the DS75 (from START to STOP).
 * @parameter R0 - register to set (T_OS: 0x3, T_HYST: 0x2; see Pointer Byte in datasheet)
 * @parameter R1 - value to set the register to
 * @return in R0: 0 on failure, 1 on success (boolean)
 */	
.thumb_func
ds75_write_to_tempreg:
	push {R4-R7, LR}			// save registers
	
	mov r4, #0					// return value "failure"
	mov r5, r1					// save register value in R6
	ldr r6, =I2C0_S				// address of the status register
	ldr r7, =I2C0_D				// address of the data register
	
	cmp r0, #POINTER_BYTE_THYST	// shall be written to T_HYST
	it eq
	beq regok_ds75_write_to_tempreg	// parameter accepted
	
	cmp r0, #POINTER_BYTE_TOS	// shall be written to T_OS
	it eq
	beq regok_ds75_write_to_tempreg // parameter accepted
	
	// other values than 2 or 3 are not allowed
	b endof_ds75_write_to_tempreg
regok_ds75_write_to_tempreg:				
	bl ds75_write_pointer_byte 	// write pointer byte value
	cmp r0, #0					// failed to write pointer byte?
	beq endof_ds75_write_to_tempreg
	
	// and now send the temperature register value
	lsr r0, r5, #8	// extract the MS Data Byte
	strb r0, [r7]	// write to the data register	
	
	bl wait_for_IICIF
	cmp r0, #0			// is IICIF still not set => failure
	beq endof_ds75_write_to_tempreg
	
	// check if RXAK == 0 (Acknowledge signal was received)
	ldrb r1, [r6]
	ands r1, r1, 0x01	// if RXAK is set => failure
	bne endof_ds75_write_to_tempreg
	
	strb r5, [r7] 		// write LS Data Byte to the data register
	
	bl wait_for_IICIF
	cmp r0, #0			// is IICIF still not set => failure
	beq endof_ds75_write_to_tempreg
	
	// we already have transfered the last byte => no need to check RXAK
	bl i2c_send_STOP
	mov r4, r0			// last sub routine determines the overall return value

endof_ds75_write_to_tempreg:
	mov r0, r4
	pop {R4-R7, PC} 		// restore registers and return
	
/**
 * Tries to read from one of the temperature registers of the DS75 (from START to STOP).
 * @parameter R0 - 0: do not send Pointer Byte, 1: send Pointer Byte
 * @parameter R1 - register to read from (T_OS: 0x3, T_HYST: 0x2, Temperature: 0x0; see Pointer Byte in datasheet)
 * @return in R0: 0 on failure, 1 on success (boolean)
 * @return in R1: content of the configuration register
 */	
.thumb_func
ds75_read_from_tempreg:
	push {R4-R6, LR}			// save registers
	
	mov r4, #0					// return value "failure"
	mov r5, r0					// save parameter R0

	cmp r1, #POINTER_BYTE_TEMP	// shall be written to Temperature
	it eq
	moveq r0, #POINTER_BYTE_TEMP // prepare argument for ds75_write_pointer_byte
	beq regok_ds75_read_from_tempreg // parameter accepted
	
	cmp r1, #POINTER_BYTE_THYST	// shall be written to T_HYST
	it eq
	moveq r0, #POINTER_BYTE_THYST // prepare argument for ds75_write_pointer_byte
	beq regok_ds75_read_from_tempreg // parameter accepted
	
	cmp r1, #POINTER_BYTE_TOS	// shall be written to T_OS
	it eq
	moveq r0, #POINTER_BYTE_TOS // prepare argument for ds75_write_pointer_byte
	beq regok_ds75_read_from_tempreg // parameter accepted
	
	// other values than 0, 2 or 3 are not allowed
	b endof_ds75_read_from_tempreg
	
regok_ds75_read_from_tempreg:
	cmp r5, #0
	beq nopb_ds75_read_from_tempreg	// do not send Pointer Byte
	
	// we have to send the Pointer Byte (value is saved in R0)
	bl ds75_write_pointer_byte
	cmp r0, #0					// failed to write pointer byte?
	beq endof_ds75_read_from_tempreg
	
nopb_ds75_read_from_tempreg:
	mov r0, #1						// parameter "transmission direction" = RX
	mov r1, r5						// parameter "transmission type"
	bl ds75_write_address_byte
	cmp r0, #0						// failed to write address byte?
	beq endof_ds75_read_from_tempreg
	
	ldr r5, =I2C0_D
	mov r3, #0				// switch to RX mode
	ldr r0, =I2C0_C1_TX		
	strb r3, [r0]
	ldrb r1, [r5]			// execute dummy read
	
	bl wait_for_IICIF
	cmp r0, #0				// is IICIF still not set => failure
	beq endof_ds75_read_from_tempreg
	
	// original: set I2C0_C1_TXAK
	mov r3, #1				// we have to set I2C0_C1[TXAK]
	ldr r0, =I2C0_C1_TXAK	
	strb r3, [r0]
	
	ldrb r1, [r5]			// read data register
	lsl r6, r1, #8			// save the MS Data Byte (at the correct position)
	
	bl wait_for_IICIF
	cmp r0, #0				// is IICIF still not set => failure
	beq endof_ds75_read_from_tempreg
	
	// send STOP and read the data register
	bl i2c_send_STOP
	mov r4, r0				// last called sub routine determines the overall return value
	ldrb r1, [r5]			// read data register
	orr r1, r6, r1
	
endof_ds75_read_from_tempreg:
	mov r3, #0				// reset TXAK
	ldr r0, =I2C0_C1_TXAK	
	strb r3, [r0]
	mov r0, r4				// update return value
	pop {R4-R6, PC} 		// restore registers and return
	

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_one_sec_passed: .word 0x0 	// flag to indicate to main that one second passed
text_prefix: .asciz "0x"
text_separator: .asciz ": "
text_suffix: .asciz " Grad Celsius\n"
text_reset_error: .asciz "I2CBus_Reset ist fehlgeschlagen!\n"
text_temp_read_error: .asciz "Lesen der Temperatur ist fehlgeschlagen!\n"
text_ds75_config_failure: .asciz "Konfigurierung des DS75 ist fehlgeschlagen!\n"
text_ds75_config_success: .asciz "Konfigurierung des DS75 war erfolgreich.\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ SIM_SCGC5_PORTA,		0x42900724		// bit band alias for bit 9  (Port A module) of SIM_SCGC5
.equ SIM_SCGC5_PORTD,		0x42900730		// bit band alias for bit 12 (Port D module) of SIM_SCGC5
.equ SIM_SCGC5_PORTE,		0x42900734		// bit band alias for bit 13 (Port E module) of SIM_SCGC5
.equ SCR_VTOR,				0xE000ED08		// address of Vector Table Offset Register
.equ OFFSET_VT_PORTA,		0x019C			// offset to the vector of port control module A
.equ OFFSET_VT_PORTE,		0x01AC			// offset to the vector of port control module E

// 0xE000E280 - 0xE000E29C NVIC_ICPR0 - NVIC_ICPR7 RW 0x00000000 Interrupt Clear-Pending Registers
// 0xE000E100 - 0xE000E11C NVIC_ISER0 - NVIC_ISER7 RW 0x00000000 Interrupt Set-Enable Registers
.equ NVIC_ICPR2, 			0xE000E288		// address of ICPR2
.equ NVIC_ISER2, 			0xE000E108		// address of ISER2

.equ BIT23_27_OF_NVIC,		0x08800000		// value to manipulate bits 23 and 27 of a NVIC register
.equ ONLY_BIT_19,			0x00080000		// value when only bit 19 is set
.equ ONLY_BIT_26,			0x04000000		// value when only bit 19 is set

.equ PORTA_PCR19, 			0x4004904C		// address of PORTA_PCR19 (SW1)
.equ PORTA_PCR19_ISF, 		0x429209E0		// address of bit 24 of PORTE_PCR19
.equ PORTE_PCR26, 			0x4004D068		// address of PORTE_PCR26 (SW2)
.equ PORTE_PCR26_ISF, 		0x429A0D60		// address of bit 24 of PORTE_PCR26

// INPUT: Since the buttons pull the potential down to ground, we need an internal pullup resistor
// => Button not pressed = HIGH, Button pressed = LOW
// MUX = 001 (ALT1), IRQC = 1010 (Interrupt on falling edge)
.equ PCR_BUTTON_CONFIG, 	0x010A0103		// Value of Pin Control Register to configure pins for the buttons SW1 & SW2

.equ GPIOA_PDDR,     		0x400FF014		// address of GPIOA_PDDR (Port Data Direction Register)
.equ GPIOE_PDDR,     		0x400FF114		// address of GPIOE_PDDR

.equ PORTD_PCR12, 			0x4004C030		// address of PORTD_PCR12 (SPI2_SCK)
.equ PORTD_PCR13, 			0x4004C034		// address of PORTD_PCR13 (SPI2_SOUT)
.equ PORTD_PCR14, 			0x4004C038		// address of PORTD_PCR14 (SPI2_SIN)
.equ PORTD_PCR15, 			0x4004C03C		// address of PORTD_PCR15 (SPI2_PCS1)

.equ ALT2_SPI2, 			0x0200			// value of PORTD_PCR12 to PCR15
.equ SIM_SCGC3_SPI2, 		0x42900630		// bit band alias for bit 12 (SPI2) of SIM_SCGC3
.equ SPI2_MCR, 				0x400AC000		// address of SPI2_MCR
.equ SPI2_CTAR0, 			0x400AC00C		// address of SPI2_CTAR0
.equ SPI2_CTAR1, 			0x400AC010		// address of SPI2_CTAR1
.equ SPI2_SR, 				0x400AC02C		// address of SPI2_SR
.equ SPI2_RSER, 			0x400AC030		// address of SPI2_RSER (controls DMA and interrupt requests)
.equ SPI2_PUSHR, 			0x400AC034		// address of SPI2_PUSHR
.equ SPI2_POPR, 			0x400AC038		// address of SPI2_POPR

.equ SPI2_MCR_HALT, 		0x43580000		// bit band alias for bit 0 (HALT) of SPI2_MCR
.equ SPI2_SR_TCF_BITPOS, 	0x80000000		// bit position of the bit SPI2_SR[TCF]
.equ SPI2_SR_EOQF_BITPOS, 	0x10000000		// bit position of the bit SPI2_SR[EOQF]

.equ SPI2_MCR_MASK_PRE,		0x82000001		// value of SPI2_MCR in order to initialize SPI2 (enable module)
.equ SPI2_MCR_MASK_POST,	0x82003C01		// value of SPI2_MCR in order to initialize SPI2 (disable TX and RX FIFOs)
/*
- Baudrate 111.607 kHz                         => PBR = 7, DBR = 0, BR = 32
- t_CSC = 400ns (in DS1722: t_CC,  Min: 400ns) => PCSSCK = 5, CSSCK = 2
- t_ASC = 160ns (in DS1722: t_CCH, Min: 100ns) => PASC   = 1, ASC   = 4
- t_DT  = 400ns (in DS1722: t_CWH, Min: 400ns) => PDT    = 5, DT    = 2
- MSB first and a frame size of 16 bits
- according to the data sheet of DS1722 we need CPHA = 1 (see Note on page 7 and figures 4 and 5)
- according to the data sheet of DS1722 we can choose CPOL as we desire
 */
.equ SPI2_CTAR_MASK,			0x7A8B0105	// value of SPI2_CTAR0 (and SPI2_CTAR1) in order to initialize SPI2
.equ SPI2_RSER_MASK,			0x00		// value of SPI2_RSER in order to initialize SPI2 (no DMA and interrupt requests)
.equ SPI2_SR_CLEARALL_MASK,		0xDA0A0000	// mask used to clear all flags in SPI2_SR
.equ SPI2_PUSHR_CMDF_MASK,		0x08020000	// content of the command field of SPI2_PUSHR
.equ SPI2_PUSHR_CFGR_INITVAL,	0x080280E9	// PUHSR content used to write to the DS1722's config register in the initialization phase

.equ SW1_FLAG_EDGEDETECT,		0x22000000	// bit band alias of data var_button_flags, bit 0 (edge detected SW1)
.equ SW2_FLAG_EDGEDETECT,		0x22000004	// bit band alias of data var_button_flags, bit 1 (edge detected SW2)

.equ OFFSET_CFG2REAL_VAL,		0x08		// offset to add to the resolution value (R2-R0) of the DS1722 config register, in order to get the real resolution value (in bit)

.equ DS1722_CFGR_BASE_MASK,		0x80E1		// base mask used to set/write the config register of DS1722 (has to be ORed with the resolution bits)
.equ DS1722_CFGR_1SHOT_BITPOS,	0x10		// bit position of the 1SHOT bit used to start a conversion
.equ DS1722_READ_TEMP_MSB_MASK,	0x0200		// content of SPI2_PUSHR[TXDATA] needed to read the MSB of the measured temperature
.equ DS1722_READ_TEMP_LSB_MASK,	0x0100		// content of SPI2_PUSHR[TXDATA] needed to read the LSB of the measured temperature
.equ DS1722_SBR_MASK,			0x00FF		// mask used to extract the read byte from SPI2_POPR using "Single Byte Read" (see DS1722 data sheet)
.equ DS1722_RESOLUTION_MAXVAL,	0x0004		// max resolution (config) value (also used as init value to start the program with)

/*
 * we have to wait for the completion of a 16 bit frame (plus about 1us delay; t_CSC, t_ASC, t_DT) with a speed of about 100kBaud.
 * This should take about (16/100,000s) + 1us = 161us
 * If we assume that the execution of one loop iteration takes 5 cycles (=40ns*5=200ns), we have to execute the loop 805 times in order to wait for 161us.
 * But we want to have a high tolerance (at least twice the time) and a "to the power of 2" number, so we take 2048 (=0x0800)
 */
.equ WAIT4TCF_LOOPCOUNT,		0x0800		// maximum number of tries to read SPI2_SR[TCF] until this bit is set 

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl SW1_2_init
	bl spi2_init

	mov r4, #DS1722_RESOLUTION_MAXVAL	// remember the current resolution
	ldr r5, =SPI2_POPR
	ldr r6, =SPI2_PUSHR
	ldr r7, =SPI2_PUSHR_CMDF_MASK		// we will use always the same command field value
	ldr r8, =SPI2_SR
	ldr r9, =SPI2_SR_EOQF_BITPOS
	// we will use R11 to remember the last value written to the configuraton register of the DS1722 (with 1SHOT always cleared)
	
	// initialize the DS1722 by writing to it's configuration register
	ldr r0, =SPI2_MCR_HALT				// (spi2_init ensures that SPI2_MCR[HALT] is set)
	mov r1, #0
	ldr r2, =SPI2_PUSHR_CFGR_INITVAL 	// 1SHOT = 0, SD = 1 and resolution = 12 bit
	str r2, [r6]						// write to PUSHR (in order to write to the DS1722 config register)
	str r1, [r0]						// start frame by clearing the SPI2_MCR[HALT] bit
	bl wait_for_TCF						// wait until the frame completes
	ldr r0, [r5] 						// read POPR (the buffer has to be emptied in order to avoid a wrong content on the next read/pop)
	// from now on we will use only SPI2_SR_EOQF to start a frame
	
	// we could read back the config register in order to check if it's content has been updated (but we do not)
	// we can not be sure, that the board is running and a different program gets overwritten by this program while the board is still running
	b main_chres_loop					// branch to the part where the resolution gets changed and a conversion is started 
	
main_loop_program:
	// first check if the buttons have been pressed
	// we map the resolution values of the config register to their real values (in bit),
	// what makes checking against the limits easier
	mov r0, r4 					// determine desired value based on current resolution
	
	ldr r3, =var_button_flags	// check if the buttons have been pressed
	ldr r1, [r3]
	ands r2, r1, #0x01			// increment desired value if SW1 has been pressed
	it ne
	addne r0, r0, #1
	
	ands r2, r1, #0x02			// decrement desired value if SW2 has been pressed
	it ne
	subne r0, r0, #1
	
	mov r2, #0					// reset the button flags (in order to recognize upcoming button presses)
	str r2, [r3]
	// regard the roll-over-character of the resolution
	// set to max resolution if we have a value less than min (=0x0 == 8-bit) resolution
	cmp r0, #0
	it mi
	movmi r0, #DS1722_RESOLUTION_MAXVAL
	// set to min (=0x0 == 8-bit) resolution if we have a value greater than max resolution
	cmp r0, #DS1722_RESOLUTION_MAXVAL
	it hi
	movhi r0, #0
	
	cmp r4, r0					// if current and desired resolutions are equal,
	beq main_read_temp			// we can skip the resolution update on the DS1722
	
	// update the current resolution, since desired (R0) and current (R4) resolution will be the same now
	mov r4, r0					// and use R4 to update the DS1722's resolution			

main_chres_loop:
	// the data sheet of the DS1722 does not mention it's behavior when the config register gets written
	// during a running conversion, but from oberservations the DS1722 seems to complete the running conversion
	// with the old config register content and then starts a conversion with the new/updated config register content.
	// In the observation a change from 12 to 8 bit resolution had been printed followed by the (8 bit) temperature 28,0625 gC and that should be impossible	
	// Thus we wait until the current conversion is completed
	str r7, [r6]					// write to PUSHR (in order to read from the DS1722 config register)
	str r9, [r8]					// clear EOQF (start frame)
	bl wait_for_TCF					// wait until the frame completes
	ldr r0, [r5] 					// read POPR
	ands r1, r0, #DS1722_CFGR_1SHOT_BITPOS // the 1SHOT bit should be cleared (= conversion is completed)
	bne main_chres_loop				// if the conversion is not complete, check it again
	
	// assumption: if we set the 1SHOT and resolution bits simultaneously,
	// it could happen that a conversion with the old resolution is started
	// => update the resolution but, do not start a new conversion
	ldr r0, =DS1722_CFGR_BASE_MASK	// OR the base config mask with the desired resolution
	orr r2, r0, r4, lsl #1			// construct data field of SPI2_PUSHR
	orr r11, r7, r2					// OR command and data field of SPI2_PUSHR (and remember the last written config register content in R11)
	str r11, [r6]					// write to PUSHR (in order to write to the config register)
	str r9, [r8]					// clear EOQF (start frame)
	bl wait_for_TCF					// wait until the frame completes
	ldr r0, [r5] 					// read POPR
		
	// now start a new conversion (but do not change the resolution)
	orr r11, r11, #DS1722_CFGR_1SHOT_BITPOS	// update R11 (by setting the 1SHOT bit)
	str r11, [r6]					// write to PUSHR (in order to write to the config register)
	str r9, [r8]					// clear EOQF (start frame)
	
	// print the current resolution (and check afterwards if the SPI frame has been transmitted)
	ldr r0, =text_resolution_prefix		// print the prefix of the text line
	bl uart_putString
	
	add r0, r4, #OFFSET_CFG2REAL_VAL	// determine current resolution in bit
	bl uart_putByteBase10				// print the value
	
	ldr r0, =text_resolution_suffix		// print the suffix of the text line
	bl uart_putString
	
	// wait until the current  SPI frame has been transmitted
	bl wait_for_TCF						// wait until the frame completes
	ldr r0, [r5] 						// read POPR
	
main_read_temp:
	// check if the temperature conversion is complete
	str r7, [r6]					// write to PUSHR (in order to read from the DS1722 config register)
	str r9, [r8]					// clear EOQF (start frame)
	bl wait_for_TCF					// wait until the frame completes
	ldr r0, [r5] 					// read POPR
	ands r1, r0, #DS1722_CFGR_1SHOT_BITPOS // the 1SHOT bit should be cleared (= conversion is completed)
	bne main_loop_program			// if the conversion is not complete, return to the main loop
	
	// read the temperature
	orr r1, r7, #DS1722_READ_TEMP_MSB_MASK
	str r1, [r6]					// write to PUSHR (in order to read from the DS1722 temperature MSB register)
	str r9, [r8]					// clear EOQF (start frame)
	bl wait_for_TCF					// wait until the frame completes
	ldr r2, [r5] 					// read POPR
	and r2, r2, #DS1722_SBR_MASK	// extract the read data byte
	lsl r10, r2, #8					// shift the byte left (since it is the MSB of a halfword) and store in R10
	
	orr r1, r7, #DS1722_READ_TEMP_LSB_MASK
	str r1, [r6]					// write to PUSHR (in order to read from the DS1722 temperature LSB register)
	str r9, [r8]					// clear EOQF (start frame)
	bl wait_for_TCF					// wait until the frame completes
	ldr r2, [r5] 					// read POPR
	and r2, r2, #DS1722_SBR_MASK	// extract the read data byte
	orr r10, r10, r2				// add the LSB (part of a halfword) to R10
	
	// start the next temperature measurement/conversion by setting the 1SHOT bit
	// since we save the last written config register content in R11, we can reuse it
	str r11, [r6]					// write to PUSHR (in order to write to the DS1722 config register)
	str r9, [r8]					// clear EOQF (start frame)
	// first print the read temperature value and check afterwards if the SPI frame has been transmitted
		
	// now R10 contains a temperature in format 8.4(4) and we will print it
	lsr r0, r10, #8					// get the integer part
	bl uart_putByteBase10			// print the integer part
	
	mov r2, #0x0F					// extract the fractional part
	and r1, r2, r10, lsr #4
	
	lsl r3, r1, #3					// muliply value with 8 to get the correct LUT entry
	ldr r0, =var_tempfrac_lut		// LUT = look up table
	add r0, r0, r3					// get address of wanted LUT entry
	bl uart_putString				// print the fractional part
	
	ldr r0, =text_temp_unit_suffix	// print suffix with unit and new line
	bl uart_putString
	
	// wait until the current  SPI frame has been transmitted
	bl wait_for_TCF						// wait until the frame completes
	ldr r0, [r5] 						// read POPR	
	
	b main_loop_program
	
	
/**
 * Registers a falling edge at SW1 and updates the regarding flag
 */
.thumb_func
SW1_IRQHandler:
	mov r3, #1
	ldr r0, =SW1_FLAG_EDGEDETECT    // load bit band alias of SW1 edge detected flag
	str r3, [r0]					// set edge detected flag
	// clear interrupt flag of PORTE
	ldr r0, =PORTA_PCR19_ISF		// load address of PCR19_ISF bit band aliias
	str r3, [r0]					// clear the interrupt flag
	bx lr							// return
	
/**
 * Registers a falling edge at SW2 and updates the regarding flag
 */
.thumb_func
SW2_IRQHandler:
	mov r3, #1
	ldr r0, =SW2_FLAG_EDGEDETECT    // load bit band alias of SW2 edge detected flag
	str r3, [r0]					// set edge detected flag
	// clear interrupt flag of PORTE
	ldr r0, =PORTE_PCR26_ISF		// load address of PCR26_ISF bit band aliias
	str r3, [r0]					// clear the interrupt flag
	bx lr							// return
	
/**
 * Initializes SW1 and SW2
 */
.thumb_func
SW1_2_init:
	// reset the button flags
	mov r0, #0
	ldr r1, =var_button_flags
	str r0, [r1]
	
	// first we have to enable the clock of Port A and E,
	// so that we can initialize them.
	mov r3, #1
	ldr r1, =SIM_SCGC5_PORTA
	ldr r2, =SIM_SCGC5_PORTE
	str r3, [r1]
	str r3, [r2]
	
	// now we have to set the interrupt vectors
	// first we need the base address of the VT (vector table)
	ldr r0, =SCR_VTOR				// load the address of the Vector Table Offset Register
	ldr r0, [r0]					// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	ldr r1, =SW1_IRQHandler			// get address of our ISR
	str r1, [r0, #OFFSET_VT_PORTA]	// set SW1_IRQHandler as our new handler of the PortA interrupt
	
	ldr r2, =SW2_IRQHandler			// get address of our ISR
	str r2, [r0, #OFFSET_VT_PORTE]	// set SW2_IRQHandler as our new handler of the PortE interrupt
	
	ldr r0, =BIT23_27_OF_NVIC	// set bit 23 and 27
	ldr r1, =NVIC_ICPR2 		// load address of NVIC_ICPR2
	ldr r2, =NVIC_ISER2			// load address of NVIC_ISER2
	str r0, [r1]				// clear the pending state of the PortA and PortE interrupts
	str r0, [r2]				// enable the PortA and PortE interrupts
	
	// configure the ports and pins
	// start with the directions (we need inputs only)
	ldr r0, =GPIOA_PDDR			// load address of GPIOA_PDDR
	ldr r1, [r0]				// get register value
	ldr r3, =ONLY_BIT_19		// clear Bit 19
	bic r2, r1, r3	
	str r2, [r0]				// update register value
	
	ldr r0, =GPIOE_PDDR			// load address of GPIOE_PDDR
	ldr r1, [r0]				// get register value
	ldr r3, =ONLY_BIT_26		// clear Bit 26
	bic r2, r1, r3
	str r2, [r0]				// update register value
	
	// configure the button pins
	ldr r0, =PCR_BUTTON_CONFIG	// load config value
	ldr r1, =PORTA_PCR19		// load address of PORTA_PCR19 (SW1)
	ldr r2, =PORTE_PCR26		// load address of PORTE_PCR26 (SW2)
	str r0, [r1]				// write config for SW1
	str r0, [r2]				// write config for SW2
	
	bx lr						// return
	
/**
 * Initializes the SPI2 Bus for communication with the DS1722.
 */	
.thumb_func
spi2_init:	
	mov r3, #1					// initialize to 1 in oder to enable clocks
	ldr r0, =SIM_SCGC5_PORTD	// enable Port D clock
	ldr r1, =SIM_SCGC3_SPI2		// enable SPI2 clock (otherwise we can not write to SPI2 registers)
	str r3, [r0]
	str r3, [r1]
	
	mov r2, #ALT2_SPI2			// pins PTD12 to PTD15 have to be configured with ALT2 (SPI2)
	ldr r0, =PORTD_PCR12		// SPI2_SCK (output pin)
	ldr r1, =PORTD_PCR13		// SPI2_SOUT (output pin)
	str r2, [r0]
	str r2, [r1]
	ldr r0, =PORTD_PCR14		// SPI2_SIN (input pin)
	ldr r1, =PORTD_PCR15		// SPI2_PCS1 (output pin)
	str r2, [r0]
	str r2, [r1]
	
	// we do not have to configure the pin directions (by writing to GPIOD_PDDR)

	// since we disable the TX and RX FIFOs and also do not use queues,
	// we can not use the registers SPIx_TXFRn, SPIx_RXFRn and do not need the SPI2_TCR register
	
	// we first have to enable the module and stop it, otherwise some register bits can not be written
	ldr r0, =SPI2_MCR
	ldr r1, =SPI2_MCR_MASK_PRE
	str r1, [r0]
	
	// we do not use DMA and interrupt requests
	ldr r1, =SPI2_RSER
	mov r2, #SPI2_RSER_MASK
	str r2, [r1]
	
	// we will use only CTAR0, but to be safe we also configure CTAR1
	ldr r1, =SPI2_CTAR0
	ldr r2, =SPI2_CTAR1
	ldr r3, =SPI2_CTAR_MASK
	str r3, [r1]
	str r3, [r2]
	
	// disalbe the RX and TX FIFOs and flush them
	ldr r1, =SPI2_MCR_MASK_POST
	str r1, [r0]
	
	// finally reset all flags in the status register
	ldr r1, =SPI2_SR
	ldr r2, =SPI2_SR_CLEARALL_MASK
	str r2, [r1]
	
	bx lr						// return
	
/**
 * Waits until SPI2_SR[TCF] is set (and clears the bit).
 * @return in R0: 0 on failure, 1 on success (boolean)
 */
.thumb_func
wait_for_TCF:
	// we do not want to wait for possibly ever, so we read the flag only multiple times
	mov r0, #WAIT4TCF_LOOPCOUNT	// initialize loop count (max num of tries to read "SPI2_SR[TCF] == 1")
	ldr r1, =SPI2_SR			// load address of SPI2_SR
	ldr r3, =SPI2_SR_TCF_BITPOS	// save bit position of SPI2_SR[TCF] (needed for check and resetting)
loop_wait_for_TCF:
	ldr r2, [r1]				// check if SPI2_SR[TCF] is set
	ands r2, r2, r3
	ittt ne
	strne r3, [r1]				// clear SPI2_SR[TCF]
	movne r0, #1				// return value "success"
	bne endof_wait_for_TCF		// return
	
	subs r0, r0, #1				// decrement counter
	bne loop_wait_for_TCF		// repeat loop until we reach counter value 0
	
endof_wait_for_TCF:
	bx lr						// return


/*** Datenbereich (ab 0x20000000) ***/
.data

// Bit 0: falling edge detected on SW1, Bit 1: falling edge detected on SW2
var_button_flags: .word 0x0 						// address: 0x20000000

/*
 * Look up table in order to print the fractional part of the temperature in decimal.
 * One (string) entry consists of two words (so we need 16*8 Bytes = 128 Bytes).
 * Example: ",0000 " = 0x3030302C, 0x2030 (a string entry is "zero-terminated")
 */
var_tempfrac_lut: .word 0x3030302C, 0x2030, 0x3236302C, 0x2035, 0x3532312C, 0x2030,	0x3738312C, 0x2035, 0x3035322C, 0x2030, 0x3231332C, 0x2035, 0x3537332C, 0x2030, 0x3733342C, 0x2035, 0x3030352C, 0x2030, 0x3236352C, 0x2035, 0x3532362C, 0x2030, 0x3738362C, 0x2035, 0x3035372C, 0x2030, 0x3231382C, 0x2035, 0x3537382C, 0x2030, 0x3733392C, 0x2035
text_temp_unit_suffix: .asciz "gC\n"
text_resolution_prefix: .asciz "\nAufloesung: "
text_resolution_suffix: .asciz " Bit\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ SIM_SCGC6_RTC,					0x429007F4		// bit band alias for bit 29 (RTC) of SIM_SCGC6
.equ SCR_VTOR,						0xE000ED08		// address of Vector Table Offset Register
.equ OFFSET_VT_RTC_ALARM_INTR,		0x0148			// offset to the vector of RTC's Alarm interrupt
.equ OFFSET_VT_RTC_SECONDS_INTR,	0x014C			// offset to the vector of RTC's Seconds interrupt

// 0xE000E280 - 0xE000E29C NVIC_ICPR0 - NVIC_ICPR7 RW 0x00000000 Interrupt Clear-Pending Registers
// 0xE000E100 - 0xE000E11C NVIC_ISER0 - NVIC_ISER7 RW 0x00000000 Interrupt Set-Enable Registers
.equ NVIC_ICPR2, 					0xE000E288		// address of ICPR2
.equ NVIC_ISER2, 					0xE000E108		// address of ISER2

.equ BIT2_3_OF_NVIC,				0x0000000C		// value to manipulate bits 2 and 3 of a NVIC register

.equ RTC_TSR, 						0x4003D000		// address of RTC_TSR
.equ RTC_TPR, 						0x4003D004		// address of RTC_TPR
.equ RTC_TAR, 						0x4003D008		// address of RTC_TAR
.equ RTC_TCR, 						0x4003D00C		// address of RTC_TCR
.equ RTC_CR, 						0x4003D010		// address of RTC_CR
.equ RTC_IER, 						0x4003D01C		// address of RTC_IER
.equ RTC_SR_TCE, 					0x427A0290		// bit band alias for bit 4 (TCE) of RTC_SR

.equ RTC_IER_INITVAL,				0x0014			// initial value of the register RTC_IER
.equ RTC_CR_INITVAL,				0x0100			// initial value of the register RTC_CR (enable 32.768 kHz oscillator)
.equ RTC_OSC_STARTUP_LOOPCNT,		0x0FE502		// loop counter value needed to wait/delay for about 125ms

.equ FLAG_RTC_SECOND,				0x22000000		// bit band alias of data var_flags, bit 0 (seconds interrupt flag)
.equ FLAG_RTC_ALARM	,				0x22000004		// bit band alias of data var_flags, bit 1 (alarm interrupt flag)

.equ RTC_TAR_VAL_DAY,				86399			// value of RTC_TAR used for timer mode "day"  (23:59:59 in seconds)
.equ RTC_TAR_VAL_HOUR,				3599			// value of RTC_TAR used for timer mode "hour" (00:59:59 in seconds)
.equ RTC_TSR_PRESETVAL_DAY,			86395			// preset value of RTC_TSR used for timer mode "day"  (23:59:55 in seconds)
.equ RTC_TSR_PRESETVAL_HOUR,		3595			// preset value of RTC_TSR used for timer mode "hour" (00:59:55 in seconds)

.equ PRESET_TIMEVAL_DAY,			0x173B3700		// preset value of timer mode "day" to set buffer register to (23:59:55; see R11 in main)
.equ PRESET_TIMEVAL_HOUR,			0x003B3700		// preset value of timer mode "hour" to set buffer register to (00:59:55; see R11 in main)

.equ CHAR_LITERAL_D,				0x64			// ASCII value of the char literal 'd'
.equ CHAR_LITERAL_H,				0x68			// ASCII value of the char literal 'h'
.equ CHAR_LITERAL_R,				0x72			// ASCII value of the char literal 'r'
.equ CHAR_LITERAL_S,				0x73			// ASCII value of the char literal 's'
.equ CHAR_LITERAL_P,				0x70			// ASCII value of the char literal 'p'
.equ CHAR_LITERAL_0,				0x30			// ASCII value of the char literal '0'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl rtc_init
	
	ldr r0, =text_24h_mode		// inform user that we are in 24h/day mode
	bl uart_putString
	
	ldr r4, =FLAG_RTC_SECOND	// preload some frequently used addresses
	ldr r5, =FLAG_RTC_ALARM
	ldr r6, =RTC_TSR
	ldr r7, =RTC_TAR
	ldr r8, =RTC_SR_TCE
	ldr r9, =RTC_TPR
	
	/* from reference:
	 * Always write to the prescaler register before writing to the seconds register,
     * because the seconds register increments on the falling edge of bit 14 of the prescaler register.
     */
	
	/* we use R11 to store flags, hours, minutes and seconds
	 * Byte 0, Bit 0: display state (0 = display off, 1 = display on)
	 * Byte 0, Bit 1: timer mode (0 = 24h/day, 1 = 1h/hour)
	 * Byte 1: seconds
	 * Byte 2: minutes
	 * Byte 3: hours
	 */
	mov r11, #0x01
	
main_loop_program:
	// first check if end time has been reached
	ldr r1, [r5]				// load value of alarm flag
	cmp r1, #0					// if the flag is not set
	beq main_check_user_input	// then there is nothing to do regarding the alarm
	
	mov r0, #0					// the alarm flag is set, so we first have to reset it
	str r0, [r5]				
	
	// inform user that we reached the end time
	ldr r0, =text_end_time_reached
	bl uart_putString

main_check_user_input:
	// check if a char is present
	bl uart_charPresent
	cmp r0, #0
	beq main_check_sec_flag		// no user input => skip checking the user input

	// user input detected => initiate regarding action dependig on the read char
	bl uart_getChar
	cmp r0, #CHAR_LITERAL_D
	beq main_set_day_mode		// execute change to day mode
	
	cmp r0, #CHAR_LITERAL_H
	beq main_set_hour_mode		// execute change to hour mode
	
	cmp r0, #CHAR_LITERAL_R
	beq main_reset_timer		// execute timer reset
	
	cmp r0, #CHAR_LITERAL_S
	beq main_toggle_display_mode // turn on or off the time display
	
	cmp r0, #CHAR_LITERAL_P
	beq main_preset_timer		// update register value so that the alarm will be triggered soon
	
	// a not accepted key has been pressed, thus act as no key has been pressed.
	b main_check_sec_flag
	
main_set_day_mode:
	// we have to disable the timer before we can set RTC_TSR
	mov r0, #0
	str r0, [r8]
	
	ldr r1, =RTC_TAR_VAL_DAY	// set RTC_TAR to "23:59:59"
	str r1, [r7]
	str r0, [r9]				// reset RTC_TPR to 0
	str r0, [r6]				// reset RTC_TSR to 0
	
	// reset internal time values and update flags
	and r11, r11, #0x01			// only display state (Bit 0) stays unchanged and timer mode is set to 24h/day
	str r0, [r4]				// clear FLAG_RTC_SECOND
	str r0, [r5]				// clear FLAG_RTC_ALARM	
	
	ldr r0, =text_24h_mode		// inform user that we are in the 24h/day mode
	bl uart_putString
	mov r0, #1					// enable timer again
	str r0, [r8]				
	b main_check_sec_flag		// branch to flag check section

main_set_hour_mode:
	// we have to disable the timer before we can set RTC_TSR
	mov r0, #0
	str r0, [r8]
	
	ldr r1, =RTC_TAR_VAL_HOUR	// set RTC_TAR to "00:59:59"
	str r1, [r7]
	str r0, [r9]				// reset RTC_TPR to 0
	str r0, [r6]				// reset RTC_TSR to 0
	
	// reset internal time values and update flags
	and r11, r11, #0x01			// only display state (Bit 0) stays unchanged
	orr r11, r11, #0x02			// update timer mode to 1h/hour
	str r0, [r4]				// clear FLAG_RTC_SECOND
	str r0, [r5]				// clear FLAG_RTC_ALARM	
	
	ldr r0, =text_1h_mode		// inform user that we are in the 1h/hour mode
	bl uart_putString
	mov r0, #1					// enable timer again
	str r0, [r8]
	b main_check_sec_flag		// branch to flag check section

main_reset_timer:
	// we have to disable the timer before we can set RTC_TSR
	mov r0, #0
	str r0, [r8]
	
	str r0, [r9]				// reset RTC_TPR to 0
	str r0, [r6]				// reset RTC_TSR to 0
	
	// reset internal time values and update flags
	and r11, r11, #0xFF			// reset time value to 0 (and keep flags)
	str r0, [r4]				// clear FLAG_RTC_SECOND
	str r0, [r5]				// clear FLAG_RTC_ALARM	
	
	ldr r0, =text_timer_reset	// inform user about timer reset
	bl uart_putString
	mov r0, #1					// enable timer again
	str r0, [r8]
	b main_check_sec_flag		// branch to flag check section

main_toggle_display_mode:
	mov r3, #0x01
	and r1, r11, r3				// extract display state
	eor r1, r1, r3				// toggle display state
	
	bic r11, r11, r3			// update display state bit in R11
	orr r11, r11, r1
	
	cmp r1, #0					// determine which text to print
	ite eq
	ldreq r0, =text_display_off
	ldrne r0, =text_display_on
	
	bl uart_putString			// print the user info
	b main_check_sec_flag		// branch to flag check section

main_preset_timer:
	// we have to disable the timer before we can set RTC_TSR
	mov r3, #0
	str r3, [r8]
	
	ands r1, r11, 0x02				// determine RTC_TSR value depending on the current timer mode
	ittee eq
	ldreq r2, =PRESET_TIMEVAL_DAY	// set time value to "23:59:55" in R11
	ldreq r0, =RTC_TSR_PRESETVAL_DAY // and RTC_TSR
	ldrne r2, =PRESET_TIMEVAL_HOUR	// set time value to "00:59:55" in R11
	ldrne r0, =RTC_TSR_PRESETVAL_HOUR // and RTC_TSR
	
	str r3, [r9]					// reset RTC_TPR to 0
	str r0, [r6]					// update/preset RTC_TSR
	
	and r11, r11, #0xFF				// keep flags of R11 (flag do not change)
	orr r11, r11, r2				// update time values in R11
	str r3, [r4]					// clear FLAG_RTC_SECOND
	str r3, [r5]					// clear FLAG_RTC_ALARM	
	
	ldr r0, =text_clock_put_forward	// inform user about preset
	bl uart_putString
	mov r0, #1						// enable timer again
	str r0, [r8]
	
main_check_sec_flag:
	ldr r1, [r4]				// load value of seconds flag
	cmp r1, #0					// if the flag is not set
	beq main_loop_program		// then there is nothing to do
	
	mov r0, #0					// the seconds flag is set, so we first have to reset it
	str r0, [r4]
	
	// now we have to increment our timer values
	lsr r3, r11, #24			// extract hours into R3
	lsr r2, r11, #16			// extract minutes into R2
	and r2, r2, 0x00FF
	lsr r1, r11, #8				// extract seconds into R1
	and r1, r1, 0x00FF
	
	add r1, r1, #1				// increment seconds
	cmp r1, #59					// seconds "overflow"?
	itt hi
	addhi r2, r2, #1			// overflow => increment minutes and reset seconds to 0
	movhi r1, #0
	
	cmp r2, #59					// minutes "overflow"?
	itt hi
	addhi r3, r3, #1			// overflow => increment hours and reset minutes to 0
	movhi r2, #0
	
	cmp r3, #23					// hours "overflow"? (next day?)
	ittt hi
	movhi r3, #0				// overflow => reset all to 0
	movhi r2, #0
	movhi r1, #0
	
	and r11, r11, 0x00FF		// update time values in R11
	orr r11, r11, r1, lsl #8
	orr r11, r11, r2, lsl #16
	orr r11, r11, r3, lsl #24
	
	// now check if we have to print the time
	ands r0, r11, 0x01
	beq main_loop_program		// no printing needed if Bit 0 is cleared
	
	// update the text_time_format buffer
	mov r10, #10				// divider used for modulo operations
	ldr r0, =text_time_format	// get address of text_time_format
	
	// start with the update of the seconds in text_time_format
	add r0, r0, #7	
		
	udiv r2, r1, r10		// divide R1 by 10 and store the result in R2 (higher seconds digit)
	mls r3, r2, r10, r1		// calculate the result of R1 modulo 10 (lower seconds digit)
	add r3, r3, #CHAR_LITERAL_0	// convert number/digit to char literal
	
	strb r3, [r0], #-1 		// update the digit in the buffer and move the address to the next seconds digit
	add r2, r2, #CHAR_LITERAL_0 // convert number/digit to char literal
	strb r2, [r0], #-2 		// update the digit in the buffer and move the address to the first minutes digit
	
	// go on with the minutes
	lsr r1, r11, #16			// extract minutes into R1
	and r1, r1, 0x00FF
	
	udiv r2, r1, r10		// divide R1 by 10 and store the result in R2 (higher minutes digit)
	mls r3, r2, r10, r1		// calculate the result of R1 modulo 10 (lower minutes digit)
	add r3, r3, #CHAR_LITERAL_0 // convert number/digit to char literal
	
	strb r3, [r0], #-1 		// update the digit in the buffer and move the address to the next minutes digit
	add r2, r2, #CHAR_LITERAL_0 // convert number/digit to char literal
	strb r2, [r0], #-2 		// update the digit in the buffer and move the address to the first/lower hours digit
	
	ands r3, r11, 0x02		// if we are in timer mode "hour", we do not have to update the hours characters
	itt ne
	addne r0, r0, #2
	bne main_print_time
	
	// we are in the mode days, thus go on with the hours
	lsr r1, r11, #24		// extract hours into R1
	and r1, r1, 0x00FF
	
	udiv r2, r1, r10		// divide R1 by 10 and store the result in R2 (higher hours digit)
	mls r3, r2, r10, r1		// calculate the result of R1 modulo 10 (lower hours digit)
	add r3, r3, #CHAR_LITERAL_0 // convert number/digit to char literal
	
	strb r3, [r0], #-1 		// update the digit in the buffer and move the address to the next hours digit
	add r2, r2, #CHAR_LITERAL_0 // convert number/digit to char literal
	strb r2, [r0] 			// update the last hours digit in the buffer
	
main_print_time:
	bl uart_putString		// print time in hour or day format

	b main_loop_program		// restart the loop
	
/**
 * Initializes Real Time Clock
 */
.thumb_func
rtc_init:
	push {LR}

	// enable the clock of RTC in order to write to it's registers
	mov r3, #1
	ldr r0, =SIM_SCGC6_RTC
	str r3, [r0]
	
	// The only thing we can do with the bits in RTC_LR, RTC_WAR and RTC_RAR is to clear them and we do not intent to do this

	mov r3, #0
	ldr r1, =RTC_IER			// disable all interrupts (just to be safe)		
	ldr r2, =RTC_SR_TCE			// disable time counter (otherwise we can not write to certain registers)
	str r3, [r1]
	str r3, [r2]
	
	ldr r0, =RTC_CR				// enable oscillator
	ldr r1, =RTC_CR_INITVAL
	str r1, [r0]
	
	// initialize further registers (and flags) with 0 (zero)
	ldr r0, =RTC_TCR
	ldr r1, =RTC_TPR
	str r3, [r0]
	str r3, [r1]
	ldr r0, =RTC_TSR
	ldr r1, =var_flags
	str r3, [r0]
	str r3, [r1]
	
	ldr r0, =RTC_TAR			// initialize RTC_TAR with value of timer mode "day"
	ldr r1, =RTC_TAR_VAL_DAY
	str r1, [r0]
	
	// no we can set the interrupt vectors and enable the needed interrupts
	// first we need the base address of the VT (vector table)
	ldr r3, =SCR_VTOR				// load the address of the Vector Table Offset Register
	ldr r0, [r3]					// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	ldr r1, =RTC_Alarm_IRQHandler				// get address of our ISR
	str r1, [r0, #OFFSET_VT_RTC_ALARM_INTR]		// set RTC_Alarm_IRQHandler as our new handler of the RTC Alarm interrupt
	
	ldr r2, =RTC_Seconds_IRQHandler				// get address of our ISR
	str r2, [r0, #OFFSET_VT_RTC_SECONDS_INTR]	// set RTC_Seconds_IRQHandler as our new handler of the RTC Seconds interrupt
	
	ldr r0, =BIT2_3_OF_NVIC		// set bit 2 and 3
	ldr r1, =NVIC_ICPR2 		// load address of NVIC_ICPR2
	ldr r2, =NVIC_ISER2			// load address of NVIC_ISER2
	str r0, [r1]				// clear the pending state of the interrupts
	str r0, [r2]				// enable the RTC interrupts
	
	// we have to wait the oscillator startup time before we can enable the time counter
	bl wait_oscillator_startup_time
	
	ldr r0, =RTC_IER			// enable the Seconds and Alarm interrupt
	mov r1, #RTC_IER_INITVAL	
	str r1, [r0]
	
	mov r3, #1					// finally enable the time counter
	ldr r0, =RTC_SR_TCE
	str r3, [r0]
	
	pop {PC}					// return
	
	
/**
 * Sets a flag that triggers an alarm after a certain timer interval has passed.
 * @return nothing
 */	
.thumb_func
RTC_Alarm_IRQHandler:
/* regarding: RTC_SR[TAF]
 * Time alarm flag is set when the TAR[TAR] equals the TSR[TSR] and the TSR[TSR] increments.
 * This bit is cleared by writing the TAR register. */
	mov r3, #1
	ldr r0, =FLAG_RTC_ALARM    	// load bit band alias of RTC alarm flag
	str r3, [r0]				// set the flag
	
	// we have to clear RTC_SR[TAF], otherwise the alarm interrupt will be triggered permanently
	ldr r0, =RTC_TAR			// load address of RTC_TAR
	ldr r1, [r0] 				// load the current value of RTC_TAR
	str r1, [r0]				// and write it back in order to clear RTC_SR[TAF]
	
	bx lr						// return
	
/**
 * Sets a flag every second (used to create a 1s period).
 * @return nothing
 */	
.thumb_func
RTC_Seconds_IRQHandler:
	mov r3, #1
	ldr r0, =FLAG_RTC_SECOND    	// load bit band alias of RTC seconds flag
	str r3, [r0]					// set the flag

	bx lr							// return
	
/**
 * Waits until the oscillator is considered stable.
 * @return nothing
 */	
.thumb_func
wait_oscillator_startup_time:
/* see reference, chapter 26.8.1.2 Oscillator Start-Up:
[...]XTL_CLK begins clocking the counter.
When the counter reaches 4096 cycles of XTL_CLK, the oscillator is considered stable and XTL_CLK is passed to the output clock OSC_CLK_OUT.
The same should be valid for the RTC oscillator.
With a frequency of 32.768kHz 4096 cycles should take 125ms (=1s/(32768/4096)), thus we have to wait for at least 125ms */

/* 25MHz system frequency == 25,000,000 (0x17D_7840) cycles per second == 40ns cycle duration
 * for 125ms we need 3,125,000 cycles and if a loop iteration needs 3 cycles, we need 1,041,666 (= 0x0FE502) iterations */
 
	ldr r0, =RTC_OSC_STARTUP_LOOPCNT 	// load repition counter
waioscstatim_loop:
	subs r0, r0, #1						// decrement counter
	bne waioscstatim_loop				// repeat loop until we reach counter value 0
	
	bx lr								// return


/*** Datenbereich (ab 0x20000000) ***/
.data
// Bit 0: RTC Seconds flag, Bit 1: RTC Alarm flag
var_flags: .word 0x0
text_24h_mode: .asciz "24-Stunden-Modus\n"
text_1h_mode: .asciz "1-Stunden-Modus\n"
text_timer_reset: .asciz "Uhr zurueckgesetzt\n"
text_display_on: .asciz "Anzeige an\n"
text_display_off: .asciz "Anzeige aus\n"
text_clock_put_forward: .asciz "Uhr vorgestellt\n"
text_end_time_reached: .asciz "Endzeitpunkt erreicht\n"
// we need a characters/string buffer which gets updated and printed
text_time_format: .asciz "hh:mm:ss\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ SIM_SCGC5_PORTA,				0x42900724		// bit band alias for bit 9 (Port A module) of SIM_SCGC5
.equ SIM_SCGC6_PIT,					0x429007DC		// bit band alias for bit 23 (PIT) of SIM_SCGC6
.equ SIM_SCGC6_RTC,					0x429007F4		// bit band alias for bit 29 (RTC) of SIM_SCGC6
.equ SCR_VTOR,						0xE000ED08		// address of Vector Table Offset Register
//.equ OFFSET_VT_RTC_ALARM_INTR,		0x0148			// offset to the vector of RTC's Alarm interrupt
.equ OFFSET_VT_RTC_SECONDS_INTR,	0x014C			// offset to the vector of RTC's Seconds interrupt
.equ OFFSET_VT_PIT1,				0x0154			// offset to the vector of the PIT1 interrupt

// 0xE000E280 - 0xE000E29C NVIC_ICPR0 - NVIC_ICPR7 RW 0x00000000 Interrupt Clear-Pending Registers
// 0xE000E100 - 0xE000E11C NVIC_ISER0 - NVIC_ISER7 RW 0x00000000 Interrupt Set-Enable Registers
.equ NVIC_ICPR2, 					0xE000E288		// address of ICPR2
.equ NVIC_ISER2, 					0xE000E108		// address of ISER2
.equ BIT3_OF_NVIC,					0x00000008		// value to manipulate bit 3 of a NVIC register (RTC seconds interrupt)

.equ PIT_MCR, 				0x40037000		// address of PIT Module Control Register
.equ PIT_LDVAL1, 			0x40037110		// address of Timer Load Value Register of PIT1
.equ PIT_TCTRL1, 			0x40037118		// address of Timer Control Register of PIT1
.equ PIT_TFLG1, 			0x4003711C		// address of Timer Flag Register of PIT1
.equ PIT_TCTRL1_TEN,		0x426E2300		// bit band alias for bit PIT_TCTRL1[TEN] (Bit 0 of PIT_TCTRL1)

/* The 25 MHz clock frequency equates to a clock period of 40ns.
 * LDVAL trigger = (period / clock period) - 1 = 0x17D_7840 - 1
 * 100ms / 40ns =  2,500,000 cycles (= 0x0026_25A0) => LDVAL trigger = 0x0026_259F
 * 200ms / 40ns =  5,000,000 cycles (= 0x004C_4B40) => LDVAL trigger = 0x004C_4B3F
*/
.equ PIT_LDVAL1_100MS,		0x0026259F		// timer start value of PIT1 needed for a pulse of 100ms (0 bit)
.equ PIT_LDVAL1_200MS,		0x004C4B3F		// timer start value of PIT1 needed for a pulse of 200ms (1 bit)

.equ PORTA_PCR6, 			0x40049018		// address of PORTA_PCR6
.equ PORTA_PCR10, 			0x40049028		// address of PORTA_PCR10
// OUTPUT: in order to switch on the LEDs we have to pull the pins down to ground
.equ PCR_OUTPUT_CONFIG,		0x01000100		// value of Pin Control Register in order to use PTA6 and PTA10 (blue LED) as outputs

.equ GPIOA_PSOR, 			0x400FF004		// address of GPIOA_PSOR (Port Set Output Register)
.equ GPIOA_PCOR, 			0x400FF008		// address of GPIOA_PCOR (Port Clear Output Register)
.equ GPIOA_PDDR, 			0x400FF014		// address of GPIOA_PDDR (Port Data Direction Register)

.equ CONS_BITS_SET_6_10, 	0x0440			// value where only bit 6 and 10 are set

.equ RTC_TSR, 						0x4003D000		// address of RTC_TSR
.equ RTC_TPR, 						0x4003D004		// address of RTC_TPR
.equ RTC_TAR, 						0x4003D008		// address of RTC_TAR
.equ RTC_TCR, 						0x4003D00C		// address of RTC_TCR
.equ RTC_CR, 						0x4003D010		// address of RTC_CR
.equ RTC_IER, 						0x4003D01C		// address of RTC_IER
.equ RTC_SR_TCE, 					0x427A0290		// bit band alias for bit 4 (TCE) of RTC_SR

//.equ RTC_LR_WAR_RAR_INITVAL,		0x00FF			// initial value of the registers RTC_LR, RTC_WAR and RTC_RAR
.equ RTC_IER_INITVAL,				0x0010			// initial value of the register RTC_IER (use only the Seconds interrupt)
.equ RTC_CR_INITVAL,				0x0100			// initial value of the register RTC_CR (enable 32.768 kHz oscillator)
.equ RTC_OSC_STARTUP_LOOPCNT,		0x0FE502		// loop counter value needed to wait/delay for about 125ms

.equ BITPOS_FLAG_RTC_SECOND,		0x01			// bit position of var_vals_flags' flag "second started"

.equ RTC_TAR_INITVAL,				60				// init and offset value used to add to RTC_TAR in order to trigger an alarm interrupt in the next minute

.equ CHAR_LITERAL_D,				0x64			// ASCII value of the char literal 'd'
.equ CHAR_LITERAL_NEWLINE,			0x0A			// ASCII value of the char literal '\n'
.equ ASCII_DIGIT_0,					0x30			// ASCII value of the char literal '0'
.equ ASCII_DIGIT_1,					0x31			// ASCII value of the char literal '1'
.equ ASCII_DIGIT_0_QUAD,			0x30303030		// four times the char literal '0' => "0000"

.equ DCF77_PREFIX_DATA_VAL,			0x000D0000		// constant containing the first 20 bits to be transmitted in the DCF77 format

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init				// execute initializations
	bl rtc_init
	bl pit1_init
	bl portA_init
	
	ldr r0, =str_user_info
	bl uart_putString
	
main_get_datetime:
	// first we have to stop all timers
	// and we start with RTC
	mov r10, #0
	mov r11, #1
	ldr r0, =RTC_SR_TCE			// disable the timer in order to reset RTC_TPR and RTC_TSR
	str r10, [r0]
	
	ldr r0, =RTC_TPR			// reset RTC_TPR and RTC_TSR to zero
	str r10, [r0]
	ldr r0, =RTC_TSR
	str r10, [r0]
	
	// now go on with PIT1
	ldr r0, =PIT_TFLG1			// clear interrupt flag of PIT1
	str r11, [r0]
		
	// disable the PIT timer, so that the main program can set PIT_LDVAL1
	// and start the timer on the next second
	ldr r0, =PIT_TCTRL1_TEN
	str r10, [r0]
	
	// finally take back the amplitude reduction
	// => turn off the LED and set PTA6 to logic 1 (high level)
	ldr r0, =GPIOA_PSOR				// load address of GPIOA_PSOR
	mov r1, #CONS_BITS_SET_6_10		// laod mask to set Bits 6 and 10
	str r1, [r0]					// set to logic 1
	
	ldr r0, =var_vals_flags			// reset flags and values
	str r10, [r0]
	
	/* we will save the current time in R4
	 * and the current date in R5 and R6 (reason of the order: see printing of date and time)
	 * R4:
     *    - Byte 3: hour (low digit) as BCD number
	 *    - Byte 2: hour (high digit) as BCD number
     *    - Byte 1: minutes (low digit) as BCD number
     *    - Byte 0: minutes (high digit) as BCD number
	 * R5:
     *    - Byte 3: day (low digit) as BCD number
     *    - Byte 2: day (high digit) as BCD number
     *    - Byte 1: 0x0
     *    - Byte 0: weekday as BCD number (monday = 1, ..., sunday = 7)
     * R6:
     *    - Byte 3: year (low digit) as BCD number
     *    - Byte 2: year (high digit) as BCD number
     *    - Byte 1: month (low digit) as BCD number
     *    - Byte 0: month (high digit) as BCD number
     */	
	ldr r0, =str_day_prompt		// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read day from terminal
	// clamp day to the range 1 - 30
	cmp r0, #1
	it lo
	movlo r0, #1
	
	cmp r0, #30
	it hi
	movhi r0, #30
	
	mov r11, r0					// store day in byte 0 of R11
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_month_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read month from terminal
	// clamp month to the range 1 - 12
	cmp r0, #1
	it lo
	movlo r0, #1
	
	cmp r0, #12
	it hi
	movhi r0, #12
		
	orr r11, r11, r0, lsl #8	// store month in byte 1 of R11
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_year_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read year from terminal
	// no extra clamping needed since uart_getByteBase10 clamps to the range 0 - 99	
	orr r11, r11, r0, lsl #16	// store year in byte 2 of R11
	bl uart_putByteBase10 		// and print the input as feedback
	
	// do not forget to start a new line
	mov r0, #CHAR_LITERAL_NEWLINE
	bl uart_putChar
	
	// calc weekday (not really random, but quick)
	and r3, r11, #0x0F			// calc number to shift R11 right
	lsr r2, r11, r3				// shift R11 right and store result in R2
	and r5, r2, #0x07			// get weekday value (0 - 7)
	cmp r5, #0					// map 0 (invalid value) to sunday (thus clamp weekday to the range 1 - 7)
	it eq
	moveq r5, #0x07
	
	mov r9, #0xFF				// prepare variables used frequently
	mov r10, #10
	// now convert day and update R5
	and r3, r11, r9				// extract day into R3
	udiv r2, r3, r10			// divide R3 by 10 and store the result in R2 (high digit)
	mls r1, r2, r10, r3			// calculate the result of R3 modulo 10 (low digit)
	orr r5, r5, r1, lsl #24 	// update R5 with low day digit
	orr r5, r5, r2, lsl #16 	// update R5 with high day digit
	
	// now convert month and update R6		
	and r3, r9, r11, lsr #8		// extract month into R3
	udiv r2, r3, r10			// divide R3 by 10 and store the result in R2 (high digit)
	mls r1, r2, r10, r3			// calculate the result of R3 modulo 10 (low digit)
	mov r6, r2				  	// update R6 with high month digit
	orr r6, r6, r1, lsl #8  	// update R6 with low month digit
	
	// now convert year and update R6			
	and r3, r9, r11, lsr #16	// extract year into R3
	udiv r2, r3, r10			// divide R3 by 10 and store the result in R2 (high digit)
	mls r1, r2, r10, r3			// calculate the result of R3 modulo 10 (low digit)
	orr r6, r6, r1, lsl #24 	// update R6 with low year digit
	orr r6, r6, r2, lsl #16 	// update R6 with high year digit
	
	// now get the time
	ldr r0, =str_hour_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read hour from terminal
	// clamp hour to the range 0 - 23
	cmp r0, #23
	it hi
	movhi r0, #23
	
	mov r11, r0					// store hour in byte 0 of R11
	bl uart_putByteBase10 		// and print the input as feedback
	
	ldr r0, =str_minutes_prompt	// load pointer to string
	bl uart_putString			// print string
	bl uart_getByteBase10		// read minutes from terminal
	// clamp minutes to the range 0 - 59
	cmp r0, #59
	it hi
	movhi r0, #59
	orr r11, r11, r0, lsl #8	// store minutes in byte 1 of R11
	bl uart_putByteBase10 		// and print the input as feedback
	
	// do not forget to start a new line
	mov r0, #CHAR_LITERAL_NEWLINE
	bl uart_putChar
	
	// now convert minutes and update R4		
	and r3, r9, r11, lsr #8		// extract minutes into R3
	udiv r2, r3, r10			// divide R3 by 10 and store the result in R2 (high digit)
	mls r1, r2, r10, r3			// calculate the result of R3 modulo 10 (low digit)
	mov r4, r2 					// update R4 with high minutes digit
	orr r4, r4, r1, lsl #8 		// update R4 with low minutes digit
	
	// now convert hour and update R4
	and r3, r11, r9				// extract day into R3
	udiv r2, r3, r10			// divide R3 by 10 and store the result in R2 (high digit)
	mls r1, r2, r10, r3			// calculate the result of R3 modulo 10 (low digit)
	orr r4, r4, r1, lsl #24  	// update R0 with low hour digit
	orr r4, r4, r2, lsl #16  	// update R0 with high hour digit
	
	// now we assume we are in second 59
	// and the next time the RTC Seconds interrupt gets triggered
	// we are in second 0 of the date and time just read in
	
	/* register R7:
	 * Byte 1: next bit (position) of R11 to use for the pulse (0 - 31)
	 * Byte 0: next second index (0 - 59)
	*/
	mov r7, #0x0000
	ldr r8, =var_vals_flags		// load address of the flags variable
	// let us use r9 to read and manipulate the content of var_vals_flags
	
	// R11 is reserved for the bits to be transmitted via DCF77 format
	ldr r11, =DCF77_PREFIX_DATA_VAL
	
	ldr r0, =RTC_SR_TCE			// enable the RTC counter
	mov r1, #1
	str r1, [r0]
	
	// prepare the pulse duration value for the next pulse
	ldr r0, =PIT_LDVAL1_100MS	// a new minute always starts with the bit 0
	lsl r1, r0, #8
	str r1, [r8]
	
main_loop:
	// check if a char is present
	bl uart_charPresent
	cmp r0, #0
	beq main_check_flags 		// if not, skip checking user input

	// user input detected
	bl uart_getChar 			// read char from terminal
	cmp r0, #CHAR_LITERAL_D
	beq main_get_datetime		// user pressed d, thus we have to read in date and time (and restart)
	
main_check_flags:
	ldr r9, [r8]				// load content of var_vals_flags	
	// if "new second" flag is set, we can updated the seconds index, the index into R11, eventually R11 and var_vals_flags
	ands r0, r9, #BITPOS_FLAG_RTC_SECOND
	beq main_loop				// the flag is not set, so skip this part
	
	// a new second has begun
	bic r9, r9, #BITPOS_FLAG_RTC_SECOND // first clear the "new second" flag
	str r9, [r8]
	
	and r10, r7, #0xFF			// get the seconds index
	
	cmp r10, #0					// print date and time if we are in second 0
	bne main_handle_seconds		// otherwise skip the printing
	
	// print date and time
	mov r0, #CHAR_LITERAL_NEWLINE	// start a new line
	bl uart_putChar
	and r1, r5, 0x00FF				// first get the weekday (from R5)
	lsl r1, r1, #2					// multiply with 4 in order to get the correct weekday string address
	ldr r0, =text_weekday_array		// load weekday string base address
	add r0, r0, r1					// correct the address
	bl uart_putString
	
	// now update the content of text_datetime_format (", TT.MM.JJ hh:mm Uhr\n")
	ldr r0, =text_datetime_format
	ldr r3, =ASCII_DIGIT_0_QUAD
	// first update the day
	lsr r1, r5, #16					// extract the day digits
	add r1, r1, r3					// convert BCD digits to chars
	strh r1, [r0, #2]				// update day
	
	// now update month and year
	add r1, r6, r3					// convert BCD digits to chars
	strh r1, [r0, #5]				// update month
	lsr r1, r1, #16					// extract the year digits
	strh r1, [r0, #8]				// update year
	
	// now update minutes and hours
	add r1, r4, r3					// convert BCD digits to chars
	strh r1, [r0, #14]				// update minutes
	lsr r1, r1, #16					// extract the hour digits
	strh r1, [r0, #11]				// update hours
	
	bl uart_putString
	
main_handle_seconds:
	// print the current transmitted bit (0 or 1)
	lsr r1, r7, #8				// get the index into R11
	
	// print a 0, 1 or "new line" (if we are in second 59)
	lsr r0, r11, r1				// extract the regarding bit from R11
	ands r3, r0, #0x01
	ite eq
	moveq r0, #ASCII_DIGIT_0
	movne r0, #ASCII_DIGIT_1
	
	cmp r10, #59				// second 59 has no pulse => print new line char
	it eq
	moveq r0, #CHAR_LITERAL_NEWLINE
	
	bl uart_putChar
	
	cmp r10, #19				// time data starts in second 20
	beq main_handle_sec_19
	
	cmp r10, #35				// date data starts in second 36
	beq main_handle_sec_35
	
	cmp r10, #58				// no pulse in second 59
	beq main_handle_sec_58
	
	cmp r10, #59				// new minute is about to start
	beq main_handle_sec_59
	
	// normal case, where neither R7 nor R11 have to be reseted/updated
	add r7, r7, #0x0101			// increment both indices
	b main_update_pulse_duration
	
main_handle_sec_19:
	// reset index into R11 to 0
	// and increment seconds index
	and r7, r7, #0x00FF
	add r7, r7, #0x01
	// load R11 with time data (we also have to calculate the parity bits P)
	// Bits in R11: Phhh hhhP mmmm mmm1 (= 2 Bytes)
	mov r11, #0x01			 // initialize R11 for the upcoming operations
	lsr r0, r4, #8			 // extract minutes low digit and move it to the start of R0
	and r0, 0x0F
	and r1, r4, #0x07		 // extract minutes high digit and place it after the low digit
	orr r0, r0, r1, lsl #4
	mov r1, #0x07			 // store the bit position of the parity bit in R1
	bl helper_set_parity_bit // set parity bit of minutes
	orr r11, r11, r0, lsl #1 // update R11 with the minutes bits
	
	lsr r0, r4, #24			 // extract hours low digit and move it to the start of R0
	and r0, 0x0F
	lsr r1, r4, #12			 // extract hours high digit and place it after the low digit
	and r1, r1, #0x30		 // 
	orr r0, r0, r1
	mov r1, #0x06			 // store the bit position of the parity bit in R1
	bl helper_set_parity_bit // set parity bit of minutes
	orr r11, r11, r0, lsl #9 // update R11 with the hours bits
	
	b main_update_pulse_duration
	
main_handle_sec_35:
	// reset index into R11 to 0
	// and increment seconds index
	and r7, r7, #0x00FF
	add r7, r7, #0x01
	// load R11 with date data (we also have to calculate the parity bit P)
	// Bits in R11: PJJ JJJJ JJMM MMMW WWTT TTTT (about 3 Bytes, bit position of P = 22)
    lsr r0, r5, #24			 // extract day low digit and move it to the start of R0
	lsr r1, r5, #12			 // extract day high digit and place it after the low digit
	and r1, r1,#0x30
	orr r0, r0, r1			 // update R0
	and r1, r5, 0x07		 // extract weekday
	orr r0, r0, r1, lsl #6	 // update R0
	
	lsr r1, r6, #8			 // extract month low digit and move it to the start of R1
	and r1, r1, 0x0F
	orr r1, r1, r6, lsl #5	 // extract month high digit and place it after the low digit
	and r1, r1, 0x1F
	lsr r2, r6, #24			 // extract year low digit and move it to the start of R2
	lsr r3, r6, #12			 // extract year high digit and place it after the low digit
	and r3, r3, 0x00F0
	orr r2, r2, r3			 // combine year low and high digit in R2
	orr r1, r1, r2, lsl #5	 // combine month and year in R1
	orr r0, r0, r1, lsl #9	 // combine day, month and year in R0
	mov r1, #22				 // store the bit position of the parity bit in R1
	bl helper_set_parity_bit // set parity bit of date
	mov r11, r0				 // update R11
	
	b main_update_pulse_duration
	
main_handle_sec_58:
	// special case: no pulse in second 59
	and r9, r9, #0x00FF			// update pulse duration in var_vals_flags to zero
	str r9, [r8]				// write the update back into memory
	
	// the value of "index into R11" does not matter
	// but we have to increment the seconds index
	add r7, r7, #0x01
	
	// use this slot/second to update time and date (increment by one minute)
    ldr r3, =0x0000FFFF // extract minutes in order to increment them
    and r0, r4, r3		
     
    // use R10 as carry-over-bit
    ldr r2, =0x0905		// do we have minute 59?
    cmp r0, r2
    ittt eq
    moveq r0, #0		// overflow => set minutes to 0
    moveq r10, #1		// set carry-over-bit
    beq main_handle_sec_58_wb_minutes // wb = write back
    
    // we have no minutes overflow
    mov r10, #0			// reset carry-over-bit
    lsr r2, r0, #8 		// extract the low digit
    cmp r2, #9			// overflow of low digit?
    itte eq
    addeq r0, r0, #0x01 // if eq: increment high digit and set low digit to zero
    andeq r0, r0, #0x00FF
    addne r0, r0, #0x0100 // if ne: only increment low digit
    
main_handle_sec_58_wb_minutes:	
	bic r4, r4, r3		// write the updated minutes back to R4	
	orr r4, r4, r0
	
	cmp r10, #0			// if we have no carry-over-bit, then the update is done
    beq main_loop

    // update/increment the hours
    lsr r0, r4, #16	// extract hours
 
    ldr r2, =0x0302 // have we hour 23?
    cmp r0, r2		
    ittt eq
    moveq r0, #0	// overflow => set hours to 0
    moveq r10, #1	// set carry-over-bit
    beq main_handle_sec_58_wb_hours
    
    // we have no hours overflow (and the carry-over-bit is not set)
    mov r10, #0			// reset carry-over-bit
    lsr r2, r0, #8 		// extract the low digit
    cmp r2, #9			// overflow of low digit?
    itte eq
    addeq r0, r0, #0x01 // if eq: increment high digit and set low digit to zero
    andeq r0, r0, #0x00FF
    addne r0, r0, #0x0100 // if ne: only increment low digit

main_handle_sec_58_wb_hours:		
	and r4, r4, r3		// write the updated hours back to R4 (R3 = 0x00FFFF)
	orr r4, r4, r0, lsl #16
	
	cmp r10, #0			// if we have no carry-over-bit, then the update is done
    beq main_loop
    
    // now we have to increment the day (we can assume that each month has 30 days)
    and r0, r5, 0x00FF	// extract weekday
    cmp r0, #7
    ite eq
    moveq r0, #1		// overflow from sunday (7) to monday (1)
    addne r0, r0, #1	// no overflow
    
    lsr r1, r5, #16		// extract day
    mov r5, r0			// update R5 with current weekday (and delete old day data)
    mov r2, #0x0003		// do we have day 30?
    cmp r1, r2		
    ittt eq
    moveq r1, #0x0100	// overflow => set day to 1
    moveq r10, #1		// set carry-over-bit
    beq main_handle_sec_58_wb_day
    
    // we have no day overflow (and the carry-over-bit is not set)
    mov r10, #0			// reset carry-over-bit
    lsr r2, r1, #8 		// extract the low digit
    cmp r2, #9			// overflow of low digit?
    itte eq
    addeq r1, r1, #0x01 // if eq: increment high digit and set low digit to zero
    andeq r1, r1, #0x00FF
    addne r1, r1, #0x0100 // if ne: only increment low digit
    
main_handle_sec_58_wb_day:
	orr r5, r5, r1, lsl #16 // write the updated day back to R5
	
	cmp r10, #0			// if we have no carry-over-bit, then the update is done
    beq main_loop
    
    // update/increment the month
    and r0, r6, r3		// extract month (R3 = 0x00FFFF)
 
    ldr r2, =0x0201 	// do we have month 12?
    cmp r0, r2		
    ittt eq
    moveq r0, #0x0100	// overflow => set month to 1
    moveq r10, #1		// set carry-over-bit
    beq main_handle_sec_58_wb_month
    
    // we have no month overflow (and the carry-over-bit is not set)
    mov r10, #0			// reset carry-over-bit
    lsr r2, r0, #8 		// extract the low digit
    cmp r2, #9			// overflow of low digit?
    itte eq
    addeq r0, r0, #0x01 // if eq: increment high digit and set low digit to zero
    andeq r0, r0, #0x00FF
    addne r0, r0, #0x0100 // if ne: only increment low digit
    
main_handle_sec_58_wb_month:
	bic r6, r6, r3		// write the updated month back to R6 (R3 = 0x00FFFF)
	orr r6, r6, r0
	
	cmp r10, #0			// if we have no carry-over-bit, then the update is done
    beq main_loop
    
    // update/increment the year
    lsr r0, r6, #16		// extract year
    
    ldr r2, =0x0909 	// do we have year 99?
    cmp r0, r2		
    ittt eq
    moveq r0, #0x00		// overflow => set year to 0
    moveq r10, #1		// set carry-over-bit
    beq main_handle_sec_58_wb_year
    
    // we have no year overflow (and the carry-over-bit is not set)
    lsr r2, r0, #8 		// extract the low digit
    cmp r2, #9			// overflow of low digit?
    itte eq
    addeq r0, r0, #0x01 // if eq: increment high digit and set low digit to zero
    andeq r0, r0, #0x00FF
    addne r0, r0, #0x0100 // if ne: only increment low digit
    
main_handle_sec_58_wb_year:
	and r6, r6, r3		// write the updated year back to R6 (R3 = 0x00FFFF)
	orr r6, r6, r0, lsl #16
	b main_loop
	
main_handle_sec_59:
	// reset index into R11 to 0
	// reset seconds index to 0
	mov r7, #0x0000
	ldr r11, =DCF77_PREFIX_DATA_VAL // load R11 with DCF77_PREFIX_DATA_VAL
	
main_update_pulse_duration:
	// set pulse duration of next pulse
	lsr r1, r7, #8				// get index into R11
	
	lsr r0, r11, r1				// extract the regarding bit from R11
	ands r3, r0, #0x01
	ite eq
	ldreq r0, =PIT_LDVAL1_100MS
	ldrne r0, =PIT_LDVAL1_200MS
	
	and r9, r9, #0x00FF			// update pulse duration in var_vals_flags
	orr r9, r9, r0, lsl #8
	str r9, [r8]				// write the update back into memory
	
	b main_loop
	
	
/**
 * Starts a pulse (amplitude reduction) and sets the regarding flags
 * @return nothing
 */	
.thumb_func
RTC_Seconds_IRQHandler:
	ldr r0, =var_vals_flags		// get the content of var_vals_flags
	ldr r3, [r0]
	orr r3, r3, #BITPOS_FLAG_RTC_SECOND // set the flag "second started"
	str r3, [r0]				// write back the update
	
	lsr r2, r3, #8				// extract the regarding pulse duration
	cmp r2, #0					// check if we have to skip the pulse
	beq endof_RTC_Seconds_IRQHandler
	
	ldr r1, =PIT_LDVAL1			// set PIT_LDVAL1 to the regarding value
	str r2, [r1]
	
	ldr r0, =GPIOA_PCOR			// reduce the amplitude and turn on the LED
	mov r1, #CONS_BITS_SET_6_10	
	mov r2, #0x01 				// enable the timer
	ldr r3, =PIT_TCTRL1_TEN
	str r1, [r0]	
	str r2, [r3]

endof_RTC_Seconds_IRQHandler:
	bx lr							// return
	
/**
 * Ends a pulse by setting pin level.
 */
.thumb_func
PIT1_IRQHandler:
	mov r3, #0x01					// clear interrupt flag of PIT1
	ldr r0, =PIT_TFLG1
	str r3, [r0]
	
	// take back the amplitude reduction
	// => turn off the LED and set PTA6 to logic 1 (high level)
	ldr r0, =GPIOA_PSOR				// load address of GPIOA_PSOR
	mov r1, #CONS_BITS_SET_6_10		// laod mask to set Bits 6 and 10
	str r1, [r0]					// set to logic 1
	
	// disable the timer, so that the main program can set PIT_LDVAL1
	// and start the timer on the next second
	mov r2, #0
	ldr r0, =PIT_TCTRL1_TEN
	str r2, [r0]
		
	bx lr
	
	
/**
 * Calculates an even parity starting checking all bits from bit 0 until the parity bit (exlusive) and updates the parity bit.
 * @parameter R0 - bit sequence with data bits and cleared parity bit
 * @parameter R1 - bit position of the parity bit (starting with 0)
 * @return R0 - given parameter R0 with updated parity bit
 */
.thumb_func
helper_set_parity_bit:
	push {R4, LR}					// save registers
	mov r4, r0						// we will have to shift the input data (but we have to keep the original content of R0)
	mov r3, r1						// initialize loop counter
	mov r2, #0						// initialize parity bit value
	
helper_set_parity_bit_loop:
	eor r2, r2, r4					// XOR Bit 0 of R2 with Bit 0 of R4
	lsr r4, r4, #1					// shift R4 to the right in order to check it's next bit
	subs r3, r3, #1					// decrement the loop counter
	bne helper_set_parity_bit_loop	// we have not checked all bits (exclusive the parity bit)
	
	and r2, r2, 0x01				// the parity bit is bit 0 of R2
	lsl r2, r2, r1					// shift the parity bit to it's correct position
	orr r0, r0, r2					// update R0 with the parity bit
	pop {R4, PC} 					// restore registers and return
	
/**
 * Waits until the oscillator is considered stable.
 * @return nothing
 */	
.thumb_func
wait_oscillator_startup_time:
/* see reference, chapter 26.8.1.2 Oscillator Start-Up:
[...]XTL_CLK begins clocking the counter.
When the counter reaches 4096 cycles of XTL_CLK, the oscillator is considered stable and XTL_CLK is passed to the output clock OSC_CLK_OUT.
The same should be valid for the RTC oscillator.
With a frequency of 32.768kHz 4096 cycles should take 125ms (=1s/(32768/4096)), thus we have to wait for at least 125ms */

/* 25MHz system frequency == 25,000,000 (0x17D_7840) cycles per second == 40ns cycle duration
 * for 125ms we need 3,125,000 cycles and if a loop iteration needs 3 cycles, we need 1,041,666 (= 0x0FE502) iterations */
 
	ldr r0, =RTC_OSC_STARTUP_LOOPCNT 	// load repition counter
waioscstatim_loop:
	subs r0, r0, #1						// decrement counter
	bne waioscstatim_loop				// repeat loop until we reach counter value 0
	
	bx lr								// return
	
/**
 * Initializes Real Time Clock
 */
.thumb_func
rtc_init:
	push {LR}

	// enable the clock of RTC in order to write to it's registers
	mov r3, #1
	ldr r0, =SIM_SCGC6_RTC
	str r3, [r0]
	
	// The only thing we can do with the bits in RTC_LR, RTC_WAR and RTC_RAR is to clear them and we do not intent to do this

	mov r3, #0
	ldr r1, =RTC_IER			// disable all interrupts (just to be safe)		
	ldr r2, =RTC_SR_TCE			// disable time counter (otherwise we can not write certain registers)
	str r3, [r1]
	str r3, [r2]
	
	ldr r0, =RTC_CR				// enable oscillator
	ldr r1, =RTC_CR_INITVAL
	str r1, [r0]
	
	// initialize further registers (and flags) with 0 (zero)
	ldr r0, =RTC_TCR
	ldr r1, =RTC_TPR
	str r3, [r0]
	str r3, [r1]
	ldr r0, =RTC_TSR
	str r3, [r0]
	
	// no we can set the interrupt vectors and enable the needed interrupts
	// first we need the base address of the VT (vector table)
	ldr r3, =SCR_VTOR				// load the address of the Vector Table Offset Register
	ldr r0, [r3]					// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	ldr r2, =RTC_Seconds_IRQHandler				// get address of our ISR
	str r2, [r0, #OFFSET_VT_RTC_SECONDS_INTR]	// set RTC_Seconds_IRQHandler as our new handler of the RTC Seconds interrupt
	
	ldr r0, =BIT3_OF_NVIC		// set bit 3 (RTC seconds interrupt
	ldr r1, =NVIC_ICPR2 		// load address of NVIC_ICPR2
	ldr r2, =NVIC_ISER2			// load address of NVIC_ISER2
	str r0, [r1]				// clear the pending state of the interrupts
	str r0, [r2]				// enable the RTC interrupts
	
	// we have to wait the oscillator startup time before we can enable the time counter
	bl wait_oscillator_startup_time
	
	ldr r0, =RTC_IER			// enable the Seconds interrupt
	mov r1, #RTC_IER_INITVAL	
	str r1, [r0]
	
	pop {PC}					// return
	
/**
 * Initializes PORT A in order to control the blue LED and PTA6.
 * @return nothing
 */	
.thumb_func
portA_init:
	// first we have to enable the clock of Port A so that we can initialize it.
	mov r3, #1							// update the PIT bit of register SIM_SCGC6
	ldr r0, =SIM_SCGC5_PORTA			// load the address of the bit band alias
	str r3, [r0]						// update the Port A bit of register SIM_SCGC5
	
	// configure the port pins
	// start with the directions	
	ldr r0, =GPIOA_PDDR					// load address of GPIOA_PDDR
	ldr r1, [r0]						// get register value
	orr r1, r1, #CONS_BITS_SET_6_10		// set bits 6 and 10 (both are outputs)
	str r1, [r0]						// update register value
	
	// turn off LED and set PTA6 to high level
	// I prefer to turn on the LED during the short impulses and turn it off otherwise.
	// The pin of PTA6 will have high level by default and a low level (ground) during a impulse.
	// use GPIOA_PSOR to turn off LEDs (pin is high)
	// use GPIOA_PCOR to turn on LEDs  (pin is low/ground)
	ldr r0, =GPIOA_PSOR					// load address of GPIOA_PSOR
	mov r1, #CONS_BITS_SET_6_10			// laod mask to set Bits 6 and 10
	str r1, [r0]						// set to logic 1
	
	ldr r0, =PCR_OUTPUT_CONFIG			// load config value for LED pins
	ldr r1, =PORTA_PCR6					// load address of PORTA_PCR6
	ldr r2, =PORTA_PCR10				// load address of PORTA_PCR10
	str r0, [r1]						// write config
	str r0, [r2]						// write config

	bx lr								// return
	
/**
 * Initializes PIT1 in order to generate 100ms and 200ms intervals.
 * @return nothing
 */	
.thumb_func
pit1_init:
	// first we have to enable the PIT clock in order to set it's registers.
	mov r3, #1
	ldr r0, =SIM_SCGC6_PIT 			// load the address of the bit band alias
	str r3, [r0]					// update the PIT bit of register SIM_SCGC6
	
	// now we have to set the interrupt vectors
	// first we need the base address of the VT (vector table)
	ldr r1, =SCR_VTOR				// load the address of the Vector Table Offset Register
	ldr r0, [r1]					// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	// SW2_IRQHandler
	ldr r2, =PIT1_IRQHandler		// get address of our ISR
	str r2, [r0, #OFFSET_VT_PIT1]	// set PIT1_IRQHandler as our new handler of the PIT1 interrupt
	
	mov r3, #0x20					// set bit 5
	ldr r0, =NVIC_ICPR2				// clear all pending interrupts regarding PIT1.
	str r3, [r0]
	ldr r1, =NVIC_ISER2				// enable PIT1 interrupt in NVIC
	str r3, [r1]
	
	// enable clock for PIT timers with timers running in debug mode (in PIT_MCR)
	ldr r0, =PIT_MCR				// load address of PIT_MCR
	mov r1, #0x00
	str r1, [r0]					// enable clock for PIT
	
	// initialize Load Value Register for a pulse of 100ms (since every frame start with a 0)
	ldr r0, =PIT_LDVAL1				// load address of PIT_LDVAL1
	ldr r1, =PIT_LDVAL1_100MS		// load timer start value
	str r1, [r0]					// write timer start value of PIT1
	
	// enable timer 1 interrupts but do not enable the timer yet
	mov r1, #0x02 					// load value where bit 1 (PIT_TCTRL1[TIE]) is set
	ldr r0, =PIT_TCTRL1				// load address of PIT_TCTRL1
	str r1, [r0]					// write config to timer 1 control register

	bx lr							// return


/*** Datenbereich (ab 0x20000000) ***/
.data
/*
 * Byte 3 - 1: pulse duration (100ms, 200ms, 0ms/no pulse)
 * Byte 0:
 *       - Bit 0: RTC Seconds flag (a new second started)
 *       - Bit 1: RTC Alarm flag (a new minute started)
 */
var_vals_flags: .word 0x0
text_datetime_format: .asciz ", TT.MM.JJ hh:mm Uhr\n"
// According to ISO 8601 Monday has the value 1 and Sunday the value 7 (so let 0 be unknown)
text_weekday_array: .asciz "???\0Mo.\0Di.\0Mi.\0Do.\0Fr.\0Sa.\0So."
str_hour_prompt: .asciz "\nStunde eingeben (hh): "
str_minutes_prompt: .asciz "\nMinuten eingeben (mm): "
str_day_prompt: .asciz "\nTag eingeben (dd): "
str_month_prompt: .asciz "\nMonat eingeben (mm): "
str_year_prompt: .asciz "\nJahr eingeben (yy): "
str_user_info: .asciz "Druecken Sie die Taste d um Datum und Uhrzeit einzugeben.\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Declarations of constants
.equ SIM_SCGC5_PORTA,				0x42900724		// bit band alias for bit 9 (Port A module) of SIM_SCGC5
.equ SIM_SCGC6_FTM0,				0x429007E0		// bit band alias for bit 24 (FTM0) of SIM_SCGC6
.equ SCR_VTOR,						0xE000ED08		// address of Vector Table Offset Register
.equ OFFSET_VT_FTM0_INTR,			0x0138			// offset to the vector of FTM0 interrupt


// 0xE000E280 - 0xE000E29C NVIC_ICPR0 - NVIC_ICPR7 RW 0x00000000 Interrupt Clear-Pending Registers
// 0xE000E100 - 0xE000E11C NVIC_ISER0 - NVIC_ISER7 RW 0x00000000 Interrupt Set-Enable Registers
.equ NVIC_ICPR1, 					0xE000E284		// address of ICPR1 (FTM0 & FTM1)
.equ NVIC_ISER1, 					0xE000E104		// address of ISER1 (FTM0 & FTM1) 
.equ BIT30_OF_NVIC,					0x40000000		// value to manipulate bit 30 of a NVIC register (FTM0)

.equ PORTA_PCR6, 					0x40049018		// address of PORTA_PCR6
.equ PCR_OUTPUT_CONFIG_FTM,			0x01000300		// value of Pin Control Register in order to configure PTA6 as FTM0 channel 3

.equ FTM0_SC, 						0x40038000		// address of FTM0_SC
.equ FTM0_CNT, 						0x40038004		// address of FTM0_CNT
.equ FTM0_MOD, 						0x40038008		// address of FTM0_MOD
.equ FTM0_C3SC, 					0x40038024		// address of FTM0_C3SC
.equ FTM0_C3V, 						0x40038028		// address of FTM0_C3V
.equ FTM0_CNTIN,					0x4003804C		// address of FTM0_CNTIN
//.equ FTM0_STATUS, 				0x40038050		// address of FTM0_STATUS
.equ FTM0_MODE, 					0x40038054		// address of FTM0_MODE
.equ FTM0_SYNC, 					0x40038058		// address of FTM0_SYNC
.equ FTM0_OUTINIT, 					0x4003805C		// address of FTM0_OUTINIT
.equ FTM0_OUTMASK, 					0x40038060		// address of FTM0_OUTMASK
.equ FTM0_COMBINE, 					0x40038064		// address of FTM0_COMBINE
.equ FTM0_DEADTIME, 				0x40038068		// address of FTM0_DEADTIME
.equ FTM0_EXTTRIG, 					0x4003806C		// address of FTM0_EXTTRIG
.equ FTM0_POL, 						0x40038070		// address of FTM0_POL
.equ FTM0_FMS, 						0x40038074		// address of FTM0_FMS
.equ FTM0_FILTER, 					0x40038078		// address of FTM0_FILTER
.equ FTM0_FLTCTRL,					0x4003807C		// address of FTM0_FLTCTRL
.equ FTM0_QDCTRL, 					0x40038080		// address of FTM0_QDCTRL
.equ FTM0_CONF, 					0x40038084		// address of FTM0_CONF
.equ FTM0_FLTPOL, 					0x40038088		// address of FTM0_FLTPOL
.equ FTM0_SYNCONF, 					0x4003808C		// address of FTM0_SYNCONF
.equ FTM0_INVCTRL, 					0x40038090		// address of FTM0_INVCTRL
.equ FTM0_SWOCTRL, 					0x40038094		// address of FTM0_SWOCTRL
.equ FTM0_PWMLOAD, 					0x40038098		// address of FTM0_PWMLOAD

.equ FTM0_C3SC_ELSA, 				0x42700488		// bit band alias for bit 2 (ELSA) of FTM0_C3SC

.equ FTM0_SC_INITVAL, 				0x00000040		// init value of FTM0_SC (FTM counter is disabled)
.equ FTM0_MOD_INITVAL, 				0x000061A7		// init value of FTM0_MOD (needed for a PWM period of 1ms)
.equ FTM0_C3SC_INITVAL, 			0x00000078		// init value of FTM0_C3SC (we use the mode EPWM and start with a positive pulse)
.equ FTM0_C3V_INITVAL, 				0x00000EA6		// init value of FTM0_C3V (3750 == 15% duty cycle)
.equ FTM0_MODE_INITVAL, 			0x00000004		// init value of FTM0_MODE (ensure MODE[WPDIS] = 1)

.equ CHAR_LITERAL_PLUS,				0x2B			// ASCII value of the char literal '+'
.equ CHAR_LITERAL_MINUS,			0x2D			// ASCII value of the char literal '-'
.equ CHAR_LITERAL_0,				0x30			// ASCII value of the char literal '0'
.equ CHAR_LITERAL_GT,				0x3E			// ASCII value of the char literal '>' (Greater Than); will be used as prompt

.equ VAR_FLAGS_BITPOS_CHINTR,		0x01			// bit position of the channel interrupt flag in var_flags
.equ VAR_FLAGS_BITPOS_OVINTR,		0x02			// bit position of the overflow interrupt flag in var_flags
.equ VAR_FLAGS_CHINTR,				0x22000000		// bit band alias of var_flags, bit 0 (channel interrupt flag)
.equ VAR_FLAGS_OVINTR,				0x22000004		// bit band alias of var_flags, bit 1 (overflow interrupt flag)

.equ BITPOS_FTM0_SC_TOF, 			0x0080			// bit position of FTM0_SC_TOF (Bit 7)
.equ BITPOS_FTM0_C3SC_CHF,			0x0080			// bit position of FTM0_C3SC_CHF (Bit 7)

.equ DUTYCYCLE_VAL_10PERCENT,		0x09C4			// value to write to FTM0_C3V to get a duty cycle of 10%
.equ DUTYCYCLE_VAL_5PERCENT,		0x04E2			// value to write to FTM0_C3V to get a duty cycle of 5%

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init				// execute the initializations
	bl ftm0_init
	
	/* we use R4 to save/remember user input.
	 * Byte 0: last entered polarity (+ or -) as ASCII char (value 0 represents nothing has been entered, or user request has been served)
	 * Byte 1: last entered duty cycle (0 - 9) as ASCII char (value 0 represents nothing has been entered, or user request has been served)
	 */
	mov r4, #0					// prepare frequently used values and addresses
	ldr r5, =var_flags
	ldr r6, =FTM0_C3V
	ldr r7, =DUTYCYCLE_VAL_10PERCENT
	ldr r8, =DUTYCYCLE_VAL_5PERCENT
	ldr r9, =FTM0_C3SC_ELSA
	ldr r10, =FTM0_CNT
	
	mov r0, #CHAR_LITERAL_GT	// write the prompt to the terminal
	bl uart_putChar
	
main_loop:
	// check if a char is present
	bl uart_charPresent
	cmp r0, #0
	beq main_check_for_intr		// if no user input is present then skip it's handling
	
	// user input detected
	bl uart_getChar 			// read char from terminal
	mov r2, #0					// initialize flag for valid input to "false"
	
	cmp r0, #CHAR_LITERAL_PLUS	// user entered '+'?
	ittt eq
	biceq r4, r4, 0x00FF		// update Byte 0 of R4
	orreq r4, r4, r0
	moveq r2, #1				// valid input has been entered
	
	cmp r0, #CHAR_LITERAL_MINUS	// user entered '-'?
	ittt eq
	biceq r4, r4, 0x00FF		// update Byte 0 of R4
	orreq r4, r4, r0
	moveq r2, #1				// valid input has been entered
	
	sub r3, r0, #CHAR_LITERAL_0	// convert ASCII char to number/digit
	cmp r3, #9					// user entered a digit between 0 and 9 (inclusive)?
	ittt ls						// is content of R3 less or same 9 (unsigned), thus between 0 and 9?		
	andls r4, r4, 0x00FF		// we have a valid digit => update Byte 1 of R4
	orrls r4, r4, r0, lsl #8
	movls r2, #1				// valid input has been entered
	
	cmp r2, #0						// if no (accepted/valid) user input has been detected
	beq main_feedback_wrong_input 	// give the user feedback
	
	bl uart_putChar				// print the valid/accepted character (entered by the user)
	ldr r0, =text_nl_prompt
	bl uart_putString
	b main_check_for_intr		// skipt printing of wrong input feedback
	
main_feedback_wrong_input:
	ldr r0, =text_invalid_input // print line informing user about invalid input and print prompt again
	bl uart_putString
	
main_check_for_intr:
	// check if one of the interrupt flags is set
	ldr r11, [r5]				// read content of the variable var_flags
	cmp r11, #0					// if no interrupt has been detected
	beq main_loop				// then there is nothing to do
	
	// at least one interrupt (overflow and/or channel has been detected)
	// on channel interrupt change duty cycle
	ands r0, r11, #VAR_FLAGS_BITPOS_CHINTR 	// channel interrupt active?
	beq main_check_for_overflow_intr		// if not, check the overflow interrupt
	
	// channel interrupt detected
	bic r11, r11, #VAR_FLAGS_BITPOS_CHINTR	// clear the channel interrupt flag in var_flags
	lsr r0, r4, #8							// extract terminal digit
	cmp r0, #0								// if we have no user input (represented by 0x0) we can skip the duty cycle update
	beq main_check_for_overflow_intr 		// and check if we have an overflow interrupt
	
	// value of FTM0_C3V =  Z * 10% + 5% (Z = terminal digit, r7 contains the 10% value and r8 the 5% value)
	sub r0, r0, #CHAR_LITERAL_0	// convert ASCII char to number
	mla r1, r0, r7, r8			// calc new value of FTM0_C3V
	str r1, [r6]				// update duty cycle
	and r4, r4, #0x00FF			// reset digit input (because user request has been served)
	
main_check_for_overflow_intr:
	// on overflow interrupt changes the pulse polarity
	/* FTM0_C3SC_ELSA:
	 *     0: positive pulse
	 *     1: negative pulse
	 */	
	ands r0, r11, #VAR_FLAGS_BITPOS_OVINTR	// overflow interrupt active?
	itt eq									// if not
	streq r11, [r5]							// update the flags variable
	beq main_loop							// and return to the main loop
	
	// overflow interrupt detected
	bic r11, r11, #VAR_FLAGS_BITPOS_OVINTR	// clear the overflow interrupt flag in var_flags 
	str r11, [r5]							// update the flags variable
	
	and r0, r4, #0x00FF			// extract the sign
	cmp r0, #0					// if we have no user input (represented by 0x0)
	beq main_loop 				// we can skip the polarity update
	
	cmp r0, #CHAR_LITERAL_PLUS	// determine the new value of FTM0_C3SC_ELSA
	ite eq
	moveq r1, #0
	movne r1, #1
	
	str r1, [r9]				// update FTM0_C3SC_ELSA
	bic r4, r4, #0x00FF			// reset sign input (because user request has been served)

	b main_loop


/**
 * Triggers the change of the duty cycle or the polarity of the PWM signal (depending on the type of interrupt).
 */
.thumb_func
FTM0_IRQHandler:
	ldr r0, =FTM0_SC				// check if the TOF bit is set (if we have an overflow interrupt)
	ldr r1, [r0]
	ands r2, r1, #BITPOS_FTM0_SC_TOF
	beq FTM0_IRQHandler_check_chintr // no overflow interrupt => check next interrupt type 
	
	// we have an overflow interrupt
	ldr r3, =VAR_FLAGS_OVINTR		// set the regarding flag in var_flags
	mov r2, #1
	str r2, [r3]
	bic r1, r1, #BITPOS_FTM0_SC_TOF // clear the TOF bit
	str r1, [r0]
	
FTM0_IRQHandler_check_chintr:
	ldr r0, =FTM0_C3SC				// check if the CHF bit is set (if we have a channel interrupt)
	ldr r1, [r0]
	ands r2, r1, #BITPOS_FTM0_C3SC_CHF
	beq endof_FTM0_IRQHandler		// CHF is not set, thus we have no channel interrupt => return from handler routine
	
	// we have a channel interrupt
	ldr r3, =VAR_FLAGS_CHINTR		// set the regarding flag in var_flags
	mov r2, #1
	str r2, [r3]
	bic r1, r1, #BITPOS_FTM0_C3SC_CHF // clear the CHF bit
	str r1, [r0]

endof_FTM0_IRQHandler:
	bx lr							// return from handler routine

	
/**
 * Initializes FTM0 and PortA in order to transmit a PWM signal over PTA6.
 * @return nothing
 */	
.thumb_func
ftm0_init:
	// first we have to enable the clock of PortA and FTM0 so that we can initialize them.
	mov r3, #1							// the regarding bits have to be set
	ldr r0, =SIM_SCGC6_FTM0				// load the address of the bit band alias
	ldr r1, =SIM_SCGC5_PORTA			// load the address of the bit band alias
	str r3, [r0]						// update the FTM0 bit of register SIM_SCGC6
	str r3, [r1]						// update the Port A bit of register SIM_SCGC5
	
	// we do not have to configure the pin direction of PTA6/FTM0_CH3 (by writing to GPIOA_PDDR)
	// but we have to write to the "Pin Control Register" in order to activate the "FTM Alternative"
	ldr r0, =PCR_OUTPUT_CONFIG_FTM		// load config value for PTA6/FTM0_CH3
	ldr r1, =PORTA_PCR6					// load address of PORTA_PCR6
	str r0, [r1]						// write config
	
	// now we have to set the interrupt vectors
	// first we need the base address of the VT (vector table)
	ldr r1, =SCR_VTOR					// load the address of the Vector Table Offset Register
	ldr r0, [r1]						// get the base address of the vector table
	// r0 should have value 0x1FFF_FE00
	ldr r2, =FTM0_IRQHandler			// get address of our ISR
	str r2, [r0, #OFFSET_VT_FTM0_INTR]	// set FTM0_IRQHandler as our new handler of the FTM0 interrupt
	
	ldr r0, =BIT30_OF_NVIC				// set bit 30
	ldr r1, =NVIC_ICPR1 				// load address of NVIC_ICPR1
	ldr r2, =NVIC_ISER1					// load address of NVIC_ISER1
	str r0, [r1]						// clear the pending state of the FTM0 interrupt
	str r0, [r2]						// enable the FTM0 interrupt
	
	// ensure that the write protection is disabled
	ldr r0, =FTM0_MODE			// set FTM0_MODE to it's init value
	mov r1, #FTM0_MODE_INITVAL
	str r1, [r0]
	
	/* We will use the mode EPWM thus we need the following configuration:
	 * QUADEN = 0, DECAPEN = 0, COMBINE = 0, CPWMS = 0, MSnB = 1 and CNTIN = 0x0000 (see reference, chapter 40.4.6)
	 * and we will also set FTMEN = 0 (since we do not need all the features available by setting FTMEN = 1)
	 */
	ldr r0, =FTM0_SC			// set FTM0_SC to it's init value
	mov r1, #FTM0_SC_INITVAL
	str r1, [r0]
	
	mov r3, #0					// set FTM0_CNTIN to 0
	ldr r0, =FTM0_CNTIN			
	str r3, [r0]
	
	// we use a bus clock (called system clock in FTM) frequency of 25MHz what results in a period of 40ns
	// also we use a prescale of 1 and want to have a FTM period of 1ms (= frequency of 1kHz)
	// formula: FTM period = (MOD – CNTIN + 0x0001) × "period of the FTM counter clock"
	// thus we have to set FTM0_MOD to 24999
	ldr r0, =FTM0_MOD			// set FTM0_MOD to it's init value
	ldr r1, =FTM0_MOD_INITVAL
	str r1, [r0]
	
	ldr r0, =FTM0_C3SC			// set FTM0_C3SC to it's init value (EPWM with positive pulse)
	mov r1, #FTM0_C3SC_INITVAL
	str r1, [r0]
	
	ldr r0, =FTM0_C3V			// set FTM0_C3V to it's init value (15% duty cycle)
	ldr r1, =FTM0_C3V_INITVAL
	str r1, [r0]
	
	// the other registers should have their reset value (0x0)
	ldr r0, =FTM0_SYNC
	ldr r1, =FTM0_OUTINIT
	ldr r2, =FTM0_OUTMASK
	str r3, [r0]
	str r3, [r1]
	str r3, [r2]
	
	ldr r0, =FTM0_COMBINE
	str r3, [r0]
	
	ldr r0, =FTM0_DEADTIME
	str r3, [r0]
	
	ldr r0, =FTM0_EXTTRIG
	str r3, [r0]
	
	ldr r0, =FTM0_POL
	str r3, [r0]
	
	ldr r0, =FTM0_FMS
	str r3, [r0]
	
	ldr r0, =FTM0_FILTER
	str r3, [r0]
	
	ldr r0, =FTM0_FLTCTRL
	str r3, [r0]
	
	ldr r0, =FTM0_QDCTRL
	str r3, [r0]
	
	ldr r0, =FTM0_CONF
	str r3, [r0]
	
	ldr r0, =FTM0_FLTPOL
	str r3, [r0]
	
	ldr r0, =FTM0_SYNCONF
	str r3, [r0]
	
	ldr r0, =FTM0_INVCTRL
	str r3, [r0]
	
	ldr r0, =FTM0_SWOCTRL
	str r3, [r0]
	
	ldr r0, =FTM0_PWMLOAD
	str r3, [r0]
	
	// (see reference, chapter 40.5 Reset overview)
	// update the FTM counter with the CNTIN register value
	ldr r0, =FTM0_CNT	// so write any value to FTM0_CNT
	str r3, [r0]
	
	ldr r0, =FTM0_SC	// enable FTM counter (set source clock to System clock)
	mov r1, #FTM0_SC_INITVAL
	orr r1, r1, #0x08
	str r1, [r0]
	
	// now the interrupts can be triggered
	bx lr				// return from routine

/*** Datenbereich (ab 0x20000000) ***/
.data
/*
 * Byte 0:
 *       - Bit 0: FTM0 - Channel Interrupt has been triggered
 *       - Bit 1: FTM0 - Overﬂow Interrupt has been triggered
 */
var_flags: .word 0x0
text_invalid_input: .asciz "Ungueltige Eingabe! Akzeptiert wird eine Ziffer (0-9) oder die Zeichen + oder -\n>"
text_nl_prompt: .asciz "\n>"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ COUNTER, 0x10
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	mov r4, #COUNTER
	ldr r5, =byteArray
	ldr r0, =str_startText
	bl uart_putString
	
loop_getByte:
	ldr r0, =str_prompt
	bl uart_putString
	bl uart_getByte
	strb r0, [r5], #1
	bl uart_putByte
	subs r4, r4, #1
	bne loop_getByte


	ldr r0 , =str_maxStart 	// Initialisierung der Maximumsuche
	bl uart_putString
	mov r4, #COUNTER
	mov r6, #0
	bl pit3_init			// Timer starten
	

loop_calcMax:
	ldrb r0, [r5, #-1]!		// pre-dekrement = Reduziert Adresse in r5 um 1 und gibt anschließend Inhalt aus (*r5)
	cmp r0, r6				// Vergleich akt. max-Wert mit dem Datensatz
	it hi					// wenn C-Flag gesetzt, dann
	movhi r6, r0			// kopiere neuen max-Wert in r6
	subs r4, r4, #1
	bne loop_calcMax
	
	ldr r0, =maxVal
	strb r6, [r0]			// [] == * in C
	ldr r0, =str_maxEnd
	bl uart_putString
	mov r0, r6
	bl uart_putByte			// max-Wert Ausgabe
	ldr r0, =str_zeit
	bl uart_putString
	bl pit3_getval			// Suchzeit ermitteln
	bl uart_putInt16		// Suchzeit ausgeben
	
	b main 					// Rücksprung nach main
	
end:
	b end

/* Aufgabe e:
Timer wird laufend dekrementiert. 
Höhere Zahl = schneller
Niedrigere Zahl = langsamer

Zeit beim Maximum zu Beginn der Eingabe: (worst-case Szenario mit Zahlen in absteigender Reihenfolge 16...01)
0x0F71
0x3CDD

Zeit beim Maximum am Ende der Eingabe:
0xF5B3
0xF222

Erklärung:
Die Maximumbestimmung beginnt mit dem letzten Element aus dem Datensatz, da r5 in der loop_getByte 16-mal inkrementiert wurde.
D.h. wird der Maxiamlwert als letztes eingegeben, so wird der Wert einmal in r6 gespeichert.
Es erfolgt keine weitere strb-Instruktion -> der Befehl wird für folgende Werte übersrpungen und Rechenzeit gespart.

Wird der Maximalwert zu Beginn eingegeben, so wird die strb-Instruktion 16-mal (worst-case) ausgeführt, 
welches die erhöhte Rechenzeit erklärt. */


/*** Datenbereich (ab 0x20000000) ***/
.data
byteArray: // label welches die Adresse! darstellt
	.rept COUNTER
	.byte 0x00
	.endr
maxVal:
	.byte 0x00
str_startText: 
	.asciz "\nBitte 16 Bytes sukzessiv eingeben!"
str_prompt:
	.asciz "\n>"
str_maxStart:
	.asciz "\nDurchsuchen gestartet"
str_maxEnd:
	.asciz "\nDurchsuchen beendet\nMaximum: "
str_zeit:
	.asciz "\nSuchzeit: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ BYTE_OFFSET, 0x200			// 16d = 0x10, Startadresse 32-Bit Variable; 16*32 = 512d = 0x200
.equ BIT_BAND_BASE, 0x22000000


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// Annahme: 0x00 entsprich Bit 0!

main:	
	bl uart_init

loop:
	ldr r0, =str_Bit0
	bl uart_putString
	bl uart_getByte
	and r0, r0, #0x1F	// eingabe auf 1F begrenzen
	ldr r6, =reset_var1	// lade adresse reset_var1
	strb r0, [r6]		// Eingabe in reset_var1 speichern
	bl uart_putByte		// Ausgabe begrenzter Wert
	
	ldr r0, =str_Bit1
	bl uart_putString
	bl uart_getByte
	and r0, r0, #0x1F	// eingabe auf 1F begrenzen
	ldr r6, =set_var2	// lade adresse set_var2
	strb r0, [r6]		// Eingabe in set_var2 speichern
	bl uart_putByte		// Ausgabe begrenzter Wert
	
	
	/******* Ohne Bit Banding *******/
	ldr r5, =w_var		// lade adresse w_var
	ldr r0, =str_Startwert_oBB
	bl uart_putString
	ldr r0, [r5]		// Startwert w_var in r0
	bl uart_putInt32	// Startwert ausgeben
	ldr r0, [r5]		// lade Wert w_var
	
reset:
	ldr r4, =reset_var1	// lade adresse reset_var1
	ldrb r4, [r4]		// lade Wert von Adresse reset_var1 in r4
	mov r6, #0x01		// Startwert Maske
	
	lsl r1, r6, r4		// schiebe Wert 1(r6) um Position(r4) in das Register r1 (w_var)
	bic r0, r0, r1		// bit zurücksetzen (AND NOT == bit clear)
	str r0, [r5]		// Abspeichern w_var

set:
	ldr r4, =set_var2	// lade adresse set_var2
	ldrb r4, [r4]		// lade Wert von Adresse set_var2 in r4
	// Startwert Maske noch in r6
	lsl r1, r6, r4		// schiebe Wert 1(r6) um Position(r4) in das Register r1
	orr r0, r0, r1		// Set Bit r0 = r0 || r1
	str r0, [r5]		// in w_var speichern
	
	
	ldr r0, =str_val	// Ausgabe
	bl uart_putString
	ldr r0, [r5]
	bl uart_putInt32
	
	
	/******* Mit Bit Banding *******/
	ldr r5, =w_bitband
	ldr r0, =str_Startwert_mBB
	bl uart_putString
	ldr r0, [r5]
	bl uart_putInt32	// Startwert Bit_Band ausgeben

bb_reset:
	ldr r4, =reset_var1	// lade Adresse reset_var1
	ldrb r4, [r4]		
	//Ermittle BitBand Alias
	mov r3, #4			// 4 byte offset
	mul r4, r4, r3		// Bit_offset in r4
	mov r3, #BYTE_OFFSET	// Byte_offset
	add r3, r3, r4		// bit_word_offset in r3
	mov r4, #BIT_BAND_BASE
	add r4, r4 ,r3		// bit_word_addr == Gesuchte Adresse in r4
	mov r6, #0
	str r6, [r4]

bb_set:
	ldr r4, =set_var2	// lade Adresse set_var2
	ldrb r4, [r4]		
	//Ermittle BitBand Alias
	mov r3, #4			// 4 byte offset
	mul r4, r4, r3		// Bit_offset
	mov r3, #BYTE_OFFSET	// Byte_offset
	add r3, r3, r4		// bit_word_offset
	mov r4, #BIT_BAND_BASE
	add r4, r4 ,r3		// bit_word_addr == Gesuchte Adresse in r4
	mov r6, #1
	str r6, [r4]

	ldr r0, =str_val	// Ausgabe
	bl uart_putString
	ldr r0, [r5]
	bl uart_putInt32
end:
	b loop

/*** Datenbereich (ab 0x20000000) ***/
.data
w_var: .word 0x0000000F
reset_var1: .byte 0x00
set_var2: .byte 0x00
hw_dummy: .hword 0x0000
w_dummy1: .word 0x00000000
w_dummy2: .word 0x00000000
w_bitband: .word 0x0000000F // 0x20000010
str_Bit0: .asciz "\nNummer des 0-Bits: 0x"
str_Bit1: .asciz "\nNummer des 1-Bits: 0x"
str_Startwert_oBB: .asciz "\nStartwert ohne BB: "
str_Startwert_mBB: .asciz "\nStartwert mit BB: "
str_val: .asciz "\nModifizierter Wert: "	

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

.thumb_func 
getVal:
	push {r5, lr}			
	bl uart_getByte		// Werte byte weise einlesen und an die entsprechende Position shiften
	lsl r0, r0, #24		// MSB
	orr r5, r5, r0
	bl uart_getByte
	lsl r0, r0, #16
	orr r5, r5, r0
	bl uart_getByte
	lsl r0, r0, #8
	orr r5, r5, r0
	bl uart_getByte
	orr r5, r5, r0		//LSB
	str r5, [r1]		// sichern in [r1]
	pop {r5, pc}
	

main:	
	bl uart_init

start:
	ldr r6, =v1
	ldr r7, =v2
	mov r0, #0
	str r0, [r6] 			// Inhalte nach erneuten Durchlauf zurücksetzen
	str r0, [r7]
	ldr r1, =max_oDSP
	str r0, [r1]
	ldr r1, =min_oDSP	
	str r0, [r1]
	ldr r1, =max_mDSP
	str r0, [r1]
	ldr r1, =min_mDSP	
	str r0, [r1]
	
	ldr r0, =str_eingabe
	bl uart_putString
	
	ldr r0, =str_v1
	bl uart_putString
	ldr r1, =v1				// Parameterübergabe in r1
	bl getVal				// Funktionsaufruf
	ldr r0, [r6]
	bl uart_putInt32		// Ausgabe 32bit Wert
	
	ldr r0, =str_v2
	bl uart_putString
	ldr r1, =v2				// Parameterübergabe in r1
	bl getVal				// Funktionsaufruf
	ldr r0, [r7]
	bl uart_putInt32		// Ausgabe 32bit Wert
	
	
	
	/***** ohne DSP *****/
	bl pit3_init			// PIT start
	mov r3, #0
	ldr r4, =max_oDSP
	ldr r5, =min_oDSP
	ldr r0, [r6]
	ldr r1, [r7]
min_max:
	and r0, r0, #0xff		// unteren 2 Byte maskieren
	and r1, r1, #0xff

	cmp r0, r1
	ittee hi				// if-esle mit 4 conditions
	strbhi r0, [r4], #1		// post dekrement, um 1 Byte
	strbhi r1, [r5], #1
	strbls r0, [r5], #1
	strbls r1, [r4], #1
	add r3, #8				// nach jedem Durchlauf um weitere 8bit shiften
	ldr r0, [r6]
	ldr r1, [r7]
	lsr r0, r0, r3			// eingelesen Werte um 8 bit shiften für den nächsten Vergleich
	lsr r1, r1, r3
	
	cmp r3, #32
	bne min_max
	
	ldr r0, =str_ohneDSP	// Ausgabe
	bl uart_putString
	ldr r0, =min_oDSP
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, =str_max
	bl uart_putString
	ldr r0, =max_oDSP
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, = str_timer
	bl uart_putString
	bl pit3_getval
	bl uart_putInt32		// PIT-Ende
	
	
	/***** mit DSP *****/
	bl pit3_init			// PIT start
	
	ldr r4, =max_mDSP
	ldr r5, =min_mDSP
	
	ldr r1, [r6]
	ldr r2, [r7]
	
	usub8 r0, r1, r2			// 4byte DSP-Befehl, evaluation im APSR GE[0..3] register
	sel r3, r2, r1				// hole max Werte, in Abhängigkeit von GE register, 3-67
	str r3, [r5]
	sel r3, r1, r2				// hole min Werte
	str r3, [r4]
	
	ldr r0, =str_mitDSP			// Ausgabe
	bl uart_putString
	ldr r0, =min_mDSP
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, =str_max
	bl uart_putString
	ldr r0, =max_mDSP
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, = str_timer
	bl uart_putString
	bl pit3_getval
	bl uart_putInt32			// PIT-Ende
	b start					


/* Die Ausführungszeit des Programms mit DSP ist schneller im Vergleich zu den 
normalen Instruktionen. Der Grund liegt an der Anzahl der Operation. Der DSP-Befehl und Auswertung benötigt
einige wenige Zyklen. 
Die Berechnung und Auswertung einzelner Bytes ohne DSP Befehl hingegen ist langwierig und umständlich. */


/*** Datenbereich (ab 0x20000000) ***/
.data
v1: .word 0x00000000
v2: .word 0x00000000
min_oDSP: .word 0x00000000
max_oDSP: .word 0x00000000
min_mDSP: .word 0x00000000
max_mDSP: .word 0x00000000
str_eingabe: .asciz "\n4 Byte einzeln eingeben."
str_v1: .asciz "\nv1: 0x"
str_v2: .asciz "\nv2: 0x"
str_ohneDSP: .asciz "\nohne DSP-Befehle:\nmin: 0x"
str_max: .asciz "\nmax: 0x"
str_mitDSP: .asciz "\nmit DSP-Befehle:\nmin: 0x"
str_timer: .asciz "\nZeit:"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ COUNTER_4, 0x04
.equ COUNTER_8, 0x08
.equ COUNTER_16, 0x10
.equ SAT, 0x0D
.equ LF, 0x0A			// ASCII LineFeed
.equ SPACE, 0x20		// ASCII Leerzeichen
.equ PUNKT, 0x2E		// ASCII Punkt
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/


main:	
	bl uart_init

/*---------------------------------------------------------------------------*/
/************** Aufgabe a: Multiplikation zweier Matrizen (4x4) **************/
/*---------------------------------------------------------------------------*/
// Matrix M der Reihe nach im Datenbereich gespeichert
// Matrix N der Spalte nach im Datenbereich gespeichert
// Ergebnismatrix O der Reihe nach im Datenbereich gespeichert O = M * N
// Eingabe: Signed 16 bit Zahlen
// Ausgabe: Signed 32 bit Zahlen
/*---------------------------------------------------------------------------*/
	
	ldr r0, =strErgebnis	// Terminalausgabe
	bl uart_putString
	ldr r10, =M_R1			// Startadresse Matrix M
	ldr r11, =N_S1			// Startadresse Matrix N
	ldr r12, =O_R1			// Startadresse Ausgabematrix O
	mov r9, #COUNTER_4		// Für Modulo-Rechnung 
	mov r8, #COUNTER_16		// Schleifenzaehler für 4*4 Matrix
	ldr r4, [r10]			// Lade zwei 16 bit Zahlen von M (m11,m12)
	ldr r5, [r11] 			// Lade zwei 16 bit Zahlen von N (n11,n21)


out_matrix:
	smuad r0, r4, r5		// r0 = (r4[0..15] x r5[0..15]) + (r4[16..31] x r5[16..31])
	ldr r4, [r10, #4]!		// Lade nächsten zwei Zahlen von M
	ldr r5, [r11, #4]!		// Lade nächsten zwei Zahlen von N
	smlad r0, r4, r5, r0	// r0 = (r4[0..15] x r5[0..15]) + (r4[16..31] x r5[16..31]) + r0
	str r0, [r12], #4		// Ergebnis in O speichern, Adresse ++
		
	bl uart_putInt32		// Terminalausgabe Ergebnis
	mov r0, #SPACE
	bl uart_putChar
	
	sub r8, #1				// Schleifenzaehler--
	udiv r0, r8, r9			// Modulo-Rechnung: r0 = Schleifenzahler / 4
	mls r1, r9, r0, r8		// r1 = r8 - (r9*r0); (r9*r0) gibt nächsten ganzzahligen Wert an; 
							// warte bis Schleifenzaehler den selbigen Wert enthält
	cmp r1, #0				// Wenn 4 mal durchgelaufen, dann nächste Reihe von M
	ittee ne
	ldrne r4, [r10, #-4]!	// M Reihe zurücksetzen
	ldrne r5, [r11, #4]!	// N Spalte ++
	ldreq r4, [r10, #4]!	// Schleifenzahler % 4 == 0: M naechste Reihe
	ldreq r5, [r11, #-28]!	// Schleifenzahler % 4 == 0: N Spalte auf Anfangsadresse N_S1 setzen
	
	itt eq					// wenn 4 mal durchgelaufen, dann füge nl hinzu //TODO itt eq notwendig?!
	moveq r0, #LF
	bleq uart_putChar
	
	cmp r8, #0				// Schleifenzaehler != 0 ? => springe zurück
	bne out_matrix
	
/*---------------------------------------------------------------------------*/
/********************* Aufgabe b: Kopiere (4x4)- Matrix  *********************/
/*---------------------------------------------------------------------------*/
	
	ldr r0, =strCopy		// Terminalausgabe
	bl uart_putString
	ldr r0, =O_R1			// source
	ldr r1, =Ocopy_R1		// destination
	ldmia r0!, {r2-r9}		// load multiple: läd 8 worte in r2-r9. Startpunkt r0; r0 wird mit letzter adresse aktualisiert
	stmia r1!, {r2-r9}		// store multiple: speicher 8 worte von r2-r9. Startpunkt r1; r1 wird mit letzter adresse aktualisiert
	ldmia r0!, {r2-r9}		// load multiple: läd 8 worte in r2-r9. Startpunkt r0; r0 wird mit letzter adresse aktualisiert
	stmia r1!, {r2-r9}		// store multiple: speicher 8 worte von r2-r9. Startpunkt r1; r1 wird mit letzter adresse aktualisiert

/*---------------------------------------------------------------------------*/
/********************* Aufgabe c: Produktmatrix S = M * N ********************/
/*---------------------------------------------------------------------------*/
// Matrix M der Reihe nach im Datenbereich gespeichert
// Matrix N der Spalte nach im Datenbereich gespeichert
// Produktmatrix S = M * N
// Eingabe: Signed 16 bit Zahlen
// Ausgabe: Signed 32 bit Zahl
/*---------------------------------------------------------------------------*/
	
	ldr r0, =strProduktSumme	// Terminalausgabe
	bl uart_putString
	mov r0, #0				// muss 0 sein, da Ergebnis in Berechnung einfließt
	
	ldr r10, =M_R1			// Startadresse Matrix M
	ldr r11, =N_S1			// Startadresse Matrix N
	mov r8, #COUNTER_8		// Schleifenzaehler für Produktsumme der 4*4 Matrix
	
loop_sum:
	ldr r4, [r10], #4		// Lade zwei 16 bit Zahlen von M, Adresse++
	ldr r5, [r11], #4 		// Lade zwei 16 bit Zahlen von N, Adresse++
	smlad r0, r4, r5, r0	// r0 = (r4[0..15] x r5[0..15]) + (r4[16..31] x r5[16..31]) + r0
	subs r8, r8, #1			// 8 mal druchlaufen? => nein, dann springe zurück
	bne loop_sum
	bl uart_putInt32		// Terminalausgabe

/*---------------------------------------------------------------------------*/
/******************* Aufgabe d: Verkettung von Operationen *******************/
/*---------------------------------------------------------------------------*/
// UADD16: Addition 2er unsigned 16-bit Zahlen ohne Sättigung
// Befehl ändert nicht die Flags
//
// Interpretation der Zahlen in unsigned16 - Wertebereich: 0..65535
// A1 = 42038	A2 = 31867
// B1 =  4426	B2 = 35123
// C1 = 50515	C2 = 24364
// D1 = 30862	D2 = 33969
//
// A,B = B4DD _ (1)05AE 
// 0xB4DD = 46301u
// 0x05AE = 1454u -> Overflow Bit 16 wird abgeschnitten
// A,C = (1)6989 _ DBA7 
// 0x6989 = 27017u -> Overflow, Bit 32 wird abgeschnitten
// 0xDBA7 = 56231u
// A,D = (1)1CC4 _ (1)012C
// 0x1CC4 = 7364u -> Overflow Bit 32 wird abgeschnitten
// 0x012C = 300u -> Overflow Bit 16 wird abgeschnitten
/*---------------------------------------------------------------------------*/

	ldr r0, =strUADD16		// Terminalausgabe
	bl uart_putString
	ldr r4, =opA
	ldmia r4, {r4-r7} 		//lade alle Variablen in r4-r7

	uadd16 r0, r4, r5		// 2 * 16-bit unsigned Addition
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	uadd16 r0, r4, r6		// 2 * 16-bit unsigned Addition 
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	uadd16 r0, r4, r7		// 2 * 16-bit unsigned Addition
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
		
/*---------------------------------------------------------------------------*/
// SADD16: Addition 2er signed 16-bit Zahlen ohne Sättigung
// Befehl ändert nicht die Flags
// 
// Interpretation der Zahlen in signed16 - Wertebereich: -32768..32767
// A1 = -23498	A2 = 31867
// B1 =  4426	B2 = -30413
// C1 = -15021	C2 = 24364
// D1 = 30862	D2 = -31567
// 
// A,B = (FFFF)B4DD _ 05AE
// 0xB4DD = -19235s (Signed (FFFF) bei B4DD abgeschnitten)
// 0x05AE = 1454s
// A,C = (FFFF)6989 _ DBA7
// 0x6989 = -38519s -> Underflow (Signed (FFFF) bei 6989 abgeschnitten)
// 0xDBA7 = 56231s -> Overflow
// A,D = 1CC4 _ 012C
// 0x1CC4 = 7364s
// 0x012C = 300s
/*---------------------------------------------------------------------------*/
	
	ldr r0, =strSADD16		// Terminalausgabe
	bl uart_putString
	
	sadd16 r0, r4, r5		// 2 * 16-bit signed Addition
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	sadd16 r0, r4, r6		// 2 * 16-bit signed Addition
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	sadd16 r0, r4, r7		// 2 * 16-bit signed Addition
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar

/*---------------------------------------------------------------------------*/
// UQADD16: Addition 2er unsigned 16-bit Zahlen mit Sättigung
//
// Interpretation der Zahlen in unsigned16 - Wertebereich: 0..65535
// A1 = 42038	A2 = 31867
// B1 =  4426	B2 = 35123
// C1 = 50515	C2 = 24364
// D1 = 30862	D2 = 33969
//
// A,B = B4DD _ FFFF 
// 0xB4DD = 46301u
// 0xFFFF = 65535u -> Overflow mit Sättigung: max. Wert wird ausgegeben
// A,C = FFFF _ DBA7 
// 0xFFFF = 65535u -> Overflow mit Sättigung: max. Wert wird ausgegeben
// 0xDBA7 = 56231u
// A,D = FFFF _ FFFF
// 0xFFFF = 65535u -> Overflow mit Sättigung: max. Wert wird ausgegeben
// 0xFFFF = 65535u -> Overflow mit Sättigung: max. Wert wird ausgegeben
// 
// Overflow mit Sättigung: 
// Die Addition der Zahlen hat der Wertebereich von 65535 überschritten.
// Das Ergebnis wird mit dem maximal Wert 0xFFFF ausgegeben - im Gegenesatz
// zur Addition ohne Sättigung. In diesem Fall überläuft das Register und 
// beginnt wieder bei 0 und setzt das Overflow-Flag.
/*---------------------------------------------------------------------------*/
	
	ldr r0, =strUQADD16		// Terminalausgabe
	bl uart_putString
	
	uqadd16 r0, r4, r5		// 2 * 16-bit unsigned Addition mit Sättigung
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	uqadd16 r0, r4, r6		// 2 * 16-bit unsigned Addition mit Sättigung
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	uqadd16 r0, r4, r7		// 2 * 16-bit unsigned Addition mit Sättigung
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar

/*---------------------------------------------------------------------------*/
// QADD16: Addition 2er signed 16-bit Zahlen mit Sättigung
//
// Interpretation der Zahlen in signed16 Wertebereich: -32768..32767
// A1 = -23498	A2 = 31867
// B1 =  4426	B2 = -30413
// C1 = -15021	C2 = 24364
// D1 = 30862	D2 = -31567
// 
// A,B = B4DD _ 05AE
// 0xB4DD = -19235s
// 0x05AE = 1454s
// A,C = 8000 _ 7FFF
// 0x8000 = -32768s -> Underflow mit Sättigung: max. Wert wird ausgegeben
// 0x7FFF = 32767s -> Overflow mit Sättigung: max. Wert wird ausgegeben
// A,D = 1CC4 _ 012C
// 0x1CC4 = 7364s
// 0x012C = 300s
// 
// Overflow/Underflow mit Sättigung: 
// Die Addition der Zahlen hat der Wertebereich von -32768 oder +32767 überschritten.
// Das Ergebnis wird mit dem min. Wert 0x8000 oder max. Wert 0x7FFF ausgegeben.
/*---------------------------------------------------------------------------*/
	
	ldr r0, =strQADD16		// Terminalausgabe
	bl uart_putString
	
	qadd16 r0, r4, r5		// 2 * 16-bit signed Addition mit Sättigung
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	qadd16 r0, r4, r6		// 2 * 16-bit signed Addition mit Sättigung
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	qadd16 r0, r4, r7		// 2 * 16-bit signed Addition mit Sättigung
	bl uart_putInt32		// Terminalausgabe

/*---------------------------------------------------------------------------*/
/********************** Aufgabe e: Sättigung auf 13-bit **********************/
/*---------------------------------------------------------------------------*/
// Wert A: 0xA436_7C7B
// Wert B: 0x10A7_8933
//
// Interpretation der Zahlen in unsigned 16-bit - Wertebereich: 0..65535
// A1 = 42038	A2 = 31867
// B1 =  4263	B2 = 35123
// Interpretation der Zahlen in signed 16-bit - Wertebereich: -32768..32767
// A1 = -23498	A2 = 31867
// B1 =  4263	B2 = -30413

// Sättigung der Werte auf unsigned 13-bit - Wertebereich: 0..8191 (0..2^13)
// A1 = 42038(-23498) 	A2 = 31867
// B1 =  4263			B2 = 35123(-30413)
// A1, B2 -> Wenn das Ergebnis der Sättigung negativ sein würde, dann wird 0x0 zurückgegeben
// Dies trifft hier zu, da das MSBit == #1 enthält.
// A2 -> Overflow mit Sättigung Ausgabe max. Wert 0x1FFF
// B1 positiv und im Wertebereich, keine Sättigung
//
// Sättigung der Werte auf signed 13-bit - Wertebereich: -4096..4095 (-2^12..2^12 -1)
// A1 = -23498	A2 = 31867
// B1 =  4263	B2 = -30413
// A1, B2 -> Underflow mit Sättigung Ausgabe min. Wert 0x1000
// Aufgrund der Ausgabe von 16-bit werden die obersten Bits mit 1 aufgefüllt. Ausgabe 0xF000
// A2, B1 -> Overflow mit Sättigung Ausgabe max. Wert 0x0FFF
/*---------------------------------------------------------------------------*/

	/* Operaden A, B identisch aus Aufgabe 1-d und bereits in r4 und r5 geladen */
	
	ldr r0, =strUSAT		// Terminalausgabe
	bl uart_putString
	
	/* USAT Wert A */
	usat16 r0, #SAT, r4		// unsigned Sättigung auf 13-bit
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	/* USAT Wert B */
	usat16 r0, #SAT, r5		// unsigned Sättigung auf 13-bit
	bl uart_putInt32		// Terminalausgabe

	ldr r0, =strSSAT		// Terminalausgabe
	bl uart_putString
	
	/* USAT Wert A */
	ssat16 r0, #SAT, r4		// signed Sättigung auf 13-bit LSB
	bl uart_putInt32		// Terminalausgabe
	mov r0, #SPACE
	bl uart_putChar
	
	/* USAT Wert B */
	ssat16 r0, #SAT, r5		// signed Sättigung auf 13-bit LSB
	bl uart_putInt32		// Terminalausgabe
	

end:
b end

/*** Datenbereich (ab 0x20000000) ***/
.data
M_R1:            		
    .hword 0x5F8C		// M Reihe 1
    .hword 0x7f48
    .hword 0x8245
    .hword 0x6048
    .hword 0xc799		// M Reihe 2
    .hword 0x9c5d
    .hword 0xd49c
    .hword 0x33d8
    .hword 0x579b		// M Reihe 3
    .hword 0x8aef
    .hword 0xf2c0
    .hword 0xa3c2
    .hword 0x41fd		// M Reihe 4
    .hword 0x50d4
    .hword 0x25c6
    .hword 0x4afa
N_S1:            
    .hword 0x7f41		// N Spalte 1
    .hword 0x0645
    .hword 0x8c8f
    .hword 0x9065
    .hword 0x78e3		// N Spalte 2
    .hword 0xf7f3
    .hword 0xd29f
    .hword 0x2961
    .hword 0x5a1e		// N Spalte 3
    .hword 0xdfed
    .hword 0x4b9f
    .hword 0x1092
    .hword 0x61bf		// N Spalte 4
    .hword 0x21be
    .hword 0x5ca1
    .hword 0xc6d3
O_R1:					// Ergebnis O in Reihe
	.rept COUNTER_16
	.word 0x0
	.endr
Ocopy_R1:				// O Kopie in Reihe
	.rept COUNTER_16
	.word 0x0
	.endr
opA: .word 	0xA4367C7B
opB: .word 	0x10A78933
opC: .word 	0xC5535F2C
opD: .word 	0x788E84B1
maxValHW: .hword 0xFFFF
strErgebnis: .asciz "\nErgebnismatrix O:\n"
strCopy: .asciz "\nKopieren der Matrix O!\n"
strProduktSumme: .asciz "\nProdukt-Summe: "
strUADD16: .asciz "\n\nUADD16:   "
strSADD16: .asciz "\nSADD16:   "
strUQADD16: .asciz "\nUQADD16: "
strQADD16: .asciz "\nQADD16:   "
strUSAT: .asciz "\n\nUSAT: "
strSSAT: .asciz "\nSSAT: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ CHECK_99, 0x63
.equ CHECK_59, 0x3B
.equ CHECK_30, 0x1E
.equ CHECK_23, 0x17
.equ CHECK_12, 0x0C
.equ ZERO, 0x0

.equ START_STOP, 0x73	// ASCII 's'
.equ TIME, 0x74			// ASCII 't'
.equ DATE, 0x64			// ASCII 'd'

.equ LF, 0x0A			// ASCII LineFeed
.equ SPACE, 0x20		// ASCII Leerzeichen
.equ PUNKT, 0x2E		// ASCII Punkt
.equ DOPPELPUNKT, 0x3A	// ASCII Doppelpunkt

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*---------------------------------------------------------------------------*/
/************************* Aufgabe c: Hauptprogramm **************************/
/*---------------------------------------------------------------------------*/
// Das Programm startet mit der delay Funktion.
// Anschließend wird gepürft ob ein gültiges Zeichen vom Terminal eingegeben
// wurde. Bei ungültigem Zeichen fährt die Berechnung fort. 
// Am Ende wird der aktuelle Zeitwert ausgegeben.
//
// Eingabeparameter: 's' (start/stop), 't' (set time), 'd' (set date)
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
main:	
	bl uart_init
	
	ldr r8, =b_Tag			// Lade Register mit Datum/Zeit
	ldr r9, =b_Monat
	ldr r10, =b_Jahr1
	ldr r11, =b_Stunde
	ldr r12, =b_Min
	mov r4, #0				// Merker Start/Stopp gesetzt: 0 = Start, 1 = Stopp
	ldrb r5, [r12]			// r5 mit Minuten vorladen
	

main_loop:
	bl print_datum			// Uhrzeitausgabe
	
	bl delay				// Verzögerung von ca. 1s
	
	bl uart_charPresent		// Zeichen vom Terminal vorhanden? dann r0 != 0
	cmp r0, #0					
	beq tick_tack			// Kein Zeichen => fahre mit tick_tack fort
	bl uart_getChar			// Zeichen da => hole vom Terminal

/*----------- Werte Zeichen vom Terminal aus, nur wenn vorhanden ------------*/
	cmp r0, #START_STOP
	bne eingabe_time			// Wenn r0 != #START_STOP => springe zum nächsten Zeichen
	
	eor r4, r4, #1				// setzte Start/Stopp: XOR 0^1 = 1; 1^1 = 0
	b tick_tack					// Zeichen wurde verarbeitet, springe zu tick_tack
	
eingabe_time:	
	cmp r0, #TIME
	bne eingabe_date			// Wenn r0 != #TIME => springe zum nächsten Zeichen
	
	ldr r0, =str_Eingabe_Stunde	// Terminalausgabe Stunden
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Stunde
	strb r0, [r11]				// Abspeichern in .data
	bl uart_putByteBase10
	
	ldr r0, =str_Eingabe_Min	// Terminalausgabe Minuten
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Minuten
	strb r0, [r12]				// Abspeichern in .data
	mov r5, r0					// r5 mit Minuten aktualisieren, wichtig für tick_tack 
	bl uart_putByteBase10
	
	mov r0, #LF					// Terminalausgabe-Format
	bl uart_putChar
	b main_loop					// Rücksprung zur main_loop
	
eingabe_date:
	cmp r0, #DATE
	bne tick_tack				// Wenn r0 != DATE => Char-Eingabe ungültig, fahre fort
	
	ldr r0, =str_Eingabe_Tag	// Terminalausgabe Tag
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Tag
	strb r0, [r8]				// Abspeichern in .data
	bl uart_putByteBase10
	
	ldr r0, =str_Eingabe_Monat	// Terminalausgabe Monat
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Monat
	strb r0, [r9]				// Abspeichern in .data
	bl uart_putByteBase10
	
	ldr r0, =str_Eingabe_Jahr	// Terminalausgabe Jahr
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Jahr
	strb r0, [r10]				// Abspeichern in .data
	bl uart_putByteBase10
	
	mov r0, #LF					// Terminalausgabe-Format
	bl uart_putChar
	b main_loop					// Rücksprung zur main_loop
	
/*----------------------- Uhrzeit inkrementieren ----------------------------*/
tick_tack:
	cmp r4, #0				// Stopp-Bit nicht gesetzt => fahre fort
	bne main_loop			// Stopp-Bit gesetzt? springe zur main_loop

/*------------------------ Schalte Minuten weiter ---------------------------*/
	teq r5, #CHECK_59		// Update conditions flags für Minuten
	itte eq					
	moveq r5, #ZERO			// 59s erreicht, setzte auf 0 zurück
	moveq r0, #1			// Flag für Stunden aktualisieren
	addne r5, r5, #1		// sonst inkrementiere Minuten um 1
	
	strb r5, [r12]			// Minuten aktualisieren im .data
	
	cmp r0, #1				// Stunden aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*----------------------- Schalte Stunden weiter ----------------------------*/
	ldrb r6, [r11]			// Lade Stunden
	mov r0, #0				// Setze Flag zurück
	teq r6, #CHECK_23		// Update conditions flags
	itte eq					
	moveq r6, #ZERO			// 24h erreicht, setzte auf 0 zurück
	moveq r0, #1			// Flag für Tag aktualisieren
	addne r6, r6, #1		
	
	strb r6, [r11]			// Stunden aktualisieren
	cmp r0, #1				// Tag aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*------------------------- Schalte Tag weiter ------------------------------*/
	ldrb r6, [r8]			// Lade Tag
	mov r0, #0
	teq r6, #CHECK_30		// Update conditions flags
	itte eq					
	moveq r6, #1			// 30d erreicht, setzte auf 1 zurück
	moveq r0, #1			// Flag für Monat aktualisieren
	addne r6, r6, #1		
	
	strb r6, [r8]			// Tag aktualisieren
	cmp r0, #1				// Monat aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*------------------------- Schalte Monat weiter ------------------------------*/
	ldrb r6, [r9]			// Lade Monat
	mov r0, #0
	teq r6, #CHECK_12		// Update conditions flags
	itte eq					
	moveq r6, #1			// 12m erreicht, setzte auf 1 zurück
	moveq r0, #1			// Flag für Jahr aktualisieren
	addne r6, r6, #1		
	
	strb r6, [r9]			// Monat aktualisieren
	cmp r0, #1				// Jahr aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*------------------------- Schalte Jahr weiter ------------------------------*/
	ldrb r6, [r10]			// Lade Jahr
	teq r6, #CHECK_99		// Update conditions flags
	ite eq					
	moveq r6, #ZERO			// 99j erreicht, setzte auf 0 zurück
	addne r6, r6, #1		
	
	strb r6, [r10]			// Stunden aktualisieren

	b main_loop


/*---------------------------------------------------------------------------*/
/************************ Aufgabe a: Funktion "delay" ************************/
/*---------------------------------------------------------------------------*/
// Die Funktion erzeugt eine Zeitverzögerung von ~1 Sekunde über eine Schleife.
// Clock: 25MHz == 25.000.000 Takte je Sekunde
// Anzahl zyklischer Takte von subs, bne: 2 Zyklen ~ 12.500.000
// Der Vergleich mit einer Uhr zeigte, dass der Wert von ca. 8.250.000 besser geeignet ist.
// Entspricht eher 3 Zkylen.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
delay:
	push {lr}
	ldr r0, =ticks
	ldr r0, [r0]
loop:
	subs r0, r0, #1
	bne loop
	pop {pc}


/*---------------------------------------------------------------------------*/
/********************* Aufgabe b: Funktion "print_datum" *********************/
/*---------------------------------------------------------------------------*/
// Funktion gibt das aktuelle Datum aus dem .data Bereich aus.
// Ausgabeformat auf dem Terminal: dd.mm.jjjj  hh:mm Uhr
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
print_datum:
	push {r4, lr}
	ldr r4, =b_Tag
	ldrb r0,[r4], #1			// Terminalausgabe Tag
	bl uart_putByteBase10
	mov r0, #PUNKT				// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4], #1			// Terminalausgabe Monat
	bl uart_putByteBase10
	mov r0, #PUNKT				// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4], #1			// Terminalausgabe Jahr
	bl uart_putByteBase10
	
	ldrb r0,[r4]				// Lade Wert von Jahr_1
	cmp r0, #10					// Wenn Jahr kleiner 10, dann wird nur eine einstellige Zahl ausgegeben ohne führende 0
	bmi doppel					// Falls kleiner 10, gebe die '0' zusätzlich aus
	bpl einfach					// Sonst einfache Ausgabe
doppel:
	mov r0, #0					// 0 muss zuerst ausgegeben werden
	bl uart_putByteBase10
einfach:
	ldrb r0,[r4], #1			// Terminalausgabe Jahr
	bl uart_putByteBase10
	
	mov r0, SPACE				// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4], #1			// Terminalausgabe Stunde
	bl uart_putByteBase10
	mov r0, DOPPELPUNKT			// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4]				// Terminalausgabe Minute
	bl uart_putByteBase10
	ldr r0, =str_Uhr			// Terminalausgabe-Format
	bl uart_putString
	
	pop {r4, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
ticks: .word 0x7DE290		// Zaehlerwert für 1 Sekudne delay Funktion
b_Tag: .byte 0x01
b_Monat: .byte 0x01
b_Jahr0: .byte 0x14
b_Jahr1: .byte 0x0E
b_Stunde: .byte 0x0
b_Min: .byte 0x0
str_Uhr: .asciz " Uhr\n"
str_Eingabe_Stunde: .asciz "\nStunde eingeben (hh): "
str_Eingabe_Min: .asciz "\nMinuten eingeben (mm): "
str_Eingabe_Tag: .asciz "\nTag eingeben (dd): "
str_Eingabe_Monat: .asciz "\nMonat eingeben (mm): "
str_Eingabe_Jahr: .asciz "\nJahr eingeben (jj): "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ CHECK_99, 0x63
.equ CHECK_59, 0x3B
.equ CHECK_30, 0x1E
.equ CHECK_23, 0x17
.equ CHECK_12, 0x0C
.equ ZERO, 0x0

.equ START_STOP, 0x73	// ASCII 's'
.equ TIME, 0x74			// ASCII 't'
.equ DATE, 0x64			// ASCII 'd'
.equ LF, 0x0A			// ASCII LineFeed
.equ SPACE, 0x20		// ASCII Leerzeichen
.equ PUNKT, 0x2E		// ASCII Punkt
.equ DOPPELPUNKT, 0x3A	// ASCII Doppelpunkt

/* Bit Banding für den PIT-1 */
.equ SIM_SCGC6_PIT, (0x4004803C - 0x40000000) << 5 + 0x42000000 + 23 << 2
.equ PIT_MCR_MDIS, (0x40037000 - 0x40000000) << 5 + 0x42000000 + 1 << 2
.equ PIT_MCR_FRZ, (0x40037000 - 0x40000000) << 5 + 0x42000000 + 0 << 2
.equ PIT_TCTRL1_TEN, (0x40037118 - 0x40000000) << 5 + 0x42000000 + 0 << 2
.equ PIT_TCTRL1_TIE, (0x40037118 - 0x40000000) << 5 + 0x42000000 + 1 << 2
.equ PIT_TFLG1, (0x4003711C - 0x40000000) << 5 + 0x42000000 + 0 << 2
.equ PIT_LDVAL1, 0x40037110

/* NVIC-Startadressen für den PIT-1 */
.equ NVIC_ISER2, 0xE000E108		// Interrupt Set-Enable Registers
.equ NVIC_ICER2, 0xE000E188		// Interrupt Clear-Enable Registers

.equ NVIC_ISPR2, 0xE000E208		// Interrupt Set-Pending Registers
.equ NVIC_ICPR2, 0xE000E288		// Interrupt Clear-Pending Registers

.equ NVIC_IABR2, 0xE000E308		// Interrupt Active Bit Register

.equ OFFSET_PIT1_IRQ69, 0x154								// PIT1 = IRQ69
.equ IVT_ADRESSE_PIT1, (0x1FFFFE00 + OFFSET_PIT1_IRQ69)		// IVT-Basisadresse +  Offset


/*---------------------------------------------------------------------------*/
/******************* Aufgabe a: Interrupt Service Routine ********************/
/*---------------------------------------------------------------------------*/
// Das Programm soll anstatt der delay Funktion aus Aufgabe 2-2 um eine
// ISR ersetzt werden.
// PIT-1 triggert jede Sekunde einen Interrupt. Der NVIC ermittelt aus der 
// Interruptnummer die Startadresse in der Interrupt-Vector-Tabelle (IVT).
// PIT-1 liegt auf Index 69 der IVT. In diesem Index wird die Adresse der
// Funktion "ISR_1s" eingetragen.
// Bei einem Interrupt sichert der uC automatisch die Register r0-r3, r12, 
// lr (r13), pc (r14) und APSR. Der SP zeigt auf den MSP-Bereich.
// Während der ISR zeigt das lr auf 0xFFFF FFF9 -> Thread-Mode und MSP.
// Die Routine wird mit bx lr verlassen.
//
// Eingabeparameter: 's' (start/stop), 't' (set time), 'd' (set date)
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/

main:	
	/* Initialisierung UART, PIT, NVIC und SIM */
	bl uart_init
	mov r10, #0				// setze r10 auf 0
	mov r11, #1				// setze r11 auf 1
	
	
	ldr r0, =SIM_SCGC6_PIT	// a: PIT clock enable, System Clock Gating Control Register 6 (SIM_SCGC6)
	str	r11, [r0]

	ldr r0, =ISR_1s			// b: setze ISR Adresse in die VectorInterruptTabelle[PIT1]; IRQ-69
	ldr r1, =IVT_ADRESSE_PIT1
	str r0,[r1]

	/* IRQ's bitfield location: IRQ-69 mod 32 = 5 */
	ldr r0, =NVIC_ICPR2		// c: setze Interrupt Clear-Pending Register
	ldr r1, [r0]
	lsl r2, r11, #5			// Setze Bit-5; 1 on writes, clears the pending state of the interrupt
	orr r1, r1, r2
	str r1, [r0]

	ldr r0, =NVIC_ISER2		// d: setze Interrupt Set Enable Register
	ldr r1, [r0]
	lsl r2, r11, #5			// Setze Bit-5; 1 on writes, enable interrupt
	orr r1, r1, r2
	str r1, [r0]
	
	ldr r0, =PIT_MCR_FRZ	// e: setze PIT Freeze, Enable Debug Mode
	str r11, [r0]
	
	/* PIT-1 LDVAL trigger = (period / clock period) -1  ||  (1s/25Mhz) -1  = 24.999.999d = 0x17D783F */
	ldr r0, =PIT_LDVAL1		// f: setze Startwert für 1 Sekunde, PIT1 Timer Load Value Register
	ldr r1, =bus_clock_1s
	ldr r1, [r1]
	str r1, [r0]
	
	ldr r0, =PIT_TCTRL1_TIE		// g: Timer Interrupt Enable, PIT1 Timer Control Register (PIT_TCTRL1)
	str r11, [r0]
	
	ldr r0, =PIT_MCR_MDIS		// g: 0 = Clock for PIT1 timers is enabled (ModulesDisabled), PIT Module Control Register (PIT_MCR)
	str r10, [r0]
	
	ldr r0, =PIT_TCTRL1_TEN		// h: Timer Enable, PIT1 Timer Control Register (PIT_TCTRL1)
	str r11, [r0]
	
	/* Initialisierung aus V2-2 */
	ldr r8, =b_Tag				// Lade Register mit Datum/Zeit
	ldr r9, =b_Monat
	ldr r10, =b_Jahr1
	ldr r11, =b_Stunde
	ldr r12, =b_Min
	mov r4, #0					// Merker Start/Stopp gesetzt: 0 = Start, 1 = Stopp
	ldr r7, =w_ISR_triggered	// Merker auf .data, welches bei der ISR gesetzt wird
	ldrb r5, [r12]				// r5 mit Minuten vorladen
	

main_loop:
	ldr r0, [r7]			// Polle Benutzerflag von ISR
	cmp r0, #0				// solange ISR nicht ausgeführt, polle weiter
	beq main_loop
	
	mov r0, #0
	str r0, [r7]			// Flag von ISR zurücksetzen
	
	bl print_datum			// Uhrzeitausgabe
	
	bl uart_charPresent		// Zeichen vom Terminal vorhanden? dann r0 != 0
	cmp r0, #0					
	beq tick_tack			// Kein Zeichen => fahre mit tick_tack fort
	bl uart_getChar			// Zeichen da => hole vom Terminal

/*----------- Werte Zeichen vom Terminal aus, nur wenn vorhanden ------------*/
	cmp r0, #START_STOP
	bne eingabe_time			// Wenn r0 != #START_STOP => springe zum nächsten Zeichen
	
	eor r4, r4, #1				// setzte Start/Stopp: XOR 0^1 = 1; 1^1 = 0
	b tick_tack					// Zeichen wurde verarbeitet, springe zu tick_tack
	
eingabe_time:	
	cmp r0, #TIME
	bne eingabe_date			// Wenn r0 != #TIME => springe zum nächsten Zeichen
	
	ldr r0, =str_Eingabe_Stunde	// Terminalausgabe Stunden
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Stunde
	strb r0, [r11]				// Abspeichern in .data
	bl uart_putByteBase10
	
	ldr r0, =str_Eingabe_Min	// Terminalausgabe Minuten
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Minuten
	strb r0, [r12]				// Abspeichern in .data
	mov r5, r0					// r5 mit Minuten aktualisieren, wichtig für tick_tack 
	bl uart_putByteBase10
	
	mov r0, #LF					// Terminalausgabe-Format
	bl uart_putChar
	b main_loop					// Rücksprung zur main_loop
	
eingabe_date:
	cmp r0, #DATE
	bne tick_tack				// Wenn r0 != DATE => Char-Eingabe ungültig, fahre fort
	
	ldr r0, =str_Eingabe_Tag	// Terminalausgabe Tag
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Tag
	strb r0, [r8]				// Abspeichern in .data
	bl uart_putByteBase10
	
	ldr r0, =str_Eingabe_Monat	// Terminalausgabe Monat
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Monat
	strb r0, [r9]				// Abspeichern in .data
	bl uart_putByteBase10
	
	ldr r0, =str_Eingabe_Jahr	// Terminalausgabe Jahr
	bl uart_putString
	bl uart_getByteBase10		// Einlesen Jahr
	strb r0, [r10]				// Abspeichern in .data
	bl uart_putByteBase10
	
	mov r0, #LF					// Terminalausgabe-Format
	bl uart_putChar
	b main_loop					// Rücksprung zur main_loop
	
/*----------------------- Uhrzeit inkrementieren ----------------------------*/
tick_tack:
	cmp r4, #0				// Stopp-Bit nicht gesetzt => fahre fort
	bne main_loop			// Stopp-Bit gesetzt? springe zur main_loop

/*------------------------ Schalte Minuten weiter ---------------------------*/
	teq r5, #CHECK_59		// Update conditions flags für Minuten
	itte eq					
	moveq r5, #ZERO			// 59s erreicht, setzte auf 0 zurück
	moveq r0, #1			// Flag für Stunden aktualisieren
	addne r5, r5, #1		// sonst inkrementiere Minuten um 1
	
	strb r5, [r12]			// Minuten aktualisieren im .data
	
	cmp r0, #1				// Stunden aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*----------------------- Schalte Stunden weiter ----------------------------*/
	ldrb r6, [r11]			// Lade Stunden
	mov r0, #0				// Setze Flag zurück
	teq r6, #CHECK_23		// Update conditions flags
	itte eq					
	moveq r6, #ZERO			// 24h erreicht, setzte auf 0 zurück
	moveq r0, #1			// Flag für Tag aktualisieren
	addne r6, r6, #1		
	
	strb r6, [r11]			// Stunden aktualisieren
	cmp r0, #1				// Tag aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*------------------------- Schalte Tag weiter ------------------------------*/
	ldrb r6, [r8]			// Lade Tag
	mov r0, #0
	teq r6, #CHECK_30		// Update conditions flags
	itte eq					
	moveq r6, #1			// 30d erreicht, setzte auf 1 zurück
	moveq r0, #1			// Flag für Monat aktualisieren
	addne r6, r6, #1		
	
	strb r6, [r8]			// Tag aktualisieren im .data
	cmp r0, #1				// Monat aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*------------------------- Schalte Monat weiter ------------------------------*/
	ldrb r6, [r9]			// Lade Monat
	mov r0, #0
	teq r6, #CHECK_12		// Update conditions flags
	itte eq					
	moveq r6, #1			// 12m erreicht, setzte auf 1 zurück
	moveq r0, #1			// Flag für Jahr aktualisieren
	addne r6, r6, #1		
	
	strb r6, [r9]			// Monat aktualisieren im .data
	cmp r0, #1				// Jahr aktualisieren?
	bne main_loop			// wenn nein, dann springe zur main_loop

/*------------------------- Schalte Jahr weiter ------------------------------*/
	ldrb r6, [r10]			// Lade Jahr
	teq r6, #CHECK_99		// Update conditions flags
	ite eq					
	moveq r6, #ZERO			// 99j erreicht, setzte auf 0 zurück
	addne r6, r6, #1		
	
	strb r6, [r10]			// Stunden aktualisieren im .data
	
	b main_loop


/*---------------------------------------------------------------------------*/
/********************** Aufgabe: Funktion "print_datum" **********************/
/*---------------------------------------------------------------------------*/
// Funktion gibt das aktuelle Datum aus dem .data Bereich aus.
// Ausgabeformat auf dem Terminal: dd.mm.jjjj  hh:mm Uhr
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
print_datum:
	push {r4, lr}
	ldr r4, =b_Tag
	ldrb r0,[r4], #1			// Terminalausgabe Tag
	bl uart_putByteBase10
	mov r0, #PUNKT				// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4], #1			// Terminalausgabe Monat
	bl uart_putByteBase10
	mov r0, #PUNKT				// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4], #1			// Terminalausgabe Jahr
	bl uart_putByteBase10
	
	ldrb r0,[r4]				// Lade Wert von Jahr_1
	cmp r0, #10					// Wenn Jahr kleiner 10, dann wird nur eine einstellige Zahl ausgegeben ohne führende 0
	bmi doppel					// Falls kleiner 10, gebe die '0' zusätzlich aus
	bpl einfach					// Sonst einfache Ausgabe
doppel:
	mov r0, #0					// 0 muss zuerst ausgegeben werden
	bl uart_putByteBase10
einfach:
	ldrb r0,[r4], #1			// Terminalausgabe Jahr
	bl uart_putByteBase10
	
	mov r0, SPACE				// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4], #1			// Terminalausgabe Stunde
	bl uart_putByteBase10
	mov r0, DOPPELPUNKT			// Terminalausgabe-Format
	bl uart_putChar
	ldrb r0,[r4]				// Terminalausgabe Minute
	bl uart_putByteBase10
	ldr r0, =str_Uhr			// Terminalausgabe-Format
	bl uart_putString
	
	pop {r4, pc}

/*---------------------------------------------------------------------------*/
/*************** Aufgabe a: Interrupt Service Routine "ISR_1s" ***************/
/*---------------------------------------------------------------------------*/
// Wird zyklisch jede 1 Sekunde von PIT-1 aufgerufen.
// Interrupt setzt Interrupt Flag von PIT-1 zurück.
// Setzt Benutzer-Flag w_ISR_triggered im .data auf 1.
/*---------------------------------------------------------------------------*/
.thumb_func
ISR_1s:
	mov r1, #1
	ldr r0, =PIT_TFLG1			// ClearOnWrite: PIT Timer Interrupt Flag Register
	str r1, [r0]
	ldr r0, =w_ISR_triggered	// Datenaustausch zwischen ISR und App -> setze Flag
	strb r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
bus_clock_1s: .word 0x17D783F	// Zaehlerwert für 1 Sekunde und 25Mhz
w_ISR_triggered: .word 0x0
b_Tag: .byte 0x01
b_Monat: .byte 0x01
b_Jahr0: .byte 0x14
b_Jahr1: .byte 0x0E
b_Stunde: .byte 0x0
b_Min: .byte 0x0
str_Uhr: .asciz " Uhr\n"
str_Eingabe_Stunde: .asciz "\nStunde eingeben (hh): "
str_Eingabe_Min: .asciz "\nMinuten eingeben (mm): "
str_Eingabe_Tag: .asciz "\nTag eingeben (dd): "
str_Eingabe_Monat: .asciz "\nMonat eingeben (mm): "
str_Eingabe_Jahr: .asciz "\nJahr eingeben (jj): "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/* Generelle Konfig */
.equ LF, 0x0A			// ASCII LineFeed
.equ COUNTER_4, 0x4

/* Register und Konfiguration CRC */
.equ REG_CRC_CRC, 0x40032000
.equ REG_CRC_GPOLY, 0x40032004
.equ REG_CRC_CTRL, 0x40032008

.equ CRC_TCRC, 0x1000000		// set TCRC=1 (32-bit CRC)
.equ CRC_TCRC_WAS, 0x3000000	// set TCRC=1, set WAS=1 (WriteAsSeed)
.equ CRC_POLYNOM, 0x4C11DB7		// c32 implizit 1
.equ CRC_SEED, 0x12345678		// Startwert (Seed)

/* Bit Banding für den SIM */
__BBREG SIM_SCGC6_CRC, 0x4004803C, 18

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

/*---------------------- CRC-Modul Initialisierung --------------------------*/
	mov r1, #1
	ldr r0, =SIM_SCGC6_CRC	// CRC clock enable
	str	r1, [r0]
	
	ldr r10, =REG_CRC_CTRL	// setze CRC TCRC = 1
	ldr r0, =CRC_TCRC
	str r0, [r10]
	
	ldr r11, =REG_CRC_GPOLY	// setze CRC Polynom 0x4C11DB7
	ldr r1, =CRC_POLYNOM
	str r1, [r11]
	
	ldr r1, =CRC_TCRC_WAS	// Initialisierung für Seed: WAS=1 
	str r1, [r10]
	
	ldr r12, =REG_CRC_CRC	// setze Seed auf 0x12345678
	ldr r1, =CRC_SEED
	str r1, [r12]
	
	str r0, [r10]			// setze WAS=0 => Daten können geschrieben werden
	
	ldr r4, =str_crc
	mov r5, #0
	mov r9, #COUNTER_4
	
get_data:					// hole Daten für CRC; Abbruchbedingung: end_of_str oder 4 byte
	ldrb r2, [r4], #1
	
	cmp r2, #0				// end of string? asciZ = zero terminated
	itt eq
	streq r5, [r12]			// schreibe Daten ins CRC register
	beq crc_end				// Beende Berechnung
				
	lsl r5, r5, #8			// shifte daten in r5
	orr r5, r5, r2
	subs r9, r9 , #1		// dekrementiere 4 byte counter
	
	cmp r9, #0				// 4 mal geshiften?
	ittt eq
	streq r5, [r12]			// Daten ins CRC register
	moveq r9, #COUNTER_4
	moveq r5, #0			// Daten zurücksetzen
	
	b get_data				// hole nächstes byte
	
crc_end:
	ldr r0, =str_out		// Terminalausgabe
	bl uart_putString
	ldr r0, =str_crc		
	bl uart_putString
	mov r0, #LF
	bl uart_putChar
	ldr r0, [r12]			// [r12] enthält CRC-Wert
	bl uart_putInt32
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str_crc: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
str_out: .asciz "\nCRC32 von: "
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/* Generelle Konfig */
.equ MASK_1, 0x1
.equ MASK_2, 0x2
.equ MASK_4, 0x4
.equ MASK_8, 0x8

.equ START_STOP, 0x73	// ASCII 's'
.equ PLUS, 0x2B			// ASCII '+'
.equ MINUS, 0x2D		// ASCII '-'

/* Register und Konfiguration LEDs, Taster */
.equ PORTA_PCR10, 0x40049028	// LED 4
.equ PORTA_PCR11, 0x4004902C	// LED 1
.equ PORTA_PCR19, 0x4004904C	// schwarzer Taster
.equ PORTA_PCR28, 0x40049070	// LED 2
.equ PORTA_PCR29, 0x40049074	// LED 3
.equ PORTE_PCR26, 0x4004D068	// gruener Taster

.equ GPIOA_PDDR, 0x400FF014		// Data Direction
.equ SET_LED_GPO, 0x30000C00	// LEDs -> GP-Out, Rest -> GP-In

.equ SET_PIN_ALT1, 0x100		// Konfig Pin -> GPIO
.equ SET_PIN_IRQ_PULLUP, 0xA0103		// Konfig Pin -> Fallende Flanke, GPIO, Pull enable, pullup

/* Konfigurationen für PIT und SIM */
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
.equ PIT_LDVAL2, 0x40037120
.equ PIT_TCTRL2, 0x40037128

.equ SIM_SCGC5, 0x40048038
.equ SET_CLOCK_PORT_A_E, 0x2200		// Konfig enable Clock Port_A, Port_E

/* Bit Banding für PIT und SIM */
__BBREG SIM_SCGC6_PIT, 0x4004803C, 23
__BBREG PIT_TFLG1_TIF, 0x4003711C, 0
__BBREG PIT_TFLG2_TIF, 0x4003712C, 0
__BBREG PORTA_IFSR_19, 0x400490A0, 19
__BBREG GPIOA_PDIR_19, 0x400FF010, 19
__BBREG PORTE_IFSR_26, 0x4004D0A0, 26
__BBREG GPIOE_PDIR_26, 0x400FF110, 26

/* NVIC-Startadressen */
.equ NVIC_ISER2, 0xE000E108		// Interrupt Set-Enable Registers
.equ NVIC_ICPR2, 0xE000E288		// Interrupt Clear-Pending Registers
.equ PIT_TIMER_1s, 0x17D783F	// Zaehlerwert für 1s
.equ PIT_TIMER_5ms, 0x1E847		// Zaehlerwert für 5ms

/* NVIC-Startadressen für den PIT-1 */
.equ OFFSET_PIT1_IRQ69, 0x154								// PIT1 = IRQ69
.equ IVT_ADRESSE_PIT1, (0x1FFFFE00 + OFFSET_PIT1_IRQ69)		// IVT-Basisadresse +  Offset

/* NVIC-Startadressen für den PIT-2 */
.equ OFFSET_PIT2_IRQ70, 0x158								// PIT2 = IRQ70
.equ IVT_ADRESSE_PIT2, (0x1FFFFE00 + OFFSET_PIT2_IRQ70)		// IVT-Basisadresse +  Offset

/* NVIC-Startadressen für den gruenen Schalter2 */
.equ OFFSET_PORTE_IRQ91, 0x1AC								// PortA = IRQ91
.equ IVT_ADRESSE_PORTE, (0x1FFFFE00 + OFFSET_PORTE_IRQ91)	// IVT-Basisadresse +  Offset


main:	
	bl uart_init
	
/*-------------------- Initialisierung SIM und Ports ------------------------*/
	mov r12, #1				// mit 1 vorladen
	mov r11, #0				// mit 0 vorladen
	
	ldr r0, =SIM_SCGC6_PIT	// PIT clock enable
	str	r12, [r0]
	
	ldr r0, =SIM_SCGC5		// Port Clock Enable
	ldr r1, =SET_CLOCK_PORT_A_E
	str r1, [r0]
	
	ldr r0, =PORTE_PCR26		// gruene Taste IRQ Enable
	ldr r1, =SET_PIN_IRQ_PULLUP
	str r1, [r0]
	
	ldr r0, =PORTA_PCR19	// schwarze Taste IRQ Enable
	str r1, [r0]
	
	ldr r0, =PORTA_PCR11	// LED1 to GPIO
	ldr r10, =SET_PIN_ALT1
	str r10, [r0]
	
	ldr r0, =PORTA_PCR28	// LED2 to GPIO
	str r10, [r0]
		
	ldr r0, =PORTA_PCR29	// LED3 to GPIO
	str r10, [r0]
		
	ldr r0, =PORTA_PCR10	// LED4 to GPIO
	str r10, [r0]
	
	ldr r0, =GPIOA_PDDR		// Port_A GPOut
	ldr r1, =SET_LED_GPO
	str r1, [r0]
	
/*----------------------- Initialisierung NVIC-Pit1 -------------------------*/
	ldr r0, =ISR_1s			
	ldr r1, =IVT_ADRESSE_PIT1	// ISR Adresse in VectorInterruptTabelle[PIT1]; IRQ-69
	str r0,[r1]

	ldr r0, =NVIC_ICPR2		// IRQ's bitfield location: IRQ-69 mod 32 = 5
	lsl r1, r12, #5			// ClearOnWrite pending state of interrupt
	str r1, [r0]

	ldr r0, =NVIC_ISER2
	lsl r1, r12, #5			// Interrupt enable
	str r1, [r0]

/*----------------------- Initialisierung NVIC-Pit2 -------------------------*/
	ldr r0, =ISR_5ms			
	ldr r1, =IVT_ADRESSE_PIT2	// ISR Adresse in VectorInterruptTabelle[PIT2]; IRQ-70
	str r0,[r1]

	ldr r0, =NVIC_ICPR2		// IRQ's bitfield location: IRQ-70 mod 32 = 6
	lsl r1, r12, #6			// ClearOnWrite pending state of interrupt
	str r1, [r0]

	ldr r0, =NVIC_ISER2
	lsl r1, r12, #6			// Interrupt enable
	str r1, [r0]
	
/*----------------------- Initialisierung NVIC-PortE ------------------------*/
	ldr r0, =ISR_SW2		
	ldr r1, =IVT_ADRESSE_PORTE	// ISR Adresse in VectorInterruptTabelle[PortE]; IRQ-91
	str r0,[r1]

	
	ldr r0, =NVIC_ICPR2		// IRQ's bitfield location: IRQ-91 mod 32 = 27
	lsl r1, r12, #27		// ClearOnWrite pending state of interrupt
	str r1, [r0]

	ldr r0, =NVIC_ISER2
	lsl r1, r12, #27		// Interrupt enable
	str r1, [r0]

/*----------------------- Initialisierung PIT-Modul -------------------------*/
	ldr r0, =PIT_MCR			
	str r12, [r0]			// Bit[0]=1 (FRZ - Debug Mode); Bit[1]=0 (MDIS Clock for PIT enabled - ModulesDisabled)

/*------------------ Initialisierung synchron PIT1-Modul --------------------*/
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_TIMER_1s	// (1s/25Mhz) -1  = 24.999.999d = 0x17D783F
	str r1, [r0]
	
	ldr r0, =PIT_TCTRL1
	mov r1, 0x3				// Bit[0]=1 (Timer Enable), Bit[1]=1 (Timer Interrupt Enable), Bit[3]=0 (Chain Mode)
	str r1, [r0]

/*----------------- Initialisierung asynchron PIT2-Modul --------------------*/
	ldr r0, =PIT_LDVAL2
	ldr r1, =PIT_TIMER_5ms	// (5ms/25Mhz) -1  = 124.999d = 0x1E847
	str r1, [r0]


/*-------------------- Initialisierung Hauptprogramm ------------------------*/
	ldr r5, =b_plus_minus		// Merker plus/minus zaehlen: 0 = +, 1 = -
	mov r6, #0					// Merker Zeahlerstand
	ldr r7, =b_ISR_1s			// Merker auf .data, welches bei der ISR_1s gesetzt wird
	ldr r8, =b_ISR_5ms			// Merker auf 5ms timer

	ldr r0, =str_Zaehler		// Terminalausgabe Startwert
	bl uart_putString
	mov r0, r6
	bl uart_putByteBase10

main_loop:

	ldr r0, =PORTA_IFSR_19		// Interrupt schwarze Taste?
	ldr r0, [r0]
	cmp r0, #1
	it eq
	bleq func_taster_schwarz	// starte 5ms debounce Pit-2


/*----------- Werte Zeichen vom Terminal aus, nur wenn vorhanden ------------*/
	bl uart_charPresent		// Zeichen vom Terminal vorhanden? dann r0 != 0
	cmp r0, #0					
	beq check_ISR_5ms		// Kein Zeichen => fahre mit ISR_5ms fort
	bl uart_getChar			// Zeichen da => hole vom Terminal
	mov r10, r0				// schiebe Zeichen in r10, da Funktionsaufrufe
	
	cmp r10, #START_STOP	// Terminaleingabe (s) empfangen?
	it eq
	bleq func_start_stopp
	cmp r10, #PLUS			// Terminaleingabe (+) empfangen?
	ittt eq
	strbeq r11, [r5]
	ldreq r0, =str_Plus
	bleq uart_putString
	cmp r10, #MINUS			// Terminaleingabe (-) empfangen?
	ittt eq
	strbeq r12, [r5]
	ldreq r0, =str_Minus
	bleq uart_putString
	
check_ISR_5ms:
	ldrb r0, [r8]			
	cmp r0, #1			// 5ms Timer abgelaufen?
	it ne
	bne check_ISR_1s	// nein? => ISR_1s 
	
	ldr r0, =mod  	   	// Welcher Taster hat Interupt ausgelöst?
	ldrb r1, [r0]
	strb r11, [r0]		// mod = 0, kein Taster gedrückt
	strb r11, [r8]		// Flag ISR_5ms zurücksetzen

	cmp r1, #2			// 1:polling, schwarz SW1 = +- || 2:ISR, gruen SW2 = s/s
	bne schwarz 
	
	ldr r0, =GPIOE_PDIR_26
	ldr r0, [r0]
	cmp r0, #0			// 0-Pegel noch anliegend? -> Taste gueltig
	it eq
	bleq func_start_stopp
	
	b check_ISR_1s
	
schwarz:
	ldr r0, =GPIOA_PDIR_19
	ldr r0, [r0]
	cmp r0, #0			// 0-Pegel noch anliegend? -> Taste gueltig
	it eq
	bleq func_plus_minus

	
check_ISR_1s:
	ldrb r0, [r7]	// Polle Benutzerflag von ISR_1s
	cmp r0, #0		// solange ISR_1s nicht ausgeführt, polle weiter
	beq main_loop
	
	strb r11, [r7]	// Flag ISR_1s zurücksetzen
	
/*------------------ 8-Bit Zaehler de/inkrementieren ------------------------*/
	ldr r0, =b_start_stopp
	ldrb r0, [r0]
	cmp r0, #0			// Stopp-Bit nicht gesetzt => fahre fort
	bne main_loop		// Stopp-Bit gesetzt? springe zur main_loop

	ldr r0, =b_plus_minus
	ldrb r0, [r0]
	cmp r0, #0				// hoch/runter zaehlen?
	ite eq
	addeq r6, r6, #1
	subne r6, r6, #1
	
	ldr r2, =SET_PIN_ALT1	// setze Pin als GPIO
	
	ldr r0, =PORTA_PCR11	// LED 1
	ldr r1, =MASK_1
	tst r6, r1				// Bit-0 gesetzt?
	ite eq
	streq r11, [r0]			// LED aus
	strne r2, [r0]			// LED an
	
	ldr r0, =PORTA_PCR28	// LED 2
	ldr r1, =MASK_2
	tst r6, r1				// Bit-1 gesetzt?
	ite eq
	streq r11, [r0]			// LED aus
	strne r2, [r0]			// LED an
	
	ldr r0, =PORTA_PCR29	// LED 3
	ldr r1, =MASK_4
	tst r6, r1				// Bit-2 gesetzt?
	ite eq
	streq r11, [r0]			// LED aus
	strne r2, [r0]			// LED an
	
	ldr r0, =PORTA_PCR10	// LED 4
	ldr r1, =MASK_8
	tst r6, r1				// Bit-3 gesetzt?
	ite eq
	streq r11, [r0]			// LED aus
	strne r2, [r0]			// LED an
	

	ldr r0, =str_Zaehler	// Terminalausgabe Zahler
	bl uart_putString
	mov r0, r6
	bl uart_putByteBase10

	b main_loop

/*---------------------------------------------------------------------------*/
/*********************** Funktion "func_taster_schwarz" **********************/
/*---------------------------------------------------------------------------*/
// Funktion startet 5ms Debounce-Timer um den Tastendruck des schwarzen Taster
// zu validieren. Setzt mod = 1
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
func_taster_schwarz:
	push {lr}
	mov r1, #1
	ldr r0, =PORTA_IFSR_19	// ClearOnWrite: Schalter-1 Interrupt Flag
	str r1, [r0]
	ldr r0, =PIT_TCTRL2		// Starte PIT2 5ms -> debouncing
	mov r2, #0x3			// Bit[0]=1 (Timer Enable), Bit[1]=1 (Timer Interrupt Enable), Bit[3]=0 (Chain Mode)
	str r2, [r0]
	ldr r0, =mod			// Datenaustausch zwischen ISR und App -> mod = 2
	strb r1, [r0]
	pop {pc}

/*---------------------------------------------------------------------------*/
/*********************** Funktion "func_plus_minus" **************************/
/*---------------------------------------------------------------------------*/
// Funktion setzt/rücksetzt Byte b_plus_minus, welches den Zaehler
// inkrementiert (0) oder dekrementiert (1) in Abhängigkeit vom schwarzen Taster
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
func_plus_minus:
	push {lr}
	ldr r0, =b_plus_minus
	ldrb r1, [r0]
	eor r1, r1, #1			// setzte hoch/runter: XOR 0^1 = 1; 1^1 = 0
	strb r1, [r0]
	cmp r1, #0					
	ite eq
	ldreq r0, =str_Plus		// Terminalausgabe Plus
	ldrne r0, =str_Minus	// Terminalausgabe Minus
	bl uart_putString
	pop {pc}
	
/*---------------------------------------------------------------------------*/
/************************ Funktion "func_start_stopp" ************************/
/*---------------------------------------------------------------------------*/
// Funktion setzt/rücksetzt Byte b_start_stopp, welches den Zaehler
// startet (0) oder stopptt (1) in Abhängigkeit vom grünen Taster
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
func_start_stopp:
	push {lr}
	ldr r0, =b_start_stopp
	ldrb r1, [r0]
	eor r1, r1, #1			// setzte Start/Stopp: XOR 0^1 = 1; 1^1 = 0
	strb r1, [r0]
	cmp r1, #0					
	ite eq
	ldreq r0, =str_Start	// Terminalausgabe Start
	ldrne r0, =str_Stopp	// Terminalausgabe Stopp
	bl uart_putString
	pop {pc}

/*---------------------------------------------------------------------------*/
/********************* Interrupt Service Routine "ISR_1s" ********************/
/*---------------------------------------------------------------------------*/
// Wird zyklisch jede 1 Sekunde von PIT-1 aufgerufen.
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
/*---------------------------------------------------------------------------*/
.thumb_func
ISR_1s:
	mov r1, #1
	ldr r0, =PIT_TFLG1_TIF	// ClearOnWrite: PIT Timer Interrupt Flag
	str r1, [r0]
	
	ldr r0, =b_ISR_1s		// -> setze Flag für Hauptprogramm
	strb r1, [r0]
	bx lr

/*---------------------------------------------------------------------------*/
/********************* Interrupt Service Routine "ISR_5ms" *******************/
/*---------------------------------------------------------------------------*/
// Wird bei Tastendruck 5 ms gestartet zur Entprellung -> PIT-2
// Setzt Benutzer-Flag b_5ms_timer im .data auf 1.
/*---------------------------------------------------------------------------*/
.thumb_func
ISR_5ms:
	mov r1, #1
	ldr r0, =PIT_TFLG2_TIF	// ClearOnWrite: PIT Timer Interrupt Flag
	str r1, [r0]
	
	ldr r0, =b_ISR_5ms		// -> setze Flag für Hauptprogramm
	strb r1, [r0]
	
	ldr r0, =PIT_TCTRL2		// Pit2 ausschalten
	mov r1, #0				// Bit[0]=0 (Timer Enable), Bit[1]=0 (Timer Interrupt Enable)
	str r1, [r0]
	bx lr

/*---------------------------------------------------------------------------*/
/******************** Interrupt Service Routine "ISR_SW2" ********************/
/*---------------------------------------------------------------------------*/
// Wird bei Tastendruck des gruenen Schalters getriggert.
// Interrupt startet 5ms Debounce-Timer PIT-2
// Setzt Benutzer-Flag mod im .data auf 2
/*---------------------------------------------------------------------------*/
.thumb_func
ISR_SW2:
	mov r1, #1
	ldr r0, =PORTE_IFSR_26	// ClearOnWrite: Schalter-2 Interrupt Flag
	str r1, [r0]
	
	ldr r0, =PIT_TCTRL2		// Starte PIT2 5ms -> debouncing
	mov r1, #0x3			// Bit[0]=1 (Timer Enable), Bit[1]=1 (Timer Interrupt Enable), Bit[3]=0 (Chain Mode)
	str r1, [r0]
	
	mov r1, #2
	ldr r0, =mod			// -> setze Flag für Hauptprogramm
	strb r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
b_ISR_1s: .byte 0x0
b_ISR_5ms: .byte 0x0
mod: .byte 0x0
b_start_stopp: .byte 0x0
b_plus_minus: .byte 0x0
str_Start: .asciz "\nStart"
str_Stopp: .asciz "\nStopp"
str_Zaehler: .asciz "\nZaehler: "
str_Minus: .asciz "\nZaehler dekrementieren --"
str_Plus: .asciz "\nZaehler inkrementieren ++"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


/* Generelle Konfig */
.equ MASK_1, 0x1
.equ MASK_2, 0x2
.equ MASK_4, 0x4
.equ MASK_8, 0x8
.equ COUNTER_6, 0x6
.equ SPACE, 0x20		// ASCII Leerzeichen

.equ START_STOP, 0x73	// ASCII 's'
.equ ADC_8BIT, 0x30		// ASCII '0'
.equ ADC_10BIT, 0x31	// ASCII '1'
.equ ADC_12BIT, 0x32	// ASCII '2'
.equ ADC_16BIT, 0x33	// ASCII '3'

/* ADC LSB*1024 für Genauigkeit */
.equ LSB_16BIT, 0x34 	// 0.05*1024 = 52uV

/* Register und Konfiguration LEDs */
.equ PORTA_PCR10, 0x40049028	// LED 4
.equ PORTA_PCR11, 0x4004902C	// LED 1
.equ PORTA_PCR28, 0x40049070	// LED 2
.equ PORTA_PCR29, 0x40049074	// LED 3

.equ GPIOA_PDDR, 0x400FF014		// Data Direction
.equ SET_LED_GPO, 0x30000C00	// LEDs -> GP-Out, Rest -> GP-In

.equ SET_PIN_ALT1, 0x100		// Konfig Pin -> GPIO

/* Konfigurationen für PIT und SIM */
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
.equ SIM_SCGC5, 0x40048038
.equ SIM_SOPT7, 0x40048018

.equ SET_CLOCK_PORT_A, 0x200

/* Bit Banding für PIT und SIM */
__BBREG SIM_SCGC6_PIT, 0x4004803C, 23
__BBREG SIM_SCGC3_ADC1, 0x40048030, 27
__BBREG PIT_TFLG1_TIF, 0x4003711C, 0
__BBREG PIT_TCTRL_TEN, 0x40037118, 0
__BBREG ADC1_SC3_CALF, 0x400BB024, 6
__BBREG GPIOA_PD0R_10, 0x400FF000, 10
__BBREG GPIOA_PD0R_11, 0x400FF000, 11
__BBREG GPIOA_PD0R_28, 0x400FF000, 28
__BBREG GPIOA_PD0R_29, 0x400FF000, 29

/* Startadressen für ADC-1 */
.equ ADC1_SC1A, 0x400BB000
.equ ADC1_CFG1, 0x400BB008
.equ ADC1_CFG2, 0x400BB00C
.equ ADC1_PG, 0x400BB02C
.equ ADC1_RA, 0x400BB010
.equ ADC1_SC2, 0x400BB020
.equ ADC1_SC3, 0x400BB024
.equ ADC1_CLP0, 0x400BB04C
// ADC1_CLP1, 0x400BB048
// ADC1_CLP2, 0x400BB044
// ADC1_CLP3, 0x400BB040
// ADC1_CLP4, 0x400BB03C
// ADC1_CLPS, 0x400BB038

/* Konfiguration ADC-1 */
.equ ADC1_SC1A_KONF, 0x14		// SC1n[ADCH]=AN20, Diff=0, AIEN=0 Interrupt Enable
.equ ADC1_CFG1_8b_KONF, 0x70	// ADIV=8 (25Mhz/8=3.125), ADLSMP=1 Long, ADICLK=0 BusClk, MODE=00 8bit
.equ ADC1_CFG1_10b_KONF, 0x78	// ADIV=8 (25Mhz/8=3.125), ADLSMP=1 Long, ADICLK=0 BusClk, MODE=10 10bit
.equ ADC1_CFG1_12b_KONF, 0x74	// ADIV=8 (25Mhz/8=3.125), ADLSMP=1 Long, ADICLK=0 BusClk, MODE=01 12bit
.equ ADC1_CFG1_16b_KONF, 0x7C	// ADIV=8 (25Mhz/8=3.125), ADLSMP=1 Long, ADICLK=0 BusClk, MODE=11 16bit
.equ ADC1_CFG2_KONF, 0x0		// ADLSTS=0 LongSample, ADHSC=0 normal Speed, ADACKEN=0 Async Clock disable, MUXSEL=0 ADxxA
.equ ADC1_SC2_KONF, 0x40		// ADTRG=HW-Trigger
.equ ADC1_SC2_CALIB_KONF, 0x0	// ADTRG=SW-Trigger
.equ ADC1_SC3_KONF, 0xE			// AVGS=16samples, AVGE=1, ADCO=Contionous
.equ ADC1_SC3_CALIB_KONF, 0x8F	// CAL=1, AVGE=1, AVGS=11
.equ SIM_SOPT7_KONF, 0x8500		// ALTTRG=1, TRGSEL=PIT1, 

/* NVIC-Startadressen */
.equ NVIC_ISER2, 0xE000E108		// Interrupt Set-Enable Registers
.equ NVIC_ICPR2, 0xE000E288		// Interrupt Clear-Pending Registers
.equ PIT_TIMER_1s, 0x17D783F	// Zaehlerwert für 1s
.equ NVIC_CONFIG_IRQ69, 0x20	// IRQ69

.equ OFFSET_PIT1_IRQ69, 0x154								// PIT1 = IRQ69
.equ IVT_ADRESSE_PIT1, (0x1FFFFE00 + OFFSET_PIT1_IRQ69)		// IVT-Basisadresse +  Offset


main:	
	bl uart_init
	
/*------------------- Initialisierung SIM, Ports, ADC -----------------------*/
	mov r12, #1				// mit 1 vorladen
	mov r11, #0				// mit 0 vorladen
	
	ldr r0, =SIM_SCGC6_PIT	// PIT clock enable
	str	r12, [r0]
	
	ldr r0, =SIM_SCGC5		// Port Clock Enable
	ldr r1, =SET_CLOCK_PORT_A
	str r1, [r0]
	
	ldr r0, =SIM_SCGC3_ADC1	// ADC1 clock enable
	str	r12, [r0]
	
	ldr r0, =SIM_SOPT7		// ADC1 Trigger Select
	ldr r2, [r0]
	ldr r1, =SIM_SOPT7_KONF
	orr r1, r2, r1
	str r1, [r0]
	
	mov r10, #SET_PIN_ALT1
	ldr r0, =PORTA_PCR11	// LED1 to GPIO
	str r10, [r0]
	
	ldr r0, =PORTA_PCR28	// LED2 to GPIO
	str r10, [r0]
		
	ldr r0, =PORTA_PCR29	// LED3 to GPIO
	str r10, [r0]
		
	ldr r0, =PORTA_PCR10	// LED4 to GPIO
	str r10, [r0]
	
	ldr r0, =GPIOA_PDDR		// Port_A GPOut
	ldr r2, [r0]
	ldr r1, =SET_LED_GPO
	orr r1, r2, r1			// maskieren
	str r1, [r0]

	ldr r0, =ADC1_CFG1
	mov r1, #ADC1_CFG1_16b_KONF	// b: ADC1-Konfig
	strb r1, [r0]
	
	ldr r0, =ADC1_CFG2
	mov r1, #ADC1_CFG2_KONF
	strb r1, [r0]	
	
	ldr r0, =ADC1_SC1A
	mov r1, #ADC1_SC1A_KONF
	strb r1, [r0]
	
	bl adc_calib
	
	ldr r0, =ADC1_SC2
	mov r1, #ADC1_SC2_KONF
	str r1, [r0]
	
	ldr r0, =ADC1_SC3
	mov r1, #ADC1_SC3_KONF
	str r1, [r0]	

/*------------------------- Initialisierung NVIC ----------------------------*/
	ldr r0, =ISR_1s			
	ldr r1, =IVT_ADRESSE_PIT1	// ISR Adresse in VectorInterruptTabelle[PIT1]; IRQ-69
	str r0, [r1]
		
	ldr r0, =NVIC_ICPR2			// ClearOnWrite: pending state of interrupt
	ldr r1, =NVIC_CONFIG_IRQ69	// IRQ's bitfield location: IRQ-69 mod 32 = 5
	str r1, [r0]
	
	ldr r0, =NVIC_ISER2		// ClearOnWrite: Interrupt enable
	str r1, [r0]
	
/*----------------------- Initialisierung PIT-Modul -------------------------*/
	ldr r0, =PIT_MCR			
	str r12, [r0]			// Bit[0]=1 (FRZ - Debug Mode); Bit[1]=0 (MDIS Clock for PIT enabled - ModulesDisabled)

	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_TIMER_1s	// (1s/25Mhz) -1  = 24.999.999d = 0x17D783F
	str r1, [r0]
	
	ldr r0, =PIT_TCTRL1
	mov r1, 0x3				// Bit[0]=1 (Timer Enable), Bit[1]=1 (Timer Interrupt Enable), Bit[3]=0 (Chain Mode)
	str r1, [r0]
	

	ldr r10, =b_ISR_1s		// Merker auf ISR_1s
	ldr r1, =A_16Bit		// Default: LookUpTabelle auf 16-Bit
	ldr r0, =w_LookUpTable
	str r1, [r0]
	mov r9, #LSB_16BIT		// Default: LSB auf 16-Bit

main_loop:
/*----------- Werte Zeichen vom Terminal aus, nur wenn vorhanden ------------*/
	bl uart_charPresent		// Zeichen vom Terminal vorhanden? dann r0 != 0
	cbz r0, check_ISR_1s	// Kein Zeichen => fahre mit ISR_5ms fort	
	bl uart_getChar			// Zeichen da => hole vom Terminal
	
	cmp r0, #START_STOP		// Terminaleingabe (s) empfangen?
	it eq
	bleq func_start_stopp
	
	ldr r1, =b_start_stopp	// Wenn nicht im Stopp-Modus, keine ADC-Wandlungsgenauigkeit
	ldrb r1, [r1]
	cbz r1, check_ISR_1s

	cmp r0, #ADC_8BIT		// Terminaleingabe (0) empfangen?
	it ne
	bne ADC_10Bit
	
	ldr r0, =str_8Bit
	ldr r1, =A_8Bit
	ldrh r9, [r1]			// setze Multiplikator
	mov r2, #ADC1_CFG1_8b_KONF
	bl func_setAdcConvMode

ADC_10Bit:	
	cmp r0, #ADC_10BIT		// Terminaleingabe (1) empfangen?
	it ne
	bne ADC_12Bit
	
	ldr r0, =str_10Bit
	ldr r1, =A_10Bit
	ldrh r9, [r1]			// setze Multiplikator
	mov r2, #ADC1_CFG1_10b_KONF
	bl func_setAdcConvMode

ADC_12Bit:	
	cmp r0, #ADC_12BIT		// Terminaleingabe (2) empfangen?
	it ne
	bne ADC_16Bit
	
	ldr r0, =str_12Bit
	ldr r1, =A_12Bit
	ldrh r9, [r1]			// setze Multiplikator
	mov r2, #ADC1_CFG1_12b_KONF
	bl func_setAdcConvMode

ADC_16Bit:	
	cmp r0, #ADC_16BIT		// Terminaleingabe (3) empfangen?
	it ne
	bne check_ISR_1s
	
	mov r9, #LSB_16BIT		// setze Multiplikator
	ldr r0, =str_16Bit
	ldr r1, =A_16Bit
	mov r2, #ADC1_CFG1_16b_KONF
	bl func_setAdcConvMode

check_ISR_1s:
	ldrb r0, [r10]		// Polle Benutzerflag von ISR_1s
	cmp r0, #0			// warte auf ISR_1s
	beq main_loop
	
	strb r11, [r10]		// Flag ISR_1s zurücksetzen
	
/*------------------- ADC1 und Ausgabe starten/stoppen ----------------------*/
	ldr r0, =b_start_stopp
	ldrb r0, [r0]
	cmp r0, #0			// Stopp-Bit nicht gesetzt => fahre fort
	bne main_loop		// Stopp-Bit gesetzt? springe zur main_loop
	
	ldr r0, =str_0x		// Terminalausgabe-Format
	bl uart_putString
	
	ldr r4 ,=ADC1_RA	// Lade ADC-Rohwert
	ldr r4, [r4]
	mov r0, r4
	bl uart_putInt16	// Ausgabe Rohwert
	
	mov r0, #SPACE		// Terminalausgabe-Format
	bl uart_putChar
	
	mul r0, r4, r9		// Umrechnung in [mV]: r0=Rohwert*(LSB*1024)
	lsr r0, r0, #10		// r0=r0/1024[mV]
	
	bl func_getAdcBereich

	mov r4, r0			// Unterer Grenzbereich
	mov r5, r1			// Oberer Grenzbereich
	mov r6, r2			// Stufe
	
	// wenn Stufe = 1, begrenze unteren Grenzbereich mit nur einer '0'
	cmp r6, #1
	it eq
	bleq uart_putByteBase10
	cmp r6, #1
	it eq
	beq next_format
	
	lsr r0, r4, #8		// Unterer Grenzbereich: HighByte
	cmp r0, #0			// führende 0 entfernen
	it ne
	blne uart_putByteBase10
	and r0, r4, #0xFF	// LowByte
	cmp r0, #0			// doppelte 0 ausgeben
	it eq
	bleq uart_putByteBase10
	mov r0, r4			
	bl uart_putByteBase10

next_format:
	ldr r0, =str_format		// Terminalausgabe-Format
	bl uart_putString
	
	lsr r0, r5, #8		// Oberer Grenzbereich: HighByte
	bl uart_putByteBase10
	mov r0, r5			
	bl uart_putByteBase10
	and r0, r5, #0xFF	// LowByte
	cmp r0, #0			// doppelte 0 ausgeben
	it eq
	bleq uart_putByteBase10

	ldr r0, =str_Stufe		// Terminalausgabe-Format
	bl uart_putString

	mov r0, r6
	bl uart_putByteBase10	// Ausgabe Stufe
	
	ldr r0, =GPIOA_PD0R_11	// Set LED 1
	tst r6, #MASK_1			// Bit-0 gesetzt?
	ite eq
	streq r12, [r0]			// LED an
	strne r11, [r0]			// LED aus
	
	ldr r0, =GPIOA_PD0R_28	// LED 2
	tst r6, #MASK_2			// Bit-1 gesetzt?
	ite eq
	streq r12, [r0]			// LED an
	strne r11, [r0]			// LED aus
	
	ldr r0, =GPIOA_PD0R_29	// LED 3
	tst r6, #MASK_4			// Bit-2 gesetzt?
	ite eq
	streq r12, [r0]			// LED an
	strne r11, [r0]			// LED aus
	
	ldr r0, =GPIOA_PD0R_10	// LED 4
	tst r6, #MASK_8			// Bit-3 gesetzt?
	ite eq
	streq r12, [r0]			// LED an
	strne r11, [r0]			// LED aus
	
	b main_loop
	
	
/*---------------------------------------------------------------------------*/
/*************************** Funktion "adc_calib" ****************************/
/*---------------------------------------------------------------------------*/
// Funktion startet die ADC-Kalibrierung gemaeß Handbuch
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
adc_calib:
	push {lr}
	ldr r0, =ADC1_SC2
	mov r1, #ADC1_SC2_CALIB_KONF	// ADC1-Calib-Konfig
	str r1, [r0]
	
	ldr r0, =ADC1_SC3
	mov r1, #ADC1_SC3_CALIB_KONF	// Start Calibration
	str r1, [r0]
	
	ldr r0, =ADC1_SC3_CALF			// CALF nicht gesetzt? -> passed
	ldr r0, [r0]
	cmp r0, #1
	it ne
	bne calc_PG
	
	ldr r0, =str_KalibFail
	bl uart_putString
	b exit

calc_PG:
	mov r0, #0
	mov r1, COUNTER_6
	ldr r2, =ADC1_CLP0
get_val:
	ldr r3, [r2], #-4
	add r0, r0, r3			// addiere CLPx Register auf
	subs r1, r1, #1
	bne get_val
	lsr r0, r0, #1			// divide by 2
	orr r0, r0, #0x8000		//set MSB
	ldr r1, =ADC1_PG
	str r0, [r1]
	
	ldr r0, =str_KalibDone
	bl uart_putString
exit:	
	pop {pc}


/*---------------------------------------------------------------------------*/
/************************ Funktion "func_start_stopp" ************************/
/*---------------------------------------------------------------------------*/
// Funktion setzt/rücksetzt Byte b_start_stopp, welches den Zaehler
// startet (0) oder stopptt (1) in Abhängigkeit vom grünen Taster
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
func_start_stopp:
	push {lr}
	ldr r0, =b_start_stopp
	ldr r2, =PIT_TCTRL_TEN
	ldrb r1, [r0]
	strb r1, [r2]			// Start/Stopp PIT => ADC start/stopp
	eors r1, r1, #1			// setzte Start/Stopp: XOR 0^1 = 1; 1^1 = 0
	strb r1, [r0]
	ite eq
	ldreq r0, =str_Start	// Terminalausgabe Start
	ldrne r0, =str_Stopp	// Terminalausgabe Stopp
	bl uart_putString
	pop {pc}


/*---------------------------------------------------------------------------*/
/********************* Funktion "func_setAdcConvMode" ************************/
/*---------------------------------------------------------------------------*/
// Funktion setzt die Wandlungsgenauigkeit des ADC und aktualisiert LookUp-
// Tabelle mit Terminalausgabe
//
// Übergabeparameter: r0=OutputString, r1=LookUpTabelle, r2=Konvertierung
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
func_setAdcConvMode:
	push {lr}	
	ldr r3, =w_LookUpTable	// LookUpTable setzen
	str r1, [r3]
	ldr r3, =ADC1_CFG1		// ADC-Konfig setzen
	str r2, [r3]
	bl uart_putString 		// Terminalausgabe
	pop {pc}
	

/*---------------------------------------------------------------------------*/
/********************** Funktion "func_getAdcBereich" ************************/
/*---------------------------------------------------------------------------*/
// Funktion ermittlet den Spannungsbereich und zugehoerige Stufe via LookUp-
// Tabelle
//
// Übergabeparameter: r0:ADC-Rohwert
// Rückgabeparameter: r0:min_Spannung, r1:max_Spannung, r2:Stufe 
/*---------------------------------------------------------------------------*/
.thumb_func
func_getAdcBereich:
	ldr r3, =w_LookUpTable
	ldr r3, [r3]
	add r3, r3, #2		// Springe LSB-Konfig
	
	// Overflow abfangen -> r0 auf max. Wert setzen
	ldr r1, =hw_maxVal
	ldrh r1, [r1]
	cmp r0, r1
	it hs
	movhs r0, r1

get_data:
	ldrh r1, [r3, #6]!	// Vergleichswert aus Array A_xBit
	cmp r0, r1
	it hi				// Rohwert ist größer? -> naechstes Element
	bhi get_data
	// kleiner/gleich? -> Bereich gefunden
	ldrh r1, [r3, #2]!	// max Spannung = aktuelles Element; Hole 10er Basis-Wert
	ldrh r0, [r3, #-6]!	// min Spannung = vorheriges Element; Hole 10er Basis-Wert
	ldrh r2, [r3, #2]!	// Stufe aus Matrix

	bx lr
	
/*---------------------------------------------------------------------------*/
/********************* Interrupt Service Routine "ISR_1s" ********************/
/*---------------------------------------------------------------------------*/
// Wird zyklisch jede 1 Sekunde von PIT-1 aufgerufen.
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
/*---------------------------------------------------------------------------*/
.thumb_func
ISR_1s:
	mov r1, #1
	ldr r0, =PIT_TFLG1_TIF	// ClearOnWrite: PIT Timer Interrupt Flag
	str r1, [r0]
	ldr r0, =b_ISR_1s		// -> setze Flag für Hauptprogramm
	strb r1, [r0]
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
b_ISR_1s: .byte 0x0
b_start_stopp: .byte 0x0
hw_maxVal: .hword 0xCE4
w_LookUpTable: .word 0x0
A_8Bit:
	.hword 0x33C4		// LSB: 12.9*1024 = 13252 uV        		
    .hword 0x0			// 0 [mV]
    .hword 0x0			// Base10
    .hword 0x1
    .hword 0x19C		// 412
    .hword 0x40C		// Base10
    .hword 0x2
    .hword 0x339		// 825
    .hword 0x819		// Base10
    .hword 0x3
    .hword 0x4D6		// 1238
    .hword 0xC26		// Base10 
    .hword 0x4
    .hword 0x672		// 1650
    .hword 0x1032		// Base10
    .hword 0x5
    .hword 0x80F		// 2063
    .hword 0x143F		// Base10
    .hword 0x6
    .hword 0x9AB		// 2475
    .hword 0x184B		// Base10
    .hword 0x7
    .hword 0xB48		// 2888
    .hword 0x1C58		// Base10
    .hword 0x8
    .hword 0xCE4		// 3300
    .hword 0x2100		// Base10
A_10Bit:
    .hword 0xCE7		// LSB: 3.22*1024 = 3303 uV     		
    .hword 0x0			// 0
    .hword 0x0			// Base10
    .hword 0x1
    .hword 0x14A		// 330
    .hword 0x31E		// Base10
    .hword 0x2
    .hword 0x294		// 660
    .hword 0x63C		// Base10
    .hword 0x3
    .hword 0x3DE		// 990
    .hword 0x95A		// Base10
    .hword 0x4
    .hword 0x528		// 1320
    .hword 0xD14		// Base10
    .hword 0x5
    .hword 0x672		// 1650
    .hword 0x1032		// Base10
    .hword 0x6
    .hword 0x7BC		// 1980
    .hword 0x1350		// Base10
    .hword 0x7
    .hword 0x906		// 2310
    .hword 0x170A		// Base10
    .hword 0x8
    .hword 0xA50		// 2640
    .hword 0x1A28		// Base10
    .hword 0x9
    .hword 0xB9A		// 2970
    .hword 0x1D46		// Base10
    .hword 0xA
    .hword 0xCE4		// 3300
    .hword 0x2100		// Base10
A_12Bit:
    .hword 0x339		// LSB: 0.80*1024 = 825 uV           		
    .hword 0x0			// 0
    .hword 0x0			// Base10
    .hword 0x1
    .hword 0x113		// 275
    .hword 0x14B		// Base10
    .hword 0x2
    .hword 0x226		// 550
    .hword 0x532		// Base10
    .hword 0x3
    .hword 0x339		// 825
    .hword 0x819		// Base10
    .hword 0x4
    .hword 0x44E		// 1100
    .hword 0xB00		// Base10
    .hword 0x5
    .hword 0x55F		// 1375
    .hword 0xD4B		// Base10
    .hword 0x6
    .hword 0x672		// 1650
    .hword 0x1032		// Base10
    .hword 0x7
    .hword 0x785		// 1925
    .hword 0x1319		// Base10
    .hword 0x8
    .hword 0x898		// 2200
    .hword 0x1600		// Base10
    .hword 0x9
    .hword 0x9AB		// 2475
    .hword 0x184B		// Base10
    .hword 0xA
    .hword 0xABE		// 2750
    .hword 0x1B32		// Base10
    .hword 0xB
    .hword 0xBD1		// 3025
    .hword 0x1E19		// Base10
    .hword 0xC   
    .hword 0xCE4		// 3300
    .hword 0x2100		// Base10
A_16Bit:
    .hword 0x34			// LSB: 0.05*1024 = 52uV
    .hword 0x0			// 0
    .hword 0x0			// Base10
    .hword 0x1
    .hword 0xCE			// 206
    .hword 0x1406		// Base10
    .hword 0x2
    .hword 0x19C		// 412
    .hword 0x40C		// Base10
    .hword 0x3
    .hword 0x26B		// 619
    .hword 0x613		// Base10
    .hword 0x4
    .hword 0x339		// 825
