    .hword 0x8
    .hword 0x672		// 1650
    .hword 0x1032		// Base10
    .hword 0x9
    .hword 0x740		// 1856
    .hword 0x1238		// Base10
    .hword 0xA
    .hword 0x80F		// 2063
    .hword 0x143F		// Base10
    .hword 0xB
    .hword 0x8E7		// 2279
    .hword 0x164F		// Base10
    .hword 0xC
    .hword 0x9AB		// 2475
    .hword 0x184B		// Base10
    .hword 0xD
    .hword 0xA79		// 2681
    .hword 0x1A51		// Base10
    .hword 0xE
    .hword 0xB48		// 2888
    .hword 0x1C58		// Base10
    .hword 0xF
    .hword 0xC16		// 3094
    .hword 0x1E5E		// Base10
    .hword 0x10
    .hword 0xCE4		// 3300
    .hword 0x2100		// Base10
str_Start: .asciz "\nStart"
str_Stopp: .asciz "\nStopp\n0: 8Bit\n1: 10Bit\n2: 12Bit\n3: 16Bit\ns: Start"
str_8Bit: .asciz "\nKonfig 8-Bit Wandlung geladen"
str_10Bit: .asciz "\nKonfig 10-Bit Wandlung geladen"
str_12Bit: .asciz "\nKonfig 12-Bit Wandlung geladen"
str_16Bit: .asciz "\nKonfig 16-Bit Wandlung geladen"
str_0x: .asciz "\n0x"
str_format: .asciz " - "
str_Stufe: .asciz " mV - Stufe "
str_KalibDone: .asciz "\nKalibrierung erfolgreich"
str_KalibFail: .asciz "\nKalibrierung fehlgeschlagen"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


/* **************** Konstantendeklarationen ********* */

.equ KOMMA, 0x2C		// ASCII Komma
.equ MASK_0x10, 0x10
.equ MASK_0x20, 0x20
.equ MASK_0x40, 0x40
.equ MASK_0x80, 0x80

// Registeradressen
.equ SIM_SCGC4, 	0x40048034
.equ SIM_SCGC5, 	0x40048038
.equ SIM_SCGC6, 	0x4004803C

.equ PORTD_PCR8, 	0x4004C020
.equ PORTD_PCR9, 	0x4004C024
.equ GPIOD_PDIR, 	0x400FF0D0
.equ GPIOD_PDDR, 	0x400FF0D4
.equ GPIOD_PDOR, 	0x400FF0C0

.equ NVIC_ISER2, 	0xE000E108	// Interrupt Set-Enable Registers
.equ NVIC_ICPR2, 	0xE000E288	// Interrupt Clear-Pending Registers

.equ PIT_MCR, 		0x40037000
.equ PIT_LDVAL1,	0x40037110
.equ PIT_TCTRL1,	0x40037118
.equ PIT_TFLG1, 	0x4003711C

.equ I2C0_F, 		0x40066001	// Frequence + Basisadresse
.equ I2C0_C1, 		0x40066002	// Ctrl
.equ I2C0_S, 		0x40066003	// Status
.equ I2C0_D, 		0x40066004	// Data I/O
.equ I2C0_SMB, 		0x40066008	// SMBus Ctrl and Status
.equ SMB, 			0x7		

.equ KONF_F, 		0x12		// Mult=1, ICR=12 => Baudrate 390kHz
.equ KONF_C1, 		0xD0 		// Maske fuer Enable, Interrupt, Tx
.equ KONF_SMB,		0x0
.equ KONF_THERMO, 	0x60		// 12-Bit, Komparator-Modus
.equ SLAVE_R, 		0x91
.equ SLAVE_W, 		0x90
.equ PD8_9, 		0x300 		// Maske fuer PD8 und PD9
.equ PD8, 			0x100 		// Maske fuer PD8
.equ ALT_GPIO, 		0x100 		// Alternative 1: GPIO
.equ ALT_IC20, 		0x203 		// ALternative 2: Port_D8:SCL; Port_D9:SDA; Pull-Up
.equ DELAY_COUNT, 	0xf 		// Zaehler für 2uS
.equ COUNTER_11, 	0xB			// Zaehler max. Initialisierungsversuche
.equ TCF_IICIF, 	0x82		// Maske fuer TCF und IF

.equ PIT_TIMER_1s, 	24999999	// (1s/25Mhz) -1  = 24.999.999d = 0x17D783F
.equ NVIC_CONFIG_IRQ69, 0x20	// IRQ69

// Bit Band-Konstanten
__BBREG SIM_I2C0, SIM_SCGC4, 6
__BBREG SIM_PORTD, SIM_SCGC5, 12
__BBREG SIM_PIT, SIM_SCGC6, 23
__BBREG PIT_TIF, PIT_TFLG1, 0

.equ OFFSET_PIT1_IRQ69, 0x154								// PIT1 = IRQ69
.equ IVT_ADRESSE_PIT1, (0x1FFFFE00 + OFFSET_PIT1_IRQ69)		// IVT-Basisadresse +  Offset


main:	
	bl uart_init
	bl I2CBus_Reset
	
	// Fuer die Initialisierung haeufig verwendete Werte vorbelegen
	mov r10, #0
	mov r11, #1
	ldr r4, =I2C0_C1
	ldr r5, =I2C0_D
	
// Takt fuer die benutzten Module aktivieren, Port-D in I2CBus_Reset gesetzt
	ldr r0, =SIM_I2C0
	str r11, [r0]
	ldr r0, =SIM_PIT
	str r11, [r0]
	
// Initialisierung NVIC
	ldr r0, =IVT_ADRESSE_PIT1	// ISR Adresse in VectorInterruptTabelle[PIT1] eintragen; IRQ-69
	ldr r1, =ISR_1s
	str r1, [r0]
		
	ldr r0, =NVIC_ICPR2			// ClearOnWrite: pending state of interrupt
	ldr r1, =NVIC_CONFIG_IRQ69	// IRQ's bitfield location: IRQ-69 mod 32 = 5
	str r1, [r0]
	
	ldr r0, =NVIC_ISER2			// ClearOnWrite: Interrupt enable
	str r1, [r0]
	
// Initialisierung PIT-Modul
	ldr r0, =PIT_MCR			
	str r11, [r0]				// FRZ=1 (Debug Mode); MDIS=0 (0=Clock enabled)(MDIS=ModuleDisabled)
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_TIMER_1s
	str r1, [r0]
	ldr r0, =PIT_TCTRL1
	mov r1, #3					// Timer Enable=1, Timer Interrupt Enable=1, Chain Mode=0
	str r1, [r0]	

// Initialisierung PORTD 8 und 9
	ldr r0, =PORTD_PCR8
	ldr r1, =ALT_IC20		// Alternative2, Pull-Up
	str r1, [r0]
	str r1, [r0, #4]		// Portleitung PD9

// Initialisierung I2C0
	ldr r0, =I2C0_F			// IC20 Frequenz
	mov r1, #KONF_F
	strb r1, [r0]
	mov r1, #KONF_C1		// Enable I2C0, Enable Interrupt, Enable TX
	strb r1, [r4]
	mov r1, #KONF_SMB		// Clear FACK => TCF inklusive ACK-Bit
	strb r1, [r0, #SMB]
	
	mov r9, #0				// Merker Init, 0 = Thyst, 1 = TOS
	ldr r12, =b_ISR_1s		// Merker auf ISR_1s
	mov r8, #1				// Error Handling Fehlerstelle

write_DSP75_Config:
	ldr r0, =str_0x			// Ausgabe
	bl uart_putString
	mov r0, #SLAVE_W
	bl uart_putByte			// Ausgabe Slaveadresse	
	ldr r0, =str_Slaveadresse
	bl uart_putString
		
	mov r0, #SLAVE_W		// setze Startadresse und W-Bit
	bl i2c_Start
	cmp r0, #1
	beq error_Handling		// Reset routine und Retry-Mechanismus
	bl i2c_waitACK
	
	mov r1, #1				// Setze Pointer Byte auf Konfigurationsregister
	strb r1, [r5]			
	bl i2c_waitACK
	
	mov r1, #KONF_THERMO	// 12-Bit Conversion, Komparator Modus
	strb r1, [r5]
	bl i2c_waitACK
	
	bl i2c_Stop				// STOP-Bit
	
	mov r8, #2				// Error Handling Fehlerstelle
	
// Read Two Byte (new pointer location)
read_Temp_newPointer:
	mov r0, #SLAVE_W		// setze Startadresse und W-Bit
	bl i2c_Start
	cmp r0, #1
	beq error_Handling		// Reset routine und Retry-Mechanismus
	bl i2c_waitACK
	
	mov r1, #0				// Setze Pointer Byte auf Temp-Register
	strb r1, [r5]	
	bl i2c_waitACK
	
	bl i2c_RepeatStart		// Laut DSP75 RST setzen
	
	mov r1, #SLAVE_R		// setze Startadresse und R-Bit
	strb r1, [r5]
	bl i2c_waitACK
	
	ldrb r1, [r4]			// Switch to Rx Mode
	bic r1, r1, 0x10
	strb r1, [r4]
	
	ldrb r0, [r5]			// Dummy Read zum Aktivieren
	bl i2c_waitACK
	
	ldrb r6, [r5]			// Valid Read MSB
	
	ldrb r1, [r4]			// Enable NACK
	orr r1, r1, 0x8
	strb r1, [r4]
	
	bl i2c_waitACK
	bl i2c_Stop				// STOP-Bit
	
	ldrb r7, [r5]			// Valid Read LSB
	lsl r0, r7, #8

	cmp r9, #1				// 2ter Durchlauf nach Temp-Konfiguration, dann mainloop
	itt eq
	moveq r8, #4			// Error Handling Fehlerstelle
	beq mainloop
	
	mov r8, #3				// Error Handling Fehlerstelle
	add r6, r6, #2			// schreibe in write_TempConfig: Thyst = temp+2
	
	ldrb r1, [r4]			// Switch to Tx Mode
	orr r1, r1, 0x10
	strb r1, [r4]
	
// Write TOS or Thsyt Register
write_TempConfig:
	mov r0, #SLAVE_W		// setze Startadresse und W-Bit
	bl i2c_Start
	cmp r0, #1
	beq error_Handling		// Reset routine und Retry-Mechanismus
	bl i2c_waitACK
	
	cmp r9, #0
	itee eq
	moveq r1, #2 			// Setze Pointer Byte Thyst
	movne r1, #4			// Setze Pointer Byte TOS
	addne r6, r6, #1		// in Thyst bereit um 2 erhöht; TOS = temp+3
	
	strb r1, [r5]			// Schreibe Pointer		
	bl i2c_waitACK
	
	strb r6, [r5]			// Schreibe MSB
	bl i2c_waitACK
	
	strb r7, [r5]			// Schreibe LSB
	bl i2c_waitACK
	bl i2c_Stop				// STOP-Bit
	
	cmp r9, #0				// Thyst geschrieben? Dann schreibe TOS
	itt eq
	moveq r9, #1
	beq write_TempConfig
	
	ldr r0, =str_KonfDone
	bl uart_putString
	
	cmp r9, #1				// TOS & Thyts geschrieben? -> Lese Temp mit neuen Pointer
	beq read_Temp_newPointer

	
mainloop:
	ldrb r0, [r12]			// PIT1 abgelaufen?
	cmp r0, #0				// warte auf ISR_1s
	beq mainloop
	
	strb r10, [r12]			// Clear ISR Flag

// Read 2-Bytes from temperature register
	mov r1, #KONF_C1		
	strb r1, [r4]

	mov r0, #SLAVE_R		// setze Startadresse und R/W-Bit
	bl i2c_Start
	cmp r0, #1
	beq error_Handling		// Reset routine und Retry-Mechanismus
	bl i2c_waitACK
			
	ldrb r1, [r4]			// Switch to Rx Mode
	bic r1, r1, 0x10
	strb r1, [r4]
	
	ldrb r1, [r5]			// Dummy Read zum Aktivieren
	bl i2c_waitACK
	
	ldrb r6, [r5]			// Valid Read MSB
	
	ldrb r1, [r4]			// Enable NACK -> TXAK =1
	orr r1, r1, 0x8
	strb r1, [r4]
	bl i2c_waitACK
	
	bl i2c_Stop				// STOP-Bit
	
	ldrb r7, [r5]			// Valid Read LSB
	
	lsl r0, r7, #8			// Fuer Ausgabe LSB shiften
	lsl r1, r6, #16			// Fuer Ausgabe MSB shiften
	orr r0, r1, r0
	bl uart_putInt32		// Ausgabe in hex
	
	ldr r0, =str_form		// Formatierung
	bl uart_putString
	
	mov r0, r6				// Ausgabe MSB
	bl output_dez
	mov r0, #KOMMA
	bl uart_putChar
	mov r0, r7				// Ausgabe LSB
	bl output_nachkomma
	
	b mainloop

error_Handling:
	bl I2CBus_Reset
	ldr r0, =str_error
	bl uart_putString
// Initialisiere PortD 
	ldr r0, =PORTD_PCR8
	ldr r1, =ALT_IC20		// Alternative2, Pull-Up
	str r1, [r0]
	str r1, [r0, #4]		// Portleitung PD9
	
	mov r0, r8
	bl uart_putByte
		
	cmp r8, #1				// Springe zur Abbruchstelle
	beq write_DSP75_Config
	cmp r8, #2
	beq read_Temp_newPointer
	cmp r8, #3
	beq write_TempConfig
	cmp r8, #4
	beq mainloop


/*** ISR und Unterprogramme ***/

/*---------------------------------------------------------------------------*/
// Funktion "i2c_Start"
//
// Beschreibung: Wartet auf Busy-Idle und sendet bis zu 100x I2C Start-Signale
//
// Übergabeparameter: r0: Slaveadresse mit (R/W)
// Rückgabeparameter: r0: 0 (OK), 1 (NOT_OK)
/*---------------------------------------------------------------------------*/
.thumb_func
i2c_Start:
	push {r4, lr}
	mov r4, r0			// Uebergabeparameter sichern
	mov r3, #100

start_idle:	
	subs r3, r3, #1		// 100-Versuche, sonst Fehlerausgabe
	ittt eq
	moveq r4, #1
	ldreq r0, =str_ErrStart
	beq start_exit
	
	ldr r1, =I2C0_S		// Pruefe ob Bus = Idle
	ldrb r2, [r1]
	and r2, r2, #0x20
	cmp r2, #0x20
	it eq
	beq start_idle		// Bus nicht Idle => wiederhole

start_loop:
	subs r3, r3, #1		// 100-Versuche, sonst Fehlerausgabe
	ittt eq
	moveq r4, #1
	ldreq r0, =str_ErrStart
	beq start_exit
	
	ldr r1, =I2C0_C1	// Schreibe MST = START-Signal
	ldrb r2, [r1]
	orr r2, r2, #0x20
	strb r2, [r1]
	
	ldrb r2, [r1]		// Pruefen ob Bit MST gesetzt wurde
	and r2, r2, #0x20
	cmp r2, #0x20
	bne start_loop		// MST nicht gesetzt => wiederhole
	
	mov r0, r4
	ldr r1, =I2C0_D
	strb r0, [r1]		// Schreibe Slaveadresse als Erstes
	
	mov r4, #0			// Rueckgabewert Funktion

start_exit:
	cmp r4, #1
	it eq
	bleq uart_putString	// Fehlerausgabe
	mov r0, r4
	pop {r4, pc}


/*---------------------------------------------------------------------------*/
// Funktion "i2c_Stop"
//
// Sendet bis zu 10 I2C Start-Signale
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
i2c_Stop:
	ldr r0, =I2C0_C1	// Schreibe MST = STOP-Signal
	ldrb r1, [r0]
	bic r1, r1, 0x20	// Clear MST
	strb r1, [r0]
	bx lr

/*---------------------------------------------------------------------------*/
// Funktion "output_nachkomma"
//
// Gibt die Nachkommastelle (0.5, 0.25, 0.125, 0.0625) *1000 in dez aus 
//
// Übergabeparameter: r0
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
output_nachkomma:
	push {r4, lr}
	mov r3, r0			// Uebergabewert in r3
	mov r0, #0			// Startwert Addition
	ldr r1, =b_temp
	
	tst r3, #MASK_0x10	// Bit-0 gesetzt?
	itt ne
	ldrhne r2, [r1]
	addne r0, r0, r2	// = 0.0625 Grad
	
	tst r3, #MASK_0x20	// Bit-1 gesetzt?
	itt ne
	ldrhne r2, [r1, #2]
	addne r0, r0, r2	// = 0.125 Grad
	
	tst r3, #MASK_0x40	// Bit-2 gesetzt?
	itt ne
	ldrhne r2, [r1, #4]
	addne r0, r0, r2	// = 0.25 Grad
	
	tst r3, #MASK_0x80	// Bit-3 gesetzt?
	itt ne
	ldrhne r2, [r1, #6]
	addne r0, r0, r2	// = 0.5 Grad

	mov r1, #100				// Divisor bzw. Multiplikator
	udiv r2, r0, r1				// Wert / 100
	mls	r4, r2, r1, r0			// Rest = Eingabewert(R0) - Quotient(R2) * 100(R1)
	mov r0, r2
	cmp r0, #0x9				// führende Null notwendig?
	ite ls						// passendes Unterprogramm (mit/ohne führende Null)auswählen
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1 						// selektiertes Unterprogramm aufrufen
	mov r0, r4					// Rest holen
	cmp r0, #0					// 00 -> keine Ausgabe notwendig
	beq output_exit
	cmp r0, #0x9				// führende Null notwendig?
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1 

output_exit:
	ldr r0, =str_grad
	bl uart_putString
	pop {r4, pc}

/*
 * Gibt einen Wert von 00 bis 99 inkl. führender Nullen dezimal auf dem Terminal aus
 * Parameter: r0: Wert
 * Rückgabe: keine 
*/
.thumb_func
output_dez:
	push {lr}
	mov r1, #100				// Divisor bzw. Multiplikator
	udiv r2, r0, r1				// Wert / 100
	mls	r0, r2, r1, r0			// Rest = Eingabewert(R0) - Quotient(R2) * 100(R1)
	cmp r0, #0x9				// führende Null notwendig?
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	pop {pc}


/*---------------------------------------------------------------------------*/
// Funktion "i2c_RepeatStart"
//
// Setzt Repeat START
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
i2c_RepeatStart:
	ldr r0, =I2C0_C1
	ldrb r1, [r0]
	orr r1, r1, 0x4		// Set RSTA
	strb r1, [r0]
	bx lr
/*---------------------------------------------------------------------------*/
// Funktion "i2c_waitACK"
// Wartet bis Statusregister die Uebertragung als beendet anzeigt und ACK
// vom DSP75 gesetzt wird.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
i2c_waitACK:
	ldr r0, =I2C0_S
waitACK_loop:
	ldrb r1, [r0]
	and r1, r1, #TCF_IICIF
	cmp r1, #TCF_IICIF
	it ne
	//tst r1, #TCF_IICIF	// Check Complete 1-byte transfer: TCF && IICIF
	bne waitACK_loop
	
	orr r1, r1, #2		// CLear InterruptFlag
	strb r1, [r0]
	bx lr

/*---------------------------------------------------------------------------*/
// Funktion "I2CBus_Reset"
// 
/*---------------------------------------------------------------------------*/
.thumb_func
I2CBus_Reset:
	push {r4, lr}
	
	ldr r0, =SIM_PORTD // Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR8 // Portleitungen PD8 , PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR // PD8 , PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	mov r4, #COUNTER_11
	
I2CBus_loop:
	// Ein Zaehler fuer maximal 10 Versuche ist zu implementieren.
	// Ggf . Fehlermeldung auf Terminal ausgeben und abbrechen.
	subs r4, r4, #1
	itt eq
	ldreq r0, =str_ErrInit
	beq I2CBus_exit
	
	ldr r0, =GPIOD_PDOR // SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD8 	// entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDOR // SCL und SDA aktivieren
	ldr r2, [r0]
	orr r2, r2 , #PD8_9
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9 	// nur Bits 9 und 10 pruefen
	cmp r2, #PD8_9 		// Bit 9 und Bit 10 gesetzt ?
	bne I2CBus_loop 	// ggf . wiederholen
	
	ldr r0, =str_Init
I2CBus_exit:
	bl uart_putString 
	pop {r4, pc}

/*---------------------------------------------------------------------------*/
// Funktion "i2c_Delay"
//
// Die Funktion erzeugt eine Verzögerung von ~2 uSekunden über eine Schleife
// fuer Bus-Takt 25MHz.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
i2c_Delay:
	ldr	r0, =DELAY_COUNT			// (1) 2 * 40 ns (2 Takte)
delay_loop:
	subs r0, r0, #1					// (2) n * 40 ns (1 Takt)
	bne	delay_loop					// (3) n * 80 ns (2 Takte), wenn der Sprung genommen wird
	nop								// (4) 1 * 40 ns (1 Takt) 
	nop								// (5) 1 * 40 ns (1 Takt)
	bx lr							// (6) 2 * 40 ns (2 Takte); Summe 2040ns

/*---------------------------------------------------------------------------*/
// Interrupt Service Routine "ISR_1s"
//
// Wird zyklisch jede 1 Sekunde von PIT-1 aufgerufen.
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
ISR_1s:
	mov r1, #1
	ldr r0, =PIT_TIF	// ClearOnWrite: PIT Timer Interrupt Flag
	str r1, [r0]
	ldr r0, =b_ISR_1s	// -> setze Flag für Hauptprogramm
	strb r1, [r0]
	bx lr

	
/*** Datenbereich (ab 0x20000000) ***/
.data
b_ISR_1s: .byte 0x0
b_temp: .hword 0x271, 0x4E2, 0x9C4, 0x1388


str_ErrInit: .asciz "\nRuecksetzen I2C NOT_OK\n"
str_Init: .asciz "\nRuecksetzen I2C OK\n"
str_ErrStart: .asciz "\nSTART konnte nicht gesetzt werden."
str_Slaveadresse: .asciz " Slaveadresse\n"
str_0x: .asciz "\n0x"
str_error: .asciz "\nFehlerruecksetz Routine wird ausgefuehrt"
str_form: .asciz ": "
str_grad: .asciz " Grad Celsius\n"
str_KonfDone: .asciz "Konfiguration abgeschlossen.\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


// Konstanten
.equ KOMMA, 0x2C
.equ MASK_0x10, 	0x10
.equ MASK_0x20, 	0x20
.equ MASK_0x40, 	0x40
.equ MASK_0x80, 	0x80

// Registeradressen
.equ SIM_SCGC3, 	0x40048030
.equ SIM_SCGC5, 	0x40048038
.equ SIM_SCGC6, 	0x4004803C

.equ PORTA_PCR19, 	0x4004904C
.equ PORTD_PCR8, 	0x4004C020
.equ PORTD_PCR9, 	0x4004C024
.equ PORTD_PCR12, 	0x4004C030
.equ PORTE_PCR26,   0x4004d068

.equ GPIOA_PDDR,    0x400FF014
.equ GPIOD_PDIR, 	0x400FF0D0
.equ GPIOD_PDDR, 	0x400FF0D4
.equ GPIOD_PDOR, 	0x400FF0C0
.equ GPIOE_PDDR,    0x400FF114

.equ NVIC_ISER2,	0xE000E108
.equ NVIC_ICPR2, 	0xE000E288
.equ IVT_BASE, 		0x1FFFFE00			// Baisadresse der Interrupt-Vektor-Tabelle
.equ IVT_PIT1, IVT_BASE + 0x154
.equ IVT_PTA, IVT_BASE + 0x019C
.equ IVT_PTE, IVT_BASE + 0x01AC

.equ PIT_MCR, 		0x40037000
.equ PIT_LDVAL1,	0x40037110
.equ PIT_TCTRL1,	0x40037118
.equ PIT_TFLG1, 	0x4003711C

.equ SPI2_MCR,		0x400AC000
.equ SPI2_CTAR0,	0x400AC00C
.equ SPI2_SR,		0x400AC02C
.equ SPI2_RSER,		0x400AC02C
.equ SPI2_PUSHR,	0x400AC034
.equ SPI2_POPR,		0x400AC038

// Bit Band-Konstanten
__BBREG SIM_SPI2, SIM_SCGC3, 12
__BBREG SIM_PIT, SIM_SCGC6, 23

__BBREG PIT_TIF, PIT_TFLG1, 0
__BBREG PIT_TEN, PIT_TCTRL1, 0

__BBREG	SW1_CIF, PORTA_PCR19, 24
__BBREG	PDDR_SW1, GPIOA_PDDR, 19

__BBREG	SW2_CIF, PORTE_PCR26, 24
__BBREG	PDDR_SW2, GPIOE_PDDR, 26

__BBREG SPI2_HALT, SPI2_MCR, 0
__BBREG SPI2_TCF, SPI2_SR ,31
__BBREG SPI2_MDIS, SPI2_MCR, 14

// Konfiguration
.equ ALT2_SPI, 			0x200
.equ GPIO_IRQ_PE_SET, 	0xA0103

.equ NVIC_ISER2_MASK, 	0x8800020 	// Bit 27 (Port E), 23 (Port A), 5 (PIT1)
.equ PIT_TIMER_75ms,	1875000
.equ PIT_TIMER_150ms,	3750000
.equ PIT_TIMER_300ms,	7500000
.equ PIT_TIMER_600ms,	15000000
.equ PIT_TIMER_1200ms,	30000000

.equ MCR_KONF,			0x80003001
.equ MCR_FLUSH_KONF,	0x80003C01
.equ CTAR0_KONF,		0x7EA82227	// 97kHz
.equ PUSHR_KONF,		0xC020000	// EOQ, ClearTransferCount, SPI2_PCS1 

.equ SLAVE_W_8BIT,		0xC0280E0
.equ SLAVE_W_9BIT,		0xC0280E2
.equ SLAVE_W_10BIT,		0xC0280E4
.equ SLAVE_W_11BIT,		0xC0280E6
.equ SLAVE_W_12BIT,		0xC0280E8

.equ SLAVE_R_KONF,		0xC020000
.equ SLAVE_R_TEMP_LSB,	0xC020100
.equ SLAVE_R_TEMP_MSB,	0xC020200

main:	
	bl uart_init

// Fuer die Initialisierung haeufig verwendete Werte vorbelegen
	mov r10, #0
	mov r11, #1

// Takt fuer die benutzten Module aktivieren
	ldr r0, =SIM_SPI2
	str r11, [r0]
	ldr r0, =SIM_PIT
	str r11, [r0]
	ldr r0, =SIM_SCGC5
	ldr r1, [r0]
	orr r1, r1, 0x3200			// Port-A, -D, -E
	str r1, [r0]

// GPIO-Pin konfigurieren
	ldr r0, =GPIO_IRQ_PE_SET 	// GPIO-Modus mit IRQ (fallende Flanke) und Pull-Up-Widerstand 	
	ldr r1, =PORTA_PCR19		// fuer SW1
	ldr r2, =PORTE_PCR26 		// fuer SW2
	str r0, [r1]
	str r0, [r2]

// Datenrichtung der GPIO-Pins festlegen
	ldr r0, =PDDR_SW1		//Eingang SW1 
	str r10, [r0]
	ldr r0, =PDDR_SW2		//Eingang SW2
	str r10, [r0]

// Initialisierung PORTD 12 - 15
	ldr r0, =PORTD_PCR12
	ldr r1, =ALT2_SPI		// ALT2 -> SPI
	str r1, [r0], #4		// PD12 -> SCK
	str r1, [r0], #4		// PD13 -> SOUT
	str r1, [r0], #4		// PD14 -> SIN
	str r1, [r0]			// PD15 -> PCS1

// Adressen der ISRs in die IVT eintragen
	ldr r0, =IVT_PTA
	ldr r1, =isr_port_a
	str r1, [r0]
	ldr r0, =IVT_PTE
	ldr r1, =isr_port_e
	str r1, [r0]
	ldr r0, =IVT_PIT1
	ldr r1, =isr_pit1
	str r1, [r0]

// NVIC-Bitmaske fuer Port A und Port E setzen
	ldr r0, =NVIC_ISER2
	ldr r1, =NVIC_ISER2_MASK
	str r1, [r0]

// Initialisierung PIT-Modul
	ldr r0, =PIT_MCR			
	str r11, [r0]				// FRZ=1 (Debug Mode); MDIS=0 (0=Clock enabled)(MDIS=ModuleDisabled)
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_TIMER_1200ms
	str r1, [r0]

// Initialisierung SPI2
	ldr r0, =SPI2_MDIS
	str r10, [r0]				// Loesche MDIS
	
	ldr r0, =SPI2_MCR
	ldr r1, =MCR_KONF			// Master, PCS2 inactive low, disable TX/RX FIFO
	str r1, [r0]
	
	ldr r0, =SPI2_CTAR0			// Frame Size 16bit, CPOL=1, CPHA=1, MSB first
	ldr r1, =CTAR0_KONF			// PCSSCK=5, PASC=5 , PDT=5 ,PBR=2, CSSCK=8, ASC=8 , DT=8, BR=128
	str r1, [r0]
	
	ldr r0, =SPI2_RSER			// kein DMA/Interrupts
	str r10, [r0]
	
	
// haeufig verwendete Werte: r8, r9, r12
	ldr r8, =b_offset
	ldr r9, =b_inc_dec
	ldr r12, =b_ISR

// Initiale Aufloesung auf 12Bit
	ldr r0, =tab_delay
	ldrb r1, [r8]
	add r0, r0, r1			// add Offset
	ldr r0, [r0, #20]		// lade Wert in ms
	bl uart_putString

	ldr r0, =SLAVE_W_12BIT	// schreibe 12-Bit konfig
	bl spi_write

//  Starte Timer
	ldr r0, =PIT_TCTRL1
	mov r1, #3				// Timer Enable=1, Timer Interrupt Enable=1, Chain Mode=0
	str r1, [r0]

mainloop:
	ldrb r0, [r12]			// PIT1 abgelaufen?
	cmp r0, #0				// warte auf ISR
	beq mainloop

	strb r10, [r12]			// loesche ISR Flag

	ldr r0, =SLAVE_R_TEMP_MSB	// Hole Temperatur
	bl spi_read
	bl uart_putByteBase10
	mov r0, #KOMMA
	bl uart_putChar
	
	ldr r0, =SLAVE_R_TEMP_LSB	// Hole Nachkommastelle
	bl spi_read
	bl output_nachkomma
	
	
	ldrb r0, [r9]			// Taste gedrueckt?
	cbz r0, exit			// nein		
	ldrb r2, [r8]			// ja => lade Offset
	cmp r0, #2				// grün(-) oder schwarz(+) gedrueckt?
	beq dec

	add r2, r2, #4			// + inkrement
	cmp r2, #16				// großer 16? -> Overflow
	it hi
	movhi r2, #0			// auf 0 setzen
	strb r2, [r8]			// Offset fuer Tabelle

	b output

dec:						// - dekrement
	subs r2, r2, #4			// kleiner 0? -> Underflow			
	it mi
	movmi r2, #16			// auf 16 setzen
	strb r2, [r8]			// Offset fuer Tabelle
	
output:
	ldr r0, = b_inc_dec		// ISR Flag loeschen
	strb r10, [r0]

	ldr r0, =tab_delay
	ldr r4, =tab_slave_konf
	ldrb r1, [r8]
	add r0, r0, r1			// Zaehlerwert + Offset
	add r4, r4, r1			// SlaveKonf + Offset
	ldr r2, [r0]			// lade Zaehlerschleife
	ldr r5, =w_pit_timer	// aktualisere PIT-Timer
	str r2, [r5]
	ldr r0, [r0, #20]		// lade Terminalausgabe
	bl uart_putString
	
	ldr r0,[r4]				// lade Slave Konfig
	bl spi_write

// setze PIT Timer
	ldr r0, =PIT_TEN		// Timer AUS
	str r10, [r0]
	ldr r1, [r5]			// lade Timerwert
	ldr r2, =PIT_LDVAL1		// Timerwert setzen
	str r1, [r2]
	str r11, [r0]			// Timer AN
	
exit:	 
	b mainloop
	

/*
 * ISR fuer SW1 (Port A)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func 
isr_port_a: 					
	ldr r0, =SW1_CIF			// Bit-Band-Adresse des Interrupt-Flags fuer SW1
	mov r1, #1
	str r1, [r0]				// Flag loeschen
	
	ldr r0, = b_inc_dec			// Wandlungsgenauigkeit inkrementieren
	strb r1, [r0]
	bx lr

/*
 * ISR fuer SW2 (Port E)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func 
isr_port_e: 					
	ldr r0, =SW2_CIF			// Bit-Band-Adresse des Interrupt-Flags fuer SW2
	mov r1, #1
	str r1, [r0]				// Flag loeschen
	
	ldr r0, = b_inc_dec			// Wandlungsgenauigkeit dekrementieren
	mov r1, #2
	strb r1, [r0]
	bx lr

/* Funktion "spi_write"-------------------------------------------------------*/
// Wartet bis Frame gesendet ist und beendet die Uebertragung.
//
// Übergabeparameter: r0=write_data
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
spi_write:
	ldr r1, =SPI2_PUSHR
	str r0, [r1]
	ldr r0, =SPI2_HALT		// Starte SPI Transfer
	mov r1, #0
	str r1, [r0]
	ldr r2, =SPI2_TCF
	mov r1, #1
waitTCF_write:				// warte SPI Uebertragung beendet
	ldr r3, [r2]
	cmp r3, #1
	bne waitTCF_write
	
	str r1, [r2]			// loesche TCF Flag	
	str r1, [r0]			// SPI-Uebertragung beenden
	
	ldr r0, =SPI2_MCR		// Flush TX/RX
	ldr r1, =MCR_FLUSH_KONF
	str r1, [r0]
	ldr r1, =MCR_KONF
	str r1, [r0]
	
	bx lr

/* Funktion "spi_read"-------------------------------------------------------*/
// Wartet bis Frame gesendet ist, beendet die Uebertragung und holt Ergebins.
//
// Übergabeparameter: r0=send_cmd
// Rückgabeparameter: r0=data
/*---------------------------------------------------------------------------*/
.thumb_func
spi_read:
	ldr r1, =SPI2_PUSHR
	str r0, [r1]
	ldr r0, =SPI2_HALT		// Starte SPI Transfer
	mov r1, #0
	str r1, [r0]
	ldr r2, =SPI2_TCF
	mov r1, #1
waitTCF_read:				// warte bis SPI Uebertragung beendet
	ldr r3, [r2]
	cmp r3, #1
	bne waitTCF_read
waitRX:
	ldr r3, =SPI2_SR
	ldr r3, [r3]
	and r3, r3, 0xF0
	lsl r3, r3, #4
	cmp r3, #0
	beq waitRX

	str r1, [r0]			// SPI-Uebertragung beenden
	str r1, [r2]			// loesche TCF Flag
	ldr r1, =SPI2_POPR		// read Result
	ldr r0, [r1]
	bx lr


/* Funktion "output_nachkomma"-----------------------------------------------*/
// Gibt die Nachkommastelle (0.5, 0.25, 0.125, 0.0625) *1000 in dez aus 
//
// Übergabeparameter: r0=data
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
output_nachkomma:
	push {r4, r5, lr}
	mov r3, r0			// Uebergabewert in r3
	mov r0, #0			// Startwert Addition
	ldr r1, =b_temp
	
	tst r3, #MASK_0x10	// Bit-0 gesetzt?
	itt ne
	ldrhne r2, [r1]
	addne r0, r0, r2	// = 0.0625 Grad
	
	tst r3, #MASK_0x20	// Bit-1 gesetzt?
	itt ne
	ldrhne r2, [r1, #2]
	addne r0, r0, r2	// = 0.125 Grad
	
	tst r3, #MASK_0x40	// Bit-2 gesetzt?
	itt ne
	ldrhne r2, [r1, #4]
	addne r0, r0, r2	// = 0.25 Grad
	
	tst r3, #MASK_0x80	// Bit-3 gesetzt?
	itt ne
	ldrhne r2, [r1, #6]
	addne r0, r0, r2	// = 0.5 Grad

	mov r1, #100				// Divisor bzw. Multiplikator
	udiv r5, r0, r1				// Wert / 100
	mls	r4, r5, r1, r0			// Rest = Eingabewert(R0) - Quotient(R2) * 100(R1)
	mov r0, r5
	bl uart_putByteBase10
	cmp r5, #0					// r5=0?
	itt eq
	moveq r0, #0
	bleq uart_putByteBase10		// doppelte 0 Ausgabe
	
	
	mov r0, r4					// Rest holen
	bl uart_putByteBase10
	cmp r4, #0					// r4=0?
	itt eq
	moveq r0, #0
	bleq uart_putByteBase10		// doppelte 0 Ausgabe
	
output_exit:
	ldr r0, =str_grad
	bl uart_putString
	pop {r4, r5, pc}


/* Interrupt Service Routine "isr_pit1"--------------------------------------*/
// Wird zyklisch von PIT-1 aufgerufen, Zahelerwert aus w_pit_timer.
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
isr_pit1:
	mov r1, #1
	ldr r0, =PIT_TIF		// loesche PIT Timer Interrupt Flag
	str r1, [r0]
	ldr r0, =b_ISR			// setze Flag für Hauptprogramm
	strb r1, [r0]
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
tab_delay: 
.word PIT_TIMER_75ms, PIT_TIMER_150ms, PIT_TIMER_300ms, PIT_TIMER_600ms, PIT_TIMER_1200ms, str_conv_75ms, str_conv_150ms, str_conv_300ms, str_conv_600ms, str_conv_1200ms
tab_slave_konf:
.word SLAVE_W_8BIT, SLAVE_W_9BIT, SLAVE_W_10BIT, SLAVE_W_11BIT, SLAVE_W_12BIT
b_temp: .hword 0x271, 0x4E2, 0x9C4, 0x1388
w_pit_timer: .word PIT_TIMER_1200ms
b_inc_dec: .byte 0
b_offset: .byte 16
b_ISR: .byte 0
str_conv_75ms: .asciz "Wandlungszeit betraegt 75ms.\n"
str_conv_150ms: .asciz "Wandlungszeit betraegt 150ms.\n"
str_conv_300ms: .asciz "Wandlungszeit betraegt 300ms.\n"
str_conv_600ms: .asciz "Wandlungszeit betraegt 600ms.\n"
str_conv_1200ms: .asciz "Wandlungszeit betraegt 1200ms.\n"
str_grad: .asciz " gC\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


// Registeradressen
.equ SIM_SCGC6, 	0x4004803C

.equ RTC_TSR,		0x4003D000
.equ RTC_TAR,		0x4003D008
.equ RTC_CR,		0x4003D010
.equ RTC_SR,		0x4003D014

.equ PIT_MCR, 		0x40037000
.equ PIT_LDVAL1,	0x40037110
.equ PIT_TCTRL1,	0x40037118
.equ PIT_TFLG1, 	0x4003711C

.equ NVIC_ISER2,	0xE000E108
.equ IVT_BASE, 		0x1FFFFE00		// Baisadresse der Interrupt-Vektor-Tabelle
.equ IVT_PIT1, IVT_BASE + 0x154

// Bit Band-Konstanten
__BBREG SIM_PIT, SIM_SCGC6, 23
__BBREG SIM_RTC, SIM_SCGC6, 29

__BBREG PIT_TIF, PIT_TFLG1, 0

__BBREG RTC_TAF, RTC_SR, 2
__BBREG RTC_TCE, RTC_SR, 4
__BBREG RTC_OSCE, RTC_CR, 8

// Konfiguration
.equ DAY_ALARM,		86399		// 23:59:59 [hh:mm:ss]
.equ HOUR_ALARM,	3599		// 59:59 [mm:ss]
.equ PRESET_DAY,	86395		// 23:59:55 [hh:mm:ss]
.equ PRESET_HOUR,	3595		// 59:55 [mm:ss]
.equ PIT_TIMER_1s, 	24999999	// (1s/25Mhz) -1  = 24.999.999d = 0x17D783F

.equ CONST_60, 		60
.equ LF,	 		10
.equ DPUNKT, 		58

main:	
	bl uart_init
	
// Fuer die Initialisierung haeufig verwendete Werte vorbelegen
	mov r10, #0
	mov r11, #1

// Takt fuer die benutzten Module aktivieren	
	ldr r0, =SIM_PIT
	str r11, [r0]
	ldr r0, =SIM_RTC
	str r11, [r0]
	
// Adressen der ISRs in die IVT eintragen
	ldr r0, =IVT_PIT1
	ldr r1, =isr_pit1
	str r1, [r0]

// NVIC-Bitmaske fuer PIT setzen
	ldr r0, =NVIC_ISER2
	mov r1, 0x20
	str r1, [r0]

// Initialisierung PIT-Modul
	ldr r0, =PIT_MCR			
	str r11, [r0]			// FRZ=1 (Debug Mode); MDIS=0 (0=Clock enabled)(MDIS=ModuleDisabled)
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_TIMER_1s
	str r1, [r0]

// Initialisierung RTC
	ldr r0, =RTC_OSCE
	str r11, [r0]
	ldr r8, =RTC_TSR		// implizit clears TIF/TOF
	str r10, [r8]
	ldr r0, =RTC_TAR
	ldr r1, =DAY_ALARM		// implizit clears TAF
	str r1, [r0]
	ldr r0, =RTC_TCE		// Starte RTC
	str r11, [r0]
	
//  Starte Timer
	ldr r0, =PIT_TCTRL1
	mov r1, #3				// Timer Enable=1, Timer Interrupt Enable=1, Chain Mode=0
	str r1, [r0]

// Vorbelegung verwendeter Register
	mov r7, #1 				// Flag fuer Anzeige An:1 / Aus:0
	// r8 = RTC_TSR bereits in Init gesetzt
	ldr r9, =b_end
	ldr r12, =b_ISR
	
mainloop:
	ldrb r0, [r12]			
	cmp r0, #0				// PIT1 abgelaufen?
	beq no_output

	strb r10, [r12]			// loesche ISR Flag
	ldr r0, =b_osci			// 1Sekunde zum einschwingen
	ldrb r1, [r0]
	cmp r1, #0
	itt eq
	strbeq r11, [r0]
	beq time_reset
	
	ldrb r0, [r9]			// Ende bereits erreicht?
	cbnz r0, no_output		// ja, dann keine Ausgabe
	cbz r7, no_output		// Sopp-Bit gesetzt? Dann keine Ausgabe
	
	ldr r0, =RTC_TAF		// Endzeitpunkt?
	ldr r0, [r0]
	cmp r0, #1
	itttt eq
	moveq r4, #1
	streq r11, [r9]			// in data speichern
	ldreq r0, =str_ende
	bleq uart_putString
	
	cmp r4, #1				// verhindert Ausgabe nach dem Endzeitpunkt
	itt eq
	moveq r4, #0
	beq mainloop

	ldr r0, [r8]			// lade RTC Sekunden
	
	mov r3, CONST_60
	udiv r1, r0, r3			// r1 = Sekunden / 60 -> r1 = minuten
	mls r6, r1, r3, r0		// r6 = r0 - (r1 * r3) -> r6 = restliche sekunden
	
	udiv r0, r1, r3			// r0 = Minuten / 60 -> r0 = stunden
	mls r5, r0, r3, r1		// r5 = r1 - (r0 * r3) -> r5 = restliche minuten
	
	ldr r1, =b_24h			// 1h oder 24h Ausgabe?
	ldr r1, [r1]
	cmp r1, #0
	it eq
	beq ausgabe_1h
	
// Ausgabe der Uhrzeit
	cmp r0, #0x9				// führende Null notwendig?
	ite ls						// passendes Unterprogramm (mit/ohne führende Null)auswählen
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	mov r0, #DPUNKT
	bl uart_putChar

ausgabe_1h:
	mov r0, r5					// Ausgabe Minuten
	cmp r5, #0x9				// führende Null notwendig?
	ite ls						// passendes Unterprogramm (mit/ohne führende Null)auswählen
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	
	mov r0, #DPUNKT
	bl uart_putChar
	
	mov r0, r6					// Ausgabe Sekunden
	cmp r6, #0x9				// führende Null notwendig?
	ite ls						// passendes Unterprogramm (mit/ohne führende Null)auswählen
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1

	mov r0, #LF					// neue Zeile
	bl uart_putChar

no_output:
	bl uart_charPresent			// wurde ein Zeichen eingegeben?
	cmp r0, #0
	beq mainloop				// nein, also zurueck zur Hautschleife
	
	bl uart_getChar				// Zeichen einlesen
	
	cmp r0, #'d'				// 'd' eingegeben?
	beq set_day_hour			// ja, also zu set_day_hour verzweigen
	
	cmp r0, #'h'				// 'h' eingegeben?
	beq set_day_hour			// ja, also zu set_day_hour verzweigen
	
	cmp r0, #'r'				// 'r' eingegeben?
	beq time_reset				// ja, also zu time_reset verzweigen		
	
	cmp r0, #'s'				// 's' eingegeben?
	beq startstop				// ja, also zu startstop verzweigen

	cmp r0, #'p'				// 'p' eingegeben?
	beq preset					// ja, also zu preset verzweigen

	b mainloop					// Zeichen nicht definiert

set_day_hour:
	ldr r1, =b_24h
	cmp r0, #'d'				// 1h/24h Modus in data sichern
	ite eq
	streq r11, [r1]
	strne r10, [r1]
	
	cmp r0, #'d'				// 1h/24h Modus? ('d' oder 'h' gedrueckt?)
	ittee eq
	ldreq r0, =str_24h
	ldreq r4, =DAY_ALARM
	ldrne r0, =str_1h
	ldrne r4, =HOUR_ALARM
	bl uart_putString			// Ausgabe: 1h/24h-Modus	
	
	ldr r1, =RTC_TCE			// Stoppe RTC
	str r10, [r1]
	ldr r0, =RTC_TSR			// Zeit ruecksetzen
	str r10, [r0]
	ldr r0, =RTC_TAR		
	str r4, [r0]				// setze 1h/24h Alarm
	str r11, [r1]				// Starte RTC
	b mainloop

time_reset:
	ldr r0, =str_reset
	bl uart_putString			// Ausgabe: Zeit reset
	ldr r1, =RTC_TCE			// Stoppe RTC
	str r10, [r1]
	ldr r0, =RTC_TSR			// Zeit ruecksetzen
	str r10, [r0]
	ldr r0, =RTC_TAR			// TAR erneut schreiben -> setzt TAF zurueck	
	ldr r2, [r0]
	str r2, [r0]
	str r10, [r9]				// setze Endzeitpunkt zurueck
	str r11, [r1]				// Starte RTC
	b mainloop

preset:
	ldr r0, =str_preset
	bl uart_putString			// Ausgabe: Uhr vorstellen
	
	ldr r0, =b_24h
	ldr r0, [r0]
	cmp r0, #0					// 1h oder 24h Modus?
	ite eq
	ldreq r0, =PRESET_HOUR
	ldrne r0, =PRESET_DAY
	
	ldr r1, =RTC_TCE			// Stoppe RTC
	str r10, [r1]
	ldr r2, =RTC_TSR			// Zeit vorstellen
	str r0, [r2]
	str r11, [r1]				// Starte RTC
	b mainloop

startstop:
	eors r7, r7, #1				// Flag invertieren, Status setzen
	ite eq						// 0: Start, 1: Stop
	ldreq r0, =str_anzeige_aus
	ldrne r0, =str_anzeige_an
	bl uart_putString			// entsprechenden String (R0) ausgeben
	b mainloop

	
/* Interrupt Service Routine "isr_pit1"--------------------------------------*/
// Wird zyklisch von PIT-1 aufgerufen, Zahelerwert aus w_pit_timer.
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
isr_pit1:
	mov r1, #1
	ldr r0, =PIT_TIF		// loesche PIT Timer Interrupt Flag
	str r1, [r0]
	ldr r0, =b_ISR			// setze Flag für Hauptprogramm
	strb r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
b_ISR: .byte 0
b_osci: .byte 0
b_end: .byte 0
b_24h: .byte 0x1
str_24h: .asciz "24-Stunden-Modus\n"
str_1h: .asciz "1-Stunden-Modus\n"
str_reset: .asciz "Uhr zurueckgesetzt\n"
str_anzeige_an: .asciz "Anzeige an\n"
str_anzeige_aus: .asciz "Anzeige aus\n"
str_preset: .asciz "Uhr vorgestellt\n"
str_ende: .asciz "Endzeitpunkt erreicht\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


// Registeradressen
.equ SIM_SCGC5,		0x40048038
.equ SIM_SCGC6, 	0x4004803C

.equ GPIOA_PDOR,    0x400FF000
.equ GPIOA_PDDR,    0x400FF014

.equ PORTA_PCR6,	0x40049018
.equ PORTA_PCR10,	0x40049028

.equ RTC_TSR,		0x4003D000
.equ RTC_TAR,		0x4003D008
.equ RTC_CR,		0x4003D010
.equ RTC_SR,		0x4003D014

.equ PIT_MCR, 		0x40037000
.equ PIT_LDVAL0,    0x40037100
.equ PIT_TCTRL0,    0x40037108
.equ PIT_TFLG0,     0x4003710C
.equ PIT_TCTRL1,	0x40037118
.equ PIT_LDVAL1,	0x40037110
.equ PIT_TFLG1, 	0x4003711C


.equ NVIC_ISER2,	0xE000E108
.equ IVT_BASE, 		0x1FFFFE00		// Baisadresse der Interrupt-Vektor-Tabelle
.equ IVT_PIT0, IVT_BASE + 0x150
.equ IVT_PIT1, IVT_BASE + 0x154


// Bit Band-Konstanten
__BBREG SIM_PORTA, SIM_SCGC5, 9
__BBREG SIM_PIT, SIM_SCGC6, 23
__BBREG SIM_RTC, SIM_SCGC6, 29

__BBREG PIT0_TIF, PIT_TFLG0, 0
__BBREG	PIT0_TEN, PIT_TCTRL0, 0
__BBREG PIT1_TIF, PIT_TFLG1, 0

__BBREG RTC_TAF, RTC_SR, 2
__BBREG RTC_TCE, RTC_SR, 4
__BBREG RTC_OSCE, RTC_CR, 8

__BBREG GPIOA_LED_10, GPIOA_PDOR, 10
__BBREG GPIOA_PTA6, GPIOA_PDOR, 6

// Konfiguration
.equ PIT_TIMER_1s, 	24999999	// (1s/25Mhz) -1  = 24.999.999d = 0x17D783F
.equ TIME_100MS,	2500000		// 100ms 
.equ TIME_200MS,	5000000		// 200ms

.equ GPIO_MODE, 0x120 			// GPIO-Modus, Open Drain
.equ PDDR_MASK_LED, (1<<6 | 1<<10)	// Maske fuer die LED und PTA6

.equ CONST_60, 		60
.equ LF,	 		10
.equ DPUNKT, 		58
.equ HEADER_PAR,	0x10120000
.equ HEADER,		0x120000
.equ PARITY_DATE,	0x20000000


main:	
	bl uart_init
	
// Fuer die Initialisierung haeufig verwendete Werte vorbelegen
	mov r10, #0
	mov r11, #1

// Takt fuer die benutzten Module aktivieren	
	ldr r0, =SIM_PIT
	str r11, [r0]
	ldr r0, =SIM_RTC
	str r11, [r0]
	ldr r0, =SIM_PORTA	
	str r11, [r0]
	
// Adressen der ISRs in die IVT eintragen
	ldr r0, =IVT_PIT1
	ldr r1, =isr_pit1
	str r1, [r0]

	ldr r0, =IVT_PIT0
	ldr r1, =isr_pit0
	str r1, [r0]

// NVIC-Bitmaske fuer PIT-0 und PIT-1 setzen
	ldr r0, =NVIC_ISER2
	mov r1, 0x30
	str r1, [r0]

// Initialisierung PIT-Modul
	ldr r0, =PIT_MCR			
	str r11, [r0]			// FRZ=1 (Debug Mode); MDIS=0 (0=Clock enabled)(MDIS=ModuleDisabled)
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_TIMER_1s
	str r1, [r0]
	
// GPIO-Pin konfigurieren
	ldr r1, =GPIO_MODE 			// GPIO-Modus (mit Open-Drain) festlegen
	ldr r0, =PORTA_PCR10
	ldr r2, =PORTA_PCR6  	
	str r1, [r0]
	str r1, [r2]

// Datenrichtung der GPIO-Pins festlegen
	ldr r0, =PDDR_MASK_LED
	ldr r1, =GPIOA_PDDR
	ldr r2, [r1]
	orr	r2, r2, r0
	str r2, [r1]

	ldr r0, =GPIOA_LED_10
	str r11, [r0]			// LED aus
	ldr r0, =GPIOA_PTA6
	str r11, [r0]

// Initialisierung RTC
	ldr r0, =RTC_OSCE
	str r11, [r0]
	ldr r8, =RTC_TSR
	str r10, [r8]
	ldr r0, =RTC_TCE		// Starte RTC
	str r11, [r0]
	
//  Starte Timer Pit-1
	ldr r0, =PIT_TCTRL0		// Pit-0: Timer Interrupt Enable
	mov r1, #2
	str r1, [r0]
	ldr r0, =PIT_TCTRL1		// Pit-1: Timer Enable, Timer Interrupt Enable
	mov r1, #3
	str r1, [r0]

// Vorbelegung verwendeter Register
	ldr r5, =datetime		// Basisadresse des Arrays laden
	ldr r9, =datetime			// Zeiger auf das Zeit-/Datum-Array
	ldr r12, =b_ISR
	
	ldr r0, =str_send
	bl uart_putString
	b calc
	
mainloop:
	bl	uart_charPresent	// wurde ein Zeichen eingegeben?
	cmp r0, #0
	it ne
	bne check_input			// ja, pruefen
	
	ldrb r0, [r12]	
	cmp r0, #0				// PIT 1s abgelaufen?
	beq mainloop
	
	strb r10, [r12]			// loesche ISR Flag

// Sende Daten auf PTA-6 und LED
	ldr r0, =b_send_counter
	ldrb r1, [r0]
	cmp r1, #59
	it eq
	beq one_low

	cmp r1, #28				// wie viele Daten wurde bereits gesendet?
	add r1, r1, #1			// Ausgabe Zaehler inkrementieren, 1 wurde unten schon geschickt
	strb r1, [r0]
	
	it ls
	bls reg_low				// register low sendet 29 Daten
	
	lsrs r7, r7, #1			// register high sendet 30 Daten
	ite cs
	movcs r0, #1
	movlo r0, #0
	bl send_data

	b no_output

reg_low:
	lsrs r6, r6, #1			// Shifte Daten aus r6(low) aus
	ite cs
	movcs r0, #1
	movlo r0, #0
	bl send_data

	b no_output

one_low:					// Ausgabe 59 low
	mov r0, #0
	bl send_data

no_output:
	ldr r0, [r8]			// lade RTC Sekunden
	mov r1, CONST_60
	udiv r0, r0, r1			// r0 = Sekunden / 60 -> r0 = Minuten
	
	ldrb r2, [r5, #4]		// Minuten laden
	cmp r0, r2				// Vergleiche aktuelle Minuten mit gepeicherten
	it eq
	beq mainloop			// gleich? dann warte

// Eine Minute ist um, aktualisiere und sende Zeit
	bl inc_datetime			// inkrementiere Datum
	ldr r0, =str_send
	bl uart_putString
	
	ldr r0, =b_send_counter	// Counter auf 0 setzen
	strb r10, [r0]

calc:
// Berechnung Minuten
	ldrb r0, [r5, #4]		// Minuten laden
	bl bin_to_bcd
	mov r2, r0, lsl #21		// sichern in richtem Format ab Bit_21 -> [mm]
	
	mov r1, #0				// counter
loop_min:					// Berechne Paritaet
	lsrs  r0, r0, #1		// shift r0 nach rechts bis 0
    it cs
    addcs r1, r1, #1        // r1 + 1, wenn 1 rausgeshiftet
	bne loop_min
    tst r1, #1              // r1==gerade? setze Z-Flag
    ite ne
    ldrne r0, =HEADER_PAR	// setze parity bit, wenn ungerade
    ldreq r0, =HEADER

    orr r6, r2, r0

// Berechnung Stunden
	ldrb r0, [r5, #3]		// Stunden laden
	bl bin_to_bcd
	mov r3, r0				// sichern in richtigem Format
	
	mov r1, #0				// counter
loop_std:					// Berechne Paritaet
	lsrs  r0, r0, #1		// shift r0 nach rechts bis 0
    it cs
    addcs r1, r1, #1        // r1 + 1, wenn 1 rausgeshiftet
	bne loop_std
    tst r1, #1              // r1==gerade? setze Z-Flag
    ite ne
    orrne r7, r3, #0x40		// setze parity bit, wenn ungerade
    moveq r7, r3			// Zwischenergebnis in r7 sichern

// Berechnung Datum
	ldrb r0, [r5]			// Tag laden
	bl bin_to_bcd
	mov r4, r0				// sichern in richtigem Format

// Wochentag auf Samstag (ist nämlicher der beste Tag der Woche) -> 6
	mov r0, #6
	orr r4, r4, r0, lsl #6
	
	ldrb r0, [r5, #1]		// Monat laden
	bl bin_to_bcd
	orr r4, r4, r0, lsl #10	// sichern in richtigem Format


	ldrb r0, [r5, #2]		// Jahr laden
	bl bin_to_bcd
	orr r4, r4, r0, lsl #15		// sichern in richtigem Format
	
	mov r0, r4				// r0 nicht verschoben, da Paritaet fehlt
	orr r7, r7, r4, lsl #7	// r4 (Datum) verschieben wegen Stunden
	mov r1, #0				// counter
loop_datum:					// Berechne Paritaet
	lsrs  r0, r0, #1		// shift r0 nach rechts bis 0
    it cs
    addcs r1, r1, #1        // r1 + 1, wenn 1 rausgeshiftet
	bne loop_datum
    tst r1, #1              // r1==gerade? setze Z-Flag
    itt ne
    ldrne r0, =PARITY_DATE
    orrne r7, r4, r0		// setze parity bit, wenn ungerade

// Ausgabe der Uhrzeit auf dem Terminal
	ldrb r0, [r5, #3]			// Stunden laden und Ausgabe
	cmp r0, #0x9
	ite ls						// passendes Unterprogramm (mit/ohne führende Null)auswählen
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	mov r0, #DPUNKT
	bl uart_putChar

	ldrb r0, [r5, #4]			// Minuten laden und Ausgabe
	cmp r0, #0x9
	ite ls						// passendes Unterprogramm (mit/ohne führende Null)auswählen
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	
	mov r0, #DPUNKT
	bl uart_putChar
	
	mov r0, #0					// Ausgabe Sekunden
	bl uart_putByte

	mov r0, #LF					// neue Zeile
	bl uart_putChar
	
// Sende Daten auf PTA-6 und LED
	lsrs r6, r6, #1
	ite cs
	movcs r0, #1
	movlo r0, #0
	bl send_data
	ldr r0, =str_piu			//TEST
	bl uart_putString
	ldr r0, =b_send_counter
	mov r1, #1					// Anzahl der Übertragungen auffrischen
	strb r1, [r0]

	b mainloop

check_input:
	bl	uart_getChar			// eingegebenes Zeichen einlesen
	cmp r0, #'t'				// war es ein 't'?
	beq ci_t					// ja, verzeigen
	cmp r0, #'d'				// war es ein 'd'?
	beq ci_d					// ja, verzeigen
	b mainloop					// keine gueltige Eingabe, normal weitermachen

ci_t:
	ldr r4, =RTC_TCE			// Stoppe RTC
	str r10, [r4]
	ldr r0, =str_std			// Text zur Stundenabfrage waehlen,
	bl	echo_input				// ausgeben und Eingabe abholen
	strb r0, [r9, #3]			// abspeichern
	ldr r0, =str_min			// gleicher Vorgang fuer die Minuten
	bl	echo_input
	strb r0, [r9, #4]
	ldr r2, =RTC_TSR
	mov r1, #60
	mul r0, r0, r1
	str r0, [r2]				// Zeit verstellen
	str r11, [r4]				// Starte RTC
	b calc						// Berechne Daten neu

ci_d:
	ldr r4, =RTC_TCE			// Stoppe RTC
	str r10, [r4]
	ldr r0, =str_tag			// Text zur Tagesabfrage waehlen,
	bl	echo_input				// ausgeben und Eingabe abholen
	strb r0, [r9]				// abspeichern
	ldr r0, =str_mon			// gleicher Vorgang fuer den Monat 
	bl	echo_input
	strb r0, [r9, #1]
	ldr r0, =str_jhr			// gleicher Vorgang fuer das Jahr
	bl	echo_input
	strb r0, [r9, #2]
	ldrb r0, [r5, #4]			// Minuten laden und im TSR neu setzen
	ldr r2, =RTC_TSR
	mov r1, #60
	mul r0, r0, r1
	str r0, [r2]				// Zeit verstellen
	str r11, [r4]				// Starte RTC
	b 	calc					// Berechne Daten neu

/* Interrupt Service Routine "isr_pit0"--------------------------------------*/
// Wird zyklisch jede Sekunde für 100ms oder 200ms eingeschalten.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
isr_pit0:
	mov r1, #1
	ldr r0, =PIT0_TIF		// loesche PIT Timer Interrupt Flag
	str r1, [r0]
	
	ldr r0, =GPIOA_LED_10	// LED aus
	str r1, [r0]
	ldr r0, =GPIOA_PTA6		// Impuls aus
	str r1, [r0]
	
	mov r0, #0				// PIT0
	ldr r1, =PIT0_TEN		// Timer Enable Flag
	str r0, [r1]			// zuruecksetzen => PIT0 deaktivieren

	bx lr


/* Interrupt Service Routine "isr_pit1"--------------------------------------*/
// Wird zyklisch von PIT-1 aufgerufen, Zahelerwert aus w_pit_timer.
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
isr_pit1:
	mov r1, #1
	ldr r0, =PIT1_TIF		// loesche PIT Timer Interrupt Flag
	str r1, [r0]
	ldr r0, =b_ISR			// setze Flag für Hauptprogramm
	strb r1, [r0]
	bx lr


/* Gibt den Text (Zeiger in r0) aus und liest einen zweistelligen Dezimalwert ein, 
 * gibt ihn (zur Kontrolle) wieder aus, haengt einen Zeilenumbruch an
 * und gibt den Wert in r0 zurueck
 * Parameter: r0 = Zeiger auf Text
 * Rueckgabe: eingelesener Wert
 */		
.thumb_func
echo_input:
	push {r4,lr}
	bl	uart_putString				// Uebergebenen String ausgeben
	bl	uart_getByteBase10			// einen zweistelligen Dezimalwert einlesen
	mov r4, r0						// sichern
	bl out_leading0					// Wert ausgeben, ggf. mit führender Null
	mov	r0, #LF						// neue Zeile
	bl	uart_putChar				// ausgeben
	mov r0, r4						// gesicherten Wert zurueckgeben
	pop {r4,pc}

/* Funktion "send_data"------------------------------------------------------*/
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
//
// Übergabeparameter: r0 (data to be send)
// Rückgabeparameter: void
.thumb_func
send_data:
	push {lr}
	
	ldr r2, =PIT_LDVAL0
	cmp r0, #1
	itte eq
	ldreq r1, =TIME_200MS		// 200ms bei einer 1
	moveq r0, #1
	ldrne r1, =TIME_100MS		// 100ms bei einer 0
	str r1, [r2]			

	bl uart_putByteBase10
	
	mov r0, #1
	ldr r1, =PIT0_TEN			// Enable Pit-0
	str r0, [r1]
	mov r0, #0				
	ldr r1, =GPIOA_LED_10		// LED an
	str r0, [r1]
	ldr r1, =GPIOA_PTA6			// Impuls an
	str r0, [r1]

	pop {pc}

/* Funktion "bin_to_bcd"-----------------------------------------------------*/
// Wandelt bin in bcd um
//
// Übergabeparameter: r0, data in bin
// Rückgabeparameter: r0, data in bcd
.thumb_func
bin_to_bcd:
	mov r1, #10
	udiv r2, r0, r1			// r2 = Monat / 10; r2 = Zehner Stelle
	mls r1, r2, r1, r0		// r1 = r0 - (r2 * r1): r1 = Einer Stelle
	orr r0, r1, r2, lsl #4	// Ergebnis r0 = r1|(r2<<4)

	bx lr


/*
 * Gibt bei Zahlen < 10 eine fuehrende Null aus
 * Parameter: Zahl in R0
 * Rueckgabe: keine
 */		
.thumb_func
out_leading0:
	push {lr}
	cmp r0, #10						// >= 10? 
	ite hs
	ldrhs r1, =uart_putByteBase10	// ohne fuehrende Null
	ldrlo r1, =uart_putByte			// mit fuehrender Null
	blx r1							// entsprechendes UP aufrufen
	pop {pc}

/*
 * Inkrementiert zunaechst nur die Minuten, bei einem Ueberlauf auch die jeweils naechsthoehere Einheit
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
inc_datetime:
	ldr r1, =datetime				// Basisadresse des Arrays laden

	ldrb r0, [r1, #4]				// Minuten laden
	add	r0, r0, #1					// inkrementieren
	cmp	r0, #60						// mit Maximum vergleichen
	it hs							// Überlauf?
	movhs r0, #0					// dann Reset-Wert laden
	strb r0, [r1, #4]				// Minuten zurückschreiben
	blo inc_datetime_end			// kein Überlauf? 
	
	ldrb r0, [r1, #3]				// Stunden laden
	add	r0, r0, #1					// inkrementieren
	cmp	r0, #24						// mit Maximum vergleichen
	it hs							// Überlauf?
	movhs r0, #0					// dann Reset-Wert laden
	strb r0, [r1, #3]				// Stunden zurückschreiben
	blo inc_datetime_end			// kein Überlauf? 
	
	ldrb r0, [r1]					// Tag laden
	add	r0, r0, #1					// inkrementieren
	cmp	r0, #30						// mit Maximum vergleichen
	it hs							// Überlauf?
	movhs r0, #1					// dann Reset-Wert laden
	strb r0, [r1]					// Tag zurückschreiben
	blo inc_datetime_end			// kein Überlauf? 
	
	ldrb r0, [r1, #1]				// Monat laden
	add	r0, r0, #1					// inkrementieren
	cmp	r0, #12						// mit Maximum vergleichen
	it hs							// Überlauf?
	movhs r0, #1					// dann Reset-Wert laden
	strb r0, [r1, #1]				// Monat zurückschreiben
	blo inc_datetime_end			// kein Überlauf? 
	
	ldrb r0, [r1, #2]				// Jahr laden
	add	r0, r0, #1					// inkrementieren
	cmp	r0, #100					// mit Maximum vergleichen
	it hs							// Überlauf?
	movhs r0, #0					// dann Reset-Wert laden
	strb r0, [r1, #2]				// Jahr zurückschreiben
	
inc_datetime_end:
	bx lr	


/*** Datenbereich (ab 0x20000000) ***/
.data
b_ISR: .byte 0
b_send_counter: .byte 0
datetime: .byte 1,1,14,1,0		// Tag, Monat, Jahr, Stunde, Minute
str_std: .asciz "\nStunde eingeben (hh): "
str_min: .asciz "Minute eingeben (mm): "
str_tag: .asciz "Tag eingeben (dd): "
str_mon: .asciz "Monat eingeben (mm): "
str_jhr: .asciz "Jahr eingeben (jj): "
str_send: .asciz "\nUebertrage als DCF-77:"
str_piu: .asciz "Piu\n"
str_zwei: .asciz " 2_"
str_cnt: .asciz "\nC:"
str_low: .asciz "low\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


// Registeradressen
.equ SIM_SCGC5,		0x40048038
.equ SIM_SCGC6, 	0x4004803C

.equ PORTA_PCR6,	0x40049018

.equ FTM0_SC,		0x40038000
.equ FTM0_CNT, 		0x40038004
.equ FTM0_MOD, 		0x40038008
.equ FTM0_CNTIN,	0x4003804C
.equ FTM0_COMBINE,	0x40038064
.equ FTM0_C3SC,		0x40038024
.equ FTM0_C3V,		0x40038028
.equ FTM0_FMS,		0x40038074
.equ FTM0_QDCTRL,	0x40038080
.equ FTM0_MODE,		0x40038054

.equ NVIC_ISER1,	0xE000E104
.equ IVT_BASE, 		0x1FFFFE00		// Baisadresse der Interrupt-Vektor-Tabelle
.equ IVT_FTM0, IVT_BASE + 0x138

.equ TIME_1MS,	25000		// 1ms

// Bit Band-Konstanten
__BBREG SIM_PORTA, SIM_SCGC5, 9
__BBREG SIM_FTM0, SIM_SCGC6, 24

__BBREG FTM0_TOF, FTM0_SC, 7
__BBREG FTM0_WPEN, FTM0_FMS, 6
__BBREG FTM0_WPDIS, FTM0_MODE, 2
__BBREG FTM0_FMEN, FTM0_MODE, 0

.equ FTM_MODE,	 		0x320 		// ALT3-Modus, Open Drain
.equ PDDR_MASK, 		(1<<6)		// Maske fuer PTA6

.equ FTM0_SC_KONF, 		0x48		// Sys-Clock, Up-Counting, T-Overflow
.equ FTM0_C3SC_KONF, 	0x68		// Edge Aligned PWM, High
.equ FTM0_COMBINE_KONF, 0

main:
	bl uart_init
	
// Fuer die Initialisierung haeufig verwendete Werte vorbelegen
	mov r10, #0
	mov r11, #1

// Takt fuer die benutzten Module aktivieren	
	ldr r0, =SIM_PORTA	
	str r11, [r0]
	ldr r0, =SIM_FTM0
	str r11, [r0]

// Adressen der ISR in die IVT eintragen
	ldr r0, =IVT_FTM0
	ldr r1, =isr_ftm0
	str r1, [r0]

// NVIC-Bitmaske fuer FTM0 setzen
	ldr r0, =NVIC_ISER1
	mov r1, (1<<30)
	str r1, [r0]

// Pin konfigurieren
	ldr r1, =FTM_MODE 				// ALT3-Modus (mit Open-Drain) festlegen
	ldr r0, =PORTA_PCR6  	
	str r1, [r0]

// FTM Init
	 ldr r0, =FTM0_WPEN				// Schreiben der Register
	 ldr r2, [r0]
	 cmp r2, #1
	 itt eq
	 ldreq r0, =FTM0_WPDIS
	 streq r11, [r0]
	 
	 ldr r0, =FTM0_FMEN
	 str r11, [r0]
	 
	 ldr r0, =FTM0_CNTIN
	 str r11, [r0]
	 
	 ldr r0, =FTM0_CNT
	 str r11, [r0]
	 
	 ldr r0, =FTM0_C3V
	 ldr r1, =tab_c3v
	 ldr r2, [r1, #5]				// 50% Duty Cycle
	 str r2, [r0]
	 
	 ldr r0, =FTM0_SC
	 ldr r1, =FTM0_SC_KONF
	 str r1, [r0]
	 
	 ldr r0, =FTM0_C3SC
	 ldr r1, =FTM0_C3SC_KONF		// Interupt enable, Edge aligned
	 str r1, [r0]
	 
	 ldr r0, =FTM0_QDCTRL			// Disable QUADEN
	 str r10, [r0]
	 
	 ldr r0, =FTM0_COMBINE			// Disable DECAPEN, COMBINE
	 str r10, [r0]
	 
	 ldr r0, =FTM0_MOD
	 ldr r1, =TIME_1MS
	 str r1, [r0]
	 
	 
	ldr r0, =str_prompt
	bl uart_putString
		
mainloop:
	bl	uart_charPresent		// wurde ein Zeichen eingegeben?
	cmp r0, #0
	it eq
	beq mainloop				// ja, pruefen
	
	bl	uart_getChar			// eingegebenes Zeichen einlesen
	cmp r0, #'-'				// war es ein '-'?
	beq ci_pm					// ja, verzeigen
	cmp r0, #'+'				// war es ein '+'?
	beq ci_pm					// ja, verzeigen
	cmp r0, #0x30				// Zeichen zwischen 0 und
	it lo
	blo mainloop
	cmp r0, #0x39				// 9?
	it ls
	bls ci_z					// ja, verzeigen
	b mainloop					// keine gueltige Eingabe, normal weitermachen

ci_pm:
	bl	echo_input
	ldr r0, =str_prompt
	bl uart_putString
	b mainloop
	
ci_z:
	bl	echo_input
	ldr r1, =tab_c3v
	ldrh r2, [r1, r0]
	ldr r0, =FTM0_C3V
	str r2, [r0]				// Impulsdauer updaten
	ldr r0, =str_prompt
	bl uart_putString
	b mainloop
	

/* Interrupt Service Routine "isr_ftm0"--------------------------------------*/
// Wird zyklisch von PIT-1 aufgerufen, Zahelerwert aus w_pit_timer.
// Setzt Benutzer-Flag b_ISR_1s im .data auf 1.
//
// Übergabeparameter: void
// Rückgabeparameter: void
/*---------------------------------------------------------------------------*/
.thumb_func
isr_ftm0:
	mov r1, #1

	bx lr


/* Gibt den Text (Zeiger in r0) aus und liest einen zweistelligen Dezimalwert ein, 
 * gibt ihn (zur Kontrolle) wieder aus, haengt einen Zeilenumbruch an
 * und gibt den Wert in r0 zurueck
 * Parameter: r0 = Zeiger auf Text
 * Rueckgabe: eingelesener Wert
 */		
.thumb_func
echo_input:
	push {r4,lr}
	mov r4, r0					// sichern
	bl uart_putByte				// Zeichen ausgeben
	mov r0, r4					// gesicherten Wert zurueckgeben
	pop {r4,pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
b_sign: .byte 0
str_prompt: .asciz "\n<"
tab_pwm: .byte 5, 15, 25, 35, 45, 55, 65, 75, 85, 95
tab_c3v: .hword 1250, 3750, 6250, 8750, 11250, 13750, 16250, 18750, 21250, 23750
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklarationen
.equ COUNTER, 0x10

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

beginn_eingabe:
	//16 Byte Einlesen
	mov r4, #COUNTER		//Schleifenzaehler initialisieren
	ldr r5, =bytearray		//Speicheradresse der Eingabe
	ldr r0, =str_eingabe	//Zeiger auf String laden
	bl uart_putString 		//String ausgeben
	
loop_eingabe:
	ldr r0, =str_promt 		//Zeiger auf Promt
	bl uart_putString		//Promt ausgeben
	bl uart_getByte			//Byte einlesen
	strb r0, [r5], #1		//eingelesenes Byte (r0) in die von r5 addressierte Speichestelle speichern, Postinkrement
	bl uart_putByte			//eingelesenes Byte ausgeben
	subs r4, r4, #1			//r4 dekrementieren
	bne loop_eingabe
	
	
	//Maximumsbestimmung
	ldr r0, =str_startsuche
	bl uart_putString		//Start Suche ausgeben
	
	bl pit3_init
	bl pit3_getval
	mov r7, r0
	
	mov r9, #0				//Maximum mit 0 initialisieren
	mov r4, #COUNTER

loop_maximum:
	ldrb r0, [r5, #-1]!		//byte aus Array auslesen; Prädekrement
	cmp r0, r9				//Vergleichen
	it hi					//wenn groesser ist
	movhi r9, r0			//Maximum ersetzen
	subs r4, r4, #1			//Zaehler dekerementieren
	bne loop_maximum
	
	//Timer zwischenspeichern
	bl pit3_getval
	mov r8, r0
	
	//Maximum speichern
	ldr r0, =maximum
	strb r9, [r0]
	
	//Maximum ausgeben
	ldr r0, =str_endesuche
	bl uart_putString
	mov r0, r9
	bl uart_putByte
	
	//Suchzeit ausgeben
	ldr r0, =str_suchzeit
	bl uart_putString
	sub r0, r7, r8
	bl uart_putInt16
	
	//Zurueck zur Eingabe
	b beginn_eingabe
	
	

/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
.rept COUNTER
.byte 0x00
.endr
maximum: .byte 0x00

str_promt: .asciz "\n>0x"
str_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben!\n"

str_startsuche: .asciz "\nDurchsuchen gestartet"
str_endesuche:  .asciz "\nDurchsuchen beendet\nMaximum: "
str_suchzeit: .asciz "\nSuchzeit: "


/** Suchzeit:
Die Suchzeit ist von der Position des Maximus unabhängig. Es wird immer das komplette Array verglichen. 
Da für das Schreiben eines neugefundenen Maximus ins Register r9 keine Verzweigung sondern ein IT Block verwendet wird,
 hat auch dies keine Auswirkung auf die Suchzeit. Die  
**/

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten
.equ BitBandAdresse, 0x22000200 //Start des BitBands für Adresse 0x20000010
.equ EingabeMaske, 0x1F

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	mov r6, #0x01
	mov r7, #0x00
	
bitnummern_einlesen:
	//Bitnummern einlesen
	ldr r0, =str_eingabe0
	bl uart_putString
	bl uart_getByte
	and r4, r0, #EingabeMaske //Eingabe auf 5 Bits begrenzen
	mov r0, r4
	bl uart_putByte
		
	ldr r0, =str_eingabe1
	bl uart_putString
	bl uart_getByte
	and r5, r0, #EingabeMaske
	mov r0, r5
	bl uart_putByte
	
	//Initiale Werte ausgeben
	ldr r0, =str_initalerWerte
	bl uart_putString	
	ldr r0, =bits0
	bl speicher_ausgeben
	ldr r0, =bits10
	bl speicher_ausgeben
	
	//Bits ohne Bitbanding aenderen
	ldr r0, =bits0
	ldr r1, [r0]
	lsl r2, r6, r4
	bic r1, r2 //bit löschen 
	lsl r2, r6, r5
	orr r1, r2 //bit setzen
	
	str r1, [r0]
	
	//Bits mit Bitbanding aendern
	ldr r0, =BitBandAdresse
	str r7, [r0, r4, lsl #2] //Bit loeschen
	str r6, [r0, r5, lsl #2] //Bit setzen	 
	
	//Neue Werte ausgeben
	ldr r0, =str_neueWerte
	bl uart_putString	
	ldr r0, =bits0
	bl speicher_ausgeben
	ldr r0, =bits10
	bl speicher_ausgeben
	
	b bitnummern_einlesen

.thumb_func	
speicher_ausgeben:
	push {r4-r11,lr}
	mov r4, r0
	ldr r0, =str_ausgabeAdresse
	bl uart_putString
	mov r0, r4
	bl uart_putInt32
	ldr r0, =str_ausgabeInhalt
	bl uart_putString	
	ldr r0, [r4]
	bl uart_putInt32
	
	pop {r4-r11,pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
bits0: .word 0x99FF0E11
.word 0x00000000
.word 0x00000000
.word 0x00000000
bits10: .word 0x99FF0E11

str_eingabe0: .asciz "\nNummer des 0-Bits: 0x"
str_eingabe1: .asciz "\nNummer des 1-Bits: 0x"
str_initalerWerte: .asciz "\n\nInitale Werte:"
str_neueWerte: .asciz "\n\nNeue Werte:"
str_ausgabeAdresse: .asciz "\n0x"
str_ausgabeInhalt:  .asciz ": 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten
.equ ASCII_UNTERSTRICH, 0x5F

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
start:	
	//v1 einlesen
	ldr r0, =str_v1
	bl uart_putString
	bl vektor_einlesen
	ldr r1, =v1
	str r0, [r1]
		
	//v2 einlesen
	ldr r0, =str_v2
	bl uart_putString
	bl vektor_einlesen
	ldr r1, =v2
	str r0, [r1]
	
	/******************************************
	 ohne DSP-Befehle
	******************************************/	
	ldr r0, =str_ohneDsp
	bl uart_putString
	
	//Zeitmessung starten
	bl pit3_init
	bl pit3_getval
	mov r11, r0
	
	ldr r0, =v1
	ldr r1, =v2
	mov r2, #0x03 //Offset initialisieren
	mov r3, #0x18 //Verschiebung initialisieren	
	mov r6, #0x00 //Maximum initialisieren
	mov r7, #0x00 //Minimum initialisieren
	
minMaxBestimmen:
	//Vektorkomponeten laden
	ldrb r4, [r0, +r2]
	ldrb r5, [r1, +r2]
	
	//Komponentenbyte auf Zielposition für Min/Max Verktor schieben
	lsl r4, r4, r3
	lsl r5, r5, r3
	
	//Komponenten vergleichen
	cmp r4, r5
	ittee hi
	orrhi r6, r6, r4
	orrhi r7, r7, r5
	orrls r7, r7, r4
	orrls r6, r6, r5
	
	//Adressoffset und Verschiebung verringern
	subs r2, r2, #1
	sub r3, r3, #8
	bpl minMaxBestimmen //wiederholen solange Offset positiv
	
	//Zeit berechnen
	bl pit3_getval
	sub r11, r11, r0	
	
	//Ausgabe
	ldr r0, =str_min
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_max
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	ldr r0, =str_zeit
	bl uart_putString
	mov r0, r11
	bl uart_putByteBase10
	
	/******************************************
	 Mit DSP-Befehle
	******************************************/
	ldr r0, =str_mitDsp
	bl uart_putString
	
	//Zeitmessung starten
	bl pit3_getval
	mov r11, r0
	
	//Vektoren aus Speicher laden
	ldr r0, =v1
	ldr r0, [r0]
	ldr r1, =v2
	ldr r1, [r1]
	
	//Vergleichen
	usub8 r3, r0, r1
	
	//Auswaehlen
	sel r3, r1, r0
	sel r4, r0, r1
	
	//Zeit berechnen
	bl pit3_getval
	sub r11, r11, r0
	
	//Ausgabe
	ldr r0, =str_min
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_max
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	ldr r0, =str_zeit
	bl uart_putString
	mov r0, r11
	bl uart_putByteBase10
		
	b start
	

.thumb_func	
vektor_einlesen:
	push {r4-r11,lr}
	mov r4, #0x00	
	bl uart_getByte
	lsl r4, r0, #0x18
	bl uart_putByte
	bl uart_getByte
	orr r4, r4, r0, lsl #0x10
	bl uart_putByte
	mov r0, #ASCII_UNTERSTRICH
	bl uart_putChar
	bl uart_getByte
	orr r4, r4, r0, lsl #0x08
	bl uart_putByte	
	bl uart_getByte
	orr r4, r4, r0
	bl uart_putByte
	mov r0, r4
	pop {r4-r11, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
v1: .word 0x00
v2: .word 0x00
str_v1: .asciz "\nv1: 0x"
str_v2: .asciz "\nv2: 0x"
str_ohneDsp: .asciz "\nOhne DSP-Befehle:"
str_mitDsp: .asciz "\n\nMit DSP-Befehlen:"
str_min: .asciz "\nmin: 0x"
str_max: .asciz "\nmax: 0x"
str_zeit: .asciz "\nDauer: "

/* Dauer der Berechnung:
Es ist wenig verwunderlich, dass die Berechnung mit DSP-Befehlen wesentlich schneller ist,
da die Berechnung lediglich 7 Befehle benoetigt (einschliesslich Laden der Vektoren aus dem Speicher).

Die Berechnung ohne DSP-Befehle erfordert, unter Beruecksichtigung aller 4 Scheifendurchlaeufe,
58 Befehle. Dies spiegelt sich so auch in den erfassten Zeiten wieder. */

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklarationen
.equ MATRIX_ZEILEN, 0x04
.equ MATRIX_ELEMENTE, 0x10
.equ MATRIX_O_KOPIERLAEUFE, 0x08
.equ ASCII_LF, 0x0A
.equ ASCII_SP, 0x20


.equ D_A, 0xa4367c7b
.equ D_B, 0x10a78933
.equ D_C, 0xc5535f2c
.equ D_D, 0x788e84b1
.equ E_A, 0xa4367c7b
.equ E_B, 0x10a78933

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	ldr r0, =str_ergebnismatrix
	bl uart_putString

/*
	a) Matrix berechnen: 
	r0, r1: Zeile  M
	r2, r3: Spalte N
	r4: Element O
	r5: Spaltenzaehler
	r6: Zeilenzaehler
	r7: Startadresse der aktuellen Zeile M
	r8: Startadresse der aktuellen Spalte N
	r9: Adresse Element  O
*/	
	ldr r9, =matrix_o 		//Startadresse Ergebnismatrix
	
	mov r6, #MATRIX_ZEILEN //Zeilenzaehler
	ldr r7, =matrix_m 		//Startadresse der aktuellen Zeile

zeile_berechnen:
	mov r5,  #MATRIX_ZEILEN //Spaltenzaehler
	ldr r8, =matrix_n
	
element_berechnen:	
	//Zeile laden
	ldrd r0, r1, [r7]

	//Spalte laden
	ldrd r2, r3, [r8], #+8	
	
	//Berechnung
	smuad r4, r0, r2
	smlad r4, r1, r3, r4
	
	//Ergebnis speichern
	str r4, [r9], #+4 
	
	//Ergebnis ausgeben
	mov r0, r4
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	//Spaltenzaehler dekrementieren
	subs r5, r5, #1
	bne element_berechnen
	
	//Naechste Zeile
	mov r0, #ASCII_LF
	bl uart_putChar
	add r7, r7, #8
	subs  r6, r6, #1
	bne zeile_berechnen
	
	
	
	/*
	b) Matix kopieren
	*/
	ldr r0, =str_matrixKopieren
	bl uart_putString
	
	/*
	r0: Quelle
	r1: Ziel
	r2, r3: aktuell zu kopierende Elemente
	r5: Schleifenzaehler
	*/	
	ldr r0, =matrix_o
	ldr r1, =kopie_matrix_o
	mov r5, #MATRIX_O_KOPIERLAEUFE
elemente_kopieren:
	ldrd r2, r3, [r0], #+8 	//Zu kopierende Elemente laden
	strd r2, r3, [r1], #+8 	//Zu kopierende Elemente speicheren
	subs r5, r5, #1			//Schleifenzähler verringern
	bne elemente_kopieren


	/*
	c) Produkt-Summe (0x7e4c6795)
	
	r0, r1: Zeile  M
	r2, r3: Spalte N
	r4: Produktsumme
	r5: Zaehler
	r7: Startadresse der aktuellen Zeile M
	r8: Startadresse der aktuellen Spalte N
	*/	
	mov r4, #0			   //Summe mit 0 initialisieren
	mov r5, #MATRIX_ZEILEN //Schleifenzaehler
	ldr r7, =matrix_m 		
	ldr r8, =matrix_n

multiplizieren:
	//Zeile laden
	ldrd r0, r1, [r7], #+8

	//Spalte laden
	ldrd r2, r3, [r8], #+8	
	
	//Berechnung
	smlad r4, r0, r2, r4
	smlad r4, r1, r3, r4	
	
	//Zaehler dekrementieren
	subs r5, r5, #1
	bne multiplizieren
	
	//Ausgabe
	ldr r0, =str_produktSumme
	bl uart_putString
	mov r0, r4
	bl uart_putInt32
	
	
	/*
	d) skalierbare Additionsbefehle
	*/
	//Werte für A,B,C,D laden
	ldr r4, =D_A
	ldr r5, =D_B
	ldr r6, =D_C
	ldr r7, =D_D
	
	//UADD16
	ldr r0, =str_uadd16
	bl uart_putString
	
	uadd16 r0, r4, r5 //A+B
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	uadd16 r0, r4, r6 //A+C
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	uadd16 r0, r4, r7 //A+D
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	//SADD16
	ldr r0, =str_sadd16
	bl uart_putString
	
	sadd16 r0, r4, r5 //A+B
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	sadd16 r0, r4, r6 //A+C
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	sadd16 r0, r4, r7 //A+D
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	//UQADD16
	ldr r0, =str_uqadd16
	bl uart_putString
	
	uqadd16 r0, r4, r5 //A+B
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	uqadd16 r0, r4, r6 //A+C
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	uqadd16 r0, r4, r7 //A+D
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	
	//QADD16
	ldr r0, =str_qadd16
	bl uart_putString
	
	qadd16 r0, r4, r5 //A+B
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	qadd16 r0, r4, r6 //A+C
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	qadd16 r0, r4, r7 //A+D
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	/*
	e) Saettigung
	*/
	//Werte für A,B laden
	ldr r4, =E_A
	ldr r5, =E_B
	
	ldr r0, =str_ssat16
	bl uart_putString
		
	ssat16 r0, #13, r4 //A vorzeichenbehaftet saettigen
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	ssat16 r0, #13, r5 //B vorzeichenbehaftet saettigen
	bl uart_putInt32
	
	ldr r0, =str_usat16
	bl uart_putString
		
	usat16 r0, #13, r4 //A vorzeichenlos saettigen
	bl uart_putInt32
	mov r0, #ASCII_SP
	bl uart_putChar
	
	usat16 r0, #13, r5 //B vorzeichenlos saettigen
	bl uart_putInt32
	
	

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
matrix_m: //Zeilenweise
.quad 0x5f8c7f4882456048, 0xc7999c5dd49c33d8, 0x579b8aeff2c0a3c2, 0x41fd50d425c64afa
matrix_n: //Spaltenweise
.quad 0x7f4106458c8f9065, 0x78e3f7f3d29f2961, 0x5a1edfed4b9f1092, 0x61bf21be5ca1c6d3
matrix_o:
.rept MATRIX_ZEILEN
.quad 0, 0
.endr

kopie_matrix_o:
.rept MATRIX_ZEILEN
.quad 0, 0
.endr

str_ergebnismatrix: .asciz "Ergebnismatrix O:\n"
str_matrixKopieren: .asciz "Kopieren der Matrix O!\n"
str_produktSumme: .asciz "Produkt-Summe: "
str_uadd16: .asciz "\nUADD16:  " 
str_sadd16: .asciz "\nSADD16:  "
str_uqadd16: .asciz "\nUQADD16: "
str_qadd16: .asciz "\nQADD16:  "
str_ssat16: .asciz "\nSSAT16:  "
str_usat16: .asciz "\nUSAT16:  "





// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten
.equ ZAEHLER, 0x007DDD9B
.equ ASCII_SP, 0x20
.equ ASCII_PUNKT, 0x2e
.equ ASCII_DPUNKT, 0x3a
.equ ASCII_D, 0x64
.equ ASCII_S, 0x73
.equ ASCII_T, 0x74
.equ ANZAHL_MINUTEN, 60
.equ ANZAHL_STUNDEN, 24
.equ ANZAHL_TAGE, 30
.equ ANZAHL_MONATE, 12
.equ ANZAHL_JAHRE, 100
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	/*
	* Initialisierung
	*/	
	bl uart_init
	
	//Adressen fuer globale Variablen der Uhr laden.
	ldr r4, =minuten
	ldr r5, =stunden
	ldr r6, =tag
	ldr r7, =monat
	ldr r8, =jahr
	mov r9, 0 //Uhr gestartet
	
	/*
	* Eingabe
	*/
eingabe:
	//Pruefen, ob Eingabe vorhanden
	bl uart_charPresent
	cmp r0, #0
	beq ausgabe //Keine Eingabe vorhanden. Fortfahren mit Ausgabe.
	
	bl uart_getChar
	cmp r0, #ASCII_S
	beq eingabeStartStop
	cmp r0, #ASCII_T
	beq eingabeTime
	cmp r0, #ASCII_D
	beq eingabeDate	
	b ausgabe //Keine gueltige Eingabe. Fortfahren mit Ausgabe

eingabeStartStop:
	cmp r9, #0
	ite eq
	moveq r9, #1
	movne r9, #0
	b ausgabe

eingabeTime:
	ldr r0, =str_eingabeStunden
	bl uart_putString
	bl uart_getByteBase10 //Stunden einlesen
	strb r0, [r5]
	
	ldr r0, =str_eingabeMinuten
	bl uart_putString
	bl uart_getByteBase10 //Minuten einlesen
	strb r0, [r4]
	
	b ausgabe
	
eingabeDate:
	ldr r0, =str_eingabeTag
	bl uart_putString
	bl uart_getByteBase10 //Tag einlesen
	strb r0, [r6]
	
	ldr r0, =str_eingabeMonat
	bl uart_putString
	bl uart_getByteBase10 //Monat einlesen
	strb r0, [r7]
	
	ldr r0, =str_eingabeJahr
	bl uart_putString
	bl uart_getByteBase10 //Jahr einlesen
	strb r0, [r8]
	
	b ausgabe
	
	/*
	* Ausgabe
	*/
ausgabe:
	//Pruefen, ob Uhr gestartet
	cmp r9, #0
	bne eingabe //Wenn nicht, zurueck zur Eingabe

	//Uhrzeit ausgeben
	bl uhrzeitAusgeben
	
	//1s warten	
	bl delay
	
	/*
	* Uhr hochzaehlen
	*/
	//Minuten hochzaehlen
	ldrb r0, [r4]
	add r0, #1
	strb r0, [r4]
	cmp r0, #ANZAHL_MINUTEN
	blt eingabe
	
	//Minuten zurueksetzen
	mov r0, #0
	strb r0, [r4]
	
	//Stunden hochzaehlen
	ldrb r0, [r5]
	add r0, #1
	strb r0, [r5]
	cmp r0, #ANZAHL_STUNDEN
	blt eingabe
	
	//Stunden zurueksetzen
	mov r0, #0
	strb r0, [r5]
	
	//Tag hochzaehlen
	ldrb r0, [r6]
	add r0, #1
	strb r0, [r6]
	cmp r0, #ANZAHL_TAGE
	ble eingabe
	
	//Tag zurueksetzen
	mov r0, #1
	strb r0, [r6]
	
	//Monat hochzaehlen
	ldrb r0, [r7]
	add r0, #1
	strb r0, [r7]
	cmp r0, #ANZAHL_MONATE
	ble eingabe
	
	//Monat zurueksetzen
	mov r0, #1
	strb r0, [r7]
	
	//Jahr hochzaehlen
	ldrb r0, [r8]
	add r0, #1
	strb r0, [r8]
	cmp r0, #ANZAHL_JAHRE
	blt eingabe
	
	//Monat zurueksetzen
	mov r0, #0
	strb r0, [r8]
	
	
	b eingabe

/*
* Unterprogram zur Erzeugung von einer Verzoegerung von etwa 1s.
* Uebergabeparamter: keine
*/
.thumb_func		
delay:
	ldr r0, =ZAEHLER
delay_schleife:
	subs r0, #1
	bne delay_schleife
	bx lr
	
/*
* Gibt Datum und Uhrzeit via uart aus.
* Uebergabeparamter: keine. Datum und Uhrzeit werden direkt aus den globalen Variablen ausgelesen.
*/	
.thumb_func
uhrzeitAusgeben:
	push {lr}
	ldr r0, =tag
	ldrb r0, [r0]	
	bl byteAusgeben
	
	mov r0, #ASCII_PUNKT
	bl uart_putChar
	
	ldr r0, =monat
	ldrb r0, [r0]
	bl byteAusgeben
	
	ldr r0, =str_jahr
	bl uart_putString
	
	ldr r0, =jahr
	ldrb r0, [r0]
	bl byteAusgeben
	
	mov r0, #ASCII_SP
	bl uart_putChar
	
	ldr r0, =stunden
	ldrb r0, [r0]
	bl byteAusgeben
	
	mov r0, #ASCII_DPUNKT
	bl uart_putChar
	
	ldr r0, =minuten
	ldrb r0, [r0]	
	bl byteAusgeben
	
	ldr r0, =str_uhr
	bl uart_putString
	
	pop {pc}

/*
* Gibt ein Byte in dezimaler Form via uart aus. Ist der Wert < 10, wird ein fuehrende 0 ergaenzt.
* Uebergabeparamter:
* 	 - r0: der auszugebende Wert.
*/	
.thumb_func
byteAusgeben:
	push {r4, lr}
	//Pruefen, ob zuerst eine 0 ausgebeben werden muss
	cmp r0, #10		
	bge zahlAusgeben
	//0 ausgeben
	mov r4, r0
	mov r0, #0
	bl uart_putByteBase10
	mov r0, r4
zahlAusgeben:
	//eigentliche Zahl ausgeben
	bl uart_putByteBase10	
	pop {r4, pc}

	

/*** Datenbereich (ab 0x20000000) ***/
.data
minuten: .byte 0
stunden: .byte 0
tag: .byte 1
monat: .byte 1
jahr: .byte 14
str_uhr: .asciz " Uhr\n"
str_jahr: .asciz ".20"
str_eingabeTag: .asciz "Tag eingeben (dd): \n"
str_eingabeMonat: .asciz "Monat eingeben (mm): \n"
str_eingabeJahr: .asciz "Jahr eingeben (jj): \n"
str_eingabeStunden: .asciz "Stunden eingeben (hh): \n"
str_eingabeMinuten: .asciz "Minuten eingeben (mm): \n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten
.equ ZAEHLER, 0x007F2815
.equ ASCII_SP, 0x20
.equ ASCII_PUNKT, 0x2e
.equ ASCII_DPUNKT, 0x3a
.equ ASCII_D, 0x64
.equ ASCII_S, 0x73
.equ ASCII_T, 0x74
.equ ANZAHL_MINUTEN, 60
.equ ANZAHL_STUNDEN, 24
.equ ANZAHL_TAGE, 30
.equ ANZAHL_MONATE, 12
.equ ANZAHL_JAHRE, 100

.equ TIMER_STARTWERT, 0x017d7840
.equ TIMER_MIT_INTERRUPT_AKTIVIEREN, 0x00000003

.equ INTERRUPT_VECTOR_PIT1, 0x1FFFFF54
.equ IRQ69_SET_MASK, 0xf0 //0x00000020
.equ IRQ69_CLEAR_MASK, 0xFFFFFFDF 

//SFRs
.equ SIM_SCGC6_PIT, 0x429007DC //Bit-Band-Alias fuer Bit 23 (PIT) in SIM_SCGC6 (0x4004803C)
.equ PIT_MCR_MDIS, 0x426E0004 //Bit-Band-Alias fuer Bit 1 (MDIS) in PIT_MCR (0x40037000)
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TFLG1_TIF, 0x426E2380 //Bit-Band-Alias fuer Bit 0 (TIF) in PIT_TFLG1
.equ NVIC_ISER2, 0xE000E108 
.equ NVIC_ICPR2, 0xE000E288
.equ NVIC_IABR2, 0xE000E308
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	/*
	* Initialisierung
	*/
	//Uart initialisieren
	bl uart_init
	
	//Taktversorgung PIT aktivieren
	ldr r0, =SIM_SCGC6_PIT
	mov r1, #1
	str r1, [r0] 
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_pit1
	ldr r1, =INTERRUPT_VECTOR_PIT1	 
	str r0, [r1]
	
	//Pending Interrupts PIT1 loeschen (NVIC)
	ldr r0, =NVIC_ICPR2
	ldr r1, [r0]
	ldr r2, =IRQ69_CLEAR_MASK
	and r1, r1, r2
	str r2, [r0]
	
	//Interrupt PIT1 aktivieren (NVIC) 
	ldr r0, =NVIC_ISER2
	ldr r1, [r0]
	ldr r2, =IRQ69_SET_MASK
	orr r1, r1, r2
	str r1, [r0]
	
	//PIT Modul aktivieren
	ldr r0, =PIT_MCR_MDIS
	mov r1, #0
	str r1, [r0]
	
	//PIT1 Startwert setzen
	ldr r0, =PIT_LDVAL1
	ldr r1, =TIMER_STARTWERT
	str r1, [r0]
	
	//PIT1 mit Interrupts aktivieren
	ldr r0, =PIT_TCTRL1
	mov r1, #TIMER_MIT_INTERRUPT_AKTIVIEREN
	str r1, [r0]
	
	
	//Adressen fuer globale Variablen der Uhr laden.
	ldr r4, =minuten
	ldr r5, =stunden
	ldr r6, =tag
	ldr r7, =monat
	ldr r8, =jahr
	mov r9, #0 //Uhr gestartet
	ldr r10, =flag_sekunde
	
	/*
	* Eingabe
	*/
eingabe:
	//Pruefen, ob Eingabe vorhanden
	bl uart_charPresent
	cmp r0, #0
	beq ausgabe //Keine Eingabe vorhanden. Fortfahren mit Ausgabe.
	
	bl uart_getChar
	cmp r0, #ASCII_S
	beq eingabeStartStop
	cmp r0, #ASCII_T
	beq eingabeTime
	cmp r0, #ASCII_D
	beq eingabeDate	
	b ausgabe //Keine gueltige Eingabe. Fortfahren mit Ausgabe

eingabeStartStop:
	cmp r9, #0
	ite eq
	moveq r9, #1
	movne r9, #0
	b ausgabe

eingabeTime:
	ldr r0, =str_eingabeStunden
	bl uart_putString
	bl uart_getByteBase10 //Stunden einlesen
	strb r0, [r5]
	
	ldr r0, =str_eingabeMinuten
	bl uart_putString
	bl uart_getByteBase10 //Minuten einlesen
	strb r0, [r4]
	
	b ausgabe
	
eingabeDate:
	ldr r0, =str_eingabeTag
	bl uart_putString
	bl uart_getByteBase10 //Tag einlesen
	strb r0, [r6]
	
	ldr r0, =str_eingabeMonat
	bl uart_putString
	bl uart_getByteBase10 //Monat einlesen
	strb r0, [r7]
	
	ldr r0, =str_eingabeJahr
	bl uart_putString
	bl uart_getByteBase10 //Jahr einlesen
	strb r0, [r8]
	
	b ausgabe
	
	/*
	* Ausgabe
	*/
ausgabe:
	//Pruefen, ob Uhr gestartet
	cmp r9, #0
	bne eingabe //Wenn nicht, zurueck zur Eingabe	
	
	//Sekunden-Flag abfragen		
	ldrb r0, [r10]
	teq r0, #0
	beq eingabe
	
	//Sekunden-Flag loeschen
	mov r0, #0
	strb r0, [r10]	
	
	//Uhrzeit ausgeben
	bl uhrzeitAusgeben
	
	
	/*
	* Uhr hochzaehlen
	*/
	//Minuten hochzaehlen
	ldrb r0, [r4]
	add r0, #1
	strb r0, [r4]
	cmp r0, #ANZAHL_MINUTEN
	blt eingabe
	
	//Minuten zurueksetzen
	mov r0, #0
	strb r0, [r4]
	
	//Stunden hochzaehlen
	ldrb r0, [r5]
	add r0, #1
	strb r0, [r5]
	cmp r0, #ANZAHL_STUNDEN
	blt eingabe
	
	//Stunden zurueksetzen
	mov r0, #0
	strb r0, [r5]
	
	//Tag hochzaehlen
	ldrb r0, [r6]
	add r0, #1
	strb r0, [r6]
	cmp r0, #ANZAHL_TAGE
	ble eingabe
	
	//Tag zurueksetzen
	mov r0, #1
	strb r0, [r6]
	
	//Monat hochzaehlen
	ldrb r0, [r7]
	add r0, #1
	strb r0, [r7]
	cmp r0, #ANZAHL_MONATE
	ble eingabe
	
	//Monat zurueksetzen
	mov r0, #1
	strb r0, [r7]
	
	//Jahr hochzaehlen
	ldrb r0, [r8]
	add r0, #1
	strb r0, [r8]
	cmp r0, #ANZAHL_JAHRE
	blt eingabe
	
	//Monat zurueksetzen
	mov r0, #0
	strb r0, [r8]
	
	
	b eingabe
	
/*
* Gibt Datum und Uhrzeit via uart aus.
* Uebergabeparamter: keine. Datum und Uhrzeit werden direkt aus den globalen Variablen ausgelesen.
*/	
.thumb_func
uhrzeitAusgeben:
	push {lr}
	ldr r0, =tag
	ldrb r0, [r0]	
	bl byteAusgeben
	
	mov r0, #ASCII_PUNKT
	bl uart_putChar
	
	ldr r0, =monat
	ldrb r0, [r0]
	bl byteAusgeben
	
	ldr r0, =str_jahr
	bl uart_putString
	
	ldr r0, =jahr
	ldrb r0, [r0]
	bl byteAusgeben
	
	mov r0, #ASCII_SP
	bl uart_putChar
	
	ldr r0, =stunden
	ldrb r0, [r0]
	bl byteAusgeben
	
	mov r0, #ASCII_DPUNKT
	bl uart_putChar
	
	ldr r0, =minuten
	ldrb r0, [r0]	
	bl byteAusgeben
	
	ldr r0, =str_uhr
	bl uart_putString
	
	pop {pc}
	
/*
* Gibt ein Byte in dezimaler Form via uart aus. Ist der Wert < 10, wird ein fuehrende 0 ergaenzt.
* Uebergabeparamter:
* 	 - r0: der auszugebende Wert.
*/
.thumb_func
byteAusgeben:
	push {r4, lr}
	//Pruefen, ob zuerst eine 0 ausgebeben werden muss
	cmp r0, #10		
	bge zahlAusgeben
	//0 ausgeben
	mov r4, r0
	mov r0, 0
	bl uart_putByteBase10
	mov r0, r4
zahlAusgeben:
	//eigentliche Zahl ausgeben
	bl uart_putByteBase10	
	pop {r4, pc}

/*
* Interruptroutine zu PIT1. 
*/
.thumb_func
isr_pit1:
	//Interrupt loeschen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	//Flag setzen
	ldr r0, =flag_sekunde
	strb r1, [r0] 
	bx lr
	

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_sekunde: .byte 0x01
minuten: .byte 0
stunden: .byte 0
tag: .byte 1
monat: .byte 1
jahr: .byte 14
str_uhr: .asciz " Uhr\n"
str_jahr: .asciz ".20"
str_eingabeTag: .asciz "Tag eingeben (dd): \n"
str_eingabeMonat: .asciz "Monat eingeben (mm): \n"
str_eingabeJahr: .asciz "Jahr eingeben (jj): \n"
str_eingabeStunden: .asciz "Stunden eingeben (hh): \n"
str_eingabeMinuten: .asciz "Minuten eingeben (mm): \n"

