// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ CRC_CRC, 0x40032000		//CRC Data register
.equ CRC_GPOLY, 0x40032004 		//CRC Polynomial register
.equ CRC_CTRL, 0x40032008		//CRC Control register
__BBREG CRC_CTRL_WAS, CRC_CTRL, 25
__BBREG SIM_SCGC6_CRC, 0x4004803c, 18

.equ CRC_CTRL_VALUE, 0x01000000 //32-Bit Modus, keine Umgruppierung, nicht invertiert
.equ CRC_GPOLY_VALUE, 0x04c11db7
.equ CRC_SEED, 0x12345678

.equ VERSCHIEBUNG, 32 //Initialer Wert fuer die Verschiebung beim Packen.
.equ ROTATION, 24     //Rotation zum Entpacken der der letzten 0-3 Bytes des Strings
.equ BYTE_MASKE, 0xFF //Maske fuer die ersten 8 Bits

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	//CRC Taktversorgung aktivieren
	ldr r0, =SIM_SCGC6_CRC
	mov r1, #1
	str r1, [r0]

	//CRC initialisieren
	ldr r0, =CRC_CTRL
	ldr r1, =CRC_CTRL_VALUE
	str r1, [r0]
	
	//CRC Polynom setzen
	ldr r0, =CRC_GPOLY
	ldr r1, =CRC_GPOLY_VALUE
	str r1, [r0]

	//Seed setzen
	ldr r0, =CRC_CTRL_WAS
	mov r1, #1
	str r1, [r0]
	ldr r4, =CRC_CRC
	ldr r3, =CRC_SEED
	str r3, [r4]
	mov r1, #0
	str r1, [r0]
	
	/*Pruefwert berechnen
	 * r0: Adresse des naechsten Zeichen
	 * r1: aktuelles Zeichen
	 * r2: Verschiebung beim Packen
	 * r3: gepackte Zeichen 
	 * r4: Addresse CRC_CRC
	 */
	ldr r0, =str
	mov r2, #VERSCHIEBUNG
	mov r3, #0
packen:
	ldrb r1, [r0], #1 //Zeichen einlesen
	teq r1, #0	//String Terminator pruefen
	beq rest_uebertragen
	
	subs r2, r2, #8 //Schiebeposition verringern
	lsl r1, r1, r2  //eingelesenes Byte auf Position schieben
	orr r3, r3, r1  //packen
	
	bne packen //pruefen, ob bereits 4 Byte eingelesen wurden
	
	str r3, [r4] //gepackte Zeichen in CRC_CRC speichern
	mov r3, #0   //gepackte Zeichen zuruecksetzen
	mov r2, #VERSCHIEBUNG  //Schiebeposition zuruecksetzen
	b packen
	
rest_uebertragen: //Restliche Zeichen, die nach dem Packen uebrig bleiben (0-3), einzeln uebertragen
	ror r3, r3, #ROTATION
	ands r2, r3, #BYTE_MASKE
	it ne
	strbne r2, [r4] //einzelnes Zeichen in CRC_CRC speichern
	bne rest_uebertragen 
	
ausgabe:
	//Ausgabe
	ldr r0, =str
	bl uart_putString
	ldr r0, =str_pruefsumme
	bl uart_putString
	ldr r0, [r4] //Pruefsumme auslesen	
	bl uart_putInt32

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
str_pruefsumme: .asciz "\nPruefsumme: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//SFRs
__BBREG PIT_MCR_MDIS, 0x40037000, 1
__BBREG PIT_TCTRL1_TEN, 0x40037118, 0 		
__BBREG PIT_TFLG1_TIF, 0x4003711C, 0   
.equ PIT_LDVAL1, 0x40037110 			
.equ PIT_TCTRL1, 0x40037118
.equ PIT_LDVAL2, 0x40037120
.equ PIT_CVAL2,  0x40037124
.equ PIT_TCTRL2, 0x40037128 

__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC5_PORTE, 0x40048038, 13
__BBREG SIM_SCGC6_PIT, 0x4004803C, 23	

.equ PORTA_PCR11,  0x4004902C		//E1
.equ PORTA_PCR19, 0x4004904C		//SW1
.equ PORTA_PCR29, 0x40049074		//E3
.equ PORTA_PCR28,  0x40049070		//E2
.equ PORTA_PCR10, 0x40049028		//E4
.equ PORTE_PCR26, 0x4004D068		//SW2
__BBREG PORTE_ISFR_PTE26, 0x4004D0A0, 26 

.equ GPIOA_PSOR,  0x400FF004
.equ GPIOA_PCOR,  0x400FF008
.equ GPIOA_PDDR,  0x400FF014
__BBREG GPIOA_PDIR_PTA19, 0x400FF010, 19 
.equ GPIOE_PDDR,  0x400FF114
__BBREG GPIOE_PDIR_PTE26, 0x400FF110, 26

.equ NVIC_ISER2, 0xE000E108 
.equ NVIC_ICPR2, 0xE000E288
.equ NVIC_IABR2, 0xE000E308

//Konstanten
.equ ASCII_S, 0x73
.equ ASCII_PLUS, 0x2b
.equ ASCII_MINUS, 0x2d
.equ ASCII_LF, 0x0A

.equ BYTE_MASKE, 0xFF //Maske fuer die ersten 8 Bits

.equ PIT2_5MS, 125000				//erforderliche Takte fuer 5ms (Berechnung: 5ms * 25MHz)
.equ PIT1_STARTWERT, 25000000     	//PIT1 Startwert, entspricht erforderlichen Takten fuer 1s (1s * 25MHz) 
.equ PIT2_STARTWERT, 0xFFFFFFFF 	//PIT2 Startwert, maximaler Startwert
.equ PIT_TCTRL1_VALUE, 0x03			//Timer mit Interrupts starten
.equ PIT_TCTRL2_VALUE, 0x01			//Timer starten

.equ INTERRUPT_MASK, 0x08000020 //Maske zum aktivieren der IRQs  69 (PIT1) und 91 (Port E)
.equ INTERRUPT_VECTOR_PIT1,  0x1FFFFF54
.equ INTERRUPT_VECTOR_PORTE, 0x1FFFFFAC

.equ PCR_LED, 0x100 //Pin als GPIO konfigurieren
.equ PCR_SW1, 0x103 //Pin als GPIO konfigurieren, Pullup aktivieren
.equ PCR_SW2, 0xb0103 //Pin als GPIO konfigrieren, Pullup aktivieren, Interrupt bei beiden Flanken

.equ GPIOA_PDDR_VALUE, 0x30000C00 	//PTA10, PTA11, PTA28, PTA29 Ausgaenge
.equ GPIOE_PDDR_VALUE, 0x0 //PTE26 Eingang

.equ E1, 0x800		//E1  Pin Position
.equ E2, 0x10000000	//E2  Pin Position
.equ E3, 0x20000000	//E3  Pin Position
.equ E4, 0x400		//E16 Pin Position

.equ BIT0, 0x1
.equ BIT1, 0x2
.equ BIT2, 0x4
.equ BIT3, 0x8


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC6_PIT
	str r1, [r0]
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]
	ldr r0, =SIM_SCGC5_PORTE
	str r1, [r0]
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_pit1
	ldr r1, =INTERRUPT_VECTOR_PIT1	 
	str r0, [r1]
	
	//Interrupt-Vektor PORTE setzen  (NVIC)
	ldr r0, =isr_portE
	ldr r1, =INTERRUPT_VECTOR_PORTE	 
	str r0, [r1]
	
	//Pending Interrupts PIT1 und PORTE loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	ldr r1, =INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt PIT1 und PORTE aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	ldr r1, =INTERRUPT_MASK
	str r1, [r0]
	
	//Pins konfigurieren
	ldr r1, =PCR_LED
	ldr r0, =PORTA_PCR11
	str r1, [r0]
	ldr r0, =PORTA_PCR29
	str r1, [r0] 
	ldr r0, =PORTA_PCR28
	str r1, [r0] 
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	ldr r1, =PCR_SW1
	ldr r0, =PORTA_PCR19
	str r1, [r0]
	ldr r1, =PCR_SW2
	ldr r0, =PORTE_PCR26
	str r1, [r0]
	 
	//GPIO konfigurieren
	ldr r0, =GPIOA_PDDR
	ldr r1, =GPIOA_PDDR_VALUE
	str r1, [r0]
	ldr r0, =GPIOA_PSOR
	str r1, [r0] //LEDs ausschalten
	ldr r0, =GPIOE_PDDR
	ldr r1, =GPIOE_PDDR_VALUE
	str r1, [r0]
	
	//PIT Modul aktivieren
	ldr r0, =PIT_MCR_MDIS
	mov r1, #0
	str r1, [r0]
	
	//PIT1 Startwert setzen
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT1_STARTWERT
	str r1, [r0]
	
	//PIT1 mit Interrupts aktivieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_VALUE
	str r1, [r0]
	
	//PIT2 Startwert setzen
	ldr r0, =PIT_LDVAL2
	ldr r1, =PIT2_STARTWERT
	str r1, [r0]
	
	//PIT2 akivieren
	ldr r0, =PIT_TCTRL2
	mov r1, #PIT_TCTRL2_VALUE
	str r1, [r0]
	
	/*
	 * Zaehlerschleife
	 * Registerbelegung:	 
	 *  - R6:  Adresse mod 
	 *  - R7:  Zaehlerstand
	 *  - R8:  Zaehlerrichtung
	 *  - R9:  Zaehler ein/ausgeschaltet
	 *  - R10: Addresse Sekunden Flag
	 */
	//Register initialisieren
	ldr r6, =mod	
	mov r7, #0 //Zaehlerstand
	mov r8, #0 //Zaehler Richtung: hoch
	mov r9, #1 //Zaehler aktiv
	ldr r10, =flag_sekunde
	
	
eingabe:
	/*
	 * Eingabe SW1 + SW2
	 */	
	 	
	 bl pollSW1	//Unterprogramm zum Auswerten von SW1 aufrufen
	 ldrb r0, [r6] //mod auslesen	 
	 
	 cmp r0, #1 //SW1 gedrueckt
	 beq onSW1
	 
	 bl checkSW2 //Unterprogramm zum Auswerten von SW2 aufrufen
	 ldrb r0, [r6] //mod auslesen
	 cmp r0, #2 //SW2 gedrueckt
	 beq onSW2
	 
	 b eingabeUart

onSW1:	 
	 eors  r8, r8, #1 //Zaehlerrichtung aendern
	 ite ne
	 ldrne r0, =str_zaehlerRunter	//String auswaehlen
	 ldreq r0, =str_zaehlerHoch
	 bl	uart_putString				//String ausgeben
	 
	 //mod auf 0 setzen
	 mov r1, #0
	 strb r1, [r6]
	 b 	eingabeUart
	 
onSW2:	
	 eors  r9, r9, #1 //Zaehler (de)aktivieren
	 ldr r0, =PIT_TCTRL1_TEN
	 str r9, [r0] //PIT1 anhalten/starten. Dies hat den Zweck, dass beim Starten eines gestoppten Zaehlers nicht zwei Zahlen innerhalb eines kurzen Zeitraums (< 1s) ausgegeben werden.
	 ite ne
	 ldrne r0, =str_start // entsprechenden String auswaehlen
	 ldreq r0, =str_stopp	 
	 bl	uart_putString	  // gewaehlten String ausgeben
	 
	 //mod auf 0 setzen
	 mov r1, #0
	 strb r1, [r6]
	 b 	eingabeUart
	 
	/*
	* Eingabe Uart
	*/
eingabeUart:
	//Pruefen, ob Eingabe vorhanden
	bl uart_charPresent
	cmp r0, #0
	beq zaehlen //Keine Eingabe vorhanden. Fortfahren mit Ausgabe.	
	
	bl uart_getChar
	cmp r0, #ASCII_S
	beq onS
	
	cmp r0, #ASCII_PLUS
	beq onPlus
	
	cmp r0, #ASCII_MINUS
	beq onMinus
	
	b zaehlen
	
onS:
	eors  r9, r9, #1
	ldr r0, =PIT_TCTRL1_TEN
	str r9, [r0] //PIT1 anhalten/starten
	ite ne
	ldrne r0, =str_start  //String auswaehlen
	ldreq r0, =str_stopp	 
	bl	uart_putString	  //String ausgeben
	b zaehlen
	
onPlus:
	mov r8, #0
	ldr r0, =str_zaehlerHoch
	bl uart_putString
	b zaehlen
	
onMinus:
	mov r8, #1
	ldr r0, =str_zaehlerRunter
	bl uart_putString
	b zaehlen
	
	
	/*
	 *	Zaehlerstand bearbeiten
	 */
zaehlen: 		
	cmp r9, #0  //Pruefen, ob Zaehler gestartet
	beq eingabe //Wenn nicht, zurueck zur Eingabe		
	
	//Sekunden-Flag abfragen		
	ldrb r0, [r10]
	teq r0, #0
	beq eingabe
	
	//Sekunden-Flag loeschen
	mov r0, #0
	strb r0, [r10]	
	
	// Zaehler in-/dekrementieren
	teq r8, #0 //Zaehlrichtung testen
	ite eq
	addeq r7, r7, #1
	subne r7, r7, #1
	and r7, r7, #BYTE_MASKE
	
	/*
	 * Ausgabe
	 */
	//Zaehler ausgeben (Uart)
	mov r0, r7
	bl uart_putByteBase10
	mov r0, #ASCII_LF
	bl uart_putChar
	
	//Zaehler ausgeben (GPIO)
	ldr r1, =GPIOA_PSOR
	ldr r0, =GPIOA_PCOR
	mov r2, #E1	
	tst r7, #BIT0 //Bit 0 pruefen
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	mov r2, #E2	
	tst r7, #BIT1 //Bit 1 pruefen 
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	mov r2, #E3	
	tst r7, #BIT2 //Bit 2 pruefen 
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	mov r2, #E4	
	tst r7, #BIT3 //Bit 3 pruefen 
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	b eingabe
	

/*
* Unterprogramm zum Abfragen von SW1. 
* Keine Uebergabeparameter.
* Keine Rueckgabe. 
*/
.thumb_func	
pollSW1:
	 //SW1 abfragen
 	 ldr r0, =GPIOA_PDIR_PTA19
	 ldr r0, [r0]
	 ldr r1, =levelPTA19
	 ldrb r2, [r1]
	 teq r0, r2 //Pegelwechsel pruefen
	 strb r0, [r1]	//akuellen Pegel sichern 
	 beq pollSW1_end //Falls kein Pegelwechsel vorliegt, zum Ende des Unterprogramms springen
	 
	 ldr r1, =PIT_CVAL2
	 ldr r1, [r1] //Zeitpunkt Pegelwechsel erfassen
	 ldr r2, =sw1Pegelwechsel
	 
	 tst r0, #1
	 it eq
	 streq r1, [r2] //Zeitpunkt der steigenden Flanke speichern
	 beq pollSW1_end  //Bei steigender Flanke zum Ende des Unterprogramms springen		 
	 
	 //Fallende Flanke	 
	 ldr r2, [r2] //Zeitpunkt der steigenden Flanke laden
	 subs r3, r2, r1 //Zeitdifferenz zwischen Pegelwechsel berechnen
	 ittt ls //Falls Timerueberlauf zwischen Pegelwechsel aufgetreten ist: Zeitdifferenz neu berechnen (TimerStartwert - ZeitpunktFallendeFlanke + ZeitpunktSteigendeFlanke
	 movls r3, #PIT2_STARTWERT
	 subls r3, r3, r1  
	 addls r3, r3, r2

	 ldr r0, =mod
	 ldr r1, =PIT2_5MS
	 cmp r3, r1
	 itt hi
	 movhi r1, #1
	 strbhi r1, [r0] //Falls Zeitdifferenz > 5ms, 1 in mod schreiben
	 
pollSW1_end:	 
	 bx lr
	 
/*
* Unterprogramm zum Abfragen von SW2. 
* Keine Uebergabeparameter.
* Keine Rueckgabe. 
*/
.thumb_func	
checkSW2:
	 ldr r0, =flag_sw2
	 ldrb r1, [r0]
	 cmp r1, #0 //Pegelwechsel pruefen
	 beq checkSW2_end //Falls kein Pegelwechsel vorliegt, zum Ende des Unterprogramms springen
	 mov r1, #0
	 strb r1, [r0] //Flag zuruecksetzen
	 ldr r0, =GPIOE_PDIR_PTE26 //Pegel abfragen
	 ldr r0, [r0]
	 	 
	 ldr r1, =PIT_CVAL2
	 ldr r1, [r1] //Zeitpunkt Pegelwechsel erfassen
	 ldr r2, =sw2Pegelwechsel
	 
	 tst r0, #1
	 it eq
	 streq r1, [r2] //Zeitpunkt der steigenden Flanke speichern
	 beq checkSW2_end  //Bei steigender Flanke zum Ende des Unterprogramms springen	 
	 
	 //Fallende Flanke	 
	 ldr r2, [r2] //Zeitpunkt der steigenden Flanke laden
	 subs r3, r2, r1 //Zeitdifferenz zwischen Pegelwechsel berechnen
	 ittt ls //Falls Timerueberlauf zwischen Pegelwechsel aufgetreten ist: Zeitdifferenz neu berechnen (TimerStartwert - ZeitpunktFallendeFlanke + ZeitpunktSteigendeFlanke
	 movls r3, #PIT2_STARTWERT
	 subls r3, r3, r1  
	 addls r3, r3, r2

	 ldr r0, =mod
	 ldr r1, =PIT2_5MS
	 cmp r3, r1
	 itt hi
	 movhi r1, #2
	 strbhi r1, [r0] //Falls Zeitdifferenz > 5ms, 2 in mod schreiben
	 
checkSW2_end:	 
	 bx lr

/*
* Interruptroutine zu PIT1. 
*/
.thumb_func
isr_pit1:
	//Interrupt loeschen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	//Flag setzen
	ldr r0, =flag_sekunde
	strb r1, [r0] 
	bx lr
	
/*
* Interruptroutine zu PORTE. 
*/
.thumb_func
isr_portE:
	//Interrupt loeschen
	ldr r0, =PORTE_ISFR_PTE26
	mov r1, #1
	str r1, [r0]
	//Flag setzen
	ldr r0, =flag_sw2
	strb r1, [r0] 
	 
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
mod: .byte 0
flag_sekunde: .byte 1
flag_sw2: .byte 0
levelPTA19: .byte 1
sw1Pegelwechsel: .word PIT2_STARTWERT
sw2Pegelwechsel: .word PIT2_STARTWERT
str_start: .asciz "Zaehler gestartet\n"
str_stopp: .asciz "Zaehler angehalten\n"
str_zaehlerHoch: .asciz "Zaehlerrichtung: hoch\n"
str_zaehlerRunter: .asciz "Zaehlerrichtung: runter\n"


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//SFRs
__BBREG PIT_MCR_MDIS, 0x40037000, 1
__BBREG PIT_TCTRL1_TEN, 0x40037118, 0 		
__BBREG PIT_TFLG1_TIF, 0x4003711C, 0   
.equ PIT_LDVAL1, 0x40037110 			
.equ PIT_TCTRL1, 0x40037118 

__BBREG SIM_SCGC3_ADC1, 0x40048030, 27
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC6_PIT, 0x4004803C, 23

.equ PORTA_PCR11, 0x4004902C		//E1
.equ PORTA_PCR29, 0x40049074		//E3
.equ PORTA_PCR28, 0x40049070		//E2
.equ PORTA_PCR10, 0x40049028		//E4 

.equ GPIOA_PSOR,  0x400FF004
.equ GPIOA_PCOR,  0x400FF008
.equ GPIOA_PDDR,  0x400FF014

.equ ADC1_SC1A, 0x400BB000
.equ ADC1_CFG1, 0x400BB008
.equ ADC1_CFG2, 0x400BB00C
.equ ADC1_RA,   0x400BB010
.equ ADC1_SC2,  0x400BB020
.equ ADC1_SC3,  0x400BB024
.equ ADC1_PG, 	0x400BB02C
.equ ADC1_MG,   0x400BB030
.equ ADC1_CLPD, 0x400BB034
.equ ADC1_CLPS, 0x400BB038
.equ ADC1_CLP4, 0x400BB03C
.equ ADC1_CLP3, 0x400BB040
.equ ADC1_CLP2, 0x400BB044
.equ ADC1_CLP1, 0x400BB048
.equ ADC1_CLP0, 0x400BB04C
__BBREG ADC1_SC3_CALF, ADC1_SC3, 6
__BBREG ADC1_SC3_CAL,  ADC1_SC3, 7

.equ NVIC_ISER2, 0xE000E108 
.equ NVIC_ICPR2, 0xE000E288
.equ NVIC_IABR2, 0xE000E308

//Konstanten
.equ ADC1_CFG1_VALUE, 0x7C 		//Normal power configuration, (input clock) / 8 -> 3.125MHz, Long sample time, 16 Bit conversion, bus clock
.equ ADC1_CFG2_VALUE, 0x00 		//A channels, Asynchronous clock output disabled, Normal conversion sequence, Default longest sample time
.equ ADC1_SC1A_ON_VALUE, 0x14  	//keine Interrupts, Single-ended conversions, ADC1_DM1 als Eingangssignal auswaehlen
.equ ADC1_SC1A_OFF_VALUE, 0x1F 	//ADC1 inaktiv
.equ ADC1_SC2_VALUE, 0x00  		//Software trigger, compare function disabled, DMA disabled, default reference voltage
.equ ADC1_SC3_CALIBRATION_VALUE, 0x87 //Kalibrierung starten, hardware average function enabled, 32 samples averaged
.equ ADC1_SC3_OPERATING_VALUE, 0x0E	//Continues conversion enabled, hardware average function enabled, 16 samples averaged
.equ ADC1_CFG1_MODE_CLEAR_MASK, 0xFFFFFFF3

.equ MODE_8, 0
.equ MODE_10, 0x08
.equ MODE_12, 0x04
.equ MODE_16, 0x0C

.equ PIT1_INTERRUPT_MASK, 0x20 //Maske zum aktivieren von IRQ  69 (PIT1)
.equ PIT1_INTERRUPT_VECTOR,  0x1FFFFF54

.equ PIT1_STARTWERT, 25000000     	//PIT1 Startwert, entspricht erforderlichen Takten fuer 1s (1s * 25MHz) 
.equ PIT_TCTRL1_VALUE, 0x03			//Timer mit Interrupts starten

.equ PCR_LED, 0x100 //Pin als GPIO konfigurieren
.equ GPIOA_PDDR_LED_MASK, 0x30000C00 	//PTA10, PTA11, PTA28, PTA29 Ausgaenge

.equ E1, 0x800		//E1  Pin Position
.equ E2, 0x10000000	//E2  Pin Position
.equ E3, 0x20000000	//E3  Pin Position
.equ E4, 0x400		//E16 Pin Position

.equ BIT0, 0x1
.equ BIT1, 0x2
.equ BIT2, 0x4
.equ BIT3, 0x8
.equ BIT15, 0x8000

.equ ASCII_LF, 0x0A
.equ ASCII_SP, 0x20
.equ ASCII_0, 0x30
.equ ASCII_1, 0x31
.equ ASCII_2, 0x32
.equ ASCII_3, 0x33 
.equ ASCII_S, 0x73

.equ INTERVAL_8BIT,  32 	//2^8  / 8
.equ INTERVAL_10BIT, 103 	//2^10 / 10 (aufgerundet)
.equ INTERVAL_12BIT, 342 	//2^12 / 12 (aufgerundet)
.equ INTERVAL_16BIT, 4096 	//2^16 / 16


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl adc1_calibrate
	bl adc1_init
	bl pit1_init
	bl leds_init

	/* Registerbelegung
	 * R4:  Flag Start/Stop
	 * R5:  aktuelle Stufe
	 * R6:  Auszugebende Ziffern Spannungsbereich
	 * R7:  Startadresse der Spannungsbereiche in der eingestellten ADC Genauigkeit
	 * R8:  Interval der eingestellten Stufe in Bezug zur ADC Genauigkeit
	 * R9:  ADC Genauigkeit in Bits
	 * R10: Flag Sekunde
	 */
	mov r4, #1 //Wandlung gestartet
	ldr r7, =voltageRange16
	mov r8, #INTERVAL_16BIT
	ldr r10, =flag_sekunde		
eingabe:
	//Pruefen, ob Eingabe vorhanden
	bl uart_charPresent
	
	cmp r0, #0
	beq ausgabe //Keine Eingabe vorhanden. Fortfahren mit Ausgabe.
	
	bl uart_getChar
	cmp r0, #ASCII_S
	beq onS
	
	cmp r4, #0 //Wenn Wandlung gestartet ist, darf die Eingabe auf 0-3 nicht ueberpueft werden. Fortfahren mit Ausgabe.
	bne ausgabe
	
	cmp r0, #ASCII_0
	beq on0
	
	cmp r0, #ASCII_1
	beq on1
	
	cmp r0, #ASCII_2
	beq on2
	
	cmp r0, #ASCII_3
	beq on3
		
	b ausgabe
	
onS:
	eors  r4, r4, #1
	ldr r0, =PIT_TCTRL1_TEN
	str r4, [r0] //PIT1 anhalten/starten
	ldr r2, =ADC1_SC1A
	ittee ne
	ldrne r0, =str_start  //String auswaehlen
	ldrne r1, =ADC1_SC1A_ON_VALUE
	ldreq r0, =str_stopp
	ldreq r1, =ADC1_SC1A_OFF_VALUE
	str r1, [r2] 		//Wandlung anhalten/starten	 
	bl	uart_putString	//String ausgeben
	b ausgabe
	
on0:
	mov r0, #MODE_8
	ldr r7, =voltageRange8
	mov r8, #INTERVAL_8BIT
	mov r9, #8
	b genauigkeitEinstellen
on1:
	mov r0, #MODE_10
	ldr r7, =voltageRange10
	mov r8, #INTERVAL_10BIT
	mov r9, #10
	b genauigkeitEinstellen
on2:
	mov r0, #MODE_12
	ldr r7, =voltageRange12
	ldr r8, =INTERVAL_12BIT
	mov r9, #12
	b genauigkeitEinstellen
on3:
	mov r0, #MODE_16
	ldr r7, =voltageRange16
	mov r8, #INTERVAL_16BIT
	mov r9, #16
	
genauigkeitEinstellen:
	//Wandlungsgenauigkeit einstellen
	ldr r1, =ADC1_CFG1
	ldr r2, [r1]
	ldr r3, =ADC1_CFG1_MODE_CLEAR_MASK
	and r2, r2, r3
	orr r2, r2, r0
	str r2, [r1]
	ldr r0, =str_wandlungsGenauigkeit
	bl uart_putString
	mov r0, r9
	bl uart_putByteBase10
	ldr r0, =str_bit
	bl uart_putString


ausgabe:	
	//Sekunden-Flag abfragen		
	ldrb r0, [r10]
	cmp r0, #0
	beq eingabe
	
	//Sekunden-Flag loeschen
	mov r0, #0
	strb r0, [r10]	
	
	//Ausgabe 0x
	ldr r0, =str_0x
	bl uart_putString
	
	//Wandlungswert auslesen
	ldr r0, =ADC1_RA
	ldr r0, [r0]
	
	//Stufe berechnen
	udiv r5, r0, r8 
	
	//Wandlungswert ausgeben
	bl uart_putInt16
	
	mov r0, #ASCII_SP
	bl uart_putChar
	
	//Spannungsbereich ausgeben
	add r6, r7, r5, lsl #1 //Startadresse des vorberechneten Spannungsbereich berechnen
	
	ldrb r0, [r6]
	cbnz r0, untereGrenze //Auf Sonderfall 0 pruefen 
	bl uart_putByteBase10
	add r6, r6, #1
	b obereGrenze
	
	untereGrenze:
	bl uart_putByteBase10
	ldrb r0, [r6, #1]!
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	obereGrenze:
	ldr r0, =str_to
	bl uart_putString
	
	ldrb r0, [r6, #1]!
	bl uart_putByteBase10
	ldrb r0, [r6, #1]
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	
	//Stufe ausgeben (Uart)	
	ldr r0, =str_stufe
	bl uart_putString
	mov r0, r5
	bl uart_putByteBase10
	ldr r0, =str_zeileBeenden
	bl uart_putString
	
	//Stufe ausgeben (LEDs)
	ldr r1, =GPIOA_PSOR
	ldr r0, =GPIOA_PCOR
	mov r2, #E1	
	tst r5, #BIT0 //Bit 0 pruefen
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	mov r2, #E2	
	tst r5, #BIT1 //Bit 1 pruefen 
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	mov r2, #E3	
	tst r5, #BIT2 //Bit 2 pruefen 
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	mov r2, #E4	
	tst r5, #BIT3 //Bit 3 pruefen 
	ite ne
	strne r2,  [r0]
	streq r2,  [r1]
	
	b eingabe

	
/*
* Unterprogramm zur Kalibrierung von ADC1.
* Keine Uebergabeparameter; Keine Rueckgabe.
* Uart muss initialisiert sein.
*/
.thumb_func
adc1_calibrate:
	push {lr}
	//Taktversorgung aktivieren
	ldr r0, =SIM_SCGC3_ADC1
	mov r1, #1
	str r1, [r0]
	
	//ADC1 fuer Kalibrierung konfigurieren
	ldr r0, =ADC1_CFG1
	mov r1, #ADC1_CFG1_VALUE
	str r1, [r0]
	
	ldr r0, =ADC1_CFG2
	mov r1, #ADC1_CFG2_VALUE
	str r1, [r0]
	
	ldr r0, =ADC1_SC2
	mov r1, #ADC1_SC2_VALUE
	str r1, [r0]
	
	ldr r0, =ADC1_SC3
	mov r1, #ADC1_SC3_CALIBRATION_VALUE
	str r1, [r0]
	
	//ADC1_SC3_CAL solange abfragen, bis es 0 ist. D.h. die Kalibrierung ist abgeschlossen.
	ldr r0, =ADC1_SC3_CAL
waitForCalibration:
	ldr r1, [r0]
	cmp r1, #0
	bne waitForCalibration
	
	//Ueberpruefen, ob Kalibrierungsfehler verliegt
	ldr r0, =ADC1_SC3_CALF
	ldr r1, [r0]
	cbz r1, finishCalibration
	
	ldr r0, =str_calibrationFailed
	bl uart_putString
	//Kalibrierung erneut starten
	ldr r0, =ADC1_SC3_CAL
	mov r1, #1 
	str r1, [r0]
	b waitForCalibration	
	
finishCalibration:
	
	//Verstaerker-Kalibrierung berechnen (+). Verstaerker-Kalibrierung fuer negative Spannungen wird nicht benoetigt.
	mov r0, #0
	ldr r1, =ADC1_CLP0
	ldr r1, [r1]
	add r0, r0, r1
	
	ldr r1, =ADC1_CLP1
	ldr r1, [r1]
	add r0, r0, r1
	
	ldr r1, =ADC1_CLP2
	ldr r1, [r1]
	add r0, r0, r1
	
	ldr r1, =ADC1_CLP3
	ldr r1, [r1]
	add r0, r0, r1
	
	ldr r1, =ADC1_CLP4
	ldr r1, [r1]
	add r0, r0, r1
	
	ldr r1, =ADC1_CLPS
	ldr r1, [r1]
	add r0, r0, r1
	
	lsr r0, r0, #1
	ldr r2, =BIT15
	orr r0, r0, r2
	
	ldr r1, =ADC1_PG
	str r0, [r1]	
	
	ldr r0, =str_calibrationSuccessful
	bl uart_putString
		 
	pop {pc}
	
/*
* Unterprogramm zur Initialisierung von ADC1 zum Auslesen des Potentiometers.
* Keine Uebergabeparameter; Keine Rueckgabe.
* ADC1 muss kalibriert sein.
*/
.thumb_func
adc1_init:
	//ADC1_CFG1, ADC1_CFG2 und ADC1_SC2 werden bereits fuer die Kalibrierung konfiguriert
	ldr r0, =ADC1_SC3
	mov r1, #ADC1_SC3_OPERATING_VALUE
	str r1, [r0]	
	
	ldr r0, =ADC1_SC1A
	mov r1, #ADC1_SC1A_ON_VALUE
	str r1, [r0]	
	
	bx lr

/*
* Unterprogramm zur Initialisierung von PIT1 zum Ausloesen von Interrupts nach je 1s. 
*/
.thumb_func
pit1_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC6_PIT
	str r1, [r0] 
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_pit1
	ldr r1, =PIT1_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts PIT1 loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	mov r1, #PIT1_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt PIT1 aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	//PIT Modul aktivieren
	ldr r0, =PIT_MCR_MDIS
	mov r1, #0
	str r1, [r0]
	
	//PIT1 Startwert setzen
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT1_STARTWERT
	str r1, [r0]
	
	//PIT1 mit Interrupts aktivieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_VALUE
	str r1, [r0]
	
	bx lr

/*
* Unterprogramm zum Initisieren der LEDs. 
*/
.thumb_func	
leds_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]

	//Pins konfigurieren
	ldr r1, =PCR_LED
	ldr r0, =PORTA_PCR11
	str r1, [r0]
	ldr r0, =PORTA_PCR29
	str r1, [r0] 
	ldr r0, =PORTA_PCR28
	str r1, [r0] 
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	 
	//GPIO konfigurieren
	ldr r0, =GPIOA_PDDR
	ldr r1, =GPIOA_PDDR_LED_MASK
	ldr r2, [r0]	//laden
	orr r2, r2, r1	//maskieren
	str r2, [r0]	//schreiben
	ldr r0, =GPIOA_PSOR
	str r1, [r0] //LEDs ausschalten
	
	bx lr

/*
* Interruptroutine zu PIT1. 
*/
.thumb_func
isr_pit1:
	//Interrupt loeschen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	//Flag setzen
	ldr r0, =flag_sekunde
	strb r1, [r0] 
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_sekunde: .byte 0
voltageRange8:  .byte 0,0, 4,13, 8,25, 12,38, 16,50, 20,63, 24,75, 28,88, 33,00 	//Intervall 412,5 mV; je 2x2 Dezimalziffern
voltageRange10: .byte 0,0, 3,30, 6,60,  9,90, 13,20, 16,50, 19,80, 23,10, 26,40, 29,70, 33,00 	//Intervall 330 mV; je 2x2 Dezimalziffern
voltageRange12: .byte 0,0, 2,75, 5,50,  8,25, 11,00, 13,75, 16,50, 19,25, 22,00, 24,75, 27,50, 30,25, 33,00 //Intervall 275 mV; je 2x2 Dezimalziffern
voltageRange16: .byte 0,0, 2,06, 4,13,  6,19,  8,25, 10,31, 12,38, 14,44, 16,50, 18,56, 20,63, 22,69, 24,75, 26,81, 28,88, 30,94, 33,00 //Intervall 206,25 mV; je 2x2 Dezimalziffern
str_calibrationFailed: .asciz "Kalibrierung fehlgeschlagen! Kalibrierung wird erneut gestartet.\n"
str_calibrationSuccessful: .asciz "Kalibrierung erfolgreich\n"
str_start: .asciz "Wandlung gestartet\n"
str_stopp: .asciz "Wandlung angehalten\n"
str_wandlungsGenauigkeit: .asciz "Wandlungsgenauigkeit: "
str_bit: .asciz " Bit\n"
str_0x: .asciz "0x"
str_to: .asciz " - "
str_stufe: .asciz " mV (Stufe "
str_zeileBeenden: .asciz ")\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten
__BBREG PIT_MCR_MDIS, 0x40037000, 1
__BBREG PIT_TCTRL1_TEN, 0x40037118, 0 		
__BBREG PIT_TFLG1_TIF, 0x4003711C, 0   
.equ PIT_LDVAL1, 0x40037110 			
.equ PIT_TCTRL1, 0x40037118 
__BBREG SIM_SCGC3_I2C0, 0x40048034, 6
.equ SIM_SCGC5, 0x40048038
__BBREG SIM_PORTD, SIM_SCGC5 , 12
__BBREG SIM_SCGC6_PIT, 0x4004803C, 23
.equ PORTD_PCR8, 0x4004C020
.equ PORTD_PCR9, 0x4004C024
.equ I2C0_F, 0x40066001
.equ I2C0_C1, 0x40066002
__BBREG I2C0_C1_RSTA, I2C0_C1, 2
__BBREG I2C0_C1_TXAK, I2C0_C1, 3
__BBREG I2C0_C1_TX, I2C0_C1, 4
__BBREG I2C0_C1_MST, I2C0_C1, 5
.equ I2C0_S, 0x40066003
__BBREG I2C0_S_RXAK, I2C0_S, 0
__BBREG I2C0_S_IICIF, I2C0_S, 1
__BBREG I2C0_S_ARBL, I2C0_S, 4
__BBREG I2C0_S_BUSY, I2C0_S, 5
__BBREG I2C0_S_TCF,  I2C0_S, 7
.equ I2C0_D, 0x40066004
.equ I2C0_C2, 0x40066005
.equ GPIOD_PDOR, 0x400FF0C0
.equ GPIOD_PDIR, 0x400FF0D0
.equ GPIOD_PDDR, 0x400FF0D4

.equ NVIC_ISER0, 0xE000E100
.equ NVIC_ISER2, 0xE000E108
.equ NNVIC_ICPR0, 0xE000E280 
.equ NVIC_ICPR2, 0xE000E288

.equ PIT1_INTERRUPT_MASK, 0x20 //Maske zum aktivieren von IRQ  69 (PIT1)
.equ PIT1_INTERRUPT_VECTOR,  0x1FFFFF54

.equ PIT1_STARTWERT, 25000000//25000000     	//PIT1 Startwert, entspricht erforderlichen Takten fuer 1s (1s * 25MHz) 
.equ PIT_TCTRL1_VALUE, 0x03			//Timer mit Interrupts starten


.equ PD8_9 , 0x300 // Maske fuer PD8 und PD9
.equ PD8 , 0x100 // Maske fuer PD8
.equ ALT_GPIO , 0x100 // Alternative 1: GPIO
.equ ALT_I2C, 0x200 //Alternative 2: I2C

.equ I2C_DELAY_COUNTER, 13 //2us * 25MHz / 4 Zyklen

.equ I2C_FREQUENCY, 0x3e //25MHz / 400kHz = 62,5 -> 1*62
.equ I2C_ENABLE, 0xc0 //I2C mit Interrupts aktivieren
.equ I2C_START_ERROR_COUNTER, 50

.equ I2C0_INTERRUPT_MASK, 0x1000000//Maske zum aktivieren von IRQ  24 (I2C0) 
.equ I2C0_INTERRUPT_VECTOR,  0x1FFFFEA0

.equ I2C_TRANSFER_IN_PROGRESS,	0
.equ I2C_TRANSFER_COMPLETE, 	1
.equ I2C_ACKNOWLEDGE_FAILED,	2
.equ I2C_ARBITRATION_LOST, 		3

.equ DS75_ADDRESS_W, 0x90
.equ DS75_ADDRESS_R, 0x91
.equ DS75_TEMPERATURE_POINTER, 0
.equ DS75_CONFIGURATION_POINTER, 1
.equ DS75_THYST_POINTER, 2
.equ DS75_TOS_POINTER, 3
.equ DS75_CONFIGURATION_VALUE, 0x60
.equ DS75_DELAY_COUNTER, 7500000 //1200ms * 25MHz / 4 Zyklen

.equ BIT_4, 0x10
.equ BIT_5, 0x20
.equ BIT_6, 0x40
.equ BIT_7, 0x80

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl I2CBus_Reset
	bl i2c_init
	bl pit1_init
	bl ds75_init	
		
	//DS75 mit Pointer lesen
	bl ds75_readTemperatureWithPointer
	bl printTemperature
	
	bl pit1_start
	
mainLoop:
	//Sekundenflag auswerten
	ldr r0, =flag_sekunde
	ldrb r1, [r0]
	cmp r1, #0
	beq mainLoop
	mov r1, #0
	strb r1, [r0]	
	
	//Temperatur auswerten
	bl ds75_readTemperatureCurrentPointer
	bl printTemperature

	b mainLoop

/*
 * Liesst das Temperaturregister des DS75. Das Temperaturregister muss bereits ausgewaehlt sein.
 * Uebergabeparamter: keine
 * Rueckgabe: r0 - Temperatur im Format 8.4
 */	
.thumb_func
ds75_readTemperatureCurrentPointer:
	push {lr}
	
	mov r0, #DS75_ADDRESS_R
	ldr r1, =i2c_address
	strb r0, [r1]
	
	mov r0, #2
	ldr r1, =i2c_length
	strb r0, [r1]
	
	ldr r0, =ds75_readWriteBuffer
	ldr r1, =i2c_dataBufferAddress
	str r0, [r1]
	
	bl i2c_transfer
	
	ldr r0, =ds75_readWriteBuffer
	ldrh r0, [r0]
	
	pop {pc}

/*
 * Liesst das Temperaturregister des DS75.
 * Uebergabeparamter: keine
 * Rueckgabe: r0 - Temperatur im Format 8.4
 */	
.thumb_func
ds75_readTemperatureWithPointer:
	push {lr}
	
	mov r0, #DS75_ADDRESS_W
	ldr r1, =i2c_address
	strb r0, [r1]
	
	mov r0, #DS75_ADDRESS_R
	ldr r1, =i2c_addressRepeatedStart
	strb r0, [r1]
	
	mov r0, #1
	ldr r1, =i2c_length
	strb r0, [r1]
	
	mov r0, #2
	ldr r1, =i2c_lengthRepeatedStart
	strb r0, [r1]
	
	ldr r0, =ds75_readWriteBuffer 
	ldr r1, =i2c_dataBufferAddress
	str r0, [r1]
	ldr r1, =i2c_dataBufferAddressRepeatedStart
	str r0, [r1]
	mov r1, #DS75_TEMPERATURE_POINTER
	strb r1, [r0]
	
	mov r0, #1
	ldr r1, =i2c_flagRepeatedStart
	strb r0, [r1]
	
	bl i2c_transfer
	
	ldr r0, =ds75_readWriteBuffer
	ldrh r0,  [r0]
	
	pop {pc}
	
/*
 * Initialisiert das DS75 (beinhaltet TOS und THYST)
 */	
.thumb_func
ds75_init:
	push {r4, r5, lr}
	//DS75 Konfiguration schreiben
	mov r0, #DS75_ADDRESS_W
	ldr r1, =i2c_address
	strb r0, [r1]
	
	mov r0, #2
	ldr r1, =i2c_length
	strb r0, [r1]
	 
	ldr r0, =ds75_readWriteBuffer
	ldr r1, =i2c_dataBufferAddress
	str r0, [r1]
	mov r1, #DS75_CONFIGURATION_POINTER
	strb r1, [r0], #1
	mov r1, #DS75_CONFIGURATION_VALUE
	strb r1, [r0]
	
	bl i2c_transfer
	
	bl ds75_delay //Warten, dass ein Temperaturwert mit 12 Bit Aufloesung gewandelt wurde
	
	//DS75 T0 lesen
	ldr r0, =str_t0
	bl uart_putString
	
	bl ds75_readTemperatureWithPointer
	mov r4, r0
	bl printTemperature
	
	
	//Berechnung TOS, THYST	
	mov r0, r4
	mov r1, #3
	add r4, r0, r1, lsl #8
	sub r1, r1, #1
	add r5, r0, r1, lsl #8
	
	//TOS schreiben
	mov r0, #DS75_ADDRESS_W
	ldr r1, =i2c_address
	strb r0, [r1]
	
	mov r0, #3
	ldr r1, =i2c_length
	strb r0, [r1]
	 
	ldr r0, =ds75_readWriteBuffer 
	ldr r1, =i2c_dataBufferAddress
	str r0, [r1]
	mov r1, #DS75_TOS_POINTER
	strb r1, [r0], #1
	lsr r2, r4, #8
	strb r2, [r0], #1
	strb r4, [r0]	
	
	bl i2c_transfer
	
	ldr r0, =str_tos
	bl uart_putString
	mov r0, r4
	bl printTemperature
	
	//THYST schreiben
	mov r0, #DS75_ADDRESS_W
	ldr r1, =i2c_address
	strb r0, [r1]
	
	mov r0, #3
	ldr r1, =i2c_length
	strb r0, [r1]
	 
	ldr r0, =ds75_readWriteBuffer 
	ldr r1, =i2c_dataBufferAddress
	str r0, [r1]
	mov r1, #DS75_THYST_POINTER
	strb r1, [r0], #1
	lsr r2, r5, #8
	strb r2, [r0], #1
	strb r5, [r0]
	
	bl i2c_transfer	
	
	ldr r0, =str_thyst
	bl uart_putString
	mov r0, r5
	bl printTemperature
	
	pop {r4, r5, pc}
	
/*
 * Unterprogram zur Erzeugung von einer Verzoegerung entsprechend des maximalen Zeitaufwands fuer eine 12-Bit Wandlung (1200ms).
 * Uebergabeparamter: keine
 */
.thumb_func		
ds75_delay:
	ldr r0, =DS75_DELAY_COUNTER
ds75_delay_loop:
	subs r0, #1
	bne ds75_delay_loop
	bx lr
	
	
/*
 * Gibt die Temperatur aus.
 * Uebergabeparameter: r0 - auszugebende Temperatur
 */	
.thumb_func
printTemperature:
	push {r4, lr}
	mov r4, r0
	mov r0, #'0'
	bl uart_putChar
	mov r0, #'x'
	bl uart_putChar
	
	lsl r0, r4, #8
	bl uart_putInt32
	
	mov r0, #':'
	bl uart_putChar
	mov r0, #' '
	bl uart_putChar
	
	mov r0, r4
	bl uart_put8p4Base10
	
	ldr r0, =str_GradCelsius
	bl uart_putString
	
	pop {r4, pc}

	
/*
 * Gibt eine Festkomma-Zahl im Format 8.4 in dezimaler Form aus.
 * Uebergabe R0: auszugebender Wert. 2^(-4) beginnt auf Bit 4.
 */	
.thumb_func
uart_put8p4Base10:
	push {r4, lr}
	mov r4, r0
	lsr r0, r0, #8
	
	bl uart_putByteBase10
	
	mov r0, #','
	bl uart_putChar
	
	//Dezimale Nachkommastellen berechnen (r0 Nachkommastellen 1-2, r1 Nachkommastellen 3-4)
	mov r1, #0
	
	tst r4, #BIT_7
	ite ne
	movne r0, #50
	moveq r0, #0
	
	tst r4, #BIT_6
	it ne
	addne r0, r0, #25
	
	tst r4, #BIT_5
	itt ne
	addne r0, r0, #12
	addne r1, r1, #50
	
	tst r4, #BIT_4
	itt ne
	addne r0, r0, #6
	addne r1, r1, #25
	
	//Nachkommastellen ausgeben
	mov r4, r1
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen	
	
	mov r0, r4
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen

	pop {r4, pc}
	
/*
 * Fuehrt eine I2C Uebertragung aus.
 */
.thumb_func
i2c_transfer:	
	push {r4, lr}
	mov r4, #0

i2c_transfer_start:		
	bl i2c_start
	bl i2c_waitRepeatedStart
	bl i2c_wait
	
	//Auf Uebertragungsfehler pruefen
	cmp r0, #I2C_TRANSFER_COMPLETE
	beq i2c_transfer_successful 
	
	bl i2c_Delay
	add r4, r4, #1
	cmp r4, #50
	bne i2c_transfer_start
	
	ldr r0, =str_transferFailed
	bl uart_putString	
	
i2c_transfer_successful:	
	bl i2c_Delay
	
	pop {r4, pc}
	
/*
 * Erzeugt die Startbedingung und gibt die Adresse fuer eine I2C Uebertragung aus.
 */
.thumb_func
i2c_start:	
	mov r0, #0
	ldr r1, =i2c_result
	strb r0, [r1]
	
	mov r0, #0
	ldr r1, =i2c_addressed
	strb r0, [r1]
		
	//TXAK setzen: NACK ausgeben
	mov r0, #0
	ldr r1, =I2C0_C1_TXAK
	strb r0, [r1]
	
	mov r1, #1
	ldr r2, =I2C0_C1_TX
	strb r1, [r2]
	
	ldr r2, =I2C0_C1_MST
	strb r1, [r2]
	
	ldr r0, =i2c_address
	ldrb r0, [r0]
	ldr r1, =I2C0_D
	strb r0, [r1]
	
	bx lr
	
/*
 * Blockiert bis zum Ende der aktuellen i2c Uebertragung
 * Rueckgabe: Status der Uebertragung
 */
.thumb_func
i2c_wait:
	ldr r1, =i2c_result
	ldrb r0, [r1]
	cmp r0, #I2C_TRANSFER_IN_PROGRESS
	beq i2c_wait
	bx lr

/*
 * Blockiert bis zum Erreichen einer Repeated Start Bedingung in der aktuellen i2c Uebertragung
 */	
.thumb_func
i2c_waitRepeatedStart:
	ldr r1, =i2c_flagRepeatedStart
	ldrb r0, [r1]
	cmp r0, #0
	bne i2c_waitRepeatedStart
	bx lr
	
	
.thumb_func
i2c_init:
	// Den Takt fuer Port D aktivieren
	ldr r0, =SIM_PORTD 
	mov r1, #1
	str r1, [r0]
	//Takt fuer I2C0 aktivieren
	ldr r0, =SIM_SCGC3_I2C0
	str r1, [r0]
	
	// Portleitungen PD8, PD9 als SCL, SDA
	ldr r0, =PORTD_PCR8 
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_I2C
	str r2, [r0]
	str r2, [r1]
	
	//Interrupt-Vektor I2C0 setzen  (NVIC)
	ldr r0, =isr_i2c0
	ldr r1, =I2C0_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts I2C0 loeschen (NVIC) 
	ldr r0, =NNVIC_ICPR0
	mov r1, #I2C0_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt I2C0 aktivieren (NVIC)
	ldr r0, =NVIC_ISER0
	str r1, [r0]
	
	//I2C Konfiguration
	ldr r0, =I2C0_F
	mov r1, #I2C_FREQUENCY
	strb r1, [r0]
	
	ldr r0, =I2C0_C2
	mov r1, #0 
	strb  r1, [r0]
	
	ldr r0, =I2C0_C1
	mov r1, #I2C_ENABLE
	strb  r1, [r0]
		
	bx lr
	
/*
 * Unterprogram zur Erzeugung von einer Verzoegerung von etwa 2us.
 * Uebergabeparamter: keine
 */
.thumb_func		
i2c_Delay:
	ldr r0, =I2C_DELAY_COUNTER
i2c_delay_loop:
	subs r0, #1
	bne i2c_delay_loop
	bx lr
	
/* **************** I2C -Bus zuruecksetzen *********** */
.thumb_func
I2CBus_Reset:
	push {lr}
	
	ldr r0, =SIM_PORTD // Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR8 // Portleitungen PD8 , PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR // PD8 , PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2 , #PD8_9
	str r2, [r0]
	
loop:
	// Ein Zaehler fuer maximal 10 Versuche ist zu implementieren .
	// Ggf. Fehlermeldung auf Terminal ausgeben und abbrechen .
	ldr r0, =GPIOD_PDOR // SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD8 // entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDOR // SCL und SDA aktivieren
	ldr r2, [r0]
	orr r2, r2 , #PD8_9
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2 , #PD8_9 // nur Bits 9 und 10 pruefen
	cmp r2, #PD8_9 // Bit 9 und Bit 10 gesetzt ?
	bne loop // ggf. wiederholen
	
	pop {pc}
	
/*
 * Unterprogramm zur Initialisierung von PIT1 zum Ausloesen von Interrupts nach je 1s.
 * PIT1 muss separat gestartet werden. 
 */
.thumb_func
pit1_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC6_PIT
	str r1, [r0] 
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_pit1
	ldr r1, =PIT1_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts PIT1 loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	mov r1, #PIT1_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt PIT1 aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	//PIT Modul aktivieren
	ldr r0, =PIT_MCR_MDIS
	mov r1, #0
	str r1, [r0]
	
	//PIT1 Startwert setzen
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT1_STARTWERT
	str r1, [r0]
		
	bx lr
	
/*
 * PIT1 mit Interrupts aktivieren
 */	
.thumb_func
pit1_start:
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_VALUE
	str r1, [r0]
	
	bx lr
	
/*
* Interruptroutine zu PIT1. 
*/
.thumb_func
isr_pit1:
	//Interrupt loeschen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	//Flag setzen
	ldr r0, =flag_sekunde
	strb r1, [r0] 
	bx lr

	
/*
* Interruptroutine zu PIT1. 
*/
.thumb_func
isr_i2c0:
	//Interrupt loeschen
	ldr r0, =I2C0_S_IICIF
	mov r1, #1
	strb r1, [r0]
	
	//Master mode?
	ldr r0, =I2C0_C1_MST
	ldrb r0, [r0]
	cmp r0, #0	
	beq checkArbitrationLost
	
	//TX / RX ?
	ldr r0, =I2C0_C1_TX
	ldrb r0,  [r0]
	cmp r0, #0
	beq isr_i2c0_rx
	
	//Last byte transmitted?
	ldr r0, =i2c_length
	ldrb r0,  [r0]
	cbz r0, tx_finish
	
	//RXAK=0?
	ldr r0, =I2C0_S_RXAK
	ldrb r0, [r0]
	cbz r0, checkAddressed
	
	mov r0, #I2C_ACKNOWLEDGE_FAILED
	ldr r1, =i2c_result
	strb r0, [r1]
	b stop
	
checkAddressed:
	ldr r0, =i2c_addressed
	ldrb r1, [r0]
	cbnz r1, writeNextByte
	
	//Addressed flag setzen
	mov r1, #1
	strb  r1, [r0]
	
	ldr r0, =i2c_address
	ldrb r0, [r0]
	
	tst r0, #1
	beq writeNextByte
	
	//Auf RX wechseln
	ldr r0, =I2C0_C1_TX
	mov r1, #0
	strb r1, [r0]
	//Dummy read
	ldr r0, =I2C0_D
	ldrb r0, [r0]
	
	b isr_i2c0_end
	
		
writeNextByte:
	//Addresse des zu schreibenden Bytes laden und erhoehen
	ldr r0, =i2c_dataBufferAddress
	ldr r2, [r0]
	add r1, r2, #1 //Addresse fuer naechstes Byte erhoehen
	str r1, [r0]
	
	//Laenge verringern
	ldr r0, =i2c_length 
	ldrb r1, [r0]
	sub r1, r1, #1
	strb r1, [r0]
	
	//Byte laden und auf Bus schreiben
	ldrb r2, [r2] 	
	ldr r0, =I2C0_D
	strb r2, [r0]
	
	b isr_i2c0_end
	
			
tx_finish:
	mov r0, #I2C_TRANSFER_COMPLETE
	ldr r1, =i2c_result
	strb r0, [r1]
	
stop:
	ldr r0, =i2c_flagRepeatedStart
	ldrb r1, [r0]
	cbnz r1, repeated_start
	mov r1, #0
	ldr r2, =I2C0_C1_MST
	strb r1, [r2]
	b isr_i2c0_end

repeated_start:
	mov r0, #0
	ldr r1, =i2c_flagRepeatedStart
	strb r0, [r1]
	
	ldr r1, =i2c_addressed
	strb r0, [r1]
	
	ldr r1, =i2c_result
	strb r0, [r1]
	
	ldr r0, =i2c_lengthRepeatedStart
	ldrb r0, [r0]
	ldr r1, =i2c_length
	strb r0, [r1]
	
	ldr r0, =i2c_dataBufferAddressRepeatedStart
	ldr r0, [r0]
	ldr r1, =i2c_dataBufferAddress
	str r0, [r1]
	
	ldr r0, =i2c_addressRepeatedStart
	ldrb r0, [r0]
	ldr r1, =i2c_address
	strb r0, [r1]
	
	ldr r1, =I2C0_C1_RSTA
	mov r2, #1
	strb r2, [r1]
	
	ldr r1, =I2C0_D
	strb r0, [r1]
	
	b isr_i2c0_end
	
isr_i2c0_rx:
	ldr r0, =i2c_length
	ldrb r3, [r0]
	subs r3, r3, #1
	strb r3, [r0]
	
	beq read_stop
	
	cmp r1, #1
	beq set_txak
	
read_byte:
	//Byte lesen
	ldr r0, =I2C0_D
	ldrb r0, [r0]
	ldr r1, =i2c_dataBufferAddress
	ldr r2, [r1]
	strb r0, [r2, +r3] //Puffer beim Lesen von hinten beschreiben 
	
	b isr_i2c0_end
	
set_txak:
	mov r0, #1
	ldr r1, =I2C0_C1_TXAK
	strb r0, [r1]
	b read_byte
	
	
read_stop:
	mov r1, #0
	ldr r2, =I2C0_C1_MST
	strb r1, [r2]
	
	mov r0, #I2C_TRANSFER_COMPLETE
	ldr r1, =i2c_result
	strb r0, [r1]
	
	b read_byte
	
	
checkArbitrationLost:
	mov r0, #I2C_ARBITRATION_LOST
	ldr r1, =i2c_result
	strb r0, [r1]
	
	mov r0, #1
	ldr r1, =I2C0_S_ARBL
	strb r0, [r1]
	
isr_i2c0_end:
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
i2c_addressed: .byte 0
i2c_address: .byte 0
i2c_length: .byte 0
i2c_result: .byte 0
i2c_dataBufferAddress: .word 0
i2c_flagRepeatedStart: .byte 0
i2c_lengthRepeatedStart: .byte 0
i2c_addressRepeatedStart: .byte 0
i2c_dataBufferAddressRepeatedStart: .word 0
flag_sekunde: .byte 0
ds75_readWriteBuffer: .word 0
str_GradCelsius: .asciz " Grad Celsius\n"
str_t0: .asciz "T0: "
str_thyst: .asciz "THYST: "
str_tos: .asciz "TOS: "
str_transferFailed: .asciz "I2C Uebertragung fehlgeschlagen\n"


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//SFRs und Konstanten
__BBREG PIT_MCR_MDIS, 0x40037000, 1
__BBREG PIT_TCTRL1_TEN, 0x40037118, 0 		
__BBREG PIT_TFLG1_TIF, 0x4003711C, 0   
.equ PIT_LDVAL1, 0x40037110 			
.equ PIT_TCTRL1, 0x40037118

__BBREG SIM_SCGC3_SPI2,  0x40048030, 12
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC5_PORTD, 0x40048038, 12
__BBREG SIM_SCGC5_PORTE, 0x40048038, 13
__BBREG SIM_SCGC6_PIT,   0x4004803C, 23

.equ PORTA_PCR19, 0x4004904C		//SW1
.equ PORTE_PCR26, 0x4004D068		//SW2
.equ PORTD_PCR12, 0x4004C030 //PTD12 SPI2_CLK
.equ PORTD_PCR13, 0x4004C034 //PTD13 SPI2_SOUT
.equ PORTD_PCR14, 0x4004C038 //PTD14 SPI2_SIN
.equ PORTD_PCR15, 0x4004C03C //PTD15 SPI2_PCS1
__BBREG PORTA_ISFR_PTA19, 0x400490A0, 19
__BBREG PORTE_ISFR_PTE26, 0x4004D0A0, 26

__BBREG GPIOA_PDDR_PTA19, 0x400FF014, 19  
__BBREG GPIOE_PDDR_PTE26, 0x400FF114, 26

.equ SPI2_MCR, 0x400AC000
.equ SPI2_CTAR0, 0x400AC00C
.equ SPI2_SR, 0x400AC02C
.equ SPI2_RSER, 0x400AC030
.equ SPI2_PUSHR, 0x400AC034
.equ SPI2_POPR, 0x400AC038
__BBREG SPI2_MCR_HALT, SPI2_MCR, 0
__BBREG SPI2_SR_TCF, SPI2_SR, 31
__BBREG SPI2_SR_EOQF, SPI2_SR, 28


.equ NVIC_ISER2, 0xE000E108 
.equ NVIC_ICPR2, 0xE000E288

.equ PIT1_INTERRUPT_MASK, 0x20 //Maske zum aktivieren von IRQ  69 (PIT1)
.equ PIT1_INTERRUPT_VECTOR,  0x1FFFFF54

.equ PIT1_STARTWERT, 25000000//25000000     	//PIT1 Startwert, entspricht erforderlichen Takten fuer 1s (1s * 25MHz) 
.equ PIT_TCTRL1_VALUE, 0x03			//Timer mit Interrupts starten

.equ SW12_INTERRUPT_MASK, 0x08800000//IRQ 87 und 91 (PORTA und E)
.equ INTERRUPT_VECTOR_PORTA, 0x1FFFFF9C
.equ INTERRUPT_VECTOR_PORTE, 0x1FFFFFAC

.equ PCR_SW, 0xa0103 //Pin als GPIO konfigrieren, Pullup aktivieren, Interrupt bei fallender Flanke
.equ PCR_SPI2, 0x200 //ALT2 (SPI2)

.equ SPI2_MCR_VALUE, 0x80003C01 //Master mode, PCS1 inaktiv auf Low, TX/RX FIFO deaktivert, TX/RX FIFO loeschen, halt
.equ SPI2_CTAR0_VALUE,0x3a009996// 0x3a006666 //8 Bit Laenge, MSB First, ca. 100 kHz Baudrate
.equ SPI2_RSER_VALUE, 0x00 //kein Interrupt/DMA Requests
.equ SPI2_CLEAR_SR_MASK, 0xda0a0000 //loescht alle gesetzten Statusbits

.equ DS1722_CONFIGURATION_ADDRESS, 0x80
.equ DS1722_TEMPERATURE_ADDRESS, 0x01
.equ DS1722_CONFIGURATION_MASK, 0xE0 //Kontinuierliche Messung. Aufloesung wird dynamisch ergaenzt.
.equ DS1722_RESOLUTION_8BIT, 0
.equ DS1722_RESOLUTION_9BIT, 1
.equ DS1722_RESOLUTION_10BIT, 2
.equ DS1722_RESOLUTION_11BIT, 3
.equ DS1722_RESOLUTION_12BIT, 4

.equ PUSHR_TEMPLATE,  0x80020000 //PCS1 aktivieren und aktiv lassen 
.equ PUSHR_LAST_BYTE, 0x08020000 //PCS1 im Anschluss deaktivieren, End of Queue

.equ MASK_BIT_0_3, 0x0F


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl sw12_init
	bl pit1_init
	bl spi2_init
	
	mov r0, #DS1722_RESOLUTION_12BIT
	bl setResolution
	
	ldr r4, =flag_sw1
	ldr r5, =flag_sw2
	ldr r6, =flag_pit
	mov r7, #0
mainLoop:
	//Taste 1 auswerten
	ldrb r1, [r4]
	cbz r1, checkSw2
	strb r7, [r4]
	bl increaseResolution	

checkSw2:
	//Taste 2 auswerten
	ldrb r1, [r5]
	cbz r1, checkPit
	strb r7, [r5]
	bl decreaseResolution

checkPit:
	//Zeit auswerten
	ldrb r1, [r6]
	cmp r1, #0
	beq mainLoop
	strb r7, [r6]
	
	bl ds1722_readTemperature
	bl printTemperature	
	b mainLoop

/*
 * Gibt die Temperatur aus.
 * Uebergabeparamter: R0 - Temperaturwert (im Format des DS1722)
 */
.thumb_func	
printTemperature:
	push {r4, lr}
	mov r4, r0
	
	//Vorkommastellen ausgeben
	lsr r0, r4, #8 
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	mov r0, #','
	bl uart_putChar
	
	//Adresse fuer vorberechnete Nachkommastellen berechnen
	lsr r0, r4, #4
	and r0, r0, #MASK_BIT_0_3	
	ldr r4, =temperatureDecimalPlaces
	add r4, r4, r0, lsl #1 
	
	//Nachkommastellen 1-2 ausgeben
	ldrb r0, [r4], #1
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	//Nachkommastellen 3-4 ausgeben
	ldrb r0, [r4]
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	//gC ausgeben
	ldr r0, =str_gC
	bl uart_putString
	
	pop {r4, pc}
	

/*
 * Erhoeht die Aufloesung des DS1722
 */
.thumb_func	
increaseResolution:
	push {lr}
	ldr r1, =resolution
	ldrb r0, [r1]
	cmp r0, #DS1722_RESOLUTION_11BIT
	ite hi
	movhi r0, #0
	addls r0, r0, #1
	strb r0, [r1]
	
	bl setResolution
	pop {pc}
	
/*
 * Verringert die Aufloesung des DS1722
 */
.thumb_func	
decreaseResolution:
	push {lr}
	ldr r1, =resolution
	ldrb r0, [r1]
	cmp r0, #DS1722_RESOLUTION_8BIT
	ite eq
	moveq r0, #DS1722_RESOLUTION_12BIT
	subne r0, r0, #1
	strb r0, [r1]
	
	bl setResolution
	pop {pc}
	
/*
 * Stellt die Aufloesung auf die uebergebene Stufe ein.
 * Uebergabe: R0 - einzustellende Stufe (0 - 4)
 */
.thumb_func
setResolution:
	push {r4, lr}
	mov r4, r0
	
	//DS1722 konfigurieren
	bl ds1722_writeConfig
	
	//PIT stoppen
	ldr r0, =PIT_TCTRL1_TEN
	mov r1, #0
	str r1, [r0]
	
	//PIT Startwert anpassen
	ldr r0, =conversionTime
	ldr r0, [r0, r4, lsl #2]
	ldr r1, =PIT_LDVAL1
	str r0, [r1]
	
	//Zeit-Flag ggf. loeschen
	ldr r0, =flag_pit
	mov r1, #0
	strb r1, [r0]	
	
	//PIT1 starten
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_VALUE
	str r1, [r0]
		
	//Aufloesung ausgeben
	ldr r0, =str_resolution
	bl uart_putString
	
	ldr r0, =bitResolution
	ldrb r0, [r0, r4]
	
	bl uart_putByteBase10 
	ldr r0, =str_bit
	bl uart_putString
	
	pop {r4, pc}

/*
 * Beschreibt das Konfigurationsregister des ds1722
 * Uebergabeparameter: R0 - Stufe der Aufloesung (0 - 4)
 */	
.thumb_func
ds1722_writeConfig: 
	push {r4, lr}
	mov r4, r0
	
	//HALT loeschen
	mov r0, #0
	ldr r1, =SPI2_MCR_HALT
	str r0, [r1]
	
	//Adresse schreiben
	ldr r0, =PUSHR_TEMPLATE
	orr r1, r0, #DS1722_CONFIGURATION_ADDRESS
	ldr r2, =SPI2_PUSHR
	str r1, [r2]
	
	bl spi2_waitTCF	
	
	//Dummy Byte lesen
	ldr r3, =SPI2_POPR
	ldr r0, [r3]
	
	//Konfiguration schreiben
	ldr r0, =PUSHR_LAST_BYTE
	orr r0, r0, #DS1722_CONFIGURATION_MASK
	orr r0, r0, r4, lsl #1 //Aufloesung	
	ldr r2, =SPI2_PUSHR
	str r0, [r2]
	
	bl spi2_waitTCF
	
	//Dummy Byte lesen
	ldr r3, =SPI2_POPR
	ldr r0, [r3]
		
	mov r0, #1
	ldr r1, =SPI2_SR_EOQF
	str r0, [r1]
	
	pop {r4, pc}

/*
 * Liesst einen Temperaturwert vom DS1722 ein.
 * Uebergabeparameter: keine
 * Rueckgabe: R0 - Temperaturwert
 */	
.thumb_func
ds1722_readTemperature:
	push {r4, lr}

	//HALT loeschen
	mov r0, #0
	ldr r1, =SPI2_MCR_HALT
	str r0, [r1]
			
	//Adresse schreiben
	ldr r0, =SPI2_PUSHR
	ldr r1, =PUSHR_TEMPLATE
	orr r2, r1, #DS1722_TEMPERATURE_ADDRESS
	str r2, [r0]
	
	bl spi2_waitTCF
	
	//Dummy Byte lesen
	ldr r0, =SPI2_POPR
	ldr r0, [r0]
	
	// 1. Dummy Write
	ldr r0, =SPI2_PUSHR
	ldr r1, =PUSHR_TEMPLATE
	str r1, [r0]
	
	bl spi2_waitTCF
	
	//1. Byte lesen
	ldr r0, =SPI2_POPR
	ldr r4, [r0]
	
	// 2. Dummy Write
	ldr r0, =SPI2_PUSHR
	ldr r1, =PUSHR_LAST_BYTE
	str r1, [r0] 
		
	bl spi2_waitTCF
	
	//2. Byte lesen
	ldr r0, =SPI2_POPR
	ldr r0, [r0]
	orr r4, r4, r0, lsl #8
	
	//EOQF loeschen		
	mov r0, #1
	ldr r1, =SPI2_SR_EOQF
	str r0, [r1]
	
	mov r0, r4
	pop {r4, pc}

/*
 * Wartet auf Abschluss der Uebertragung
 */	
.thumb_func
spi2_waitTCF:
	ldr r0, =SPI2_SR_TCF
checkTCF:
	ldr r1, [r0]
	cmp r1, #1
	bne checkTCF
	
	//Flag loeschen
	str r1, [r0]
	bx lr

	
/*
 * Initialisiert die SPI2 Schnittstelle
 */
.thumb_func
spi2_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC5_PORTD
	str r1, [r0]
	ldr r0, =SIM_SCGC3_SPI2
	str r1, [r0]
	
	//Pins konfigurieren
	ldr r1, =PCR_SPI2
	ldr r0, =PORTD_PCR12
	str r1, [r0]
	ldr r0, =PORTD_PCR13
	str r1, [r0]
	ldr r0, =PORTD_PCR14
	str r1, [r0]
	ldr r0, =PORTD_PCR15
	str r1, [r0]
	
	//SPI2 Modul konfigurieren
	ldr r1, =SPI2_MCR_VALUE
	ldr r0, =SPI2_MCR
	str r1, [r0] //MDIS loeschen
	str r1, [r0] //DIS_TXF / DIS_RXF setzen
	
	ldr r1, =SPI2_CTAR0_VALUE
	ldr r0, =SPI2_CTAR0
	str r1, [r0]
	
	mov r1, #SPI2_RSER_VALUE
	ldr r0, =SPI2_RSER
	str r1, [r0]
	
	//Status loeschen
	ldr r0, =SPI2_CLEAR_SR_MASK
	ldr r1, =SPI2_SR
	str r0, [r1]	
		
	bx lr
	
/*
 * Initialisiert die Verwendung der Tasten 1 und 2 zum Ausloesen eines Interrupts.
 */	
.thumb_func
sw12_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]
	ldr r0, =SIM_SCGC5_PORTE
	str r1, [r0]
	
	//Interrupt-Vektor PORTA und PORTE setzen  (NVIC)
	ldr r0, =isr_portA
	ldr r1, =INTERRUPT_VECTOR_PORTA	 
	str r0, [r1]
	ldr r0, =isr_portE
	ldr r1, =INTERRUPT_VECTOR_PORTE	 
	str r0, [r1]
	
	//Pending Interrupts PORTA und PORTE loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	ldr r1, =SW12_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt PIT1 und PORTE aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	ldr r1, =SW12_INTERRUPT_MASK
	str r1, [r0]
	
	//Pins konfigurieren
	ldr r1, =PCR_SW
	ldr r0, =PORTA_PCR19
	str r1, [r0]
	ldr r0, =PORTE_PCR26
	str r1, [r0]
	
	//GPIO konfigurieren (Tasten)
	mov r0, #0
	ldr r1, =GPIOA_PDDR_PTA19
	str r0, [r1]
	ldr r1, =GPIOE_PDDR_PTE26
	str r0, [r1]
		
	bx lr
	
	
/*
 * Unterprogramm zur Initialisierung von PIT1 zum Ausloesen von Interrupts nach je 1s.
 * PIT1 muss separat gestartet werden. 
 */
.thumb_func
pit1_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC6_PIT
	str r1, [r0] 
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_pit1
	ldr r1, =PIT1_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts PIT1 loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	mov r1, #PIT1_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt PIT1 aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	//PIT Modul aktivieren
	ldr r0, =PIT_MCR_MDIS
	mov r1, #0
	str r1, [r0]
	
	//PIT1 Startwert setzen
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT1_STARTWERT
	str r1, [r0]
		
	bx lr
	
	
/*
* Interruptroutine zu PIT1. 
*/
.thumb_func
isr_pit1:
	//Interrupt loeschen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	//Flag setzen
	ldr r0, =flag_pit
	strb r1, [r0] 
	bx lr

/*
 * Interruptroutine zu PORTA. 
 */
.thumb_func
isr_portA:
	//Interrupt loeschen
	ldr r0, =PORTA_ISFR_PTA19
	mov r1, #1
	str r1, [r0]
	
	//Flag setzen
	ldr r0, =flag_sw1
	strb r1, [r0] 
		 
	bx lr
	
/*
 * Interruptroutine zu PORTE. 
 */
.thumb_func
isr_portE:
	//Interrupt loeschen
	ldr r0, =PORTE_ISFR_PTE26
	mov r1, #1
	str r1, [r0]
	
	//Flag setzen
	ldr r0, =flag_sw2
	strb r1, [r0] 
		 
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_pit: .byte 0
flag_sw1: .byte 0
flag_sw2: .byte 0
resolution: .byte 4
bitResolution: .byte 8, 9, 10, 11, 12
conversionTime: .word 1875000, 3750000, 7500000, 15000000, 30000000 //PIT1 Startwerte, entspricht erforderlichen Takten fuer 0.075s, 0.15s, 0.3s, 0.6s oder 1.2s (t * 25MHz) 
temperatureDecimalPlaces: .byte 0,0, 06,25, 12,50, 18,75, 25,00, 31,25, 37,50, 43,75, 50,00, 56,25, 62,50, 68,75, 75,00, 81,25, 87,50, 93,75 //Nachkommastellen der Temperaturwerte. Jeweils 2 * 2 Nachkommastellen
str_gC: .asciz " gC\n"
str_resolution: .asciz "Aufloesung: "
str_bit: .asciz " Bit\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//SFRs
.equ RTC_TSR, 0x4003D000
.equ RTC_TPR, 0x4003D004
.equ RTC_TAR, 0x4003D008
.equ RTC_TCR, 0x4003D00C
.equ RTC_CR, 0x4003D010
.equ RTC_SR, 0x4003D014
.equ RTC_IER, 0x4003D01C
__BBREG RTC_SR_TCE, RTC_SR, 4
__BBREG RTC_SR_TAF, RTC_SR, 2

__BBREG SIM_SCGC6_RTC, 0x4004803C, 29

.equ NVIC_ISER2, 0xE000E108 
.equ NVIC_ICPR2, 0xE000E288


.equ RTC_TCR_VALUE, 0x00 //Keine Kompensation
.equ RTC_CR_VALUE, 0x100 //Keine zusaetzlichen Kapazitaeten, kein Clock output, Oszillator aktiviert, kein UpdateMode, Supervisor Access, Wakeup Pin deaktiviert.
.equ RTC_TAR_VALUE1H, 3599
.equ RTC_TAR_VALUE24H,86399
.equ RTC_IER_VALUE, 0x10 //Interrupt nur fuer Time Seconds Interrupt
 
.equ RTC_INTERRUPT_MASK, 0x08 //Maske zum aktivieren von IRQ  67 (RTC - Seconds interrupt)
.equ RTC_INTERRUPT_VECTOR,  0x1FFFFF4C

.equ RTC_DELAY_COUNTER, 6250000 //1s * 25MHz / 4 Zyklen    Aufgrund keiner genaueren Kenntnisse ueber das Einschwingverhalten, wird hier grosszuegig 1s gewartet.

.equ DAY_IN_SECONDS, 86400
.equ HOUR_IN_SECONDS, 3600
.equ MINUTE_IN_SECONDS, 60
.equ DELTA_PRESET, 4



/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl rtc_init

	ldr r4, =flagSecond
	ldr r5, =RTC_TSR
loop:
	//Pruefen, ob Eingabe vorhanden
	bl uart_charPresent
	
	cmp r0, #0
	beq output //Wenn keine Eingabe vorhanden, fortfahren mit Ausgabe.
	
	//Zeichen laden
	bl uart_getChar
	mov r6, r0
	
	//Zeichenvergleich d
	cmp r6, #'d'
	bne checkH
	mov r0, #0
	bl setMode
	
checkH:
	//Zeichenvergleich h
	cmp r6, #'h'
	bne checkR
	mov r0, #1
	bl setMode
	
checkR:
	cmp r6, #'r'
	bne checkS
	
	//Timer deaktivieren
	mov r0, #0
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	//Uhr zuruecksetzen
	ldr r1, =RTC_TPR
	str r0, [r1]
	ldr r1, =RTC_TSR
	str r0, [r1]
	
	//Timer aktivieren
	mov r0, #1
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	ldr r0, =str_clockReset
	bl uart_putString
	
	
checkS:
	cmp r6, #'s'
	bne checkP
	
	ldr r0, =flagOutput
	ldrb r1, [r0]
	eors r1, r1, #1
	strb r1, [r0] 
	
	ite eq
	ldreq r0, =str_outputDisabled
	ldrne r0, =str_outputEnabled
	bl uart_putString 
	
checkP:
	cmp r6, #'p'
	bne output
	
	//Timer deaktivieren
	mov r0, #0
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	//Uhr vorstellen
	ldr r1, =RTC_TPR
	str r0, [r1]
	
	ldr r0, =RTC_TAR
	ldr r0, [r0]
	sub r0, r0, #DELTA_PRESET
	
	ldr r1, =RTC_TSR
	str r0, [r1]
	
	//Timer aktivieren
	mov r0, #1
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	ldr r0, =str_clockPreset
	bl uart_putString
	
output:
	//Alarmflag ueberpruefen
	ldr r0, =RTC_SR_TAF //TODO register vor schleife initialisieren
	ldr r0, [r0]
	cbz r0, printClock
	
	//Ausgabe Endzeitpunkt erreicht
	ldr r0, =str_alarm
	bl uart_putString
	
	//RTC_SR_TAF loeschen
	ldr r0, =RTC_TAR
	ldr r1, [r0]
	str r1, [r0]
		
printClock:
	//Ausgabeflag ueberpruefen
	ldr r0, =flagOutput //TODO register vor schleife initialisieren
	ldrb r0, [r0]
	cmp r0, #0
	beq loop
	
	//Sekundenflag ueberpruefen
	ldrb r0, [r4]
	cmp r0, #1
	bne loop
	
	//Flag loeschen
	mov r0, #0
	strb r0, [r4] 
	
	//abgelaufene Sekunden laden
	ldr r6, [r5]
	
	//Ausgabe
	mov r0, #'\n'
	bl uart_putChar
	
	//Tage
	ldr r1, =DAY_IN_SECONDS 
	udiv r0, r6, r1
	mls r6, r0, r1, r6 //Tage in Sekunden von den abgelaufenen Sekunden abziehen.
	
	//Stunden
	mov r1, #HOUR_IN_SECONDS
	udiv r0, r6, r1
	mls r6, r0, r1, r6
	
	ldr r2, =flagMode
	ldrb r2, [r2]
	cbnz r2, output_minutes
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	mov r0, #':'
	bl uart_putChar
	
output_minutes:
	//Minuten
	mov r1, #MINUTE_IN_SECONDS
	udiv r0, r6, r1
	mls r6, r0, r1, r6
	
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	mov r0, #':'
	bl uart_putChar
	
	//Sekunden
	mov r0, r6
	
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	

	b loop	

/*
 * Setzt den Modus (1-Stunden / 24-Stundenmodus)
 * Uebergabeparamter: R0 - Modus ( 1 = 1-Stunden; 0 = 24-Stundenmodus)
 */	
.thumb_func
setMode:
	push {lr}
	//Modus-Flag setzten
	ldr r1, =flagMode
	strb r0, [r1]
	
	cmp r0, #0
	ittee eq
	ldreq r0, =str_mode24h
	ldreq r1, =RTC_TAR_VALUE24H
	ldrne r0, =str_mode1h
	ldrne r1, =RTC_TAR_VALUE1H
	
	//Timer deaktivieren
	mov r2, #0
	ldr r3, =RTC_SR_TCE
	str r2, [r3]
	
	//Uhr zuruecksetzen
	ldr r3, =RTC_TPR
	str r2, [r3]
	ldr r3, =RTC_TSR
	str r2, [r3]
	
	//Alarmregister beschreiben
	ldr r2, =RTC_TAR
	str r1, [r2]
	
	//Timer aktivieren
	mov r2, #1
	ldr r3, =RTC_SR_TCE
	str r2, [r3]
	
	bl uart_putString
	pop {pc}
	
/*
 * Initialisiert die RTC
 * Uebergabeparamter: keine
 */	
.thumb_func
rtc_init:
    push {lr}
	//Taktversorung aktivieren
	mov r0, #1
	ldr r1, =SIM_SCGC6_RTC
	str r0, [r1]
	
	//Timer deaktivieren
	mov r0, #0
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	//Oszillator aktivieren
	mov r0, #RTC_CR_VALUE
	ldr r1, =RTC_CR
	str r0, [r1]
	
	//Einschwingzeit abwarten	
	ldr r0, =RTC_DELAY_COUNTER
rtc_init_delay_loop:
	subs r0, #1
	bne rtc_init_delay_loop
	
	//Uhr zuruecksetzen
	mov r0, #0
	ldr r1, =RTC_TPR
	str r0, [r1]
	ldr r1, =RTC_TSR
	str r0, [r1]
	
	ldr r0, =str_clockReset
	bl uart_putString
	
	//Alarmregister setzen
	ldr r0, =RTC_TAR_VALUE24H
	ldr r1, =RTC_TAR
	str r0, [r1]
	
	ldr r0, =str_mode24h
	bl uart_putString	

	//Zeitkompensation
	mov r0, #RTC_TCR_VALUE
	ldr r1, =RTC_TCR
	str r0, [r1]	 
	
	//Interrupts konfigurieren (RTC)
	mov r0, #RTC_IER_VALUE
	ldr r1, =RTC_IER
	str r0, [r1]
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_rtc
	ldr r1, =RTC_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	mov r1, #RTC_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	str r1, [r0]
		
	//Timer aktivieren
	mov r0, #1
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	pop {pc}
	
/*
* Interruptroutine zu RTC - Seconds interrupt. 
*/
.thumb_func
isr_rtc:
	//Flag setzen
	mov r1, #1
	ldr r0, =flagSecond
	strb r1, [r0] 
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
flagSecond: .byte 0
flagMode: .byte 0  //24-Stunden-Modus
flagOutput: .byte 1 //Ausgabe aktiv
str_clockReset: .asciz "\nUhr zurueckgesetzt"
str_clockPreset: .asciz "\nUhr vorgestellt"
str_mode24h: .asciz "\n24-Stunden-Modus"
str_mode1h: .asciz "\n1-Stunden-Modus"
str_outputEnabled: .asciz "\nAnzeige an"
str_outputDisabled: .asciz "\nAnzeige aus"
str_alarm: .asciz "\nEndzeitpunkt erreicht"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//SFRs
__BBREG PIT_MCR_MDIS, 0x40037000, 1
__BBREG PIT_TCTRL1_TEN, 0x40037118, 0 		
__BBREG PIT_TFLG1_TIF, 0x4003711C, 0   
.equ PIT_LDVAL1, 0x40037110 			
.equ PIT_TCTRL1, 0x40037118 

.equ RTC_TSR, 0x4003D000
.equ RTC_TPR, 0x4003D004
.equ RTC_TAR, 0x4003D008
.equ RTC_TCR, 0x4003D00C
.equ RTC_CR, 0x4003D010
.equ RTC_SR, 0x4003D014
.equ RTC_IER, 0x4003D01C
__BBREG RTC_SR_TCE, RTC_SR, 4
__BBREG RTC_SR_TAF, RTC_SR, 2

__BBREG SIM_SCGC6_RTC, 0x4004803C, 29
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC6_PIT, 0x4004803C, 23


.equ PORTA_PCR6,  0x40049018	//PTA6 
.equ PORTA_PCR10, 0x40049028	//PTA10 (Blaue LED)

.equ GPIOA_PSOR,  0x400FF004
.equ GPIOA_PCOR,  0x400FF008
.equ GPIOA_PDDR,  0x400FF014

.equ NVIC_ISER2, 0xE000E108 
.equ NVIC_ICPR2, 0xE000E288


//Konstanten
.equ RTC_TCR_VALUE, 0x00 //Keine Kompensation
.equ RTC_CR_VALUE, 0x100 //Keine zusaetzlichen Kapazitaeten, kein Clock output, Oszillator aktiviert, kein UpdateMode, Supervisor Access, Wakeup Pin deaktiviert.
.equ RTC_TAR_VALUE, 0// 0xFFFFFFFF
.equ RTC_IER_VALUE, 0x10 //Interrupt nur fuer Time Seconds Interrupt
 
.equ RTC_INTERRUPT_MASK, 0x08 //Maske zum aktivieren von IRQ  67 (RTC - Seconds interrupt)
.equ RTC_INTERRUPT_VECTOR,  0x1FFFFF4C

.equ RTC_DELAY_COUNTER, 6250000 //1s * 25MHz / 4 Zyklen    Aufgrund keiner genaueren Kenntnisse ueber das Einschwingverhalten, wird hier grosszuegig 1s gewartet.

.equ PCR_GPIO, 0x100 //Pin als GPIO konfigurieren
.equ GPIOA_OUTPUT_MASK, 0x00000440 	//PTA6, PTA10 Ausgaenge

.equ PIT1_INTERRUPT_MASK, 0x20 //Maske zum aktivieren von IRQ  69 (PIT1)
.equ PIT1_INTERRUPT_VECTOR,  0x1FFFFF54

.equ PIT_100MS, 2500000     	//PIT1 Startwert, entspricht erforderlichen Takten fuer 100ms (100ms * 25MHz) 
.equ PIT_200MS, 5000000     	//PIT1 Startwert, entspricht erforderlichen Takten fuer 200ms (200ms * 25MHz)
.equ PIT_TCTRL1_VALUE, 0x03		//Timer mit Interrupts starten

.equ S58, 58
.equ S59, 59
.equ S60, 60
.equ SECONDS, 59
.equ WEATHER_BITS, 14
.equ BITS_MINUTE, 7
.equ BITS_HOUR, 6
.equ BITS_DAY, 6
.equ BITS_DAY_IN_WEEK, 3
.equ BITS_MONTH, 5
.equ BITS_YEAR, 8

.equ MINUTES_IN_HOUR_BCD, 0x60
.equ HOURS_IN_DAY_BCD, 0x24
.equ DAYS_IN_WEEK, 7
.equ DAYS_IN_MONTH_BCD, 30
.equ MONTHS_IN_YEAR_BCD, 12

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl gpioa_init
	bl pit1_init
	bl rtc_init
	
	
	bl readTimeDate //Datum und Uhrzeit einlesen
	mov r5, r0		//Rueckgabe (Sekunden) richtigem Register zuweisen
	bl dcf77_clock_addMinute

	mov r4, #0  //Signalausgabe
	ldr r6, =dcf77NextPulsWidth
	ldr r7, =dcf77Bits
	ldr r8, =flagSecond
	ldr r9, =current_clock_hours
	ldr r10, =current_clock_minutes
mainLoop:
	//Pruefen, ob Eingabe vorhanden
	bl uart_charPresent
	cbz r0, testSecondFlag
	
	mov r4, #0
	str r4, [r6] //Ausgabe des DCF77-Singnals beenden
	
	bl uart_getChar //Eingegebens Zeichen lesen. Es wird nicht weiter benoetigt, muss aber ausgelesen werden, um 
					//im Folgenden die Uhrzeit korrekt einzulesen.
	bl readTimeDate
	mov r5, r0
	bl dcf77_clock_addMinute
	
testSecondFlag:
	//Sekundenflag abfragen
	ldrb r0, [r8]
	cmp r0, #0
	beq mainLoop
	
	//Flag zuruecksetzen
	mov r0, #0
	strb r0, [r8]
	
	/*
	Hier entspricht die im Speicher und R5 (Sekunden) hinterlegte Zeit der aktuellen Uhrzeit. 
	Es wird zunaechst das aktuell auszugebende Bit angezeit.
	Anschlissend wird die Sekunde hochgezaehlt, um die Laenge des
	zu Beginn der naechsten Sekunde beginnenden	Puls zu bestimmen.
	Bis zum Ausloesen des naechsten Sekunden Flags, hat die im Speicher und R5 hinterlegte
	Uhrzeit eine Sekunde Vorlauf.	 
	*/
	cmp r5, #0				//Pruefen, ob Sekunde 0 ist
	it eq
	bleq printBits 
		
	//Uhrzeit auf uart ausgeben (hh:mm:ss)
	ldr r0, [r9]
	bl uart_putByte 		//aktuelle Stunde ausgeben
	
	mov r0, #':'
	bl uart_putChar
	
	ldr r0, [r10]
	bl uart_putByte 		//aktuelle Minute ausgeben
	
	mov r0, #':'
	bl uart_putChar
	
	mov r0, r5				//akutelle Sekunde ausgeben (Achtung: Sekunden liegen nicht in BCD vor)
	cmp r0, #10 // >= 10?
	ite hs
	ldrhs r1, =uart_putByteBase10 // ohne fuehrende Null
	ldrlo r1, =uart_putByte // mit fuehrender Null
	blx r1 // entsprechendes UP aufrufen
	
	mov r0, #' '
	bl uart_putChar
	
	cbz r4, increaseSecond
	cmp r5, #S59
	beq increaseSecond
	//Ausgabe aktuelles Bit
	ldrb r0, [r7, +r5]
	bl uart_putByteBase10
		
increaseSecond:
	mov r0, #'\n'
	bl uart_putChar

	//Sekunde erhoehen
	add r5, r5, #1	
	
	//59. Sekunde?
	cmp r5, #S59
	beq second59
	
	//60. Sekunde?
	cmp r5, #S60
	bne setNextBit
	
	mov r5, #0 				 //Sekunden auf 0 setzen	
	bl dcf77_clock_addMinute //Minute erhoehen	
	bl createNextDCF77Bits   //Naechste BitFolge berechnen
	mov r4, #1  			 //Mit Signalausgabe beginnen
	
setNextBit:
	//Pruefen, ob Signalausgabe aktiv ist
	cmp r4, #1
	bne mainLoop
	
	//Naechstes Bit auslesen
	ldrb r1, [r7, +r5]
	
	//Naechste Pulslaenge bestimmen
	cmp r1, #0
	ite eq
	ldreq r2, =PIT_100MS
	ldrne r2, =PIT_200MS 
	str r2, [r6]
	
	
	b mainLoop

second59:	
	mov r0, #0
	str r0, [r6] //kein Signalpuls	
	b mainLoop 


/*
 * Gibt die Bit-Folge des DCF77-Signals aus.
 * Uebergabeparamert: keine
 * Rueckgabe: keine
 */
.thumb_func
printBits:
	push { r4, r5, lr }
	mov r5, #0
	ldr r4, =dcf77Bits
	
	
printLoop:
	ldrb r0, [r4, +r5]
	bl uart_putByteBase10
	
	add r5, r5, #1
	
	cmp r5, #59
	bne printLoop
	
	mov r0, #'\n'
	bl uart_putChar
	
	pop { r4, r5, pc }
	
/*
 * Liesst Uhrzeit und Datum via uart ein.
 * Uebergabeparameter: keine
 * Rueckgabe: R0 - Sekunden
 * 			  Minuten, Stunden und Datum werden direkt im Speicher der Uhr gesetzt.
 */
.thumb_func	
readTimeDate:
	push {r4, lr}

	//Stunden einlesen
	ldr r0, =str_inputHours
	bl uart_putString
	bl uart_getByteBase10 
	bl convertToBcd	
	ldr r1, =dcf77_clock_hours
	strb r0, [r1]
	ldr r1, =current_clock_hours
	strb r0, [r1]  
	bl uart_putByte
	
	//Minuten einlesen
	ldr r0, =str_inputMinutes
	bl uart_putString
	bl uart_getByteBase10 
	bl convertToBcd	
	ldr r1, =dcf77_clock_minutes
	strb r0, [r1]
	ldr r1, =current_clock_minutes
	strb r0, [r1]  
	bl uart_putByte
	
	//Sekunden einlesen
	ldr r0, =str_inputSeconds
	bl uart_putString
	bl uart_getByteBase10 
	mov r4, r0  
	bl uart_putByteBase10
	
	//Tag einlesen
	ldr r0, =str_inputDay
	bl uart_putString
	bl uart_getByteBase10 
	bl convertToBcd	
	ldr r1, =dcf77_clock_day
	strb r0, [r1]  
	bl uart_putByte
	
	//Monat einlesen
	ldr r0, =str_inputMonth
	bl uart_putString
	bl uart_getByteBase10 
	bl convertToBcd	
	ldr r1, =dcf77_clock_month
	strb r0, [r1]  
	bl uart_putByte
	
	//Jahr einlesen
	ldr r0, =str_inputYear
	bl uart_putString
	bl uart_getByteBase10 
	bl convertToBcd	
	ldr r1, =dcf77_clock_year
	strb r0, [r1]  
	bl uart_putByte
	
	//Hinweis fuer erneute Eingabe anzeigen
	ldr r0, =str_startInput
	bl uart_putString
	
	mov r0, r4
	pop {r4, pc}
	
/*
 * Uberfuehrt eine Zahl im binaeren Format in eine 2-stellige Zahl in gepacktem BCD-Format.
 * Uebergabe: R0 - Zahl in binaerer Form (0 <= R0 < 100 (dezimal))
 * Rueckgabe: R0 - Zahl in gepacktem BCD-Format
 */	
.thumb_func
convertToBcd:
	mov r1, #10
	udiv r2, r0, r1
	mls r3, r2, r1, r0
	orr r3, r3, r2, lsl #4
	
	mov r0, r3
	bx lr
	
/*
 * Erzeugt die Bitfolge fuer die naechste Minute des DCF77 Signals
 * Parameter: akuelle Uhrzeit (ueber Speicher)
 * Rueckgabe: DCF77 Bitfolge (ueber Speicher)
 */	
.thumb_func
createNextDCF77Bits:
	push { r4, r5, lr }
	mov r0, #0
	mov r1, #1
	ldr r2, =dcf77Bits
	
	//Start einer neuen Minute
	strb r0, [r2], #1
	
	//Wetterinformationen (Hier immer 14 x 0)
	mov r3, #WEATHER_BITS
weather_bits_loop:
	cbz r3, infoBits
	strb r0, [r2], #1
	sub r3, r3, #1
	b weather_bits_loop
	
infoBits:
	//Rufbit (Hier immer 0)
	strb r0, [r2], #1
	
	//Umstellung auf MEZ/MESZ (Hier immer 0)
	strb r0, [r2], #0
	
	//MEZ (01) / MESZ (10)
	ldr r3, =dcf77_clock_MESZ
	ldrb r3, [r3]
	
	cmp r3, #0
	ittee eq
	strbeq r0, [r2], #1
	strbeq r1, [r2], #1
	strbne r1, [r2], #1
	strbne r0, [r2], #1
	
	//Einfuegen einer Schaltsekunde (Hier immer 0)
	strb r0, [r2], #1
	
		
	//Begin der Zeitinformation
	strb r1, [r2], #1
	
	//Minute
	ldr r3, =dcf77_clock_minutes
	ldrb r3, [r3] //Minute laden (im gepackten BCD-Format)
	
	mov r4, #BITS_MINUTE
	mov r5, #0 //Paritaet

minuteBits_loop:	
	cbz r4, parityMinute
	sub r4, r4, #1
	lsrs r3, r3, #1
	
	itte cs
	strbcs r1, [r2], #1
	addcs r5, r5, #1
	strbcc r0, [r2], #1
	b minuteBits_loop	
	
parityMinute:
	tst r5, #1
	ite eq
	strbeq r0, [r2], #1
	strbne r1, [r2], #1
	
	//Stunde
	ldr r3, =dcf77_clock_hours
	ldrb r3, [r3] 
	
	mov r4, #BITS_HOUR
	mov r5, #0 //Paritaet

hourBits_loop:	
	cbz r4, parityHour
	sub r4, r4, #1
	lsrs r3, r3, #1
	
	itte cs
	strbcs r1, [r2], #1
	addcs r5, r5, #1
	strbcc r0, [r2], #1
	b hourBits_loop	
	
parityHour:
	tst r5, #1
	ite eq
	strbeq r0, [r2], #1
	strbne r1, [r2], #1
	
	//Datum
	mov r5, #0 //Paritaet
	//Tag
	ldr r3, =dcf77_clock_day
	ldrb r3, [r3] 
	
	mov r4, #BITS_DAY

dayBits_loop:	
	cbz r4, dayInWeek
	sub r4, r4, #1
	lsrs r3, r3, #1
	
	itte cs
	strbcs r1, [r2], #1
	addcs r5, r5, #1
	strbcc r0, [r2], #1
	b dayBits_loop	


dayInWeek: 	//Wochentag
	ldr r3, =dcf77_clock_dayInWeek
	ldrb r3, [r3] 
	
	mov r4, #BITS_DAY_IN_WEEK

dayInWeekBits_loop:	
	cbz r4, month
	sub r4, r4, #1
	lsrs r3, r3, #1
	
	itte cs
	strbcs r1, [r2], #1
	addcs r5, r5, #1
	strbcc r0, [r2], #1
	b dayInWeekBits_loop
	
month: 	//Monat
	ldr r3, =dcf77_clock_month
	ldrb r3, [r3] 
	
	mov r4, #BITS_MONTH

monthBits_loop:	
	cbz r4, year
	sub r4, r4, #1
	lsrs r3, r3, #1
	
	itte cs
	strbcs r1, [r2], #1
	addcs r5, r5, #1
	strbcc r0, [r2], #1
	b monthBits_loop
	
year: 	//Jahr
	ldr r3, =dcf77_clock_year
	ldrb r3, [r3] 
	
	mov r4, #BITS_YEAR

yearBits_loop:	
	cbz r4, parityDate
	sub r4, r4, #1
	lsrs r3, r3, #1
	
	itte cs
	strbcs r1, [r2], #1
	addcs r5, r5, #1
	strbcc r0, [r2], #1
	b yearBits_loop
	
parityDate:
	tst r5, #1
	ite eq
	strbeq r0, [r2], #1
	strbne r1, [r2], #1	
		
	pop {r4, r5, pc}
	
/*
 * Erhoeht die Uhrzeit um eine Minute.
 * Uebergabeparameter: keine
 * Rueckgabe: keine
 */
.thumb_func
dcf77_clock_addMinute:	
	//Speichern der akutellen Uhrzeit. Da die im DCF77-Signal uebertragende Uhrzeit sich auf die kommende Minute bezieht,
	//kann der gespeicherte Wert der DCF77 Zeit als aktuelle Uhrzeit verwendet werden.
	ldr r0, =dcf77_clock_hours
	ldr r2, =current_clock_hours
	ldrb r1, [r0]
	strb r1, [r2]
	
	ldr r0, =dcf77_clock_minutes
	ldr r2, =current_clock_minutes
	ldrb r1, [r0]
	strb r1, [r2]
	
	//DCF77-Zeit erhoehen
	//Minute erhoehen
	and r2, r1, #0x0F
	cmp r2, #9
	itte hs
	andhs r1, r1, #0xF0
	addhs r1, r1, #0x10
	addlo r1, r1, #0x01
	
	cmp r1, #MINUTES_IN_HOUR_BCD
	blo dcf77_clock_addMinute_end
	
	mov r1, #0
	strb r1, [r0]
	
	//Stunde erhoehen
	ldr r0, =dcf77_clock_hours
	ldrb r1, [r0]
	
	and r2, r1, #0x0F
	cmp r2, #9
	itte hs
	andhs r1, r1, #0xF0
	addhs r1, r1, #0x10
	addlo r1, r1, #0x01
	
	cmp r1, #HOURS_IN_DAY_BCD
	blo dcf77_clock_addMinute_end
	
	mov r1, #0
	strb r1, [r0] 
	
	//Wochentag erhoehen
	ldr r0, =dcf77_clock_dayInWeek
	ldrb r1, [r0]
	add r1, r1, #1
	cmp r1, #DAYS_IN_WEEK
	it eq
	moveq r1, #0
	strb r1, [r0]
	         	
	//Tag erhoehen
	ldr r0, =dcf77_clock_day
	ldrb r1, [r0]
	
	and r2, r1, #0x0F
	cmp r2, #9
	itte hs
	andhs r1, r1, #0xF0
	addhs r1, r1, #0x10
	addlo r1, r1, #0x01
	
	cmp r1, DAYS_IN_MONTH_BCD 
	bls dcf77_clock_addMinute_end
	
	mov r1, #1
	strb r1, [r0]
	
	//Monat erhoehen
	ldr r0, =dcf77_clock_month
	ldrb r1, [r0]
	
	and r2, r1, #0x0F
	cmp r2, #9
	itte hs
	andhs r1, r1, #0xF0
	addhs r1, r1, #0x10
	addlo r1, r1, #0x01
	
	cmp r1, #MONTHS_IN_YEAR_BCD
	bls dcf77_clock_addMinute_end
	
	mov r1, #1
	strb r1, [r0] 
	
	//Jahr erhoehen
	ldr r0, =dcf77_clock_year
	ldrb r1, [r0]
	
	and r2, r1, #0x0F
	cmp r2, #9
	itte hs
	andhs r1, r1, #0xF0
	addhs r1, r1, #0x10
	addlo r1, r1, #0x01 
		
dcf77_clock_addMinute_end:
	strb r1, [r0]
	bx lr
	
	
/*
 * Initialisiert die RTC
 * Uebergabeparamter: keine
 */	
.thumb_func
rtc_init:
    push {lr}
	//Taktversorung aktivieren
	mov r0, #1
	ldr r1, =SIM_SCGC6_RTC
	str r0, [r1]
	
	//Timer deaktivieren
	mov r0, #0
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	//Oszillator aktivieren
	mov r0, #RTC_CR_VALUE
	ldr r1, =RTC_CR
	str r0, [r1]
	
	//Einschwingzeit abwarten	
	ldr r0, =RTC_DELAY_COUNTER
rtc_init_delay_loop:
	subs r0, #1
	bne rtc_init_delay_loop
	
	//Uhr zuruecksetzen
	mov r0, #0
	ldr r1, =RTC_TPR
	str r0, [r1]
	ldr r1, =RTC_TSR
	str r0, [r1]
	
	//Alarmregister setzen
	ldr r0, =RTC_TAR_VALUE
	ldr r1, =RTC_TAR
	str r0, [r1]	

	//Zeitkompensation
	mov r0, #RTC_TCR_VALUE
	ldr r1, =RTC_TCR
	str r0, [r1]	 
	
	//Interrupts konfigurieren (RTC)
	mov r0, #RTC_IER_VALUE
	ldr r1, =RTC_IER
	str r0, [r1]
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_rtc
	ldr r1, =RTC_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	mov r1, #RTC_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	str r1, [r0]
		
	//Timer aktivieren
	mov r0, #1
	ldr r1, =RTC_SR_TCE
	str r0, [r1]
	
	pop {pc}
	
/*
* Unterprogramm zum Initisieren der LEDs. 
*/
.thumb_func	
gpioa_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]

	//Pins konfigurieren
	ldr r1, =PCR_GPIO
	ldr r0, =PORTA_PCR6
	str r1, [r0]
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	
	//GPIO konfigurieren
	ldr r0, =GPIOA_PDDR
	ldr r1, =GPIOA_OUTPUT_MASK
	ldr r2, [r0]	//laden
	orr r2, r2, r1	//maskieren
	str r2, [r0]	//schreiben
	ldr r0, =GPIOA_PSOR
	str r1, [r0] //Ausgaenge High schalten
	
	bx lr
	
/*
* Unterprogramm zur Initialisierung von PIT1 zum Ausloesen von Interrupts nach je 1s. 
*/
.thumb_func
pit1_init:
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC6_PIT
	str r1, [r0] 
	
	//Interrupt-Vektor PIT1 setzen  (NVIC)
	ldr r0, =isr_pit1
	ldr r1, =PIT1_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts PIT1 loeschen (NVIC) 
	ldr r0, =NVIC_ICPR2
	mov r1, #PIT1_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt PIT1 aktivieren (NVIC)
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	//PIT Modul aktivieren
	ldr r0, =PIT_MCR_MDIS
	mov r1, #0
	str r1, [r0]
	

	bx lr
	
/*
 * Interruptroutine zu RTC - Seconds interrupt. 
 */
.thumb_func
isr_rtc:	
	//Auszugebende Pulslaenge auslesen
	ldr r0, =dcf77NextPulsWidth
	ldr r0, [r0]
	
	//Wenn Pulslaenge = 0 (59 Sekunde oder vor der 1. auszugebende Minute)
	//direkt zum Setzen des Sekundenflags springen
	cbz r0, isr_rtc_setFlag	
	
	//PIT1 Startwert setzen
	ldr r1, =PIT_LDVAL1
	str r0, [r1]
	
	//Ausgaenge LOW schalten
	ldr r1, =GPIOA_OUTPUT_MASK
	ldr r0, =GPIOA_PCOR
	str r1, [r0] 
	
	//PIT1 mit Interrupts aktivieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_VALUE
	str r1, [r0]
	
	
isr_rtc_setFlag:
	//Flag setzen
	mov r1, #1
	ldr r0, =flagSecond
	strb r1, [r0] 
	bx lr

/*
* Interruptroutine zu PIT1. 
*/
.thumb_func
isr_pit1:
	//Interrupt loeschen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	
	//PIT1 abschalten
	ldr r0, =PIT_TCTRL1_TEN
	mov r1, #0
	str r1, [r0]
	 
	//Ausgaenge LOW schalten
	ldr r1, =GPIOA_OUTPUT_MASK
	ldr r0, =GPIOA_PSOR
	str r1, [r0] 
	
	bx lr	
	

/*** Datenbereich (ab 0x20000000) ***/
.data
dcf77Bits:
.rept SECONDS
.byte 0x00
.endr
dcf77NextPulsWidth: .word 0
dcf77OuptutEnabled: .byte 0
flagSecond: .byte 0
dcf77_clock_MESZ: .byte 0
dcf77_clock_minutes: .byte 0x58 //packed BCD
dcf77_clock_hours: .byte 0x13
dcf77_clock_day: .byte 0x17
dcf77_clock_dayInWeek: .byte 3
dcf77_clock_month: .byte 0x08
dcf77_clock_year: .byte 0x24
current_clock_minutes: .byte 0x58
current_clock_hours: .byte 0x13

str_inputDay: .asciz "\nTag eingeben (dd): "
str_inputMonth: .asciz "\nMonat eingeben (mm): "
str_inputYear: .asciz "\nJahr eingeben (jj): "
str_inputHours: .asciz "Stunden eingeben (hh): "
str_inputMinutes: .asciz "\nMinuten eingeben (mm): "
str_inputSeconds: .asciz "\nSekunden eingeben (ss): "

str_startInput: .asciz "\nDuecken Sie eine beliebige Taste, um erneut die Eingabe von Datum und Uhrzeit zu starten.\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


//SFRs
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC6_FTM0, 0x4004803C, 24
.equ PORTA_PCR6, 0x40049018

.equ FTM0_SC,	  0x40038000
.equ FTM0_CNT,    0x40038004
.equ FTM0_MOD, 	  0x40038008
.equ FTM0_C3SC,   0x40038024
.equ FTM0_C3V, 	  0x40038028
.equ FTM0_CNTIN,  0x4003804C
.equ FTM0_MODE,   0x40038054
.equ FTM0_SYNC,   0x40038058
.equ FTM0_COMBINE,0x40038064
.equ FTM0_POL, 	  0x40038070
.equ FTM0_FMS, 	  0x40038074
.equ FTM0_CONF, 	0x40038084
__BBREG FTM0_POL_POL3, FTM0_POL, 3
__BBREG FTM0_SC_TOF, FTM0_SC, 7
__BBREG FTM0_C3SC_CHF, FTM0_C3SC, 7

.equ NVIC_ISER1, 0xE000E104 
.equ NVIC_ICPR1, 0xE000E284

//Konstanten
.equ PCR_PWM, 0x300 		//ALT 3 (FTM0_CH3)
.equ FTM0_CONF_VALUE, 0xC0 	//BDM -> Functional mode (s.AN5142)
.equ FTM0_FMS_VALUE, 0 		//WPEN loeschen, sodass FTM0_MODE_WPDIS gesetzt wird
.equ FTM0_MODE_VALUE, 0x05 	//WPDIS setzen und FTM aktivieren
.equ FTM0_MOD_VALUE, 25000 	//= 1ms * 25MHz
.equ FTM0_C3SC_VALUE, 0x68 	//Edge Aligned PWM positiver Puls, Interrupt zulassen
.equ FTM0_C3V_VALUE, 6250	//12500 //50% = 500us
.equ FTM0_COMBINE_VALUE, 0 	//keine kombinierten Kanaele
.equ FTM0_CNTIN_VALUE, 0 
.equ FTM0_SC_VALUE, 0x48	//Systemtakt, Teiler = 1, PWM Edge aligned, Overflow Interrupt zulassen 
.equ FTM0_SC_OFF_VALUE, 0xC0 //kein Zaehlertakt, Overflow Interrupt zulassen, OverflowFlag beibehalten
.equ FTM0_SYNC_VALUE, 0 	//PWM Synchronisation steht nur im Combine Mode zur Verfuegung

.equ FTM0_INTERRUPT_VECTOR, 0x1FFFFF38
.equ FTM0_INTERRUPT_MASK, 0x40000000 //IRQ62

.equ PROMPT, '>'
.equ ASCII_0, '0'


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	//PORTA initialisieren
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]

	//Pins konfigurieren
	ldr r1, =PCR_PWM
	ldr r0, =PORTA_PCR6
	str r1, [r0]
	
	
	//Flex Timer initialisieren
	//Interrupt-Vektor setzen  (NVIC)
	ldr r0, =isr_ftm0
	ldr r1, =FTM0_INTERRUPT_VECTOR	 
	str r0, [r1]
	
	//Pending Interrupts loeschen (NVIC) 
	ldr r0, =NVIC_ICPR1
	mov r1, #FTM0_INTERRUPT_MASK
	str r1, [r0]
	
	//Interrupt PIT1 aktivieren (NVIC)
	ldr r0, =NVIC_ISER1
	str r1, [r0]
	
	//Taktversorgung aktivieren
	mov r1, #1
	ldr r0, =SIM_SCGC6_FTM0
	str r1, [r0]
	
	//Konfiguration
	//set up BDM in 11
	mov r0, #FTM0_CONF_VALUE
	ldr r1, =FTM0_CONF
	str r0, [r1]
	
	//WPEN loeschen, sodass FTM0_MODE_WPDIS gesetzt wird
	mov r0, #FTM0_FMS_VALUE
	ldr r1, =FTM0_FMS
	str r0, [r1]
	
	//WPDIS setzen und FTM aktivieren
	mov r0, #FTM0_MODE_VALUE
	ldr r1, =FTM0_MODE
	str r0, [r1]
	
	//MOD einstellen -> Grundschwingung 1ms
	ldr r0, =FTM0_MOD_VALUE
	ldr r1, =FTM0_MOD
	str r0, [r1]
	
	//Channel einrichten
	mov r0, #FTM0_C3SC_VALUE
	ldr r1, =FTM0_C3SC
	str r0, [r1]
	
	//Kanalverkettung deaktivieren 
	mov r0, #FTM0_COMBINE_VALUE
	ldr r1, =FTM0_COMBINE
	str r0, [r1]
	
	//Initielle Pulsweite einstellen
	ldr r0, =FTM0_C3V_VALUE
	ldr r1, =FTM0_C3V
	str r0, [r1]
	
	//Initiellen Zaehlerwert festlegen
	mov r0, #FTM0_CNTIN_VALUE
	ldr r1, =FTM0_CNTIN
	str r0, [r1]
	ldr r1, =FTM0_CNT
	str r0, [r1]
	
	//Synchronisierung deaktivieren (steht nur im  Combine Mode zur Verfuegung)
	mov r0, #FTM0_SYNC_VALUE
	ldr r1, =FTM0_SYNC
	str r0, [r1]
	
	//Kanalpolaritaet einstellen (positiv)
	mov r0, #0
	ldr r1, =FTM0_POL_POL3
	str r0, [r1]
	
	//Zaehlertakt auswaehlen
	mov r0, #FTM0_SC_VALUE
	ldr r1, =FTM0_SC
	str r0, [r1]	
	

mainLoop:
	//Eingabe Prompt ausgeben
	mov r0, #PROMPT
	bl uart_putChar
	
	mov r0, #' '
	bl uart_putChar
	
	bl uart_getChar
	mov r4, r0
	
	bl uart_putChar //Echo
	
	mov r0, #'\n'
	bl uart_putChar
	
	cmp r4, #'+'
	bne checkNegativePolarity
	
	//Wechsel auf positive Polaritaet vorbereiten
	ldr r0, =currentPolarity
	mov r1, #0
	strb r1, [r0]
	
	ldr r0, =flagChangePolarity
	mov r1, #1
	strb r1, [r0]
	
	b mainLoop
	
checkNegativePolarity:
	cmp r4, #'-'
	bne checkZ
	
	//Wechsel auf negative Polaritaet vorbereiten
	ldr r0, =currentPolarity
	mov r1, #1
	strb r1, [r0]
	
	ldr r0, =flagChangePolarity
	mov r1, #1
	strb r1, [r0]
	
	b mainLoop

checkZ:
	sub r4, r4, #ASCII_0
	cmp r4, #10
	bhs mainLoop //Ungueltiges Zeichen
	
	//Pulslaenge auswaehlen
	ldr r0, =pulsWidths
	ldrh r0, [r0, +r4, lsl #1]
	ldr r1, =currentPulsWidth
	strh r0, [r1]
	
	ldr r0, =flagChangePulsWidth
	mov r1, #1
	strb r1, [r0]

/*
 * Interrupt Routine FTM0
 */	
.thumb_func
isr_ftm0:	
	//TOF oder CHF?
	ldr r1, =FTM0_SC_TOF
	ldr r0, [r1]
	cbz r0, isr_ftm0_chf
	
	//TOF loeschen
	mov r0, #0
	str r0, [r1]
	
	//Pruefen, ob Polaritaet gewechselt werden soll
	ldr r0, =flagChangePolarity
	ldrb r1, [r0]
	cbz r1, isr_ftm0_end
	mov r1, #0
	strb r1, [r0]
	ldr r0, =currentPolarity
	ldrb r0, [r0]
	ldr r1, =FTM0_POL_POL3
	str r0, [r1]

	b isr_ftm0_end
	
isr_ftm0_chf:
	//CHF loeschen
	mov r0, #0
	ldr r1, =FTM0_C3SC_CHF
	str r0, [r1]
		
	//Pruefen, ob Pulweite geaendert werden soll
	ldr r0, =flagChangePulsWidth
	ldrb r1, [r0]
	cbz r1, isr_ftm0_end
	mov r1, #0
	strb r1, [r0]
	
	//Timer anhalten, um schreiben zu koennen
	ldr r0, =FTM0_SC
	mov r1, #FTM0_SC_OFF_VALUE
	str r1, [r0]
	
	//Neue Pulsweite setzen
	ldr r2, =currentPulsWidth
	ldrh r2, [r2]
	ldr r3, =FTM0_C3V
	str r2, [r3]
	
	//Timer fortsetzen
	mov r1, #FTM0_SC_VALUE
	str r1, [r0]
	
isr_ftm0_end:
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
flagChangePolarity: .byte 0
flagChangePulsWidth: .byte 0
currentPolarity: .byte 0
currentPulsWidth: .word 12500

//Vorberechnete Pulslaengen (FTM0C3V). Berechnung: (i * 0,1 + 0,05) * 25000 fuer i = 0..9
pulsWidths: .hword  1250, 3750, 6250, 8750, 11250, 13750, 16250, 18750, 21250, 23750
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Deklaration von Konstanten
.equ COUNT, 0x10

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	//16 Bytes einlesen
	mov r4, #COUNT
	ldr r5, =bytearray
	ldr r0, =str_input
	bl uart_putString
	
loop_input:					// Kommentierung entfällt. (Teil des Studientags)
	ldr r0, =str_prompt
	bl uart_putString
	bl uart_getByte
	strb r0, [r5], #1
	bl uart_putByte
	subs r4, r4, #1
	bne loop_input
	
	
	
	
	
	//Maximumsbestimmung
	ldr r0, =str_suchestart
	bl uart_putString
	
		
	bl pit3_init			//Initialisierung des PIT - Zählers
	
	bl pit3_getval			//Abfrage des Zählerwertes
	mov r6, r0	
	
	
	mov r9, #0
	mov r4, #COUNT
	

loop_max:					// Schleife für die Maximumsbestimmung
	ldrb r0, [r5, #-1]!		// lade einen Werte aus dem Array in r0	
	cmp r0, r9				// vergleiche r0 mit r9
	it hi					// wenn r0 größer ist
	movhi r9, r0			// schreibe r0 in r9 (r9 -> Puffer für das Maximum)
	subs r4, r4, #1			// Dekrementieren des Zählregisters um 1.
	bne loop_max			// Schleifenende <-- wenn subs r4, r4, #0x1 = 0 -> r4 - 1 = 0 
	
	bl pit3_getval			// Abfrage des Zählerwertes
	mov r8, r0				
	
	sub r6, r6, r8			// Zeitdauer als Differenz der Register r6 (Wert des Zählers vor der Berechnung) und r8 (Wert des Zählers nach der Berechnung)
	
	ldr r0, =maximum		// Speichern des Maximumwertes
	strb r9, [r0]
	
	
	
	ldr r0, =str_sucheende	// Ausgabe des String auf dem Terminal
	bl uart_putString
	
	ldr r0, =maximum		// Der Wert der Variable wird ausgelesen und in r0 gespeichert. Anschließend ausgegeben.
	ldr r0, [r0] 
	bl uart_putByte
	
	ldr r0, =str_suche		
	bl uart_putString
	
	mov r0, r6				// Ausgabe des Timerwertes
	bl uart_putInt16



	// Timer beenden
	// speichere 0x0 in Adresse 0x40037138 (PIT_TCRTL3 - Register)
	// PIT_TCTRL3 = 0x0
	
	ldr r0, =0x40037138
	mov r9, #0x0
	str r9, [r0]
	

	b main 					// Rücksprung zu main: (s.o.)
	
/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
.rept COUNT
.byte 0x00
.endr
maximum: .byte 0x00
str_prompt: .asciz "\n>0x"
str_input: .asciz "\n\nBitte 16 Bytes sukessziv einlesen!\n" 
str_suchestart: .asciz "\nDurchsuchen gestartet\n"
str_sucheende: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_suche: .asciz "\nSuchzeit: 0x"


/* Versuch 1-1 - Aufgabe e)
	
	Die Suchzeit ist nicht von der Lage des Maximums abhängig. Die Schleife wird immer 16 mal durchlaufen
	und es wird die gleiche Anzahl an Befehlen ausgeführt. -> Die Suchzeit ist abhängig von dem Wert von COUNT.
			
*/
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// Deklaration von Konstanten
.equ BB_base_adr, 0x22000000	// Basisadresse der Bit-Band-alias-Region  

 
main:	
	
	bl uart_init				//Initialisierung UART-Schnittstelle


	ldr r0, =str_0bit			// Stringausgabe von str_0bit
	bl uart_putString
	
	bl uart_getByte				// Eingabe des Wertes (0-Bit)
	
	mov r5, r0 
	and r5, #0x0000001f			// Begrenzung der Eingabe
	
	ldr r0, =var_0bit			// Der Inhalt von r0 wird in der Variable var_0bit gespeichert
	strb r5, [r0]			
				
	ldr r0, [r0]				// Der Wert der Variable wird ausgelesen und in r0 gespeichert. Anschließend ausgegeben. 
	bl uart_putByte				
	
		
	
	
	ldr r0, =str_1bit			// Stringausgabe von str_1bit
	bl uart_putString
	
	bl uart_getByte				// Eingabe des Wertes (1-Bit)
	
	mov r5, r0 
	and r5, #0x0000001f			// Begrenzung der Eingabe
	
	
	ldr r0, =var_1bit			// Der Inhalt von r0 wird in der Variable var_1bit gespeichert
	strb r5, [r0]
	
	ldr r0, [r0] 				// Der Wert der Variable wird ausgelesen und in r0 gespeichert. Anschließend ausgegeben.
	bl uart_putByte
	
	
	// Ausgabe der Variablen vor Veränderung
	
	ldr r0, =str_var_32bit_Ausgabe		// Stringausgabe von str_var_32bit_Ausgabe
	bl uart_putString
	
	ldr r0, adr_var1					// Terminalausgabe: var_32bit als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]	
	bl uart_putInt32
	
	
	ldr r0, =str_varBB_32bit_Ausgabe	// Stringausgabe von str_varBB_32bit_Ausgabe
	bl uart_putString
	
	ldr r0, adr_var2					// Terminalausgabe: varBB_32bit als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]	
	bl uart_putInt32
	
	
	
	//Ausgabe der 32 Bit Variable
	
	ldr r0, =str_var_32bit		// Stringausgabe von str_var_32bit
	bl uart_putString
	
	
	ldr r5, adr_var1			// Die Adresse von var_32bit wird in r5 gespeichert. r5 dient als Zwischenspeicher für die Adresse von var_32bit
	
	ldr r0, [r5] 				// Der Wert der Variable var_32bit wird ausgelesen und in r0 gespeichert. r0 dient als Arbeitsregister in dem der neue Wert für var_32bit berechnet wird
	
	
	mov r6, #0x1				// r6 dient zur "Markierung" der Bitposition
	
	ldr r9, =var_0bit			// Der Wert der Variable wird ausgelesen und in r9 gespeichert. --> Position des auf 0 zu setzende Bit
	ldrb r9, [r9] 
	
	lsl	r6, r9					// Verschiebung an die richtige Bitposition. --> Bedingt durch die Eingabe
	bic r0, r6					// auf 0 setzen durch Bit-Clear-Operation
	
	
	mov r6, #0x1				// r6 dient zur "Markierung" der Bitposition
	
	ldr r9, =var_1bit			// Der Wert der Variable wird ausgelesen und in r9 gespeichert. --> Position des auf 1 zu setzende Bit
	ldrb r9, [r9] 
	
	lsl r6, r9					// Verschiebung an die richtige Bitposition. --> Bedingt durch die Eingabe
	orr r0, r6					// auf 1 setzen durch Oder-Verknüpfung
	
	str r0, [r5]				// Der neuberechnete Wert von var_32bit wird im Speicher unter der Adresse von var_32bit gespeichert.
	
	
	bl uart_putInt32			// Terminalausgabe in hex. Schreibweise
	
	
	
	
	// mit Bit Banding			
	
	// In der Bit-Band-alias-Region (ab 0x22000000) repräsentiert jedes 32 Bit Wort ein Bit aus dem Datenbereich (ab 0x20000000). 
	// Das jeweilige Bit wird in der Bit-Band-alias-Region als 0x00000001 dargestellt, wenn es auf 1 gesetzt ist. Ist es auf 0 gesetzt, wird das Bit als 0x00000000 in der Bit-Band-alias-Region repräsentiert.
	// (mittels Memory Browser (im Debug-Modus) nachvollziehbar)
	
	ldr r0, =str_varBB_32bit	// Stringausgabe von str_varBB_32bit
	bl uart_putString
	
		
	
	mov r6, #0x0				
	
	ldr r9, =var_0bit			// Der Wert der Variable wird ausgelesen und in r9 gespeichert. Position des auf 0 zu setzende Bit
	ldrb r9, [r9] 
	
	
								// Berechnung der Bit-Band-alias-Adresse gem. Formel aus den Skript zum Studientag
	mov r0, #BB_base_adr		// Laden der Basisadresse (0x22000000) in r0
	add r0, #0x200				// + (0x20000010 - 0x20000000) * 0x20 = 0x200 --> 0x22000000 Basisadresse des der Bit-Band-alias-Region für 0x20000010 
	lsl r9, #2					// Position des auf 0 zu setzenden Bits * 4 => r9 << 2
	add r0, r9					// In r0 ist nach Ausführung die Bit-Band-alias-Adresse zum jeweiligen Bit enthalten.
		
	str r6, [r0]				// Das jeweilige Bit wird auf 0 gesetzt.


	
	
	mov r6, #0x1
	
	ldr r9, =var_1bit			// Der Wert der Variable wird ausgelesen und in r9 gespeichert. Position des auf 1 zu setzende Bit
	ldrb r9, [r9] 
	
	
								// Berechnung der Bit-Band-alias-Adresse gem. Formel aus den Skript zum Studientag
	mov r0, #BB_base_adr		// Laden der Basisadresse (0x22000000)
	add r0, #0x200				// + (0x20000010 - 0x20000000) * 0x20 = 0x200 --> 0x22000000 Basisadresse des der Bit-Band-alias-Region für 0x20000010 
	lsl r9, #2					// Position des auf 1 zu setzenden Bits * 4 => r9 << 2
	add r0, r9					// In r0 ist nach Ausführung die Bit-Band-alias-Adresse zum jeweiligen Bit enthalten.
	
	str r6, [r0]				// Das jeweilige Bit wird auf 1 gesetzt.
	
					
	ldr r0, adr_var2			// Terminalausgabe: varBB_32bit als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]	
	bl uart_putInt32
	
	
	
		
	b main						// Rücksprung zu main: (s.o.)
	

adr_var1: .word var_32bit
adr_var2: .word varBB_32bit
	
	
	
/*** Datenbereich (ab 0x20000000) ***/
.data
var_32bit: 
	.4byte 0xFFFFFFFF 

.align 4 						// Verschiebung der Variable varBB_32bit an die Adresse 0x20000010

varBB_32bit:
	.4byte 0xFFFFFFFF



str_0bit: .asciz "\n\nNummer des 0-Bits : 0x"
str_1bit: .asciz "\nNummer des 1-Bits : 0x"
str_var_32bit_Ausgabe: .asciz "\nAktueller Wert der Variable (ohne BB): 0x"
str_varBB_32bit_Ausgabe: .asciz "\nAktueller der Variable (mit BB): 0x"
str_var_32bit: .asciz "\nNeuer Wert der Variable (ohne BB): 0x"
str_varBB_32bit: .asciz "\nNeuer Wert der Variable (mit BB): 0x"

var_0bit: .byte 0x00
var_1bit: .byte 0x00
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Deklaration von Konstanten
.equ COUNT_func, 0x20
.equ BYTECOUNT, 0x4


.thumb_func: input_V:			// Unterprogramm für die Eingabe der Vektoren und Speicherung der Werte in die Variablen. Übergabe der Variablen-Adresse in r1. Rückgabe des Ergebnisses der Eingabe in r0 
	push {r1, r4, r5, lr}		// r1 wird als Übergaberegister genutzt (s.o.). r4 und r5 müssen gem. AAPCS erhalten bleiben. In lr ist die Rücksprungadresse gespeichert. --> Sicherung auf dem Stack
	
	// ldr r0, =str_input_V
	// bl uart_putString
	
	mov r4, #COUNT_func			// r4 als Zählregister für loop_input. Initialisierung auf 32 um die Verschiebe-Operation (lsl r5, r4) byteweise durchführen zu können (32 Bit --> 4 Byte)
	mov r0, #0x0				// r0 dient als Arbeitsregister, um den Eingabe zu berechnen und in die Variable zu schreiben. (Adresse der Variable in r1)
	
	// pop {r1}
	// ldr r0, [r1]
	// push {r1}
	
	
loop_input:						// Anfang der Schleife --> 4 Durchläufe
	push {r0}					// Sicherung von r0, da dieses Register für die Funktionen uart_getByte, uart_putByte, uart_putString benötigt und überschrieben wird.
	
	bl uart_getByte
	mov r5, r0					// r5 dient als Zwischenspeicher für die Eingabe
	bl uart_putByte
	
	cmp r4, #0x18				// Durch die 5 Befehle wird nach Ausgabe des 2ten Bytes (in hexadezimaler Schreibweise) automatisch ein "_"-ascii-Zeichen eingefügt. 
	it eq 
	ldreq r0, =uscore 
	it eq 
	bleq uart_putString
	
	pop {r0}
	
	subs r4, r4, #0x8			// Dekrementieren des Zählregisters um 8.	
	lsl r5, r4					// das Zählregister enthält die Byteposition innerhalb der o.a. 4Byte (32 Bit) Variable
	add r0, r5					// Berechnung des Wertes der Variable (s.o.)
	
	bne loop_input				// Ende der Schleife. <-- wenn subs r4, r4, #0x8 -> r4 - 8 = 0  


	pop {r1, r4, r5}			// Zurückholen der Registerinhalte
	str r0, [r1]				// Der eingegebene Wert der Variable (in r0 zwischengespeichert) wird in die Variable (hier: v1, v2) geschrieben. 
	
	pop {lr}					// Zurückholen der Registerinhalte
	bx lr						// Rücksprung zur Adresse in lr



/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:	
	
	bl uart_init
	
		
	
	
	ldr r0, =str_input_v1	// Terminalausgabe: str_input_v1
	bl uart_putString
	
	ldr r1, =v1				// Übergabe der Adresse von v1 in r1
	bl input_V				// Funktionsaufruf input_V
	
	
	ldr r0, =str_input_v2	// Terminalausgabe: str_input_v2
	bl uart_putString
	
	ldr r1, =v2				// Übergabe der Adresse von v2 in r1
	bl input_V				// Funktionsaufruf input_V
	
	
	/* Ausgabe v1	
	ldr r0, =str_v1
	bl uart_putString
	
	ldr r0, =v1
	ldr r0, [r0]
	bl uart_putInt32
		
	
	   Ausgabe v2	
	ldr r0, =str_v2
	bl uart_putString
	
	ldr r0, =v2
	ldr r0, [r0]
	bl uart_putInt32
	*/	
	
	
	
	bl pit3_init
	
		
	// Ausgabe min & max (ohne DSP)
	ldr r0, =str_ohneDSP	// Terminalausgabe: str_ohneDSP
	bl uart_putString


	// Ausgabe min (ohne DSP)
	ldr r0, =str_min		// Terminalausgabe: str_min
	bl uart_putString
	
	
	ldr r3, =min			// dient zur Speicherung der Adresse für die Variable min
	mov r4, #BYTECOUNT		// die u.a. Schleife wird 4 mal durchlaufen --> Variable (hier: min) wird byteweise "angesprochen"
	
	bl pit3_getval			// Abfrage des Zählerwertes für Bestimmung d. Zeitdauer Berechnung min ohne DSP
	mov r8, r0		
	
loop_min:	
	push {r4}
	sub r4, #1				// Durch diese Operation kann r4 als Offset für die ldrb und strb Befehle genutzt werden.
	
	ldr r0, =v1				// Die Vektoren werden byteweise in r1 (-> v1) und r2 (-> v2) eingelesen und anschließend verglichen
	ldrb r1, [r0, r4]
	ldr r0, =v2
	ldrb r2, [r0, r4]

	cmp r1, r2				// Hierdurch wird erreicht, dass in r1 immer der kleiner Wert aus r1 und r2 gespeichert ist. --> Minimum
	it hi
	movhi r1, r2
	
	mov r0, r1
		
	strb r0, [r3, r4]		// Die Variable (hier: min) wird byteweise beschrieben. --> Abhängig von r4.
	
	pop {r4}
	subs r4, r4, #1			// Dekrementieren des Zählregisters um 1.
	bne loop_min			// Schleifenende <-- wenn subs r4, r4, #0x1 = 0 -> r4 - 1 = 0  
	
	bl pit3_getval			// Abfrage des Zählerwertes für Bestimmung d. Zeitdauer Berechnung min ohne DSP
	mov r9, r0	
	sub r8, r8, r9			// Zeitdauer als Differenz der Register r8 (Wert des Zählers vor der Berechnung) und r9 (Wert des Zählers nach der Berechnung)
	ldr r0, =t_ohneDSPmin	// Speicherung der Dauer in t_ohneDSPmin
	str r8, [r0]
		
	ldr r0, =min			// Terminalausgabe: min als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]
	bl uart_putInt32
	// Ende Ausgabe min (ohne DSP)
	
	
	
	
	// Ausgabe max (ohne DSP)
	ldr r0, =str_max		// Terminalausgabe: str_max
	bl uart_putString
	
	
	ldr r3, =max			// dient zur Speicherung der Adresse für die Variable max
	mov r4, #BYTECOUNT		// die u.a. Schleife wird 4 mal durchlaufen --> Variable (hier: max) wird byteweise "angesprochen"
	
	
	bl pit3_getval			// Abfrage des Zählerwertes für Bestimmung d. Zeitdauer Berechnung max ohne DSP
	mov r8, r0	
	
loop_max:	
	push {r4}
	sub r4, #1				// Durch diese Operation kann r4 als Offset für die ldrb und strb Befehle genutzt werden.
	
	ldr r0, =v1				// Die Vektoren werden byteweise in r1 (-> v1) und r2 (-> v2) eingelesen und anschließend verglichen
	ldrb r1, [r0, r4]
	
	ldr r0, =v2
	ldrb r2, [r0, r4]

	cmp r1, r2				// Hierdurch wird erreicht, dass in r1 immer der größere Wert aus r1 und r2 gespeichert ist. --> Maximum
	it lo
	movlo r1, r2
	
	mov r0, r1
		
	strb r0, [r3, r4]		// Die Variable (hier: max) wird byteweise beschrieben. --> Abhängig von r4.
		
	pop {r4}
	subs r4, r4, #1			// s.o.
	bne loop_max			// s.o.
	
	bl pit3_getval			// Abfrage des Zählerwertes für Bestimmung d. Zeitdauer Berechnung max ohne DSP
	mov r9, r0	
	sub r8, r8, r9			// Zeitdauer als Differenz der Register r8 (Wert des Zählers vor der Berechnung) und r9 (Wert des Zählers nach der Berechnung)
	ldr r0, =t_ohneDSPmax	// Speicherung der Dauer in t_ohneDSPmax
	str r8, [r0]
		
	ldr r0, =max			// Terminalausgabe: max als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]
	bl uart_putInt32
	// Ende Ausgabe max (ohne DSP)
	
	
	
	// Ausgabe min/max (mit DSP) 
	ldr r0, =str_mitDSP		// Terminalausgabe: str_mitDSP
	bl uart_putString
	
	bl pit3_getval			// Abfrage des Zählerwertes für Bestimmung d. Zeitdauer Berechnung min/max mit DSP
	mov r8, r0	
	
	ldr r0, =v1				// Die Vektoren werden in r4 (-> v1) und r5 (-> v2) eingelesen und anschließend verglichen
	ldr r4, [r0]
	
	ldr r0, =v2
	ldr r5, [r0]
	
		
	usub8 r0, r4, r5		// Der Befehl bildet die Differenz - byteweise - aus r4 und r5 (hier: r4 - r5) und setzt die entsprenchenden GE-Flags. Sollte die Subtraktion für ein Byte ein negatives Ergebnis
							// haben, wird das zugehörige GE-Flag (im ASPR) auf 1 gesetzt. Das Ergebnis wird hier in r0 gespeichert aber nicht weiter benötigt.
	
	ldr r6, =min_DSP
	sel r0, r5, r4			// sel setzt r0 aus r4 und r5 zusammen, abhängig von den GE-Flags. Hier: Minimum
	str r0, [r6]
	
	ldr r6, =max_DSP
	sel r0, r4, r5			// sel setzt r0 aus r4 und r5 zusammen, abhängig von den GE-Flags. Hier: Maximum
	str r0, [r6]
	
	
	bl pit3_getval			// Abfrage des Zählerwertes für Bestimmung d. Zeitdauer Berechnung min/max mit DSP
	mov r9, r0	
	sub r8, r8, r9			// Zeitdauer als Differenz der Register r8 (Wert des Zählers vor der Berechnung) und r9 (Wert des Zählers nach der Berechnung)
	ldr r0, =t_mitDSP		// Speicherung der Dauer in t_mitDSP
	str r8, [r0]
	
	
	
	ldr r0, =str_min		// Terminalausgabe: str_min
	bl uart_putString
	
	ldr r0, =min_DSP		// Terminalausgabe: min_DSP als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]
	bl uart_putInt32
	
		
	ldr r0, =str_max		// Terminalausgabe:	str_max
	bl uart_putString
	
	ldr r0, =max_DSP		// Terminalausgabe: max_DSP als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]
	bl uart_putInt32
	// Ende Ausgabe min/max (mit DSP) 
	
	
	
	// Ausgabe Zeitwerte 
	ldr r0, =str_t_ohneDSP	// Terminalausgabe: str_t_ohneDSP
	bl uart_putString
	
	ldr r0, =t_ohneDSPmin	// Berechnung der Zeitwerte für die beiden Schleifen loop_min und loop_max mit anschließender Terminalausgabe
	ldr r0, [r0]
	ldr r1, =t_ohneDSPmax
	ldr r1, [r1]
	add r0, r1
	bl uart_putInt16
		
	ldr r0, =str_t_mitDSP	// Terminalausgabe: str_t_mitDSP
	bl uart_putString
	
	ldr r0, =t_mitDSP		// Terminalausgabe: t_mitDSP als 32 Bit Wert in hex. Schreibweise
	ldr r0, [r0]
	bl uart_putInt16
	// Ende Ausgabe Zeitwerte 
	
	
	// Timer beenden
	// speichere 0x0 in Adresse 0x40037138 (PIT_TCRTL3 - Register)
	// PIT_TCTRL3 = 0x0
	ldr r0, =0x40037138
	mov r9, #0x0
	str r9, [r0]
	
	b main					// Rücksprung zu main: (s.o.) (Aufg. e))

/*** Datenbereich (ab 0x20000000) ***/
.data
v1: .4byte 0x00000000
v2: .4byte 0x00000000
// str_input_V: .asciz "\nVektor byteweise eingeben: 0x"
str_input_v1: .asciz "\n\nv1: 0x"
str_input_v2: .asciz "\nv2: 0x"
str_v1: .asciz "\nVektor v1: 0x"
str_v2: .asciz "\nVektor v2: 0x"
uscore: .asciz "_"
str_ohneDSP: .asciz "\n\nohne DSP - Befehle:"
str_mitDSP: .asciz "\n\nmit DSP - Befehlen:"
str_min: .asciz "\nmin: 0x"
str_max: .asciz "\nmax: 0x"
min: .4byte 0x0
max: .4byte 0x0
min_DSP: .4byte 0x0
max_DSP: .4byte 0x0
t_ohneDSPmin: .word 0x0
t_ohneDSPmax: .word 0x0
t_mitDSP: .word 0x0
str_t_ohneDSP: .asciz "\n\nDauer ohne DSP: 0x"
str_t_mitDSP: .asciz "\nDauer mit DSP: 0x"

/* Versuch 1-3 - Aufgabe d)
	
	Die Ausführungszeiten sind nicht von der Eingabe abhängig und immer die selben. Hierbei ist zu erkennen, dass die Berechnung des Minimumns/Maximums bei Nutzung der DSP-Befehle deutlich schneller geht.
	Die Berechnung mittels der Schleifen dauert erheblich länger. --> Fazit: Im Rahmen der Aufgabe ist die Lösung der Minimum-/Maximumbestimmung mit DSP-Befehlen effizienter und leichter zu implementieren.
			
*/

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ MATRIX, 0x10				// Konstante zum Festlegen der Matrixgroeße O und O_kopie
.equ COUNTSMLAD, 0x2			// Zaehler fuer die Schleife zur Multiplikation der Matrizen M und N mittels smlad
.equ COUNTWORD, 0x4				// Zaehler um innerhalb der Schleifen word-weise zu adressieren
.equ COUNTDWORD, 0x8			// Zaehler um innerhalb der Schleifen dword-weise zu adressieren --> Eine Zeile/Spalte von M/N benoetigt als Speicherplatz 2 Woerter (8 bytes)
.equ INDEXMN, 0x1C				// Index zur Adressierung der Matrizen M und N
.equ INDEXO, 0x3C				// Index zur Adressierung der Matrix O
.equ ABSATZ, '\n'
.equ LEERZ, ' '
.equ COUNT, 0x3					// Zaehler fuer Schleifen
.equ US_SAT, 0xD

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:	

	bl uart_init

	
	// Multiplikation der Matrizen M, N
	mov r5, #0x0					// Ruecksetzen von r5 --> r5 dient als Speicher fuer die Zwischenergebnisse
	mov r6, #INDEXMN
	mov r7, #INDEXMN
	mov r8, #INDEXO
	
	ldr r2, =m_zeile				// Die Basisadressen der Eingabematrizen M und N werden in r2 und r3 gespeichert.
	ldr r3, =n_spalte
	ldr r9, =o_matrix				// Die Basisadresse der Zielmatrix O wird in r9 gespeichert.
	
/*  
	Zu a) 
	Zur Berechnung des Produktes der Matrizen M und N ohne die Nutzung von DSP-Befehlen waeren 64 Multiplikationen noetig.
    Werden DSP-Befehle zur Ergebnisberechnung genutzt, kann diese Anzahl um die Haelfte auf 32 reduziert werden.
*/
	
	
loop_mul1:
	mov r4, #COUNTSMLAD				// Initialisierung des Zaehlers fuer die Multiplikation der Matrizen M und N mittels smlad --> 2 Durchlaeufe
loop_mul2:	
	ldr r0, [r2, r6]				// Die 2 Werte an der Position INDEXMN der Matrix M werden in r0 geladen
	ldr r1, [r3, r7]				// Die 2 Werte an der Position INDEXMN der Matrix N werden in r1 geladen
	smlad r5, r0, r1, r5       		// Multiplikation der oben geladenen Werte der Matrizen M und N mittels --> Ergebnis in r5
	sub r6, r6, #COUNTWORD			// Dekrementieren der Zaehler um 4 um das naechste word laden zu koennen
	sub r7, r7, #COUNTWORD
	subs r4, r4, #1					// Dekrementieren des Zaehlers
	bne loop_mul2
	
	str r5, [r9, r8]				// Das Ergebnis der Multiplikationen in r5 wird in Matrix O gespeichert an der Position INDEXO
	sub r8, r8, #COUNTWORD
	mov r5, #0x0					// Ruecksetzen von r5
	
	add r6, r6, #COUNTDWORD			// Ruecksetzen des Index fuer M und N, da dieser durch die zwei Schleifendurchlaeufe (s.o.) um 8 reduziert wurde.
	add r7, r7, #COUNTDWORD
		
	subs r7, r7, #COUNTDWORD		// Der Index fuer N wird um 8 reduziert (2 Woerter -> 8 Byte) --> Die naechste Spalte von N wird fuer die Multiplikation ausgewaehlt.
	bpl loop_mul1
	
	mov r7, #INDEXMN				// Ruecksetzen des Index fuer N
	subs r6, r6, #COUNTDWORD		// Der Index fuer M wird um 8 reduziert (2 Woerter -> 8 Byte) --> Die naechste Zeile von M wird fuer die Multiplikation ausgewaehlt.
	bpl loop_mul1
	
	//Ausgabe Matrix O
	ldr r0, =str_ergebnis_o
	bl uart_putString
	
	mov r4, #COUNT					// Intitialisierung der Zaehler fuer insgesamt 4 * 4 = 16 Durchlaeufe
	mov r5, #COUNT
	
	ldr r0, [r9]					// Der erste Eintrag der Matrix O wird in r0 geladen.

loop_out:
	bl uart_putInt32				// Ausgabe eines Wertes der Matix O
	
	mov r0, #LEERZ					// Ausgabe von 2 Leerzeichen auf dem Terminal.
	bl uart_putChar
	mov r0, #LEERZ
	bl uart_putChar
	
	ldr r0, [r9, #4]!				// laden des n-ten Eintrags der Matrix (n => 2-16)
	
	subs r4, r4, #1					// Dekrementieren des Zaehlers
	bpl loop_out
	
	mov r4, #COUNT
	mov r0, #ABSATZ					// Ausgabe von einem Absatz (\n) auf dem Terminal. Um die "Matrixdarstellung" auf dem Terminal zu erhalten
	bl uart_putChar
	ldr r0, [r9]					// erneutes Laden des n-ten Eintrags der Matrix (n => 2-16), da r0 zur Ausgabe von \n ueberschrieben wurde.
	
	subs r5, r5, #1					// Dekrementieren des Zaehlers
	bpl loop_out
	
	//Kopieren der Matix
	ldr r5, =o_matrix				// Die Basisadresse der Matrix O wird in r5 gespeichert.  
	ldr r6, =o_matrix_kopie			// Die Basisadresse der vor dem Kopiervorgang "noch leeren" Matrix O_kopie wird in r6 gespeichert.
	
	mov r4, #COUNT					// Initialisierung des Zaehler --> 4 Durchlaeufe
	
loop_kopieren:
	ldm r5!, {r0-r3}				// Die 16 Woerter der Matrix O werden in 4 Schritten mittels Zwischenspeicherung in den Registern r0-r3
	stm r6!, {r0-r3}				// in die Matrix O_kopie uebertragen.
	
	ldr r0, =str_kopieren			// Ausgabe des Strings "Kopieren der Matrix O!" erfolgt somit 4 mal (s.o.) 
	bl uart_putString
	
	subs r4, r4, #1					// Dekrementieren des Zaehlers
	bpl loop_kopieren
	
	//Produktsumme
	ldr r0, =str_Summe
	bl uart_putString
		
	ldr r2, =m_zeile				// Die Basisadressen der Eingabematrizen M und N werden in r2 und r3 gespeichert.
	ldr r3, =n_spalte
	
	ldr r1, [r2]					// Der ersten 2 Eintraege der Matrix M werden in r1 geladen
	ldr r6, [r3]					// Der ersten 2 Eintraege der Matrix N werden in r6 geladen
	
	mov r0, #0x0					// Ruecksetzen von r0
	mov r4, #COUNTDWORD				// Initialisierung des Zaehlers (r4) --> 8 Durchlaeufe 
	
	
loop_Summe:
	smlad r0, r1, r6, r0			// Berechnung der Produktsumme mittels smlad
	ldr r1, [r2, #4]!				// laden von 2 n-ten Eintraegen der Matrix M (n => 3,4; 5,6; 7,8 ... 15,16)
	ldr r6, [r3, #4]!				// laden von 2 n-ten Eintraegen der Matrix N (n => 3,4; 5,6; 7,8 ... 15,16)
			
	subs r4, r4, #1					// Dekrementieren des Zaehlers
	bne loop_Summe					
	
	bl uart_putInt32				// Ausgabe der in r0 berechneten Produktsumme 
	
	
	//Additionsbefehle
	
/*  
	Zu d)
	Bei folgenden Halbworten besteht nach der Berechnung eine Saettigung des Overflows:
        
                    A+B        A+C        A+D
    UQADD16:    	O 1        1 O        1 1
    QADD16:         O O        1 1        O O
	 -> Legende: 0 = keine Saettigung, 1 = Saettigung
	
    UQADD16: Vorzeichenlos Addition mit Saettigung: Tritt ein Ueberlauf auf, wird auf den Maximalwert 0xFFFF gesaettigt.  
   	QADD16: Vorzeichenbehaftete Addition mit Saettigung: Ueberlauf im negativen Bereich -> Saettigung auf den kleinsten Wert (0x8000) / Ueberlauf im positiven Bereich -> Saettigung auf den 
   			groeßten Wert (0x7FFF).   
*/
	
	//UADD16
	ldr r0, =str_uadd
	bl uart_putString
	
	ldr r5, =wert_abcd				// Basisadresse von wert_abcd wird in in r5 geladen 
	ldr r6, [r5]					// Der erste der 4 Werte wird in r6 gespeichert	
	mov r4, #COUNT					// Intitialisierung des Zaehlers --> 3 Durchlaeufe	
loop_uadd16:
	ldr r7, [r5, #4]!				// laden des 2, 3, 4 Werte aus wert_abcd in r7
	uadd16 r0, r6, r7				// Ausfuehrung von uadd16 --> Ergebnis in r0 + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
	
	mov r0, #LEERZ					// Ausgabe eines Leerzeichen
	bl uart_putChar
	
	subs r4, r4, #1					// Dekrementieren des Zaehlers	
	bne loop_uadd16
	
	
	//SADD16
	ldr r0, =str_sadd				
	bl uart_putString
	
	ldr r5, =wert_abcd				// Ruecksetzen von r5 auf die Basisadresse von wert_abcd		
	mov r4, #COUNT					// s.o
loop_sadd16:
	ldr r7, [r5, #4]!				// s.o
	sadd16 r0, r6, r7				// Ausfuehrung von sadd16 --> Ergebnis in r0 + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
	
	mov r0, #LEERZ					// s.o
	bl uart_putChar
	
	subs r4, r4, #1					// s.o
	bne loop_sadd16
	
	
	//UQADD16
	ldr r0, =str_uqadd
	bl uart_putString
	
	ldr r5, =wert_abcd				// s.o.		
	mov r4, #COUNT					// s.o
loop_uqadd16:
	ldr r7, [r5, #4]!				// s.o
	uqadd16 r0, r6, r7				// Ausfuehrung von uqadd16 --> Ergebnis in r0 + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
	
	mov r0, #LEERZ					// s.o
	bl uart_putChar
	
	subs r4, r4, #1					// s.o
	bne loop_uqadd16
	
	//QADD16
	ldr r0, =str_qadd
	bl uart_putString
	
	ldr r5, =wert_abcd				// s.o		
	mov r4, #COUNT					// s.o
loop_qadd16:
	ldr r7, [r5, #4]!				// s.o
	qadd16 r0, r6, r7				// Ausfuehrung von qadd16 --> Ergebnis in r0 + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
	
	mov r0, #LEERZ					// s.o
	bl uart_putChar
	
	subs r4, r4, #1					// s.o
	bne loop_qadd16
	
/*  
	Zu e) 
	Die Operanden (hier: in den Registern r5 und r6) fuer die Befehle usat16 und ssat16 werden als vorzeichenbehaftete Zahlen interpretiert.
	usat16 "erzeugt" ein vorzeichenloses Ergebnis, waehrend ssat16 eine vorzeichnenbehaftete Berechnung zurueckgibt (hier: jeweils in r0 fuer die Ausgabe zwischengespeichert)
	
	In Aufgabe e) werden die 16 Bit Halbworte auf 13 Bits begrenzt (vorzeichenlos: 0 <= x <= 8.191; vorzeichenbehaftet: -4.096 <= x <= 4.095)
	
	Die zwei Halbwoerter des Wertes A sind außerhalb des Wertebereichs (0xA436 -> -23.498; 0x7C7B -> 31.867); somit wird die Saettigung der Halbwoerter durchgefuehrt.
	Das erste Halbwort des Wertes B befindet sich innerhalb des Wertebereichs (nur vorzeichenlos; 0x10A7 -> 4.263); somit keine Saettigung bei usat16
	Das zweite Halbwort des Wertes B befindet sich außerhalb des Wertebereichs (0x8933 -> -30.413); somit wird die Saettigung durchgefuehrt.
*/
	
	
	//USAT16
	ldr r0, =str_usat
	bl uart_putString
	
	ldr r4, =wert_abcd				// Basisadresse von wert_abcd wird in in r4 geladen
	ldr r5, [r4]					// Der erste der 4 Werte wird in r5 gespeichert
	ldr r6, [r4, #4]				// Der 2te der 4 Werte wird in r6 gespeichert
	       
	usat16 r0, #US_SAT, r5			// Vorzeichenlose Saettigung des ersten Wertes + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
	
	mov r0, #LEERZ					// Ausgabe eines Leerzeichen
	bl uart_putChar
	
	usat16 r0, #US_SAT, r6			// Vorzeichenlose Saettigung des 2ten Wertes + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
	
	//SSAT16
	ldr r0, =str_ssat
	bl uart_putString
			       
	ssat16 r0, #US_SAT, r5			// Vorzeichenbehaftete Saettigung des ersten Wertes + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
	
	mov r0, #LEERZ					// s.o
	bl uart_putChar
	
	ssat16 r0, #US_SAT, r6			// Vorzeichenbehaftete Saettigung des 2ten Wertes + anschließende Ausgabe auf dem Terminal
	bl uart_putInt32
		

end:
	
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
//Die Matrix M ist zeilenweise im Speicher abgelegt.  
m_zeile: .hword 0x5f8c, 0x7f48, 0x8245, 0x6048, 0xc799, 0x9c5d, 0xd49c, 0x33d8, 0x579b, 0x8aef, 0xf2c0, 0xa3c2, 0x41fd, 0x50d4, 0x25c6, 0x4afa

//Die Matrix N ist spaltenweise im Speicher abgelegt.  
n_spalte: .hword 0x7f41, 0x0645, 0x8c8f, 0x9065, 0x78e3, 0xf7f3, 0xd29f, 0x2961, 0x5a1e, 0xdfed, 0x4b9f, 0x1092, 0x61bf, 0x21be, 0x5ca1, 0xc6d3

o_matrix: 
.rept MATRIX
.word 0x0
.endr

o_matrix_kopie: 
.rept MATRIX
.word 0x0
.endr

//Strings fuer die Ausgabe auf dem Terminal
str_ergebnis_o: .asciz "Ergebnismatrix O:\n"  
str_kopieren: .asciz "\nKopieren der Matrix O!"
str_Summe: .asciz "\n\nProduktsumme:  "
str_uadd: .asciz "\n\nUADD16:\t"
str_sadd: .asciz "\nSADD16:\t"
str_uqadd: .asciz "\nUQADD16:\t"
str_qadd: .asciz "\nQADD16:\t"
str_usat: .asciz "\n\nUSAT16:\t"
str_ssat: .asciz "\nSSAT16:\t"

// Werte fuer Aufg. d) und e)
wert_abcd: .word 0xA4367C7B, 0x10A78933, 0xC5535F2C, 0x788E84B1
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten
.equ TIMERDELAY, 0x7F2815		//Wert fuer die Verzoegerungsschleife -> Verzoegerung um ca. 1 Sekunde

.equ PUNKT, '.'					
.equ DPUNKT, ':'
.equ ABSATZ, '\n'
.equ LEERZ, ' '
.equ TAB, '\t'
.equ JAHRH, 0x14				//Konstante fuer die Ausgabe von 20 auf dem Terminal
.equ STD, 0x3C					//Maximal Wert: Minuten
.equ TAG, 0x18					//Maximal Wert: Stunden
.equ MONAT, 0x1F				//Maximal Wert: Tage
.equ JAHR, 0xD					//Maximal Wert: Monate
.equ JAHRRESETMAX, 0x64			//Maximal Wert: Jahre
.equ CHARS, 0x73				//ascii-Wert von s
.equ CHART, 0x74				//ascii-Wert von t
.equ CHARD, 0x64				//ascii-Wert von d
.equ LEADZERO, 0xA				//Konstante fuer das Setzen der fuehrenden Nullen fuer die Ausgabe
.equ ZERO, '0'					
.equ INITJAHR, 0xE				//Reset-Wert: Jahre
.equ COUNT, 0x4					//Zaehlerwert
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	ldr r4, =date_time			//Laden der Adresse der Variable zur Speicherung des Datums und der Zeit.

jb_standby:	
	ldrb r5, [r4]				//r5 dient als Zwischenspeicher fuer die Minuten; Offset -> 0
	ldrb r6, [r4, #1]			//r6 dient als Zwischenspeicher fuer die Stunden; Offset -> 1
	ldrb r7, [r4, #4]			//r7 dient als Zwischenspeicher fuer die Tage; Offset -> 4
	ldrb r8, [r4, #3]			//r8 dient als Zwischenspeicher fuer die Monate; Offset -> 3
	ldrb r9, [r4, #2]			//r9 dient als Zwischenspeicher fuer die Jahre; Offset -> 2
	
loop_minute:
	bl delay					//Aufruf der Verzoegerungsfunktion; Verzoegerung um etwa eine Sekunde				
	
	mov r0, #0					 
	bl uart_charPresent			//Unterprogrammaufruf zur Pruefung, ob ein Zeichen eingegeben wurde
	
	cmp r0, #0
	it ne
	blne uart_getChar			//Ist ein Zeichen eingegeben worden (-> r0 ungleich 0), wird das eingegebene Zeichen in r0 geladen.
	
	cmp r0, #CHARS				//Vergleiche r0 mit 0x73 ('s'), ist r0 gleich 0x73 -> Sprung in die standby-Schleife -> Uhr stoppt.
	beq standby 
	
	cmp r0, #CHART				//Vergleiche r0 mit 0x74 ('t'), ist r0 gleich 0x74 -> Sprung zum Aufruf zur Eingabe der Zeit
	beq call_input_time
	
	cmp r0, #CHARD				//Vergleiche r0 mit 0x64 ('d'), ist r0 gleich 0x64 -> Sprung zum Aufruf zur Eingabe des Datums
	beq call_input_date
	
	
jb_input_td:	
	mov r0, r4					//Unterprogrammaufruf zur Ausgabe des Datums und der Uhrzeit -> Uebergabe des Parameters (Adresse des Arrays date_time) in r0
	bl out_td
	
	add r5, r5, #1				//Inkrementieren der Minuten; ist der Maximalwert erreicht (hier: 60) wird r5 auf den Anfangswert zurueckgesetzt (hier: 0) + Sprung zu j_h
	cmp r5, #STD
	itt cs
	movcs r5, #0x0
	strbcs r5, [r4]				//Speichern des zurueckgesetzten Wertes im Array date_time
	bcs j_h
	strb r5, [r4]				//Speichern des aktualisierten Wertes im Array date_time
	b loop_minute				//Ruecksprung zu loop_minute 
	
j_h:		
	add r6, r6, #1				//Inkrementieren der Stunden; ist der Maximalwert erreicht (hier: 24) wird r6 auf den Anfangswert zurueckgesetzt (hier: 0) + Sprung zu j_d
	cmp r6, #TAG
	itt cs
	movcs r6, #0x0
	strbcs r6, [r4, #1]			//Speichern des zurueckgesetzten Wertes im Array date_time
	bcs j_d	
	strb r6, [r4, #1]			//Speichern des aktualisierten Wertes im Array date_time
	b loop_minute				//Ruecksprung zu loop_minute 
	
j_d:	
	add r7, r7, #1				//Inkrementieren der Stunden; ist der Maximalwert erreicht (hier: 31) wird r7 auf den Anfangswert zurueckgesetzt (hier: 1) + Sprung zu j_m	
	cmp r7, #MONAT	
	itt cs
	movcs r7, #0x1
	strbcs r7, [r4, #4]			//Speichern des zurueckgesetzten Wertes im Array date_time
	bcs j_m
	strb r7, [r4, #4]			//Speichern des aktualisierten Wertes im Array date_time
	b loop_minute				//Ruecksprung zu loop_minute 
	
j_m:	
	add r8, r8, #1				//Inkrementieren der Stunden; ist der Maximalwert erreicht (hier: 13) wird r8 auf den Anfangswert zurueckgesetzt (hier: 1) + Sprung zu j_y
	cmp r8, #JAHR
	itt cs
	movcs r8, #0x1
	strbcs r8, [r4, #3]			//Speichern des zurueckgesetzten Wertes im Array date_time
	bcs j_y	
	strb r8, [r4, #3]			//Speichern des aktualisierten Wertes im Array date_time
	b loop_minute				//Ruecksprung zu loop_minute 

j_y:
	add r9, r9, #1				//Inkrementieren der Stunden; ist der Maximalwert erreicht (hier: 100) wird r9 auf den Anfangswert zurueckgesetzt (hier: 14)
	it eq
	moveq r9, #INITJAHR	
	strb r9, [r4, #2]			//Speichern des aktualisierten/zurueckgesetzten Wertes im Array date_time
	b loop_minute				//Ruecksprung zu loop_minute 
	
// Standby-Schleife -> Die Uhr ist gestoppt.
standby:
	mov r0, #0					//s.o.
	bl uart_charPresent
	
	cmp r0, #0					//s.o.
	it ne
	blne uart_getChar
	
	cmp r0, #CHARS				//Vergleiche r0 mit 0x73 ('s'), ist r0 gleich 0x73 -> Sprung zu jb_standby -> Uhr laeuft weiter.
	beq jb_standby
	
	cmp r0, #CHART				//Vergleiche r0 mit 0x74 ('t'), ist r0 gleich 0x74 -> Eingabe der neuen Zeit
	bne j_skip_chart
	ldr r0, =str_in_min			//Unterprogrammaufruf zur Eingabe der Minuten; uebergabe der Parameter in r0 (Eingabe-String; wird vor d. Eingabe auf dem Terminal ausgegeben),
	mov r1, r4					//r1 (Adresse des Arrays date_time) und r2 (Offset des Arrays)
	mov r2, #0
	bl input
	ldr r0, =str_in_h			//Unterprogrammaufruf zur Eingabe der Stunden; s.o.
	mov r1, r4
	mov r2, #1
	bl input
	mov r0, #ABSATZ				//Ausgabe eines Absatzes ('\n')
	bl uart_putChar
j_skip_chart:	

	cmp r0, #CHARD				//Vergleiche r0 mit 0x64 ('d'), ist r0 gleich 0x64 -> Eingabe des neuen Datums
	bne j_skip_chard
	ldr r0, =str_in_d			//Unterprogrammaufruf zur Eingabe der Tage; s.o.
	mov r1, r4
	mov r2, #4
	bl input
	ldr r0, =str_in_m			//Unterprogrammaufruf zur Eingabe der Monate; s.o.
	mov r1, r4
	mov r2, #3
	bl input
	ldr r0, =str_in_y			//Unterprogrammaufruf zur Eingabe der Jahre; s.o.
	mov r1, r4
	mov r2, #2
	bl input
	mov r0, #ABSATZ				//Ausgabe eines Absatzes ('\n')
	bl uart_putChar
j_skip_chard:
	
	b standby					//Ruecksprung zu standby

// Aufruf zum Setzen der Zeit
call_input_time:
	ldr r0, =str_in_min			//Unterprogrammaufruf zur Eingabe der Minuten; uebergabe der Parameter in r0 (Eingabe-String; wird vor d. Eingabe auf dem Terminal ausgegeben),  
	mov r1, r4					//r1 (Adresse des Arrays date_time) und r2 (Offset des Arrays)
	mov r2, #0
	bl input
	
	ldr r0, =str_in_h			//Unterprogrammaufruf zur Eingabe der Stunden; s.o.
	mov r1, r4					
	mov r2, #1
	bl input
	
	mov r0, #ABSATZ				//Ausgabe eines Absatzes ('\n')
	bl uart_putChar
			
	ldrb r5, [r4]				//Nach dem Setzen des neuen Datums muessen in die zugehoerigen Register die neuen Werten geladen werden.
	ldrb r6, [r4, #1]
	b jb_input_td				//Ruecksprung zu jb_input_td -> Uhr laeuft anschliessend weiter
	
// Aufruf zum Setzen des Datums	
call_input_date:
	ldr r0, =str_in_d			//Unterprogrammaufruf zur Eingabe der Tage; s.o.
	mov r1, r4					
	mov r2, #4
	bl input
	
	ldr r0, =str_in_m			//Unterprogrammaufruf zur Eingabe der Monate; s.o.
	mov r1, r4					
	mov r2, #3
	bl input
	
	ldr r0, =str_in_y			//Unterprogrammaufruf zur Eingabe der Jahre; s.o.
	mov r1, r4					
	mov r2, #2
	bl input
	
	mov r0, #ABSATZ				//Ausgabe eines Absatzes ('\n') 
	bl uart_putChar
		
	ldrb r7, [r4, #4]			//Nach dem Setzen des neuen Datums muessen in die zugehoerigen Register die neuen Werten geladen werden. 	
	ldrb r8, [r4, #3]			
	ldrb r9, [r4, #2]
	b jb_input_td				//Ruecksprung zu jb_input_td -> Uhr laeuft anschliessend weiter

	
// Unterprogramme
// Funktion zum Setzen der/des Zeit/Datums
.thumb_func
input:
	push {r4-r6, lr}
		
	mov r4, r1					//Adresse des Arrays wird in r4 zwischengespeichert
	mov r5, r2					//Offset wird in r5 zwischengespeichert
	bl uart_putString			//Ausgabe des "Eingabe-Strings" 
	
	bl uart_getByteBase10		//Auf die Eingabe warten; Eingegebenes Zeichen in r0 laden.
	strb r0, [r4, r5]			//Speichern der Eingabe an der jeweiligen Position im Array date_time
	cmp r0, #LEADZERO			//ggf. Setzen der fuehrenden Null bei den Ziffern 0 bis 9
	bhs j_skip_leadzero_input
	mov r6, r0
	mov r0, #ZERO
	bl uart_putChar
	mov r0, r6
j_skip_leadzero_input:
	bl uart_putByteBase10		//Ausgabe des eingegeben Zeichens
	
	pop {r4-r6, pc}

// Delay-Funktion	
.thumb_func
delay:							//Unterprogramm zur Verzoegerung um etwa eine Sekunde
	push {lr}
	
	ldr r0, =TIMERDELAY			//r0 wurde so intialisiert, dass die Durchfuehrung des Unterprogramms ca. 1 Sekunde dauert.
loop_delay:						//Schleife zur Dekrementierung von r0, um o.a. Verzoegerung zu erzeugen. 
	subs r0, r0, #1
	bne loop_delay
	
	pop {pc}

// Ausgabe Uhrzeit	
.thumb_func
out_td:
	push {r4-r6, lr}
	
	mov r4, r0					//Adresse des Arrays wird in r4 zwischengespeichert
	mov r6, #COUNT				//Initialisierung des Zaehlers; 5 Durchlaeufe
loop_out_td:		
	ldrb r0, [r4, r6]
	cmp r0, #LEADZERO			//ggf. Setzen der fuehrenden Null bei den Ziffern 0 bis 9
	bhs j_skip_leadzero
	mov r5, r0
	mov r0, #ZERO
	bl uart_putChar
	mov r0, r5
j_skip_leadzero:	
	bl uart_putByteBase10		//Ausgabe des jeweiligen, aktuellen Zeichens
	
	cmp r6, #4					//Ist der Zaehler gleich 4 -> Ausgabe eines Punktes
	itt eq
	moveq r0, #PUNKT
	bleq uart_putChar
	
	cmp r6, #3					//Ist der Zaehler gleich 3 -> Ausgabe von ".20"
	bne j_skip_pj
	mov r0, #PUNKT
	bl uart_putChar
	mov r0, #JAHRH
	bl uart_putByteBase10
j_skip_pj:
	
	cmp r6, #2					//Ist der Zaehler gleich 2 -> Ausgabe eines Absatzes
	itt eq
	moveq r0, #TAB
	bleq uart_putChar
	
	cmp r6, #1					//Ist der Zaehler gleich 1 -> Ausgabe eines Doppelpunktes
	itt eq
	moveq r0, #DPUNKT
	bleq uart_putChar
	
	subs r6, r6, #1				//Dekrementieren des Zaehlers
	bpl loop_out_td

	ldr r0, =str_uhr			//Ausgabe des String: str_uhr auf dem Terminal
	bl uart_putString
	
	pop {r4-r6, pc}	
	
	
/*** Datenbereich (ab 0x20000000) ***/
.data
// Strings fuer Terminalausgaben
str_uhr: .asciz " Uhr\n"
str_in_h: .asciz "\nStunde eingeben (hh): "
str_in_min: .asciz "\nMinuten eingeben (mm): "
str_in_d: .asciz "\nTag eingeben (dd): "
str_in_m: .asciz "\nMonat eingeben (mm): "
str_in_y: .asciz "\nJahr eingeben (jj): "

// Array zur Speicherung der Zeit und des Datums
date_time: .byte 0x0, 0x0, 0xE, 0x1, 0x1
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
__BBREG PIT_SIM_SCGC6, 0x4004803C, 23		//BitBanding-Adresse fuer das PIT-Bit im SIM_SCGC6-Register
.equ SIM_SCGC6_BIT_PIT, 1

.equ PIT_MCR, 0x40037000					//Adresse des PIT_MCR-Registers
.equ PIT_MCR_VAL, 0x0
.equ PIT_LDVAL1, 0x40037110					//Adresse des PIT_LDVAL1-Registers
.equ PIT_TCTRL1, 0x40037118					//Adresse des PIT_TCTRL1-Registers
.equ PIT_TFLG1, 0x4003711C					//Adresse des PIT_TFLG1-Registers
.equ NVIC_ISER2, 0xE000E108					//Adresse des NVIC_ISER2-Registers
.equ NVIC_ICPR2, 0xE000E288					//Adresse des NVIC_ICPR2-Registers
.equ NVIC_BITPOS, 0x5						//Konstante fuer die Bitposition innerhalb der NVIC-Register
.equ NVIC_BIT, 1 << NVIC_BITPOS				//Wert zum Setzen des Bit 5 innerhalb der NVIC-Register

.equ PIT1_VAL, 0x17D783F					//Startwert fuer PIT1 -> Dauer bis zum Interrupt: 1 Sekunde

.equ PIT_TCTRL1_TIE_TEN, 0x3				//Wert zum Setzen des Bit 1 und 2 innerhalb des PIT_TCTRL1-Registers

.equ SCR_VTOR, 0xE000ED08					//Adresse des Basisregisters der IVT
.equ OFFS_PIT1, 0x154						//Offset fuer IVT (PIT1) 
/*
	============================================ Der Source-Code fuer die "Uhr-Funktion" ist unveraendert zu Versuch 2-2 -> Kommentierung entfaellt. =========================================================
*/
.equ PUNKT, '.'
.equ DPUNKT, ':'
.equ ABSATZ, '\n'
.equ LEERZ, ' '
.equ TAB, '\t'
.equ JAHRH, 0x14
.equ STD, 0x3C
.equ TAG, 0x18
.equ MONAT, 0x1F
.equ JAHR, 0xD
.equ JAHRRESETMAX, 0x64
.equ CHARS, 0x73
.equ CHART, 0x74
.equ CHARD, 0x64
.equ LEADZERO, 0xA
.equ ZERO, '0'
.equ INITJAHR, 0xE
.equ COUNT, 0x4
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:								// Initialisierungen				
	bl uart_init				
									//Ablauf einer Interrupt-Initialisierung:
									
	ldr r0, =PIT_SIM_SCGC6			//a) Takt fuer PIT aktivieren (System Integration Module –> SIM_SCGC6 Bitpos.: 23)
	mov r1, #SIM_SCGC6_BIT_PIT
	str r1, [r0]
	
	ldr r0, =SCR_VTOR				//b) Interrupt-Vektor zu PIT1 setzen
	ldr r0, [r0]
	ldr r1, =isr_pit1
	str r1, [r0, #OFFS_PIT1]
				
	ldr r0, =NVIC_ICPR2				//c) eventuell haengende (pending) Interrupts zu PIT1 loeschen (NVIC)
	mov r1, #NVIC_BIT
	str r1, [r0]
	
	ldr r0, =NVIC_ISER2				//d) Interrupt zu PIT1 aktivieren (NVIC)
	mov r1, #NVIC_BIT
	str r1, [r0]
				
	ldr r0, =PIT_MCR				//e) alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	mov r1, #PIT_MCR_VAL
	str r1, [r0]
	
	ldr r0, =PIT_LDVAL1				//f) Startwert fuer PIT1 auf 1 Sekunde initialisieren
	ldr r1, =PIT1_VAL
	str r1, [r0]
	
	ldr r0, =PIT_TCTRL1				//g) Interrupt zu PIT1 aktivieren (PIT-Modul), h) PIT1 aktivieren (PIT-Modul)
	mov r1, #PIT_TCTRL1_TIE_TEN
	str r1, [r0]
	
					
	ldr r4, =date_time				
	ldr r10, =flag					//Laden der Adresse des Benutzerflags zur Anzeige der Dauer von 1 Sekunde.
	
jb_standby:	
	ldrb r5, [r4]					
	ldrb r6, [r4, #1]				
	ldrb r7, [r4, #4]				
	ldrb r8, [r4, #3]				
	ldrb r9, [r4, #2]				
	
	
loop_minute:
	ldrb r0, [r10]					//Der aktuelle Wert des Benutzerflags wird in r0 geladen und mit 1 verglichen.
	cmp r0, #1						
	bne loop_minute					//Ist r0 gleich 0 wird der Ruecksprung zu loop_minute nicht durchgefuehrt -> Dies geschiet im Sekundentakt.
	
	mov r0, #0						//Ruecksetzen des Benutzerflags
	strb r0, [r10]
		
	mov r0, #0
	bl uart_charPresent
	
	cmp r0, #0
	it ne
	blne uart_getChar
	
	cmp r0, #CHARS
	beq standby 
	
	cmp r0, #CHART
	beq call_input_time
	
	cmp r0, #CHARD
	beq call_input_date
	
	
jb_input_td:	
	mov r0, r4
	bl out_td
	
	add r5, r5, #1
	cmp r5, #STD
	itt cs
	movcs r5, #0x0
	strbcs r5, [r4]
	bcs j_h
	strb r5, [r4]
	b loop_minute
	
j_h:		
	add r6, r6, #1
	cmp r6, #TAG
	itt cs
	movcs r6, #0x0
	strbcs r6, [r4, #1]
	bcs j_d	
	strb r6, [r4, #1]
	b loop_minute
	
j_d:
	add r7, r7, #1		
	cmp r7, #MONAT
	itt cs
	movcs r7, #0x1
	strbcs r7, [r4, #4]
	bcs j_m
	strb r7, [r4, #4]
	b loop_minute
	
j_m:	
	add r8, r8, #1	
	cmp r8, #JAHR
	itt cs
	movcs r8, #0x1
	strbcs r8, [r4, #3]
	bcs j_y	
	strb r8, [r4, #3]
	b loop_minute

j_y:
	add r9, r9, #1	
	cmp r9, #JAHRRESETMAX
	it eq
	moveq r9, #INITJAHR	
	strb r9, [r4, #2]
	b loop_minute
	
// Standby-Schleife
standby:
	mov r0, #0
	bl uart_charPresent
	
	cmp r0, #0
	it ne
	blne uart_getChar
	
	cmp r0, #CHARS
	beq jb_standby
	
	cmp r0, #CHART
	bne j_skip_chart
	ldr r0, =str_in_min
	mov r1, r4
	mov r2, #0
	bl input
	ldr r0, =str_in_h
	mov r1, r4
	mov r2, #1
	bl input
	mov r0, #ABSATZ
	bl uart_putChar
j_skip_chart:	

	cmp r0, #CHARD
	bne j_skip_chard
	ldr r0, =str_in_d
	mov r1, r4
	mov r2, #4
	bl input
	ldr r0, =str_in_m
	mov r1, r4
	mov r2, #3
	bl input
	ldr r0, =str_in_y
	mov r1, r4
	mov r2, #2
	bl input
	mov r0, #ABSATZ
	bl uart_putChar
j_skip_chard:
	
	b standby

// Aufruf zum Setzen der Zeit
call_input_time:
	ldr r0, =str_in_min
	mov r1, r4
	mov r2, #0
	bl input
	
	ldr r0, =str_in_h
	mov r1, r4
	mov r2, #1
	bl input
	
	mov r0, #ABSATZ
	bl uart_putChar
			
	ldrb r5, [r4]
	ldrb r6, [r4, #1]
	b jb_input_td
	
// Aufruf zum Setzen des Datums	
call_input_date:
	ldr r0, =str_in_d
	mov r1, r4
	mov r2, #4
	bl input
	
	ldr r0, =str_in_m
	mov r1, r4
	mov r2, #3
	bl input
	
	ldr r0, =str_in_y
	mov r1, r4
	mov r2, #2
	bl input
	
	mov r0, #ABSATZ
	bl uart_putChar
		
	ldrb r7, [r4, #4]				
	ldrb r8, [r4, #3]			
	ldrb r9, [r4, #2]
	b jb_input_td

// Unterprogramme
// ISR	
.thumb_func
isr_pit1:
	push {lr}			
	ldr r0, =flag			//Setzen des Benutzerflags auf 1
	mov r1, #1
	strb r1, [r0]
	
	ldr r0, =PIT_TFLG1		//Ruecksetzen des Interruptflags im PIT-Modul (-> In das PIT_TFLG1-Register wird eine 0x1) geschrieben.
	mov r1, #1
	str r1, [r0]
	pop {pc}

// Funktion zum Setzen der/des Zeit/Datums
.thumb_func
input:
	push {r4-r6, lr}
		
	mov r4, r1
	mov r5, r2
	bl uart_putString
	
	bl uart_getByteBase10
	strb r0, [r4, r5]
	cmp r0, #LEADZERO
	bhs j_skip_leadzero_input
	mov r6, r0
	mov r0, #ZERO
	bl uart_putChar
	mov r0, r6
j_skip_leadzero_input:
	bl uart_putByteBase10
	
	pop {r4-r6, pc}

// Ausgabe Uhrzeit	
.thumb_func
out_td:
	push {r4-r6, lr}
	
	mov r4, r0
	mov r6, #COUNT
loop_out_td:		
	ldrb r0, [r4, r6]
	cmp r0, #LEADZERO
	bhs j_skip_leadzero
	mov r5, r0
	mov r0, #ZERO
	bl uart_putChar
	mov r0, r5
j_skip_leadzero:	
	bl uart_putByteBase10
	
	cmp r6, #4
	itt eq
	moveq r0, #PUNKT
	bleq uart_putChar
	
	cmp r6, #3
	bne j_skip_pj
	mov r0, #PUNKT
	bl uart_putChar
	mov r0, #JAHRH
	bl uart_putByteBase10
j_skip_pj:
	
	cmp r6, #2
	itt eq
	moveq r0, #TAB
	bleq uart_putChar
	
	cmp r6, #1
	itt eq
	moveq r0, #DPUNKT
	bleq uart_putChar
	
	subs r6, r6, #1
	bpl loop_out_td

	ldr r0, =str_uhr				
	bl uart_putString
	
	pop {r4-r6, pc}	
	
	
/*** Datenbereich (ab 0x20000000) ***/
.data
// Flag zur Anzeige der Dauer von 1 Sekunde.
flag: .byte 0x0

// Strings fuer Terminalausgaben
str_uhr: .asciz " Uhr\n"
str_in_h: .asciz "\nStunde eingeben (hh): "
str_in_min: .asciz "\nMinuten eingeben (mm): "
str_in_d: .asciz "\nTag eingeben (dd): "
str_in_m: .asciz "\nMonat eingeben (mm): "
str_in_y: .asciz "\nJahr eingeben (jj): "

// Array zur Speicherung der Zeit und des Datums
date_time: .byte 0x0, 0x0, 0xE, 0x1, 0x1
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6, 0x4004803C
__BBREG CRC_SIM_SCGC6, SIM_SCGC6, 18		//BitBanding-Adresse fuer das CRC-Bit im SIM_SCGC6-Register

.equ CRC_SET_WAS, 0x3 << 24
.equ CRC_CLEAR_WAS, 0x1 << 24				//CRC_CLEAR_WAS und CRC_TCRC haben den gleich Wert, aber hier unterschiedliche Funktionen. 
.equ CRC_TCRC, 0x1 << 24


.equ CRC_GPOLY, 0x40032004					//Adresse des CRC_GPOLY-Reg.
.equ CRC_CRC, 0x40032000					//Adresse des CRC_CRC-Reg.
.equ CRC_CTRL, 0x40032008					//Adresse des CRC_CTRL-Reg.

.equ CRC_SEED, 0x12345678					//Intitialwert für CRC_CRC-Reg.
.equ CRC_GENPOLY_VAL, 0x04C11DB7			//Vorgegebenes Generatorpolynom


.equ STR_TERM, 0x00							//String-Terminator
.equ ABSATZ, '\n'
.equ COUNT, 0x3
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
// Initialisierungen
	bl uart_init
	
	ldr r0, =CRC_SIM_SCGC6				//Takt fuer CRC aktivieren (System Integration Module –> SIM_SCGC6 Bitpos.: 18)
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =CRC_CTRL					//Einschalten des 32-Bit CRC Modus
	mov r1, #CRC_TCRC
	str r1, [r0]
	
	ldr r0, =CRC_GPOLY					//Setzen des Generator-Polynoms
	ldr r1, =CRC_GENPOLY_VAL
	str r1, [r0]
	
	ldr r0, =CRC_CTRL					//Setzen von WAS um den CRC-Seed laden zu können
	mov r1, #CRC_SET_WAS
	str r1, [r0]	
	
	ldr r0, =CRC_CRC					//Laden des Intitialwerts für CRC_CRC-Reg.
	ldr r1, =CRC_SEED
	str r1, [r0]
	
	ldr r0, =CRC_CTRL					//Ruecksetzen von WAS 
	mov r1, #CRC_CLEAR_WAS
	str r1, [r0]
	
	
	ldr r2, =str_crc					//Zu "ueberpruefender" String
	ldr r3, =crc						//Hilfsvariable für das Zusammenfassen von 4 Bytes zu einem Wort.
			
	mov r4, #COUNT						//Initialisierung des Zaehlregisters -> 4 Durchläufe
	mov r5, #0x0
	ldr r6, =CRC_CRC					//Die Adresse vom CRC_CRC-Reg. wird in r6 gespeichert.
			
loop:
	ldrb r0, [r2, r5]					//Der String str_crc wird byteweise eingelesen.	-> Position des Zeichens -> r5
	cmp r0, #STR_TERM					//Tritt ein String-Terminator auf wird die CRC-Berechnung beendet. -> Sprung zu leave_loop	
	beq leave_loop
	
	strb r0, [r3, r4]					//Zusammenfassung von 4 eingelesen Bytes (-> 4 Zeichen) zur einen Wort. -> Wechsel der "Endianness"
		
	add r5, r5, #1
	subs r4, r4, #1
	bpl loop
	
	mov r4, #COUNT
	
	ldr r1, [r3]						//Berechnung des CRC-Wertes (wortweise)
	str r1, [r6]
	b loop
	
leave_loop:	
// Hat der eingelesen String eine Zeichen Anzahl, die nicht durch 4 teilbar ist, muss die CRC-Berechnung noch für 1, 2 oder 3 weitere Zeichen durchgeführt werden. Dies wird durch die folgenden IT-Bloecke
// bewerkstelligt. Hierbei wird das Zaehlregister (Zusammenfassen von 4 Bytes zu einem Wort) herangezogen. 	
	cmp r4, #2
	itt eq
	ldrbeq r1, [r3, #3]
	strbeq r1, [r6, #3]
	
	cmp r4, #1
	itt eq
	ldrheq r1, [r3, #2]
	strheq r1, [r6, #2]
	
	cmp r4, #0
	itttt eq
	ldrheq r1, [r3, #2]
	strheq r1, [r6, #2]
	ldrbeq r1, [r3, #1]
	strbeq r1, [r6, #1]
	
			
	ldr r0, =str_crc				//Ausgabe des Strings str_crc
	bl uart_putString
	
	mov r0, #ABSATZ					//Ausgabe eines Absatzes
	bl uart_putChar
	
	ldr r0, =str_out				//Ausgabe des Strings str_out
	bl uart_putString
	
	ldr r0, [r6]					//Auslesen des berechneten CRC-Ergebnisses mit anschließender Terminalausgabe
	bl uart_putInt32
	
	mov r0, #ABSATZ					//Ausgabe eines Absatzes
	bl uart_putChar
	
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data

crc: .word 0x0

str_crc: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"

str_out: .asciz "CRC-Pruefwert: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ PIT_LDVAL1, 0x40037110					//Adresse des PIT_LDVAL1-Registers
.equ PIT_TCTRL1, 0x40037118					//Adresse des PIT_TCTRL1-Registers
.equ PIT_TFLG1, 0x4003711C					//Adresse des PIT_TFLG1-Registers
.equ NVIC_ISER2, 0xE000E108					//Adresse des NVIC_ISER2-Registers
.equ NVIC_ICPR2, 0xE000E288					//Adresse des NVIC_ICPR2-Registers
.equ NVIC_BIT_PIT_PORTE, 0x08000020			//Wert zum Setzen des Bit 5 und 27 innerhalb der NVIC-Register

.equ PIT1_VAL, 0x17D783F					//Startwert fuer PIT1 -> Dauer bis zum Interrupt: 1 Sekunde

.equ PIT_TCTRL1_TIE_TEN, 0x3				//Wert zum Setzen des Bit 1 und 2 innerhalb des PIT_TCTRL1-Registers

.equ SCR_VTOR, 0xE000ED08					//Adresse des Basisregisters der IVT
.equ OFFS_PIT1, 0x154						//Offset fuer IVT (PIT1) 
.equ OFFS_PORTE, 0x1AC						//Offset fuer IVT (PORTE)

.equ SIM_SCGC5, 0x40048038
__BBREG SIM_SCGC5_PORTA, SIM_SCGC5, 9		//BitBanding-Adresse fuer das PORTA-Bit im SIM_SCGC5-Register
__BBREG SIM_SCGC5_PORTE, SIM_SCGC5, 13		//BitBanding-Adresse fuer das PORTE-Bit im SIM_SCGC5-Register

//Pin Control Register (PCR) für Schalter und LED
.equ PORTA_PCR19, 0x4004904C 				//SW1
.equ PORTE_PCR26, 0x4004D068 				//SW2
.equ PORTA_PCR11, 0x4004902C 				//LED1
.equ PORTA_PCR28, 0x40049070 				//LED2
.equ PORTA_PCR29, 0x40049074 				//LED3
.equ PORTA_PCR10, 0x40049028 				//LED4

//Init-Werte für LEDs, SW1 und Sw2 für Pin Control Register (PCR)
.equ PCR_MUX_LED, 0x100
.equ PCR_MUX_SW1, 0x103
.equ PCR_MUX_SW2, 0xB0103


.equ GPIOA_PDOR, 0x400FF000					//Adresse des GPIOA_PDOR
.equ GPIOA_PDIR, 0x400FF010					//Adresse des GPIOA_PDIR
.equ GPIOA_PDDR, 0x400FF014					//Adresse des GPIOA_PDDR

__BBREG GPIOA_PDIR_SW1, GPIOA_PDIR, 19		//BitBanding-Adresse fuer das PDIR-Bit des SW1 

.equ PORTE_ISFR, 0x4004D0A0 				//Adresse des PORTE_ISFR
.equ CLR_ISFR, 0x1 << 26
.equ ALL_LED, 0x30000c00

.equ PIT_CVAL3, 0x40037134					//Adresse des PIT_CVAL3-Reg.
.equ DEBOUNCE, 0x1E848						//Debounce-Wert für 5 ms -> 125.000 Takte -> unter Verwendung von pit3
.equ DEBOUNCE_POLL, 0xF424					//Debounce-Wert für 5 ms -> für die Verzögerung innerhalb des UP sw1_polling

.equ CHARS, 0x73							//ascii-Wert von s
.equ CHARPL, 0x2B							//ascii-Wert von +
.equ CHARMI, 0x2D							//ascii-Wert von -
.equ ABSATZ, '\n'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init
	
// Initialisierungen von: PIT-Modul, NVIC, GPIO PORTA und PORTE
	
	mov r1, #1						//Takt fuer PORTA und PORTE aktivieren (System Integration Module –> SIM_SCGC5 Bitpos.: 9 und 13)
	ldr r0, =SIM_SCGC5_PORTA		
	str r1, [r0]
	ldr r0, =SIM_SCGC5_PORTE		
	str r1, [r0]
	
	ldr r2, =PCR_MUX_SW1			//Initialisierung der PCR für die Taster SW1 und SW2
	ldr r3, =PCR_MUX_SW2	
	ldr r0, =PORTA_PCR19
	str r2, [r0]
	ldr r0, =PORTE_PCR26
	str r3, [r0]
	
	mov r2, #PCR_MUX_LED			//Initialisierung der PCR für die LEDs
	ldr r0, =PORTA_PCR11
	str r2, [r0]
	ldr r0, =PORTA_PCR28
	str r2, [r0]
	ldr r0, =PORTA_PCR29
	str r2, [r0]
	ldr r0, =PORTA_PCR10
	str r2, [r0]
	
	ldr r1, =ALL_LED				//GPIO-Pins für die LEDs werden als Output konfiguriert -> durch Schreiben einer 1 an die entsprechende Bitposition wird die LED ausgeschaltet.
	ldr r0, =GPIOA_PDDR
	str r1, [r0]
	ldr r0, =GPIOA_PDOR
	str r1, [r0] 
			
	ldr r0, =SCR_VTOR				//Interrupt-Vektor zu PIT1 und PORTE setzen
	ldr r0, [r0]
	ldr r1, =isr_pit1
	str r1, [r0, #OFFS_PIT1]
	ldr r1, =isr_sw2
	str r1, [r0, #OFFS_PORTE]			
	
	ldr r1, =NVIC_BIT_PIT_PORTE
	ldr r0, =NVIC_ICPR2				//eventuell haengende (pending) Interrupts zu PIT1 und PORTE loeschen (NVIC)
	str r1, [r0]
	ldr r0, =NVIC_ISER2				//Interrupt zu PIT1 und PORTE aktivieren (NVIC)
	str r1, [r0]
	
	ldr r0, =PIT_LDVAL1				//Startwert fuer PIT1 auf 1 Sekunde initialisieren
	ldr r1, =PIT1_VAL
	str r1, [r0]
	ldr r0, =PIT_TCTRL1				//Interrupt zu PIT1 aktivieren (PIT-Modul), h) PIT1 aktivieren (PIT-Modul)
	mov r1, #PIT_TCTRL1_TIE_TEN
	str r1, [r0]
		    	 
	
// Initialisierung für den Dual-Zaehler	
	mov r11, #1						//Zaehlerzustand für "Start/Stop" --> Start = 1; Stop = 0
	ldr r10, =flag_sec
	ldr r9, =mod
	mov r8, #1						//Zaehlerzustand für "Hochzaehlen/Herunterzaehlen" --> Hochzaehlen = 1; Herunterzaehlen = 0
	mov r7, #0
	ldr r6, =GPIOA_PDOR
	mov r5, #0

	ldr r0, =flag_isrsw
	mov r1, #0
	str r1, [r0]
	
// Hauptschleife 			
loop_zaehler:
	bl sw1_polling
	ldrb r0, [r10]					//Der aktuelle Wert des Benutzerflags flag_sec wird in r0 geladen und mit 1 verglichen.
	cmp r0, #1						
	bne loop_zaehler				//Ist r0 gleich 1 wird der Ruecksprung zu loop_zaehler nicht durchgefuehrt -> Dies geschieht im Sekundentakt.
	
	mov r0, #0						//Ruecksetzen des Benutzerflags flag_sec
	strb r0, [r10]
	
	bl set_mod						//UP-Aufruf zum Setzen von mod

	bl uart_charPresent				//Unterprogrammaufruf zur Pruefung, ob ein Zeichen eingegeben wurde
	cmp r0, #0						//Ist ein Zeichen eingegeben worden (-> r0 ungleich 0), wird das eingegebene Zeichen in r0 geladen.
	beq skip_getChar
	
	bl uart_getChar					
	
	cmp r0, #CHARS					//Vergleiche r0 mit 0x73 ('s'), ist r0 gleich 0x73 -> mod wird auf 2 gesetzt -> Zaehlerzustand für "Start/Stop" wird geändert.
	itt eq
	moveq r1, #2
	strbeq r1, [r9]
	
	cmp r0, #CHARPL					//Vergleiche r0 mit 0x2B ('+'), ist r0 gleich 0x2B -> Zaehlerzustand für "Hochzaehlen/Herunterzaehlen" (r8) wird auf 1 geändert (hochzaehlen).
	it eq
	moveq r5, #1
	
	cmp r0, #CHARMI					//Vergleiche r0 mit 0x2D ('-'), ist r0 gleich 0x2D -> Zaehlerzustand für "Hochzaehlen/Herunterzaehlen" (r8) wird auf 0 geändert (herunterzaehlen).
	it eq
	moveq r5, #2	
skip_getChar:

	ldrb r4, [r9]					//Wert von mod wird in r4 geladen.

// toggle Start/Stop --> Zähler anhalten/fortsetzen!	
	cmp r4, #2						//Vergleiche r4 (beinhaltet Wert von mod) mit 2, ist r0 gleich 2 -> Anpassen es Zaehlerzustands für "Start/Stop"
	bne skip_toogle_startstop
	mvn r11, r11					//Invertieren des Zaehlerzustands für "Start/Stop"
	cmp r11, #1
	ite eq							//Je nach dem welchen Zustand der Zaehler nach dem Wechsel des Zaehlerzustand für "Start/Stop" wird entweder 
	ldreq r0, =str_start			//str_start (-> Zaehler läuft weiter) oder str_stop (-> Zaehler stoppt) auf dem Terminal ausgegeben
	ldrne r0, =str_stop
	bl uart_putString
skip_toogle_startstop:	
	
	cmp r11, #1						//Ist r11 = 0 (-> Zaehlerzustand für "Stop") -> Rücksprung zu loop_zaehler -> Zähler stoppt bis r11 wieder auf 1 gesetzt wird.		
	bne loop_zaehler
					
// Ausgabe		
	mov r0, r7
	cmp r0, #10 					//Prüfen ob r0 >= 10
	ite hs
	ldrhs r1, =uart_putByteBase10 	//ohne fuehrende Null
	ldrlo r1, =uart_putByte 		//mit fuehrender Null
	blx r1 							//entsprechendes UP aufrufen
	mov r0, #ABSATZ					//Ausgabe eines Absatzes ('\n')
	bl uart_putChar
	
// Abbildung der untersten 4 Bits auf LED 1 bis 4 (Übergabeparameter -> aktueller Zählerwert: in r7 gespeichert)	
	mov r0, r7
	bl set_leds
	str r0, [r6]

// toggle Direction --> Zählrichtung setzen!			
	cmp r4, #1						//Vergleiche r4 (beinhaltet Wert von mod) mit 1, ist r0 gleich 1 -> Anpassen es Zaehlerzustands für "Hochzaehlen/Herunterzaehlen"
	bne skip_toogle_direction
	mvn r8, r8						//Invertieren des Zaehlerzustands für "Hochzaehlen/Herunterzaehlen"
	ldr r0, =str_richtungswechsel	//Ausgabe von str_richtungswechsel.
	bl uart_putString
skip_toogle_direction:	

// toggle up/down --> Zählrichtung setzen!
	cmp r5, #0
	beq skip_toggle_up_down
	cmp r5, #1
	itt eq
	moveq r8, #1
	ldreq r0, =str_pl
	cmp r5, #2
	itt eq
	moveq r8, #0
	ldreq r0, =str_mi
	mov r5, #0
	bl uart_putString
skip_toggle_up_down:
	
//In- oder Dekremieren des Zählregisters r7 --> Abhängig von r8		
	cmp r8, #1
	ite eq
	addeq r7, r7, #1
	subne r7, r7, #1

// Rücksetzen des Zählregisters r7 bei einen Überlauf  
	cmp r7, #255
	it gt
	movgt r7, #0
	cmp r7, #0
	it lt 
	movlt r7, #255
			
	b loop_zaehler
	
// Unterprogramme
// ISR PIT1
.thumb_func
isr_pit1:
	mov r1, #1	
	ldr r0, =flag_sec				//Setzen des Benutzerflags auf 1
	strb r1, [r0]
	
	ldr r0, =PIT_TFLG1				//Ruecksetzen des Interruptflags im PIT-Modul (-> In das PIT_TFLG1-Register wird eine 0x1 geschrieben.)
	str r1, [r0]
	bx lr

// ISR PORTE
// Um die Pegelprüfung für den Taster durchzuführen, wird von dem pit3 Gebrauch gemacht. Ein Interrupt wird bei einer fallenden und steigender Flanke ausgelöst.
// Wird der Taster gedrückt, wird ein Interrupt ausgelöst (hier: fallende Flanke), nun wird ein Zeitstempel mittles pit3 ermittelt. Wird der Taster wieder losgelassen, wird erneut ein Interrupt ausgelöst 
// und entsprechend ein neuer Zeitstempel ermittelt. Ist die Zeit zwischen dem Auftreten der beiden Interrupts mindestens 5 ms wir der Tastendruck als gültig erkannt -> flag_isrsw wird auf 1 gesetzt.
.thumb_func
isr_sw2:
	ldr r0, =PORTE_ISFR				//Ruecksetzen des Interruptflags im PORTE_ISFR	
	ldr r1, =CLR_ISFR
	str r1, [r0]

	ldr r3, =flag_isrsw
	ldr r0, [r3]
	
	cmp r0, #0
	bne skip_isr_sw2_sub
	ldr r1, =PIT_CVAL3
	ldr r2, =DEBOUNCE
	ldr r1, [r1]
	sub r1, r1, r2
	str r1, [r3]
skip_isr_sw2_sub:
	
	cmp r0, #0
	beq skip_isr_sw2_set
	ldr r1, =PIT_CVAL3
	ldr r1, [r1]
	cmp r1, r0
	ittee ls
	movls r2, #1
	strls r2, [r3]
	movhi r2, #0
	strhi r2, [r3]
skip_isr_sw2_set:
	
	bx lr

// UP zum Polling des Tasters SW1
.thumb_func
sw1_polling:
	ldr r1, =flag_pollsw
	
	ldr r3, =GPIOA_PDIR_SW1
	ldr r0, [r3]
	cmp r0, #0						//Prüfung ob SW1 gedrückt wurde -> hier: r0 = 0
	bne skip_poll
	ldr r2, =DEBOUNCE_POLL
pegel:								//Verzögerung um 5 ms
	subs r2, r2, #1
	bne pegel	
	ldr r0, [r3]
	cmp r0, #0						//Erneute Prüfung ob SW1 immernoch gedrückt ist.
	itt eq							//Ist SW1 immer noch gedrückt -> flag_pollsw wird auf 1 gesetzt.
	moveq r0, #1
	strbeq r0, [r1]
skip_poll:
	
	bx lr

// UP zum Setzen der LEDs E1 bis E4
// Die relevanten Bits innerhalb des GPIOA_PDOR (hier für LEDs E1 = Bit 11; E2 = Bit 28; E3 = Bit 29; E4 = Bit 10) sind abhängig von dem aktuellen Zaehlerwert (hier: r7). Im Rahmen des UP werden also die
// untersten 4 Bit des aktuellen Zaehlerwertes auf die LEDs E1 bis E4 gemappt.
.thumb_func
set_leds:
	mov r3, r0
	ldr r0, =ALL_LED
	
	and r2, r3, #8
	cmp r2, #8
	itt eq
	lsleq r2, r2, #7
	biceq r0, r0, r2
	and r2, r3, #4
	cmp r2, #4
	itt eq
	lsleq r2, r2, #27
	biceq r0, r0, r2
	and r2, r3, #2
	cmp r2, #2
	itt eq
	lsleq r2, r2, #27
	biceq r0, r0, r2
	and r2, r3, #1
	cmp r2, #1
	itt eq
	lsleq r2, r2, #11
	biceq r0, r0, r2
	
	bx lr

// UP zur Abfrage ob ein Taster gedrückt wurden -> Setzt mod
.thumb_func
set_mod:
	ldr r1, =mod
	
	ldrb r0, [r1]				//Ist keiner der Taster SW1 oder SW2 gedrückt worden, wird mod auf 0 gesetzt.
	cmp r0, #0
	itt ne
	movne r0, #0
	strbne r0, [r1]
		
	ldr r2, =flag_pollsw		//Wurde der Taster SW1 gedrückt (falg_pollsw = 1) wird mod auf 1 gesetzt. Anschließend wird das Benutzerflag flag_pollsw zurückgesetzt (-> 0)
	ldrb r0, [r2]
	cmp r0, #1
	itttt eq
	moveq r0, #1
	strbeq r0, [r1]
	moveq r0, #0
	strbeq r0, [r2]	
	
	ldr r2, =flag_isrsw			//Wurde der Taster SW2 gedrückt (falg_isrsw = 1) wird mod auf 2 gesetzt. Anschließend wird das Benutzerflag flag_isrsw zurückgesetzt (-> 0)
	ldr r0, [r2]
	cmp r0, #1
	itttt eq
	moveq r0, #2
	strbeq r0, [r1]
	moveq r0, #0
	strbeq r0, [r2]
	
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
mod: .byte 0x0 

flag_sec: .byte 0x0

flag_isrsw: .word 0x0 
flag_pollsw: .byte 0x0 

str_start: .asciz "Zaehler gestartet!\n"
str_stop: .asciz "Zaehler gestoppt!\n"
str_richtungswechsel: .asciz "Zaehlrichtung gewechselt!\n"
str_pl: .asciz "Hochzaehlen!\n"
str_mi: .asciz "Herunterzaehlen!\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC3, 0x40048030
__BBREG ADC1_SIM_SCGC3, SIM_SCGC3, 27		//BitBanding-Adresse fuer das PIT-Bit im SIM_SCGC6-Register

.equ SIM_SCGC6, 0x4004803C
__BBREG PIT_SIM_SCGC6, SIM_SCGC6, 23		//BitBanding-Adresse fuer das PIT-Bit im SIM_SCGC6-Register


.equ ADC1_CFG1, 0x400bb008					//Adresse des ADC1_CFG1
.equ ADC1_CFG2, 0x400bb00c					//Adresse des ADC1_CFG2
.equ ADC1_SC1A, 0x400bb000					//Adresse des ADC1_SC1A
.equ ADC1_SC3, 0x400bb024					//Adresse des ADC1_SC3
__BBREG CAL_ADC1_SC3, ADC1_SC3, 7			//BitBanding-Adresse fuer das CAL-Bit im ADC1_SC3
.equ ADC1_SC2, 0x400bb020					//Adresse des ADC1_SC2

.equ ADC1_RA, 0x400bb010					//Adresse des ADC1_RA
.equ ADC1_PG, 0x400bb02c					//Adresse des ADC1_PG
.equ ADC1_CLPS, 0x400bb038					//Adresse des ADC1_CLPS
.equ ADC1_CLP4, 0x400bb03c					//Adresse des ADC1_CLP4
.equ ADC1_CLP3, 0x400bb040					//Adresse des ADC1_CLP3
.equ ADC1_CLP2, 0x400bb044					//Adresse des ADC1_CLP2
.equ ADC1_CLP1, 0x400bb048					//Adresse des ADC1_CLP1
.equ ADC1_CLP0, 0x400bb04c					//Adresse des ADC1_CLP0

.equ ADC1_CFG1_CAL, 0x60					//Init-Wert für Kalibrierung

.equ ADC1_CFG1_VAL_n16, 0x6c				//Init-Wert für ADC1_CFG1 -> Setzen des Wandlungsgenauigkeit N=16
.equ ADC1_CFG1_VAL_n12, 0x64				//Init-Wert für ADC1_CFG1 -> Setzen des Wandlungsgenauigkeit N=12
.equ ADC1_CFG1_VAL_n10, 0x68				//Init-Wert für ADC1_CFG1 -> Setzen des Wandlungsgenauigkeit N=10
.equ ADC1_CFG1_VAL_n08, 0x60				//Init-Wert für ADC1_CFG1 -> Setzen des Wandlungsgenauigkeit N=08

.equ ADC1_SC1A_VAL_START, 0x14				//Wert zum Starten des AD-Wandlung
.equ ADC1_SC1A_VAL_STOP, 0x1F				//Wert zum Stoppen des AD-Wandlung

.equ ADC1_SC3_VAL, 0xE						//Init-Wert für ADC1_SC3  
.equ ADC1_SC3_VAL_CAL, 0x87					//Kalibrierungswert für ADC1_SC3
	
.equ PIT_MCR, 0x40037000					//Adresse des PIT_MCR-Registers
.equ PIT_MCR_VAL, 0x0
.equ PIT_LDVAL1, 0x40037110					//Adresse des PIT_LDVAL1-Registers
.equ PIT_TCTRL1, 0x40037118					//Adresse des PIT_TCTRL1-Registers
.equ PIT_TFLG1, 0x4003711C					//Adresse des PIT_TFLG1-Registers
.equ NVIC_ISER2, 0xE000E108					//Adresse des NVIC_ISER2-Registers
.equ NVIC_ICPR2, 0xE000E288					//Adresse des NVIC_ICPR2-Registers
.equ NVIC_BITPOS, 0x5						//Konstante fuer die Bitposition innerhalb der NVIC-Register
.equ NVIC_BIT, 1 << NVIC_BITPOS				//Wert zum Setzen des Bit 5 innerhalb der NVIC-Register

.equ PIT1_VAL, 0x17D783F					//Startwert fuer PIT1 -> Dauer bis zum Interrupt: 1 Sekunde

.equ PIT_TCTRL1_TIE_TEN, 0x3				//Wert zum Setzen des Bit 1 und 2 innerhalb des PIT_TCTRL1-Registers

.equ SCR_VTOR, 0xE000ED08					//Adresse des Basisregisters der IVT
.equ OFFS_PIT1, 0x154						//Offset fuer IVT (PIT1) 


.equ SIM_SCGC5, 0x40048038
__BBREG SIM_SCGC5_PORTA, SIM_SCGC5, 9		//BitBanding-Adresse fuer das PORTA-Bit im SIM_SCGC5-Register

//Pin Control Register (PCR) fuer Schalter und LED
.equ PORTA_PCR11, 0x4004902C 				//LED1
.equ PORTA_PCR28, 0x40049070 				//LED2
.equ PORTA_PCR29, 0x40049074 				//LED3
.equ PORTA_PCR10, 0x40049028 				//LED4

//Init-Werte fuer LEDs -> Pin Control Register (PCR)
.equ PCR_MUX_LED, 0x100

.equ GPIOA_PDOR, 0x400FF000					//Adresse des GPIOA_PDOR
.equ GPIOA_PDIR, 0x400FF010					//Adresse des GPIOA_PDIR
.equ GPIOA_PDDR, 0x400FF014					//Adresse des GPIOA_PDDR
.equ GPIOA_PSOR, 0x400FF004					//Adresse des GPIOA_PSOR
.equ GPIOA_PCOR, 0x400FF008					//Adresse des GPIOA_PCOR

.equ ALL_LED, 0x30000c00
.equ MSB_SET, 0x8000	

.equ ABSATZ, '\n'
.equ KLAMMERZU, ')'
.equ STR_LENGTH, 24							//Länge der String innerhalb der String-Arrays
.equ STEP_N16, 0x1000						//Schrittweite bei N=16
.equ STEP_N12, 0x156						//Schrittweite bei N=12
.equ STEP_N10, 0x67							//Schrittweite bei N=10
.equ STEP_N08, 0x20							//Schrittweite bei N=08

.equ CHARS, 0x73							//ascii-Wert von s
.equ CHARNULL, 0x30							//ascii-Wert von 0
.equ CHAREINS, 0x31							//ascii-Wert von 1
.equ CHARZWEI, 0x32							//ascii-Wert von 2
.equ CHARDREI, 0x33							//ascii-Wert von 3
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	ldr r1, =ADC1_SIM_SCGC3			//Takt fuer ADC aktivieren (System Integration Module –> SIM_SCGC3 Bitpos.: 27)
	mov r0, #1
	str r0, [r1]
		
	ldr r0, =PIT_SIM_SCGC6			//Takt fuer PIT aktivieren (System Integration Module –> SIM_SCGC6 Bitpos.: 23)
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =SCR_VTOR				//Interrupt-Vektor zu PIT1 setzen
	ldr r0, [r0]
	ldr r1, =isr_pit1
	str r1, [r0, #OFFS_PIT1]
				
	ldr r0, =NVIC_ICPR2				//eventuell haengende (pending) Interrupts zu PIT1 loeschen (NVIC)
	mov r1, #NVIC_BIT
	str r1, [r0]
	
	ldr r0, =NVIC_ISER2				//Interrupt zu PIT1 aktivieren (NVIC)
	mov r1, #NVIC_BIT
	str r1, [r0]
				
	ldr r0, =PIT_MCR				//alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	mov r1, #PIT_MCR_VAL
	str r1, [r0]
	
	ldr r0, =PIT_LDVAL1				//Startwert fuer PIT1 auf 1 Sekunde initialisieren
	ldr r1, =PIT1_VAL
	str r1, [r0]
	
	ldr r0, =PIT_TCTRL1				//Interrupt zu PIT1 aktivieren (PIT-Modul), h) PIT1 aktivieren (PIT-Modul)
	mov r1, #PIT_TCTRL1_TIE_TEN
	str r1, [r0]
	
	mov r1, #1						//Takt fuer PORTA und PORTE aktivieren (System Integration Module –> SIM_SCGC5 Bitpos.: 9 und 13)
	ldr r0, =SIM_SCGC5_PORTA		
	str r1, [r0]
	
	mov r2, #PCR_MUX_LED			//Initialisierung der PCR fuer die LEDs
	ldr r0, =PORTA_PCR11
	str r2, [r0]
	ldr r0, =PORTA_PCR28
	str r2, [r0]
	ldr r0, =PORTA_PCR29
	str r2, [r0]
	ldr r0, =PORTA_PCR10
	str r2, [r0]	
	
	ldr r1, =ALL_LED				//GPIO-Pins fuer die LEDs werden als Output konfiguriert -> durch Schreiben einer 1 an die entsprechende Bitposition wird die LED ausgeschaltet.
	ldr r0, =GPIOA_PDDR
	ldr r2, [r0]
	orr r2, r2, r1 
	str r2, [r0]
	ldr r0, =GPIOA_PDOR
	ldr r2, [r0]
	orr r2, r2, r1 
	str r2, [r0]	
	
	mov r11, #0						//Zustand: start/stop: r11 = 0 -> Wandlung gestoppt; r11 = 1 -> Wandlung gestartet.
	ldr r10, =flag_sec
	ldr r9, =ADC1_RA				//Adresse des ADC1-Ausgaberegister -> Bestimmumg des aktuellen Ausgabewerts 
	ldr r8, =flag_n					//Adresse des Benutzerflags flag_n -> legt die Wandlungsgenauigkeit N der AD-Wandlung fest
	ldr r6, =flag_currentlvl		//Adresse des Benutzerflags flag_currentlvl -> Aktuelle Stufe (abhaengig von der Wandlungsgenauigkeit N)
	
	ldr r0, =str_init				//Ausgabe von str_1 -> Dies geschieht einmal bei Programmstart.
	bl uart_putString
	
	bl adc1_init
	
init_adc:		
//Initialisierung ADC1: Clock-Rate + Wandlungsgenauigkeit -> in Abhaengigkeit von flag_n
	ldr r1, =ADC1_CFG1
	ldrb r0, [r8]
	cmp r0, #3
	ittt eq
	moveq r0, #ADC1_CFG1_VAL_n16	//Setzen der Wandlungsgenauigkeit N=16
	moveq r5, #STEP_N16				//Setzen der Schrittweite und des Startwerts zur Bestimmung der aktuellen Stufe (flag_currentlvl)
	ldreq r7 , =str_n16				//Setzen der Basisadresse des String-Arrays bei der Wandlungsgenauigkeit N=16
	
	cmp r0, #2
	ittt eq
	moveq r0, #ADC1_CFG1_VAL_n12	//Setzen der Wandlungsgenauigkeit N=12
	moveq r5, #STEP_N12				//Setzen der Schrittweite und des Startwerts zur Bestimmung der aktuellen Stufe (flag_currentlvl)
	ldreq r7 , =str_n12				//Setzen der Basisadresse des String-Arrays bei der Wandlungsgenauigkeit N=12
	
	cmp r0, #1
	ittt eq
	moveq r0, #ADC1_CFG1_VAL_n10	//Setzen der Wandlungsgenauigkeit N=10
	moveq r5, #STEP_N10				//Setzen der Schrittweite und des Startwerts zur Bestimmung der aktuellen Stufe (flag_currentlvl)
	ldreq r7 , =str_n10				//Setzen der Basisadresse des String-Arrays bei der Wandlungsgenauigkeit N=10
	
	cmp r0, #0
	ittt eq
	moveq r0, #ADC1_CFG1_VAL_n08	//Setzen der Wandlungsgenauigkeit N=08
	moveq r5, #STEP_N08				//Setzen der Schrittweite und des Startwerts zur Bestimmung der aktuellen Stufe (flag_currentlvl)
	ldreq r7 , =str_n08				//Setzen der Basisadresse des String-Arrays bei der Wandlungsgenauigkeit N=08
	
	str r0, [r1]
					
	mov r4, r5
		
loop_adc:
	bl uart_charPresent				//Unterprogrammaufruf zur Pruefung, ob ein Zeichen eingegeben wurde
	cbz r0, skip_getChar			//Ist ein Zeichen eingegeben worden (-> r0 ungleich 0), wird das eingegebene Zeichen in r0 geladen.
		
	bl uart_getChar					
	
	cmp r0, #CHARS					//Vergleiche r0 mit 0x73 ('s'), ist r0 gleich 0x73 -> mod wird auf 2 gesetzt -> Zaehlerzustand fuer "Start/Stop" wird geaendert.
	bne no_s
	ldr r2, =ADC1_SC1A
	eors r11, r11, #1				//Invertieren des ADC-Zustands fuer "Start/Stop"
	ittee ne						//Je nach dem welchen Zustand der Zaehler nach dem Wechsel des ADC-Zustand fuer "Start/Stop" wird entweder 
	ldrne r0, =str_start			//str_start (-> Wandlung laeuft weiter) oder str_stop (-> Wandlung stoppt) auf dem Terminal ausgegeben
	movne r1, #ADC1_SC1A_VAL_START
	ldreq r0, =str_stop
	moveq r1, #ADC1_SC1A_VAL_STOP
	str r1, [r2]					//Interrupts deaktivieren + Input-Channel einstellen bzw. ADC1 deaktivieren
	bl uart_putString
no_s:	
	
	cmp r11, #1
	beq skip_getChar
	
	cmp r0, #CHARNULL				//Vergleiche r0 mit 0x30 ('0'), ist r0 gleich 0x30 ->  Die Wandlungsgenauigkeit N wird auf 08 gesetzt. + Ausgabe von str_0
	bne no_0
	mov r1, #0
	strb r1, [r8]
	ldr r0, =str_0
	bl uart_putString
	b init_adc
no_0:	

	cmp r0, #CHAREINS				//Vergleiche r0 mit 0x31 ('1'), ist r0 gleich 0x31 -> Die Wandlungsgenauigkeit N wird auf 10 gesetzt. + Ausgabe von str_1
	bne no_1
	mov r1, #1
	strb r1, [r8]
	ldr r0, =str_1
	bl uart_putString
	b init_adc
no_1:	
	
	cmp r0, #CHARZWEI				//Vergleiche r0 mit 0x32 ('2'), ist r0 gleich 0x32 -> Die Wandlungsgenauigkeit N wird auf 12 gesetzt. + Ausgabe von str_2
	bne no_2
	mov r1, #2
	strb r1, [r8]
	ldr r0, =str_2
	bl uart_putString
	b init_adc
no_2:	
	
	cmp r0, #CHARDREI				//Vergleiche r0 mit 0x33 ('3'), ist r0 gleich 0x33 -> Die Wandlungsgenauigkeit N wird auf 16 gesetzt. + Ausgabe von str_3
	bne skip_getChar
	mov r1, #3
	strb r1, [r8]
	ldr r0, =str_3
	bl uart_putString
	b init_adc
skip_getChar:	
	
	ldrb r0, [r10]					//Der aktuelle Wert des Benutzerflags flag_sec wird in r0 geladen und mit 1 verglichen.
	cmp r0, #1						
	bne loop_adc					//Ist r0 gleich 0 wird der Ruecksprung zu loop_minute nicht durchgefuehrt -> Dies geschiet im Sekundentakt.
	
	mov r0, #0						//Ruecksetzen des Benutzerflags flag_sec
	strb r0, [r10]
	
	cmp r11, #0          			//Die Berechnung der aktuellen Stufe ist nur bei "r11 = 1 -> Wandlung gestartet" aktiviert
	beq skip_loop_n
	mov r3, #1          
loop_n:								//Die aktuelle Stufe (abhaengig von N) wird durch schrittweise Vergleiche von r4 (Grenzwert der nächst-höheren Stufe) und r0 (Aktueller Ausgabewert des ADC1) bestimmt.
	ldrh r0, [r9]
	cmp r0, r4
	blo leave_n
	add r4, r4, r5
	add r3, r3, #1
	b loop_n
leave_n:	
	mov r4, r5						//r4 wird auf den Startwert zurückgesetzt.
	strb r3, [r6]					//Ermittelte Stufe wird in flag_currentlvl gespeichert.	
skip_loop_n:
	
	cmp r11, #0						//r11 = 0 -> Wandlung gestoppt -> Ruecksprung zu loop_adc
	beq loop_adc

// Ausgabe			
	ldr r0, =str_nullx				//Ausgabe von str_nullx
	bl uart_putString
	
	ldrh r0, [r9]
	bl uart_putInt16
	
	mov r0, r7						//Anhand der aktuellen Stufe wird der jeweilige String fuer die Ausgabe aus dem String-Array ausgewaehlt.
	ldrb r1, [r6]
loop_str:
	cmp r1, #1
	beq leave_str
	sub r1, r1, #1
	add r0, r0, #STR_LENGTH			//-> Stringlänge ist genau 24 Byte
	b loop_str
leave_str:
	bl uart_putString				//Ausgabe des selektierten Strings
	
	ldrb r0, [r6]
	cmp r0, #10 					//r0 >= 10
	ite hs
	ldrhs r1, =uart_putByteBase10 	//ohne fuehrende Null
	ldrlo r1, =uart_putByte 		//mit fuehrender Null
	blx r1							//entsprechendes UP aufrufen
		
	mov r0, #KLAMMERZU				//Ausgabe einer geschlossenen Klammer (')')
	bl uart_putChar
	
	mov r0, #ABSATZ					//Ausgabe eines Absatzes ('\n')
	bl uart_putChar

// Abbildung der Stufe auf den LEDs 1 bis 4 (Uebergabeparameter -> aktuelle Stufe: in flag_currentlvl gespeichert)		
	ldrb r0, [r6]
	bl set_leds
	ldr r1, =GPIOA_PSOR
	ldr r2, =ALL_LED
	str r2, [r1]
	ldr r1, =GPIOA_PCOR
	str r0, [r1]

	b loop_adc


// Unterprogramme
// UP zur Kalibrierung des ADC1
.thumb_func
adc1_init:	
	ldr r1, =ADC1_CFG1				//Setzen des ADC-internen Takts auf 3,125 MHz
	ldr r0, [r1] 
	orr r0, r0, #ADC1_CFG1_CAL
	str r0, [r1]
	
	ldr r1, =ADC1_CFG2						
	mov r0, #0
	str r0, [r1]
	ldr r1, =ADC1_SC2
	str r0, [r1]
	
	ldr r1, =ADC1_SC3				//Starte Auto-Kalibrierung						
	mov r0, #ADC1_SC3_VAL_CAL
	str r0, [r1] 
	
	ldr r2, =CAL_ADC1_SC3			//Verzoegerung bis die Kalibrierungsfunktion beendet ist.
loop_cal:
	ldr r0, [r2]
	cmp r0, #1
	beq loop_cal

	mov r1, #0x0					//Aufaddieren der Config-Register CLP0 bis CLPS
	ldr r0, =ADC1_CLPS
	ldr r3, [r0]
	add r1, r1, r3
	ldr r0, =ADC1_CLP0
	ldr r3, [r0]
	add r1, r1, r3
	ldr r0, =ADC1_CLP1
	ldr r3, [r0]
	add r1, r1, r3
	ldr r0, =ADC1_CLP2
	ldr r3, [r0]
	add r1, r1, r3
	ldr r0, =ADC1_CLP3
	ldr r3, [r0]
	add r1, r1, r3
	ldr r0, =ADC1_CLP4
	ldr r3, [r0]
	add r1, r1, r3
	
	lsr r1, r1, #1					//Division durch 2 als Verschiebung um 1 nach rechts (rsl)
	orr r1, r1, #MSB_SET			//MSB wird auf 1 gesetzt
			
	ldr r0, =ADC1_PG				//Kalibrierungswert wird in ADC1_PG geschrieben 
	str r1, [r0]
	
	ldr r1, =ADC1_SC3				//Der ADC wird nach Kalibrierung auf "16 samples mitteln" und "Kontinuierliche Wandlung" konfiguriert -> gemaeß Aufgabe. 				
	mov r0, #ADC1_SC3_VAL
	str r0, [r1]
		
	bx lr

// ISR	
.thumb_func
isr_pit1:		
	ldr r0, =flag_sec		//Setzen des Benutzerflags auf 1
	mov r1, #1
	strb r1, [r0]
	
	ldr r0, =PIT_TFLG1		//Ruecksetzen des Interruptflags im PIT-Modul (-> In das PIT_TFLG1-Register wird eine 0x1) geschrieben.
	str r1, [r0]
	bx lr

// UP zum Setzen der LEDs E1 bis E4
// Die relevanten Bits innerhalb des GPIOA_PDOR (hier fuer LEDs E1 = Bit 11; E2 = Bit 28; E3 = Bit 29; E4 = Bit 10) sind abhaengig von dem aktuellen Zaehlerwert (hier: r7). Im Rahmen des UP werden also die
// untersten 4 Bit des aktuellen Zaehlerwertes auf die LEDs E1 bis E4 gemappt.
.thumb_func
set_leds:
	mov r3, r0
	mov r0, #0
	
	ands r2, r3, #8	
	it ne
	orrne r0, r0, r2, lsl #7
	ands r2, r3, #4
	it ne
	orrne r0, r0, r2, lsl #27
	ands r2, r3, #2	
	it ne
	orrne r0, r0, r2, lsl #27
	ands r2, r3, #1	
	it ne
	orrne r0, r0, r2, lsl #11
	
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data

flag_sec: .byte 0x0

flag_n: .byte 0x3

flag_currentlvl: .byte 0x0

str_nullx: .asciz "0x"

str_init: .asciz "AD-Wandlung mit Eingabe: 's' starten. Die Genauigkeit des ADC1 (N=8,10,12,16) mit Eingabe: '0-3' setzen (Default: N=16).\n" //Dieser String wird initial ausgegeben.

str_0: .asciz "Die Genauigkeit des ADC1 wurde auf N=08 gesetzt.\n"

str_1: .asciz "Die Genauigkeit des ADC1 wurde auf N=10 gesetzt.\n"

str_2: .asciz "Die Genauigkeit des ADC1 wurde auf N=12 gesetzt.\n"

str_3: .asciz "Die Genauigkeit des ADC1 wurde auf N=16 gesetzt.\n"

str_start: .asciz "Wandlung gestartet!\n"
str_stop: .asciz "Wandlung gestoppt! Die Genauigkeit des ADC1 (N=8,10,12,16) mit Eingabe: '0-3' setzen.\n"

// String-Arrays -> Die Anzahl der String (Länge pro String = 24 Byte) ist abhaengig von der Genauigkeit N.
str_n16: .asciz "\t0000 - 0206 mV\t(Stufe ", "\t0207 - 0413 mV\t(Stufe ", "\t0414 - 0620 mV\t(Stufe ", "\t0621 - 0827 mV\t(Stufe ", "\t0828 - 1034 mV\t(Stufe ", "\t1035 - 1240 mV\t(Stufe ", "\t1241 - 1446 mV\t(Stufe ", "\t1447 - 1652 mV\t(Stufe ", "\t1653 - 1858 mV\t(Stufe ", "\t1859 - 2064 mV\t(Stufe ", "\t2065 - 2270 mV\t(Stufe ", "\t2271 - 2476 mV\t(Stufe ", "\t2477 - 2682 mV\t(Stufe ", "\t2683 - 2888 mV\t(Stufe ", "\t2889 - 3094 mV\t(Stufe ", "\t3095 - 3300 mV\t(Stufe "

str_n12: .asciz "\t0000 - 0275 mV\t(Stufe ", "\t0276 - 0550 mV\t(Stufe ", "\t0551 - 0825 mV\t(Stufe ", "\t0826 - 1100 mV\t(Stufe ", "\t1101 - 1375 mV\t(Stufe ", "\t1376 - 1650 mV\t(Stufe ", "\t1651 - 1925 mV\t(Stufe ", "\t1926 - 2200 mV\t(Stufe ", "\t2201 - 2475 mV\t(Stufe ", "\t2476 - 2750 mV\t(Stufe ", "\t2751 - 3025 mV\t(Stufe ", "\t3026 - 3300 mV\t(Stufe "

str_n10: .asciz "\t0000 - 0330 mV\t(Stufe ", "\t0331 - 0660 mV\t(Stufe ", "\t0661 - 0990 mV\t(Stufe ", "\t0991 - 1320 mV\t(Stufe ", "\t1321 - 1650 mV\t(Stufe ", "\t1651 - 1980 mV\t(Stufe ", "\t1981 - 2310 mV\t(Stufe ", "\t2311 - 2640 mV\t(Stufe ", "\t2641 - 2970 mV\t(Stufe ", "\t2971 - 3300 mV\t(Stufe "

str_n08: .asciz "\t0000 - 0413 mV\t(Stufe ", "\t0414 - 0826 mV\t(Stufe ", "\t0827 - 1240 mV\t(Stufe ", "\t1241 - 1652 mV\t(Stufe ", "\t1653 - 2065 mV\t(Stufe ", "\t2066 - 2479 mV\t(Stufe ", "\t2480 - 2890 mV\t(Stufe ", "\t2891 - 3300 mV\t(Stufe "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC5, 0x40048038
__BBREG SIM_PORTD, SIM_SCGC5, 12
.equ PD8_9, 0x300 							//Maske fuer PD8 und PD9
.equ PD8, 0x100 							//Maske fuer PD8
.equ ALT_GPIO, 0x100 						//Alternative 1: GPIO
.equ ALT_SCL_SDA, 0x200 					//Alternative 2: SCL; SDA --> I2C0

.equ PORTD_PCR8, 0x4004C020					//Adresse des PORTD_PCR8
.equ PORTD_PCR9, 0x4004C024					//Adresse des PORTD_PCR9
.equ GPIOD_PDDR, 0x400FF094					//Adresse des GPIOD_PDDR
.equ GPIOD_PDOR, 0x400FF0C0					//Adresse des GPIOD_PDOR
.equ GPIOD_PDIR, 0x400FF0D0					//Adresse des GPIOD_PDIR

.equ SIM_SCGC4, 0x40048034
__BBREG I2C0_SIM_SCGC4, SIM_SCGC4, 6		//BitBanding-Adresse fuer das I2C0-Bit im SIM_SCGC4-Register

// Adressen der I2C0-Register
.equ I2C0_A1, 0x40066000
.equ I2C0_F, 0x40066001
.equ I2C0_C1, 0x40066002
.equ I2C0_S, 0x40066003
.equ I2C0_D, 0x40066004
.equ I2C0_C2, 0x40066005
.equ I2C0_FLT, 0x40066006
.equ I2C0_RA, 0x40066007
.equ I2C0_SMB, 0x40066008
.equ I2C0_A2, 0x40066009
.equ I2C0_SLTH, 0x4006600A
.equ I2C0_SLTL, 0x4006600B

__BBREG MST_I2C0_C1, I2C0_C1, 5				//BitBanding-Adresse fuer das MST-Bit im I2C0_C1
__BBREG TX_I2C0_C1, I2C0_C1, 4				//BitBanding-Adresse fuer das TX-Bit im I2C0_C1
__BBREG TXAK_I2C0_C1, I2C0_C1, 3			//BitBanding-Adresse fuer das TXAK-Bit im I2C0_C1
__BBREG RSTA_I2C0_C1, I2C0_C1, 2			//BitBanding-Adresse fuer das RSTA-Bit im I2C0_C1
__BBREG IICIF_I2C0_S, I2C0_S, 1				//BitBanding-Adresse fuer das IICIF-Bit im I2C0_S

.equ INIT_I2C0_F, 0x12 						//Die maximale Frequenz für den DS75 beträgt 400 KHz. Somit muss der Frequenzteiler auf 64 konfiguriert werden --> 0x12 => 25.000.000Hz / 64 = 390,625 KHz -> Antwort zu Aufgabe b)
.equ INIT_I2C0_C1, 0xC0

.equ DS75_READ_ADR, 0x91					//Lesezugriff
.equ DS75_WRITE_ADR, 0x90					//Schreibzugriff
.equ CONFIG_DS75, 0x68						//Configbyte --> für DS75 --> Auflösung 12 Bit

.equ COUNT, 0x7F2815

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	bl I2CBus_Reset
	cmp r0, #0						//Der I2C-Bus kann nicht zurueckgesetzt werden --> Abbruch! 
	bne skip_fail_reset
	ldr r0, =str_error_I2CBus_Reset
	bl uart_putString
	b failure
skip_fail_reset:
	
	ldr r2, =PORTD_PCR8         	//Konfiguration der Portleitungen: PD8 -> I2C0_SCL; PD9 -> I2C0_SDA 
    ldr r3, =PORTD_PCR9
    mov r1, #ALT_SCL_SDA 
    str r1, [r2]
    str r1, [r3]
		
	mov r1, #1
	ldr r0, =I2C0_SIM_SCGC4			//Takt fuer I2C0 aktivieren
	str r1, [r0]
	
	mov r1, #0						//Nicht-verwendete Register von I2C0 werden zurückgesetzt.
	ldr r0, =I2C0_A1
	strb r1, [r0]
    ldr r0, =I2C0_C2
    strb r1, [r0]
    ldr r0, =I2C0_FLT
    strb r1, [r0]
    ldr r0, =I2C0_RA
    strb r1, [r0]
    ldr r0, =I2C0_SMB
    strb r1, [r0]
    ldr r0, =I2C0_A2
    strb r1, [r0]
    ldr r0, =I2C0_SLTH
    strb r1, [r0]
    ldr r0, =I2C0_SLTL
    strb r1, [r0]

    ldr r0, =I2C0_F             	//Busfreq. fuer I2C0 setzen.
    mov r1, #INIT_I2C0_F
    strb r1, [r0]
    
    ldr r0, =I2C0_C1            	//Setzen der I2C0-Startkonfiguration. 
    mov r1, #INIT_I2C0_C1
    strb r1, [r0]
  
    bl config_DS75 					
    
//Auslesen der Anfangstemperatur zur Konfiguration von TOS und THYST
    bl read_I2C0_Temp 
	
//Konfiguration von TOS und HYST
	mov r8, r0
	mov r9, r1
		
	mov r0, #3
    add r1, r8, #3              	//T0 + 3
    mov r2, r9
    bl config_HYST_OS
    
    mov r0, #2
    add r1, r8, #2              	//T0 + 2
    mov r2, r9
    bl config_HYST_OS
	             
loop_i2c_ds75:
    bl read_I2C0_Temp 				//Auslesen der Temperatur
        
	mov r6, r0
    mov r7, r1
    
    lsl r1, r6, #16
    lsl r2, r7, #8
    orr r0, r1, r2 
    
    bl uart_putInt32				//Ausgabe der Temperatur (in hexadezimaler Schreibweise)
    
    mov r0, #':'
    bl uart_putChar					//Ausgabe eines Doppelpunktes
    mov r0, #' '
    bl uart_putChar					//Ausgabe eines Leerzeichens
    
    mov r0, r6						//Ausgabe der Vorkommazahl
    bl uart_putByteBase10
    
    mov r0, #','					
    bl uart_putChar					//Ausgabe eines Kommas 
    
    mov r0, #0						//Berechnung der Nachkommazahl -> mit Hilfe von Grenzwerten (0x80 - 0x10 --> 1000 0000 bis 0001 0000)
    tst r7, #0x80
    it ne
    addne r0, r0, #0x32
    tst r7, #0x40
    it ne
    addne r0, r0, #0x19
    tst r7, #0x20
    it ne
    addne r0, r0, #0xC
    tst r7, #0x10
    it ne
    addne r0, r0, #0x6
    
    bl uart_putByteBase10			//Ausgabe der Nachkommazahl
    
    ldr r0, =str_grad_cel			//Ausgabe des Strings: str_grad_cel
    bl uart_putString
	
	bl delay
	
	b loop_i2c_ds75 
	
failure:
	b failure

// Unterprogramme
// UP zum Zuruecksetzen des I2C-Bus
.thumb_func
I2CBus_Reset:
    push {r4, lr}

    ldr r0, =SIM_PORTD          // In SCGC5 den Takt fuer Port D aktivieren
    mov r1, #1
    str r1, [r0]
    ldr r0, =PORTD_PCR8         // Portleitungen PD8, PD9 als GPIO
    ldr r1, =PORTD_PCR9
    mov r2, #ALT_GPIO
    str r2, [r0]
    str r2, [r1]
    ldr r0, =GPIOD_PDDR         // PD8 , PD9 als Ausgang schalten
    ldr r2, [r0]
    orr r2, r2, #PD8_9
    str r2, [r0]
    
    mov r4, #10
loop:
    // Ein Zaehler fuer maximal 10 Versuche ist zu implementieren.
    // Danach Fehlermeldung auf Terminal ausgeben und abbrechen.
    ldr r0, =GPIOD_PDOR     // SCL deaktivieren
    ldr r2, [r0]
    bic r2, r2, #PD8        // entsprechendes Bit loeschen
    str r2, [r0]
    bl i2c_Delay
    
    ldr r0, =GPIOD_PDOR     // SCL und SDA aktivieren
    ldr r2, [r0]
    orr r2, r2, #PD8_9
    str r2, [r0]
    bl i2c_Delay
    
    ldr r0, =GPIOD_PDIR
    ldr r2, [r0]
    and r2, r2, #PD8_9      // nur Bits 9 und 10 pruefen
    cmp r2, #PD8_9          // Bit 9 und Bit 10 gesetzt?
    beq leave_loop
    
    subs r4, r4, #1
    bne loop                // ggf. wiederholen

    mov r0, #0
    b return

leave_loop:
    mov r0, #1
    
return:
    pop {r4, pc}

// UP zur Erzeugung der Verzögerung für den I2C-Bus
.thumb_func
i2c_Delay:
	mov r0, #17
loop_i2c_Delay:
	subs r0, r0, #1
	bne loop_i2c_Delay

    bx lr

// UP zum Starten des I2C-Bus -> Es wird 10 mal versucht den I2C-Bus unter Kontrolle zu bringen.
.thumb_func
start_I2C0:
	push {r4, lr}
	mov r0, #0
	mov r1, #1
    ldr r2, =MST_I2C0_C1
    mov r3, #10
        
loop_start_I2C0:
    strb r0, [r2]           		//Slave Mode aktivieren
    strb r1, [r2]           		//Kontrolle über I2C-Bus erhalten?
    
    ldrb r4, [r2]           		//--> Pruefen, ob MST-Bit gesetzt wurde.
    cmp r4, #1 
    beq leave_loop_start_I2C0
    
    subs r3, r3, #1
    bne loop_start_I2C0   
// Der Bus wurde nach 10 Versuchen nicht unter Kontrolle gebracht. 
    ldr r0, =str_error_start_I2C0
	bl uart_putString
leave_loop_start_I2C0:
// Der Bus wurde nach 10 Versuchen unter Kontrolle gebracht.   
    pop {r4, pc}

// UP zum Stoppen des I2C-Bus
.thumb_func
stop_I2C0:
    ldr r1, =MST_I2C0_C1 			//Ruecksetzen des MST Bit -> I2C-Bus wird wieder freigegeben.
    mov r0, #0
    strb r0, [r1]
    
    bx lr

// UP zur Konfiguration von THYST und OS
.thumb_func
config_HYST_OS:
    push {r4-r8, lr}
    
    mov r7, r0          			//Zeiger -> 3 = OS; 2 = HYST
    mov r6, r1          			//MSB
    mov r5, r2          			//LSB
    ldr r4, =I2C0_D
    
    ldr r1, =TX_I2C0_C1				//Setzen des TX-Bits für Transmit
    mov r0, #1
    strb r0, [r1]
            
    bl start_I2C0					//Starte den I2C-Bus       
            
    mov r0, #DS75_WRITE_ADR			//Adress-Byte wird an den Thermostat uebertragen
    strb r0, [r4]
    bl poll_I2C0_IF
    
    strb r7, [r4]					//Zeiger-Byte wird an den Thermostat uebertragen
    bl poll_I2C0_IF
    
    strb r6, [r4]					//MSB wird an den Thermostat uebertragen
    bl poll_I2C0_IF
    
    strb r5, [r4]					//LSB wird an den Thermostat uebertragen
    bl poll_I2C0_IF
    
    bl stop_I2C0					//stoppe den I2C-Bus
    bl i2c_Delay
    
    pop {r4-r8, pc}

// UP zur Konfiguration des DS75 
.thumb_func
config_DS75:
	push {r4, r5, lr}
	
	ldr r0, =TX_I2C0_C1				//Setzen des TX-Bits für Transmit
    mov r1, #1
    strb r1, [r0]
    
    ldr r4, =I2C0_D 
    
    bl start_I2C0					//Starte den I2C-Bus
       
    mov r1, #DS75_WRITE_ADR			//Adress-Byte wird an den Thermostat uebertragen
    strb r1, [r4]
    bl poll_I2C0_IF
            
    mov r1, #1						//Zeiger-Byte wird an den Thermostat uebertragen --> 1 zeigt an das die Konfiguration für den DS75 uebertragen wird.
    strb r1, [r4]
    bl poll_I2C0_IF
    
    mov r1, #CONFIG_DS75			//Konfigurations-Byte wird an den Thermostat uebertragen
    strb r1, [r4]
    bl poll_I2C0_IF

    bl stop_I2C0					//stoppe den I2C-Bus
    bl i2c_Delay
        
    pop {r4, r5, pc}

// UP zum Auslesen der vom DS75 gemessenen Temperatur
.thumb_func
read_I2C0_Temp:
    push {r4-r7, lr}
    ldr r6, =TX_I2C0_C1
    ldr r5, =TXAK_I2C0_C1
    ldr r4, =I2C0_D
    
    mov r1, #1						//Setzen des TX-Bits für Transmit
    strb r1, [r6]
    mov r1, #0						//Loeschen des TXAK-Bits um Transmit Acknowledge einzuschalten.
    strb r1, [r5]
    
    bl start_I2C0					//Starte den I2C-Bus
    
    mov r1, #DS75_WRITE_ADR 		//Adress-Byte wird an den Thermostat uebertragen
    strb r1, [r4]
    bl poll_I2C0_IF
    
    mov r1, #0
    strb r1, [r4]					//Zeiger-Byte wird an den Thermostat uebertragen --> 0 = Temperatur auslesen
    bl poll_I2C0_IF
    
    ldr r2, =RSTA_I2C0_C1			//Durch setzen des RSTA-Bits wird ein "Repeat Start" erzeugt.
    mov r3, #1
    strb r3, [r2]
    
    mov r1, #DS75_READ_ADR 			//Adress-Byte wird an den Thermostat uebertragen
    strb r1, [r4]
    bl poll_I2C0_IF
    
    mov r1, #0						//Loeschen des TX-Bits für Recieve
    strb r1, [r6]
    
    ldrb r3, [r4] 					//Dummy-Read 
    bl poll_I2C0_IF
    
    ldrb r6, [r4]					//Auslesen des ersten Bytes
    mov r1, #0						//Setzen des TXAK-Bits um Transmit Acknowledge auszuschalten.
    strb r1, [r5]
    bl poll_I2C0_IF
    
    ldrb r5, [r4]					//Auslesen des zweiten Bytes
    bl poll_I2C0_IF
    
    bl stop_I2C0					//stoppe den I2C-Bus
    bl i2c_Delay
    
    mov r0, r6
    mov r1, r5
    
    pop {r4-r7, pc}

// UP zur Abfrage des IICIF
.thumb_func
poll_I2C0_IF:
    ldr r1, =IICIF_I2C0_S
    mov r3, #70            			//Prüfe 70 mal ob das Interrupt Flag gesetzt wurde.
    
loop_poll_I2C0_IF:
    ldrb r0, [r1]
    cmp r0, #1						//Ist das IICIF gesetzt? -> Sprung zum Rückstezen des IICIF
    beq iicif_w1c
    subs r3, r3, #1
    bne loop_poll_I2C0_IF
iicif_w1c:
    strb r0, [r1]					//Ruecksetzen vom IICIF
    
    bx lr

// UP zur Verzögerung um 1 sec   
.thumb_func
delay:
	ldr r0, =COUNT					//Konstante zur Verzögerung um 1 sec 
loop_delay: 							 	
	subs r0, r0, #1	
	bne loop_delay

	bx lr
    
/*** Datenbereich (ab 0x20000000) ***/
.data
str_error_I2CBus_Reset: .asciz "Fehler! I2C-Bus wurde nicht zurueckgesetzt.\n"
str_error_start_I2C0: .asciz "Fehler! I2C-Bus wurde nicht gestartet.\n"
str_grad_cel: .asciz " Grad Celsius\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6, 0x4004803C
__BBREG PIT_SIM_SCGC6, SIM_SCGC6, 23		//BitBanding-Adresse fuer das PIT-Bit im SIM_SCGC6-Register

.equ SIM_SCGC5, 0x40048038
__BBREG PORTA_SIM_SCGC5, SIM_SCGC5, 9		//BitBanding-Adresse fuer das PORTA-Bit im SIM_SCGC5-Register
__BBREG PORTD_SIM_SCGC5, SIM_SCGC5, 12		//BitBanding-Adresse fuer das PORTD-Bit im SIM_SCGC5-Register
__BBREG PORTE_SIM_SCGC5, SIM_SCGC5, 13		//BitBanding-Adresse fuer das PORTE-Bit im SIM_SCGC5-Register

.equ SIM_SCGC3, 0x40048030
__BBREG SPI2_SIM_SCGC3, SIM_SCGC3, 12       //BitBanding-Adresse fuer das SPI2-Bit im SIM_SCGC3-Register              

.equ PORTA_PCR19, 0x4004904C 				//PCR fuer SW1
.equ PORTE_PCR26, 0x4004D068 				//PCR fuer SW2

.equ GPIOA_PDDR, 0x400FF014					//Adresse des GPIOA_PDDR
.equ GPIOE_PDDR, 0x400FF114					//Adresse des GPIOE_PDDR
__BBREG GPIOA_PDDR_19, GPIOA_PDDR, 19       //BitBanding-Adresse fuer das Bit 19 im GPIOA_PDDR 
__BBREG GPIOE_PDDR_26, GPIOE_PDDR, 26       //BitBanding-Adresse fuer das Bit 26 im GPIOE_PDDR

.equ PORTD_PCR12, 0x4004C030                //Adresse des PORTD_PCR12
.equ PORTD_PCR13, 0x4004C034                //Adresse des PORTD_PCR13
.equ PORTD_PCR14, 0x4004C038                //Adresse des PORTD_PCR14
.equ PORTD_PCR15, 0x4004C03C                //Adresse des PORTD_PCR15

.equ ALT_PCR_SPI, 0x200 					//Alternative 2: SPI

.equ NVIC_ISER2, 0xE000E108					//Adresse des NVIC_ISER2
.equ NVIC_ICPR2, 0xE000E288					//Adresse des NVIC_ICPR2
.equ NVIC_BITS_PIT_PORTE_PORTA, 0x08800020	//Wert zum Setzen des Bit 5, 23, 27 innerhalb der NVIC-Register

.equ PIT_MCR, 0x40037000					//Adresse des PIT_MCR
.equ PIT_LDVAL1, 0x40037110					//Adresse des PIT_LDVAL1-Registers
.equ PIT_TCTRL1, 0x40037118					//Adresse des PIT_TCTRL1-Registers
.equ PIT_TFLG1, 0x4003711C					//Adresse des PIT_TFLG1-Registers

.equ PIT1_VAL_8, 0x1C9C37                   //max. Wandlungsdauer: 08Bit -> 0.075s => 0x17D783F * 0.075
.equ PIT1_VAL_9, 0x39386F                   //max. Wandlungsdauer: 09Bit -> 0.150s => 0x17D783F * 0.150
.equ PIT1_VAL_10, 0x7270DF                  //max. Wandlungsdauer: 10Bit -> 0.300s => 0x17D783F * 0.300
.equ PIT1_VAL_11, 0xE4E1BF                  //max. Wandlungsdauer: 11Bit -> 0.600s => 0x17D783F * 0.600
.equ PIT1_VAL_12, 0x1C9C37F                 //max. Wandlungsdauer: 12Bit -> 1.200s => 0x17D783F * 1.200
__BBREG TEN_PIT_TCTRL1, PIT_TCTRL1, 0

.equ SCR_VTOR, 0xE000ED08					//Adresse des Basisregisters der IVT
.equ OFFS_PIT1, 0x154						//Offset fuer IVT (PIT1)
.equ OFFS_PORTE, 0x1AC						//Offset fuer IVT (PORTE)
.equ OFFS_PORTA, 0x19C						//Offset fuer IVT (PORTA)

.equ PCR_SW1_SW2, 0xA0103

.equ PORTE_ISFR, 0x4004D0A0 				//Adresse des PORTE_ISFR
.equ CLR_ISFR_SW2, 0x1 << 26
.equ PORTA_ISFR, 0x400490A0 				//Adresse des PORTA_ISFR
.equ CLR_ISFR_SW1, 0x1 << 19

.equ SPI2_MCR, 0x400AC000                   //Adresse des SPI2_MCR 
.equ SPI2_CTAR0, 0x400AC00C                 //Adresse des SPI2_CTAR0 
.equ SPI2_SR, 0x400AC02C                    //Adresse des SPI2_SR
.equ SPI2_RSER, 0x400AC030                  //Adresse des SPI2_RSER
.equ SPI2_PUSHR, 0x400AC034                 //Adresse des SPI2_PUSHR (Senden)
.equ SPI2_POPR, 0x400AC038                  //Adresse des SPI2_POPR (Empfangen)

__BBREG TCF_SPI2_SR, SPI2_SR, 31            //BitBanding-Adresse fuer das Transfer Complete Flag im SPI2_SR
__BBREG MDIS_SPI2_MCR, SPI2_MCR, 14         //BitBanding-Adresse fuer das SPI2_MCR Module Disable (MDIS) Bit

.equ INIT_VAL_SPI2_MCR, 0x80003000          //Konfiguration für SPI2 -> Master Mode + Kommunikation deaktiviert + Queues deaktiviert
.equ INIT_VAL_SPI2_CTAR0, 0x3E441117        //Uebertragungs-Config: 8 Bit Frames; Clock Polarity = 1; Clock Phase = 1; f = 97,65625 kHz; CSSCK, DT = 480ns; ASC = 160ns

.equ EOQ_SPI2_PUSHR, 0x08000000             //Maske zum Setzen des EOQ-Flags
.equ CONT_SPI2_PUSHR, 0x80000000            //Maske zum Setzen des CONT-Flags
.equ PCS_SPI2_PUSHR, 0x20000 				//Maske zum Setzen von Chip Select 1 (PCS 1) --> DS1722
.equ READ_TEMP_SPI2_PUSHR, 0x88020000 		//Maske zum Setzen von PCS 1, EOQ, CONT

.equ DS1722_WRITE_CONFIG_REG, 0x80          //Schreibadresse des Config-Registers
.equ DS1722_LSB_TEMP_REG, 1                 //Leseadresse des Registers LSB -> Nachkommastelle
.equ DS1722_MSB_TEMP_REG, 2                 //Leseadresse des Registers MSB -> Vorkommastelle

.equ DS1722_BASIC_CONF, 0xE0               	//DS1722 Basiskonfiguration gem. Manual

.equ MAX_RES, 12                			//Grenzwert: Maximale Auflösung -> 12 Bit
.equ MIN_RES, 8                 			//Grenzwert: Minimale Auflösung -> 08 Bit
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	mov r1, #1
	ldr r0, =PIT_SIM_SCGC6					//Takt fuer PIT aktivieren 
	str r1, [r0]
	ldr r0, =PORTA_SIM_SCGC5				//Takt fuer PORTA aktivieren
	str r1, [r0]
	ldr r0, =PORTD_SIM_SCGC5				//Takt fuer PORTD aktivieren
	str r1, [r0]
	ldr r0, =PORTE_SIM_SCGC5				//Takt fuer PORTE aktivieren
	str r1, [r0]
	ldr r0, =SPI2_SIM_SCGC3					//Takt fuer SPI2 aktivieren
	str r1, [r0]

	ldr r2, =PCR_SW1_SW2					//Initialisierung der PCR fuer die Taster SW1 und SW2
	ldr r0, =PORTA_PCR19
	str r2, [r0]
	ldr r0, =PORTE_PCR26
	str r2, [r0]
	
	mov r1, #0								//PDDR setzen fuer die Taster SW1 und SW2
	ldr r0, =GPIOA_PDDR_19
	str r1, [r0]
	ldr r0, =GPIOE_PDDR_26
	str r1, [r0]
	
	mov r1, #ALT_PCR_SPI					//Initialisierung der PCR fuer PORTD (SPI)
	ldr r0, =PORTD_PCR12
	str r1, [r0]
	ldr r0, =PORTD_PCR13
	str r1, [r0]
	ldr r0, =PORTD_PCR14
	str r1, [r0]
	ldr r0, =PORTD_PCR15
	str r1, [r0]
	
	ldr r0, =SCR_VTOR						//Interrupt-Vektor zu PIT1, PORTA, PORTE setzen
	ldr r0, [r0]
	ldr r1, =isr_pit1
	str r1, [r0, #OFFS_PIT1]
	ldr r1, =isr_sw1
	str r1, [r0, #OFFS_PORTA]
	ldr r1, =isr_sw2
	str r1, [r0, #OFFS_PORTE]
	
	ldr r1, =NVIC_BITS_PIT_PORTE_PORTA
	ldr r0, =NVIC_ICPR2						//eventuell haengende (pending) Interrupts zu PIT1, PORTA, PORTE loeschen (NVIC)
	str r1, [r0]
	ldr r0, =NVIC_ISER2						//Interrupt zu PIT1, PORTA, PORTE aktivieren (NVIC)
	str r1, [r0]		
	
	ldr r0, =PIT_MCR						//alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	mov r1, #0
	str r1, [r0]
		
	ldr r0, =PIT_TCTRL1						//Interrupt zu PIT1 aktivieren
	mov r1, #2
	str r1, [r0]
	
	mov r3, #0								//SPI2 Modul aktivieren
	ldr r0, =MDIS_SPI2_MCR	
	str r3, [r0]
	
	ldr r0, =SPI2_MCR						//Init-Wert für das SPI2_MCR setzen 
	ldr r2, =INIT_VAL_SPI2_MCR
	str r2, [r0]
	
	ldr r0, =SPI2_CTAR0						//Uebertragungsparameter konfigurieren (frame size etc.)
	ldr r2, =INIT_VAL_SPI2_CTAR0
	str r2, [r0]
	
	ldr r0, =SPI2_RSER						//Deaktivierung: Interrupt + DMA
	str r3, [r0]
	
	mov r0, #MAX_RES						//DS1722 initial mit Auflösung -> 12Bit konfigurieren
	bl write_config_ds1722
	
	ldr r0, =PIT_LDVAL1						//Wert für PIT_LDVAL1 initial setzen
	ldr r1, =PIT1_VAL_12	
	str r1, [r0]
	
	ldr r0, =TEN_PIT_TCTRL1					//PIT1 starten
	mov r1, #1						
	str r1, [r0]
	
	ldr r0, =str_init						//Init-String auf dem Terminal ausgeben
	bl uart_putString
	
	ldr r10, =flag_sec						//Laden der Adresse des Benutzerflags flag_sec
	ldr r9, =str_temp_lsb					//Laden der Adresse des Strings zur Ausgabe der Nachkommastelle der Temperatur
	ldr r8, =current_res					//Laden der Adresse der Variable zur Sicherung der aktuellen Aufloesung
	ldr r7, =flag_res_changed				//Laden der Adresse des Benutzerflags flag_res_changed	
	
loop_spi2_ds1722:
    ldrb r0, [r10]							//Der aktuelle Wert des Benutzerflags wird in r0 geladen und mit 1 verglichen.
	cmp r0, #1						
	bne loop_spi2_ds1722					//Ist r0 gleich 1 wird der Ruecksprung zu loop_spi2_ds1722 nicht durchgefuehrt.
	
	mov r0, #0								//Ruecksetzen des Benutzerflags flag_sec
	strb r0, [r10]
	
// Wurde die Aufloesung geaendert -> ist das Benutzerflag flag_res_changed gesetzt?	
	ldrb r0, [r7]
	cmp r0, #1
	bne skip_change_res
		
	mov r2, #0								//Ruecksetzen des Benutzerflags flag_res_changed
	strb r2, [r7]
	
	ldrb r0, [r8]							//DS1722 mit neuer Aufloesung konfigurieren
	mov r5, r0
	bl write_config_ds1722
	
	ldr r0, =str_changed_res				//Neue Aufloesung auf dem Terminal ausgeben
	bl uart_putString
	mov r0, r5
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	ldr r0, =str_changed_res_end
	bl uart_putString
	
	ldr r2, =TEN_PIT_TCTRL1					//PIT1 abschalten
	mov r1, #0
	str r1, [r2]
	
	sub r1, r5, #8							//Neues Zeitintervall für PIT1 festlegen -> Ausgabeintervall
	mov r0, #4
	ldr r3, =pit1_vals
	mla r4, r1, r0, r3
	
	ldr r0, =PIT_LDVAL1						//Wert für PIT_LDVAL1 setzen
	ldr r1, [r4]
	str r1, [r0]
	
	mov r1, #1								//PIT1 starten
	str r1, [r2]
skip_change_res:

// Auslesen der Temperatur und anschließende Ausgabe
	mov r0, #DS1722_MSB_TEMP_REG			//Auslesen der Temperatur + Terminalausgabe: Vorkommastelle
	bl read_temp_ds1722
	bl uart_putByteBase10
	
	mov r0, #DS1722_LSB_TEMP_REG			//Auslesen der Temperatur + Terminalausgabe: Nachkommastelle
	bl read_temp_ds1722
	lsr r1, r0, #4							//Berechnung der Anfangsadresse des Strings für die Darstellung der Nachkommastelle (max. stehen 4 Bit für die Nachkommastelle zur Verfuegung)
	mov r2, #10								
	mla r0, r1, r2, r9
	bl uart_putString
	
	b loop_spi2_ds1722

// Unterprogramme
// ISR PIT1
.thumb_func
isr_pit1:	
	mov r1, #1
	ldr r0, =flag_sec						//Setzen des Benutzerflags auf 1
	strb r1, [r0]
	ldr r0, =PIT_TFLG1						//Ruecksetzen des Interruptflags im PIT-Modul (-> In das PIT_TFLG1-Register wird eine 0x1 geschrieben).
	str r1, [r0]
	bx lr

// ISR PORTA SW1 
.thumb_func
isr_sw1:
	ldr r0, =PORTA_ISFR						//Ruecksetzen des Interruptflags im PORTA_ISFR	
	ldr r1, =CLR_ISFR_SW1
	str r1, [r0]

	ldr r0, =flag_res_changed				//Setzen des Benutzerflags flag_res_changed
	mov r1, #1
	strb r1, [r0]
	
	ldr r0, =current_res            		//Aufloesung inkrementieren
    ldrb r1, [r0]
    add r1, r1, #1
    cmp r1, #MAX_RES             			//Aufloesung groeßer als 12?
    it hi
    movhi r1, #MIN_RES       				//Aufloesung auf Minimum setzen (gem. Aufgabe) 
    strb r1, [r0]
			
	bx lr

// ISR PORTE SW1 
.thumb_func
isr_sw2:
	ldr r0, =PORTE_ISFR						//Ruecksetzen des Interruptflags im PORTE_ISFR	
	ldr r1, =CLR_ISFR_SW2
	str r1, [r0]

	ldr r0, =flag_res_changed				//Setzen des Benutzerflags flag_res_changed
	mov r1, #1
	strb r1, [r0]
	
	ldr r0, =current_res           			//Aufloesung dekrementieren
    ldrb r1, [r0]
    sub r1, r1, #1    
    cmp r1, #MIN_RES             			//Aufloesung kleiner als 8?
    it lo
    movlo r1, #MAX_RES       				//Aufloesung auf Maximum setzen (gem. Aufgabe)     
    strb r1, [r0]
			
	bx lr

// UP zum Warten auf den Abschluss der Uebertragung (transfer complete)
.thumb_func
poll_tcf_set:
    ldr r3, =TCF_SPI2_SR       
loop_poll_tcf_set:
    ldr r0, [r3]                			//Uebertragung abgeschlossen?
    cmp r0, #1
    bne loop_poll_tcf_set
    str r0, [r3]                			//Ruecksetzen des TCF

    bx lr

// UP zum Setzen der gewuenschten Konfiguration des DS1722
.thumb_func
write_config_ds1722:
    push {r4, r5, lr}
    
    lsl r3, r0, #1							//Konfiguration in Abhaengigkeit von der Auflösung festlegen (gem. Manual DS1722)
    orr r5, r3, #DS1722_BASIC_CONF
    
    ldr r4, =PCS_SPI2_PUSHR					//Adresse des Konfigurationsregisters des DS1722 übermitteln -> DS1722 "mitteilen", dass die gewuenschte Konfiguration über SPI uebertragen wird
    mov r2, #DS1722_WRITE_CONFIG_REG
    ldr r1, =CONT_SPI2_PUSHR
    orr r3, r4, r2
    orr r3, r3, r1
    ldr r1, =SPI2_PUSHR
    str r3, [r1]
    bl poll_tcf_set
    
    ldr r3, =SPI2_PUSHR 					//Gewuenschte Konfiguration über SPI an DS1722 uebertragen
    ldr r1, =EOQ_SPI2_PUSHR 
    orr r2, r4, r5
    orr r1, r1, r2
    str r1, [r3] 
    bl poll_tcf_set
    
    ldr r2, =SPI2_PUSHR						//Uebertragung eines leeren Frames --> Ruecksetzen von CONT
	ldr r0, =PCS_SPI2_PUSHR
	str r0, [r2]
	bl poll_tcf_set
    
    pop {r4, r5, pc}

// UP zum Auslesen der aktuell gemessenen Temperatur    
.thumb_func
read_temp_ds1722:
	push {r4, lr}
	
	ldr r3, =READ_TEMP_SPI2_PUSHR			//Adresse des (Temperatur-)Leseregister des DS1722 übermitteln -> DS1722 "mitteilen", dass die Temperatur ausgelesen und über SPI uebertragen werden soll
	ldr r2, =SPI2_PUSHR
	orr r1, r0, r3
	str r1, [r2]
	bl poll_tcf_set
	
	ldr r3, =SPI2_POPR						//aktuelle Temperatur auslesen -> Rueckgabewert (Rueckgabe in r0)
	ldr r4, [r3]
	
	ldr r2, =SPI2_PUSHR						//Uebertragung eines leeren Frames --> Ruecksetzen von CONT
	ldr r0, =PCS_SPI2_PUSHR
	str r0, [r2]
	bl poll_tcf_set
	
	mov r0, r4
	
	pop {r4, pc}
            
/*** Datenbereich (ab 0x20000000) ***/
.data
flag_sec: .byte 0x0	
flag_res_changed: .byte 0x0
current_res: .byte 0xC

pit1_vals: .word PIT1_VAL_8, PIT1_VAL_9, PIT1_VAL_10, PIT1_VAL_11, PIT1_VAL_12

str_init: .asciz "Initialisierung abgeschlossen. Aufloesung auf 12Bit gesetzt. Hinweis: Das Ausgabe-Intervall ist von der aktuellen Aufloesung abhaengig.\n"
str_changed_res: .asciz "\nDie Aufloesung wurde auf "
str_changed_res_end: .asciz "Bit gesetzt.\n"

//String für die Ausgabe der Nachkommastellen
str_temp_lsb: .asciz ",0000\tgC\n", ",0625\tgC\n", ",1250\tgC\n", ",1875\tgC\n", ",2500\tgC\n", ",3125\tgC\n", ",3750\tgC\n", ",4375\tgC\n", ",5000\tgC\n", ",5625\tgC\n", ",6250\tgC\n", ",6875\tgC\n", ",7500\tgC\n", ",8125\tgC\n", ",8750\tgC\n", ",9375\tgC\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6, 0x4004803C
__BBREG PIT_SIM_SCGC6, SIM_SCGC6, 23		//BitBanding-Adresse fuer das PIT-Bit im SIM_SCGC6-Register
__BBREG RTC_SIM_SCGC6, SIM_SCGC6, 29		//BitBanding-Adresse fuer das RTC-Bit im SIM_SCGC6-Register

.equ NVIC_ISER2, 0xE000E108					//Adresse des NVIC_ISER2
.equ NVIC_ICPR2, 0xE000E288					//Adresse des NVIC_ICPR2

.equ NVIC_BITS_RTC, 0xC						//Wert zum Setzen des Bits 2, 3 innerhalb der NVIC-Register

.equ SCR_VTOR, 0xE000ED08					//Adresse des Basisregisters der IVT
.equ OFFS_RTC, 0x148						//Offset fuer IVT (RTC - Alarm interrupt)
.equ OFFS_RTC_SEC, 0x14C					//Offset fuer IVT (RTC - Seconds interrupt)

// RTC-Register
.equ RTC_TSR, 0x4003D000					//Adresse des RTC_TSR
.equ RTC_TPR, 0x4003D004					//Adresse des RTC_TPR
.equ RTC_TAR, 0x4003D008					//Adresse des RTC_TAR
.equ RTC_CR,  0x4003D010					//Adresse des RTC_CR
.equ RTC_SR,  0x4003D014					//Adresse des RTC_SR
.equ RTC_IER, 0x4003D01C					//Adresse des RTC_IER

__BBREG SWR_RTC_CR, RTC_CR, 0 				//BitBanding-Adresse fuer das SWR-Bit im RTC_CR
__BBREG TCE_RTC_SR, RTC_SR, 4				//BitBanding-Adresse fuer das TCE-Bit im RTC_SR

.equ INIT_VAL_RTC_CR, 0x104 				//Konfiguration fuer RTC_CR setzen (Supervisor Access, Software Reset) 
.equ INIT_VAL_RTC_IER, 0x17					//Konfiguration fuer RTC_IER setzen (TIIE, TOIE, TAIE, TSIE)  				
.equ T_RTC_OSC, 75000000 					//Dauer fuer das Einschwingen --> ca. 9s 

.equ D_RTC_VAL, 86399						//Werte fuer RTC_TAR in Abhaengigkeit des Modus
.equ H_RTC_VAL, 3599

.equ D_RTC_VAL_PRESET, 86395				//Preset-Werte fuer RTC_TAR in Abhaengigkeit des Modus
.equ H_RTC_VAL_PRESET, 3595

.equ HOUR, 3600
.equ MIN, 60

.equ CHAR_R, 'r'
.equ CHAR_S, 's'
.equ CHAR_D, 'd'
.equ CHAR_H, 'h'
.equ CHAR_P, 'p'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	mov r1, #1
	ldr r0, =PIT_SIM_SCGC6					//Takt fuer PIT aktivieren 
	str r1, [r0]
	ldr r0, =RTC_SIM_SCGC6					//Takt fuer RTC aktivieren 
	str r1, [r0]
	
	ldr r0, =SCR_VTOR						//Interrupt-Vektor zu RTC - Alarm interrupt und RTC - Seconds interrupt setzen
	ldr r0, [r0]
	ldr r1, =isr_rtc_alarm
	str r1, [r0, #OFFS_RTC]
	ldr r1, =isr_rtc_time
	str r1, [r0, #OFFS_RTC_SEC]

	ldr r1, =NVIC_BITS_RTC
	ldr r0, =NVIC_ICPR2						//eventuell haengende (pending) Interrupts zu RTC - Alarm interrupt und RTC - Seconds interrupt loeschen (NVIC)
	str r1, [r0]
	ldr r0, =NVIC_ISER2						//Interrupt zu RTC - Alarm interrupt und RTC - Seconds interrupt aktivieren (NVIC)
	str r1, [r0]	
	
	mov r1, #0         
	mov r2, #1								//RTC Software Reset durchfuehren
	ldr r0, =SWR_RTC_CR
	str r2, [r0]
	str r1, [r0]
	
	mov r1, #INIT_VAL_RTC_CR				//Konfiguration fuer RTC-Modul setzen
	ldr r2, =RTC_CR
	str r1, [r2]

	ldr r3, =T_RTC_OSC						//Auf Einschwingen warten --> ca. 9s
loop_settle_osc:
	subs r3, r3, #1
	bne loop_settle_osc
	
	mov r1, #INIT_VAL_RTC_IER				//Konfiguration im RTC_IER setzen
	ldr r2, =RTC_IER
	str r1, [r2]
			
	ldr r1, =D_RTC_VAL
	ldr r0, =RTC_TAR
	str r1, [r0]
	
	mov r1, #0								//RTC ausschalten
	ldr r0, =TCE_RTC_SR
	str r1, [r0]
	
	mov r3, #0								//RTC_TSR und RTC_TPR zuruecksetzen
	ldr r0, =RTC_TPR
	str r3, [r0]
	ldr r0, =RTC_TSR
	str r3, [r0]
	
	mov r1, #1								//RTC einschalten
	ldr r0, =TCE_RTC_SR
	str r1, [r0]
		
	ldr r11, =flag_time_end
	ldr r10, =flag_rtc_time
	ldr r9, =mod
	mov r8, #1								//Anzeige-Modus --> 1 -> Anzeige eingeschaltet; 0 -> Anzeige ausgeschaltet

loop_rtc:
	bl uart_charPresent						//Wurde ein Zeichen im Terminal eingegeben?
	cmp r0, #0
	beq skip_input
	
	bl uart_getChar							//-> das eingebene Zeichen wird in r0 geladen
	
	cmp r0, #CHAR_D							//Ein 'd' wurde eingegeben -> setze Uhr-Modus --> 24h-Modus
	bne skip_d
	mov r0, #0								//RTC_TSR und RTC_TPR zuruecksetzen.
	bl set_time
	ldr r3, =RTC_TAR
	ldr r2, =D_RTC_VAL
	mov r1, #1
	str r2, [r3]
	strb r1, [r9]
	ldr r0, =str_d
	bl uart_putString
	b skip_input
skip_d:	

	cmp r0, #CHAR_H							//Ein 'h' wurde eingegeben -> setze Uhr-Modus --> 1h-Modus
	bne skip_h
	mov r0, #0								//RTC_TSR und RTC_TPR zuruecksetzen.
	bl set_time
	ldr r3, =RTC_TAR
	ldr r2, =H_RTC_VAL
	mov r1, #0
	str r2, [r3]
	strb r1, [r9]
	ldr r0, =str_h
	bl uart_putString
	b skip_input
skip_h:	

	cmp r0, #CHAR_S							//Ein 's' wurde eingegeben -> Setze Anzeige-Modus 
	bne skip_s				
	eor r8, r8, #1                 			//-> in r8 gespeichert --> 1 -> Anzeige eingeschaltet; 0 -> Anzeige ausgeschaltet 
    cmp r8, #0
    ite eq
    ldreq r0, =str_out_off
    ldrne r0, =str_out_on
    bl uart_putString
	b skip_input
skip_s:	
	
    cmp r0, #CHAR_R							//Ein 'r' wurde eingegeben -> Zeit zuruecksetzen 
	bne skip_r
	mov r0, #0              				//RTC_TSR und RTC_TPR zuruecksetzen.
    bl set_time
    ldr r0, =str_reset
    bl uart_putString
	b skip_input
skip_r:
	
	cmp r0, #CHAR_P							//Ein 'p' wurde eingegeben -> Setze Preset 
	bne skip_input
	ldrb r1, [r9]
	cmp r1, #0								//-> in Abhaengigkeit von Uhr-Modus wird der Preset-Wert gesetzt
	ite eq
	ldreq r1, =H_RTC_VAL_PRESET
	ldrne r1, =D_RTC_VAL_PRESET
	mov r0, r1              
    bl set_time								//Preset-Wert im RTC_TSR setzen und RTC_TPR zuruecksetzen 
    ldr r0, =str_preset
    bl uart_putString
skip_input:

	ldrb r0, [r11]
	cbz r0, skip_time_end					//Ist der Endzeitpunkt erreicht? --> RTC - Alarm interrupt
	mov r1, #0
	strb r1, [r11]
	ldr r0, =str_time_end
	bl uart_putString
skip_time_end:
	
	cmp r8, #0								//Pruefe ob Ausgabe erfolgen soll --> Anzeige ein-/ ausgeschaltet
	beq skip_output
	ldr r6, =RTC_TSR
	ldr r6, [r6]							//Aktueller Wert des RTC_TSR --> Aktuelle Zeit
	mov r5, #0
// Ausgabe der Stunden	
	ldrb r3, [r9]							
	cmp r3, #0
	beq skip_hour							//Entfaellt bei 1h-Modus 
	mov r7, #HOUR
	udiv r5, r6, r7							//Berechnung der vergangenen Stunden
	mov r0, r5
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	mov r0, #':'
    bl uart_putChar
// Ausgabe der Minuten	   
skip_hour:								
	mov r3, #MIN						
	mov r2, #HOUR
	mls r7, r2, r5, r6
	udiv r4, r7, r3							//Berechnung der vergangenen Minuten
	mov r0, r4
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	mov r0, #':'
    bl uart_putChar
// Ausgabe der Sekunden    
    mov r3, #MIN
    mls r0, r3, r4, r7						//Berechnung der vergangenen Sekunden
    cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
    
    mov r0, #'\n'
    bl uart_putChar
    
skip_output:	
	ldrb r0, [r10]							//Auf RTC Seconds Interrupt warten	
	cmp r0, #1
	bne skip_output
	
	mov r1, #0								//Ruecksetzen des Benutzerflags flag_rtc_time
	strb r1, [r10]
	
	b loop_rtc

// Unterprogramme
// ISR RTC-Alarm Interrupt  
.thumb_func
isr_rtc_alarm:
    push {lr}
    mov r1, #1
    ldr r0, =flag_time_end       			//Benutzerflag zur Anzeige des Endzeitpunktes setzen
    strb r1, [r0]
    
    mov r0, #0                          	//RTC_TSR und RTC_TPR zuruecksetzen
    bl set_time
    
    ldr r0, =RTC_TAR 						//RTC_TAR in Abhaengigkeit vom aktuellen Modus der Uhr setzen   
    ldr r3, =mod		                
    ldrb r2, [r3]
    cmp r2, #0
    ite ne
    ldrne r1, =D_RTC_VAL
    ldreq r1, =H_RTC_VAL 
    str r1, [r0]  
    pop {pc}

// ISR RTC-Seconds Interrupt    
.thumb_func
isr_rtc_time:
    ldr r3, =flag_rtc_time					//Setzen des Benutzerflags flag_rtc_time
    mov r0, #1
    strb r0, [r3]        
    bx lr

// UP zum Setzen der Uhrzeit
.thumb_func
set_time:
    mov r1, #0								//RTC abschalten
    ldr r3, =TCE_RTC_SR                
    str r1, [r3]
    
    ldr r2, =RTC_TPR						//RTC_TSR und RTC_TPR setzen
    str r1, [r2]
    ldr r2, =RTC_TSR                    
    str r0, [r2]
    
    mov r2, #1                         	 	//RTC einschalten
    str r2, [r3]
    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_rtc_time: .byte 0x0
mod: .byte 0x1
flag_time_end: .byte 0x0

str_d: .asciz "24-Stunden-Modus\n"
str_h: .asciz "1-Stunden-Modus\n"
str_reset: .asciz "Uhr zurueckgesetzt\n"
str_time_end: .asciz "Endzeitpunkt erreicht\n"
str_preset: .asciz "Uhr vorgestellt\n"
str_out_on: .asciz "Anzeige an\n"
str_out_off: .asciz "Anzeige aus\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6, 0x4004803C
.equ SIM_SCGC5, 0x40048038
__BBREG PIT_SIM_SCGC6, SIM_SCGC6, 23		//BitBanding-Adresse fuer das PIT-Bit im SIM_SCGC6-Register
__BBREG RTC_SIM_SCGC6, SIM_SCGC6, 29		//BitBanding-Adresse fuer das RTC-Bit im SIM_SCGC6-Register
__BBREG PORTA_SIM_SCGC5, SIM_SCGC5, 9		//BitBanding-Adresse fuer das PORTA-Bit im SIM_SCGC5-Register

.equ NVIC_ISER2, 0xE000E108					//Adresse des NVIC_ISER2
.equ NVIC_ICPR2, 0xE000E288					//Adresse des NVIC_ICPR2

.equ NVIC_BITS_RTC_PIT, 0x48				//Wert zum Setzen des Bits 3, 6 innerhalb der NVIC-Register

.equ SCR_VTOR, 0xE000ED08					//Adresse des Basisregisters der IVT
.equ OFFS_RTC_SEC, 0x14C					//Offset fuer IVT (RTC - Alarm interrupt)
.equ OFFS_PIT2, 0x158						//Offset fuer IVT (PIT2)

// Control-Reg fuer PIT2
.equ PIT_MCR, 0x40037000					//Adresse des PIT_MCR
.equ PIT_LDVAL2, 0x40037120					//Adresse des PIT_LDVAL2
.equ PIT_TCTRL2, 0x40037128					//Adresse des PIT_TCTRL2
.equ PIT_TFLG2, 0x4003712C					//Adresse des PIT_TFLG2

__BBREG TIF_PIT_TFLG2, PIT_TFLG2, 0			//BitBanding-Adresse fuer das TIF-Bit im PIT_TFLG2-Register
__BBREG TEN_PIT_TCTRL2, PIT_TCTRL2 , 0		//BitBanding-Adresse fuer das TEN-Bit im PIT_TCTRL2-Register

// Konfiguration fuer PIT2
.equ PIT_LDVAL2_100, 0x250000    			//100ms bei Clock-Freq 25 MHz ->  ((25000000 Takte pro Sekunde)-1/100)
.equ PIT_LDVAL2_200, 0x500000    			//200ms bei Clock-Freq 25 MHz ->  ((25000000 Takte pro Sekunde)-1/200)

// GPIOA Konstanten
.equ GPIOA_PDDR, 0x400FF014					//Adresse des GPIOA_PDDR
.equ GPIOA_PSOR, 0x400FF004					//Adresse des GPIOA_PSOR
.equ GPIOA_PCOR, 0x400FF008					//Adresse des GPIOA_PCOR
__BBREG GPIOA_PSOR_6, GPIOA_PSOR, 6			//BitBanding-Adresse fuer das Bit 6 im GPIOA_PSOR
__BBREG GPIOA_PCOR_6, GPIOA_PCOR, 6			//BitBanding-Adresse fuer das Bit 6 im GPIOA_PCOR
__BBREG GPIOA_PSOR_10, GPIOA_PSOR, 10		//BitBanding-Adresse fuer das Bit 10 im GPIOA_PSOR
__BBREG GPIOA_PCOR_10, GPIOA_PCOR, 10		//BitBanding-Adresse fuer das Bit 10 im GPIOA_PCOR

// Pin Control Register (PCR)
.equ PORTA_PCR6, 0x40049018                 //Adresse des PORTA_PCR6
.equ PORTA_PCR10, 0x40049028 				//Adresse des PORTA_PCR10
.equ PCR_MUX_LED_PTA6, 0x100
.equ PCR_BITMSK_PDDR, 0x440

// RTC-Register
.equ RTC_TSR, 0x4003D000					//Adresse des RTC_TSR
.equ RTC_TPR, 0x4003D004					//Adresse des RTC_TPR
.equ RTC_TAR, 0x4003D008					//Adresse des RTC_TAR
.equ RTC_CR,  0x4003D010					//Adresse des RTC_CR
.equ RTC_SR,  0x4003D014					//Adresse des RTC_SR
.equ RTC_IER, 0x4003D01C					//Adresse des RTC_IER

__BBREG SWR_RTC_CR, RTC_CR, 0 				//BitBanding-Adresse fuer das SWR-Bit im RTC_CR
__BBREG TCE_RTC_SR, RTC_SR, 4				//BitBanding-Adresse fuer das TCE-Bit im RTC_SR

.equ INIT_VAL_RTC_CR, 0x104 				//Konfiguration fuer RTC_CR setzen (Supervisor Access, Software Reset) 
.equ INIT_VAL_RTC_IER, 0x10					//Konfiguration fuer RTC_IER setzen (TIIE, TOIE, TAIE, TSIE)  				
.equ T_RTC_OSC, 75000000 					//Dauer fuer das Einschwingen --> ca. 9s 

.equ HOUR, 3600
.equ MIN, 60

.equ CHAR_D, 'd'							
.equ CHAR_T, 't'

// Max-Werte fuer sec, min, hour etc.
.equ SEC, 60            
.equ MIN, 60   	
.equ HOUR, 24  	
.equ DAY, 31  	
.equ MONTH, 13  	
.equ YEAR, 99   
  

.equ HEADER_DCF77, 0x20000 					//Header des DCF-Signal -> Bit 17 gesetzt --> MESZ



/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	mov r1, #1
	ldr r0, =PIT_SIM_SCGC6					//Takt fuer PIT aktivieren 
	str r1, [r0]
	ldr r0, =RTC_SIM_SCGC6					//Takt fuer RTC aktivieren 
	str r1, [r0]
	ldr r0, =PORTA_SIM_SCGC5				//Takt fuer PORTA aktivieren 
	str r1, [r0]
	
	ldr r0, =SCR_VTOR						//Interrupt-Vektor zu PIT2 und RTC - Seconds interrupt setzen
	ldr r0, [r0]
	ldr r1, =isr_pit2
	str r1, [r0, #OFFS_PIT2]
	ldr r1, =isr_rtc_time
	str r1, [r0, #OFFS_RTC_SEC]

	ldr r1, =NVIC_BITS_RTC_PIT
	ldr r0, =NVIC_ICPR2						//eventuell haengende (pending) Interrupts zu RTC - Alarm interrupt und RTC - Seconds interrupt loeschen (NVIC)
	str r1, [r0]
	ldr r0, =NVIC_ISER2						//Interrupt zu RTC - Alarm interrupt und RTC - Seconds interrupt aktivieren (NVIC)
	str r1, [r0]
	
	mov r2, #PCR_MUX_LED_PTA6				//Initialisierung der PCR fuer die LED4 und PTA6
	ldr r0, =PORTA_PCR10
	str r2, [r0]
	ldr r0, =PORTA_PCR6
	str r2, [r0]
	
	mov r1, #PCR_BITMSK_PDDR				//GPIO-Pins fuer LED4 und PTA6 werden als Output konfiguriert
	ldr r0, =GPIOA_PDDR
	ldr r2, [r0]
	orr r2, r2, r1 
	str r2, [r0]
	
	mov r0, #1								//LED4 anschalten + PTA6 auf 1 setzen
	ldr r1, =GPIOA_PCOR_10
	ldr r2, =GPIOA_PSOR_6
	str r0, [r1]
	str r0, [r2]
	
	ldr r0, =PIT_MCR						//alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	mov r1, #0
	str r1, [r0]
		
	ldr r0, =PIT_TCTRL2						//Interrupt zu PIT1 aktivieren
	mov r1, #2
	str r1, [r0]
	
	mov r1, #0         
	mov r2, #1								//RTC Software Reset durchfuehren
	ldr r0, =SWR_RTC_CR
	str r2, [r0]
	str r1, [r0]
	
	mov r1, #INIT_VAL_RTC_CR				//Konfiguration fuer RTC-Modul setzen
	ldr r2, =RTC_CR
	str r1, [r2]

	ldr r3, =T_RTC_OSC						//Auf Einschwingen warten --> ca. 9s
loop_settle_osc:
	subs r3, r3, #1
	bne loop_settle_osc
	
	mov r1, #INIT_VAL_RTC_IER				//Konfiguration im RTC_IER setzen
	ldr r2, =RTC_IER
	str r1, [r2]
	
	mov r3, #0
	ldr r0, =RTC_TPR
	str r3, [r0]
	ldr r0, =RTC_TSR
	str r3, [r0]
	
// Initiale Eingabe der Uhrzeit und des Datums --> Eingaben werden in date_time gespeichert 		
	ldr r4, =date_time
	
	ldr r0, =str_hour_input
	bl uart_putString
	mov r0, r4
	mov r1, #2
	bl input								//Eingabe der Stunden
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	ldr r0, =str_minute_input
	bl uart_putString
	mov r0, r4
	mov r1, #1
	bl input								//Eingabe der Minuten
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
			
	ldr r0, =str_day_input
	bl uart_putString
	mov r0, r4
	mov r1, #3
	bl input								//Eingabe der Tage
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	ldr r0, =str_month_input
	bl uart_putString
	mov r0, r4
	mov r1, #4
	bl input								//Eingabe der Monate
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	ldr r0, =str_year_input
	bl uart_putString
	mov r0, r4
	mov r1, #5
	bl input								//Eingabe der Jahre
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	mov r0, #'\n'
    bl uart_putChar
	
	mov r1, #1								//RTC einschalten
	ldr r0, =TCE_RTC_SR
	str r1, [r0]
	
	ldr r11, =dcf77_current_bit				//Aktuelle Position innerhalb des DCF77-Signals
	ldr r10, =flag_rtc_time
	ldr r9, =date_time
	ldr r6, =HEADER_DCF77
	
loop_dcf77:
	bl uart_charPresent						//Wurde ein Zeichen im Terminal eingegeben?
	cmp r0, #0
	beq skip_input
	
	bl uart_getChar							//-> das eingebene Zeichen wird in r0 geladen

	cmp r0, #CHAR_D							//Ein 'd' wurde eingegeben -> setze Datum
	bne skip_d

	ldr r0, =str_day_input
	bl uart_putString
	mov r0, r9
	mov r1, #3
	bl input
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	ldr r0, =str_month_input
	bl uart_putString
	mov r0, r9
	mov r1, #4
	bl input
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	ldr r0, =str_year_input
	bl uart_putString
	mov r0, r9
	mov r1, #5
	bl input
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	mov r0, #'\n'
    bl uart_putChar
	
	b skip_input
skip_d:

	cmp r0, #CHAR_T							//Ein 't' wurde eingegeben -> setze Uhrzeit
	bne skip_input
	
	ldr r0, =str_hour_input
	bl uart_putString
	mov r0, r9
	mov r1, #2
	bl input
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	ldr r0, =str_minute_input
	bl uart_putString
	mov r0, r9
	mov r1, #1
	bl input
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
			
	mov r0, #'\n'
    bl uart_putChar
      	
skip_input:	
// Konvertierung der aktuellen Uhrzeit in ein DCF77-Signal	--> da DCF77-Signal wird in den Registern r6, r7 u. r8 gespeichert.
	ldrb r0, [r11]    
    cmp r0, #0
    bne skip_cal_dcf77
	
    ldrb r0, [r9, #1]						//Lade Minute
    bl convert_dcf77         				//Minute konvertieren
    and r0, r0, #0x7F
    mov r5, r0             
    bl set_parity_bit               		//Paritaetsbit fuer Minute bestimmen
    lsl r0, r0, #7          				//Left-Shift des Paritaetsbit um 7 
    orr r7, r0, r5          
    
    ldrb r0, [r9, #2]        				//Lade Stunde
    bl convert_dcf77         				//Stunde konvertieren
    and r0, r0, #0x3F        
    mov r5, r0             
    bl set_parity_bit                		//Paritaetsbit fuer Stunde bestimmen
    lsl r0, r0, #6
    orr r5, r5, r0         
    lsl r5, r5, #8
    orr r7, r7, r5         					//"Uhrzeit-Anteil" des DCF77-Signals in r7 gespeichert
        
    lsl r7, r7, #1							//Anzeigen des "Beginn der Zeitinformation"		
    orr r7, r7, #1
    
    ldrb r0, [r9, #3]        				//Lade Tag
    bl convert_dcf77       					//Tag konvertieren
    and r0, r0, #0x3F        
    mov r8, r0               				
    
    mov r0, #0x80            				//Wochentag setzen
    orr r8, r8, r0
    
    ldrb r0, [r9, #4]       				//Lade Monat 
    bl convert_dcf77         				//Monat konvertieren
    and r0, r0, #0x1F        
    lsl r0, r0, #9
    orr r8, r8, r0           
    
    ldrb r0, [r9, #5]        				//Lade Jahr
    bl convert_dcf77          				//Jahr konvertieren
    and r0, r0, #0xFF        
    lsl r0, r0, #14
    orr r8, r8, r0           
    mov r0, r8               				//Paritaetsbit fuer Datum bestimmen
    bl set_parity_bit
    lsl r0, r0, #22
    orr r8, r8, r0							//"Datums-Anteil" des DCF77-Signals in r8 gespeichert
skip_cal_dcf77:
	
	ldrb r0, [r9, #2]
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	mov r0, #':'
    bl uart_putChar
    
    ldrb r0, [r9, #1]
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	mov r0, #':'
    bl uart_putChar
    
    ldrb r0, [r9]
	cmp r0, #10 							//r0 >= 10? 
    ite hs
	ldrhs r1, =uart_putByteBase10 			//Ausgabe ohne fuehrende Null
	ldrlo r1, =uart_putByte 				//Ausgabe mit fuehrender Null
	blx r1 									//UP aufrufen
	
	ldr r0, =str_clock
	bl uart_putString
	
	ldrb r0, [r11]            				//Position des aktuellen Bits laden ->	Abhaengig von der Pos. wird das aktuelle Bit ausgewaehlt
    mov r1, r6
    mov r4, r0 						
    cmp r0, #20
    itt hs
    movhs r1, r7
    subhs r4, r0, #20
    cmp r0, #36
    itt hs
    movhs r1, r8
    subhs r4, r0, #36
    
    lsr r1, r1, r4          				//Das auszugebende Bit an die LSB-Pos. schieben
    and r0, r1, #1         
    mov r5, r0  
    bl uart_putByteBase10   				//Ausgabe des Bits 
    
    mov r0, #'\n'
    bl uart_putChar
    
    ldrb r0, [r11]
    cmp r0, #59
    bhs skip_gpio
    
    ldr r0, =GPIOA_PCOR_6   				//LED4 ausschalten + PTA6 auf 0 setzen
    mov r1, #1
    str r1, [r0]
    ldr r0, =GPIOA_PSOR_10
    str r1, [r0]
    
    tst r5, #1
    ite eq             						//starten des PIT2 --> 1 -> Dauer bis zum Interrupt: 200 ms; 0 -> Dauer bis zum Interrupt: 100 ms
    ldreq r1, =PIT_LDVAL2_100
    ldrne r1, =PIT_LDVAL2_200

    ldr r0, =PIT_LDVAL2         			//Setze PIT_LDVAL2
    str r1, [r0]
    
    mov r2, #1                  			//PIT2 einschalten und ggf. wartende Interrupts zuruecksetzen
    ldr r0, =TEN_PIT_TCTRL2
    str r2, [r0]
    ldr r0, =TIF_PIT_TFLG2
    str r2, [r0]

skip_gpio:   
//Aktualisieren der Uhrzeit    
    mov r0, r9
    mov r1, #0								//Inkrementieren der Sekunden
    mov r2, #SEC								
    bl add_one_to_byte_date_time   
    teq r1, #1
    bne skip_add_one
    
    mov r1, #0								//Inkrementieren der Minuten --> bei Ueberlauf nach dem Inkrementieren der Sekunden
    mov r2, #MIN							
    bl add_one_to_byte_date_time   
    teq r1, #1
    bne skip_add_one
    
    mov r1, #0								//Inkrementieren der Stunden --> bei Ueberlauf nach dem Inkrementieren der Minuten
    mov r2, #HOUR
    bl add_one_to_byte_date_time   
    teq r1, #1
    bne skip_add_one   
    
    mov r1, #1								//Inkrementieren der Tage --> bei Ueberlauf nach dem Inkrementieren der Stunden
    mov r2, #DAY
    bl add_one_to_byte_date_time   
    teq r1, #1
    bne skip_add_one    
    
    mov r1, #1								//Inkrementieren der Monate --> bei Ueberlauf nach dem Inkrementieren der Tage
    mov r2, #MONTH
    bl add_one_to_byte_date_time   
    teq r1, #1
    bne skip_add_one   
    
    mov r1, #0								//Inkrementieren der Jahre --> bei Ueberlauf nach dem Inkrementieren der Monate
    mov r2, #YEAR
    bl add_one_to_byte_date_time   

skip_add_one:
	ldrb r0, [r10]							//Auf RTC Seconds Interrupt warten
	cmp r0, #1
	bne skip_add_one
	
	mov r1, #0								//Ruecksetzen des Benutzerflags flag_rtc_time
	strb r1, [r10]
    
    ldrb r0, [r11]           				//Lade Position des naechsten Bit fuer die Ausgabe
    add r0, r0, #1
    cmp r0, #60        						//Bit-Position > 60 -> Bit-Pos. zuruecksetzen 
    it hs
    movhs r0, #0
    strb r0, [r11]

	b loop_dcf77

// Unterprogramme
// ISR RTC-Seconds Interrupt    
.thumb_func
isr_rtc_time:
    ldr r3, =flag_rtc_time
    mov r0, #1
    strb r0, [r3]        
    bx lr

//PIT2 ISR
.thumb_func
isr_pit2:
    mov r1, #1
    ldr r3, =GPIOA_PCOR_10      			//LED4 einschalten + PTA6 auf 1 setzen
    ldr r2, =GPIOA_PSOR_6 
    str r1, [r3]      			
    str r1, [r2]
    
    ldr r0, =TEN_PIT_TCTRL2     			//PIT2 ausschalten.
    mov r2, #0
    str r2, [r0]

    ldr r0, =TIF_PIT_TFLG2      			//Interrupt-Flag zuruecksetzen
    str r1, [r0]
    bx lr   

//BCD-Konvertierung -> mittels double_dabble Algorithmus
.thumb_func
convert_dcf77:
	mov r3, #8         						//8 Durchgaenge, da zur Speicherung der Zeit-/Datumswerte jeweils max. 2 Ziffern zur dezimalen Darstellung benoetigt werden.
loop_algorithm_double_dabble:
    lsl r0, r0, #1      					//Left-Shift um 1 pro Durchgang
	subs r3, r3, #1    						
    beq leave_loop_algorithm_double_dabble

	mov r1, 0xF00       					//Sind die 4 Bits zur Darstellung der Einer > 4 --> addiere 3 auf das Ergebnisbyte 
	and r1, r0, r1
	lsr r1, r1, #8
	cmp r1, #4
	itt hi
	movhi r2, #0x300
	addhi r0, r0, r2
	mov r1, 0xF000      					//Sind die 4 Bits zur Darstellung der Zehner > 4 --> addiere 3 auf das Ergebnisbyte
    and r1, r0, r1
    lsr r1, r1, #12
    cmp r1, #4
    itt hi
    movhi r2, #0x3000
    addhi r0, r0, r2
    b loop_algorithm_double_dabble   
    
leave_loop_algorithm_double_dabble:
	lsr r0, r0, #8     						//Ergebnisbyte nach der Durchfuehrung des Algorithmus auf das niederwertigste Byte schieben 
	bx lr
	
//UP zur Aktualisierung der Uhrzeit und des Datums
.thumb_func
add_one_to_byte_date_time:
    ldrb r3, [r0]              				//aktuellen Zeit-/Datumswert in r3 laden. -> um 1 inkrementieren 
    add r3, r3, #1             
    
    cmp r3, r2                 				//Ueberlauf eingetreten? -> Zeit-/Datumswert auf Resetwert setzen
    itte hs
    movhs r3, r1              				
    movhs r1, #1
    movlo r1, #0
    
    strb r3, [r0], #1          				//neuen Zeit-/Datumswert im Array speichern + Adresse um 1 Byte inkrementieren
    bx lr    

// UP zur Berechnung der positiven Paritaet des Werts 
.thumb_func
set_parity_bit:
	mov r2, #0             
loop_set_parity_bit:
	tst r0, #1             					 
	it ne
	eorne r2, r2, #1       					//invertiere Paritaetsbit um gerade Paritaet zu erreichen
	lsr r0, r0, #1         					//Right-Shift bis r0 = 0  
	cmp r0, #0             					
	bne loop_set_parity_bit	
	mov r0, r2								//Paritaets-Bit wird in r0 zurueckgegeben
	bx lr

// UP zum Einlesen der Uhrzeit und des Datums
.thumb_func
input:
	push {r4, r5, lr}
		
	mov r4, r0
	mov r5, r1
	bl uart_getByteBase10
	strb r0, [r4, r5]
		
	pop {r4, r5, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_rtc_time: .byte 0x0
dcf77_current_bit: .byte 0x0
					
//				 sec  min  hour	day	 mon  year
date_time: .byte 0x0, 0x0, 0x0, 0x1, 0x1, 0x16

str_clock: .asciz " Uhr\t"
str_hour_input: .asciz "\nStunde eingeben (hh): "
str_minute_input: .asciz "\nMinute eingeben (mm): "
str_day_input: .asciz "\nTag eingeben (dd): "
str_month_input: .asciz "\nMonat eingeben (mm): "
str_year_input: .asciz "\nJahr eingeben (jj): " 
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6, 0x4004803C
.equ SIM_SCGC5, 0x40048038
__BBREG FTM0_SIM_SCGC6, SIM_SCGC6, 24		//BitBanding-Adresse fuer das FTM-Bit im SIM_SCGC6-Register
__BBREG PORTA_SIM_SCGC5, SIM_SCGC5, 9		//BitBanding-Adresse fuer das PORTA-Bit im SIM_SCGC5-Register

.equ NVIC_ISER1, 0xE000E104					//Adresse des NVIC_ISER1
.equ NVIC_ICPR1, 0xE000E284					//Adresse des NVIC_ICPR1

.equ NVIC_BITS_FTM0, 0x40000000				//Wert zum Setzen des Bits 30 innerhalb der NVIC-Register

.equ SCR_VTOR, 0xE000ED08					//Adresse des Basisregisters der IVT
.equ OFFS_FTM0, 0x138						//Offset fuer IVT (RTC - Alarm interrupt)

// GPIOA Konstanten
.equ GPIOA_PDDR, 0x400FF014					//Adresse des GPIOA_PDDR
.equ GPIOA_PSOR, 0x400FF004					//Adresse des GPIOA_PSOR
.equ GPIOA_PCOR, 0x400FF008					//Adresse des GPIOA_PCOR
__BBREG GPIOA_PSOR_10, GPIOA_PSOR, 10		//BitBanding-Adresse fuer das Bit 10 im GPIOA_PSOR
__BBREG GPIOA_PCOR_10, GPIOA_PCOR, 10		//BitBanding-Adresse fuer das Bit 10 im GPIOA_PCOR

// Pin Control Register (PCR)
.equ PORTA_PCR6, 0x40049018                 //Adresse des PORTA_PCR6
.equ PORTA_PCR10, 0x40049028 				//Adresse des PORTA_PCR10
//Init-Werte fuer LED4 und PTA6
.equ PCR_MUX_LED, 0x100
.equ PCR_MUX_PTA6, 0x300					//Konfiguration MUX -> Alternative 3 FTM0_CH3 fuer PTA6
.equ PCR_BITMSK_PDDR, 0x400

// FTM0-Register
.equ FTM0_SC, 0x40038000    				//Adresse des FTM0_SC 
.equ FTM0_CNT, 0x40038004    				//Adresse des FTM0_CNT
.equ FTM0_MOD, 0x40038008    				//Adresse des FTM0_MOD
.equ FTM0_CNTIN, 0x4003804C     			//Adresse des FTM0_CNTIN
.equ FTM0_STATUS, 0x40038050    			//Adresse des FTM0_STATUS
.equ FTM0_MODE, 0x40038054      			//Adresse des FTM0_MODE
.equ FTM0_SYNC, 0x40038058      			//Adresse des FTM0_SYNC
.equ FTM0_OUTINIT, 0x4003805C   			//Adresse des FTM0_OUTINIT
.equ FTM0_OUTMASK, 0x40038060   			//Adresse des FTM0_OUTMASK
.equ FTM0_COMBINE, 0x40038064   			//Adresse des FTM0_COMBINE
.equ FTM0_DEADTIME, 0x40038068  			//Adresse des FTM0_DEADTIME
.equ FTM0_EXTTRIG, 0x4003806C   			//Adresse des FTM0_EXTTRIG
.equ FTM0_POL, 0x40038070    				//Adresse des FTM0_POL
.equ FTM0_FMS, 0x40038074   				//Adresse des FTM0_FMS
.equ FTM0_FILTER, 0x40038078    			//Adresse des FTM0_FILTER
.equ FTM0_FLTCTRL, 0x4003807C   			//Adresse des FTM0_FLTCTRL
.equ FTM0_QDCTRL, 0x40038080    			//Adresse des FTM0_QDCTRL
.equ FTM0_CONF, 0x40038084      			//Adresse des FTM0_CONF
.equ FTM0_FLTPOL, 0x40038088    			//Adresse des FTM0_FLTPOL
.equ FTM0_SYNCONF, 0x4003808C   			//Adresse des FTM0_SYNCONF
.equ FTM0_INVCTRL, 0x40038090  				//Adresse des FTM0_INVCTRL
.equ FTM0_SWOCTRL, 0x40038094  				//Adresse des FTM0_SWOCTRL
.equ FTM0_PWMLOAD, 0x40038098  				//Adresse des FTM0_PWMLOAD
.equ FTM0_C3SC, 0x40038024     				//Adresse des FTM0_C3SC
.equ FTM0_C3V, 0x40038028      				//Adresse des FTM0_C3V

__BBREG TOF_FTM0_SC, FTM0_SC, 7  			//BitBanding-Adresse fuer das TOF-Bit im FTM0_SC-Register

__BBREG ELSA_FTM0_C3SC, FTM0_C3SC, 2  		//BitBanding-Adresse fuer das ELSA-Bit im FTM0_C3SC-Register
__BBREG CHF_FTM0_C3SC, FTM0_C3SC, 7  		//BitBanding-Adresse fuer das CHF-Bit im FTM0_C3SC-Register

.equ INIT_VAL_FTM0_SC, 0x48     			//Init-Wert für FTM0_SC (TOF: 1, "System Clock", "Prescale divide by 1")
.equ INIT_VAL_FTM0_MODE, 0x6    			//Konfiguration des FTM0-Moduls (FTMEN: 0, INIT: 1, WPDIS: 1)
.equ INIT_VAL_FTM0_MOD, 24999   			//Konfiguration der Grundschwingung -> 1kHz
.equ INIT_VAL_FTM0_C3SC, 0x68   			//Konfiguration für CH3 (MSB: 1; MSA: X, ELSB: 1, ELSA: 0; CH_Int on)

.equ CHAR_PLUS, '+'
.equ CHAR_MINUS, '-'

// Pulsweiten fuer das PWM-Signal -> Berechnung gem. Formel aus V7-3
.equ FTM0_VAL_PWM05, 1250
.equ FTM0_VAL_PWM15, 3750
.equ FTM0_VAL_PWM25, 6250
.equ FTM0_VAL_PWM35, 8750
.equ FTM0_VAL_PWM45, 11250
.equ FTM0_VAL_PWM55, 13750
.equ FTM0_VAL_PWM65, 16250
.equ FTM0_VAL_PWM75, 18750
.equ FTM0_VAL_PWM85, 21250
.equ FTM0_VAL_PWM95, 23750  


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	mov r1, #1
	ldr r0, =FTM0_SIM_SCGC6					//Takt fuer FTM0 aktivieren 
	str r1, [r0]
	ldr r0, =PORTA_SIM_SCGC5				//Takt fuer PORTA aktivieren 
	str r1, [r0]
	
	mov r2, #PCR_MUX_LED					//Initialisierung der PCR fuer die LED4 und PTA6
	mov r3, #PCR_MUX_PTA6
	ldr r0, =PORTA_PCR10
	str r2, [r0]
	ldr r0, =PORTA_PCR6
	str r3, [r0]
	
	mov r1, #PCR_BITMSK_PDDR				//GPIO-Pins fuer LED4 als Output konfiguriert
	ldr r0, =GPIOA_PDDR
	ldr r2, [r0]
	orr r2, r2, r1 
	str r2, [r0]
	
	mov r0, #1								//LED4 ausschalten
	ldr r1, =GPIOA_PSOR_10
	str r0, [r1]
	
	ldr r0, =SCR_VTOR						//Interrupt-Vektor zu FTM0 setzen
	ldr r0, [r0]
	ldr r1, =isr_ftm0
	str r1, [r0, #OFFS_FTM0]

	ldr r1, =NVIC_BITS_FTM0
	ldr r0, =NVIC_ICPR1						//eventuell haengende (pending) Interrupts zu RTC - Alarm interrupt und RTC - Seconds interrupt loeschen (NVIC)
	str r1, [r0]
	ldr r0, =NVIC_ISER1						//Interrupt zu RTC - Alarm interrupt und RTC - Seconds interrupt aktivieren (NVIC)
	str r1, [r0]
	
    ldr r2, =INIT_VAL_FTM0_MOD				//FTM0_MOD + FTM0_MODE initialisieren + 1kHz Grundschwinung einstellen
    mov r1, #INIT_VAL_FTM0_MODE
    ldr r0, =FTM0_MODE 
    str r1, [r0]
    ldr r0, =FTM0_MOD           			
    strh r2, [r0]
	
	mov r1, #INIT_VAL_FTM0_C3SC     		//FTM0_C3SC Konfiguration setzen + Initialisiere auf 55% Pulsweite
	ldr r2, =FTM0_VAL_PWM55
	ldr r0, =FTM0_C3SC         
    str r1, [r0]
    ldr r0, =FTM0_C3V          
    strh r2, [r0]
    
    ldr r0, =FTM0_SC            			//FTM0_SC konfigurieren
    mov r1, #INIT_VAL_FTM0_SC
    str r1, [r0]
    
    ldr r0, =str_prompt_sign
	bl uart_putString
    
    ldr r10, =flag_ftm0						//Laden der Adresse des Benutzerflags flag_ftm0
    
loop_ftm0:
	bl uart_charPresent						//Wurde ein Zeichen im Terminal eingegeben?
	cmp r0, #0
	beq ftm0_wait_for_interrupt
	
	bl uart_getChar							//-> das eingebene Zeichen wird in r0 geladen
	mov r4, r0
	
	cmp r0, #CHAR_PLUS						//Ein '+' wurde eingegeben 
	bne skip_plus
	mov r1, #2
	ldr r0, =set_pol
	strb r1, [r0]
	b output_prompt_sign
skip_plus:

	cmp r0, #CHAR_MINUS						//Ein '-' wurde eingegeben 
	bne skip_minus
	mov r1, #1
	ldr r0, =set_pol
	strb r1, [r0]
	b output_prompt_sign
skip_minus:
	
	cmp r4, #0x30							//Wurde eine Zahl eingegeben?
	blo ftm0_wait_for_interrupt
	
	cmp r4, #0x39							//Zahl > 9 --> Abbruch
    bhi ftm0_wait_for_interrupt
	
	and r0, r4, #0xF          				
	      
    ldr r3, =width_PWM
    mov r2, #2
    smlabb r0, r0, r2, r3
    ldrh r1, [r0]
    ldr r2, =set_PWM
    strh r1, [r2]
    
output_prompt_sign:
	mov r0, r4
	bl uart_putChar
	ldr r0, =str_prompt_sign
	bl uart_putString
	
ftm0_wait_for_interrupt:
	ldrb r0, [r10]							//Auf FTM0 Interrupt warten
	cmp r0, #1
	bne ftm0_wait_for_interrupt
	
	mov r1, #0								//Ruecksetzen des Benutzerflags flag_ftm0
	strb r1, [r10]
    
    b loop_ftm0

// Unterprogramme
// ISR FTM0
.thumb_func
isr_ftm0:
    ldr r3, =TOF_FTM0_SC        			//TOF ueberpruefen
    ldr r0, [r3]
    cmp r0, #1
    bne skip_overflow_int           		//liegt Overflow-Int vor?
      
    mov r0, #0								//TOF zuruecksetzen
    str r0, [r3]                			

    ldr r3, =ELSA_FTM0_C3SC    				//Pruefen, ob eine falling edge/rising edge vorliegt -> zur Ueberpruefung z.B. im Debug-Modus 
    ldr r2, [r3]							//-> in Abhängig von der Polarität und Pulsweite ist eine "Dimmung" der LED zu beobachten.
    cmp r2, #0
    ite eq
    ldreq r3, =GPIOA_PSOR_10    			//falling edge -> LED ausschalten
    ldrne r3, =GPIOA_PCOR_10    			//rising edge -> LED anschalten
    mov r1, #1
    str r1, [r3]
    
    ldr r2, =set_pol     					//Pruefen, ob Polaritaet angepasst werden soll -> falls ja -> setzen der Polaritaet Abhaengig von der Eingabe '+' bzw. '-'
    ldrb r1, [r2]
    subs r1, r1, #1             			
    bmi skip_overflow_int           		
    ldr r3, =ELSA_FTM0_C3SC     			
    str r1, [r3]   
    strb r0, [r2]               			//Ruecksetzen 
        
skip_overflow_int:
    ldr r3, =CHF_FTM0_C3SC      			//CHF ueberpruefen
    ldr r0, [r3]
    cmp r0, #1
    bne skip_channel_int                 	//liegt Channel-Int vor?
            
    mov r0, #0                  			//CHF zuruecksetzen
    str r0, [r3]
    
    ldr r3, =ELSA_FTM0_C3SC
    ldr r2, [r3]
    cmp r2, #0
    ite eq
    ldreq r3, =GPIOA_PCOR_10    			//rising edge -> LED anschalten
    ldrne r3, =GPIOA_PSOR_10    			//falling edge -> LED ausschalten
    mov r1, #1
    str r1, [r3]
    
    ldr r2, =set_PWM    					//Pruefen, ob Pulsweite angepasst werden soll -> falls ja -> setzen der Pulsweite Abhaengig von der Eingabe '0' bis '9'
    ldrh r1, [r2]
    cmp r1, #0
    beq skip_channel_int           			
    ldr r3, =FTM0_C3V           			
    str r1, [r3]
    strh r0, [r2]

skip_channel_int:
    mov r1, #1								//Setzen des Benutzerflags flag_ftm0	
    ldr r0, =flag_ftm0
    strb r1, [r0]
    
    bx lr
    
/*** Datenbereich (ab 0x20000000) ***/
.data
set_PWM: .hword 0x0
set_pol: .byte 0x0
flag_ftm0: .byte 0x0

//Array zur Berechnung der Pulsweite in Abhaengigkeit von der Eingabe
width_PWM: .hword FTM0_VAL_PWM05, FTM0_VAL_PWM15, FTM0_VAL_PWM25, FTM0_VAL_PWM35, FTM0_VAL_PWM45, FTM0_VAL_PWM55, FTM0_VAL_PWM65, FTM0_VAL_PWM75, FTM0_VAL_PWM85, FTM0_VAL_PWM95

str_prompt_sign: .asciz "\n> "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


// Konstanten
.equ COUNTER, 0x10
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init
	
main_loop:
	mov r4, #COUNTER			// Zähler laden
	ldr r5, =bytearray			// Adresse des Arrays
	ldr r0, =string_eingabe 	// pointer laden
	bl uart_putString			// String ausgeben
	
loop_eingabe:
	ldr r0, =string_prompt		// Zeiger auslesen
	bl uart_putString
	bl uart_getByte				// ein Byte einlesen
	strb r0, [r5], #1			// Adresse von r5 auslesen und danach erhöhen
	bl uart_putByte				// Byte ausgeben
	subs r4, r4, #1				// decrement counter 
	bne loop_eingabe			// So lange Zero Flag nicht gesetzt springe zur loop_eingabe
	
// Maximum der Eingabe bestimmen


	ldr r0, =string_durchsuchen_start	// Zeiger auf String laden
	bl uart_putString
	mov r9, #0							// Maximum mit null initialisieren
	mov r4, #COUNTER
	
						
	
	// Timerticks für Laufzeitbestimmung holen und in r6 ablegen
	bl pit3_getval						// Anzahl Zyklen zum initialisieren => 0x6. Das ist aber ein gleichbleibender Fehler und wird bei der Berechnung nicht berücksichtigt					
	mov r6, r0							// Counter_Wert sichern
	
	/*
	// Bestimmung der benötigten Taktzyklen von pit3_getval
	bl pit3_init						// Initialzustand 0xffff ffff
	bl pit3_getval
	mov r1, 0xf							 
	ANDS r0,r0,r1						// Filter. Nur die 1. Stelle ist Interessant => r0 & 0xf
	subs r10, r1,r0						// Anzahl Zyklen => 0xf-r0 
	*/
	

loop_maximum:
	ldrb r0, [r5, #-1]!				// Byte aus dem Array holen, vorher Adresse in R5 dekrementieren
	cmp r0, r9						// mit bisherigem Maximum vergleichen
	it hi							// if high then
	movhi r9,r0						// Neues Maximum 
	subs r4,r4, #1
	bne loop_maximum

/*
// Andere Möglichkeit das Maximum zu bestimmen. So werden anhand der Taktzyklen zeitliche Unterschiede bemerkt 
loop_maximum:
	ldrb r0, [r5, #-1]!				// Byte aus dem Array holen, vorher Adresse in R5 dekrementieren
	cmp r0, r9						// mit bisherigem Maximum vergleichen
	bhi higher
	subs r4,r4, #1
	bne loop_maximum
	b maximum_finished
higher:
	mov r9,r0						// Neues Maximum 
	subs r4,r4, #1
	bne loop_maximum

maximum_finished:
*/	

	// Notwendige Laufzeit zur Max Bestimmung berechnen
	bl pit3_getval
	subs r7,r6,r0					// Differenz => Alter Timerwert Minus aktueller Timerwert

	// Maximum speichern
	ldr r0, =maximum				// Adresse des Speichers fuer Maximum laden		
	strb r9, [r0]					// das Maximum speichern
	
	// Ausgabe auf der Konsole
	ldr r0, =string_durchsuchen_ende
	bl uart_putString				// String ausgeben
	ldr r0, =string_ergebnis_maximum
	bl uart_putString
	mov r0,r9 						// in r9 steht das Maximum. R0 als Übergabeparameter (Konvention)
	bl uart_putByte					// Maximum ausgeben
	
	//Laufzeit ausgeben
	ldr r0, =string_laufzeit	
	bl uart_putString
	mov r0,r7						// In r7 steht die Differenz des Timers
	bl uart_putInt16

	/*
	Auswertung Maximumberechnung:
	Es lässt sich unabhängig der Lage des Maximums im Datensatz kein Unterschied der Laufzeit feststellen.
	Dies empfand ich als seltsam, da theoretisch weniger Registerzugriffe benötigt werden je früher 
	das Maximum sich im Register befindet.
	Deshalb wurde eine Alternativ-Implementierung vorgenommen mit "normalen" Verzweigungen und Sprungbefehlen.  
	Hiermit lassen sich Laufzeitunterschiede erkennen. Diese ist auskommentiert im Quellcode hinterlegt. 
	
	Todo: Eine Untersuchung in der Doku, weshalb mittels "it hi" keine Laufzeitunterschiede festzustellen sind.
	*/	

	b main_loop					// main_loop eingeführt, da uart_init und pit3_init nicht jedes mal neu ausgeführt werden müssen!	
	

end:
	b end
/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
.rept COUNTER
.byte 0x00
.endr
maximum: .byte 0x0
string_prompt: .asciz "\n>0x"
string_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben!\n"
string_durchsuchen_start:.asciz "\nDurchsuchen gestartet \n"
string_durchsuchen_ende: .asciz "Durchsuchen beendet\n"
string_ergebnis_maximum: .asciz "Maximum: "
string_laufzeit: .asciz "\nLaufzeit: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ BIT_BAND_ALIAS, 0x22000000
.equ COUNTER, 0x2
.equ COUNTER2, 0x3

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	//0x40047000
main_loop:
	//mov r4, #COUNTER
	ldr r5, =hexarray
	
//eingabe:
// Erste Zahl einlesen und ausgeben
	ldr r0, =string_erste_eingabe	// Pointer laden
	bl uart_putString				// String ausgeben
	bl uart_getByte					// Einlesen
	cmp r0,#31						// Mit Maximalem Wert vergleichen
	bhi eingabe_korrigieren1		// Eingabe war zu hoch
	b eingabe_ok1 					// Eingabe war i.o.
eingabe_korrigieren1:	
	ANDS r0,r0,#0x1f				// Filter für 5 Bit-Stellen
eingabe_ok1:
	strb r0, [r5], #1				// Ins Array ablegen
	bl uart_putByte					// Eingebene Zahl ausgeben
	
// Zweite Zahl einlesen und ausgeben	
	ldr r0, =string_zweite_eingabe	// Pointer laden
	bl uart_putString				// String ausgeben
	bl uart_getByte					// Einlesen
	cmp r0,#31
	bhi eingabe_korrigieren2		// Eingabe war zu hoch 
	b eingabe_ok2					// Eingabe war i.o.
eingabe_korrigieren2:
	ANDS r0,r0,#0x1f				// Filter für 5 Bit-Stellen
eingabe_ok2:
	strb r0, [r5], #1				// Ins Array ablegen
	bl uart_putByte					// Eingebene Zahl ausgeben

	
	ldr r0, =string_trennung1		// String für bessere Übersicht... 
	bl uart_putString				// ...auf dem Terminal ausgeben

// TEIL_AUFGABE B
	// Bit Zurücksetzen
	// Konsolen Ausgabe
    ldr r0, =string_vor_zurücksetzen
    bl uart_putString
    ldr r4, =variable				// Adresse von variable holen
	ldr r5, [r4]					// Inhalt von Variable holen	
    movs r0, r5						// Inhalt in r0 kopieren, da r0 Übergabeparameter
    bl uart_putInt32 				// Alten Wert ausgeben

    // Eigentliche Operation
	ldr r8, =hexarray				// Adresse vom 1. eingebenem Wert 
    ldrb r6, [r8]					// Inhalt vom 1. eingegebenem Wert
    mov r7,#1						
	lsls r7,r7,r6					// shift um den eingebenen Wert
	bics r5,r5,r7					// r5 = r5 AND not r7 => r7 wird invertiert => Die Stelle, die zurückgesetzt werden soll ist 0, der Rest 1. Danach &-Verknüpfung
    str r5, [r4]					// Zurückgesetztes Bit im Speicher ablegen 
    
    // Konsolen Ausgabe
    ldr r0, =string_nach_zurücksetzen
    bl uart_putString
    movs r0, r5
    bl uart_putInt32				// Neuen Wert ausgeben
    
    
    // Bit setzen  
	// Konsolen Ausgabe
    ldr r0, =string_vor_setzen		
    bl uart_putString 
	ldr r4, =variable
	ldr r5, [r4]
	mov r0, r5
    bl uart_putInt32 				// Alten Wert ausgeben
	
	// Eigentliche Operation
	ldr r8, =hexarray+1				// Adresse vom zweiten eingegebenem Wert
    ldrb r6, [r8]					// Zweiter eingegebener Wert
    mov r7,#1
	lsls r7,r7,r6					// Left-shift um den eingegebenem Wert
	orrs r5,r5,r7					// Bit an der entsprechenden Stelle setzen mittels ODER-Verknüpfung
	str r5, [r4]					// Neuen Wert Im Speicher ablegen (variable)

	// Konsolen Ausgabe
	ldr r0, =string_nach_setzen
    bl uart_putString
    movs r0, r5						
    bl uart_putInt32				// Neuen Wert ausgeben
    
    // Trennung auf Konsole
    ldr r0, =string_trennung2		// String für bessere Übersicht...
    bl uart_putString				// ...auf dem Terminal ausgeben
    
// TEIL_AUFGABE C
    // Bit Zurücksetzen
    // Konsolen Ausgabe
    ldr r0, =string_vor_zurücksetzen_bit_band
    bl uart_putString
    ldr r1, =variable2
    ldr r0, [r1]
    bl uart_putInt32
    
    // Eigentliche Operation
	mov r4, BIT_BAND_ALIAS
	movw r5, 0x200					// 0x200, da Zielbereich 0x20000010
	ldr r6, =hexarray
	ldrb r7, [r6]					// Erste eingegebene Zahl
	movs r6,#0x4					// Faktor für Multiplikation
	muls r7, r7, r6					// eingebene_Zahl * 4
	adds r5, r5, r7 				// 0x200 + eingebene_Zahl*4
	adds r4, r4, r5					// 0x22000000 + 0x200 + eingebene_Zahl * 4
	mov r5, #0x0					// Clear Bit => 0x0
	str r5, [r4]					// 0x0 an die berechnete Adresse
	
	// Konsolen Ausgabe
	ldr r0, =string_nach_zurücksetzen_bit_band
    bl uart_putString
    ldr r1, =variable2
    ldr r0, [r1]
    bl uart_putInt32
    
    // Bit setzen
    // Konsolen Ausgabe
	ldr r0, =string_vor_setzen_bit_band
    bl uart_putString
    ldr r1, =variable2
    ldr r0, [r1]
    bl uart_putInt32
    
    // Eigentliche Operation
	mov r4, BIT_BAND_ALIAS
	movw r5, 0x200					// 0x200, da Zielbereich 0x20000010
	ldr r6, =hexarray+1
	ldrb r7, [r6]					// Zweite eingegebene Zahl
	movs r6,#0x4					// Faktor für Multiplikation
	muls r7, r7, r6					// eingebene_Zahl * 4
	adds r5, r5, r7 				// 0x200 + eingebene_Zahl*4
	adds r4, r4, r5					// 0x22000000 + 0x200 + eingebene_Zahl * 4
	mov r5, #0x1					// Set Bit => 0x1
	str r5, [r4]					// 0x1 an die berechnete Adresse
	
	// Konsolen Ausgabe
	ldr r0, =string_nach_setzen_bit_band
    bl uart_putString
    ldr r1, =variable2
    ldr r0, [r1]
    bl uart_putInt32
    
    // Ende
    ldr r0, =string_ende
    bl uart_putString
	
end:
	b main_loop

/*** Datenbereich (ab 0x20000000) ***/
.data
variable: .long 0xffffffff
freespace_:
.rept COUNTER2
.long 0x00000000
.endr
variable2: .long 0xffffffff
hexarray:
.rept COUNTER
.byte 0x00
.endr
string_erste_eingabe: .asciz "\nNummer des 0 - Bits: 0x"
string_zweite_eingabe: .asciz "\nNummer des 1 - Bits: 0x"
string_vor_zurücksetzen: .asciz "\nWert bevor Bit zurueckgesetzt: 0x "
string_nach_zurücksetzen: .asciz "\nWert nachdem Bit zurueckgesetzt: 0x"
string_vor_setzen: .asciz "\nWert bevor Bit gesetzt: 0x "
string_nach_setzen: .asciz "\nWert nachdem Bit gesetzt: 0x "
string_vor_zurücksetzen_bit_band: .asciz "\nWert bevor Bit mittels Bit Banding zurueckgesetzt: 0x "
string_nach_zurücksetzen_bit_band: .asciz "\nWert nachdem Bit mittels Bit Banding zurueckgesetzt: 0x"
string_vor_setzen_bit_band: .asciz "\nWert bevor mittels Bit Banding Bit gesetzt: 0x "
string_nach_setzen_bit_band: .asciz "\nWert nachdem mittels Bit Banding Bit gesetzt: 0x "
string_trennung1: .asciz "\n####################    NORMAL     ####################"
string_trennung2: .asciz "\n#################### BIT BANDING ####################"
string_ende: .asciz "\n####################      ENDE       ####################"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ COUNTER, 0x4

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init					
	
main_loop:
	// String v1 ausgeben
	ldr r0, =string_v1				// Pointer laden
	bl uart_putString				// String ausgeben
	
	// Vector v1 Eingabe Subroutine	
	ldr r0, =vector1				// Übergabeparameter in r0
	bl vektor_eingabe
	
	// Eingegebenen Vektor v1 ausgeben
	ldr r4, =vector1
	ldr r0, [r4]
	bl uart_putInt32
	
	// String v2 ausgeben
	ldr r0, =string_v2				// Pointer laden
	bl uart_putString				// String ausgeben
	
	// Vector v2 Eingabe Subroutine
	ldr r0, =vector2				// Übergabeparameter in r0
	bl vektor_eingabe
	
	// Eingegebenen Vektor v2 ausgeben
	ldr r5, =vector2
	ldr r0, [r5]
	bl uart_putInt32
	

	// Timerticks für Laufzeitbestimmung holen und in r9 ablegen	
	bl pit3_getval	
	mov r9, r0
// Teilaufgabe b	
	ldr r6, =vector_min
	ldr r7, =vector_max
	ldrb r0, [r4]				// Inhalt von vector1
	ldrb r1, [r5]				// Inhalt von vector2
	mov r8, COUNTER
compare_vector_loop:
	cmp r0,r1					// Beiden eingegebenen Werte vergleichen
	bhi v1_größer
v2_größer:		
	strb r0, [r6], #0x1			// größeren Wert in Min ablegen und von Min-Vektor um 1 erhöhen
	strb r1, [r7], #0x1			// größeren Wert in Max ablegen und von Max-Vektor um 1 erhöhen
	b compare_vector_pre_end
v1_größer:		
	strb r0, [r7], #0x1			// größeren Wert in Max ablegen und von Max-Vektor um 1 erhöhen
	strb r1, [r6], #0x1			// größeren Wert in Min ablegen und von Min-Vektor um 1 erhöhen
compare_vector_pre_end:	
	adds r4,r4,#0x1				// Adresse von vector1 erhöhen 
	adds r5,r5,#0x1				// Adresse von vector2 erhöhen
	ldrb r0, [r4]				// => nächster eingegebener v1-Wert
	ldrb r1, [r5]				// => nächster eingegebener v2-Wert
	subs r8,r8,#0x1
	bne compare_vector_loop
	// Min_Max Bestimmung ENDE
	
	// Notwendige Laufzeit zur Min_Max Bestimmung berechnen
	bl pit3_getval
	subs r9,r9,r0

	// Konsolenausgabe: ohne DSP-Befehle
	ldr r0, =string_ohne_dsp
	bl uart_putString
	
	// Min-Vector ausgeben
	ldr r0, =string_min
	bl uart_putString
	ldr r6, =vector_min
	ldr r0, [r6]
	bl uart_putInt32

	// Max-Vector ausgeben
	ldr r0, =string_max
	bl uart_putString
	ldr r7, =vector_max
	ldr r0, [r7]
	bl uart_putInt32
	
	//Laufzeit ausgeben
	ldr r0, =string_laufzeit	
	bl uart_putString
	mov r0,r9						// In r9 steht die Differenz des Timers
	bl uart_putInt16
	
	bl pit3_getval	
	mov r9, r0
// Teilaufgabe c
	// Inhalt von vector 1 und Vector 2 holen
	ldr r4,=vector1
	ldr r5, =vector2
	ldr r6, [r4]				
	ldr r7, [r5]
	//  Min_Max Bestimmung 
	usub8 r10, r6, r7			// damit die APSR GE flags gesetzt werden
	sel r10, r6, r7				// Wertet die GE flags aus. Wenn GE[x] Flag gesetzt, kommt in r10 der Wert vom 1. Operanden. Ansonsten vom 2. => Maximum
	sel r11, r7 ,r6				// Wertet die GE flags aus. Wenn GE[x] Flag gesetzt, kommt in r11 der Wert vom 1. Operanden. Ansonsten vom 2.  => Minimum
	
	// Im Speicher ablegen
	ldr r4, =vector_min_dsp
	str r11, [r4]
	ldr r4, =vector_max_dsp
	str r10, [r4]
	
	// Notwendige Laufzeit zur Min_Max Bestimmung berechnen
	bl pit3_getval
	subs r9,r9,r0
	
	// Konsolenausgabe: mit DSP-Befehlen	
	ldr r0, =string_mit_dsp
	bl uart_putString
	
	// Min-Vector ausgeben
	ldr r0, =string_min
	bl uart_putString
	ldr r6, =vector_min
	ldr r0, [r6]
	bl uart_putInt32

	// Max-Vector ausgeben
	ldr r0, =string_max
	bl uart_putString
	ldr r7, =vector_max
	ldr r0, [r7]
	bl uart_putInt32
	
	//Laufzeit ausgeben
	ldr r0, =string_laufzeit	
	bl uart_putString
	mov r0,r9						// In r9 steht die Differenz des Timers
	bl uart_putInt16
	 
	/* 
	
	Laufzeitbestimmung Ergebnisvergleich:
	Als Werte für die Vektoren wurden die Beispielwerte aus der Aufgabenstellung herangezogen.
	Laufzeit ohne DSP-Befehle: 0049
	Laufzeit mit DSP-Befehlen: 001C
	
	Mit DSP-Befehlen ist es, wie zu erwarten, deutlich schneller. Grund hierfür sind weniger Speicherzugriffe, 
	geringere Anzahl an Befehlsausführungen und die parallele Abarbeitung mit einer Instruction.
	Zusätzlich variiert die Laufzeit ohne DSP-Befehle abhängig von den eingegebenen Werten. 
	Dies ist mit DSP-Befehlen nicht der Fall. 
	 
	Anmerkung: Bei der Laufzeitbestimmung mittels DSP-Befehlen wurde das Ablegen der Werte in den Speicher mitberücksichtigt, 
	da dies bei den Befehlen ohne DSP auch der Fall ist. 
	Ansonsten fällt die Laufzeit für die reine Min_Max Bestimmung noch geringer aus mit: 0015
	
	Fazit: Die Min_Max Bestimmung mittels DSP ist nicht nur schneller, sondern auch deutlich komfortabler beim 
	Programmieren.
	
	*/
	
	 
	 
	// ENDE
	b main_loop

	// Unterprogramm für die Eingabe
.thumb_func		
vektor_eingabe: 
	push {r4-r5, lr}			// hier nur 1x sichern, da lr von uart_getByte verändert wird. r4-r5 sichern, da es innerhalb der Subroutine verändert wird
	mov r4, r0
	mov r5, COUNTER
vektor_eingabe_loop:
	bl uart_getByte				// Einlesen
	strb r0, [r4], #1			// Adresse von r4 auslesen und danach erhoehen
	subs r5, r5, #1				// decrement counter 
	bne vektor_eingabe_loop		
	pop {r4-r5, pc } 			// r4-r5 und lr wieder holen, zurückspringen, da lr in pc geladen wird

	

/*** Datenbereich (ab 0x20000000) ***/
.data

vector1:
.rept COUNTER
.byte 0x00
.endr
vector2:
.rept COUNTER
.byte 0x00
.endr
vector_min:
.rept COUNTER
.byte 0x00
.endr
vector_max:
.rept COUNTER
.byte 0x00
.endr
vector_min_dsp:
.rept COUNTER
.byte 0x00
.endr
vector_max_dsp:
.rept COUNTER
.byte 0x00
.endr

string_v1: .asciz "\nv1: 0x"
string_v2: .asciz "\nv2: 0x"
string_min: .asciz "\nmin: 0x"
string_max: .asciz "\nmax: 0x"
string_ohne_dsp: .asciz "\nohne DSP - Befehle :"
string_mit_dsp: .asciz "\nmit DSP - Befehlen :"
string_laufzeit: .asciz "\nLaufzeit: "


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ COUNTER_MATRIX, 0x10
.equ COUNTER_OUTER_LOOP, 0x4
.equ COUNTER_INNER_LOOP, 0x2
.equ COUNTER_SUMME, 0x08
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
/*
Die Brechnung des unten implementierten Programms mit Hilfe von DSP-Befehlen lässt sich mit der halben Anzahl an 
Multiplikationen durchführen verglichen mit einer Implementierung ohne DSP-Befehlen!

Eine Alternativ-Implementierung ohne "SMLAD" könnte folgenermaßen aussehen: Eine Modifikation an der innersten 
Schleife müsste durchgeführt werden:
	mov r3, r3,#0x4
multiply_loop:	
	ldrsh r7, [r4],#0x2			
	ldrsh r8, [r5],#0x2
	mul r0, r7,r8
	add r11,r11,r0
	subs r3,r3,#0x1				
	bne multiply_loop
Dadurch, dass so jedes Half-Word geladen werden muss, werden auch die Schleifendurchläufe insgesamt
doppelt an der Zahl.
Zusätzlich lässt sich bei jedem Schleifendurchlauf der innersten Schleife ein zusätzlicher "add" Befehl einsparen.

Schleifendurchläufe ohne DSP: 4*4*4 => 64
Schleifendurchläufe mit DSP: 2*4*4 => 32

*/	
	ldr r4,=Matrix_M
	ldr r5,=Matrix_N
	ldr r6,=Matrix_O
	
	// Matrix String ausgeben
	ldr r0,=String_Matrix_O
	bl uart_putString
		
	mov r10, COUNTER_OUTER_LOOP
	mov r11, 0x0					// Init r11 for sum result
	mov r3, COUNTER_INNER_LOOP				
	mov r12,COUNTER_OUTER_LOOP

multiply_loop:
//Multiplikation Zeile * Spalte
	ldr r7, [r4],#0x4				// Wert von Matrix_M in r7 laden und dann um 32 bit erhöhen
	ldr r8, [r5],#0x4				// Wert von Matrix_N in r8 laden und dann um 32 bit erhöhen
	SMLAD r11,r7,r8,r11				// jeweils bottom und top halfwords von r7 und r8 multiplizieren, Ergebnisse in r11 hinzuaddieren				
	subs r3,r3,#0x1					// loop condition
	bne multiply_loop	
//Store Matrix Result
	str r11, [r6],#0x4				// Ergebnis in Matrix_O abgelegen und post-inkrement für die nächsten 32 bit 	
	mov r0,r11						// Wert ausgeben
	bl uart_putInt32				
	ldr r0, =String_Leerzeichen
	bl uart_putString
	
	mov r11, 0x0					// Init r11 for sum result	
	sub r4, #0x8					// zurück zum Zeilenanfang der Matrix_M
	mov r3, COUNTER_INNER_LOOP		// Counter für die innere Schleife setzen				
	subs r10,r10,#0x1
	bne multiply_loop

	add r4,#0x8						// nächste Zeile von Matrix_M
	sub r5,#0x20					// Matrix_N wieder auf Anfang
	ldr r0,=String_Next_Line		// Neue Zeile bei der Ausgabe
	bl uart_putString
	
	mov r3, COUNTER_INNER_LOOP		// Counter für die innere Schleife setzen
	mov r10,COUNTER_OUTER_LOOP		// Counter für die äußere Schleife setzen
	subs r12,r12,#0x1				// Abbruchbedingung Schleife	
	bne multiply_loop
	
// ###### Kopieren der Matrix O ######
	ldr r0, =String_Kopieren_Matrix
	bl uart_putString
		
	// Quell und Zieladresse laden
	ldr r11, =Matrix_O
	ldr r12, =Matrix_O_kopiert	

	ldm r11!, {r1-r8}				// In Register r1-r8 nacheinander Inhalt laden, R11 fungiert als Basisregister, das nach jedem Laden inkrementiert wird.
	stm r12!, {r1-r8}				// In Register r1-r8 nacheinander Inhalt laden und an die Adresse von R12 ablegen. R12 fungiert als Basisregister, das nach jedem Laden inkrementiert wird.
	ldm r11!, {r1-r8}		
	stm r12!, {r1-r8}
// Teilaufgabe c
	ldr r4,=Matrix_M
	ldr r5,=Matrix_N
	mov r9, COUNTER_SUMME
	mov r11,#0x0				// Für das Ergebnis
summe_loop:	
	ldr r7, [r4],#0x4			// Werte laden und Adresse erhöhen
	ldr r8, [r5],#0x4			// Werte laden und Adresse erhöhen
	SMLAD r11,r7,r8,r11			// Multiplikation und Addition
	subs r9,r9,#0x1				// Abbruchbedingung
	bne summe_loop
	
	ldr r0,=String_Produkt_Summe
	bl uart_putString
	mov r0,r11
	bl uart_putInt32
	
// Teilaufgabe d
	ldr r4, =VARIABLE_A
	ldr r5, [r4], #0x4			// VARIABLE_A
	ldr r6, [r4], #0x4			// VARIABLE_B
	ldr r7, [r4], #0x4			// VARIABLE_C
	ldr r8, [r4]				// VARIABLE_D
	/*
	   Es werden die 32-Bit Variablen in 2x 16 Bit "angenommen" und darauf
	   die Addition angewandt. z.B. bei UADD16(A+C) (Bits 31..16) => 0xC553+0xA436 
	   gibt einen Overflow, da 0xa+0xc > 0xf.
	   Somit Ist das Egebnis am Ende ein Wert, der in den 16 Bit Wertebereich nicht mehr
	   passt. Korrekter Wert: 0x16989. Berechnetes Ergebnis => 0x6989. Man
	   beachte, dass die 1 (msb) abgeschnitten wird, da der Wert nicht mehr in 
	   16 Bits passen würde. => Overflow.
	*/
	
	/* 
	   Ein Overflow liegt bei uadd16 bei jeder Addition vor. Jedoch gibt es keine
	   Sättigung. Wenn das Ergebnis nicht mehr in 16 Bits passt, wird der Übertrag
	   einfach abgeschnitten.
	*/
	
	ldr r10, =String_Leerzeichen
	//UADD16 
	ldr r0, =String_UADD16
	bl uart_putString
	/*
	UADD16(A,B)
	Bei Bits 15..0: Ergebnis passt nicht mehr in den 16 Bits Bereich. Der Übertrag
	wird abgeschnitten. Korrektes Ergebnis: 0x105AE
	Bei Bits 31..16: Ergebnis korrekt
	*/
	uadd16 r0,r5,r6
	bl uart_putInt32
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	UADD16(A,C)
	Bei Bits 15..0: Ergebnis korrekt
	Bei Bits 31..16: Ergebnis bei passt nicht mehr in den 16 Bits Bereich. Der Übertrag
	wird abgeschnitten. Korrektes Ergebnis: 0x16989
	*/
	uadd16 r0,r5,r7
	bl uart_putInt32	
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	UADD16(A,D)
	Bei Bits 15..0: Ergebnis passt nicht mehr in den 16 Bits Bereich. Der Übertrag
	wird abgeschnitten. Korrektes Ergebnis: 0x1012C
	Bei Bits 31..16: Ergebnis passt nicht mehr in den 16 Bits Bereich. Der Übertrag
	wird abgeschnitten. Korrektes Ergebnis: 0x11CC4
	*/
	uadd16 r0,r5,r8
	bl uart_putInt32
	
	/*
	Die berechneten Ergebnisse bei uadd16 und sadd16 sind gleich.
	Der Overflow und das Abschneiden der Werte tritt an den selben Stellen auf.
	*/	
	//SADD16
	ldr r0, =String_SADD16
	bl uart_putString
	/* 
	SADD16(A,B)
	Bei Bits 15..0 => Ergebnis ist korrekt, obwohl ein Übertrag stattgefunden hat.
	Bei Bits 31..16 => Ergebnis korrekt
	*/
	sadd16 r0,r5,r6
	bl uart_putInt32
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	SADD16(A,C)
	Bei Bits 15..0: Es findet kein Übertrag statt, dennoch ist das Ergebnis im Zweierkomplement
	"falsch". Maximal möglicher positiver Wert von 0x7fff wird überschritten.
	Bei Bits 31..16: Ergebnis passt nicht mehr in den 16 Bits Bereich. Der Übertrag
	wird abgeschnitten. Korrektes Ergebnis: 0xFFFF6989
	
	*/
	sadd16 r0,r5,r7
	bl uart_putInt32	
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	SADD16(A,D)
	Bei Bits 15..0:	Ergebnis ist korrekt, obwohl ein Übertrag stattgefunden hat.
	Bei Bits 31..16: Ergebnis ist korrekt, obwohl ein Übertrag stattgefunden hat.
	*/
	sadd16 r0,r5,r8
	bl uart_putInt32
	
	/*If the full result would be greater than 2^n-1, the result returned is 2^n-1.*/
	//UQADD16
	ldr r0, =String_UQADD16
	bl uart_putString
	/* 
	UQADD16(A,B)
	Bei Bits 15..0:	Overflow tritt auf => Ergebnis Sättigt auf _ffff
	Bei Bits 31..16: Ergebnis korrekt
	*/
	uqadd16 r0,r5,r6
	bl uart_putInt32
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	UQADD16(A,C) 
	Bei Bits 15..0: Ergebnis korrekt
	Bei Bits 31..16: Overflow tritt auf => Ergebnis Sättigt auf ffff_
	*/	
	uqadd16 r0,r5,r7
	bl uart_putInt32	
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/* UQADD16(A,D)
	Overflow tritt sowohl bei Bits 31..16 als auch bei Bits 15..0 auf 
	=> Ergebnis Sättigt auf ffff_ffff
	*/
	uqadd16 r0,r5,r8
	bl uart_putInt32

	
	/*For a signed saturating operation, if the full result would be 
	less than -2^n, the result returned is -2^n.*/
	//QADD16	
	ldr r0, =String_QADD16
	bl uart_putString
	/*QADD16(A,B)
	Keine Sättigung, obwohl ein Overflow stattfindet, da Werte in range sind!
	*/
	qadd16 r0,r5,r6
	bl uart_putInt32
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	QADD16(A,C)
	Sättigung tritt hier sowohl bei Bits 31..16 als auch bei Bits 15..0 auf
	=> Sättigung 1x auf Minimum (8000) 1x auf Maximum (7fff).
	Sättigung bei 31..16 tritt auf, da 2 negative Werte addiert werden und das 
	Ergebnis aufgrund eines Overflows positiv wäre. Deswegen Sättigung auf den 
	niedrigsten möglichen Wert!
	Sättigung bei 15..0 tritt auf, da das Ergebnis zweier positiver Zahlen negativ
	geworden wäre. Deshalb Sättigung auf den höchsten möglichen Wert im Zweierkomplement!
	*/
	qadd16 r0,r5,r7
	bl uart_putInt32	
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*QADD16(A,D)
	Keine Sättigung, obwohl ein Overflow stattfindet, da Werte in range sind!
	*/
	qadd16 r0,r5,r8
	bl uart_putInt32
	
// Teilaufgabe e

	ldr r0, =String_SSAT16
	bl uart_putString
	/*
	SSAT16 => saturates a signed value to a signed range. 
	*/
	/*
	SSAT16(A)
	Ergebnis Bits 15..0: 0x0fff => 2¹² -1 => 4095
	0x7C7B ist ein positiver Wert, welcher größer als die positive Sättigungsgrenze ist. 
	Deshalb erfolgt hier die Sättigung auf den positiven Wert.
	Ergebnis Bits 31..16: 0xf000 => -2¹² => -4096 
	0xA436 ist ein negativer Wert, welcher kleiner als die negative Sättigungsgrenze ist.
	Deshalb erfolgt hier die Sättigung auf den negativen Wert.
	*/
	ssat16 r0,#0xD,r5		// Sättigt auf -2¹³⁻¹ <= x <=2¹³⁻¹-1
	bl uart_putInt32
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	SSAT16(B)
	Ergebnis Bits 15..0: 0xf000 => 2¹² => -4096
	0x8933 ist ein negativer Wert, welcher kleiner als die negative Sättigungsgrenze ist. 
	Deshalb erfolgt hier die Sättigung auf den negativen Wert.
	Ergebnis Bits 31..16: 0x0fff => -2¹² -1 => 4095 
	0x10A7 ist ein positiver Wert, welcher größer als die positive Sättigungsgrenze ist.
	Deshalb erfolgt hier die Sättigung auf den positiven Wert.
	*/
	ssat16 r0,#0xD,r6		// Sättigt auf -2¹³⁻¹ <= x <= 2¹³⁻¹-1
	bl uart_putInt32
	/*
	USAT16 => saturates a signed value to an unsigned range.
	*/
	ldr r0, =String_USAT16
	bl uart_putString
	/*
	USAT16(A) 
	Ergebnis Bits 15..0: 0x1fff
	0x7C7B ist ein positiver Wert, welcher Größer ist als die obere Sättigungsgrenze.
	Deshalb erfolgt hier die Sättigung auf den maximalen positiven Wert. (8191)
	Ergebnis Bits 31..16: 0x0000
	0xA436 ist ein negativer Wert. Deshalb erfolgt hier die Sättigung auf die untere
	Sättigungsgrenze. (0)
	*/
	usat16 r0,#0xD,r5		// Sättigt auf 0 <= x <= 2¹³-1
	bl uart_putInt32
	// Leerzeichen
	mov r0, r10
	bl uart_putString
	/*
	USAT16(B) 
	Ergebnis Bits 15..0: 0x0000
 	0x8933 ist ein negativer Wert. Deshalb erfolgt hier die Sättigung auf die untere
	Sättigungsgrenze. (0)
	Ergebnis Bits 31..16: 0x10a7
	0x10A7 wird nicht gesättigt, dieser Wert sich innerhalb des Sättigungsbereiches
	befindet. Dezimal: 4263 liegt innerhalb von 0<= x <= 8191
	*/
	usat16 r0,#0xD,r6		// Sättigt auf 0 <= x <= 2¹³-1
	bl uart_putInt32	

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data


Matrix_M:
.word 0x7f485f8c
.word 0x60488245
.word 0x9c5dc799
.word 0x33d8d49c 
.word 0x8aef579b
.word 0xa3c2f2c0
.word 0x50d441fd 
.word 0x4afa25c6
Matrix_N:
.word 0x06457f41 
.word 0x90658c8f
.word 0xf7f378e3
.word 0x2961d29f
.word 0xdfed5a1e
.word 0x10924b9f
.word 0x21be61bf
.word 0xc6d35ca1
Matrix_O:
.rept COUNTER_MATRIX
.long 0x00000000
.endr
Matrix_O_kopiert:
.rept COUNTER_MATRIX
.long 0x00000000
.endr

VARIABLE_A: .word 0xA4367C7B
VARIABLE_B: .word 0x10A78933
VARIABLE_C:	.word 0xC5535F2C
VARIABLE_D:	.word 0x788E84B1

String_Matrix_O: .asciz "Ergebnismatrix O :\n"
String_Next_Line: .asciz "\n"
String_Leerzeichen: .asciz " "
String_Kopieren_Matrix: .asciz "\nKopieren der Matrix O! \n"
String_Produkt_Summe: .asciz "\nProdukt - Summe :  "
String_UADD16: .asciz "\nUADD16 :  "
String_SADD16: .asciz "\nSADD16 :  "
String_UQADD16: .asciz "\nUQADD16 :  "
String_QADD16: .asciz "\nQADD16 :  "
String_SSAT16: .asciz "\nSSAT16 :  "
String_USAT16: .asciz "\nUSAT16 :  "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ MAX_MINUTEN, 	0x3B
.equ MAX_STUNDEN, 	0x17 
.equ MAX_TAGE,		0x1E
.equ MAX_MONATE,	0x0C
.equ MAX_JAHR2, 	0x63
.equ MAX_JAHR1,		0x15

// Init Werte für Jahrhunderüberlauf
.equ INIT_MIN,  	0x00
.equ INIT_HR,	 	0x00 
.equ INIT_DAY,		0x01
.equ INIT_MONTH,	0x01
.equ INIT_YR2,	 	0x0E
.equ INIT_YR1,		0x14

.equ DELAY_COUNTER, 0x7F2813


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	ldr r4, =var_clock_state
	ldr r5, =var_time_state
	ldr r6, =var_date_state
main_loop:	

	ldrb r0, [r6]					// Prüfe, ob das 
	cmp r0, #0x0					// Datum neu eingegeben werden soll
	it eq
	beq date_no_change				// Datum nicht neu eingeben

// Datum soll neu eingegeben werden
	mov r3, #0x0					// Für Merker
	strb r3, [r6]					// Merker resetten
	ldr r0, =string_Tag_Eingeben		
	bl uart_putString
// Tag eingeben
loop_input_day:						// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_day
// Tag wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Tag-Wert
	ldr r1, =var_Tag
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_day_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7
print_input_day_without_zero:
	bl uart_putByteBase10		
	
// Monat eingeben	
	ldr r0, =string_Monat_Eingeben		
	bl uart_putString
loop_input_month:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_month
// Monat wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Monat-Wert
	ldr r1, =var_Monat
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_month_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7
print_input_month_without_zero:
	bl uart_putByteBase10
	
// Jahr2 eingeben	
	ldr r0, =string_Jahr_Eingeben		
	bl uart_putString
loop_input_year:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_year
// Jahr wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Jahr-Wert
	ldr r1, =var_Jahr2
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_year_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7
print_input_year_without_zero:
	bl uart_putByteBase10
	bl print_new_line
	
	b clock_not_running				// Direkt nach dem Eingeben soll nicht sofort ein Inkrementieren erfolgen
		
date_no_change:						// Datum soll nicht neu eingegeben werden	
// Prüfe, ob Uhrzeit neu eingegeben werden soll	
	ldrb r0, [r5]			
	cmp r0, #0x0 
	it eq
	beq clock_no_change				// Uhrzeit nicht neu eingeben
// Uhrzeit soll neu eingegeben werden
	mov r3, #0x0					// Für Merker
	strb r3, [r5]					// Merker resetten
// Stunden eingeben	
	ldr r0, =string_Stunde_Eingeben		
	bl uart_putString
loop_input_hour:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_hour
// Stunde wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Stundenwert
	ldr r1, =var_Stunde	
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_hour_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7	
print_input_hour_without_zero:
	bl uart_putByteBase10	
		
	ldr r0, =string_Minute_Eingeben	// Minuten eingeben
	bl uart_putString
loop_input_minute:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_minute
// Minute wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Minutenwert
	ldr r1, =var_Minute
	strb r0, [r1]					// und lege ihn im Speicher ab	
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_minutes_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7						// eingegebenen Wert holen und	
print_input_minutes_without_zero:	
	bl uart_putByteBase10			// ausgeben
	bl print_new_line
	
	b clock_not_running				// Direkt nach dem Eingeben soll nicht sofort ein Inkrementieren erfolgen
	
	
clock_no_change:					// Uhrzeit soll nicht neu eingegeben werden
// Prüfe, ob Uhr laufen soll	
	ldrb r0, [r4]			
	cmp r0, #0x0					// Wenn "Merker" Null, soll Uhr nicht weiterlaufen
	it eq
	beq clock_not_running
	
/*
Anmerkung: Es kann davon ausgegangen werden, dass ein Umschalten erst notwendig ist,
wenn die Minuten den Max-Wert erreicht haben. Nur deshalb kann die komplette Umschaltkette
und der Vergleich mit r1 funktionieren. Ansonsten müsste jedes Mal jede einzelne 
Variable aus dem Speicher geladen und auf Max-Wert überprüft werden.
*/
// Minuten inkrementieren und auf Überlauf überprüfen
	ldr r0, =var_Minute			// übergeben r1, r0, r3
	mov r1, 0x0					// Wert auf den Minute Zurückgesetzt werden soll
	mov r2, MAX_MINUTEN			// Maximaler Wert für Minuten
	bl check_overflow_and_inc	

// Überlauf aufgetreten bei Minuten, Stunden erhöhen  
	cmp r1, #MAX_MINUTEN		// Max Minuten erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Stunde		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x0				// Wert auf den Stunde Zurückgesetzt werden soll
	movhi r2, MAX_STUNDEN		// Maximaler Wert für Stunden
	blhi check_overflow_and_inc	
	
// Überlauf aufgetreten bei Stunden, Tage erhöhen 
	cmp r1, #MAX_STUNDEN		// Max Stunden erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Tag			// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x1				// Wert auf den Tag Zurückgesetzt werden soll
	movhi r2, MAX_TAGE			// Maximaler Wert für Tage
	blhi check_overflow_and_inc	

// Überlauf aufgetreten bei Tage, Monat erhöhen 
	cmp r1, #MAX_TAGE			// Max Tage erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Monat		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x1				// Wert auf den Monat Zurückgesetzt werden soll
	movhi r2, MAX_MONATE		// Maximaler Wert für Monate
	blhi check_overflow_and_inc	

// Überlauf aufgetreten bei Monate, Jahr erhöhen 
	cmp r1, #MAX_MONATE			// Max Tage erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Jahr2		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x0				// Wert auf den Jahr Zurückgesetzt werden soll
	movhi r2, MAX_JAHR2			// Maximaler Wert für Jahr2
	blhi check_overflow_and_inc	

// Überlauf aufgetreten bei Jahr2, Jahr1 erhöhen 
	cmp r1, #MAX_JAHR2			// Max Jahre erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Jahr1		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x0				// Wert auf den Jahr Zurückgesetzt werden soll
	movhi r2, MAX_JAHR1			// Maximaler Wert für Jahr1
	blhi check_overflow_and_inc		
	
clock_not_running:				// Für Direktsprung, falls Uhr nicht laufen soll
// Jahrhundertüberlauf abfangen.
	ldr r0, =var_Jahr1
	ldrb r1, [r0]				// Wert vom Jahr1
	cmp r1, #MAX_JAHR1			// Vergleich auf max
	itt eq
	ldreq r0,=var_Jahr2			// Jahr2 braucht man auch, da das aktuelle Jahrhundert bis 31.12.2100 geht, Übergabeparameter r0
	bleq check_century_end
	
// Datum und Uhrzeit ausgeben
	bl print_date_and_time
// 1 Sekunde Delay
	bl delay
	
	bl uart_charPresent			// Prüfen, ob ein Zeichen eingegeben wurde
	cmp r0, 0x0					// Prüfen, ob ein Zeichen eingegeben wurde
	it hi						
	blhi evaluate_input			// ja, ansonsten wieder Sprung an den Anfang des Programms
	
	b main_loop


// Eingegebenes Zeichen auswerten	
.thumb_func	
evaluate_input:
	push {lr} 
	bl uart_getChar				// Eingegebenes Zeichen holen
	cmp r0, 's'					// Überprüfe, ob Eingabe ein 's' war
	it ne
	bne eval_time
// Das eingegebene Zeichen war ein 's'
	ldr r1,=var_clock_state		// 
	ldrb r2, [r1]				// Aktuellen Wert der Uhr-Status-Variable aus dem Speicher holen 
	cmp r2, #0x1				// Prüfen, ob die Uhr gerade läuft
	it eq
	beq stop_time				// Ja, Uhr läuft. => Muss gestoppt werden
// Nein, Uhr läuft nicht	
	mov r3, #0x1				// Für Merker, dass Uhrzeit laufen soll
	strb r3, [r1]				// Setze den Merker, dass Uhrzeit laufen soll
	b end						// eingegebenes Zeichen war ein 's' => ENDE

stop_time:				
	mov r3, #0x0				// Variable nullen und 
	strb r3, [r1]				// Im Speicher ablegen => Uhr wird ausgeschaltet  
	b end         				// eingegebenes Zeichen war ein 's' => ENDE

eval_time:
	cmp r0, 't'					// Überprüfe, ob Eingabe ein 't' war
	it ne
	bne eval_date				// eingegebenes Zeichen war kein 't'
// Das eingegebene Zeichen war ein 't'
	ldr r1,=var_time_state		
	mov r3, #0x1				// Für Merker
	strb r3, [r1]				// setze den Merker, dass die Uhrzeit neu eingegeben werden soll
	b end						// eingegebenes Zeichen war ein 't' => ENDE

eval_date:
	cmp r0, 'd'					// Überprüfe, ob Eingabe ein 'd' war
	it ne
	bne end						// eingegebenes Zeichen war kein 'd' => kein gültiges Zeichen eingegeben. => ENDE
// eingegebenes Zeichen war ein d'
	ldr r1,=var_date_state		
	mov r3, #0x1				// Für Merker
	strb r3, [r1]				// setze den Merker, dass das Datum neu eingegeben werden soll
	
end:
	pop {pc} 
/*
Taktfrequenz 24MHz => 24 Millionen Takte...
	Init Cycles: 3 Takte weniger wegen Vorbereitung
	End loop:~5 Takte Weniger wegen wegen Nachbereitung (pop)
	1 zusätzlich, da bei bne am Ende nicht gesprungen wird
	3+5-1 => 7 Takte subtrahieren
	Loop: 3 Takte pro Durchlauf
	Abgleich mit pit3 ergab Übereinstimmung.
	(25 MHz-7)/3 = 8.333.331 => 0x7F2813  => DELAY_COUNTER	
*/
// Unterprogramm delay
.thumb_func
delay:
	push {lr} 					// 1 + N Takte => 2 Takte
	ldr r0, =DELAY_COUNTER		// 1 Takt
delay_loop:	
	subs r0, r0, #0x1			// 1 Takt
	bne delay_loop				// 1 + P or 1 if branch not taken ...=> 2 Takte
	pop {pc}					// 1 + N + P Takte P=1..3 => 5 Takte
	

// Unterprogramm Uhrzeit und Datumausgabe
.thumb_func
print_date_and_time:
	push {r4-r9,lr}
	ldr r1,=char_Punkt			// Anfangsadresse für Datumausgabe holen
	ldrb r4, [r1], #0x1			// Für Punkt ausgeben
	ldrb r8, [r1], #0x1			// Für Doppelpunkt ausgeben
	ldrb r5, [r1]				// Für Leerzeichen ausgeben
	mov r6, 0x4					// 4 Durchläufe der date_Loop
	ldr r7, =var_Tag			// Anfangsadresse für Datumsausgabe holen
date_Loop:
	ldrb r0, [r7], 0x01			// Tag,Monat,Jahr,Jahr
	cmp r0, #0xA				// Vergleich, falls eine Null zusätzlich ausgegeben werden soll 
	it ge
	bge print_date_without_zero	// Keine Ausgabe für zusätzliche Null nötig, ansonsten
	mov r9,r0					// Den eigentlichen Wert, der ausgegeben werden soll, zwischenspeichern
	mov r0, #0x0				// Zusätzliche Null
	bl uart_putByteBase10		// ausgeben
	mov r0, r9					// Den Zwischengespeicherten Wert holen und
	
print_date_without_zero:	
	bl uart_putByteBase10		// ausgeben
	cmp r6, #0x2				// Bedingung, falls ein Punkt ausgegeben werden soll
	itt hi
	movhi r0, r4				// Punkt
	blhi uart_putChar			// ausgeben
	subs r6, r6, 0x1			// check condition
	bne date_Loop
	
	mov r0, r5					// Leerzeichen
	bl uart_putChar				// ausgeben
	
	ldr r7, =var_Stunde			// Anfangsadresse für Uhrzeitausgabe holen
	mov r6, 0x2					// 2 Durchläufe der clock_Loop
clock_Loop:
	ldrb r0, [r7], #-0x01		// Stunde, Minute
	cmp r0, #0xA				// Vergleich, falls eine Null zusätzlich ausgegeben werden soll
	it ge
	bge print_clock_without_zero// Keine Ausgabe für zusätzliche Null nötig, ansonsten
	mov r9,r0					// Den eigentlichen Wert, der ausgegeben werden soll, zwischenspeichern
	mov r0, #0x0				// Zusätzliche Null
	bl uart_putByteBase10		// ausgeben
	mov r0, r9					// Den Zwischengespeicherten Wert holen und
print_clock_without_zero:	
	bl uart_putByteBase10		// ausgeben
	cmp r6, #0x1				// Bedingung für Doppelpunkt
	itt hi
	movhi r0, r8				// Doppelpunkt
	blhi uart_putChar			// ausgeben
	subs r6, r6, 0x1			// check condition
	bne clock_Loop
	
	ldr r0, =string_Uhr			// String Uhr
	bl uart_putString			// ausgeben
	pop {r4-r9,pc}


// Führt das Inkrementieren und den Overflow durch
// r0 Adresse für Speicherbereich
// r1 Wert auf den Zurückgesetzt werden soll, falls der Max Wert erreicht wurde
// r2 Max Wert
// return r1
.thumb_func
check_overflow_and_inc:
	push {r4, lr}			
    ldrb r4, [r0]		// Wert an der übergebenen Adresse aus dem Speicher laden
	          
	add r4, r4, #0x1	// inkrementieren
	cmp r4, r2			// Mit Max Wert Vergleichen
	ittt hi				// Wenn höher zurücksetzen. Ein Überlauf hat stattgefunden
	movhi r3, r1		// Wert von r1 Zwischenspeichern	
	movhi r1, r4		// Den "Merker", dass ein Überlauf stattgefunden hat in r1 als Rückgabewert	
	movhi r4, r3		// Hier auf den übergebenen Wert zurücksetzen und
	strb r4, [r0]		// Im Speicher ablegen
	pop {r4, pc}
	
// Funktion setzt Datum und Zeit auf Default-Werte, falls das aktuelle Jahrhundert überschritten wurde
// Übergabeparameter r0
.thumb_func
check_century_end:
	push {lr}
	
	ldrb r1,[r0]
	cmp r1,#0x0
	it eq				// Noch in diesem Jahrhundert => 2100
	beq return
// Ansonsten alles auf Init zurücksetzen!
	
	mov r1, INIT_YR2				// Jahr2
	strb r1, [r0],#-0x1
	mov r1, INIT_YR1				// Jahr1
	strb r1, [r0],#-0x1
	mov r1, INIT_MONTH				// Monat
	strb r1, [r0],#-0x1
	mov r1, INIT_DAY				// Tag
	strb r1, [r0],#-0x1
	mov r1, INIT_HR					// Stunde
	strb r1, [r0],#-0x1	
	mov r1, INIT_MIN				// Minute
	strb r1, [r0]
	ldr r0, =string_Jahrhundert_Ueberschritten
	bl uart_putString
return:
	pop {pc}

// Funktion, um eine zusätzliche Null auszugeben
.thumb_func
print_zero:
	push {lr}
	mov r0, #0x0				// Null
	bl uart_putByteBase10		// ausgeben
	pop {pc}
	
// Funktion für neue Zeile 
.thumb_func
print_new_line:
	push {lr}
	ldr r0, =string_new_line
	bl uart_putString
	pop {pc}
	
/*** Datenbereich (ab 0x20000000) ***/
.data

char_Punkt: 	  .byte 0x2E
char_Doppelpunkt: .byte 0x3A
char_Leerzeichen: .byte 0x20

var_Minute: .byte 0x00
var_Stunde: .byte 0x00
var_Tag:    .byte 0x01
var_Monat:  .byte 0x01
var_Jahr1:  .byte 0x14
var_Jahr2:  .byte 0x0E

var_clock_state: .byte 0x00
var_time_state:  .byte 0x00
var_date_state:  .byte 0x00

string_Uhr:		  		.asciz " Uhr\n"
string_Stunde_Eingeben: .asciz "\nStunde eingeben ( hh ) : "
string_Minute_Eingeben: .asciz "\nMinuten eingeben ( mm ) : "
string_Tag_Eingeben: 	.asciz "\nTag eingeben ( dd ) : "
string_Monat_Eingeben: 	.asciz "\nMonat eingeben ( mm ) : "
string_Jahr_Eingeben: 	.asciz "\nJahr eingeben ( jj ) : "
string_Jahrhundert_Ueberschritten: .asciz "Jahrhundert wurde ueberschritten. Defaultwerte werden geladen!\n"
string_new_line:		.asciz "\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten

.equ MAX_MINUTEN, 	0x3B
.equ MAX_STUNDEN, 	0x17 
.equ MAX_TAGE,		0x1E
.equ MAX_MONATE,	0x0C
.equ MAX_JAHR2, 	0x63
.equ MAX_JAHR1,		0x15

// Init Werte für Jahrhunderüberlauf
.equ INIT_MIN,  	0x00
.equ INIT_HR,	 	0x00 
.equ INIT_DAY,		0x01
.equ INIT_MONTH,	0x01
.equ INIT_YR2,	 	0x0E
.equ INIT_YR1,		0x14

.equ IV_PIT1, 0x1FFFFF54			// (IRQn69) => 0x1FFFFE00 + 0x0000_0154
.equ NVIC_ICPR2, 0xE000E288		
.equ NVIC_ISER2, 0xE000E108
.equ PIT_LDVAL1_ADDR, 0x40037110
//.equ PIT_TCTRL1, 0x40037118

.equ PIT1_COUNTER_VALUE, 0x17D7840

.equ SIM_SCGC6_ADDR, 0x4004803C
.equ SIM_SCGC6_PIT_POS, 0x17
.equ BB_ENABLE_PIT_CLK, 0x0

.equ PIT_MCR_ADDR, 0x40037000
.equ PIT_MCR_MDIS, 0x1
.equ BB_PIT_MCR_MDIS, 0x0

.equ PIT_TFLG1_ADDR, 0x4003711C
.equ PIT_TFLG1_TIF, 0x0
.equ BB_PIT_TFLG1_TIF, 0x0

.equ PIT_TCTRL1_ADDR, 0x40037118
.equ PIT_TCTRL1_TEN, 0x0
.equ BB_PIT_TCTRL1_TEN, 0x0
// Bit Banding Macro 
__BBREG BB_ENABLE_PIT_CLK, SIM_SCGC6_ADDR, SIM_SCGC6_PIT_POS
__BBREG BB_PIT_MCR_MDIS, PIT_MCR_ADDR, PIT_MCR_MDIS
__BBREG BB_PIT_TFLG1_TIF, PIT_TFLG1_ADDR, PIT_TFLG1_TIF
__BBREG BB_PIT_TCTRL1_TEN, PIT_TCTRL1_ADDR, PIT_TCTRL1_TEN

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit_init
	ldr r4, =var_clock_state
	ldr r5, =var_time_state
	ldr r6, =var_date_state
	ldr r11, =var_second_over
main_loop:	

	ldrb r0, [r11]			// Prüfe, ob sekunde vorbei
	cmp r0, #0x0
	it eq
	beq second_not_over
	mov r1, #0x0
	strb r1, [r11]					// reset Sekunden Flag

	ldrb r0, [r6]					// Prüfe, ob das 
	cmp r0, #0x0					// Datum neu eingegeben werden soll
	it eq
	beq date_no_change				// Datum nicht neu eingeben

// Datum soll neu eingegeben werden
	mov r3, #0x0					// Für Merker
	strb r3, [r6]					// Merker resetten
	bl stop_PIT1					// PIT1 wird hier gestoppt, damit eine erschnellte Ausgabe der Uhrzeit und des Datums nach der Eingabe nicht erfolgt  		
	ldr r0, =string_Tag_Eingeben	
	bl uart_putString
// Tag eingeben
loop_input_day:						// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_day
// Tag wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Tag-Wert
	ldr r1, =var_Tag
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_day_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7
print_input_day_without_zero:
	bl uart_putByteBase10		
	
// Monat eingeben	
	ldr r0, =string_Monat_Eingeben		
	bl uart_putString
loop_input_month:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_month
// Monat wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Monat-Wert
	ldr r1, =var_Monat
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_month_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7
print_input_month_without_zero:
	bl uart_putByteBase10
	
// Jahr2 eingeben	
	ldr r0, =string_Jahr_Eingeben		
	bl uart_putString
loop_input_year:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_year
// Jahr wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Jahr-Wert
	ldr r1, =var_Jahr2
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_year_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7
print_input_year_without_zero:
	bl uart_putByteBase10
	bl print_new_line
	bl start_PIT1					// Nach der Eingabe wird PIT1 wieder gestartet => Beginnt von vorne zu zählen
	b clock_not_running				// Direkt nach dem Eingeben soll nicht sofort ein Inkrementieren erfolgen
	
date_no_change:						// Datum soll nicht neu eingegeben werden	
// Prüfe, ob Uhrzeit neu eingegeben werden soll	
	ldrb r0, [r5]			
	cmp r0, #0x0 
	it eq
	beq clock_no_change				// Uhrzeit nicht neu eingeben
	bl stop_PIT1
// Uhrzeit soll neu eingegeben werden
	mov r3, #0x0					// Für Merker
	strb r3, [r5]					// Merker resetten
// Stunden eingeben	
	ldr r0, =string_Stunde_Eingeben		
	bl uart_putString
loop_input_hour:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_hour
// Stunde wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Stundenwert
	ldr r1, =var_Stunde
	strb r0, [r1]					// und lege ihn im Speicher ab
// eingegebenen Wert ausgeben
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_hour_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7	
print_input_hour_without_zero:
	bl uart_putByteBase10	
		
	ldr r0, =string_Minute_Eingeben	// Minuten eingeben
	bl uart_putString
loop_input_minute:					// so lange warten, bis ein Wert eingegeben wurde
	bl uart_charPresent
	cmp r0, #0x0
	it eq
	beq loop_input_minute
// Minute wurde eingegeben
	bl uart_getByteBase10			// hole eingegebenen Minutenwert
	ldr r1, =var_Minute
	strb r0, [r1]					// und lege ihn im Speicher ab	
	cmp r0, #0xA					// Für Vergleich, ob zusätzliche Null ausgegeben werden soll
	it ge
	bge print_input_minutes_without_zero
	mov r7, r0						// eingegebenen Wert zwischenspeichern
	bl print_zero					// zusätzliche Null ausgeben
	mov r0, r7						// eingegebenen Wert holen und	
print_input_minutes_without_zero:	
	bl uart_putByteBase10			// ausgeben
	bl print_new_line
	
	bl start_PIT1					// PIT1 wieder starten
	b clock_not_running				// Direkt nach dem Eingeben soll nicht sofort ein Inkrementieren erfolgen
	
clock_no_change:					// Uhrzeit soll nicht neu eingegeben werden
// Prüfe, ob Uhr laufen soll	
	ldrb r0, [r4]			
	cmp r0, #0x0					// Wenn "Merker" Null, soll Uhr nicht weiterlaufen
	it eq
	beq clock_not_running
	
/*
Anmerkung: Es kann davon ausgegangen werden, dass ein Umschalten erst notwendig ist,
wenn die Minuten den Max-Wert erreicht haben. Nur deshalb kann die komplette Umschaltkette
und der Vergleich mit r1 funktionieren. Ansonsten müsste jedes Mal jede einzelne 
Variable aus dem Speicher geladen und auf Max-Wert überprüft werden.
*/
// Minuten inkrementieren und auf Überlauf überprüfen
	ldr r0, =var_Minute			// übergeben r1, r0, r3
	mov r1, 0x0					// Wert auf den Minute Zurückgesetzt werden soll
	mov r2, MAX_MINUTEN			// Maximaler Wert für Minuten
	bl check_overflow_and_inc	

// Überlauf aufgetreten bei Minuten, Stunden erhöhen  
	cmp r1, #MAX_MINUTEN		// Max Minuten erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Stunde		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x0				// Wert auf den Stunde Zurückgesetzt werden soll
	movhi r2, MAX_STUNDEN		// Maximaler Wert für Stunden
	blhi check_overflow_and_inc	
	
// Überlauf aufgetreten bei Stunden, Tage erhöhen 
	cmp r1, #MAX_STUNDEN		// Max Stunden erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Tag			// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x1				// Wert auf den Tag Zurückgesetzt werden soll
	movhi r2, MAX_TAGE			// Maximaler Wert für Tage
	blhi check_overflow_and_inc	

// Überlauf aufgetreten bei Tage, Monat erhöhen 
	cmp r1, #MAX_TAGE			// Max Tage erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Monat		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x1				// Wert auf den Monat Zurückgesetzt werden soll
	movhi r2, MAX_MONATE		// Maximaler Wert für Monate
	blhi check_overflow_and_inc	

// Überlauf aufgetreten bei Monate, Jahr erhöhen 
	cmp r1, #MAX_MONATE			// Max Tage erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Jahr2		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x0				// Wert auf den Jahr Zurückgesetzt werden soll
	movhi r2, MAX_JAHR2			// Maximaler Wert für Jahr2
	blhi check_overflow_and_inc	

// Überlauf aufgetreten bei Jahr2, Jahr1 erhöhen 
	cmp r1, #MAX_JAHR2			// Max Jahre erreicht, Überlauf durchführen
	itttt hi
	ldrhi r0, =var_Jahr1		// Adresse, an der der Wert inkrementiert werden soll
	movhi r1, 0x0				// Wert auf den Jahr Zurückgesetzt werden soll
	movhi r2, MAX_JAHR1			// Maximaler Wert für Jahr1
	blhi check_overflow_and_inc		
	
clock_not_running:				// Für Direktsprung, falls Uhr nicht laufen soll
// Jahrhundertüberlauf abfangen.
	ldr r0, =var_Jahr1
	ldrb r1, [r0]				// Wert vom Jahr1
	cmp r1, #MAX_JAHR1			// Vergleich auf max
	itt eq
	ldreq r0,=var_Jahr2			// Jahr2 braucht man auch, da das aktuelle Jahrhundert bis 31.12.2100 geht, Übergabeparameter r0
	bleq check_century_end
// Datum und Uhrzeit ausgeben
	bl print_date_and_time
/* 
Anmerkung, hier wird bewusst nur jede Sekunde gepollt, da es auf eine Sekunde mehr
oder weniger nicht drauf ankommt... Für eine schnellere Reaktionszeit auf die Eingabe
könnte man beim Marker "second_not_over" pollen. Dies hätte aber zur Folge, dass bei jedem
main_loop Durchlauf gepollt werden würde, was mmN zu oft ist. Nachteil ist, dass etwas
verzögert auf Eingaben reagiert wird.
*/
	bl uart_charPresent			// Prüfen, ob ein Zeichen eingegeben wurde
	cmp r0, 0x0					// Prüfen, ob ein Zeichen eingegeben wurde
	it hi						
	blhi evaluate_input			// ja, ansonsten wieder Sprung an den Anfang des Programms
	
second_not_over:

	
	b main_loop


// Eingegebenes Zeichen auswerten	
.thumb_func	
evaluate_input:
	push {lr} 
	bl uart_getChar				// Eingegebenes Zeichen holen
	cmp r0, 's'					// Überprüfe, ob Eingabe ein 's' war
	it ne
	bne eval_time
// Das eingegebene Zeichen war ein 's'
	ldr r1,=var_clock_state		// 
	ldrb r2, [r1]				// Aktuellen Wert der Uhr-Status-Variable aus dem Speicher holen 
	cmp r2, #0x1				// Prüfen, ob die Uhr gerade läuft
	it eq
	beq stop_time				// Ja, Uhr läuft. => Muss gestoppt werden
// Nein, Uhr läuft nicht	
	mov r3, #0x1				// Für Merker, dass Uhrzeit laufen soll
	strb r3, [r1]				// Setze den Merker, dass Uhrzeit laufen soll
	b end						// eingegebenes Zeichen war ein 's' => ENDE

stop_time:				
	mov r3, #0x0				// Variable nullen und 
	strb r3, [r1]				// Im Speicher ablegen => Uhr wird ausgeschaltet  
	b end         				// eingegebenes Zeichen war ein 's' => ENDE

eval_time:
	cmp r0, 't'					// Überprüfe, ob Eingabe ein 't' war
	it ne
	bne eval_date				// eingegebenes Zeichen war kein 't'
// Das eingegebene Zeichen war ein 't'
	ldr r1,=var_time_state		
	mov r3, #0x1				// Für Merker
	strb r3, [r1]				// setze den Merker, dass die Uhrzeit neu eingegeben werden soll
	b end						// eingegebenes Zeichen war ein 't' => ENDE

eval_date:
	cmp r0, 'd'					// Überprüfe, ob Eingabe ein 'd' war
	it ne
	bne end						// eingegebenes Zeichen war kein 'd' => kein gültiges Zeichen eingegeben. => ENDE
// eingegebenes Zeichen war ein d'
	ldr r1,=var_date_state		
	mov r3, #0x1				// Für Merker
	strb r3, [r1]				// setze den Merker, dass das Datum neu eingegeben werden soll
	
end:
	pop {pc} 


// Unterprogramm Uhrzeit und Datumausgabe
.thumb_func
print_date_and_time:
	push {r4-r9,lr}
	ldr r1,=char_Punkt			// Anfangsadresse für Datumausgabe holen
	ldrb r4, [r1], #0x1			// Für Punkt ausgeben
	ldrb r8, [r1], #0x1			// Für Doppelpunkt ausgeben
	ldrb r5, [r1]				// Für Leerzeichen ausgeben
	mov r6, 0x4					// 4 Durchläufe der date_Loop
	ldr r7, =var_Tag			// Anfangsadresse für Datumsausgabe holen
date_Loop:
	ldrb r0, [r7], 0x01			// Tag,Monat,Jahr,Jahr
	cmp r0, #0xA				// Vergleich, falls eine Null zusätzlich ausgegeben werden soll 
	it ge
	bge print_date_without_zero	// Keine Ausgabe für zusätzliche Null nötig, ansonsten
	mov r9,r0					// Den eigentlichen Wert, der ausgegeben werden soll, zwischenspeichern
	mov r0, #0x0				// Zusätzliche Null
	bl uart_putByteBase10		// ausgeben
	mov r0, r9					// Den Zwischengespeicherten Wert holen und
	
print_date_without_zero:	
	bl uart_putByteBase10		// ausgeben
	cmp r6, #0x2				// Bedingung, falls ein Punkt ausgegeben werden soll
	itt hi
	movhi r0, r4				// Punkt
	blhi uart_putChar			// ausgeben
	subs r6, r6, 0x1			// check condition
	bne date_Loop
	
	mov r0, r5					// Leerzeichen
	bl uart_putChar				// ausgeben
	
	ldr r7, =var_Stunde			// Anfangsadresse für Uhrzeitausgabe holen
	mov r6, 0x2					// 2 Durchläufe der clock_Loop
clock_Loop:
	ldrb r0, [r7], #-0x01		// Stunde, Minute
	cmp r0, #0xA				// Vergleich, falls eine Null zusätzlich ausgegeben werden soll
	it ge
	bge print_clock_without_zero// Keine Ausgabe für zusätzliche Null nötig, ansonsten
	mov r9,r0					// Den eigentlichen Wert, der ausgegeben werden soll, zwischenspeichern
	mov r0, #0x0				// Zusätzliche Null
	bl uart_putByteBase10		// ausgeben
	mov r0, r9					// Den Zwischengespeicherten Wert holen und
print_clock_without_zero:	
	bl uart_putByteBase10		// ausgeben
	cmp r6, #0x1				// Bedingung für Doppelpunkt
	itt hi
	movhi r0, r8				// Doppelpunkt
	blhi uart_putChar			// ausgeben
	subs r6, r6, 0x1			// check condition
	bne clock_Loop
	
	ldr r0, =string_Uhr			// String Uhr
	bl uart_putString			// ausgeben
	pop {r4-r9,pc}


// Führt das Inkrementieren und den Overflow durch
// r0 Adresse für Speicherbereich
// r1 Wert auf den Zurückgesetzt werden soll, falls der Max Wert erreicht wurde
// r2 Max Wert
// return r1
.thumb_func
check_overflow_and_inc:
	push {r4, lr}			
    ldrb r4, [r0]		// Wert an der übergebenen Adresse aus dem Speicher laden
	          
	add r4, r4, #0x1	// inkrementieren
	cmp r4, r2			// Mit Max Wert Vergleichen
	ittt hi				// Wenn höher zurücksetzen. Ein Überlauf hat stattgefunden
	movhi r3, r1		// Wert von r1 Zwischenspeichern	
	movhi r1, r4		// Den "Merker", dass ein Überlauf stattgefunden hat in r1 als Rückgabewert	
	movhi r4, r3		// Hier auf den übergebenen Wert zurücksetzen und
	strb r4, [r0]		// Im Speicher ablegen
	pop {r4, pc}
	
// Funktion setzt Datum und Zeit auf Default-Werte, falls das aktuelle Jahrhundert überschritten wurde
// Übergabeparameter r0
.thumb_func
check_century_end:
	push {lr}
	
	ldrb r1,[r0]
	cmp r1,#0x0
	it eq						// Noch in diesem Jahrhundert => 2100
	beq return
// Ansonsten alles auf Init zurücksetzen!
	mov r1, INIT_YR2			// Jahr2
	strb r1, [r0],#-0x1
	mov r1, INIT_YR1			// Jahr1
	strb r1, [r0],#-0x1
	mov r1, INIT_MONTH			// Monat
	strb r1, [r0],#-0x1
	mov r1, INIT_DAY			// Tag
	strb r1, [r0],#-0x1
	mov r1, INIT_HR				// Stunde
	strb r1, [r0],#-0x1	
	mov r1, INIT_MIN			// Minute
	strb r1, [r0]
	ldr r0, =string_Jahrhundert_Ueberschritten
	bl uart_putString
return:
	pop {pc}

// Funktion, um eine zusätzliche Null auszugeben
.thumb_func
print_zero:
	push {lr}
	mov r0, #0x0				// Null
	bl uart_putByteBase10		// ausgeben
	pop {pc}
	
// Funktion für neue Zeile 
.thumb_func
print_new_line:
	push {lr}
	ldr r0, =string_new_line
	bl uart_putString
	pop {pc}
	
// Init Pit, enable interrupts, setting counter value
.thumb_func
pit_init:
	push {lr}
		mov r2, #0x1
	mov r3, #0x0
/*Takt für PIT aktivieren*/	
	ldr r0, =BB_ENABLE_PIT_CLK
	str r2, [r0]
/*Interrupt Vektor zu PIT1 setzen*/
	ldr r0, =IV_PIT1
	ldr r1, =PIT1_IRQHandler
	str r1, [r0]

// pending interrupts zu PIT1 löschen (NVIC)
	ldr r0, =NVIC_ICPR2
	mov r1, (1<<5)				// NVIC IRQn69 => 2*32+5 => NVICISER2 und (1<<5)
	str r1, [r0]
	
/*Interrupt zu PIT1 aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
/* alle PITs aktivieren */
/*Anmerkung: Ein direktes Schreiben einer 0x0 in das MCR Register wäre 
dem Bit Banding vorzuziehen */
	ldr r0, =BB_PIT_MCR_MDIS
	str r3, [r0]
	sub r1, r0, #0x4			// FRZ Register
	str r3, [r1]				// Timers continue to run in debug mode
	
/*PIT1 Startwert 1 sek initialisieren*/	
// 25MHz => 40ns => 1/40ns => 0x17D7840
/*Anmerkung: Mehrere Register werden hier gleichzeitig gesetzt => Deshalb kein Bit Banding*/
	
	ldr r0, =PIT_LDVAL1_ADDR
	ldr r1, =PIT1_COUNTER_VALUE
	str r1, [r0]

/*Interrupt PIT1 aktivieren (PIT-Modul) && PIT1 aktivieren (PIT-Modul)*/
/*Anmerkung: Mehrere Register werden hier gleichzeitig gesetzt => Deshalb kein Bit Banding*/
	ldr r0, =PIT_TCTRL1_ADDR
	mov r1, 0x3					// PIT_TCTRL1 Timer enable, interrupt enable, timer not chained 
	str r1, [r0]

	pop {pc}


.thumb_func	
stop_PIT1:
	push {lr}	
	// The counter period can be restarted, by first disabling, and then enabling the timer with TCTRLn[TEN]
	ldr r0, =BB_PIT_TCTRL1_TEN
	mov r1, #0x0
	str r1, [r0]				// TEN = 0

	pop {pc}

.thumb_func
start_PIT1:				
	push {lr}	
	// The counter period can be restarted, by first disabling, and then enabling the timer with TCTRLn[TEN]
	ldr r0, =BB_PIT_TCTRL1_TEN
	mov r1, #0x1
	str r1, [r0]				// TEN = 1
	
	pop {pc}
	
// PIT1 Interrupt Handler	
.thumb_func
PIT1_IRQHandler:			
/*Anmerkung: Hier werden bewusst nur die Register benutzt, die gesichert werden, damit
nach der ISR keine Inkonsistenz entsteht */
	push {r4-r5, lr}
			
// clear interrupt, writing TIF = 1 in PIT_TFLG1
	ldr r4, =BB_PIT_TFLG1_TIF 		// reset via Bit-Banding
	mov r5, #0x1
	str r5, [r4]
	
// Flag setzen	         
	ldr r4, =var_second_over	
	strb r5, [r4]	// Flag, dass 1 Sek vorbei im Speicher ablegen
	
	pop {r4-r5, pc}
	
	
/*** Datenbereich (ab 0x20000000) ***/
.data

char_Punkt: 	  .byte 0x2E
char_Doppelpunkt: .byte 0x3A
char_Leerzeichen: .byte 0x20

var_Minute: .byte 0x00
var_Stunde: .byte 0x00
var_Tag:    .byte 0x01
var_Monat:  .byte 0x01
var_Jahr1:  .byte 0x14
var_Jahr2:  .byte 0x0E
/*
var_clock_state: .byte 0x00
var_time_state:  .byte 0x00
var_date_state:  .byte 0x00
var_second_over: .byte 0x00
*/
string_Uhr:		  		.asciz " Uhr\n"
string_Stunde_Eingeben: .asciz "\nStunde eingeben ( hh ) : "
string_Minute_Eingeben: .asciz "\nMinuten eingeben ( mm ) : "
string_Tag_Eingeben: 	.asciz "\nTag eingeben ( dd ) : "
string_Monat_Eingeben: 	.asciz "\nMonat eingeben ( mm ) : "
string_Jahr_Eingeben: 	.asciz "\nJahr eingeben ( jj ) : "
string_Jahrhundert_Ueberschritten: .asciz "Jahrhundert wurde ueberschritten. Defaultwerte werden geladen!\n"
string_new_line:		.asciz "\n"


var_clock_state: .byte 0x00
var_time_state:  .byte 0x00
var_date_state:  .byte 0x00
var_second_over: .byte 0x00
	
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified



.equ STRING_TERMINATOR, 0
.equ COUNTER_LOOP, 0x4

.equ CRC_CTRL, 0x40032008
.equ CRC_GPOLY, 0x40032004
.equ CRC_CRC, 0x40032000

.equ CRC_POLYNOM, 0b00000100110000010001110110110111		// CRC32 Polynom
.equ CRC_SEED, 0x12345678

.equ SIM_SCGC6, 0x4004803C
.equ SIM_SCGC6_CRC_POS, 18

.equ CRC_CTRL_TCRC_POS, 24
.equ CRC_CTRL_WAS_POS, 25

__BBREG BB_ENABLE_CRC_CLK, SIM_SCGC6, SIM_SCGC6_CRC_POS
__BBREG BB_SET_32BIT_CRC, CRC_CTRL, CRC_CTRL_TCRC_POS
__BBREG BB_ENABLE_SEED_VALUE, CRC_CTRL, CRC_CTRL_WAS_POS



/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl CRC_init

main_loop:	
	
	ldr r0, =str
	mov r1, #COUNTER_LOOP	
	mov r2, #0x0			// init r2. r2 for one byte from string
	mov r3, #0x0			// init r3. r3 for complete 32 bit word from string
	ldr r4, =CRC_CRC
loop_string:	
	ldrb r2, [r0], #0x1
	cmp r2, #STRING_TERMINATOR	// Check string ende
	beq string_end
	
	lsl r3, r3, #0x8
	orr r3, r3, r2			

	subs r1, r1, #0x1			// check loop condition					
	bne loop_string

	str r3, [r4]				// Calc CRC
	
// loop condition init
    mov r1, #COUNTER_LOOP
	mov r3, #0x0				
	b loop_string

// Das Ende des Strings wurde erreicht. Ein letztes Mal CRC Berechnen, in Abhängigkeit vom "Rest-String"
string_end:
	
	cmp r1, #3				// 1 byte übrig, dass nicht in die Berechnung eingebracht wurde
	it eq
	strbeq r3, [r4] 		
	
	cmp r1, #2				// 2 byte übrig, dass nicht in die Berechnung eingebracht wurden
	it eq
	strheq r3, [r4]
	
	cmp r1, #1				// 3 byte übrig, dass nicht in die Berechnung eingebracht wurden
	itttt eq
	moveq r1, r3			
	lsreq r1, r1, #16		// HL vom Rest-String 
	strbeq r1, [r4]
	strheq r3, [r4]			// LU + LL vom Rest-String
	
/*Terminalausgabe*/	
	ldr r0, =str
	bl uart_putString
	ldr r0, =crc_str
	bl uart_putString
	ldr r0, [r4]
	bl uart_putInt32
	
end:
	b end


.thumb_func
CRC_init:

	mov r2, #0x1		
	mov r3, #0x0		
/* Enable Clock for CRC*/
	ldr r0, =BB_ENABLE_CRC_CLK
	str r2, [r0]
	
/*CRC_CTRL resetten*/ 
	// TOT => 00 => no transposition for writes 
	// TOTR => 00 => no transposition for reads
	// FXOR => 0 => No XOR on reading	
	ldr r0, =CRC_CTRL
	str r3, [r0]
	
/*####### Schritte aus Datenblatt durchführen #######*/

/*Enable 32-bit CRC mode*/
	ldr r0, =BB_SET_32BIT_CRC
	str r2, [r0]
	
/*Write 32-bit polynomial to GPOLY*/
	ldr r0, =CRC_GPOLY
	ldr r1, =CRC_POLYNOM
	str r1, [r0]	
/*Set CTRL[WAS] to program the seed value*/
	ldr r0, =BB_ENABLE_SEED_VALUE
	str r2, [r0]  
/*Write a 32-bit seed to CRC[HU:HL:LU:LL]*/
	ldr r1, =CRC_CRC
	ldr r2, =CRC_SEED
	str r2, [r1]
/*Clear CTRL[WAS] to start writing data values*/	
	str r3, [r0]    
	
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
str: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
crc_str: .asciz "\nBerechnete CRC-Pruefsumme: "

 
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// GPIO Registers
.equ GPIOA_PDOR, 0x400FF000		// Port Data Output Register
.equ GPIOA_PSOR, 0x400FF004		// Port Set Output Register	
.equ GPIOA_PCOR, 0x400FF008		// Port Clear Output Register	
.equ GPIOA_PDDR, 0x400FF014 	// Port Data Direction Register
.equ GPIOA_PDIR, 0x400FF010		// Port Data Input Register 

.equ GPIOE_PDDR, 0x400FF114		// Port Data Direction Register
.equ GPIOE_PDIR, 0x400FF110		// Port Data Input Register 


// MASKS for config Registers
.equ MASK_CLEAR_MUX_PCR, 0xFFFFF8FF // Stellen 8-10 NULL, rest EINS
.equ MASK_PORTA_LED_REGISTERS, 0x30000C00		// Pins 10,11,28,29 EINS, rest NULL 
.equ MASK_CONFIG_PTE_PCR, 0xA0003	// interrupt falling edge, Pull up enable

// MASKS for LED 1 - 4
.equ MASK_LED1, 1
.equ MASK_LED2, 2
.equ MASK_LED3, 4
.equ MASK_LED4, 8
// Interrupt 
.equ IV_PTE, 0x1FFFFFAC			// (IRQn91) => 0x1FFFFE00 + 0x000001AC
.equ IV_PIT1, 0x1FFFFF54		// (IRQn69) => 0x1FFFFE00 + 0x0000_0154
.equ IV_PIT0, 0x1FFFFF50		// (IRQn68) => 0x1FFFFE00 + 0x0000_0150
.equ NVIC_ICPR2, 0xE000E288		
.equ NVIC_ISER2, 0xE000E108
	 
// PIT0
.equ PIT_LDVAL0, 0x40037100
.equ PIT0_COUNTER_VALUE, 125000	// 5ms, debounce
.equ PIT_TFLG0, 0x4003710C
.equ PIT_TFLG0_TIF, 0
.equ PIT_TCTRL0_TEN, 0
.equ PIT_TCTRL0, 0x40037108

// PIT1 
.equ PIT_LDVAL1, 0x40037110
.equ PIT_MCR, 0x40037000
.equ PIT1_COUNTER_VALUE, 25000000
.equ SIM_SCGC6, 0x4004803C
.equ SIM_SCGC6_PIT_POS, 23
.equ PIT_TFLG1, 0x4003711C
.equ PIT_TFLG1_TIF, 0
.equ PIT_TCTRL1, 0x40037118

__BBREG BB_ENABLE_PIT_CLK, SIM_SCGC6, SIM_SCGC6_PIT_POS
__BBREG BB_PIT_TFLG1_TIF, PIT_TFLG1, PIT_TFLG1_TIF

__BBREG BB_PIT_TFLG0_TIF, PIT_TFLG0, PIT_TFLG0_TIF
__BBREG BB_PIT0_ENABLE, PIT_TCTRL0, PIT_TCTRL0_TEN


// REGISTER POSITIONS	
.equ MUX_ALT_GPIO, 8
.equ PORT10, 10		
.equ PORT11, 11
.equ PORT19, 19
.equ PORT26, 26
.equ PORT28, 28
.equ PORT29, 29
.equ PORTE_PCR_ISF_POS, 24

// Pin Control Register n
.equ PORTA_PCR10, 0x40049028
.equ PORTA_PCR11, 0x4004902C
.equ PORTA_PCR28, 0x40049070
.equ PORTA_PCR29, 0x40049074
.equ PORTA_PCR19, 0x4004904C
.equ PORTE_PCR26, 0x4004D068

// Clock
.equ SIM_SCGC5, 0x40048038
.equ SIM_SCGC5_PORTA_POS, 9
.equ SIM_SCGC5_PORTE_POS, 13

__BBREG BB_ENABLE_PORTA_CLK, SIM_SCGC5, SIM_SCGC5_PORTA_POS
__BBREG BB_ENABLE_PORTE_CLK, SIM_SCGC5, SIM_SCGC5_PORTE_POS

__BBREG BB_SET_MUX_ALT_GPIOA_PORT11, PORTA_PCR11, MUX_ALT_GPIO				// LED E1
__BBREG BB_SET_MUX_ALT_GPIOA_PORT28, PORTA_PCR28, MUX_ALT_GPIO				// LED E2
__BBREG BB_SET_MUX_ALT_GPIOA_PORT29, PORTA_PCR29, MUX_ALT_GPIO				// LED E3
__BBREG BB_SET_MUX_ALT_GPIOA_PORT10, PORTA_PCR10, MUX_ALT_GPIO				// LED E4

__BBREG BB_SET_MUX_ALT_GPIOA_PORT19, PORTA_PCR19, MUX_ALT_GPIO			// SW1, black
__BBREG BB_SET_MUX_ALT_GPIOE_PORT26, PORTE_PCR26, MUX_ALT_GPIO			// SW2, green

// GPIO
__BBREG BB_SET_GPIOA_PDDR19, GPIOA_PDDR, PORT19			
__BBREG BB_SET_GPIOE_PDDR26, GPIOE_PDDR, PORT26			


// Interrupt
__BBREG BB_CLEAR_ISF_PORTE26, PORTE_PCR26, PORTE_PCR_ISF_POS		

// LEDs OFF
__BBREG BB_SET_OUTPUT_HIGH_LED4, GPIOA_PSOR, PORT10	
__BBREG BB_SET_OUTPUT_HIGH_LED1, GPIOA_PSOR, PORT11	
__BBREG BB_SET_OUTPUT_HIGH_LED2, GPIOA_PSOR, PORT28	
__BBREG BB_SET_OUTPUT_HIGH_LED3, GPIOA_PSOR, PORT29
// LEDs ON
__BBREG BB_SET_OUTPUT_LOW_LED4, GPIOA_PCOR, PORT10	
__BBREG BB_SET_OUTPUT_LOW_LED1, GPIOA_PCOR, PORT11	
__BBREG BB_SET_OUTPUT_LOW_LED2, GPIOA_PCOR, PORT28
__BBREG BB_SET_OUTPUT_LOW_LED3, GPIOA_PCOR, PORT29


__BBREG BB_GPIOA_PDIR_SW1, GPIOA_PDIR, PORT19
__BBREG BB_GPIOE_PDIR_SW2, GPIOE_PDIR, PORT26

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl init_GPIO
	bl pit_init
		
	ldr r9, =var_Second_Over
	ldr r8, =mod
	mov r11, #0					// Value for Counter
	mov r10, #0					// Immer nützlich		
	mov r12, #1					// Immer nützlich
	mov r7, #0					// Start/Stop. Stop = 0, Start = 1	// SW2
	mov r6, #0					// Count up/down. Up = 0, Down = 1	// SW1
	
main_loop:

	bl check_sw1
	bl check_sw2
	bl reset_mod
	
// Steuerung vom Terminal aus
	bl uart_charPresent
	cmp r0, #0					// Zeichen eingegeben?
	beq no_Input_From_Terminal  // nein
//Ja, Zeichen eingegeben	
	bl uart_getChar
	cmp r0, #'+'
	ittt eq
	moveq r6, #0				// r6 = 0 => Count up
	ldreq r0, =string_Counter_Up
	bleq uart_putString
	
	cmp r0, #'-'
	ittt eq
	moveq r6, #1				// r6 = 1 => Count down
	ldreq r0, =string_Counter_Down
	bleq uart_putString
	
	cmp r0, #'s'
	itt eq
	moveq r0, #2
	strbeq r0, [r8]				// Set mod=2 for start/stop evaluation
	
	
no_Input_From_Terminal:	

// Check Second Over	
	ldrb r0, [r9]
	cmp r0, #1
	bne second_not_over
	
// Second over	
	strb r10, [r9]		// reset second_over_flag

// Check SW pressed
	ldrb r4, [r8]		// Inhalt von mod
	cmp r4, #2			// SW2, green pressed?
	bne sw2_not_pressed
// SW2 pressed
	eor r7, r7, #1		// Flag invertieren
	ldr r0, =var_merker_reset_mod		// for set mod=0
	strb r12, [r0]
// Für String Ausgabe	
	cmp r7, #1			
	ite eq
	ldreq r0, =string_Counter_Start
	ldrne r0, =string_Counter_Stop
	bl uart_putString

sw2_not_pressed:	
	cmp r7, #1			// Counter run?
	bne second_not_over	// nein...
// Counter run
	cmp r4, #1			// SW1, black pressed?
	bne sw1_not_pressed	// nein...
	
// SW1 pressed					
	eors r6, r6, #1		// Flag invertieren
	cmp r6, #1
	ite eq
	ldreq r0, =string_Counter_Down
	ldrne r0, =string_Counter_Up
	bl uart_putString
	
sw1_not_pressed:	 
	cmp r6, #0
	ite eq
	addeq r11, r11, #1	// inc counter
	subne r11, r11, #1  // dec counter
	
/* die unteren 4 Bits prüfen */

//LED1
	mov r0, #MASK_LED1				// 0b0001 Filter für Erkennung, ob Bit gesetzt
	and r1, r11, r0					// Counter Wert mit Maske "filtern"
	cmp r1, #MASK_LED1				// War das entsprechende Bit gesetzt? 
	ittee eq						
	ldreq r2, =BB_SET_OUTPUT_LOW_LED1
	streq r12, [r2]		// LED E1 ON		// Falls ja, LED on
	ldrne r2, =BB_SET_OUTPUT_HIGH_LED1
	strne r12, [r2]		// LED E1 OFF		// Falls nein, LED off
//LED2	
	mov r0, #MASK_LED2				// 0b0010
	and r1, r11, r0
	cmp r1, #MASK_LED2
	ittee eq
	ldreq r2, =BB_SET_OUTPUT_LOW_LED2
	streq r12, [r2]		// LED E2 ON	
	ldrne r2, =BB_SET_OUTPUT_HIGH_LED2
	strne r12, [r2]		// LED E2 OFF
//LED3	
	mov r0, #MASK_LED3				// 0b0100
	and r1, r11, r0
	cmp r1, #MASK_LED3
	ittee eq
	ldreq r2, =BB_SET_OUTPUT_LOW_LED3
	streq r12, [r2]		// LED E3 ON	
	ldrne r2, =BB_SET_OUTPUT_HIGH_LED3
	strne r12, [r2]		// LED E3 OFF	
//LED4	
	mov r0, #MASK_LED4				// 0b1000
	and r1, r11, r0
	cmp r1, #MASK_LED4
	ittee eq
	ldreq r2, =BB_SET_OUTPUT_LOW_LED4
	streq r12, [r2]		// LED E4 ON	
	ldrne r2, =BB_SET_OUTPUT_HIGH_LED4
	strne r12, [r2]		// LED E4 OFF	

// Print Counter
	ldr r0, =string_Counter
	bl uart_putString
	mov r0, r11
	bl uart_putByteBase10

	ldr r0, =var_merker_reset_mod		// for set mod=0
	strb r12, [r0]	

second_not_over:	
	
	b main_loop
	
.thumb_func
check_sw1:
	ldr r0, =BB_GPIOA_PDIR_SW1	// black SW
	ldrb r1, [r0]
	
// für softwaretechnische Erkennung fallende Flanke und damit, falls SW1 gedrückt gehalten wird nicht immer Zählrichtung geändert wird	
    cmp r1, #1
	itt eq
	ldreq r2, =sw1_was_high	
	strbeq r1, [r2]	
   
    cmp r1, #0				// Pegel prüfen,
	bne switch1_not_pressed
	ldr r2, =sw1_was_high
	ldrb r3, [r2]
	cmp r3, #1				// sw1 war mal high, jetzt low => fallende Flanke
	bne switch1_not_pressed
	
// check PIT0 running? 
	ldr r0, =BB_PIT0_ENABLE
	ldr r1, [r0]
	cmp r1, #1
	itt ne
	movne r1, #1
	strbne r1, [r0]			// enable pit0, 5ms for debouncing	

// Check 5 ms over?	
	ldr r2, =var_5ms_Over
	ldrb r3, [r2]
	cmp r3, #1
	bne switch1_not_pressed
// 5 ms over
	mov r1, #0
	strb r1, [r2]			// reset var_5ms_Over
	strb r1, [r0]			// turn off pit0
	ldr r2, =sw1_was_high
	strb r1, [r2]			// sw1_was_high resetten
	
	ldr r1, =BB_GPIOA_PDIR_SW1
	ldrb r1, [r1]
	cmp r1, #0				// Ist Pegel noch unten?
	bne switch1_not_pressed	


	ldr r0, =mod
	mov r1, #1
	strb r1, [r0]			// set mod=1

switch1_not_pressed:
    bx lr

.thumb_func
check_sw2:
	ldr r0, =flag_SW2_interrupt
	ldrb r1, [r0]
	cmp r1, #1
	bne switch2_not_pressed
	
// check PIT0 running? 
	ldr r2, =BB_PIT0_ENABLE
	ldr r1, [r2]
	cmp r1, #1
	itt ne
	movne r1, #1
	strbne r1, [r2]	// enable pit0, 5ms for debouncing	

// Check 5 ms over?		
	ldr r2, =var_5ms_Over
	ldrb r3, [r2]
	cmp r3, #1
	bne switch2_not_pressed
	
// 5 ms over
	mov r1, #0
	strb r1, [r2]			// reset var_5ms_Over
	strb r1, [r0]			// reset flag_SW2_interrupt
	ldr r2, =BB_PIT0_ENABLE	
	strb r1, [r2]			// turn off pit0
	
	ldr r1, =BB_GPIOE_PDIR_SW2
	ldrb r1, [r1]
	
	cmp r1, #0				// Ist Pegel noch unten?
	bne switch2_not_pressed
	mov r1, #2
	ldr r0, =mod
	strb r1, [r0]			// set mod=2	
switch2_not_pressed:	

	bx lr


	
.thumb_func	
reset_mod:
	ldr r0, =var_merker_reset_mod
	ldrb r1, [r0]
	cmp r1, #1
	itttt eq
	moveq r1, #0
	strbeq r1, [r0]			// var_merker_reset_mod reset
	ldreq r0, =mod
	strbeq r1, [r0]			// mod = 0
	
	bx lr

.thumb_func
init_GPIO:
	mov r3, #1
	
/*Enable Clock*/	
// Anmerkung: Hier wird Bit Banding verwendet, da es übersichtlicher ist, und 
// keine OR-Operation mit dem bisherigen Registerwert notwendig ist, um die 
// usprünglichen Werte beizubehalten
	
	ldr r0, =BB_ENABLE_PORTA_CLK
	str r3, [r0]
	ldr r0, =BB_ENABLE_PORTE_CLK
	str r3, [r0]
	
/* PTA 10, 11, 28, 29 als output setzen  */
	ldr r0, =GPIOA_PDDR
	ldr r1, =MASK_PORTA_LED_REGISTERS
	ldr r2, [r0]
	orr r2, r2, r1
	str r2, [r0]
/* PTA 19 als input setzen  */
	ldr r0, =BB_SET_GPIOA_PDDR19
	mov r1, #0 
	str r1, [r0]
/* PTE 26 als input setzen  */
	ldr r0, =BB_SET_GPIOE_PDDR26
	mov r1, #0 
	str r1, [r0]
	
/* Clear Mux PORTA 10, 11, 28, 29, 19, PORTE 26 */
	ldr r0, =PORTA_PCR10
	ldr r1, =MASK_CLEAR_MUX_PCR
	ldr r2, [r0]
	and r2, r2, r1
	str r2, [r0]

	ldr r0, =PORTA_PCR11
	ldr r2, [r0]
	and r2, r2, r1
	str r2, [r0]
	
	ldr r0, =PORTA_PCR28
	ldr r2, [r0]
	and r2, r2, r1
	str r2, [r0]
	
	ldr r0, =PORTA_PCR29
	ldr r2, [r0]
	and r2, r2, r1
	str r2, [r0]
	
	ldr r0, =PORTA_PCR19
	ldr r2, [r0]
	and r2, r2, r1
	str r2, [r0]
	
	ldr r0, =PORTE_PCR26
	ldr r2, [r0]
	and r2, r2, r1
	str r2, [r0]

/* Set Alternative 1 (GPIO)	PORTA 10, 11, 28, 29, 19, PORTE 26 */
	ldr r0, =BB_SET_MUX_ALT_GPIOA_PORT10
	str r3, [r0]	
	ldr r0, =BB_SET_MUX_ALT_GPIOA_PORT11
	str r3, [r0]
	ldr r0, =BB_SET_MUX_ALT_GPIOA_PORT28
	str r3, [r0]
	ldr r0, =BB_SET_MUX_ALT_GPIOA_PORT29	
	str r3, [r0]
	ldr r0, =BB_SET_MUX_ALT_GPIOA_PORT19
	str r3, [r0]
	ldr r0, =BB_SET_MUX_ALT_GPIOE_PORT26
	str r3, [r0]
	
/* PTA 10, 11, 28, 29 Logic Level 1, damit LEDs bei Beginn nicht leuchten */	
	ldr r0, =GPIOA_PDOR
	ldr r1, =MASK_PORTA_LED_REGISTERS	
	ldr r2, [r0]
	orr r2, r2, r1
	str r2, [r0]	
	
/* Config PTE26, enable interrupt falling edge, Pull up enable */
    ldr r0, =PORTE_PCR26
	ldr r1, =MASK_CONFIG_PTE_PCR
	ldr r2, [r0]
	orr r2, r2, r1
	str r2, [r0]
	
/*Interrupt Vektor zu PTE setzen*/
	ldr r0, =IV_PTE
	ldr r1, =PTE_IRQHandler
	str r1, [r0]
/* pending interrupts zu PTE löschen (NVIC) */
	ldr r0, =NVIC_ICPR2
	mov r1, (1<<27)				// NVIC IRQn91 => 2*32+27 => NVICISER2 und (1<<27)
	str r1, [r0]
	
/*Interrupt zu PTE aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]

	bx lr
/* Init Pit, enable interrupts, setting counter value */
.thumb_func
pit_init:

/*Takt für PIT aktivieren*/	
	ldr r0, =BB_ENABLE_PIT_CLK
	str r2, [r0]
	
/* #################### PIT1 ####################*/
/*Interrupt Vektor zu PIT1 setzen*/
	ldr r0, =IV_PIT1
	ldr r1, =PIT1_IRQHandler
	str r1, [r0]

/* pending interrupts zu PIT1 löschen (NVIC) */
	ldr r0, =NVIC_ICPR2
	mov r1, (1<<5)				// NVIC IRQn69 => 2*32+5 => NVICISER2 und (1<<5)
	str r1, [r0]
	
/*Interrupt zu PIT1 aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]

		
/*PIT1 Startwert 1 sek initialisieren*/	
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT1_COUNTER_VALUE
	str r1, [r0]

/*Interrupt PIT1 aktivieren (PIT-Modul) && PIT1 aktivieren (PIT-Modul)*/
	ldr r0, =PIT_TCTRL1
	mov r1, #3					
	str r1, [r0]	// PIT_TCTRL1 Timer enable, interrupt enable, timer not chained 
	
/* #################### PIT0 ####################*/
// Anmerkung. Merhmaliges Laden von NVIC_ICPR2 und NVIC_ISER2 wurde bewusst gemacht,
// um die Initialisierung von PIT0 und PIT1 separat durchzuführen

/*Interrupt Vektor zu PIT0 setzen*/
	ldr r0, =IV_PIT0
	ldr r1, =PIT0_IRQHandler
	str r1, [r0]
	
/* pending interrupts zu PIT0 löschen (NVIC) */
	ldr r0, =NVIC_ICPR2
	mov r1, (1<<4)				// NVIC IRQn68 => 2*32+4 => NVICISER2 und (1<<4)
	str r1, [r0]	
	
/*Interrupt zu PIT0 aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
/*PIT0 Startwert 5 ms initialisieren*/	
	ldr r0, =PIT_LDVAL0
	ldr r1, =PIT0_COUNTER_VALUE
	str r1, [r0]
	
/*Interrupt PIT0 aktivieren (PIT-Modul) && PIT0 aktivieren (PIT-Modul)*/
	ldr r0, =PIT_TCTRL0					
	mov r1, #2
	str r1, [r0]		// PIT_TCTRL0 Timer disable, interrupt enable, timer not chained 

	
/* alle PITs aktivieren */	
	ldr r0, =PIT_MCR
	mov r1, #0
	str r1, [r0]

	bx lr
/* PIT1 Interrupt Handler */	
.thumb_func
PIT1_IRQHandler:				
/* clear interrupt */
	ldr r0, =BB_PIT_TFLG1_TIF 
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =var_Second_Over
	strb r1, [r0]		// Flag, dass Sekunde vorbei ist aktualisieren
	
	bx lr
/* PIT0 Interrupt Handler */	
.thumb_func
PIT0_IRQHandler:				
/* clear interrupt */
	ldr r0, =BB_PIT_TFLG0_TIF 
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =var_5ms_Over
	strb r1, [r0]		// Flag, dass Sekunde vorbei ist aktualisieren
	
	
	bx lr
/* PTE Interrup Handler */
.thumb_func
PTE_IRQHandler:
	ldr r0, =BB_CLEAR_ISF_PORTE26
    ldrb r2, [r0]
    cmp r2, #1				// Abfragen, ob PORTE26 Interrupt
    ittt eq
    streq r2, [r0]			/* clear interrupt */
	ldreq r0, =flag_SW2_interrupt
	strbeq r2, [r0]
	
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
var_Second_Over: .byte 0
var_5ms_Over: .byte 0	
flag_SW2_interrupt: .byte 0
mod: .byte 0
var_merker_reset_mod: .byte 0
sw1_was_high: .byte 0

string_Counter: .asciz "\nZaehlerstand: "
string_Counter_Start: .asciz "\nCounter start"
string_Counter_Stop: .asciz "\nCounter stop"
string_Counter_Up: .asciz "\nCount up"
string_Counter_Down: .asciz "\nCount down"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Pin Control Register n
.equ PORTA_PCR10, 0x40049028
.equ PORTA_PCR11, 0x4004902C
.equ PORTA_PCR28, 0x40049070
.equ PORTA_PCR29, 0x40049074

.equ MASK_SET_MUX_ALT1_PCR, 0x00000100			// 8. Bit EINS => Alternate 1 GPIO
.equ MASK_PORTA_LED_REGISTERS, 0x30000C00		// Pins 10,11,28,29 EINS, rest NULL 

// GPIO Registers
.equ GPIOA_PDOR, 0x400FF000		// Port Data Output Register
.equ GPIOA_PSOR, 0x400FF004		// Port Set Output Register	
.equ GPIOA_PCOR, 0x400FF008		// Port Clear Output Register	
.equ GPIOA_PDDR, 0x400FF014 	// Port Data Direction Register

// LEDs OFF
__BBREG BB_SET_OUTPUT_HIGH_LED4, GPIOA_PSOR, 10	
__BBREG BB_SET_OUTPUT_HIGH_LED1, GPIOA_PSOR, 11	
__BBREG BB_SET_OUTPUT_HIGH_LED2, GPIOA_PSOR, 28	
__BBREG BB_SET_OUTPUT_HIGH_LED3, GPIOA_PSOR, 29
// LEDs ON
__BBREG BB_SET_OUTPUT_LOW_LED4, GPIOA_PCOR, 10	
__BBREG BB_SET_OUTPUT_LOW_LED1, GPIOA_PCOR, 11	
__BBREG BB_SET_OUTPUT_LOW_LED2, GPIOA_PCOR, 28
__BBREG BB_SET_OUTPUT_LOW_LED3, GPIOA_PCOR, 29


// Clock PortA
.equ SIM_SCGC5, 0x40048038
__BBREG BB_ENABLE_PORTA_CLK, SIM_SCGC5, 9			// Clock Port A

// Interrupt
.equ IV_PIT1, 0x1FFFFF54		// (IRQn69) => 0x1FFFFE00 + 0x0000_0154
.equ NVIC_ICPR2, 0xE000E288		
.equ NVIC_ISER2, 0xE000E108
// PIT1 
.equ PIT_LDVAL1, 0x40037110		
.equ PIT_MCR, 0x40037000
.equ PIT1_COUNTER_VALUE, 25000000	// 1 Sec
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TFLG1, 0x4003711C
__BBREG BB_PIT_TFLG1_TIF, PIT_TFLG1, 0			// Timer Interrupt Flag

// Clock PIT1
.equ SIM_SCGC6, 0x4004803C
__BBREG BB_ENABLE_PIT_CLK, SIM_SCGC6, 23		// SCGC6_PIT


// ADC
.equ ADC1_SC3,  0x400BB024
.equ ADC1_SC1A, 0x400BB000

.equ ADC1_CLP0, 0x400BB04C
.equ ADC1_CLP1, 0x400BB048
.equ ADC1_CLP2, 0x400BB044
.equ ADC1_CLP3, 0x400BB040
.equ ADC1_CLP4, 0x400BB03C
.equ ADC1_CLPS, 0x400BB038
.equ ADC1_PG, 	0x400BB02C

.equ ADC1_RA, 0x400BB010	// Data Result Register

.equ ADC1_CFG1, 0x400BB008
.equ ADC_CHANNEL_20, 20

.equ ADC1_CFG_16BIT, 0x6C	 // Bus Clock/8 => 3,125 MHz, 16 bit conversion, short sample time, normal power configuration
.equ ADC1_CFG_12BIT, 0x64	 // Bus Clock/8 => 3,125 MHz, 12 bit conversion, short sample time, normal power configuration
.equ ADC1_CFG_10BIT, 0x68	 // Bus Clock/8 => 3,125 MHz, 10 bit conversion, short sample time, normal power configuration
.equ ADC1_CFG_8BIT,  0x60	 // Bus Clock/8 => 3,125 MHz, 8 bit conversion, short sample time, normal power configuration

.equ CAL_MASK, 0x87 		// For ADC1 SC3[AVGE]=1 and SC3[AVGS]=11, SC3[CAL]=1 in calibration mode
.equ ADC1_SC3_MASK, 0xE		// For ADC1 SC3[ADCO]=1 SC3[AVGE]=1 and SC3[AVGS]=10 in init mode
.equ MSB_16BIT, 0x8000	

// Clock ADC1
.equ SIM_SCGC3, 0x40048030
.equ SIM_SCGC3_ADC1_POS, 27
__BBREG BB_ENABLE_ADC1_CLK, SIM_SCGC3, SIM_SCGC3_ADC1_POS

__BBREG BB_CHECK_ADC1_CALF, ADC1_SC3, 6			// CALF
__BBREG BB_CHECK_ADC1_CAL, ADC1_SC3, 7			// CAL

// Resoultion
.equ RES_8BIT, 0
.equ RES_10BIT, 1
.equ RES_12BIT, 2
.equ RES_16BIT, 3

// MASKS for LED 1 - 4
.equ MASK_LED1, 1
.equ MASK_LED2, 2
.equ MASK_LED3, 4
.equ MASK_LED4, 8
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:	
	bl uart_init
	bl calibrate_and_init_adc1	
	ldr r0, =str_cal_finished
	bl uart_putString	
	bl pit1_init
	bl init_GPIO
	
	ldr r9, =var_Second_Over
	ldr r12, =ADC1_RA
	mov r10, #0
	mov r11, #1 	
	mov r8, #0						// for ADC start/stop evaluation
	ldr r7, =var_resolution_mode	// for checking mode 

main_loop:	
// Check Second Over	
	ldrb r0, [r9]
	cmp r0, #1
	bne main_loop		// second not over
// Second over	
	strb r10, [r9]		// reset second_over_flag
// Steuerung vom Terminal aus
	bl uart_charPresent			// Zeichen eingegeben?
	cmp r0, #0
	beq no_Input_From_Terminal	// Nein, kein Zeichen eingegeben
//Ja, Zeichen eingegeben	
	bl uart_getChar
	mov r4, r0
	cmp r4, #'s'
	bne check_resolution		// 's' wurde nicht eingegeben
	it eq						// 's' wurde eingegeben
	eoreq r8, #1				// toggle start/stop 	

// start or stop mode?	
	cmp r8, #1
	bne stop_mode	
// Start Mode	
	ldr r0, =str_start
	bl uart_putString			// ADC Start String ausgeben
	
// Aktuelle ausgewählte Auflösung soll nur beim ADC-Start ausgeben	
	ldrb r2, [r7]					// for check which resolution is set
	
	cmp r2, #RES_8BIT
	itt eq
	ldreq r0, =str_8bit_resolution
	beq print_actual_resolution 

	cmp r2, #RES_10BIT
	itt eq
	ldreq r0, =str_10bit_resolution
	beq print_actual_resolution

	cmp r2, #RES_12BIT
	itt eq
	ldreq r0, =str_12bit_resolution
	beq print_actual_resolution

	cmp r2, #RES_16BIT
	it eq
	ldreq r0, =str_16bit_resolution
print_actual_resolution:	
	bl uart_putString
	b no_Input_From_Terminal
	
stop_mode:
// ADC stop String ausgeben
	ldr r0, =str_stop
	bl uart_putString

check_resolution:
	cmp r8, #0						// stop mode?
	bne no_Input_From_Terminal
	ldr r5, =ADC1_CFG1				// for resolution
	ldr r6, =ADC1_SC1A				// stop/start ADC Conversion
		
//Turn all LEDs OFF
	ldr r1, =BB_SET_OUTPUT_HIGH_LED4
	str r11, [r1]	
	ldr r1, =BB_SET_OUTPUT_HIGH_LED1	
	str r11, [r1]
	ldr r1, =BB_SET_OUTPUT_HIGH_LED2	
	str r11, [r1]
	ldr r1, =BB_SET_OUTPUT_HIGH_LED3
	str r11, [r1]
// 8 BIT => N=8
	cmp r4, #0x30					
	bne check_10_bit
// set resolution mode 
	mov r1, #RES_8BIT				
	strb r1, [r7]
// stop ADC Conversion
	mov r2, #ADC_CHANNEL_20	
	str r2, [r6]
// Change resolution to 8 bit
	mov r1, #ADC1_CFG_8BIT		
	str r1, [r5]
// start ADC Conversion
	str r2, [r6]
// String Terminal output 8bit resolution   
	ldr r0, =str_8bit_resolution
	bl uart_putString
	
	b no_Input_From_Terminal		// end Terminal
	
check_10_bit:
// 10 BIT => N=10	
	cmp r4, #0x31
	bne check_12_bit	
// set resolution mode 
	mov r1, #RES_10BIT
	strb r1, [r7]	
// stop ADC Conversion
	ldr r0, =ADC1_SC1A
	mov r2, #ADC_CHANNEL_20		
	str r2, [r0]
// Change resolution to 10 bit
	mov r1, #ADC1_CFG_10BIT
	str r1, [r5]
// start ADC Conversion
	str r2, [r0]
// String Terminal output 10bit resolution 
	ldr r0, =str_10bit_resolution
	bl uart_putString
	
	b no_Input_From_Terminal		// end Terminal
check_12_bit:
// 12 BIT => N=12
	cmp r4, #0x32
	bne check_16_bit
// set resolution mode 
	mov r1, #RES_12BIT
	strb r1, [r7]	
// stop ADC Conversion
	ldr r0, =ADC1_SC1A
	mov r2, #ADC_CHANNEL_20				
	str r2, [r0]
// Change resolution to 12 bit
	mov r1, #ADC1_CFG_12BIT
	str r1, [r5]
// start ADC Conversion
	str r2, [r0]
// String Terminal output 12bit resolution
	ldr r0, =str_12bit_resolution
	bl uart_putString
	
	b no_Input_From_Terminal		// end Terminal
check_16_bit:
// 16 BIT => N=16
	cmp r4, #0x33
	bne no_Input_From_Terminal
// set resolution mode	
	mov r1, #RES_16BIT
	strb r1, [r7]	
// stop ADC Conversion
	ldr r0, =ADC1_SC1A
	mov r2, #ADC_CHANNEL_20		
	str r2, [r0]
// Change resolution to 16 bit
	mov r1, #ADC1_CFG_16BIT
	str r1, [r5]
// start ADC Conversion	
	str r2, [r6]			
// String Terminal output 16bit resolution		
	ldr r0, =str_16bit_resolution
	bl uart_putString

// Keine Terminaleingabe 
no_Input_From_Terminal:	
	cmp r8, #1				// check start/stop		
	bne	main_loop
		
start_conversion:
// Print "0x"
	ldr r0, =str_hex
	bl uart_putString
	
// Check resolution mode
	ldrb r0, [r7]
	cmp r0, #RES_8BIT
	bne Check_10_bit
	
// Resolution is 8 Bit
	ldr r5, =array_8Bit		// Array mit Bereichswerten bei 8 Bit Auflösung
	ldrb r0, [r12]			// get adc result
	mov r4, r0				// save adc result
    bl uart_putInt16		// print adc result
// Bereich checken
    mov r0, #0				// Für Anzahl der Durchläufe tracken 
print_loop_8bit:	
	ldrb r6, [r5], #1		// Wert des entsprechenden Bereichs holen und post increment für den nächsten Durchlauf		
	add r0, r0, #1			// Anzahl Durchläufe inkrementieren
	cmp r4, r6				// Ist der aktuelle ADC-Wert Höher als der aktuelle Wert aus dem Array? 
	bhi print_loop_8bit		// Falls ja, nächster Durchgang mit dem Nächshöheren Wert aus dem Bereichsarray
// Falls nein, ist der aktuelle Bereich gefunden
	sub r4, r0, #1			// damit Stufe passt
	mov r0, r4				// Übergabeparameter für die Visualisierung
	lsl r4, #2				// Offset, vielfaches von 4 für korrekten String-Array
	bl visualize			// visualisieren über LEDs
// passenden String ausgeben
	ldr r0, =str_array_8_bit
	add r0, r0, r4			// offset drauf rechnen, für die Korrekte Stringadresse
	ldr r0, [r0]			// Inhalt ist die Adresse des passenden Strings
	bl uart_putString		
	
	b main_loop				// ende
Check_10_bit:
	cmp r0, #RES_10BIT
	bne Check_12_bit
// Resolution is 10 Bit
	ldr r5, =array_10Bit	// Array mit Bereichswerten bei 10 Bit Auflösung
	ldrh r0, [r12]			// get adc result
	mov r4, r0				// save adc result
    bl uart_putInt16		// print adc result
// Bereich checken
    mov r0, #0				// Für Anzahl der Durchläufe tracken
print_loop_10bit:	
	ldrh r6, [r5], #2		// Wert des entsprechenden Bereichs holen und post increment für den nächsten Durchlauf	
	add r0, r0, #1			// Anzahl Durchläufe inkrementieren
	cmp r4, r6				// Ist der aktuelle ADC-Wert Höher als der aktuelle Wert aus dem Array? 
	bhi print_loop_10bit	// Falls ja, nächster Durchgang mit dem Nächshöheren Wert aus dem Bereichsarray
// Falls nein, ist der aktuelle Bereich gefunden	
	sub r4,r0,#1			// damit Stufe passt
	mov r0, r4				// Übergabeparameter für die Visualisierung
	lsl r4, #2				// Offset, vielfaches von 4 für String-Array
	
	bl visualize			// visualisieren über LEDs
	
// passenden String ausgeben
	ldr r0, =str_array_10_bit
	add r0, r0, r4			// offset drauf rechnen, für die Korrekte Stringadresse
	ldr r0, [r0]			// Inhalt ist die Adresse des passenden Strings
	bl uart_putString	
	
	b main_loop			// ende
Check_12_bit:
	cmp r0, #RES_12BIT
	bne Check_16_bit
// Resolution is 12 Bit
	ldr r5, =array_12Bit	// Array mit Bereichswerten bei 12 Bit Auflösung
	ldrh r0, [r12]			// get adc result
	mov r4, r0				// save adc result
    bl uart_putInt16		// print adc result
// Bereich checken
    mov r0, #0				// Für Anzahl der Durchläufe tracken
print_loop_12bit:	
	ldrh r6, [r5], #2		// Wert des entsprechenden Bereichs holen und post increment für den nächsten Durchlauf
	add r0, r0, #1			// Anzahl Durchläufe inkrementieren
	cmp r4, r6				// Ist der aktuelle ADC-Wert Höher als der aktuelle Wert aus dem Array? 
	bhi print_loop_12bit	// Falls ja, nächster Durchgang mit dem Nächshöheren Wert aus dem Bereichsarray
// Falls nein, ist der aktuelle Bereich gefunden	
	sub r4, r0, #1			// damit Stufe passt
	mov r0, r4				// Übergabeparameter für die Visualisierung
	lsl r4, #2				// Offset, vielfaches von 4 für String-Array
	
	bl visualize			// visualisieren über LEDs
	
// passenden String ausgeben
	ldr r0, =str_array_12_bit
	add r0, r0, r4			// offset drauf rechnen, für die Korrekte Stringadresse
	ldr r0, [r0]			// Inhalt ist die Adresse des passenden Strings
	bl uart_putString	
	
	b main_loop				// ende
	
Check_16_bit:
	cmp r0, #RES_16BIT		// Array mit Bereichswerten bei 16 Bit Auflösung
	bne main_loop			
// Resolution is 16 Bit
	ldr r5, =array_16Bit	
	ldrh r0, [r12]			// get adc result
	mov r4, r0				// save adc result
    bl uart_putInt16		// print adc result
// Bereich checken
    mov r0, #0				// Für Anzahl der Durchläufe tracken
print_loop_16bit:			
	ldrh r6, [r5], #2		// Wert des entsprechenden Bereichs holen und post increment für den nächsten Durchlauf
	add r0, r0, #1			// Anzahl Durchläufe inkrementieren
	cmp r4, r6				// Ist der aktuelle ADC-Wert Höher als der aktuelle Wert aus dem Array? 
	bhi print_loop_16bit	// Falls ja, nächster Durchgang mit dem Nächshöheren Wert aus dem Bereichsarray
// Falls nein, ist der aktuelle Bereich gefunden		
	sub r4, r0, #1			// damit Stufe passt
	mov r0, r4				// Übergabeparameter für die Visualisierung
	lsl r4, #2				// Offset, vielfaches von 4 für String-Array

	bl visualize			// visualisieren über LEDs
	
// passenden String ausgeben
	ldr r0, =str_array_16_bit
	add r0, r0, r4			// offset drauf rechnen, für die Korrekte Stringadresse
	ldr r0, [r0]			// Inhalt ist die Adresse des passenden Strings
	bl uart_putString	
	
	b main_loop

/*
Funktion soll anhand der momentanen ADC Stufe LEDs an/aus-schalten
Übergabe in r0: Momentante Stufe
Rückgabe: keine
*/
.thumb_func
visualize:
	mov r3, #1
	
	ands r1, r0, #MASK_LED1	
	ite ne								
	ldrne r2, =BB_SET_OUTPUT_LOW_LED1	// LED E1 ON
	ldreq r2, =BB_SET_OUTPUT_HIGH_LED1	// LED E2 OFF
	str r3, [r2]
	
	ands r1, r0, #MASK_LED2
	ite ne								
	ldrne r2, =BB_SET_OUTPUT_LOW_LED2	// LED E1 ON
	ldreq r2, =BB_SET_OUTPUT_HIGH_LED2	// LED E2 OFF
	str r3, [r2]
	
	ands r1, r0, #MASK_LED3	
	ite ne								
	ldrne r2, =BB_SET_OUTPUT_LOW_LED3	// LED E1 ON
	ldreq r2, =BB_SET_OUTPUT_HIGH_LED3	// LED E2 OFF
	str r3, [r2]
	
	ands r1, r0, #MASK_LED4	
	ite ne								
	ldrne r2, =BB_SET_OUTPUT_LOW_LED4	// LED E1 ON
	ldreq r2, =BB_SET_OUTPUT_HIGH_LED4	// LED E2 OFF
	str r3, [r2]
	
	bx lr


/*
Diese Funktion führt die Kalibrierung des ADC1 durch.
Übergabe: keine
Rückgabe: keine
*/
.thumb_func	
calibrate_and_init_adc1:
	mov r2, #1
	/* Enable clock ADC1 */
	ldr r0, =BB_ENABLE_ADC1_CLK
	str r2, [r0]
/*
// Auszug aus dem Datenblatt:
For best calibration results:
• Set hardware averaging to maximum, that is, SC3[AVGE]=1 and SC3[AVGS]=11
for an average of 32
• Set ADC clock frequency f ADCK less than or equal to 4 MHz
• V REFH =V DDA
• Calibrate at nominal voltage and temperature
*/	
	ldr r2, =ADC1_CFG1
	mov r1, #0x60		// Bus Clock/8 => 3,125 MHz
	str r1, [r2]		
	
// initiate calibration	
	ldr r3, =ADC1_SC3
	mov r1, #CAL_MASK	// Enable and Set hardware averaging to max, set calibration flag
	str r1, [r3]		

/*1. Initialize or clear a 16-bit variable in RAM*/
//  Es wird alles im Register R1 zwischengespeichert werden			

 // Warte, bis Kalibrierung vorbei 
    ldr r0,=BB_CHECK_ADC1_CAL
wait_for_calibration:	
	ldr r1, [r0]
	cmp r1, #0
	bne wait_for_calibration

/* 2. Add the plus-side calibration results CLP0, CLP1, CLP2, CLP3, CLP4, and CLPS to the variable */			
	mov r1, #0
	ldr r0, =ADC1_CLP0
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLP1
	ldr r0, [r0]
	add r1, r1, r0 
	ldr r0, =ADC1_CLP2
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLP3
	ldr r0, [r0]
	add r1, r1, r0 
	ldr r0, =ADC1_CLP4
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLPS
	ldr r0, [r0]
	add r1, r1, r0 
/* 3. Divide the variable by two */
	lsr r1, r1, #1
/* 4. Set the MSB of the variable */
	orr r1, r1, #MSB_16BIT
/* 6. Store the value in the plus-side gain calibration register PG */
	ldr r0, =ADC1_PG
	strh r1, [r0]
/* 7. Repeat the procedure for the minus-side gain calibration value */
	//ignored in single-ended mode...

// at the end of calibration routine check whether calibration succeeded	
	ldr r0, =BB_CHECK_ADC1_CALF
	ldr r0, [r0]
	cmp r0, #0
	beq calibration_done
	ldr r0, =str_cal_failed
	bl uart_putString
endless_loop: 
	b endless_loop

// Init ADC
calibration_done:
	mov r1, #ADC1_SC3_MASK	 	// ADCO = enabled, AVGE=enabled, AVGS= 16 samples
	str r1, [r3]	
				
	mov r1, #ADC1_CFG_16BIT		// Bus Clock/8 => 3,125 MHz, 16 bit conversion, short sample time, normal power configuration
	str r1, [r2]
	
	ldr r0, =ADC1_SC1A
	mov r1, #ADC_CHANNEL_20		// interrupt disabled, single ended conversion, ADC channel 20
	str r1, [r0]	
					
	bx lr

/* Init Pit, enable interrupts, setting counter values */
.thumb_func
pit1_init:

/*Takt für PIT aktivieren*/	
	mov r2, #1
	ldr r0, =BB_ENABLE_PIT_CLK
	str r2, [r0]
	
/*Interrupt Vektor zu PIT1 setzen*/
	ldr r0, =IV_PIT1
	ldr r1, =PIT1_IRQHandler
	str r1, [r0]
	
// pending interrupts zu PIT1 löschen (NVIC)
	ldr r0, =NVIC_ICPR2
	mov r1, #(1<<5)				// NVIC IRQn69 => 2*32+5 => NVIC_ICPR2 und (1<<5)
	str r1, [r0]				
	
/*Interrupt zu PIT1 aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]
		
/*PIT1 Startwert 1 sek initialisieren*/	
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT1_COUNTER_VALUE
	str r1, [r0]

/*Interrupt PIT1 aktivieren (PIT-Modul) && PIT1 aktivieren (PIT-Modul)*/
	ldr r0, =PIT_TCTRL1
	mov r1, #3					
	str r1, [r0]		// PIT_TCTRL1 Timer enable, interrupt enable, timer not chained 
	
/* alle PITs aktivieren */	
	ldr r0, =PIT_MCR
	mov r1, #0
	str r1, [r0]
	
	bx lr

.thumb_func
init_GPIO:
	
/*Enable Clock*/	
	mov r3, #1
	
	ldr r0, =BB_ENABLE_PORTA_CLK
	str r3, [r0]
	
/* PTA 10, 11, 28, 29 als output setzen  */
	ldr r0, =GPIOA_PDDR
	ldr r2, =MASK_PORTA_LED_REGISTERS
	str r2, [r0]


/* Clear Register PORTA 10, 11, 28, 29, 19, Set Mux to Alternative 1 GPIO*/
	
	mov r1, #MASK_SET_MUX_ALT1_PCR	
	
	ldr r0, =PORTA_PCR10
	str r1, [r0]

	ldr r0, =PORTA_PCR11
	str r1, [r0]	
	
	ldr r0, =PORTA_PCR28
	str r1, [r0]
	
	ldr r0, =PORTA_PCR29
	str r1, [r0]
	
/* PTA 10, 11, 28, 29 Logic Level 1, damit LEDs bei Beginn nicht leuchten */	
	ldr r0, =GPIOA_PDOR	
	str r2, [r0]	
	
	bx lr


/* PIT1 Interrupt Handler */	
.thumb_func
PIT1_IRQHandler:				
/* clear interrupt */
	ldr r0, =BB_PIT_TFLG1_TIF 
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =var_Second_Over
	strb r1, [r0]		// Flag, dass Sekunde vorbei ist, aktualisieren
	
	bx lr

