// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Für Aufgabenstellung
.equ SIM_SCGC5, 0x40048038
.equ PORTD_PCR8, 0x4004C020
.equ PORTD_PCR9, 0x4004C024
.equ GPIOD_PDDR, 0x400FF0D4
.equ GPIOD_PDOR, 0x400FF0C0
.equ GPIOD_PDIR, 0x400FF0D0

.equ DELAY_COUNTER, 20				// ca 2µs
// Aus Aufgabenstellung 
__BBREG SIM_PORTD, SIM_SCGC5, 12 	// Maske fuer PD8 und PD9
.equ PD8_9, 0x300					// Maske fuer PD8
.equ PD8, 0x100						// Alternative 1: GPIO
.equ ALT_GPIO, 0x100
.equ ALT2_MASK, 0x200			// Alternative2 

// Interrupt
.equ IV_PIT1, 0x1FFFFF54		// (IRQn69) => 0x1FFFFE00 + 0x0000_0154
.equ NVIC_ICPR2, 0xE000E288		
.equ NVIC_ISER2, 0xE000E108

// PIT1 
.equ PIT_LDVAL1, 0x40037110		
.equ PIT_MCR, 0x40037000
.equ PIT1_COUNTER_VALUE, 25000000	// 1 Sec
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TFLG1, 0x4003711C
.equ NVIC_IRQn69, 0x20				// (1<<5)

__BBREG BB_PIT_TFLG1_TIF, PIT_TFLG1, 0			// Timer Interrupt Flag

// Clock PIT1
.equ SIM_SCGC6, 0x4004803C
__BBREG BB_ENABLE_PIT_CLK, SIM_SCGC6, 23		// SCGC6_PIT


// I2C
.equ I2C0_C1, 0x40066002
.equ I2C0_F,  0x40066001
.equ I2C0_S,  0x40066003 
.equ I2C0_D,  0x40066004
.equ I2C0_C2, 0x40066005
.equ I2C0_FLT,  0x40066006
.equ I2C0_RA,   0x40066007
.equ I2C0_SMB , 0x40066008
.equ I2C0_A2,   0x40066009
.equ I2C0_SLTH, 0x4006600A
.equ I2C0_SLTL, 0x4006600B

// I2C constant
.equ TRANSMIT_MODE, 1
.equ RECEIVE_MODE, 0
.equ SLAVE_MODE, 0
.equ MASTER_MODE, 1

// I2C Masks 
.equ C1_MASK, 0xC0		// enable i2c, enable interrupt
.equ C2_MASK, 0x0		// no general call, 7bit address scheme, normal drive mode, baud rate slave=master, Range mode disabled
.equ F_MASK, 0x49		// 01001001	=> ~390kbaud => ICR = 0x09(SCL div = 32) MULT = 0x01 (mul=2) => 390.625 baud Tempsensor max baud => 400kbaud
.equ MASK_READ,  0x91
.equ MASK_WRITE, 0x90
.equ S_RESET, 0x12		// 10010010, reset Register
.equ SMB_RESET, 0xA		// 00001010, reset Register
.equ A2_RESET, 0xC1		// 11000010, reset Register


// TEMP D75
.equ COMMAND_POINTER_CONFIG, 1		// Configuration Pointer
.equ COMMAND_POINTER_T_HYST, 2		// T_HYST Pointer
.equ COMMAND_POINTER_T_OS, 3		// T_OS Pointer
.equ COMMAND_12BIT_COMP, 0x60		// 12 bit resolution, comparator mode, active conversion
.equ COMMAND_READ_TEMP, 0			// Temperatur auslesen
//Clock
.equ SIM_SCGC4, 0x40048034
// Bit Banding
__BBREG BB_CHECK_ARBITRATION, I2C0_S, 4 		// ARBL 
__BBREG BB_CHECK_BUS_BUSY, I2C0_S, 5 			// BUSY 
__BBREG BB_TRANSMIT_MODE_SELECT, I2C0_C1, 4		// TX
__BBREG BB_MASTER_MODE_SELECT, I2C0_C1, 5		// MST
__BBREG BB_REPEAT_START, I2C0_C1, 2				// RSTA
__BBREG BB_INTERRUPT_FLAG, I2C0_S,1				// IICIF 
__BBREG BB_TXAK, I2C0_C1,3						// TXAK
__BBREG BB_I2C0_ENABLE_CLOCK, SIM_SCGC4, 6 

.equ FILTER_BIT4to7, 0xf0

// Für Temperatur bei Nachkommastellen  
.equ BIT1, 1
.equ BIT2, 2
.equ BIT3, 4
.equ BIT4, 8

.equ KOMMA, 44



/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl I2CBus_Reset
	bl pit1_init
	bl i2c_Init
	ldr r8, =I2C0_D
	ldr r9, =var_Second_Over
	mov r10, #0	
main_loop:	
// ############################################## Config DS75 ##############################################
	bl i2c_start_transmission
// Adresse vom Slave in Data Register schreiben 	
	mov r0, #MASK_WRITE
	strb r0, [r8]
	
	bl i2c_check_end_of_transmission
// Config Befehl senden	
	mov r0, #COMMAND_POINTER_CONFIG	
	strb r0, [r8]
	
	bl i2c_check_end_of_transmission

// Befehl für Einstellung 12bit + comp-mode senden		
	mov r0, #COMMAND_12BIT_COMP	
	strb r0, [r8]
	
	bl i2c_check_end_of_transmission	

// config vorbei
// stop senden
	bl i2c_stop_transmission
	bl i2c_Delay
	
// ############################################## Write to T_OS and T_HYST ##############################################

	mov r0, #0			// damit Lese-Pointer gesetzt wird
	bl i2c_read_temp
// Temperaturwerte nachbereiten		
	lsr r6, r0, #16		
	add r6, r6, #3			// T_0 + 3
	lsr r5, r0, #8
// Filter für Nachkomastelen
	mov r1, #FILTER_BIT4to7		
	and r5, r5, r1
	bl i2c_start_transmission	
// Adresse vom Slave in Data Register schreiben 	
	mov r7, #MASK_WRITE
	strb r7, [r8]
	
	bl i2c_check_end_of_transmission
// Befehl, dass in T_OS geschrieben werden soll, senden	
	mov r1, #COMMAND_POINTER_T_OS	
	strb r1, [r8]

	bl i2c_check_end_of_transmission

	strb r6, [r8]			// MS Data Byte schreiben => T_0 + 3	
					
	bl i2c_check_end_of_transmission	
	
	strb r5, [r8]			// LS Data Byte (Nachkommastelle) schreiben			
	
	bl i2c_check_end_of_transmission
	
	bl i2c_repeat_start

	strb r7, [r8]
	bl i2c_check_end_of_transmission
	
// Befehl für reinschreiben in T_HYST senden	
	
	mov r1, #COMMAND_POINTER_T_HYST	
	strb r1, [r8]
	
	bl i2c_check_end_of_transmission
	
	sub r6, r6, #1			// => T_0 + 2	
	strb r6, [r8]			// MS Data Byte schreiben => T_0 + 2
	
	bl i2c_check_end_of_transmission
			
	strb r5, [r8]			// LS Data Byte (Nachkommastelle) schreiben				
	
	bl i2c_check_end_of_transmission
// stop senden
	bl i2c_stop_transmission
	bl i2c_Delay
	
// Nochmal Temperatur lesen, damit der Pointer korrekt gesetzt wird
	mov r0, #0			// Übergabeparameter für korrektes Pointer Setzen
	bl i2c_read_temp
	
	b wait_for_second
	
	
read_temp:
	mov r0, #1			// Übergabeparameter, damit beim Lesen der Pointer nicht erneut gesetzt wird
	bl i2c_read_temp
	mov r4, r0
// Temp Ausgabe im hex-format	
	bl uart_putInt32
	ldr r0, =doppelpunkt_leerzeichen
	bl uart_putString
	
// Vorkommastellen in Dezimal ausgeben
	lsr r0, r4, #16
	
	bl uart_putByteBase10
	mov r0, #KOMMA
	bl uart_putChar
	
// Nachkommastellen in Dezimal ausgeben	

// Nur die Stellen Bit 15 bis Bit 12 sind relevant	
	and r0, r4, (0xf<<12)
	lsr r0, r0, #12
	
	mov r4, #100		// Für Berechnung, damit keine Nachkommastellen entstehen
	mov r3, #0			// Für das Ergebnis
	
// Prüfen, ob Bit 1 bis Bit 4 gesetzt sind. Falls ja entsprechend Teilen und Ergebnis addieren	
	ands r1, r0, #BIT1		
	itt ne
	lsrne r2, r4, #4	// durch 16 teilen
	addne r3, r3, r2	// Ergebnis aufaddieren
	
	ands r1, r0, #BIT2		
	itt ne
	lsrne r2, r4, #3	// durch 8 teilen
	addne r3, r3, r2	// Ergebnis aufaddieren
	
	ands r1, r0, #BIT3	
	itt ne
	lsrne r2, r4, #2	// durch 4 teilen
	addne r3, r3, r2	// Ergebnis aufaddieren
	
	ands r1, r0, #BIT4	
	itt ne
	lsrne r2, r4, #1	// durch 2 teilen
	addne r3, r3, r2	// Ergebnis aufaddieren
	
	mov r0, r3

// Falls kleiner 10, fuehrende Null mitausgeben	
    cmp r0, #10                     // >= 10?
    ite hs
    ldrhs r1, =uart_putByteBase10   // ohne fuehrende Null
    ldrlo r1, =uart_putByte         // mit fuehrender Null
    blx r1                          // entsprechendes UP aufrufen
	

	ldr r0, =temperatur_string
	bl uart_putString
	
	
wait_for_second:	
	ldrb r0, [r9]
	cmp r0, #1
	bne wait_for_second
	strb r10, [r9]		// reset second_over flag
	
	b read_temp

// read 2 bytes from temp register
// Rückgabe: Temperatur in r0, hex-format
.thumb_func
i2c_read_temp:
	push {r4-r6, lr}
	
	ldr r6, =I2C0_D
	mov r4, r0
	bl i2c_start_transmission
	cmp r4, #1
	beq skip_set_pointer
// Slave-Adresse für lesen 	
	mov r1, #MASK_WRITE	
	strb r1, [r6]
	
	bl i2c_check_end_of_transmission	

// Vorhaben: Temp lesen
	mov r1, #COMMAND_READ_TEMP		
	strb r1, [r6]
	
	bl i2c_check_end_of_transmission	
	
	bl i2c_repeat_start

skip_set_pointer:	
// Slave soll schreiben
	mov r1, #MASK_READ	
	strb r1, [r6]
	
// Check end of Transmission	
	bl i2c_check_end_of_transmission	
// set rx mode
	ldr r0, =BB_TRANSMIT_MODE_SELECT
	mov r1, #RECEIVE_MODE		
	strb r1, [r0]	
// Dummy Read	
	ldrb r1, [r6]
	
	bl i2c_check_end_of_transmission	

	ldrb r4, [r6]	// MSB data auslesen
	
	bl i2c_check_end_of_transmission	
// for NAK	
	ldr r0, =BB_TXAK
	mov r1, #1
	strb r1, [r0]

	ldrb r5, [r6]	// LSB data auslesen
	
	bl i2c_check_end_of_transmission	
	bl i2c_stop_transmission	
	bl i2c_Delay
	
// Daten nachbereiten	
	mov r0, r4
	lsl r0, r0, #16
	lsl r5, r5, #8
	orr r0, r0, r5		// Rückgabe in r0
	
	pop {r4-r6, pc}

/*
Setzt die Bedingung für das Beenden einer Übertragung
*/
.thumb_func
i2c_stop_transmission:
// clear tx mode
	ldr r0, =BB_TRANSMIT_MODE_SELECT
	mov r1, #RECEIVE_MODE		
	strb r1, [r0]
// clear Master Mode	
	ldr r0, =BB_MASTER_MODE_SELECT
	mov r1, #SLAVE_MODE
	strb r1, [r0]

	bx lr
/*
Setzt das Repeat-Start Signal
*/
.thumb_func
i2c_repeat_start:		
	mov r1, #1
	ldr r0, =BB_REPEAT_START
	strb r1, [r0]
	
	bx lr

/*
Prüft, ob die I2C Übertragung beendet wurde, gibt einen String auf dem Terminal bei Timeout aus
*/
.thumb_func
i2c_check_end_of_transmission:	
	push {lr}
	
	ldr r0, =BB_INTERRUPT_FLAG
	movw r2, #0xffff			//wie lange ist hier ok zu warten?
check_transfer_complete_loop:
	sub r2, r2, #1
	cbz r2, loop_end
	ldrb r1, [r0]
	cmp r1, #1
	bne check_transfer_complete_loop
	strb r1, [r0]			// clear pending interrupt	
loop_end:
	cmp r2, #0
	itt eq
	ldreq r0, =str_timeout			// Zu lange gewartet
	bleq uart_putString			
	
	pop {pc}

/*
Startet eine I2C Übertragung, gibt einen String im Falle von Arbitrierungsproblem am Terminal aus
*/
.thumb_func
i2c_start_transmission:	
	push {lr}

	mov r1, #TRANSMIT_MODE
	mov r3, #11				// max. Anzahl an Versuchen 
start_transmission_loop:
	sub r3, r3, #1
	cmp r3, #0
	beq transmission_loop_end
// clear interrupts	
	ldr r0, =BB_INTERRUPT_FLAG
	strb r1, [r0]
// set tx mode
	ldr r0, =BB_TRANSMIT_MODE_SELECT
	strb r1, [r0]
// clear TXAK
	ldr r0, =BB_TXAK
	mov r1, #0
	strb r1, [r0]
	
// Set Master Mode	
	ldr r0, =BB_MASTER_MODE_SELECT
	mov r1, #MASTER_MODE
	strb r1, [r0]
// Check, ob Bus erfolgreich zugeteilt	
	ldr r0, =BB_CHECK_BUS_BUSY
	ldrb r2, [r0]
	cmp r2, #1
	bne start_transmission_loop
	
transmission_loop_end:
	cmp r3, #0
	itt eq
	ldreq r0, =str_bus_busy
	bleq uart_putString


// Check Arbitration loss		
	ldr r0, =BB_CHECK_ARBITRATION	
	ldrb r1, [r0]
	cmp r1, #1
	itt eq
	ldreq r0, =str_arbitration_loss
	bleq uart_putString

	pop {pc}

/*
Initiiert bzw. resettet alle I2C Register
*/	
.thumb_func
i2c_Init:	
// Enable Clock for i2c0
	ldr r0, =BB_I2C0_ENABLE_CLOCK
	mov r1, #1
	str r1, [r0]
// Set up Frequency
	ldr r0, =I2C0_F
	mov r1, #F_MASK
	strb r1, [r0]
// enable i2c	
	ldr r0, =I2C0_C1
	mov r1, #C1_MASK
	strb r1, [r0]
// reset C2 Register		
	ldr r0, =I2C0_C2
	mov r2, #0			// no general call, 7bit address scheme, normal drive mode, baud rate slave=master, Range mode disabled
	strb r2, [r0]
// reset Status Register	
	ldr r0, =I2C0_S
	mov r1, #S_RESET
	strb r1, [r0]
// reset FLT Register
    ldr r0, =I2C0_FLT
	strb r2, [r0]
// reset RA Register
    ldr r0, =I2C0_RA
    strb r2, [r0]
// reset SMB Register
    ldr r0, =I2C0_SMB
    mov r1, #SMB_RESET
    strb r1, [r0]
// reset A2 Register     
    ldr r0, =I2C0_A2
    mov r1, #A2_RESET
    strb r1, [r0]
// reset SLTH Register  
	ldr r0, =I2C0_SLTH
	strb r2, [r0]
// reset SLTL Register  
	ldr r0, =I2C0_SLTL
	strb r2, [r0]
    
	bx lr
	
/* Init Pit, enable interrupts, setting counter values */
.thumb_func
pit1_init:

/*Takt für PIT aktivieren*/	
	mov r2, #1
	ldr r0, =BB_ENABLE_PIT_CLK
	str r2, [r0]
	
/*Interrupt Vektor zu PIT1 setzen*/
	ldr r0, =IV_PIT1
	ldr r1, =PIT1_IRQHandler
	str r1, [r0]
	
// pending interrupts zu PIT1 löschen (NVIC)
	ldr r0, =NVIC_ICPR2
	mov r1, #NVIC_IRQn69
	str r1, [r0]				
	
/*Interrupt zu PIT1 aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]
		
/*PIT1 Startwert 1 sek initialisieren*/	
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT1_COUNTER_VALUE
	str r1, [r0]

/*Interrupt PIT1 aktivieren (PIT-Modul) && PIT1 aktivieren (PIT-Modul)*/
	ldr r0, =PIT_TCTRL1
	mov r1, #3					
	str r1, [r0]		// PIT_TCTRL1 Timer enable, interrupt enable, timer not chained 
	
/* alle PITs aktivieren */	
	ldr r0, =PIT_MCR
	mov r1, #0
	str r1, [r0]
	
	bx lr
	
/* PIT1 Interrupt Handler */	
.thumb_func
PIT1_IRQHandler:				
/* clear interrupt */
	ldr r0, =BB_PIT_TFLG1_TIF 
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =var_Second_Over
	strb r1, [r0]		// Flag, dass Sekunde vorbei ist, aktualisieren
	
	bx lr
/*
~2 µs Delay
*/
.thumb_func
i2c_Delay:
	mov r0, #DELAY_COUNTER	
loop_delay:	
	sub r0, r0, #1
	cmp r0, #0
	bne loop_delay
	
	bx lr
/* **************** I2C - Bus zuruecksetzen *********** */
.thumb_func
I2CBus_Reset:
	push {lr}
	ldr r0, =SIM_PORTD		// Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR8		// Portleitungen PD8 , PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR		// PD8 , PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	
	mov r3, #11				// Zaehler fuer max. 10 Versuche
loop:
// Ein Zaehler fuer maximal 10 Versuche ist zu implementieren.
// Ggf . Fehlermeldung auf Terminal ausgeben und abbrechen.
	sub r3, r3, #1
	cbz r3, max_versuche_abgelaufen 
	
	ldr r0, =GPIOD_PDOR		// SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD8		// entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDOR		// SCL und SDA aktivieren
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9		// nur Bits 9 und 10 pruefen
	cmp r2, #PD8_9			// Bit 9 und Bit 10 gesetzt ?
	bne loop				// ggf . wiederholen
	
max_versuche_abgelaufen:
	cmp r2, #PD8_9			// Bit 9 und Bit 10 gesetzt ?
	ite ne
	ldrne r0, =i2c_string_nicht_erfolgreich
	ldreq r0, =i2c_string_erfolgreich
	bl uart_putString
	
// Config PORTD8+9 for i2c
	
	ldr r0, =PORTD_PCR8		// Portleitungen PD8 , PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT2_MASK
	str r2, [r0]
	str r2, [r1]
	
	pop {pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
var_Second_Over: .byte 0

temperatur_string: .asciz " Grad Celsius\n"	
i2c_string_nicht_erfolgreich: .asciz "I2C Ruecksetzen hat nicht geklappt!\n"
i2c_string_erfolgreich: .asciz "I2C Ruecksetzen hat geklappt!\n"
str_arbitration_loss: .asciz "Arbitration loss!\n"	
str_bus_busy: .asciz "BUS BUSY!\n"
str_timeout: .asciz "TIMEOUT waehrend Uebertragung!\n"	
doppelpunkt_leerzeichen: .asciz ": "	


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


// Für SPI Bus Reset
.equ ALT_GPIO, 0x100
.equ PD12_13_14_15, 0xF000				//  Maske fuer PD12, 13, 14 und 15
.equ PD12, 0x1000
.equ delay_2us, 40						// ca 2µs
.equ GPIOD_PDDR, 0x400FF0D4
.equ GPIOD_PDOR, 0x400FF0C0
.equ GPIOD_PDIR, 0x400FF0D0


.equ GPIOA_PDDR, 0x400FF014 	// Port Data Direction Register
.equ GPIOA_PDIR, 0x400FF010		// Port Data Input Register 

.equ GPIOE_PDDR, 0x400FF114		// Port Data Direction Register
.equ GPIOE_PDIR, 0x400FF110		// Port Data Input Register 

.equ ALT2_MASK, 0x200			// Alternative2: SPI

// Pin Control Register n
.equ PORTE_PCR26, 0x4004D068
.equ PORTA_PCR19, 0x4004904C
.equ PORTD_PCR12, 0x4004C030
.equ PORTD_PCR13, 0x4004C034
.equ PORTD_PCR14, 0x4004C038
.equ PORTD_PCR15, 0x4004C03C


// Interrupts
.equ IV_PIT1, 0x1FFFFF54		// (IRQn69) => 0x1FFFFE00 + 0x0000_0154
.equ IV_PTE, 0x1FFFFFAC			// (IRQn91) => 0x1FFFFE00 + 0x000001AC 
.equ IV_PTA, 0x1FFFFF9C			// (IRQn87) => 0x1FFFFE00 + 0x0000019C
.equ NVIC_ICPR2, 0xE000E288		
.equ NVIC_ISER2, 0xE000E108
.equ IRQn91_AND_87, 0x8800000	 // NVIC IRQn91 + IRQn87 => 2*32+27+23 => NVICISER2 und (1<<27) || (1<<23)

// SPI2
.equ SPI2_MCR, 0x400AC000
.equ SPI2_CTAR0, 0x400AC00C		
.equ SPI2_RSER, 0x400AC030
.equ SPI2_SR, 0x400AC02C
.equ SPI2_PUSHR, 0x400AC034
.equ SPI2_POPR, 0x400AC038

// SPI2 Config	
.equ MCR_CONFIG, 0x80003001		// 10000000000000000011000000000001: master mode, run in debug mode, enable module clock, stop state 
.equ CTAR0_CONFIG,0x7a541017    // 01111010010101000001000000010111: 16 bit frame, CPHA = 1, CPOL = 0 msb first, T cs to clk 480ns, T clk to cs 240ns, T cs to cs 480ns, baud rate: 97656,25 Hz

// Temp Sensor Commands for PUSHR
.equ READ_MSB, 0x08020200	// use CTAR0, last data to transfer, Slave Select = 1, Byte 1 = 0x02 for MSB READ
.equ READ_LSB, 0x08020100	// // use CTAR0, last data to transfer, Slave Select = 1,  Byte 1 = 0x01  for LSB READ
.equ TEMP_SENSOR_CONFIG, 0x08028000	//use CTAR0, last data to transfer, Slave Select = 1, Byte 1 = 0x80: Configuration Register 		


__BBREG BB_DISABLE_FIFO_TX, SPI2_MCR, 13 	
__BBREG BB_DISABLE_FIFO_RX, SPI2_MCR, 12 	
 
__BBREG BB_CHECK_TRANSFER_COMPLETE, SPI2_SR, 31 	// TCF 
__BBREG BB_END_OF_QUEUE, SPI2_SR, 28 				// EOQF
__BBREG BB_MCR_HALT, SPI2_MCR, 0 					// HALT
__BBREG BB_MCR_FRZ, SPI2_MCR, 27		 			// FRZ

// PIT1 
.equ PIT_LDVAL1, 0x40037110		
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TFLG1, 0x4003711C
.equ NVIC_IRQn69, 0x20				// (1<<5)

.equ COUNTER_12_BIT, 30000000		// 1.2 Sec

__BBREG BB_PIT_TFLG1_TIF, PIT_TFLG1, 0			// Timer Interrupt Flag

// Clock
.equ SIM_SCGC6, 0x4004803C
.equ SIM_SCGC5, 0x40048038
.equ SIM_SCGC3, 0x40048030
__BBREG BB_ENABLE_SPI2_CLK, SIM_SCGC3, 12
__BBREG BB_ENABLE_PIT_CLK, SIM_SCGC6, 23
__BBREG BB_ENABLE_PORTE_CLK, SIM_SCGC5, 13
__BBREG BB_ENABLE_PORTA_CLK, SIM_SCGC5, 9
__BBREG BB_ENABLE_PORTD_CLK, SIM_SCGC5, 12

// GPIO
__BBREG BB_SET_GPIOA_PDDR19, GPIOA_PDDR, 19			
__BBREG BB_SET_GPIOE_PDDR26, GPIOE_PDDR, 26	
		
// Interrupt
__BBREG BB_CLEAR_ISF_SW_BLK, PORTA_PCR19, 24	
__BBREG BB_CLEAR_ISF_SW_GRN, PORTE_PCR26, 24	

.equ MASK_CONFIG_PCR, 0xA0103	// interrupt falling edge, Pull up enable, Alternate 1 GPIO



// Für Temperatur bei Nachkommastellen 
.equ MASK_BIT_4_TO_7, 0xF0
.equ MASK_BIT_0_TO_3, 0xF
.equ KOMMA, 44


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:	
 	bl uart_init
	bl SPIBus_Reset
	bl init_SPI2
	
	bl pit1_init
	bl init_GPIO
	
	ldr r8, =flag_pit_over
	mov r11, #0
	ldr r9, =flag_sw_blk_interrupt
	ldr r10, =flag_sw_grn_interrupt
	
	mov r12, #4					// Für die passende Auflösung und für Array Zugriffe #0: 8bit, #1: 9bit, #2: 10bit, #3: 11bit, #4: 12bit  
	bl spi_start_condition
	
	ldr r1, =arr_config_resolution	
	ldrb r0, [r1, r12]			// passenden Config-Wert aus dem Array holen
	bl config_Temp_Sensor		// und übergeben
	
	
// aktuelle Auflösung ausgeben. Dieser Code wird zwar weiter unten auch nochmal ausgeführt, auf eine Funktion wird jedoch verzichtet, um während der main-loop Sprünge zu reduzieren
	ldr r0, =str_resolution
	bl uart_putString
	ldr r0, =arr_str_resolution
	mov r1, r12	
	lsl r1, r1, #2			// offset anpassen
	ldr r0, [r0, r1]		// String für passende Auflösung aus dem Array laden...
	bl uart_putString		// ... und diese ausgeben
	
main_loop:	

// Überprüfen, ob Schalter gedrückt. Falls ja, Auflösung anpassen, Pit1 anpassen und Aktuelle Auflösung am Terminal ausgeben
 	//flag_sw_blk_interrupt, Auflösung vergrößern
	ldrb r0, [r9]
	cmp r0, #1
	bne check_sw_grn
	strb r11, [r9]

	add r12, r12, #1			// inc. Auflösung
// Auf Überlauf prüfen
	cmp r12, #4
	it hi
	movhi r12, #0				// Auflösung höher als 12bit => zurück auf 8 bit
	
	b config_sensor
check_sw_grn:	
//flag_sw_grn_interrupt, Auflösung verringern
	ldrb r0, [r10] 
	cmp r0, #1
	bne button_not_pressed		// keiner der Tasten wurden gedrückt
	strb r11, [r10]
		
// auf Überlauf prüfen
	subs r12, r12, #1			// dec. Auflösung	
	it lo
	movlo r12, #4				// Auflösung kleiner als 8bit => zurück auf 12bit

// ############### Temp Sensor neu konfigurieren ###############	
config_sensor:	
	ldr r1, =arr_config_resolution
	ldrb r0, [r1, r12]			// passenden Config-Wert aus dem Array holen
	bl config_Temp_Sensor		// und übergeben
	
// aktuelle Auflösung ausgeben
	ldr r0, =str_resolution
	bl uart_putString
	ldr r0, =arr_str_resolution
	mov r1, r12	
	lsl r1, r1, #2			// offset anpassen
	ldr r0, [r0, r1]
	
	bl uart_putString

// ########## PIT umkonfigurieren, entsprechend der aktuellen Auflösung ########## 

// PIT_TCTRL1 Timer disable 
	ldr r3, =PIT_TCTRL1
	str r11, [r3] 

// PIT1 entsprechenden Wert laden
	ldr r0, =arr_pit_counter
	mov r1, r12
	lsl r1, r1, #2			// offset anpassen
	ldr r0, [r0, r1]		// entsprechenden Zählerwert aus dem Array holen
	ldr r2, =PIT_LDVAL1	
	str r0, [r2]			// und setzen

	mov r1, #3					
	str r1, [r3]		// PIT_TCTRL1 Timer enable, interrupt enable, timer not chained 
	
	
button_not_pressed:
	ldrb r0, [r8]
	cmp r0, #1				// check, ob pit abgelaufen
	bne main_loop			
	strb r11, [r8]			// reset pit over


	bl read_Temp_Sensor		// Temp lesen
	
	
/*############################ TEMP AUSGEBEN ############################*/	
	mov r4, r0 		// Temp zwischenspeichern
	
	lsr r0, r0, #4	// Temp "Hauptwert" 
	bl uart_putByteBase10	// Temp. "Hauptwert" ausgeben.
	mov r0, #KOMMA
	bl uart_putChar
		
// Nachkommastellen in Dezimal ausgeben	
				
	and r0, r4, #MASK_BIT_0_TO_3	// Nur die Stellen Bit 0 bis Bit 3 sind relevant fuer Nachkommastellen
	
	ldr r1, =arr_temp_values
	lsl r0, r0, #1		// für offset hword
	ldrh r0, [r1, r0]
	
	bl uart_putInt16
	
	ldr r0, =str_degree
	bl uart_putString
	
	b main_loop

	

/*
Diese Funktion liest MSB und LSB vom Temp Sensor und gibt diese vereint in r0 zurück
*/
.thumb_func
read_Temp_Sensor:	
	push {r4, lr}
		
	ldr r1, =READ_MSB		// MSB
	ldr r0, =SPI2_PUSHR
	str r1, [r0]
	
	bl wait_for_transmission_end

	mov r4, r0					// MSB Temp. Wert zwischenspeichern
	
	ldr r1, =READ_LSB			// LSB	
	ldr r0, =SPI2_PUSHR
	str r1, [r0]
	
	bl wait_for_transmission_end

	and r0, r0, #MASK_BIT_4_TO_7	// Bit 4 bis 7 sind relevant 
	lsr r0, r0, #4					// Temp LSB sollen bit 0 bis bit 3 sein
	lsl r4, r4, #4					// Temp MSB sollen bit 4 bis bit 11 sein
	orr r0, r0, r4					// Rückgabewert MSB: bit 4 bis bit 11, LSB: bit 0 bis bit 3
		
	pop {r4, pc}

/*
Übergabeparameter in r0: Position des Config-Wertes im Array 
*/
.thumb_func
config_Temp_Sensor: 	
	push {lr}
	ldr r1, =TEMP_SENSOR_CONFIG			
	orr r1, r1, r0				// Für passenden Config Wert aus dem Array
	ldr r0, =SPI2_PUSHR
	str r1, [r0]
	
	bl wait_for_transmission_end
	
	pop {pc}

/*
Diese Funktion setzt die Bedingung für den Start des SPI2 Busses
EOQF = 0 
FRZ = 0 
HALT = 0
*/
.thumb_func
spi_start_condition:
	mov r3, #1
	ldr r0, =BB_END_OF_QUEUE
	str r3, [r0]

	mov r3, #0
	ldr r0, =BB_MCR_FRZ
	ldr r1, =BB_MCR_HALT
	str r3, [r0]
	str r3, [r1]

	bx lr
/*
Diese Funktion Setzt die Bedingung für den Stop des SPI2 Busses
HALT = 1
*/
.thumb_func
spi_stop_condition:	
	mov r3, #1

	ldr r0, =BB_MCR_HALT
	str r3, [r0]
	
	bx lr
/*
Diese Funktion wartet bis die SPI Übertragung abgeschlossen ist und
gibt den ausgelesenen Temperaturwert zurück
Rückgabewert: Ausgelesener Temperaturwert in R0
*/
.thumb_func
wait_for_transmission_end:
	push {lr}		
	ldr r3, =BB_CHECK_TRANSFER_COMPLETE
	movw r2, #0xFFF	//  Übertragung dauert 0x1BB (mittels Counter ermittelt) + Puffer => 0xFFF
	
tcf_loop:		
	subs r2, r2, #1
	beq loop_end		
	ldr r1, [r3]
	cmp r1, #1
	bne tcf_loop
loop_end:
	str r1, [r3]		// reset tcf. Falls r2 zuerst ausläuft, wird tcf hier nicht resetten, da es aber ohnehin 0 ist, ist das auch nicht notwendig 		
	
	cmp r2, #0
	itt eq
	ldreq r0, =str_nicht_erfolgreich
	bleq uart_putString

	ldr r2, =SPI2_POPR
	ldr r0, [r2]		// POPR auslesen. Ausgelesener TempWert als Rückgabewert

	pop {pc}	
	
.thumb_func
init_SPI2:
	mov r3, #1
	ldr r0, =BB_ENABLE_SPI2_CLK
	str r3, [r0]
	
	ldr r0, =SPI2_MCR
	ldr r1, =MCR_CONFIG
	str r1, [r0]
	
// explicit disable fifo, weil schreiben nur möglich wenn MDIS=0 	
	ldr r0, =BB_DISABLE_FIFO_TX
	str r3, [r0]
	ldr r0, =BB_DISABLE_FIFO_RX
	str r3, [r0]

	ldr r0, =SPI2_CTAR0
	ldr r1, =CTAR0_CONFIG
	str r1, [r0]
		
// disable interrupt and dma requests	
	ldr r0, =SPI2_RSER
	mov r1, #0
	str r1, [r0]
	
	bx lr

.thumb_func
init_GPIO:
	mov r3, #1
	
	ldr r0, =BB_ENABLE_PORTA_CLK
	str r3, [r0]
	ldr r0, =BB_ENABLE_PORTE_CLK
	str r3, [r0]
	
/* PTA 19 als input setzen  */
	ldr r0, =BB_SET_GPIOA_PDDR19
	mov r1, #0 
	str r1, [r0]
/* PTE 26 als input setzen  */
	ldr r0, =BB_SET_GPIOE_PDDR26
	str r1, [r0]
	
/* Config PTE26+PTA19, enable interrupt falling edge, Pull up enable, set alternative 1 GPIO*/	
	ldr r0, =PORTE_PCR26
	ldr r1, =MASK_CONFIG_PCR
	str r1, [r0]
	
	ldr r0, =PORTA_PCR19
	str r1, [r0]
	
/*Interrupt Vektor zu PTE setzen*/
	ldr r0, =IV_PTE
	ldr r1, =PTE_IRQHandler
	str r1, [r0]
	
/*Interrupt Vektor zu PTA setzen*/
	ldr r0, =IV_PTA
	ldr r1, =PTA_IRQHandler
	str r1, [r0]
	
/* pending interrupts zu PTE & PTA löschen (NVIC) */
	ldr r0, =NVIC_ICPR2
	mov r1, #IRQn91_AND_87				
	str r1, [r0]
	
/*Interrupt zu PTE & PTA aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]

	bx lr

/* Init Pit, enable interrupts, setting counter values */
.thumb_func
pit1_init:

/*Takt für PIT aktivieren*/	
	mov r2, #1
	ldr r0, =BB_ENABLE_PIT_CLK
	str r2, [r0]
	
/*Interrupt Vektor zu PIT1 setzen*/
	ldr r0, =IV_PIT1
	ldr r1, =PIT1_IRQHandler
	str r1, [r0]
	
// pending interrupts zu PIT1 löschen (NVIC)
	ldr r0, =NVIC_ICPR2
	mov r1, #NVIC_IRQn69
	str r1, [r0]				
	
/*Interrupt zu PIT1 aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]
		
/*PIT1 Startwert 1.2 sek initialisieren*/	
	ldr r0, =PIT_LDVAL1
	ldr r1, =COUNTER_12_BIT
	str r1, [r0]

/*Interrupt PIT1 aktivieren (PIT-Modul) && PIT1 aktivieren (PIT-Modul)*/
	ldr r0, =PIT_TCTRL1
	mov r1, #3					
	str r1, [r0]		// PIT_TCTRL1 Timer enable, interrupt enable, timer not chained 
	
/* alle PITs aktivieren */	
	ldr r0, =PIT_MCR
	mov r1, #0
	str r1, [r0]
	
	bx lr


/* PTA Interrup Handler */
.thumb_func
PTA_IRQHandler: 	
	ldr r0, =BB_CLEAR_ISF_SW_BLK		
    mov r1, #1
    str r1, [r0]	/* clear interrupt */
            			
	ldr r0, =flag_sw_blk_interrupt	/* set flag */
	strb r1, [r0]
   	
	bx lr


/* PTE Interrup Handler */
.thumb_func
PTE_IRQHandler:	
	ldr r0, =BB_CLEAR_ISF_SW_GRN		
	mov r1, #1
	str r1, [r0]	/* clear interrupt */
    			
	ldr r0, =flag_sw_grn_interrupt	/* set flag */
	strb r1, [r0]
	
	bx lr

/* PIT1 Interrupt Handler */	
.thumb_func
PIT1_IRQHandler:				
/* clear interrupt */
	ldr r0, =BB_PIT_TFLG1_TIF 
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =flag_pit_over
	strb r1, [r0]		// Flag, dass Sekunde vorbei ist, aktualisieren
	
	bx lr
	
/* **************** SPI - Bus zuruecksetzen *********** */
.thumb_func
SPIBus_Reset:		
	push {r4, lr}
	ldr r0, =BB_ENABLE_PORTD_CLK
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR12		// Portleitungen PD12 , PD13 als GPIO
	ldr r1, =PORTD_PCR13
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =PORTD_PCR14		// Portleitungen PD14 , PD15 als GPIO
	ldr r1, =PORTD_PCR15
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR			// PD12-15 als Ausgang schalten	
	ldr r2, [r0]
	orr r2, r2, #PD12_13_14_15
	str r2, [r0]
	
	mov r4, #11				// Zaehler fuer max. 10 Versuche
loop:
// Ein Zaehler fuer maximal 10 Versuche ist zu implementieren.
// Ggf . Fehlermeldung auf Terminal ausgeben und abbrechen.
	sub r4, r4, #1
	cbz r4, max_versuche_abgelaufen 
	
	ldr r0, =GPIOD_PDOR		// CLK deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD12		// entsprechendes Bit loeschen
	str r2, [r0]
	bl Delay	
		
	ldr r0, =GPIOD_PDOR		// CLK, MISO, MOSI und CS1 aktivieren
	ldr r2, [r0]
	orr r2, r2, #PD12_13_14_15
	str r2, [r0]
	bl Delay
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD12_13_14_15	// nur Bits 12-15 
	cmp r2, #PD12_13_14_15		// Bit 12-15 gesetzt ?
	bne loop					// ggf . wiederholen
max_versuche_abgelaufen:
	cmp r2, #PD12_13_14_15		// Bit 12-15 gesetzt ?
	ite ne
	ldrne r0, =spi_string_nicht_erfolgreich
	ldreq r0, =spi_string_erfolgreich
	bl uart_putString
	
// Config PORTD12-15 for spi2
	ldr r0, =PORTD_PCR12
	ldr r1, =PORTD_PCR13
	mov r2, #ALT2_MASK
	str r2, [r0]
	str r2, [r1]
	ldr r0, =PORTD_PCR14
	ldr r1, =PORTD_PCR15
	str r2, [r0]
	str r2, [r1]
	
	pop {r4, pc}	

/*
~2 µs Delay
*/
.thumb_func
Delay:
	mov r0, #delay_2us	
loop_delay:	
	subs r0, r0, #1	
	bne loop_delay
	bx lr	
	
/*** Datenbereich (ab 0x20000000) ***/
.data
flag_sw_blk_interrupt: .byte 0
flag_sw_grn_interrupt: .byte 0
flag_pit_over: .byte 0

arr_config_resolution: .byte 0xF0, 0xF2, 0xF4, 0xF6, 0xF8					// 8bit, 9bit, 10bit, 11bit, 12bit
arr_pit_counter: .word 1875000, 3750000, 7500000, 15000000, 30000000		// 0.075s, 0.15s, 0.3s, 0.6s, 1.2s

// Array mit Temp. Werten für die Nachkommazahlen. Achtung: Jede Hex-Werte Stelle entspricht bei der Ausgabe einer Dezimalzahl => z.B. 0x3125 = .3125
arr_temp_values: .hword 0x0000, 0x0625, 0x1250, 0x1875, 0x2500, 0x3125, 0x3750, 0x4375, 0x5000, 0x5625, 0x6250, 0x6875, 0x7500, 0x8125, 0x8750, 0x9375

arr_str_resolution: .word str_resolution_8_bit, str_resolution_9_bit, str_resolution_10_bit, str_resolution_11_bit, str_resolution_12_bit
str_resolution_8_bit: .asciz "8 BIT \n"
str_resolution_9_bit: .asciz "9 BIT \n"
str_resolution_10_bit: .asciz "10 BIT \n"
str_resolution_11_bit: .asciz "11 BIT \n"
str_resolution_12_bit: .asciz "12 BIT \n"

str_degree: .asciz " gC\n"
str_resolution: .asciz "\nMomentante Aufloesung: "

spi_string_nicht_erfolgreich: .asciz "SPI Ruecksetzen hat nicht geklappt!\n"
spi_string_erfolgreich: .asciz "SPI Ruecksetzen hat geklappt!\n"

str_nicht_erfolgreich: .asciz "Uebertragung nicht erfolgreich!!!\n"



// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// RTC
.equ RTC_CR,  0x4003D010
.equ RTC_IER, 0x4003D01C
.equ RTC_TSR, 0x4003D000
.equ RTC_TAR, 0x4003D008
.equ RTC_SR,  0x4003D014
.equ RTC_TPR, 0x4003D004

// Konstanten für Uhrzeit
.equ ALARM_ONE_DAY, 86399			// 60*60*24 - 1
.equ ALARM_ONE_HOUR, 3599 			// 60*60 - 1
.equ PRESET_DAY, 86395				// 60*60*24 - 5
.equ PRESET_HOUR, 3595 				// 60*60-5 
.equ HOUR_SECS, 3600
.equ MIN_SECS, 60

// Im Internet finden sich fuer die Einschwingzeiten von Uhrenquarzen (32 kHz) Werte von 300 ms bis 10 Sekunden!
// Da wir keine technischen Daten zum verwendeten Quarz (Hersteller, Typ, Güte usw.) haben, warten wir ca. 10 Sekunden.
// Damit sind wir definitiv auf der sicheren Seite. (aus Forumeintrag)
.equ QUARZ_DELAY, 83333333

// Konstanten fuer Konsolenausgabe
.equ DOPPELPUNKT, 0x3A
.equ NEUE_ZEILE, 0x0A



.equ OSCILLATOR_ENABLE, 0x100		// Mask für Oscillator enable	

// Interrupts
.equ IV_RTC_SECONDS, 0x1FFFFF4C		// (IRQn67) => 0x1FFFFE00 + 0x0000_014C
.equ IV_RTC_ALARM, 0x1FFFFF48		// (IRQn66) => 0x1FFFFE00 + 0x0000_0148
.equ NVIC_ICPR2, 0xE000E288		
.equ NVIC_ISER2, 0xE000E108
.equ IRQn66_AND_67, 0xC	 // NVIC IRQn66 + IRQn67 => 2*32+2+3 => NVICISER2 und (1<<3) || (1<<2)
.equ second_and_alarm_interrupt, 0x14	// TSIE, TAIE

// Clock
.equ SIM_SCGC6, 0x4004803C

// Bitbanding
__BBREG BB_ENABLE_RTC_CLK, SIM_SCGC6, 29
__BBREG BB_SW_RESET, RTC_CR, 0
__BBREG BB_ENABLE_TIME_COUNTER, RTC_SR, 4

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	ldr r0, =str_einschwingzeit
	bl uart_putString
		
	bl RTC_init
	
	ldr r0, =str_einschwingzeit_erledigt
	bl uart_putString
	
// Uhr reset ausgeben	
	ldr r0, =str_reset		
	bl uart_putString

// Vorbereitungen
	ldr r7, =rtc_alarm	// Für Alarm Erkennung
	ldr r10, =second_over
	mov r11, #0			
	mov r8, #1
	mov r12, #1			// Für Start/Stop Ausgabe Uhrzeit bei 's' Eingabe
	mov r9, #0			// Für Mode Erkennung: 0: Day-Mode, 1: Hour-Mode
main_loop:
	
// Alarm gesetzt?
	ldrb r0, [r7]
	cbz r0, check_second
	strb r11, [r7]		// Alarm Flag reset
	
// Parameter für Funktion "set_alarm_and_reset_clock" setzen
	ldr r0, =str_end
	mov r2, #1									
	bl set_alarm_and_reset_clock 
	
// Sekunde vorbei?
check_second:
	ldrb r0, [r10]
	cbz r0, check_input
	strb r11, [r10]		// sekunden Flag zurücksetzen

// Anzeige an? Falls ja Uhrzeit ausgeben
	cmp r12, #1
	bne check_input
	ldr r0, =RTC_TSR	
	ldr r0, [r0]		// Aktuellen Sekundenwert für Parameteruebergabe
	mov r1, r9			// Aktuellen Mode für Parameteruebergabe
	bl calc_and_print_time
		
check_input:	
	bl uart_charPresent
	cmp r0, #0		
	beq main_loop

// Abfrage, ob was eingegeben wurde
	bl uart_getChar
	cmp r0, #'d'
	beq day
	cmp r0, #'h'
	beq hour
	cmp r0, #'r'
	beq reset
	cmp r0, #'s'
	beq start_stop
	cmp r0, #'p'
	beq preset
	
	b main_loop			// Keiner der oberen Buchstaben eingegeben
day:
	
// Day Mode setzen
	mov r9, r11
	
// Parameter für Funktion "set_alarm_and_reset_clock" setzen
	ldr r0, =str_day
	ldr r1, =ALARM_ONE_DAY
	mov r2, #0
	bl set_alarm_and_reset_clock
	
	b main_loop
hour:
	mov r9, r8		// Hour Mode setzen
	
// Parameter für Funktion "set_alarm_and_reset_clock" setzen
	ldr r0, =str_hour
	movw r1, #ALARM_ONE_HOUR
	mov r2, #0
	bl set_alarm_and_reset_clock
	
	b main_loop

reset:	
// Parameter für Funktion "set_alarm_and_reset_clock" setzen
	ldr r0, =str_reset
	mov r2, #1									
	bl set_alarm_and_reset_clock 
	
	b main_loop
start_stop:
	eors r12, r12, #1		// Uhrzeit-Anzeige Flag invertieren
	ite eq
	ldreq r0, =str_stop
	ldrne r0, =str_start
	bl uart_putString
	
	b main_loop
preset:
	cmp r9, #0
	ite eq
	ldreq r0, =PRESET_DAY
	movwne r0, #PRESET_HOUR
	ldr r1, =BB_ENABLE_TIME_COUNTER
	str r11, [r1]			// RTC stop

	ldr r2, =RTC_TSR
	str r0, [r2]			// entsprechenden Sekundenwert einstellen
	
	str r8, [r1]			// RTC start
	ldr r0, =str_preset
	bl uart_putString
	
	b main_loop
/*
Funktion für Das setzen des Alarmwertes, der entsprechenden String Ausgabe und für den Reset der RTC
Übergabeparameter: r0:Adresse des Strings für Ausgabe r1: entsprechender Alarmwert r2: Kennung, ob Alarmwert auch geaendert werden soll
*/
.thumb_func
set_alarm_and_reset_clock:	
	push {lr}
	cbnz r2, no_alarm	
// entsprechenden Alarm setzen 
	ldr r2, =RTC_TAR
	str r1, [r2]
no_alarm:	
// Entsprechenden String ausgeben 
	bl uart_putString
//reset_clock
	mov r2, #1
	mov r3, #0
// disable RTC	 
	ldr r0, =BB_ENABLE_TIME_COUNTER
	str r3, [r0]
// reset Time Seconds Register
	ldr r1, =RTC_TSR
	str r3, [r1]
// reset Prescaler
	ldr r1, =RTC_TPR
	str r3, [r1]
// enable rtc
	str r2, [r0]
	
	pop {pc}


/*
Funktion um die übergebenen Sekunden entsprechend des aktuellen Modes umzurechnen und die Zeit auszugeben
Parameter: r0: Sekunden, r1: Mode 
Rückgabe: keine
*/
.thumb_func
calc_and_print_time:
	push {r4, lr}
	mov r4, r0		// sekunden zwischenspeichern
	cmp r1, #0		// day mode?
	bne hour_mode
	mov r3, #HOUR_SECS
	udiv r0, r4, r3		// Anzahl Stunden
	mul r3, r0, r3		// Anzahl Stunden in Sekunden
	sub r4, r4, r3		// übrige Sekunden
// Ausgabe Stunden	
	cmp r0, #9
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	mov r0, #DOPPELPUNKT	
	bl uart_putChar
hour_mode:
	mov r3, #MIN_SECS
	udiv r0, r4, r3		// Anzahl Minuten
	mul r3, r0, r3		// Anzahl Minuten in Sekunden
	sub r4, r4, r3	// übrige Sekunden
// Ausgabe Minuten
	cmp r0, #9
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	mov r0, #DOPPELPUNKT
	bl uart_putChar
	mov r0, r4		
// Ausgabe Sekunden
	cmp r0, #9
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	mov r0, #NEUE_ZEILE	
	bl uart_putChar

	pop {r4, pc}
/*
Funktion fuer Initialisierung der RTC
*/	
.thumb_func
RTC_init:
	mov r2, #0
	mov r3, #1
	
// Clock aktivieren
	ldr r0, =BB_ENABLE_RTC_CLK
	str r3, [r0]
	
// SW Reset RTC durchführen
	ldr r0, =BB_SW_RESET
	str r3, [r0]
	str r2, [r0]
	
// 32.768kHz Oszillator aktivieren
	ldr r0, =RTC_CR
	movw r1, #OSCILLATOR_ENABLE		
	str r1, [r0]

// Einschwingvorgang abwarten
	ldr r0, =QUARZ_DELAY			
wait_loop:
	subs r0, r0, #1
	bne wait_loop	
	
// Sekundenzähler auf 0 setzen	
	ldr r0, =RTC_TSR
	str r2, [r0]	
// reset Prescaler
	ldr r1, =RTC_TPR
	str r2, [r1]		
// Alarm interrupt enable, Second interrupt enable
	ldr r0, =RTC_IER
	mov r1, #second_and_alarm_interrupt
	str r1, [r0]
// Alarm Counter für 23:59:59 einstellen
	ldr r0, =RTC_TAR
	ldr r1, =ALARM_ONE_DAY
	str r1, [r0]
	
// Interrupt Vektor setzen
	ldr r0, =IV_RTC_SECONDS
	ldr r1, =RTC_Seconds_IRQHandler
	str r1, [r0]
	
	ldr r0, =IV_RTC_ALARM
	ldr r1, =RTC_Alarm_IRQHandler
	str r1, [r0]
// pending interrupts löschen
	ldr r0, =NVIC_ICPR2
	mov r1, #IRQn66_AND_67				
	str r1, [r0]	
// RTC interrupts alarm & seconds aktivieren
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
// Enable Time Counter
	ldr r0, =BB_ENABLE_TIME_COUNTER
	str r3, [r0]
	
	bx lr

/*
ISR für Alarm Flag
*/
.thumb_func
RTC_Alarm_IRQHandler:
// Writing to the TAR clears the SR[TAF]
	ldr r0, =RTC_TAR
	ldr r1, [r0]			// Alarmwert holen
	str r1, [r0]			// und wieder reinschreiben
	
	ldr r0, =rtc_alarm	// Alarm Flag setzen
	mov r1, #1
	strb r1, [r0]
	bx lr
	
/*
ISR für Sekunden Flag
*/
.thumb_func
RTC_Seconds_IRQHandler:
	
	ldr r0, =second_over
	mov r1, #1
	strb r1, [r0]
	
	bx lr
		
/*** Datenbereich (ab 0x20000000) ***/
.data
second_over: .byte 0x0
rtc_alarm: .byte 0x0

str_day: .asciz "24-Stunden-Modus\n"
str_hour: .asciz "1-Stunden-Modus\n"
str_reset: .asciz "Uhr zurueckgesetzt\n"
str_start: .asciz "Anzeige an\n"
str_stop: .asciz "Anzeige aus\n"
str_preset: .asciz "Uhr vorgestellt\n"
str_end: .asciz "Endzeitpunkt erreicht\n"

str_einschwingzeit: .asciz "ca. 10 Sekunden Einschwingzeit vom Quarz abwarten...\n" 
str_einschwingzeit_erledigt: .asciz "Erledigt!\n"




// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Pin Control Register n
.equ PORTA_PCR06, 0x40049018
.equ PORTA_PCR10, 0x40049028

.equ MASK_SET_MUX_ALT1_PCR, 0x00000100			// 8. Bit EINS => Alternate 1 GPIO
.equ MASK_PORTA6_AND10, 0x000000440				// Bit 6,10 EINS, rest NULL

// GPIO Registers
.equ GPIOA_PDOR, 0x400FF000		// Port Data Output Register
.equ GPIOA_PDDR, 0x400FF014 	// Port Data Direction Register
.equ GPIOA_PSOR, 0x400FF004		// Port Set Output Register	
.equ GPIOA_PCOR, 0x400FF008		// Port Clear Output Register	

// Clock PortA
.equ SIM_SCGC5, 0x40048038
__BBREG BB_ENABLE_PORTA_CLK, SIM_SCGC5, 9			// Clock Port A


// Konstanten fuer Konsolenausgabe
.equ DOPPELPUNKT, 0x3A
.equ PUNKT, 0x2E
.equ NEUE_ZEILE, 0x0A
.equ LEERZEILE, 0x20

// Konstanten fuer Offset im zeit_und_datum Array
.equ MINUTE, 4
.equ STUNDE, 3
.equ TAG, 0
.equ MONAT, 1
.equ JAHR, 2

// Konstanten fuer Uhrzeit und Datum
.equ MAX_MIN, 59
.equ MAX_HR, 23
.equ MAX_TAG, 30
.equ MAX_MON, 12
.equ MAX_YR, 99
.equ RESET_MIN, 0
.equ RESET_HR, 0
.equ RESET_TAG, 1
.equ RESET_MON, 1
.equ RESET_YR, 0
.equ MAX_WOCHENTAG, 6
.equ RESET_WOCHENTAG, 0

// RTC
.equ RTC_CR,  0x4003D010
.equ RTC_IER, 0x4003D01C
.equ RTC_TSR, 0x4003D000
.equ RTC_SR,  0x4003D014
.equ RTC_TPR, 0x4003D004

.equ OSCILLATOR_ENABLE, 0x100		// Mask für Oscillator enable	
.equ ALARM_ONE_MINUTE, 60			// 1 Minute in Sekunden

// Interrupts
.equ IV_RTC_SECONDS, 0x1FFFFF4C		// (IRQn67) => 0x1FFFFE00 + 0x0000_014C
.equ NVIC_ICPR2, 0xE000E288		
.equ NVIC_ISER2, 0xE000E108
.equ IRQn66, 0xC	 // NVIC IRQn67 => 2*32+3 => NVICISER2 und (1<<3)
.equ second_interrupt, 0x10	// TSIE

// Clock
.equ SIM_SCGC6, 0x4004803C

// PIT1
.equ PIT_LDVAL1, 0x40037110		
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TFLG1, 0x4003711C
.equ NVIC_IRQn69, 0x20			// (1<<5)
.equ IV_PIT1, 0x1FFFFF54		// (IRQn69) => 0x1FFFFE00 + 0x0000_0154
// PIT 1 Bitbanding
__BBREG BB_ENABLE_PIT_CLK, SIM_SCGC6, 23
__BBREG BB_PIT_TFLG1_TIF, PIT_TFLG1, 0			// Timer Interrupt Flag
__BBREG BB_PIT1_START_STOP, PIT_TCTRL1, 0			// PIT1 Start
// Konstanten fuer PIT 1
.equ HUNDERT_ms, 2500000		// Fuer DCF77 => 0
.equ ZWEIHUNDERT_ms, 5000000	// Fuer DCF77 => 1

// Bitbanding
__BBREG BB_ENABLE_RTC_CLK, SIM_SCGC6, 29
__BBREG BB_SW_RESET, RTC_CR, 0
__BBREG BB_ENABLE_TIME_COUNTER, RTC_SR, 4
__BBREG BB_ENABLE_TIME_COUNTER, RTC_SR, 4
__BBREG BB_DCF77_OUTPUT, GPIOA_PDOR, 6
// LED
__BBREG BB_LED_OFF, GPIOA_PSOR, 10		
__BBREG BB_LED_ON, GPIOA_PCOR, 10		

// Im Internet finden sich fuer die Einschwingzeiten von Uhrenquarzen (32 kHz) Werte von 300 ms bis 10 Sekunden!
// Da wir keine technischen Daten zum verwendeten Quarz (Hersteller, Typ, Güte usw.) haben, warten wir ca. 10 Sekunden.
// Damit sind wir definitiv auf der sicheren Seite. (aus Forumeintrag)
.equ QUARZ_DELAY, 83333333

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	ldr r0, =str_einschwingzeit
	bl uart_putString	
	
	bl RTC_init
	
	ldr r0, =str_einschwingzeit_erledigt
	bl uart_putString
	
	bl GPIO_init
	bl PIT1_init
	

	mov r11, #1
	mov r12, #0
	ldr r10, =datum_und_zeit
	
	ldr r0, =str_datum
	bl uart_putString
	
	bl set_time_and_date

main_loop:	
	bl uart_charPresent
	cmp r0, #0
	beq no_change
	
	bl uart_getChar
	cmp r0, #'c'
	bne no_change
	
	ldr r0, =str_eingabe_erfolgt
	bl uart_putString
	
	bl set_time_and_date

	
no_change:	
	
// Lt. Wikipedia wird immer die nachfolgende Minute uebertragen		
	bl inc_time_and_date
	bl print_time_and_date
	ldr r0, =str_bitfolge
	bl uart_putString
	
// RTC resetten	
	ldr r1, =BB_ENABLE_TIME_COUNTER
	str r12, [r1]			// RTC stop

	ldr r2, =RTC_TPR
	str r12, [r1]			// prescaler reset
	ldr r2, =RTC_TSR
	str r12, [r2]			// Sekundenwert reset
	
	str r11, [r1]			// RTC start	
		
// Bedeutung der Bits 0-59 aus Wikipedia
// Bit 0	 => 0: Start einer neuen Minute
// Bit 1-14  => Wetterinformationen der Firma MeteoTime sowie Informationen des Katastrophenschutzes
// Bit 15	 => Rufbit
// Bit 16	 => 1: Am Ende dieser Stunde wird MEZ/MESZ umgestellt

	mov r4, #17	
bitfolge_null:
	mov r0, #0
	bl create_signal
	subs r4, r4, #1
	bne bitfolge_null
	
// Bit 17 &  => 01: MEZ
// Bit 18	 => 10: MESZ
// Sommerzeit einstellen	
	mov r0, #1
	bl create_signal
	mov r0, #0
	bl create_signal
// Bit 19	 => 1: Am Ende dieser Stunde wird eine Schaltsekunde eingefuegt
	mov r0, #0
	bl create_signal
// Bit 20 	 => 1: Beginn der Zeitinformation
	mov r0, #1
	bl create_signal
	
// Bit 21-24 => Minute(Einer)
	ldrb r0, [r10, #MINUTE]
	bl extract_einer // Einer Extrahieren
	mov r1, #4		 // Anzahl Stellen uebergeben
	bl calc_bcd
	mov r6, r0		// paritaet zwischenspeichern
// Bit 25-27 => Minute(Zehner)
    ldrb r0, [r10, #MINUTE]
    bl extract_zehner
    mov r1, #3
    bl calc_bcd
    
// Bit 28 	 => Paritaet Minute
	eor r0, r6, r0	// paritaet bestimmen
	bl create_signal
// Bit 29-32 => Stunde(Einer)
	ldrb r0, [r10, #STUNDE]
	bl extract_einer	
	mov r1, #4		// Anzahl Stellen uebergeben
	bl calc_bcd
	mov r6, r0		// paritaet zwischenspeichern
// Bit 33-34 => Stunde(Zehner)
    ldrb r0, [r10, #STUNDE]
    bl extract_zehner
    mov r1, #2
    bl calc_bcd

// Bit 35	 => Paritaet Stunde
	eor r0, r6, r0	// paritaet bestimmen
	bl create_signal
	
// Bit 36-39 => Kalendertag(Einer)
	ldrb r0, [r10, #TAG]
    bl extract_einer	
	mov r1, #4		// Anzahl Stellen uebergeben
	bl calc_bcd
	mov r6, r0		// paritaet zwischenspeichern
	
// Bit 40-41 => Kalendertag(Zehner)
	ldrb r0, [r10, #TAG]
    bl extract_einer	
	mov r1, #2		// Anzahl Stellen uebergeben
	bl calc_bcd
	eor r0, r6, r0	// paritaet bestimmen
	
// Bit 42-44 => Wochentag
	ldr r0, =wochentag
	ldrb r0, [r0]
	add r0, r0, #1	// damit Wochentage wieder passen => 1 = Montag,... 7 = Sonntag
	mov r1, #3		// Anzahl Stellen uebergeben
	bl calc_bcd
	eor r0, r6, r0	// paritaet bestimmen
	
// Bit 45-48 =>	Monatsnummer(Einer)
	ldrb r0, [r10, #MONAT]
    bl extract_einer	
	mov r1, #4		// Anzahl Stellen uebergeben
	bl calc_bcd
	eor r0, r6, r0	// paritaet bestimmen
	
// Bit 49	 => Monatsnummer(Zehner)
	ldrb r0, [r10, #MONAT]
    bl extract_zehner	
	mov r1, #1		// Anzahl Stellen uebergeben
	bl calc_bcd
	eor r0, r6, r0	// paritaet bestimmen
	
// Bit 50-53 => Jahr(Einer)
	ldrb r0, [r10, #JAHR]
    bl extract_einer	
	mov r1, #4		// Anzahl Stellen uebergeben
	bl calc_bcd
	eor r0, r6, r0	// paritaet bestimmen
	
// Bit 54-57 => Jahr(Zehner)
	ldrb r0, [r10, #JAHR]
    bl extract_zehner	
	mov r1, #4		// Anzahl Stellen uebergeben
	bl calc_bcd
	
// Bit 58 	 => Paritaet Datum

	eor r0, r6, r0	// paritaet bestimmen
	bl create_signal
// Bit 59 	=>	Bei einer Minute ohne Schaltsekunde wird zur Sekunde 59 keine Sekundenmarke gesendet. 
// Bei einer Minute mit Schaltsekunde wird zur Sekunde 59 eine „0“ und zur Sekunde 60 keine Sekundenmarke gesendet.
	// erstmal ignorieren und 1 sec abwarten
	bl delay_until_second_over
	
	mov r0, #NEUE_ZEILE
	bl uart_putChar
	
	b main_loop

/*
Diese Funktion bestimmt die Paritaet einer Bitfolge
Übergabeparameter: r0: Zu bestimmende Bitfolge
Rückgabeparamter: r0: 0: bei gerader Paritaet, 1: bei ungerader Paritaet
*/
.thumb_func
calc_parity:
	
	bx lr
/*
Diese Funktion extrahiert die Einer-Stelle einer Zahl
Übergabeparameter: r0: Zu extrahierende Zahl
*/
.thumb_func
extract_einer:

	mov r3, #10
	udiv r1, r0, r3		// Zehner
	mul r2, r1, r3
	sub r0, r0, r2 		// Einer fuer Uebergabe
	
	bx lr

/*
Diese Funktion extrahiert die Zehner-Stelle einer Zahl
Übergabeparameter: r0: Zu extrahierende Zahl
*/		
.thumb_func
extract_zehner:
	mov r1, #10
	udiv r0, r0, r1		// Zehner fuer Uebergabe
	
	bx lr

/*
Diese Funktion berechnet den BCD Wert der übergebenen Zahl mittels Schiebeoperation. Zusätzlich wird jeweils das entsprechende Bit ausgegeben
Die Parität wird bestimmt und zurückgegeben.
Übergabeparameter: r0: Zahl von der BCD berechnet werden soll, r1: Anzahl der Stellen für die Bits
Rückgabeparameter: r0: Paritaet 
*/
.thumb_func
calc_bcd:
	push {r4-r6,lr}
	mov r4, r0			// uebergabeparameter zwischenspeichern
	mov r5, r1			// uebergabeparameter zwischenspeichern
	mov r6, #0			// fuer Paritaet 
bcd_loop:	
	and r0, r4, #1		// nur 1. bit beachten
	eor r6, r6, r0		// paritaet
	bl create_signal
	lsr	r4, r4, #1		// für Prüfen der nächsten Stelle 			
	subs r5, r5, #1
	bhi bcd_loop
	mov r0, r6			// Rückgabeparameter paritaet
	
	pop {r4-r6,pc}
	
.thumb_func
delay_until_second_over:
	
	ldr r0, =second_over
second_not_over:	
	ldrb r1, [r0]
	cmp r1, #1
	bne second_not_over
	mov r1, #0
	strb r1, [r0]	// reset second over flag
	
	bx lr
	
/*
Funktion, fuer das passende "Amplitudenmodulierte" Signal
Uebergabeparamer: r0: darzustellendes Bit (0 oder 1)
*/
.thumb_func
create_signal:
	push {lr}
// ueberprüfen welches Bit uebergeben wurde und entsprechenden Wert fuer PIT1 laden	
	cmp r0, #0
	ite eq
	ldreq r1, =HUNDERT_ms
	ldrne r1, =ZWEIHUNDERT_ms
		
	ldr r2, =PIT_LDVAL1
	str r1, [r2]		// Entsprechenden Wert fuer PIT setzen
	
	bl uart_putByteBase10	// uebergebenes Bit ausgeben
	
	ldr r0, =BB_PIT1_START_STOP       	 	 // start pit
	mov r1, #1
	str r1, [r0]

 
	ldr r2, =BB_DCF77_OUTPUT				
	mov r3, #0
	str r3, [r2]		// PORTA6 LOW 	
		
    ldr r2, =BB_LED_OFF	// LED AUS
    str r1, [r2]
    
    ldr r2, =flag_pit_over

wait_for_pit:
	ldrb r3, [r2]
	cmp r3, #1
	bne wait_for_pit
	
	mov r3, #0
	strb r3, [r2]		// reset pit flag
	
	ldr r2, =BB_DCF77_OUTPUT
	str r1, [r2]		// PORTA6 HIGH
    ldr r2, =BB_LED_ON			
    str r1, [r2]		// LED AN	
    
	str r3, [r0]		// stop pit	
	
	bl delay_until_second_over	// restliche Zeit bis Sekunde vorbei warten
	
	pop {pc}
/*
Ink. Zeit und bei Bedarf Datum
*/	
.thumb_func
inc_time_and_date:
// Minute
	ldr r2, =datum_und_zeit
	ldrb r0, [r2, #MINUTE]
	cmp r0, #MAX_MIN
	ite ne
	addne r0, r0, #1
	moveq r0, #RESET_MIN	// max Min erreicht. Reset 
	strb r0, [r2, #MINUTE]	// Neuen Minuten Wert ablegen
	bne finish				// Ueberlauf? Falls nein, fertig
// Stunde
	ldrb r0, [r2, #STUNDE]
	cmp r0, #MAX_HR
	ite ne
	addne r0, r0, #1
	moveq r0, #RESET_HR		// max Stunde erreicht. Reset 
	strb r0, [r2, #STUNDE]	// Neuen Stunden Wert ablegen
	bne finish				// Ueberlauf? Falls nein, fertig
// Wochentag	
	ldr r0, =wochentag
	ldrb r1, [r0]
	cmp r1, #MAX_WOCHENTAG	
	ite ne
	addne r1, r1, #1			// inc. Wochentag
	moveq r1, #RESET_WOCHENTAG	// reset Wochentag, 
	strb r1, [r0]				// Neuen Wochentag ablegen
// Tag
	ldrb r0, [r2, #TAG]
	cmp r0, #MAX_TAG
	ite ne
	addne r0, r0, #1
	moveq r0, #RESET_TAG	// max Tag erreicht. Reset 
	strb r0, [r2, #TAG]		// Neuen Tag Wert ablegen
	bne finish				// Ueberlauf? Falls nein, fertig
// Monat
	ldrb r0, [r2, #MONAT]
	cmp r0, #MAX_MON
	ite ne
	addne r0, r0, #1
	moveq r0, #RESET_MON	// max Monat erreicht. Reset
	strb r0, [r2, #MONAT]	// Neuen Monat Wert ablegen
	bne finish				// Ueberlauf? Falls nein, fertig
// Jahr
	ldrb r0, [r2, #JAHR]
	cmp r0, #MAX_YR
	ite ne
	addne r0, r0, #1
	moveq r0, #RESET_YR		// max Jahr erreicht. Reset 
	strb r0, [r2, #JAHR]	// Neuen Tag Wert ablegen	
finish:
	bx lr
	
/*
Zeit und Datum ausgeben am Terminal
*/
.thumb_func
print_time_and_date:
	push {r4, lr}
	
	ldr r4, =datum_und_zeit
	
	mov r0, #NEUE_ZEILE
	bl uart_putChar
	
// Tag
	ldrb r0, [r4], #1
	bl print_with_zero_or_not

	mov r0, #PUNKT
	bl uart_putChar
// Monat
	ldrb r0, [r4], #1
	bl print_with_zero_or_not
	
	mov r0, #PUNKT
	bl uart_putChar
// Jahr
	ldrb r0, [r4], #1
	bl print_with_zero_or_not
	
	mov r0, #LEERZEILE
	bl uart_putChar
// Stunde	
	ldrb r0, [r4], #1
	bl print_with_zero_or_not
	
	mov r0, #DOPPELPUNKT
	bl uart_putChar
// Minute	
	ldrb r0, [r4]
	bl print_with_zero_or_not
	
	mov r0, #LEERZEILE
	bl uart_putChar
	
// Wochentag
	ldr r0, =arr_str_wochentage
	ldr r1, =wochentag
	ldrb r1, [r1]
	lsl r1, r1, #2			// offset anpassen
	ldr r0, [r0, r1]		// entsprechenden String aus dem Array mit Wochentagen laden
	bl uart_putString
	
	mov r0, #NEUE_ZEILE
	bl uart_putChar
	
	pop {r4, pc}
/*
Ausgabe mit oder ohne fuehrende Null
Übergabe: r0: auszugebende Zahl
*/	
.thumb_func
print_with_zero_or_not:
	push {lr}
	cmp r0, #9
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	pop {pc}
	
/*
Diese Funktion ist für das Setzen von Tag, Datum, Zeit via Terminal
*/
.thumb_func
set_time_and_date:
	push {r4, lr}
	
	ldr r4, =datum_und_zeit // Anfangsadresse des Arrays fuer Datum und Zeit	
// Tag
	ldr r0, =str_tag
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4], #1	// postinkrement
// Monat
	ldr r0, =str_monat
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4], #1	// postinkrement
// Jahr
	ldr r0, =str_jahr
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4], #1	// postinkrement
// Stunde	
	ldr r0, =str_stunde
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4], #1	// postinkrement
// Minute	
	ldr r0, =str_minute
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4]
// Wochentag	
	ldr r0, =str_wochentag
	bl uart_putString	
	bl uart_getByteBase10			
	ldr r1, =wochentag

	strb r0, [r1]		// Wochentag ablegen
	pop {r4, pc}

/*
Funktion fuer Initialisierung der GPIO
*/
.thumb_func
GPIO_init:
	
/*Enable Clock*/	
	mov r3, #1
	
	ldr r0, =BB_ENABLE_PORTA_CLK
	str r3, [r0]
	
/* PTA 6+10 als output setzen  */
	ldr r0, =GPIOA_PDDR
	ldr r1, =MASK_PORTA6_AND10
	ldr r2, [r0]
	orr r2, r2, r1
	str r2, [r0]
	
	
/* Clear Register PORTA 6, 10 Set Mux to Alternative 1 GPIO*/
	mov r1, #MASK_SET_MUX_ALT1_PCR	
	
	ldr r0, =PORTA_PCR06
	str r1, [r0]

	ldr r0, =PORTA_PCR10
	str r1, [r0]	
	
// LED ausschalten
	ldr r0, =BB_LED_OFF
	str r3, [r0]
	
	bx lr
/*
Funktion fuer Initialisierung der RTC
*/	
.thumb_func
RTC_init:
	mov r2, #0
	mov r3, #1
	
// Clock aktivieren
	ldr r0, =BB_ENABLE_RTC_CLK
	str r3, [r0]
	
// SW Reset RTC durchführen
	ldr r0, =BB_SW_RESET
	str r3, [r0]
	str r2, [r0]
	
// 32.768kHz Oszillator aktivieren
	ldr r0, =RTC_CR
	movw r1, #OSCILLATOR_ENABLE		
	str r1, [r0]

// Einschwingvorgang abwarten
	ldr r0, =QUARZ_DELAY
wait_loop:
	subs r0, r0, #1
	bne wait_loop
	
// Sekundenzähler auf 0 setzen	
	ldr r0, =RTC_TSR
	str r2, [r0]	
// reset Prescaler
	ldr r1, =RTC_TPR
	str r2, [r1]		
// Second interrupt enable
	ldr r0, =RTC_IER
	mov r1, #second_interrupt	
	str r1, [r0]

// Interrupt Vektor setzen
	ldr r0, =IV_RTC_SECONDS
	ldr r1, =RTC_Seconds_IRQHandler
	str r1, [r0]

// pending interrupts löschen
	ldr r0, =NVIC_ICPR2
	mov r1, #IRQn66				
	str r1, [r0]	
// RTC interrupts alarm & seconds aktivieren
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
// Enable Time Counter
	ldr r0, =BB_ENABLE_TIME_COUNTER
	str r3, [r0]
	
	bx lr

/* Init Pit, enable interrupts, setting counter values */
.thumb_func
PIT1_init:

/*Takt für PIT aktivieren*/	
	mov r2, #1
	ldr r0, =BB_ENABLE_PIT_CLK
	str r2, [r0]
	
/*Interrupt Vektor zu PIT1 setzen*/
	ldr r0, =IV_PIT1
	ldr r1, =PIT1_IRQHandler
	str r1, [r0]
	
// pending interrupts zu PIT1 löschen (NVIC)
	ldr r0, =NVIC_ICPR2
	mov r1, #NVIC_IRQn69
	str r1, [r0]				
	
/*Interrupt zu PIT1 aktivieren (NVIC)*/        
	ldr r0, =NVIC_ISER2
	str r1, [r0]
		
/*PIT1 Startwert 0 sek initialisieren*/	
	ldr r0, =PIT_LDVAL1
	mov r2, #0	
	str r1, [r0]

/*Interrupt PIT1 aktivieren*/
	ldr r0, =PIT_TCTRL1
	mov r1, #2					
	str r1, [r0]		// interrupt enable, timer not chained 
	
/* alle PITs aktivieren */	
	ldr r0, =PIT_MCR
	str r2, [r0]
	
	bx lr

/* PIT1 Interrupt Handler */	
.thumb_func
PIT1_IRQHandler:				
/* clear interrupt */
	ldr r0, =BB_PIT_TFLG1_TIF 
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =flag_pit_over
	strb r1, [r0]		// Flag, dass Sekunde vorbei ist, aktualisieren
	
	bx lr


	
/*
ISR für Sekunden Flag
*/
.thumb_func
RTC_Seconds_IRQHandler:
	
	ldr r0, =second_over
	mov r1, #1
	strb r1, [r0]
	
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
second_over: .byte 0x0
flag_pit_over: .byte 0x0

wochentag: .byte 0						// 0 = Montag, 1 = Dienstag, ... 6 = Sonntag
datum_und_zeit: .byte 0, 0, 0, 0, 0		// Tag, Monat, Jahr, Stunde, Minute

