// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// FTM Register
.equ FTM0_C3SC, 0x40038024		// Status and Control Ch3 
.equ FTM0_C3V, 0x40038028		// Value Ch3 
.equ FTM0_SC, 0x40038000		// Status and Control  
.equ FTM0_CNT, 0x40038004		// Counter 
.equ FTM0_MOD, 0x40038008		// Modulo
.equ FTM0_CNTIN, 0x4003804C								 
.equ FTM0_MODE, 0x40038054		
.equ FTM0_QDCTRL, 0x40038080	

// configs
.equ FTM0_SC_CONFIG, 0x48 		// 1001000: TOIE enable, up counting, system clock, no prescale 
.equ FTM0_MODE_CONFIG, 0x5		// FTM enable, write protection disable
.equ FTM0_C3SC_CONFIG, 0x68		// 1101000	// channel interrupt enable, edge aligned PWM high true, rising edge, no dma
.equ FTM0_MOD_CONFIG, 24999		// 25MHz/25000 => 1kHz
.equ CHECK_INTERRUPT_FLAG, 0x80	

// FTM0 interrupt
.equ NVIC_ICPR1, 0xE000E284		
.equ NVIC_ISER1, 0xE000E104
.equ NVIC_IRQn62, 0x40000000	// (1<<30)		
.equ IV_FTM0, 0x1FFFFF38		// (IRQn69) => 0x1FFFFE00 + 0x0000_0138

// FTM bitbanding
__BBREG BB_FTM0_WPDIS, FTM0_MODE, 2		// Write Protect


// start/top ftm for interrupt procedure
.equ STOP_FTM,	0xE7				// for FTM0_SC[CLKS]: Clock Source Selection 00 => ftm stop
.equ START_FTM,	0x8					// for FTM0_SC[CLKS]: Clock source Selection 01 => System Clock => ftm start

// clock
.equ SIM_SCGC5, 0x40048038			 
.equ SIM_SCGC6, 0x4004803C			
// clock bitbanding
__BBREG BB_ENABLE_CLK_PORTA, SIM_SCGC5, 9
__BBREG BB_ENABLE_CLK_FTM0, SIM_SCGC6, 24

// Port A
.equ PORTA_PCR6, 0x40049018
.equ ALTERNATE_FUNCTION_FTM0_CH3, 0x300	

// fuer Konsolenausgabe
.equ PROMPT, 0x3E

// Filter
.equ FILTER_SEVEN_BIT, 0x7F		// 1111111
// Aus DatenblattS.958,959: Positiv: ELSnB:1,ELSnA:0. Negativ: ELSnB:X, ELSnA:1 somit reicht es aus nur ELSnA zu ändern
.equ FILTER_BIT_2, 0x7B			// 1111011	ELSnA:0
.equ SET_BIT_2, 0x4				// 0000100	ELSnA:1

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl FTM_init
	
	ldr r4, =var_pwm_value	
	ldr r5, =var_polarity
	ldr r6, =arr_str_prozent
	ldr r8, =arr_pwm_values
	mov r9, #0
	mov r10, #1

print_prompt:	
	mov r0, #PROMPT
	bl uart_putChar
	
main_loop:		
	bl uart_charPresent
	cmp r0, #0
	beq main_loop
	
	bl uart_getChar
	cmp r0, #'+'
	bne check_minus
	
	ldr r1, =flag_polarity_change	// Erkennung, dass Polaritaet angepasst werden soll
	strb r10, [r1]
	
	strb r9, [r5]			// Polaritaet variable auf 0 setzen
	ldr r0, =str_pol_pos
	bl uart_putString
	
	b print_prompt			// Prompt fuer nächste Eingabe ausgeben und main_loop von vorne starten
	
check_minus:
	cmp r0, #'-'
	bne check_zero
	
	ldr r1, =flag_polarity_change	// Erkennung, dass Polaritaet angepasst werden soll
	strb r10, [r1]
	
	strb r10, [r5]			// Polaritaet variable auf 1 setzen
	ldr r0, =str_pol_neg	
	bl uart_putString
		
	b print_prompt			// Prompt fuer nächste Eingabe ausgeben und main_loop von vorne starten

check_zero:	// PWM 5%	
	cmp r0, #'0'
	itt eq
	moveq r1, #0
	beq new_pwm_val

//check_one: PWM 15%
	cmp r0, #'1'	
	itt eq
	moveq r1, #1
	beq new_pwm_val

// check_two: PWM 25%
	cmp r0, #'2'
	itt eq
	moveq r1, #2
	beq new_pwm_val

// check_three: PWM 35%
	cmp r0, #'3'
	itt eq
	moveq r1, #3
	beq new_pwm_val
	
// check_four: PWM 45%
	cmp r0, #'4'
	itt eq
	moveq r1, #4
	beq new_pwm_val
	
// check_five: PWM 55%
	cmp r0, #'5'
	itt eq
	moveq r1, #5
	beq new_pwm_val

// check_six: PWM 65%
	cmp r0, #'6'
	itt eq
	moveq r1, #6
	beq new_pwm_val

//check_seven: PWM 75%
	cmp r0, #'7'
	itt eq
	moveq r1, #7
	beq new_pwm_val

// check_eight: PWM 85%
	cmp r0, #'8'
	itt eq
	moveq r1, #8
	beq new_pwm_val

// check_nine: PWM 95%	
	cmp r0, #'9'
	bne main_loop
	mov r1, #9

new_pwm_val:
	ldr r3, =flag_pwm_value_change
	strb r10, [r3]			// fuer Erkennung im Interrupt
	lsl r1, r1, #2			// fuer offset
	ldr r2, [r8, r1]		// entsprechenden PWM Wert aus dem Array holen
	str r2, [r4]			// In der Variable ablegen fuer Interrupt Behandlung
	ldr r0, [r6, r1]		// ensptrechenden String aus dem Array holen
	bl uart_putString
	
	mov r0, #PROMPT
	bl uart_putChar
	
	b main_loop


.thumb_func
FTM_init:
	mov r3, #0
	mov r2, #1
// enable clock PORTA	
	ldr r0, =BB_ENABLE_CLK_PORTA
	str r2, [r0]
// Alternate 3 funtion => FTM0_CH3 	
	ldr r0, =PORTA_PCR6
	mov r1, #ALTERNATE_FUNCTION_FTM0_CH3
	str r1, [r0]
	 
// Enable Clock	FTM0
	ldr r0, =BB_ENABLE_CLK_FTM0
	str r2, [r0]
	
// disable write protect
	ldr r0, =BB_FTM0_WPDIS
	str r2, [r0]
// ftm0 enable	
	ldr r0, =FTM0_MODE	
	mov r1, #FTM0_MODE_CONFIG
	str r1, [r0]
// disable quadrature decoder	
	ldr r0, =FTM0_QDCTRL
	str r3, [r0]
		
	ldr r0, =FTM0_C3SC
	mov r1,	#FTM0_C3SC_CONFIG
	str r1, [r0]
	
// Periodendauer 1kHz
	ldr r0, =FTM0_MOD
	ldr r1, =FTM0_MOD_CONFIG
	str r1, [r0]
	
// 	Counter Initial Value resetten
	ldr r0, =FTM0_CNTIN
	str r3, [r0]
	
// 55% Pulsweite Init
	ldr r0, =FTM0_C3V
	ldr r1, =var_pwm_value
	ldr r1, [r1]
	str r1, [r0]

// Interrupt Vektor zu FTM0 setzen
	ldr r0, =IV_FTM0
	ldr r1, =FTM0_IRQHandler
	str r1, [r0]
	
// pending interrupts zu FTM0 löschen (NVIC)
	ldr r0, =NVIC_ICPR1
	mov r1, #NVIC_IRQn62
	str r1, [r0]		
	
// Interrupt zu FTM0 aktivieren (NVIC)
	ldr r0, =NVIC_ISER1
	str r1, [r0]
		
// FTM0 starten	
	ldr r0, =FTM0_SC
	mov r1, #FTM0_SC_CONFIG
	str r1, [r0]	
	
	bx lr
	
	
.thumb_func
FTM0_IRQHandler:
// check, ob TOF gesetzt
	ldr r0, =FTM0_SC
	ldr r1, [r0]
	ands r2, r1, #CHECK_INTERRUPT_FLAG
	beq check_channel_interrupt
// clear Overflow Flag
	and r1, r1, #FILTER_SEVEN_BIT
	str r1, [r0]		

//Pruefen, ob Polarität ändern
	ldr r0, =flag_polarity_change
	ldrb r1, [r0]
	cmp r1, #1
	bne check_channel_interrupt
// Polatitaet soll geaendert werden
	mov r2, #0
	strb r2, [r0]		// reset_polarity_change flag
	
	ldr r3, =var_polarity
	ldrb r1, [r3]	
	  
	ldr r3, =FTM0_C3SC
	ldr r2, [r3]

	cmp r1, #0			// pol = 0 => auf positiv setzen // ELSA: 0
	itttt eq
	moveq r0, #FILTER_BIT_2
	andeq r1, r2, r0		// clear ELSnA-bit
	streq r1, [r3]			// change polarity	
	beq check_channel_interrupt
	
	cmp r1, #1			// pol = 1 => auf negativ setzen	// ELSA: 1
	ittt eq	
	moveq r0, #SET_BIT_2
	orreq r1, r2, r0		// set ELSnA-bit
	streq r1, [r3]			// change polarity
		
check_channel_interrupt:
	ldr r0, =FTM0_C3SC
	ldr r1, [r0]
	ands r2, r1, #CHECK_INTERRUPT_FLAG
	beq isr_end
// clear Channel Flag
	and r1, r1, #FILTER_SEVEN_BIT
	str r1, [r0]
	
// Check, ob PWM geaendert werden soll	
	ldr r0, =flag_pwm_value_change
	ldrb r1, [r0]
	
	cmp r1, #1
	bne isr_end
// PWM soll geaendert werden 
	mov r2, #0
	strb r2, [r0]		// flag_pwm_value_change reset
	
	ldr r0, =FTM0_SC
	ldr r1, [r0]
	and r1, r1, #STOP_FTM
	str r1, [r0]						// stop FTM
	
// Pulsweite anpassen	
	ldr r2, =FTM0_C3V
	ldr r3, =var_pwm_value
	ldr r3, [r3]
	str r3, [r2]	
	
	orr r1, r1, #START_FTM
	str r1, [r0]						// start FTM
		
isr_end:	

	bx lr
	
/*** Datenbereich (ab 0x20000000) ***/
.data
var_polarity: .byte 0	// 0 = positiv, 1 = negativ
flag_polarity_change: .byte 0	

var_pwm_value: .word 13750	// Init bei 55%
flag_pwm_value_change: .byte 0
// Berechnung PWM Werte: 25000*Prozentwert/100, wobei Prozentwert: 5,15,25...95
arr_pwm_values: .word 1250, 3750, 6250, 8750, 11250, 13750, 16250, 18750, 21250, 23750 //5%,15%,25%...95%	

str_pol_pos: .asciz "Polaritaet eingestellt: positiv\n"
str_pol_neg: .asciz "Polaritaet eingestellt: negativ\n"

str_5Prozent:  .asciz "5% \n"
str_15Prozent: .asciz "15% \n"
str_25Prozent: .asciz "25% \n"
str_35Prozent: .asciz "35% \n"
str_45Prozent: .asciz "45% \n"
str_55Prozent: .asciz "55% \n"
str_65Prozent: .asciz "65% \n"
str_75Prozent: .asciz "75% \n"
str_85Prozent: .asciz "85% \n"
str_95Prozent: .asciz "95% \n"
arr_str_prozent: .word str_5Prozent, str_15Prozent, str_25Prozent, str_35Prozent, str_45Prozent, str_55Prozent, str_65Prozent, str_75Prozent, str_85Prozent, str_95Prozent






// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ COUNTER, 0x05				//Eingabemenge 16

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/



main:	
	bl uart_init

	// Einlesen von 16 Bytes
	mov r4, #COUNTER		//Zaehler laden
	ldr r5, =bytearray		//Adresse des Arrays
	ldr r0, =str_eingabe	// Zeiger auf String laden
	bl uart_putString		// String ausgeben
	
	
	
	
	//Einlesen 
loop_eingabe: 
	ldr r0, =str_prompt		//Zeiger auf Prompt laden
	bl uart_putString		//Prompt ausgeben
	bl uart_getByte			//ein Byte einlesen
	strb r0, [r5], #1		//im Array ablegen und Adresse in r5 um eins erhoehen
	bl uart_putByte			//Byte ausgeben
	subs r4, r4, #1			//Zaehler dekrementieren
	bne loop_eingabe		//solange Zaehler noch nicht Null
	
	
	
	//Maximumbestimmung
	ldr r0, =str_startsuche 	//Zeiger auf String laden
	bl uart_putString			//String ausgeben
	
	bl pit3_init				//Hier wird der Zaehler (PeriodicTimer) initialisiert
	
	
	
	
	
	mov r9, #0					//Maximum mit null initialisieren 
	mov r4, #COUNTER
	
	
	
loop_maximum:
	ldrb r0, [r5, #-1]!			//Byte aus dem Array holen, vorher wird die Adresse r5 dekrementiert
	cmp r0, r9					//MIt bisherigem Maximum vergleichen
	it hi						//wenn es groesser ist (unsigned) 
	movhi r9, r0				//wenn groesser, wird bisheriges Maximum ersetzt
	subs r4, r4, #1				//Zaehler dekrementieren
	bne loop_maximum			//solange Zaehler noch nicht Null
	
	bl pit3_getval
	mov r6, r0					//Speichern Speichern Inhalt r0 in r6
	
	
	
	

	
	ldr r0, =maximum			//Adresse des Speichers fuer maximum laden
	strb r9, [r0]				//das Maximum speichern
	
	
	
	//Ausgabe der Ergebnisse
	ldr r0, =str_endesuche		//zeiger auf String laden 
	bl uart_putString			//String ausgeben
	
	mov r0, r9					//Maximum in R0 kopieren 
	bl uart_putByte				//als Byte ausgeben
	
	ldr r0, =str_suche			//Adresse nach r0	
	bl uart_putString			//Ausgabe des Strings
	
	mov r0, r6					//Inhalt r6 nach r0	
	
	bl uart_putInt16			//Ausgabe der "gemessenen" Zeit
	
	
	
	
	//Beenden Timer und Reset
	//Das Register PIT_TCTRL3 muss Wert 0x0 erhalten
	
	ldr r0, =0x40037138		//Adresse in r0
	mov r9, #0x0			//0x0 nach r9
	str r9, [r0]			//Wert aus r0 als Adresse "definiert" und Wert aus r9 in Adresse speichern
	
	/*ldr r0, =0x40037134
	mov r9, 0x0
	strb r9, [r0]*/
	
	
	
	
	b main					//Neustart am Anfang
	
	

/*** Datenbereich (ab 0x20000000) ***/
.data

bytearray:
.rept COUNTER
.byte 0x00
.endr
maximum: .byte 0x0
str_prompt: .asciz "\n>0x"
str_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben!\n"
str_startsuche: .asciz "\nDurchsuchen gestartet\n"
str_endesuche: .asciz "Durchsuchen beendet\nMaximum: 0x" 
str_suche: .asciz "\nSuchzeit: 0x"



//Versuch 1-1 e)

/*Nach mehreren Eingaben mit dem Hoechstwert an unerschiedlichen Stellen, ist die benoetigte Zeit immer gleich. 
Die Programmausfuehrung (insbesondere der Loop) ist unabhaengig von der Eingabe immer identisch.*/

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)



// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


//Konstantendeklaration

.equ BitBand_Base, 0x22000000	//Definieren der Bit-Banding-Basisadresse




/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/




main:

	//Aufgabe a)	Einlesen der zwei Bit-Nummern

	bl uart_init				//Initialisiert das Terminal

	ldr r0, =str_0				//Text in R0				
	bl uart_putString			//Gibt einen nullterminierten String auf dem Terminal aus
	bl uart_getByte				//Liest einen zweistelligen hexadezimalen Wert vom Terminal ein und gibt ihn in R0 zurueck.
	mov r4, r0					//Wert 1 (0_Bit) in Register r
	and r4, #0x1f				//UND_Verknuepfung um das Abschneiden der drei hoechstwertigen Bits des 0Bit-Wertes zu ermoeglichen
	
	
	movs r0, r4					//Wert in R0, zur Ausgabe
	bl uart_putByte				//Gibt ein Byte in hexdezimaler Form auf dem Terminal aus

	
	
	
	
	ldr r0, =str_1				//Text in R0	
	bl uart_putString			
	bl uart_getByte
	mov r5, r0					//R5 = 1Bit-Wert
	and r5, #0x1f				//UND_Verknuepfung um das Abschneiden der drei hoechstwertigen Bits des 1Bit-Wertes zu ermoeglichen
	
	
	movs r0, r5					//Fuer Ausgabe in R0 
	bl uart_putByte				//Ausgabe 






/****************************************************************************************************************************************************/	

	//Aufgabe b) Ohne Bitbanding

	ldr r6, =VAR32				//Adresse der 32-Bit-Variable in Register 
	ldr r6, [r6]				//Inhalt der Variable "VAR32" in r6
	

	
	//Aufgabe d) Ausgabe 
	ldr r0, =str_B_old			//Ausgabe des Strings in Terminal
	bl uart_putString
	
	mov r0, r6					//Ausgabe des Wertes in Terminal 
	bl uart_putInt32		


	mov r8, #0x1				//Hilfs-Register zum Setzen der Bits
	lsl r8, r4					//Linksschub zum erreichen der Bitposition
	bic r6, r8					//Bit-Clear --> die "1" wird durch  "0" ersetzt
	lsr r8, r4 					//Rechtsschub fuer die Ausgangsposition
	
	lsl r8, r5					//Linksschub zur erreichen der Bitposition
	orr r6, r8					//Oder-Verknuepfung zum Setzen der "1" an der vorher bestimmten Position
	
		
	ldr r0, =str_B_new			//Schreiben der neuen 32-Bit-Variable in R0 zur Ausgabe
	bl uart_putString			
	mov r0, r6					//In R0 zur Ausgabe
	bl uart_putInt32			//Ausgabe 
	
						
	ldr r0, =VAR32				
	str r6, [r0]				//Speichern des Wertes in der Variable im Datenbereich 





/***************************************************************************************************************************************************/


	//Aufgabe c) Bit Banding
	//Aufgabe d) Ausgabe der initialen Werte

	ldr r0, =str_C_old			//Ausgabe des Strings in Terminal						
	bl uart_putString
	
	ldr r0, =BiBa				//Ausgabe des Wertes im Terminal 
	ldr r0, [r0]
	bl uart_putInt32

	
	ldr r0, =str_C_new
	bl uart_putString
	
	//Bit-Band-Berechnung 0-Bit
						
	
	mov r6, #BitBand_Base	  	//Bitbandbasisaddresse in Register R6 - Arbeitsregister	
	add r6, #0x200				//Bestimmung der Basisaddresse der Variable mit der Addresse 0x20000010 im "Bitbandingbereich" 
	
	lsl r4, #2					//Berechnung der Position 
	add r6, r4					//Berechnung der Position 
	
	mov r8, #0x0				//Laden von 0x0 in R8 		
	str r8, [r6]				//Setzen von "0" an der Bit-Band-Adresse
	
	
	//Bit-Band-Berechnung 1-Bit
	
	
	mov r6, #BitBand_Base		//Bitbandbasisaddresse in Register R6 - Arbeitsregister
	add r6, #0x200				//Bestimmung der Basisaddresse der Variable mit der Addresse 0x20000010 im "Bitbandingbereich" 
	
	lsl r5, #2					//Berechnung der Position
	add r6, r5					//Berechnung der Position 	
	
	mov r8, #0x1				//Laden von 0x1 in R8
	str r8, [r6]				//Setzen der "1" an der Bit-Band-Adresse
	
	
	ldr r0, =BiBa
	ldr r0, [r0]
	bl uart_putInt32
	
	
/***************************************************************************************************************************************************/	

	//Aufgabe e) Erneuter Programmaufruf
	b main
	


/***************************************************************************************************************************************************/






/*** Datenbereich (ab 0x20000000) ***/
.data

VAR32: .4byte 0xFFFFFFFF

.align 4						//Verschieben des Datenbereiches auf 0x20000010

BiBa: .4byte 0xFFFFFFFF

str_0: .asciz "\n\nNummer des 0-Bits: 0x"
str_1: .asciz "\nNummer des 1-Bits: 0x"
str_B_old: .asciz "\n(Ohne Bit-Banding) alter 32-Bit-Wert: 0x"
str_B_new: .asciz "\n(Ohne Bit-Banding) neuer 32-Bit-Wert: 0x"
str_C_old: .asciz "\n(Mit Bit-Banding) alter 32-Bit-Wert: 0x"
str_C_new: .asciz "\n(Mit Bit-Banding) neuer 32-Bit-Wert: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten
.equ COUNTER, 0x4		//Konstante fuer Schleifen Min/Max




//Unterprogramme

//Aufgabe a) Einlesen der Vektoren 

.thumb_func: Input: 			//Init Unterfunktion fuer Eingabe der Vektoren V1/V2 
	
	
	push {r4, r5, lr}			//pushen der benoetigten Register und LinkR (Fuer Ruecksprung) auf Stack 
	mov r4, #COUNTER			//Zaehler fuer Input 
	mov r5, r0
	
loop_1:							
	push {r4}	
					
	sub r4, #1					//Runterzaehlen fuer die "Byteauswahl"
	bl uart_getByte				//Liest einen zweistelligen hexadezimalen Wert vom Terminal ein und gibt ihn in R0 zurueck.
	strb r0, [r5, r4]			//Speichern der Eingabe 
	pop {r4}					//r4 vom Stack 
	subs r4, r4, #1				//Counter fuer die Schleife 
	bne loop_1					//beenden der Schleife
	
	
	
	ldr r0, [r5]
	bl uart_putInt32			//Ausgabe 
	pop {r4, r5, lr}			//"Rueckholen" der Registerinhalte vom Stack 
	
	bx lr						//Ruecksprung via lr




/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:

	bl pit3_init					//Timer initialisieren fuer Aufgabe d)
	
	bl uart_init
	
	ldr r0, =str_V1					//Anzeige : Aufforderung fuer V1
	bl uart_putString				
	ldr r0, =v1						//Addresse von V1 in r0
	
	
	bl Input						//Funktionsaufruf
		
	ldr r0, =str_V2					//Anzeige: Aufforderung fuer V2
	bl uart_putString		
	ldr r0, =v2						//Addresse von V2 in r0
	
	
	bl Input						//Funktionsaufruf





/***************************************************************************************************************************/	
	
//Aufgabe b) MIN_MAX ohne DSP 

	bl pit3_getval
	mov r8, r0
	
	
// Ermittlung des Minimums

	ldr r5, =noDSPmin				//Speichern der Adresse fuer die Variable max
	mov r4, #COUNTER				//Schleife 4x durchlaufen
	
loop_min:
	push {r4}						//R4 auf den Stack 
	
	sub r4, #1						//Runterzaehlen fuer die "Byteauswahl"
	
	
	
	
	ldr r3, =v1						//Die Vektoren werden byteweise  eingelesen 
	ldrb r1, [r3, r4]				
	ldr r3, =v2
	ldrb r2, [r3, r4]
	
	cmp r1, r2						//Vergleich r1/r2
	it hi							//Minimum
	movhi r1, r2					//kleineres Byte in R1
	
	strb r1, [r5, r4]				//Schreiben des min Wertes an die Stelle R4 in R5			
	
	pop {r4}						//Rueckholen R4 vom Stack
	subs r4, r4, #1					//Runterzaehlen des Schleifenzaehlers
	bne loop_min					//ende Schleife
	
	
	ldr r0, =str_noDSP				//"\n\nkeine DSP-Befehle:"
	bl uart_putString				//Gibt einen nullterminierten String auf dem Terminal aus. Uebergabe der Anfangsadresse in R0.
	
	ldr r0, =str_min				//"\nmin: 0x"
	bl uart_putString
	
	
	ldr r0, =noDSPmin					//min Ausgabe
	ldr r0, [r0]
	bl uart_putInt32
	
	
	
	
/**************************************************************************************************************************************/	
	
	
//Ermittlung des Maximuns	
	
	ldr r5, =noDSPmax					//Speichern der Adresse fuer die Variable max
	mov r4, #COUNTER
	
	
loop_max:
	push {r4}						//R4 auf den Stack
	
	sub r4, #1						//Runterzaehlen fuer die "Byteauswahl"
	
	
	ldr r1, =v1						//Die Vektoren werden byteweise  eingelesen
	ldrb r1, [r1, r4]
	ldr r2, =v2
	ldrb r2, [r2, r4]
	
	cmp r1, r2						//Vergleich r1/r2				
	it lo							//Maximum
	movlo r1, r2					//groesseres Byte in r1		
	
	strb r1, [r5, r4]				//Schreiben des max Wertes an die Stelle R4 in R5
	
	pop {r4}						//Rueckholen R4 vom Stack
	subs r4, r4, #1					//Runterzaehlen des Schleifenzaehlers
	bne loop_max					//Ende Schleife
	
	
	ldr r0, =str_max
	bl uart_putString
	
	
	ldr r0, =noDSPmax					//max Ausgabe
	ldr r0, [r0]
	bl uart_putInt32				
	
	bl pit3_getval					//zweiter Timer-Wert in R9
	mov r9, r0
	
	sub r8, r8, r9					//Differenz bildet die Zeit fuer Min/Max-Berechnung 
		
/**************************************************************************************************************************************/

	
//Aufgabe c) Mit DSP

	bl pit3_getval					//Start Timer und speichern in r10
	mov r10, r0

	ldr r1, =v1						//Laden Variable v1 in r1
	ldr r1, [r1]
	
	
	ldr r2, =v2						//Laden Variable v2 in r2
	ldr r2, [r2]
	
	
	
	ldr r3, =DSPmin					//Laden von min in r3
	usub8 r0, r1, r2				//Subtraktion (Byteweise) von V1 und V2 (mit r1/r2), setzen GE-Flags im APSR, Wenn Subtraktion ein "negatives" Ergebnis ergibt -> GE-Flag = 1
	sel r0, r2, r1					//kleineres Byte wird ausgewaehlt und schreiben nach r0
	str r0, [r3]					//r0 nach r3 (DSPmin)
	
	
	
	ldr r3, =DSPmax					//Laden von max nach r3
	sel r0, r1, r2					//groesseres Byte wird ausgewaehlt und schreiben nach r0
	str r0, [r3]					//r0 nach r3 (DSPMAX)
	
	
	
	
	
	
	ldr r0, =str_DSP				//Ausgabe der "DSP-Werte" 
	bl uart_putString
	
	ldr r0, =str_min
	bl uart_putString
		
	ldr r0, =DSPmin
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, =str_max
	bl uart_putString	
	
	ldr r0, =DSPmax
	ldr r0, [r0]
	bl uart_putInt32



	bl pit3_getval					//Timer Wert in r11
	mov r11, r0
	
	sub r10, r10, r11				//Zeit fuer min/max Ermittlung mit DSP in r10

/***************************************************************************************************************************************************/	

//Aufgabe d) Ausfuehrungszeiten 
	
	ldr r0, =str_timeNoDSP				//Ausgabe der ermittelten Zeit fuer min/max-Berechnung ohne DSP
	bl uart_putString
	
	mov r0, r8
	bl uart_putInt32
	
	
	
	
	
	ldr r0, =str_timeDSP				//Ausgabe der ermittelten Zeit fuer min/max-Berechnung mit DSP
	bl uart_putString
	
	mov r0, r10
	bl uart_putInt32	

/************************************************************************************************************************/
/*Antwort zu Aufgabe d):																								*/
/*																														*/
/*Die Berechnung der Min- und Max-Werte mit Hilfe von DSP-Befehlen ist schneller die Variante ohne DSP-Befehle.			*/
/*Ebenfalls ist die die DSP-Variante ebenfalls schneller und weniger aufwändig zu programmieren.						*/
/*																														*/
/************************************************************************************************************************/





/***************************************************************************************************************************************************************/

//Aufgabe e)	Erneute Ausfuehrung des Programms
	
	
	b main			//erneute Ausführung



/**************************************************************************************************************************************************************/

/*** Datenbereich (ab 0x20000000) ***/
.data

v1: .4byte 0x00000000
v2: .4byte 0x00000000

noDSPmin: .4byte 0x00000000
noDSPmax: .4byte 0x00000000

DSPmin: .4byte 0x00000fff
DSPmax: .4byte 0x00000000

str_V1: .asciz "\n\nV1: 0x" 
str_V2:	.asciz "\nV2: 0x" 
str_noDSP: .asciz "\n\nkeine DSP-Befehle:"
str_DSP: .asciz "\n\nmit DSP-Befehlen:"
str_min: .asciz "\nmin: 0x"
str_max: .asciz "\nmax: 0x"
str_timeNoDSP: .asciz "\n\nZeit ohne DSP: 0x"
str_timeDSP: .asciz "\nZeit mit DSP: 0x"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text		  					// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten 
.equ MAT, 0x10
.equ COUNTER, 0x04
.equ COUNTER2, 0x03
.equ COUNTER3, 0x02
.equ COUNTER4, 0x07
.equ DREIZEHN, 0xD

.equ S, 0x04
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:	
	bl uart_init


	/*Antwort zu Frage 2-1 a)
	  Ohne DSP-Befehle waeren 64 Multiplikationen notwendig. 
	  Mit DSP-Befehlen werden nur 32 Multiplikationen benoetigt. 
	  Einsparung: 32*/
	
	//Multiplizieren der Matrizen Aufgabe a)
	
	ldr r1, =o			//Laden/Speichern der Matrix
	ldr r0, [r1]
	bl uart_putInt32
	ldr r3, =m			//Laden/Speichern der Matrix m 
	ldr r4,[r3]
	
	
	ldr r5, [r3, #S]!	
	
	ldr r6, =n			//Laden/Speichern der Matrix n 
	ldr r7, [r6]
	
	mov r9, #COUNTER
	mov r10, #COUNTER
	
//Multiplizieren der Matrizen 
//Zeilen und zugehoerige Spalten werden nach Rechenregel mit smlad (hier der Schluesel zur Loesung) multipliziert
//Um alle Werte zu nutzen, wird um vier Stellen verschoben
	
loop_Mat:
	
	smlad r0, r4, r7, r0		
	
	ldr r7, [r6, #S]!		//Weiterschieben fuer naechstes halfword	
	smlad r0, r5, r7, r0		
	
	str  r0, [r1]
	ldr r7, [r6, #S]!	//"Weiterschieben" fuer naechstes halfword
	ldr r0, [r1, #S]!
	
	
	subs r9, r9,  #1	// Schleifenzaehler
	bne loop_Mat
	
	
	ldr r4, [r3, #S]!
	ldr r5, [r3, #S]!
	mov r9, #COUNTER
	ldr r6, =n
	ldr r7, [r6]
	
	
	subs r10, r10, #1
	bne loop_Mat
	
	
	//Ausgabe des Ergebnisses 
	
	mov r7, #COUNTER2
	mov r8, #COUNTER2

	ldr r0, =str_output
	bl uart_putString
	
	
	ldr r5, =o
	ldr r0, [r5]
	
	
	

ausgabe:	

	bl uart_putInt32
	ldr r0, =str_leerzeile
	bl uart_putString 
	ldr r0, [r5, #S]!
	
	subs r8, r8, #1
	bpl ausgabe 
	
	
	ldr r0, =str_dabsatz
	bl uart_putString 
	
	
	ldr r0, [r5]
	mov r8, #COUNTER2
	subs r7, r7, #1
	bpl ausgabe 
	
	
	ldr r0, =str_copie 
	bl uart_putString 
	
	// Aufgabe b) Kopieren der Matrix o 
	//o2 angelegt im Datenbereich 
	
	ldr r0, =o
	ldr r1, =o2
	
	mov r10, #COUNTER3
	
	
	
// Hier erfolgt der Kopiervorgang 
	
Copie:	
	ldm r0!, {r2, r3, r4, r5, r6, r7, r8, r9}
	stm r1!, {r2, r3, r4, r5, r6, r7, r8, r9}
	
	subs r10, r10, #1
	bne Copie
	
	
	ldr r0, =str_dabsatz
	bl uart_putString
	
	
	
//Aufgabe c) Summe S von Element-Produkten 
//Nutzung der smlad-Operation
//schieben der Werte 
	
	
    ldr r0, =str_pd
    bl uart_putString

    mov r9, #COUNTER4
    
  	mov r0, #0x0
    
    ldr r1, =m
    ldr r2, [r1]
    ldr r3, =n
    ldr r4, [r3]
    
loop_Sum:
    smlad r0, r2, r4, r0
    ldr r2, [r1, #4]!
    ldr r4, [r3, #4]!
    subs r9, r9, #1
    bpl loop_Sum
   

    bl uart_putInt32
    
    ldr  r0, =str_dabsatz
	bl uart_putString
    
    
	// Aufgabe d) Skalierbare Additionsbefehle 
	
	
	/* Antwort zu Frage 2-1 d) 
	
						
	   UQUADD16:  	AB: Saettigung zweites Halfword, AC: Saettigung des ersten Halfword, AD: Keine
	   QADD16:		AB: keine, AC: Beide HW mit Saettigung, AD: keine
	   
	   Bei UQUADD16: Bei ueberlauf wird auf Maximalwert 0xFFFF gesaettigt
	   Bei QADD16:	 Ueberlauf im negativen Bereich auf 0x8000 gesaetigt(1. HW), Hier auf den groesstmoeglichen Wert gesaettigt: 0x7FFF*/
	
	
	ldr  r0, =str_uadd
	bl uart_putString
	
	ldr r5, =a			//Speichern der Werte in Register
	ldr r5, [r5]
	
	ldr r6, =bb
	ldr r6, [r6]
	
	ldr r7, =c
	ldr r7, [r7]
	
 	ldr r8, =d
	ldr r8, [r8]
	
	// Nutzung UADD
	
	uadd16 r0, r5, r6
	bl uart_putInt32 
	
	ldr r0, =str_leerzeile
	bl uart_putString
	
	
	uadd16 r0, r5, r7
	bl uart_putInt32 
	
	ldr r0, =str_leerzeile
	bl uart_putString
	
	uadd16 r0, r5, r8
	bl uart_putInt32 
	
	
	ldr  r0, =str_dabsatz
	bl uart_putString
	
	
	//Nutzung SADD
	
    ldr  r0, =str_sadd
	bl uart_putString
	

	sadd16 r0, r5, r6
	bl uart_putInt32 
	
	ldr r0, =str_leerzeile
	bl uart_putString
	
	
	sadd16 r0, r5, r7
	bl uart_putInt32 
	
	ldr r0, =str_leerzeile
	bl uart_putString
	
	sadd16 r0, r5, r8
	bl uart_putInt32 
	
	
	ldr  r0, =str_dabsatz
	bl uart_putString
	
	
	//Nutzung UQADD
	
	ldr  r0, =str_uqadd
	bl uart_putString
	
	
	uqadd16 r0, r5, r6
	bl uart_putInt32 
	ldr r0, =str_leerzeile
	bl uart_putString
	
	
	uqadd16 r0, r5, r7
	bl uart_putInt32 
	ldr r0, =str_leerzeile
	bl uart_putString
	
	uqadd16 r0, r5, r8
	bl uart_putInt32 
	
	
	ldr  r0, =str_dabsatz
	bl uart_putString
	
	
	
	//Nutzung QADD
	
	
	ldr  r0, =str_qadd
	bl uart_putString
	
	
	qadd16 r0, r5, r6
	bl uart_putInt32 
	ldr r0, =str_leerzeile
	bl uart_putString
	
	
	qadd16 r0, r5, r7
	bl uart_putInt32 
	ldr r0, =str_leerzeile
	bl uart_putString
	
	qadd16 r0, r5, r8
	bl uart_putInt32 
	
	
	ldr  r0, =str_dabsatz
	bl uart_putString
	
	
	// Aufgabe e) 
	//Saettigung auf 13 Bits Vorzeichenbehaftet und Vorzeichenlos
	
	/*Interpretieren Sie die Ergebnisse: 
	usat16: Gibt ein vorzeichenloses Ergebnis
	ssat16 gibt ein vorzeichenbehaftetes Ergebnis
	
	Durch die Begrenzung der Woerter auf 13 Bits geraten einige Ergebnisse aus dem Wertebereich und werden "gesaetigt".
	
	Saettigung notwendig: A: beide Halbwoerter, B: zweites Halbwort
	Keine Saettigung notwendig: B: erstes Halbwort
	
			
	*/
	
	ssat16 r7, #DREIZEHN, r5
	ssat16 r8, #DREIZEHN, r6
	
	//Vorzeichenlose 
	
	usat16 r9, #DREIZEHN, r5
	usat16 r10, #DREIZEHN, r6
	
	//Ausgabe
	
	ldr r0, =str_ssad
	bl uart_putString

	mov r0, r7
	bl uart_putInt32 
	
	ldr r0, =str_leerzeile
	bl uart_putString
	
	mov r0, r8
	bl uart_putInt32 

	
	ldr  r0, =str_absatz
	bl uart_putString
	
	ldr r0, =str_usad
	bl uart_putString
	
	mov r0, r9
	bl uart_putInt32 
	
	ldr r0, =str_leerzeile
	bl uart_putString
	
	mov r0, r10
	bl uart_putInt32 
	
	
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/

.data

m: .hword 0x5f8c, 0x7f48, 0x8245, 0x6048, 0xc799, 0x9c5d, 0xd49c, 0x33d8, 0x579b, 0x8aef, 0xf2c0, 0xa3c2, 0x41fd, 0x50d4, 0x25c6, 0x4afa

n: .hword 0x7f41, 0x0645, 0x8c8f, 0x9065, 0x78e3, 0xf7f3, 0xd29f, 0x2961, 0x5a1e, 0xdfed, 0x4b9f, 0x1092, 0x61bf, 0x21be, 0x5ca1, 0xc6d3

a: .word 0xA4367C7B 
bb: .word 0x10A78933
c: .word 0xC5535F2C
d: .word 0x788E84B1 


o:
.rept MAT
.word 0x00
.endr

o2:
.rept MAT
.word 0x00
.endr

str_output: .asciz "\nErgebnis o:\n\n"
str_leerzeile: .asciz "  "
str_dabsatz: .asciz "\n\n"
str_absatz: .asciz "\n"
str_copie: .asciz "Kopieren der Matrix O:"
str_pd: .asciz "Produkt - Summe : "
str_uadd: .asciz "UADD16: "
str_sadd: .asciz "SADD16: "
str_uqadd: .asciz "UQADD16: "
str_qadd: .asciz "QADD16: "
str_ssad: .asciz "SSAD16: "
str_usad: .asciz "USAT16: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstanten

.equ COUNTER, 0x7F2815
.equ NINE, 0x09
.equ ZERO, 0x00
.equ SECH, 0x3c
.equ VUZ, 0x18
.equ EDREIS, 0x1F
.equ DREIZ, 0x0D
.equ HUND, 0x64
.equ S, 0x73
.equ D, 0x64
.equ T, 0x74



/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	

	bl uart_init		//Speichern der im Datenbereich angelegten Variablen

	ldr r4, =tag
	ldrb r4, [r4]
	
	ldr r5, =monat
	ldrb r5, [r5]
	
	ldr r6, =jahr
	ldrb r6, [r6]
	
	ldr r7, =stunde
	ldrb r7, [r7]
	
	ldr r8, =minute
	ldrb r8, [r8]

	
refresh:							//Aufrufen von "delay" um Sekunde zu "erzeugen" 
									//ueberpruefen ob Eingabe stattgefunden hat
	bl delay	

	b inputcheck	
	
	

addminute: 							//Weiterzaehlen der Minuten im ca. Sekundentakt

	bl ausgabe
	
	
	
	ldr r1, =minute 				
	
	add r8, r8, #1
	
	
	cmp r8, #SECH					//Bei 59 Minuten zurueckspringen auf 0
	ittt eq
	moveq r8, #0x0
	strbeq r8, [r1]
	beq addstunde					//Stunde muss hochgezaehlt werden, mit Sprungmarke "addstunde"
	
	strb r8, [r1] 

	b refresh
	
addstunde:							//Stunden werden hochgezaehlt, bei erreichen von 24h Ruecksetzen auf 0 und sprung zu "addtag"
	
	ldr r1, =stunde
		
	add r7, r7, #1
	cmp r7, #VUZ
	ittt eq
	moveq r7, #0x0
	strbeq r7, [r1]
	beq addtag

	strb r7, [r1]

	b refresh
	
addtag:								//Tage werden hochgezaehlt, bei erreichen von 30 Ruecksetzen auf 1 und sprung zu "addmonat"
	
	ldr r1, =tag
		
	add r4, r4, #1
	cmp r4, #EDREIS
	ittt eq
	moveq r4, #0x1
	strbeq r4, [r1]
	beq addmonat

	strb r4, [r1]

	b refresh
	
	
addmonat: 							//Monate werden hochgezaehlt, bei erreichen von 12 Ruecksetzen auf 1 und sprung zu "addmonat"

	ldr r1, =monat
		
	add r5, r5, #1
	cmp r5, #DREIZ
	ittt eq
	moveq r5, #0x1
	strbeq r5, [r1]
	beq addjahr

	strb r5, [r1]


	b refresh
	
	
	
addjahr:							//Jahre werden hochgezaehlt, bei erreichen von  (20)99 Ruecksetzen auf (20)14 


	ldr r1, =jahr
		
	add r6, r6, #1
	cmp r6, #HUND
	it eq
	moveq r6, #0xE
	
	strb r6, [r1]

	b refresh
	

inputcheck:						//Sprungmarke zur ueberpruefung einer Eingabe
								//Schluessel war hier : uart_charPresent
	bl uart_charPresent			//Abfrage des eingegebenen Zeichen
								//Je nach Input wird zur dazugehoerigen Sprungmarke gesprungen 
	cmp r0, #0
	it ne
	blne uart_getChar	
	
	cmp r0, #S 		
	it eq
	beq stop 
	
	cmp r0, #T
	it eq
	beq input_t
	
	
	cmp r0, #D
	it eq
	beq input_d
	
	
	
	b addminute
	
	//
stop: 							//Bei Eingabe von "s" 
								// Mit dazugehoeriger Abfrage auf Input User, wie oben.
	bl uart_charPresent

	cmp r0, #0
	it ne
	blne uart_getChar
	
	cmp r0, #S

	it eq
	beq addminute

	cmp r0, #D
	it eq
	beq input_d


	cmp r0, #T
	it eq
	beq input_t
	
	b stop
	
input_t:								// Bei "detektierten" t wird hier die neue Zeit per Eingabe gesetzt

	ldr r0, =inpstunde
	bl uart_putString
	
	bl uart_getByteBase10
	
	
	mov r7, r0							
	ldr r1, =stunde
	strb r0, [r1]
	
	
	cmp r0, #NINE					//Fuehrende Nullen schreiben
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r7
	
	bl uart_putByteBase10
	
	
	ldr r0, =zeile
	bl uart_putString
	
	ldr r0, =inpmin
	bl uart_putString
	
	bl uart_getByteBase10
	
	mov r8, r0
	ldr r1, =minute
	strb r0, [r1]
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r8
	
	bl uart_putByteBase10
	
	ldr r0, =zeile
	bl uart_putString
	
	
	b addminute 



input_d:								// Bei "detektierten" d wird hier das neue Datum per Eingabe gesetzt
										//gleiches Prinzip wie bei input_t
	ldr r0, =inptag
	bl uart_putString
	
	bl uart_getByteBase10
	
	
	
	mov r4, r0
	ldr r1, =tag
	strb r0, [r1]
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r4
	bl uart_putByteBase10
	
	
	ldr r0, =zeile
	bl uart_putString
	
	
	ldr r0, =inpmonat
	bl uart_putString
	
	bl uart_getByteBase10
	
	mov r5, r0
	ldr r1, =monat
	strb r0, [r1]
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r5	
	bl uart_putByteBase10
	
	
	
	ldr r0, =zeile
	bl uart_putString
	
	
	
	ldr r0, =inpjahr
	bl uart_putString
	
	bl uart_getByteBase10
	
	
	mov r6, r0
	ldr r1, =jahr
	strb r0, [r1]
	
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r6
	
	
	bl uart_putByteBase10
	
	
	ldr r0, =zeile
	bl uart_putString
	
	
	
	b addminute 

	
end:
	b end
	
	
//Unterprogramm Zeitverzoegerung 
	
.thumb_func

delay:

	push {lr}	
	ldr r3, =COUNTER			//Register bekommt ermittelte Konstante zugewiesen 

loop: 							//loop zaehlt runter und verlaesst nach ca. 1 Sekunde die U.Funkt. 
	
	subs r3, r3, #1	
	bne loop
	
	pop {pc}
	


// Unterfunktion Ausgabe
.thumb_func 

ausgabe:

	push {lr}

	ldr r0, =tag			//Ausgabe Tag
	ldrb r0, [r0]
	
	cmp r0, #NINE			//Vergleich mit Konstante (9)
	itt ls  				//KLeine-Gleich Check
	movls r0, #ZERO			//Wenn Bedingung zutrifft, dann setzen von "0" 
	blls uart_putByteBase10
	
	ldr r0, =tag			//Setzen des Tages 
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	
	
	ldr r0, =punkt			
	bl 	uart_putString
	
	ldr r0, =monat			//Gleiche Funktion wie "Ausgabe Tag", nur hier fuer den Monat
	ldrb r0, [r0]
	
	cmp r0, #NINE
	itt ls  
	movls r0, #ZERO
	blls uart_putByteBase10

	ldr r0, =monat
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	
	ldr r0, =punkt
	bl 	uart_putString
	
	ldr r0, =zwanz			//Fuehrende 20 
	bl 	uart_putString
	
	ldr r0, =jahr			//Ausgabe Jahr
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	ldr r0, =leer3
	bl 	uart_putString
	
	
	ldr r0, =stunde			//Ausgabe Stunde, analog zu Tag/Monat
	ldrb r0, [r0]
	
	
	cmp r0, #NINE
	itt ls  
	movls r0, #ZERO
	blls uart_putByteBase10
	
	ldr r0, =inpstunde
	ldr r0, =stunde
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	ldr r0, =dpunkt
	bl 	uart_putString
	
	ldr r0, =minute			//Ausgabe Minute, analog zu Tag/Monat/Stunde
	ldrb r0, [r0]
	
	
	cmp r0, #NINE
	itt ls  
	movls r0, #ZERO
	blls uart_putByteBase10
	
	ldr r0, =minute
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	
	ldr r0, =uhr
	bl 	uart_putString
	
    pop {pc}

	
/*** Datenbereich (ab 0x20000000) ***/

.data
uhr: .asciz "  Uhr\n"
punkt: .asciz " . "
dpunkt: .asciz ":"
zwanz:	.asciz "20"
leer3: .asciz "   " 
inpstunde: .asciz "Stunde eingeben (hh) :"
inpmin: .asciz "Minuten eingeben (mm) :"
inptag: .asciz "Tag eingeben (dd) :"
inpmonat: .asciz "Monat eingeben (mm) :"
inpjahr: .asciz "Jahr eingeben (jj) :"
zeile: .asciz "\n"


tag: .byte 0x1
monat: .byte 0x1
jahr: .byte 0xE
stunde: .byte 0x0
minute: .byte 0x0


// Include-Dateien

.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven

.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


//Konstanten


.equ NINE, 0x09
.equ ZERO, 0x0
.equ SECH, 0x3c
.equ VUZ, 0x18
.equ EDREIS, 0x1F
.equ DREIZ, 0x0D
.equ HUND, 0x64
.equ S, 0x73
.equ D, 0x64
.equ T, 0x74
.equ ENABLE, 0x1

__BBREG PIT_SIM_SCGC6, 0x4004803C, 23
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TFLG1, 0x4003711C
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_ICPR2, 0xE000E288


.equ NVIC_INT_ON, 0x20


.equ PIT1_VAL, 0x17D783F

.equ PIT_TCTRL1_TIE_TEN, 0x3

.equ SCR_VTOR, 0xE000ED08
.equ OFFS_PIT1, 0x154

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:	

	ldr r0, =PIT_SIM_SCGC6   				// a) Hier wird der Takt fuer PIT aktiviert(SIM_SCGC6 Bitpos.: 23)
    mov r1, #ENABLE 
    str r1, [r0]

    ldr r0, =SCR_VTOR          				 // b) Hier wird Interrupt-Vektor fuer PIT1 gesetzt
    ldr r0, [r0]
    ldr r1, =isr_pit1
    str r1, [r0, #OFFS_PIT1]

    ldr r0, =NVIC_ICPR2      				 // c) Hier werden moegliche pending Interrupts fuer PIT1 geloescht (NVIC)
    mov r1, #NVIC_INT_ON
    str r1, [r0]

    ldr r0, =NVIC_ISER2               		 // d) Hier wird derInterrupt fuer PIT1 aktiviert (NVIC)
    mov r1, #NVIC_INT_ON
    str r1, [r0]

    ldr r0, =PIT_MCR              			  // e) Hier werden alle PITs aktiviert, und im Debug-Modus laufen gelassen (PIT-Modul)
    mov r1, #0x0
    str r1, [r0]

    ldr r0, =PIT_LDVAL1          			  // f) Hier wird der Startwert fuer PIT1 auf 1 Sekunde initialisiert
    ldr r1, =PIT1_VAL
    str r1, [r0]

    ldr r0, =PIT_TCTRL1         			 //g) Hier wird der Interrupt fuer PIT1 aktiviert , h) und PIT1 aktiviert (PIT-Modul)
    mov r1, #PIT_TCTRL1_TIE_TEN
    str r1, [r0] 
	
	bl uart_init



	ldr r4, =tag
	ldrb r4, [r4]
	
	ldr r5, =monat
	ldrb r5, [r5]
	
	ldr r6, =jahr
	ldrb r6, [r6]
	
	ldr r7, =stunde
	ldrb r7, [r7]
	
	ldr r8, =minute
	ldrb r8, [r8]
	ldr r9, =flag
	
refresh:					//Wegfall des "delay" Aufrufs 
							// Flag-Abfrage hinzugefuegt
	ldrb r0, [r9]
    cmp r0, #1
    bne refresh

    mov r0, #ZERO
    strb r0, [r9]
	

	b inputcheck	
	
	

addminute: 

	bl ausgabe
	
	
	
	ldr r1, =minute 
	
	add r8, r8, #1
	
	
	cmp r8, #SECH
	ittt eq
	moveq r8, #0x0
	strbeq r8, [r1]
	beq addstunde
	
	strb r8, [r1] 

	b refresh
	
addstunde:
	
	ldr r1, =stunde
		
	add r7, r7, #1
	cmp r7, #VUZ
	ittt eq
	moveq r7, #0x0
	strbeq r7, [r1]
	beq addtag

	strb r7, [r1]

	b refresh
	
addtag:
	
	ldr r1, =tag
		
	add r4, r4, #1
	cmp r4, #EDREIS
	ittt eq
	moveq r4, #0x1
	strbeq r4, [r1]
	beq addmonat

	strb r4, [r1]

	b refresh
	
	
addmonat: 

	ldr r1, =monat
		
	add r5, r5, #1
	cmp r5, #DREIZ
	ittt eq
	moveq r5, #0x1
	strbeq r5, [r1]
	beq addjahr

	strb r5, [r1]


	b refresh
	
	
	
addjahr:

	ldr r1, =jahr
		
	add r6, r6, #1
	cmp r6, #HUND
	it eq
	moveq r6, #0xE
	
	strb r6, [r1]

	b refresh
	

inputcheck:

	bl uart_charPresent

	cmp r0, #0
	it ne
	blne uart_getChar	
	
	cmp r0, #S
	it eq
	beq stop 
	
	cmp r0, #T
	it eq
	beq input_t
	
	
	cmp r0, #D
	it eq
	beq input_d
	
	
	
	b addminute
	
	
stop: 

	bl uart_charPresent

	cmp r0, #0
	it ne
	blne uart_getChar
	
	cmp r0, #S
	it eq
	beq addminute

	cmp r0, #D
	it eq
	beq input_d


	cmp r0, #T
	it eq
	beq input_t
	
	b stop
	
input_t:

	ldr r0, =inpstunde
	bl uart_putString
	
	bl uart_getByteBase10
	
	
	mov r7, r0
	ldr r1, =stunde
	strb r0, [r1]
	
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r7
	
	bl uart_putByteBase10
	
	
	ldr r0, =zeile
	bl uart_putString
	
	ldr r0, =inpmin
	bl uart_putString
	
	bl uart_getByteBase10
	
	mov r8, r0
	ldr r1, =minute
	strb r0, [r1]
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r8
	
	bl uart_putByteBase10
	
	ldr r0, =zeile
	bl uart_putString
	
	
	b addminute 



input_d:

	ldr r0, =inptag
	bl uart_putString
	
	bl uart_getByteBase10
	
	
	
	mov r4, r0
	ldr r1, =tag
	strb r0, [r1]
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r4
	bl uart_putByteBase10
	
	
	ldr r0, =zeile
	bl uart_putString
	
	
	ldr r0, =inpmonat
	bl uart_putString
	
	bl uart_getByteBase10
	
	mov r5, r0
	ldr r1, =monat
	strb r0, [r1]
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r5	
	bl uart_putByteBase10
	
	
	
	ldr r0, =zeile
	bl uart_putString
	
	
	
	ldr r0, =inpjahr
	bl uart_putString
	
	bl uart_getByteBase10
	
	
	mov r6, r0
	ldr r1, =jahr
	strb r0, [r1]
	
	
	cmp r0, #NINE			
	itt ls  				
	movls r0, #ZERO			
	blls uart_putByteBase10
	
	mov r0, r6
	
	
	bl uart_putByteBase10
	
	
	ldr r0, =zeile
	bl uart_putString
	
	
	
	b addminute 
 
	
end:
	b end
	
	
// ISR						//Hinzugefuegte ISR
.thumb_func
isr_pit1:
    push {lr}
    ldr r0, =flag
    mov r3, #ENABLE			
    strb r3, [r0]

    ldr r0, =PIT_TFLG1
    mov r3, #ENABLE
    str r3, [r0]
    pop {pc}
	


// Unterfunktion Ausgabe
.thumb_func 

ausgabe:

	push {lr}

	ldr r0, =tag			//Ausgabe Tag
	ldrb r0, [r0]
	
	cmp r0, #NINE			//Vergleich mit Konstante 
	itt ls  				//KLeine-Gleich Check
	movls r0, #ZERO			//Wenn Bedingung zutrifft, dann setzen von "0" 
	blls uart_putByteBase10
	
	ldr r0, =tag			//Setzen des Tages 
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	
	
	ldr r0, =punkt			
	bl 	uart_putString
	
	ldr r0, =monat			//Gleiche Funktion wie "Ausgabe Tag", nur hier fuer den Monat
	ldrb r0, [r0]
	
	cmp r0, #NINE
	itt ls  
	movls r0, #ZERO
	blls uart_putByteBase10

	ldr r0, =monat
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	
	ldr r0, =punkt
	bl 	uart_putString
	
	ldr r0, =zwanz			//Fuehrende 20 
	bl 	uart_putString
	
	ldr r0, =jahr			//Ausgabe Jahr
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	ldr r0, =leer3
	bl 	uart_putString
	
	
	ldr r0, =stunde			//Ausgabe Stunde, analog zu Tag/Monat
	ldrb r0, [r0]
	
	
	cmp r0, #NINE
	itt ls  
	movls r0, #ZERO
	blls uart_putByteBase10
	
	ldr r0, =inpstunde
	ldr r0, =stunde
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	ldr r0, =dpunkt
	bl 	uart_putString
	
	ldr r0, =minute			//Ausgabe Minute, analog zu Tag/Monat/Stunde
	ldrb r0, [r0]
	
	
	cmp r0, #NINE
	itt ls  
	movls r0, #ZERO
	blls uart_putByteBase10
	
	ldr r0, =minute
	ldrb r0, [r0]
	bl uart_putByteBase10
	
	
	ldr r0, =uhr
	bl 	uart_putString
	
    pop {pc}


	
