/*** Datenbereich (ab 0x20000000) ***/
.data
text: .asciz "Test-String\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)
 
// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6, 0x4004803C		//Addresse fuer aktivieren des Taktes CRC

__BBREG CRC_SIM_SCGC6, SIM_SCGC6, 18

.equ CRC_GPOLY, 0x40032004		//Das Register enthaelt den Wert des Polynomsfuer die CRC-Berechnung
.equ CRC_CRC, 0x40032000		//Das Register enthaelt den Wert des Seed, der Daten und der Pruefsummer
.equ CRC_CTRL, 0x40032008		//Dieses Register steuert die Konfiguration und den Betrieb des CRC-Moduls

.equ CRC_CTRL_TCRC, 0x1000000		//Stelle 24 im CTRL-Register - Enable 32 Bit CRC 
.equ CRC_CTRL_WAS_TCRC, 0x3000000	//Stelle 24 und 25 - fuer zusaetzliches setzen des WAS laut Kapitel 32.3.2.2 

.equ CRC_SEED, 0x12345678			//gegebener Seed

.equ CRC_32_POLY, 0x04C11DB7   //Erechnetes CRC-32-Polynom fuer vorgegebenen String 

.equ LEERZEILE, '\n'
.equ DREI, 0x3


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	

	bl uart_init
	
	ldr r0, =CRC_SIM_SCGC6   	//Takt fuer CRC_Modul aktivieren 			
    mov r1, #0x1 
    str r1, [r0]
	
	ldr r0, =CRC_CTRL     		//Enable 32-bit CRC mode	 
	mov r1, #CRC_CTRL_TCRC
    str r1, [r0]
    
    ldr r0, =CRC_GPOLY     		//Schreiben des 32-Bit Polynom in CRC_GPOLY				 
	ldr r1, =CRC_32_POLY
    str r1, [r0] 
    
    ldr r0, =CRC_CTRL     		//Setzen 1 in WAS von CRC_CTRL		 
	ldr r1, =CRC_CTRL_WAS_TCRC
    str r1, [r0]
    
    ldr r0, =CRC_CRC  			//Seed laden in CRC_CRC		 
	ldr r1, =CRC_SEED
    str r1, [r0]
    
    ldr r0, =CRC_CTRL     		//WAS wieder auf 0		 
	ldr r1, =CRC_CTRL_TCRC
    str r1, [r0] 
    
    ldr r9, =CRC_CRC
	ldr r4, =str_c				//String nach R4
	
	ldr r5, =input_str			//String in den der Text geschrieben werden soll 
	
	mov r6, #0x0				//Hilfszaehler fuer Zeichen des Quellstrings
	mov r7, #DREI				//Hilfszahler fuer speichern der Zeichen an richtiger Stellen im "word"

input_loop:
	
	ldrb r0, [r4, r6]			//String an stelle 0x0 "P"
	
	cmp r0, #0					//Bei Ende des Strings, sprung zur Ausgabe des CRC-PW
	beq ausgabe_catch
	
	strb r0, [r5, r7]			//Speichern in Variable Höchste Stelle Byte 3 
	
	cmp r7, #0					// Pruefung, ob 4 Zeichen eingelesen (Nomralfall)
	beq crc_gen
	
	add r6, r6, #1				//Stellen weiterschieben, um naechstes Zeichen zu "kriegen" 
	sub r7, r7, #1				//Stellen weiterschieben, um Zeichen an richtiger Stelle zu speichern 
	
	b input_loop
	
crc_gen:
	//Schreiben der 4 Chars in CRC-Register
	ldr r3, [r5]	
	str r3, [r9]
	
	mov r7, #DREI	//Ruecksetzen des Hilfszaehlers
	add r6, r6, #1	//Weitersprung 
	
	b input_loop
	
ausgabe_catch: 
	//Die ersten drei Bloecke dienen dazu, den Fall abzudecken, wenn ungleich 4 Zeichen + Terminator
	cmp r7, #2					
	itt eq
	ldrbeq r3, [r5, #DREI]			//Ein Zeichen in CRC-Reg (Stelle HU), andere Stellen nicht beschreiben
	strbeq r3, [r9,#DREI]
	
	cmp r7, #1
	itt eq							//Zwei Zeichen in CRC-Reg (Stelle: HU/HL), andere Stellen nicht beschreiben
	ldrheq r3, [r5, #2]
	strheq r3, [r9, #2]
	
	itttt lo						//Drei Zeichen in CRC-Reg (Stelle: HU/HL/LU, andere Stelle nicht beschreiben
	ldrhlo r3, [r5, #2]
	strhlo r3, [r9, #2]
	ldrblo r3, [r5, #1]
	strblo r3, [r9,#1]
	//Ausgabe 
	mov r0, r4
	bl uart_putString
	 
	mov r0, #LEERZEILE
	bl uart_putChar
	
	ldr r0, =crc_pw
	bl uart_putString
	
	ldr r0, [r9]
	bl uart_putInt32		
	
	mov r0, #LEERZEILE
	bl uart_putChar
	 
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data

str_c: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hgen"
input_str: .word 0x0
crc_pw: .asciz "CRC-Pruefwert: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified
//Konstanten
//SIM (System Integration Module)

.equ SIM_SCGC5, 0x40048038  //Adresse zum System Clock Gating Control Register 5 -> Port E und Port A muss spaeter aktiv sein
__BBREG SCGC5_A, SIM_SCGC5, 9			//Port A
__BBREG SCGC5_E, SIM_SCGC5, 13 			//Port E 

.equ SIM_SCGC6, 0x4004803C 	//Adresse zum System Clock Gating Control Register 6 -> PIT muss spaeter aktiv sein 
__BBREG SCGC6_PIT, SIM_SCGC6, 23 	//PIT

//PCR (Werden aufgefuehrt weil MUX (8-10) auf 001 fuer GPIO gesetzt werden muss)


//Addressen der einzelnen benoetigten PCR Register
 .equ PORTA_PCR10, 0x40049028
 .equ PORTA_PCR11, 0x4004902C
 .equ PORTA_PCR19, 0x4004904C
 .equ PORTA_PCR28, 0x40049070
 .equ PORTA_PCR29, 0x40049074
 .equ PORTE_PCR26, 0x4004D068
 
__BBREG PCR_E4_MUX, PORTA_PCR10, 8 		//LED E4
__BBREG PCR_E1_MUX, PORTA_PCR11, 8 		//LED E1 	
__BBREG PCR_E2_MUX, PORTA_PCR28, 8 		//LED E2 
__BBREG PCR_E3_MUX, PORTA_PCR29, 8 		//LED E3


.equ PCR19_SW1_MUX, 0x103			//Digital Input/GPIO
.equ PCR26_SW2_MUX, 0xB0103			//Digital Input/ Interrupt on -either- edge/GPIO - wegen Debounce auf either gestellt - Erklaerung bei Debounce in ISR2

//GPIO_Register (PDDR -> In/Output, PDIR -> Logic Level set)
//Adressen der Register 
.equ GPIOA_PDIR, 0x400FF010
.equ GPIOA_PDDR, 0x400FF014		
.equ GPIOE_PDIR, 0x400FF114
.equ GPIOE_PDDR, 0x400FF014
//Fuer spaeteres ansprechen der entsprechenden Stellen im Register (Ausgang/Eingang, high/low) 
__BBREG PDDR_E4, GPIOA_PDDR, 10 	
__BBREG PDDR_E1, GPIOA_PDDR, 11 	
__BBREG PDDR_SW1, GPIOA_PDDR, 19 
__BBREG PDIR_SW1, GPIOA_PDIR, 19 
__BBREG PDDR_E2, GPIOA_PDDR, 28
__BBREG PDDR_E3, GPIOA_PDDR, 29
__BBREG PDDR_SW2, GPIOE_PDDR, 26 
__BBREG PDIR_SW2, GPIOE_PDIR, 26 

.equ GPIOA_PTOR, 0x400FF00C 		//Port Toggle Output   
.equ LED_E1, 0x1 << 11		//800
.equ LED_E2, 0x1 << 28		//10000000
.equ LED_E3, 0x1 << 29		//20000000
.equ LED_E4, 0x1 << 10		//400

.equ GPIOA_PSOR, 0x400FF004		//This register configures whether to set the fields of the PDOR.
.equ GPIOA_PCOR, 0x400FF008		//This register configures whether to clear the fields of PDOR.
.equ GPIOA_PDOR, 0x400FF000

.equ LEDS_ON, 0x30000C00		//Konstante zum ansprechen aller LEDs gleichzeitig
 
//IR-Register und Konstanten 
.equ PIT_MCR, 0x40037000		//Adresse PIT_MCR_Register
.equ PIT_LDVAL1, 0x40037110		//Adresse PIT_LDVAL1_Register
.equ PIT_TCTRL1, 0x40037118		//Adresse PIT_TCTRL1_Register
.equ PIT_TFLG1, 0x4003711C		//Adresse PIT_TFLG1_Register
.equ NVIC_ISER2, 0xE000E108		//Adresse NVIC_ISER2_Register
.equ NVIC_ICPR2, 0xE000E288		//Adresse NVIC_ICPR2_Register
.equ PIT_CVAL3, 0x40037134		//Aktueller Wert des Zaehler kann hier ausgelesen werden 

.equ PIT1_VAL, 0x17D783F 
.equ PIT_TCTRL1_TIE_TEN, 0x3
.equ SCR_VTOR, 0xE000ED08			//Basisregisteradresse der IVT
.equ OFFS_PIT1, 0x154
.equ LEERZEILE, '\n'
.equ ENABLE, 0x1
.equ OFFS_SW2, 0x1AC
.equ NVIC_PIT_PORTE, 0x08000020
.equ PORTE_ISR2, 0x4004D0A0
.equ ISR2_CLEAR, 0x1 <<26			//Ruecksetzen ISR 2 

.equ PLUS, 0x2b		//HEX feur +
.equ MINUS, 0x2d	//HEX fuer -
.equ S, 0x73	//HEX fuer s
.equ time, 0x1E848 //125000 Takte -> entsprechen ca. 5ms
.equ time_poll, 0xF424 // 125000 Takte / 2 -> Weil Sub-Befehl "Takte kostet"

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
//Initialisierung
	bl uart_init
	bl pit3_init
	
    mov r1, #ENABLE							//Takt fuer PORTA und PORTE aktivieren (SIM_SCGC5 Bitpos.: 9 und 13)
	ldr r0, =SCGC5_A		
	str r1, [r0]
	ldr r0, =SCGC5_E	
	str r1, [r0]
		
	ldr r0, =PORTA_PCR19					//Setzen PCR auf GPIO und digital Input
	ldr r2, =PCR19_SW1_MUX			
    str r2, [r0]
    
    ldr r0, =PORTE_PCR26					//Setzen PCR auf GPIO, digital Input und Interrupt auf fallende Flanke
	ldr r2, =PCR26_SW2_MUX			
    str r2, [r0]
    
    ldr r0, =PCR_E4_MUX						//Schreiben von "001" in MUX von PCR mit BB
    str r1, [r0]
    
    ldr r0, =PCR_E1_MUX						//Schreiben von "001" in MUX von PCR mit BB
    str r1, [r0]
    
    ldr r0, =PCR_E2_MUX						//Schreiben von "001" in MUX von PCR mit BB
    str r1, [r0]
    
    ldr r0, =PCR_E3_MUX						//Schreiben von "001" in MUX von PCR mit BB
    str r1, [r0]
    
    mov r2, #0								//Setzen von 0 in PDDR fuer GPIO Input 
    ldr r0, =PDDR_SW2		
    str r2, [r0]
          	 	 	 	 	 	
    ldr r0, =PDDR_SW1						//Setzen von 0 in PDDR fuer GPIO Input 
    str r2, [r0]
	
	ldr r0, =PDDR_E4						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]
	
	ldr r0, =PDDR_E1						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]	
	
	ldr r0, =PDDR_E2						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]
	
	ldr r0, =PDDR_E3						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]
	
	ldr r0, =GPIOA_PDOR						//Nach Init der LEDS blieben diese an, hiermit werden Sie ausgeschaltet
	ldr r1, =LEDS_ON
	str r1, [r0]  
	
	ldr r0, =SCGC6_PIT   					//Hier wird der Takt fuer PIT aktiviert(SIM_SCGC6 Bitpos.: 23)
    mov r1, #ENABLE
    str r1, [r0] 
 
    ldr r0, =SCR_VTOR          				 //Hier wird Interrupt-Vektor fuer PIT1 gesetzt und PORTE gesetzt
    ldr r0, [r0]
    ldr r1, =isr_pit1
    str r1, [r0, #OFFS_PIT1]
    ldr r1, =isr_2
    str r1, [r0, #OFFS_SW2]
    
    ldr r0, =NVIC_ICPR2      				 //Hier werden moegliche pending Interrupts fuer PIT1/PORTE geloescht (NVIC)
    ldr r1, =NVIC_PIT_PORTE
    str r1, [r0]
    ldr r0, =NVIC_ISER2               		 //Hier wird derInterrupt fuer PIT1/PORTE aktiviert (NVIC)
    str r1, [r0]
    
    ldr r0, =PIT_MCR              			  //Hier werden alle PITs aktiviert, und im Debug-Modus laufen gelassen (PIT-Modul)
    mov r1, #0x0
    str r1, [r0]
    
    ldr r0, =PIT_LDVAL1          			  //Hier wird der Startwert fuer PIT1 auf 1 Sekunde initialisiert
    ldr r1, =PIT1_VAL
    str r1, [r0]
    
    ldr r0, =PIT_TCTRL1         			  //Hier wird der Interrupt fuer PIT1 aktiviert und PIT1 aktiviert (PIT-Modul)
    mov r1, #PIT_TCTRL1_TIE_TEN
    str r1, [r0]  
	
	ldr r0, =start
	bl uart_putString
	
	ldr r10, =flagisr										
	mov r5, #0
	ldr r6, =LED_E1
    ldr r7, =LED_E2
    ldr r8, =LED_E3     
    ldr r9, =LED_E4
	
counter:
	
	ldrb r0, [r10]			//ISR - Pruefen ob Interrrupt-Flag gesetzt wurde
	cmp r0, #1
    bne counter
    bl sw1					//Abfrage SW1 
    ldr r4, =mod
    mov r0, #0				//Ruecksetzen Interrrupt-Flag
    strb r0, [r10]
    
    bl uart_charPresent		//wenn keine Eingabe detektiert -> jump zum "normalen" Zaehlverhalten
    cmp r0, #0
    beq jump 
    
    bl uart_getChar			//Eingabe wurde erkannt-> Zeichen "s" erkannt , schreibe eine "2" in mod -> dadurch sprung in "stop"
    ldr r2, [r4]			//Wert von mod in r1
    cmp r0, #S				
    itt eq
    eoreq r2, r2, #2		//Verknuepfung mit xor -> Bit mit index 
    strbeq r2, [r4]			//schreibt wert nach mod
    
    cmp r0, #PLUS			//Abfrage des + 
    itttt eq
    moveq r2, #0
    strbeq r2, [r4]			//Bei Eingabe + -> setze 0 in mod
    ldreq r0, =change		//Hinweis auf Wechsel der Zaehlrichtung
	bleq uart_putString
        
    cmp r0, #MINUS			//Abfrage - 
    itttt eq
    moveq r2, #1
    strbeq r2, [r4]			//Bei Eingabe - -> setze 1 in mod
    ldreq r0, =change		//Hinweis auf Wechsel der Zaehlrichtung
	bleq uart_putString 
    
jump:
	 		
	ldrb r4, [r4]
	cmp r4, #2				//Vergleich des Wertes in mod, wenn '2' dann stop. 
	bhs stop				//higher same
	
	mov r0, r5				//Ausgabe Zaehler
	bl uart_putByteBase10
	
	ldr r0, =LEERZEILE
	bl uart_putChar
	
	cmp r4, #0
	ite eq 					//Vergleich welcher Wert in mod steht und dementsprechend hoch- oder runterzaehlen
	addeq r5, r5, #1
	subne r5, r5, #1
	
	bl leds					//Sprung zum UP zum schalten der LEDS
	b counter 				
	
stop:
	ldr r0, =stopped		//Bei SW 2 oder Eingabe zum stoppen des Zaehlers wird hier einmalig hineingesprungen, um den String auszugeben
	bl uart_putString 
	
stop2:
	
	ldr r4, =mod
	
	bl uart_charPresent		//Abfrage neu eingegebenes Zeichen
    cmp r0, #0
    beq jump_2				//Wenn keine Eingabe dann zu jump_2
   
    bl uart_getChar			// Bei Eingabe Zeichen vergleichen mit "s"
    ldrb r2, [r4]
    cmp r0, #S
    itt eq
    eoreq r2, r2, #2		//Bei Eingabe "s" , wieder XOR-Verknüpfung, um in den Zustand vor "Stop" zu springen 
    strbeq r2, [r4]			//Speichern von Wert in mod
        
jump_2:
   
	ldrb r4, [r4]
	cmp r4, #2
	blo counter			//niedriger als 2 springe zu counter
	bhs stop2			//higher same 2 springe weiter in stop2
	       
.thumb_func
isr_pit1:			//ISR1 (Uebernahme aus Vorversuch)

    ldr r0, =flagisr
    mov r3, #ENABLE			
    strb r3, [r0]

    ldr r0, =PIT_TFLG1
    
    str r3, [r0]
    BX LR

.thumb_func			//ISR 2
isr_2:
    
    ldr r0, =PORTE_ISR2
	ldr r1, =ISR2_CLEAR
	
	str r1, [r0]
    
    //Realisierung Debounce- bei betätigen SW 2 werden zwei Interrupts ausgelöst - einmal auf fallende Flanke und einmal steigene
    //Flanke. Jeweils wird ein Zeitstempel genommen, der Wert (time) wird verrechnet und die Werte verglichen 
    //Bei erfüllter Bedingung darf Variable mod gesetzt werden
    
    ldr r2, =flag_db		//laden des Flags
    ldr r0, [r2]
    
    cmp r0, #0				// Vergleich ob bereits ein Wert in r0 steht
    bne jump3				
    
    ldr r1, =PIT_CVAL3		//Zeitstempel holen
    ldr r3, =time			// Wert fuer ca. 5ms
    ldr r1, [r1]
    
    sub r1, r1, r3			//Differenz bilden und abspeichern
    str r1, [r2]
     
jump3:    
    
    cmp r0, #0				// Bei zweiten Interrupt und einem vorhandenen ermittelten Wert vom 1. Interr. wird der Block ausgefuehrt
    beq isr2_stop			// Kein Wert -> dann raus
    ldr r1, =PIT_CVAL3 		// 2. Zeitstempel
    ldr r1, [r1]
    
    cmp r1, r0				//Wenn hier der Differenzwert aus r1 kleiner oder geich des neuen Zeitstempels ist, 
    itttt ls 				//ist die 5ms Bedingung erfüllt und mod kann gesetzt werden 
    
    ldrls r1, =mod			//setzen von 2 in mod , da Programm gestoppt
	ldrbls r0, [r1]		
	
	eorls r0, r0, #2
	strbls r0, [r1]
	
	mov r1, #0				//Ruecksetzen 
	str r1, [r2]
    
isr2_stop:   
    
	bx lr

//Unterfunktion zum Schalten der LEDs 		
.thumb_func
leds:

push {r5 ,r6, r7, r8, r9, lr}

	ldr r2, =GPIOA_PTOR
	ldr r0, =GPIOA_PDOR					
	ldr r1, =LEDS_ON
	str r1, [r0]
	// Nutzen von logischer AND Verknuepfung um LEDs zu schalten
	and r0, r5, #1			 
	cmp r0, #1
	it eq
	streq r6, [r2]
	
	and r0, r5, #2
	cmp r0, #2
	it eq
	streq r7, [r2]
	
	and r0, r5, #4
	cmp r0, #4
	it eq
	streq r8, [r2]
	
	and r0, r5, #8
	cmp r0, #8
	it eq
	streq r9, [r2]
	
	pop {r5, r6, r7, r8, r9, pc}
	
.thumb_func
sw1:

	push {lr}				//Notwendig das uart_putString in der UF

	ldr r0, =PDIR_SW1		//High Pegel
	ldr r1, =mod 
	
	ldr r0, [r0]
	
	cmp r0, #1				//Wenn Schalter gedrueckt dann schreiben von 1 in r1 ansonsten verbleibt die 0 
	beq	skipsetmod
	//Herunterzaehlen um 5ms zu erzwingen
	ldr r2, =time_poll
delay:
	subs r2, r2, #1
	bne delay
	
	ldr r0, =PDIR_SW1
	ldr r0, [r3]
	//Wurde hier der Taster vorzeitig losgelassen, wuerde hier aus der Funktion gesprungen werden
	cmp r0, #1
	beq skipsetmod
	// Wenn Taster mindestens 5ms gedrueckt wurde, dann kann "mod" geschrieben werden 
	ldrb r2, [r1]	
	eor r2, r2, #1		
	strb r2, [r1]	
	//Ausgabe des Richtungswechsel		 
	ldr r0, =change2
	bl uart_putString
	
skipsetmod:	
	
	pop {pc} 
	
/*** Datenbereich (ab 0x20000000) ***/
.data

mod: .byte 0x0
flagisr: .byte 0x0
flagisr2: .byte 0x0
flag_db: .word 0x0


stopped: .asciz "\nZaehler wurde gestoppt! \n\n"
change: .asciz "\nZaehlrichtung wurde mit einer Tastatureingabe geaendert \n\n"
change2: .asciz "\nZaehlrichtung wurde durch betaetigen SW1 geaendert \n\n"
start: .asciz "\nInitialisierung abgeschlossen. Zaehler gestartet... \n\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//ADC
.equ ADC1_PG, 0x400BB02C		
.equ ADC1_RA, 0x400BB010

//Fuer die Kalibrierung
.equ ADC1_CLPS, 0x400BB038
.equ ADC1_CLP4, 0x400BB03C
.equ ADC1_CLP3, 0x400BB040
.equ ADC1_CLP2, 0x400BB044
.equ ADC1_CLP1, 0x400BB048
.equ ADC1_CLP0, 0x400BB04C

.equ SIM_SCGC3, 0x40048030				//Adresse zum System Clock Gating Control Register 3 - Aktivierung Takt
__BBREG SCGC3_ADC1, SIM_SCGC3, 27

.equ ADC_SC3_CAL, 0x8E					//Zum setzen Bit, zum Starten der Kalibrierung in SC3/ kontinuierliche Wandlung über 16 samples
.equ ADC1_SC3, 0x400BB024				//Bit 3 - Cont. Mode
.equ ADC1_STOP, 0x86					//Konstante: AD-Wandlung stoppen
.equ ADC1_CFG1_INIT, 0x6C				//Zum setzen 11 an Stelle 6-5 fuer divide 8, Conversion mode 11 auf Stelle 2-3
.equ ADC1_CFG1, 0x400BB008				//input Clock und Conversion mode

.equ ADC1_SC1A_INIT, 0x14				//Zum setzen des Input_Channels und keine Interrupts
.equ ADC1_SC1A, 0x400BB000
.equ ADC1_CFG1_16, 0x6C		//Konstante zum setzen der Clockrate (25MHz/8= 3,125MHz) und setzen des Conversion-Modes auf 16Bit
.equ ADC1_CFG1_12, 0x64		//Konstante zum setzen der Clockrate (25MHz/8= 3,125MHz) und setzen des Conversion-Modes auf 12Bit
.equ ADC1_CFG1_10, 0x68		//Konstante zum setzen der Clockrate (25MHz/8= 3,125MHz) und setzen des Conversion-Modes auf 10Bit
.equ ADC1_CFG1_8, 0x60		//Konstante zum setzen der Clockrate (25MHz/8= 3,125MHz) und setzen des Conversion-Modes auf 8Bit

.equ PIT_TFLG1, 0x4003711C				//Adresse PIT_TFLG1_Register

//ISR-Register

.equ SIM_SCGC6, 0x4004803C 				//Adresse zum System Clock Gating Control Register 6 - Aktivierung Takt 
__BBREG SCGC6_PIT, SIM_SCGC6, 23

.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TFLG1, 0x4003711C
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_ICPR2, 0xE000E288

.equ NVIC_INT_ON, 0x20
.equ PIT1_VAL, 0x17D783F
.equ PIT_TCTRL1_TIE_TEN, 0x3
.equ SCR_VTOR, 0xE000ED08
.equ OFFS_PIT1, 0x154

//PORT A / LEDS

.equ SIM_SCGC5, 0x40048038  //Adresse zum System Clock Gating Control Register 5 -> Port E und Port A muss spaeter aktiv sein
__BBREG SCGC5_A, SIM_SCGC5, 9			//Port A

.equ PORTA_PCR10, 0x40049028
.equ PORTA_PCR11, 0x4004902C
.equ PORTA_PCR28, 0x40049070
.equ PORTA_PCR29, 0x40049074

.equ GPIOA_PDIR, 0x400FF010
.equ GPIOA_PDDR, 0x400FF014

__BBREG PDDR_E4, GPIOA_PDDR, 10 	
__BBREG PDDR_E1, GPIOA_PDDR, 11 

__BBREG PDDR_E2, GPIOA_PDDR, 28
__BBREG PDDR_E3, GPIOA_PDDR, 29

.equ GPIOA_PTOR, 0x400FF00C 		//Port Toggle Output   
.equ LED_E1, 0x1 << 11		//800
.equ LED_E2, 0x1 << 28		//10000000
.equ LED_E3, 0x1 << 29		//20000000
.equ LED_E4, 0x1 << 10	

.equ GPIOA_PSOR, 0x400FF004		//This register configures whether to set the fields of the PDOR.
.equ GPIOA_PCOR, 0x400FF008		//This register configures whether to clear the fields of PDOR.
.equ GPIOA_PDOR, 0x400FF000

__BBREG E1_OFF, GPIOA_PDOR, 11		//Zum ausschalten der LEDs zum Start 
__BBREG E2_OFF, GPIOA_PDOR, 28
__BBREG E3_OFF, GPIOA_PDOR, 29
__BBREG E4_OFF,GPIOA_PDOR, 10

.equ PCR_LEDS, 0x100 
.equ LEERZEILE, '\n'
.equ LEDS_ON, 0x30000C00		//Konstante zum ansprechen aller LEDs gleichzeitig

//8 Spannungsbereiche - Grenzwerte fuer 8 Stufige Ausgabe (bei 3300mv)						
.equ S8_7, 0xFF
