.equ SECHZ, 16
.equ ZEHN, 0xA
.equ ZWOELF, 12
.equ SECHSZ, 16
.equ S, 0x73	//HEX fuer s
.equ NULL, 0x30	//ASCII 0
.equ EINS, 0x31 //ASCII 1
