/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	//Takt fuer PIT, PORT A und ADC1 aktivieren 
	mov r1, 0x1	
				
	ldr r0, =SCGC3_ADC1		
	str r1, [r0]
	ldr r0, =SCGC6_PIT	
	str r1, [r0]
	ldr r0, =SCGC5_A		
	str r1, [r0]
	
	ldr r0, =ADC1_CFG1
	mov r1, #ADC1_CFG1_INIT
	str r1, [r0]
	
	//Initialisierung PIT
    ldr r0, =SCR_VTOR          				 // Hier wird Interrupt-Vektor fuer PIT1 gesetzt
    ldr r0, [r0]
    ldr r1, =isr_pit1
    str r1, [r0, #OFFS_PIT1]

    ldr r0, =NVIC_ICPR2      				 // Hier werden moegliche pending Interrupts fuer PIT1 geloescht (NVIC)
    mov r1, #NVIC_INT_ON
    str r1, [r0]
    ldr r0, =NVIC_ISER2               		 // Hier wird derInterrupt fuer PIT1 aktiviert (NVIC)
    str r1, [r0]

    ldr r0, =PIT_MCR              			  // Hier werden alle PITs aktiviert, und im Debug-Modus laufen gelassen (PIT-Modul)
    mov r1, #0x0
    str r1, [r0]

    ldr r0, =PIT_LDVAL1          			  // Hier wird der Startwert fuer PIT1 auf 1 Sekunde initialisiert
    ldr r1, =PIT1_VAL
    str r1, [r0]

    ldr r0, =PIT_TCTRL1         			 // Hier wird der Interrupt fuer PIT1 aktiviert ,  und PIT1 aktiviert (PIT-Modul)
    mov r1, #PIT_TCTRL1_TIE_TEN
    str r1, [r0] 

	//Initialisierung Port A LEDs      
	mov r1, 0x1	
	mov r3, #PCR_LEDS
	    
	ldr r0, =PORTA_PCR10					
    str r3, [r0]
    
    ldr r0, =PORTA_PCR11					
    str r3, [r0]
    
    ldr r0, =PORTA_PCR28					
    str r3, [r0]
    
    ldr r0, =PORTA_PCR29					
    str r3, [r0]
	
	ldr r0, =PDDR_E4						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]
	
	ldr r0, =PDDR_E1						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]	
	
	ldr r0, =PDDR_E2						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]
	
	ldr r0, =PDDR_E3						//Setzen von 1 in PDDR fuer GPIO Output
	str r1, [r0]
	//Ausschalten der LEDs fuer Grundzustand
	ldr r0, =E1_OFF							
	str r1, [r0]
	
	ldr r0, =E2_OFF
	str r1, [r0]
	
	ldr r0, =E3_OFF
	str r1, [r0]
	
	ldr r0, =E4_OFF
	str r1, [r0]
	
kalibrieren:	

	//Starten der Kalibrierung 
	ldr r3, =ADC1_SC3
	mov r1, #ADC_SC3_CAL
	str r1, [r3]
		
	ldr r1, =adc_conf
	ldrh r0, [r1]
	
	
	//Kalibrierung laut Seite 860 -  Schritt 2 :Aufaddieren
	ldr r1, =ADC1_CLPS
	ldr r2, [r1]
	add r0, r0, r2 
	
	ldr r1, =ADC1_CLP1
	ldr r2, [r1]
	add r0, r0, r2 
	
	ldr r1, =ADC1_CLP2
	ldr r2, [r1]
	add r0, r0, r2
	
	ldr r1, =ADC1_CLP3
	ldr r2, [r1]
	add r0, r0, r2 
	
	ldr r1, =ADC1_CLP4
	ldr r2, [r1]
	add r0, r0, r2
	
	ldr r1, =ADC1_CLP0
	ldr r2, [r1]
	add r0, r0, r2 
	
	lsr r0, r0, #1		//Schritt 3: Division durch 2
	orr r0, r0, #0x8000 //Schritt 4: Setzen des MSB
	
	ldr r0, =ADC1_PG	//Schritt 6: Store to PG
	strh r0, [r0]
	
	
	ldr r0, =ADC1_SC1A
	mov r1, #ADC1_SC1A_INIT
	str r1, [r0]
	
	ldr r0, =starten
	bl uart_putString
	
	ldr r10, =flagisr
	
	ldr r6, =LED_E1
    ldr r7, =LED_E2
    ldr r8, =LED_E3     
    ldr r9, =LED_E4
	
refresh:
//Setzen der LEDs abhaengig der gewaehlten Stufe (Uebernahme aus Vorversuch)	
	
	ldr r4, =stufe
    ldrb r4, [r4]
    ldr r3, =GPIOA_PCOR

	and r0, r4, #1
	cmp r0, #1
	it eq
	streq r6, [r3]
	
	and r0, r4, #2
	cmp r0, #2
	it eq
	streq r7, [r3]
	
	and r0, r4, #4
	cmp r0, #4
	it eq
	streq r8, [r3]
	
	and r0, r4, #8
	cmp r0, #8
	it eq
	streq r9, [r3]
	
	
	bl uart_charPresent		//Abfrage nach User-Eingabe
    cmp r0, #0
    beq jump
    
    bl uart_getChar			//Eingabe wurde erkannt-> Zeichen "s" abfragen
    cmp r0, #S
    beq stop1	
    b jump
//stop1 dient dazu, Konstanten und Variablen zu laden, ADC zu stoppen und erste Strings auszugeben     
stop1: 

    ldr r5, =ADC1_CFG1	
	ldr r4, =n

	ldr r0, =stopped		//Ausgabe Wandlung und Ausgabe gestopped
	bl uart_putString 
	
	ldr r1, =ADC1_SC3
	mov r2, #ADC1_STOP		//Stoppen der ADC - Wandlung
	str r2, [r1]
	
	ldr r0, =anweisung
	bl uart_putString
	
	ldr r0, =anweisung1
	bl uart_putString
//stop2 dient hauptsaechlich dazu, einen evtl. Neustart zu detektieren und die Genauigkeiten zu ändern - Weiterhin wird hier drin "gewartet" bis wieder gestartet wird		         
stop2:

	bl uart_charPresent			//Abfrage neu eingegebenes Zeichen			
	cmp r0, #0
    				
    it ne 						 
    blne uart_getChar			// Bei Eingabe Zeichen vergleichen mit "s"  
    cmp r0, #S  
    it eq
    beq kalibrieren
    
    cmp r0, #NULL				// Abfrage ob "0" eingegeben wurde
    itttt eq
    moveq r1, #ADC1_CFG1_8		//Konstante zum setzen der Genauigkeit in r1
    moveq r2, #8				// n = 8 vorbereiten
    ldreq r0, =genauigkeit8		// String laden
    beq set						// Ausgabe und setzen in: set
    
    cmp r0, #EINS				// Abfrage ob "0" eingegeben wurde
    itttt eq
    moveq r1, #ADC1_CFG1_10		//Konstante zum setzen der Genauigkeit in r1
    moveq r2, #10				// n = 8 vorbereiten
    ldreq r0, =genauigkeit10		// String laden
    beq set						// Ausgabe und setzen in: set
    
    cmp r0, #ZWEI				// Abfrage ob "0" eingegeben wurde
    itttt eq
    moveq r1, #ADC1_CFG1_12		//Konstante zum setzen der Genauigkeit in r1
    moveq r2, #12				// n = 8 vorbereiten
    ldreq r0, =genauigkeit12		// String laden
    beq set						// Ausgabe und setzen in: set
    
    cmp r0, #DREI				// Abfrage ob "0" eingegeben wurde
    itttt eq
    moveq r1, #ADC1_CFG1_16		//Konstante zum setzen der Genauigkeit in r1
    moveq r2, #16				// n = 8 vorbereiten
    ldreq r0, =genauigkeit16		// String laden
    beq set						// Ausgabe und setzen in: set
    
    b stop2
//Set setzt zuerst die gewaehlte Auflösung und dient der Ausgabe  
set:

    strb r1, [r5]				//Gewaehlte Aufloesung wird hier in ADC1_CFG1_8 geschrieben
    strb r2, [r4]				//Schreiben von n
    
    
    //Ausgabe der gewaehlten Stufe und weitere Anweisungen 
    bl uart_putString			 
    ldr r0, =anweisung3
    bl uart_putString
    ldr r0, =anweisung1
    bl uart_putString
    
    b stop2	// Erst bei erneuter Eingabe von "s" wird mit mit neuer Genauigkeit weiter gemacht
    
// jump dient hauptsächlich zum setzen der Stufe mit vorheriger Ueberpruefung und git die notwendigen Strings/ADC-Wert im Sekundentakt aus          
jump:					
	//ISR-Check und Ruecksetzen					
	ldrb r0, [r10]
    cmp r0, #1
    bne refresh
    mov r0, #0
    strb r0, [r10]
    //Ausgabe "Ox"
    ldr r0, =nullx
    bl uart_putString
	//Ausgabe des ADC-Wertes 
	ldr r0, =ADC1_RA
	ldr r11, [r0]
	ldr r0, [r0]
	bl uart_putInt16
	
	ldr r4, =stufe
	//Erfassen der gesetzten Stufe 8 -16 mit Vergleichen 
	ldr r5, =n 
	ldrb r5, [r5]
	cmp r5, SECHZ
	beq sechzehnstufig
	cmp r5, ZWOELF
	beq zwoelfstufig
	cmp r5, ZEHN
	beq zehnstufig
	cmp r5, #8
	beq achtstufig
	
//Sprungmarke wird je nach gesetzter Stufe "ausgewaehlt", aktueller ADC-Wert wird verglichen und dann entsprechend die Stufe gesetzt ->Zugehöriger String wird geladen und in
//"anzeige" ausgegeben 	
