	bls anzeige	
	
	ldr r0, =S8_4
	cmp r11, r0 		//Vergleich ADC-Wert 
	itttt ls 
	movls r0, #4		//Stufe "4" 
	strbls r0, [r4]		//Speichern in Byte-Variable "Stufe"
	ldrls r0, =n8_4		//Laden des Strings 
	bls anzeige	  
	
	ldr r0, =S8_5
	cmp r11, r0 		//Vergleich ADC-Wert 
	itttt ls 
	movls r0, #5		//Stufe "5" 
	strbls r0, [r4]		//Speichern in Byte-Variable "Stufe"
	ldrls r0, =n8_5		//Laden des Strings 
	bls anzeige	
	
	ldr r0, =S8_6
	cmp r11, r0 		//Vergleich ADC-Wert 
	itttt ls 
	movls r0, #6		//Stufe "6" 
	strbls r0, [r4]		//Speichern in Byte-Variable "Stufe"
	ldrls r0, =n8_6		//Laden des Strings 
	bls anzeige	
	
	ldr r0, =S8_7
	cmp r11, r0			//Vergleich ADC-Wert 
	itttt ls 
	movls r0, #7		//Stufe "7" 
	strbls r0, [r4]		//Speichern in Byte-Variable "Stufe"
	ldrls r0, =n8_7		//Laden des Strings 
	bls anzeige			 
	
	
//Hier erfolgt zunaechst die Ausgabe des "Stufen-Strings" und Stufenwert (abhängig von ADC-Wert) anschließend schließen der Klammer und setzen der Leerzeile
anzeige:	

	bl uart_putString //Ausgabe 
	
	ldr r0, [r4] 
	bl uart_putByteBase10
	
	ldr r0, =klazu
    bl uart_putString
	
	ldr r0, =LEERZEILE
	bl uart_putChar
	
	ldr r1, =GPIOA_PSOR			//Ausschalten aller LEDs, da ansonsten bei jedem Durchgang die LEDs getoggled
    ldr r0, =LEDS_ON 
    str r0, [r1]
	 
	b refresh  
	 
.thumb_func
isr_pit1:			//ISR1 (Uebernahme aus Vorversuch)

    ldr r0, =flagisr
    mov r1, #0x1		
    strb r1, [r0]

    ldr r0, =PIT_TFLG1
    
    str r1, [r0]
    BX LR	

/*** Datenbereich (ab 0x20000000) ***/
.data
flagisr: .byte 0x0
adc_conf: .hword 0x00
nullx: .asciz "0x"
klazu: .asciz ")"
stopped: .asciz "\nAnzeige und Wandlung gestoppt! \n\n"
anweisung: .asciz "Sie haben folgende Eingabemoeglichkeiten: \n \ns:    Neustarten der Wandlung\n\n" 
anweisung1: .asciz "0:    Aendern der ADC-Genauigkeit auf 8 bit \n1:    Aendern der ADC-Genauigkeit auf 10 bit \n2:    Aendern der ADC-Genauigkeit auf 12 bit \n3:    Aendern der ADC-Genauigkeit auf 16 bit\n\n"
