// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ SIM_SCGC5, 0x40048038
.equ SIM_SCGC4, 0x40048034

__BBREG SIM_I2C0, SIM_SCGC4, 6		//Clock fuer I2C0
__BBREG SIM_PORTD, SIM_SCGC5, 12	//Clock fuer PORTD

.equ PD8_9, 0x300 			// Maske fuer PD8 und PD9
.equ PD8, 0x100 			// Maske fuer PD8
.equ ALT_GPIO, 0x100 		// Alternative 1: GPIO
.equ PORTD_PCR8, 0x4004C020
.equ GPIOD_PDDR, 0x400FF0D4
.equ GPIOD_PDOR, 0x400FF0C0
.equ GPIOD_PDIR, 0x400FF0D0
.equ PORTD_PCR9, 0x4004C024
.equ PORTD_PCR89_CONF, 0x200		//MUX 010 -> I2C

//I2C0 Register 
.equ I2C0_A1, 0x40066000		//This register contains the slave address to be used by the I2C module.
.equ I2C0_F, 0x40066001			//I2C Frequency Divider register
.equ I2C0_C1, 0x40066002		//I2C Control Register 1
.equ I2C0_D, 0x40066004			//Data-Register
.equ I2C0_C2, 0x40066005		//Control Register 2
.equ I2C0_S, 0x40066003			//Status Register 
.equ I2C0_FLT, 0x40066006
.equ I2C0_RA,  0x40066007
.equ I2C0_SMB, 0x40066008
.equ I2C0_A2, 0x40066009
.equ I2C0_SLTH, 0x4006600A
.equ I2C0_SLTL, 0x4006600B

//BB zum Ansprechen der einzelnen benoetigten Bits 
__BBREG I2C0_C1_TX_SET, I2C0_C1, 4
__BBREG I2C0_C1_TXAK_SET, I2C0_C1, 3
__BBREG I2C0_C1_RSTA_SET, I2C0_C1, 2
__BBREG I2C0_C1_MST_SET, I2C0_C1, 5
__BBREG I2C0_S_IICIF_CHECK, I2C0_S, 1

.equ I2C0_C1_INIT, 0xC0		//Enable (IICEBN) Enables I2C module operation, Int. enable 

.equ I2C0_READ, 0x91		//lesen
.equ I2C0_WRITE, 0x90		//schreiben
.equ I2C0_D_CONF_DS75, 0x68	//Aufloesung 12 bit 
.equ DS75_TOS, 3
.equ DS75_THYST, 2

.equ COUNTER, 0x19			//zum erreichen von ungefaehr 2micro Sekunden 
.equ LEERZEILE, '\n'
.equ I2C0_F_INIT, 0x12	//Für ca. 400 KHz - Multiiplikator 1x , ICR: 64
.equ START_TX, 0x1 << 3
.equ COUNTER_SEK, 0x7F2815			//Prozessor mit 25 MHz -> 25 mio Takte/Sekunde, das habe zum "ausprobieren" als Startwert genommen -> war zu lang (ca. 3sek) 
.equ TXAK, 0
.equ KOMMA, ','
.equ NDSCR, '_'
.equ COUNTER2, 80 //Anzahl der ICIIF-Pruefung 
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	

	bl uart_init
	bl I2CBus_Reset 
	//Abfang bei Fehler eines Resets
	cmp r0, #1
	bne run
	
	ldr r0, =error
	bl uart_putString
fail:		//Aufhängen bei Reset Fehler oder Fehler bei Konfiguration DS75
	b fail
run:

	
	//Port Init
	ldr r0, =PORTD_PCR8         // MUX 001 : GPIO
    ldr r1, =PORTD_PCR9
    mov r2, #PORTD_PCR89_CONF
    str r2, [r0]
    str r2, [r1]
    
    //Abfang des ersten Temp_Wertes
	ldr r0, =nicetry
	bl uart_putString
    
	mov r11, 0x1
	mov r10, 0x0	
				
	ldr r0, =SIM_I2C0		//Clock aktiv
	str r11, [r0]
	
	//Reset der nicht verwendeten Register
	ldr r0, =I2C0_SMB
    strb r10, [r0]
	
	ldr r0, =I2C0_SLTL
    strb r10, [r0]
               
    ldr r0, =I2C0_SLTH
    strb r10, [r0]
    
    ldr r0, =I2C0_A1
    strb r10, [r0]
    
    ldr r0, =I2C0_C2
    strb r10, [r0]
    
    ldr r0, =I2C0_FLT
    strb r10, [r0]
    
    ldr r0, =I2C0_RA
    strb r10, [r0]
   
    ldr r0, =I2C0_A2
    strb r10, [r0]
		
	//Init IC20  
	ldr r0, =I2C0_F			//Frequency Divider register to set the I2C baud rate 390635 Baud - Aus Datenblättern ermittelt -> Antwort zu Aufgabe b)
	mov r1, #I2C0_F_INIT
	strb r1, [r0]
		
	ldr r0, =I2C0_C1		//Control Register 1 :Enable I2C
	mov r1, #I2C0_C1_INIT
	strb r1, [r0] 
	     
	 //Write to the Configuration Register - Konfigurieren des DS75 nach Datenblatt Seite 13 a)
write_config_DS75:	 
	//Setze 1 in TX 
    ldr r9, =I2C0_C1_TX_SET
    strb r11, [r9]
    //Setze 1 fuer Master    
	ldr r9, =I2C0_C1_MST_SET 
	
	mov r4, #11
	
	check_MST:			//Pruefe ob MST gesetzt und breche nach 10 Versuchen ab  
	subs r4, r4, #1		//wenn Zaehler durchgelaufen, springe in "fail" 
	beq fail
	
	strb r10, [r9]		//Reset Wert "0"
	strb r11, [r9]		//Setze "1"
	
	ldrb r7, [r9]     
	
	cmp r7, #1
	bne check_MST
		
	//Setze 0x90 in DataRegister, um hinein schreiben zu können. 
	ldr r9, =I2C0_D
	mov r0, #I2C0_WRITE
    strb r0, [r9]
    
    //Pruefen des IICIF Bits
    bl check_IICIF 
    
    //Pointer Byte 
    strb r11, [r9]
    
     //Pruefen des IICIF Bits
    bl check_IICIF
    
    //Config Byte 
    mov r8, #I2C0_D_CONF_DS75 //Setzen von Aufloesung 12 Bit, Fehler Toleranz : 2
    strb r8, [r9]
     //Pruefen des IICIF Bits
    bl check_IICIF
    
    bl stop_I2C0	//stoppen 
    // Lesen von 2 Byte
    bl read_temp 
    //Sichern der Werte
    mov r4, r0		//MSB
    mov r5, r1		//LSB
    
    mov r0, #DS75_TOS
    add r1, r4, #3              // T0 + 3
    mov r2, r5
    bl WriteTosThys
    
    mov r0, #DS75_THYST
    add r1, r4, #2              // T0 + 2
    mov r2, r5
    bl WriteTosThys
   
main_loop: 
    bl read_temp
    
    //Sichern der Werte
    mov r8, r0
    mov r9, r1
    //Ausgabe

    mov r0, r8
    bl uart_putInt16
    
    mov r0, #NDSCR
    bl uart_putChar
    
    mov r0, r9
    bl uart_putInt16
      
    // Doppelpunkt
    ldr r0, =doppu
    bl uart_putString
    
    // Vorkommazahl
    mov r0, r8
    bl uart_putByteBase10
    
    mov r0, #KOMMA
    bl uart_putChar
    
    //Nachkommastellen - Hier habe ich nicht leider nicht das gewuenschte Ergebnis erzielt. Hier wuerde ich bei der Korrektur um kurze Hilfesstellung bitten. 
    //Die Nachkommastelle steig/faellt in 16er Schritten bis 240 -> Meine Idee: Wert durch 2,4 zu teilen -> Ich kam leider auf keine Loesung und die Zeit war zu weit fortgeschritten. 
    
    mov r0, r9
    bl uart_putByteBase10
    
    ldr r0, =grace
    bl uart_putString
    
    ldr r0, =LEERZEILE
    bl uart_putChar
  
    bl delay_sek
    b main_loop
    
/**********************************Temperatur auslesen****************************************/
.thumb_func 
read_temp:

	push {r4-r9, lr}
	
	mov r1, #1
	mov r2, #0
	
	//1 in TX von C1 
	ldr r6, =I2C0_C1_TX_SET
	strb r1, [r6]
 
	//0 in TXAK
	ldr r8, =I2C0_C1_TXAK_SET
	strb r2, [r8]
	
	mov r3, #11
	//Start
	ldr r9, =I2C0_C1_MST_SET
		
check_MST_2:			//Pruefe ob MST gesetzt , nach 10 Versuchen abbrechen
	subs r3, r3, #1
	bne jump
	ldr r0, =fail23
	bl uart_putString 
fail_2:
	b fail_2
jump:	
	strb r2, [r9]		//Vorher auf Null setzen
	
	strb r1, [r9]
	ldrb r7, [r9]

	cmp r7, #1
	bne check_MST_2
    
    //Address Byte 
    ldr r7, =I2C0_D
    mov r0, #I2C0_WRITE
    strb r0, [r7]
    
    bl check_IICIF
    
    //Pointer Byte 
    mov r2, #0
    strb r2, [r7] 	//0 nach I2C0_D - Fuer Temperatur 
    
    bl check_IICIF
    
    //Repeat Start
    mov r1, #1						//"ggf. in Unterprogramm" : Wird nur an dieser Stelle benutzt
    ldr r0, =I2C0_C1_RSTA_SET
    strb r1, [r0]
    
    //Auf Lesen konfigurieren
    mov r0, #I2C0_READ
    strb r0, [r7]
    
    bl check_IICIF
 
    //Auf Empfang konfigurieren
    mov r2, #0
    strb r2, [r6]
    
    //Dummy read
    ldrb r0, [r7]
    
    bl check_IICIF
    
    //Laden und Speichern des 1. Bytes
    ldrb r4, [r7]		//MSB
    
    //Setze TXAK
    mov r1, #1
    strb r1, [r8]
    
    bl check_IICIF
    
    //Laden und Speichern des 2. Bytes
    ldrb r5, [r7]		//LSB		
     
    bl check_IICIF
    
    bl stop_I2C0
    
    mov r0, r4
    mov r1, r5
    
    pop {r4-r9, pc}
    
/*****************************************Grenzwerteintrgaung**************************/
.thumb_func
WriteTosThys:

	push {r4-r9, lr}
	//Sichern der Werte 
	mov r6, r0		//TOS/THYS		
	mov r4, r1		//MSB
	mov r5, r2		//LSB
	
	mov r1, #1
	mov r2, #0
 
    //TX auf 1
    ldr r7, =I2C0_C1_TX_SET
    strb r1, [r7]
    
    mov r3, #11
    
    //Start
	ldr r9, =I2C0_C1_MST_SET
	
check_MST_3:			//Pruefe ob MST gesetzt , Abbruch nach 10 Versuchen 
	subs r3, r3, #1
	bne jump1
	ldr r0, =fail23
	bl uart_putString 
fail_3:
	b fail_3
jump1:	
	strb r2, [r9]		//Vorher auf Null setzen 
	strb r1, [r9]
	ldrb r7, [r9]

	cmp r7, #1
	
	bne check_MST_3
	
	ldr r8, =I2C0_D
	mov r7, #I2C0_WRITE
    strb r7, [r8]
    
    bl check_IICIF
    
    //Pointer Byte
    strb r6, [r8]
   
    bl check_IICIF
  
    // Sende MSB_T0 + 3
    strb r4, [r8]
    
    bl check_IICIF
    
    // Sende LSB
    strb r5, [r8]
    
    bl check_IICIF
    
    bl stop_I2C0
  
    pop {r4-r9, pc}
      
 /***********************************IICIF-Pruefung***********************/
.thumb_func
check_IICIF:

	ldr r0, =I2C0_S_IICIF_CHECK
	mov r3, #COUNTER2
	
	//Vergleich mit 1 
check:	
	
	ldrb r1, [r0]
	cmp r1, #1
	beq okay

	subs r3, r3, #1 //falls Interrupt nicht kommt 
	bne check

//IICIF = 1 : This bit must be cleared by software by writing a 1 to it -> setze 1 	
okay:
	strb r1, [r0]
	
	bx lr
		
/***************************Stoppen**************************/	
.thumb_func
stop_I2C0:

	ldr r0, =I2C0_C1_MST_SET 			//Master-Bit auf 0 setzen
	mov r1, #0
	strb r1, [r0]

	bx lr         

/*************************Sekunden_Loop*********************/
.thumb_func
delay_sek:
	ldr r3, =COUNTER_SEK			//Register bekommt ermittelte Konstante (Vorversuch) zugewiesen 
loop_sek: 							//loop zaehlt runter und verlaesst nach ca. 1 Sekunde die U.Funkt. 	
	subs r3, r3, #1	
	bne loop_sek

	bx lr
		
	/* **************** I2C -Bus zuruecksetzen *********** */
	
.thumb_func
I2CBus_Reset:
    push {lr}

    mov r3, #10
    ldr r0, =SIM_PORTD          // In SCGC5 den Takt fuer Port D aktivieren
    mov r1, #1
    str r1, [r0]
    ldr r0, =PORTD_PCR8         // Portleitungen PD8, PD9 als GPIO
    ldr r1, =PORTD_PCR9
    mov r2, #ALT_GPIO
    str r2, [r0]
    str r2, [r1]
    ldr r0, =GPIOD_PDDR         // PD8 , PD9 als Ausgang schalten
    ldr r2, [r0]
    orr r2, r2, #PD8_9
    str r2, [r0]
        
loop:
    // Ein Zaehler fuer maximal 10 Versuche ist implementiert.
    // Danach wird Fehlermeldung auf Terminal ausgeben und abbrechen.
    ldr r0, =GPIOD_PDOR     // SCL deaktivieren
    ldr r2, [r0]
    bic r2, r2, #PD8        // entsprechendes Bit loeschen
    str r2, [r0]
    bl I2C_Delay
    
    ldr r0, =GPIOD_PDOR     // SCL und SDA aktivieren
    ldr r2, [r0]
    orr r2, r2, #PD8_9
    str r2, [r0]
    bl I2C_Delay
    
    ldr r0, =GPIOD_PDIR
    ldr r2, [r0]
    and r2, r2, #PD8_9       // nur Bits 9 und 10 pruefen
    cmp r2, #PD8_9           // Bit 9 und Bit 10 gesetzt?
    beq end
    
    subs r3, r3, #1
    bne loop                // ggf. wiederholen
    
    ldr r0, =fail1
    bl uart_putString
    mov r0, #1 
  
end:
    pop {pc}		

/******************************** Verzoegerung***************************************/	
	.thumb_func
I2C_Delay:
	mov r1, #17		//1 Takt: 1/25000000hz: 40ns : 2us/40ns = 50 Takte : 50/3 (subs und bne) ~ 17

loop_1:
	subs r1, r1, #1
	bne loop_1

    bx lr
		    
/*** Datenbereich (ab 0x20000000) ***/
.data

grace: .asciz "Grad Celsius"
nullx: .asciz "0x"
doppu: .asciz ": "
fail1: .asciz "Reset-Fehler\n"
fail23: .asciz "Fehler beim setzen des Master_Bits. Programm wurde angehalten"
error: .asciz "Programm wurde aufgrund eines Fehlers beendet"
nicetry: .asciz "Programm gestartet! Erster Temperaturausgabewert ist ungueltig! \n\n" 

//Aufgabe c) : Ich konnte keine wirkliche Veränderung der LED beobachten. Die Temperatur hingegen steigt wie gewollt, bei betätigen des Tasters. 

.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)
// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified
//SPI
.equ SIM_SCGC3_SPI2, 0x40048030
__BBREG SCGC3_SPI2, SIM_SCGC3_SPI2 12     // SPI2 - Clock aktivieren 

.equ SPI2_MCR, 0x400AC000                 //SPI2 Module Configuration Register
__BBREG SPI2_MCR_MODULE, SPI2_MCR, 14     //SPI2 MDIS Module Disable 

.equ SPI2_TCR, 0x400AC008			 //Transfer Count Register
.equ SPI2_CTAR0, 0x400AC00C          //DSPI Clock and Transfer Attributes Register (In Master Mode)
.equ SPI2_CTAR1, 0x400AC010			 //DSPI Clock and Transfer Attributes Register
.equ SPI2_SR, 0x400AC02C             //DSPI Status Register
__BBREG SPI2_SR_TCF, SPI2_SR, 31     //Transfer Complete Flag ansprechen

.equ SPI2_RSER, 0x400AC030           //DMA/Interrupt Request Select and Enable Register
.equ SPI2_PUSHR, 0x400AC034          //PUSH TX FIFO Register 
.equ SPI2_POPR, 0x400AC038           //POP RX FIFO Register - Empfang


.equ SPI2_MCR_CONF, 0x80003000  	// Master Config: Master Mode, Kommunikation aus und Queues aus
.equ SPI2_CTAR0_CONF, 0x3E441117    //8 Bit Frames, Clck Polarity = 1, Clk Phase = 1, CSSCK, DT = 480ns, ASC = 160ns , 97656,25 Hz

.equ SPI2_PUSHR_EOQ,  0x08000000      // EOQ Flag im PUSHR ansprechen
.equ SPI2_PUSHR_PCS,  0x00020000     // PCS Flag im PUSHR ansprechen
.equ SPI2_PUSHR_CONT, 0x80000000     // CONT Flag im PUSHR ansprechen
.equ SPI2_PUSHR_R, 	  0x88020000 	//Konfig zum lesen 

.equ DS1722_CONF_W, 0x80            //Fuer Config-Registers
.equ DS1722_TEMP_L, 0x01            // Fuer unteres Bytes der Temperatur
.equ DS1722_TEMP_H, 0x02           // Fuer oberes Bytes der Temperatur

.equ RESOLUTION_MAX, 12             // Maximale Res.
.equ RESOLUTION_MIN, 8              // Minimale Res
.equ DS1722_BASIS, 0xE0            // Basis Konfig. des DS

//PIT 
.equ SIM_SCGC6_PIT, 0x4004803C 			//Adresse zum System Clock Gating Control Register 6 -> PIT muss spaeter aktiv sein 
__BBREG SCGC6_PIT, SIM_SCGC6_PIT, 23 	//PIT

.equ PIT_MCR, 0x40037000		//Adresse PIT_MCR_Register
.equ PIT_LDVAL1, 0x40037110		//Adresse PIT_LDVAL1_Register
.equ PIT_TCTRL1, 0x40037118		//Adresse PIT_TCTRL1_Register
.equ PIT_TFLG1, 0x4003711C		//Adresse PIT_TFLG1_Register
.equ NVIC_ISER2, 0xE000E108		//Adresse NVIC_ISER2_Register(Interrupt Set Enable)
.equ NVIC_ICPR2, 0xE000E288		//Adresse NVIC_ICPR2_Register(Clear Pending Interrupt Requests)
.equ NVIC_INT_ON, 0x20

__BBREG PIT_TCTRL1_TEN, PIT_TCTRL1, 0

.equ PIT1_VAL, 0x17D783F
.equ PIT_TCTRL1_TIE_TEN, 0x2
.equ SCR_VTOR, 0xE000ED08
.equ OFFS_PIT1, 0x154

.equ PIT1_VAL_8, 0x1C9C37		  // 8 Bit  (0.075s),	0x17D783F * 0.075
.equ PIT1_VAL_9, 0x39386E 		  // 9 Bit 	(0.15s), 	0x17D783F * 0.15
.equ PIT1_VAL_10, 0x7270DC 	 	 // 10 Bit (0.3s), 	0x17D783F * 0.3
.equ PIT1_VAL_11, 0xE4E1B8		 // 11 Bit (0.6s), 	0x17D783F * 0.6
.equ PIT1_VAL_12, 0x1C9C370	  	// 12 Bit (1.2s), 	0x17D783F * 1.2

//PCR 
.equ SIM_SCGC5_PORTA, 0x40048038
.equ SIM_SCGC5_PORTD, 0x40048038
.equ SIM_SCGC5_PORTE, 0x40048038

__BBREG SCGC5_PORTA, SIM_SCGC5_PORTA, 9     // Takt Port A
__BBREG SCGC5_PORTD, SIM_SCGC5_PORTD, 12    // Takt Port D
__BBREG SCGC5_PORTE, SIM_SCGC5_PORTE, 13    // Takt Port E

.equ PORTA_PCR19, 0x4004904C		//SW1
.equ PORTE_PCR26, 0x4004D068		//SW2


.equ PORTE_ISR, 0x4004D0A0		
.equ PORTA_ISR, 0x400490A0

__BBREG ISR_PORTE, PORTE_ISR, 26		//Interrupt Status Flag Register
__BBREG ISR_PORTA, PORTA_ISR, 19		//Interrupt Status Flag Register

.equ PORTD_PCR12, 0x4004C030            // Port D PCR 12 Clock
.equ PORTD_PCR13, 0x4004C034            // Port D PCR 13 MOSI
.equ PORTD_PCR14, 0x4004C038            // Port D PCR 14 MISO
.equ PORTD_PCR15, 0x4004C03C            // Port D PCR 15 CS

.equ PORTD_MUX, 0x200            		// Port D Pin Konfiguration als Alternative 2 -> 010 in MUX

.equ GPIOA_PDIR, 0x400FF010
.equ GPIOA_PDDR, 0x400FF014		
.equ GPIOE_PDIR, 0x400FF114
.equ GPIOE_PDDR, 0x400FF014
//Fuer spaeteres ansprechen der entsprechenden Stellen im Register (Ausgang/Eingang, high/low)
__BBREG PDDR_SW1, GPIOA_PDDR, 19 
__BBREG PDIR_SW1, GPIOA_PDIR, 19 
__BBREG PDDR_SW2, GPIOE_PDDR, 26 
__BBREG PDIR_SW2, GPIOE_PDIR, 26 

.equ PCRN_SWX_MUX, 0xA0103			//Digital Input/ Interrupt on -falling- edge/GPIO 
//ISR SW1/SW2
.equ OFFS_SW2, 0x1AC			//Interrupt Request Offset SW2
.equ OFFS_SW1, 0x19C      		// Interrupt Request Offset SW1
//NVIC MASK fuer PIT, ISRSW2, ISRSW1
.equ NVIC_MASK, 0x8800020 		//Errechnet mit Interrupt Nummern  / Modulo 32 / Bits geschoben und als ganzen Wert zusammengefasst
.equ ZWOELF, 12
.equ ten, 10 
.equ LEERZEILE, '\n'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/ 
main:	
	bl uart_init
    mov r10, #0
    mov r11, #1
    // Clock Gates - Takte aktivieren
    ldr r0, =SCGC5_PORTA
    str r11, [r0]
    ldr r0, =SCGC5_PORTD
    str r11, [r0]
    ldr r0, =SCGC5_PORTE
    str r11, [r0]
    ldr r0, =SCGC6_PIT
    str r11, [r0]
    ldr r0, =SCGC3_SPI2
    str r11, [r0]
    //Port Konfig - Hier wird der oben erechnete Wert (PCRN_SWX_MUX) in die Register eingetragen (Digital Input/ Interrupt on -falling- edge/GPIO fuer SW1undSW2)  
    ldr r0, =PORTA_PCR19    
    ldr r1, =PCRN_SWX_MUX
    str r1, [r0]
    ldr r0, =PORTE_PCR26
    str r1, [r0]
    //Port in PDDR fuer Sw1 und Sw2 auf GPIO Output setzen -> 0 an ermitelte Stelle
    ldr r0, =PDDR_SW1
    str r10, [r0]
    ldr r0, =PDDR_SW2
    str r10, [r0]
    // Port D Pin Konfiguration als Alternative 2 -> 010 in MUX (fuer PortD 12 - 15 [CLK, MOSI, MISO, CS1]        
    ldr r0, =PORTD_PCR12
    ldr r1, =PORTD_MUX
    str r1, [r0]
    ldr r0, =PORTD_PCR13
    str r1, [r0]
    ldr r0, =PORTD_PCR14
    str r1, [r0]
    ldr r0, =PORTD_PCR15
    str r1, [r0]
    //Interrupt-Vektor fuer PIT1, SW1, SW2 setzen
    ldr r0, =SCR_VTOR          				
    ldr r0, [r0]
    ldr r1, =isr_pit1
    str r1, [r0, #OFFS_PIT1]
    ldr r1, =isr_sw1
    str r1, [r0, #OFFS_SW1]
    ldr r1, =isr_sw2
    str r1, [r0, #OFFS_SW2]
    //NVIC
    // Hier werden moegliche pending Interrupts fuer PIT1, SW1, SW2 geloescht (NVIC)
    ldr r0, =NVIC_ICPR2
    ldr r1, =NVIC_MASK
    str r1, [r0]
    // Hier wird derInterrupt fuer PIT1, SW1, SW2  aktiviert (NVIC)
    ldr r0, =NVIC_ISER2
    str r1, [r0]
    //Init PIT-Modul
    ldr r0, =PIT_MCR         // Hier werden alle PITs aktiviert, und im Debug-Modus laufen gelassen (PIT-Modul)
    str r11, [r0]
  /*  // Hier wird der Startwert fuer PIT1 auf 1 Sekunde initialisiert
    ldr r0, =PIT_LDVAL1          			  
    ldr r1, =PIT1_VAL
    str r1, [r0]*/
    
    // Hier wird der Interrupt fuer PIT1 aktiviert ,  und PIT1 aktiviert (PIT-Modul)-> Timer enable, Timer Interrupt enable ->3:011
    ldr r0, =PIT_TCTRL1         			 
    mov r1, #PIT_TCTRL1_TIE_TEN
    str r1, [r0] 
    //Init SPI2
    ldr r0, =SPI2_MCR_MODULE		//Enables the module clocks.
    str r10, [r0]
    ldr r0, =SPI2_MCR				// Master Config: Master Mode, Kommunikation aus und Queues aus
    ldr r1, =SPI2_MCR_CONF			
    str r1, [r0]
    ldr r0, =SPI2_CTAR0
    ldr r1, =SPI2_CTAR0_CONF		//8 Bit Frames, Clck Polarity = 1, Clk Phase = 1, CSSCK, DT = 480ns, ASC = 160ns , 97656,25 Hz
    str r1, [r0]
    ldr r0, =SPI2_RSER				//Disable DMA und Int -> 0 
    str r10, [r0]
    
    ldr r0, =progstart				//Ausgabe zum Start des Programms 
	bl uart_putString
    
    mov r0, #ZWOELF 
    bl write_config
    
   ldr r8, =nachkomma
   ldr r5, =aufloesung
   ldr r4, =aufloesung_check 
   ldr r9, =flagisr
    
main_loop:

	mov r0, #DS1722_TEMP_H          //Auslesen des 1. Bytes
	bl read_temp
	bl uart_putByteBase10
	
	mov r0, #DS1722_TEMP_L			//Auslesen des 2. Bytes
	bl read_temp
	lsr r0, r0, #4					
	mov r1, #ten					//Stringlaenge : 10 Byte
	mla r0, r0, r1, r8				//Multiplizieren mir der Stringlaenge und addiere sie auf die Anfangsangsaddresse der Nachkommastellen 
	bl uart_putString				//Ausgabe
	//Vergleichen der Aufloesungen und checkup einer neu gewaehlten 
	ldrb r0, [r4]                  
    ldrb r2, [r5]
    //Bei neu gewaehlter Auflösung, wird hier umkonfiguriert
	cmp r0, r2
	it eq
	beq check_isr
	
	mov r0, r2
	
	strb r0, [r4]
	mov  r7, r0
	//Asugabe der Auflösung auf dem Terminal 
	ldr r0, =aufloesung_ausg			
	bl uart_putString 
	mov r0, r7
	bl uart_putByteBase10
	ldr r0, =LEERZEILE
    bl uart_putChar

	mov r0, r7
	
	sub r0, r0, #8                 //Aufloesungs-Ziffer-Berechnung 
    mov r1, #4
    
    ldr r2, =pit_time
    mla r7, r0, r1, r2
    
    bl write_config
    
    ldr r0, =PIT_TCTRL1_TEN		//Abschalten des PIT
    str r10, [r0]
    
    ldr r1, =PIT_LDVAL1
    ldr r2, [r7]
    str r2, [r1]
    
    str r11, [r0]		//Starten PIT
    
    
    
//Ueberpruefen das Int. "gekommen" ist    
check_isr:
	ldrb r1, [r9]
	cmp r1, #0
	beq check_isr
	
	strb r10, [r9]
	
	b main_loop
	
    
.thumb_func
write_config:

	push {r6, r7, lr}
	
	lsl r1, r0, #1					//Verschiebe die Auflösung eine Stelle nach links
	orr r6, r1, #DS1722_BASIS		//Hier wird mit dem Conig-Byte "verodet"
	
	ldr r7, =SPI2_PUSHR_PCS			//Hier wird das PCS-Flag gesetzt im PUSHR
	mov r1, #DS1722_CONF_W			
	orr r1, r1, r7
	ldr r0, =SPI2_PUSHR_CONT		//Hier wird das CONT-Flag gesetzt im PUSHR
	orr r1, r1, r0 
	ldr r0, =SPI2_PUSHR         	//Hier wird die Adresse gesendet 
    str r1, [r0]
    //Ueberpruefen der vollst.Uebertragung
    ldr r2, =SPI2_SR_TCF        	// Lade der Adresse für das Transfer Complete   
check:
    ldr r3, [r2]               		 // Checke das gesetzte TCF-Bit (1) 
    cmp r3, #1
    bne check
    str r3, [r2]                	//Wenn gesetzt -> Ruecksetzen 
    
    ldr r0, =SPI2_PUSHR_EOQ
    orr r1, r6, r7 					//Hier werden Config, PCS, und EOQ "verodert"  
    orr r1, r1, r0
    
    ldr r0, =SPI2_PUSHR         	//Sende das Config Byte
    str r1, [r0]
    
check_2:
    ldr r3, [r2]                	//Checke das gesetzte TCF-Bit (1) 
    cmp r3, #1
    bne check_2
    str r3, [r2]                	//Wenn gesetzt -> Ruecksetzen 
    
    pop {r6, r7, pc}
    
    
.thumb_func
read_temp:
	 
	ldr r1, =SPI2_PUSHR_R        // Hier wird die Konfiguration zu Lesen geladen
    orr r0, r0, r1               // Verodern mit 

    ldr r1, =SPI2_PUSHR          //Hier wird die Adresse gesendet
    str r0, [r1]

     //Ueberpruefen der vollst.Uebertragung
    ldr r2, =SPI2_SR_TCF        // Lade der Adresse für das Transfer Complete   
check_3:
    ldr r3, [r2]                // Checke das gesetzte TCF-Bit (1) 
    cmp r3, #1
    bne check_3
    str r3, [r2]                //Wenn gesetzt -> Ruecksetzen 
    
            
    ldr r0, =SPI2_POPR              //Daten aus dem Register laden
    ldr r3, [r0]

    ldr r0, =SPI2_PUSHR_PCS         // Zurücksetzen
    ldr r1, =SPI2_PUSHR             // Sende Frame
    str r0, [r1]
     //Ueberpruefen der vollst.Uebertragung
check_4:
    ldr r1, [r2]   // Checke das gesetzte TCF-Bit (1) 
    cmp r1, #1
    bne check_4
    str r1, [r2]  //Wenn gesetzt -> Ruecksetzen 
    
    mov r0, r3	//Uebergabe
    
    bx lr
	
/***************ISR PIT1***************/
.thumb_func
isr_pit1:			//ISR1 
    ldr r0, =flagisr
    mov r1, #0x1		
    strb r1, [r0]

    ldr r0, =PIT_TFLG1
    
    str r1, [r0]
    BX LR       
/****************ISR SW1****************/    
.thumb_func
isr_sw1:
    push {lr}    
    ldr r0, =ISR_PORTA                  // Port 19 
    ldr r1, [r0]
    cmp r1, #1                          // Check ob an 19 ein Int. anliegt
    bne stop_isr_sw1                    // Kein Int- -> Beenden
    
    bl add_aufloesung
        
    str r1, [r0]						//Int. Ruecksetzen
stop_isr_sw1:
    pop {pc}
/***************Erhoehen der Aufloesung***************/       
.thumb_func
add_aufloesung:
 
   ldr r3, =aufloesung      //Taster wurde gedrueckt (Int. ausgeloest), also erhoehe die Aufloesung um eins 
   ldrb r2, [r3]
   add r2, r2, #1 
   
   cmp r2, ZWOELF			//Wenn der nächste Wert groeßer ist als die maximal zulässige Aufloesung - Starte bei der kleinsten (8)		
   it gt
   movgt r2, #8
   
   strb r2, [r3]
   
   bx lr 
    
/****************ISR SW2****************/
.thumb_func
isr_sw2:
   	push {lr}   
   	ldr r0, =ISR_PORTE                  // Port 26 
    ldr r1, [r0]
    cmp r1, #1                          // Check ob an 26 ein Int. anliegt
    bne stop_isr_sw2                    // Kein Int- -> Beenden
    
    bl sub_aufloesung
    str r1, [r0]						//Int. Ruecksetzen
stop_isr_sw2:

   	pop {pc} 
   	
.thumb_func
sub_aufloesung:
   	
   	ldr r3, =aufloesung               //Taster wurde gedrueckt (Int. ausgeloest), also V die Aufloesung um eins 
    ldrb r2, [r3]
    sub r2, r2, #1
        
    cmp r2, #8            			 //Wenn der nächste Wert kleiner ist als die maximal zulässige Aufloesung - Starte bei der groeßten (12)	
    it lt
    movlt r2, #ZWOELF          		 
    
    strb r2, [r3]
    
    bx lr 
       

/*** Datenbereich (ab 0x20000000) ***/
.data
//ISR flag
flagisr: .byte 0x0
//Aktuelle Aufloesung
aufloesung: .byte 12
//Zum Erkennen einer neuen Aufloesung 
aufloesung_check: .byte 0


pit_time: .word PIT1_VAL_8, PIT1_VAL_9, PIT1_VAL_10, PIT1_VAL_11, PIT1_VAL_12

aufloesung_ausg: .asciz "Es wurde eine neue Aufloesung durch den Nutzer gewaehlt: " 

nachkomma: .asciz ",0000\tgC\n", ",0625\tgC\n", ",1250\tgC\n", ",1875\tgC\n",
		   .asciz ",2500\tgC\n", ",3125\tgC\n", ",3750\tgC\n", ",4375\tgC\n",
		   .asciz ",5000\tgC\n", ",5625\tgC\n", ",6250\tgC\n", ",6875\tgC\n",
		   .asciz ",7500\tgC\n", ",8125\tgC\n", ",8750\tgC\n", ",9375\tgC\n"
		   
		   
progstart: .asciz "Initialisierung erfolgreich abgeschlossen! \nStartaufloeung: 12 Bit \nStart der Temperaturausgabe: \n\n"	   
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// SIM 
.equ SIM_SCGC6_RTC, 0x4004803C
__BBREG SCGC6_RTC, SIM_SCGC6_RTC, 29 //Takt Aktivierung fur RTC

.equ SIM_SCGC6_PIT, 0x4004803C 	//Adresse zum System Clock Gating Control Register 6 -> PIT muss spaeter aktiv sein 
__BBREG SCGC6_PIT, SIM_SCGC6_PIT, 23
// Int. Vektortabelle
.equ SCR_VTOR,           0xE000ED08                          
// Int. Konstanten
.equ NVIC2_REG, 2
.equ NVIC2_ISER, 0xE000E108		//Interrupt Set Enable
.equ NVIC2_ICPR, 0xE000E288		//Clear Pending Interrupt Requests


.equ RTC_ALARM_NVIC_REG_BITPOS, 0x2   // Bitposition für die NVIC Konfiguratiosregister, IRQNR:66
.equ RTC_ALARM_NVIC_BIT_MSK, 1 << RTC_ALARM_NVIC_REG_BITPOS // Bitmaske zur Manipulation der NVIC Konfigurationsregister
.equ RTC_ALARM_NVIC_REG_NR, 2    // Nummer des Konfigurationsregister
.equ RTC_ALARM_IRQ_OFFSET,  0x00000148    // Interrupt Request Offset für PIT1

.equ RTC_SEC_NVIC_REG_BIT, 0x3	// Bitposition für die NVIC Konfiguratiosregister, IRQNR: 67
.equ RTC_SEC_NVIC_BIT_MSK,  1 << RTC_SEC_NVIC_REG_BIT   // Bitmaske fuer NVIC Konfigreg.
.equ RTC_SEC_NVIC_REG_NR,   2  // Nr. des Konfigurationsregister
.equ RTC_SEC_IRQ_OFFSET,    0x0000014C   // Interrupt Request Offset 

.equ NVIC_MSK, RTC_SEC_NVIC_BIT_MSK | RTC_ALARM_NVIC_BIT_MSK // Bit fuer NVIC Register

// RTC
.equ RTC_TSR, 0x4003D000		//RTC Time Seconds Register
.equ RTC_TPR, 0x4003D004		//RTC Time Prescaler Register (RTC_TPR)
.equ RTC_TAR, 0x4003D008		//RTC Time Alarm Register (RTC_TAR)
.equ RTC_CR,  0x4003D010		//RTC Control Register (RTC_CR)
.equ RTC_SR,  0x4003D014		//RTC Status Register (RTC_SR)
.equ RTC_IER, 0x4003D01C		//RTC Interrupt Enable Register (RTC_IER)

__BBREG RTC_CR_SWR, RTC_CR, 0 
__BBREG RTC_SR_TCE, RTC_SR, 4

.equ RTC_CR_INIT, 0x104 // Supervisor Access, Software Reset beschreiben 
.equ RTC_IER_INIT, 0x17	//TIIE, TOIE, TAIE, TSIE beschreiben 				
.equ RTC_CRYSTAL_OSC, 62500000 // Wert fuer ca. 10 Sekunden -> Wartezeit/Einschwingen 

.equ RTC_DAY, 86399
.equ RTC_HOUR, 3599

.equ RTC_PRESET_DAY, 86395
.equ RTC_PRESET_HOUR, 3595

.equ ONE_HOUR, 3600
.equ ONE_MINUTE, 60

// Buchstaben für die Eingabe
.equ INPUT_R, 'r'
.equ INPUT_S, 's'
.equ INPUT_D, 'd'
.equ INPUT_H, 'h'
.equ INPUT_P, 'p'

.equ ZEHN, 10


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	bl uart_init
	
	mov r10, #0
	mov r11, #1


	// Clock Gates 
    ldr r0, =SCGC6_RTC
    str r11, [r0]
    
    ldr r0, =SCGC6_PIT
    str r11, [r0]
    
    // Schreibe in Vektortabelle
    ldr r0, =SCR_VTOR               
    ldr r1, [r0]

    ldr r0, =rtc_time             		  
    str r0, [r1, #RTC_SEC_IRQ_OFFSET]     // Schreibe ISR in Vektortabelle
    ldr r0, =rtc_alarm         			  
    str r0, [r1, #RTC_ALARM_IRQ_OFFSET]   // Schreiben ISR in Vektortabelle
   
    // NVIC
    ldr r1, =NVIC_MSK
    
    // Hier werden moegliche pending Interrupts geloescht
    ldr r0, =NVIC2_ICPR
    str r1, [r0]
    
    // Schalte Interrupts für RTC ein
    ldr r0, =NVIC2_ISER
    str r1, [r0]
    
    //Initialisierung des RTC
    
    ldr r0, =RTC_CR_SWR		//Software Reset
    str r11, [r0]
    str r10, [r0]
    
    ldr r0, =RTC_CR		// Supervisor Access, Software Reset beschreiben 
    mov r1, #RTC_CR_INIT
    str r1, [r0]
    
    //Einschwingen des Quartz : ca. 10 Sekunden
    ldr r5, =RTC_CRYSTAL_OSC

osc_loop:   
    subs r5, r5, #1
    bne osc_loop
   
    //Sekunden Interrupt: ein
    ldr r0, =RTC_IER
    mov r1, #RTC_IER_INIT
    str r1, [r0]
    
    // Setze das Alarm Register
    ldr r0, =RTC_TAR
    ldr r1, =RTC_DAY  //86399
    str r1, [r0]
    
    //Alarm und Sekunden Interrupt: ein
    ldr r0, =RTC_IER		////TIIE, TOIE, TAIE, TSIE beschreiben 
    mov r1, #RTC_IER_INIT
    str r1, [r0]
    
    // Setzen der Zählregiser auf 0
    ldr r0, =RTC_TPR
    str r10, [r0]
    ldr r0, =RTC_TSR
    str r10, [r0]
    
    // Schalte die RTC ein: 1 in 4(TCE)
    ldr r0, =RTC_SR_TCE
    str r11, [r0]
   
   
    ldr r12, =preset_byte
    strb r10, [r12]
    ldr r10, =flagisr               // Run User Flag
    ldr r7,  =clock_mode         // Uhr Modus: 1 = 24h, 0 = 1h
    mov r6, #1
  
   ldr r0, =start_init
   bl uart_putString
  
    
main_loop:

    bl uart_charPresent    // Wenn kein Zeichen eingegeben wurde mach weiter, ansonsten zu output 
    cmp r0, #0
    beq output
    
    bl uart_getChar        //Input holen 
    
    cmp r0, #INPUT_D	  //Check gegen "d"
    bne hour
 
    ldr r8, =RTC_DAY		//86399
    ldr r9, =day_mode		//String laden 
    mov r4, #1				//1 fuer den Day-Mode 
    b change_mode
   
hour:

	cmp r0, #INPUT_H
    bne reset
    
    ldr r8, =RTC_HOUR
    ldr r9, =hour_mode	//String laden 
    mov r4, #0			//0 fuer Hour-Mode
    
change_mode:    
   
  	mov r0, #0              // Setze das TSR Register zurück
    bl tpr_tsr
    
    ldr r0, =RTC_TAR        // Lade den Alarm Wert für eine Stunde - 1 Sekunde
    str r8, [r0]
                  
    strb r4, [r7]			// Setze den Uhr Modus auf 0 oder 1 

    mov r0, r9              // Ausgabe für den Benutzer
    bl uart_putString
    b output
        
reset:

	cmp r0, #INPUT_R
    bne startstop
    
    mov r0, #0              // Setze das TSR und TPR Register zurück
    bl tpr_tsr
    
    ldr r0, =clock_reset    // Ausgabe für den Benutzer
    bl uart_putString
    
    b output

startstop:  

	cmp r0, #INPUT_S               // Start/Stop
    bne preset

    eor r6, r6, #1                // Bit in r6 flippen 
    
    cmp r6, #0
    ite eq
    ldreq r0, =output_off
    ldrne r0, =output_on

    bl uart_putString
    b output

preset:

	cmp r0, #INPUT_P
    bne output

    ldrb r0, [r7]               // Lade den aktuellen Modus der Uhr (24h oder 1h)
    
    cmp r0, #0
    ite eq
    ldreq r0, =RTC_PRESET_HOUR  // 1h Modus: setze das TSR Register auf 1h - 5 Sekunden
    ldrne r0, =RTC_PRESET_DAY   // 24h Modus: setze das TSR Register auf 24h - 5 Sekunden
    
    bl tpr_tsr                  // TSR und TPR Register setzen
    
    ldr r0, =preset_config         // Ausgabe auf dem Terminal
    bl uart_putString

output:

	ldrb r0, [r12]             // Flag, ob die Endzeit erreicht wurde und die Ausgabe erscheinen soll
	cmp r0, #1
	bne output_t
	
	mov r0, #0
	strb r0, [r12]
	
	ldr r0, =end_reached
	bl uart_putString

output_t:

    cmp r6, #1                  // Ist die Ausgabe aktiviert?
    bne wait

    ldr r11, =RTC_TSR           // Lade den aktuellen Wert im TSR Register
	ldr r9, [r11]

    mov r4, #0
	ldrb r1, [r7]              // Ist der 24h Modus eingschaltet?
    cbz r1, output_h
    
	mov r11, #ONE_HOUR         // Lade eine Stunde in Sekunden
	udiv r4, r9, r11           // Ermittle die abgelaufenen Stunden
	mov r0, r4
	
	bl output_dec
    
    mov r0, #':'
    bl uart_putChar

output_h:

	mov r1, #ONE_MINUTE         // Lade eine Minute in Sekunden
	mov r2, #ONE_HOUR           // Lade eine Stunde in Sekunden
	mls r8, r2, r4, r9          // Ermittle die abgelaufenen Minuten
	udiv r5, r8, r1
    
    mov r0, r5
    bl output_dec


    mov r0, #':'
    bl uart_putChar
    
    mov r1, #ONE_MINUTE         // Ermittle abgelaufene Sekunden
    mls r0, r1, r5, r8
    bl output_dec

	mov r0, #'\n'
	bl uart_putChar

//Int von PIT 1 abwarten 
wait:  
    ldrb r0, [r10]
    cmp r0, #0
    beq wait

    mov r0, #0
    strb r0, [r10]
    b main_loop
               
.thumb_func
rtc_alarm:

    push {lr}

    ldr r0, =preset_byte        // Setze Flag zur Ausgabe 
    mov r1, #1
    strb r1, [r0]
    
    mov r0, #0                          // Setze die Zeit Register zurück
    bl tpr_tsr
    
    ldr r0, =clock_mode                 // Überprüfe User Flag 
    ldrb r1, [r0]
    
    cmp r1, #0
    ite eq
    ldreq r1, =RTC_HOUR
    ldrne r1, =RTC_DAY

    ldr r0, =RTC_TAR                    // Setze geladenen Wert im TAR Register    
    str r1, [r0]
    
    pop {pc}

//ISR PIT1    
.thumb_func
rtc_time:
    mov r1, #1
    ldr r0, =flagisr
    strb r1, [r0]        

    bx lr


//Setzt das RTC_TSR Register 

.thumb_func
tpr_tsr:
    ldr r1, =RTC_SR_TCE                 // Schalte das RTC Modul ab
    mov r2, #0
    str r2, [r1]
    
    ldr r3, =RTC_TPR
    str r2, [r3]
    
    ldr r3, =RTC_TSR                    // Setze RTC Register auf übergebenen Wert
    str r0, [r3]
    
    mov r2, #1                          // Schalte Modul ein
    str r2, [r1]
    
    bx lr
 
//Ausgabe dezimal rechts ausgerichtet mit 2 Stellen

.thumb_func
output_dec:
    push {r4, lr}
    
    mov r4, r0                	
    
    cmp r4, #ZEHN               // Falls Zahl kleiner 10 ist ...
    bge no_zero      	       // Überspringe die Ausgabe der führenden 0
    
    mov r0, #'0'
    bl uart_putChar           
    
no_zero:
    mov r0, r4
    bl uart_putByteBase10      
    
    pop {r4, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data

//ISR flag
flagisr: .byte 0x0

preset_byte: .byte 0

//Flag für Uhren-Modus: 1:24h	 0:1h
clock_mode: .byte 1


start_init: .asciz "Programm gestartet... \nEs sind bereits 6 Sekunden vergangen. \n\n" 
day_mode: .asciz "24-Stunden-Modus\n"
hour_mode: .asciz "1-Stunden-Modus\n"
clock_reset: .asciz "Uhr zurueckgesetzt\n"
end_reached: .asciz "Endzeitpunkt erreicht\n"
preset_config: .asciz "Uhr vorgestellt\n"
output_on: .asciz "Anzeige an\n"
output_off: .asciz "Anzeige aus\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// SIM Clock Gates
.equ SIM_SCGC6_RTC, 0x4004803C
.equ SIM_SCGC6_PIT, 0x4004803C
.equ SIM_SCGC5_PORTA, 0x40048038

__BBREG SCGC6_PIT, SIM_SCGC6_PIT, 23        // PIT Clock Gate
__BBREG SCGC6_RTC, SIM_SCGC6_RTC, 29        // RTC Clock Gate
__BBREG SCGC5_PORTA, SIM_SCGC5_PORTA, 9     // Port A Clock Gate

// PIT Control Register
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL2, 0x40037120
.equ PIT_TCTRL2, 0x40037128
.equ PIT_TFLG2, 0x4003712C
.equ PIT_TCTRL2, 0x40037128

__BBREG PIT_TFLG2_TIF, PIT_TFLG2, 0
__BBREG PIT_TCTRL2_TEN, PIT_TCTRL2 , 0

// PIT2 Konfiguration
.equ PIT_LDVAL2_100, 0x250000    // PIT Clock mit 25 MHz: ((25000000 Takte pro Sekunde)-1/100)
.equ PIT_LDVAL2_200, 0x500000    // PIT Clock mit 25 MHz: ((25000000 Takte pro Sekunde)-1/200)
.equ PIT_TCTRL2_DATA, 2          // PIT2 Kein Chain Mode, Interrupts eingeschaltet, Timer ausgeschaltet.

// Interrupt Vektortabelle
.equ SCR_VTOR, 0xE000ED08      // Anfang der Interruptvektortabelle

// Int. Konstanten
.equ NVIC2_REG, 2
.equ NVIC2_ISER, 0xE000E108		//Interrupt Set Enable
.equ NVIC2_ICPR, 0xE000E288		//Clear Pending Interrupt Requests

.equ RTC_SEC_NVIC_REG_BIT, 0x3	// Bitposition für die NVIC Konfiguratiosregister, IRQNR: 67
.equ RTC_SEC_NVIC_BIT_MSK,  1 << RTC_SEC_NVIC_REG_BIT   // Bitmaske fuer NVIC Konfigreg.
.equ RTC_SEC_NVIC_REG_NR,   2  // Nr. des Konfigurationsregister
.equ RTC_SEC_IRQ_OFFSET,    0x0000014C   // Interrupt Request Offset 


.equ PIT2_NVIC_REG_BITPOS, 0x6			                  // Bitposition für die NVIC Konfiguratiosregister , 70 modulo 32 -> 6
.equ PIT2_NVIC_BIT_MSK, 1 << PIT2_NVIC_REG_BITPOS           // Bitmaske zur Manipulation der NVIC Konfigurationsregister
.equ PIT2_NVIC_REG_NR, 2                                   // Nummer des Konfigurationsregister
.equ PIT2_IRQ_OFFSET, 0x00000158                          // Interrupt Request Offset für PIT2

.equ NVIC_MSK, RTC_SEC_NVIC_BIT_MSK | PIT2_NVIC_BIT_MSK // Bit Maske zur Manipulation der NVIC Register

//PORT A
.equ PORTA_PCR10, 0x40049028                    // PCR 10 fuer LED E4
.equ PORTA_PCR6, 0x40049018                     // PCR 6

.equ PORTA_PCR_MUX, 1 << 8                      // Konfiguration für LED MUX auf GPIO

.equ PORTA_MSK, 0x440	//E1: 1 an 9 und PTA6: 1 an Stelle in Register -> 0x220

// Port A Manipulation
.equ GPIOA_PSOR, 0x400FF004 	// Port A Set Output Register
.equ GPIOA_PCOR, 0x400FF008 	// Port A Clear Output Register
.equ GPIOA_PDDR, 0x400FF014     // Port A Data Direction Register
__BBREG GPIOA_PSOR_6, GPIOA_PSOR, 6
__BBREG GPIOA_PCOR_6, GPIOA_PCOR, 6
__BBREG GPIOA_PSOR_10, GPIOA_PSOR, 10
__BBREG GPIOA_PCOR_10, GPIOA_PCOR, 10

// RTC
.equ RTC_TSR, 0x4003D000		//RTC Time Seconds Register
.equ RTC_TPR, 0x4003D004		//RTC Time Prescaler Register (RTC_TPR)
.equ RTC_TAR, 0x4003D008		//RTC Time Alarm Register (RTC_TAR)
.equ RTC_CR,  0x4003D010		//RTC Control Register (RTC_CR)
.equ RTC_SR,  0x4003D014		//RTC Status Register (RTC_SR)
.equ RTC_IER, 0x4003D01C		//RTC Interrupt Enable Register (RTC_IER)

__BBREG RTC_CR_SWR, RTC_CR, 0 
__BBREG RTC_SR_TCE, RTC_SR, 4

.equ RTC_CR_INIT, 0x104 // Supervisor Access, Software Reset beschreiben 
.equ RTC_IER_INIT, 0x17	//TIIE, TOIE, TAIE, TSIE beschreiben 				
.equ RTC_CRYSTAL_OSC, 62500000 // ca. 10 Sekunden -> Wartezeit/Einschwingen
.equ ONE_HOUR, 3600
.equ ONE_MINUTE, 60

// Buchstaben für die Eingabe
.equ INPUT_TIME, 't'                  
.equ INPUT_DATE, 'd'      
.equ MAX_SEC, 60            
.equ MAX_MIN, 60   	
.equ MAX_HOUR, 24  	
.equ MAX_DAY, 31  	
.equ MAX_MON, 13  	
.equ MAX_YEAR, 99   
.equ ZEHN, 0xA                  
.equ ZEILE, 0x0a                 
.equ PUNKT, '.' 	 
.equ DPUNKT, ':'     

.equ DCF77_START, 0x120000

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:
	bl uart_init
	
	mov r10, #0
	mov r11, #1	
	
	// Clock Gates
    ldr r0, =SCGC6_PIT
    str r11, [r0]
    ldr r0, =SCGC6_RTC
    str r11, [r0]
    ldr r0, =SCGC5_PORTA
    str r11, [r0]
    
    // Port A konfigurieren
    // LED Pin und PTA6  GPIO -> MUX 
    ldr r1, =PORTA_PCR_MUX
    
    ldr r0, =PORTA_PCR10
    str r1, [r0]
    ldr r0, =PORTA_PCR6
    str r1, [r0]
    
    //Datenrichtung
    ldr r0, =GPIOA_PDDR
    ldr r1, [r0]
    mov r2, #PORTA_MSK
    orr r1, r1, r2
    str r1, [r0]
    
    //Output für LED: 0 -> LED an
    ldr r0, =GPIOA_PCOR_10
    str r11, [r0]
    
    // Setze PTA6 auf HIGH
    ldr r0, =GPIOA_PSOR_6
    str r11, [r0]
    
    // Schreibe die ISR (RTC, PIT2) in die Vektortabelle
    ldr r0, =SCR_VTOR               // Lade das SCR_VTOR Register
    ldr r1, [r0]

    ldr r0, =rtc_sec_isr            // Lade die Anfangsadresse der PIT1 ISR
    str r0, [r1, #RTC_SEC_IRQ_OFFSET] // Schreiben die ISR in die Vektortabelle
    ldr r0, =pit2_isr               // Lade die Anfangsadresse der PIT2 ISR
    str r0, [r1, #PIT2_IRQ_OFFSET]  // Schreiben die ISR in die Vektortabelle

    // NVIC
    ldr r1, =NVIC_MSK               // Bitmaske 
    
    // Setze wartende Interruptanforderungen des PIT2 und RTC im NVIC zurück
    ldr r0, =NVIC2_ICPR
    str r1, [r0]
    
    // Schalte Interrupts für PIT2 und RTC im NVIC ein
    ldr r0, =NVIC2_ISER
    str r1, [r0]

    // Initialisiere das PIT Modul
    ldr r0, =PIT_MCR
    str r11, [r0]            // MDIS=0, FRZ=1

    // Initialisiere PIT2
    ldr r0, =PIT_TCTRL2         // Konfiguriere PIT2
    mov r1, #PIT_TCTRL2_DATA
    str r1, [r0]
    
    // Initialisiere RTC
    ldr r0, =RTC_CR_SWR         // RTC zurücksetzen
    str r11, [r0]
    str r10, [r0]

    ldr r0, =RTC_CR             // RTC Control Register schreiben
    mov r1, #RTC_CR_INIT
    str r1, [r0]

    //Einschwingen des Quartz : ca. 10 Sekunden
    ldr r5, =RTC_CRYSTAL_OSC

osc_loop:   
    subs r5, r5, #1
    bne osc_loop
    
    // Schalte den Sekunden Interrupt ein
    ldr r0, =RTC_IER
    mov r1, #RTC_IER_INIT
    str r1, [r0]
    
    // Zeit Register zurücksetzen
    ldr r0, =RTC_TPR
    str r10, [r0]
    ldr r0, =RTC_TSR
    str r10, [r0]

    bl input_t  // Datum/Uhrzeit abfragen : "Fragen Sie hierzu zunächst ein Datum und eine Uhrzeit ab."
    bl input_d
    
    //Timer ein 
    ldr r0, =RTC_SR_TCE
    str r11, [r0]     
    
    
    ldr r10, =flagisr               // isr FLAG 
    mov r6, #1                  
    ldr r7, =DCF77_START
    mov r8, #0
    mov r9, #0
    mov r11, #0     
     
main_loop:
    bl uart_charPresent    			// Wenn kein Zeichen vorhanden ist, dann mache weiter
    cmp r0, #0
    beq next_dcf77_bit
    
    bl uart_getChar   
time_check:
    cmp r0, #INPUT_TIME             // Zeichen:'t'?
    bne day_check                 
    
    bl input_t
    b next_dcf77_bit             
    
day_check:
    cmp r0, #INPUT_DATE            //Zeichen: 'd'
    bne next_dcf77_bit            

    bl input_d  
        
next_dcf77_bit:
    ldr r4, =dcf77_bit            // Auswerten, ob eine neue Bit-Ausgabe notwendig
    ldrb r1, [r4]
    cmp r1, #59
    bge end_bits
    
    cmp r1, #0
    bne output_next_bit  
    
    // Inkrementiert die Uhrzeit 
        
    ldr r0, =timestamp            // Lade das Register 
    
    mov r1, #MAX_SEC
    mov r2, #0
    bl add_datime   
    teq r1, #1
    bne print_time
    
    mov r1, #MAX_MIN                 // Lade Grenzwert der Minuten
    mov r2, #0                      // Setze r2 auf den Startwert für Minuten
    bl add_datime                  // Inkrementiere die Minuten
    teq r1, #1                    // Teste auf Überlauf
    bne print_time                // Kein Überlauf, fahre mit der Ausgabe fort
    
    mov r1, #MAX_HOUR             // Lade den Grenzwert der Stunden
    mov r2, #0                    
    bl add_datime          
    teq r1, #1                    
    bne print_time               
    
    mov r1, #MAX_DAY              // Lade den Grenzwert der Tage
    mov r2, #1                    
    bl add_datime             
    teq r1, #1                    
    bne print_time                
    
    mov r1, #MAX_MON              // Lade den Grenzwert der Monate
    mov r2, #1                    
    bl add_datime          
    teq r1, #1                    
    bne print_time
    
    mov r1, #MAX_YEAR             // Lade den Grenzwert für das Jahr
    mov r2, #0                    // Setze r2 auf den Startwert der Jahre
    bl add_datime         
    
print_time:
    mov r0, #ZEILE
    bl uart_putChar
    
    //Ausgabe der Uhrzeit 
    ldr r5, =timestamp+1
    ldrb r0, [r5], #-1           // Lade die Stunden/ dekrementiere zur Adresse der Minuten
                     	  
    bl output_dec 
        
    mov r0, #DPUNKT                 
    bl uart_putChar
    
    //ldrb r0, [r5]               // Lade Wert der Sekunden
   // ldrb r0, [r5], #-1
    //bl output_dec               
    
    //mov r0, #DPUNKT                
    //bl uart_putChar
    
    ldrb r0, [r5]
    bl output_dec 
    
    ldr r0, =time                 
    bl uart_putString

    // Berrechne DCF77 Frame
    ldr r5, =timestamp       // Lade Minuten
    
    ldrb r0, [r5], #1
    bl conv_bin_bcd         // Minuten nach BCD konvertieren
    and r0, r0, #0x7F
    mov r12, r0             
    bl parity                
    lsl r0, r0, #7           // Paritätsbit um 7 Stellen nach rechts verschieben
    orr r8, r0, r12          
    
    ldrb r0, [r5], #1        // Stunden laden
    bl conv_bin_bcd         
    and r0, r0, #0x3F        // Übrige Bits abschneiden
    mov r12, r0             
    bl parity                // Paritätsbit für Stunden ausrechnen
    lsl r0, r0, #6
    orr r12, r12, r0         // Paritätsbit den Stunden anhängen
    lsl r12, r12, #8
    orr r8, r8, r12          // Stunden zu den Minuten hinzufügen
    
    // Zeit einmal nach rechts und LSB setzen
    lsl r8, r8, #1
    orr r8, r8, #1
    
    ldrb r0, [r5], #1        // Tag laden
    bl conv_bin_bcd       
    and r0, r0, #0x3F        // Übrige Bits abschneiden
    mov r9, r0               // Ergebnis abspeichern
    
    mov r0, #0xC0            // Wochentag ausdenken
    orr r9, r9, r0
    
    ldrb r0, [r5], #1        // Monat laden
    bl conv_bin_bcd         
    and r0, r0, #0x1F        // Übrige Bits abschneiden
    lsl r0, r0, #9
    orr r9, r9, r0           // Ergebnis abspeichern
    
    ldrb r0, [r5], #1        // Jahr laden
    bl conv_bin_bcd          
    and r0, r0, #0xFF        // Übrige Bits abschneiden
    lsl r0, r0, #14
    orr r9, r9, r0           // Ergebnis abspeichern
    
    mov r0, r9               // Paritätsbit des Datums berechnen und anfügen
    bl parity
    lsl r0, r0, #22
    orr r9, r9, r0

output_next_bit:
    ldrb r0, [r4]            // Lade die Position des aktuellen Bits
    
    mov r1, r7               // Entscheide, aus welchem Register das nächste Bit geholt wird
    cmp r0, #20
    itt ge
    movge r1, r8
    subge r5, r0, #20
    
    cmp r0, #36
    itt ge
    movge r1, r9
    subge r5, r0, #36

    lsr r1, r1, r5          // Verschiebe das nächste Bit an die LSB Position
    and r11, r1, #1         // Und wirf den Rest weg
    mov r0, r11
    
    bl uart_putByteBase10   // Bit auf dem Terminal ausgeben

    ldr r0, =GPIOA_PCOR_6   // GPIO Pins setzen
    mov r1, #1
    str r1, [r0]
    ldr r0, =GPIOA_PSOR_10
    str r1, [r0]
    
    tst r11, #1             // Den PIT2 starten
    ite eq
    ldreq r0, =PIT_LDVAL2_100
    ldrne r0, =PIT_LDVAL2_200
    
    bl start_pit2

end_bits:
    ldrb r0, [r4]           // Speichere die Position des nächsten Bit
    adds r0, r0, #1
    cmp r0, #MAX_MIN        // Wenn Bitposition über 60 -> setze auf 0 zurück 
    it gt
    movgt r0, #0
    strb r0, [r4]
    
wait:
    // Warte auf den Interrupt von RTC
    ldrb r0, [r10]
    cmp r0, #0
    beq wait

    mov r0, #0
    strb r0, [r10]
    b main_loop 

// Hier wird der Nutzer aufgefordert das Datum einzugeben 
.thumb_func    
input_d:

    push {r4, r5, lr}
    
    ldr r4, =timestamp+2
    ldr r0, =day_inp            
    bl uart_putString
    
    bl uart_getByteBase10        
    mov r5, r0
    
    bl output_dec 
      
    strb r5, [r4], #1
    
    ldr r0, =month_inp         
    bl uart_putString
    
    bl uart_getByteBase10         
    mov r5, r0
    
    bl output_dec 
      
    strb r5, [r4], #1
    
    ldr r0, =year_inp          
    bl uart_putString
    
    bl uart_getByteBase10       
    mov r5, r0
    
    bl output_dec                 
    
    mov r0, #ZEILE                 
    bl uart_putChar
    
    pop {r4, r5, pc}

// Hier wird der Nutzer aufgefordert eine Zeit einzugeben 
.thumb_func
input_t:

	push {r4, r5, lr}
	
    ldr r4, =timestamp+1
    ldr r0, =hour_inp          // Gib die Aufforderungen für die Stunden aus
    bl uart_putString
    
    bl uart_getByteBase10         // Lese die Stunden ein, gebe sie auf dem Terminal aus und speicher sie ab
    mov r5, r0
    
    bl output_dec 
    
    strb r5, [r4]     
    strb r5, [r4], #-1
    
    ldr r0, =min_inp           // Gib die Aufforderungen für die Minuten aus
    bl uart_putString
    
    bl uart_getByteBase10         // Lese die Minuten ein, gebe sie auf dem Terminal aus und speicher sie ab
    mov r5, r0
    
    bl output_dec 
    
    strb r5, [r4]     
   // strb r5, [r4], #-1
    
    //ldr r0, =sec_inp
    //bl uart_putString
    
    //bl uart_getByteBase10
    //mov r5, r0
   // bl output_dec   
    strb r5, [r4]

    mov r0, #ZEILE              
    bl uart_putChar
    
    pop {r4, r5, pc}

 //Hier wird die BCD Kodierung einer Zahl vorgenommen

.thumb_func
conv_bin_bcd:
	mov r2, #8         

alg_loop:
    lsl r0, r0, #1      // Schiebe um eine Stelle nach Links
	subs r2, r2, #1     // Wenn das letzte mal verschoben wurde -> abbrechen.
    beq stop_1

	mov r3, 0xF00       // Wenn die Einer > 4 sind, addiere 3
	and r3, r0, r3
	lsr r3, r3, #8
	cmp r3, #4
	itt gt
	movgt r1, #0x300
	addgt r0, r0, r1

	mov r3, 0xF000      // Wenn die Zehner > 4 -> addiere 3
    and r3, r0, r3
    lsr r3, r3, #12
    cmp r3, #4
    itt gt
    movgt r1, #0x3000
    addgt r0, r0, r1
    b alg_loop   
stop_1:
	lsr r0, r0, #8     // Das Ergebnis in das erste Byte schieben	
	bx lr
//Berechnet positive Parität des Werts 
.thumb_func
parity:
	mov r1, r0             // Initialiseren
	mov r0, #0

parity_loop:
	tst r1, #1             // Überprüfe, ob das Bit gesetzt ist 
	it ne
	eorne r0, r0, #1       // Dann invertiere das Paritätsbit
	lsr r1, r1, #1         // Rechtsschub 
	cmp r1, #0             // Wenn fertig -> Abbruch 
	bne parity_loop	
	bx lr

//Erhoehen ein Minute, Stunde, Tag, Monat
.thumb_func
add_datime:
    ldrb r3, [r0]              // Lade Wert  
    add r3, r3, #1             // Erhoehe das Wert
    cmp r3, r1                 //	Check Ueberlauf
    itte eq
    moveq r3, r2               // Bei Ueberlauf-> "Reset"
    moveq r1, #1
    movne r1, #0
    strb r3, [r0], #1          // Speichern
    
    bx lr

//RTC ISR
.thumb_func
rtc_sec_isr:

    ldr r0, =flagisr
    mov r1, #1
    strb r1, [r0]                       

    bx lr   

//PIT2 ISR zum ausschalten der GPIO Outputs
.thumb_func
pit2_isr:
    mov r1, #1
    ldr r0, =GPIOA_PCOR_10      // Schalte die LED wieder ein
    
    str r1, [r0]
    
    ldr r0, =GPIOA_PSOR_6       // Setze PTA6 HIGH
    str r1, [r0]
    
    ldr r0, =PIT_TCTRL2_TEN     // Schalte den PIT2 aus.
    mov r1, #0
    str r1, [r0]

    ldr r0, =PIT_TFLG2_TIF      // Interrupt Anfrage zurücksetzen
    mov r1, #1
    str r1, [r0]

    bx lr

// Starte PIT2 mit Takt
 .thumb_func
start_pit2:
    ldr r1, =PIT_LDVAL2         // Setze den Counter von PIT2
    str r0, [r1]
    
    mov r0, #1                  // Schalte ihn ein und setze wartende Interrupts zurück
    ldr r1, =PIT_TCTRL2_TEN
    str r0, [r1]
    
    ldr r1, =PIT_TFLG2_TIF
    str r0, [r1]
    
    bx lr
    
//Ausgabe dezimal rechts ausgerichtet mit 2 Stellen

.thumb_func
output_dec:
    push {r4, lr}
    
    mov r4, r0                	//Parameter zwischenspeichern 
    
    cmp r4, #ZEHN               // Falls Zahl kleiner 10 ist ...
    bge no_zero      	       // Überspringe die Ausgabe der führenden 0
    
    mov r0, #'0'
    bl uart_putChar           
    
no_zero:
    mov r0, r4
    bl uart_putByteBase10      
    
    pop {r4, pc}    
    

/*** Datenbereich (ab 0x20000000) ***/
.data
//Pit1_flag
flagisr: .byte 0

dcf77_bit: .byte 0
timestamp:
//.byte 0    //Sekunden
.byte 0    // Minuten
.byte 0    // Stunde
.byte 01    // Tag
.byte 02    // Monat
.byte 03    // Jahr
time: .asciz ":00 Uhr\n"
hour_inp: .asciz "\nStunde eingeben ( hh ): "
min_inp: .asciz "\nMinuten eingeben ( mm ): "
//sec_inp: .asciz "\nSekunden eingeben ( ss ): "
day_inp: .asciz "\nTag eingeben ( dd ): "
month_inp: .asciz "\nMonat eingeben ( mm ): "
year_inp: .asciz "\nJahr eingeben ( jj ): " 
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

//SIM

.equ SIM_SCGC6_FTM0, 0x4004803C
.equ SIM_SCGC5_PORTA, 0x40048038

__BBREG SCGC6_FTM0, SIM_SCGC6_FTM0, 24       // FTM0 Clock Gate
__BBREG SCGC5_PORTA, SIM_SCGC5_PORTA, 9      // Port A Clock Gate

//Interrupt Vektortabelle
.equ SCR_VTOR, 0xE000ED08  //Anfang der Interruptvektortabelle


// Interrupt Konstanten
.equ NVIC1_ISER, 0xE000E104   // Basisadresse des NVIC1_ISER 4*1
.equ NVIC1_ICPR, 0xE000E284

.equ FTM0_IRQNR, 62            // Interrupt Nummer :FTM0 
.equ FTM0_NVIC_REG_BITPOS, 30  //Bitpos NVIC Konfireg
.equ NVIC1_MSK, 0x40000000		//KonfNr.:1 , 30 Stellen Schieben -> 40000000
.equ FTM0_IRQ_OFFSET, 0x00000138	//IRQ Offset FTM0

// PORT A
.equ PORTA_PCR10, 0x40049028    // Port A PCR 10 -> E4
.equ PORTA_PCR6,  0x40049018    // Port A PCR 6
.equ PORTA_PCR6_MUX_DATA, 0x300   // Konfiguration für MUX -> ALT3 FTM0_CH3
.equ PORTA_PCR10_MUX, 0x100
.equ E4_MSK,  1 << 10   // Bit Maske zur Manipulation von E1

// Port A : 10. Bit
.equ GPIOA_PSOR, 0x400FF004  // Port A Set Output Register
.equ GPIOA_PCOR, 0x400FF008  // Port A Clear Output Register
.equ GPIOA_PDDR, 0x400FF014  // Port A Data Direction Register

__BBREG GPIOA_PDDR_10, GPIOA_PDDR ,10      
__BBREG GPIOA_PSOR_10, GPIOA_PSOR, 10
__BBREG GPIOA_PCOR_10, GPIOA_PCOR, 10

// FTM
.equ FTM0_SC, 0x40038000    // FTM0 status and control
.equ FTM0_CNT, 0x40038004    // FTM0 Counter
.equ FTM0_MOD, 0x40038008    // FTM0 Modulo
.equ FTM0_CNTIN, 0x4003804C     // FTM0 Counter initial Value
.equ FTM0_STATUS, 0x40038050    // FTM0 Capture and Compare status
.equ FTM0_MODE, 0x40038054      // FTM0 Features Mode Selection
.equ FTM0_SYNC, 0x40038058      // FTM0 Synchronization
.equ FTM0_OUTINIT, 0x4003805C   // FTM0 Initial State for Channels Output
.equ FTM0_OUTMASK, 0x40038060   // FTM0 Output Mask
.equ FTM0_COMBINE, 0x40038064   // FTM0 Function For Linked Channels
.equ FTM0_DEADTIME, 0x40038068  // FTM0 Deadtime Insertion Control
.equ FTM0_EXTTRIG, 0x4003806C   // FTM0 External Trigger
.equ FTM0_POL, 0x40038070    	// FTM0 Channels Polarity
.equ FTM0_FMS, 0x40038074   	// FTM0 Fault Mode Status
.equ FTM0_FILTER, 0x40038078    // FTM0 Input Capture Filter Control
.equ FTM0_FLTCTRL, 0x4003807C   // FTM0 Fault Control
.equ FTM0_QDCTRL, 0x40038080    // FTM0 Quadrature Decoder Control And Status
.equ FTM0_CONF, 0x40038084      // FTM0 Configuration
.equ FTM0_FLTPOL, 0x40038088    // FTM0 Fault Input Polarity
.equ FTM0_SYNCONF, 0x4003808C   // FTM0 Synchronization Configuration
.equ FTM0_INVCTRL, 0x40038090  // FTM0 Inverting Control
.equ FTM0_SWOCTRL, 0x40038094  // FTM0 Software Output Control
.equ FTM0_PWMLOAD, 0x40038098  // FTM0 PWM Load
.equ FTM0_C3SC, 0x40038024     // Channel 3 Status and Control
.equ FTM0_C3V, 0x40038028      // Channel 3 Value


__BBREG FTM0_OUTINIT_CH3OI, FTM0_OUTINIT, 3  // FTM0 Initial State for Channels Output
__BBREG FTM0_SC_TOF, FTM0_SC, 7  // FTM0 Timer Overflow Flag

__BBREG FTM0_C3SC_ELSA, FTM0_C3SC, 2  // Channel 3 Status and Control ELSA Bit
__BBREG FTM0_C3SC_CHF,FTM0_C3SC, 7  // Channel 3 Status and Control Channel Interrupt Flag

.equ FTM0_SC_DATA, 0x48     // TOF=1, System Clock, Prescale divide by 1
.equ FTM0_MODE_DATA, 0x6    // FTMEN=0, INIT=1, WPDIS=1
.equ FTM0_MOD_DATA, 24999   // 1kHz Grundschwingung
.equ FTM0_C3SC_DATA, 0x68   // MSB=1,MSA=X,ELSB=1,ELSA=0; Channel Interrupts enabled

.equ PLUS_SIGN, '+'
.equ MINUS_SIGN, '-'

//FTM0_MOD_DATA * (%/100)
.equ PWM_05, 1250
.equ PWM_15, 3750
.equ PWM_25, 6250
.equ PWM_35, 8750
.equ PWM_45, 11250
.equ PWM_55, 13750
.equ PWM_65, 16250
.equ PWM_75, 18750
.equ PWM_85, 21250
.equ PWM_95, 23750  

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:   
    bl uart_init
    
	
	mov r10, #0
    mov r11, #1
    
    // Clock Gates einschalten
    ldr r0, =SCGC6_FTM0
    str r11, [r0]
    ldr r0, =SCGC5_PORTA
    str r11, [r0]
    
    // Port A konfigurieren    
    ldr r1, =PORTA_PCR6_MUX_DATA
    
    ldr r0, =PORTA_PCR6
    str r1, [r0]
    
    ldr r1, =PORTA_PCR10_MUX
    ldr r0, =PORTA_PCR10
    str r1, [r0]
        
    ldr r0, =GPIOA_PDDR_10
    str r11, [r0]
    
    //Output LEDs  
    ldr r0, =GPIOA_PSOR_10
    str r11, [r0]
    
    // Schreibe die ISR in die Vektortabelle
    ldr r0, =SCR_VTOR               
    ldr r1, [r0]
    
    ldr r0, =ftm_isr               // Lade die Anfangsadresse der FTM0 ISR
    str r0, [r1, #FTM0_IRQ_OFFSET]  // Schreiben die ISR in die Vektortabelle
    
    // NVIC1
    ldr r1, =NVIC1_MSK     // Bitmaske :NVIC2 Register /PIT1/ Port E
    
    // Reset IRQ
    ldr r0, =NVIC1_ICPR
    str r1, [r0]
    
    //Interrupts  FTM0 im NVIC:on
    ldr r0, =NVIC1_ISER
    str r1, [r0]

    ldr r0, =FTM0_MODE          // FTM Mode Register
    mov r1, #FTM0_MODE_DATA		//INIT, WPDIS
    str r1, [r0]
    ldr r0, =FTM0_MOD           // 1kHz 
    ldr r1, =FTM0_MOD_DATA
    strh r1, [r0]

    ldr r0, =FTM0_C3SC          // Schreibe Channel 3 Control register
    mov r1, #FTM0_C3SC_DATA		//ELSnB:1 ELSnB:0 : Enabled/FallingEdge, MSB:1 only if (MODE[WPDIS] = 1), CHIE:1 Channel Int
    str r1, [r0]
    ldr r0, =FTM0_C3V           // Starte: 55% Duty Cycle
    ldr r1, =PWM_55
    strh r1, [r0]
    
    ldr r0, =FTM0_SC            // Status und Control vom FTM0 : 01 System clock, Timer Overflow Interrupt Enable
    mov r1, #FTM0_SC_DATA
    str r1, [r0]
 
    ldr r0, =prompt            // Prompt output
    bl uart_putString
    
    ldr r12, =flagisr         // ISR flag
    
main_loop:
	bl uart_charPresent        
	cmp r0, #0
	beq wait
	
	bl uart_getChar
	
	cmp r0, #PLUS_SIGN         // Check "+"
	it eq
	moveq r2, #2
	beq set_pol
	
	cmp r0, #MINUS_SIGN        // Check "-"
	it eq
	moveq r2, #1
	beq set_pol
	
	b check_num    

set_pol:
	ldr r1, =polarity
	strb r2, [r1]
	b print_prompt
	
	
.thumb_func	
check_num:
	ands r3, r0, #0xF          // Check auf Input
	it lt
	blt wait
	
    cmp r3, #9
    it gt
    bgt wait
    
    mov r1, #0x2               // Berechne Adresse mit naechsten PWM Duty cycle 
    ldr r2, =pulse_width
    smlabb r3, r3, r1, r2      // Variablen Adresse + n * 2
    ldrh r1, [r3]
    ldr r3, =duty_cycle       // Speicher den duty cycle für die FTM ISR ab
    strh r1, [r3]
    BX LR 
    
print_prompt:
	bl uart_putChar
	ldr r0, =prompt
	bl uart_putString    
	
// Warte auf Int
wait:
    ldrb r0, [r12]
    cmp r0, #0
    beq wait

    mov r0, #0
    strb r0, [r12]
    b main_loop
 
//FTM0 Interrupt Service Routine
.thumb_func
ftm_isr:

    ldr r0, =FTM0_SC_TOF        // Lade Overflow Interrupt Flag
    ldr r1, [r0]
    cmp r1, #0
    beq check_channel           
//Neustart Grundschwingung (FTM0_MOD)  
    mov r1, #0
    str r1, [r0]                // Flag zurücksetzen
    
//    ldr r0, =FTM0_C3SC_ELSA     // Überprüfe, ob eine positive oder negative Flanke vorliegt
//    ldr r3, [r0]
//    cmp r3, #0
//    ite eq
//    ldreq r0, =GPIOA_PSOR_10    // Schalte die LED bei negativer Flanke aus
//    ldrne r0, =GPIOA_PCOR_10    // Schalte die LED bei positiver Flanke an
//    mov r3, #1
//    str r3, [r0]

    ldr r0, =polarity      			// Nächste Polarität laden
    ldrb r3, [r0]
    subs r3, r3, #1             // Wenn die Polarität geändert werden soll ist der Wert > 0
    bmi check_channel          
    ldr r2, =FTM0_C3SC_ELSA     // Schreibe das Bit in das ELSA Flag
    str r3, [r2]   
    strb r1, [r0]               // Setze next_polarity zuruck auf 0

check_channel:
    ldr r0, =FTM0_C3SC_CHF      // Lade das Channel Interrupt Flag
    ldr r1, [r0]
    cmp r1, #0
    beq end_isr                	
    
   
    mov r1, #0                  // Setze das Flag zurück
    str r1, [r0]
    
//    ldr r0, =FTM0_C3SC_ELSA
//    ldr r3, [r0]
//    cmp r3, #0
//    ite eq
//    ldreq r0, =GPIOA_PCOR_10    // Schalte die LED bei positiver Flanke an
//    ldrne r0, =GPIOA_PSOR_10    // Schalte die LED bei negativer Flanke aus
//    mov r3, #1
//    str r3, [r0]

    ldr r0, =duty_cycle    		// Check ob neuer Duty Cycle gesetzt werden soll
    ldrh r3, [r0]
    cmp r3, #0
    beq end_isr                 // duty_cycle ist 0 -> beende
    ldr r2, =FTM0_C3V           // Setze neuen duty cycle/ setze duty_cycle zurück
    str r3, [r2]
    strh r1, [r0]
    
end_isr:
    ldr r0, =flagisr
    mov r1, #1
    strb r1, [r0]
    
    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
// Run Flag, um auf den PIT1 zu warten

flagisr: .byte 0

duty_cycle: .hword 0

polarity: .byte 0
prompt: .asciz "\n> "
pulse_width:
.hword PWM_05
.hword PWM_15
.hword PWM_25
.hword PWM_35
.hword PWM_45
.hword PWM_55
.hword PWM_65
.hword PWM_75
.hword PWM_85
.hword PWM_95
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantentdeklarationen
.equ COUNTER, 0x10
.equ NEWLINE, '\n'

.equ START_TIME, 0xFFFFFFFF
.equ CLEAR_BIT, 0x0000

// Registeradressen
.equ PIT_TCTRL3, 0x40037000 + 0x108 + (16 * 3)

// Bit-Band-Adressen
.equ PERIPHERAL_BIT_BAND_REGION_BASE, 0x40000000
.equ PERIPHERAL_BIT_BAND_ALIAS_BASE, 0x42000000

.equ PIT_TCTRL3_TEN, PERIPHERAL_BIT_BAND_ALIAS_BASE + (PIT_TCTRL3 - PERIPHERAL_BIT_BAND_REGION_BASE) * 32 + 0 * 4

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl		uart_init
	bl		pit3_init
	
loop_main:
	// Zeige Eingabeaufforderung
	ldr		r0, =string_command
	bl		uart_putString
	
	// a) Lies 16 Byte von der Benutzereingabe
	mov		r4, #COUNTER
	ldr		r5, =array_bytes
	
loop_input:
	mov		r0, #NEWLINE
	bl		uart_putChar
	ldr		r0, =string_prompt
	bl		uart_putString
	bl		uart_getByte
	strb	r0, [r5], #1		// Lege einzelnes Byte im Array ab und erhöhe Adresse
	bl		uart_putByte
	subs	r4, r4, #1			// Verringere Schleifenvariable
	bne		loop_input
	
	// b) Bestimme Maximum
	mov		r0, #NEWLINE
	bl		uart_putChar
	ldr		r0, =string_start_search
	bl		uart_putString
	
	// Setze Timer zurück
	//
	// `PIT_LDVAL3` beinhält den Startwert des Timers, der von `pit3_init` auf 0xFFFFFFFF
	// initialisiert wird. Um den laufenden Timerzyklus abzubrechen und neu zu starten,
	// muss der Timer über das `TEN`-Bit von `PIT_TCTRL3` ab- und wieder angeschaltet werden.
	ldr		r6, =#PIT_TCTRL3_TEN
	mov		r7, #CLEAR_BIT
	str		r7, [r6, #0]
	add		r7, r7, #1
	str		r7, [r6, #0]
		
	// Suche nach Maximum beginnend beim letzten Element
	ldrb	r9, [r5, #-1]!		// Initialisiere Maximum mit letztem Array-Element
	mov		r4, #COUNTER - 1	// Initialisiere Zähler

loop_search:
	ldrb	r0, [r5, #-1]!
	cmp		r0, r9				// Vergleiche mit bisherigem Maximum
	it		hi					// Wenn neues Element größer ist...
	movhi	r9, r0				// ... dann ersetze bisheriges Maximum
	subs	r4, r4, #1
	bne		loop_search			// Wenn Zähler noch nicht null, dann suche weiter
	
	// Speichere Maximum
	ldr		r0, =maximum
	strb	r9, [r0, #0]		// Maximum speichern
	
	// d) Messe die Suchzeit
	bl		pit3_getval
	mov		r8, #START_TIME
	sub		r8, r8, r0
	
	// Gib Ergebnisse aus
	mov		r0, #NEWLINE
	bl		uart_putChar
	ldr		r0, =string_end_search
	bl		uart_putString
	mov		r0, r9
	bl		uart_putByte		// Gib Maximum im Byteformat aus
	mov		r0, #NEWLINE
	bl		uart_putChar
	ldr		r0, =string_end_timer
	bl		uart_putString
	mov		r0, r8
	bl		uart_putInt16		// Gib gemessene Laufzeit als vierstellige Hexadezimalzahl aus
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// c) Starte mit einer neuen Eingabeaufforderung
	b		loop_main
	
	// e) Ändert sich die Suchzeit mit der Lage des Maximums? Wenn ja, warum?
	//
	// Die Messungen ergeben tatsälich eine konstante Suchzeit von 0x0083 PIT-Ticks.
	// Der Zeitbedarf für die Ausführung des Suchalgorithmus ist damit konstant. Eine
	// variable Suchzeit wäre nur dann, wenn bei jeder Iteration fallbedingt eine
	// unterschiedliche Anzahl von Befehlen ausgeführt würde.
	//
	// Die einzige variable Kontrollflussabhängigkeit ergibt sich in Zeilen 90 - 91
	// durch den `it`- und den nachfolgenden `movhi`-Befehl. Bei Umsetzung des
	// Algorithmus an dieser Stelle mit einer normalen bedingten Kontrollfluss-
	// verzweigung, wäre der Ausführungspfad genau dann minimal, wenn das Maximum an
	// erster Stelle stünde und alle nachfolgenden Elemente kleiner wären. In diesem
	// Fall würde der Registertransfer in Zeile 91 nur einmal notwendig. Wäre der
	// Array jedoch aufsteigend sortiert, dann würde der Registertransfer in Zeile 91
	// in jeder Iteration ausgeführt werden. Die Ausführungszeit wäre damit maximal.
	//
	// Durch die Umsetzung jedoch mittels der konditionale Befehle `it` und `movhi`
	// ist der Ausführungspfad in allen Fällen gleich lang.

/*** Datenbereich (ab 0x20000000) ***/
.data
array_bytes:
	.rept COUNTER
	.byte 0x00
	.endr

maximum:
	.byte 0x0

// Stringkonstanten
string_command:
	.asciz "Bitte 16 Bytes sukzessiv eingeben!"

string_prompt:
	.asciz ">"
	
string_start_search:
	.asciz "Durchsuchen gestartet"
	
string_end_search:
	.asciz "Durchsuche beendet\nMaximum: 0x"
	
string_end_timer:
	.asciz "Zeitbedarf: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantentdeklarationen
.equ MASK, 0b00011111
.equ NEWLINE, '\n'
.equ SCRATCH_SPACE, 0x20

// Bit-Band-Adressen
.equ SRAM_BIT_BAND_REGION_BASE, 0x20000000
.equ SRAM_BIT_BAND_ALIAS_BASE, 0x22000000

.equ DIRECT_DATA_ADDRESS, 0x20000000
.equ BIT_BAND_DATA_ADDRESS, 0x20000010

.equ BIT_BAND_ALIAS_ADDRESS_BASE, SRAM_BIT_BAND_ALIAS_BASE + (BIT_BAND_DATA_ADDRESS - SRAM_BIT_BAND_REGION_BASE) * 32

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl		uart_init
	
loop_main:
	// a) Lies zwei 5-Bit Nummber von der Benutzereingabe
	ldr		r0, =string_command_zero_bit
	bl		uart_putString
	bl		uart_getByte
	and		r0, r0, #MASK
	mov		r4, r0
	bl		uart_putByte
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Lies die Nummer des zweiten Bits ein
	ldr		r0, =string_command_one_bit
	bl		uart_putString
	bl		uart_getByte
	and		r0, r0, #MASK
	mov		r5, r0
	bl		uart_putByte
	mov 	r0, #NEWLINE
	bl		uart_putChar
	
	// d) Gib initialen Werte aus
	ldr		r0, =string_before_without
	bl		uart_putString
	ldr		r6, =#DIRECT_DATA_ADDRESS	// Streng genommen würde hier auch `mov` gehen
	ldr		r7, [r6, #0]
	mov		r0, r7
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	ldr		r0, =string_before_with
	bl		uart_putString
	ldr		r8, =#BIT_BAND_DATA_ADDRESS
	ldr		r9, [r8, #0]
	mov		r0, r9
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// b) Manipuliere Bits ohne Bit-Banding
	mov		r10, #1
	lsl		r11, r10, r4				// Wähle das vom Nutzer angegebene Bit
	bic		r7, r7, r11					// Setze das gewählte Bit zurück
	lsl		r11, r10, r5				// Wähle das nächste vom Nutzer angegebene Bit
	orr		r7, r7, r11					// Setze das gewählte Bit
	str		r7, [r6, #0]
	
	// c) Manipuliere Bits mit Bit-Banding
	ldr		r11, =#BIT_BAND_ALIAS_ADDRESS_BASE
	mov		r10, #0
	str		r10, [r11, r4, lsl #2]			// Setze das gewählte Bit zurück mittels Offset von der Bit-Band-Basisadresse
	mov		r10, #1
	str		r10, [r11, r5, lsl #2]			// Setze das gewählte Bit mittels Offset von der Bit-Band-Basisadresse
	
	// Gib Ergebniss ohne Einsatz von Bit-Banding aus
	ldr		r0, =string_after_without
	bl		uart_putString
	mov		r0, r7
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Gib Ergebnisse mit Einsatz von Bit-Banding aus
	ldr		r0, =string_after_with
	bl		uart_putString
	ldr		r0, [r8, #0]
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// e) Starte mit einer neuen Eingabeaufforderung
	b 		loop_main

/*** Datenbereich (ab 0x20000000) ***/
.data
	.rept SCRATCH_SPACE
	.byte 0x00
	.endr

// Stringkonstanten
string_command_zero_bit:
	.asciz "Nummer des 0-Bits: 0x"

string_command_one_bit:
	.asciz "Nummer des 1-Bits: 0x"

string_before_without:
	.asciz "Vorher (ohne Bit-Banding): 0x"
	
string_before_with:
	.asciz "Vorher (mit Bit-Banding): 0x"
	
string_after_without:
	.asciz "Nachher (ohne Bit-Banding): 0x"
	
string_after_with:
	.asciz "Nachher (mit Bit-Banding): 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantentdeklarationen
.equ SIZE, 4
.equ NEWLINE, '\n'

.equ START_TIME, 0xFFFFFFFF
.equ CLEAR_BIT, 0x0000

// Registeradressen
.equ PIT_TCTRL3, 0x40037000 + 0x108 + (16 * 3)

// Bit-Band-Adressen
.equ PERIPHERAL_BIT_BAND_REGION_BASE, 0x40000000
.equ PERIPHERAL_BIT_BAND_ALIAS_BASE, 0x42000000

.equ PIT_TCTRL3_TEN, PERIPHERAL_BIT_BAND_ALIAS_BASE + (PIT_TCTRL3 - PERIPHERAL_BIT_BAND_REGION_BASE) * 32 + 0 * 4

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl		uart_init
	bl		pit3_init

loop_main:
	// a) Lies ein paar von Vektoren mit jeweils 4 Byte von der Benutzereingabe 
	ldr		r0, =string_name_v1
	ldr		r1, =array_v1
	bl		read_vector
	mov		r4, r0
	
	ldr		r0, =string_name_v2
	ldr		r1, =array_v2
	bl		read_vector
	mov		r5, r0
	
	// Setze Timer zurück
	ldr		r6, =#PIT_TCTRL3_TEN
	mov		r7, #CLEAR_BIT
	str		r7, [r6, #0]
	add		r7, r7, #1
	str		r7, [r6, #0]
	
	ldr		r6, =array_minimum
	ldr		r7, =array_maximum
	mov		r8, #SIZE

loop_minmax:
	// b) Bestimme Minima und Maxima ohne DSP-Befehle
	sub		r8, r8, #1			// Berücksichtige 0-Indizierung!
	ldrb	r9, [r4, r8]
	ldrb	r10, [r5, r8]
	
	// Swappe Register falls nötig
	cmp		r9, r10
	ittt	hi					// Falls `r9` die größere Zahl enthält..
	movhi	r11, r9				// ... dann vertausche `r9` und `r10`
	movhi	r9, r10
	movhi	r10, r11
	
	// Schreibe geordnete Werte zurück in die Zielarrays
	strb	r9, [r6, r8]
	strb	r10, [r7, r8]	
	cmp		r8, #0
	bne		loop_minmax			// `loop_minmax` liegt außerhalb der `cbnz`-Reichweite
	
	// d) Messe die Suchzeit
	bl		pit3_getval
	mov		r8, #START_TIME
	sub		r8, r8, r0
	
	// Gib Ergebnis aus
	ldr		r0, =string_summary_without_dsp
	bl		uart_putString
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Gib Minima aus
	ldr		r0, =string_minimum
	bl		uart_putString
	ldr		r0, [r6, #0]
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Gib Maxima aus
	ldr		r0, =string_maximum
	bl		uart_putString
	ldr		r0, [r7, #0]
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Gib Zeitbedarf aus
	ldr		r0, =string_end_timer
	bl		uart_putString
	mov		r0, r8
	bl		uart_putInt16
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Setze erneut Timer zurück
	ldr		r8, =#PIT_TCTRL3_TEN
	mov		r9, #CLEAR_BIT
	str		r9, [r8, #0]
	add		r9, r7, #1
	str		r9, [r8, #0]
	
	// c) Bestimme Minima und Maxima mit DSP-Befehlen
	ldr		r8, [r4, #0]
	ldr		r9, [r5, #0]
	
	// Die `GE`-Bits des `APSR`-Registers entsprechen dem Carry-Statusbit normaler
	// arithmetischer Operationen. Bei einer Subtraktion wird das Carry-Bit auf `0`
	// gesetzt, wenn es dabei zu einem vorzeichenlosen ganzzahligen Underflow kam.
	// Das heißt, in der folgenden DSP-Operation entsprechen die `1`-Bits denen
	// Bytes, in denen der Minuend (`r8`) größer war, als der Subtrahend (`r9`).
	usub8	r10, r8, r9			// Setze `APSR.GE`-Bits
	sel		r10, r9, r8			// Wähle die Minima aus beiden Vektoren
	sel		r11, r8, r9			// Wähle die Maxima aus beiden Vektoren
	
	// Schreibe die Ergebnisse wieder zurück
	str		r10, [r6, #0]
	str		r11, [r7, #0]
	
	// Messe erneut die Suchzeit
	bl		pit3_getval
	mov		r8, #START_TIME
	sub		r8, r8, r0
	
	// Gib Ergebnis aus
	ldr		r0, =string_summary_with_dsp
	bl		uart_putString
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Gib Minima aus
	ldr		r0, =string_minimum
	bl		uart_putString
	ldr		r0, [r6, #0]
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Gib Maxima aus
	ldr		r0, =string_maximum
	bl		uart_putString
	ldr		r0, [r7, #0]
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Gib Zeitbedarf aus
	ldr		r0, =string_end_timer
	bl		uart_putString
	mov		r0, r8
	bl		uart_putInt16
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Der Zeibedarf ohne DSP-Befehle ist `0x4E` Ticks, der Zeitbedarf mit Benutzung
	// von DSP-Befehlen ist nur `0x0F` Ticks. In diesem Fall ist die Berechnung also
	// mehr als 5-mal so schnell, wie der iterative Algorithmus. Das lässt sich zum
	// einen direkt an der Zahl der Assemblerbefehle ansehen, die durch die Schleife
	// in der Variante ohne DSP-Befehle noch mit 4 multipliziert werden muss.

	// e) Starte mit einer neuen Eingabeaufforderung
	b		loop_main
	
.thumb_func
read_vector:
	// Rette Registerwerte des Aufrufers
	push	{r4-r5,lr}
	mov		r4, r1
	bl		uart_putString
	ldr		r0, =string_prompt
	bl		uart_putString
	mov		r5, #SIZE			// Die Arraygröße ist implizit auf 4 Bytes festgelegt

read_next_byte:
	// Lies genau 4 Bytes von der Eingabe
	bl		uart_getByte
	strb	r0, [r4], #1
	subs	r5, r5, #1
	bne		read_next_byte
	
	// Echoe eingegebene Werte an Nutzer zurück
	ldr		r0, [r4, #-SIZE]!
	bl		uart_putInt32
	mov		r0, #NEWLINE
	bl		uart_putChar
	
	// Stelle Registerwerte wieder her und springe zu Aufrufer zurück
	mov		r0, r4
	pop		{r4-r5,pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
array_v1:
	.rept SIZE
	.byte 0x00
	.endr
	
array_v2:
	.rept SIZE
	.byte 0x00
	.endr
	
array_minimum:
	.rept SIZE
	.byte 0x00
	.endr
	
array_maximum:
	.rept SIZE
	.byte 0x00
	.endr

// Stringkonstanten
string_name_v1:
	.asciz "V1"

string_name_v2:
	.asciz "V2"
	
string_prompt:
	.asciz ": 0x"

string_summary_without_dsp:
	.asciz "Ohne DSP-Befehle:"
	
string_summary_with_dsp:
	.asciz "Mit DSP-Befehlen:"
	
string_minimum:
	.asciz "Min: 0x"
	
string_maximum:
	.asciz "Max: 0x"
	
string_end_timer:
	.asciz "Zeitbedarf: 0x"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantentdeklarationen
.equ ROWS, 4
.equ COLS, 4

// Stride ist die Adressdistanz zwischen dem Beginn einer Matrixzeile und der nächsten.
.equ MSTRIDE, COLS * 2
.equ NSTRIDE, ROWS * 2

// Benötigt für Aufgabe 2-1d
.equ A, 0xa4367c7b
.equ B, 0x10a78933
.equ C, 0xc5545f2c
.equ D, 0x788e84b1

.equ NEWLINE, '\n'
.equ TAB, '\t'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*
* Zu a):	Für die Multiplikation zweier 4x4 Matrizen wären für die Berechnung jedes einzelnen
* 			Elementes der Ergebnismatrix 4 Multiplikationen notwendig. Damit fallen für die gesamte
*			Berechnung 4 * 4 * 4 = 64 Multiplikationen an. Durch den DSP-Befehl `smlad` können wir
* 			pro Ausführung doppelt so viele Elemente miteinander verknüpfen. Damit halbiert sich die
*			Zahl an Multiplikationsbefehlen auf insgesamt 4 * 4 * 2 = 32 Befehle.
*
* Zu d):	Der Sättigungswert der Addition zweier vorzeichenloser 16-Bit Zahlen ist 0xFFFF. Bei der
* 			Verknüpfung mittels `uqadd16`, kam es in jedem Berechnungspaar mindestens einmal zu einer
* 			Sättigung. Grundsätzlich lässt sich eine drohende Bereichsüberschreitung hier an den
*			signifikantesten Stellenwerten abschätzen. Die signifikantesten Stellen der oberen
* 			Halbwörter von A (0xa436) und B (0x10a7) addieren sich zu 0xb, womit ein Overflow bereits
* 			ausgeschlossen ist. Zu einer Sättigung kam es bei der Addition der untere Halbworte von
*			A und B, also bei 0x7c7b + 0x8933, bei der Addition der oberen Halbworte von A und C, also
*			0xa436 + 0xc553, und bei beiden Additionen der Halbworte von A und D, also sowohl
*			0xa436 + 0x788e, als auch 0x7c7b + 0x84b1.
*			Bei der Addition vorzeichenbehafteter 16-Bit Zahlen kann es sowohl zu einer Bereichsüber-
*			als auch Unterschreitung kommen. So geschehen ist das bei der Addition beider Halbworte von
* 			A und C: 0xa436 + 0x5f2c wurde auf die untere Bereichsgrenze (0x8000), 0x7c7b + 05f2c wurde
* 			auf die obere Bereichsgrenze (0x7fff) gesättigt.
*
* Zu e): 	Bei der Sättigung mittels `usat16` fällt auf, dass die Operanden als vorzeichenbehaftete
*			Zahlen betrachtet werden um zu bestimmen, ob eine Bereichsüber- oder Unterschreitung vorliegt.
*			Es zeigt sich nämlich, dass alle Halbworte, die vorzeichenlos größer als 0x8000 sind, auf
*			0x0000 gesättigt wurden. So geschehen ist das bei der Sättigung des oberen Halbwortes bei A und
*			beim unteren Halbwort von B. Das untere Halbwort von A (0x7c7b) ist kleiner als 0x8000, damit also
*			eine positive Zahl, aber größer als 2^13 - 1 = 8191 = 0x1fff und wurde damit auf 0x1fff gesättigt.
*			Bei `ssat16` sind die oberen und unteren Bereichsgrenzen jeweils 2^12 - 1 = 0x0fff und
*			-2^12 = 0xf000 gegeben. Das obere Halbwort von A und das untere Halbwort von B haben dabei jeweils
*			den Sättigungsbereich unterschritten. Das untere Halbwort von A und das obere Halbwort von B
*			hingegen haben den Sättigungsbereich überschritten. 
*/
main:	
	bl		uart_init
	
	// a) Multipliziere die Matrizen M und N.
	ldr		r0, =string_result_matmul
	bl		uart_putString
	ldr		r4, =matrix_o
	ldr		r5, =matrix_m
	
	// Lade Enditeratoren für eine bereichsbasierte Schleife.
	ldr		r6, =(matrix_m + MSTRIDE * ROWS)
	ldr		r8, =(matrix_n + NSTRIDE * COLS)
	
loop_matmul_outer:
	// Berechne die Matrix O Reihe für Reihe...
	ldr		r7, =matrix_n
	ldrd	r9, r10, [r5], #MSTRIDE
	
loop_matmul_inner:
	// ... und innerhalb jeder Reihe Spalte für Spalte.
	mov		r0, #0			// Initialisiere Akkumulator.
	ldrd	r11, r12, [r7], #NSTRIDE
	smlad	r0, r9, r11, r0
	smlad	r0, r10, r12, r0
	str		r0, [r4], #4
	
	// Gib berechnetes Ergebnis für O(i, j) aus.
	bl		uart_putInt32
	cmp		r7, r8
	ite		lt
	movlt	r0, #TAB
	movge	r0, #NEWLINE
	bl		uart_putChar
	
	// Falls `r6` noch nicht hinter N zeigt, fahre mit nächster Spalte fort.
	cmp		r7, r8
	blt		loop_matmul_inner
	
	// Falls `r5` noch nicht hinter M zeigt, fahre mit nächster Reihe fort.
	cmp		r5, r6
	blt		loop_matmul_outer
	
	// b) Kopiere die Matrix O in einen neuen Speicherbereich.
	ldr		r0, =string_copying
	bl		uart_putString
	ldr		r5, =matrix_o
	ldr		r6, =matrix_copy_o
	
loop_4byte_memcopy:
	ldm		r5!, {r7-r10}
	stm		r6!, {r7-r10}
	cmp		r5, r4				// `r4` zeigt noch immer auf die erste Adresse hinter O.
	blt		loop_4byte_memcopy
	
	// c) Summiere die Elementprodukte von M und N.
	ldr		r0, =string_result_sum_of_products
	bl		uart_putString
	mov		r0, #0
	ldr		r4, =matrix_m
	ldr		r5, =(matrix_m + MSTRIDE * ROWS)
	ldr		r6, =matrix_n

loop_sum_of_products:
	ldrd	r7, r8, [r4], #MSTRIDE
	ldrd	r10, r11,[r6], #NSTRIDE
	smlad	r0, r7, r10, r0
	smlad	r0, r8, r11, r0
	cmp		r4, r5
	blt		loop_sum_of_products
	
	// Gib die berechnete Produkt-Summe aus
	bl		uart_putInt32
	
	// d) Verknüpfe nacheinander A mittels der skalierbaren Additionsbefehle mit B, C und D.
	ldr		r4, =#A
	ldr		r5, =#B
	ldr		r6, =#C
	ldr		r7, =#D
	
	// Verknüpfe mittels `uadd16`.
	ldr		r0, =string_result_uadd
	bl		uart_putString
	uadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	uadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	uadd16	r0, r4, r7
	bl		uart_putInt32
	
	// Verknüpfe mittels `sadd16`.
	ldr		r0, =string_result_sadd
	bl		uart_putString
	sadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	sadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	sadd16	r0, r4, r7
	bl		uart_putInt32
	
	// Verknüpfe mittels `uqadd16`.
	ldr		r0, =string_result_uqadd
	bl		uart_putString
	uqadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	uqadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	uqadd16	r0, r4, r7
	bl		uart_putInt32
	
	// Verknüpfe mittels `qadd16`.
	ldr		r0, =string_result_qadd
	bl		uart_putString
	qadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	qadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	qadd16	r0, r4, r7
	bl		uart_putInt32
	
	// e) Sättige A und B auf jeweils 13 Bits.
	ldr		r0, =string_result_usat
	bl		uart_putString
	usat16	r0, #13, r4			// `r4` beinhaltet noch den Wert von A.
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	usat16	r0, #13, r5			// `r5` beinhaltet noch den Wert von B.
	bl		uart_putInt32
	
	// Sättige als vorzeichenbehaftete Zahlen.
	ldr		r0, =string_result_ssat
	bl		uart_putString
	ssat16	r0, #13, r4
	bl		uart_putInt32
	mov		r0, #TAB
	bl		uart_putChar
	ssat16	r0, #13, r5
	bl		uart_putInt32
	
	// Beende Ausgabe mit einer neuen Zeile.
	mov		r0, #NEWLINE
	bl		uart_putChar
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
matrix_m:
	// Reihenweise Ordnung
	.short 0x5f8c, 0x7f48, 0x8245, 0x6048
	.short 0xc799, 0x9c5d, 0xd49c, 0x33d8
	.short 0x579b, 0x8aef, 0xf2c0, 0xa3c2
	.short 0x41fd, 0x50d4, 0x25c6, 0x4afa
	
matrix_n:
	// Spaltenweise Ordnung
	.short 0x7f41, 0x0645, 0x8c8f, 0x9065
	.short 0x78e3, 0xf7f3, 0xd29f, 0x2961
	.short 0x5a1e, 0xdfed, 0x4b9f, 0x1092
	.short 0x61bf, 0x21be, 0x5ca1, 0xc6d3

matrix_o:
	.rept ROWS * COLS
	.word 0x0000
	.endr
	
matrix_copy_o:
	.rept ROWS * COLS
	.word 0x0000
	.endr
	
string_result_matmul:
	.asciz "Ergebnismatrix O:\n"
	
string_copying:
	.asciz "Kopieren der Matrix 0!\n"
	
string_result_sum_of_products:
	.asciz "Produkt-Summe: "
	
string_result_uadd:
	.asciz "\nUADD16:\t"
	
string_result_sadd:
	.asciz "\nSADD16:\t"
	
string_result_uqadd:
	.asciz "\nUQADD16:\t"
	
string_result_qadd:
	.asciz "\nQADD16:\t"
	
string_result_usat:
	.asciz "\nUSAT16:\t"
	
string_result_ssat:
	.asciz "\nSSAT16:\t"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantentdeklarationen
.equ TRUE, 1

.equ SECS_PER_MIN, 1
.equ MINS_PER_HOUR, 60
.equ HOURS_PER_DAY, 24
.equ DAYS_PER_MONTH, 30
.equ MONTHS_PER_YEAR, 12
.equ YEARS_LIMIT, 100

.equ COLON, ':'
.equ DOT, '.'
.equ NEWLINE, '\n'
.equ NIL, '0'
.equ SPACE, ' '
.equ TAB, '\t'

.equ CHAR_D, 'd'
.equ CHAR_S, 's'
.equ CHAR_T, 't'

// Die Zahl der Befehle innerhalb der Verzögerungsschleife beträgt 2 Befehle à 1 Zyklus pro Befehl. Messungen
// zufolge muss jedoch eher von 3 statt 2 Zyklen pro Schleifendurchlauf ausgegangen werden. Das kann evtl. daran
// liegen, dass die bedingte Verzweigung in jedem Durchlauf einen Pipeline-Flush und -Refill durchführen muss,
// wobei das offenbar eine Verzögerung von einem zusätzlichen Zyklus verursacht.
.equ DELAY_CYCLES, 25000000 / 3

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl		uart_init
	
	// c) Implementiere Hauptprogramm
	mov		r4, #TRUE					// Gibt an, ob die Uhr gerade läuft oder steht.
	mov		r5, #0						// Zähler für die vergangenen Sekunden.
	ldr		r6, =datetime_now

loop_main:
	cbz		r4, handle_input			// Falls die Uhr gestoppt wurde, fahre direkt mit der Eingabeüberprüfung fort.
	bl		delay
	add		r5, r5, #1					// Eine Sekunde ist vergangen.
	
	// Berechne die neue Uhrzeit und das Datum.
	cmp		r5, #SECS_PER_MIN
	blt		handle_input
	
	// Berechne die Sekunden der neuen Uhrzeit
	sub		r5, r5, #SECS_PER_MIN
	
	// Berechne die Minuten der neuen Uhrzeit
	ldrb	r7, [r6, #4]
	add		r7, r7, #1
	subs	r8, r7, #MINS_PER_HOUR		// Bestimme, ob bereits eine Stunde vergangen ist.
	ite		lt
	strblt	r7, [r6, #4]
	strbge	r8, [r6, #4]
	blt		handle_datetime_update		// Falls keine Stunde vergangen ist, schließe den Rest der Uhrzeitberechnung kurz.
	
	// Berechne die Stunden der neuen Uhrzeit
	ldrb	r7, [r6, #3]
	add		r7, r7, #1
	subs	r8, r7, #HOURS_PER_DAY		// Bestimme, ob bereits ein Tag vergangen ist.
	ite		lt
	strblt	r7, [r6, #3]
	strbge	r8, [r6, #3]
	blt		handle_datetime_update		// Falls kein Tag vergangen ist, schließe den Rest der Datumsberechnung kurz.
	
	// Berechne den Tag des neuen Datums
	ldrb	r7, [r6]
	add		r7, r7, #1
	subs	r8, r7, #DAYS_PER_MONTH		// Bestimme, ob bereits ein Monat vergangen ist.
	ite		le
	strble	r7, [r6]
	strbgt	r8, [r6]
	ble		handle_datetime_update		// Falls kein Monat vergangen ist, schließe den Rest der Datumsberechnung kurz.
	
	// Berechne den Monat des neuen Datums
	ldrb	r7, [r6, #1]
	add		r7, r7, #1
	subs	r8, r7, #MONTHS_PER_YEAR	// Bestimme, ob bereits ein Jahr vergangen ist.
	ite		le
	strble	r7, [r6, #1]
	strbgt	r8, [r6, #1]
	ble		handle_datetime_update		// Falls kein Jahr vergangen ist, schließe den Rest der Datumsberechnung kurz.
	
	// Berechne das Jahr des neuen Datums
	ldrb	r7, [r6, #2]
	add		r7, r7, #1
	subs	r8, r7, #YEARS_LIMIT		// Bestimme, ob das neue Jahr die obere Bereichsgrenze verlässt.
	ite		lt
	strblt	r7, [r6, #2]
	strbge	r8, [r6, #2]

handle_datetime_update:
	// Gib das aktualisierte Datum und die Uhrzeit aus.
	bl		printDateTimeNow
	
handle_input:
	bl		uart_charPresent
	cmp		r0, #0
	beq		loop_main
	
	// Es liegt eine Eingabe vor.
	bl		uart_getChar
	cmp		r0, #CHAR_S
	beq		handle_s
	cmp		r0, #CHAR_T
	beq		handle_t
	cmp		r0, #CHAR_D
	beq		handle_d
	b		loop_main
	
handle_s:
	// Invertiere den Wahrheitswert in `r4`
	eor		r4, r4, #TRUE
	b		loop_main

handle_t:
	// Lies Stunde ein.
	ldr		r0, =string_prompt_hour
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6, #3]
	mov		r7, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r7
	bl		uart_putByteBase10
	
	// Lies Minute ein.
	ldr		r0, =string_prompt_minute
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6, #4]
	mov		r7, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r7
	bl		uart_putByteBase10
	
	// Schließ Eingabe ab.
	mov		r0, #NEWLINE
	bl		uart_putChar
	b		loop_main

handle_d:
	// Lies Tag ein.
	ldr		r0, =string_prompt_day
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6]
	mov		r7, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r7
	bl		uart_putByteBase10
	
	// Lies Monat ein.
	ldr		r0, =string_prompt_month
	bl		uart_putString
	bl		uart_getByteBase10
	strb 	r0, [r6, #1]
	mov		r7, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r7
	bl		uart_putByteBase10
	
	// Lies Jahr ein.
	ldr		r0, =string_prompt_year
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6, #2]
	mov		r7, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r7
	bl		uart_putByteBase10
	
	// Schließ Eingabe ab.
	mov		r0, #NEWLINE
	bl		uart_putChar
	b		loop_main

/*
* a) Schreibe ein Unterprogramm `delay`, dass eine Verzögerung von einer Sekunde erzeugt.
*
* Unterprogramm (delay): Führt eine Verzögerungsschleife mit fester Periode aus. Die Kernschleife rotiert für
* 25 Millionen Zyklen (entspricht 25MHz = 25 Million Zyklen / Sekunde). Abweichungen um wenige Zyklen können 
* entstehen durch Fehler in der Adressspekulation, sowie durch Pipeline-Flushes, -Refills und zusätzliche
* Befehle außerhalb der Verzögerungsschleife. 
*/
.thumb_func
delay:
	ldr		r0, =#DELAY_CYCLES

loop_delay:
	subs	r0, r0, #1
	bne		loop_delay
	
	bx		lr

/*
* b) Schreibe ein Unterprogramm, dass das aktuelle Datum und die Uhrzeit auf dem Terminal ausgibt.
*
* Unterprogramm (printDateTimeNow): Gibt gegenwärtiges Datum und Uhrzeit im Format `dd.mm.jjjj hh:mm Uhr`
* aus. 
*/
.thumb_func
printDateTimeNow:
	push	{r4-r5, lr}
	ldr		r4, =datetime_now
	
	// Gib Tag aus.
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Monat aus.
	mov		r0, #DOT
	bl		uart_putChar
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Jahr aus.
	ldr		r0, =string_year_prefix	// Die oberen beiden Ziffern ("20") stehen fest.
	bl		uart_putString
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Stunde aus.
	mov		r0, #SPACE
	bl		uart_putChar
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Minute aus.
	mov		r0, #COLON
	bl		uart_putChar
	ldrb	r5, [r4]
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	ldr		r0, =string_datetime_postfix
	bl		uart_putString
	pop		{r4-r5, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
datetime_now:
	.byte 01						// Tag		(default: 01)
	.byte 01						// Monat	(default: 01)
	.byte 14						// Jahr		(default: 14)
	.byte 00						// Stunde	(default: 00)
	.byte 00						// Minute	(default: 00)
	
string_year_prefix:
	.asciz ".20"
	
string_datetime_postfix:
	.asciz " Uhr\n"
	
string_prompt_hour:
	.asciz "Stunde eingeben (hh): "
	
string_prompt_minute:
	.asciz "\nMinuten eingeben (mm): "

string_prompt_day:
	.asciz "Tag eingeben (dd): "
	
string_prompt_month:
	.asciz "\nMonat eingeben (mm): "
	
string_prompt_year:
	.asciz "\nJahr eingeben (jj): "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Bool'sche Konstanten
.equ TRUE, 1
.equ FALSE, 0

// Umrechnungskonstanten
.equ CYCLES_PER_SECOND, 25000000
.equ SECS_PER_MIN, 1
.equ MINS_PER_HOUR, 60
.equ HOURS_PER_DAY, 24
.equ DAYS_PER_MONTH, 30
.equ MONTHS_PER_YEAR, 12
.equ YEARS_LIMIT, 100

// Zeichenkonstanten
.equ COLON, 	':'
.equ DOT, 		'.'
.equ NEWLINE, 	'\n'
.equ NIL, 		'0'
.equ SPACE, 	' '
.equ TAB, 		'\t'

// Eingabezeichen
.equ CHAR_D, 'd'
.equ CHAR_S, 's'
.equ CHAR_T, 't'

// Interruptvektoradresse
.equ IRQ, 			69
.equ OFFSET_IRQ69, 	0x154
.equ IVT, 			0x1ffffe00
.equ IV_PIT1, 		IVT + OFFSET_IRQ69

// Steuerregister
.equ PIT_MCR,		0x40037000
.equ PIT_LDVAL1,	0x40037110
.equ PIT_TCTRL1,	0x40037118
.equ PIT_TFLG1,		0x4003711c
.equ SIM_SCGC6,		0x4004803c
.equ NVIC_ISER2,	0xe000e100 + 2 * 4
.equ NVIC_ICPR2,	0xe000e280 + 2 * 4

// Steuerwörter
.equ CLRPEND,		0x1 << (IRQ % 32)
.equ SETENA,		0x1 << (IRQ % 32)
.equ TEN,			0x0
.equ TIE,			0x1

// Bitband-Alias Adressen
__BBREG	PIT_TCTRL1_TEN, PIT_TCTRL1, TEN
__BBREG	PIT_TCTRL1_TIE, PIT_TCTRL1, TIE
__BBREG SIM_SCGC6_PIT, 	SIM_SCGC6, 	23 

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl		uart_init
	
	// Aktiviere Takt für PIT.
	ldr		r0, =#SIM_SCGC6_PIT
	mov		r1, #0x1
	str		r1, [r0]
	
	// b) Setze Interrupt-Vektor zu PIT1.
	ldr		r0, =#IV_PIT1
	ldr		r1, =handle_pit1_irq
	str		r1, [r0]
	
	// Lösche hängende Interrupts für PIT1.
	ldr		r0, =#NVIC_ICPR2
	mov		r1, #CLRPEND
	str		r1, [r0]
	
	// Aktiviere Interrupts für PIT.
	ldr		r0, =#NVIC_ISER2
	mov		r1, #SETENA
	str		r1, [r0]
	
	// Aktiviere die PITs und deaktiviere den Freeze-Modus.
	ldr		r0, =#PIT_MCR
	mov		r1, #0x0
	str		r1, [r0]
	
	// c) Initialisiere Zähler auf eine Sekunde.
	ldr		r0, =#PIT_LDVAL1
	ldr		r1, =#CYCLES_PER_SECOND
	str		r1, [r0]
	
	// Aktiviere erst den PIT1 und anschließend dessen Interrupts mittels Bitbanding.
	ldr		r0, =#PIT_TCTRL1_TIE
	mov		r1, #0x1
	str		r1, [r0]
	ldr		r0, =#PIT_TCTRL1_TEN
	mov		r1, #0x1
	str		r1, [r0]
	
	// Initialisiere Zustandsvariablen für das Hauptprogramm.
	mov		r4, #TRUE					// Gibt an, ob die Uhr gerade läuft oder steht.
	mov		r5, #0						// Zähler für die vergangenen Sekunden.
	ldr		r6, =datetime_now			// Die Struktur für die aktuelle Uhrzeit.
	ldr		r7, =pit1_is_lapsed			// Eine Flag, die angiebt, ob bereits wieder eine Sekunde vergangen ist.
	
	// d) Aktiviere Interrupts und nutze PIT Interrupts um Zeit zu messen.
	cpsie	if

loop_main:

	// Überprüfe ob die Uhr gegenwärtig läuft (und nicht durch eine Eingabe gestoppt wurde).
	cmp		r4, #TRUE
	bne		handle_input				// Andernfalls fahre direkt mit Eingabeüberprüfung fort.
	
	// Falls nicht, dann überprüfe, ob bereits eine Sekunde vergangen ist.
	ldrb	r8, [r7]
	cmp		r8, #TRUE
	bne		handle_input				// Andernfalls fahre direkt mit Eingabeüberprüfung fort.
	
	// Falls ja, dann berechne die aktuelle Uhrzeit neu.
	mov		r8, #FALSE
	strb	r8, [r7]					// Setze die Flag zurück.
	add		r5, r5, #1					// Eine Sekunde ist vergangen.
	
	// Berechne die neue Uhrzeit und das Datum.
	//
	// Da wir grundsätzlich im vorliegenden Fall wissen, dass 1 Minute == 1 Sekunde gelten soll, ist die
	// ausführliche Umrechnung von Sekunden in Minuten theoretisch überflüssig. Aus der Perspektive des 
	// Softwareingenieursego fühlt es sich jedoch gut, maximal den Wert der Umrechnungskonstanten
	// korrigieren zu müssen, sollte man sich tatsächlich doch mal für 1 Minute == 60 Sekunden oder so
	// entscheiden wollen.
	cmp		r5, #SECS_PER_MIN
	blt		handle_input
	
	// Berechne die Sekunden der neuen Uhrzeit
	sub		r5, r5, #SECS_PER_MIN
	
	// Berechne die Minuten der neuen Uhrzeit
	ldrb	r8, [r6, #4]
	add		r8, r8, #1
	subs	r9, r8, #MINS_PER_HOUR		// Bestimme, ob bereits eine Stunde vergangen ist.
	ite		lt
	strblt	r8, [r6, #4]
	strbge	r9, [r6, #4]
	blt		handle_datetime_update		// Falls keine Stunde vergangen ist, schließe den Rest der Uhrzeitberechnung kurz.
	
	// Berechne die Stunden der neuen Uhrzeit
	ldrb	r8, [r6, #3]
	add		r8, r8, #1
	subs	r9, r8, #HOURS_PER_DAY		// Bestimme, ob bereits ein Tag vergangen ist.
	ite		lt
	strblt	r8, [r6, #3]
	strbge	r9, [r6, #3]
	blt		handle_datetime_update		// Falls kein Tag vergangen ist, schließe den Rest der Datumsberechnung kurz.
	
	// Berechne den Tag des neuen Datums
	ldrb	r8, [r6]
	add		r8, r8, #1
	subs	r9, r8, #DAYS_PER_MONTH		// Bestimme, ob bereits ein Monat vergangen ist.
	ite		le
	strble	r8, [r6]
	strbgt	r9, [r6]
	ble		handle_datetime_update		// Falls kein Monat vergangen ist, schließe den Rest der Datumsberechnung kurz.
	
	// Berechne den Monat des neuen Datums
	ldrb	r8, [r6, #1]
	add		r8, r8, #1
	subs	r9, r8, #MONTHS_PER_YEAR	// Bestimme, ob bereits ein Jahr vergangen ist.
	ite		le
	strble	r8, [r6, #1]
	strbgt	r9, [r6, #1]
	ble		handle_datetime_update		// Falls kein Jahr vergangen ist, schließe den Rest der Datumsberechnung kurz.
	
	// Berechne das Jahr des neuen Datums
	ldrb	r8, [r6, #2]
	add		r8, r8, #1
	subs	r9, r8, #YEARS_LIMIT		// Bestimme, ob das neue Jahr die obere Bereichsgrenze verlässt.
	ite		lt
	strblt	r8, [r6, #2]
	strbge	r9, [r6, #2]

handle_datetime_update:
	// Gib das aktualisierte Datum und die Uhrzeit aus.
	bl		printDateTimeNow
	
handle_input:
	bl		uart_charPresent
	cmp		r0, #0
	beq		loop_main
	
	// Es liegt eine Eingabe vor.
	bl		uart_getChar
	cmp		r0, CHAR_S
	beq		handle_s
	cmp		r0, CHAR_T
	beq		handle_t
	cmp		r0, CHAR_D
	beq		handle_d
	b		loop_main
	
handle_s:
	// Invertiere den Wahrheitswert in `r4`
	eor		r4, r4, #TRUE
	b		loop_main

handle_t:
	// Lies Stunde ein.
	ldr		r0, =string_prompt_hour
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6, #3]
	mov		r8, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r8
	bl		uart_putByteBase10
	
	// Lies Minute ein.
	ldr		r0, =string_prompt_minute
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6, #4]
	mov		r8, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r8
	bl		uart_putByteBase10
	
	// Schließ Eingabe ab.
	mov		r0, #NEWLINE
	bl		uart_putChar
	b		loop_main

handle_d:
	// Lies Tag ein.
	ldr		r0, =string_prompt_day
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6]
	mov		r8, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r8
	bl		uart_putByteBase10
	
	// Lies Monat ein.
	ldr		r0, =string_prompt_month
	bl		uart_putString
	bl		uart_getByteBase10
	strb 	r0, [r6, #1]
	mov		r8, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r8
	bl		uart_putByteBase10
	
	// Lies Jahr ein.
	ldr		r0, =string_prompt_year
	bl		uart_putString
	bl		uart_getByteBase10
	strb	r0, [r6, #2]
	mov		r8, r0
	cmp		r0, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r8
	bl		uart_putByteBase10
	
	// Schließ Eingabe ab.
	mov		r0, #NEWLINE
	bl		uart_putChar
	b		loop_main

/*
* Unterprogramm (printDateTimeNow): Gibt gegenwärtiges Datum und Uhrzeit im Format `dd.mm.jjjj hh:mm Uhr`
* aus. 
*/
.thumb_func
printDateTimeNow:
	push	{r4-r5, lr}
	ldr		r4, =datetime_now
	
	// Gib Tag aus.
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Monat aus.
	mov		r0, #DOT
	bl		uart_putChar
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Jahr aus.
	ldr		r0, =string_year_prefix	// Die oberen beiden Ziffern ("20") stehen fest.
	bl		uart_putString
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Stunde aus.
	mov		r0, #SPACE
	bl		uart_putChar
	ldrb	r5, [r4], #1
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	
	// Gib Minute aus.
	mov		r0, #COLON
	bl		uart_putChar
	ldrb	r5, [r4]
	cmp		r5, #10
	itt		lt
	movlt	r0, #NIL
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	ldr		r0, =string_datetime_postfix
	bl		uart_putString
	pop		{r4-r5, pc}

/*
* a) Implementiere eine Interrupt Service Routine zu PIT1.
* 
* Interrupt Service Routine (handle_pit1_irq): Behandelt eine Unterbrechung des Periodic
* Interrupt Timer Moduls auf Kanal 1 bei Ablaufen des Zählers. 
*/
.thumb_func
handle_pit1_irq:
	ldr		r0, =pit1_is_lapsed
	mov		r1, #TRUE
	strb	r1, [r0]
	
	// Quittiere die Unterbrechungsanforderung am PIT Modul.	
	ldr		r0, =#PIT_TFLG1
	mov		r1, #0x1
	str		r1, [r0]
	
	// Kehre von der Unterbrechung zurück.
	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
datetime_now:
	.byte 01						// Tag		(default: 01)
	.byte 01						// Monat	(default: 01)
	.byte 14						// Jahr		(default: 14)
	.byte 00						// Stunde	(default: 00)
	.byte 00						// Minute	(default: 00)
	
pit1_is_lapsed:
	.byte FALSE
	
string_year_prefix:
	.asciz ".20"
	
string_datetime_postfix:
	.asciz " Uhr\n"
	
string_prompt_hour:
	.asciz "Stunde eingeben (hh): "
	
string_prompt_minute:
	.asciz "\nMinuten eingeben (mm): "

string_prompt_day:
	.asciz "Tag eingeben (dd): "
	
string_prompt_month:
	.asciz "\nMonat eingeben (mm): "
	
string_prompt_year:
	.asciz "\nJahr eingeben (jj): "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ BYTE,			0x08
.equ HALFWORD,		0x10
.equ ISO_8023_POLY, 0x04c11db7
.equ SEED,			0x12345678

// Registeradressen
.equ CRC_CRC,	 	0x40032000
.equ CRC_GPOLY, 	0x40032004
.equ CRC_CTRL, 		0x40032008
.equ SIM_SCGC6,		0x4004803c

// Steuerwörter
.equ TCRC,			0x1 << 24
.equ WAS,			0x1 << 25

// Bitband-Alias Adressen
__BBREG CRC_CTRL_WAS, 	CRC_CTRL, 	25
__BBREG SIM_SCGC6_CRC, 	SIM_SCGC6, 	18

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Aktiviere Takt für CRC.
	ldr		r0, =SIM_SCGC6_CRC
	mov		r1, #1
	str		r1, [r0]
	
	// b) Initialisiere CRC im 32-bit Modus ohne Transposition oder Komplementierung.
	ldr		r2, =CRC_CTRL
	mov		r3, #TCRC
	str		r3, [r2]
	
	// c) Initialisiere CRC mit dem CRC-32 Standardpolynom gemäß ISO 802.3.
	ldr		r0, =CRC_GPOLY
	ldr		r1, =ISO_8023_POLY
	str		r1, [r0]
	
	// d) Setze den CRC-Startwert auf 0x12345678.
	orr		r3, r3, #WAS
	str		r3, [r2]
	ldr		r4, =CRC_CRC
	ldr		r5, =SEED
	str		r5, [r4]
	bic		r3, r3, #WAS
	str		r3, [r2]
	
	// e) Berechne CRC von `str`.
	ldr		r6, =string
	mov		r7, r6
	
loop_crc:
	ldrb	r5, [r6], #1
	cbz		r5, read_crc
	
	// Falls in einer CRC-Berechnungsrunde kein voller 4-Byte Satz mit Daten gefüllt
	// werden kann, müssen die partiellen Daten als Byte oder Halbwörter separat
	// geschrieben werden. Wichtig ist die Auswahl der korrekten Breite des Datentyps
	// im Schreibbefehl um nicht unbeabsichtigte Nullbytes in die Berechnung einzufügen.
	ldrb	r0, [r6], #1
	cbz		r0, write_crc_byte
	orr		r5, r0, r5, lsl #BYTE
	
	ldrb	r0, [r6], #1
	cbz		r0, write_crc_2bytes
	orr		r5, r0, r5, lsl #BYTE
	
	ldrb	r0, [r6], #1
	cbz		r0, write_crc_3bytes
	orr		r5, r0, r5, lsl #BYTE
	
	// Gib 4-Byte Satz in die CRC-Berechnung ein.
	str		r5, [r4]
	b		loop_crc
	
write_crc_3bytes:
	// Falls der Terminator an vierter Byteposition war, dann muss zuerst das Byte im
	// oberen Halbwort des Sammelregisters in die CRC-Berechnung eingegeben werden.
	lsr		r0, r5, #HALFWORD
	strb	r0, [r4]
	
write_crc_2bytes:
	strh	r5, [r4]
	b		read_crc
	
write_crc_byte:
	strb	r5, [r4]

read_crc:
	// f) Gib zum Abschluss den Eingabestring und das Ergebnis der Berechnung aus.
	ldr		r0, =string_input
	bl		uart_putString
	mov		r0, r7
	bl		uart_putString
	ldr		r0, =string_output
	bl		uart_putString
	ldr		r0, [r4]
	bl		uart_putInt32

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
string:
	// a) Lege den Eingabestring im Datenbereich ab.
	//
	// Der rote Pfeil in der Aufgabenstellung ist von der Bedeutung her uneindeutig. Eine
	// Interpretation wäre, dass es nur eine Lesehilfte aufgrund der Textbreite ist, er
	// könnte aber auch als Symbol für einen Zeilenumbruch im Eingabestring stehen. Hier
	// wird davon ausgegangen, dass kein Zeilenumbruch im String berücksichtigt sein sollte.
	// Daraus ergibt sich ein Prüfwert von 0x284051f1. Würde man den Zeilenumbruch mit
	// berücksichtigen, dann ergäbe sich stattdessen ein Prüfwert von 0xf542833a.
	.asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"

string_input:
	.asciz "Berechnete CRC-32 von:\n"
	
string_output:
	.asciz "\nErgebnis: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ HALFWORD,			0x10
.equ SEC, 				25000000
.equ MS,				SEC / 1000
.equ PIN10,				(1 << 10)
.equ PIN11,				(1 << 11)
.equ PIN19,				(1 << 19)
.equ PIN26,				(1 << 26)
.equ PIN28,				(1 << 28)
.equ PIN29,				(1 << 29)

.equ CHAR_S,			's'
.equ CHAR_PLUS,			'+'
.equ CHAR_MINUS,		'-'
.equ NEWLINE,			'\n'

.equ COMPLEMENT,		0xffffffff

// Interrupt-Vektor-Konstanten
.equ IVT,				0x1ffffe00
.equ OFFSET_IRQ0,		0x40

.equ IRQ69,				69
.equ IRQ91,				91

.equ OFFSET_IRQ69,		IVT + OFFSET_IRQ0 + (IRQ69 << 2)
.equ OFFSET_IRQ91,		IVT + OFFSET_IRQ0 + (IRQ91 << 2)

.equ IRQ69_BIT,			(1 << (IRQ69 % 32))
.equ IRQ91_BIT,			(1 << (IRQ91 % 32))

// SRAM Basisadressen
.equ SRAM_ALIAS_BASE,	0x22000000

// Nested Interrupt Controller (NVIC) Registeradressen
.equ NVIC_ISER2,		0xe000e100 + 2 << 2
.equ NVIC_ICPR2,		0xe000e280 + 2 << 2

// Port Control and Interrupts (PORT) Registeradressen
.equ PORTA_PCR19,		0x4004904c
.equ PORTA_GPCLR,		0x40049080
.equ PORTA_GPCHR,		0x40049084

.equ PORTE_PCR26,		0x4004d068

// System Integration Module (SIM) Registeradressen
.equ SIM_SCGC5,			0x40048038
.equ SIM_SCGC6,			0x4004803c

// Periodic Interrupt Timer (PIT) Registeradressen
.equ PIT_LDVAL1,		0x40037110
.equ PIT_TCTRL1,		0x40037118
.equ PIT_TFLG1,			0x4003711c

// General-Purpose I/O (GPIO) Registeradressen
.equ GPIOA_PDOR,		0x400ff000
.equ GPIOA_PDIR,		0x400ff010
.equ GPIOA_PDDR,		0x400ff014

.equ GPIOE_PDIR,		0x400ff110

// Steuerwörter
.equ GPIO,				(1 << 8)		// Setze MUX auf GPIO.
.equ IRQC_FE,			(10 << 16)		// Setze IRQC auf Interrupt bei fallender Flanke.
.equ PORTA,				(1 << 9)		// Aktiviere Takt für PORTA.
.equ PORTE,				(1 << 13)		// Aktiviere Takt für PORTE.

// Bitband-Alias Adressen
__BBREG	PIT_TCTRL1_TEN, 	PIT_TCTRL1, 0
__BBREG	PIT_TCTRL1_TIE, 	PIT_TCTRL1, 1
__BBREG PORTA_PCR19_ISF, 	PORTA_PCR19, 24
__BBREG PORTE_PCR26_ISF, 	PORTE_PCR26, 24
__BBREG SIM_SCGC6_PIT, 		SIM_SCGC6, 23

.equ MOD_SW1, SRAM_ALIAS_BASE
.equ MOD_SW2, SRAM_ALIAS_BASE + 1 << 2

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init
	
	// Aktiviere Takt für PORTA und PORTE.
	ldr		r0, =SIM_SCGC5
	ldr		r1, [r0]
	orr		r1, r1, #(PORTA | PORTE)
	str		r1, [r0]
	
	// Aktiviere Takt für PIT (wird eigentlich bereits von `pit3_init` gemacht,
	// aber da es nicht in der Funktionsdokumentation steht, lieber noch mal
	// hier zur Sicherheit).
	ldr		r0, =SIM_SCGC6_PIT
	mov		r2, #1
	str		r2, [r0]
	
	// Setze Interrupt-Vektor zu PIT1.
	ldr		r0, =OFFSET_IRQ69
	ldr		r1, =handle_pit1_irq
	str		r1, [r0]
	
	// Setze Interrupt-Vektor zu PORTE.
	ldr		r0, =OFFSET_IRQ91
	ldr		r1, =handle_porte_irq
	str		r1, [r0]
	
	// Lösche anhängende Interrupts für PIT1 und PORTE.
	ldr		r0, =NVIC_ICPR2
	ldr		r1, =(IRQ69_BIT | IRQ91_BIT)
	str		r1, [r0]
	
	// Aktiviere Interrupts für PIT1 und PORTE.
	ldr		r0, =NVIC_ISER2
	str		r1, [r0]
	
	// Initialisiere Zähler auf eine Sekunde. Die konfiguration der PIT_MCR
	// wurde bereits durch `pit3_init` vorgenommen.
	ldr		r0, =#PIT_LDVAL1
	ldr		r1, =#SEC
	str		r1, [r0]
	
	// Aktiviere erst den PIT1 und anschließend dessen Interrupts mittels Bit-
	// banding.
	ldr		r0, =#PIT_TCTRL1_TIE
	str		r2, [r0]
	ldr		r0, =#PIT_TCTRL1_TEN
	str		r2, [r0]
	
	// a) Aktiviere die erfoderlichen Ports die LEDs als GPIO Ausgänge und die
	// Taster als Eingänge zu konfigurieren.
	//
	//Konfiguriere PORTA Pins 10 und 11 als GPIO.
	ldr		r0, =PORTA_GPCLR
	mov		r1, #GPIO
	mov		r2, #(PIN10 | PIN11)
	pkhbt	r1, r1, r2, lsl #HALFWORD
	str		r1, [r0]
	
	// Konfiguriere PORTA Pins 28 und 29 als GPIO.
	ldr		r0, =PORTA_GPCHR
	mov		r3, #(PIN28 | PIN29)
	pkhtb	r1, r3, r1
	str		r1, [r0]
	
	// Konfiguriere PORTA Pin 19 als GPIO mit Interrupt bei fallender Flanke.
	ldr		r0, =PORTA_PCR19
	mov		r4, #IRQC_FE
	pkhtb	r1, r4, r1
	str		r1, [r0]
	
	// Konfiguriere PORTE Pin 26 als GPIO mit Interrupt bei fallender Flanke.
	ldr		r0, =PORTE_PCR26
	str		r1, [r0]
	
	// Deaktiviere erst die LEDs und schalte dann die Pins 10, 11, 28 und 29 in
	// GPIOA auf Ausgang. `r4` enthält das LED-Ausgaberegister.
	pkhtb	r1, r3, r2
	ldr		r4, =GPIOA_PDOR
	str		r1, [r4]
	ldr		r0, =GPIOA_PDDR
	str		r1, [r0]
	
	// `r5 beinhält die Adresse der Anzeige, ob laut PIT1 bereits wieder eine
	// Sekunde vergangen ist.
	ldr		r5, =is_pit1_lapsed
	
	// b) Realisiere einen zyklischen 8-bit Dualzähler.
	//
	// `r6` enthält den aktuellen Zählerstand. Der Zähler nutzt die volle
	// 32-bit Breite des Registers zum Zählen. Das hat folgenden Gründe: Zum
	// einen ist ein 32-bit Zähler, deren oberen drei Bit man trunkiert,
	// äquivalent zu einem 8-bit Zähler mit Modulo-256-Semantik. D.h. wenn
	// wir nur die unteren 8-bit ausgeben, dann zeigt die Ausgabe zu jedem
	// Zeitpunkt einen korrekten 8-bit Zählerstand. Zum anderen ersparen wir
	// uns damit Korrekturen durch Sättigung bei Über- oder Unterschreitung
	// des Zahlenbereichs. Die vorzeichenlose Addition implementiert bei diesem
	// MCU eine Modulo-2^32-Semantik.
	mov		r6, #0
	
	// `r7` enthält eine Maske mit der aktiven Konfiguration des Zählers. Es
	// sind folgende Optionen vefügbar:
	// 		r7[0] = 1 -> Der Zähler ist aktiv.
	//		r7[1] = 1 -> Der Zähler zählt abwärts.
	mov		r7, #0
	
	// Falls einer der beiden Taster getriggert wurde, dann enthält `r8` den
	// Zeitstempel für SW1 und `r9` den Zeitstempel für SW2.
	mov 	r8, #0
	mov		r9, #0
	
	// Gib initialen Zählerzustand aus.
	mov		r0, r6
	bl		uart_putByte
	mov		r0, #NEWLINE
	bl		uart_putChar
	tst		r7, #1
	ite		eq
	ldreq	r0, =string_status_stop
	ldrne	r0, =string_status_start
	bl		uart_putString

loop_main:
	bl		poll_sw1
	
	// Prüfe ob eine Sekunde abgelaufen ist. Korrigiere die Zeitstempel für SW1
	// und SW2 entsprechend.
	ldrb	r0, [r5]
	cbz		r0, handle_input
	mov		r0, #0
	strb	r0, [r5]

	// Prüfe, ob der Zähler gestoppt ist oder läuft.
	tst		r7, #1
	beq		handle_input
	
	// Der Zähler läuft: Prüfe die Zählrichtung.
	tst		r7, #2
	ite		eq
	
	// Berechne neuen Zählerstand.
	addeq	r6, r6, #1
	subne	r6, r6, #1
	
	// Aktualisiere die LEDs.
	ldr		r0, [r4]
	eor		r1, r6, #COMPLEMENT
	
	// Setze LED_E1.
	bfi		r0, r1, #11, #1
	lsr		r1, r1, #1
	
	// Setze LED_E2.
	bfi		r0, r1, #28, #1
	lsr		r1, r1, #1
	
	// Setze LED_E3.
	bfi		r0, r1, #29, #1
	lsr		r1, r1, #1
	
	// Setze LED_E4.
	bfi		r0, r1, #10, #1
	str		r0, [r4]
	
	// Gib den Zählerstand aus.
	mov		r0, r6
	bl		uart_putByte
	mov		r0, #NEWLINE
	bl		uart_putChar
	
handle_input:
	// e) Erweitere das Programm so, dass durch Benutzereingaben die Zähler-
	// konfiguration verändert werden kann.
	//
	// Prüfe ob eine Nutzereingabe vorliegt.
	bl		uart_charPresent
	cbz		r0, check_sw1
	
	// Eine Eingabe liegt vor.
	bl		uart_getChar
	
	// Wurde '+' gedrückt?
	teq		r0, #CHAR_PLUS
	beq		handle_plus
	
	// Wurde '-' gedrückt?
	teq		r0, #CHAR_MINUS
	beq		handle_minus
	
	// Wurde 's' gedrückt?
	teq		r0, #CHAR_S
	bne		check_sw1

handle_s:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_s
	bl		uart_putString
	
	// Stoppe, bzw. starte den Zähler.
	eor		r7, r7, #1
	tst		r7, #1
	ite		eq
	ldreq	r0, =string_status_stop
	ldrne	r0, =string_status_start
	
	// Gib aus, ob Zähler gestartet oder gestoppt wurde.
	bl		uart_putString
	b		check_sw1

handle_plus:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_plus
	bl		uart_putString
	
	// Setze Zählrichtung auf aufwärts.
	bic		r7, r7, #2
	
	// Gib neue Zählrichtung aus.
	ldr		r0, =string_status_up
	bl		uart_putString
	b		check_sw1

handle_minus:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_minus
	bl		uart_putString
	
	// Setze Zählrichtung auf abwärts.
	orr		r7, r7, #2
	
	// Gib neue Zählrichtung aus.
	ldr		r0, =string_status_down
	bl		uart_putString

check_sw1:
	bl		pit3_getval
	mov		r10, r0
	
	// Prüfe ob gerade eine Messung für SW1 aktiv ist.
	ldr		r11, =MOD_SW1
	ldr		r0, [r11]
	teq		r0, #0

	// Es ist momentan keine Messung aktiv.
	beq		reset_sw1
	
	// Es ist momentan eine Messung aktiv: Prüfe, ob SW1 noch gedrückt ist.
	ldr		r0, =GPIOA_PDIR
	ldr		r1, [r0]
	tst		r1, #PIN19			// Liegt der Eingang für SW1 auf Masse?
	
	// SW1 wurde zwischenzeitlich wieder gelöst.
	bne		reset_sw1
	
	// Der Schalter ist weiterhin gedrückt
	ldr		r0, =(5 * MS)
	add		r0, r10, r0
	cmp		r8, r0				// Sind bereits 5ms vergangen?
	blt		check_sw2
	
	// Es sind bereits 5ms vergangen.
	ldr		r0, =string_input_sw1
	bl		uart_putString
	
	// d) Ergänze das Programm so, dass durch Tastendruck die Zähler-
	// konfiguration verändert werden kann.
	eor		r7, r7, #2			// Invertiere das Bit für die Zählrichtung.
	tst		r7, #2
	ite		eq
	ldreq	r0, =string_status_up
	ldrne	r0, =string_status_down
	bl		uart_putString
	
reset_sw1:
	// Es ist eines der folgenden Szenarien passiert:
	//		i) 	 Es ist momentan keine Messung für SW1 aktiv,
	//		ii)  SW1 wurde seit Begin der Messung wieder gelöst oder
	//		iii) SW1 ist 5ms lang betätigt gewesen.
	mov		r0, #0
	str		r0, [r11]			// Setze das SW1-Bit zurück.
	mov		r8, r10				// Setze einen neuen Zeitstempel für SW1.

check_sw2:
	bl		pit3_getval
	mov		r10, r0
	
	// Prüfe ob gerade eine Messung für SW2 aktiv ist.
	ldr		r11, =MOD_SW2
	ldr		r0, [r11]
	teq		r0, #0

	// Es ist momentan keine Messung aktiv.
	beq		reset_sw2
	
	// Es ist momentan eine Messung aktiv: Prüfe, ob SW2 noch gedrückt ist.
	ldr		r0, =GPIOE_PDIR
	ldr		r1, [r0]
	tst		r1, #PIN26			// Liegt der Eingang für SW2 auf Masse?
	
	// SW2 wurde zwischenzeitlich wieder gelöst.
	bne		reset_sw2
	
	// SW2 ist weiterhin gedrückt
	ldr		r0, =(5 * MS)
	add		r0, r10, r0
	cmp		r9, r0				// Sind bereits 5ms vergangen?
	blt		loop_main
	
	// Es sind bereits 5ms vergangen.
	ldr		r0, =string_input_sw2
	bl		uart_putString
	eor		r7, r7, #1			// Invertiere das Bit für Start und Stopp.
	tst		r7, #1
	ite		eq
	ldreq	r0, =string_status_stop
	ldrne	r0, =string_status_start
	bl		uart_putString
	
reset_sw2:
	// Es ist eines der folgenden Szenarien passiert:
	//		i) 	 Es ist momentan keine Messung für SW2 aktiv,
	//		ii)  SW2 wurde seit Begin der Messung wieder gelöst oder
	//		iii) SW2 ist 5ms lang betätigt gewesen.
	mov		r0, #0
	str		r0, [r11]			// Setze das SW2-Bit zurück.
	mov		r9, r10				// Setze einen neuen Zeitstempel für SW2.
	b 		loop_main

/*
* c) Schreibe jeweils ein nicht blockierendes Unterprogramm zur Abfrage der
* Taster.
*
* Unterprogramm (poll_sw1): Fragt den Status von PIN 19 auf PORTA ab, welcher
* ein Betätigen des Schalters SW1 signalisiert.
*
* Da ein Halten des Schalters von wenigstens 5ms für die Erkennung einer
* Betätigung des Schalters vorausgesetzt wird, würde auch eine Abfrage des
* des Levels von PIN 19 im Eingaberegister von GPIO Port A ausreichen. In der
* Aufgabestellung wurde jedoch gesagt, dass eine fallende Flanke eines Tasten-
* drucks erkannt werden soll. Dies wird durch die ISF von Port A angezeigt, der
* entsprechend konfiguriert wurde. Die Anzeige über die ISF des Pins hat den
* Vorteil, dass der Beginn des Tastendrucks wohl definiert ist und eigenständig
* quittiert werden kann. Damit lässt sich auch verhindern, dass Tastendruck,
* der länger, als 5ms dauert, als mehrer Tastendrucke erkannt würde.
*
* Die Interruptanfrage von Port A wird jedoch nicht an den Prozessor weiterge-
* leitet, wodurch der Bedingung der Aufgabenstellung Rechnung getragen wird,
* dass SW1 ohne Verwendung von Interrupts realisiert werden soll. 
*/
.thumb_func
poll_sw1:
	ldr		r1, =PORTA_PCR19_ISF
	ldr		r0, [r1]
	teq		r0, #1
	ittt	eq
	
	// Starte eine Messung (setze das SW1-Bit in `mod`).
	ldreq	r2, =MOD_SW1
	streq	r0, [r2]
	
	// Quittiere die negative Flanke auf dem Eingang von SW2.
	streq	r0, [r1]
	bx		lr
	
/*
* Interrupt Service Routine (handle_pit1_irq): Behandelt eine Unterbrechung des
* PIT Moduls auf Kanal 1 bei Ablaufen des Zählers. 
*/
.thumb_func
handle_pit1_irq:
	ldr 	r1, =is_pit1_lapsed
	mov		r0, #1
	strb	r0, [r1]
	
	// Quittiere die Unterbrechungsanforderung am PIT Modul.	
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	bx		lr

/*
* Interrupt Service Routine (handle_porte_irq): Behandelt eine Unterbrechung
* durch PORTE auf PIN 26 durch Betätigen des SW2-Tasters.
*/
.thumb_func
handle_porte_irq:
	ldr		r1, =PORTE_PCR26_ISF
	ldr		r0, [r1]
	teq		r0, #1
	ittt	eq
	
	// Starte eine Messung (setze das SW2-Bit in `mod`).
	ldreq	r2, =MOD_SW2
	streq	r0, [r2]
	
	// Quittiere die negative Flanke auf dem Eingang von SW2.
	streq	r0, [r1]
	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
mod:
	.byte 0x00
	
is_pit1_lapsed:
	.byte 0x00
	
string_input_s:
	.asciz "Eingabe: s\n"
	
string_status_start:
	.asciz "Zaehler wurde gestartet.\n"
	
string_status_stop:
	.asciz "Zaehler wurde angehalten.\n"
	
string_input_plus:
	.asciz "Eingabe: +\n"
	
string_status_up:
	.asciz "Zaehler zaehlt aufwaerts.\n"
	
string_input_minus:
	.asciz "Eingabe: -\n"
	
string_status_down:
	.asciz "Zaehler zaehlt abwaerts.\n"

string_input_sw1:
	.asciz "Eingabe: Schwarzer Taster betaetigt.\n"
	
string_input_sw2:
	.asciz "Eingabe: Gruener Taster betaetigt.\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ MSB_16BIT,			(1 << 15)
.equ SEC, 				25000000
.equ MS,				SEC / 1000
.equ MVOLT_LO,			0
.equ MVOLT_HI,			3300
.equ NL,				'\n'	// Newline
.equ WS,				' '		// Whitespace
.equ CENTI,				100		// Teiler um die Ausgabe des Spannungsbereichs in mV zu ermöglichen.
.equ MAX_BYTE,			0xff

.equ CHAR_S,			's'
.equ CHAR_0,			'0'
.equ CHAR_1,			'1'
.equ CHAR_2,			'2'
.equ CHAR_3,			'3'

.equ LEVELS_8BIT,		0x8		// 8-stufiger Spannungsbereich.
.equ LEVELS_10BIT,		0xa		// 10-stufiger Spannungsbereich.
.equ LEVELS_12BIT,		0xc		// 12-stufiger Spannungsbereich.
.equ LEVELS_16BIT,		0x10	// 16-stufiger Spannungsbereich.

.equ UPPER_8BIT,		0x100	// Maximaler Messwert (+1) bei 8 Bit Genauigkeit.
.equ UPPER_10BIT,		0x400	// Maximaler Messwert (+1) bei 10 Bit Genauigkeit.
.equ UPPER_12BIT,		0x1000	// Maximaler Messwert (+1) bei 12 Bit Genauigkeit.
.equ UPPER_16BIT,		0x10000	// Maximaler Messwert (+1) bei 16 Bit Genauigkeit.

// Interrupt-Vektor-Konstanten
.equ IVT,				0x1ffffe00			// Basisadresse der IVT.
.equ IVT_PIT,			IVT + 0x40 + (69 << 2)	// IV-Tabellenindex für IRQ 69 (PIT).
.equ IRQ_PIT,			(1 << (69 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 69 (PIT).

// Nested Interrupt Controller (NVIC) Registeradressen
.equ NVIC_ISER2,		0xe000e100 + 2 << 2
.equ NVIC_ICPR2,		0xe000e280 + 2 << 2

// Port Control and Interrupts (PORT) Registeradressen
.equ PORTA_PCR10,		0x40049028
.equ PORTA_PCR11,		0x4004902c
.equ PORTA_PCR28,		0x40049070
.equ PORTA_PCR29,		0x40049074

// Analog-to-Digital Converter 1 (ADC1) Registeradressen
.equ ADC1_SC1A,			0x400bb000
.equ ADC1_CFG1,			0x400bb008
.equ ADC1_CFG2,			0x400bb00c
.equ ADC1_RA,			0x400bb010
.equ ADC1_SC2,			0x400bb020
.equ ADC1_SC3,			0x400bb024
.equ ADC1_PG,			0x400bb02c
.equ ADC1_CLPS,			0x400bb038
.equ ADC1_CLP4,			0x400bb03c
.equ ADC1_CLP3,			0x400bb040
.equ ADC1_CLP2,			0x400bb044
.equ ADC1_CLP1,			0x400bb048
.equ ADC1_CLP0,			0x400bb04c

// System Integration Module (SIM) Registeradressen
.equ SIM_SCGC3,			0x40048030
.equ SIM_SCGC5,			0x40048038
.equ SIM_SCGC6,			0x4004803c

// Periodic Interrupt Timer (PIT) Registeradressen
.equ PIT_MCR,			0x40037000
.equ PIT_LDVAL1,		0x40037110
.equ PIT_TCTRL1,		0x40037118
.equ PIT_TFLG1,			0x4003711c

// General-Purpose I/O (GPIO) Registeradressen
.equ GPIOA_PDOR,		0x400ff000
.equ GPIOA_PDIR,		0x400ff010
.equ GPIOA_PDDR,		0x400ff014

// Steuerwörter
.equ ADC1,				(1 << 27)		// Aktiviere Takt für ADC1.
.equ AD20,				(20)			// Wähle AD20 als ADC-Eingabekanal.
.equ ADCH,				(31)			// Deaktiviere ADC1a.
.equ AIEN,				(1 << 6)		// Erzeuge eine Unterbrechung, wenn COCO gesetzt wird.
.equ COCO,				(1 << 7)		// Konvertierung ist beendet.
.equ MODE10,			(2 << 2)		// Setze die ADC-Auflösung auf 10 Bit.
.equ MODE12,			(1 << 2)		// Setze die ADC-Auflösung auf 12 Bit.
.equ MODE16,			(3 << 2)		// Setze die ADC-Auflösung auf 16 Bit.
.equ ADIV8,				(3 << 5)		// Teile den ADC-Eingabetakt durch 8.
.equ ADCT,				(1 << 7)		// Konvertierung läuft.
.equ AVGS16,			(2)				// Mittle das Konvertierungsergebnis über 16 Messungswerte.
.equ AVGE,				(1 << 2)		// Aktiviere hardwareseitige Mittelwertbildung für ADC1.
.equ ADCO,				(1 << 3)		// Aktiviere kontinuierliche Wandlung.
.equ CALF,				(1 << 6) 		// Kalibrierung ist fehlgeschlagen.
.equ CAL,				(1 << 7)		// Starte die Kalibrierungssequenz.
.equ PORTA,				(1 << 9)		// Aktiviere Takt für PORTA.
.equ PIT,				(1 << 23)		// Aktiviere Takt für PIT in SIM.
.equ GPIO,				(1 << 8)		// Setze MUX auf GPIO.
.equ PIN10,				(1 << 10)		// LED 4.
.equ PIN11,				(1 << 11)		// LED 1.
.equ PIN28,				(1 << 28)		// LED 2.
.equ PIN29,				(1 << 29)		// LED 3.
.equ TEN,				(1)				// Aktiviere den ausgewählten PIT-Kanal.
.equ TIE,				(1 << 1)		// Aktiviere Interrups für den ausgewählten PIT-Kanal.

// Bitband-Alias Adressen
__BBREG GPIOA_PDOR_PIN10,	GPIOA_PDOR, 10
__BBREG GPIOA_PDOR_PIN11,	GPIOA_PDOR, 11
__BBREG GPIOA_PDOR_PIN28,	GPIOA_PDOR, 28
__BBREG GPIOA_PDOR_PIN29,	GPIOA_PDOR, 29

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	// Aktiviere Takt für ADC1.
	ldr		r0, =SIM_SCGC3
	ldr		r1, [r0]
	orr		r1, r1, #ADC1
	str		r1, [r0]
	
	// Aktiviere Takt für PORTA.
	ldr		r0, =SIM_SCGC5
	ldr		r1, [r0]
	orr		r1, r1, #PORTA
	str		r1, [r0]
	
	// Aktiviere Takt für PIT.
	ldr		r0, =SIM_SCGC6
	ldr		r1, [r0]
	orr		r1, r1, #PIT
	str		r1, [r0]
	
	// Kalibriere ADC1.
	bl		adc1_calibrate
	cmp		r0, #0
	bne		calibrate_fail
	ldr		r0, =string_calibrate_success
	bl		uart_putString
	
	// Setze Interrupt-Vektor zu PIT1.
	ldr		r0, =IVT_PIT
	ldr		r1, =handle_pit1_irq
	str		r1, [r0]
	
	// Lösche anhängende Interrupts für PIT.
	mov		r1, #IRQ_PIT
	ldr		r0, =NVIC_ICPR2
	str		r1, [r0]
	
	// Aktiviere Interrupts für PIT.
	ldr		r0, =NVIC_ISER2
	str		r1, [r0]
	
	// Aktiviere die PITs und deaktiviere den Freeze-Modus.
	ldr		r0, =PIT_MCR
	mov		r1, #0x0
	str		r1, [r0]
	
	// Initialisiere Zähler auf eine Sekunde.
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =SEC
	str		r1, [r0]
	
	// Lösche eventuell bereits anhängende Interrupts für PIT1.
	ldr		r0, =PIT_TFLG1
	mov		r1, #0
	str		r1, [r0]
	
	// Aktiviere den PIT1 und dessen Interrupts.
	ldr		r0, =PIT_TCTRL1
	mov		r1, #(TIE | TEN)
	str		r1, [r0]
	
	// Setze die Ports der LEDs in GPIO-Modus.
	mov		r1, #GPIO
	ldr		r0, =PORTA_PCR11	// LED 1
	str		r1, [r0]
	ldr		r0, =PORTA_PCR28	// LED 2
	str		r1, [r0]
	ldr		r0, =PORTA_PCR29	// LED 3
	str		r1, [r0]
	ldr		r0, =PORTA_PCR10	// LED 4
	str		r1, [r0]
	
	// Deaktiviere die LEDs und schalter ihre GPIO-Pins auf Ausgang.
	ldr		r1, =(PIN10 | PIN11 | PIN28 | PIN29)
	ldr		r0, =GPIOA_PDOR
	str		r1, [r0]
	ldr		r0, =GPIOA_PDDR
	str		r1, [r0]
	
	// Starte Wandlung. `r4` speichert den momentanen Zustand des ADCH-Feldes
	// in ADC1_SC1a.
	ldr		r0, =ADC1_SC1A
	mov		r4, #AD20
	str		r4, [r0]
	
	// `r5` beinhält gegenwärtige Zahl an Stufen des Spannungsbereichs. `r6`
	// speichert die Obergrenze möglicher Messwerte für die gewählte Auflösung.
	mov		r5, #LEVELS_16BIT
	mov		r6, #UPPER_16BIT
	
loop_main:
	// Prüfe, ob Wandlungen momentan gestoppt sind.
	teq		r4, #ADCH
	beq		handle_input
	
	// Prüfe, ob bereits eine Sekunde vergangen ist.
	ldr		r0, =is_pit1_lapsed
	ldrb	r1, [r0]
	teq		r1, #0
	beq		handle_input
	
	// Quittiere PIT1.
	mov		r1, #0
	strb	r1, [r0]
	
	// Lies Messung der AD-Wandlung.
	ldr		r1, =ADC1_RA
	ldrh	r7, [r1]
	
	// Berechne Stufe des Spannungsbereichs (im Dreisatz).
	mul		r8, r7, r5
	udiv	r8, r8, r6
	
	// Gib Stufe des aktuellen Spannungsbereichs über die LEDs aus.
	mov		r1, #1
	
	// Setze LED_E1.
	ldr		r0, =GPIOA_PDOR_PIN11
	eor		r2, r1, r8			// Lege Stufenbit 0 auf LED 1.	
	str		r2, [r0]
	
	// Setze LED_E2.
	ldr		r0, =GPIOA_PDOR_PIN28
	eor		r2, r1, r8, lsr #1	// Lege Stufenbit 1 auf LED 2.
	str		r2, [r0]
	
	// Setze LED_E3.
	ldr		r0, =GPIOA_PDOR_PIN29
	eor		r2, r1, r8, lsr #2	// Lege Stufenbit 2 auf LED 3.
	str		r2, [r0]
	
	// Setze LED_E4.
	ldr		r0, =GPIOA_PDOR_PIN10
	eor		r2, r1, r8, lsr #3	// Lege Stufenbit 3 auf LED 4.
	str		r2, [r0]
	
	// Zeige den vom ADC1 ermittelten Messwert an.
	ldr		r0, =string_hex_prefix
	bl		uart_putString
	mov		r0, r7
	bl		uart_putInt16
	mov		r0, #WS
	bl		uart_putChar
	
	// Zeige den unteren Grenzwert des aktuellen Spannungsbereichs an.
	ldr		r12, =MVOLT_HI
	mul		r0, r8, r12
	udiv	r0, r0, r5
	bl		put_mV_base10
	ldr		r0, =string_range_infix
	bl		uart_putString
	
	// Zeige den oberen Grenzwert des aktuellen Spannungsbereichs an.
	add		r9, r8, #1			// Die nächste Stufe über dem aktuellen Spannungsbereich.
	mul		r0, r9, r12
	udiv	r0, r0, r5
	bl		put_mV_base10
	ldr		r0, =string_voltage_infix
	bl		uart_putString
	
	// Gib die Stufe des aktuellen Spannungsbereichs aus.
	mov		r0, r8
	bl		uart_putByteBase10
	ldr		r0, =string_parens_postfix
	bl		uart_putString
	
handle_input:
	// Prüfe ob eine Nutzereingabe vorliegt.
	bl		uart_charPresent
	cmp		r0, #0
	beq		loop_main
	
	// Nutzereingabe liegt vor.
	bl		uart_getChar
	
	// Wurde 's' gedrückt?
	teq		r0, #CHAR_S
	beq		handle_s
	
	// Änderung der Genauigkeit des ADC1 soll nur im Stopp-Modus möglich sein.
	teq		r4, #ADCH
	bne		loop_main
	
	// Wurde '0' gedrückt?
	teq		r0, #CHAR_0
	beq		handle_0
	
	// Wurde '1' gedrückt?
	teq		r0, #CHAR_1
	beq		handle_1
	
	// Wurde '2' gedrückt?
	teq		r0, #CHAR_2
	beq		handle_2
	
	// Wurde '3' gedrückt?
	teq		r0, #CHAR_3
	bne		loop_main

handle_3:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_3
	bl		uart_putString
	
	// Setze die Auflösung der AD-Wandlung auf 16 Bit.
	ldr		r1, =ADC1_CFG1
	ldr		r0, [r1]
	bfc		r0, #2, #2
	orr		r0, r0, #MODE16
	str		r0, [r1]
	
	// Setze die Zahl der Stufen des Spannungsbereichs auf 16 und die
	// Obergrenze des Messbereichs.
	mov		r5, #LEVELS_16BIT
	mov		r6, #UPPER_16BIT

	// Gib die geänderte Genauigkeit der AD-Wandlung aus.
	ldr		r0, =string_status_16bit
	bl		uart_putString
	b		loop_main

handle_2:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_2
	bl		uart_putString
	
	// Setze die Auflösung der AD-Wandlung auf 12 Bit.
	ldr		r1, =ADC1_CFG1
	ldr		r0, [r1]
	bfc		r0, #2, #2
	orr		r0, r0, #MODE12
	str		r0, [r1]
	
	// Setze die Zahl der Stufen des Spannungsbereichs auf 12 und die
	// Obergrenze des Messbereichs.
	mov		r5, #LEVELS_12BIT
	mov		r6, #UPPER_12BIT

	// Gib die geänderte Genauigkeit der AD-Wandlung aus.
	ldr		r0, =string_status_12bit
	bl		uart_putString
	b		loop_main

handle_1:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_1
	bl		uart_putString
	
	// Setze die Auflösung der AD-Wandlung auf 10 Bit.
	ldr		r1, =ADC1_CFG1
	ldr		r0, [r1]
	bfc		r0, #2, #2
	orr		r0, r0, #MODE10
	str		r0, [r1]
	
	// Setze die Zahl der Stufen des Spannungsbereichs auf 10 und die
	// Obergrenze des Messbereichs.
	mov		r5, #LEVELS_10BIT
	mov		r6, #UPPER_10BIT

	// Gib die geänderte Genauigkeit der AD-Wandlung aus.
	ldr		r0, =string_status_10bit
	bl		uart_putString
	b		loop_main
	
handle_0:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_0
	bl		uart_putString
	
	// Setze die Auflösung der AD-Wandlung auf 8 Bit.
	ldr		r0, =ADC1_CFG1
	ldr		r1, [r0]
	bfc		r1, #2, #2
	str		r1, [r0]
	
	// Setze die Zahl der Stufen des Spannungsbereichs auf 8 und die
	// Obergrenze des Messbereichs.
	mov		r5, #LEVELS_8BIT
	mov		r6, #UPPER_8BIT

	// Gib die geänderte Genauigkeit der AD-Wandlung aus.
	ldr		r0, =string_status_8bit
	bl		uart_putString
	b		loop_main
	
handle_s:
	// Gib Benutzereingabe zurück.
	ldr		r0, =string_input_s
	bl		uart_putString
	
	// Prüfe, ob Wandlungen gegenwärtig gestoppt sind.
	teq		r4, #ADCH
	itete	eq
	moveq	r4, #AD20			// Starte neue Wandlung auf AD20 (Potentiometer).
	movne	r4, #ADCH			// Stoppe Wandlung und Ausgabe.
	ldreq	r0, =string_status_start
	ldrne	r0, =string_status_stop
	
	// Setze den Eingabekanal von ADC1_SC1a.
	ldr		r1, =ADC1_SC1A
	ldr		r2, [r1]
	bfi		r2, r4, #0, #5
	str		r2, [r1]
	
	// Gib aus, ob AD-Wandlungen gestoppt oder gestartet wurden.
	bl		uart_putString
	b		loop_main

calibrate_fail:
	ldr		r0, =string_calibrate_fail
	bl		uart_putString
	
loop_fail:
	wfi
	b		loop_fail
	
/*
* Unterprogramm (adc1_calibrate): Führt die initiale Kalibrierung des ADC1-
* Moduls durch. Gibt Null in `r0` zurück, falls die Kalibrierung erfolgreich
* war. Ist `r0` ungleich Null, dann ist bei der Kalibrierung ein Fehler auf-
* getreten.
*
* Die Kalibrierung findet mit den Werten statt, die später auch für die Messung
* verwendet werden. Die Kalibrierung findet mit einer Auflösung von 16 Bit
* statt und nutzt den Bustakt heruntergeteilt auf 3.125Mhz als Taktquelle. Ge-
* mittelt wird über 16 Messwerte. Nach der Kalibrierung ist ADC1 im Software-
* triggermodus mit kontinuerlicher Wandlung. Die Wandlung kann dann angestoßen
* werden, durch Beschreiben von ADC1_SC1n.
*/	
.thumb_func
adc1_calibrate:
	// Wähle Bustakt als Taktquelle, 16-bit vorzeichenlose Auflösung und teile
	// den Bustakt durch 8 (von 25Mhz auf 3.125Mhz).
	ldr		r1, =ADC1_CFG1
	ldr		r0, [r1]
	orr		r0, r0, #(MODE16 | ADIV8)
	str		r0, [r1]
	
	// Setze Hochgeschwindigkeitskonfiguration und langer Wandlungsmodus auf
	// Standardwerte zurück.
	ldr		r1, =ADC1_CFG2
	mov		r0, #0
	str		r0, [r1]
	
	// Wähle softwaregesteuerter Auslöser und Standardreferenzspannung. De-
	// aktiviere DMA und Vergleicher.
	ldr		r1, =ADC1_SC2
	mov		r0, #0
	str		r0, [r1]
	
	// Aktiviere hardwareseitige Mittelwertbildung über 16 Messwerte und
	// kontinuierliche Wandlung. Starte die Autokalibrierung.
	ldr		r1, =ADC1_SC3
	ldr		r0, [r1]
	orr		r0, r0, #(AVGS16 | AVGE | ADCO | CAL)
	str		r0, [r1]
	
busy_wait:
	// Warte, bis die Autokalibrierung abgeschlossen ist.
	ldr		r0, [r1]
	tst		r0, #CAL
	bne		busy_wait
	
	// Berechne Korrekturwert für positiven Gain (negativer Gain wird nur im
	// Differenzialmodus benötigt).
	ldr		r1, =ADC1_CLP0
	ldr		r2, [r1]
	ldr		r1, =ADC1_CLP1
	ldr		r3, [r1]
	add		r2, r2, r3
	ldr		r1, =ADC1_CLP2
	ldr		r3, [r1]
	add		r2, r2, r3
	ldr		r1, =ADC1_CLP3
	ldr		r3, [r1]
	add		r2, r2, r3
	ldr		r1, =ADC1_CLP4
	ldr		r3, [r1]
	add 	r2, r2, r3
	ldr		r1, =ADC1_CLPS
	ldr		r3, [r1]
	add		r2, r2, r3
	lsr		r2, r2, #1
	orr		r2, r2, #MSB_16BIT
	ldr		r1, =ADC1_PG
	strh	r2, [r1]
	
	// Gib zurück, ob die Autokalibrierung erfolgreich war (d.h. den CALF-
	// Wert).
	ubfx	r0, r0, #6, #1
	bx		lr

/*
* Unterprogramm (put_mV_base10): Gibt eine Spannung im Bereich 0 - 3300mV als
* Dezimalzahl ohne führende Nullen aus. 
*/	
.thumb_func
put_mV_base10:
	push	{r4, lr}
	cmp		r0, #MAX_BYTE
	bls		put_mV_base10_single
	
	// Gib erst die oberen zwei Ziffern aus.
	mov		r1, #CENTI
	udiv	r2, r0, r1
	mul		r3, r2, r1
	sub		r4, r0, r3
	mov		r0, r2
	bl		uart_putByteBase10
	
	// Gib dann die unteren zwei Ziffern aus.
	mov		r0, r4
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	b		cleanup
	
put_mV_base10_single:
	bl		uart_putByteBase10
	
cleanup:
	pop		{r4, pc}
	
	
/*
* Interrupt Service Routine (handle_pit1_irq): Behandelt eine Unterbrechung des
* PIT Moduls auf Kanal 1 bei Ablaufen des Zählers. 
*/
.thumb_func
handle_pit1_irq:
	ldr 	r1, =is_pit1_lapsed
	mov		r0, #1
	strb	r0, [r1]
	
	// Quittiere die Unterbrechungsanforderung am PIT Modul.	
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
is_pit1_lapsed:
	.byte 0x00
	
string_calibrate_success:
	.asciz "ADC-Kalibrierung erfolgreich!\n"
	
string_input_3:
	.asciz "Eingabe: 3\n"
	
string_status_16bit:
	.asciz "Aufloesung: 16 Bit (16 Stufen)\n"
	
string_input_2:
	.asciz "Eingabe: 2\n"
	
string_status_12bit:
	.asciz "Aufloesung: 12 Bit (12 Stufen)\n"
	
string_input_1:
	.asciz "Eingabe: 1\n"
	
string_status_10bit:
	.asciz "Aufloesung: 10 Bit (10 Stufen)\n"

string_input_0:
	.asciz "Eingabe: 0\n"
	
string_status_8bit:
	.asciz "Aufloesung: 8 Bit (8 Stufen)\n"
	
string_input_s:
	.asciz "Eingabe: s\n"
	
string_status_start:
	.asciz "Wandlung wurde gestartet.\n"
	
string_status_stop:
	.asciz "Wandlung wurde gestoppt.\n"

string_calibrate_fail:
	.asciz "ADC-Kalibrierung fehlgeschlagen!\n"

string_hex_prefix:
	.asciz "0x"
	
string_range_infix:
	.asciz " - "
	
string_voltage_infix:
	.asciz " mV (Stufe "

string_parens_postfix:
	.asciz ")\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SEC, 				25000000
.equ US,				SEC / 1000000
.equ MAX_RETRIES,		10
.equ BYTE,				8
.equ COMMA,				','
.equ HUNDRED,			100
.equ HALF,				5000
.equ QUARTER,			2500
.equ EIGHTH,			1250
.equ SIXTEENTH,			625
.equ BIT7,				128
.equ BIT6,				64
.equ BIT5,				32
.equ BIT4,				16

// Port Control and Interrupts (PORT) Registeradressen
.equ PORTD_PCR8,		0x4004c020
.equ PORTD_PCR9,		0x4004c024

// System Integration Module (SIM) Registeradressen
.equ SIM_SCGC4,			0x40048034
.equ SIM_SCGC5,			0x40048038
.equ SIM_SCGC6,			0x4004803c

// Periodic Interrupt Timer (PIT) Registeradressen
.equ PIT_MCR,			0x40037000
.equ PIT_LDVAL1,		0x40037110
.equ PIT_TCTRL1,		0x40037118
.equ PIT_TFLG1,			0x4003711c

// Inter-Integrated Circuit (I2C) Registeradressen
.equ I2C0_A1,			0x40066000
.equ I2C0_F,			0x40066001
.equ I2C0_C1,			0x40066002
.equ I2C0_S,			0x40066003
.equ I2C0_D,			0x40066004
.equ I2C0_C2,			0x40066005
.equ I2C0_FLT,			0x40066006
.equ I2C0_RA,			0x40066007
.equ I2C0_SMB,			0x40066008
.equ I2C0_A2,			0x40066009
.equ I2C0_SLTH,			0x4006600a
.equ I2C0_SLTL,			0x4006600b

// General-Purpose I/O (GPIO) Registeradressen
.equ GPIOD_PDOR,		0x400ff0c0
.equ GPIOD_PDIR,		0x400ff0d0
.equ GPIOD_PDDR,		0x400ff0d4

// DS75 Adressen und Konstanten.
.equ WADDR,				0x90			// DS75-Schreibadresse.
.equ RADDR,				0x91			// DS75-Leseadresse.
.equ TEMP,				0
.equ CONF,				1
.equ THYST,				2
.equ TOS,				3
.equ RES12,				(11 << 5)		// Selektiere 12-bit Temperaturmessgenauigkeit.
.equ OSHI,				( 1 << 2)		// Selektiere aktiv-hoch Thermostatausgang.

// Steuerwörter
.equ PIN8,				(1 << 8)
.equ PIN9,				(1 << 9)
.equ MUX_ALT_GPIO,		(1 << 8)
.equ MUX_ALT_I2C,		(2 << 8)
.equ TEN,				(1)
.equ ICR,				(0x12)
.equ IICEN,				(1 << 7)		// Aktiviere I2C-Modul.
.equ IICIE,				(1 << 6)		// Aktiviere I2C-Unterbrechungen.
.equ MST,				(1 << 5)		// Selektiere Master-Modus.
.equ TX,				(1 << 4)		// Selektiere Sender-Modus.
.equ TXAK,				(1 << 3)		// Aktiviere I2C-Empfangsbestätigung.
.equ RSTA,				(1 << 2)		// Führe einen Wiederholungsstart aus.
.equ IICIF,				(1 << 1)		// Ist eine I2C-Unterbrechungsanforderung anhängend.
.equ RXAK,				(1)				// Ist eine ACK-Bestätigung nach einem I2C-Transfer ausgeblieben.

// Bitband-Alias Adressen
__BBREG SIM_SCGC4_I2C0,		SIM_SCGC4, 6
__BBREG SIM_SCGC5_PORTD, 	SIM_SCGC5, 12
__BBREG SIM_SCGC6_PIT, 		SIM_SCGC6, 23

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl		uart_init
	bl		pit1_init
	bl		i2c_init
	cbnz	r0, fail
	
	ldr		r4, =is_i2c_transfer_failed
	
	// Konfiguriere den DS75 mit 12-bit Auflösung.
	mov		r0, #CONF
	mov		r1, #RES12
	bl		i2c_putByte
	ldrb	r1, [r4]
	cbnz	r1, fail
	
	// Lies die Temparatur aus dem DS75 aus.
	mov		r0, #TEMP
	bl		i2c_getInt16
	ldrb	r1, [r4]
	cbnz	r1, fail
	mov		r5, r0
	
	// Setze TOS.
	mov		r0, #TOS
	add		r1, r5, #(3 << BYTE)
	bl		i2c_putInt16
	ldrb	r1, [r4]
	cbnz	r1, fail
	
	// Setze THYST.
	mov		r0, #THYST
	add 	r1, r5, #(2 << BYTE)
	bl		i2c_putInt16
	ldrb	r1, [r4]
	cbnz	r1, fail
	
	// Initialisierung erfolgreich abgeschlossen.
	ldr		r0, =string_success
	bl		uart_putString
	
loop_main:
	// Warte eine Sekunde.
	ldr		r0, =SEC
	bl		pit1_delay

	// Lies die Temparatur aus dem DS75 aus.
	mov		r0, #TEMP
	bl		i2c_getInt16
	ldrb	r1, [r4]
	cbnz	r1, fail
	
	// Gib die gemessene Temparatur an den Benutzer zurück.
	bl		uart_putTemp
	
	b		loop_main
	
fail:
	ldr		r0, =string_failed
	bl		uart_putString

end:
	b 		end

/*
* Unterprogramm (uart_putTemp): Gib eine 8.4-bit Temparatur als Dezimalzahl aus.
*
* Die Temparatur wird in `r0` übergeben. 
*/
.thumb_func
uart_putTemp:
	push	{r4, lr}
	mov		r4, r0
	
	// Gib Temparatur als Hexadezimalzahl aus.
	ldr		r0, =string_hex_prefix
	bl		uart_putString
	
	mov		r0, r4
	bl		uart_putInt16
	
	ldr		r0, =string_temp_infix
	bl		uart_putString
	
	// Gib ganzzahligen Teil aus.
	mov		r0, r4, lsr #BYTE
	bl		uart_putByteBase10
	
	mov		r0, #COMMA
	bl		uart_putChar
	
	// Berechne Temperaturwert auf 4 Stellen.
	tst		r4, #BIT7
	ite		ne
	ldrne	r1, =HALF
	moveq	r1, #0
	
	tst		r4, #BIT6
	itt		ne
	ldrne	r2, =QUARTER
	addne	r1, r1, r2
	
	tst		r4, #BIT5
	itt		ne
	ldrne	r2, =EIGHTH
	addne	r1, r1, r2
	
	tst		r4, #BIT4
	itt		ne
	ldrne	r2, =SIXTEENTH
	addne	r1, r1, r2
	
	// Zerlege Bruchteil in zwei zweistellige Zahlen.
	mov		r2, #HUNDRED
	udiv	r0, r1, r2
	mls		r4, r0, r2, r1
	
	// Gib Bruchteil aus.
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	
	mov		r0, r4
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	
	ldr		r0, =string_temp_postfix
	bl		uart_putString
	
	pop		{r4, pc}

/*
* Unterprogramm (pit1_init): Initialisiere PIT-Kanal 1. 
*/		
.thumb_func
pit1_init:
	// Aktiviere Takt für PIT.
	ldr		r0, =SIM_SCGC6_PIT
	mov		r1, #0x1
	str		r1, [r0]
	
	// Aktiviere PIT Modul.
	ldr		r0, =PIT_MCR
	mov		r1, #0
	str		r1, [r0]
	
	bx		lr
	
/*
* Unterprogramm (pit1_delay): Verzögere den Programmablauf.
*
* Die Zahl der Verzögerungszyklen werden in `r0` übergeben. 
*/		
.thumb_func
pit1_delay:
	// Lade Zähler.
	ldr		r1, =PIT_LDVAL1
	str		r0, [r1]
	
	// Setze vorhergehende Unterbrechungen zurück.
	ldr		r0, =PIT_TFLG1
	mov		r2, #1
	str		r2, [r0]
	
	// Aktiviere Zähler (ohne Unterbrechungen).
	ldr		r1, =PIT_TCTRL1
	mov		r2, #TEN
	str		r2, [r1]
	
delay:
	ldr		r2, [r0]
	cmp		r2, #0
	beq		delay
	
	// Deaktiviere Zähler.
	mov		r2, #0
	str		r2, [r1]
	
	bx		lr
	
/*
* Unterprogramm (i2c_init): Initialisiere I2C-Modul 0.
*
* Gibt Null in `r0` zurück, falls Initialisierung erfolgreich war. Ansonsten
* enthält `r0` einen Wert ungleich Null.
*/		
.thumb_func
i2c_init:
	push	{lr}
	
	// Aktiviere Takt für I2C0.
	ldr		r0, =SIM_SCGC4_I2C0
	mov		r1, #1
	str		r1, [r0]
	
	// Aktiviere Takt für Port D.
	ldr		r0, =SIM_SCGC5_PORTD
	mov		r1, #1
	str		r1, [r0]
	
	// Setze I2C Bus zurück.
	bl		ic2_bus_reset
	cbnz	r0, return_init
	
	// Setze I2C Slave-Adresse zurück.
	ldr		r0, =I2C0_A1
	mov		r1, #0
	strb	r1, [r0]
	
	// Wähle 7-bit Adressschema.
	ldr		r0, =I2C0_C2
	strb	r1, [r0]
	
	// Setze SMBus-Modus zurück.
	ldr		r0, =I2C0_SMB
	strb	r1, [r0]
	
	// Setze I2C Busfrequenz.
	ldr		r0, =I2C0_F
	mov		r1, #ICR
	strb	r1, [r0]
	
	// Aktiviere Modul und Unterbrechungen.
	ldr		r0, =I2C0_C1
	mov		r1, #(IICEN | IICIE)
	strb	r1, [r0]
	
	mov		r0, #0

return_init:	
	pop		{pc}
	
/*
* Unterprogramm (ic2_bus_reset): Setze den I2C-Bus zurück.
*
* Gibt Null in `r0` zurück, falls das Zurücksetzen erfolgreich war. Ansonsten
* enthält `r0` einen Wert ungleich Null. 
*/		
.thumb_func
ic2_bus_reset:
	push	{r4-r6, lr}
	
	// Konfiguriere PD8 und PD9 als GPIO.
	mov		r0, #MUX_ALT_GPIO
	ldr		r1, =PORTD_PCR8
	ldr		r2, =PORTD_PCR9
	str		r0, [r1]
	str		r0, [r2]
	
	// Schalte PD8 und PD9 als Ausgänge.
	ldr		r0, =GPIOD_PDDR
	ldr		r2, [r0]
	orr		r2, r2, #(PIN8 | PIN9)
	str		r2, [r0]
	
	ldr		r4, =GPIOD_PDOR
	ldr		r5, =GPIOD_PDIR
	mov		r6, #(MAX_RETRIES + 1)
	
retry_reset:
	subs	r6, r6, #1
	cbz		r6, return_reset

	// Deaktiviere SCL.
	ldr		r1, [r4]
	bic		r1, r1, #PIN8
	str		r1, [r4]
	mov		r0, #(2 * US)
	bl		pit1_delay
	
	// Aktiviere SCL und SDA.
	ldr		r1, [r4]
	orr		r1, r1, #(PIN8 | PIN9)
	str		r1, [r4]
	mov		r0, #(2 * US)
	bl		pit1_delay
	
	// Prüfe, ob Aktivierung erfolgreich war.
	ldr		r1, [r5]
	and		r1, r1, #(PIN8 | PIN9)
	cmp		r1, #(PIN8 | PIN9)
	bne		retry_reset
	
	// Konfiguriere PD8 und PD9 für I2C.
	mov		r0, #MUX_ALT_I2C
	ldr		r1, =PORTD_PCR8
	ldr		r2, =PORTD_PCR9
	str		r0, [r1]
	str		r0, [r2]

return_reset:
	// Gib zurück, ob ein Fehler aufgetreten ist.
	cmp		r6, #0
	ite		eq
	moveq	r0, #1
	movne	r0, #0
	
	pop		{r4-r6, pc}

/*
* Unterprogramm (i2c_busy_wait): Warte auf eine I2C-Unterbrechung.
*
* Gibt Null in `r0` zurück, falls nach der Übertragung ein ACK empfangen wurde.
* Ist bei der Übertragung kein ACK empfangen worden, dann enthält `r0` einen
* Wert ungleich Null.
*/		
.thumb_func
i2c_busy_wait:
	ldr		r0, =I2C0_S
	
wait:
	// Prüfe I2C-Unterbrechungsanforderungen.
	ldrb	r1, [r0]
	tst		r1, #IICIF
	beq		wait

	// Quittiere Anforderung und gib zurück, ob ein ACK empfangen wurde.
	strb	r1, [r0]
	and		r0, r1, #RXAK
	
	bx		lr
	
/*
* Unterprogramm (i2c_start): Sende ein Startsignal als Master auf den I2C-Bus.
*
* Die Slaveadresse wird in `r0` übergeben. Falls die Adressierung erfolgreich
* war und ein ACK empfangen wurde, dann gib Null in `r0` zurück. Anderfalls
* enthält `r0` einen Wert ungleich Null.
*/		
.thumb_func
i2c_start:
	push	{r4-r5, lr}
	mov		r4, r0
	mov		r5, #(MAX_RETRIES + 1)

retry_start:
	subs	r5, r5, #1
	cbz		r5, return_start
	
	// Aktiviere Master-Sendemodus.
	ldr		r1, =I2C0_C1
	ldrb	r2, [r1]
	orr		r2, r2, #(TX | MST)
	strb	r2, [r1]
	
	// Übertrage Slaveadresse.
	ldr		r1, =I2C0_D
	strb	r4, [r1]
	
	// Warte bis Adresse übertragen ist.
	bl		i2c_busy_wait
	cbz		r0, return_start
	
	// Falls Fehler aufgetreten ist, sende Stoppsignal und versuche erneut.
	bl		i2c_stop
	b		retry_start
	
return_start:
	// Gib zurück, ob ein Fehler aufgetreten ist.
	cmp		r5, #0
	it		eq
	moveq	r0, #1
	
	pop		{r4-r5, pc}
	
/*
* Unterprogramm (i2c_repeat_start): Sende ein Repeat-Startsignal als Master auf
* dem I2C-Bus.
*
* Die Slaveadresse wird in `r0` übergeben. Ist die Adressierung erfolgreich und
* es wurde ein ACK empfangen, enthält `r0` Null. Andernfalls enthält `r0` einen
* Wert ungleich Null.
*/		
.thumb_func
i2c_repeat_start:
	push	{r4-r5, lr}
	mov		r4, r0
	mov		r5, #(MAX_RETRIES + 1)

retry_repeat_start:
	subs	r5, r5, #1
	cbz		r5, return_repeat_start
	
	// Aktiviere Repeat-Start-Sendemodus.
	ldr		r1, =I2C0_C1
	ldrb	r2, [r1]
	orr		r2, r2, #(TX | RSTA)
	strb	r2, [r1]
	
	// Übertrage Slaveadresse.
	ldr		r1, =I2C0_D
	strb	r4, [r1]
	
	// Warte bis die Adresse übertragen ist.
	bl		i2c_busy_wait
	cmp		r0, #0
	bne		retry_repeat_start
	
return_repeat_start:
	// Gib zurück, ob ein Fehler aufgetreten ist.
	cmp		r5, #0
	it		eq
	moveq	r0, #1
	
	pop		{r4-r5, pc}
	
/*
* Unterprogramm (i2c_stop): Sende ein Stopsignal auf dem I2C-Bus.
*
* Falls das I2C-Modul vor Aufruf der Routine nicht in Mastermodus versetzt
* wurde, dann wird kein Signal gesendet. Die Routine führt in jedem Fall
* eine Verzögerung von 2us durch.
*/		
.thumb_func
i2c_stop:
	push	{lr}

	// Sende Stoppsignal (hat keinen Effekt, falls `MST` bereits Null ist).
	ldr		r0, =I2C0_C1
	ldrb	r1, [r0]
	bic		r1, r1, #MST
	strb	r1, [r0]
	
	// Warte, bis I2C-Bus wieder Ruhezustand eingenommen hat.
	mov		r0, #(2 * US)
	bl		pit1_delay
	
	pop		{pc}
	
/*
* Unterprogramm (i2c_putPtr): Adressiere ein spezielles Register eines Slaves.
*
* Die Registeradresse wird in `r0` übergeben. Die Routine geht davon aus, dass
* noch keine Slaveadressierung durchgeführt wurde. Sie beginnt mit dem Senden
* eines Startsignals und einem Adresszyklus. Anschließend wird dem Slave die
* Adresse des internen Registers übergeben.
*
* Bei erfolgreicher Adressierung befindet sich das I2C-Modul im Master-Sende-
* Modus. Eine weitere Datenübermittlung kann direkt im Anschluss durchgeführt
* werden. Für einen anschließenden Empfang eines Datums vom Slave, muss zuvor
* ein Repeat-Startsignal mit erneuter Slaveadressierung durchgeführt werden. Im
* Fehlerfall ist der aktuelle Modus des I2C-Moduls unbestimmt.
*
* Falls die Registeradressierung erfolgreich war, gib Null in `r0` zurück.
* Andernfalls enthält `r0` einen Wert ungleich Null.
*/		
.thumb_func
i2c_putPtr:
	push	{r4-r5, lr}
	mov		r4, r0
	mov		r5, #(MAX_RETRIES + 1)

retry_put_ptr:
	subs	r5, r5, #1
	cbz		r5, return_put_ptr
	
	// Sende Startsignal.
	mov		r0, #WADDR
	bl		i2c_start
	cbnz	r0, return_put_ptr
	
	// Setze Zeiger auf DS75-internes Register.
	ldr		r1, =I2C0_D
	strb	r4, [r1]
	
	// Warte auf ACK.
	bl		i2c_busy_wait
	cmp		r0, #0
	beq		return_put_ptr

	// Falls Fehler aufgetreten ist, setze den Bus zurück.
	bl		ic2_bus_reset
	cmp		r0, #0
	beq		retry_put_ptr
	
return_put_ptr:
	// Gib zurück, ob ein Fehler aufgetreten ist.
	cmp		r5, #0
	it		eq
	moveq	r0, #1
	
	pop		{r4-r5, pc}
	
/*
* Unterprogramm (i2c_getInt16): Lies ein 16-bit breites Datenwort aus einem
* Register des DS75.
*
* Die Adresse des gewünschten Registers wird in `r0` übergeben. Ist die globale
* Variable `is_i2c_transfer_failed` gleich Null, dann enthält `r0` das gelesene
* 16-bit Registerwort des DS75. Enthält `is_i2c_transfer_failed` einen Wert
* ungleich Null, dann ist der Lesevorgang fehlgeschlagen und der Inhalt von `r0`
* unbestimmt. 
*/		
.thumb_func
i2c_getInt16:
	push	{r4-r6, lr}
	
	// Setze DS75-internen Zeiger.
	bl		i2c_putPtr
	cbnz	r0, fail_get_int16
	
	// Sende Repeat-Startsignal.
	mov		r0, #RADDR
	bl		i2c_repeat_start
	cbnz	r0, fail_get_int16
	
	// Selektiere Lesemodus mit ACK-Empfangsbestägigung.
	ldr		r4, =I2C0_C1
	ldrb	r1, [r4]
	bic		r1, r1, #(TX | TXAK)
	strb	r1, [r4]
	
	// Stoße Lesebefehl an.
	ldr		r5, =I2C0_D
	ldrb	r1, [r5]
	bl		i2c_busy_wait
	cbnz	r0, fail_get_int16
	
	// Lies erstes Byte.
	ldrb	r6, [r5]
	
	// Selektiere NACK-Empfangsbestätigung.
	ldrb	r1, [r4]
	orr		r1, r1, #TXAK
	strb	r1, [r4]
	
	// Stoße Lesebefehl erneut an.
	ldrb	r1, [r5]
	bl		i2c_busy_wait
	
	// Sende Stoppsignal.
	bl		i2c_stop
	
	// Lies zweites Byte.
	ldrb	r0, [r5]
	orr		r0, r0, r6, lsl #BYTE
	
	// Setze Empfangsbestätigungen zurück auf ACK.
	ldrb	r1, [r4]
	bic		r1, r1, #TXAK
	strb	r1, [r4]
	
	b		return_get_int16
	
fail_get_int16:
	mov		r6, r0
	ldr		r1, =is_i2c_transfer_failed
	strb	r6, [r1]
	
	// Sende Stoppsignal.
	bl		i2c_stop
	mov		r0, r6
	
return_get_int16:
	pop		{r4-r6, pc}

/*
* Unterprogramm (i2c_putByte): Schreibe ein 8-bit breites Datenwort in ein
* spezifiziertes Register des DS75.
*
* Die Adresse des Zielregisters wird in `r0` übergeben. Das Datenwort wird in
* `r1` übergeben. Falls ein Fehler während der Übertragung festgestellt wurde,
* dann hat die globale Variable `is_i2c_transfer_failed` einen Wert ungleich
* Null.
*/			
.thumb_func
i2c_putByte:
	push	{r4, lr}
	mov		r4, r1
	
	// Setze DS75-internen Zeiger.
	bl		i2c_putPtr
	cbnz	r0, fail_put_byte
	
	// Schreibe Byte und warte auf ACK.
	ldr		r0, =I2C0_D
	strb	r4, [r0]
	bl		i2c_busy_wait
	cbnz	r0, fail_put_byte
	
	mov 	r4, r0
	b		return_put_byte
	
fail_put_byte:
	mov		r4, r0
	ldr		r1, =is_i2c_transfer_failed
	strb	r4, [r1]
	
return_put_byte:
	// Sende Stoppsignal.
	bl		i2c_stop
	mov		r0, r4
	
	pop		{r4, pc}
	
/*
* Unterprogramm (i2c_putInt16): Schreibe ein 16-bit breites Datenwort in ein
* spezifiziertes Register des DS75.
*
* Die Adresse des Zielregisters wird in `r0` übergeben. Das Datenwort wird in
* `r1` übergeben. Falls ein Fehler während der Übertragung festgestellt wurde,
* dann hat die globale Variable `is_i2c_transfer_failed` einen Wert ungleich
* Null.
*/		
.thumb_func:
i2c_putInt16:
	push	{r4-r5, lr}
	mov		r4, r1, lsr #BYTE
	mov		r5, r1
	
	// Setze DS75-internen Zeiger.
	bl		i2c_putPtr
	cbnz	r0, fail_put_int16
	
	// Schreibe erstes Byte und warte auf ACK.
	ldr		r0, =I2C0_D
	strb	r4, [r0]
	bl		i2c_busy_wait
	cbnz	r0, fail_put_int16
	
	// Schreibe zweites Byte und warte auf ACK.
	ldr		r0, =I2C0_D
	strb	r5, [r0]
	bl		i2c_busy_wait
	cbnz	r0, fail_put_int16

	mov		r5, r0
	b		return_put_int16
	
fail_put_int16:
	mov		r5, r0
	ldr		r1, =is_i2c_transfer_failed
	strb	r5, [r1]
	
return_put_int16:
	// Sende Stoppsignal.
	bl		i2c_stop
	mov		r0, r5
	
	pop		{r4-r5, pc}
	

/*** Datenbereich (ab 0x20000000) ***/
.data
is_i2c_transfer_failed:
	.byte 0x00
	
string_success:
	.asciz "Initialisierung erfolgreich!\n"

string_failed:
	.asciz "Eine Ausnahme ist bei der I2C-Uebertragung aufgetreten und konnte nicht behoben werden\n"
	
string_hex_prefix:
	.asciz "0x"
	
string_temp_infix:
	.asciz ": "
	
string_temp_postfix:
	.asciz " Grad Celsius\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ BYTE,				8
.equ HALFWORD,			16
.equ SEC, 				25000000
.equ MAX_CTIME_8BIT,	1875000		// Maximale Wandlungsdauer bei 8 Bit Auflösung (0.075 Sec).
.equ MAX_CTIME_9BIT,	3750000		// Maximale Wandlungsdauer bei 9 Bit Auflösung (0.15 Sec).
.equ MAX_CTIME_10BIT,	7500000		// Maximale Wandlungsdauer bei 10 Bit Auflösung (0.3 Sec).
.equ MAX_CTIME_11BIT,	15000000	// Maximale Wandlungsdauer bei 11 Bit Auflösung (0.6 Sec).
.equ MAX_CTIME_12BIT,	30000000	// Maximale Wandlungsdauer bei 12 Bit Auflösung (1.2 Sec).
.equ DUMMY_W,			0xffffffff
.equ DUMMY_H,			0xffff
.equ DUMMY_B,			0xff
.equ DEC,				10
.equ TENTHOUSEND,		10000
.equ HALF,				5000
.equ QUARTER,			2500
.equ EIGHTH,			1250
.equ SIXTEENTH,			625
.equ BIT7,				128
.equ BIT6,				64
.equ BIT5,				32
.equ BIT4,				16
.equ DIGITS,			6
.equ COMMA,				','

// Interrupt-Vektor-Konstanten
.equ IVT,				0x1ffffe00			// Basisadresse der IVT.
.equ IVT_PIT1,			IVT + 0x40 + (69 << 2)	// IV-Tabellenindex für IRQ 69 (PIT1).
.equ IVT_PORTA,			IVT + 0x40 + (87 << 2)	// IV-Tabellenindex für IRQ 87 (PORTA).
.equ IVT_PORTE,			IVT + 0x40 + (91 << 2)	// IV-Tabellenindex für IRQ 91 (PORTE).
.equ IRQ_PIT1,			(1 << (69 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 69 (PIT1).
.equ IRQ_PORTA,			(1 << (87 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 87 (PORTA).
.equ IRQ_PORTE,			(1 << (91 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 91 (PORTE).

// Nested Interrupt Controller (NVIC) Registeradressen
.equ NVIC_ISER2,		0xe000e100 + 2 << 2
.equ NVIC_ICPR2,		0xe000e280 + 2 << 2

// Port Control and Interrupts (PORT) Registeradressen
.equ PORTA_PCR19,		0x4004904c
.equ PORTD_PCR12,		0x4004c030
.equ PORTD_PCR13,		0x4004c034
.equ PORTD_PCR14,		0x4004c038
.equ PORTD_PCR15,		0x4004c03c
.equ PORTE_PCR26,		0x4004d068

// System Integration Module (SIM) Registeradressen
.equ SIM_SCGC3,			0x40048030
.equ SIM_SCGC4,			0x40048034
.equ SIM_SCGC5,			0x40048038
.equ SIM_SCGC6,			0x4004803c

// Periodic Interrupt Timer (PIT) Registeradressen
.equ PIT_MCR,			0x40037000
.equ PIT_LDVAL1,		0x40037110
.equ PIT_TCTRL1,		0x40037118
.equ PIT_TFLG1,			0x4003711c

// Serieal Peripheral Interface (SPI) Registeradressen
.equ SPI2_MCR,			0x400ac000
.equ SPI2_TCR,			0x400ac008
.equ SPI2_CTAR0,		0x400ac00c
.equ SPI2_SR,			0x400ac02c
.equ SPI2_RSER,			0x400ac030
.equ SPI2_PUSHR,		0x400ac034
.equ SPI2_POPR,			0x400ac038

// General-Purpose I/O (GPIO) Registeradressen
.equ GPIOA_PDIR,		0x400ff010
.equ GPIOA_PDDR,		0x400ff014
.equ GPIOE_PDIR,		0x400ff110
.equ GPIOE_PDDR,		0x400ff114

// Steuerwörter
.equ SPI2,				(1 << 12)	// Aktiviere Takt für SPI2.
.equ PORTA,				(1 <<  9)	// Aktiviere Takt für PORTA.
.equ PORTD,				(1 << 12)	// Aktiviere Takt für PORTD.
.equ PORTE,				(1 << 13)	// Aktiviere Takt für PORTE.
.equ PIT,				(1 << 23)	// Aktiviere Takt für PIT.

.equ GPIO,				(1 <<  8)	// Konfiguriere Port als GPIO (Alt 1).
.equ SPI,				(2 <<  8)	// Konfiguriere Port als SPI (Alt 2).
.equ IRQC_FE,			(10 << 16)	// Setze IRQC auf Interrupt bei fallender Flanke.
.equ PE,				(1 <<  1)	// Setze Port auf Pull Enable.
.equ PS,				(1)			// Setze Pull Select auf Internal Pull-up für Port.

.equ TEN,				(1)			// Aktiviere den ausgewählten PIT-Kanal.
.equ TIE,				(1 <<  1)	// Aktiviere Interrups für den ausgewählten PIT-Kanal.

.equ MSTR,				(1 << 31)	// Selektiere Mastermodus für das ausgewählte SPI-Modul.
.equ FRZ,				(1 << 27)	// Stoppe alle Transfers im Debugmodus.
.equ DIS_TXF,			(1 << 13)	// Deaktiviere TX FIFO für das ausgewählte SPI-Modul.
.equ DIS_RXF,			(1 << 12)	// Deaktiviere RX FIFO für das ausgewhälte SPI-Modul.
.equ CLR_TXF,			(1 << 11)	// Setze TX FIFO des ausgewählten SPI-Moduls zurück.
.equ CLR_RXF,			(1 << 10)	// Setze RX FIFO des ausgewählten SPI-Moduls zurück.
.equ HALT,				(1)			// Stoppe Transfers für das ausgewählte SPI-Modul.

.equ FMSZ,				(7 << 27)	// Setze die Größe für SPI-Transferrahmen auf 8 Bit.
.equ CPHA,				(1 << 25)	// Setze die Clock-Phase des SPI-Transfers auf "Shift" bei steigender Flanke und "Latch" bei fallender Flanke.
.equ PCSSCK,			(2 << 22)	// Verlängere die PCS-zu-SCK-Verzögerung um das 5-fache.
.equ ASC,				(1 <<  8)	// Verlängere die SCK-zu-PCS-Verzögerung am Ende eines Transfers um das 4-fache.
.equ BR,				(7)			// Teile die effektive SCK Baudrate durch 128.

.equ TCF,				(1 << 31)	// Zeigt, ob alle Bits eines Transferrahmens übertragen wurden.
.equ EOQF,				(1 << 28)	// Zeigt, ob ein TX FIFO-Eintrag mit einem EOQ-Bit fertig übertragen wurde.
.equ RXCTR,				(15 << 4)	// Bitmaske für den RX-Pufferzähler.

.equ CONT,				(1 << 31)	// Halte das CS Signal zwischen SPI-Transfers.
.equ EOQ,				(1 << 27)	// Markiere den ausgewählten SPI-Transfer als den letzten in seiner Warteschlange.
.equ CTCNT,				(1 << 26)	// Setze den Transferzähler zurück, bevor der ausgewählte Transfer durchgeführt wird.
.equ PCS,				(2 <<  16)	// Selektiere das PCS-Signal 1.

.equ DS1722_CONFIG,		(0x80)		// Schreibe in das Konfigurationsregister des DS1722s.
.equ DS1722_TEMP_LSB,	(0x01)		// Lies das Temperatur-LSB-Register des DS1722s.
.equ DS1722_TEMP_MSB,	(0x02)		// Lies das Temperatur-MSB-Register des DS1722s.
									
.equ RES_8BIT,			(0 <<  1)	// Setze Temperaturauflösung auf 8 Bit.
.equ RES_9BIT,			(1 <<  1)	// Setze Temperaturauflösung auf 9 Bit.
.equ RES_10BIT,			(2 <<  1)	// Setze Temperaturauflösung auf 10 Bit.
.equ RES_11BIT,			(3 <<  1)	// Setze Temperaturauflösung auf 11 Bit.
.equ RES_12BIT,			(4 <<  1)	// Setze Temperaturauflösung auf 12 Bit.			

// Bitband-Alias Adressen
__BBREG PIT_TCTRL1_TEN,		PIT_TCTRL1,		0
__BBREG PORTA_PCR19_ISF,	PORTA_PCR19,	24
__BBREG PORTE_PCR26_ISF,	PORTE_PCR26,	24
__BBREG GPIOA_PDDR_PIN19,	GPIOA_PDDR,		19
__BBREG GPIOE_PDDR_PIN26,	GPIOE_PDDR, 	26

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Aktiviere Takt für SPI2.
	ldr		r0, =SIM_SCGC3
	ldr		r1, [r0]
	orr		r1, r1, #SPI2
	str		r1, [r0]
	
	// Aktiviere Takt für PORTA, PORTD und PORTE.
	ldr		r0, =SIM_SCGC5
	ldr		r1, [r0]
	orr		r1, r1, #(PORTA | PORTD | PORTE)
	str		r1, [r0]
	
	// Aktiviere Takt für PIT.
	ldr		r0, =SIM_SCGC6
	ldr		r1, [r0]
	orr		r1, r1, #PIT
	str		r1, [r0]
	
	// Setze Interrupt-Vektor zu PIT1.
	ldr		r0, =handle_pit1_irq
	ldr		r1, =IVT_PIT1
	str		r0, [r1]
	
	// Setze Interrupt-Vektor zu PORTA.
	ldr		r0, =handle_porta_irq
	ldr		r1, =IVT_PORTA
	str		r0, [r1]
	
	// Setze Interrupt-Vektor zu PORTE.
	ldr		r0, =handle_porte_irq
	ldr		r1, =IVT_PORTE
	str		r0, [r1]
	
	// Lösche anhängende Interrupts und anschließend aktiviere Interrupts für
	// PIT1, PORTA und PORTE.
	ldr		r0, =(IRQ_PIT1 | IRQ_PORTA | IRQ_PORTE)
	ldr		r1, =NVIC_ICPR2
	ldr		r2, =NVIC_ISER2
	str		r0, [r1]
	str		r0, [r2]
	
	// Konfiguriere PORTD Pins 12, 13, 14 und 15 als SPI.
	mov		r0, #SPI
	ldr		r1, =PORTD_PCR12
	ldr		r2, =PORTD_PCR13
	ldr		r3, =PORTD_PCR14
	ldr		r4, =PORTD_PCR15
	str		r0, [r1]
	str		r0, [r2]
	str		r0, [r3]
	str		r0, [r4]
	
	// Konfiguriere SPI2 als SPI-Busmaster im Stoppmodus, setze die TX und RX.
	ldr		r0, =(MSTR | HALT)
	ldr		r1, =SPI2_MCR
	str		r0, [r1]
	
	// Deaktiviere alle Interrupts für SPI2.
	mov		r0, #0
	ldr		r2, =SPI2_RSER
	str		r0, [r2]
	
	// Setze die Rahmengröße für SPI2 auf 8 Bit, ändere die Clock-Phase und
	// setze die Baudrate auf ca. 100Khz.
	ldr		r0, =(FMSZ | CPHA | PCSSCK | ASC | BR)
	ldr		r2, =SPI2_CTAR0
	str		r0, [r2]
	
	// Deaktiviere SPI2 TX und RX Puffer und versetze Modul in Startmodus.
	ldr		r0, =(MSTR | DIS_TXF | DIS_RXF | CLR_TXF | CLR_RXF)
	str		r0, [r1]
	
	// Konfiguriere den DS1722 auf 12 Bit Auflösung mit kontinuierlicher Wandlung.
	mov		r0, #RES_12BIT
	bl		spi2_put_config
	
	// Gib Initialisierungsbestätigung an Benutzer aus.
	ldr		r0, =ds1722_initialised
	bl		uart_putString
	
	// Konfiguriere PORTA Pin 19 und PORTE Pin 26 als GPIO mit Interrupt bei
	// fallender Flanke und aktiviere internen Pull-up Widerstand.
	ldr		r0, =(IRQC_FE | GPIO | PE | PS)
	ldr		r1, =PORTA_PCR19
	ldr		r2, =PORTE_PCR26
	str		r0, [r1]
	str		r0, [r2]
	
	// Schalte GPIOA Pin 19 (SW1) und GPIOE Pin 26 (SW2) als Eingänge.
	mov		r0, #0
	ldr		r1, =GPIOA_PDDR_PIN19
	ldr		r2, =GPIOE_PDDR_PIN26
	str		r0, [r1]
	str		r0, [r2]
	
	// Aktiviere PIT Modul und lösche anhängende Interrupts.
	ldr		r1, =PIT_MCR
	ldr		r2, =PIT_TFLG1
	str		r0, [r1]
	str		r0, [r2]
	
	// Initialisiere PIT1 auf die maximale Wandlungszeit bei 12-bit Temperatur-
	// messgenauigkeit.
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =MAX_CTIME_12BIT
	str		r1, [r0]
	
	// Aktiviere PIT1 mit Interrupts.
	ldr		r0, =PIT_TCTRL1
	mov		r1, #(TIE | TEN)
	str		r1, [r0]
	
loop:
	// Prüfe Tastendruck auf SW1.
	ldr		r4, =is_sw1_pressed
	ldr		r0, [r4]
	cbz		r0, skip_sw1
	
	bl		handle_sw1
	
	// Setze SW1-Flagge zurück
	mov		r0, #0
	str		r0, [r4]
	
skip_sw1:	
	// Prüfe Tastendruck auf SW2.
	ldr		r4, =is_sw2_pressed
	ldr		r0, [r4]
	cbz		r0, skip_sw2
	
	bl		handle_sw2
	
	// Setze SW2-Flagge zurück
	mov		r0, #0
	str		r0, [r4]

skip_sw2:
	// Verzögere die Anzeigelogik um 1 Sekunde um Benutzerausgaben zu drosseln.
	ldr		r0, =is_pit1_lapsed
	ldr		r1, [r0]
	cbz		r1, end
	
	// Setze PIT1-Flagge zurück.
	mov		r1, #0
	str		r1, [r0]
	
	// Lies die Temparatur aus.
	bl		spi2_get_temp
	
	// Gibt Temperaturmessung aus.
	bl		uart_put_temp
	
end:
	wfi
	b loop

/*
* Unterprogramm (spi2_put_config): Lade DS1722 mit neuer Konfiguration.
*
* Die neue Konfiguration wird mittels SPI in das Konfigurationsregister des
* Sensors geladen.
*
* Die neue Konfiguration wird als 8 Bit Steuerwort in `r0` übergeben.
*/	
.thumb_func
spi2_put_config:
	// Setze das Statusregister für SPI2 zurück und deaktiviere Interrupts.
	mov		r1, #DUMMY_W
	ldr		r2, =SPI2_SR
	str		r1, [r2]

	// Adressiere das Konfigurationsregister des DS1722s.
	ldr		r1, =(CONT | CTCNT | PCS | DS1722_CONFIG)
	ldr		r3, =SPI2_PUSHR
	str		r1, [r3]
	
loop_put_config_0:
	// Warte bis der Transfer abgeschlossen ist.
	ldr		r1, [r2]
	tst		r1, #TCF
	beq		loop_put_config_0
	
	// Quittiere Transfer-Complete-Flagge.
	str		r1, [r2]
	
	// Sende die gewünschte neue Konfiguration an den DS1722s.
	movt	r0, #((EOQ | PCS) >> HALFWORD)
	str		r0, [r3]
	
loop_put_config_1:
	// Warte bis der Transfer abgeschlossen ist.
	ldr		r1, [r2]
	tst		r1, #TCF
	beq		loop_put_config_1
	
	// Lösche TX und RX Puffer.
	ldr		r0, =SPI2_MCR
	ldr		r1, [r0]
	orr		r1, r1, #(CLR_TXF | CLR_RXF)
	str		r1, [r0]
	
	bx		lr

/*
* Unterprogramm (spi2_get_temp): Lies die aktuelle Temperatur aus.
*
* Die Temperatur wird als 16 Bit Zahl im 8.4 Bit Format in `r0` ausgegeben. 
*/		
.thumb_func
spi2_get_temp:
	push	{r4-r5, lr}
	
	// Setze das Statusregister für SPI2 zurück und deaktiviere Interrupts.
	mov		r0, #DUMMY_W
	ldr		r1, =SPI2_SR
	str		r0, [r1]

	// Adressiere das LSB-Temperaturregister des DS1722s.
	ldr		r2, =(CONT | CTCNT | PCS | DS1722_TEMP_LSB)
	ldr		r3, =SPI2_PUSHR
	str		r2, [r3]
	
loop_get_temp_0:
	// Warte bis der Transfer abgeschlossen ist.
	ldr		r2, [r1]
	tst		r2, #RXCTR
	beq		loop_get_temp_0
	
	// Leere RX Puffer.
	ldr		r4, =SPI2_POPR
	ldr		r5, [r4]
	
	// Quittiere Transfer.
	str		r2, [r1]

	// Schiebe ein Dummybyte zum DS1722s.
	ldr		r0, =(CONT | PCS | DUMMY_H)
	str		r0, [r3]
	
loop_get_temp_1:
	// Warte bis der Transfer abgeschlossen ist.
	ldr		r2, [r1]
	tst		r2, #RXCTR
	beq		loop_get_temp_1
	
	// Lies Temperatur LSB.
	ldr		r5, [r4]
	
	// Quittiere Transfer.
	str		r2, [r1]
	
	// Schiebe letztes Dummybyte zum DS1722s.
	ldr		r0, =(EOQ | PCS | DUMMY_H)
	str		r0, [r3]
	
loop_get_temp_2:
	// Warte bis der Transfer abgeschlossen ist.
	ldr		r2, [r1]
	tst		r2, #RXCTR
	beq		loop_get_temp_2
	
	// Lies Temperatur MSB.
	ldr		r2, [r4]
	orr		r0, r5, r2, lsl #BYTE
	
	// Lösche TX und RX Puffer.
	ldr		r1, =SPI2_MCR
	ldr		r2, [r1]
	orr		r2, r2, #(CLR_TXF | CLR_RXF)
	str		r2, [r1]
	
	pop		{r4-r5, pc}

/*
* Unterprogramm (handle_sw1): Erhöhe die Wandlungsauflösung des DS1722 und
* passe die Abfragerate des Sensors entsprechend an. 
*/
.thumb_func
handle_sw1:
	push	{lr}

	// Stoppe PIT1.
	mov		r0, #0
	ldr		r1, =PIT_TCTRL1_TEN
	ldr		r2, =is_pit1_lapsed
	str		r0, [r1]
	str		r0, [r2]
	
	// Lösche anhängende Interrupts.
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	
	// Erhöhe die Wandlungsauflösung.
	ldr		r2, =resolution
	ldr		r1, [r2]
	
	// Ist die aktuelle Auflösung 12 Bit?
	teq		r1, #RES_12BIT
	bne		sw1_check_11bit
	
	ldr		r0, =sw1_pressed_12bit
	bl		uart_putString

	mov		r0, #RES_8BIT
	ldr		r1, =MAX_CTIME_8BIT
	
	b		return_sw1
	
sw1_check_11bit:
	// Ist die aktuelle Auflösung 11 Bit?
	teq		r1, #RES_11BIT
	bne		sw1_check_10bit
	
	ldr		r0, =sw1_pressed_11bit
	bl		uart_putString
	
	mov		r0, #RES_12BIT
	ldr		r1, =MAX_CTIME_12BIT
	
	b		return_sw1

sw1_check_10bit:
	// Ist die aktuelle Auflösung 10 Bit?
	teq		r1, #RES_10BIT
	bne		sw1_check_9bit
	
	ldr		r0, =sw1_pressed_10bit
	bl		uart_putString
	
	mov		r0, #RES_11BIT
	ldr		r1, =MAX_CTIME_11BIT
	
	b		return_sw1
	
sw1_check_9bit:
	// Ist die aktuelle Auflösung 9 Bit?
	teq		r1, #RES_9BIT
	bne		sw1_check_8bit
	
	ldr		r0, =sw1_pressed_9bit
	bl		uart_putString
	
	mov		r0, #RES_10BIT
	ldr		r1, =MAX_CTIME_10BIT
	
	b		return_sw1
	
sw1_check_8bit:
	// Ansonsten muss die Auflösung 8 Bit sein.
	ldr		r0, =sw1_pressed_8bit
	bl		uart_putString
	
	mov		r0, #RES_9BIT
	ldr		r1, =MAX_CTIME_9BIT
	
return_sw1:
	// Speichere die neue Auflösung ab.
	ldr		r2, =resolution
	str		r0, [r2]

	// Passe PIT1 an die neue maximale Wandlungsdauer an.
	ldr		r2, =PIT_LDVAL1
	str		r1, [r2]
	
	// Rekonfiguriere den DS1722s.
	bl		spi2_put_config

	// Starte PIT1.
	mov		r0, #1
	ldr		r1, =PIT_TCTRL1_TEN
	str		r0, [r1]
	
	pop		{pc}

/*
* Unterprogramm (handle_sw2): Verringere die Wandlungsauflösung des DS1722 und
* passe die Abfragerate des Sensors entsprechend an. 
*/
.thumb_func
handle_sw2:
	push	{lr}

	// Stoppe PIT1.
	mov		r0, #0
	ldr		r1, =PIT_TCTRL1_TEN
	ldr		r2, =is_pit1_lapsed
	str		r0, [r1]
	str		r0, [r2]
	
	// Lösche anhängende Interrupts.
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	
	// Verringere die Wandlungsauflösung.
	ldr		r2, =resolution
	ldr		r1, [r2]
	
	// Ist die aktuelle Auflösung 12 Bit?
	teq		r1, #RES_12BIT
	bne		sw2_check_11bit
	
	ldr		r0, =sw2_pressed_12bit
	bl		uart_putString

	mov		r0, #RES_11BIT
	ldr		r1, =MAX_CTIME_11BIT
	
	b		return_sw2
	
sw2_check_11bit:
	// Ist die aktuelle Auflösung 11 Bit?
	teq		r1, #RES_11BIT
	bne		sw2_check_10bit
	
	ldr		r0, =sw2_pressed_11bit
	bl		uart_putString
	
	mov		r0, #RES_10BIT
	ldr		r1, =MAX_CTIME_10BIT
	
	b		return_sw2

sw2_check_10bit:
	// Ist die aktuelle Auflösung 10 Bit?
	teq		r1, #RES_10BIT
	bne		sw2_check_9bit
	
	ldr		r0, =sw2_pressed_10bit
	bl		uart_putString
	
	mov		r0, #RES_9BIT
	ldr		r1, =MAX_CTIME_9BIT
	
	b		return_sw2
	
sw2_check_9bit:
	// Ist die aktuelle Auflösung 9 Bit?
	teq		r1, #RES_9BIT
	bne		sw2_check_8bit
	
	ldr		r0, =sw2_pressed_9bit
	bl		uart_putString
	
	mov		r0, #RES_8BIT
	ldr		r1, =MAX_CTIME_8BIT
	
	b		return_sw2
	
sw2_check_8bit:
	// Ansonsten muss die Auflösung 8 Bit sein.
	ldr		r0, =sw2_pressed_8bit
	bl		uart_putString
	
	mov		r0, #RES_12BIT
	ldr		r1, =MAX_CTIME_12BIT
	
return_sw2:
	// Speichere die neue Auflösung ab.
	ldr		r2, =resolution
	str		r0, [r2]

	// Passe PIT1 an die neue maximale Wandlungsdauer an.
	ldr		r2, =PIT_LDVAL1
	str		r1, [r2]
	
	// Rekonfiguriere den DS1722s.
	bl		spi2_put_config

	// Starte PIT1.
	mov		r0, #1
	ldr		r1, =PIT_TCTRL1_TEN
	str		r0, [r1]
	
	pop		{pc}

/*
* Unterprogramm (uart_put_temp): Gib eine 8.4 Bit Temparatur als Dezimalzahl aus.
*
* Die Temparatur wird in `r0` übergeben. 
*/	
.thumb_func
uart_put_temp:
	push	{r4-r6, lr}

	// Verschiebe die Temparatur um 4 Dezimalstellen nach links und schneide
	// die Nachkommastellen ab.
	ldr		r1, =TENTHOUSEND
	lsr		r2, r0, #BYTE
	mul		r2, r1, r2
	
	// Berechne Nachkommastellen als Hunderstel und addiere die gesamte
	// Temperatur wieder auf.
	tst		r0, #BIT7
	itt		ne
	ldrne	r1, =HALF
	addne	r2, r2, r1
	
	tst		r0, #BIT6
	itt		ne
	ldrne	r1, =QUARTER
	addne	r2, r2, r1
	
	tst		r0, #BIT5
	itt		ne
	ldrne	r1, =EIGHTH
	addne	r2, r2, r1
	
	tst		r0, #BIT4
	itt		ne
	ldrne	r1, =SIXTEENTH
	addne	r2, r2, r1
	
	// Lege die Temperatur als Dezimalzahl im Speicher ab.
	ldr		r4, =temp
	add		r1, r4, #DIGITS
	mov		r3, #DEC
	
loop_put_temp_0:
	// Berechne die nächste Dezimalziffer von rechts.
	udiv	r0, r2, r3
	mul		r5, r0, r3
	sub		r6, r2, r5
	strb	r6, [r1, #-1]!
	mov		r2, r0
	
	// Ist der Enditerator bereits am Arrayanfang angekommen?
	cmp		r4, r1
	bne		loop_put_temp_0

	// Gib die Ziffern nacheinander aus.
	ldrb	r0, [r4], #1
	bl		uart_putByteBase10
	
	ldrb	r0, [r4], #1
	bl		uart_putByteBase10
	
	mov		r0, #COMMA
	bl		uart_putChar
	
	ldrb	r0, [r4], #1
	bl		uart_putByteBase10
	
	ldrb	r0, [r4], #1
	bl		uart_putByteBase10
	
	ldrb	r0, [r4], #1
	bl		uart_putByteBase10
	
	ldrb	r0, [r4], #1
	bl		uart_putByteBase10
	
	ldr		r0, =temp_suffix
	bl		uart_putString
	
	pop		{r4-r6, pc}

/*
* Interrupt Service Routine (handle_porta_irq): Behandelt eine Unterbrechung
* durch PORTA auf PIN 19 durch Betätigen des SW1-Tasters.
*/
.thumb_func	
handle_porta_irq:
	mov		r0, #1
	ldr		r1, =PORTA_PCR19_ISF
	ldr		r2, =is_sw1_pressed
	str		r0, [r1]
	str		r0, [r2]
	bx		lr

/*
* Interrupt Service Routine (handle_pit1_irq): Behandelt eine Unterbrechung des
* PIT Moduls auf Kanal 1 bei Ablaufen des Zählers. 
*/
.thumb_func
handle_pit1_irq:
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	ldr 	r2, =is_pit1_lapsed
	str		r0, [r1]
	str		r0, [r2]
	bx		lr

/*
* Interrupt Service Routine (handle_porte_irq): Behandelt eine Unterbrechung
* durch PORTE auf PIN 26 durch Betätigen des SW2-Tasters.
*/
.thumb_func
handle_porte_irq:
	mov		r0, #1
	ldr		r1, =PORTE_PCR26_ISF
	ldr		r2, =is_sw2_pressed
	str		r0, [r1]
	str		r0, [r2]
	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
is_pit1_lapsed:
	.word	0x00
	
is_sw1_pressed:
	.word	0x00
	
is_sw2_pressed:
	.word	0x00
	
resolution:
	.word	RES_12BIT
	
temp:
	.rept	6
	.byte	0x00
	.endr
	
temp_suffix:
	.asciz	" gC\n"
	
ds1722_initialised:
	.asciz	"DS1722 initialisiert: Aufloesung gesetzt auf 12 Bit\n"
	
sw1_pressed_12bit:
	.asciz	"SW1 gedrueckt: Aufloesung geandert 12 Bit -> 8 Bit\n"
	
sw1_pressed_11bit:
	.asciz	"SW1 gedrueckt: Aufloesung geandert 11 Bit -> 12 Bit\n"
	
sw1_pressed_10bit:
	.asciz	"SW1 gedrueckt: Aufloesung geandert 10 Bit -> 11 Bit\n"
	
sw1_pressed_9bit:
	.asciz	"SW1 gedrueckt: Aufloesung geandert 9 Bit -> 10 Bit\n"
	
sw1_pressed_8bit:
	.asciz	"SW1 gedrueckt: Aufloesung geandert 8 Bit -> 9 Bit\n"
	
sw2_pressed_12bit:
	.asciz	"SW2 gedrueckt: Aufloesung geandert 12 Bit -> 11 Bit\n"
	
sw2_pressed_11bit:
	.asciz	"SW2 gedrueckt: Aufloesung geandert 11 Bit -> 10 Bit\n"
	
sw2_pressed_10bit:
	.asciz	"SW2 gedrueckt: Aufloesung geandert 10 Bit -> 9 Bit\n"
	
sw2_pressed_9bit:
	.asciz	"SW2 gedrueckt: Aufloesung geandert 9 Bit -> 8 Bit\n"
	
sw2_pressed_8bit:
	.asciz	"SW2 gedrueckt: Aufloesung geandert 8 Bit -> 12 Bit\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ BYTE,				8
.equ HALFWORD,			16
.equ SEC, 				25000000
.equ ENABLE,			0xff
.equ MODULO_24H,		86400	// 24h 0min 0sec in Sekunden.
.equ ALARM_24H,			86399	// 23h 59min 59sec in Sekunden.
.equ PRESET_24H,		86395	// 23h 59min 55sec in Sekunden.
.equ MODULO_1H,			3600	// 1h 0min 0sec in Sekunden.
.equ ALARM_1H,			3599	// 59min 59sec in Sekunden.
.equ PRESET_1H,			3595	// 59min 55sec in Sekunden.
.equ MODULO_1M,			60		// 1min 0sec in Sekunden.

.equ COLON,				':'
.equ NL,				'\n'

.equ CHAR_P,			'p'
.equ CHAR_S,			's'
.equ CHAR_R,			'r'
.equ CHAR_H,			'h'
.equ CHAR_D,			'd'

// Interrupt-Vektor-Konstanten
.equ IVT,				0x1ffffe00			// Basisadresse der IVT.
.equ IVT_RTC_ALARM,		IVT + 0x40 + (66 << 2)	// IV-Tabellenindex für IRQ 66 (RTC Alarm-Interrupt).
.equ IVT_RTC_SECONDS,	IVT + 0x40 + (67 << 2)	// IV-Tabellenindex für IRQ 67 (RTC Sekunden-Interrupt).
.equ IRQ_RTC_ALARM,		(1 << (66 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 66 (RTC Alarm-Interrupt).
.equ IRQ_RTC_SECONDS,	(1 << (67 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 67 (RTC Sekunden-Interrupt).

// Nested Interrupt Controller (NVIC) Registeradressen
.equ NVIC_ISER2,		0xe000e100 + 2 << 2
.equ NVIC_ICPR2,		0xe000e280 + 2 << 2

// System Integration Module (SIM) Registeradressen
.equ SIM_SCGC6,			0x4004803c

// Periodic Interrupt Timer (PIT) Registeradressen
.equ PIT_MCR,			0x40037000
.equ PIT_LDVAL1,		0x40037110
.equ PIT_TCTRL1,		0x40037118
.equ PIT_TFLG1,			0x4003711c

// Real Time Clock (RTC) Registeradressen
.equ RTC_TSR,			0x4003d000
.equ RTC_TPR,			0x4003d004
.equ RTC_TAR,			0x4003d008
.equ RTC_TCR,			0x4003d00c
.equ RTC_CR,			0x4003d010
.equ RTC_SR,			0x4003d014
.equ RTC_LR,			0x4003d018
.equ RTC_IER,			0x4003d01c
.equ RTC_WAR,			0x4003d800
.equ RTC_RAR,			0x4003d804

// Steuerwörter
.equ RTC,				(1 << 29)	// Aktiviere Takt für RTC in SIM.
.equ PIT,				(1 << 23)	// Aktiviere Takt für PIT in SIM.
.equ TEN,				(1)			// Aktiviere den ausgewählten PIT-Kanal.
.equ CLKO,				(1 << 9)	// Deaktiviere die Ausgabe des RTC-Signals an andere Peripheriemodule.
.equ OSCE,				(1 << 8)	// Aktiviere den RTC-Oszillator.
.equ UM,				(1 << 3)	// Erlaube TCE-Bit selbst dann zu setzen, wenn RTC_SR gesperrt ist.
.equ SUP,				(1 << 2)	// Deaktiviere Schreibbeschränkungen für unprivilegierten Code.
.equ TCE,				(1 << 4)	// Aktiviere Timer Counter.
.equ TAF,				(1 << 2)	// Prüfe, ob ein Alarm ausgelöst wurde.
.equ TOF,				(1 << 1)	// Prüfe, ob es zu einem Zählerüberlauf kam.
.equ TIF,				(1 << 0)	// Prüfe, ob die Zeit ungültig ist.
.equ TSIE,				(1 << 4)	// Aktiviere Sekunden-Interrupt.
.equ TAIE,				(1 << 2)	// Aktiviere Alarm-Interrupt.
.equ TOIE,				(1 << 1)	// Aktiviere Zählerüberlauf-Interrupt.

// Bitband-Alias Adressen
__BBREG SIM_SCGC6_PIT,	SIM_SCGC6, 	23

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Aktiviere Takt für RTC- und PIT-Modul.
	ldr		r0, =SIM_SCGC6
	ldr		r1, [r0]
	orr		r1, r1, #(RTC | PIT)
	str		r1, [r0]
	
	// Setze Interrupt-Vektor zu RTC-Alarm.
	ldr		r0, =handle_rtc_alarm_irq
	ldr		r1, =IVT_RTC_ALARM
	str		r0, [r1]
	
	// Setze Interrupt-Vektor zu RTC-Seconds.
	ldr		r0, =handle_rtc_second_irq
	ldr		r1, =IVT_RTC_SECONDS
	str		r0, [r1]
	
	// Lösche anhängende Interrupts und anschließend aktiviere Interrupts für
	// RTC-Alarm und RTC-Seconds.
	mov		r0, #(IRQ_RTC_ALARM | IRQ_RTC_SECONDS)
	ldr		r1, =NVIC_ICPR2
	ldr		r2, =NVIC_ISER2
	str		r0, [r1]
	str		r0, [r2]
	
	// Aktiviere die PITs und deaktiviere den Freeze-Modus.
	ldr		r0, =PIT_MCR
	mov		r1, #0x0
	str		r1, [r0]
	
	// Initialisiere Zähler auf eine Sekunde.
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =SEC
	str		r1, [r0]
	
	// Setze Schreib- und Leserechte für alle RTC-Register.
	mov		r0, #ENABLE
	ldr		r1, =RTC_LR
	ldr		r2, =RTC_WAR
	ldr		r3, =RTC_RAR
	str		r0, [r1]
	str		r0, [r2]
	str		r0, [r3]
	
	// Deaktiviere Interrupts.
	mov		r0, #0
	ldr		r1, =RTC_IER
	str		r0, [r1]
	
	// Deaktiviere Ausgabe des RTC-Signals und deaktiviere Schreibbeschränk-
	// ungen der RTC-Register.
	mov		r0, #(CLKO | OSCE | UM | SUP)
	ldr		r2, =RTC_CR
	str		r0, [r2]
	
	// Aktiviere den PIT1.
	mov		r0, #TEN
	ldr		r2, =PIT_TCTRL1
	str		r0, [r2]
	ldr		r2, =PIT_TFLG1

wait_osc_startup:
	// Warte, bis sich RTC-Oszillator stablisiert hat (1000ms).
	ldr		r0, [r2]
	teq		r0, #0
	beq		wait_osc_startup
	
	// Deaktiviere PIT-Modul.
	mov		r0, #0
	ldr		r2, =SIM_SCGC6_PIT
	str		r0, [r2]
	
	// Deaktiviere Timer Counter.
	ldr		r2, =RTC_SR
	str		r0, [r2]
	
	// Setze Kompensationsregister zurück.
	ldr		r3, =RTC_TCR
	str		r0, [r3]
	
	// Setze Prescalerregister zurück.
	ldr		r3, =RTC_TPR
	str		r0, [r3]
	
	// Setze Alarmregister auf 23:59:59 (dh. Alarm feuert bei 24:00:00).
	ldr		r3, =ALARM_24H
	ldr		r4, =RTC_TAR
	str		r3, [r4]
	
	// Setze Sekundenregister zurück.
	ldr		r3, =RTC_TSR
	str		r0, [r3]
	
	// Aktiviere Timer Counter.
	mov		r0, #TCE
	str		r0, [r2]
	
	// Aktiviere Interrupts für Sekunden, Alarm und Overflow.
	mov		r0, #(TSIE | TAIE | TOIE)
	str		r0, [r1]
	
	// Gib Konfiguration auf der Konsole aus.
	ldr		r0, =mode_24h
	bl		uart_putString
	
	ldr		r0, =timer_reset
	bl		uart_putString
	
loop:
	ldr		r0, =is_alarm_lapsed
	ldr		r1, [r0]
	cbz		r1, handle_second_lapsed
	
	// Setze Flag zurück.
	mov		r1, #0
	str		r1, [r0]
	
	// Gib eine Meldung auf der Konsole aus.
	ldr		r0, =alarm_lapsed
	bl		uart_putString
	
handle_second_lapsed:
	ldr		r0, =is_second_lapsed
	ldr		r1, [r0]
	cbz		r1, handle_input
	
	// Setze Flag zurück.
	mov		r1, #0
	str		r1, [r0]
	
	// Prüfe, ob Anzeige der Uhrzeit aktiviert ist.
	ldr		r0, =is_output_enabled
	ldr		r1, [r0]
	cbz		r1, handle_input
	
	// Bestimme, ob die Uhrzeit im 24h-Format ausgegeben werden soll.
	ldr		r0, =ALARM_24H
	ldr		r1, =RTC_TAR
	ldr		r2, [r1]
	teq		r2, r0
	ite		eq
	ldreq	r0, =uart_put_24h
	ldrne	r0, =uart_put_1h
	blx		r0
	
handle_input:
	bl		uart_charPresent
	teq		r0, #0
	beq		loop
	
	// Lade Benutzereingabe.
	bl		uart_getChar
	
	// Falls 'p' eingegeben wurde, stelle die Uhr testweise vor.
	teq		r0, #CHAR_P
	beq		handle_p
	
	// Falls 's' eingegeben wurde, starte / stoppe die Anzeige.
	teq		r0, #CHAR_S
	beq		handle_s
	
	// Falls 'r' eingegeben wurde, setze die Uhrzeit zurück.
	teq		r0, #CHAR_R
	beq		handle_r
	
	// Falls 'h' eingegeben wurde, setze Alarm in 1h-Modus.
	teq		r0, #CHAR_H
	beq		handle_h
	
	// Falls 'd' eingegeben wurde, setze Alarm in 24h-Modus.
	teq		r0, #CHAR_D
	bne		loop
	
	// Deaktiviere Timer Counter.
	mov		r0, #0
	ldr		r1, =RTC_SR
	str		r0, [r1]
	
	// Setze Alarm auf 23:59:59.
	ldr		r2, =ALARM_24H
	ldr		r3, =RTC_TAR
	str		r2, [r3]
	
	// Setze Timer Counter zurück.
	ldr		r2, =RTC_TSR
	str		r0, [r2]
	
	// Reaktiviere Timer Counter.
	mov		r2, #TCE
	str		r2, [r1]
	
	// Setze Flags zurück.
	ldr		r1, =is_alarm_lapsed
	ldr		r2, =is_second_lapsed
	str		r0, [r1]
	str		r0, [r2]
	
	// Gib Aktion auf der Konsole aus.
	ldr		r0, =mode_24h
	bl		uart_putString
	
	b		loop
	
handle_h:
	// Deaktiviere Timer Counter.
	mov		r0, #0
	ldr		r1, =RTC_SR
	str		r0, [r1]
	
	// Setze Alarm auf 59:59.
	ldr		r2, =ALARM_1H
	ldr		r3, =RTC_TAR
	str		r2, [r3]
	
	// Setze Timer Counter zurück.
	ldr		r2, =RTC_TSR
	str		r0, [r2]
	
	// Reaktiviere Timer Counter.
	mov		r2, #TCE
	str		r2, [r1]
	
	// Setze Flags zurück.
	ldr		r1, =is_alarm_lapsed
	ldr		r2, =is_second_lapsed
	str		r0, [r1]
	str		r0, [r2]
	
	// Gib Aktion auf der Konsole aus.
	ldr		r0, =mode_1h
	bl		uart_putString
	
	b		loop

handle_r:
	// Deaktiviere Timer Counter.
	mov		r0, #0
	ldr		r1, =RTC_SR
	str		r0, [r1]
	
	// Setze Timer Counter zurück.
	ldr		r2, =RTC_TSR
	str		r0, [r2]
	
	// Reaktiviere Timer Counter.
	mov		r2, #TCE
	str		r2, [r1]
	
	// Setze Flags zurück.
	ldr		r1, =is_alarm_lapsed
	ldr		r2, =is_second_lapsed
	str		r0, [r1]
	str		r0, [r2]
	
	// Gib Aktion auf der Konsole aus.
	ldr		r0, =timer_reset
	bl		uart_putString
	
	b		loop

handle_s:
	// Starte, bzw. stoppe Anzeige der Uhrzeit.
	ldr		r0, =is_output_enabled
	ldr		r1, [r0]
	eors	r1, r1, #1		// Falls Anzeige gestoppt wurde, ist 'z' = 1. 
	str		r1, [r0]
	
	// Gib Aktion auf der Konsole aus.
	ite		eq
	ldreq	r0, =stop_output
	ldrne	r0, =start_output
	bl		uart_putString
	
	b		loop

handle_p:
	// Prüfe, ob gerade der 24h-Modus aktiviert ist.
	ldr		r0, =ALARM_24H
	ldr		r1, =RTC_TAR
	ldr		r2, [r1]
	teq		r2, r0
	ite		eq
	ldreq	r3, =PRESET_24H
	ldrne	r3, =PRESET_1H
	
	// Deaktiviere Timer Counter.
	mov		r0, #0
	ldr		r1, =RTC_SR
	str		r0, [r1]
	
	// Stelle Timer Counter vor.
	ldr		r2, =RTC_TSR
	str		r3, [r2]
	
	// Reaktiviere Timer Counter.
	mov		r2, #TCE
	str		r2, [r1]
	
	// Setze Flags zurück.
	ldr		r1, =is_alarm_lapsed
	ldr		r2, =is_second_lapsed
	str		r0, [r1]
	str		r0, [r2]
	
	// Gib Aktion auf der Konsole aus.
	ldr		r0, =timer_preset
	bl		uart_putString
	
	b 		loop


/*
* Unterprogramm (uart_put_24h): Gib die aktuelle Uhrzeit im Format HH:MM:SS
* aus.
*/
.thumb_func
uart_put_24h:
	push	{lr}
	
	// Beschränke die Uhrzeit auf 00:00:00 - 23:59:59.
	ldr		r0, =RTC_TSR
	ldr		r1, =MODULO_24H
	ldr		r2, [r0]
	udiv	r3, r2, r1
	mul		r1, r3, r1
	sub		r2, r2, r1
	
	// Bestimme die Anzahl der Stunden.
	ldr		r1, =MODULO_1H
	udiv	r0, r2, r1
	
	// Gib die Anzahl der Stunden aus.
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	
	// Gib die Anzahl der Minuten und Sekunden aus.
	mov		r0, #COLON
	bl		uart_putChar
	bl		uart_put_1h
	
	pop		{pc}


/*
* Unterprogramm (uart_put_1h): Gib die aktuelle Uhrzeit im Format MM:SS aus.
*/
.thumb_func
uart_put_1h:
	push	{r4, lr}
	
	// Beschränke die Uhrzeit auf 00:00 - 59:59.
	ldr		r0, =RTC_TSR
	ldr		r1, =MODULO_1H
	ldr		r2, [r0]
	udiv	r3, r2, r1
	mul		r1, r3, r1
	sub		r2, r2, r1
	
	// Bestimme die Anzahl der Minuten und Sekunden.
	ldr		r1, =MODULO_1M
	udiv	r0, r2, r1		// Anzahl der Minuten.
	mul		r1, r0, r1
	sub		r4, r2, r1		// Anzahl der Sekunden.
	
	// Gib die Anzahl der Minuten aus.
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	mov		r0, #COLON
	bl		uart_putChar
	
	// Gib die Anzahl der Sekunden aus.
	mov		r0, r4
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	mov		r0, #NL
	bl		uart_putChar
	
	pop		{r4, pc}


/*
* Interrupt Service Routine (handle_rtc_alarm_irq): Behandle eine Unter-
* brechung durch RTC ausgelöst durch einen RTC-Alarm oder einen Timer-Overflow.
*/
.thumb_func
handle_rtc_alarm_irq:
	ldr		r0, =RTC_SR
	ldr		r1, [r0]
	
	// Prüfe Quelle der Unterbrechungsanforderung.
	tst		r1, #TAF
	beq		check_timer_overflow
	
	// Setze TAF zurück.
	ldr		r2, =RTC_TAR
	ldr		r3, [r2]
	str		r3, [r2]
	
	// Setze Alarm-Flag.
	ldr		r2, =is_alarm_lapsed
	mov		r3, #1
	str		r3, [r2]
	
check_timer_overflow:
	tst		r1, #(TOF | TIF)
	beq		return_rtc_alarm
	
	// Deaktiviere Zähler.
	mov		r1, #0
	str		r1, [r0]
	
	// Reinitialisiere Zählerregister.
	ldr		r2, =RTC_TSR
	str		r1, [r2]
	
	// Reaktiviere Zähler
	mov		r1, #TCE
	str		r1, [r0]
	
return_rtc_alarm:
	bx		lr


/*
* Interrupt Service Routine (handle_rtc_second_irq): Behandle eine Unter-
* brechung durch den Ablauf einer RTC-Periode/-Sekunde.
*/
.thumb_func
handle_rtc_second_irq:
	mov		r0, #1
	ldr		r1, =is_second_lapsed
	str		r0, [r1]
	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
is_output_enabled:
	.word	0x01

is_alarm_lapsed:
	.word	0x00
	
is_second_lapsed:
	.word	0x00
	
mode_24h:
	.asciz	"24-Stunden-Modus\n"
	
mode_1h:
	.asciz	"1-Stunden-Modus\n"
	
timer_reset:
	.asciz	"Uhr zurueckgesetzt\n"

start_output:
	.asciz	"Anzeige an\n"

stop_output:
	.asciz	"Anzeige aus\n"

timer_preset:
	.asciz	"Uhr vorgestellt\n"

alarm_lapsed:
	.asciz	"Endzeitpunkt erreicht\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ NIBBLE,			4
.equ SEC, 				25000000
.equ ENABLE,			0xff
.equ SEC_PRO_24H,		86400	// 24h 0min 0sec in Sekunden.
.equ SEC_PRO_1H,		3600	// 1h 0min 0sec in Sekunden.
.equ SEC_PRO_1M,		60		// 1min 0sec in Sekunden.
.equ MAX_YEARS,			99
.equ MAX_MONTHS,		12
.equ MAX_DAYS,			30
.equ MAX_HOURS,			23
.equ MAX_MINS,			59
.equ MAX_SECS,			59
.equ BIT_OFFSET_YEARS,	49
.equ BIT_OFFSET_MONTHS,	44
.equ BIT_OFFSET_DAYS,	35
.equ BIT_OFFSET_HOURS,	28
.equ BIT_OFFSET_MINS,	20

.equ PULS_0BIT,			(SEC / 10)		// 0-Bit hat 100ms Pulslänge.
.equ PULS_1BIT,			(SEC * 2 / 10)	// 1-Bit hat 200ms Pulslänge.

.equ COLON,				':'
.equ NL,				'\n'

.equ CHAR_S,			's'

// Interrupt-Vektor-Konstanten
.equ IVT,				0x1ffffe00			// Basisadresse der IVT.
.equ IVT_RTC,			IVT + 0x40 + (67 << 2)	// IV-Tabellenindex für IRQ 67 (RTC Sekunden-Interrupt).
.equ IVT_PIT1,			IVT + 0x40 + (69 << 2)	// IV-Tabellenindex für IRQ 69 (PIT1).
.equ IRQ_RTC,			(1 << (67 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 67 (RTC Sekunden-Interrupt).
.equ IRQ_PIT1,			(1 << (69 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 69 (PIT1).

// Nested Interrupt Controller (NVIC) Registeradressen
.equ NVIC_ISER2,		0xe000e100 + 2 << 2
.equ NVIC_ICPR2,		0xe000e280 + 2 << 2

// Port Control and Interrupts (PORT) Registeradressen
.equ PORTA_PCR6,		0x40049018
.equ PORTA_PCR10,		0x40049028

// System Integration Module (SIM) Registeradressen
.equ SIM_SCGC5,			0x40048038
.equ SIM_SCGC6,			0x4004803c

// Periodic Interrupt Timer (PIT) Registeradressen
.equ PIT_MCR,			0x40037000
.equ PIT_LDVAL1,		0x40037110
.equ PIT_TCTRL1,		0x40037118
.equ PIT_TFLG1,			0x4003711c

// Real Time Clock (RTC) Registeradressen
.equ RTC_TSR,			0x4003d000
.equ RTC_TPR,			0x4003d004
.equ RTC_TAR,			0x4003d008
.equ RTC_TCR,			0x4003d00c
.equ RTC_CR,			0x4003d010
.equ RTC_SR,			0x4003d014
.equ RTC_LR,			0x4003d018
.equ RTC_IER,			0x4003d01c
.equ RTC_WAR,			0x4003d800
.equ RTC_RAR,			0x4003d804

// General-Purpose I/O (GPIO) Registeradressen
.equ GPIOA_PSOR,		0x400ff004
.equ GPIOA_PCOR,		0x400ff008
.equ GPIOA_PDDR,		0x400ff014

// Steuerwörter
.equ PIN10,				(1 << 10)
.equ PIN6,				(1 << 6)
.equ ALT1,				(1 << 8)	// Betreibe PORT Pin im GPIO-Modus.
.equ RTC,				(1 << 29)	// Aktiviere Takt für RTC in SIM.
.equ PIT,				(1 << 23)	// Aktiviere Takt für PIT in SIM.
.equ TIE,				(1 << 1)	// Aktiviere Interrups für den ausgewählten PIT-Kanal.
.equ TEN,				(1)			// Aktiviere den ausgewählten PIT-Kanal.
.equ CLKO,				(1 << 9)	// Deaktiviere die Ausgabe des RTC-Signals an andere Peripheriemodule.
.equ OSCE,				(1 << 8)	// Aktiviere den RTC-Oszillator.
.equ UM,				(1 << 3)	// Erlaube TCE-Bit selbst dann zu setzen, wenn RTC_SR gesperrt ist.
.equ SUP,				(1 << 2)	// Deaktiviere Schreibbeschränkungen für unprivilegierten Code.
.equ TCE,				(1 << 4)	// Aktiviere Timer Counter.
.equ TAF,				(1 << 2)	// Prüfe, ob ein Alarm ausgelöst wurde.
.equ TOF,				(1 << 1)	// Prüfe, ob es zu einem Zählerüberlauf kam.
.equ TIF,				(1 << 0)	// Prüfe, ob die Zeit ungültig ist.
.equ TSIE,				(1 << 4)	// Aktiviere Sekunden-Interrupt.
.equ TAIE,				(1 << 2)	// Aktiviere Alarm-Interrupt.
.equ TOIE,				(1 << 1)	// Aktiviere Zählerüberlauf-Interrupt.

// Bitband-Alias Adressen
__BBREG SIM_SCGC5_PORTA,	SIM_SCGC5, 	9
__BBREG PIT_TCTRL1_TEN,		PIT_TCTRL1, 0

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Aktiviere Takt für PORTA.
	mov		r0, #1
	ldr		r1, =SIM_SCGC5_PORTA
	str		r0, [r1]
	
	// Aktiviere Takt für RTC- und PIT-Modul.
	ldr		r0, =SIM_SCGC6
	ldr		r1, [r0]
	orr		r1, r1, #(RTC | PIT)
	str		r1, [r0]
	
	// Setze Interrupt-Vektor zu RTC-Seconds.
	ldr		r0, =handle_rtc_irq
	ldr		r1, =IVT_RTC
	str		r0, [r1]
	
	// Setze Interrupt-Vektor zu PIT1.
	ldr		r0, =handle_pit1_irq
	ldr		r1, =IVT_PIT1
	str		r0, [r1]
	
	// Konfiguriere PORTA Pin 6 und 10 als GPIO.
	mov		r0, #ALT1
	ldr		r1, =PORTA_PCR6
	ldr		r2, =PORTA_PCR10
	str		r0, [r1]
	str		r0, [r2]
	
	// Ziehe GPIOA Pins 6 und 10 auf hohes Potenzial und konfiguriere als
	// Ausgang.
	mov		r0, #(PIN10 | PIN6)
	ldr		r1, =GPIOA_PSOR
	str		r0, [r1]
	ldr		r1, =GPIOA_PDDR
	ldr		r2, [r1]
	orr		r2, r2, r0
	str		r2, [r1]
	
	// Aktiviere die PITs und lösche anhängende Interrupts.
	mov		r4, #0
	ldr		r0, =PIT_MCR
	ldr		r1, =PIT_TFLG1
	str		r4, [r0]
	str		r4, [r1]
	
	// Initialisiere Zähler auf eine Sekunde.
	ldr		r0, =SEC
	ldr		r1, =PIT_LDVAL1
	str		r0, [r1]
	
	// Setze Schreib- und Leserechte für alle RTC-Register.
	mov		r0, #ENABLE
	ldr		r1, =RTC_LR
	ldr		r2, =RTC_WAR
	ldr		r3, =RTC_RAR
	str		r0, [r1]
	str		r0, [r2]
	str		r0, [r3]
	
	// Deaktiviere Ausgabe des RTC-Signals und deaktiviere Schreibbeschränk-
	// ungen der RTC-Register.
	mov		r0, #(CLKO | OSCE | UM | SUP)
	ldr		r1, =RTC_CR
	str		r0, [r1]
	
	// Aktiviere den PIT1.
	mov		r0, #TEN
	ldr		r6, =PIT_TCTRL1
	str		r0, [r6]
	ldr		r1, =PIT_TFLG1

wait_osc_startup:
	// Warte, bis sich RTC-Oszillator stablisiert hat (1000ms).
	ldr		r0, [r1]
	teq		r0, #0
	beq		wait_osc_startup
	
	// Deaktiviere PIT-Modul, aktiviere Interrupts.
	mov		r0, #TIE
	str		r0, [r6]
	
	// Deaktiviere Timer Counter.
	ldr		r6, =RTC_SR
	str		r4, [r6]
	
	// Setze Kompensationsregister zurück.
	ldr		r0, =RTC_TCR
	str		r4, [r0]
	
	// Setze Prescalerregister zurück.
	ldr		r0, =RTC_TPR
	str		r4, [r0]
	
	// Setze Alarmregister zurück.
	ldr		r0, =RTC_TAR
	str		r4, [r0]
	
	// Frage Datum und Uhrzeit ab.
	bl		uart_get_datetime
	
	// Setze Sekundenregister.
	ldr		r0, =seconds
	ldr		r1, [r0]
	ldr		r0, =RTC_TSR
	str		r1, [r0]
	
	// Aktiviere Timer Counter.
	mov		r0, #TCE
	str		r0, [r6]
	
	// Aktiviere Interrupts für Sekunden.
	mov		r0, #TSIE
	ldr		r1, =RTC_IER
	str		r0, [r1]
	
	// Lösche anhängende Interrupts und anschließend aktiviere Interrupts für
	// RTC-Seconds und PIT1.
	mov		r0, #(IRQ_RTC | IRQ_PIT1)
	ldr		r1, =NVIC_ICPR2
	ldr		r2, =NVIC_ISER2
	str		r0, [r1]
	str		r0, [r2]
	
loop:
	ldr		r0, =is_second_lapsed
	ldr		r1, [r0]
	teq		r1, #0
	beq		handle_input
	
	// Setze Flag zurück.
	mov		r1, #0
	str		r1, [r0]

	// Aktualisiere Sekundenzahl.
	ldr		r0, =seconds
	mov		r1, #MAX_SECS
	ldr		r4, [r0]
	add		r4, r4, #1
	cmp		r4, r1
	it		hi
	movhi	r4, #0
	str		r4, [r0]
	bls		print_datetime
	
	// Aktualsiere Minutenzahl.
	ldr		r0, =minutes
	ldr		r2, [r0]
	add		r2, r2, #1
	cmp		r2, r1
	it		hi
	movhi	r2, #0
	str		r2, [r0]
	bls		print_datetime
	
	// Aktualisiere Stundenzahl.
	ldr		r0, =hours
	mov		r1, #MAX_HOURS
	ldr		r2, [r0]
	add		r2, r2, #1
	cmp		r2, r1
	it		hi
	movhi	r2, #0
	str		r2, [r0]
	bls		print_datetime
	
	// Aktualisiere Monatstag.
	ldr		r0, =day
	mov		r1, #MAX_DAYS
	ldr		r2, [r0]
	add		r2, r2, #1
	cmp		r2, r1
	it		hi
	movhi	r2, #1
	str		r2, [r0]
	bls		print_datetime
	
	// Aktualisiere Monat.
	ldr		r0, =month
	mov		r1, #MAX_MONTHS
	ldr		r2, [r0]
	add		r2, r2, #1
	cmp		r2, r1
	it		hi
	movhi	r2, #1
	str		r2, [r0]
	bls		print_datetime
	
	// Aktualisiere Jahr.
	ldr		r0, =year
	mov		r1, #MAX_YEARS
	ldr		r2, [r0]
	add		r2, r2, #1
	cmp		r2, r1
	it 		hi
	movhi	r2, #0
	str		r2, [r0]

print_datetime:
	// Prüfe, ob eine Minute vergangen ist.
	teq		r4, #0
	bne		print_signal_bit
	
	// Gib die Uhrzeit aus.
	bl		uart_put_time
	
	// Berechne Datum und Uhrzeit für die kommende Minute.
	bl		update_next_datetime

print_signal_bit:
	// Gib aktuelles Signalbit auf der Konsole aus.
	ldr		r0, =PULS_0BIT
	ldr		r1, =next_pulse_width
	ldr		r2, [r1]
	
	cmp		r2, r0
	blo		print_end_marker
	ite		hi
	movhi	r0, #1
	movls	r0, #0
	bl		uart_putByteBase10
	
	b		set_next_pulse
	
print_end_marker:
	// Terminiere aktuelle Signalbitsequenz.
	mov		r0, #NL
	bl		uart_putChar

set_next_pulse:	
	// Bestimme das Signalbit für den nächsten Puls.
	ldr		r0, =transition_table
	tbb		[r0, r4]

case_const0:
	// Setze ein 0-Bit als nächstes Signalbit.
	ldr		r0, =PULS_0BIT
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_const1:
	// Setze ein 1-Bit als nächstes Signalbit.
	ldr		r0, =PULS_1BIT
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_minutes:
	// Berechne nächste zu signalisierende Minute.
	ldr		r1, =minutes
	ldr		r0, [r1, #4] 
	bl		cast_bcd
	
	// Berechne nächste zu signalisierende Bitposition.
	sub		r2, r4, #(BIT_OFFSET_MINS - 1)
	lsrs	r2, r0, r2
	ite		cc
	ldrcc	r0, =PULS_0BIT
	ldrcs	r0, =PULS_1BIT
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_minutes_parity:
	// Berechne signalisierte Minute.
	ldr		r1, =minutes
	ldr		r0, [r1, #4]
	bl		cast_bcd
	
	mov		r1, #0

loop_minutes_parity:
	// Berechne Parität.
	lsrs	r0, r0, #1
	adc		r1, r1, #0
	bne		loop_minutes_parity
	
	// Setze nächstes Signalbit.
	tst		r1, #1				// Teste, ob gerade oder ungerade.
	ite		eq
	ldreq	r0, =PULS_0BIT		// Bei gerade Bitzahl ist Paritätsbit 0.
	ldrne	r0, =PULS_1BIT		// Bei ungerader Bitzahl ist Paritätsbit 1.
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_hours:
	// Berechne nächste zu signalisierende Stunde.
	ldr		r1, =hours
	ldr		r0, [r1, #4] 
	bl		cast_bcd
	
	// Berechne nächste zu signalisierende Bitposition.
	sub		r2, r4, #(BIT_OFFSET_HOURS - 1)
	lsrs	r2, r0, r2
	ite		cc
	ldrcc	r0, =PULS_0BIT
	ldrcs	r0, =PULS_1BIT
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_hours_parity:
	// Berechne signalisierte Stunde.
	ldr		r1, =hours
	ldr		r0, [r1, #4]
	bl		cast_bcd
	
	mov		r1, #0

loop_hours_parity:
	// Berechne Parität.
	lsrs	r0, r0, #1
	adc		r1, r1, #0
	bne		loop_hours_parity
	
	// Setze nächstes Signalbit.
	tst		r1, #1				// Teste, ob gerade oder ungerade.
	ite		eq
	ldreq	r0, =PULS_0BIT		// Bei gerade Bitzahl ist Paritätsbit 0.
	ldrne	r0, =PULS_1BIT		// Bei ungerader Bitzahl ist Paritätsbit 1.
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_days:
	// Berechne nächsten zu signalisierenden Monatstag.
	ldr		r1, =day
	ldr		r0, [r1, #4] 
	bl		cast_bcd
	
	// Berechne nächste zu signalisierende Bitposition.
	sub		r2, r4, #(BIT_OFFSET_DAYS - 1)
	lsrs	r2, r0, r2
	ite		cc
	ldrcc	r0, =PULS_0BIT
	ldrcs	r0, =PULS_1BIT
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_month:
	// Berechne nächsten zu signalisierenden Monat.
	ldr		r1, =month
	ldr		r0, [r1, #4] 
	bl		cast_bcd
	
	// Berechne nächste zu signalisierende Bitposition.
	sub		r2, r4, #(BIT_OFFSET_MONTHS - 1)
	lsrs	r2, r0, r2
	ite		cc
	ldrcc	r0, =PULS_0BIT
	ldrcs	r0, =PULS_1BIT
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_year:
	// Berechne nächstes zu signalisierendes Jahr.
	ldr		r1, =year
	ldr		r0, [r1, #4] 
	bl		cast_bcd
	
	// Berechne nächste zu signalisierende Bitposition.
	sub		r2, r4, #(BIT_OFFSET_YEARS - 1)
	lsrs	r2, r0, r2
	ite		cc
	ldrcc	r0, =PULS_0BIT
	ldrcs	r0, =PULS_1BIT
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_date_parity:
	// Berechne signalisierten Tag.
	ldr		r1, =day
	ldr		r0, [r1, #4]
	bl		cast_bcd
	
	mov		r4, #0

loop_day_parity:
	// Berechne Parität des Monatstags.
	lsrs	r0, r0, #1
	adc		r4, r4, #0
	bne		loop_day_parity
	
	// Füge festkodierte Bits des Wochentags hinzu.
	add		r4, r4, #3
	
	// Berechne signalisierten Monat.
	ldr		r1, =month
	ldr		r0, [r1, #4]
	bl		cast_bcd
	
loop_month_parity:
	// Füge Monatsbits hinzu.
	lsrs	r0, r0, #1
	adc		r4, r4, #0
	bne		loop_month_parity
	
	// Berechne signalisiertes Jahr.
	ldr		r1, =year
	ldr		r0, [r1, #4]
	bl		cast_bcd
	
loop_year_parity:
	// Füge Jahresbits hinzu.
	lsrs	r0, r0, #1
	adc		r4, r4, #0
	bne		loop_year_parity
	
	// Setze nächstes Signalbit.
	tst		r4, #1				// Teste, ob gerade oder ungerade.
	ite		eq
	ldreq	r0, =PULS_0BIT		// Bei gerade Bitzahl ist Paritätsbit 0.
	ldrne	r0, =PULS_1BIT		// Bei ungerader Bitzahl ist Paritätsbit 1.
	ldr		r1, =next_pulse_width
	str		r0, [r1]
	
	b		handle_input

case_const_none:
	// Setze kein Signalbit im nächsten Pulsinterval.
	mov		r0, #0
	ldr		r1, =next_pulse_width
	str		r0, [r1]

handle_input:
	bl		uart_charPresent
	teq		r0, #0
	beq		end
	
	// Lade Benutzereingabe.
	bl		uart_getChar
	
	// Falls 's' eingegeben wurde, fordere Eingabe von neuem Datum und Uhrzeit
	// an.
	teq		r0, #CHAR_S
	bne		end
	
	// Deaktiviere Timer Counter.
	mov		r0, #0
	ldr		r4, =RTC_SR
	str		r0, [r4]
	
	// Stoppe PIT1.
	ldr		r5, =PIT_TCTRL1_TEN
	str		r0, [r5]
	
	// Fordere Benutzer zur Eingabe auf.
	mov		r0, #NL
	bl		uart_putChar
	bl		uart_get_datetime

	// Lösche Flags.
	mov		r0, #0
	ldr		r1, =is_second_lapsed
	str		r0, [r1]
	
	// Setze Sekundenregister.
	ldr		r0, =seconds
	ldr		r1, [r0]
	ldr		r0, =RTC_TSR
	str		r1, [r0]
	
	// Aktiviere Timer Counter.
	mov		r0, #TCE
	str		r0, [r4]

end:
	wfi
	b		loop


/*
* Unterprogramm (cast_bcd): Wandle eine Binärzahl im Bereich 0-99 um in Binary-
* Decimal-Format um.
*/
.thumb_func
cast_bcd:
	// Berechne 10er Ziffer.
	mov		r1, #10
	udiv	r2, r0, r1
	
	// Berechne 1er Ziffer.
	mul		r3, r2, r1
	sub		r3, r0, r3
	
	// Setze zweistellige BCD-Zahl wieder zusammen.
	orr		r0, r3, r2, lsl #NIBBLE
	
	bx		lr


/*
* Unterprogramm (update_next_datetime): Berechne Datum und Uhrzeit des aus-
* zugebenden DCF77-Signals. Das DCF77-Signal codiert jeweils das Datum, die
* Uhrzeit und weitere Daten der Minute, die auf die gegenwärtige Signalperiode
* folgt.
*/
.thumb_func
update_next_datetime:
	// Leite nächste Minute ab.
	ldr		r0, =minutes
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_MINS
	itte	hi
	movhi	r1, #0
	movhi	r2, #1					// Carry-Forward für Minutenüberlauf.
	movls	r2, #0
	str		r1, [r0, #4]
	
	// Leite nächste Stunde ab.
	ldr		r0, =hours
	ldr		r1, [r0]
	add		r1, r1, r2
	cmp		r1, #MAX_HOURS
	ite		hi
	movhi	r1, #0
	movls	r2, #0
	str		r1, [r0, #4]
	
	// Leite nächsten Monatstag ab.
	ldr		r0, =day
	ldr		r1, [r0]
	add		r1, r1, r2
	cmp		r1, #MAX_DAYS
	ite		hi
	movhi	r1, #1
	movls	r2, #0
	str		r1, [r0, #4]
	
	// Leite nächsten Monat ab.
	ldr		r0, =month
	ldr		r1, [r0]
	add		r1, r1, r2
	cmp		r1, #MAX_MONTHS
	ite		hi
	movhi	r1, #1
	movls	r2, #0
	str		r1, [r0, #4]
	
	// Leite nächstes Jahr ab.
	ldr		r0, =year
	ldr		r1, [r0]
	add		r1, r1, r2
	cmp		r1, #MAX_YEARS
	it		hi
	movhi	r1, #0
	str		r1, [r0, #4]
	
	bx		lr


/*
* Unterprogramm (uart_get_datetime): Fordere Benutzer zur Eingabe eines neuen
* Datums und einer neuen Uhrzeit auf und aktualisiere damit die lokale Zeit des
* Programs.
*/
.thumb_func
uart_get_datetime:
	push	{lr}
	
	// Gib Jahreszahl ein.
	ldr		r0, =prompt_year
	bl		uart_putString
	bl		uart_getByteBase10
	ldr		r1, =year
	str		r0, [r1]
	bl		uart_putByteBase10
	
	// Gib Monatszahl ein.
	ldr		r0, =prompt_month
	bl		uart_putString
	bl		uart_getByteBase10
	ldr		r1, =month
	str		r0, [r1]
	bl		uart_putByteBase10

	// Gib Monatstag ein.
	ldr		r0, =prompt_day
	bl		uart_putString
	bl		uart_getByteBase10
	ldr		r1, =day
	str		r0, [r1]
	bl		uart_putByteBase10

	// Gib Stunde ein.
	ldr		r0, =prompt_hour
	bl		uart_putString
	bl		uart_getByteBase10
	ldr		r1, =hours
	str		r0, [r1]
	bl		uart_putByteBase10

	// Gib Minute ein.
	ldr		r0, =prompt_minute
	bl		uart_putString
	bl		uart_getByteBase10
	ldr		r1, =minutes
	str		r0, [r1]
	bl		uart_putByteBase10

	// Gib Sekunde ein.
	ldr		r0, =prompt_second
	bl		uart_putString
	bl		uart_getByteBase10
	ldr		r1, =seconds
	str		r0, [r1]
	bl		uart_putByteBase10
	mov		r0, #NL
	bl		uart_putChar
	
	bl		update_next_datetime
	
	pop		{pc}


/*
* Unterprogramm (uart_put_24h): Gib die aktuelle Uhrzeit im Format HH:MM:SS
* aus.
*/
.thumb_func
uart_put_time:
	push	{lr}
	
	// Gib die Anzahl der Stunden aus.
	ldr		r1, =hours
	ldr		r0, [r1]
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	mov		r0, #COLON
	bl		uart_putChar
	
	// Gib die Anzahl der Minuten aus.
	ldr		r1, =minutes
	ldr		r0, [r1]
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	mov		r0, #COLON
	bl		uart_putChar
	
	// Gib die Anzahl der Sekunden aus
	ldr		r1, =seconds
	ldr		r0, [r1]
	cmp		r0, #10
	ite		hs
	ldrhs	r1, =uart_putByteBase10
	ldrlo	r1, =uart_putByte
	blx		r1
	mov		r0, #NL
	bl		uart_putChar
	
	pop		{pc}


/*
* Interrupt Service Routine (handle_rtc_irq): Behandle eine Unterbrechung aus-
* gelöst durch eine RTC-Sekunde. Nach Ablauf jeder Sekunde wird ein Puls auf
* GPIOA Pin 6 ausgegeben und PIT1 mit der Pulsweite geladen.
*/
.thumb_func
handle_rtc_irq:
	mov		r0, #1
	ldr		r1, =is_second_lapsed
	str		r0, [r1]
	
	// Lade das nächste DCF77-Signalbit.
	ldr		r0, =next_pulse_width
	ldr		r1, [r0]
	cbz		r1, return_handle_rtc
	
	// Lade PIT1 mit Pulsweite.
	ldr		r0, =PIT_LDVAL1
	str		r1, [r0]
	
	// Aktiviere PIT1.
	mov		r0, #1
	ldr		r1, =PIT_TCTRL1_TEN
	str		r0, [r1]
	
	// Ziehe GPIOA Pins 6 und 11 auf niedriges Potenzial.
	mov		r0, #(PIN10 | PIN6)
	ldr		r1, =GPIOA_PCOR
	str		r0, [r1]
	
return_handle_rtc:
	bx		lr


/*
* Interrupt Service Routine (handle_pit1_irq): Behandle einen PIT1-Interrupt.
* Der PIT1 wird nach Ablauf jeder RTC-Sekunde mit einer Pulsweite geladen, die
* dem kodierten Signal entspricht. Nach Ablauf des PIT1-Zählers wird das Signal
* wieder auf hohes Potenzial zurückgesetzt.
*/
.thumb_func
handle_pit1_irq:
	// Quittiere Interrupt.	
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	
	// Ziehe GPIOA Pins 6 und 11 auf hohes Potenzial.
	mov		r0, #(PIN10 | PIN6)
	ldr		r1, =GPIOA_PSOR
	str		r0, [r1]
	
	// Deaktiviere PIT1.
	mov		r0, #0
	ldr		r1, =PIT_TCTRL1_TEN
	str		r0, [r1]
	
	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
transition_table:
	// Bits 1 - 16
	.rept	16
	.byte	0x00								
	.endr
	
	// Bit  17 (CEST)
	.byte	(case_const1 - case_const0) / 2
	
	// Bits 18 - 19
	.rept	2
	.byte	0x00								
	.endr
	
	// Bit 	20 (Start der kodierten Zeit)
	.byte	(case_const1 - case_const0) / 2
	
	// Bits 21 - 27 (Minuten)
	.rept	7
	.byte	(case_minutes - case_const0) / 2
	.endr
	
	// Bit  28 (Parität über die Minutenzahl)
	.byte	(case_minutes_parity - case_const0) / 2
	
	// Bits 29 - 34 (Stunden)
	.rept	6
	.byte	(case_hours - case_const0) / 2
	.endr
	
	// Bit  34 (Parität über die Stundenzahl)
	.byte	(case_hours_parity - case_const0) / 2
	
	// Bits 36 - 41 (Monatstag)
	.rept	6
	.byte	(case_days - case_const0) / 2
	.endr
	
	// Bits 42 - 44 (Wochentag - festkodiert auf Sonntag)
	.rept	3
	.byte	(case_const1 - case_const0) / 2
	.endr
	
	// Bits 45 - 49 (Monat)
	.rept	5
	.byte	(case_month - case_const0) / 2
	.endr
	
	// Bits 50 - 57 (Jahr)
	.rept	8
	.byte	(case_year - case_const0) / 2
	.endr
	
	// Bit	58 (Parität über das Datum)
	.byte	(case_date_parity - case_const0) / 2
	
	// Bit	59 (Minutenmarke)
	.byte	(case_const_none - case_const0) / 2
	
	// Bit	0 (Start der Minute)
	.byte	0x00

year:
	.word	0x00	// Aktuelles Jahr.
	.word	0x00	// Nächstes anzuzeigendes Jahr.

month:
	.word	0x00	// Aktueller Monat.
	.word	0x00	// Nächster anzuzeigender Monat.

day:
	.word	0x00	// Aktueller Tag.
	.word	0x00	// Nächster anzuzeigender Tag.

hours:
	.word	0x00	// Aktuelle Stunde.
	.word	0x00	// Nächste anzuzeigende Stunde.

minutes:
	.word	0x00	// Aktuelle Minute.
	.word	0x00	// Nächste Anzuzeigende Minute.

seconds:
	.word	0x00

next_pulse_width:
	.word	0x00

is_second_lapsed:
	.word	0x00

prompt_year:
	.asciz	"Jahr (0 - 99): "

prompt_month:
	.asciz	"\nMonat (1 - 12): "

prompt_day:
	.asciz	"\nTag (1 - 30): "

prompt_hour:
	.asciz	"\nStunde (0 - 23): "

prompt_minute:
	.asciz	"\nMinute (0 - 59): "

prompt_second:
	.asciz	"\nSekunde (0 - 59): "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SEC, 				25000000
.equ MS,				(SEC / 1000)

.equ NL,				'\n'
.equ CHAR_PLUS,			'+'
.equ CHAR_MINUS,		'-'
.equ CHAR_0,			'0'
.equ CHAR_9,			'9'

// Interrupt-Vektor-Konstanten
.equ IVT,				0x1ffffe00			// Basisadresse der IVT.
.equ IVT_FTM0,			IVT + 0x40 + (62 << 2)	// IV-Tabellenindex für IRQ 62 (FTM0).
.equ IRQ_FTM0,			(1 << (62 % 32))	// NVIC-Bitmaske zur Selektion von IRQ 62 (FTM0).

// Nested Interrupt Controller (NVIC) Registeradressen
.equ NVIC_ISER1,		0xe000e100 + 1 << 2
.equ NVIC_ICPR1,		0xe000e280 + 1 << 2

// Port Control and Interrupts (PORT) Registeradressen
.equ PORTA_PCR6,		0x40049018
.equ PORTA_PCR10,		0x40049028

// System Integration Module (SIM) Registeradressen
.equ SIM_SCGC5,			0x40048038
.equ SIM_SCGC6,			0x4004803c

// Flexible Timer Module (FTM) Registeradressen
.equ FTM0_SC,			0x40038000
.equ FTM0_CNT,			0x40038004
.equ FTM0_MOD,			0x40038008
.equ FTM0_C3SC,			0x40038024
.equ FTM0_C3V,			0x40038028
.equ FTM0_CNTIN,		0x4003804c
.equ FTM0_MODE,			0x40038054
.equ FTM0_SYNC,			0x40038058
.equ FTM0_CONF,			0x40038084
.equ FTM0_SYNCONF,		0x4003808c
.equ FTM0_PWMLOAD,		0x40038098

// Steuerwörter
.equ ALT3,				(3 << 8)
.equ ALT1,				(1 << 8)
.equ PIN10,				(1 << 10)
.equ BDMMODE,			(3 << 6)	// Wähle BDM-Modus so, dass FTM seine Funktion im BDM-Modus weiter ausführt.
.equ WPDIS,				(1 << 2)	// Deaktiviere Schreibschutz der FTM-Register.
.equ FTMEN,				(1)			// Aktiviere alle FTM-Funktionen (nicht nur TPM).
.equ MOD,				(MS - 1)	// Setze Grundfrequenz des PWM-Signals auf 1kHz.
.equ CHIE,				(1 << 6)	// Aktiviere Channel-Interrupts für den gewählten FTM-Channel. 
.equ MSB,				(1 << 5)	// Setze Channelmodus auf PWM für FTM.
.equ ELSB,				(1 << 3)	// Konfiguriere High-true Puls auf dem FTM-Channel.
.equ VAL,				(MOD / 2)	// Setze initale Impulsdauer des FTM-Channels auf die Hälfte der Grundfrequenz.
.equ TOIE,				(1 << 6)	// Aktiviere Timer-Overflow-Interrupts für das FTM-Modul.
.equ CLKS,				(1 << 3)	// Wähle den Systemtakt als Taktquelle für das FTM-Modul.
.equ CNTMIN,			(1)			// Setze Ladepunkt bei niedrigstem Zählerwert für das FTM-Modul.
.equ SYNCMODE,			(1 << 7)	// Aktiviere erweiterte PWM-Synchronisation für das FTM-Modul.
.equ LDOCK,				(1 << 9)	// Aktiviere Registerupdates für MOD, CNTIN und CV für das FTM-Modul.

// Bitband-Alias Adressen
__BBREG SIM_SCGC5_PORTA,	SIM_SCGC5,	9
__BBREG SIM_SCGC6_FTM0,		SIM_SCGC6,	24
__BBREG FTM0_SC_TOF,		FTM0_SC,	7
__BBREG FTM0_C3SC_CHF,		FTM0_C3SC,	7
__BBREG	FTM0_C3SC_ELSA,		FTM0_C3SC,	2

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Aktiviere Takt für PORTA.
	mov		r0, #1
	ldr		r1, =SIM_SCGC5_PORTA
	str		r0, [r1]
	
	// Aktiviere Takt für FMT0.
	ldr		r1, =SIM_SCGC6_FTM0
	str		r0, [r1]
	
	// Setze Interrupt-Vektor zu FTM0.
	ldr		r0, =handle_ftm0_irq
	ldr		r1, =IVT_FTM0
	str		r0, [r1]
	
	// Lösche anhängende Interrupts und anschließend aktiviere Interrupts für
	// FTM0.
	mov		r0, #IRQ_FTM0
	ldr		r1, =NVIC_ICPR1
	ldr		r2, =NVIC_ISER1
	str		r0, [r1]
	str		r0, [r2]
	
	// Konfiguriere PORTA Pin 6 als FTM0_CH3.
	mov		r0, #ALT3
	ldr		r1, =PORTA_PCR6
	str		r0, [r1]
	
	// Konfiguriere FTM0 BDM-Modus.
	mov		r0, #BDMMODE
	ldr		r1, =FTM0_CONF
	str		r0, [r1]
	
	// Deaktiviere Schreibschutz für FTM0.
	mov		r0, #(WPDIS | FTMEN)
	ldr		r1, =FTM0_MODE
	str		r0, [r1]
	
	// Setze die Grundfrequenz für FTM0 auf 1ms.
	ldr		r0, =MOD
	ldr		r1, =FTM0_MOD
	str		r0, [r1]
	
	// Selektivere Edge-Aligned PWM mit High-true für FTM0 Channel 3. Aktiviere
	// Channel-Interrupts.
	mov		r0, #(CHIE | MSB | ELSB)
	ldr		r1, =FTM0_C3SC
	str		r0, [r1]
	
	// Setze initiale Pulsweite auf 50% der Grundfrequenz.
	ldr		r0, =VAL
	ldr		r1, =FTM0_C3V
	str		r0, [r1]
	
	// Setze den PWM-Synchronisationspunkt für FTM0 auf den niedrigsten
	// Zählerwert.
	mov		r0, #CNTMIN
	ldr		r1, =FTM0_SYNC
	str		r0, [r1]
	
	// Aktiviere erweiterte PWM-Synchronisation für FTM0.
	mov		r0, #SYNCMODE
	ldr		r1, =FTM0_SYNCONF
	str		r0, [r1]
	
	// Setzte Basiswert des Zählers auf 0 für FTM0.
	mov		r0, #0
	ldr		r1, =FTM0_CNTIN
	str		r0, [r1]
	
	// Aktiviere Systemtakt für FTM0.
	mov		r0, #(TOIE | CLKS)
	ldr		r1, =FTM0_SC
	str		r0, [r1]
	
loop:
	// Fordere Benutzer zur Eingabe auf.
	ldr		r0, =prompt
	bl		uart_putString
	
	// Lade Benutzereingabe und echoe sie zurück.
	bl		uart_getChar
	mov		r4, r0
	bl		uart_putChar
	mov		r0, #NL
	bl		uart_putChar
	
	// Prüfe, ob '+' oder '-' eingegeben wurde.
	teq		r4, #CHAR_PLUS
	beq		handle_change_polarity
	teq		r4, #CHAR_MINUS
	beq		handle_change_polarity
	
	// Prüfe, ob eine Zahl aus [0-9] eingegeben wurde.
	cmp		r4, #CHAR_0
	blo		end
	cmp		r4, #CHAR_9
	bhi		end
	
	// Berechne das neue Pulsweitenverhältnis als Hundertstel.
	mov		r1, #10
	sub		r0, r4, #CHAR_0
	mul		r0, r0, r1
	add		r0, r0, #5
	
	// Berechne die neue Pulsweite.
	ldr		r1, =MOD
	mov		r2, #100
	mul		r0, r1, r0
	udiv	r0, r0, r2
	
	// Setze die nächste Pulsweite.
	ldr		r1, =next_puls_width
	str		r0, [r1]
	
	// Gib Aktion an der Konsole aus.
	ldr		r0, =puls_width_changed
	bl		uart_putString
	mov		r0, r4
	bl		uart_putChar
	ldr		r0, =puls_width_changed_suffix
	bl		uart_putString
	
	b		end
	
handle_change_polarity:
	// Bestimme die neue Polarität.
	teq		r4, #CHAR_MINUS
	itete	eq
	moveq	r1, #1
	movne	r1, #0
	ldreq	r0, =polarity_changed_low
	ldrne	r0, =polarity_changed_high
	
	// Setze die nächste Polarität.
	ldr		r2, =next_polarity
	str		r1, [r2]
	
	// Gib Aktion an der Konsole aus.
	bl		uart_putString 
	
end:
	b 		loop


/*
* Interrupt Service Routine (handle_ftm0_irq): Behandle eine Unterbrechung
* durch FTM0, entweder durch ein Event auf Channel 3 oder ein Timer-Overflow-
* Interrupt.
*/
.thumb_func
handle_ftm0_irq:
	// Prüfe, ob ein Channel Interrupt vorliegt.
	mov		r0, #0
	ldr		r1, =FTM0_C3SC_CHF
	ldr		r2, [r1]
	teq		r2, r0
	beq		handle_tof
	
	// Quittiere den Interrupt.
	str		r0, [r1]
	
	// Prüfe, ob die Pulsweite geändert werden soll.
	ldr		r0, =next_puls_width
	ldr		r1, [r0]
	ldr		r2, =FTM0_C3V
	ldr		r3, [r2]
	teq		r0, r3
	it		ne
	strne	r0, [r2]
	
handle_tof:
	// Prüfe, ob ein Overflow Interrupt vorliegt.
	mov		r0, #0
	ldr		r1, =FTM0_SC_TOF
	ldr		r2, [r1]
	teq		r2, r0
	beq		return_fmt0_irq
	
	// Quittiere den Interrupt.
	str		r0, [r1]
	
	// Prüfe, ob die Polarität geändert werden soll.
	ldr		r0, =next_polarity
	ldr		r1, [r0]
	ldr		r2, =FTM0_C3SC_ELSA
	ldr		r3, [r2]
	teq		r0, r3
	itttt	ne
	strne	r0, [r2]
	movne	r0, #LDOCK
	ldrne	r1, =FTM0_PWMLOAD
	strne	r0, [r1]
	
return_fmt0_irq:
	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
next_puls_width:
	.word	0x00
	
next_polarity:
	.word	0x00

prompt:
	.asciz "> "
	
puls_width_changed:
	.asciz "Die Pulsweite wurde aktualisiert auf: "

puls_width_changed_suffix:
	.asciz "5%\n"

polarity_changed_low:
	.asciz "Die Polaritaet wurde aktualisiert auf: active low\n"

polarity_changed_high:
	.asciz "Die Polaritaet wurde aktualisiert auf: active high\n"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ COUNTER, 0x10

/*
 *  Overhead der Zeitmessung mit pit3_getval. Gemessen mit:
 *
 *  bl pit3_getval
 *  mov r11, r0            // Startzeitpunkt sichern nach r11
 *  ..
 *  zumessender Code
 *  ..
 *  bl pit3_getval
 *  sub r0, r11, r0        // Zeit in Takten (r0) = Endzeitpunkt (r0) - Startzeitpunkt (r11)
 */
.equ PIT_OVERHEAD, 0x0B

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
    bl uart_init
    bl pit3_init

start:
    // Einlesen von 16 Bytes
    mov r4, #COUNTER            // Zaehler laden
    ldr r5, =bytearray          // Adresse des Arrays
    ldr r0, =str_eingabe        // Zeiger auf String laden
    bl uart_putString           // String ausgeben

loop_eingabe:
    ldr r0, =str_prompt         // Zeiger auf Prompt laden
    bl uart_putString           // Prompt ausgeben
    bl uart_getByte             // ein Byte einlesen
    strb r0, [r5], #1           // im Array ablegen und Adresse in R5 um eins erhöhen
    bl uart_putByte             // das Byte ausgeben
    subs r4, r4, #1             // Zaehler dekrementieren
    bne loop_eingabe            // solange Zaehler noch nicht null

    // Maximumsbestimmung
    ldr r0, =str_startsuche     // Zeiger auf String laden
    bl uart_putString           // String ausgeben

    bl pit3_getval
    mov r11, r0                 // Startzeitpunkt sichern nach r11
    mov r9, #0                  // Maximum mit null initialisieren
    mov r4, #COUNTER

loop_maximum:
    ldrb r0, [r5, #-1]!         // Byte aus dem Array holen, vorher Adresse in R5 dekrementieren
    cmp r0, r9                  // mit bisherigem Maximum vergleichen
    it hi                       // wenn es groesser ist (unsigned)
    movhi r9, r0                // wird das bisherige Maximum ersetzt
    subs r4, r4, #1             // Zaehler dekrementieren
    bne loop_maximum            // solange Zaehler noch nicht null

    // Maximum speichern
    ldr r0, =maximum            // Adresse des Speichers fuer Maximum laden
    strb r9, [r0]               // das Maximum speichern

    bl pit3_getval
    sub r11, r11, r0            // Zeit in Takten (r11) = Endzeitpunkt (r0) - Startzeitpunkt (r11) - PIT_OVERHEAD
    sub r11, r11, #PIT_OVERHEAD

    // e) Die Suchzeit betraegt immer konstant 131 Takte unabhaengig von der Position des Maximums im Datensatz,
    // da es keine konditionalen Spruenge gibt und somit unabhaengig von der Position des Maximum immer der gleiche Codepfad ausgefuehrt wird.
    // Zur Erkennung des Maximums wird lediglich eine konditionale Instruktion verwendet, die im Falle einer nicht erfuellten Kondition nur als NOP ausgefuehrt wird.

    // Ausgabe der Ergebnisse
    ldr r0, =str_endesuche      // Zeiger auf String laden
    bl uart_putString           // String ausgeben

    mov r0, r9                  // Maximum in R0 kopieren
    bl uart_putByte             // und als Byte ausgeben

    // Ausgabe der Ergebnisse
    ldr r0, =str_suchzeit       // Zeiger auf String laden
    bl uart_putString           // String ausgeben
    mov r0, r11                 // Suchzeit nach r0 kopieren
    bl uart_putInt16

    b start                     // Wieder zum Start springen und erneut Werte abfragen


/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
.rept COUNTER
.byte 0x00
.endr
maximum: .byte 0x0
str_prompt: .asciz "\n>0x"
str_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben!\n"
str_startsuche: .asciz "\nDurchsuchen gestartet\n"
str_endesuche: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_suchzeit: .asciz "\nSuchzeit: 0x"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ BIT_MASK, 31               // Bit 0 - 31 zulaessig, Maske zum abschneiden anderer Werte 
.equ ADDR_WO_BITBAND,       0x20000000
.equ ADDR_WITH_BITBAND_RAW, 0x20000010

// ADDR_WITH_BITBAND_RAW @ 0x20000010 -> 0x22000000 + (0x20000010 - 0x20000000) * 32
.equ ADDR_WITH_BITBAND,     0x22000200 

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
    bl uart_init

start:
    // 0-Bit abfragen und in r4 abspeichern
    ldr r0, =str_prompt_zerobit
    bl uart_putString
    bl uart_getByte
    and r4, r0, #BIT_MASK
    bl uart_putByte

    // 1-Bit abfragen und in r5 abspeichern
    ldr r0, =str_prompt_onebit
    bl uart_putString
    bl uart_getByte
    and r5, r0, #BIT_MASK
    bl uart_putByte

    // Ohne Bit Banding
    ldr r0, =str_wo_bitband
    bl uart_putString

    ldr r6, =ADDR_WO_BITBAND
    ldr r7, [r6]                // Wort laden

    // Initialen Wert ausgeben
    ldr r0, =str_intial_value
    bl uart_putString
    mov r0, r7
    bl uart_putInt32

    mov r2, #1
    lsl r3, r2, r4              // Maske zum Loeschen erzeugen (1 << zerobit)
    bic r7, r7, r3              // Bit loeschen

    lsl r3, r2, r5              // Maske zum Setzen erzeugen (1 << onebit)
    orr r7, r7, r3              // Bit setzen

    str r7, [r6]                // Veraendertes Wort zurueckschreiben

    // Modifizierten Wert ausgeben
    ldr r0, =str_modified_value
    bl uart_putString
    mov r0, r7
    bl uart_putInt32

    // Mit Bit Banding
    ldr r0, =str_with_bitband
    bl uart_putString

    // Initialen Wert ausgeben
    ldr r0, =str_intial_value
    bl uart_putString
    ldr r0, =ADDR_WITH_BITBAND_RAW
    ldr r0, [r0]
    bl uart_putInt32

    ldr r6, =ADDR_WITH_BITBAND  // Bit Band Basisadresse zum Wert Laden
    mov r1, #0
    str r1, [r6, r4, lsl #2]    // Bit mit Nummer aus r4 loeschen
    mov r1, #1
    str r1, [r6, r5, lsl #2]    // Bit mit Nummer aus r5 setzen

    // Modifizierten Wert ausgeben
    ldr r0, =str_modified_value
    bl uart_putString
    ldr r0, =ADDR_WITH_BITBAND_RAW
    ldr r0, [r0]
    bl uart_putInt32

    b start                     // Wieder zum Start springen und erneut Werte abfragen

/*** Datenbereich (ab 0x20000000) ***/
.data
.skip 32                        // Bereich am Anfang des Datenbereichs reservieren, der mit absoluten Adressen aus Aufgabenstellung angesprochen wird 
str_prompt_zerobit: .asciz "\nNummer des 0-Bits: 0x"
str_prompt_onebit: .asciz "\nNummer des 1-Bits: 0x"
str_intial_value: .asciz "\nInitialer Wert: 0x"
str_modified_value: .asciz "\nModifizierter Wert: 0x"
str_wo_bitband: .asciz "\nOhne Bit Banding"
str_with_bitband: .asciz "\nMit Bit Banding"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ VECTOR_LENGTH, 0x4         // Vektorlänge 4x 8-bit

/*
 *  Overhead der Zeitmessung mit pit3_getval. Gemessen mit:
 *
 *  bl pit3_getval
 *  mov r11, r0            // Startzeitpunkt sichern nach r11
 *  ..
 *  zumessender Code
 *  ..
 *  bl pit3_getval
 *  sub r0, r11, r0        // Zeit in Takten (r0) = Endzeitpunkt (r0) - Startzeitpunkt (r11)
 */
.equ PIT_OVERHEAD, 0x0B

// Einlesen eines 32-bit Vektors vom UART
.thumb_func
readVector:
    push {r4, lr}
    bl uart_getByte             // 1. Byte einlesen
    mov r4, r0
    bl uart_getByte             // 2. Byte einlesen
    orr r4, r0, r4, lsl #8      // 1. Byte verschieben und 2. Byte hinzufügen
    bl uart_getByte
    orr r4, r0, r4, lsl #8      // analog 3. Byte hinzufügen
    bl uart_getByte
    orr r0, r0, r4, lsl #8      // analog 4. Byte hinzufügen
    push {r0}
    bl uart_putInt32            // Empfangenen Vektor ausgeben
    pop {r0, r4, pc}

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
    bl uart_init
    bl pit3_init

start:
    ldr r4, =v1                 // Adresse des Speichers fuer v1 laden
    ldr r5, =v2                 // Adresse des Speichers fuer v2 laden

    // v1 vom Benutzer einlesen
    ldr r0, =str_v1
    bl uart_putString
    bl readVector
    str r0, [r4]

    // v2 vom Benutzer einlesen
    ldr r0, =str_v2
    bl uart_putString
    bl readVector
    str r0, [r5]

    //
    // MinMax Bestimmung ohne DSP-Instruktionen
    //
    ldr r0, =str_wo_dsp_instr
    bl uart_putString

    bl pit3_getval              // Zeitmessung starten
    mov r11, r0                 // Startzeitpunkt sichern nach r11

    ldr r4, =v1                 // Adresse des Speichers fuer v1 laden
    ldr r5, =v2                 // Adresse des Speichers fuer v2 laden
    ldr r6, =vmin               // Adresse des Speichers fuer vmin laden
    ldr r7, =vmax               // Adresse des Speichers fuer vmax laden

    mov r2, #VECTOR_LENGTH

loop_minmax_bytewise:
    ldrb r0, [r4], #1           // Byte von v1 und v2 laden
    ldrb r1, [r5], #1
    cmp r0, r1                  // v1 und v2 vergleichen
    iteet hi
    strbhi r0, [r7], #1         // Byte von v1 > Byte von v2, dann entsprechendes Byte von vmax auf Byte von v1 setzen,
    strbls r1, [r7], #1         // sonst auf v2 setzen
    strbls r0, [r6], #1         // Byte von v1 <= Byte von v2, dann entsprechendes Byte von vmin auf Byte von v1 setzen,
    strbhi r1, [r6], #1         // sonst auf v2 setzen
    subs r2, r2, #1             // Zähler dekrementieren und mit nächstem Byte fortfahren, bis alle 4 Bytes verarbeitet wurden
    bne loop_minmax_bytewise

    bl pit3_getval              // Zeitmessung stoppen
    sub r11, r11, r0            // Zeit in Takten (r11) = Endzeitpunkt (r0) - Startzeitpunkt (r11) - PIT_OVERHEAD
    sub r11, r11, #PIT_OVERHEAD

    // Vektor mit Minima ausgeben
    ldr r0, =str_min
    bl uart_putString
    ldr r0, [r6, #-VECTOR_LENGTH]
    bl uart_putInt32

    // Vektor mit Maxima ausgeben
    ldr r0, =str_max
    bl uart_putString
    ldr r0, [r7, #-VECTOR_LENGTH]
    bl uart_putInt32

    // Rechenzeit ausgeben
    ldr r0, =str_rechenzeit
    bl uart_putString
    mov r0, r11
    bl uart_putInt16

    //
    // MinMax-Bestimmung mit DSP-Instruktionen
    //
    ldr r0, =str_w_dsp_instr
    bl uart_putString

    bl pit3_getval              // Zeitmessung starten
    mov r11, r0                 // Startzeitpunkt sichern nach r11

    ldr r4, =v1                 // Adresse des Speichers fuer v1 laden
    ldr r5, =v2                 // Adresse des Speichers fuer v2 laden
    ldr r6, =vmin               // Adresse des Speichers fuer vmin laden
    ldr r7, =vmax               // Adresse des Speichers fuer vmax laden

    ldr r0, [r4]                // Vektoren v1 und v2 laden
    ldr r1, [r5]
    usub8 r2, r0, r1            // v1 und v2 byteweise subtrahieren und GE-Flags setzen
    sel r2, r0, r1              // Die größeren Bytes aus v1 und v2 selektieren und in Vektor zusammenfassen
    sel r3, r1, r0              // Die kleineren Bytes aus v1 und v2 selektieren und in Vektor zusammenfassen
    str r2, [r7]                // vmin und vmax abspeichern
    str r3, [r6]

    bl pit3_getval              // Zeitmessung stoppen
    sub r11, r11, r0            // Zeit in Takten (r11) = Endzeitpunkt (r0) - Startzeitpunkt (r11) - PIT_OVERHEAD
    sub r11, r11, #PIT_OVERHEAD

    // Vektor mit Minima ausgeben
    ldr r0, =str_min
    bl uart_putString
    ldr r0, [r6]
    bl uart_putInt32

    // Vektor mit Maxima ausgeben
    ldr r0, =str_max
    bl uart_putString
    ldr r0, [r7]
    bl uart_putInt32

    // Rechenzeit ausgeben
    ldr r0, =str_rechenzeit     // Zeiger auf String laden
    bl uart_putString           // String ausgeben
    mov r0, r11                 // Suchzeit nach r0 kopieren
    bl uart_putInt16

    // d) ohne DSP Instruktionen: 0x32 / mit DSP Instruktionen: 0x0D
    // -> Beschleunigung durch parallele statt serieller Bearbeitung des Vektors
    //      - 'usub8' entspricht 4x 'sub' ohne DSP, 4x schneller
    //      - Selektieren und speichern ('sel', 'sel', 'str', 'str') ersetzt hier 4x ('iteet', 'strbhi', 'strbls', 'strbls', 'strbhi') -> 5x schneller
    //      - Zusätzlich hier kein Overhead durch Schleife

    b start                     // Wieder zum Start springen und erneut Werte abfragen

/*** Datenbereich (ab 0x20000000) ***/
.data
v1: .word 0x0
v2: .word 0x0
vmin: .word 0x0
vmax: .word 0x0
str_v1: .asciz "\nv1: 0x"
str_v2: .asciz "\nv2: 0x"
str_wo_dsp_instr: .asciz "\nohne DSP-Befehle:"
str_w_dsp_instr: .asciz "\nmit DSP-Befehlen:"
str_min: .asciz "\nmin: 0x"
str_max: .asciz "\nmax: 0x"
str_rechenzeit: .asciz "\nRechenzeit: 0x"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ MATRIX_DIM, 4   // 4x4 Matrizen
.equ MATRIX_SIZE, 32 // Dim * Dim * 16bit = 32 Byte

.equ ASCII_NEWLINE, 10
.equ ASCII_SPACE, 32

// Konstanten aus Teil D
.equ PART_D_A, 0xa4367c7b
.equ PART_D_B, 0x10a78933
.equ PART_D_C, 0xc5535f2c
.equ PART_D_D, 0x788e84b1

// Konstanten aus Teil E
.equ PART_E_A, 0xa4367c7b
.equ PART_E_B, 0x10a78933

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    ldr r4, =matrix_m
    ldr r5, =matrix_n
    ldr r6, =matrix_result

    // Matrizen M und N multiplizieren
    mov r0, r6
    mov r1, r4
    mov r2, r5
    bl matrix4x4_mult

    // Ergebnis Matrix O ausgeben
    ldr r0, =str_matrix_result
    bl uart_putString
    mov r0, r6
    bl matrix4x4_print

    // Matrix O nach `matrix_result_copy` kopieren
    ldr r0, =str_matrix_copy
    bl uart_putString
    mov r0, r6
    ldr r1, =matrix_result_copy
    bl matrix4x4_copy

    // Spur(MxN) (Produktsumme) berechnen und ausgeben
    ldr r0, =str_matrix_trace
    bl uart_putString
    mov r0, r4
    mov r1, r5
    bl matrix4x4_product_trace
    bl uart_putInt32

    // Unterprogramm zur Untersuchung der verschiedenen Additionsbefehle aufrufen
    bl test_add_instructions

    // Unterprogramm zum Testen der Saettigungsbefehle aufrufen
    bl test_saturate_instructions

end:
    b end

// matrix4x4_mult multipliziert zwei 4x4 Matrizen miteinander (O=MxN),
// wobei N transponiert im Speicher abgelegt ist, wodurch alle Speicherzugriffe linear sind
// r0 = Adresse fuer Ergebnis (O)
// r1 = Adresse zu Matrix M
// r2 = Adresse zu transponierter Matrix N

// Benutzt SIMD Befehle, dadurch 2x 16-bit Multiplikation in einem Befehl -> Multiplikationen halbiert im Vergleich zu ohne SIMD
// Gleichzeitig 3 Additionen mit den 2 SIMD Befehlen -> Insgesamt durch SIMD 2 Befehle statt 4x Mul + 3x Add -> 3.5x schneller
.thumb_func
matrix4x4_mult:
    push {r4-r11}
    mov r11, #MATRIX_DIM

mult_loop_row:
    // Spalte von M laden
    ldm r1!, {r3, r4}

    // 1. Zeile von N laden und Zeile mit Spalte multiplizieren
    ldm r2!, {r9, r10}
    smuad r5, r3, r9
    smlad r5, r4, r10, r5

    // 2. Zeile von N laden und Zeile mit Spalte multiplizieren
    ldm r2!, {r9, r10}
    smuad r6, r3, r9
    smlad r6, r4, r10, r6

    // 3. Zeile von N laden und Zeile mit Spalte multiplizieren
    ldm r2!, {r9, r10}
    smuad r7, r3, r9
    smlad r7, r4, r10, r7

    // 4. Zeile von N laden und Zeile mit Spalte multiplizieren
    ldm r2!, {r9, r10}
    smuad r8, r3, r9
    smlad r8, r4, r10, r8

    // Eine Reihe der Ergebnismatrix O abspeichern
    stm r0!, {r5, r6, r7, r8}

    // Zeiger wieder auf erste Zeile von N
    sub r2, r2, #MATRIX_SIZE // 4 * 4 * 2

    // Zeile fertig, wiederhole bis alle (4) Zeilen von O berechnet sind
    subs r11, r11, #1
    bne mult_loop_row

    pop {r4-r11}
    bx lr

// matrix4x4_copy kopiert eine 4x4 Matrix von A nach B
// r0 = Adresse zu A
// r1 = Adresse zu B
.thumb_func
matrix4x4_copy:
    push {r4-r9}

    // 16 Eintraege von A laden und dann nach B speichern
    ldm r0!, {r2, r3, r4, r5, r6, r7, r8, r9}
    stm r1!, {r2, r3, r4, r5, r6, r7, r8, r9}

    // Die zweiten 16 Eintraege von A laden und dann nach B speichern
    ldm r0!, {r2, r3, r4, r5, r6, r7, r8, r9}
    stm r1!, {r2, r3, r4, r5, r6, r7, r8, r9}

    pop {r4-r9}
    bx lr

// matrix4x4_product_trace berechnet die Spur des Produkts zweier Matrizen M und N (Tr(MxN)) (Produkt-Summe)
// wobei N transponiert im Speicher abgelegt ist, wodurch alle Speicherzugriffe linear sind
// r0 = Adresse zu Matrix M
// r1 = Adresse zu transponierter Matrix N
// Gibt die Produktsumme in r0 zurueck
.thumb_func
matrix4x4_product_trace:
    push {r4-r10}

    // Diagonaleintraege von MxN berechnen und addieren

    // 1. und 2. Spalte von M sowie 1. und 2. Zeile von N laden
    ldm r0!, {r3, r4, r5, r6}
    ldm r1!, {r7, r8, r9, r10}

    // 1. Zeile und 1. Spalte multiplizieren
    smuad r2, r3, r7
    smlad r2, r4, r8, r2

    // 2. Zeile und 2. Spalte multiplizieren und dazu addieren
    smlad r2, r5, r9, r2
    smlad r2, r6, r10, r2

    // 3. und 4. Spalte von M sowie 3. und 4. Zeile von N laden
    ldm r0!, {r3, r4, r5, r6}
    ldm r1!, {r7, r8, r9, r10}

    // 3. Zeile und 3. Spalte multiplizieren und dazu addieren
    smlad r2, r3, r7, r2
    smlad r2, r4, r8, r2

    // 4. Zeile und 4. Spalte multiplizieren und dazu addieren
    smlad r2, r5, r9, r2
    smlad r2, r6, r10, r2

    // Register wiederherstellen und Ergebnis zurueckgeben
    pop {r4-r10}
    mov r0, r2
    bx lr

// matrix4x4_print gibt eine 4x4 Matrix auf dem UART aus
.thumb_func
matrix4x4_print:
    push {r4, r5, lr}

    mov r4, r0
    mov r5, #MATRIX_DIM

    // Zeilenweise auf dem UART ausgeben
print_loop_row:
    // Neue Zeile
    mov r0, #ASCII_NEWLINE
    bl uart_putChar

    // Ersten Eintrag der Zeile ausgeben
    ldr r0, [r4], #4
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    // Zweiten Eintrag der Zeile ausgeben
    ldr r0, [r4], #4
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    // Dritten Eintrag der Zeile ausgeben
    ldr r0, [r4], #4
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    // Vierten Eintrag der Zeile ausgeben
    ldr r0, [r4], #4
    bl uart_putInt32

    // Weitere Zeile? Dann mit naechster Zeile weitermachen
    subs r5, r5, #1
    bne print_loop_row

    pop {r4, r5, pc}


// Unterprogramm zur Untersuchung der verschiedenen Additionsbefehle (Aufgabenteil d)
.thumb_func:
test_add_instructions:
    push {r4-r7, lr}

    ldr r4, =PART_D_A
    ldr r5, =PART_D_B
    ldr r6, =PART_D_C
    ldr r7, =PART_D_D

    //
    // UADD16
    //

    ldr r0, =str_uadd16
    bl uart_putString

    //               Hex     |     Dec
    // A      =   A436  7C7B | 42038 31867
    // B      =   10A7  8933 |  4263 35123
    // A + B  =  0B4DD 105AE | 46301 66990 (17-bit)
    // UADD16 =>  B4DD  05AE | 46301  1454
    // Ueberlauf         xx

    uadd16 r0, r4, r5
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex     |     Dec
    // A      =   A436  7C7B | 42038 31867
    // C      =   C553  5F2C | 50515 24364
    // A + C  =  16989 0DBA7 | 92553 56231 (17-bit)
    // UADD16 =>  6989  DBA7 | 27017 56231
    // Ueberlauf   xx

    uadd16 r0, r4, r6
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex     |     Dec
    // A      =   A436  7C7B | 42038 31867
    // D      =   788E  84B1 | 30862 33969
    // A + D  =  11CC4 1012C | 72900 65836 (17-bit)
    // UADD16 =>  1CC4  012C |  7364   300
    // Ueberlauf   xx    xx

    uadd16 r0, r4, r7
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //
    // SADD16
    //

    ldr r0, =str_sadd16
    bl uart_putString

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // B      =   10A7  8933 |   4263 -30413
    // A + B  =  1B4DD 005AE | -19235   1454 (17-bit)
    // SADD16 =>  B4DD  05AE | -19235   1454
    // Ueberlauf
    // Unterlauf

    sadd16 r0, r4, r5
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // C      =   C553  5F2C | -15021  24364
    // A + C  =  16989 0DBA7 | -38519  56231  (17-bit)
    // SADD16 =>  6989  DBA7 |  27017  -9305
    // Ueberlauf         xx
    // Unterlauf   xx

    sadd16 r0, r4, r6
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // D      =   788E  84B1 |  30862 -31567
    // A + D  =  01CC4 1012C |   7364    300 (17-bit)
    // SADD16 =>  1CC4  012C |   7364    300
    // Ueberlauf
    // Unterlauf

    sadd16 r0, r4, r7
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //
    // UQADD16
    //

    ldr r0, =str_uqadd16
    bl uart_putString

    //                Hex     |     Dec
    // A       =   A436  7C7B | 42038 31867
    // B       =   10A7  8933 |  4263 35123
    // A + B   =  0B4DD 105AE | 46301 66990 (17-bit)
    // UQADD16 =>  B4DD  FFFF | 46301 65535
    // Ueberlauf          xx
    // Gesaettigt         xx
    uqadd16 r0, r4, r5
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //                Hex     |     Dec
    // A       =   A436  7C7B | 42038 31867
    // C       =   C553  5F2C | 50515 24364
    // A + C   =  16989 0DBA7 | 92553 56231 (17-bit)
    // UQADD16 =>  FFFF  DBA7 | 65535 56231
    // Ueberlauf    xx
    // Gesaettigt   xx
    uqadd16 r0, r4, r6
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //                Hex     |     Dec
    // A       =   A436  7C7B | 42038 31867
    // D       =   788E  84B1 | 30862 33969
    // A + D   =  11CC4 1012C | 72900 65836 (17-bit)
    // UQADD16 =>  FFFF  FFFF | 65535 65535
    // Ueberlauf    xx    xx
    // Gesaettigt   xx    xx
    uqadd16 r0, r4, r7
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    // QADD16

    ldr r0, =str_qadd16
    bl uart_putString

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // B      =   10A7  8933 |   4263 -30413
    // A + B  =  1B4DD 005AE | -19235   1454 (17-bit)
    // QADD16 =>  B4DD  05AE | -19235   1454
    // Ueberlauf
    // Unterlauf
    // Gesaettigt
    qadd16 r0, r4, r5
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // C      =   C553  5F2C | -15021  24364
    // A + C  =  16989 0DBA7 | -38519  56231  (17-bit)
    // QADD16 =>  8000  7FFF | -32768  32767
    // Ueberlauf         xx
    // Unterlauf   xx
    // Gesaettigt  xx    xx
    qadd16 r0, r4, r6
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // D      =   788E  84B1 |  30862 -31567
    // A + D  =  01CC4 1012C |   7364    300 (17-bit)
    // QADD16 =>  1CC4  012C |   7364    300
    // Ueberlauf
    // Unterlauf
    // Gesaettigt
    qadd16 r0, r4, r7
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    pop {r4-r7, pc}

// Unterprogramm zum Testen der Saettigungsbefehle (Aufgabenteil e)
.thumb_func
test_saturate_instructions:
    push {r4-r5, lr}

    ldr r4, =PART_E_A
    ldr r5, =PART_E_B

    ldr r0, =str_usat16
    bl uart_putString

    //13-bit unsigned -> 0...8191

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // USAT16 =>  0000  1FFF |      0   8191 (13-bit)
    // Ueberlauf         xx
    // Unterlauf   xx
    // Gesaettigt  xx    xx
    usat16 r0, #13, r4
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex            Dec
    // B      =   10A7  8933 |   4263 -30413
    // USAT16 =>  10A7  0000 |   4263      0 (13-bit)
    // Ueberlauf
    // Unterlauf         xx
    // Gesaettigt        xx
    usat16 r0, #13, r5
    bl uart_putInt32

    ldr r0, =str_ssat16
    bl uart_putString

    // 13-bit signed -> -4096...4095

    //               Hex            Dec
    // A      =   A436  7C7B | -23498  31867
    // SSAT16 =>  F000  0FFF |  -4096   4095 (13-bit)
    // Ueberlauf         xx
    // Unterlauf   xx
    // Gesaettigt  xx    xx
    ssat16 r0, #13, r4
    bl uart_putInt32
    mov r0, #ASCII_SPACE
    bl uart_putChar

    //               Hex            Dec
    // B      =   10A7  8933 |   4263 -30413
    // SSAT16 =>  0FFF  F000 |   4095  -4096 (13-bit)
    // Ueberlauf   xx
    // Unterlauf         xx
    // Gesaettigt  xx    xx
    ssat16 r0, #13, r5
    bl uart_putInt32

    pop {r4-r5, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
matrix_m:
.hword 0x5f8c, 0x7f48, 0x8245, 0x6048
.hword 0xc799, 0x9c5d, 0xd49c, 0x33d8
.hword 0x579b, 0x8aef, 0xf2c0, 0xa3c2
.hword 0x41fd, 0x50d4, 0x25c6, 0x4afa

matrix_n:
.hword 0x7f41, 0x0645, 0x8c8f, 0x9065
.hword 0x78e3, 0xf7f3, 0xd29f, 0x2961
.hword 0x5a1e, 0xdfed, 0x4b9f, 0x1092
.hword 0x61bf, 0x21be, 0x5ca1, 0xc6d3

matrix_result:
.rept MATRIX_DIM
.rept MATRIX_DIM
.word 0
.endr
.endr

matrix_result_copy:
.rept MATRIX_DIM
.rept MATRIX_DIM
.word 0
.endr
.endr

str_matrix_result: .asciz "\nErgebnismatrix O:"
str_matrix_copy: .asciz "\nKopieren der Matrix O!"
str_matrix_trace: .asciz "\nProdukt-Summe: "
str_uadd16: .asciz "\nUADD16: "
str_sadd16: .asciz "\nSADD16: "
str_uqadd16: .asciz "\nUQADD16: "
str_qadd16: .asciz "\nQADD16: "
str_usat16: .asciz "\nUSAT16: "
str_ssat16: .asciz "\nSSAT16: "
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_NEWLINE, 10
.equ ASCII_SPACE,   32
.equ ASCII_DOT,     46
.equ ASCII_ZERO,    48
.equ ASCII_COLON,   58

// Konstante fuer Verzoegerung um 1 Sekunde, Berechnung siehe unten
.equ DELAY_CONST, 0x6cfdc7

// Maxima fuer Stellen der Zeit
.equ MINUTES_MAX,    60
.equ HOURS_MAX,      24
.equ DAYS_MAX,       31
.equ MONTHS_MAX,     13
.equ YEARS_MAX,     100
.equ CENTURIES_MAX, 100

// Gepackte Maxima fuer parallele Verarbeitung
.equ MINUTES_HOURS_DAYS_MONTHS_MAX, 0x0d1f183c
.equ YEARS_CENTURIES_MAX, 0x6464

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    ldr r4, =running

    bl clock_print              // Aktuelle Zeit ausgeben

main_loop:
    bl delay                    // 1s warten

    // Wenn Uhr laeuft (running == 0), Zeit erhoehen um 1 Minute
    ldrb r0, [r4]
    cbnz r0, skip_clock_tick
    bl clock_tick
    bl clock_print              // Aktuelle Zeit ausgeben
skip_clock_tick:

    // Wenn ein Zeichen empfangen wurde, Unterprogramm zur Behandlung aufrufen
    bl uart_charPresent
    cbz r0, skip_handle_input
    bl handle_input
skip_handle_input:

    b main_loop

// delay verzoegert um ~25.000.000 Takte = 1 Sekunde
.align 2
.thumb_func
delay:
    // Aufruf von delay (bl delay) braucht 2-3 Takte

    // Konstante fuer Verzoegerungsschleife laden
    ldr r0, =DELAY_CONST  // 2 Takte

delay_loop:
    subs r0, r0, #1      // 1 Takt
    bne delay_loop       // 1 Takt, falls Sprung nicht genommen, 2-3 Takte falls Sprung genommen
    bx lr                // 2-4 Takte

    // -> Insgesamt mit Schleifenkonstante n: 2.5 + 2 + 1 * n + 1 + 2.5 * (n-1) + 3 = 6 + 3,5 * n
    // Fuer Verzoegerung von ~1s = 25.000.000 Takte -> n = ~7142855 = 0x6cfdc7

    // Fuer eine einmalige Korrektur kann mit einer Armbanduhr z.B. 10 Minuten abgestoppt werden und Start- und
    // Endzeit dieser Uhr notiert werden. Die neue Schleifenkonstante n' ist dann:
    // n' = (Stop - Start)/600s * n

    // Wenn laengere Zeit eine Referenz zur Verfuegung steht (z.B. GPS-Empfaenger) bietet sich eine Regelung mittels "all digital phase locked loop (ADPLL)" an
    // Die Komponenten der ADPLL koennen dann wie folgt realisiert werden:
    //   - "Digitally controlled oscillator (DCO)" mittels delay und variabler Schleifenkonstante n, wird n erhoeht, sinkt die Frequenz und umgekehrt
    //   - Phasenkomparator: Wird z.B. eine steigende Flanke eines 1Hz Signals vom GPS-Empfaenger erkannt, kann der aktuelle Wert des Schleifenzaehlers als Phasenfehler benutzt werden
    //                       Ist die ADPLL synchronisiert, ist der Phasenfehler ~0, ansonsten entsprechend groesser
    //   - "Loop filter": z.B. Filter 2. Ordnung aus Integrierender Teil x' = x + Ki * Phasenfehler und proportionalem Teil (Kp * Phasenfehler)
    //                    -> Insgesamt: n' = x' + Kp * Phasenfehler (x', n' neue Werte, x vorheriger Werte)

// clock_tick erhoeht die aktuelle Uhrzeit um eine Minute
.thumb_func
clock_tick:
    // Aktuelle Zeit laden
    ldr r3, =datetime
    ldr r0, [r3]       // Minuten + Stunden + Tage + Monate
    ldrh r1, [r3, #4]  // Jahre + Jahrhunderte

    // Minuten erhoehen
    ubfx r2, r0, 0, 8
    add r2, #1
    bfi r0, r2, 0, 8
    cmp r2, #MINUTES_MAX // Modulo-60 Arithmetik -> Carry erzeugen, wenn nach Addition > 59

    // Stunden erhoehen, falls es einen Uebertrag aus den Minuten gibt
    ubfx r2, r0, 8, 8
    adc r2, #0
    bfi r0, r2, 8, 8
    cmp r2, #HOURS_MAX   // Modulo-24 Arithmetik -> Carry erzeugen, wenn nach Addition > 23

    // Tage erhoehen, falls es einen Uebertrag aus den Stunden gibt
    ubfx r2, r0, 16, 8
    adc r2, #0
    bfi r0, r2, 16, 8
    cmp r2, #DAYS_MAX    // Modulo-31 Arithmetik -> Carry erzeugen, wenn nach Addition > 30

    // Monate erhoehen, falls es einen Uebertrag aus den Tagen gibt
    ubfx r2, r0, 24, 8
    adc r2, #0
    bfi r0, r2, 24, 8
    cmp r2, #MONTHS_MAX  // Modulo-13 Arithmetik -> Carry erzeugen, wenn nach Addition > 12

    // Jahre erhoehen, falls es einen Uebertrag aus den Monaten gibt
    ubfx r2, r1, 0, 8
    adc r2, #0
    bfi r1, r2, 0, 8

    // Hier koennte analog Carry fuer Jahrhunderte erzeugt und entsprechend erhoeht werden

    // Jetzt parallel alle Stellen bei denen es einen Ueberlauf gab zurueck setzen
    // Minuten, Stunden, Jahre auf 0 und Tage, Monate auf 1

    // Hier fuer Minuten + Stunden + Monate + Jahre
    ldr r2, =MINUTES_HOURS_DAYS_MONTHS_MAX
    usub8 r2, r0, r2
    movt r2, #0x0101     // Tage und Monate beginnen bei 1
    sel r0, r2, r0

    // Hier fuer Jahre + Jahrhunderte
    movw r2, #YEARS_CENTURIES_MAX
    usub8 r2, r1, r2
    sel r1, r2, r1

    // Neue Zeit speichern
    str r0, [r3]
    strh r1, [r3, #4]

    bx lr

// clock_print gibt die aktuelle Uhrzeit auf dem UART aus
// mit dem Format: dd.mm.jjjj  hh:mm Uhr
.thumb_func
clock_print:
    push {r4, r5, lr}

    // Aktuelle Zeit laden
    ldr r5, =datetime
    ldr r4, [r5]       // Minuten + Stunden + Tage + Monate
    ldrh r5, [r5, #4]  // Jahre + Jahrhunderte

    mov r0, #ASCII_NEWLINE
    bl uart_putChar

    // Tag ausgeben
    ubfx r0, r4, 16, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_day_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_day_skip_prefix:
    ubfx r0, r4, 16, 8
    bl uart_putByteBase10

    mov r0, #ASCII_DOT
    bl uart_putChar

    // Monat ausgeben
    ubfx r0, r4, 24, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_month_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_month_skip_prefix:
    ubfx r0, r4, 24, 8
    bl uart_putByteBase10

    mov r0, #ASCII_DOT
    bl uart_putChar

    // Jahrhundert ausgeben
    ubfx r0, r5, 8, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_century_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_century_skip_prefix:
    ubfx r0, r5, 8, 8
    bl uart_putByteBase10

    // Jahr ausgeben
    ubfx r0, r5, 0, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_year_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_year_skip_prefix:
    ubfx r0, r5, 0, 8
    bl uart_putByteBase10

    mov r0, #ASCII_SPACE
    bl uart_putChar
    mov r0, #ASCII_SPACE
    bl uart_putChar

    // Stunden ausgeben
    ubfx r0, r4, 8, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_hour_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_hour_skip_prefix:
    ubfx r0, r4, 8, 8
    bl uart_putByteBase10

    mov r0, #ASCII_COLON
    bl uart_putChar

    // Minuten ausgeben
    ubfx r0, r4, 0, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_minute_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_minute_skip_prefix:
    ubfx r0, r4, 0, 8
    bl uart_putByteBase10

    ldr r0, =str_time
    bl uart_putString

    pop {r4, r5, pc}

// handle_input verarbeitet Benutzereingaben
.thumb_func
handle_input:
    push {r4, lr}

    // Zeichen einlesen
    bl uart_getChar
    cmp r0, #115        // 's' -> zu Start/Stop Behandlung springen
    beq handle_input_s
    cmp r0, #116        // 't' -> zum Einstellen einer neuen Zeit springen
    beq handle_input_t
    cmp r0, #100        // 'd' -> zum Einstellen eines neuen Datums springen
    beq handle_input_d
    b handle_input_exit // Ansonsten Behandlung beenden

    // Behandlung von Start/Stopp
handle_input_s:
    ldr r1, =running    // Aktuellen Zustand abrufen
    ldrb r0, [r1]
    eor r0, r0, #1      // Zustand invertieren
    strb r0, [r1]       // Neuen Zustand speichern
    b handle_input_exit // Fertig

    // Neue Zeit einstellen
handle_input_t:
    ldr r4, =datetime

    // Stunden abfragen und abspeichern
    ldr r0, =str_input_hours
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #1]
    bl uart_putByteBase10

    // Minuten abfragen und abspeichern
    ldr r0, =str_input_minutes
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #0]
    bl uart_putByteBase10

    // Neue Uhrzeit ausgeben
    bl clock_print

    b handle_input_exit // Fertig

    // Neues Datum einstellen
handle_input_d:
    ldr r4, =datetime

    // Tag abfragen und abspeichern
    ldr r0, =str_input_day
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #2]
    bl uart_putByteBase10

    // Monat abfragen und abspeichern
    ldr r0, =str_input_month
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #3]
    bl uart_putByteBase10

    // Jahr abfragen und abspeichern
    ldr r0, =str_input_year
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #4]
    bl uart_putByteBase10

    // Neue Uhrzeit ausgeben
    bl clock_print

    // Fertig

handle_input_exit:
    pop {r4, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
datetime:
.byte 00   // Minuten
.byte 00   // Stunden
.byte 01   // Tage
.byte 01   // Monate
.byte 14   // Jahre
.byte 20   // Jahrhunderte

running:
.byte 0    // 0 = Uhr laeuft, bei nicht 0 Uhr laeuft nicht

str_time: .asciz " Uhr"
str_input_hours: .asciz "\nStunde eingeben (hh): "
str_input_minutes: .asciz "\nMinuten eingeben (mm): "
str_input_day: .asciz "\nTag eingeben (dd): "
str_input_month: .asciz "\nMonat eingeben (mm): "
str_input_year: .asciz "\nJahr eingeben (jj): "
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_NEWLINE, 10
.equ ASCII_SPACE,   32
.equ ASCII_DOT,     46
.equ ASCII_ZERO,    48
.equ ASCII_COLON,   58

// Konstante fuer Verzoegerung um 1 Sekunde, Berechnung siehe unten
.equ DELAY_CONST, 0x6cfdc7

// Maxima fuer Stellen der Zeit
.equ MINUTES_MAX,    60
.equ HOURS_MAX,      24
.equ DAYS_MAX,       31
.equ MONTHS_MAX,     13
.equ YEARS_MAX,     100
.equ CENTURIES_MAX, 100

// Gepackte Maxima fuer parallele Verarbeitung
.equ MINUTES_HOURS_DAYS_MONTHS_MAX, 0x0d1f183c
.equ YEARS_CENTURIES_MAX, 0x6464

.equ PIT1_PERIOD, 24999999 // 1s -> 25.000.000 clocks

// PIT1 - Vektor 85 (IRQ 69)
// -> Offset fuer Vektortabelle 85 * 4 = 0x154
// zugehoerig NVIC_*2, Bit 5
.equ PIT1_IRQ_OFFSET, 0x154
.equ PIT1_NVIC_MASK, 0x20

// SIM Register
__BBREG SIM_SCGC6_PIT, 0x4004803c, 23

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// NVIC Register
.equ NVIC_ISER2, 0xe000e108
.equ NVIC_ICPR2, 0xe000e288

// PIT Register
.equ PIT_BASE, 0x40037000
.equ PIT_MCR, 0x0
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1, 0x11c

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    // Takt fuer PIT aktivieren
    ldr r0, =SIM_SCGC6_PIT
    mov r1, #1
    str r1, [r0]

    // Interruptvektor zu PIT1 setzen
    ldr r0, =SCR_VTOR
    ldr r0, [r0]
    ldr r1, =pit1_isr
    str r1, [r0, #PIT1_IRQ_OFFSET]

    // NVIC konfigurieren
    mov r1, #PIT1_NVIC_MASK

    // Ausstehende Interrupts von PIT1 loeschen
    ldr r0, =NVIC_ICPR2
    str r1, [r0]

    // Interrupt von PIT1 im NVIC aktivieren
    ldr r0, =NVIC_ISER2
    str r1, [r0]

    // Alle PITs aktivieren und im Debug-Modus laufen lassen
    ldr r0, =PIT_BASE
    mov r1, #0x00               // MDIS=0, FRZ=0
    str r1, [r0, #PIT_MCR]

    // Startwert von PIT1 auf 1 Sekunde initialisieren
    ldr r1, =PIT1_PERIOD
    str r1, [r0, #PIT_LDVAL1]
    
    // Interrupt von PIT1 aktivieren und PIT1 starten
    mov r1, #0x03               // CHN=0, TIE=1, TEN=1
    str r1, [r0, #PIT_TCTRL1]

    ldr r4, =running
    ldr r5, =pit_tick

    bl clock_print              // Aktuelle Zeit ausgeben

main_loop:
    // Wenn keine Sekunde um ist, Tick überspringen
    ldrb r0, [r5]
    cbz r0, skip_clock_tick

    // Tick Flag zuruecksetzen
    mov r0, #0
    strb r0, [r5]

    // Wenn Uhr laeuft (running == 0), Zeit erhoehen um 1 Minute
    ldrb r0, [r4]
    cbnz r0, skip_clock_tick
    bl clock_tick
    bl clock_print              // Aktuelle Zeit ausgeben
skip_clock_tick:

    // Wenn ein Zeichen empfangen wurde, Unterprogramm zur Behandlung aufrufen
    bl uart_charPresent
    cbz r0, skip_handle_input
    bl handle_input
skip_handle_input:

    b main_loop

// Interrupt Service Routine fuer PIT1
.thumb_func
pit1_isr:
    // Eine Sekunde vorbei -> Flag setzen
    ldr r0, =pit_tick
    mov r1, #1
    strb r1, [r0]

    // Interrupt Flag von PIT1 loeschen
    ldr r0, =PIT_BASE
    mov r1, #1
    str r1, [r0, #PIT_TFLG1]

    bx lr

// clock_tick erhoeht die aktuelle Uhrzeit um eine Minute
.thumb_func
clock_tick:
    // Aktuelle Zeit laden
    ldr r3, =datetime
    ldr r0, [r3]       // Minuten + Stunden + Tage + Monate
    ldrh r1, [r3, #4]  // Jahre + Jahrhunderte

    // Minuten erhoehen
    ubfx r2, r0, 0, 8
    add r2, #1
    bfi r0, r2, 0, 8
    cmp r2, #MINUTES_MAX // Modulo-60 Arithmetik -> Carry erzeugen, wenn nach Addition > 59

    // Stunden erhoehen, falls es einen Uebertrag aus den Minuten gibt
    ubfx r2, r0, 8, 8
    adc r2, #0
    bfi r0, r2, 8, 8
    cmp r2, #HOURS_MAX   // Modulo-24 Arithmetik -> Carry erzeugen, wenn nach Addition > 23

    // Tage erhoehen, falls es einen Uebertrag aus den Stunden gibt
    ubfx r2, r0, 16, 8
    adc r2, #0
    bfi r0, r2, 16, 8
    cmp r2, #DAYS_MAX    // Modulo-31 Arithmetik -> Carry erzeugen, wenn nach Addition > 30

    // Monate erhoehen, falls es einen Uebertrag aus den Tagen gibt
    ubfx r2, r0, 24, 8
    adc r2, #0
    bfi r0, r2, 24, 8
    cmp r2, #MONTHS_MAX  // Modulo-13 Arithmetik -> Carry erzeugen, wenn nach Addition > 12

    // Jahre erhoehen, falls es einen Uebertrag aus den Monaten gibt
    ubfx r2, r1, 0, 8
    adc r2, #0
    bfi r1, r2, 0, 8

    // Hier koennte analog Carry fuer Jahrhunderte erzeugt und entsprechend erhoeht werden

    // Jetzt parallel alle Stellen bei denen es einen Ueberlauf gab zurueck setzen
    // Minuten, Stunden, Jahre auf 0 und Tage, Monate auf 1

    // Hier fuer Minuten + Stunden + Monate + Jahre
    ldr r2, =MINUTES_HOURS_DAYS_MONTHS_MAX
    usub8 r2, r0, r2
    movt r2, #0x0101     // Tage und Monate beginnen bei 1
    sel r0, r2, r0

    // Hier fuer Jahre + Jahrhunderte
    movw r2, #YEARS_CENTURIES_MAX
    usub8 r2, r1, r2
    sel r1, r2, r1

    // Neue Zeit speichern
    str r0, [r3]
    strh r1, [r3, #4]

    bx lr

// clock_print gibt die aktuelle Uhrzeit auf dem UART aus
// mit dem Format: dd.mm.jjjj  hh:mm Uhr
.thumb_func
clock_print:
    push {r4, r5, lr}

    // Aktuelle Zeit laden
    ldr r5, =datetime
    ldr r4, [r5]       // Minuten + Stunden + Tage + Monate
    ldrh r5, [r5, #4]  // Jahre + Jahrhunderte

    mov r0, #ASCII_NEWLINE
    bl uart_putChar

    // Tag ausgeben
    ubfx r0, r4, 16, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_day_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_day_skip_prefix:
    ubfx r0, r4, 16, 8
    bl uart_putByteBase10

    mov r0, #ASCII_DOT
    bl uart_putChar

    // Monat ausgeben
    ubfx r0, r4, 24, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_month_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_month_skip_prefix:
    ubfx r0, r4, 24, 8
    bl uart_putByteBase10

    mov r0, #ASCII_DOT
    bl uart_putChar

    // Jahrhundert ausgeben
    ubfx r0, r5, 8, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_century_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_century_skip_prefix:
    ubfx r0, r5, 8, 8
    bl uart_putByteBase10

    // Jahr ausgeben
    ubfx r0, r5, 0, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_year_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_year_skip_prefix:
    ubfx r0, r5, 0, 8
    bl uart_putByteBase10

    mov r0, #ASCII_SPACE
    bl uart_putChar
    mov r0, #ASCII_SPACE
    bl uart_putChar

    // Stunden ausgeben
    ubfx r0, r4, 8, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_hour_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_hour_skip_prefix:
    ubfx r0, r4, 8, 8
    bl uart_putByteBase10

    mov r0, #ASCII_COLON
    bl uart_putChar

    // Minuten ausgeben
    ubfx r0, r4, 0, 8
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r0, #10
    bge clock_print_minute_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_minute_skip_prefix:
    ubfx r0, r4, 0, 8
    bl uart_putByteBase10

    ldr r0, =str_time
    bl uart_putString

    pop {r4, r5, pc}

// handle_input verarbeitet Benutzereingaben
.thumb_func
handle_input:
    push {r4, lr}

    // Zeichen einlesen
    bl uart_getChar
    cmp r0, #115        // 's' -> zu Start/Stop Behandlung springen
    beq handle_input_s
    cmp r0, #116        // 't' -> zum Einstellen einer neuen Zeit springen
    beq handle_input_t
    cmp r0, #100        // 'd' -> zum Einstellen eines neuen Datums springen
    beq handle_input_d
    b handle_input_exit // Ansonsten Behandlung beenden

    // Behandlung von Start/Stopp
handle_input_s:
    ldr r1, =running    // Aktuellen Zustand abrufen
    ldrb r0, [r1]
    eor r0, r0, #1      // Zustand invertieren
    strb r0, [r1]       // Neuen Zustand speichern
    b handle_input_exit // Fertig

    // Neue Zeit einstellen
handle_input_t:
    ldr r4, =datetime

    // Stunden abfragen und abspeichern
    ldr r0, =str_input_hours
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #1]
    bl uart_putByteBase10

    // Minuten abfragen und abspeichern
    ldr r0, =str_input_minutes
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #0]
    bl uart_putByteBase10

    // Neue Uhrzeit ausgeben
    bl clock_print

    b handle_input_exit // Fertig

    // Neues Datum einstellen
handle_input_d:
    ldr r4, =datetime

    // Tag abfragen und abspeichern
    ldr r0, =str_input_day
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #2]
    bl uart_putByteBase10

    // Monat abfragen und abspeichern
    ldr r0, =str_input_month
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #3]
    bl uart_putByteBase10

    // Jahr abfragen und abspeichern
    ldr r0, =str_input_year
    bl uart_putString
    bl uart_getByteBase10
    strb r0, [r4, #4]
    bl uart_putByteBase10

    // Neue Uhrzeit ausgeben
    bl clock_print

    // Fertig

handle_input_exit:
    pop {r4, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
datetime:
.byte 00   // Minuten
.byte 00   // Stunden
.byte 01   // Tage
.byte 01   // Monate
.byte 14   // Jahre
.byte 20   // Jahrhunderte

running:
.byte 0    // 0 = Uhr laeuft, bei nicht 0 Uhr laeuft nicht

pit_tick:
.byte 0

str_time: .asciz " Uhr"
str_input_hours: .asciz "\nStunde eingeben (hh): "
str_input_minutes: .asciz "\nMinuten eingeben (mm): "
str_input_day: .asciz "\nTag eingeben (dd): "
str_input_month: .asciz "\nMonat eingeben (mm): "
str_input_year: .asciz "\nJahr eingeben (jj): "
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_NEWLINE, 0x0a

__BBREG SIM_SCGC6_CRC_ADR, 0x4004803c, 18

.equ CRC_POLY, 0x04c11db7 // Polynom: 1 0000 01000 1100 0001 1101 1011 0111
.equ CRC_SEED, 0x12345678

// CRC Register
.equ CRC_BASE, 0x40032000
.equ CRC_CRC,   0x0
.equ CRC_GPOLY, 0x4
.equ CRC_CTRL,  0x8

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    // Takt fuer CRC einschalten
    ldr r0, =SIM_SCGC6_CRC_ADR
    mov r1, #1
    str r1, [r0]

    // CRC-Modul konfigurieren
    ldr r5, =CRC_BASE
    mov r1, #0x03000000       // kein Transpose von Ein-/Ausgabewerten (TOT/TOTR=0), kein XOR (FXOR=0), 32-bit CRC (TCRC=1), Seed laden (WAS=1)
    str r1, [r5, #CRC_CTRL]
    ldr r1, =CRC_POLY
    str r1, [r5, #CRC_GPOLY]
    ldr r1, =CRC_SEED
    str r1, [r5, #CRC_CTRL]
    mov r1, #0x01000000       // kein Transpose von Ein-/Ausgabewerten (TOT/TOTR=0), kein XOR (FXOR=0), 32-bit CRC (TCRC=1), Daten verarbeiten (WAS=0)
    str r1, [r5, #CRC_CTRL]

    ldr r2, =str

read_data:
    ldr r1, [r2], #4
    str r1, [r5, #CRC_CRC]
    // Pruefen, ob ein Nullbyte (Terminator) dabei ist, wenn nicht dann weiter lesen
    clz r4, r1
    cmp r4, #8
    blt read_data

    // Text ueber den die CRC berechnet wurde ausgeben
    mov r0, #ASCII_NEWLINE
    bl uart_putChar
    ldr r0, =str
    bl uart_putString

    // CRC ausgeben
    mov r0, #ASCII_NEWLINE
    bl uart_putChar
    ldr r0, [r5, #CRC_CRC]
    bl uart_putInt32

end:
    b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
__BBREG SIM_SCGC5_PORTA_ADR, 0x40048038, 9
__BBREG SIM_SCGC5_PORTE_ADR, 0x40048038, 13

// LED orange
.equ PORTA_PCR11, 0x4004902c
__BBREG GPIOA_PDOR_11, 0x400ff000, 11
__BBREG GPIOA_PDDR_11, 0x400ff014, 11

// LED gelb
.equ PORTA_PCR28, 0x40049070
__BBREG GPIOA_PDOR_28, 0x400ff000, 28
__BBREG GPIOA_PDDR_28, 0x400ff014, 28

// LED gruen
.equ PORTA_PCR29, 0x40049074
__BBREG GPIOA_PDOR_29, 0x400ff000, 29
__BBREG GPIOA_PDDR_29, 0x400ff014, 29

// LED blau
.equ PORTA_PCR10, 0x40049028
__BBREG GPIOA_PDOR_10, 0x400ff000, 10
__BBREG GPIOA_PDDR_10, 0x400ff014, 10

.equ LED_PORT_FLAGS, 0x00000120 // MUX=1 (GPIO), ODE=1 (open-drain)

// SW1
.equ PORTA_PCR19, 0x4004904c
__BBREG GPIOA_PDIR_19, 0x400ff010, 19
__BBREG GPIOA_PDDR_19, 0x400ff014, 19

// SW2
.equ PORTE_PCR26, 0x4004d068
__BBREG GPIOE_PDIR_26, 0x400ff110, 26
__BBREG GPIOE_PDDR_26, 0x400ff114, 26
__BBREG PORTE_ISFR_26, 0x4004d0a0, 26

.equ SW1_PORT_FLAGS, 0x00000103 // MUX=1 (GPIO), Pull-Up (PS=1, PE=1)
.equ SW2_PORT_FLAGS, 0x000a0103 // MUX=1 (GPIO), Pull-Up (PS=1, PE=1), Interrupt on falling edge (IRQC=1010)

.equ PIT1_PERIOD, 124999 // 5ms -> 125.000 clocks

// PORTE - Vektor 107 (IRQ 91)
// -> Offset fuer Vektortabelle 107 * 4 = 0x1ac
// zugehoerig NVIC_*2, Bit 27
.equ PORTE_IRQ_OFFSET, 0x1ac
.equ PORTE_NVIC_MASK, 0x08000000

// PIT1 - Vektor 85 (IRQ 69)
// -> Offset fuer Vektortabelle 85 * 4 = 0x154
// zugehoerig NVIC_*2, Bit 5
.equ PIT1_IRQ_OFFSET, 0x154
.equ PIT1_NVIC_MASK, 0x20

// SIM Register
__BBREG SIM_SCGC6_PIT, 0x4004803c, 23

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// NVIC Register
.equ NVIC_ISER2, 0xe000e108
.equ NVIC_ICPR2, 0xe000e288

// PIT Register
.equ PIT_BASE, 0x40037000
.equ PIT_MCR, 0x0
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1, 0x11c

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    // Ports einschalten
    mov r1, #1
    ldr r0, =SIM_SCGC5_PORTA_ADR
    str r1, [r0]
    ldr r0, =SIM_SCGC5_PORTE_ADR
    str r1, [r0]

    // LED Ports konfigurieren
    ldr r1, =LED_PORT_FLAGS
    ldr r0, =PORTA_PCR11
    str r1, [r0]
    ldr r0, =PORTA_PCR28
    str r1, [r0]
    ldr r0, =PORTA_PCR29
    str r1, [r0]
    ldr r0, =PORTA_PCR10
    str r1, [r0]

    // LEDs als Ausgang konfigurieren
    mov r1, #1
    ldr r0, =GPIOA_PDDR_11
    str r1, [r0]
    ldr r0, =GPIOA_PDDR_28
    str r1, [r0]
    ldr r0, =GPIOA_PDDR_29
    str r1, [r0]
    ldr r0, =GPIOA_PDDR_10
    str r1, [r0]

    // SW1/2 Ports konfigurieren
    ldr r1, =SW1_PORT_FLAGS
    ldr r0, =PORTA_PCR19
    str r1, [r0]
    ldr r1, =SW2_PORT_FLAGS
    ldr r0, =PORTE_PCR26
    str r1, [r0]

    // SWs als Eingang konfigurieren
    mov r1, #0
    ldr r0, =GPIOA_PDDR_19
    str r1, [r0]
    ldr r0, =GPIOE_PDDR_26
    str r1, [r0]

    // Interruptvektor zu PORTE setzen
    ldr r0, =SCR_VTOR
    ldr r0, [r0]
    ldr r1, =porte_isr
    str r1, [r0, #PORTE_IRQ_OFFSET]

    // NVIC konfigurieren
    mov r1, #PORTE_NVIC_MASK

    // Ausstehende Interrupts von PORTE loeschen
    ldr r0, =NVIC_ICPR2
    str r1, [r0]

    // Interrupt von PORTE im NVIC aktivieren
    ldr r0, =NVIC_ISER2
    str r1, [r0]

    // Takt fuer PIT aktivieren
    ldr r0, =SIM_SCGC6_PIT
    mov r1, #1
    str r1, [r0]

    // Interruptvektor zu PIT1 setzen
    ldr r0, =SCR_VTOR
    ldr r0, [r0]
    ldr r1, =pit1_isr
    str r1, [r0, #PIT1_IRQ_OFFSET]

    // NVIC konfigurieren
    mov r1, #PIT1_NVIC_MASK

    // Ausstehende Interrupts von PIT1 loeschen
    ldr r0, =NVIC_ICPR2
    str r1, [r0]

    // Interrupt von PIT1 im NVIC aktivieren
    ldr r0, =NVIC_ISER2
    str r1, [r0]

    // Alle PITs aktivieren und im Debug-Modus laufen lassen
    ldr r0, =PIT_BASE
    mov r1, #0x00               // MDIS=0, FRZ=0
    str r1, [r0, #PIT_MCR]

    // Startwert von PIT1 auf 1 Sekunde initialisieren
    ldr r1, =PIT1_PERIOD
    str r1, [r0, #PIT_LDVAL1]
    
    // Interrupt von PIT1 aktivieren und PIT1 starten
    mov r1, #0x03               // CHN=0, TIE=1, TEN=1
    str r1, [r0, #PIT_TCTRL1]

    mov r8, #0
    mov r9, #0
    ldr r5, =pit_tick
    ldr r6, =paused

    // Zaehlrichtung
    mov r7, #1

    // Startzustand von SW1 speichern
    ldr r0, =GPIOA_PDIR_19
    ldr r1, [r0]
    ldr r0, =sw1_last
    strb r1, [r0]

main_loop:
    // Pruefen auf Zeichen vom UART
    bl uart_charPresent
    cbz r0, handle_input_done

    bl uart_getChar
    cmp r0, #0x2b // +
    beq handle_plus
    cmp r0, #0x2d // -
    beq handle_minus
    cmp r0, #0x73 // s
    beq handle_s
    b handle_input_done

    // + erhalten, jetzt hochzaehlen
handle_plus:
    mov r7, #1
    ldr r0, =hoch_txt
    bl uart_putString
    b handle_input_done

    // - erhalten, jetzt runterzaehlen
handle_minus:
    mov r7, #-1
    ldr r0, =runter_txt
    bl uart_putString
    b handle_input_done

    // s erhalten, starten oder stoppen
handle_s:
    ldrb r1, [r6]
    eor r1, #1
    strb r1, [r6]

    ldr r0, =start_txt
    ldr r2, =stop_txt

    cmp r1, #1
    it eq
    moveq r0, r2
    bl uart_putString

handle_input_done:
    // Gab es einen Tick von PIT1?
    ldrb r0, [r5]
    cmp r0, #0
    beq main_loop

    // Tick Flag zuruecksetzen
    mov r0, #0
    strb r0, [r5]

    // Tasten abfragen
    bl check_keys
    mov r4, r0

    cmp r4, #0
    beq keys_done
    cmp r4, #1
    beq sw1_pressed

    // SW2 wurde gedrueckt -> starten oder stoppen
    ldrb r1, [r6]
    eor r1, #1
    strb r1, [r6]

    ldr r0, =start_txt
    ldr r2, =stop_txt

    cmp r1, #1
    it eq
    moveq r0, r2
    bl uart_putString
    b keys_done

    // SW1 wurde gedrueckt, Zaehlrichtung wecheln
sw1_pressed:
    neg r7, r7

    ldr r0, =runter_txt
    ldr r2, =hoch_txt

    cmp r7, #1
    it eq
    moveq r0, r2
    bl uart_putString
    b keys_done
    

keys_done:
    // 1s (100 PIT ticks) vorbei?
    add r8, r8, #1
    cmp r8, #100
    blt main_loop
    mov r8, #0

    // Zaehler aktualisieren, falls nicht gestoppt
    ldrb r0, [r6]
    cmp r0, #0
    it eq
    addeq r9, r9, r7
    and r9, r9, #0xff

    // Zaehler ausgeben
    ldr r0, =zaehler_txt
    bl uart_putString
    mov r0, r9
    bl uart_putByte

    // Untere 4 Bit auf LEDs anzeigen
    ldr r0, =GPIOA_PDDR_11
    ubfx r1, r9, #0, #1
    str r1, [r0]
    ldr r0, =GPIOA_PDDR_28
    ubfx r1, r9, #1, #1
    str r1, [r0]
    ldr r0, =GPIOA_PDDR_29
    ubfx r1, r9, #2, #1
    str r1, [r0]
    ldr r0, =GPIOA_PDDR_10
    ubfx r1, r9, #3, #1
    str r1, [r0]
    b main_loop

.thumb_func
check_keys:
    // SW1 abfragen
    ldr r0, =GPIOA_PDIR_19
    ldr r3, [r0]
    ldr r0, =sw1_pending
    ldrb r2, [r0]
    bic r2, r2, r3          // War gedrueckt und ist immernoch gedrueckt?
    ldr r0, =sw1_last
    ldrb r1, [r0]
    strb r3, [r0]
    bic r3, r1, r3          // Fallende Flanke?
    ldr r0, =sw1_pending
    strb r3, [r0]           // Abspeichern bis durch Entprellen bestaetigt

    // SW2 abfragen
    ldr r0, =GPIOE_PDIR_26
    ldr r3, [r0]
    ldr r0, =sw2_pending
    ldrb r1, [r0]
    bic r1, r1, r3          // War gedrueckt und ist immernoch gedrueckt?
    mov r3, #0
    strb r3, [r0]           // sw2_pending zuruecksetzen

    // r2 = 1, falls SW1 gedrueckt sonst 0
    // r1 = 1, falls SW2 gedrueckt sonst 0

    // mod erzeugen
    cmp r1, #1
    it eq
    moveq r2, #2
    ldr r0, =mod
    strb r2, [r0]

    // mod zurueckgeben
    mov r0, r2

    bx lr

// Interrupt Service Routine fuer PIT1
.thumb_func
pit1_isr:
    // 5ms vorbei -> Flag setzen
    ldr r0, =pit_tick
    mov r1, #1
    strb r1, [r0]

    // Interrupt Flag von PIT1 loeschen
    ldr r0, =PIT_BASE
    mov r1, #1
    str r1, [r0, #PIT_TFLG1]

    bx lr

// Interrupt Service Routine fuer SW2
.thumb_func
porte_isr:
    // Fallende Flanke von SW2 abspeichern zur Entprellung
    ldr r0, =sw2_pending
    mov r1, #1
    strb r1, [r0]

    // Interrupt Flag von SW2 loeschen
    ldr r0, =PORTE_ISFR_26
    mov r1, #1
    str r1, [r0]

    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
pit_tick:
.byte 0
mod:
.byte 0
sw1_last:
.byte 0
sw1_pending:
.byte 0
sw2_pending:
.byte 0
paused:
.byte 0
zaehler_txt: .asciz "\nZaehler: "
runter_txt: .asciz "\nZaehle runter!"
hoch_txt: .asciz "\nZaehle hoch!"
start_txt: .asciz "\nZaehler gestartet!"
stop_txt: .asciz "\nZaehler gestoppt!"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_NEWLINE,     0x0A
.equ ASCII_SPACE,       0x20
.equ ASCII_RIGHT_BRACE, 0x29
.equ ASCII_ZERO,        0x30
.equ ASCII_S,           0x73

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// SIM Register
__BBREG SIM_SCGC3_ADC1,  0x40048030, 27
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC6_PIT,   0x4004803c, 23

// LED orange
.equ PORTA_PCR11, 0x4004902c
__BBREG GPIOA_PDOR_11, 0x400ff000, 11
__BBREG GPIOA_PDDR_11, 0x400ff014, 11

// LED gelb
.equ PORTA_PCR28, 0x40049070
__BBREG GPIOA_PDOR_28, 0x400ff000, 28
__BBREG GPIOA_PDDR_28, 0x400ff014, 28

// LED gruen
.equ PORTA_PCR29, 0x40049074
__BBREG GPIOA_PDOR_29, 0x400ff000, 29
__BBREG GPIOA_PDDR_29, 0x400ff014, 29

// LED blau
.equ PORTA_PCR10, 0x40049028
__BBREG GPIOA_PDOR_10, 0x400ff000, 10
__BBREG GPIOA_PDDR_10, 0x400ff014, 10

.equ LED_PORT_FLAGS, 0x00000120 // MUX=1 (GPIO), ODE=1 (open-drain)

// NVIC Register
.equ NVIC_ISER2, 0xe000e108
.equ NVIC_ICPR2, 0xe000e288

// PIT1 - Vektor 85 (IRQ 69)
// -> Offset fuer Vektortabelle 85 * 4 = 0x154
// zugehoerig NVIC_*2, Bit 5
.equ PIT1_IRQ_OFFSET, 0x154
.equ PIT1_NVIC_MASK, 0x20

// PIT Register
.equ PIT_BASE, 0x40037000
.equ PIT_MCR, 0x0
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1, 0x11c

.equ PIT_MCR_VAL, 0        // MDIS=0, FRZ=0
.equ PIT_TCTRL1_VAL, 3     // CHN=0, TIE=1, TEN=1
.equ PIT1_PERIOD, 24999999 // 1s -> 25.000.000 clocks

// ADC1 Register
.equ ADC1_BASE, 0x400BB000
.equ ADCx_SC1A, 0x00
.equ ADCx_SC1B, 0x04
.equ ADCx_CFG1, 0x08
.equ ADCx_CFG2, 0x0c
.equ ADCx_RA,   0x10
.equ ADCx_RB,   0x14
.equ ADCx_CV1,  0x18
.equ ADCx_CV2,  0x1C
.equ ADCx_SC2,  0x20
.equ ADCx_SC3,  0x24
.equ ADCx_OFS,  0x28
.equ ADCx_PG,   0x2C
.equ ADCx_MG,   0x30
.equ ADCx_CLPD, 0x34
.equ ADCx_CLPS, 0x38
.equ ADCx_CLP4, 0x3C
.equ ADCx_CLP3, 0x40
.equ ADCx_CLP2, 0x44
.equ ADCx_CLP1, 0x48
.equ ADCx_CLP0, 0x4C
.equ ADCx_PGA,  0x50
.equ ADCx_CLMD, 0x54
.equ ADCx_CLMS, 0x48
.equ ADCx_CLM4, 0x5C
.equ ADCx_CLM3, 0x60
.equ ADCx_CLM2, 0x64
.equ ADCx_CLM1, 0x68
.equ ADCx_CLM0, 0x6C

__BBREG ADC1_SC1A_COCO_ADR, ADC1_BASE + ADCx_SC1A, 7
__BBREG ADC1_SC3_CALF_ADR,  ADC1_BASE + ADCx_SC3,  6

// SAR ADC, Referenzspannung VREFH=3.3V/VREFL=GND
// Spannungsbereich des Potentiometer an ADC1_DM1 0.0V bis 3.3V

.equ ADC1_CFG1_VAL_16,       0x6C // ADICLK=0 (Bus clock)
                                  // MODE=3 (16-bit)
                                  // ADLSMP=0 (Short sample time)
                                  // ADIV=3 (ADC clock = Bus clock/8 = 3.125MHz)
                                  // ADLPC=0 (Normal power configuration)

.equ ADC1_CFG1_VAL_12,       0x64 // ADICLK=0 (Bus clock)
                                  // MODE=1 (16-bit)
                                  // ADLSMP=0 (Short sample time)
                                  // ADIV=3 (ADC clock = Bus clock/8 = 3.125MHz)
                                  // ADLPC=0 (Normal power configuration)

.equ ADC1_CFG1_VAL_10,       0x68 // ADICLK=0 (Bus clock)
                                  // MODE=2 (16-bit)
                                  // ADLSMP=0 (Short sample time)
                                  // ADIV=3 (ADC clock = Bus clock/8 = 3.125MHz)
                                  // ADLPC=0 (Normal power configuration)

.equ ADC1_CFG1_VAL_8,        0x60 // ADICLK=0 (Bus clock)
                                  // MODE=0 (16-bit)
                                  // ADLSMP=0 (Short sample time)
                                  // ADIV=3 (ADC clock = Bus clock/8 = 3.125MHz)
                                  // ADLPC=0 (Normal power configuration)

.equ ADC1_CFG2_VAL,          0x00 // ADLSTS=0 (Default sample time)
                                  // ADHSC=0 (Normal conversion sequence)
                                  // ADACKEN=0 (Asynchronous clock output disabled)
                                  // MUXSEL=0 (ADxxa channels selected)

.equ ADC1_SC2_VAL,           0x00 // REFSEL=0 (use VREFH=3.3V/VREFL=GND)
                                  // DMAEN=0 (DMA disabled)
                                  // ACREN=0 (Compare range function disabled)
                                  // ACFGT=0 (Compare greater than function disabled)
                                  // ACFE=0 (Compare function disabled)
                                  // ADTRG=0 (Software trigger)

.equ ADC1_SC3_VAL_CAL,       0x87 // AVGS=3 (32 samples averaged)
                                  // AVGE=1 (Averaging enabled)
                                  // ADCO=0 (Continous conversion disabled)
                                  // CAL=1 (Start calibration)

.equ ADC1_SC3_VAL_APP,       0x0E // AVGS=2 (16 samples averaged)
                                  // AVGE=1 (Averaging enabled)
                                  // ADCO=1 (Continous conversion disabled)
                                  // CAL=0 (Start calibration)

.equ ADC1_PGA_VAL,           0x00 // PGAG=0 (Gain 1)
                                  // PGALPb=0 (Low-Power mode)
                                  // PGAEN=0 (PGA disabled)

.equ ADC1_SC1A_VAL_DISABLED, 0x1f // ADCH=31 (Module disabled)
                                  // DIFF=0 (Single-ended conversion)
                                  // AIEN=0 (Interrupt disabled)

// ADC1_DM1 -> ADC1_AD20
.equ ADC1_SC1A_VAL_AD20,     0x14 // ADCH=20 (Channel)
                                  // DIFF=0 (Single-ended conversion)
                                  // AIEN=0 (Interrupt disabled)


.equ reciprocal_10000, 0x00068DB9 // 1/10000 in Q0.31
.equ reciprocal_100,   0x028F5C29 // 1/100 in Q0.31

.equ NO_PRECISION_LEVELS, 3       // 8bit, 10bit, 12bit, 16bit

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    //
    // ADC1
    //

    // Takt fuer ADC1 einschalten
    mov r2, #1
    ldr r0, =SIM_SCGC3_ADC1
    str r2, [r0]

    // ADC konfigurieren
    ldr r4, =ADC1_BASE
    mov r0, #ADC1_SC1A_VAL_DISABLED
    str r0, [r4, #ADCx_SC1A]
    mov r0, #ADC1_CFG1_VAL_16
    str r0, [r4, #ADCx_CFG1]
    mov r0, #ADC1_CFG2_VAL
    str r0, [r4, #ADCx_CFG2]
    mov r0, #ADC1_SC2_VAL
    str r0, [r4, #ADCx_SC2]
    mov r0, #ADC1_PGA_VAL
    str r0, [r4, #ADCx_PGA]

    // ADC1 kalibrieren
    mov r0, #ADC1_SC3_VAL_CAL
    str r0, [r4, #ADCx_SC3]

    ldr r0, =ADC1_SC1A_COCO_ADR
calibration_check_coco:
    ldr r1, [r0]
    cmp r1, #1
    bne calibration_check_coco

    // Pruefen, ob Kalibrierung erfolgreich war
    ldr r0, =ADC1_SC3_CALF_ADR
    ldr r0, [r0]
    cbz r0, calibration_ok
    ldr r0, =cal_error_txt
    bl uart_putString
calibration_error:
    b calibration_error

calibration_ok:
    // Plus side gain calibration
    ldr r0, [r4, #ADCx_CLP0]
    ldr r1, [r4, #ADCx_CLP1]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLP2]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLP3]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLP3]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLP4]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLPS]
    add r0, r0, r1
    movt r0, #0xffff
    asr r0, r0, #1
    strh r0, [r4, #ADCx_PG]

    // Minus side gain calibration
    ldr r0, [r4, #ADCx_CLM0]
    ldr r1, [r4, #ADCx_CLM1]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLM2]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLM3]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLM3]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLM4]
    add r0, r0, r1
    ldr r1, [r4, #ADCx_CLMS]
    add r0, r0, r1
    movt r0, #0xffff
    asr r0, r0, #1
    strh r0, [r4, #ADCx_MG]

    // Kalibrierung fertig, ADC fuer Anwendung konfigurieren
    mov r0, #ADC1_SC3_VAL_APP
    str r0, [r4, #ADCx_SC3]

    // Wandlung starten
    mov r0, #ADC1_SC1A_VAL_AD20
    str r0, [r4, #ADCx_SC1A]

    //
    // GPIOs
    //

    // Takt fuer Port einschalten
    ldr r0, =SIM_SCGC5_PORTA
    str r2, [r0]

    // LED Ports konfigurieren
    ldr r1, =LED_PORT_FLAGS
    ldr r0, =PORTA_PCR11
    str r1, [r0]
    ldr r0, =PORTA_PCR28
    str r1, [r0]
    ldr r0, =PORTA_PCR29
    str r1, [r0]
    ldr r0, =PORTA_PCR10
    str r1, [r0]

    // LEDs als Ausgang konfigurieren
    ldr r0, =GPIOA_PDDR_11
    str r2, [r0]
    ldr r0, =GPIOA_PDDR_28
    str r2, [r0]
    ldr r0, =GPIOA_PDDR_29
    str r2, [r0]
    ldr r0, =GPIOA_PDDR_10
    str r2, [r0]

    //
    // PIT
    //

    // Takt fuer PIT aktivieren
    ldr r0, =SIM_SCGC6_PIT
    str r2, [r0]

    // Interruptvektor zu PIT1 setzen
    ldr r0, =SCR_VTOR
    ldr r0, [r0]
    ldr r1, =pit1_isr
    str r1, [r0, #PIT1_IRQ_OFFSET]

    // Alle PITs aktivieren und im Debug-Modus laufen lassen
    ldr r0, =PIT_BASE
    mov r1, #PIT_MCR_VAL
    str r1, [r0, #PIT_MCR]

    // Startwert von PIT1 auf 1 Sekunde initialisieren
    ldr r1, =PIT1_PERIOD
    str r1, [r0, #PIT_LDVAL1]
    
    // Interrupt von PIT1 aktivieren und PIT1 starten
    mov r1, #PIT_TCTRL1_VAL
    str r1, [r0, #PIT_TCTRL1]

    //
    // NVIC
    //
    mov r1, #PIT1_NVIC_MASK

    // Ausstehende Interrupts von PIT1 loeschen
    ldr r0, =NVIC_ICPR2
    str r1, [r0]

    // Interrupt von PIT1 im NVIC aktivieren
    ldr r0, =NVIC_ISER2
    str r1, [r0]


    //
    // Register fuer Hauptschleife initialisieren
    //

    ldr r5, =pit_tick

    mov r6, #1          // 1 = AD-Wandlung gestartet, 0 = AD-Wandlung gestoppt
    mov r7, #3          // Aufloesung der AD-Wandlung 0 = 8-bit, 1 = 10-bit, 2 = 12-bit, 3 = 16-bit

main_loop:
    // Pruefen auf Zeichen vom UART
    bl uart_charPresent
    cbz r0, handle_input_done

    bl uart_getChar
    cmp r0, #ASCII_S
    beq handle_s
    sub r1, r0, #ASCII_ZERO
    cmp r1, #NO_PRECISION_LEVELS
    bls handle_precision
    b handle_input_done

handle_precision:
    // '0', '1', '2' oder '3' empfangen

    // Pruefen, ob AD-Wandlung gestoppt ist
    cbnz r6, handle_input_done

    // Neue Aufloesung abspeichern
    mov r7, r1

    // ADC Konfiguration aktualisieren
    ldr r0, =adc_cfg1_reg
    ldrb r0, [r0, r7]
    str r0, [r4, #ADCx_CFG1]

    // Text mit neuer Aufloesung ausgeben
    ldr r0, =adc_resolution_txt
    bl uart_putString
    ldr r0, =adc_resolution
    ldrb r0, [r0, r7]
    bl uart_putByteBase10

    b handle_input_done

handle_s:
    // 's' empfangen, starte/stoppe AD-Wandlung
    eors r6, r6, #1

    ite eq
    moveq r0, #ADC1_SC1A_VAL_DISABLED
    movne r0, #ADC1_SC1A_VAL_AD20
    str r0, [r4, #ADCx_SC1A]

    ite eq
    ldreq r0, =stop_adc_txt
    ldrne r0, =start_adc_txt
    bl uart_putString

handle_input_done:
    // Gab es einen Tick von PIT1?
    ldrb r0, [r5]
    cmp r0, #0
    beq main_loop

    // Tick Flag zuruecksetzen
    mov r0, #0
    strb r0, [r5]

    // AD-Wandlung deaktiviert?
    cmp r6, #0
    beq main_loop

    // ADC Messwert ausgeben
    mov r0, #ASCII_NEWLINE
    bl uart_putChar
    ldr r8, [r4, #ADCx_RA]
    mov r0, r8
    bl uart_putInt16

    mov r0, #ASCII_SPACE
    bl uart_putChar

    // Stufe k bei N bit Aufloesung bestimmen, k = (ADC_RA)*N/(2^N)
    ldr r0, =adc_resolution
    ldrb r0, [r0, r7]
    mul r8, r8, r0
    lsr r8, r8, r0

    // Bereichsgrenzen fuer Bereich k..k+1 bestimmen mit Rundung
    // k * 3300/N = (k*f + 2)/4, N=8: f=1650, N=10: f=1320, N=12: f=1100, N=16: f=825
    // Optimiert fuer SMMULR: ((k << 26) * (f << 5) + 0x80000000) >> 32
    // Optimierte Konstanten fuer SMMULR (f << 5): N=16: 13200, N=12: 17600, N=10: 21120, N=8: 26400
    lsl r9, r8, #26
    ldr r10, =range_const
    ldrh r10, [r10, r7, lsl#1]
    smmulr r0, r9, r10
    bl uart_putShortBase10

    ldr r0, =volt_sep_txt
    bl uart_putString

    // Obere Bereichsgrenze k+1 bestimmen
    add r9, r9, #0x04000000   // (k + 1) << 26 hier mit (k << 26) + (1 << 26)
    smmulr r0, r9, r10
    bl uart_putShortBase10

    // Stufe ausgeben
    ldr r0, =step_txt
    bl uart_putString
    mov r0, r8
    bl uart_putByteBase10
    mov r0, #ASCII_RIGHT_BRACE
    bl uart_putChar

    // Stufe auf LEDs anzeigen
    mvn r2, r8              // LED active-low -> Bits negieren vor Ausgabe
    ldr r0, =GPIOA_PDOR_11
    ubfx r1, r2, #0, #1
    str r1, [r0]
    ldr r0, =GPIOA_PDOR_28
    ubfx r1, r2, #1, #1
    str r1, [r0]
    ldr r0, =GPIOA_PDOR_29
    ubfx r1, r2, #2, #1
    str r1, [r0]
    ldr r0, =GPIOA_PDOR_10
    ubfx r1, r2, #3, #1
    str r1, [r0]

    b  main_loop

// 16-bit Zahl in dezimal auf dem UART ausgeben, Zahl wird in r0 uebergeben
.thumb_func
uart_putShortBase10:
    push {r4, r5, lr}

    // 10.000er Stelle bestimmen
    movw r3, #10000
    ldr r1, =reciprocal_10000
    smmul r5, r0, r1
    mls r4, r3, r5, r0

    // Falls 1000er Stelle = 0, ohne 0-Prefix fortfahren
    cbz r5, putShort_thousands_without_prefix

    // 10.000er Stelle ausgeben
    mov r0, r5
    bl uart_putByteBase10

    // 1000er und 100er Stelle bestimmen
    mov r3, #100
    ldr r1, =reciprocal_100
    smmul r5, r4, r1
    mls r4, r3, r5, r4

    // Falls <10, '0' Praefix ausgeben, sonst direkt 1000er und 100er Stelle ausgeben
    cmp r5, #10
    bge putShort_thousands_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
putShort_thousands_skip_prefix:
    mov r0, r5
    bl uart_putByteBase10

    // 10er und 1er Stelle ausgeben
    // Falls <10, '0' Praefix ausgeben, sonst direkt 10er und 1er Stelle ausgeben
    cmp r4, #10
    bge putShort_hundreds_skip_prefix_1
    mov r0, #ASCII_ZERO
    bl uart_putChar
putShort_hundreds_skip_prefix_1:
    mov r0, r4
    bl uart_putByteBase10
    
    b putShort_done 

putShort_thousands_without_prefix:
    // Zahl < 10000

    // 1000er und 100er Stelle bestimmen
    mov r3, #100
    ldr r1, =reciprocal_100
    smmul r0, r4, r1
    mls r4, r3, r0, r4

    // Falls 1000er und 100er Stelle = 0, ohne 0-Prefix fortfahren
    cbz r0, putShort_hundreds_without_prefix

    // 1000er und 100er Stelle ausgeben
    bl uart_putByteBase10

    // 10er und 1er Stelle ausgeben
    // Falls <10, '0' Praefix ausgeben, sonst direkt 10er und 1er Stelle ausgeben
    cmp r4, #10
    bge putShort_hundreds_skip_prefix_2
    mov r0, #ASCII_ZERO
    bl uart_putChar
putShort_hundreds_skip_prefix_2:
    mov r0, r4
    bl uart_putByteBase10
    b putShort_done    

putShort_hundreds_without_prefix:
    // Zahl < 100, direkt mit uart_putByteBase10 ausgeben
    mov r0, r4
    bl uart_putByteBase10

putShort_done:
    pop {r4, r5, pc}

// Interrupt Service Routine fuer PIT1
.thumb_func
pit1_isr:
    // 1s vorbei -> Flag setzen
    ldr r0, =pit_tick
    mov r1, #1
    strb r1, [r0]

    // Interrupt Flag von PIT1 loeschen
    ldr r0, =PIT_BASE
    str r1, [r0, #PIT_TFLG1]

    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
adc_cfg1_reg:
.byte ADC1_CFG1_VAL_8
.byte ADC1_CFG1_VAL_10
.byte ADC1_CFG1_VAL_12
.byte ADC1_CFG1_VAL_16

adc_resolution:
.byte 8
.byte 10
.byte 12
.byte 16

// Bereichsgrenzen fuer Bereich k..k+1 bestimmen mit Rundung
// k * 3300/N = (k*f + 2)/4, N=8: f=1650, N=10: f=1320, N=12: f=1100, N=16: f=825
// Optimiert fuer SMMULR: ((k << 26) * (f << 5) + 0x80000000) >> 32
// Optimierte Konstanten fuer SMMULR (f << 5): N=16: 13200, N=12: 17600, N=10: 21120, N=8: 26400
range_const:
.short 26400
.short 21120
.short 17600
.short 13200

pit_tick:
.byte 0

cal_error_txt: .asciz "\nKalibrierung fehlgeschlagen!"
volt_sep_txt: .asciz " - "
step_txt: .asciz " mV (Stufe "
start_adc_txt: .asciz "\nStarte AD-Wandlung"
stop_adc_txt: .asciz "\nStoppe AD-Wandlung"
adc_resolution_txt: .asciz "\nAufloesung der AD-Wandlung (Bit): "
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_SPACE,       0x20
.equ ASCII_COMMA,       0x2c
.equ ASCII_COLON,       0x3a
.equ ASCII_S,           0x73

// Konstante fuer Verzoegerung um ca. 2us, damit der I2C-Bus Ruhezustand einnehmen kann
.equ i2c_delay_const, 0x16

// SIM Register
__BBREG SIM_SCGC4_I2C0,  0x40048034,  6
__BBREG SIM_SCGC5_PORTD, 0x40048038, 12
__BBREG SIM_SCGC6_PIT,   0x4004803c, 23

// GPIO Register
.equ GPIOD_PDOR, 0x400ff0c0
.equ GPIOD_PDIR, 0x400ff0d0
.equ GPIOD_PDDR, 0x400ff0d4

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// NVIC Register
.equ NVIC_ISER2, 0xe000e108
.equ NVIC_ICPR2, 0xe000e288

// PIT1 - Vektor 85 (IRQ 69)
// -> Offset fuer Vektortabelle 85 * 4 = 0x154
// zugehoerig NVIC_*2, Bit 5
.equ PIT1_IRQ_OFFSET, 0x154
.equ PIT1_NVIC_MASK, 0x20

// PIT Register
// Basisadresse
.equ PIT_BASE,   0x40037000
// Offsets der Register zur Basisadresse
.equ PIT_MCR,    0x000
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1,  0x11c

.equ PIT_MCR_VAL,           0 // MDIS=0, FRZ=0
.equ PIT_TCTRL1_VAL,        3 // CHN=0, TIE=1, TEN=1
.equ PIT1_PERIOD,    24999999 // 1s -> 25.000.000 clocks

// I2C Register
// Basisadresse
.equ I2C0_BASE, 0x40066000
// Offsets der Register zur Basisadresse
.equ I2Cx_A1,   0x00
.equ I2Cx_F,    0x01
.equ I2Cx_C1,   0x02
.equ I2Cx_S,    0x03
.equ I2Cx_D,    0x04
.equ I2Cx_C2,   0x05
.equ I2Cx_FLT,  0x06
.equ I2Cx_RA,   0x07
.equ I2Cx_SMB,  0x08
.equ I2Cx_A2,   0x09
.equ I2Cx_SLTH, 0x0A
.equ I2Cx_SLTL, 0x0B

// Flags vom Statusregisters
.equ I2Cx_S_ARBL,  0x10
.equ I2Cx_S_IICIF, 0x02
.equ I2Cx_S_RXACK, 0x01

// I2C (SCL=PTD8, SDA=PTD9)
.equ PORTD_PCR8, 0x4004c020
.equ PORTD_PCR9, 0x4004c024
.equ I2C_PORT_FLAGS_I2C,  0x00000220 // MUX=2 (I2C), ODE=1 (open-drain)
.equ I2C_PORT_FLAGS_GPIO, 0x00000100 // MUX=1 (GPIO)
.equ PORTD_SCL_MASK, 0x100
.equ PORTD_SDA_MASK, 0x200

.equ I2C0_FLT_VAL, 0x02 // Glitch Filter 50ns (nach I2C-Bus Spezifikation) * 25MHz

// DS75 SCL Frequenz                    (fSCL im Datenblatt) min. 0Hz, max. 400kHz
// Kinetis K60 SCL Frequenz (Fast Mode) (fSCL im Datenblatt) min. 0HZ, max. 400kHz
//   -> Kommunikation maximal mit 400kHz moeglich
.equ I2C0_F_VAL,   0x12 // SCL clk divider 64 -> (390kHz, hoechster Takt unter 400kHz)
                        // SDA hold time 520ns, SCL start hold time 1040ns, SCL stop hold time 1320ns
                        // -> ICR=0x12 + MULT=0 (x1)

.equ I2C0_C1_VAL_IDLE,           0x80 // IICEN=1, MST=0, RSTA=0, TX=0, TXAK=0
.equ I2C0_C1_VAL_START,          0xb0 // IICEN=1, MST=1, RSTA=0, TX=1, TXAK=0
.equ I2C0_C1_VAL_REPEATED_START, 0xb4 // IICEN=1, MST=1, RSTA=1, TX=1, TXAK=0
.equ I2C0_C1_VAL_RX_ACK,         0xa0 // IICEN=1, MST=1, RSTA=0, TX=0, TXAK=0
.equ I2C0_C1_VAL_RX_NACK,        0xa8 // IICEN=1, MST=1, RSTA=0, TX=0, TXAK=1

// DS75
.equ DS75_I2C_ADDR,          0x48 // 7-bit I2C Adresse

// DS75 Register
.equ DS75_TEMPERATURE_REG,   0x00
.equ DS75_CONFIGURATION_REG, 0x01
.equ DS75_THYST_REG,         0x02
.equ DS75_TOS_REG,           0x03

.equ DS75_CONFIGURATION_REG_VAL, 0x60 // SD=0 (active)
                                      // TM=0 (Comparator mode)
                                      // POL=0 (O.S. active low)
                                      // F=0 (1 conversion to trigger O.S.)
                                      // R=3 (12-bit)

// THYST auf aktuelle Temperatur +2.0°C
// TOS auf aktuelle Temperatur   +3.0°C
.equ DS75_THYST_OFFSET, 0x0200
.equ DS75_TOS_OFFSET,   0x0300

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init
    bl I2CBus_Reset

    // Takt fuer Ports einschalten
    mov r2, #1
    ldr r0, =SIM_SCGC5_PORTD
    str r2, [r0]

    //
    // I2C0
    //

    // Takt fuer I2C einschalten
    ldr r0, =SIM_SCGC4_I2C0
    str r2, [r0]

    // I2C konfigurieren
    ldr r4, =I2C0_BASE
    mov r0, #I2C0_F_VAL
    strb r0, [r4, #I2Cx_F]
    mov r0, #I2C0_FLT_VAL
    strb r0, [r4, #I2Cx_FLT]
    mov r0, #I2C0_C1_VAL_IDLE
    strb r0, [r4, #I2Cx_C1]

    // I2C Ports konfigurieren
    ldr r1, =I2C_PORT_FLAGS_I2C
    ldr r0, =PORTD_PCR8
    str r1, [r0]
    ldr r0, =PORTD_PCR9
    str r1, [r0]

    //
    // PIT
    //

    // Takt fuer PIT aktivieren
    ldr r0, =SIM_SCGC6_PIT
    str r2, [r0]

    // Interruptvektor zu PIT1 setzen
    ldr r0, =SCR_VTOR
    ldr r0, [r0]
    ldr r1, =pit1_isr
    str r1, [r0, #PIT1_IRQ_OFFSET]

    // Alle PITs aktivieren und im Debug-Modus laufen lassen
    ldr r0, =PIT_BASE
    mov r1, #PIT_MCR_VAL
    str r1, [r0, #PIT_MCR]

    // Startwert von PIT1 auf 1 Sekunde initialisieren
    ldr r1, =PIT1_PERIOD
    str r1, [r0, #PIT_LDVAL1]

    // Interrupt von PIT1 aktivieren und PIT1 starten
    mov r1, #PIT_TCTRL1_VAL
    str r1, [r0, #PIT_TCTRL1]

    //
    // NVIC
    //
    mov r1, #PIT1_NVIC_MASK

    // Ausstehende Interrupts von PIT1 loeschen
    ldr r0, =NVIC_ICPR2
    str r1, [r0]

    // Interrupt von PIT1 im NVIC aktivieren
    ldr r0, =NVIC_ISER2
    str r1, [r0]

    //
    // DS75 initialisieren
    //
    mov r0, #DS75_CONFIGURATION_REG
    mov r1, #DS75_CONFIGURATION_REG_VAL
    bl ds75_write_reg

    // Temperaturregelung initialisieren
    // LED schaltet ein, wenn TOS ueberschrriten wird und wird dann wieder ausgeschaltet, sobald die
    // Temperatur unter THYST faellt

    // Aktuelle Temperatur einlesen
    mov r0, #DS75_TEMPERATURE_REG
    bl ds75_read_reg
    mov r9, r0

    // THYST auf aktuelle Temperatur +2.0°C
    mov r0, #DS75_THYST_REG
    add r1, r9, #DS75_THYST_OFFSET
    bl ds75_write_reg

    // TOS auf aktuelle Temperatur +3.0°C
    mov r0, #DS75_TOS_REG
    add r1, r9, #DS75_TOS_OFFSET
    bl ds75_write_reg

    //
    // Register fuer Hauptschleife initialisieren
    //
    ldr r5, =pit_tick

main_loop:
    // Gab es einen Tick von PIT1?
    ldrb r0, [r5]
    cmp r0, #0
    beq main_loop

    // Tick Flag zuruecksetzen
    mov r0, #0
    strb r0, [r5]

    //
    // Temperatur ausgeben
    //
    ldr r0, =temperature_prefix_txt
    bl uart_putString

    // Aktuelle Temperatur bestimmen
    mov r0, #DS75_TEMPERATURE_REG
    bl ds75_read_reg
    mov r9, r0

    // Temperatur in Hex ausgeben
    lsl r0, r0, #8
    bl uart_putInt32

    mov r0, #ASCII_COLON
    bl uart_putChar
    mov r0, #ASCII_SPACE
    bl uart_putChar

    // Ganzzahligen Anteil der Temperatur ausgeben
    uxtb r0, r9, ROR #8
    bl uart_putByteBase10

    mov r0, #ASCII_COMMA
    bl uart_putChar

    // 1. Nachkommastelle ausgeben
    mov r10, #10
    uxtb r9, r9
    mul r9, r9, r10
    uxtb r0, r9, ROR #8
    bl uart_putByteBase10

    // 2. Nachkommastellen ausgeben
    uxtb r9, r9
    mul r9, r9, r10
    add r0, r9, #0x80      // Runden
    uxtb r0, r0, ROR #8
    bl uart_putByteBase10

    ldr r0, =temperature_suffix_txt
    bl uart_putString

    b main_loop

// ds75_write_reg schreibt ein Register des DS75
// Parameter: DS75 Registeradresse in r0, Wert des Registers in r1
.thumb_func
ds75_write_reg:
    push {r4-r6, lr}
    mov r4, r0

    // 16-bit Register bis auf Configuration
    cmp r0, #DS75_CONFIGURATION_REG
    ite eq
    moveq r5, r1
    rev16ne r5, r1 // Bytereihenfolge tauschen fuer 16-bit Register

    ldr r6, =I2C0_BASE

    // I2C Start Bedingung erzeugen
    bl i2c_start

    // DS75 schreibend adressieren
    mov r0, #(DS75_I2C_ADDR << 1)
    bl i2c_write_byte
    cbnz r0, ds75_write_reg_nack

    // DS75 Register Adresse schreiben
    mov r0, r4
    bl i2c_write_byte
    cbnz r0, ds75_write_reg_nack

    // 1. Byte vom Register schreiben
    uxtb r0, r5
    bl i2c_write_byte
    cbnz r0, ds75_write_reg_nack

    // 16-bit Register bis auf Configuration, fuer Config nur 1 Byte schreiben
    cmp r4, #DS75_CONFIGURATION_REG
    beq ds75_write_reg_stop

    // 2. Byte vom Register schreiben
    uxtb r0, r5, ROR #8
    bl i2c_write_byte
    cbnz r0, ds75_write_reg_nack

ds75_write_reg_stop:
    // I2C Stop Bedingung erzeugen
    mov r0, #I2C0_C1_VAL_IDLE
    strb r0, [r6, #I2Cx_C1]

    // Warten bis Bus wieder in Ruhezustand ist
    bl i2c_Delay
    pop {r4-r6, pc}

ds75_write_reg_nack:
    ldr r0, =i2c_nack_error_txt
    bl uart_putString
    bkpt
    b .

// ds75_read_reg liest ein Register des DS75
// Parameter: DS75 Registeradresse in r0
// Rueckgabewert: Inhalt des Registers in r0
.thumb_func
ds75_read_reg:
    push {r4-r5, lr}
    mov r4, r0
    ldr r5, =I2C0_BASE

    // I2C Start Bedingung erzeugen
    bl i2c_start

    // DS75 schreibend adressieren
    mov r0, #(DS75_I2C_ADDR << 1)
    bl i2c_write_byte
    cbnz r0, ds75_read_reg_nack

    // DS75 Register Adresse schreiben
    mov r0, r4
    bl i2c_write_byte
    cbnz r0, ds75_read_reg_nack

    // I2C Repeated Start Bedingung erzeugen
    mov r0, #I2C0_C1_VAL_REPEATED_START
    strb r0, [r5, #I2Cx_C1]

    // DS75 lesend adressieren
    mov r0, #((DS75_I2C_ADDR << 1) | 0x01)
    bl i2c_write_byte
    cbnz r0, ds75_read_reg_nack

    // 16-bit Register bis auf Configuration
    cmp r4, #DS75_CONFIGURATION_REG
    beq ds75_read_reg_8b

    // Kontrollregister fuer naechsten Zugriff, Byte lesen und ACK senden
    mov r0, #I2C0_C1_VAL_RX_ACK
    strb r0, [r5, #I2Cx_C1]

    // Dummy read um Lesevorgang zu starten
    ldrb r0, [r5, #I2Cx_D]

    // Kontrollregister fuer naechsten Zugriff, letztes Byte -> NACK senden
    mov r0, #I2C0_C1_VAL_RX_NACK
    bl i2c_read_byte
    lsl r4, r0, #8

    // Kontrollregister fuer naechsten Zugriff, letztes Byte fertig -> Stop Bedingung erzeugen
    mov r0, #I2C0_C1_VAL_IDLE
    bl i2c_read_byte
    orr r4, r4, r0
    b ds75_read_reg_done

ds75_read_reg_8b:
    // Kontrollregister fuer naechsten Zugriff, (erstes und letztes) Byte lesen und NACK senden
    mov r0, #I2C0_C1_VAL_RX_NACK
    strb r0, [r5, #I2Cx_C1]

    // Dummy read um Lesevorgang zu starten
    ldrb r0, [r5, #I2Cx_D]

    // Kontrollregister fuer naechsten Zugriff, letztes Byte fertig -> Stop Bedingung erzeugen
    mov r0, #I2C0_C1_VAL_IDLE
    bl i2c_read_byte
    mov r4, r0

ds75_read_reg_done:
    // Warten bis Bus wieder in Ruhezustand ist
    bl i2c_Delay

    mov r0, r4
    pop {r4-r5, pc}

ds75_read_reg_nack:
    ldr r0, =i2c_nack_error_txt
    bl uart_putString
    bkpt
    b .

// i2c_start erzeugt eine Start Bedingung auf dem I2C-Bus und prueft auf erfolgreiche Arbitrierung
.thumb_func
i2c_start:
    ldr r3, =I2C0_BASE
    mov r1, #I2C0_C1_VAL_START

    mov r0, #10 // 10 Versuche
i2c_start_retry:
    // Arbitration Lost Flag zuruecksetzen
    mov r2, #I2Cx_S_ARBL
    strb r2, [r3, #I2Cx_S]

    // Start Bedingung erzeugen
    strb r1, [r3, #I2Cx_C1]

    // Steuerregister pruefen
    ldrb r2, [r3, #I2Cx_C1]
    cmp r1, r2
    bne i2c_start_fail

    // Arbitration Lost Flag pruefen, wenn gesetzt war Start nicht erfolgreich
    ldrb r2, [r3, #I2Cx_S]
    ands r2, #I2Cx_S_ARBL
    beq i2c_start_success

i2c_start_fail:
    // Nicht erfolgreich -> erneut versuchen
    subs r0, r0, #1
    bne i2c_start_retry

    // Endgueltig gescheitert, sollte hier nicht passieren
    ldr r0, =i2c_start_error_txt
    bl uart_putString
    bkpt
    b .

i2c_start_success:
    bx lr

// i2c_write_byte gibt ein Byte auf dem I2C-Bus aus und wartet bis es erfolgreich uebertragen wurde
// Parameter: Datenbyte in r0
// Rueckgabewert in r0, 0 falls Slave mit ACK antwortet, ansonsten wurde ein NACK empfangen
.thumb_func
i2c_write_byte:
    ldr r3, =I2C0_BASE

    // Datenbyte schreiben
    strb r0, [r3, #I2Cx_D]

    // Warten auf Interruptstatusflag
i2c_write_byte_wait:
    ldrb r0, [r3, #I2Cx_S]
    ands r1, r0, #I2Cx_S_IICIF
    beq i2c_write_byte_wait

    // Interruptstatusflag zuruecksetzen
    mov r1, #I2Cx_S_IICIF
    strb r1, [r3, #I2Cx_S]

    // ACK/NACK pruefen
    and r0, r0, #I2Cx_S_RXACK
    bx lr

// i2c_read_byte liest ein Byte vom I2C-Bus und setzt das Steuerregister vor dem Lesen des Datenregisters,
// um den naechsten Zustand fuer den I2C-Controller einzustellen
.thumb_func
i2c_read_byte:
    ldr r3, =I2C0_BASE

    // Warten auf Interruptstatusflag
i2c_read_byte_wait:
    ldrb r2, [r3, #I2Cx_S]
    ands r1, r2, #I2Cx_S_IICIF
    beq i2c_read_byte_wait

    // Interruptstatusflag zuruecksetzen
    mov r1, #I2Cx_S_IICIF
    strb r1, [r3, #I2Cx_S]

    // Neuen Wert ins Steuerregister bevor State Machine vom I2C-Controller durch lesen des Datenregisters weitergeschaltet wird
    strb r0, [r3, #I2Cx_C1]

    // Datenbyte lesen
    ldrb r0, [r3, #I2Cx_D]
    bx lr

// Verzoegerung um ca. 2us, damit I2C Bus Ruhezustand einnehmen kann
.align 2
.thumb_func
i2c_Delay:
    mov r0, #i2c_delay_const
i2c_delay_loop:
    mov r0, r0
    subs r0, r0, #1
    bne i2c_delay_loop
    mov r0, r0
    bx lr

// I2C-Bus Resetfunktion, um I2C-Bus in einen definierten Zustand zurueckzusetzen.
.thumb_func
I2CBus_Reset:
    push {lr}

    // Den Takt fuer Port D aktivieren
    ldr r0, =SIM_SCGC5_PORTD
    mov r1, #1
    str r1, [r0]

    // Portleitungen SCL, SDA als GPIO
    ldr r0, =PORTD_PCR8
    ldr r1, =PORTD_PCR9
    mov r2, #I2C_PORT_FLAGS_GPIO
    str r2, [r0]
    str r2, [r1]

    // SCL, SDA als Ausgang schalten
    ldr r0, =GPIOD_PDDR
    ldr r2, [r0]
    orr r2, r2, #(PORTD_SCL_MASK | PORTD_SDA_MASK)
    str r2, [r0]

    mov r3, #10 // 10 Versuche
I2CBus_Reset_loop:
    // SCL deaktivieren
    ldr r0, =GPIOD_PDOR
    ldr r2, [r0]
    bic r2, r2, #PORTD_SCL_MASK
    str r2, [r0]
    bl i2c_Delay

    // SCL und SDA aktivieren
    ldr r0, =GPIOD_PDOR
    ldr r2, [r0]
    orr r2, r2, #(PORTD_SCL_MASK | PORTD_SDA_MASK)
    str r2, [r0]
    bl i2c_Delay

    // Pruefen, ob SCL/SDA gesetzt sind
    ldr r0, =GPIOD_PDIR
    ldr r2, [r0]
    and r2, r2, #(PORTD_SCL_MASK | PORTD_SDA_MASK)
    cmp r2, #(PORTD_SCL_MASK | PORTD_SDA_MASK)
    beq I2CBus_Reset_success

    // Reset nicht erfolgreich -> ggf. wiederholen
    subs r3, r3, #1
    bne I2CBus_Reset_loop

    // Endgueltig gescheitert, sollte hier nicht passieren
    ldr r0, =i2cbus_reset_error_txt
    bl uart_putString
    bkpt
    b .

I2CBus_Reset_success:
    pop {pc}

// Interrupt Service Routine fuer PIT1
.thumb_func
pit1_isr:
    // 1s vorbei -> Flag setzen
    ldr r0, =pit_tick
    mov r1, #1
    strb r1, [r0]

    // Interrupt Flag von PIT1 loeschen
    ldr r0, =PIT_BASE
    str r1, [r0, #PIT_TFLG1]

    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
pit_tick: .byte 0

temperature_prefix_txt: .asciz "\n0x"
temperature_suffix_txt: .asciz " Grad Celsius"
i2cbus_reset_error_txt: .asciz "\nI2C-Bus Reset fehlgeschlagen"
i2c_start_error_txt: .asciz "\nStart Bedingung konnte nicht ausgegeben werden"
i2c_nack_error_txt: .asciz "\nUnerwartetes NACK erhalten"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_NEWLINE,     0x0a
.equ ASCII_COMMA,       0x2c

// SIM Register
__BBREG SIM_SCGC3_SPI2,  0x40048030, 12
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC5_PORTD, 0x40048038, 12
__BBREG SIM_SCGC5_PORTE, 0x40048038, 13
__BBREG SIM_SCGC6_PIT,   0x4004803c, 23

// PIT Register
// Basisadresse
.equ PIT_BASE,   0x40037000
// Offsets der Register zur Basisadresse
.equ PIT_MCR,    0x000
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1,  0x11c

// PIT1 - Vektor 85 (IRQ 69)
// -> Offset fuer Vektortabelle 85 * 4 = 0x154
// zugehoerig NVIC_*2, Bit 5
.equ PIT1_IRQ_OFFSET, 0x154
.equ PIT1_NVIC_MASK, 0x20

.equ PIT_MCR_VAL,           0 // MDIS=0, FRZ=0
.equ PIT_TCTRL1_VAL,        3 // CHN=0, TIE=1, TEN=1
.equ PIT1_PERIOD,     1875000 // 0.075s -> 1.875.000 clocks @ 25MHz

// SW1 (schwarz)
.equ PORTA_PCR19, 0x4004904c
__BBREG GPIOA_PDIR_19, 0x400ff010, 19
__BBREG GPIOA_PDDR_19, 0x400ff014, 19
__BBREG PORTA_ISFR_19, 0x400490a0, 19

// SW2 (gruen)
.equ PORTE_PCR26, 0x4004d068
__BBREG GPIOE_PDIR_26, 0x400ff110, 26
__BBREG GPIOE_PDDR_26, 0x400ff114, 26
__BBREG PORTE_ISFR_26, 0x4004d0a0, 26

.equ SW_PORT_FLAGS, 0x000a0103 // MUX=1 (GPIO), Pull-Up (PS=1, PE=1), Interrupt on falling edge (IRQC=1010)

// PORTA - Vektor 103 (IRQ 87)
// -> Offset fuer Vektortabelle 103 * 4 = 0x19c
// zugehoerig NVIC_*2, Bit 23
.equ PORTA_IRQ_OFFSET, 0x19c
.equ PORTA_NVIC_MASK, 0x00800000

// PORTE - Vektor 107 (IRQ 91)
// -> Offset fuer Vektortabelle 107 * 4 = 0x1ac
// zugehoerig NVIC_*2, Bit 27
.equ PORTE_IRQ_OFFSET, 0x1ac
.equ PORTE_NVIC_MASK, 0x08000000

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// NVIC Register
.equ NVIC_ISER2, 0xe000e108
.equ NVIC_ICPR2, 0xe000e288

.equ NVIC_IxxR2_MASK, PORTA_NVIC_MASK | PORTE_NVIC_MASK | PIT1_NVIC_MASK

// SPI Register
// Basisadresse
.equ SPI2_BASE, 0x400AC000
// Offsets der Register zur Basisadresse
.equ SPIx_MCR,   0x00
.equ SPIx_TCR,   0x08
.equ SPIx_CTAR0, 0x0C
.equ SPIx_CTAR1, 0x10
.equ SPIx_SR,    0x2C
.equ SPIx_RSER,  0x30
.equ SPIx_PUSHR, 0x34
.equ SPIx_POPR,  0x38
.equ SPIx_TXFR0, 0x3C
.equ SPIx_TXFR1, 0x40
.equ SPIx_TXFR2, 0x44
.equ SPIx_TXFR3, 0x48
.equ SPIx_RXFR0, 0x7C
.equ SPIx_RXFR1, 0x80
.equ SPIx_RXFR2, 0x84
.equ SPIx_RXFR3, 0x88

__BBREG SPI2_SR_TCF, SPI2_BASE + SPIx_SR, 31

// Flags fuer PUSHR Register
.equ SPIx_PUSHR_CONT, 0x80000000
.equ SPIx_PUSHR_PCS1, 0x00020000

// SPI2
//   SCK  (connector pin 12, PTD12)
//   MOSI (connector pin 10, PTD13)
//   MISO (connector pin  9, PTD14)
//   CS   (connector pin 11, PTD15)
.equ PORTD_PCR12, 0x4004c030
.equ PORTD_PCR13, 0x4004c034
.equ PORTD_PCR14, 0x4004c038
.equ PORTD_PCR15, 0x4004c03c
.equ SPI_PORT_FLAGS, 0x00000200 // MUX=2 (SPI)

.equ SPI2_MCR_VAL_RESET,   0x80000c01 // HALT=1 (Stop transfers, bis alle Register konfiguriert)
                                      // CLR_RXF=1 (Reset RX FIFO)
                                      // CLR_TXF=1 (Reset TX FIFO)
                                      // DIS_RXF=0 (RX FIFO enabled)
                                      // DIS_TXF=0 (TX FIFO enabled)
                                      // MDIS=0 (Enable clocks)
                                      // PCSIS=0 (DS1722 CS active-high)
                                      // MSTR=1 (Master mode)

// Nach SPI2_MCR_VAL_RESET, damit MDIS=0 bevor FIFOs ausgeschaltet werden koennen
.equ SPI2_MCR_VAL_HALTED,  0x80003001 // HALT=1 (Stop transfers, bis alle Register konfiguriert)
                                      // CLR_RXF=0 (*No* reset RX FIFO)
                                      // CLR_TXF=0 (*No* reset TX FIFO)
                                      // DIS_RXF=1 (RX FIFO disabled)
                                      // DIS_TXF=1 (TX FIFO disabled)
                                      // MDIS=0 (Enable clocks)
                                      // PCSIS=0 (DS1722 CS active-high)
                                      // MSTR=1 (Master mode)

.equ SPI2_MCR_VAL_RUNNING, 0x80003000 // HALT=0 (Start transfers)
                                      // CLR_RXF=0 (*No* reset RX FIFO)
                                      // CLR_TXF=0 (*No* reset TX FIFO)
                                      // DIS_RXF=1 (RX FIFO disabled)
                                      // DIS_TXF=1 (TX FIFO disabled)
                                      // MDIS=0 (Enable clocks)
                                      // PCSIS=0 (DS1722 CS active-high)
                                      // MSTR=1 (Master mode)

// Nach SPI2_MCR_VAL_HALTED, vor SPI2_MCR_VAL_RUNNING, da nicht in Running mode schreibbar
.equ SPI2_RSER_VAL,        0x00000000 // Alle IRQ/DMA Requests abgeschaltet

// Baudrate = 25MHz / PBR * (1+DBR)/BR = 25MHz / 256 = 97kHz
.equ SPI2_CTAR0_VAL,       0x3e000007 // BR=7 (Divide by 128)
                                      // PBR=0 (Baud Rate prescale by 2)
                                      // DBR=0
                                      // CPHA=1 (Data is changed on the leading edge of SCK and captured on the following edge)
                                      // CPOL=1 (The inactive state value of SCK is high)
                                      // FMSZ=7 (8-bit Worte)

// DS1722 Register
.equ DS1722_CONFIG_REG,     0x00
.equ DS1722_TEMP_LSB_REG,   0x01
.equ DS1722_TEMP_MSB_REG,   0x02

// MSB der Adresse ist R/W Flag
.equ DS1722_REG_WRITE_FLAG, 0x80

.equ DS1722_CONFIG_BASE, 0xe0 // 1SHOT=0, SD=0, Bit 7-5=1 (reserved)

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    // Takt fuer Ports einschalten
    mov r2, #1
    ldr r0, =SIM_SCGC5_PORTA
    str r2, [r0]
    ldr r0, =SIM_SCGC5_PORTD
    str r2, [r0]
    ldr r0, =SIM_SCGC5_PORTE
    str r2, [r0]

    //
    // SPI2
    //

    // Takt fuer SPI einschalten
    ldr r0, =SIM_SCGC3_SPI2
    str r2, [r0]

    // SPI konfigurieren
    ldr r4, =SPI2_BASE

    // SPI Steuerregister auf sicheren Wert zuruecksetzen, damit die anderen Steuerregister konfiguriert werden koennen
    // im besonderen MDIS=0 und HALT=1
    ldr r0, =SPI2_MCR_VAL_RESET
    str r0, [r4, #SPIx_MCR]

    // FIFOs ausschalten (benoetigt MDIS=0)
    ldr r0, =SPI2_MCR_VAL_HALTED
    str r0, [r4, #SPIx_MCR]

    // Interrupt/DMA-Requests abschalten (benoetigt HALT=1)
    ldr r0, =SPI2_RSER_VAL
    str r0, [r4, #SPIx_RSER]
    // Transfer-Parameter einstellen (benoetigt HALT=1)
    ldr r0, =SPI2_CTAR0_VAL
    str r0, [r4, #SPIx_CTAR0]

    // Konfiguration fertig -> SPI Controller starten (HALT=0)
    ldr r0, =SPI2_MCR_VAL_RUNNING
    str r0, [r4, #SPIx_MCR]

    // SPI Ports konfigurieren
    ldr r1, =SPI_PORT_FLAGS
    ldr r0, =PORTD_PCR12
    str r1, [r0]
    ldr r0, =PORTD_PCR13
    str r1, [r0]
    ldr r0, =PORTD_PCR14
    str r1, [r0]
    ldr r0, =PORTD_PCR15
    str r1, [r0]

    // SW1/2 Ports konfigurieren
    ldr r1, =SW_PORT_FLAGS
    ldr r0, =PORTA_PCR19
    str r1, [r0]
    ldr r0, =PORTE_PCR26
    str r1, [r0]

    // SWs als Eingang konfigurieren
    mov r3, #0
    ldr r0, =GPIOA_PDDR_19
    str r3, [r0]
    ldr r0, =GPIOE_PDDR_26
    str r3, [r0]

    // Interruptvektor zu PORTA/PORTE setzen
    ldr r3, =SCR_VTOR
    ldr r3, [r3]
    ldr r1, =porta_isr
    str r1, [r3, #PORTA_IRQ_OFFSET]
    ldr r1, =porte_isr
    str r1, [r3, #PORTE_IRQ_OFFSET]


    //
    // PIT
    //

    // Takt fuer PIT aktivieren
    ldr r0, =SIM_SCGC6_PIT
    str r2, [r0]

    // Interruptvektor zu PIT1 setzen
    ldr r1, =pit1_isr
    str r1, [r3, #PIT1_IRQ_OFFSET]

    // Alle PITs aktivieren und im Debug-Modus laufen lassen
    ldr r0, =PIT_BASE
    mov r1, #PIT_MCR_VAL
    str r1, [r0, #PIT_MCR]

    // Startwert von PIT1 auf 0.075s initialisieren
    ldr r1, =PIT1_PERIOD
    str r1, [r0, #PIT_LDVAL1]

    // Interrupt von PIT1 aktivieren und PIT1 starten
    mov r1, #PIT_TCTRL1_VAL
    str r1, [r0, #PIT_TCTRL1]

    //
    // NVIC
    //
    ldr r1, =NVIC_IxxR2_MASK

    // Ausstehende Interrupts von PORTA/PORTE/PIT1 loeschen
    ldr r0, =NVIC_ICPR2
    str r1, [r0]

    // Interrupt von PORTA/PORTE/PIT1 im NVIC aktivieren
    ldr r0, =NVIC_ISER2
    str r1, [r0]

    //
    // DS1722
    //
    mov r7, #4   // Register mit Aufloesung fuer Hauptschleife, Aufloesung ist (8 + r7) bit
    mov r0, r7
    bl ds1722_set_resolution

    mov r6, #16  // Zaehler fuer Wandlungszeit, ADC braucht 2^r7 PIT ticks (0.075s) -> Wandlungszeit (1 << r7) PIT ticks

    //
    // Register fuer Hauptschleife initialisieren
    //
    ldr r5, =pit_tick
    ldr r8, =sw_pending

main_loop:
    // Gab es einen Tick von PIT1?
    ldrb r0, [r5]
    cmp r0, #0
    beq main_loop

    // Tick Flag zuruecksetzen
    mov r0, #0
    strb r0, [r5]

    // Wurde SW1 gedrueckt?
    ldrb r0, [r8, #0]
    cbz r0, skip_sw1

    // SW1 Flag zuruecksetzen
    mov r0, #0
    strb r0, [r8, #0]

    // Aufloesung um 1 bit erhoehen. Falls Aufloesung 12 bit ist, auf 8 bit aendern
    cmp r7, #4
    ite eq
    moveq r7, #0
    addne r7, r7, #1

    // Zaehler fuer Wandlungszeit anpassen
    // ADC braucht 2^r7 PIT ticks (0.075s) -> Wandlungszeit (1 << r7) PIT ticks
    mov r6, #1
    lsl r6, r6, r7

    // Neue Aufloesung in DS1722 einstellen
    mov r0, r7
    bl ds1722_set_resolution

    // Neue Aufloesung auf UART ausgeben
    ldr r0, =temperature_resolution_txt
    bl uart_putString
    add r0, r7, #8
    bl uart_putByteBase10

skip_sw1:
    // Wurde SW2 gedrueckt?
    ldrb r0, [r8, #1]
    cbz r0, skip_sw2

    // SW2 Flag zuruecksetzen
    mov r0, #0
    strb r0, [r8, #1]

    // Aufloesung um 1 bit erniedrigen. Falls Aufloesung 8 bit ist, auf 12 bit aendern
    cmp r7, #0
    ite eq
    moveq r7, #4
    subne r7, r7, #1

    // Zaehler fuer Wandlungszeit anpassen
    // ADC braucht 2^r7 PIT ticks (0.075s) -> Wandlungszeit (1 << r7) PIT ticks
    mov r6, #1
    lsl r6, r6, r7

    // Neue Aufloesung in DS1722 einstellen
    mov r0, r7
    bl ds1722_set_resolution

    // Neue Aufloesung auf UART ausgeben
    ldr r0, =temperature_resolution_txt
    bl uart_putString
    add r0, r7, #8              // Aufloseung = r7 + 8 bit
    bl uart_putByteBase10

skip_sw2:
    // Zaehler fuer Wandlungszeit runterzaehlen
    subs r6, r6, #1

    // Wandlung noch nicht fertig, dann wieder zum Anfang
    bne main_loop

    // Zaehler fuer Wandlungszeit zuruecksetzen
    // ADC braucht 2^r7 PIT ticks (0.075s) -> Wandlungszeit (1 << r7) PIT ticks
    mov r6, #1
    lsl r6, r6, r7

    //
    // Temperatur ausgeben
    //
    mov r0, #ASCII_NEWLINE
    bl uart_putChar

    // Temperaturregister adressieren
    mov r0, #DS1722_TEMP_LSB_REG
    bl spi_exchange_byte

    // Dummy byte senden und LSB der Temperatur lesen
    mov r0, #0
    bl spi_exchange_byte
    mov r9, r0

    // Dummy byte senden, MSB der Temperatur lesen und Chip Select nach Transfer deaktivieren, da Uebertragung abgeschlossen
    mov r0, #0
    bl spi_exchange_byte_release_cs

    // Ganzzahligen Anteil der Temperatur ausgeben
    bl uart_putByteBase10

    mov r0, #ASCII_COMMA
    bl uart_putChar

    // 4 BCD kodierte Nachkommastellen laden aus Array
    ubfx r1, r9, #4, #4
    ldr r0, =temperature_decimal
    ldrh r9, [r0, r1, lsl #1]

    // 1. Nachkommastelle ausgeben
    ubfx r0, r9, #12, #4
    bl uart_putByteBase10

    // 2. Nachkommastelle ausgeben
    ubfx r0, r9, #8, #4
    bl uart_putByteBase10

    // 3. Nachkommastelle ausgeben
    ubfx r0, r9, #4, #4
    bl uart_putByteBase10

    // 4. Nachkommastelle ausgeben
    ubfx r0, r9, #0, #4
    bl uart_putByteBase10

    // Einheit ausgeben
    ldr r0, =temperature_suffix_txt
    bl uart_putString

    b main_loop

// Funktion zum Setzen der Aufloesung des DS1722 Thermometers
// Parameter r0 = Aufloesung: 0 = 8 bit, 1 = 9 bit, ..., 4 = 12 bit
.thumb_func
ds1722_set_resolution:
    push {r4, lr}

    // Basiskonfiguration vom DS1722 laden und Aufloesung einfuegen
    mov r4, #DS1722_CONFIG_BASE
    bfi r4, r0, #1, #3

    // Sende Registeradresse
    mov r0, #(DS1722_REG_WRITE_FLAG | DS1722_CONFIG_REG)
    bl spi_exchange_byte

    // Sende neuen Wert vom Konfigurationsregister
    mov r0, r4
    bl spi_exchange_byte_release_cs // Letztes Byte -> Chip Select nach Transfer deaktivieren

    pop {r4, pc}

// spi_exchange_byte fuehrt einen vollduplexen Transfer auf dem SPI durch,
// dass heisst das Byte als Parameter in r0 wird gesendet und ein Byte wird gelesen und in r0 zurueckgegeben
// Falls der Chip Select des DS1277 noch nicht gesetzt ist, wird dieser aktiviert und bleibt auch nach dem Transfer aktiviert,
// so dass noch weitere Bytes uebertragen werden koennen
.thumb_func
spi_exchange_byte:
    orr r0, r0, #SPIx_PUSHR_CONT  // Chip Select nach Transfer aktiviert lassen

// Beabsichtigtes "durchfallen" zu spi_exchange_byte_release_cs

// Analog zu spi_exchange_byte, jedoch wird nach dem Transfer der Chip Select deaktiviert
.thumb_func
spi_exchange_byte_release_cs:
    ldr r2, =SPI2_BASE

    // Transfer Complete Flag zuruecksetzten, falls noch gesetzt war
    ldr r3, =SPI2_SR_TCF
    mov r1, #1
    str r1, [r3]

    // PCS1 fuer DS1722 verwenden
    orr r0, r0, #SPIx_PUSHR_PCS1

    // Transfer ausfuehren
    str r0, [r2, #SPIx_PUSHR]

    // Warten bis Transfer Complete Flag gesetzt ist
spi_exchange_byte_loop_tcf:
    ldr r0, [r3]
    cmp r0, #0
    beq spi_exchange_byte_loop_tcf

    // Transfer Complete Flag zuruecksetzen
    str r0, [r3]

    // Empfangenes Byte lesen
    ldr r0, [r2, #SPIx_POPR]

    bx lr

// Interrupt Service Routine fuer PIT1
.thumb_func
pit1_isr:
    // 0.075s vorbei -> Flag setzen
    ldr r0, =pit_tick
    mov r1, #1
    strb r1, [r0]

    // Interrupt Flag von PIT1 loeschen
    ldr r0, =PIT_BASE
    str r1, [r0, #PIT_TFLG1]

    bx lr

// Interrupt Service Routine fuer SW1
.thumb_func
porta_isr:
    // Fallende Flanke von SW1 abspeichern zur Verarbeitung in Hauptschleife
    ldr r0, =sw_pending
    mov r1, #1
    strb r1, [r0, #0]

    // Interrupt Flag von SW1 loeschen
    ldr r0, =PORTA_ISFR_19
    str r1, [r0]

    bx lr

// Interrupt Service Routine fuer SW2
.thumb_func
porte_isr:
    // Fallende Flanke von SW2 abspeichern zur Verarbeitung in Hauptschleife
    ldr r0, =sw_pending
    mov r1, #1
    strb r1, [r0, #1]

    // Interrupt Flag von SW2 loeschen
    ldr r0, =PORTE_ISFR_26
    str r1, [r0]

    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
pit_tick: .byte 0  // Flag fuer PIT, wird alle 0.075s gesetzt
sw_pending:
.byte 0            // Flag fuer SW1
.byte 0            // Flag fuer SW2

// 0/16 - 15/16 Nachkommaanteil
// Hier BCD kodiert, gleicher Speicherbedarf aber keine Fallunterscheidung fuer fuehrende Null bei uart_putByteBase10 notwendig
.align 2
temperature_decimal:
.hword 0x0000
.hword 0x0625
.hword 0x1250
.hword 0x1875
.hword 0x2500
.hword 0x3125
.hword 0x3750
.hword 0x4375
.hword 0x5000
.hword 0x5625
.hword 0x6250
.hword 0x6875
.hword 0x7500
.hword 0x8125
.hword 0x8750
.hword 0x9375

temperature_suffix_txt: .asciz " gC"
temperature_resolution_txt: .asciz "\nTemperaturaufloesung (Bit): "
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_NEWLINE, 0x0a
.equ ASCII_ZERO,    0x30
.equ ASCII_COLON,   0x3a
.equ ASCII_D,       0x64
.equ ASCII_H,       0x68
.equ ASCII_P,       0x70
.equ ASCII_R,       0x72
.equ ASCII_S,       0x73

.equ SECONDS_PER_HOUR, 3600
.equ SECONDS_PER_MINUTE, 60

// SIM Register
__BBREG SIM_SCGC6_RTC, 0x4004803c, 29

// RTC Register
// Basisadresse
.equ RTC_BASE, 0x4003d000
// Offsets der Register zur Basisadresse
.equ RTC_TSR, 0x000
.equ RTC_TPR, 0x004
.equ RTC_TAR, 0x008
.equ RTC_TCR, 0x00c
.equ RTC_CR,  0x010
.equ RTC_SR,  0x014
.equ RTC_LR,  0x018
.equ RTC_IER, 0x01c
.equ RTC_WAR, 0x800
.equ RTC_RAR, 0x804

__BBREG RTC_CR_SWR, RTC_BASE + RTC_CR, 0
__BBREG RTC_SR_TCE, RTC_BASE + RTC_SR, 4

// RTC Alarm IRQ - Vektor 82 (IRQ 66)
// -> Offset fuer Vektortabelle 82 * 4 = 0x148
// zugehoerig NVIC_*2, Bit 2
.equ RTC_ALARM_IRQ_OFFSET, 0x148
.equ RTC_ALARM_NVIC_MASK, 0x04

// RTC Seconds IRQ - Vektor 83 (IRQ 67)
// -> Offset fuer Vektortabelle 83 * 4 = 0x14c
// zugehoerig NVIC_*2, Bit 3
.equ RTC_SECONDS_IRQ_OFFSET, 0x14c
.equ RTC_SECONDS_NVIC_MASK, 0x08

.equ RTC_CR_VAL, 0x00000100 // SWR = 0 (No reset)
                            // WPE = 0 (Wakeup pin disabled)
                            // SUP = 0 (Non-supervisor mode write accesses are forbidden)
                            // UM = 0 (Registers cannot be written when locked)
                            // OSCE = 1 (Oscillator enabled)
                            // CLKO = 0 (Clock is not output to other peripherals)
                            // Keine Kapazitaet nach Aufgabenblatt
                            // SC16P = 0
                            // SC8P = 0
                            // SC4P = 0
                            // SC2P = 0

.equ RTC_TAR_VAL_DAY, 86399 // 23h 59m 59s in Sekunden
.equ RTC_TAR_VAL_HOUR, 3599 // 59m 59s in Sekunden

.equ RTC_IER_VAL, 0x00000014 // TIE = 0 (Time Invalid Interrupt disabled)
                             // TOIE = 0 (Time Overflow Interrupt disabled)
                             // TAIE = 1 (Time Alarm Interrupt enabled)
                             // TSIE = 1 (Time Seconds Interrupt disabled)
                             // WPON = 0 (Wake-up pin no effect) 

// Startzeit tStart = 1s in Abschnitt 6.3.3.2 im Kinetis Datenblatt fuer den RTC Oszillator
// Geprueft mit pit3 aus V1, Verzoegerung 25.165.824 Takte = ~1s @ 25MHz 
.equ RTC_OSC_STARTUP_DELAY, 0x800000

// Zeit, auf die die RTC mit einem "p" Presetkommando vorgestellt wird
.equ RTC_TIME_PRESET_DAY, 86395 // 23h 59m 55s in Sekunden
.equ RTC_TIME_PRESET_HOUR, 3595 // 59m 55s in Sekunden

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// NVIC Register
.equ NVIC_ISER2, 0xe000e108
.equ NVIC_ICPR2, 0xe000e288

.equ NVIC_IxxR2_MASK, RTC_ALARM_NVIC_MASK | RTC_SECONDS_NVIC_MASK

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    //
    // RTC
    //

    // Takt fuer RTC einschalten
    ldr r0, =SIM_SCGC6_RTC
    mov r2, #1
    str r2, [r0]

    // RTC zuruecksetzen, setzt alle RTC Register auf Resetwert bis auf RTC_WAR und RTC_RAR
    // RTC_WAR und RTC_RAR werden benutzt um Schreib- bzw. Lesezugriff auf die RTC-Register zu verhindern
    // Diese werden nur beim System-Reset auf 1 (Zugriff erlaubt) gesetzt, waeren sie an dieser Stelle nicht mehr 1,
    // koennte dies an dieser Stelle auch nicht mehr geaendert werden. Somit muss ihr Wert hier auch nicht veraendert werden,
    // da alle Zugriffe erlaubt sein sollen.
    ldr r0, =RTC_CR_SWR
    str r2, [r0]
    mov r1, #0
    str r1, [r0]

    // RTC Oszillator starten
    ldr r4, =RTC_BASE
    mov r0, #RTC_CR_VAL
    str r0, [r4, #RTC_CR]

    // Warten bis RTC Oszillator gestartet ist
    mov r0, #RTC_OSC_STARTUP_DELAY
wait_osc_startup:
    subs r0, r0, #1
    bne wait_osc_startup

    // RTC_TCR durch Reset auf 0, kann auf 0 bleiben, keine Feinabstimmung noetig bzw. moeglich (wuerde GPS oder aehnliche Uhr mit hoeherer Genauigkeit als Quarz benoetigen)
    // RTC_LR kann auf Resetwert bleiben. Es sollen keine Register gesperrt werden.

    // Sekunden- und Alarminterrupt einschalten
    mov r0, #RTC_IER_VAL
    str r0, [r4, #RTC_IER]

    // Interruptvektor zu Alarm- und Sekundeninterrupt setzen
    ldr r3, =SCR_VTOR
    ldr r3, [r3]
    ldr r0, =rtc_alarm_isr
    str r0, [r3, #RTC_ALARM_IRQ_OFFSET]
    ldr r0, =rtc_seconds_isr
    str r0, [r3, #RTC_SECONDS_IRQ_OFFSET]

    // Aktuelle Zeit (RTC_TSR) auf 0 setzen (zwar durch Reset schon 0, muss aber geschrieben werden um Time Invalid Flag zurueckzusetzen)
    // RTC_TPR bereits durch Reset auf 0 gesetzt
    str r1, [r4, #RTC_TSR]
    
    // Alarm setzen auf 23:59:59
    ldr r0, =RTC_TAR_VAL_DAY
    str r0, [r4, #RTC_TAR]

    // RTC starten
    ldr r5, =RTC_SR_TCE
    str r2, [r5]

    //
    // NVIC
    //
    ldr r0, =NVIC_IxxR2_MASK

    // Ausstehende Interrupts von Alarm- und Sekundeninterrupt loeschen
    ldr r3, =NVIC_ICPR2
    str r0, [r3]

    // Interrupt von Alarm- und Sekundeninterrupt im NVIC aktivieren
    ldr r3, =NVIC_ISER2
    str r0, [r3]

    //
    // Register fuer Hauptschleife initialisieren
    //
    ldr r10, =rtc_flags
    mov r7, #1             // Ausgabe der Uhrzeit auf dem Terminal, 1 = aktiviert, 0 = deaktiviert
    mov r6, #0             // Modus, 0 = 24-Stunden-Modus, 1 = 1-Stunden-Modus

    // Direkt nach Start einmal die Zeit ausgeben und dann normal mit Hauptschleife fortfahren
    b force_output_time

main_loop:
    // Pruefen auf Zeichen vom UART
    bl uart_charPresent
    cmp r0, #0
    beq handle_input_done

    bl uart_getChar
    cmp r0, #ASCII_D
    beq handle_d
    cmp r0, #ASCII_H
    beq handle_h
    cmp r0, #ASCII_P
    beq handle_p
    cmp r0, #ASCII_R
    beq handle_r
    cmp r0, #ASCII_S
    beq handle_s
    b handle_input_done

handle_d:
    mov r6, #0

    // Alarm setzen auf 23:59:59
    ldr r0, =RTC_TAR_VAL_DAY
    str r0, [r4, #RTC_TAR]

    // Aktuelle Zeit (RTC_TSR) auf 0 setzen. Dazu RTC kurz deaktivieren und nach dem Schreiben von RTC_TSR wieder aktivieren
    str r6, [r5]
    str r6, [r4, #RTC_TSR]
    mov r0, #1
    str r0, [r5]

    // Sekundenflag setzen um Zeitausgabe zu erzwingen
    strb r0, [r10, #0]

    ldr r0, =twenty_four_hour_mode_txt
    bl uart_putString

    b handle_input_done

handle_h:
    mov r6, #1

    // Alarm setzen auf 59:59
    ldr r0, =RTC_TAR_VAL_HOUR
    str r0, [r4, #RTC_TAR]

    // Aktuelle Zeit (RTC_TSR) auf 0 setzen. Dazu RTC kurz deaktivieren und nach dem Schreiben von RTC_TSR wieder aktivieren
    mov r0, #0
    str r0, [r5]
    str r0, [r4, #RTC_TSR]
    str r6, [r5]

    // Sekundenflag setzen um Zeitausgabe zu erzwingen
    strb r6, [r10, #0]

    ldr r0, =one_hour_mode_txt
    bl uart_putString

    b handle_input_done

handle_r:
    // Aktuelle Zeit (RTC_TSR) auf 0 setzen. Dazu RTC kurz deaktivieren und nach dem Schreiben von RTC_TSR wieder aktivieren
    mov r0, #0
    str r0, [r5]
    str r0, [r4, #RTC_TSR]
    mov r0, #1
    str r0, [r5]

    // Sekundenflag setzen um Zeitausgabe zu erzwingen
    strb r0, [r10, #0]

    ldr r0, =reset_txt
    bl uart_putString

    b handle_input_done

handle_p:
    // Aktuelle Zeit (RTC_TSR) auf 23:59:55 bzw. 59:55 setzen. Dazu RTC kurz deaktivieren und nach dem Schreiben von RTC_TSR wieder aktivieren
    mov r0, #0
    str r0, [r5]

    cmp r6, #0
    ite eq
    ldreq r1, =RTC_TIME_PRESET_DAY
    ldrne r1, =RTC_TIME_PRESET_HOUR
    str r1, [r4, #RTC_TSR]

    mov r0, #1
    str r0, [r5]

    // Sekundenflag setzen um Zeitausgabe zu erzwingen
    strb r0, [r10, #0]

    ldr r0, =preset_txt
    bl uart_putString

    b handle_input_done

handle_s:
    // 's' empfangen, starte/stoppe Ausgabe der Uhrzeit
    eors r7, r7, #1

    ite eq
    ldreq r0, =stop_display_txt
    ldrne r0, =start_display_txt
    bl uart_putString

handle_input_done:
    // Gab es einen Alarm?
    ldrb r0, [r10, #1]
    cbz r0, output_time

    // Alarm Flag zuruecksetzen
    mov r0, #0
    strb r0, [r10, #1]

    // Endzeitpunkt erreicht aktuelle Zeit (RTC_TSR) wieder auf 0 setzen.
    // Dazu RTC kurz deaktivieren und nach dem Schreiben von RTC_TSR wieder aktivieren
    str r0, [r5]
    str r0, [r4, #RTC_TSR]
    mov r0, #1
    str r0, [r5]

    ldr r0, =alarm_txt
    bl uart_putString

output_time:
    // Ist eine Sekunde vorbei?
    ldrb r0, [r10, #0]
    cmp r0, #0
    beq main_loop

    // Sekunden Flag zuruecksetzen
    mov r0, #0
    strb r0, [r10, #0]

    // Ausgabe deaktiviert?
    cmp r7, #0
    beq main_loop

force_output_time:
    mov r0, #ASCII_NEWLINE
    bl uart_putChar

    ldr r8, [r4, #RTC_TSR]

    // 1h Modus aktiviert?
    cbnz r6, output_minutes

    // Stunden bestimmen
    mov r1, #SECONDS_PER_HOUR
    udiv r9, r8, r1
    mls r8, r9, r1, r8

    // Stunden ausgeben
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r9, #10
    bge clock_print_hours_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_hours_skip_prefix:
    mov r0, r9
    bl uart_putByteBase10

    mov r0, #ASCII_COLON
    bl uart_putChar

output_minutes:
    // Minuten und Sekunden bestimmen
    mov r1, #SECONDS_PER_MINUTE
    udiv r9, r8, r1
    mls r8, r9, r1, r8

    // Minuten ausgeben
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r9, #10
    bge clock_print_minutes_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_minutes_skip_prefix:
    mov r0, r9
    bl uart_putByteBase10

    mov r0, #ASCII_COLON
    bl uart_putChar

    // Sekunden ausgeben
    // Wenn < 0 "0" als Prefix zuerst ausgeben
    cmp r8, #10
    bge clock_print_seconds_skip_prefix
    mov r0, #ASCII_ZERO
    bl uart_putChar
clock_print_seconds_skip_prefix:
    mov r0, r8
    bl uart_putByteBase10

    b main_loop

// Interrupt Service Routine fuer RTC Alarm
.thumb_func
rtc_alarm_isr:
    // RTC Alarm abspeichern zur Verarbeitung in Hauptschleife
    ldr r0, =rtc_flags
    mov r1, #1
    strb r1, [r0, #1]

    // Alarm wieder auf denselben Wert setzen, um Time Alarm Flag zu loeschen
    ldr r0, =RTC_BASE
    ldr r1, [r0, #RTC_TAR]
    str r1, [r0, #RTC_TAR]

    bx lr

// Interrupt Service Routine fuer RTC Sekundeninterrupt
.thumb_func
rtc_seconds_isr:
    // Sekunde vorbei, zur Verarbeitung in Hauptschleife Flag setzen
    ldr r0, =rtc_flags
    mov r1, #1
    strb r1, [r0, #0]

    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
rtc_flags:
.byte 0            // Flag fuer Sekunde
.byte 0            // Flag fuer Alarm

one_hour_mode_txt: .asciz "\n1-Stunden-Modus"
twenty_four_hour_mode_txt: .asciz "\n24-Stunden-Modus"
preset_txt: .asciz "\nUhr vorgestellt"
reset_txt: .asciz "\nUhr zurueckgesetzt"
alarm_txt: .asciz "\nEndzeitpunkt erreicht"
stop_display_txt: .asciz "\nAnzeige aus"
start_display_txt: .asciz "\nAnzeige an"
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_NEWLINE, 0x0a
.equ ASCII_COLON,   0x3a
.equ ASCII_D,       0x64
.equ ASCII_T,       0x74

.equ SECONDS_PER_DAY, 86400
.equ SECONDS_PER_HOUR, 3600
.equ SECONDS_PER_MINUTE, 60
.equ MINUTES_PER_HOUR,   60
.equ DAYS_PER_WEEK,       7
.equ MONTHS_PER_YEAR,    12

// SIM Register
__BBREG SIM_SCGC5_PORTA, 0x40048038,  9
__BBREG SIM_SCGC6_PIT,   0x4004803c, 23
__BBREG SIM_SCGC6_RTC,   0x4004803c, 29

// DCF77 Port (PTA6)
// LED blau (PTA10)
.equ PORTA_PCR6,  0x40049018
.equ PORTA_PCR10, 0x40049028

.equ LED_PORT_FLAGS,   0x00000120 // MUX=1 (GPIO), ODE=1 (open-drain)
.equ DCF77_PORT_FLAGS, 0x00000100 // MUX=1 (GPIO)

// Bitbandadressen fuer GPIO A Register
__BBREG GPIOA_PDOR_0, 0x400ff000, 0
__BBREG GPIOA_PSOR_0, 0x400ff004, 0
__BBREG GPIOA_PCOR_0, 0x400ff008, 0
__BBREG GPIOA_PDDR_0, 0x400ff014, 0

// Addressoffset fuer Bitbandadresse ausgehend von GPIOA_*_0
.equ DCF77_PORTA_BBOFFSET, 24 //  6 * 4 (jedes Bit wird auf 32-bit gemappt)
.equ LED_PORTA_BBOFFSET,   40 // 10 * 4 (jedes Bit wird auf 32-bit gemappt)

// PIT Register
// Basisadresse
.equ PIT_BASE,   0x40037000
// Offsets der Register zur Basisadresse
.equ PIT_MCR,    0x000
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1,  0x11c

// PIT1 - Vektor 85 (IRQ 69)
// -> Offset fuer Vektortabelle 85 * 4 = 0x154
// zugehoerig NVIC_*2, Bit 5
.equ PIT1_IRQ_OFFSET, 0x154
.equ PIT1_NVIC_MASK, 0x20

.equ PIT_MCR_VAL,          0x00 // MDIS=0, FRZ=0
.equ PIT_TCTRL1_VAL_STOP,  0x02 // CHN=0, TIE=1, TEN=0
.equ PIT_TCTRL1_VAL_START, 0x03 // CHN=0, TIE=1, TEN=1
.equ PIT1_PERIOD_100MS, 2499999 // 100ms -> 2.500.000 clocks @ 25MHz
.equ PIT1_PERIOD_200MS, 4999999 // 200ms -> 5.000.000 clocks @ 25MHz

// RTC Register
// Basisadresse
.equ RTC_BASE, 0x4003d000
// Offsets der Register zur Basisadresse
.equ RTC_TSR, 0x000
.equ RTC_TPR, 0x004
.equ RTC_TAR, 0x008
.equ RTC_TCR, 0x00c
.equ RTC_CR,  0x010
.equ RTC_SR,  0x014
.equ RTC_LR,  0x018
.equ RTC_IER, 0x01c
.equ RTC_WAR, 0x800
.equ RTC_RAR, 0x804

__BBREG RTC_CR_SWR, RTC_BASE + RTC_CR, 0
__BBREG RTC_SR_TCE, RTC_BASE + RTC_SR, 4

// RTC Seconds IRQ - Vektor 83 (IRQ 67)
// -> Offset fuer Vektortabelle 83 * 4 = 0x14c
// zugehoerig NVIC_*2, Bit 3
.equ RTC_SECONDS_IRQ_OFFSET, 0x14c
.equ RTC_SECONDS_NVIC_MASK, 0x08

.equ RTC_CR_VAL, 0x00000100 // SWR = 0 (No reset)
                            // WPE = 0 (Wakeup pin disabled)
                            // SUP = 0 (Non-supervisor mode write accesses are forbidden)
                            // UM = 0 (Registers cannot be written when locked)
                            // OSCE = 1 (Oscillator enabled)
                            // CLKO = 0 (Clock is not output to other peripherals)
                            // Keine Kapazitaet nach Aufgabenblatt
                            // SC16P = 0
                            // SC8P = 0
                            // SC4P = 0
                            // SC2P = 0

.equ RTC_IER_VAL, 0x00000010 // TIE = 0 (Time Invalid Interrupt disabled)
                             // TOIE = 0 (Time Overflow Interrupt disabled)
                             // TAIE = 0 (Time Alarm Interrupt enabled)
                             // TSIE = 1 (Time Seconds Interrupt disabled)
                             // WPON = 0 (Wake-up pin no effect) 

// Startzeit tStart = 1s in Abschnitt 6.3.3.2 im Kinetis Datenblatt fuer den RTC Oszillator
// Geprueft mit pit3 aus V1, Verzoegerung 25.165.824 Takte = ~1s @ 25MHz 
.equ RTC_OSC_STARTUP_DELAY, 0x800000

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// NVIC Register
.equ NVIC_ISER2, 0xe000e108
.equ NVIC_ICPR2, 0xe000e288

.equ NVIC_IxxR2_MASK, RTC_SECONDS_NVIC_MASK | PIT1_NVIC_MASK

// Alle nicht dynamischen Bits des DCF77-Codes, also alle ausser die fuer Minuten, Stunden, Tag, Wochentag, Monat und Jahr, werden hier festgelegt.
.equ DCF77_RESET_LOW,  0x00120000 // Bits 0-31 der DCF77-Sequenz
                                  // Bit 17 + 18: fest auf 10 fuer CEST
                                  // Bit 20: Start der Zeit. Immer 1.
.equ DCF77_RESET_HIGH, 0x00000000 // Bits 32-59 der DCF77-Sequenz

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    //
    // Ports konfigurieren
    //

    // Takt fuer Ports einschalten
    mov r2, #1
    ldr r0, =SIM_SCGC5_PORTA
    str r2, [r0]

    // Ports konfigurieren
    ldr r1, =LED_PORT_FLAGS
    ldr r0, =PORTA_PCR10
    str r1, [r0]
    ldr r1, =DCF77_PORT_FLAGS
    ldr r0, =PORTA_PCR6
    str r1, [r0]

    // Blaue LED und DCF77 Port als Ausgang konfigurieren
    ldr r0, =GPIOA_PDDR_0
    str r2, [r0, #LED_PORTA_BBOFFSET]
    str r2, [r0, #DCF77_PORTA_BBOFFSET]

    //
    // PIT
    //

    // Takt fuer PIT aktivieren
    ldr r0, =SIM_SCGC6_PIT
    str r2, [r0]

    // Alle PITs aktivieren und im Debug-Modus laufen lassen
    ldr r0, =PIT_BASE
    mov r1, #PIT_MCR_VAL
    str r1, [r0, #PIT_MCR]

    // Interrupt von PIT1 aktivieren
    mov r1, #PIT_TCTRL1_VAL_STOP
    str r1, [r0, #PIT_TCTRL1]

    //
    // RTC
    //

    // Takt fuer RTC einschalten
    ldr r0, =SIM_SCGC6_RTC
    str r2, [r0]

    // RTC zuruecksetzen, setzt alle RTC Register auf Resetwert bis auf RTC_WAR und RTC_RAR
    // RTC_WAR und RTC_RAR werden benutzt um Schreib- bzw. Lesezugriff auf die RTC-Register zu verhindern
    // Diese werden nur beim System-Reset auf 1 (Zugriff erlaubt) gesetzt, waeren sie an dieser Stelle nicht mehr 1,
    // koennte dies an dieser Stelle auch nicht mehr geaendert werden. Somit muss ihr Wert hier auch nicht veraendert werden,
    // da alle Zugriffe erlaubt sein sollen.
    ldr r0, =RTC_CR_SWR
    str r2, [r0]
    mov r1, #0
    str r1, [r0]

    // RTC Oszillator starten
    ldr r4, =RTC_BASE
    mov r0, #RTC_CR_VAL
    str r0, [r4, #RTC_CR]

    // Warten bis RTC Oszillator gestartet ist
    mov r0, #RTC_OSC_STARTUP_DELAY
wait_osc_startup:
    subs r0, r0, #1
    bne wait_osc_startup

    // RTC_TCR durch Reset auf 0, kann auf 0 bleiben, keine Feinabstimmung noetig bzw. moeglich (wuerde GPS oder aehnliche Uhr mit hoeherer Genauigkeit als Quarz benoetigen)
    // RTC_LR kann auf Resetwert bleiben. Es sollen keine Register gesperrt werden.

    // Sekundeninterrupt einschalten
    mov r0, #RTC_IER_VAL
    str r0, [r4, #RTC_IER]

    // Datum abfragen und damit Datumsregister initialisieren
    bl input_date
    mov r7, r0

    // Aktuelle Zeit abfragen und RTC_TSR entsprechend setzen
    // RTC_TPR bereits durch Reset auf 0 gesetzt
    bl input_time
    str r0, [r4, #RTC_TSR]

    // RTC starten
    ldr r0, =RTC_SR_TCE
    mov r2, #1
    str r2, [r0]

    //
    // NVIC
    //

    // Interruptvektor zu Sekundeninterrupt/PIT1 setzen
    ldr r3, =SCR_VTOR
    ldr r3, [r3]
    ldr r0, =rtc_seconds_isr
    str r0, [r3, #RTC_SECONDS_IRQ_OFFSET]
    ldr r1, =pit1_isr
    str r1, [r3, #PIT1_IRQ_OFFSET]

    ldr r0, =NVIC_IxxR2_MASK

    // Ausstehende Interrupts von Sekundeninterrupt loeschen
    ldr r3, =NVIC_ICPR2
    str r0, [r3]

    // Interrupt von Sekundeninterrupt im NVIC aktivieren
    ldr r3, =NVIC_ISER2
    str r0, [r3]

    ldr r0, =instructions_txt
    bl uart_putString

    // Beim Starten wird RTC initialisert, dabei wird kein Interrupt erzeugt, deswegen beim ersten Mal Abfrage des rtc_flag hier ueberspringen
    // und direkt mit erster DCF77-Sequenz starten
    b skip_rtc_flag_check

main_loop:
    // Pruefen auf Zeichen vom UART
    bl uart_charPresent
    cmp r0, #0
    beq handle_input_done

    bl uart_getChar
    cmp r0, #ASCII_D
    beq handle_d
    cmp r0, #ASCII_T
    beq handle_t
    b handle_input_done

handle_d:
    // Datum abfragen und damit Datumsregister aktualsieren
    bl input_date
    mov r7, r0
    b handle_input_done

handle_t:
    // Zeit abfragen
    bl input_time

    // Aktuelle Zeit (RTC_TSR) auf eingegebene Zeit setzen. Dazu RTC kurz deaktivieren und nach dem Schreiben von RTC_TSR wieder aktivieren
    ldr r1, =RTC_SR_TCE
    mov r2, #0
    str r2, [r1]

    str r0, [r4, #RTC_TSR]

    mov r2, #1
    str r2, [r1]

handle_input_done:
    // Ist eine Sekunde vorbei?
    ldr r1, =rtc_flag
    ldrb r0, [r1]
    cmp r0, #0
    beq main_loop

    // Sekunden Flag zuruecksetzen
    mov r0, #0
    strb r0, [r1]

skip_rtc_flag_check:
    // Uhrzeit aus RTC laden
    ldr r8, [r4, #RTC_TSR]

    // Ein Tag vorbei?
    ldr r0, =SECONDS_PER_DAY
    cmp r8, r0
    blt skip_date_increment

    // Aktuelle Zeit (RTC_TSR) wieder auf 0 zuruecksetzen. Dazu RTC kurz deaktivieren und nach dem Schreiben von RTC_TSR wieder aktivieren
    ldr r1, =RTC_SR_TCE
    mov r8, #0
    str r8, [r1]

    str r8, [r4, #RTC_TSR]

    mov r2, #1
    str r2, [r1]

    // Wochentag aus Datumsregister extrahieren
    ubfx r0, r7, #0, #8

    // Auf naechsten Wochentag wechseln
    add r0, r0, #1
    cmp r0, #DAYS_PER_WEEK
    it gt
    movgt r0, #1

    // Wochentag im Datumsregister aktualisieren
    bfi r7, r0, #0, #8

    // Tag aus Datumsregister extrahieren
    ubfx r0, r7, #8, #8

    // Monat aus Datumsregister extrahieren
    ubfx r1, r7, #16, #8

    // Zu naechstem Tag wechseln
    add r0, r0, #1
    bfi r7, r0, #8, #8

    // Noch nicht letzter Tag des Monats vorbei? Dann nur Tag erhoehen und fertig
    ldr r2, =days_per_month
    ldrb r2, [r2, r1]

    cmp r0, r2 // Noch nicht letzter Tag im Monat vorbei?
    ble skip_date_increment

    // Monat vorbei -> erster Tag des Monats
    mov r0, #1
    bfi r7, r0, #8, #8

    // Monate erhoehen, falls es einen Uebertrag aus den Tagen gibt
    add r1, r1, #1
    bfi r7, r1, #16, #8

    cmp r1, #MONTHS_PER_YEAR // Noch nicht letzter Monat des Jahres vorbei?
    ble skip_date_increment

    // Jahr vorbei -> Januar
    mov r1, #1
    bfi r7, r1, #16, #8

    // Jahr aus Datumsregister extrahieren
    ubfx r0, r7, #24, #8
    add r0, r0, #1
    bfi r7, r0, #24, #8

skip_date_increment:
    // Stunden bestimmen
    mov r1, #SECONDS_PER_HOUR
    udiv r9, r8, r1
    mls r8, r9, r1, r8

    // Minuten und Sekunden bestimmen
    mov r1, #SECONDS_PER_MINUTE
    udiv r10, r8, r1
    mls r8, r10, r1, r8

    // r9 = Stunden, r10 = Minuten, r8 = Sekunden

    cmp r8, #0
    bne skip_dcf77_encoding

    //
    // DCF77-Code erzeugen
    //

    mov r0, #ASCII_NEWLINE
    bl uart_putChar

    // DCF77-Code zuruecksetzen auf Startwert
    mov r5, #DCF77_RESET_LOW
    mov r6, #DCF77_RESET_HIGH

    //
    // Stunden einfuegen
    //

    // Zehner von Stunden bestimmen und einfuegen
    mov r0, #10
    udiv r2, r9, r0
    bfi r6, r2, #1, #2

    // Einer von Stunde bestimmen und einfuegen
    mls r11, r0, r2, r9
    bfi r5, r11, #29, #3
    orr r6, r6, r11, lsr #3

    // Paritaet der Stundenbits bestimmen und einfuegen
    eor r0, r2, r11
    eor r0, r0, r0, lsr #2
    eor r0, r0, r0, lsr #1
    bfi r6, r0, #3, #1

    // Stunden auf Terminal ausgeben
    mov r0, r2
    bl uart_putByteBase10
    mov r0, r11
    bl uart_putByteBase10

    mov r0, #ASCII_COLON
    bl uart_putChar

    //
    // Minute einfuegen
    //

    // Zehner von Minuten bestimmen und einfuegen
    mov r0, #10
    udiv r2, r10, r0
    bfi r5, r2, #25, #3

    // Einer von Minute bestimmen und einfuegen
    mls r11, r0, r2, r10
    bfi r5, r11, #21, #4

    // Paritaet der Minutenbits bestimmen und einfuegen
    eor r0, r2, r11
    eor r0, r0, r0, lsr #2
    eor r0, r0, r0, lsr #1
    bfi r5, r0, #28, #1

    // Minuten auf Terminal ausgeben
    mov r0, r2
    bl uart_putByteBase10
    mov r0, r11
    bl uart_putByteBase10

    mov r0, #ASCII_COLON
    bl uart_putChar

    // Sekunden auf Terminal ausgeben (immer 0 wenn DCF77-Code erzeugt wird)
    mov r0, #0
    bl uart_putByteBase10
    mov r0, #0
    bl uart_putByteBase10

    // Tag aus Datumsregister extrahieren
    ubfx r9, r7, #8, #8

    // Zehner von Tag bestimmen und einfuegen
    mov r0, #10
    udiv r2, r9, r0
    bfi r6, r2, #8, #2

    // Einer von Tag bestimmen und einfuegen
    mls r11, r0, r2, r9
    bfi r6, r11, #4, #4

    // Wochentag aus Datumsregister extrahieren
    ubfx r9, r7, #0, #8
    bfi r6, r9, #10, #3

    // Monat aus Datumsregister extrahieren
    ubfx r9, r7, #16, #8

    // Zehner vom Monat bestimmen und einfuegen
    mov r0, #10
    udiv r2, r9, r0
    bfi r6, r2, #17, #1

    // Einer vom Monat bestimmen und einfuegen
    mls r11, r0, r2, r9
    bfi r6, r11, #13, #4

    // Jahr aus Datumsregister extrahieren
    ubfx r9, r7, #24, #8

    // Zehner vom Jahr bestimmen und einfuegen
    mov r0, #10
    udiv r2, r9, r0
    bfi r6, r2, #22, #4

    // Einer vom Jahr bestimmen und einfuegen
    mls r11, r0, r2, r9
    bfi r6, r11, #18, #4

    // Alle Datumsbits extrahieren, Paritaet bestimmen und einfuegen
    ubfx r0, r6, #4, #22
    eor r0, r0, r0, lsr #16
    eor r0, r0, r0, lsr #8
    eor r0, r0, r0, lsr #4
    eor r0, r0, r0, lsr #2
    eor r0, r0, r0, lsr #1
    bfi r6, r0, #26, #1

    // DCF77-Code auf Terminal ausgeben
    ldr r0, =dcf_code_txt
    bl uart_putString

    // Die ersten 32 bit ausgeben
    mov r9, #1              // Bit-Maske zur Abfrage, starten mit Bit 0
loop_print_low_bits:
    // Bit entsprechend der Maske ausgeben
    ands r0, r9, r5
    it ne
    movne r0, #1
    bl uart_putByteBase10

    // Maske verschieben fuer das naechste Bit
    lsls r9, r9, #1
    bcc loop_print_low_bits

    // Die zweiten 28 bit ausgeben
    mov r9, #1              // Bit-Maske zur Abfrage, starten mit Bit 0
loop_print_high_bits:
    // Bit entsprechend der Maske ausgeben
    ands r0, r9, r6
    it ne
    movne r0, #1
    bl uart_putByteBase10

    // Maske verschieben fuer das naechste Bit
    lsl r9, r9, #1
    lsls r0, r9, #4           // Stoppen nach 28 Bit
    bcc loop_print_high_bits

skip_dcf77_encoding:
    // Fuer Sekunde 59 kein Puls erzeugen
    cmp r8, #59
    beq main_loop

    // Maske erzeugen um passendes DCF Bit auszulesen
    and r1, r8, #31
    mov r2, #1
    lsl r0, r2, r1

    // Bit lesen aus DCF low (r5) oder high (r6) Register
    cmp r8, #32
    ite lt
    andlt r0, r5, r0
    andge r0, r6, r0

    // Bei '0' 100ms Puls erzeugen, ansonsten 200ms Puls
    cmp r0, #0
    ite eq
    ldreq r0, =PIT1_PERIOD_100MS
    ldrne r0, =PIT1_PERIOD_200MS

    // PIT1 zur Pulserzeugung konfigurieren
    ldr r3, =PIT_BASE
    str r0, [r3, #PIT_LDVAL1]

    // DCF77 Port auf low und LED auf low (an) setzen
    ldr r1, =GPIOA_PCOR_0
    str r2, [r1, #LED_PORTA_BBOFFSET]
    str r2, [r1, #DCF77_PORTA_BBOFFSET]

    // PIT1 starten
    mov r0, #PIT_TCTRL1_VAL_START
    str r0, [r3, #PIT_TCTRL1]

    b main_loop

// input_date fragt auf dem Terminal ein Datum ab
// Rueckgabewert 32-bit Wort 0xYYMMDDww mit YY=Jahr, MM=Monat, DD=Tag und ww=Wochentag mit 01=Montag und 07=Sonntag
.thumb_func
input_date:
    push {r4, lr}

    // Tag abfragen
    ldr r0, =str_input_day
    bl uart_putString
    bl uart_getByteBase10
    bfi r4, r0, #8, #8
    bl uart_putByteBase10

    // Wochentag abfragen
    ldr r0, =str_input_weekday
    bl uart_putString
    bl uart_getByteBase10
    bfi r4, r0, #0, #8
    bl uart_putByteBase10

    // Monat abfragen
    ldr r0, =str_input_month
    bl uart_putString
    bl uart_getByteBase10
    bfi r4, r0, #16, #8
    bl uart_putByteBase10

    // Jahr abfragen
    ldr r0, =str_input_year
    bl uart_putString
    bl uart_getByteBase10
    bfi r4, r0, #24, #8
    bl uart_putByteBase10

    mov r0, r4
    pop {r4, pc}

// input_time fragt auf dem Terminal eine Zeit ab
// Rueckgabewert: Zeit in Sekunden
.thumb_func
input_time:
    push {r4, lr}

    // Stunden abfragen
    ldr r0, =str_input_hours
    bl uart_putString
    bl uart_getByteBase10
    mov r4, r0
    bl uart_putByteBase10

    // Minuten abfragen
    ldr r0, =str_input_minutes
    bl uart_putString
    bl uart_getByteBase10
    mov r1, #MINUTES_PER_HOUR
    mla r4, r4, r1, r0
    bl uart_putByteBase10

    // Sekunden abfragen
    ldr r0, =str_input_seconds
    bl uart_putString
    bl uart_getByteBase10
    mov r1, #SECONDS_PER_MINUTE
    mla r4, r4, r1, r0
    bl uart_putByteBase10

    mov r0, r4
    pop {r4, pc}

// Interrupt Service Routine fuer PIT1
.thumb_func
pit1_isr:
    ldr r0, =PIT_BASE

    // PIT1 stoppen
    mov r1, #PIT_TCTRL1_VAL_STOP
    str r1, [r0, #PIT_TCTRL1]

    // Interrupt Flag von PIT1 loeschen
    mov r1, #1
    str r1, [r0, #PIT_TFLG1]

    // DCF77 Port auf high und LED auf high (aus) setzen
    ldr r0, =GPIOA_PSOR_0
    str r1, [r0, #LED_PORTA_BBOFFSET]
    str r1, [r0, #DCF77_PORTA_BBOFFSET]

    bx lr

// Interrupt Service Routine fuer RTC Sekundeninterrupt
.thumb_func
rtc_seconds_isr:
    // Sekunde vorbei, zur Verarbeitung in Hauptschleife Flag setzen
    ldr r0, =rtc_flag
    mov r1, #1
    strb r1, [r0]

    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
rtc_flag:
.byte 0

// Tage im Monat
days_per_month:
.byte  0  // kein Monat 0
.byte 31  // Januar
.byte 28  // Februar
.byte 31  // Maerz
.byte 30  // April
.byte 31  // Mai
.byte 30  // Juni
.byte 31  // Juli
.byte 31  // August
.byte 30  // September
.byte 31  // Oktober
.byte 30  // November
.byte 31  // Dezember

instructions_txt: .asciz "\n'd' senden zum Aendern des Datums\n't' senden zum Aendern der Zeit"
dcf_code_txt: .asciz "\nDCF77-Code: "
str_input_day: .asciz "\nTag eingeben (dd): "
str_input_weekday: .asciz "\nWochentag eingeben (ww, 01=Mo, 07=So): "
str_input_month: .asciz "\nMonat eingeben (mm): "
str_input_year: .asciz "\nJahr eingeben (jj): "
str_input_hours: .asciz "\nStunde eingeben (hh): "
str_input_minutes: .asciz "\nMinuten eingeben (mm): "
str_input_seconds: .asciz "\nSekunden eingeben (ss): "
// Include-Dateien
.include "k1514.inc"            // Praktikumsspezifische Definitionen
.include "lib_pit.inc"          // Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"         // Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text                           // hier beginnt ein Code-Segment
.align  2                       // Ausrichtung an eine gerade Adresse
.global main                    // "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ ASCII_PERCENT, 0x25

// SIM Register
__BBREG SIM_SCGC5_PORTA, 0x40048038,  9
__BBREG SIM_SCGC6_FTM0,  0x4004803c, 24

// PTA6 / FTM0_CH3
.equ PORTA_PCR6, 0x40049018
.equ PTA6_PORT_FLAGS, 0x00000300 // MUX=3 (FTM0_CH3)

// FTM Register
// Basisadresse
.equ FTM0_BASE, 0x40038000
// Offsets der Register zur Basisadresse
.equ FTMx_SC,       0x00
.equ FTMx_CNT,      0x04
.equ FTMx_MOD,      0x08
.equ FTMx_C0SC,     0x0c
.equ FTMx_C0V,      0x10
.equ FTMx_C1SC,     0x14
.equ FTMx_C1V,      0x18
.equ FTMx_C2SC,     0x1c
.equ FTMx_C2V,      0x20
.equ FTMx_C3SC,     0x24
.equ FTMx_C3V,      0x28
.equ FTMx_C4SC,     0x2c
.equ FTMx_C4V,      0x30
.equ FTMx_C5SC,     0x34
.equ FTMx_C5V,      0x38
.equ FTMx_C6SC,     0x3c
.equ FTMx_C6V,      0x40
.equ FTMx_C7SC,     0x44
.equ FTMx_C7V,      0x48
.equ FTMx_CNTIN,    0x4c
.equ FTMx_STATUS,   0x50
.equ FTMx_MODE,     0x54
.equ FTMx_SYNC,     0x58
.equ FTMx_OUTINIT,  0x5c
.equ FTMx_OUTMASK,  0x60
.equ FTMx_COMBINE,  0x64
.equ FTMx_DEADTIME, 0x68
.equ FTMx_EXTTRIG,  0x6c
.equ FTMx_POL,      0x70
.equ FTMx_FMS,      0x74
.equ FTMx_FILTER,   0x78
.equ FTMx_FLTCTRL,  0x7c
.equ FTMx_QDCTRL,   0x80
.equ FTMx_CONF,     0x84
.equ FTMx_FLTPOL,   0x88
.equ FTMx_SYNCONF,  0x8c
.equ FTMx_INVCTRL,  0x90
.equ FTMx_SWOCTRL,  0x94
.equ FTMx_PWMLOAD,  0x98

__BBREG FTM0_SC_TOF, FTM0_BASE + FTMx_SC, 7
__BBREG FTM0_C3SC_CHF, FTM0_BASE + FTMx_C3SC, 7

// FTM0 IRQ - Vektor 78 (IRQ 62)
// -> Offset fuer Vektortabelle 78 * 4 = 0x0138
// zugehoerig NVIC_*1, Bit 30
.equ FTM0_IRQ_OFFSET, 0x00000138
.equ FTM0_NVIC_MASK,  0x40000000

.equ FTM0_SC_VAL,             0x00000048 // PS=0 (divide by 1)
                                         // CLKS=1 (System clock)
                                         // CPWMS=0 (edge-aligned PWM)
                                         // TOIE=1 (Timer Overflow Interrupt enabled)

.equ FTM0_MOD_VAL,                 24999 // Fuer 1kHz PWM 25000 Clks @ 25MHz

.equ FTM0_MODE_VAL_UNPROTECT, 0x00000001 // FTMEN=0 (Only TPM-compatible registers)
                                         // INIT=0
                                         // WPDIS=1 (Disable write protection)
                                         // PWMSYNC=0
                                         // CAPTEST=0 (Capture test mode is disabled)
                                         // FAULTM=0 (Fault control is disabled for all channels)
                                         // FAULTIE=0 (Fault control interrupt is disabled)

.equ FTM0_MODE_VAL,           0x00000004 // FTMEN=0 (Only TPM-compatible registers)
                                         // INIT=0
                                         // WPDIS=0 (No effect)
                                         // PWMSYNC=0
                                         // CAPTEST=0 (Capture test mode is disabled)
                                         // FAULTM=0 (Fault control is disabled for all channels)
                                         // FAULTIE=0 (Fault control interrupt is disabled)

// Kanalkonfiguration fuer positive Pulse, Ablenkung aus der Ruhelage mit niedrigem Potential
.equ FTM0_C3SC_POS,           0x00000068 // DMA=0 (Disable DMA transfers)
                                         // Edge-aligned PWM:
                                         //   ELSA=0
                                         //   ELSB=1
                                         //   MSA=0
                                         //   MSB=1
                                         // CHIE=1 (Channel Interrupt disabled)

// Kanalkonfiguration fuer negative Pulse, Ablenkung aus der Ruhelage mit hohem Potential
.equ FTM0_C3SC_NEG,           0x0000006C // DMA=0 (Disable DMA transfers)
                                         // Edge-aligned PWM:
                                         //   ELSA=1
                                         //   ELSB=1
                                         //   MSA=0
                                         //   MSB=1
                                         // CHIE=1 (Channel Interrupt disabled)

.equ PWM_MIN_PULSE_WIDTH,  1250 // 5% von einer Periode (25000 Takte)
.equ PWM_PULSE_INCREMENTS, 2500 // verstellbar in 10% Schritten von einer Periode (25000 Takte)

// SCR Register
.equ SCR_VTOR, 0xe000ed08

// NVIC Register
.equ NVIC_ISER1, 0xe000e104
.equ NVIC_ICPR1, 0xe000e284

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen,
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */
main:
    bl uart_init

    //
    // Ports konfigurieren
    //

    // Takt fuer Ports einschalten
    mov r2, #1
    ldr r0, =SIM_SCGC5_PORTA
    str r2, [r0]

    // Ports konfigurieren
    ldr r1, =PTA6_PORT_FLAGS
    ldr r0, =PORTA_PCR6
    str r1, [r0]

    //
    // FTM
    //

    // Takt fuer FTM0 einschalten
    ldr r0, =SIM_SCGC6_FTM0
    str r2, [r0]

    // Schreibschutz ausschalten
    // "WPDIS is set when WPEN bit is read as a 1 and then 1 is written to WPDIS."
    // "WPEN is cleared when WPEN bit is read as a 1 and then 1 is written to WPDIS."
    ldr r0, =FTM0_BASE
    ldr r1, [r0, #FTMx_FMS]
    mov r1, #FTM0_MODE_VAL_UNPROTECT
    str r1, [r0, #FTMx_MODE]

    // Nur TPM-kompatible Register (FTM0_SC - FTM0_C7V) nutzen (FTMEN=0), erweiterte Funktionalitaet wird nicht benoetigt
    mov r1, #FTM0_MODE_VAL
    str r1, [r0, #FTMx_MODE]

    // Periode auf 1kHz stellen
    ldr r1, =FTM0_MOD_VAL
    str r1, [r0, #FTMx_MOD]

    // FTM Kanal 3 fuer PWM Pulse mit positiver Polaritaet konfigurieren
    mov r1, #FTM0_C3SC_POS
    str r1, [r0, #FTMx_C3SC]

    // PWM Pulsweite auf 5% initialisieren
    ldr r1, =PWM_MIN_PULSE_WIDTH
    str r1, [r0, #FTMx_C3V]

    // Timer starten
    mov r1, #FTM0_SC_VAL
    str r1, [r0, #FTMx_SC]

    //
    // NVIC
    //

    // Interruptvektor zu FTM0 setzen
    ldr r3, =SCR_VTOR
    ldr r3, [r3]
    ldr r0, =ftm0_isr
    str r0, [r3, #FTM0_IRQ_OFFSET]

    ldr r0, =FTM0_NVIC_MASK

    // Ausstehende Interrupts von FTM0 loeschen
    ldr r3, =NVIC_ICPR1
    str r0, [r3]

    // Interrupt von FTM0 im NVIC aktivieren
    ldr r3, =NVIC_ISER1
    str r0, [r3]

    //
    // Register fuer Hauptschleife initialisieren
    //
    ldr r4, =pulse_width
    ldr r5, =pulse_polarity

    // Prompt ausgeben
    ldr r0, =prompt_txt
    bl uart_putString

main_loop:
    // Pruefen auf Zeichen vom UART
    bl uart_charPresent
    cmp r0, #0
    bne main_loop

    // Zeichen laden und echoen
    bl uart_getChar
    mov r8, r0
    bl uart_putChar

    cmp r8, #0x2b
    beq handle_plus
    cmp r8, #0x2d
    beq handle_minus
    subs r7, r8, #0x30
    blt handle_input_done
    cmp r8, #0x39
    bgt handle_input_done

    // '0' - '9' empfangen
    // Speichere neue Pulsweite
    strb r7, [r4]

    // Pulsweite auf Terminal ausgeben
    ldr r0, =pulse_width_txt
    bl uart_putString

    cbz r7, skip_tens_if_0
    mov r0, r7
    bl uart_putByteBase10

skip_tens_if_0:
    // Einerstelle immer 5
    mov r0, #5
    bl uart_putByteBase10
    mov r0, #ASCII_PERCENT
    bl uart_putChar

    b handle_input_done

handle_plus:
    // Aendere Polaritaet zu positiv
    mov r0, #0
    strb r0, [r5]

    ldr r0, =pol_pos_txt
    bl uart_putString

    b handle_input_done

handle_minus:
    // Aendere Polaritaet zu negativ
    mov r0, #1
    strb r0, [r5]

    ldr r0, =pol_neg_txt
    bl uart_putString

handle_input_done:
    // Neuen Prompt ausgeben
    ldr r0, =prompt_txt
    bl uart_putString

    b main_loop

// Interrupt Service Routine fuer FTM Interrupt
.thumb_func
ftm0_isr:
    // Pruefen, ob es ein Timer Overflow Interrupt ist
    ldr r0, =FTM0_SC_TOF
    ldr r1, [r0]
    cbz r1, no_timer_overflow

    // Timer Overflow Interrupt zuruecksetzen
    mov r1, #0
    str r1, [r0]

    // Polaritaet des Pulses aktualisieren
    ldr r0, =FTM0_BASE
    ldr r1, =pulse_polarity
    ldrb r1, [r1]
    cmp r1, #0
    ite eq
    moveq r2, #FTM0_C3SC_POS
    movne r2, #FTM0_C3SC_NEG
    str r2, [r0, #FTMx_C3SC]

no_timer_overflow:
    // Pruefen, ob es ein Channel Interrupt ist
    ldr r0, =FTM0_C3SC_CHF
    ldr r1, [r0]
    cbz r1, no_channel_irq

    // Channel Interrupt zuruecksetzen
    mov r1, #0
    str r1, [r0]

    // Pulsweite aktualisieren
    ldr r0, =FTM0_BASE
    ldr r1, =pulse_width
    ldrb r1, [r1]
    ldr r3, =PWM_MIN_PULSE_WIDTH
    ldr r2, =PWM_PULSE_INCREMENTS
    mla r1, r1, r2, r3
    str r1, [r0, #FTMx_C3V]

no_channel_irq:
    bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
pulse_width: .byte 0
pulse_polarity: .byte 0

prompt_txt: .asciz "\n> "
pol_pos_txt: .asciz "\nErzeuge positive Pulse"
pol_neg_txt: .asciz "\nErzeuge negative Pulse"
pulse_width_txt: .asciz "\nPulsbreite "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ COUNTER, 0x10
.equ OVH, 0x0B					// Overhead-Konstante

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init				// PIT initialisieren: startet Zählen bei 0xFFFFFFFF
	
	// Bestimmung des Overheads (als Konstante deklariert)
	// bl pit3_getval
	// mov r4, r0
	// bl pit3_getval
	// sub r0, r4, r0
	// bl uart_putByte

	// Einlesen von 16 Bytes
	mov r4, #COUNTER			// Zaehler laden
	ldr r5, =bytearray			// Adresse des Arrays
	ldr r0, =str_eingabe		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	
loop_eingabe:
	ldr r0, =str_prompt			// Zeiger auf Prompt laden
	bl uart_putString			// Prompt ausgeben
	bl uart_getByte				// ein Byte einlesen
	strb r0, [r5], #1			// im Array ablegen und Adresse in R5 um eins erhöhen
	bl uart_putByte				// das Byte ausgeben
	subs r4, r4, #1				// Zaehler dekrementieren
	bne loop_eingabe			// solange Zaehler noch nicht null

	// Maximumsbestimmung
	ldr r0, =str_startsuche		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	mov r9, #0					// Maximum mit null initialisieren
	mov r4, #COUNTER
	
	// Abfragen des Timer-Wertes vor Maximum-Suche
	bl pit3_getval				// Feststellug des aktuellen Timer-Wertes
	mov r7, r0					// Time-Byte speichern
	
loop_maximum:
	ldrb r0, [r5, #-1]!			// Byte aus dem Array holen, vorher Adresse im R5 dekrementieren
	cmp r0, r9					// mit bisherigem Maximum vergleichen
	it hi						// wenn es groesser ist (unsigned)
	movhi r9, r0				// wird das bisherige Maximum ersetzt
	subs r4, r4, #1				// Zaehler dekrementieren
	bne loop_maximum			// solange zaehler noch nicht null
	
	// Maximum speichern
	ldr r0, =maximum			// Adresse des Speichers fuer Maximum laden
	strb r9, [r0]				// das Maximum speichern
	
	// Abfragen des Timer-Wertes nach Maximumsbestimmung und Bestimmung der Suchzeit
	bl pit3_getval				// Feststellug des aktuellen Timer-Wertes
	sub r7, r7, r0				// Bytes subtrahieren und speichern
	sub r7, r7, #OVH			// Subtrahieren der Overhead-Takte
	
	// Ausgabe der Ergebnisse
	ldr r0, =str_endesuche		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	mov r0, r9					// Maximum in R0 kopieren
	bl uart_putByte				// und als Byte ausgeben
	
	ldr r0, =str_suchzeit		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	mov r0, r7					// Timer-Wert laden
	bl uart_putInt16			// und als vierstellige Hexadezimal-Zahl ausgeben
	
	ldr r0, =str_leerzeilen_programmneustart		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	
	b main						// Programm-Neustart

end:
	b end						// Programmende (Sprung)
	


/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
.rept COUNTER
.byte 0x00
.endr
maximum: .byte 0x0
str_prompt: .asciz "\n>0x"
str_eingabe: .asciz "Bitte 16 Bytes sukessiv eingeben!\n"
str_startsuche: .asciz "\nDurchsuchen getartet\n"
str_endesuche: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_suchzeit: .asciz "\nSuchzeit in Takten: "
str_leerzeilen_programmneustart: .asciz "\n\n"

// zu Aufgabenteil e): Die Suchzeit bleibt stets konstant bei unterschiedlichen Positionen des Maximums.
// Man könnte eigentlich annehmen, dass die Bedingung, die abfrägt, ob der aktuelle Wert größer als das bisherige Maximum ist, 
// und der "dazugehörige" movhi_Befehl zu einer unterschiedlichen zeit je nach Lage des Maximums führen sollte.
// Dies ist aber anscheinend nicht der Fall, der it-Thumb-Befehl und der davon abhängige movhi-Befehl werden immer mit konstanter Taktzahl ausgeführt.
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ SELECTOR, 0x1F				// 1F = 0011111
.equ FOUR, 0x04

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Einlesen und Korrektur der zwei Bytes
	ldr r0, =str_bit_0			// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	bl uart_getByte				// Einlesen des ersten Bytes (bestimmt Bit, das zurückgesetzt werden soll)
	
	and r0, r0, #SELECTOR 		// Beschränken des Bytes auf 5 Bits
	mov r4, r0					// Byte in Register ablegen
	bl uart_putByte				// Byte ausgeben
	
	ldr r0, =str_bit_1			// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	bl uart_getByte				// Einlesen des zweiten Bytes (bestimmt Bit, das gesetzt werden soll)
	
	and r0, r0, #0x1F 			// Beschränken des Bytes auf 5 Bits
	mov r5, r0					// Byte in Register ablegen
	bl uart_putByte				// Byte ausgeben
	
	
	// 1. ohne Nutzung des Bit Bandings: ------------------------------------------------------------------
	
	
	ldr r0, =str_ohne_bit_banding			// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	
	// Laden des Zeigers auf die Speicheradresse 0x20000000	
	ldr r9, =0x20000000				
	ldr r6, [r9]
	
	// Terminalausgabe des initialen Speicherwortes
	mov r0, r6
	bl uart_putInt32						// String ausgeben
	
	// Zurücksetzen des Bits mit dem Index des ersten Bytes:
	mov r0, #0x1							// Register 0 mit 1 initialisieren
	lsl r0, r0, r4							// Logisches Verschieben des Bits mit dem Wert 1 nach links
	bic r7, r6, r0							// Logische UND-Verknüpfung mit dem bitweisen Komplement aus vorherigem Schritt (BIC=MOVN+AND)
	str r7, [r9]							// Speichern der neuen Bits
	
	// Setzen des Bits mit dem Index des zweiten Bytes:
	mov r0, #0x1							// Register 0 mit 1 initialisieren
	lsl r0, r0, r5							// Logisches Verschieben des Bits mit dem Wert 1 nach links
	orr r8, r7, r0							// Logische ODER-Verknüpfung mit den Bits aus vorherigem Schritt
	str r8, [r9]							// Speichern der neuen Bits
	
	// Terminalausgabe des veränderten Speicherwortes:
	ldr r0, =str_ergebnis_ohne_bit_banding	// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	
	ldr r0, [r9]							// Laden des Speicherzelleninhalts 0x20000000
	bl uart_putInt32						// String ausgeben
	
	
	// 2. mit Nutzung des Bit Bandings: -------------------------------------------------------------------
	
	
	ldr r0, =str_mit_bit_banding			// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	
	// Laden des Inhalts der Speicheradresse 0x20000010	
	ldr r9, =0x20000010
	ldr r6, [r9]
	
	// Terminalausgabe des initialen Speicherwortes
	mov r0, r6
	bl uart_putInt32						// Wort ausgeben
	
	mov r11, #FOUR							// Konstante 4 in Register laden
	
	ldr r8, =0x22000200						// Zeiger auf Speicheradresse laden
	
	// Bitband-Alias-Adresse des ersten Bits berechnen: 0x22000200 + Bitnummer x 4
	mul r10, r4, r11						// Byte-Offset berechnen
	add r10, r8, r10						// Bestimmung der entsprechenden Bitband-Alias-Adresse durch Addition des Offsets
	
	// Inhalt der Adresse ausgeben, Bit zurücksetzen und Inhalt erneut ausgeben
	ldr r0, =str_zuruecksetzen_bit_1		// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	ldr r0, =str_alias_ini_bit_banding		// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	ldr r0, [r10]
	bl uart_putInt32						// Wort ausgeben
	mov r12, #0
	strb r12, [r10]							// in dieser Alias-Zieladresse Bit 0 setzen
	ldr r0, =str_alias_ergebnis_bit_banding	// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	ldr r0, [r10]
	bl uart_putInt32						// Wort ausgeben (der Alias-Speicherzelle)
	
	// Bitband-Alias-Adresse des zweiten Bits berechnen: 0x22000200 + Bitnummer x 4
	mul r10, r5, r11						// Byte-Offset berechnen
	add r10, r8, r10						// Bestimmung der entsprechenden Bitband-Alias-Adresse durch Addition des Offsets
	
	// Inhalt der Adresse ausgeben, Bit setzen und Inhalterneut ausgeben
	ldr r0, =str_setzen_bit_2				// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	ldr r0, =str_alias_ini_bit_banding		// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	ldr r0, [r10]
	bl uart_putInt32						// Wort ausgeben
	mov r12, #1
	strb r12, [r10]							// in dieser Alias-Zieladresse Bit 1 setzen
	ldr r0, =str_alias_ergebnis_bit_banding	// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	ldr r0, [r10]
	bl uart_putInt32						// Wort ausgeben (der Alias-Speicherzelle)
	
	// Terminalausgabe des veränderten Speicherwortes: ALIAS
	
	ldr r0, =str_ergebnis_mit_bit_banding	// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	
	ldr r0, [r9]							// Laden des neuen Inhalts der Speicheradresse 0x20000010
	bl uart_putInt32						// String ausgeben
	
	ldr r0, =str_leerzeilen_programmneustart		// Zeiger auf String laden
	bl uart_putString						// String ausgeben
	
	b main									// Programm-Neustart
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str_platzhalter: .asciz "PlatzhalterPlatzhalterPlatzhalter"
str_bit_0: .asciz "Nummer des 0-Bits: 0x"
str_bit_1: .asciz "\nNummer des 1-Bits: 0x"
str_zuruecksetzen_bit_1: .asciz "\nZuruecksetzen des Bits mit der ersten Nummer: "
str_setzen_bit_2: .asciz "\nSetzen des Bits mit der zweiten Nummer: "
str_ohne_bit_banding: .asciz "\n\nohne Bit-Banding:\nSpeicherzelle 0x20000000 bei Initialisierung: 0x"
str_mit_bit_banding: .asciz "\n\nmit Bit-Banding:\nSpeicherzelle 0x20000010 bei Initialisierung: 0x"
str_alias_ini_bit_banding: .asciz "\nBit-Banding-Alias-Speicherzelle bei Initialisierung: 0x"
str_ergebnis_ohne_bit_banding: .asciz "\nSpeicherzelle 0x20000000 nach (Zurueck)Setzen der Bits: 0x"
str_ergebnis_mit_bit_banding: .asciz "\nSpeicherzelle 0x20000010 nach (Zurueck)Setzen der Bits: 0x"
str_alias_ergebnis_bit_banding: .asciz "\nBit-Banding-Alias-Speicherzelle nach Bit-Veraenderung: 0x"
str_leerzeilen_programmneustart: .asciz "\n\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ COUNTER, 0x04
.equ OVH, 0x0B					// Overhead, übernommen von V1-1

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Ausgabe der Eingabeaufforderung für 2 Vektoren
	ldr r0, =str_eingabe_vektoren
	bl uart_putString
	
	// Einlesen Vektor 1
	ldr r0, =str_v1				// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	
	ldr r1, =bytevector1		// Adresse des Vektors 1
	bl eingabe_vektor			// Aufruf Unterprogramm
	
	ldr r5, =bytevector1		// Byte-Vektor erneut laden
	ldr r0, [r5]				// Eingabe-Vektor in Register 0 zur Ausgabe laden
	mov r5, r0					// Eingabe-Vektor in Register 5 sichern
	bl uart_putInt32			// Ausgabe Vektor 1

	// Einlesen Vektor 2
	ldr r0, =str_v2				// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	
	ldr r1, =bytevector2		// Adresse des Vektors 2
	bl eingabe_vektor			// Aufruf Unterprogramm
	
	ldr r6, =bytevector2		// Byte-Vektor erneut laden
	ldr r0, [r6]				// Vektor in Register 0 zur Ausgabe laden
	mov r6, r0					// Eingabe-Vektor in Register 5 sichern
	bl uart_putInt32			// Ausgabe Vektor 2

	
	// Vektorpaar min und max erzeugen ohne DSP-Befehle ------------------------------------------------------------------
	
	// Timer-Startwert bestimmen und sichern
	bl pit3_init
	bl pit3_getval
	mov r11, r0
	
	// Laden der Zeiger auf die Ergebnis-Vektoren
	ldr r7, =vektorpaar_min		// Adresse des Vektor-Minimum laden
	ldr r8, =vektorpaar_max		// Adresse des Vektor-Maximum laden
	
	// Speichern der eingegebenen Vektoren in Minimum- und Maximum-Vektor als Ausgangswerte
	str r5, [r7]
	str r6, [r8]

	mov r4, #COUNTER			// Zaehler laden
	
	// Laden der ersten Bytes des Vektor-Minimum und Maximums
	ldrb r9, [r7]
	ldrb r10, [r8]
loop_check:
	// Bytes nacheinander vergleichen und gegebenenfalls vertauschen
	cmp r9, r10		
	itt hi						// wenn Byte in r9 größer als in r10
	// "tauschen" beim Zurückspeichern der Bytes
	strbhi r10, [r7]			
	strbhi r9, [r8]
	
	ldrb r9, [r7, #1]!			// Byte aus dem Vektor holen, vorher Adresse inkrementieren
	ldrb r10, [r8, #1]!			// Byte aus dem Vektor holen, vorher Adresse inkrementieren
	
	subs r4, r4, #1				// Zaehler dekrementieren
	bne loop_check				// solange Zaehler noch nicht null
	
	// Ausführungszeit berechnen
	bl pit3_getval
	sub r11, r11, r0			// Bytes subtrahieren und speichern
	sub r11, r11, #OVH			// Overhead subtrahieren
	
	// Ausgabe der Ergebnisse
	
	ldr r7, =vektorpaar_min		// Adresse des Vektorpaar-Minimums laden
	ldr r8, =vektorpaar_max		// Adresse des Vektorpaar-Maximums laden
	
	ldr r0, =str_ohne_dsp
	bl uart_putString			// Ausgabe String "Bestimmung ohne DSP"
	
	// Ausgabe Vektor-Miniumum
	ldr r0, =str_min
	bl uart_putString
	ldr r0, [r7]
	bl uart_putInt32			
	
	// Ausgabe Vektor-Maximum
	ldr r0, =str_max
	bl uart_putString
	ldr r0, [r8]
	bl uart_putInt32			

	// Ausführungszeit ausgeben
	ldr r0, =str_ausführungszeit_ohne_dsp
	bl uart_putString
	mov r0, r11					// Timer-Wert laden
	bl uart_putByte				// und als Byte ausgeben
	

	// Vektorpaar min und max erzeugen mit DSP-Befehlen ohne Sprung- und Verzweigungsbefehle -----------------------------
	// Verwenden der Bits GE[3:0] im APSR-Register
	
	
	// Timer-Startwert bestimmen
	bl pit3_getval
	mov r11, r0
	
	// Laden der eingegebenen Vektorpaare
	ldr r7, =vektorpaar_min		// Adresse des Vektor-Minimums laden
	ldr r8, =vektorpaar_max		// Adresse des Vektor-Maximums laden
	usub8 r10, r5, r6			// unsigned Subtraktion beider Vektoren, diese setzten GE-Bits je nach Ergebnis
	sel r7, r6, r5				// Selektion der Vektor min Bytes
	sel r8, r5, r6				// Selektion der Vektor max Bytes
	
	// Ausführungszeit berechnen
	bl pit3_getval
	sub r11, r11, r0			// Bytes subtrahieren und speichern
	sub r11, r11, #OVH			// Overhead subtrahieren
	
	
	// Ausgabe der Ergebnisse
	ldr r0, =str_mit_dsp
	bl uart_putString			// Ausgabe "Bestimmung mit DSP"
	
	// Ausgabe Vektor-Minimum
	ldr r0, =str_min
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	
	// Ausgabe Vektor-Maximum
	ldr r0, =str_max
	bl uart_putString
	mov r0, r8
	bl uart_putInt32

	// Ausführungszeit ausgeben
	ldr r0, =str_ausführungszeit_mit_dsp
	bl uart_putString
	mov r0, r11					// Timer-Wert laden
	bl uart_putByte				// und als Byte ausgeben
	
	ldr r0, =str_leerzeilen_programmneustart		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	
	b main						// Programmwiederholung
	
end:
	b end

.thumb_func
eingabe_vektor:
	push {lr}
	mov r4, #COUNTER			// Zaehler laden
loop_eingabe:
	bl uart_getByte
	strb r0, [r1], #1			// im Vektor ablegen und Adresse in R5 um eins erhöhen, vorzeichenlose, ganze Zahlen als Bytes    
	subs r4, r4, #1				// Zaehler dekrementieren
	bne loop_eingabe			// solange Zaehler noch nicht null
	pop {pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
bytevector1:
.rept COUNTER
.byte 0x00
.endr
bytevector2:
.rept COUNTER
.byte 0x00
.endr
vektorpaar_min:
.rept COUNTER
.byte 0x00
.endr
vektorpaar_max:
.rept COUNTER
.byte 0x00
.endr
str_eingabe_vektoren: .asciz "Bitte geben Sie fuer die folgenden 2 Vektoren jeweils 4 Bytes ein (Vektoren werden von rechts aufgefuellt):"
str_v1: .asciz "\nv1: 0x"
str_v2: .asciz "\nv2: 0x"
str_ohne_dsp: .asciz "\nohne DSP-Befehle:"
str_mit_dsp: .asciz "\nmit DSP-Befehlen:"
str_min: .asciz "\nmin: 0x"
str_max: .asciz "\nmax: 0x"
str_ausführungszeit_ohne_dsp: .asciz "\nAusfuehrungszeit in Takten ohne DSP-Befehle: "
str_ausführungszeit_mit_dsp: .asciz "\nAusfuehrungszeit in Takten mit DSP-Befehlen: "
str_leerzeilen_programmneustart: .asciz "\n\n"

// zu Aufgabenteil e): Die Verwendung von DSP-Befehlen verringert generell die Taktzeit der Ausführung.
// In diesem Versuch liegt beispielsweise die Ausführungszeit bei einem Beispiel in Takten ohne DSP-Befehle 
// bei "2E" und mit DSP-Befehlen bei "7".
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
.equ COUNTER_ZELLE, 0x02
.equ COUNTER_ZEILE, 0x4
.equ COUNTER_SPALTE, 0x4
.equ COUNTER_MATRIX, 0x8
.equ OPERAND_A, 0xA4367C7B
.equ OPERAND_B, 0x10A78933
.equ OPERAND_C, 0xC5535F2C
.equ OPERAND_D, 0x788E84B1
.equ SAT_BITS, 0xC
.equ INCR_FOUR, 0x4
.equ EIGHT, 0x8
.equ THIRTY_TWO, 0x20

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
* zu Aufgabenteil a):
* Wie viele Multiplikationsbefehle wurden durch DSP_Befehle eingespart?
* 3 Multiplikationsbefehle, da für die Berechnung der Matrix 32 mal der DSP-Befehl verwendet wird und ein DSP-Befehl die Arbeit von 2 klassischen Multiplikationsbefehlen
* eingespart (=64)
* 
* zu Aufgabenteil d):
* QADD16 und UQADD17 sind sättigende Additionsbefehle.
* UQADD16 führt zwei nicht-vorzeichenbehaftete Additionsbefehle durch und sättigt in einem nicht-vorzeichenbehafteten Bereich.
* die (4) Ergebnisse 0xFFFF beschreiben daher die Sättigung eines Overflows, da dieser den höchsten Wert innerhalb des Sättigungsbereichs darstellt
* QADD16 führt zwei vorzeichenbehaftete Additionsbefehle durch und sättigt in einem vorzeichenbehafteten Bereich.
* die ergebnisse 0x7FFF und 0x8000 beschreibt in diesem Fall die Sättigung eines Overflows
*
* zu Aufgabenteil e):
* SSAT16: Eingabe als signed interpretiert und werden in vorzeichenbbehafteten Bereich gesättigt -> keine 0er wie bei USAT16
* Zahlen größer als 0x7fff haben eine "führende 1" und sind negativ und werden zu 8000 gesättigt + Vorzeichenerweiterung
* 
* USAT16: hier wird zwar auf eine Zahl ohne Vorzeichen gesättigt, jedoch wird die Eingabe aber als signed interpretiert
* Zahlen größer als 0x7fff haben eine "führende 1" und sind negativ und werden zu 0 gesättigt, Zahlen kleiner 0x7fff sind positiv und werden
* an die obere Grenze gesättigt -> 0FFF
*/

main:	
	bl uart_init
	
	// Multiplizieren der beiden Matrizen M * N, DSP-Befehle verwenden ---------------------------------------------------------------------
	
	// Laden der Zeiger auf die jeweiligen ersten Adressen der Matrizen
	ldr r4, =m12
	ldr r5, =n12
	ldr r6, =o11								// Laden des Zeigers auf die erste Adresse der Zielmatrix
	
	mov r12, #COUNTER_SPALTE 					// Laden der Spalten-Zaehlers4
	
loop_gesamtberechnung:
	// dieser Loop wird vier mal aufgerufen (für jede Matrixzeile)
	
	mov r11, #COUNTER_ZEILE 					// Laden der Zeilen-Zaehlers
	
loop_zeilenberechnung:
	// dieser Loop wird vier mal aufgerufen (für jede Matrixspalte)
	
	mov r9, #0x0								// Für die Berechnung jeder Zelle der Matrix 0 wird zunächst R9 zurück auf null gesetzt
	mov r10, #COUNTER_ZELLE 					// Laden des Zellen-Zaehlers
	
loop_zellenberechnung:
	// dieser Loop wird zweimal aufgerufen (für jeweils zwei Matrixzellen aus m und n pro Ausführung, zwei Ausführungen nötig für die Berechnung einer Zelle in o)

	ldr r7, [r4], #INCR_FOUR					// Matrix-Element aus m laden und anschließend Zeiger um 4 erhöhen zum Zugriff auf das nächste Element
	ldr r8, [r5], #INCR_FOUR					// Matrix-Element aus n laden und anschließend Zeiger um 4 erhöhen zum Zugriff auf das nächste Element

	smlad r9, r7, r8, r9						// Multiplizieren der jeweiligen Botton- und Top-Halfwords miteinander und addieren beider Produkte zum Zwischenergebnis der Zellen
		
	subs r10, r10, #1							// Zaehler dekrementieren
	bne loop_zellenberechnung					// solange Zaehler noch nicht null ---------------------------
	
	str r9, [r6], #INCR_FOUR					// Speichern des Ergebnisses in die Zelle der Matrix o und erhöhen des Zeigers um 2 Bytes
	sub r4, #EIGHT								// Zurücksetzen des Zeilenstarts für die Berechnung der nächsten Zelle der Matrix-Zeile
	
	subs r11, r11, #1							// Zaehler dekrementieren
	bne loop_zeilenberechnung					// solange Zaehler noch nicht null ---------------------------
	
	add r4, #EIGHT								// Zeilenstart um 8 erhöhen
	sub r5, #THIRTY_TWO							// Zurücksetzen des Spaltenstarts
	
	subs r12, r12, #1							// Zaehler dekrementieren
	bne loop_gesamtberechnung					// solange Zaehler noch nicht null ---------------------------
	

	// Terminalausgabe der Ergebnismatrix O:

	mov r12, #COUNTER_SPALTE					// Laden der Spalten-Zaehlers

	ldr r0, =str_ergebnismatrix_o				// Zeiger auf String laden
	bl uart_putString							// String ausgeben
	
	ldr r4, =o11								// Zeiger auf ELement o11 der zu kopierenden Matrix laden

loop_ausgabe_matrix:

	mov r11, #COUNTER_ZEILE						// Laden der Zeilen-Zaehlers
	
loop_ausgabe_zeile:
	
	ldr r0, [r4], #INCR_FOUR					// Matrix-Element in R0 laden und Zeiger um 4 erhöhen zum Zugriff auf das nächste Element
	bl uart_putInt32							// Matrix-Element ausgeben
	
	ldr r0, =str_tab							// Zeiger auf String laden
	bl uart_putString							// String ausgeben
	
	subs r11, r11, #1							// Zaehler dekrementieren
	bne loop_ausgabe_zeile						// solange Zaehler noch nicht null
	
	ldr r0, =str_zeilenumbruch					// Zeiger auf String laden
	bl uart_putString							// String ausgeben
	
	subs r12, r12, #1							// Zaehler dekrementieren
	bne loop_ausgabe_matrix						// solange Zaehler noch nicht null
	
	

	// Kopieren der Matrix O im .data-Speicherbereich --------------------------------------------------------------------------------------
	
	ldr r0, =str_kopieren_der_matrix			// Zeiger auf String laden
	bl uart_putString							// String ausgeben
		
	mov r12, #COUNTER_ZEILE						// Laden des Zeilen-Zaehlers
	
	ldr r4, =o11								// Laden des Zeigers auf die erste Adresse der Matrix O
	ldr r5, =copy_o11							// Laden des Zeigers auf die erste Adresse der Zielmatrix
	
loop_kopieren:
	ldm r4!,{r6,r7,r8,r9}						// Lade vier Wörter aus der Matrix o und inkrementiere anschließend die Adresse um die geladenen Wörter
	stm r5!,{r6,r7,r8,r9}						// Speichere diese 4 Wörter in die Matrix copy_o und inkrementiere anschließend die Zieladresse um die gespeicherten Wörter
	
	subs r12, r12, #1							// Zaehler dekrementieren
	bne loop_kopieren							// solange Zaehler noch nicht null

	ldr r0, =str_kopieren_abgeschlossen			// Zeiger auf String laden
	bl uart_putString							// String ausgeben

	

	// Berechnen der Summe von Element-Produkten der Matrizen M und N ----------------------------------------------------------------------
	
	ldr r0, =str_produkt_summe					// Zeiger auf String laden
	bl uart_putString							// String ausgeben
	
	mov r12, #COUNTER_MATRIX 					// Laden des Matrix-Zaehlers (Wert 8)

	// Laden der Zeiger auf die jeweiligen ersten Adressen der Matrizen
	ldr r4, =m12								
	ldr r5, =n12
	
	mov r9, #0									// Register zum Speichern der Zwischenergebnisse auf null setzen
	
loop_produktsummenberechnung:
	// Loop wird 8 mal aufgerufen (pro Loop-Aufruf werden aus jeder Matrix jeweils 2 Zellenprodukte dazugerechnet)

	ldr r7, [r4], #INCR_FOUR					// Matrix-Element aus m laden und anschließend Zeiger um 4 erhöhen zum Zugriff auf das nächste Element
	ldr r8, [r5], #INCR_FOUR					// Matrix-Element aus n laden und anschließend Zeiger um 4 erhöhen zum Zugriff auf das nächste Element

	smlad r9, r7, r8, r9						// Multiplizieren der jeweiligen Botton- und Top-Halfwords miteinander und addieren beider Produkte zum Zwischenergebnis

	subs r12, r12, #1							// Zaehler dekrementieren
	bne loop_produktsummenberechnung			// solange Zaehler noch nicht null

	mov r0, r9									
	bl uart_putInt32							// Ausgabe des Ergebnisses
	


	// Skalierbare Additionsbefehle: -------------------------------------------------------------------------------------------------------
	
	// Laden der Operanden in die jeweiligen Register
	ldr r4, =OPERAND_A
	ldr r5, =OPERAND_B
	ldr r6, =OPERAND_C
	ldr r7, =OPERAND_D
	
	// Durchführung der Operationen mit UADD16: nicht-vorzeichenbehaftete parallele Halfword-weise Addition
	uadd16 r8, r4, r5 
	uadd16 r9, r4, r6
	uadd16 r10, r4, r7
	
	// Terminalausgabe der UADD16-Ergebnisse
	ldr r0, =str_uadd16							// Zeiger auf String laden
	bl uart_putString							// String ausgeben
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis UADD16 mit A und B
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis UADD16 mit A und C
	mov r0, r9
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis UADD16 mit A und D
	mov r0, r10
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Durchführung der Operationen mit SADD16: vorzeichenbehaftete parallele Halfword-weise Addition
	sadd16 r8, r4, r5
	sadd16 r9, r4, r6
	sadd16 r10, r4, r7
	
	// Terminalausgabe der SADD16-Ergebnisse
	ldr r0, =str_sadd16
	bl uart_putString
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis SADD16 mit A und B
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis SADD16 mit A und C
	mov r0, r9
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis SADD16 mit A und D
	mov r0, r10
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Durchführung der Operationen mit UQADD16: nicht-vorzeichenbehaftete, sättigende, parallele Halfword-weise Addition
	uqadd16 r8, r4, r5
	uqadd16 r9, r4, r6
	uqadd16 r10, r4, r7
	
	// Terminalausgabe der UQADD16-Ergebnisse
	ldr r0, =str_uqadd16
	bl uart_putString
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis UQADD16 mit A und B
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis UQADD16 mit A und C
	mov r0, r9
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis UQADD16 mit A und D
	mov r0, r10
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Durchführung der Operationen mit QADD16: vorzeichenbehaftete, sättigende, parallele Halfword-weise Addition
	qadd16 r8, r4, r5
	qadd16 r9, r4, r6
	qadd16 r10, r4, r7
	
	// Terminalausgabe der QADD16-Ergebnisse
	ldr r0, =str_qadd16
	bl uart_putString
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis QADD16 mit A und B
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis QADD16 mit A und C
	mov r0, r9
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ergebnis QADD16 mit A und D
	mov r0, r10
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
		
	
	// Sättigung von zwei 32-Bit Werten - als jeweils zwei 16 Bit Werte interpretiert - auf 13 Bits ----------------------------------------
	
	// USAT16 - nicht-vorzeichenbehaftete, Halfword-weise, parallele Sättigung
	usat16 r8, #SAT_BITS, r4
	usat16 r9, #SAT_BITS, r5
	
	// SSAT16 - vorzeichenbehaftete, Halfword-weise, parallele Sättigung
	ssat16 r10, #SAT_BITS, r4
	ssat16 r11, #SAT_BITS, r5
	
	// Ausgabe der USAT16 Ergebnisse
	ldr r0, =str_usat16
	bl uart_putString
	ldr r0, =str_tab
	bl uart_putString
	
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	mov r0, r9
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	// Ausgabe der SSAT16-Ergebnisse
	ldr r0, =str_ssat16
	bl uart_putString
	ldr r0, =str_tab
	bl uart_putString
	
	mov r0, r10
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	mov r0, r11
	bl uart_putInt32
	ldr r0, =str_tab
	bl uart_putString
	
	ldr r0, =str_zeilenumbruch					// Zeiger auf String laden
	bl uart_putString							// String ausgeben
	ldr r0, =str_zeilenumbruch					// Zeiger auf String laden
	bl uart_putString							// String ausgeben
	

end:
	b end


/*** Datenbereich (ab 0x20000000) ***/
.data
