// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ MINUTEN_MAX, 0x3C				// Maximale Minuten-Anzahl: 60
.equ STUNDEN_MAX, 0x18				// Maximale Stunden-Anzahl: 24
.equ TAGE_MAX, 0x1F					// Maximale Tage-Anzahl: 30 -> Maximum bei 31 (vereinfacht nach Aufgabenstellung)
.equ MONATE_MAX, 0xD				// Maximale Monate-Anzahl: 12 -> Maximum bei 13
.equ JAHRE_MAX, 0x64				// Maximale Jahre-Anzahl: 100
.equ ZEHN, 0xA
.equ CHAR_0, '0'

/* 
* Taktzyklen für eine Sekunde
* K60 mit 25 MHz getaktet -> in einer Sekunde werden 25.000.000 Taktzyklen abgearbeitet
* SUBS braucht einen Zyklus, BNE drei, also theoretisch:
* 25.000.000 / 4 = 6250000
* Nachbesserung durch Vergleich mit digitaler Stoppuhr (Terminal-Ausgaben pro Zeit)
*/
.equ CLOCK_CYCLES_SECOND, 0x7DD714

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:	
	bl uart_init
	
	
loop_minute:
	
	// Überprüfung, ob ein Zeichen in das Terminal eingegeben wurde
	bl uart_charPresent					// Funktion gibt 0 in R0 zurück, falls kein char eingegeben wurde
	teq r0, #0							// Überprüfung des Rückgabewertes auf Gleichheit mit 0
	bne char_available					// falls nicht gleich: char verfügbar -> Überprüfen des char
	beq update_clock_elements			// falls gleich: Uhr-Elemente erneuern und ausgeben
	
char_available:
	// ein Zeichen ist verfügbar, diese Funktion übeprüft, welches Zeichen es ist und ruft entsprechende Funktionalitäten auf
	
	bl uart_getChar						// Laden des Zeichens in R0
	
	cmp r0, #'s'
	beq start_stop_clock				// falls 's' in R0: springe zu den Funktionalitäten für das Zeichen 's'
	
	cmp r0, #'t'
	beq input_time						// falls 't' in R0: springe zu den Funktionalitäten für das Zeichen 't'
	
	cmp r0, #'d'
	beq input_date						// falls 'd' in R0: springe zu den Funktionalitäten für das Zeichen 'd'
	bne update_clock_elements			// falls anderes Zeichen in R0: keine Funktionalitäten -> Uhr-Elemente erneuern und ausgeben

	
start_stop_clock:	
	ldr r0, =str_uhr_gestoppt			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
loop_clock_stopped:
	// Loop sorgt für Pause bis wieder 's' eingegeben wurde
	
	// Flag setzen, dass Uhr gestoppt wurde (Rücksprungbedingung für Uhrzeit/Datum-Eingabe
	mov r5, #0x1
	ldr r4, =stop_flag
	str r5, [r4]
	
	// 1. Check: Wurde ein Zeichen eingegeben?
	bl uart_charPresent
	teq r0, #0
	bne loop_clock_stopped				// falls nein: im Pause-Loop bleiben
	
	// 2. Check: Ist das Zeichen ein 't'?
	bl uart_getChar
	cmp r0, #'t'
	beq input_time
	
	// 3. Check: Ist das Zeichen ein 'd'?
	cmp r0, #'d'
	beq input_date
	
	// 4. Check: Ist das Zeichen ein 's'?
	cmp r0, #'s'
	bne loop_clock_stopped				// falls nein: im Pause-Loop bleiben
	
	// Checks successful
	ldr r0, =str_uhr_gestartet			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	// Stop-Flag zurücksetzen
	mov r5, #0x0
	ldr r4, =stop_flag
	str r5, [r4]
	
	b update_clock_elements				// Fortsetzen des Uhr-Zyklus
	
input_time:
	ldr r4, =stunde						// Laden des Zeigers auf das Stunden-Byte
	ldr r0, =str_stunde_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r5, =minuten					// Laden des Zeigers auf das Minuten-Byte
	ldr r0, =str_minuten_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r5]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =stop_flag
	ldrb r5, [r4]
	cmp r5, #0x1						// Überprüfen, ob Stop-Flag gesetzt 
	beq loop_clock_stopped				// falls ja: Rücksprung in den Stop-Loop
	
	b update_clock_elements				// Fortsetzen des Uhr-Zyklus
	
input_date:
	ldr r4, =tag						// Laden des Zeigers auf das Tag-Byte
	ldr r0, =str_tag_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r5, =monat						// Laden des Zeigers auf das Monat-Byte
	ldr r0, =str_monat_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r5]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r6, =jahr						// Laden des Zeigers auf das Jahr-Byte
	ldr r0, =str_jahr_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r6]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =stop_flag
	ldrb r5, [r4]
	cmp r5, #0x1						// Überprüfen, ob Stop-Flag gesetzt 
	beq loop_clock_stopped				// falls ja: Rücksprung in den Stop-Loop
	
	b update_clock_elements				// Fortsetzen des Uhr-Zyklus
	
	
update_clock_elements:
	// Zu Beginn wird das Programm mit dem Untnerprogramm "delay" in eine "Pause" von einer Sekunde gesetzt.
	// Anschließend werden die einzelnen Elemente der Uhr aktualisiert, beginnend bei der Minute.
	// Die nachfolgenden Elemente werden immer nur aufgerufen, wenn es einen "Überlauf" des Vorgängers gab, da diese sonst nicht
	// aktualisiert werden müssen. 
	// Die Erhöhung des jeweiligen Elements und die Überprüfung auf Überlauf erfolgt im generischen Unterprogramm "increment_element".
	
	bl delay							// Zeitverzögerung um eine Sekunde (entspricht Minute auf dem Terminal)
	
	// Minuten inkrementieren
	ldr r0, =minuten					// 1. Argument: Zeiger auf das Minuten-Byte
    mov r1, #MINUTEN_MAX				// 2. Argument: Minuten-Maximum
    mov r2, #0							// 3. Argument: Startwert für Minuten nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Stunde inkrementieren
    ldr r0, =stunde						// 1. Argument: Zeiger auf das Stunden-Byte
    mov r1, #STUNDEN_MAX				// 2. Argument: Stunden-Maximum
    mov r2, #0							// 3. Argument: Startwert für Stunden nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Tag inkrementieren
    ldr r0, =tag						// 1. Argument: Zeiger auf das Tag-Byte
    mov r1, #TAGE_MAX					// 2. Argument: Tag-Maximum
    mov r2, #1							// 3. Argument: Startwert für Tage nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Monat inkrementieren
    ldr r0, =monat						// 1. Argument: Zeiger auf das Monat-Byte
    mov r1, #MONATE_MAX					// 2. Argument: Monat-Maximum
    mov r2, #1							// 3. Argument: Startwert für Monate nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Jahr inkrementieren
    ldr r0, =jahr						// 1. Argument: Zeiger auf das Jahr-Byte
	mov r1, #JAHRE_MAX					// 2. Argument: Jahr-Maximum
	mov r2, #0							// 3. Argument: Startwert für Jahre nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    
    
call_print_terminal:
    bl print_terminal					// Datum und Uhrzeit auf Terminal ausgeben
	
	b loop_minute						// Minuten-Loop erneut starten



.thumb_func
delay:
    // Unterprogramm sorgt für eine Zeitverzögerung von etwa einer Sekunde

    push {lr}
    
    ldr r6, =CLOCK_CYCLES_SECOND 		// Laden der Loop-Zyklen-Anzahl für die Dauer des Unterprogramms von einer Sekunde
    
loop_delay:
    
    subs r6, r6, #1						// Zaehler dekrementieren
    bne loop_delay						// solange Zaehler noch nicht null
    
    pop {pc}



.thumb_func
increment_element:
	// Inkrementiert ein einzelnes Elemnt der Uhr und überprüft auf einen eventuellen "Überlauf"
	// Argumente: 
	// R0: Adresse des Elements
	// R1: Maximalwert des Elements
	// R2: Startwert des Elements nach "Überlauf"
	// Rückgabewerte:
	// R0: Adresse des Elements
	// R1: Anzeige eines eventuellen Überlaufs (Wert 1)
	
    push {lr}
    
    ldrb r3, [r0]						// Laden des Wertes des Elements
    add r3, r3, #0x1					// Erhöhen des Elements um 1
    
    // "Überlauf" überprüfen
    cmp r3, r1							// Vergleich des Erhöhten Elements mit dem zulässigen Maximum
    itte eq								// falls gleich -> Überlauf
    moveq r1, #0x1						// Überlauf durch Rückgabewert in R1 anzeigen
    moveq r3, r2						// Element auf den in R2 übergebenen Startwert zurücksetzen
    movne r1, #0x0						// falls nicht gleich: kein Überlauf durch Rückgabewert in R1 anzeigen
    
    strb r3, [r0]						// Abspeichern des Elements
    
    pop {pc}



.thumb_func
print_terminal:
	// Gibt aktuelles Datum und Uhrzeit auf dem Terminal aus
	// Ausgabeformat: "dd.mm.jjjj hh:mm Uhr"

	push  {lr}
	
	// Tag
	ldr r1, =tag
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// "Punkt"
	ldr r0, =str_punkt
	bl uart_putString
	
	// Monat
	ldr r1, =monat
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// "Punkt"
	ldr r0, =str_punkt
	bl uart_putString
	
	// Jahrhundert (konstant)
	ldr r1, =jahrhundert
	ldr r0, [r1]
	bl uart_putByteBase10
	
	// Jahr
	ldr r1, =jahr
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Leerzeichen
	ldr r0, =str_leerzeichen
	bl uart_putString
	
	// Stunde
	ldr r1, =stunde
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Doppelpunkt
	ldr r0, =str_doppelpunkt
	bl uart_putString
	
	// Minute
	ldr r1, =minuten
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Leerzeichen
	ldr r0, =str_leerzeichen
	bl uart_putString
	
	// "Uhr"
	ldr r0, =str_uhr
	bl uart_putString
	
	pop {pc}



.thumb_func
print_element:
	// Überprüft neben dem Ausgeben, ob auszugebender Wert eine einstellige oder zweistellige Dezimalzahl darstellt und setzt ggf. eine '0' davor

    push {lr}
    
    cmp r0, #ZEHN						// Vergleiche den Wert in R1 mit dem Wert 10 (Dezimal)
    bhs no_zero_jump					// Falls der Wert größer oder gleich 10: kein Hinzufügen einer '0' bei der Ausgabe: springe zur Marke 'no_zero'
    
    mov r1, r0							// Sichern des auszugebenden Wertes in R1
    mov r0, #CHAR_0
    bl uart_putChar						// zunächst Ausgeben der '0' auf dem Terminal
    mov r0, r1							// Zurückschreiben des Wertes in R0
    
no_zero_jump:
    bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
    
    pop {pc}


/*** Datenbereich (ab 0x20000000) ***/
.data
minuten: .byte 0x0
stunde: .byte 0x0
tag: .byte 0x1
monat: .byte 0x1
jahr: .byte 0xE
jahrhundert: .byte 0x14
str_stunde_eingeben: .asciz "\nStunde eingeben: "
str_minuten_eingeben: .asciz "\nMinuten eingeben: "
str_tag_eingeben: .asciz "\nTag eingeben: "
str_monat_eingeben: .asciz "\nMonat eingeben: "
str_jahr_eingeben: .asciz "\nJahr eingeben: "
str_uhr: .asciz "Uhr\n"
str_punkt: .asciz "."
str_leerzeichen: .asciz " "
str_doppelpunkt: .asciz ":"
str_zeilenumbruch: .asciz "\n\n"
str_uhr_gestoppt: .asciz "\nUhr gestoppt!\n"
str_uhr_gestartet: .asciz "Uhr gestartet!\n\n"
stop_flag: .byte 0x0
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Allg. Konstanten
.equ MINUTEN_MAX, 0x3C				// Maximale Minuten-Anzahl: 60
.equ STUNDEN_MAX, 0x18				// Maximale Stunden-Anzahl: 24
.equ TAGE_MAX, 0x1F					// Maximale Tage-Anzahl: 30 -> Maximum bei 31 (vereinfacht nach Aufgabenstellung)
.equ MONATE_MAX, 0xD				// Maximale Monate-Anzahl: 12 -> Maximum bei 13
.equ JAHRE_MAX, 0x64				// Maximale Jahre-Anzahl: 100
.equ ZEHN, 0xA
.equ CHAR_0, '0'

// Interrupt/PIT Konstanten
__BBREG SIM_SCGC6_PIT,  0x4004803C, 23
.equ SIM_SCGC6_BIT, 0x1

.equ SCR_VTOR, 0xE000ED08		// Basisadresse der IVT
.equ OFFSET_PIT, 0x00000154		// Offset für PIT1

.equ NVIC_ICPR2, 0xE000E288
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BITMASK, 1 << 5

__BBREG PIT_MCR_MDIS, 0x40037000, 1
__BBREG PIT_MCR_FRZ, 0x40037000, 0
.equ PIT_MCR, 0x0

.equ PIT_LDVAL1, 0x40037110
.equ PIT_LDVAL1_START_VALUE, 0x017D7840

__BBREG PIT_TCTRL1_TIE, 0x40037118, 1
__BBREG PIT_TCTRL1_TEN, 0x40037118, 0
.equ TCTRL1_BIT, 0x1

__BBREG PIT_TFLG1_TIF, 0x4003711c, 0
.equ TFLG1_BIT, 0x1
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// A. Initialisierung

	// a) Takt für PIT aktivieren (System Integration Module – SIM)
	
	ldr r4, =SIM_SCGC6_PIT
    mov r5, #SIM_SCGC6_BIT
    str r5, [r4]
    
    // b) Index des Interrupt-Vektor zu PIT1 setzen
    
    ldr r8, =SCR_VTOR
    ldr r6, [r8]
    ldr r7, =OFFSET_PIT
    add r4, r7, r6
    
    ldr r5, =isr_pit1				// Laden der Startadresse der ISR
    str r5, [r4]					// Speichern der Adresse in die Interrupt-Vektor-Tabelle
    
    // c) eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC)
    
    ldr r4, =NVIC_ICPR2
    ldr r5, =NVIC_BITMASK
    str r5, [r4] 
   
    // d) Interrupt zu PIT1 aktivieren (NVIC)
    
    ldr r4, =NVIC_ISER2
    ldr r5, =NVIC_BITMASK
    str r5, [r4] 
    
    // e) alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
    
    // alle Pits aktivieren
    ldr r4, =PIT_MCR_MDIS
    mov r5, #PIT_MCR
    str r5, [r4] 
    
    // im Debug-Modus laufen lassen
    ldr r4, =PIT_MCR_FRZ
	mov r5, #PIT_MCR
    str r5, [r4] 
    
	// f) Startwert für PIT1 auf 1 Sekunde initialisieren

	ldr r4, =PIT_LDVAL1
	ldr r5, =PIT_LDVAL1_START_VALUE
    str r5, [r4] 
	
	// g) Interrupt zu PIT1 aktivieren (PIT-Modul)
	ldr r4, =PIT_TCTRL1_TIE
	mov r5, #TCTRL1_BIT
    str r5, [r4]					
	
	// h) PIT1 aktivieren (PIT-Modul)
	ldr r4, =PIT_TCTRL1_TEN
	mov r5, #TCTRL1_BIT
    str r5, [r4]	
	
	

loop_minute:
	
	// Überprüfung, ob ein Zeichen in das Terminal eingegeben wurde
	bl uart_charPresent					// Funktion gibt 0 in R0 zurück, falls kein char eingegeben wurde
	teq r0, #0							// Überprüfung des Rückgabewertes auf Gleichheit mit 0
	bne char_available					// falls nicht gleich: char verfügbar -> Überprüfen des char
	beq update_clock_elements			// falls gleich: Uhr-Elemente erneuern und ausgeben
	
char_available:
	// ein Zeichen ist verfügbar, diese Funktion übeprüft, welches Zeichen es ist und ruft entsprechende Funktionalitäten auf
	
	bl uart_getChar						// Laden des Zeichens in R0
	
	cmp r0, #'s'
	beq start_stop_clock				// falls 's' in R0: springe zu den Funktionalitäten für das Zeichen 's'
	
	cmp r0, #'t'
	beq input_time						// falls 't' in R0: springe zu den Funktionalitäten für das Zeichen 't'
	
	cmp r0, #'d'
	beq input_date						// falls 'd' in R0: springe zu den Funktionalitäten für das Zeichen 'd'
	bne update_clock_elements			// falls anderes Zeichen in R0: keine Funktionalitäten -> Uhr-Elemente erneuern und ausgeben

	
start_stop_clock:	
	ldr r0, =str_uhr_gestoppt			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
loop_clock_stopped:
	// Loop sorgt für Pause bis wieder 's' eingegeben wurde
	
	// Flag setzen, dass Uhr gestoppt wurde (Rücksprungbedingung für Uhrzeit/Datum-Eingabe
	mov r5, #0x1
	ldr r4, =stop_flag
	str r5, [r4]
	
	// 1. Check: Wurde ein Zeichen eingegeben?
	bl uart_charPresent
	teq r0, #0
	bne loop_clock_stopped				// falls nein: im Pause-Loop bleiben
	
	// 2. Check: Ist das Zeichen ein 't'?
	bl uart_getChar
	cmp r0, #'t'
	beq input_time
	
	// 3. Check: Ist das Zeichen ein 'd'?
	cmp r0, #'d'
	beq input_date
	
	// 4. Check: Ist das Zeichen ein 's'?
	cmp r0, #'s'
	bne loop_clock_stopped				// falls nein: im Pause-Loop bleiben
	
	// Checks successful
	ldr r0, =str_uhr_gestartet			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	// Stop-Flag zurücksetzen
	mov r5, #0x0
	ldr r4, =stop_flag
	str r5, [r4]
	
	b update_clock_elements				// Fortsetzen des Uhr-Zyklus
	
input_time:
	ldr r4, =stunde						// Laden des Zeigers auf das Stunden-Byte
	ldr r0, =str_stunde_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r5, =minuten					// Laden des Zeigers auf das Minuten-Byte
	ldr r0, =str_minuten_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r5]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =stop_flag
	ldrb r5, [r4]
	cmp r5, #0x1						// Überprüfen, ob Stop-Flag gesetzt 
	beq loop_clock_stopped				// falls ja: Rücksprung in den Stop-Loop
	
	b update_clock_elements				// Fortsetzen des Uhr-Zyklus
	
input_date:
	ldr r4, =tag						// Laden des Zeigers auf das Tag-Byte
	ldr r0, =str_tag_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r5, =monat						// Laden des Zeigers auf das Monat-Byte
	ldr r0, =str_monat_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r5]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r6, =jahr						// Laden des Zeigers auf das Jahr-Byte
	ldr r0, =str_jahr_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r6]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =stop_flag
	ldrb r5, [r4]
	cmp r5, #0x1						// Überprüfen, ob Stop-Flag gesetzt 
	beq loop_clock_stopped				// falls ja: Rücksprung in den Stop-Loop
	
	b update_clock_elements				// Fortsetzen des Uhr-Zyklus

update_clock_elements:
	// Zu Beginn wird das Programm mit dem Untnerprogramm "delay" in eine "Pause" von einer Sekunde gesetzt.
	// Anschließend werden die einzelnen Elemente der Uhr aktualisiert, beginnend bei der Minute.
	// Die nachfolgenden Elemente werden immer nur aufgerufen, wenn es einen "Überlauf" des Vorgängers gab, da diese sonst nicht
	// aktualisiert werden müssen. 
	// Die Erhöhung des jeweiligen Elements und die Überprüfung auf Überlauf erfolgt im generischen Unterprogramm "increment_element".
	
loop_wait_for_flag:
	// Loop "wartet", bis die Interrupt Service Routine das Benutzer-Flag setzt
	
	ldr r7, =benutzer_flag
	ldrb r1, [r7]
	teq r1, #0x1	
	bne loop_wait_for_flag
	
	// Flasg zurücksetzen
	mov r10, #0x0
	strb r10, [r7]
	
	// Minuten inkrementieren
	ldr r0, =minuten					// 1. Argument: Zeiger auf das Minuten-Byte
    mov r1, #MINUTEN_MAX				// 2. Argument: Minuten-Maximum
    mov r2, #0							// 3. Argument: Startwert für Minuten nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Stunde inkrementieren
    ldr r0, =stunde						// 1. Argument: Zeiger auf das Stunden-Byte
    mov r1, #STUNDEN_MAX				// 2. Argument: Stunden-Maximum
    mov r2, #0							// 3. Argument: Startwert für Stunden nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Tag inkrementieren
    ldr r0, =tag						// 1. Argument: Zeiger auf das Tag-Byte
    mov r1, #TAGE_MAX					// 2. Argument: Tag-Maximum
    mov r2, #1							// 3. Argument: Startwert für Tage nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Monat inkrementieren
    ldr r0, =monat						// 1. Argument: Zeiger auf das Monat-Byte
    mov r1, #MONATE_MAX					// 2. Argument: Monat-Maximum
    mov r2, #1							// 3. Argument: Startwert für Monate nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r1, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne call_print_terminal				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe

    // Jahr inkrementieren
    ldr r0, =jahr						// 1. Argument: Zeiger auf das Jahr-Byte
	mov r1, #JAHRE_MAX					// 2. Argument: Jahr-Maximum
	mov r2, #0							// 3. Argument: Startwert für Jahre nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    
    
call_print_terminal:
    bl print_terminal					// Datum und Uhrzeit auf Terminal ausgeben
	
	b loop_minute						// Minuten-Loop erneut starten




.thumb_func
increment_element:
	// Inkrementiert ein einzelnes Elemnt der Uhr und überprüft auf einen eventuellen "Überlauf"
	// Argumente: 
	// R0: Adresse des Elements
	// R1: Maximalwert des Elements
	// R2: Startwert des Elements nach "Überlauf"
	// Rückgabewerte:
	// R0: Adresse des Elements
	// R1: Anzeige eines eventuellen Überlaufs (Wert 1)
	
    push {lr}
    
    ldrb r3, [r0]						// Laden des Wertes des Elements
    add r3, r3, #0x1						// Erhöhen des Elements um 1
    
    // "Überlauf" überprüfen
    cmp r3, r1							// Vergleich des Erhöhten Elements mit dem zulässigen Maximum
    itte eq								// falls gleich -> Überlauf
    moveq r1, #0x1						// Überlauf durch Rückgabewert in R1 anzeigen
    moveq r3, r2						// Element auf den in R2 übergebenen Startwert zurücksetzen
    movne r1, #0x0						// falls nicht gleich: kein Überlauf durch Rückgabewert in R1 anzeigen
    
    strb r3, [r0]						// Abspeichern des Elements
    
    pop {pc}


.thumb_func
print_terminal:
	// Gibt aktuelles Datum und Uhrzeit auf dem Terminal aus
	// Ausgabeformat: "dd.mm.jjjj hh:mm Uhr"

	push  {lr}
	
	// Tag
	ldr r1, =tag
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// "Punkt"
	ldr r0, =str_punkt
	bl uart_putString
	
	// Monat
	ldr r1, =monat
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// "Punkt"
	ldr r0, =str_punkt
	bl uart_putString
	
	// Jahrhundert (konstant)
	ldr r1, =jahrhundert
	ldr r0, [r1]
	bl uart_putByteBase10
	
	// Jahr
	ldr r1, =jahr
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Leerzeichen
	ldr r0, =str_leerzeichen
	bl uart_putString
	
	// Stunde
	ldr r1, =stunde
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Doppelpunkt
	ldr r0, =str_doppelpunkt
	bl uart_putString
	
	// Minute
	ldr r1, =minuten
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Leerzeichen
	ldr r0, =str_leerzeichen
	bl uart_putString
	
	// "Uhr"
	ldr r0, =str_uhr
	bl uart_putString
	
	pop {pc}


.thumb_func
print_element:
	// Überprüft neben dem Ausgeben, ob auszugebender Wert eine einstellige oder zweistellige Dezimalzahl darstellt und setzt ggf. eine '0' davor

    push {lr}
    
    cmp r0, #ZEHN						// Vergleiche den Wert in R1 mit dem Wert 10 (Dezimal)
    bhs no_zero_jump					// Falls der Wert größer oder gleich 10: kein Hinzufügen einer '0' bei der Ausgabe: springe zur Marke 'no_zero'
    
    mov r1, r0							// Sichern des auszugebenden Wertes in R1
    mov r0, #CHAR_0
    bl uart_putChar						// zunächst Ausgeben der '0' auf dem Terminal
    mov r0, r1							// Zurückschreiben des Wertes in R0
    
no_zero_jump:
    bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
    
    pop {pc}



// Interrupt Service Routine zu PIT1
.thumb_func
isr_pit1:
	// Register-Sicherung hier nicht extra notwendig, ISR möglichst knapp halten

	// Interrupt-Flag zum PIT1 zurücksetzen
	ldr r1, =PIT_TFLG1_TIF
	ldr r2, =TFLG1_BIT
    strb r2, [r1]
    	
	// Setzen eines Benutzerflags, das dem Hauptprogramm den Ablauf einer Sekunde anzeigt
	ldr r1, =benutzer_flag
	mov r2, #0x1
	strb r2, [r1]

	bx lr					// Rücksprung



/*** Datenbereich (ab 0x20000000) ***/
.data
minuten: .byte 0x0
stunde: .byte 0x0
tag: .byte 0x1
monat: .byte 0x1
jahr: .byte 0xE
jahrhundert: .byte 0x14
str_stunde_eingeben: .asciz "\nStunde eingeben: "
str_minuten_eingeben: .asciz "\nMinuten eingeben: "
str_tag_eingeben: .asciz "\nTag eingeben: "
str_monat_eingeben: .asciz "\nMonat eingeben: "
str_jahr_eingeben: .asciz "\nJahr eingeben: "
str_uhr: .asciz "Uhr\n"
str_punkt: .asciz "."
str_leerzeichen: .asciz " "
str_doppelpunkt: .asciz ":"
str_zeilenumbruch: .asciz "\n\n"
str_uhr_gestoppt: .asciz "\nUhr gestoppt!\n"
str_uhr_gestartet: .asciz "Uhr gestartet!\n\n"
stop_flag: .byte 0x0
benutzer_flag: .byte 0x0

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6_CRC, 0x429007C8	// Bit 18

.equ CRC_CTRL, 0x40032008
.equ CRC_CTRL_BITMASK, 0x03000000
.equ CRC_CTRL_RESET_BITMASK, 0x01000000

.equ CRC_CRC, 0x40032000
.equ CRC_SEED, 0x12345678

.equ CRC_GPOLY, 0x40032004
.equ CRC_POLYNOM, 0x04C11DB7	// 0x04C11DB7 entspricht binär 100110000010001110110110111

.equ CRC_CRC, 0x40032000

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	mov r5, #0x1
    mov r11, #0x0

	// Takt für CRC aktivieren (SIM)
	ldr r4, =SIM_SCGC6_CRC
    strb r5, [r4]	

	// Initialisierung des CRC-Moduls (Eingabe und Ausgabewerte nicht umgruppiert, Ausgabewerte nicht invertiert (kein XOR) und 32-Bit Prüfzeichen)    
	ldr r4, =CRC_CTRL
    ldr r5, =CRC_CTRL_BITMASK					// Bit 24 und 25 gesetzt (WAS und TCRC), Bits von TOT und TOTR und FXOR auf 0 setzen
    str r5, [r4] 

	// standardisiertes CRC32-Polynom in Register eintragen
	ldr r4, =CRC_GPOLY
    ldr r5, =CRC_POLYNOM
    str r5, [r4] 
		
	// Startwert (seed) der CRC Generierung auf 0x12345678 setzen
	ldr r4, =CRC_CRC
    ldr r5, =CRC_SEED
    str r5, [r4] 
    
	// WAS-Bit (Bit 24) zurücksetzen
	ldr r4, =CRC_CTRL
    ldr r5, =CRC_CTRL_RESET_BITMASK
    str r5, [r4] 
	
    ldr r7, =str				// Laden des abgelegten Strings
    ldr r4, =CRC_CRC			// Laden des CRC_CRC-Registers

    
loop_einlesen_und_pruefwert_ermittteln:
	// in einer Schleife abgelegten String byteweise einlesen, 4 Byte zu 32 Bit Wort zusammenfasen
	
	ldr r8, [r7], #4			// Laden des zur Berechnung notwendigen Wortes des Strings und Erhöhen der Adresse in R7 um 4
	rev r8, r8					// Umkehrung der Bytereihenfolge im Wort (sinnvoll zum Vergleich mit Online CRC Rechnern, wieder im Big Endian Format)
	str r8, [r4]				// Wort ins CRC_CRC schreiben
	
	// bis Ende vom String erreicht (String-Terminator 0x0 kommt in Wort vor) Prüfsumme berechnen
	// -> Speicheradresse des nachfolgenden Wortes kopieren
	mov r5, r7

	// Laden des ersten Bytes des nachfolgenden Wortes
	ldrb r6, [r5], #1
	teq r6, #0x0				// Überprüfen, ob Byte gleich 0x0
	beq finished				// falls ja: Einlese-Loop beenden
	
	// Laden des zweiten Bytes des nachfolgenden Wortes
	ldrb r6, [r5], #1
	teq r6, #0x0				// Überprüfen, ob Byte gleich 0x0
	beq finished				// falls ja: Einlese-Loop beenden
	
	// Laden des dritten Bytes des nachfolgenden Wortes
	ldrb r6, [r5], #1
	teq r6, #0x0				// Überprüfen, ob Byte gleich 0x0
	beq finished				// falls ja: Einlese-Loop beenden
	
	// Laden des vierten Bytes des nachfolgenden Wortes
	ldrb r6, [r5], #1
	teq r6, #0x0				// Überprüfen, ob Byte gleich 0x0
	beq finished				// falls ja: Einlese-Loop beenden
	
	// falls alle Bytes ungleich 0x0: kein String-Terminator und daher Loop erneut durchlaufen
	b loop_einlesen_und_pruefwert_ermittteln
	
	
finished:	
	
	ldr r11, [r4]					// Ergebniswort auslesen
	
	// Terminalausgabe des Strings
	ldr r0, =str_ausgabe_str		
	bl uart_putString
	ldr r0, =str
	bl uart_putString
	
	// Terminalausgabe des CRC-Prüfwerts vom String
	ldr r0, =str_ausgabe_crc_pruefwert
	bl uart_putString
	ldr r0, =str_prompt
	bl uart_putString
	mov r0, r11
	bl uart_putInt32
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
pruefwert: .word 0x0
str: .asciz "Praktikum und Werkstatt Technische Informatik, \nFernUniversitaet Hagen"
str_ausgabe_str: .asciz "Verwendeter String:\n"
str_prompt: .asciz "0x"
str_ausgabe_crc_pruefwert: .asciz "\n\nErmittelter CRC-Pruefwert zum String:\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten

.equ CLOCK_CYCLES_5MS, 41667 // Takte für ca 5ms

// GPIO PORT Konstanten

.equ PORTA_PCR10, 0x40049028
.equ PORTA_PCR11, 0x4004902C
.equ PORTA_PCR28, 0x40049070
.equ PORTA_PCR29, 0x40049074
.equ PORTA_PCR19, 0x4004904C
.equ PORTE_PCR26, 0x4004D068
.equ PORT_MUX_IRQC_BITMASK, 0x20100

.equ SIM_SCGC5_PORTA, 0x42900724	// Bit 9
.equ SIM_SCGC5_PORTE, 0x42900734	// Bit 13

.equ GPIOA_PDDR, 0x400FF014
.equ GPIOA_PDOR, 0x400FF000

.equ GPIOE_PDDR, 0x400FF114
.equ GPIOE_PDOR, 0x400FF100

.equ GPIOA_PDDR_BITMASK, 0x30000C00
.equ GPIOE_PDDR_BITMASK, 0x0

.equ GPIOA_PTOR, 0x400FF00C

.equ GPIOA_PDIR, 0x400FF010


// Interrupt/PIT Konstanten
.equ SIM_SCGC6_PIT, 0x429007DC

.equ SCR_VTOR, 0xE000ED08				// Basisadresse der IVT
.equ OFFSET_PIT, 0x00000154				// Offset für PIT1

.equ NVIC_ICPR2, 0xE000E288
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BITMASK, 1 << 5

.equ PIT_MCR, 0x40037000

.equ PIT_LDVAL1, 0x40037110
.equ PIT_LDVAL1_START_VALUE, 0x017D7840

.equ PIT_TCTRL1, 0x40037118
.equ PIT_TCTRL1_BITMASK, 0x3 			// Bit 0 und 1 müssen auf 1 gesetzt werden -> Binär: 11

.equ PIT_TFLG1_TIF, 0x4003711c

.equ DUAL_COUNTER_MAXIMUM, 0xFF

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	mov r5, #0x1
	ldr r9, =PORT_MUX_IRQC_BITMASK

// a) Aktivieren und Initialisieren der Ports, dass Funktion als GPIO selektiert
//    und Leitungen zu LEDs als Ausgänge und Leitungen zu Tastern als Eingänge verwendet werden

	// Port Control Register: die GPIO Funktion im MUX Bitfeld setzen und DMA Request auf fallende Flanke
	// folgende Ports werden für die LEDs verwendet nach Schaltplan: PTA10, PTA11, PTA28, PTA29
    ldr r4, =PORTA_PCR10
    str r9, [r4] 
    ldr r4, =PORTA_PCR11
    str r9, [r4] 
    ldr r4, =PORTA_PCR28
    str r9, [r4] 
    ldr r4, =PORTA_PCR29
    str r9, [r4]
    // folgende Ports werden für die Schalter verwendet nach Schaltplan: PTA19, PTE26
    ldr r4, =PORTA_PCR19
    str r9, [r4]
    ldr r4, =PORTE_PCR26
    str r9, [r4]
    
    // aktiviere  Port A und E am SIM
    
    ldr r4, =SIM_SCGC5_PORTA
    strb r5, [r4]
    ldr r4, =SIM_SCGC5_PORTE
    strb r5, [r4]

    // setze die Richtung der Ports:
    // A: Bits 10, 11, 28, 29 (LEDs) als Ausgang, Bit 19 (SW) als Eingang
    // E: Bit 26 (SW) als Eingang
    
    ldr r4, =GPIOA_PDDR
	ldr r9, =GPIOA_PDDR_BITMASK
    str r9, [r4]   
    ldr r4, =GPIOE_PDDR
	ldr r9, =GPIOE_PDDR_BITMASK
    str r9, [r4]
    
	// Toggle -> LEDs ausschalten
    ldr r4, =GPIOA_PTOR
	ldr r9, =GPIOA_PDDR_BITMASK
    str r9, [r4]   
    
    //setze danach GPIOA_PDOR Bits 10, 11, 28, 29 auf 0 -> logisches Level setzen
    
    ldr r4, =GPIOA_PDOR
	mov r9, #0x0
    str r9, [r4] 	
    
    // setze danach GPIOE_PDOR Bits auf 0
    
    ldr r4, =GPIOE_PDOR
	mov r9, #0x0
    str r9, [r4] 




// b) zyklischer 8-Bit Dualzähler, der im Sekundentakt durch PIT1 seinen Zustand ändert
//    Zählerstand mit Zeilenvorschub auf Terminal ausgeben sowie untere 4 Bits auf LEDs 1 bis 4
             
    // PIT1 initialisieren
    
    // a) Takt für PIT aktivieren (System Integration Module – SIM)
	ldr r4, =SIM_SCGC6_PIT
    str r5, [r4]
    
    // b) Index des Interrupt-Vektor zu PIT1 setzen
    
    ldr r8, =SCR_VTOR
    ldr r6, [r8]
    ldr r7, =OFFSET_PIT
    
    ldr r9, =isr_pit1				// Laden der Startadresse der ISR
    str r9, [r6, r7]				// Speichern der Adresse in die Interrupt-Vektor-Tabelle
    
    // c) eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC)
    
    ldr r4, =NVIC_ICPR2
    mov r9, #NVIC_BITMASK
    str r9, [r4] 
   
    // d) Interrupt zu PIT1 aktivieren (NVIC)
    
    ldr r4, =NVIC_ISER2
    str r9, [r4] 
    
    // e) alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
    
    // alle Pits aktivieren und (Bit 1)
    // im Debug-Modus laufen lassen (Bit 0)
    ldr r4, =PIT_MCR
    mov r9, #0x0					// Bit 0 und 1 müssen auf 0 gesetzt werden -> Binär: 00
    str r9, [r4] 
    
	// f) Startwert für PIT1 auf 1 Sekunde initialisieren

	ldr r4, =PIT_LDVAL1
	ldr r9, =PIT_LDVAL1_START_VALUE
    str r9, [r4] 
	
	// g) Interrupt zu PIT1 aktivieren (PIT-Modul) und
	// h) PIT1 aktivieren (PIT-Modul)
	ldr r4, =PIT_TCTRL1
	mov r9, #PIT_TCTRL1_BITMASK
    str r9, [r4]
    
    ldr r7, =benutzer_flag
    
    // PIT starten, bei Erreichen von 255 wieder von 0
	
loop_wait_for_flag:
	// Loop "wartet", bis die Interrupt Service Routine das Benutzer-Flag setzt
	
	// Variable gibt an, ob ein Button gepusht wurde während eines Loops -> zu Beginn auf null setzen
	ldr r4, =button_pushed
	str r9, [r4]
	
	
	ldrb r1, [r7]
	teq r1, #0x1						// Überprüfen, ob Benutzer-Flag gleich 1
	bne loop_wait_for_flag				// falls nein: Warte-Loop
	
	// Flag zurücksetzen
	mov r10, #0x0
	strb r10, [r7]
    
    
	ldr r10, =dual_counter					// Zeiger auf das Dual-Counter-Byte
	ldrb r11, [r10]							// Byte laden 
	add r11, r11, r5						// Byte um 1 erhöhen
	
    
    // Terminalausgabe und LED-Ausgabe Zählerstand    
    
    // Bitband-Alias-Adresse des Bits berechnen: Basisadresse + Bitnummer x 4	
    mov r7, #0x1C				// Bit 7 mal 4 = 28		
    sub r10, r10, #0x2000000	// Bitbandadresse berechnen (Bit 0)	
    add r10, r10, r10			// Bitbandadresse berechnen (Bit 0)
    add r10, r10, r7			// Addieren zur Basisadresse 
    
    ldr r4, =GPIOA_PDOR
	mov r9, #0x0
	mov r8, #0x1
    str r9, [r4]
    
    // Bit 7 ausgeben (Terminal)
    ldr r0, [r10, #-4]
    bl uart_putByte
    
    // Bit 6 ausgeben (Terminal)
    
    ldr r0, [r10, #-4]
    bl uart_putByte
    
    // Bit 5 ausgeben (Terminal)
    
    ldr r0, [r10, #-4]
    bl uart_putByte
    
    // Bit 4 ausgeben (Terminal)
    
    ldr r0, [r10, #-4]
    bl uart_putByte
    
    // Bit 3 ausgeben (Terminal + LED1)
    
    ldr r5, [r10, #-4]
    mov r0, r5
    bl uart_putByte
    cmp r5, 0x1
    ite eq
    streq r9, [r4]
    strne r8, [r4]
    
    // Bit 2 ausgeben (Terminal + LED2)
    
    ldr r5, [r10, #-4]
    mov r0, r5
    bl uart_putByte
    cmp r5, 0x1
    ite eq
    streq r9, [r4]
    strne r8, [r4]
    
    // Bit 1 ausgeben (Terminal + LED3)
    
    ldr r5, [r10, #-4]
    mov r0, r5
    bl uart_putByte
    cmp r5, 0x1
    ite eq
    streq r9, [r4]
    strne r8, [r4]
    
    // Bit 0 ausgeben (Terminal + LED4)
    
    ldr r5, [r10, #-4]
    mov r0, r5
    bl uart_putByte
    cmp r5, 0x1
    ite eq
    streq r9, [r4]
    strne r8, [r4]
    
    
    // Check ob Maximum erreicht ist 
    mov r1, #DUAL_COUNTER_MAXIMUM
    cmp r11, r1							// Vergleich des Erhöhten Elements mit dem zulässigen Maximum
    it eq								// falls gleich -> Überlauf
    streq r5, [r11]						// Rücksetzen des Counters auf 0
    
    
    bl check_for_button_push_sw1
    
    // wenn während des Loops kein Button gedrückt wurde, ist die variable noch null -> Unterprogramm aufrufen, dass mod auf "0" setzt
    ldr r4, =button_pushed
    ldr r5, [r4]
    cmp r5, #0x0
    it eq
    bleq no_button_push
    
    
// d) durch SW1 Zählrichtung hoch/runter geändert
//    durch SW2 Zähler gestartet/gestoppt
    	// Stopp-Loop
// e) Funktionen aus d auch über Terminal steuerbar, + hochzählen, - runterzählen, s starten/stoppen   
    
    
    b loop_wait_for_flag				// Erneutes starten des Loops (und warten auf Interrupt durch PIT1)


end:
	b end
	
.thumb_func
no_button_push:
// Unterprogramm setzt mod auf 0

	push {lr}
	
	mov r1, #0x0
	ldr r0, =mod
	str r1, [r0]
	
	pop {pc}					// Rücksprung

	
.thumb_func
check_for_button_push_sw1:
//nicht blockierendes Unterprogramm zur Abfrage des Tasters SW1 (fallende Flanke, "Polling")
    
    push {lr}
    
    // SW1 -> PTA19 -> Bit 19
    
    ldr r2, =GPIOA_PDIR		
    ldr r1, [r2]			// Lesen des Port Data Input Registers
    and r1, r1, #0x40000	// mit Bitmaske verUnden (1 bei Bitmaske bei Bit 19)
    
    cmp r1, 0x0				// wenn gleich 0 -> kein SW1 gedrückt
    bne not_pushed_jump   	// überspringen des Variablen-Setzens auf 1
    
    
    // nun muss zusätzlich der 5ms Debounce eingehalten werden
    // Loop: warten 5 ms und erneut checken
    
    ldr r3, =CLOCK_CYCLES_5MS	 		// Laden der Loop-Zyklen-Anzahl für die Dauer des Unterprogramms von einer Sekunde
loop_5_ms:
    subs r3, r3, #1						// Zaehler dekrementieren
    bne loop_5_ms						// solange Zaehler noch nicht null    
    
    
    ldr r1, [r2]			// Lesen des Port Data Input Registers
    and r1, r1, #0x40000	// mit Bitmaske verUnden (1 bei Bitmaske bei Bit 19)
    
    cmp r1, 0x0				// wenn gleich 0 -> kein SW1 gedrückt
    bne not_pushed_jump   	// überspringen des Variablen-Setzens auf 1
    
    mov r1, #0x1
    
    // button_pushed-Information auf 1 setzen
    ldr r3, =button_pushed
    str r1, [r3]
    
    // mod auf 1 setzen
    ldr r0, =mod
    str r1, [r0]

not_pushed_jump:

	pop {pc}					// Rücksprung
	

// Interrupt Service Routine zu SW2
.thumb_func
isr_sw2:
	
	mov r1, #0x2
    
    // button_pushed-Information auf 2 setzen
    ldr r3, =button_pushed
    str r1, [r3]
    
    // mod auf 2 setzen
    ldr r0, =mod
    str r1, [r0]
	
	bx lr					// Rücksprung



// Interrupt Service Routine zu PIT1
.thumb_func
isr_pit1:
	// Register-Sicherung hier nicht extra notwendig, ISR möglichst knapp halten

	// Interrupt-Flag zum PIT1 zurücksetzen
	ldr r1, =PIT_TFLG1_TIF
	mov r2, #0x1
    strb r2, [r1]
    	
	// Setzen eines Benutzerflags, das dem Hauptprogramm den Ablauf einer Sekunde anzeigt
	ldr r1, =benutzer_flag
	strb r2, [r1]

	bx lr					// Rücksprung
	
	

/*** Datenbereich (ab 0x20000000) ***/
.data
mod: .byte 0x0
dual_counter: .byte 0x0
benutzer_flag: .byte 0x0
button_pushed: .byte 0x0
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// GPIO PORT Konstanten

.equ SIM_SCGC5_PORTA, 0x42900724			// Bit 9
.equ SIM_SCGC5_PORTE, 0x42900734			// Bit 13

.equ PORTA_PCR10, 0x40049028
.equ PORTA_PCR11, 0x4004902C
.equ PORTA_PCR28, 0x40049070
.equ PORTA_PCR29, 0x40049074

.equ PORT_MUX_BITMASK, 0x100				// Konfiguration: MUX: GPIO

.equ GPIOA_PDDR, 0x400FF014
.equ GPIOA_PDDR_OUT_BITMASK, 0x30000C00

.equ GPIOA_PTOR, 0x400FF00C
.equ GPIOA_PDOR, 0x400FF000

.equ GPIOA_PDIR, 0x400FF010

.equ GPIOA_PDOR_PORT10_BITMASK, 0x400
.equ GPIOA_PDOR_PORT11_BITMASK, 0x800
.equ GPIOA_PDOR_PORT28_BITMASK, 0x10000000
.equ GPIOA_PDOR_PORT29_BITMASK, 0x20000000

// Bit-Band-Konstanten der LEDs
__BBREG	E1, GPIOA_PDOR, 11
__BBREG	E2, GPIOA_PDOR, 28
__BBREG	E3, GPIOA_PDOR, 29
__BBREG	E4, GPIOA_PDOR, 10

// Interrupt/PIT Konstanten
.equ SIM_SCGC6_PIT, 0x429007DC

.equ SCR_VTOR, 0xE000ED08				// Basisadresse der IVT
.equ OFFSET_PIT, 0x00000154				// Offset für PIT1

.equ NVIC_ICPR2, 0xE000E288
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BITMASK, 0x20					// Aktivieren der Interrupts: Bit 5 (PIT1)

.equ PIT_MCR, 0x40037000

.equ PIT_LDVAL1, 0x40037110
.equ PIT_LDVAL1_START_VALUE, 0x017D7840

.equ PIT_TCTRL1, 0x40037118
.equ PIT_TCTRL1_BITMASK, 0x3 			// Bit 0 und 1 müssen auf 1 gesetzt werden -> Binär: 11

.equ PIT_TFLG1, 0x4003711c

// ADC1 Konstanten

.equ SIM_SCGC3_ADC1, 0x4290066C
// - Adressen zur Kalibrierung
.equ ADC1_SC3, 0x400BB024
.equ ADC1_PG, 0x400BB02C
.equ ADC1_CLPD, 0x400BB034
.equ ADC1_CLPS, 0x400BB038
.equ ADC1_CLP4, 0x400BB03C
.equ ADC1_CLP3, 0x400BB040
.equ ADC1_CLP2, 0x400BB044
.equ ADC1_CLP1, 0x400BB048
.equ ADC1_CLP0, 0x400BB04C

// Bitmasks zur Kalibrierung
.equ ADC1_SC3_CAL_BITMASK, 0x80			// Bit 7 (CAL) setzen

// Bit-Band-Konstanten zur Konfiguration
__BBREG	COCO, ADC1_SC1A, 7
__BBREG	CALF, ADC1_SC3, 6

// - Adressen zur Konfiguration
.equ ADC1_CFG1, 0x400BB008
.equ ADC1_CFG2, 0x400BB00C
.equ ADC1_SC2, 0x400BB020
.equ ADC1_SC3, 0x400BB024
.equ ADC1_SC1A, 0x400BB000

// Bitmasks zur Konfiguration
.equ ADC1_CFG1__16BIT_BITMASK, 0x6C	// MODE: 11 -> 16-bit conversion; ADIV: 11 -> divide ratio is 8 and the clock rate is (input clock)/8
.equ ADC1_CFG1__12BIT_BITMASK, 0x64
.equ ADC1_CFG1__10BIT_BITMASK, 0x68
.equ ADC1_CFG1__8BIT_BITMASK, 0x60
.equ ADC1_SC3_BITMASK, 0xE		// AVGS: 10 -> 16 sample averaged; AVGE: 1 -> Hardware average function enabled; ADCO: 1 -> Continuous conversions or sets of conversions 
.equ ADC1_SC1A_BITMASK, 0x14	// ADCH: 10100 -> When DIFF=0, AD20 is selected as input; when DIFF=1, it is reserved 
								// (Kanal AD20 für den Pin ADC1_DM1); Interrupt disabled
.equ ADC1_SC1A_CONVERTER_OFF_BITMASK, 0x1F					

// - Adresse des Ergebnis-Registers
.equ ADC1_RA, 0x400BB010
.equ MSB_BITMASK, 0x8000

// - Intervallgrenzen  -
// Genauigkeit von 8Bit -> Maximum bei 0xFF
.equ INTERVAL_8BIT_0, 0x20
.equ INTERVAL_8BIT_1, 0x40
.equ INTERVAL_8BIT_2, 0x60
.equ INTERVAL_8BIT_3, 0x80
.equ INTERVAL_8BIT_4, 0x9f
.equ INTERVAL_8BIT_5, 0xbf
.equ INTERVAL_8BIT_6, 0xdf

// Genauigkeit von 10Bit -> Maximum bei 0x3FF
.equ INTERVAL_10BIT_0, 0x66
.equ INTERVAL_10BIT_1, 0xcd
.equ INTERVAL_10BIT_2, 0x133
.equ INTERVAL_10BIT_3, 0x199
.equ INTERVAL_10BIT_4, 0x200
.equ INTERVAL_10BIT_5, 0x266
.equ INTERVAL_10BIT_6, 0x2cc
.equ INTERVAL_10BIT_7, 0x332
.equ INTERVAL_10BIT_8, 0x399

// Genauigkeit von 12Bit -> Maximum bei 0xFFF
.equ INTERVAL_12BIT_0, 0x155
.equ INTERVAL_12BIT_1, 0x2ab
.equ INTERVAL_12BIT_2, 0x400
.equ INTERVAL_12BIT_3, 0x555
.equ INTERVAL_12BIT_4, 0x6aa
.equ INTERVAL_12BIT_5, 0x800
.equ INTERVAL_12BIT_6, 0x955
.equ INTERVAL_12BIT_7, 0xaaa
.equ INTERVAL_12BIT_8, 0xbff
.equ INTERVAL_12BIT_9, 0xd55
.equ INTERVAL_12BIT_10, 0xeaa

// Genauigkeit von 12Bit -> Maximum bei 0xFFFF
.equ INTERVAL_16BIT_0, 0x1000
.equ INTERVAL_16BIT_1, 0x2000
.equ INTERVAL_16BIT_2, 0x3000
.equ INTERVAL_16BIT_3, 0x4000
.equ INTERVAL_16BIT_4, 0x5000
.equ INTERVAL_16BIT_5, 0x6000
.equ INTERVAL_16BIT_6, 0x7000
.equ INTERVAL_16BIT_7, 0x8000
.equ INTERVAL_16BIT_8, 0x9000
.equ INTERVAL_16BIT_9, 0xa000
.equ INTERVAL_16BIT_10, 0xb000
.equ INTERVAL_16BIT_11, 0xc000
.equ INTERVAL_16BIT_12, 0xd000
.equ INTERVAL_16BIT_13, 0xe000
.equ INTERVAL_16BIT_14, 0xf000

// Numbers
.equ ZERO, 0x0
.equ ONE, 0x1
.equ TWO, 0x2
.equ THREE, 0x3
.equ FOUR, 0x4
.equ FIVE, 0x5
.equ SIX, 0x6
.equ SEVN, 0x7
.equ EIGHT, 0x8
.equ NINE, 0x9
.equ TEN, 0xa
.equ ELEV, 0xb
.equ TWEL, 0xc
.equ THIR, 0xd
.equ FOURT, 0xe
.equ FIVT, 0xf
.equ SIXT, 0x10

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	mov r5, #0x1	
	mov r7, #0x0

	// Programmieren des Analog-Digital-Wandlers ADC1
	
	// Sein Analog- Eingang ist über ein Potentiometer mit der positiven Betriebsspannung verbunden.
	// Die Auflösung (Genauigkeit) des Wandlers kann auf 8, 10, 12 und 16 bit eingestellt werden.
	// Bevor Sie mit der Programmierung beginnen, sollten Sie sich mit den Grundlagen der A/D-Wandlung ausein- andersetzen und insbesondere klären,
	// nach welchem Verfahren der ADC1 arbeitet, wie groß die relevanten Spannungen (Betriebsspannung, Referenzspannung usw.) sind
	// und an welchem Pin bzw. welcher Portleitung das Potentiometer bzw. der ADC1 angeschlossen sind.
	
	
	// a) Schreiben Sie eine Funktion, die die Kalibrierung des ADC gemäß des Handbuchs realisiert. Kalibrieren Sie den ADC mit Hilfe dieser Funktion.
	
	// Aktivieren des ADC1 im SIM
	ldr r4, =SIM_SCGC3_ADC1
    str r5, [r4]
	
	bl calibrate_adc					// Aufrufen des Unterprogramms zur Kalibrierung
	
	ldr r0, =str_kalibrierung_erfolgreich
	bl uart_putString
	
	// b) Initialisieren Sie den A/D-Wandler ADC1 so, dass
	//		- er keine Interrupts erzeugt
	//		- er mit dem Bus-Takt (Bus Clock) und mit einem Wandlertakt (input clock) von 3,125 MHz arbeitet
	//		- er mit einer Wandlungsgenauigkeit von 16 bit (vorzeichenlos) arbeitet
	//		- er kontinuierlich wandelt und über jeweils 16 Werte (Samples) mittelt
	
	ldr r4, =ADC1_CFG1					// Laden der Adresse des ADC Configuration Register 1 
	ldr r6, =ADC1_CFG1__16BIT_BITMASK	
	str r6, [r4]
	
	ldr r4, =ADC1_CFG2					// Laden der Adresse des ADC Configuration Register 2
	str r7, [r4]
	
	ldr r4, =ADC1_SC2					// Laden der Adresse des Status and Control Register 2 
	str r7, [r4]
	
	ldr r4, =ADC1_SC3					// Laden der Adresse des  Status and Control Register 3
	ldr r6, =ADC1_SC3_BITMASK
	str r6, [r4]
	
	ldr r4, =ADC1_SC1A					
	ldr r6, =ADC1_SC1A_BITMASK			// muss "zuletzt" geschehen!
	str r6, [r4]

	
	// c) Initialisieren Sie den Periodic Interrupt Timer PIT1 so, dass er nach jeweils einer Sekunde einen Interrupt auslöst.
    
    // 1) Takt für PIT aktivieren (System Integration Module – SIM)
	ldr r4, =SIM_SCGC6_PIT
    str r5, [r4]
    
    // 2) Index des Interrupt-Vektor zu PIT1 setzen
    
    ldr r8, =SCR_VTOR
    ldr r6, [r8]
    
    ldr r9, =isr_pit1						// Laden der Startadresse der ISR
    str r9, [r6, #OFFSET_PIT]				// Speichern der Adresse in die Interrupt-Vektor-Tabelle
    
    // 3) eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC)
    
    ldr r4, =NVIC_ICPR2
    mov r9, #NVIC_BITMASK
    str r9, [r4] 
   
    // 4) Interrupt zu PIT1 aktivieren (NVIC)
    
    ldr r4, =NVIC_ISER2
    str r9, [r4] 
    
    // 5) alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
    
    // alle Pits aktivieren und (Bit 1)
    // im Debug-Modus laufen lassen (Bit 0)
    ldr r4, =PIT_MCR
    str r7, [r4] 							// Bit 0 und 1 müssen auf 0 gesetzt werden -> Binär: 00
    
	// 6) Startwert für PIT1 auf 1 Sekunde initialisieren

	ldr r4, =PIT_LDVAL1
	ldr r9, =PIT_LDVAL1_START_VALUE
    str r9, [r4] 
    
    // 7) Interrupt zu PIT1 aktivieren (PIT-Modul) und
	// 8) PIT1 aktivieren (PIT-Modul)
	ldr r4, =PIT_TCTRL1
	mov r9, #PIT_TCTRL1_BITMASK
    str r9, [r4]
	
	
	
	// d) Initialisieren Sie PortA so, dass die LEDs E1 bis E4 angesteuert werden können.
	
	// aktiviere Port A am SIM
    
    ldr r4, =SIM_SCGC5_PORTA
    strb r5, [r4]

	// Port Control Register: die GPIO Funktion im MUX Bitfeld setzen und für SW2 Interrupt Request auf fallende Flanke setzen
	// folgende Ports werden für die LEDs verwendet nach Schaltplan: PTA10, PTA11, PTA28, PTA29
	
	ldr r10, =PORT_MUX_BITMASK
	
    ldr r4, =PORTA_PCR10
    str r10, [r4] 
    ldr r4, =PORTA_PCR11
    str r10, [r4] 
    ldr r4, =PORTA_PCR28
    str r10, [r4] 
    ldr r4, =PORTA_PCR29
    str r10, [r4]
	
	// Setzen der Richtung der Ports (Input - Output) im jeweiligen Port Data Direction Register
    // Port A: Bits 10, 11, 28, 29 (LEDs) als Ausgang
    ldr r4, =GPIOA_PDDR
    ldr r6, [r4]							// Laden des Register-Wertes
	ldr r9, =GPIOA_PDDR_OUT_BITMASK			// Laden der Bitmaske für die ODER-Verknüpfung
	orr r6, r6, r9							// Maskieren mit der ODER-Verknüpfung -> jew. Bits setzen
	str r6, [r4]   							// Zurückspeichern des Ergebnisses



	// Laden der Adresse des ADC Data Result Registers und des Stopp-Flags
    ldr r11, =ADC1_RA
    ldr r12, =stop_flag
    
loop_sekunde:

	// Überprüfung, ob ein Zeichen in das Terminal eingegeben wurde
	bl uart_charPresent						// Funktion gibt 0 in R0 zurück, falls kein char eingegeben wurde
	teq r0, #0								// Überprüfung des Rückgabewertes auf Gleichheit mit 0
	beq skip_char_check						// falls gleich: kein char eingegeben -> char-Check überspringen
	
	bl uart_getChar							// Laden des Zeichens in R0
	cmp r0, #'s'							
	beq funktion_start_stopp
	
	// falls eine 0, 1, 2 oder 3 eingegeben wurde -> Funktion zur Genauigkeitsänderung aufrufen
	cmp r0, #'0'							
	beq funktion_genauigkeit_aendern
	cmp r0, #'1'
	beq funktion_genauigkeit_aendern
	cmp r0, #'2'							
	beq funktion_genauigkeit_aendern
	cmp r0, #'3'
	beq funktion_genauigkeit_aendern
	
	
skip_char_check:
	
	// check ob Stopp-Flag aktiv
	ldrb r6, [r12]							// Lade das Stopp-Flag
	cmp r6, #0x1							// falls es auf 1 gesetzt ist
	bhs loop_sekunde						// Counter ist aktuell gestoppt un darf nicht zählen, Rücksprung zum Haupt-Loop
	b loop_wait_for_flag					// ansonsten: in den Wait-Loop, um auf PIT1 (Interrupt) zu warten
	
funktion_start_stopp:
	// Flag invertieren, dass Ausgabe gestarted/gestoppt wurde und entsprechende Terminalausgabe
	
	ldrb r6, [r12]
	ldr r4, =ADC1_SC1A
	mov r9, #ADC1_SC1A_BITMASK
	mov r10, #ADC1_SC1A_CONVERTER_OFF_BITMASK
	
	cmp r6, #0x1
	beq branch_gestartet								// falls ja: Wandler muss gestartet werden, falls nein: Wandler muss gestoppt werden

branch_gestoppt:
	
	mov r6, #0x1										// falls nein: Flag auf 1 setzen
	strb r6, [r12]										// Flag sichern
	ldr r0, =str_wandlung_und_ausgabe_gestoppt			// und entsprechenden Zeiger auf String laden
	bl uart_putString									// String ausgeben
	str r10, [r4]
										
	b loop_sekunde										// Rücksprung zum Loop-Anfang
	
branch_gestartet:

	mov r6, #0x0										// falls ja: Flag auf 0 zurücksetzen
	strb r6, [r12]										// Flag sichern
	ldr r0, =str_wandlung_und_ausgabe_gestartet			// und entsprechenden Zeiger auf String laden
	bl uart_putString									// String ausgeben
	str r9, [r4]
	
	b loop_sekunde										// Rücksprung zum Loop-Anfang

funktion_genauigkeit_aendern:
	
	// zuerst wird geprüft, ob Programm im Stopp-Modus
	ldrb r6, [r12]							// Lade das Stopp-Flag
	cmp r6, #0x1							// falls es nicht auf 1 gesetzt ist
	bne loop_wait_for_flag					// dann nicht im Stopp-Modus, in den Wait-Loop, um auf PIT1 (Interrupt) zu warten
	
	ldr r6, =ADC1_CFG1						// Laden der Adresse des ADC Configuration Register 1
	
	// in r0 ist der Genauigkeits-Auswahlswert gesichert
	
	// da die Eingaben als char interpretiert werden , muss die Zugehörige ASCII-Zahl des jeweiligen Zeichens abgefragt werden
	
	cmp r0, #0x30
	itttt eq								// Wurde eine 8 eingegeben?
	moveq r9, #ADC1_CFG1__8BIT_BITMASK		
	streq r9, [r6]							// Speichern der Bitmaske im ADC1_CFG1, um eine Genauigkeit von 8 Bit einzustellen
	moveq r6, #EIGHT						// Laden der später zu speichernden Genauigkeitsstufen in R6
	ldreq r0, =str_genauigkeit_8_stufen		// laden des später auszugebenden Strings in R0
	
	cmp r0, #0x31							// Wurde eine 10 eingegeben?
	itttt eq
	moveq r9, #ADC1_CFG1__10BIT_BITMASK
	streq r9, [r6]
	moveq r6, #TEN
	ldreq r0, =str_genauigkeit_10_stufen
	
	cmp r0, #0x32							// Wurde eine 12 eingegeben?
	itttt eq
	moveq r9, #ADC1_CFG1__12BIT_BITMASK
	streq r9, [r6]
	moveq r6, #TWEL
	ldreq r0, =str_genauigkeit_12_stufen
	
	cmp r0, #0x33							// Wurde eine 16 eingegeben?
	itttt eq
	moveq r9, #ADC1_CFG1__16BIT_BITMASK
	streq r9, [r6]
	moveq r6, #SIXT
	ldreq r0, =str_genauigkeit_16_stufen
	
	bl uart_putString						// geänderte Stufe auf dem Terminal ausgeben
	
	// geänderte Genauigkeitsstufen in entsprechender Variable sichern
	ldr r9, =aktuelle_genauigkeit
	strb r6, [r9]
	
	// ADC1 "reaktivieren"
	ldr r4, =ADC1_SC1A
	ldr r6, =ADC1_SC1A_BITMASK
	str r6, [r4]
	
	b loop_sekunde							// Programm noch im Stopp-Modus -> Rücksprung


loop_wait_for_flag:
	// Loop "wartet", bis die Interrupt Service Routine das Benutzer-Flag setzt
	
	// Benutzer-Flag laden und Überprüfen, ob es durch einen Interrupt ausgelöst von PIT1 gesetzt wurde
	ldr r10, =pit1_benutzer_flag
	ldrb r1, [r10]
	teq r1, #0x1
	bne loop_wait_for_flag					// falls nein: im Warte-Loop bleiben
	
	// Flag zurücksetzen
	strb r7, [r10]
	
	// i)  Vom PIT1 gesteuert, soll nach jeweils einer Sekunde der vom ADC1 ermittelte Digitalwert als (4-stelliger) Hexadezimalwert auf dem Terminal ausgegeben werden.
	ldr r0, =str_adc1_digitalwert
	bl uart_putString
	ldr r6, [r11]							// aktuellen Digitalwert laden
	mov r0, r6
	bl uart_putInt16						// Digitalwert ausgeben
	
	/* Kommentar: 
	Vorteile von fest codierten, bedingten Strings zur Berechnung der Intervalle in jedem Loop:
	- die genauen Spannungsgrenzen einer Stufe lassen sich flexibler und leichter angeben 
	- die Codeausführung ist braucht weniger Takte pro Zyklus
	Nachteile:
	- erhöhter Speicherverbrauch durch 46 Strings
	*/
	
	ldr r9, =aktuelle_genauigkeit			// Laden der aktuellen Genauigkeitsstufen-Einstellung
	ldrb r10, [r9]
	           
	// je nach Eistellung wird zur entsprechenden Marke mit der dort vom Digitalwert bedingten Auswahl des Intervall-Stufen-Strings gesprungen
	cmp r10, #10
	beq genauigkeit_10
	cmp r10, #12
	beq genauigkeit_12
	cmp r10, #16
	beq genauigkeit_16
	
	// Die nun stattfinden Intervall- und Stufen-Auswahlen sind immer gleich aufgebaut:
	// Es werden aufsteigend die für der Genauigkeits-Einstellung entsprechenden Stufen-Grenzen des Digitalwertes geladen und jeweils mit dem aktuellen Digitalwert verglichen
	// -> falls dieser darunter liegt, befindet man sich in der betrachteten Stufe
	// -> dann wird die Zahl der entsprechenden Stufe in R6 gespeichert, der auszugebende String mit Spannungsbereich und Stufenangabe in R0 geladen und zur Ausgabe gesprungen

genauigkeit_8:
	
	ldr r1, =INTERVAL_8BIT_0
	cmp r6, r1
	ittt lo
	movlo r6, #ONE
	ldrlo r0, =str_genauigkeitsspanne_8bit_stufe_0
	blo genauigkeitsspanne_ausgewaehlt_8
	
	ldr r1, =INTERVAL_8BIT_1
	cmp r6, r1
	ittt lo
	movlo r6, #TWO
	ldrlo r0, =str_genauigkeitsspanne_8bit_stufe_1
	blo genauigkeitsspanne_ausgewaehlt_8
	
	ldr r1, =INTERVAL_8BIT_2
	cmp r6, r1
	ittt lo
	movlo r6, #THREE
	ldrlo r0, =str_genauigkeitsspanne_8bit_stufe_2
	blo genauigkeitsspanne_ausgewaehlt_8
	
	ldr r1, =INTERVAL_8BIT_3
	cmp r6, r1
	ittt lo
	movlo r6, #FOUR
	ldrlo r0, =str_genauigkeitsspanne_8bit_stufe_3
	blo genauigkeitsspanne_ausgewaehlt_8
	
	ldr r1, =INTERVAL_8BIT_4
	cmp r6, r1
	ittt lo
	movlo r6, #FIVE
	ldrlo r0, =str_genauigkeitsspanne_8bit_stufe_4
	blo genauigkeitsspanne_ausgewaehlt_8
	
	ldr r1, =INTERVAL_8BIT_5
	cmp r6, r1
	ittt lo
	movlo r6, #SIX
	ldrlo r0, =str_genauigkeitsspanne_8bit_stufe_5
	blo genauigkeitsspanne_ausgewaehlt_8
	
	ldr r1, =INTERVAL_8BIT_6
	cmp r6, r1
	ittt lo
	movlo r6, #SEVN
	ldrlo r0, =str_genauigkeitsspanne_8bit_stufe_6
	blo genauigkeitsspanne_ausgewaehlt_8
	
	ldr r0, =str_genauigkeitsspanne_8bit_stufe_7
	b genauigkeitsspanne_ausgewaehlt_8

genauigkeitsspanne_ausgewaehlt_8:
	
	bl uart_putString						// entsprechenden String der Genauigkeitsstufe ausgeben
	b led_ausgabe							// springe zur LED-Ausgabe

genauigkeit_10:

	ldr r1, = INTERVAL_10BIT_0
	cmp r6, r1
	ittt lo
	movlo r6, #ONE
	ldrlo r0, =str_genauigkeitsspanne_10bit_stufe_0
	blo genauigkeitsspanne_ausgewaehlt_10
	
	ldr r1, = INTERVAL_10BIT_1
	cmp r6, r1
	ittt lo
	movlo r6, #TWO
	ldrlo r0, =str_genauigkeitsspanne_10bit_stufe_1
