	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_0
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_1
	cmp r6, r1
	ittt lo
	movlo r6, #TWO
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_1
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_2
	cmp r6, r1
	ittt lo
	movlo r6, #THREE
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_2
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_3
	cmp r6, r1
	ittt lo
	movlo r6, #FOUR
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_3
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_4
	cmp r6, r1
	ittt lo
	movlo r6, #FIVE
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_4
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_5
	cmp r6, r1
	ittt lo
	movlo r6, #SIX
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_5
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_6
	cmp r6, r1
	ittt lo
	movlo r6, #SEVN
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_6
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_7
	cmp r6, r1
	ittt lo
	movlo r6, #EIGHT
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_7
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_8
	cmp r6, r1
	ittt lo
	movlo r6, #NINE
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_8
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_9
	cmp r6, r1
	ittt lo
	movlo r6, #TEN
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_9
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_10
	cmp r6, r1
	ittt lo
	movlo r6, #ELEV
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_10
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_11
	cmp r6, r1
	ittt lo
	movlo r6, #TWEL
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_11
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r1, =INTERVAL_16BIT_12
	cmp r6, r1
	ittt lo
	movlo r6, #THIR
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_12
	blo genauigkeitsspanne_ausgewaehlt_16

	ldr r1, =INTERVAL_16BIT_13
	cmp r6, r1
	ittt lo
	movlo r6, #FOURT
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_13
	blo genauigkeitsspanne_ausgewaehlt_16

	ldr r1, =INTERVAL_16BIT_14
	cmp r6, r1
	ittt lo
	movlo r6, #FIVT
	ldrlo r0, =str_genauigkeitsspanne_16bit_stufe_14
	blo genauigkeitsspanne_ausgewaehlt_16
	
	ldr r0, =str_genauigkeitsspanne_16bit_stufe_15
	b genauigkeitsspanne_ausgewaehlt_16

genauigkeitsspanne_ausgewaehlt_16:
	
	bl uart_putString						// entsprechenden String der Genauigkeitsstufe ausgeben
	
led_ausgabe:
	
	// Am Ende jedes Loops werden die LEDs entsprechend der Genauigkeisstufe geschaltet
	
	// LED 1
	ldr r0, =E1								// Bit-Band-Alias-Adresse der LED E1 laden
	bic r2, r5, r6							// R2 = R5 AND NOT R6; Bit 0 (R5 = 1) der Genauigkeisstufe (R6) invertiert nach R2 schreiben 
	str r2, [r0]							// in Bitband-Alias-Register sichern
	
	// LED 2
	ldr r0, =E2
	bic r2, r5, r6, LSR #1					// R2 = R5 AND NOT (R6 >> 1) -> Bit 1 der Genauigkeisstufe (R6) invertiert nach R2 schreiben 
	str r2, [r0]
	
	// LED 3
	ldr r0, =E3
	bic r2, r5, r6, LSR #2					// R2 = R5 AND NOT (R6 >> 2) -> Bit 2 der Genauigkeisstufe (R6) invertiert nach R2 schreiben 
	str r2, [r0]
	
	// LED 4
	ldr r0, =E4
	bic r2, r5, r6, LSR #3					// R2 = R5 AND NOT (R6 >> 3) -> Bit 3 der Genauigkeisstufe (R6) invertiert nach R2 schreiben 
	str r2, [r0]
	
	
	b loop_sekunde
	
	

.thumb_func
calibrate_adc:
// Diese Funktion Kalibriert den ADC1

start_calibration:
	// Starten der automatischen Kalibrierung
	ldr r3, =ADC1_SC3						// Laden des Status und Kontrollregister 3
	ldr r2, [r3]							// Laden der aktuellen Konfiguration
	ldr r1, =ADC1_SC3_CAL_BITMASK
	orr r2, r2, r1							// OR-Maskieren (Konfiguration siehe oben) -> die jeweiligen Bits setzen
	str r2, [r3]   							// Zurückspeichern des Ergebnisses ins Register
	
	// Um sicherzugehen, ob die Kalibrierung erfolgreich war, muss man CALF checken, nachdem COCO gestzt wurde (bzw. alternativ ein Interrupt ausgelöst wurde)
	
	ldr r1, =COCO
finish_calibration_loop:
	// Loop wartet so lange, bis Kalibrierung beendet wird
	ldrb r2, [r1]
	teq r2, #0x1
	bne finish_calibration_loop					// falls nein: im Warte-Loop bleiben
	
	// CALF-Bit im ADC1_SC3 checken, ob Kalibrierung erfolgreich war (muss dazu 0 sein)
	ldr r1, =CALF
	ldrb r2, [r1]
	teq r2, #0x0
	beq calibration_successful
	
	b start_calibration

calibration_successful:

	// Laden und aufeinander-Addieren aller Werte der Plus Side General Calibration Value Register
	
	mov r3, 0x0					// Laden des Startwerts 0 in das Register 3 (auf diesen werden die folgenden Registerwerte addiert)
									
	ldr r1, =ADC1_CLPD
	ldr r2, [r1]
	add r3, r3, r2
	 
	ldr r1, =ADC1_CLPS
	ldr r2, [r1]
	add r3, r3, r2
	 
	ldr r1, =ADC1_CLP4
	ldr r2, [r1]
	add r3, r3, r2
	 
	ldr r1, =ADC1_CLP3
	ldr r2, [r1]
	add r3, r3, r2
	 
	ldr r1, =ADC1_CLP2
	ldr r2, [r1]
	add r3, r3, r2
	 
	ldr r1, =ADC1_CLP1
	ldr r2, [r1]
	add r3, r3, r2
	 
	ldr r1, =ADC1_CLP0
	ldr r2, [r1]
	add r3, r3, r2
	 
	lsr r4, r4, #1							// Die Summe durch 2 teilen (durch Rechts-Verschiebung)
	orr r3, #MSB_BITMASK					// MSB setzen durch verODERn
	 
	ldr r2, =ADC1_PG
	str r3, [r2]							// Ergebnis in das Register ADC1_PG schreiben

    bx lr									// Rücksprung zum Hauptprogramm


// Interrupt Service Routine zu PIT1
.thumb_func
isr_pit1:
	// Register-Sicherung hier nicht extra notwendig, ISR möglichst knapp halten

	// Interrupt-Flag zum PIT1 zurücksetzen
	ldr r1, =PIT_TFLG1
	mov r2, #0x1
    str r2, [r1]
    
	// Setzen eines Benutzerflags, das dem Hauptprogramm den Ablauf einer Sekunde anzeigt
	ldr r1, =pit1_benutzer_flag
	strb r2, [r1]

	bx lr									// Rücksprung


/*** Datenbereich (ab 0x20000000) ***/
.data
