// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified
 
// Bit-Band Konstanten

__BBREG SIM_PORTD , SIM_SCGC5 , 12
__BBREG BUSY_FLAG , I2C0_S , 5
__BBREG IICIF_FLAG , I2C0_S , 1

// Registeradressen

.equ SIM_SCGC5, 		0x40048038
.equ SIM_SCGC4_I2C0, 	0x42900698
.equ SIM_SCGC5_PORTA, 	0x42900724
.equ SIM_SCGC6_PIT, 	0x429007DC

.equ PIT_MCR,       0x40037000
.equ PIT_LDVAL1,    0x40037110
.equ PIT_TCTRL1,    0x40037118
.equ PIT_TFLG1,     0x4003711C

.equ NVIC_ISER2, 	0xe000e108

.equ I2C0_F, 	0x40066001
.equ I2C0_C1, 	0x40066002
.equ I2C0_C2, 	0x40066005
.equ I2C0_SMB, 	0x40066008
.equ I2C0_S, 	0x40066003
.equ I2C0_D, 	0x40066004

.equ PORTD_PCR8, 0x4004C020
.equ PORTD_PCR9, 0x4004C024
.equ GPIOD_PDDR, 0x400FF0D4
.equ GPIOD_PDOR, 0x400FF0C0
.equ GPIOD_PDIR, 0x400FF0D0

.equ SCR_VTOR,		0xE000ED08	// Register für die Interrupt-Vektor-Tabelle (IVT)

// Setter und Bitmasks

.equ I2C0_F_SET, 0x12 		// MULT 0x00 (mul = 1) und ICR 0x12 (SCL divider = 64) entspricht ca. 391 Baudrate (-> ca. 391 kHz)
.equ I2C0_C1_SET, 0xC0		// IICEN und IICIE aktiviert, Rest auf 0 gesetzt (restliche Bits werden erst zu späteren Zeitpunkten auf 1 initialisiert)

.equ I2C0_C1_RSTA_BITMASK, 	0x4  	// Bit 2
.equ I2C0_C1_TXAK_BITMASK, 	0x8		// Bit 3
.equ I2C0_C1_TX_BITMASK, 	0x10  	// Bit 4
.equ I2C0_C1_MST_BITMASK, 	0x20  	// Bit 5

.equ I2C0_S_IICIF_BITMASK, 	0x2 	// Bit 1
.equ I2C0_S_BUSY_BITMASK, 	0x20 	// Bit 5

.equ PD8_9, 0x300 			// Maske fuer PD8 und PD9 
.equ PD8, 0x100				// Maske fuer PD8
.equ ALT_GPIO , 0x100		// Alternative 1: GPIO
.equ ALT_2, 0x203			// Alternative 2

.equ NVIC_ISER2_MASK, 0x20		// PIT1
.equ IVT_OFS_PIT1, 0x154		// Offeset IVT-Vektor von PIT1

.equ ONE_SECOND, 25000000		// Takte entsprechen bei 25MHz: 1 Sekunde
.equ CLOCK_CYCLES_2MS, 50 		// Takte für ca. 2 Mikrosekunden bei 25 MHz = 50

.equ WAIT_LIMITER, 1000			// sorgt dafür, dass Warte-Schleifen nicht unendlich lange laufen
.equ MAX_TEN_TRIES, 10			// sorgt dafür, dass Loop nicht mehr als 10 Versuche braucht

.equ SH_16_BITS, 16
.equ SH_8_BITS, 8
.equ FIRST_BYTE_BITMASK, 0xFF
.equ DEC_100, 100
.equ DEC_1000, 1000

.equ BIT_7, 0x80
.equ BIT_6, 0x40
.equ BIT_5, 0x20
.equ BIT_4, 0x10

.equ DEC_BIT_7, 5000			// Dezimalwerte für Nachkommastellen nach entsprechenden Hex-Bits
.equ DEC_BIT_6, 2500
.equ DEC_BIT_5, 1250
.equ DEC_BIT_4, 625

// DS75 Konfig
.equ ADRESS_WRITE, 0x90			// Pointer für schreibenden Zufriff
.equ ADRESS_READ, 0x91			// Pointer für lesenden Zugriff

.equ DS75_TEMPERATURE_POINTER, 0x0		// P1=0, P0=0
.equ DS75_CONFIGURATION_POINTER, 0x1	// P1=0, P0=1
.equ DS75_THYST_POINTER, 0x2			// P1=1, P0=0
.equ DS75_TOS_POINTER, 0x3				// P1=1, P0=1

.equ DS75_CONFIG_SET, 0x60				// Conversion resolution: 12-bit, Thermostat Fault Tolerance: 1, 
										// POL: active low, TM: Comparator Mode, Shutdown: Active conversion and thermostat operation

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
* zu Aufgabe b):	Das I2C-Modul wird standardmäßig mit 25 MHz Taktfrequenz betrieben. Das Thermometer kann maximal mit 400 kHz Busfrequenz arbeiten.
*
* zu Aufgabe c): 	es ist zu sehen, wie die orangene LED bei Überschreitung der 3 Grad Celsius über der zu Beginn gemessenen Temperatur das leuchten beginnt (TOS)
*					und erst wieder aufhört, sobald die Temperatur auf 2 Grad Celsius über der Starttemperatur abgesunken ist (THYST)
*/

main:	
	bl uart_init
	
	// Aktivieren des I2C0 im SIM
	ldr r4, =SIM_SCGC4_I2C0
	mov r5, #1
    str r5, [r4]

	// Aktivieren des PIT
	ldr r4, =SIM_SCGC6_PIT
    str r5, [r4]
    
    // Initialisierung des Periodic Interrupt Timers PIT1
    
    // NVIC-Bitmaske fuer PIT1 setzen
	ldr r0, =NVIC_ISER2 
	mov r1, #NVIC_ISER2_MASK
	str r1, [r0]
	
	// Adresse der ISR fuer PIT1 in die IVT eintragen
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_pit1
	str r0, [r1, #IVT_OFS_PIT1]
	
	// PIT-Modul konfigurieren
	ldr r4, =PIT_MCR
	mov r1, #1					// FRZ=1, MDIS=0 (PIT stopped in Debug mode, PIT-Clock enabled) 
	str r1, [r4]
	
	// PIT1 auf eine Sekunde einstellen
	ldr r4, =PIT_LDVAL1
	ldr r1, =ONE_SECOND
	str r1, [r4]
	
	//PIT1 Konfigurieren
	ldr r4, =PIT_TCTRL1
	mov r1, #3					// nicht mit PIT0 verkettet, Interrupt aktiviert, Timer aktiviert
	str r1, [r4]
    
    
	// Unterprogramm zum Zurücksetzen des I2C-Busses aufrufen
	bl I2CBus_Reset
	
	// Initialisieren des I2C-Busses (Master) (RA und A1/2 müssen nur im Slave-Modus konfiguiert werden) -----------
	
	// - I2C Frequency Divider Register (I2C0_F)
	ldr r1, =I2C0_F
	mov r2, #I2C0_F_SET
	strb r2, [r1]
	
	// - I2C Control Register 1 (I2C0_C1)
	ldr r1, =I2C0_C1
	mov r2, #I2C0_C1_SET
	strb r2, [r1]
	
	// I2C0_SMB und I2C0_C2 komplett auf 0 setzen
	ldr r1, =I2C0_C2
	mov r2, #0
	strb r2, [r1]
	
	ldr r1, =I2C0_SMB
	mov r2, #0
	strb r2, [r1]

	// Die gewählten Einstellungen ins Configuration Register schreiben ----------------------------------------------
	
	// TX auf 1 setzen -> Transmit Mode
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	orr r2, r2, #I2C0_C1_TX_BITMASK
	strb r2, [r1]
	// TXAK-Flag auf 0 setzen
	ldrb r2, [r1]
	bic r2, r2, #I2C0_C1_TXAK_BITMASK
	strb r2, [r1]
	// Start-Bedingung -> START-Signal durch Setzen von MST
	bl start_signal_and_check			
	
	// Adresse 0x90 (WRITE) in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #ADRESS_WRITE
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// Pointer 0x01 (CONFIGURATION) in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #DS75_CONFIGURATION_POINTER
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// 7. Config nach I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #DS75_CONFIG_SET
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// STOP-Signal erzeugen durch Setzen von MST auf 0
	bl stop_condition
	
	// Ersten Temperaturwert auslesen und ausgeben ------------------------------------------------------------------
	
	ldr r0, =str_erster_temperaturwert
	bl uart_putString
	ldr r0, =str_prompt
	bl uart_putString
	
	bl read_temperature				// Aufruf des Unterprogramms zum Auslesen der Temperatur-Bytes

	mov r9, r0						// Sichern des Rückgabewertes in R9
	bl uart_putInt32				// Ausgabe des Rückgabewertes (Hexadezimalform)
	
	// Es folgt die Dezimal-Ausgabe
	ldr r0, =str_spacing
	bl uart_putString
	
	// Dazu wird der erhaltene Temperaturwert auseinandergebaut und die 2 Bytes in zwei Register gesichert, um sie später nach TOS und THYST zu schreiben
	// LSB sichern
	lsr r7, r9, #SH_8_BITS
	and r7, r7, #FIRST_BYTE_BITMASK
	// MSB sichern
	lsr r8, r9, #16
	
	// MSB wird direkt als Ganzzahl ausgeben
	mov r0, r8
	bl uart_putByteBase10
	
	// LSB wird als dezimle Nachkommastellen ausgegeben
	ldr r0, =str_comma
	bl uart_putString
	mov r9, #0
	
	// dazu werden die 4 für die Nachkommastellen relevanten Bits des Bytes 
	// nacheinander geprüft und entsprechende Dezimalwerte summiert (weitere Nachkommastellen müssen nicht überprüft werden -> fixed point gemäß Aufgabenstellung))
	and r5, r7, #BIT_7
	ldr r6, =#DEC_BIT_7
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r6				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_6
	ldr r6, =#DEC_BIT_6
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r6				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_5
	ldr r6, =#DEC_BIT_5
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r6				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_4
	ldr r6, =#DEC_BIT_4
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r6				// addieren des entsprechenden Wertes zu Wert in R9
	
	// Berechnen der Werte der dezimalen Nachkommastellen aus dem ermittelten summierten Wertes 
	
	ldr r6, =DEC_1000
	udiv r0, r9, r6
	mul r1, r0, r6
	sub r9, r9, r1
	bl uart_putByteBase10
	
	ldr r6, =DEC_100
	udiv r0, r9, r6
	mul r1, r0, r6
	sub r9, r9, r1
	bl uart_putByteBase10
	
	/*
	// OPTIONAL für weitere zwei Dezimal-Nachkommastellen (hier eher nicht sinnvoll)
	mul r1, r0, r11
	sub r9, r9, r1
	
	ldr r6, =#10
	udiv r0, r9, r6
	mul r1, r0, r6
	sub r9, r9, r1
	bl uart_putByteBase10
	
	ldr r6, =#1
	udiv r0, r9, r6
	mul r1, r0, r6
	sub r9, r9, r1
	bl uart_putByteBase10
	*/
	
	ldr r0, =str_celsius
	bl uart_putString
	
	
	// 2 Temperatur-Bytes nach THYST schreiben -----------------------------------------------------------------------
	
	// TX auf 1 setzen -> Transmit Mode
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	orr r2, r2, #I2C0_C1_TX_BITMASK
	strb r2, [r1]
	// TXAK-Flag auf 0 setzen
	ldrb r2, [r1]
	bic r2, r2, #I2C0_C1_TXAK_BITMASK
	strb r2, [r1]
	// Start-Bedingung -> START-Signal durch Setzen von MST
	bl start_signal_and_check
	
	// Adresse 0x90 (WRITE) in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #ADRESS_WRITE
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// Pointer (0x02) in I2C0_D schreiben, um Pointer auf THYST Register zu setzen
	ldr r1, =I2C0_D
	mov r2, #DS75_THYST_POINTER
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// MSB in I2C0_D schreiben
	ldr r1, =I2C0_D
	add r2, r8, #2
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// LSB in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, r7
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// STOP-Signal erzeugen durch Setzen von MST auf 0
	bl stop_condition
	
	
	// 2 Temperatur-Bytes nach TOS schreiben -----------------------------------------------------------------------

	// TX auf 1 setzen -> Transmit Mode
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	orr r2, r2, #I2C0_C1_TX_BITMASK
	strb r2, [r1]
	// TXAK-Flag auf 0 setzen
	ldrb r2, [r1]
	bic r2, r2, #I2C0_C1_TXAK_BITMASK
	strb r2, [r1]
	// Start-Bedingung -> START-Signal durch Setzen von MST
	bl start_signal_and_check
	
	// Adresse 0x90 (WRITE) in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #ADRESS_WRITE
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// Pointer (0x03) in I2C0_D schreiben, um Pointer auf TOS Register zu setzen
	ldr r1, =I2C0_D
	mov r2, #DS75_TOS_POINTER
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// MSB in I2C0_D schreiben
	ldr r1, =I2C0_D
	add r2, r8, #3
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// LSB in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, r7
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// STOP-Signal erzeugen durch Setzen von MST auf 0
	bl stop_condition
	
	
	ldr r0, =str_TOS_THYST_abgeschlossen
	bl uart_putString
	
	// Starten des Loops zum Temperatur auslesen und ausgeben -------------------------------------------------------
	
	ldr r0, =str_starte_temperaturausgabe
	bl uart_putString
	
	// Vorinitialisierung verwendeter Register
	ldr r6, =pit1_flag			// Adresse der Variablen pit_flag
	
main_loop:
	ldrb r1, [r6]				// PIT1 abgelaufen?
	cmp r1, #0x0
	beq main_loop				// nein, also warten und  keine Temperatur auslesen
	
	// Zurücksetzen des PIT1-Flags
	mov r1, #0
	strb r1, [r6]
	
	// Ersten Temperaturwert auslesen und ausgeben ------------------------------------------------------------------
	
	ldr r0, =str_prompt
	bl uart_putString
	
	bl read_temperature				// Aufruf des Unterprogramms zum Auslesen der Temperatur-Bytes

	mov r9, r0						// Sichern des Rückgabewertes in R9
	bl uart_putInt32				// Ausgabe des Rückgabewertes (Hexadezimalform)
	
	// Es folgt die Dezimal-Ausgabe
	ldr r0, =str_spacing
	bl uart_putString
	
	// Dazu wird der erhaltene Temperaturwert auseinandergebaut und die 2 Bytes in zwei Register gesichert, um sie später nach TOS und THYST zu schreiben
	// LSB sichern
	lsr r7, r9, #SH_8_BITS
	and r7, r7, #FIRST_BYTE_BITMASK
	// MSB sichern
	lsr r8, r9, #16
	
	// MSB wird direkt als Ganzzahl ausgeben
	mov r0, r8
	bl uart_putByteBase10
	
	// LSB wird als dezimle Nachkommastellen ausgegeben
	ldr r0, =str_comma
	bl uart_putString
	mov r9, #0
	
	// dazu werden die 4 für die Nachkommastellen relevanten Bits des Bytes 
	// nacheinander geprüft und entsprechende Dezimalwerte summiert (weitere Nachkommastellen müssen nicht überprüft werden -> fixed point gemäß Aufgabenstellung))
	and r5, r7, #BIT_7
	ldr r10, =#DEC_BIT_7
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_6
	ldr r10, =#DEC_BIT_6
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_5
	ldr r10, =#DEC_BIT_5
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_4
	ldr r10, =#DEC_BIT_4
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	
	// Berechnen der Werte der dezimalen Nachkommastellen aus dem ermittelten summierten Wertes 
	
	ldr r11, =DEC_1000
	udiv r0, r9, r11
	bl uart_putByteBase10
	mul r1, r0, r11
	sub r9, r9, r1
	
	ldr r11, =DEC_100
	udiv r0, r9, r11
	bl uart_putByteBase10
	
	/*
	// OPTIONAL für weitere zwei Dezimal-Nachkommastellen (hier eher nicht sinnvoll)
	mul r1, r0, r11
	sub r9, r9, r1
	
	ldr r10, =#10
	udiv r0, r9, r10
	mul r1, r0, r10
	sub r9, r9, r1
	bl uart_putByteBase10
	
	ldr r10, =#1
	udiv r0, r9, r10
	mul r1, r0, r10
	sub r9, r9, r1
	bl uart_putByteBase10
	*/
	
	ldr r0, =str_celsius
	bl uart_putString

	b main_loop

end_cancellation:
	b end_cancellation


/*
* Unterprogramm zum Auslesen des aktuellen Temperturwertes (2 Bytes)
* Parameter: keine
* Rueckgabe: R0: MSB und LSB des temperaturwertes zusammengeführt
*/	
.thumb_func
read_temperature:
	
	push {r7, r8, lr}
	
	// ------------------------------- Read ------------------------
	// TX auf 1 setzen -> Transmit Mode
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	orr r2, r2, #I2C0_C1_TX_BITMASK
	strb r2, [r1]
	// TXAK-Flag auf 0 setzen
	ldrb r2, [r1]
	bic r2, r2, #I2C0_C1_TXAK_BITMASK
	strb r2, [r1]
	// Start-Bedingung -> START-Signal durch Setzen von MST
	bl start_signal_and_check
	
	// Adresse 0x90 (WRITE) in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #ADRESS_WRITE
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// Pointer 0x00 (TEMPERATURE) in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #DS75_TEMPERATURE_POINTER
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// Repeat_Start auslösen
	bl repeat_start
	
	// Adresse 0x91 (READ) in I2C0_D schreiben
	ldr r1, =I2C0_D
	mov r2, #ADRESS_READ
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// TX auf 0 setzen
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	bic r2, r2, #I2C0_C1_TX_BITMASK
	strb r2, [r1]
	// ein Byte aus I2C0_D lesen ("Dummy Read") zur Aktivierung des Lesevorgangs
	ldr r1, =I2C0_D
	ldrb r0, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// MSB aus I2C0_D lesen
	ldr r1, =I2C0_D
	ldrb r7, [r1]
	// TXAK auf 1 setzen
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	orr r2, r2, #I2C0_C1_TXAK_BITMASK
	strb r2, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
		
	// LSB aus I2C0_D lesen
	ldr r1, =I2C0_D
	ldrb r8, [r1]
	// Auf IICIF-Flag warten und zurücksetzen
	bl wait_for_IICIF_and_reset
	
	// STOP-Signal erzeugen durch Setzen von MST auf 0
	bl stop_condition
	
	// MSB und LSB zusammenführen und in R0 zurückgeben
	lsl r7, r7, #SH_16_BITS
	lsl r8, r8, #SH_8_BITS
	orr r0, r7, r8
	
	pop {r7, r8, pc}
	

/*
* Unterprogramm zum Zurücksetzen des I2C-Bus
* Parameter: keine
* Rueckgabe: keine
*/		
.thumb_func
I2CBus_Reset:
	push {lr}
	
	ldr r0, =SIM_PORTD 		// Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	
	ldr r0, =PORTD_PCR8 	// Portleitungen PD8, PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2,[r0]
	str r2, [r1]

	ldr r0, =GPIOD_PDDR 	// PD8, PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	
	mov r3, #MAX_TEN_TRIES	// Zähler zur Begrenzung der Loops

loop:

	ldr r0, =GPIOD_PDOR 	// SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD8 		// entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDOR 	// SCL und SDA aktivieren ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9 		// nur Bits 9 und 10 pruefen cmp r2, #PD8_9 // Bit 9 und Bit 10 gesetzt?
	
	// Wiederholungen checken
	subs r3, r3, #1			// Zaehler dekrementieren
	beq error
	
	cmp r2, #PD8_9 			// Bit 9 und Bit 10 gesetzt?
	bne loop 				// ggf. wiederholen
	
	// statt Alternative 1 auf Alternative 2 konfiguieren
	ldr r0, =PORTD_PCR8
	ldr r1, =PORTD_PCR9
	ldr r2, =ALT_2
	str r2,[r0]
	str r2, [r1]
	
	b no_error

error:
	ldr r0, =str_fehlermeldung_ic2o
	bl uart_putString
	b end_cancellation
no_error:
	pop {pc}

/*
 * Unterprogramm zum Erzeugen eines  Delays (ca. 2 Mikrosek.)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
i2c_Delay:
	//warte ich stumpf 100k mal in einer Schleife, ca 2us entspricht
    ldr r3, =CLOCK_CYCLES_2MS 			// Laden der Loop-Zyklen-Anzahl für die Dauer des Delays
    
loop_delay:
    subs r3, r3, #1						// Zaehler dekrementieren
    bne loop_delay						// solange Zaehler noch nicht null
    
    bx lr								// Rücksprung

/*
 * Unterprogramm zum Warten auf das IICIF-Flag (Interrupt-Flag)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
wait_for_IICIF_and_reset:
    push {r4, lr}
    ldr r1, =I2C0_S
    mov r4, #WAIT_LIMITER
wait_for_IICIF_loop:
    ldrb r2, [r1]
    and r2, r2, #I2C0_S_IICIF_BITMASK
    
    // Wiederholungen checken
	subs r4, r4, #1			// Zaehler dekrementieren
	beq error_iicif
    
    cmp r2, #0x0						// ist 0 in IICIF gesetzt?
    beq wait_for_IICIF_loop				// dann warten, bis 1 gestezt ist
    // reset IICIF -> write 1 to it
	ldr r2, =IICIF_FLAG
	mov r3, #1
	strb r3, [r2]
	b no_error_iicif
error_iicif:
	ldr r0, =str_fehlermeldung_iicif
	bl uart_putString
	b end_cancellation
no_error_iicif:
    pop {r4,pc}
   
 /*
 * Unterprogramm zum Erzeugen eines START-Signals und anschließende Überprüfung des BUSY-Flags
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
start_signal_and_check:
	//push {lr}
	mov r3, #WAIT_LIMITER
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	orr r2, r2, #I2C0_C1_MST_BITMASK
	strb r2, [r1]
	// check BUSY-Flag
	ldr r1, =BUSY_FLAG
	ldrb r2, [r1]
	
	// Wiederholungen checken
	subs r3, r3, #1			// Zaehler dekrementieren
	beq error_start_signal
	
	cmp r2, #0
	beq start_signal_and_check	// Fehlermeldung Counter
	b no_error_start_signal
error_start_signal:
	ldr r0, =str_fehlermeldung_start_signal
	bl uart_putString
	b end_cancellation
no_error_start_signal:
	bx lr					// Ruecksprung

/*
 * Unterprogramm zum Erzeugen eines REPEAT_START-Signals und eines anschließenden Delays (ca. 2 Mikrosek.)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
repeat_start:
	push {lr}
	
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	orr r2, r2, #I2C0_C1_RSTA_BITMASK
	strb r2, [r1]
	bl i2c_Delay
	
	pop {pc}						// Ruecksprung

/*
 * Unterprogramm zum Erzeugen eines STOP-Signals und eines anschließenden Delays (ca. 2 Mikrosek.)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
stop_condition:
	push {lr}
	
	ldr r1, =I2C0_C1
	ldrb r2, [r1]
	bic r2, r2, #I2C0_C1_MST_BITMASK
	strb r2, [r1]
	bl i2c_Delay

	pop {pc}

/*
 * ISR fuer PIT1 (sekündlich)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func	
isr_pit1:						// ISR fuer PIT1
	mov r0, #1					
	ldr r1, =pit1_flag			// Flag fuer PIT
	strb r0, [r1]				// setzen
	ldr r1, =PIT_TFLG1			// Interrupt-Flag
	str r0, [r1] 				// zuruecksetzen
	bx lr						// Ruecksprung





/*** Datenbereich (ab 0x20000000) ***/
.data
pit1_flag: .byte 0x0
str_erster_temperaturwert: .asciz "\n\nErster eingelesener Temperaturwert:"
str_prompt: .asciz "\n0x"
str_spacing:  .asciz ":  "
str_comma: .asciz ","
str_celsius:  .asciz "  Grad Celsius"
str_TOS_THYST_abgeschlossen: .asciz "\n\nEs wurden der Temperaturwert jeweils erfolgreich nach TOS und THYST geschrieben \n(T0 + 3 und T0 + 2 fuer TOS und THYST).\n"
str_starte_temperaturausgabe: .asciz "\nSekuendliche Temperaturausgabe starten:\n"
str_fehlermeldung_start_signal: .asciz "\n\nERROR: Die vorgegebene Anzahl an Wiederholungen wurde ueberschritten, um das START-Signal zu erzeugen!\n"
str_fehlermeldung_iicif: .asciz "\n\nERROR: Die vorgegebene Anzahl an Wiederholungen wurde ueberschritten, um das gesetzte IICIF-Flag zu erhalten!\n"
str_fehlermeldung_ic2o: .asciz "\n\nERROR: Die vorgegebene Anzahl an Wiederholungen wurde ueberschritten, um den I2C0-Bus zu initialisieren!\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// Registeradressen

.equ SIM_SCGC3,		0x40048030
.equ SIM_SCGC5, 	0x40048038
.equ SIM_SCGC6, 	0x4004803C

.equ PIT_MCR,       0x40037000
.equ PIT_LDVAL1,    0x40037110
.equ PIT_TCTRL1,    0x40037118
.equ PIT_TFLG1,     0x4003711C

.equ NVIC_ISER2, 	0xE000E108

.equ PORTD_PCR12, 	0x4004C030
.equ PORTD_PCR13, 	0x4004C034
.equ PORTD_PCR14, 	0x4004C038
.equ PORTD_PCR15, 	0x4004C03C

.equ GPIOD_PDDR, 	0x400FF0D4
.equ GPIOD_PDOR, 	0x400FF0C0
.equ GPIOD_PDIR, 	0x400FF0D0

.equ PORTA_PCR19,   0x4004904C
.equ PORTE_PCR26,   0x4004d068

.equ GPIOA_PDOR,    0x400FF000
.equ GPIOA_PDIR,    0x400FF010
.equ GPIOA_PDDR,    0x400FF014
.equ GPIOE_PDIR,    0x400FF110
.equ GPIOE_PDDR,    0x400FF114

.equ SCR_VTOR, 		0xE000ED08		// Register für die Interrupt-Vektor-Tabelle (IVT)
.equ IVT_OFS_PIT1, 	0x154			// Offeset IVT-Vektor von PIT1
.equ IVT_OFS_PTA, 	0x19C			// Offeset IVT-Vektor von PORTA
.equ IVT_OFS_PTE, 	0x01AC			// Offeset IVT-Vektor von PORTE

.equ DS1722_CONFIG_ADRESS, 		0x80
.equ DS1722_TEMP_LSB_ADRESS, 	0x01
.equ DS1722_TEMP_MSB_ADRESS, 	0x02

// SPI2 Registeradressen
.equ SPI2_MCR, 		0x400AC000 
.equ SPI2_CTAR0, 	0x400AC00C
.equ SPI2_RSER, 	0x400AC030 
.equ SPI2_SR, 		0x400AC02C
.equ SPI2_PUSHR, 	0x400AC034
.equ SPI2_POPR, 	0x400AC038

// Bit-Banding Konstanten
__BBREG SPI2_MCR_HALT , SPI2_MCR , 0
__BBREG SPI2_MCR_FRZ , SPI2_MCR , 27
__BBREG SPI2_SR_EOQF , SPI2_SR , 28
__BBREG SPI2_SR_TCF , SPI2_SR , 31

__BBREG	SIM_PIT, SIM_SCGC6, 23
__BBREG	SIM_PORTA, SIM_SCGC5, 9
__BBREG SIM_PORTD , SIM_SCGC5 , 12
__BBREG	SIM_PORTE, SIM_SCGC5, 13
__BBREG	SIM_SPI2, SIM_SCGC3, 12

__BBREG	SW1, GPIOA_PDIR , 19
__BBREG	SW2, GPIOE_PDIR , 26
__BBREG	PDDR_SW1, GPIOA_PDDR , 19
__BBREG	PDDR_SW2, GPIOE_PDDR , 26

__BBREG	SW1_CIF, PORTA_PCR19 , 24
__BBREG	SW2_CIF, PORTE_PCR26 , 24

// Setter, Bitmasks und andere Konstanten						
.equ SPI2_MCR_SET, 0x80003001				// DIS_TXF, DIS_RXF, MSTR, keine FIFOs und PCSIS auf 0
.equ SPI2_CTAR0_SET, 0x3A451017				// DT und CSSCK auf 0001; ASC auf 0000; BR auf 0111
											// DBR auf 0; FMSZ auf 0111; CPHA auf 1;CPOL auf 0; LSBFE auf 0; PCSSCK auf 01 (3), PDT auf 01 (3), PASC auf 00 (1), PBR auf 01 (3)
											// -> TCSC 0,48 microsec., TASC: 0,08 microsec., TDT: 0,48 microsec.
											// -> 97 kHz, 8-bit, MSB first
.equ SPI2_PUSHR_SET_CS1_CONT, 	0x80020000
.equ SPI2_PUSHR_SET_CS1, 		0x00020000
.equ SPI2_PUSHR_SET_CS1_EOQ, 	0x08020000

.equ PD12, 0x1000 							// Maske fuer PD12
.equ PD12_13_14_15, 0xF000					// Maske fuer PD12-15
.equ ALT_GPIO , 0x100						// Alternative 1: GPIO
.equ ALT_2, 0x203							// Alternative 2

.equ NVIC_ISER2_MASK, 0x8800020				// PIT1 (Bit 5), Port A (Bit 23) , Port E (Bit 27)

.equ WAIT_LIMITER, 1000						// sorgt dafür, dass Warte-Schleifen nicht unendlich lange laufen (eigens festgelegter Wert)
.equ MAX_TEN_TRIES, 10						// sorgt dafür, dass Loop nicht mehr als 10 Versuche braucht

.equ CLOCK_CYCLES_2MS, 17 					// Takte für ca. 2 Mikrosekunden bei 25 MHz: 50 -> BNE benötigt bei dieser Ausrichtung des Ziels 2 Takte, SUBS 1 Takt -> 50Takte/3 sind circa 17

.equ SH_16_BITS, 16
.equ SH_8_BITS, 8
.equ FIRST_BYTE_BITMASK, 0xFF
.equ DEC_1, 1
.equ DEC_10, 10
.equ DEC_100, 100
.equ DEC_1000, 1000

.equ BIT_7, 0x80
.equ BIT_6, 0x40
.equ BIT_5, 0x20
.equ BIT_4, 0x10

.equ DEC_BIT_7, 5000						// Dezimalwerte für Nachkommastellen nach entsprechenden Hex-Bits
.equ DEC_BIT_6, 2500
.equ DEC_BIT_5, 1250
.equ DEC_BIT_4, 625

// Äuflösungsgrenzen und (max.) Wandlungszeiten für das Thermmometer DS1722

.equ AUFLOESUNG_9_BIT, 0xE2
.equ AUFLOESUNG_10_BIT, 0xE4
.equ AUFLOESUNG_11_BIT, 0xE6

.equ AUFLOESUNG_MINIMUM, 0xE0
.equ AUFLOESUNG_MAXIMUM, 0xE8

.equ WANDLUNGSZEIT_12_BIT, 30000000			// 30.000.000 Takte entsprechen bei 25MHz: 1.2s
.equ WANDLUNGSZEIT_11_BIT, 15000000			// 15.000.000 Takte entsprechen bei 25MHz: 0.6s
.equ WANDLUNGSZEIT_10_BIT, 7500000			// 7.500.000 Takte entsprechen bei 25MHz: 0.3s
.equ WANDLUNGSZEIT_9_BIT, 3750000			// 3.750.000 Takte entsprechen bei 25MHz: 0.15s
.equ WANDLUNGSZEIT_8_BIT, 1875000			// 1.875.000 Takte entsprechen bei 25MHz: 0.075s

.equ GPIO_IRQ_PE_SET, 0xA0103				// GPIO-Modus, IRQ (fallende Flanke), Pull-Up-Widerstand

main:	
	bl uart_init
	
	mov r11, #1
    
	// Takt fuer die benutzten Module aktivieren
    ldr r0, =SIM_SPI2
	str r11, [r0]
	ldr r0, =SIM_PORTA
	str r11, [r0]
	ldr r0, =SIM_PORTE
	str r11, [r0]
	ldr r0, =SIM_PIT
	str r11, [r0]
    
    // Initialisierung des Periodic Interrupt Timers PIT1, GPIO für die SW1- und SW2-Pins und ISR
	
	ldr r1, =GPIO_IRQ_PE_SET 	// GPIO-Modus mit IRQ (fallende Flanke) und Pull-Up-Widerstand 
	ldr r0, =PORTA_PCR19 		// SW1
	str r1, [r0]				// für SW1 festlegen
	ldr r0, =PORTE_PCR26 		// SW2
	str r1, [r0]				// für SW1 festlegen

	
	// Datenrichtung der GPIO-Pins festlegen
	// Eingaenge (SW1 und SW2)
	ldr r0, =PDDR_SW1
	str r10, [r0]
	ldr r0, =PDDR_SW2
	str r10, [r0]
	
	// Adresse der ISR fuer PIT1 SWs in die IVT eintragen
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_pit1
	str r0, [r1, #IVT_OFS_PIT1]
	ldr r0, =isr_sw1
	str r0, [r1, #IVT_OFS_PTA]
	ldr r0, =isr_sw2
	str r0, [r1, #IVT_OFS_PTE]
	
	// PIT-Modul konfigurieren
	ldr r4, =PIT_MCR
	mov r1, #1					// FRZ=1, MDIS=0 (PIT stopped in Debug mode, PIT-Clock enabled) 
	str r1, [r4]
	
	// PIT1 auf 1,2 Sekunden einstellen
	ldr r4, =PIT_LDVAL1
	ldr r1, =WANDLUNGSZEIT_12_BIT
	str r1, [r4]
	
	//PIT1 Konfigurieren
	ldr r4, =PIT_TCTRL1
	mov r1, #3					// nicht mit PIT0 verkettet, Interrupt aktiviert, Timer aktiviert
	str r1, [r4]
	
	// NVIC-Bitmaske fuer PIT1 und Port E setzen
	ldr r0, =NVIC_ISER2
	ldr r1, =NVIC_ISER2_MASK
	str r1, [r0]
	
	// -------------------------------------------------------------------------------------------------------------
	
	bl SPIBus_Reset
	
	
	// Initialisieren von SPI2
	ldr r1, =SPI2_MCR
	mov	r0, #1					// set HALT-Modus aktiviert
	str r0, [r1]
	
	ldr r1, =SPI2_MCR
	ldr	r0, =SPI2_MCR_SET		// Bit 17 setzen?
	str r0, [r1]
	
	ldr r1, =SPI2_CTAR0			// setze SPI2_CTAR0
	ldr r0, =SPI2_CTAR0_SET
	str r0, [r1]
	
	ldr r1, =SPI2_RSER			// schreibe 0 in SPI2_RSER
	mov r0, #0
	str r0, [r1]
	
	// Setzen der Startbedingung
	bl start_condition
	
	// -------------- UP Config_Schreiben (Übergabe 0xF8) ----------------------------------------
	mov r0, #AUFLOESUNG_MAXIMUM
	bl write_config
	// -------------------------------------------------------------------------------------------------
	
	// Vorinitialisierung verwendeter Register
	ldr r6, =pit1_flag			// Adresse der Variablen pit_flag
	ldr r12, =mod
	mov r8, #AUFLOESUNG_MAXIMUM
	
main_loop:
	
	// Durchgehend überprüfen, ob einer der Knöpfe gedrückt wurde (mod)
	ldrb r1, [r12]
	
	cmp r1, #0x0
	beq skip_aufloesung_change
	
	cmp r1, #0x2
	beq aufloesung_verringern

aufloesung_erhöhen:

	ldr r0, =str_aufloesung_erhöhen
	bl uart_putString

	// mod zurücksetzen
	mov r1, #0
	strb r1, [r12]
	
	cmp r8, #AUFLOESUNG_MAXIMUM
	itt eq
	moveq r8, #AUFLOESUNG_MINIMUM
	beq aufloesung_ausgeben_und_pit1_aktualisieren
	
	// neue Config_in DS1722 schreiben mit Hilfe des Unterprogramms
	add r8, r8, #0x2
	
	b aufloesung_ausgeben_und_pit1_aktualisieren

aufloesung_verringern:

	ldr r0, =str_aufloesung_verringern
	bl uart_putString

	// mod zurücksetzen
	mov r1, #0
	strb r1, [r12]
	
	cmp r8, #AUFLOESUNG_MINIMUM
	itt eq
	moveq r8, #AUFLOESUNG_MAXIMUM
	beq aufloesung_ausgeben_und_pit1_aktualisieren
	
	// neue Config_in DS1722 schreiben mit Hilfe des Unterprogramms
	sub r8, r8, #0x2

aufloesung_ausgeben_und_pit1_aktualisieren:

	mov r0, r8
	bl write_config
	
	// geänderte Auflösung und Wandlungszeit im PIT1 anpassen
	ldr r0, =str_12_bit
	ldr r9, =WANDLUNGSZEIT_12_BIT
	
	cmp r8, #AUFLOESUNG_MINIMUM
	itt eq
	ldreq r0, =str_8_bit
	ldreq r9, =WANDLUNGSZEIT_8_BIT
	
	cmp r8, #AUFLOESUNG_9_BIT
	itt eq
	ldreq r0, =str_9_bit
	ldreq r9, =WANDLUNGSZEIT_9_BIT
	
	cmp r8, #AUFLOESUNG_10_BIT
	itt eq
	ldreq r0, =str_10_bit
	ldreq r9, =WANDLUNGSZEIT_10_BIT
	
	cmp r8, #AUFLOESUNG_11_BIT
	itt eq
	ldreq r0, =str_11_bit
	ldreq r9, =WANDLUNGSZEIT_11_BIT
	
	// Auflösung ausgeben
	bl uart_putString
	
	// PIT1-Counter mit der aktualisierten Wandlungszeit anpassen
	ldr r4, =PIT_LDVAL1
	str r9, [r4]
	
skip_aufloesung_change:
	
	ldrb r1, [r6]				// PIT1 abgelaufen?
	cmp r1, #0x0
	beq main_loop				// nein, also warten und  keine Temperatur auslesen
	
	// Zurücksetzen des PIT1-Flags
	mov r1, #0
	strb r1, [r6]
	
	// Temperaturwert auslesen
	bl read_temp
	// Temperaturwert sichern
	mov r10, r0
	
	// --------------------------------------- Ausgabe in Dezimalform -----------------------------------
	
	// Dazu wird der erhaltene Temperaturwert auseinandergebaut
	// LSB sichern
	and r7, r10, #FIRST_BYTE_BITMASK
	// MSB sichern
	lsr r0, r10, #8
	
	// MSB wird direkt als Ganzzahl ausgeben
	bl uart_putByteBase10
	
	// LSB wird als dezimle Nachkommastellen ausgegeben
	cmp r8, #AUFLOESUNG_MINIMUM
	itt ne
	ldrne r0, =str_comma
	blne uart_putString
	
	mov r9, #0
	
	// dazu werden die 4 für die Nachkommastellen relevanten Bits des Bytes 
	// nacheinander geprüft und entsprechende Dezimalwerte summiert (weitere Nachkommastellen müssen nicht überprüft werden -> fixed point gemäß Aufgabenstellung))
	and r5, r7, #BIT_7
	ldr r10, =DEC_BIT_7
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_6
	ldr r10, =DEC_BIT_6
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_5
	ldr r10, =DEC_BIT_5
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	
	and r5, r7, #BIT_4
	ldr r10, =DEC_BIT_4
	cmp r5, #0x0
	it ne							// falls Bit gesetzt auf 1
	addne r9, r9, r10				// addieren des entsprechenden Wertes zu Wert in R9
	

	// Berechnen der Werte der dezimalen Nachkommastellen aus dem ermittelten summierten Werten
	
	cmp r8, #AUFLOESUNG_MINIMUM				// Je nach Auflösunh kann die Berechnung der restlichen Nachkommastellen übersprungen werden
	beq skip_restliche_nachkommastellen
	
	ldr r11, =DEC_1000
	udiv r7, r9, r11						// Teilen des Nachkomma-Bytes durch 1000
	mov r0, r7
	bl uart_putByteBase10					// Ausgabe der ersten Nachkommastelle
	
	cmp r8, #AUFLOESUNG_9_BIT				// usw...
	beq skip_restliche_nachkommastellen
	  
	mls r9, r7, r11, r9						// multiplizieren des Divisions-Ergebnisses mit 1000 und abziehen vom letzten Ergebnis
	mov r11, #DEC_100
	udiv r7, r9, r11
	mov r0, r7
	bl uart_putByteBase10
	
	cmp r8, #AUFLOESUNG_10_BIT
	beq skip_restliche_nachkommastellen
	  
	mls r9, r7, r11, r9
	mov r11, #DEC_10
	udiv r7, r9, r11
	mov r0, r7
	bl uart_putByteBase10
	
	cmp r8, #AUFLOESUNG_11_BIT
	beq skip_restliche_nachkommastellen
	
	mls r9, r7, r11, r9
	mov r11, #DEC_1
	udiv r0, r9, r11
	bl uart_putByteBase10

skip_restliche_nachkommastellen:

	ldr r0, =str_gC
	bl uart_putString
	
	b main_loop

end_cancellation:
	b end_cancellation



/*
 * Unterprogramm zum Schreiben der Konfiguration in das DS1722 Thermometer
 * Parameter: Aufloesung
 * Rueckgabe: keine
 */	
.thumb_func
write_config:

	push {r4,lr}
	
	// Sichern des übergebenen Parameters
	mov r3, r0
	
	// Laden der CONFIG-Adresse und verodern dieser mit CS1 und CONT
	mov r2, #DS1722_CONFIG_ADRESS
	ldr r1, =0x80020000
	orr r2, r2, r1
	
	// Schreiben des Ergebnisses in das SPI2_PUSHR-Register
	ldr r4, =SPI2_PUSHR
	str r2, [r4]
	
	// Warten auf das TCF-Flag und zurücksetzen dieses
	bl wait_for_tcf_and_reset
	
	// Laden des übergebenen Wertes und verodern dieses mit CS1
	ldr r2, =SPI2_PUSHR_SET_CS1
	orr r2, r2, r3
	
	// Schreiben des Ergebnisses in das SPI2_PUSHR-Register
	str r2, [r4]
	
	// Warten auf das TCF-Flag und zurücksetzen dieses
	bl wait_for_tcf_and_reset
	
	pop {r4,pc}


/*
 * Unterprogramm zum Lesen der Temperatur aus dem DS1722 Thermometer
 * Parameter: keine
 * Rueckgabe: Temperaturwert (zusammengefügt)
 */	
.thumb_func
read_temp:

	push {r4,lr}
	
	// Laden der MSB-Adresse und verodern dieser mit CS1 und CONT
	mov r2, #DS1722_TEMP_MSB_ADRESS
	ldr r1, =SPI2_PUSHR_SET_CS1_CONT
	orr r2, r2, r1
	
	// Schreiben des Ergebnisses in das SPI2_PUSHR-Register
	ldr r4, =SPI2_PUSHR
	str r2, [r4]
	
	// Warten auf das TCF-Flag und zurücksetzen dieses
	bl wait_for_tcf_and_reset
	
	// Transfer abschließen: EOQ und CS1 setzen
	ldr r2, =SPI2_PUSHR_SET_CS1_EOQ
	// Schreiben des Ergebnisses in das SPI2_PUSHR-Register
	str r2, [r4]
	
	// Warten auf das TCF-Flag und zurücksetzen dieses
	bl wait_for_tcf_and_reset
	// Sichern des Rückgabewerts
	mov r3, r0
	
	// Laden der LSB-Adresse und verodern dieser mit CS1 und CONT
	mov r2, #DS1722_TEMP_LSB_ADRESS
	ldr r1, =SPI2_PUSHR_SET_CS1_CONT
	orr r2, r2, r1
	
	// Schreiben des Ergebnisses in das SPI2_PUSHR-Register
	str r2, [r4]
	
	// Warten auf das TCF-Flag und zurücksetzen dieses
	bl wait_for_tcf_and_reset
	
	// Transfer abschließen: EOQ und CS1 setzen
	ldr r2, =SPI2_PUSHR_SET_CS1_EOQ
	// Schreiben des Ergebnisses in das SPI2_PUSHR-Register
	str r2, [r4]
	
	// Warten auf das TCF-Flag und zurücksetzen dieses
	bl wait_for_tcf_and_reset
	// Sichern des Rückgabewerts
	mov r2, r0
	
	// LSB und MSB-Ergebnisse zusammensetzen, um den Temperaturwert in R0 zurückzugeben
	orr r0 , r2, r3, lsl #8
	
	pop {r4,pc}


/*
 * Unterprogramm zum Erzeugen eines START-Signals
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
start_condition:
	
	mov r0, #0
	ldr r1, =SPI2_SR_EOQF
	str r0, [r1]
	ldr r1, =SPI2_MCR_FRZ
	str r0, [r1]
	ldr r1, =SPI2_MCR_HALT
	str r0, [r1]

	bx lr


/*
 * Unterprogramm zum Warten auf das TCF-Flag und Zurücksetzen dieses
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
wait_for_tcf_and_reset:
	push {r3,lr}
	ldr r1, =SPI2_SR_TCF
loop_wait_for_tcf:
	ldrb r2, [r1]

	cmp r2, #0x1						// ist 0 in IICIF gesetzt?
    bne loop_wait_for_tcf				// dann warten, bis 1 gestezt ist
    
    // POPR auslesen (neuer Rückgabewert)
    ldr r3, =SPI2_POPR
    ldr r0, [r3]

    // TCF = 1 (zum Reseten)
    mov r2, #1
    str r2, [r1]
    
    // Rückgabewert zurückgeben

	pop {r3,pc}
	
/*
* Unterprogramm zum Zurücksetzen des SPI-Bus
* Parameter: keine
* Rueckgabe: keine
*/		
.thumb_func
SPIBus_Reset:
	push {lr}
	
	ldr r0, =SIM_PORTD 		// Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	
	mov r2, #ALT_GPIO
	ldr r0, =PORTD_PCR12 	// Portleitungen PD12, PD13, PD14, PD15 als GPIO
	ldr r1, =PORTD_PCR13
	str r2, [r0]
	str r2, [r1]
	ldr r0, =PORTD_PCR14
	ldr r1, =PORTD_PCR15
	str r2, [r0]
	str r2, [r1]

	ldr r0, =GPIOD_PDDR 	// PD8, PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2, #PD12_13_14_15
	str r2, [r0]
	
	mov r3, #MAX_TEN_TRIES	// Zähler zur Begrenzung der Loops

loop:

	ldr r0, =GPIOD_PDOR 	// SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD12 		// entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDOR 	// SCL und SDA aktivieren 
	ldr r2, [r0]
	orr r2, r2, #PD12_13_14_15
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD12_13_14_15 		// nur Bits 9 und 10 pruefen 
	cmp r2, #PD12_13_14_15 			// Bit 9 und Bit 10 gesetzt?
	
	// Wiederholungen checken
	subs r3, r3, #1					// Zaehler dekrementieren
	beq error
	
	cmp r2, #PD12_13_14_15 			// Bit 9 und Bit 10 gesetzt?
	bne loop 						// ggf. wiederholen
	
	// GPIOD 12,13,14,15 statt Alternative 1 auf Alternative 2
	ldr r2, =ALT_2
	
	ldr r0, =PORTD_PCR12
	ldr r1, =PORTD_PCR13
	str r2,[r0]
	str r2, [r1]
	
	ldr r0, =PORTD_PCR14
	ldr r1, =PORTD_PCR15
	str r2,[r0]
	str r2, [r1]
	
	b no_error

error:
	ldr r0, =str_fehlermeldung_spi2
	bl uart_putString
	b end_cancellation
no_error:
	pop {pc}


/*
 * ISR fuer PIT1 (sekündlich)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func	
isr_pit1:						// ISR fuer PIT1
	mov r0, #1					
	ldr r1, =pit1_flag			// Flag fuer PIT
	strb r0, [r1]				// setzen
	ldr r1, =PIT_TFLG1			// Interrupt-Flag
	str r0, [r1] 				// zuruecksetzen
	bx lr						// Ruecksprung
	

// Interrupt Service Routine zu SW1
.thumb_func
isr_sw1:
	
	// Interrupt-Flag zu PORTE zurücksetzen
	ldr r1, =SW1_CIF
	mov r2, #0x1
    strb r2, [r1]
	
	// Variable "mod" auf "1" setzen
	mov r1, #0x1
    ldr r0, =mod
    strb r1, [r0]
	
	bx lr									// Rücksprung

// Interrupt Service Routine zu SW2
.thumb_func
isr_sw2:
	
	//  Interrupt-Flag zu PORTE zurücksetzen
	ldr r1, =SW2_CIF
	mov r2, #0x1
    strb r2, [r1]
	
	// Variable "mod" auf "2" setzen
	mov r1, #0x2
    ldr r0, =mod
    strb r1, [r0]
	
	bx lr									// Rücksprung
	

/*
 * Unterprogramm zum Erzeugen eines  Delays (ca. 2 Mikrosek.)
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func
i2c_Delay:
    ldr r3, =CLOCK_CYCLES_2MS 			// Laden der Loop-Zyklen-Anzahl für die Dauer des Delays
    
loop_delay:
    subs r3, r3, #1						// Zaehler dekrementieren
    bne loop_delay						// solange Zaehler noch nicht null
    
    bx lr								// Rücksprung



/*** Datenbereich (ab 0x20000000) ***/
.data
pit1_flag: .byte 0x0
mod: .byte 0x0
tab_wandlungszeiten: .word WANDLUNGSZEIT_12_BIT, WANDLUNGSZEIT_11_BIT, WANDLUNGSZEIT_10_BIT, WANDLUNGSZEIT_9_BIT, WANDLUNGSZEIT_8_BIT
str_gC: .asciz " gC\n"
str_comma: .asciz ","
str_fehlermeldung_spi2: .asciz "\n\nERROR: Die vorgegebene Anzahl an Wiederholungen wurde ueberschritten, um den SPI2-Bus zu initialisieren!\n"
str_aufloesung_verringern: .asciz "\n\nDie Aufloesung wurde verringert\nNeue eingestellte Aufloesung: "
str_aufloesung_erhöhen: .asciz "\n\nDie Aufloesung wurde erhoeht\nNeue eingestellte Aufloesung: "
str_12_bit: .asciz "12-bit\n\n"
str_11_bit: .asciz "11-bit\n\n"
str_10_bit: .asciz "10-bit\n\n"
str_9_bit: .asciz "9-bit\n\n"
str_8_bit: .asciz "8-bit\n\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// Registeradressen

.equ SIM_SCGC6, 		0x4004803C

.equ RTC_CR, 0x4003D010
.equ RTC_SR, 0x4003D014
.equ RTC_LR, 0x4003D018
.equ RTC_TAR, 0x4003D008
.equ RTC_TSR, 0x4003D000
.equ RTC_IER, 0x4003D01C
.equ RTC_RAR, 0x4003D804
.equ RTC_WAR, 0x4003D800

.equ NVIC_ISER2, 	0xE000E108
.equ NVIC_ICPR2, 	0xE000E288 

.equ SCR_VTOR, 0xE000ED08		// Register für die Interrupt-Vektor-Tabelle (IVT)
.equ IVT_OFS_RTC_ALARM, 0x148	// Offeset IVT-Vektor von RTC Alarm interrupt
.equ IVT_OFS_RTC_SEC, 0x14C		// Offeset IVT-Vektor von Seconds interrupt

// Bit-Banding Adressen

__BBREG	SIM_RTC, SIM_SCGC6, 29
__BBREG	RTC_IER_TAIE, RTC_IER, 2
__BBREG	RTC_IER_TSIE, RTC_IER, 4

// Setter und Bitmasks

.equ RTC_CR_SET, 0x100			// Supervisor Access Enable
.equ RTC_IER_SET, 0x14
.equ NVIC_SET, 0xC
.equ RTC_SR_SET, 0x10			// Time Counter enable
.equ RTC_SR_SET_STOP_COUNTER, 0x0
.equ RTC_RAR_SET, 0xFF			// every read completes as normal
.equ RTC_WAR_SET, 0xF5			// set everything except Prescaler and Compensation (not used)
.equ RTC_TAR_SET_DAY, 86399
.equ RTC_TAR_SET_HOUR, 3599
.equ RTC_TSR_SET_NEARLY_DAY, 86394
.equ RTC_TSR_SET_NEARLY_HOUR, 3594
.equ SECONDS_HOUR, 3600
.equ SECONDS_MINUTE, 60

.equ RTC_EINSCHWINGZEIT_1000MS, 8333333   // Takte für ca. 2 Mikrosekunden bei 25 MHz: 25000000 -> BNE benötigt bei dieser Ausrichtung des Ziels 2 Takte, SUBS 1 Takt -> 25000000Takte/3 sind circa 8333333

// Zeichen

.equ DOPPELPUNKT, ':'
.equ ZEHN, 10

main:	
	bl uart_init
	
	mov r10, #0
	mov r11, #1
	
	// Initialisierung des RTC --------------------------------------------------------------
	
	// Takt fuer RTC im SIM aktivieren
	ldr r0, =SIM_RTC
	str r11, [r0]
	
	// RTC Read Access Register (alles aktivieren)
	ldr r1, =RTC_RAR
	mov r2, #RTC_RAR_SET
	str r2, [r1]
	
	// RTC Lock Register (alles aktivieren)
	ldr r1, =RTC_LR
	mov r2, #RTC_RAR_SET
	str r2, [r1]
	
	// RTC Write Access Register
	ldr r1, =RTC_WAR
	mov r2, #RTC_WAR_SET
	str r2, [r1]
	
	// RTC Control Register: OSCE setzen (Um Kapazitäten nicht kümmern)
	ldr r1, =RTC_CR
	mov r2, #RTC_CR_SET
	str r2, [r1]
	
	// warte 100 ms als Einschwingzeit des Quarz
	ldr r6, =RTC_EINSCHWINGZEIT_1000MS
loop_wait:
	subs r6, r6, #1				// Zaehler dekrementieren
	bne loop_wait				// solange Zaehler noch nicht null
	
	// RTC Time Alarm Register: Wert, bei dem Alarm ausgelöst wird: 24 Stunden
	ldr r1, =RTC_TAR
	ldr r2, =RTC_TAR_SET_DAY
	str r2, [r1]
	
	// RTC Interrupt Enable Register: TSIE und TAIE setzen
	ldr r1, =RTC_IER
	mov r2, #RTC_IER_SET
	str r2, [r1]
	
	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]

	// RTC Time Seconds Register: Auf "0" als Startwert zurücksetzen
	ldr r1, =RTC_TSR
	str r10, [r1]
	
	// RTC Status Register: Counter aktiviert
	mov r2, #RTC_SR_SET
	str r2, [r3]
	
	// NVICISER2 und NCICICPR2: Bit 2 (Alarm) und Bit 3 (Seconds Interrupt) setzen
	ldr r1, =NVIC_ISER2
	ldr r3, =NVIC_ICPR2
	mov r2, #NVIC_SET
	str r2, [r1]
	str r2, [r3]
	
	// Adresse der ISRs fuer RTC Alarm und Seconds Interrupt in die IVT eintragen
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_rtc_alarm
	str r0, [r1, #IVT_OFS_RTC_ALARM]
	ldr r0, =isr_rtc_sec
	str r0, [r1, #IVT_OFS_RTC_SEC]
	
	// Ausgabe der Fertigstellung der Initialisierung
	ldr r0, =str_initialisierung
	bl uart_putString
	
	
	
	
	// Schleife -----------------------------------------------------------------------------
	
	// Vorinitialisierung verwendeter Register
	ldr r4, =mode_flag
	ldr r6, =seconds_flag
	ldr r7, =alarm_flag
	ldr r8, =RTC_TSR
	ldr r11, =anzeige_stopped_flag
	ldr r12, =stop_flag

loop_main:
	
	// Überprüfung, ob ein Zeichen in das Terminal eingegeben wurde
	bl uart_charPresent						// Funktion gibt 0 in R0 zurück, falls kein char eingegeben wurde
	teq r0, #0								// Überprüfung des Rückgabewertes auf Gleichheit mit 0
	beq skip_char_check						// falls gleich: kein char eingegeben -> char-Check überspringen
	
	bl uart_getChar							// Laden des Zeichens in R0
	
	// Prüfen, ob das Zeichen eine Funktion aufruft und Sprung zu dieser
	cmp r0, #'s'
	beq funktion_start_stopp
	cmp r0, #'r'							
	beq funktion_reset
	cmp r0, #'d'							
	beq funktion_day
	cmp r0, #'h'							
	beq funktion_hour
	cmp r0, #'p'							
	beq funktion_preset

skip_char_check:
	
	// Prüfen, ob das Stopp-Flag gesetzt ist
	ldrb r5, [r12]							// Lade das Stopp-Flag
	cmp r5, #0x1							// falls es auf 1 gesetzt ist
	bhs loop_main							// Counter ist aktuell gestoppt un darf nicht zählen, Rücksprung zum Haupt-Loop
	b wait_for_flag							// ansonsten: in den Wait-Loop, um Seconds Flag zu warten
	
funktion_start_stopp:
	// Prüfen, ob Anzeige aktuell aktiv
	ldrb r0, [r11]							// Laden des anzeige_stopped_flag
	cmp r0, #1
	bne anzeige_stoppen						// falls nicht gesetzt: Anzeige stoppen, sonst Anzeige starten
	
	// Anzeige starten: Flag zurücksetzen
	mov r0, #0
	strb r0, [r11]
	
	// Terminalausgabe
	ldr r0, =str_anzeige_an
	bl uart_putString						// Info ausgeben, dass Terminalausgabe wieder gestartet wurde
	
	b wait_for_flag
	
anzeige_stoppen:
	
	// Anzeige stoppen: Flasg setzen
	mov r0, #1
	strb r0, [r11]

	// Terminalausgabe
	ldr r0, =str_anzeige_aus
	bl uart_putString						// Info ausgeben, dass Terminalausgabe gestoppt wurde
	
	b wait_for_flag

funktion_reset:

	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]

	// RTC Time Seconds Register: Zurücksetzen des Sekunden-Counters
	ldr r1, =RTC_TSR
	str r10, [r1]
	
	// RTC Status Register: Counter wieder aktivieren
	mov r2, #RTC_SR_SET
	str r2, [r3]

	// Terminalausgabe 
	ldr r0, =str_reset						// Info ausgeben, dass Timer zurückgesetzt wurde
	bl uart_putString
	
	b wait_for_flag

funktion_day:

	// Modus-Flag auf Tag setzen (0 -> nicht gesetzt)
	mov r0, #0
	strb r0, [r4]

	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]
	
	// RTC Time Alarm Register: Wert, bei dem Alarm ausgelöst wird, auf Sekunden eines Tages anpassen
	ldr r1, =RTC_TAR
	ldr r2, =RTC_TAR_SET_DAY
	str r2, [r1]

	// RTC Time Seconds Register: Zurücksetzen des Sekunden-Counters
	ldr r1, =RTC_TSR
	str r10, [r1]
	
	// RTC Status Register: Counter wieder aktivieren
	mov r2, #RTC_SR_SET
	str r2, [r3]
	
	// Terminalausgabe
	ldr r0, =str_day						// Info ausgeben, dass der 24-Stunden-Modus ausgewählt wurde
	bl uart_putString
	
	b wait_for_flag

funktion_hour:

	// Modus-Flag auf Stunde setzen (1)
	mov r0, #1
	strb r0, [r4]

	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]
	
	// RTC Time Alarm Register: Wert, bei dem Alarm ausgelöst wird, auf Sekunden einer Stunde anpassen
	ldr r1, =RTC_TAR
	ldr r2, =RTC_TAR_SET_HOUR
	str r2, [r1]

	// RTC Time Seconds Register: Zurücksetzen des Sekunden-Counters
	ldr r1, =RTC_TSR
	str r10, [r1]
	
	// RTC Status Register: Counter wieder  aktivieren
	mov r2, #RTC_SR_SET
	str r2, [r3]
	
	// Terminalausgabe
	ldr r0, =str_hour
	bl uart_putString						// Info ausgeben, dass der Tages-Modus ausgewählt wurde
	
	b wait_for_flag

funktion_preset:

	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]
	
	// Modus-Flag laden und je nach Modus entsprechende Zeit/Sekunden auswählen (Sekundenwerte jeweils knapp vor dem Alarm-Wert)
	ldrb r0, [r4]
	cmp r0, #1
	ite eq
	ldreq r0, =RTC_TSR_SET_NEARLY_HOUR
	ldrne r0, =RTC_TSR_SET_NEARLY_DAY
	
	// diese Sekunden in das Time Seconds Register speichern
	str r0, [r8]
	
	// RTC Status Register: Counter wieder aktivieren
	mov r2, #RTC_SR_SET
	str r2, [r3]	

	// Terminalausgabe
	ldr r0, =str_uhr_vorgestellt			// Info ausgeben, dass die Uhr vorgestellt wurde
	bl uart_putString

wait_for_flag:
	
	ldrb r1, [r6]							// Sekunden-Flag gesetzt?
	cmp r1, #0x0
	beq skip_sekunden_flag					// nein, also Sprung zum Alarm-Flag-Check
	
	// Sekunden-Flag zurücksetzen
	mov r1, #0x0
	strb r1, [r6]
	
	// Sekunden-Wert ausgeben, falls Sekunden-Anzeige aktiv
	ldrb r0, [r11]
	cmp r0, #1
	beq skip_sekunden_flag
	
	ldr r0, =str_uhrzeit
	bl uart_putString
	
	// Sekunden-Wert laden und in entsprechender Tag/Stunden/Minuten-Anzeige ausgeben ------------------------
	
	ldr r9, [r8]							// Laden des Sekundenwertes
	
	// falls 24-Stunden-Modus aktiviert: Berechnen der Anzahl der Stunden und Ausgabe dieser
	
	ldrb r5, [r4]							// Laden des Modus-Flag
	cmp r5, #1								// falls 1-Stunden-Modus aktiviert
	beq skip_print_stunden					// Überspringen der Ausgabe der Stunden
	
	ldr r1, =SECONDS_HOUR
	udiv r0, r9, r1							// Sekundenwert durch Sekunden einer Stunde teilen
	mov r5, r0								// Zwischensichern des Ergebnisses in R5
	
	cmp r0, #ZEHN							// Vergleiche den Wert in R0 mit dem Wert 10 (Dezimal)
    ite hs									// größer gleich 10?
    ldrhs r1, =uart_putByteBase10			// Ausgeben des Wertes des Bytes ohne führende 0
    ldrlo r1, =uart_putByte					// Ausgeben des Wertes des Bytes mit führender 0
    blx r1									// Aufrufen des entsprechenden Unterprogramms
	
	ldr r1, =SECONDS_HOUR
	mls r9, r5, r1, r9						// Berechnen des restlichen Sekundenwertes R9-(R5*Sekunden einer Stunde)
		
	mov r0, #DOPPELPUNKT
	bl uart_putChar							// Doppelpunkt ausgeben
	
skip_print_stunden:	
	
	// Berechnen der Anzahl der Stunden und Ausgabe dieser
	mov r1, #SECONDS_MINUTE
	udiv r0, r9, r1							// Sekundenwert durch Sekunden eines Tages teilen
	mov r5, r0								// Zwischensichern des Ergebnisses in R5
	
	cmp r0, #ZEHN							// Vergleiche den Wert in R0 mit dem Wert 10 (Dezimal)
    ite hs									// größer gleich 10?
    ldrhs r1, =uart_putByteBase10			// Ausgeben des Wertes des Bytes ohne führende 0
    ldrlo r1, =uart_putByte					// Ausgeben des Wertes des Bytes mit führender 0
    blx r1									// Aufrufen des entsprechenden Unterprogramms
	
	mov r1, #SECONDS_MINUTE
	mls r9, r5, r1, r9						// Berechnen des restlichen Sekundenwertes R8-(R5*Sekunden einer Stunde)
	
	mov r0, #DOPPELPUNKT
	bl uart_putChar							// Doppelpunkt ausgeben
	
	// Berechnen der Anzahl der Sekunden und Ausgabe dieser
	mov r0, r9								// Zwischensichern des Ergebnisses in R5
	
	cmp r0, #ZEHN							// Vergleiche den Wert in R0 mit dem Wert 10 (Dezimal)
    ite hs									// größer gleich 10?
    ldrhs r1, =uart_putByteBase10			// Ausgeben des Wertes des Bytes ohne führende 0
    ldrlo r1, =uart_putByte					// Ausgeben des Wertes des Bytes mit führender 0
    blx r1									// Aufrufen des entsprechenden Unterprogramms
	
	# --------------------------------------------------------------------------------------------------------
	
skip_sekunden_flag:
	
	ldrb r1, [r7]							// Alarm-Flag gesetzt?
	cmp r1, #0x1
	bne skip_alarm_flag						// falls nicht gleich, Alarm-Flag Reaktion überspringen
	
	// Alarm-Flag zurücksetzen
	mov r1, #0x0
	strb r1, [r7]

	// Alarm ausgeben
	ldr r0, =str_alarm
	bl uart_putString
	
	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]

	// RTC Time Seconds Register: Auf "0" als Startwert zurücksetzen
	ldr r1, =RTC_TSR
	str r10, [r1]
	
	// RTC Status Register: Counter aktiviert
	mov r2, #RTC_SR_SET
	str r2, [r3]
	
skip_alarm_flag:
	
	b loop_main




// Interrupt Service Routine zur Behandlung des RTC Alarm Interrupt
.thumb_func
isr_rtc_alarm:
	// TAF-Flag zurücksetzen durch schreiben von TAR
	ldr r2, =mode_flag
	ldrb r2, [r2]							// Laden des Mode-Flag und abfragen des aktuellen Modus (Stunden- oder Tag-Modus)
	ldr r1, =RTC_TAR
	cmp r2, #1
	ite eq
	ldreq r2, =RTC_TAR_SET_HOUR				// falls Stunden-Modus: schreiben der Sekunden einer Stunde in das RTC_TAR-Register
	ldrne r2, =RTC_TAR_SET_DAY				// falls Stunden-Modus: schreiben der Sekunden eines Tages in das RTC_TAR-Register
	str r2, [r1]
    
    // Alarm-Flag setzen
    ldr r1, =alarm_flag
    mov r2, #0x1
    strb r2, [r1]
    
	bx lr


// Interrupt Service Routine zur Behandlung des RTC Seconds Interrupt
.thumb_func
isr_rtc_sec:
    
    // Seconds-Flag setzen
    ldr r1, =seconds_flag
    mov r2, #0x1
    strb r2, [r1]
    
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
seconds_flag: .byte 0x0
alarm_flag: .byte 0x0
stop_flag: .byte 0x0
mode_flag: .byte 0x0
anzeige_stopped_flag: .byte 0x0
str_uhrzeit: .asciz "\nTimer: "
str_initialisierung: .asciz "\n\nDie Initialisierung des RTC wurde erfolgreich abgeschlossen und die Uhr zurueckgesetzt.\nDer Alarm-Interrupt ist aktiviert und das Alarmregister auf einen Tag eingestellt.\n"
str_alarm: .asciz "     ALARM: Endzeitpunkt erreicht!\n"
str_anzeige_an: .asciz "\nAnzeige an\n"
str_anzeige_aus: .asciz "\nAnzeige aus\n"
str_reset: .asciz "\n\nUhr zurueckgesetzt\n"
str_day: .asciz "\n\n24-Stunden-Modus\n"
str_hour: .asciz "\n\n1-Stunden-Modus\n"
str_uhr_vorgestellt: .asciz "\n\nUhr vorgestellt\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// Registeradressen

.equ SIM_SCGC5, 		0x40048038
.equ SIM_SCGC6, 		0x4004803C

.equ PIT_MCR,       0x40037000
.equ PIT_LDVAL1,    0x40037110
.equ PIT_TCTRL1,    0x40037118
.equ PIT_TFLG1,     0x4003711C

.equ NVIC_ISER2, 	0xE000E108

.equ RTC_CR, 0x4003D010
.equ RTC_SR, 0x4003D014
.equ RTC_LR, 0x4003D018
.equ RTC_TAR, 0x4003D008
.equ RTC_TSR, 0x4003D000
.equ RTC_IER, 0x4003D01C
.equ RTC_RAR, 0x4003D804
.equ RTC_WAR, 0x4003D800

.equ GPIOA_PSOR, 0x400FF004
.equ GPIOA_PCOR, 0x400FF008
.equ GPIOA_PDIR, 0x400FF010
.equ GPIOA_PDDR, 0x400FF014
.equ PORTA_PCR6, 0x40049018
.equ PORTA_PCR10, 0x40049028

.equ NVIC_ISER2, 	0xE000E108
.equ NVIC_ICPR2, 	0xE000E288 

.equ SCR_VTOR, 0xE000ED08		// Register für die Interrupt-Vektor-Tabelle (IVT)
.equ IVT_OFS_PIT1, 	0x154		// Offeset IVT-Vektor von PIT1
.equ IVT_OFS_RTC_ALARM, 0x148	// Offeset IVT-Vektor von RTC Alarm interrupt
.equ IVT_OFS_RTC_SEC, 0x14C		// Offeset IVT-Vektor von Seconds interrupt

// Bit-Banding Adressen

__BBREG	SIM_PORTA, SIM_SCGC5, 9
__BBREG	SIM_PIT, SIM_SCGC6, 23
__BBREG	SIM_RTC, SIM_SCGC6, 29
__BBREG	RTC_IER_TAIE, RTC_IER, 2
__BBREG	RTC_IER_TSIE, RTC_IER, 4
__BBREG PIT_PIT_TCTRL1_TEN, PIT_TCTRL1, 0

__BBREG	PDDR_PTA6, GPIOA_PDDR, 	6
__BBREG PTA6_LOW, GPIOA_PSOR, 	6
__BBREG PTA6_HIGH, GPIOA_PCOR,	6

__BBREG	PDDR_PTA10, GPIOA_PDDR, 10
__BBREG LED_LOW, GPIOA_PSOR, 	10
__BBREG LED_HIGH, GPIOA_PCOR,	10

// Setter und Bitmasks

.equ PORTA_PCR6_SET_ALT1, 	0x103			// Alternative 1 für PTA6, Pull Enable, Pull Select 
.equ PORTA_PCR10_SET_ALT1,  0x103			// Alternative 1 für GPIO, Pull Enable, Pull Select 

.equ NVIC_SET, 0x2C				// Bit 2 (Alarm) und Bit 3 (Seconds Interrupt) und Bit 5 (PIT1) setzen

.equ RTC_CR_SET, 0x100			// Supervisor Access Enable
.equ RTC_IER_SET, 0x14			// Time Seconds and Interrupt Alarm Enable
.equ RTC_SR_SET, 0x10			// Time Counter enable
.equ RTC_SR_SET_STOP_COUNTER, 0x0
.equ RTC_RAR_SET, 0xFF			// every read completes as normal
.equ RTC_WAR_SET, 0xF5			// set everything except Prescaler and Compensation (not used)
.equ RTC_TAR_SET_MINUTE, 59
.equ RTC_TSR_SET_NEARLY_DAY, 86394
.equ RTC_TSR_SET_NEARLY_HOUR, 3594

.equ RTC_EINSCHWINGZEIT_1000MS, 8333333   // Takte für ca. 2 Mikrosekunden bei 25 MHz: 25000000 -> BNE benötigt bei dieser Ausrichtung des Ziels 2 Takte, SUBS 1 Takt -> 25000000Takte/3 sind circa 8333333

.equ PIT_100_MS, 2500000		// 2.500.000 Takte entsprechen bei 25MHz: 0.1s
.equ PIT_200_MS, 5000000		// 5.000.000 Takte entsprechen bei 25MHz: 0.2s

// Zeichen

.equ DOPPELPUNKT, ':'
.equ NEW_LINE, '\n'
.equ LEERZEICHEN, ' '
.equ ZEHN, 10
.equ NINETEEN, 19
.equ THIRTY_FIVE, 35
.equ LAST_SEC, 59

.equ SHIFT_TWO, 2
.equ SHIFT_THREE, 3
.equ SHIFT_FOUR, 4
.equ SHIFT_FIVE, 5
.equ SHIFT_SIX, 6
.equ SHIFT_SEVEN, 7
.equ DIV_EIGHT, 8
.equ DIV_TEN, 10
.equ DIV_TWENTY, 20
.equ DIV_FOURTY, 40
.equ DIV_EIGHTY, 80

.equ MINUTEN_MAX, 60			// Maximale Minuten-Anzahl: 60
.equ STUNDEN_MAX, 24			// Maximale Stunden-Anzahl: 24
.equ TAGE_MAX, 31				// Maximale Tage-Anzahl: 30 -> Maximum bei 31 (vereinfacht nach Aufgabenstellung)
.equ MONATE_MAX, 13				// Maximale Monate-Anzahl: 12 -> Maximum bei 13
.equ JAHRE_MAX, 100				// Maximale Jahre-Anzahl: 100

// BITFOLGEN

.equ BITS_0_TO_19_MEZ, 0x40000
.equ BITS_0_TO_19_MESZ, 0x20000

.equ BITS_ZEIT_INI, 1			// erstes Bit ("Beginn Zeitinfo") ist stets auf 1 gesetzt

.equ BITS_RANDOM_WOCHENTAG_SONNTAG, 0x7
.equ BIT_PARITY_MINUTE_SET, 0x100
.equ BIT_PARITY_HOUR_SET, 0x8000
.equ BIT_PARITY_DATE_SET, 0x400000

main:	
	bl uart_init 
	
		
	mov r10, #0
	mov r11, #1
	
	// Takt für die benutzten Module aktivieren
	ldr r0, =SIM_PIT
	str r11, [r0]
	ldr r0, =SIM_RTC
	str r11, [r0]
	ldr r0, =SIM_PORTA
	str r11, [r0]
	
	// Port Konfuguration --------------------------------------------------------------------------
	
	// PTA6-Port konfiguieren
	ldr r1, =PORTA_PCR6_SET_ALT1 	// ALT1 (PTA6), Pull Enable, Pull Select
	ldr r0, =PORTA_PCR6
	str r1, [r0]
	
	// Datenrichtung von PTA6 als Ausgang
	ldr r0, =PDDR_PTA6
	strb r11, [r0]
	
	// LED-Port konfiguieren
	ldr r1, =PORTA_PCR10_SET_ALT1 	// ALT1 (GPIO), Pull Enable, Pull Select
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	
	// Datenrichtung von Port 10 als Ausgang
	ldr r0, =PDDR_PTA10
	strb r11, [r0]
	
	// Initialisierung des PIT --------------------------------------------------------------
	
	// Adresse der ISR fuer PIT1 in die IVT eintragen
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_pit1
	str r0, [r1, #IVT_OFS_PIT1]
	
	// PIT-Modul konfigurieren
	ldr r4, =PIT_MCR
	mov r1, #1					// FRZ=1, MDIS=0 (PIT stopped in Debug mode, PIT-Clock enabled) 
	str r1, [r4]
	
	// PIT1 Konfigurieren
	ldr r4, =PIT_TCTRL1
	mov r1, #2					// nicht mit PIT0 verkettet, Interrupt aktiviert, Timer zunächst deaktiviert
	str r1, [r4]
	
	// Initialisierung des RTC --------------------------------------------------------------
	
	// RTC Read Access Register (alles aktivieren)
	ldr r1, =RTC_RAR
	mov r2, #RTC_RAR_SET
	str r2, [r1]
	
	// RTC Lock Register (alles aktivieren)
	ldr r1, =RTC_LR
	mov r2, #RTC_RAR_SET
	str r2, [r1]
	
	// RTC Write Access Register
	ldr r1, =RTC_WAR
	mov r2, #RTC_WAR_SET
	str r2, [r1]
	
	// RTC Control Register: OSCE setzen (Um Kapazitäten nicht kümmern)
	ldr r1, =RTC_CR
	mov r2, #RTC_CR_SET
	str r2, [r1]
	
	// warte 100 ms als Einschwingzeit des Quarz
	ldr r6, =RTC_EINSCHWINGZEIT_1000MS
loop_wait:
	subs r6, r6, #1				// Zaehler dekrementieren
	bne loop_wait				// solange Zaehler noch nicht null
	
	// RTC Time Alarm Register: Wert, bei dem Alarm auslöst (eine Minute)
	ldr r1, =RTC_TAR
	ldr r2, =RTC_TAR_SET_MINUTE
	str r2, [r1]
	
	// RTC Interrupt Enable Register: TSIE und TAIE setzen
	ldr r1, =RTC_IER
	mov r2, #RTC_IER_SET
	str r2, [r1]
	
	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]

	// RTC Time Seconds Register: Auf "0" als Startwert zurücksetzen
	ldr r1, =RTC_TSR
	str r10, [r1]
	
	# -------------------------------------------------------------------------------------------------------
	// zunächst: Abfrage des Datums und der Uhrzeit (Wochentag muss nicht geändert werden und ist fix Montag)
	ldr r0, =str_eingabe_ini			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =stunde						// Laden des Zeigers auf das Stunden-Byte
	ldr r0, =str_stunde_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r5, =minuten					// Laden des Zeigers auf das Minuten-Byte
	ldr r0, =str_minuten_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r5]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =tag						// Laden des Zeigers auf das Tag-Byte
	ldr r0, =str_tag_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r5, =monat						// Laden des Zeigers auf das Monat-Byte
	ldr r0, =str_monat_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r5]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r6, =jahr						// Laden des Zeigers auf das Jahr-Byte
	ldr r0, =str_jahr_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r6]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben

	# -------------------------------------------------------------------------------------------------------
	
	// RTC Status Register: Counter aktiviert
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET
	str r2, [r3]
	
	// Adresse der ISRs fuer RTC Alarm und Seconds Interrupt in die IVT eintragen
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_rtc_alarm
	str r0, [r1, #IVT_OFS_RTC_ALARM]
	ldr r0, =isr_rtc_sec
	str r0, [r1, #IVT_OFS_RTC_SEC]
	
	// NVICISER2 und NCICICPR2: Bit 2 (Alarm) und Bit 3 (Seconds Interrupt) und Bit 5 (PIT1) setzen
	ldr r1, =NVIC_ISER2
	ldr r3, =NVIC_ICPR2
	mov r2, #NVIC_SET
	str r2, [r1]
	str r2, [r3]
	
	// Ausgabe der Fertigstellung der Initialisierung
	ldr r0, =str_initialisierung
	bl uart_putString
	
	


	
	
	// Schleife -----------------------------------------------------------------------------
	
	// Vorinitialisierung verwendeter Register
	ldr r5, =bit_counter
	ldr r6, =seconds_flag
	ldr r7, =alarm_flag
	ldr r8, =RTC_TSR
	
	// R9:  Startbits
	// R10: Datum
	// R11: Uhrzeit
	
	// Alarm-Flag sicherheitshalber zurücksetzen nach Abschluss Konfiguration (nach anschließen des K60 tritt dort Alarm Interrupt auf)
    ldr r1, =alarm_flag
    mov r2, #0x0
    strb r2, [r1]
	// zu Beginn Alarm-Überprüfung überspringen, da noch keine Minute erfolgt
	b skip_alarm_check
	
main_loop:

	// Überprüfung, ob das Zeichen 'n' in das Terminal eingegeben wurde
	bl uart_charPresent					// Funktion gibt 0 in R0 zurück, falls kein char eingegeben wurde
	teq r0, #0							// Überprüfung des Rückgabewertes auf Gleichheit mit 0
	beq skip_char_check					// falls gleich: kein char eingegeben -> char-Check überspringen
	
	bl uart_getChar						// Laden des Zeichens in R0
	
	cmp r0, #'n'							
	bne skip_char_check
	
	// neues Datum und Uhrzeit eingeben (bei einer solchen Art Eingabe ist das weiterlaufen des Signaloutputs unmöglich;
	// eine alternative Version, bei der das DCF77 Signal weiterhin ausgegeben werden könnte, wäre das festlegen eines
	// fixen Eingabecodes ohne Unterbrechung und Erläuterung wie (ttmmjjhhmm). Das wäre dann jedoch nicht so Benutzer-freundlich.
	
	ldr r0, =str_eingabe_laufzeit		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =stunde						// Laden des Zeigers auf das Stunden-Byte
	ldr r0, =str_stunde_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r4, =minuten					// Laden des Zeigers auf das Minuten-Byte
	ldr r0, =str_minuten_eingeben		// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
	ldr r4, =tag						// Laden des Zeigers auf das Tag-Byte
	ldr r0, =str_tag_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r4, =monat						// Laden des Zeigers auf das Monat-Byte
	ldr r0, =str_monat_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r4, =jahr						// Laden des Zeigers auf das Jahr-Byte
	ldr r0, =str_jahr_eingeben			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	bl uart_getByteBase10				// einen zweistelligen dezimalen Wert einlesen (Umandlung von DEC in HEX)
	strb r0, [r4]						// Speichern des Bytes
	bl uart_putByteBase10				// Ausgeben des Wertes des Bytes als Dezimalzahl
	
	ldr r0, =str_zeilenumbruch			// Zeiger auf String laden
	bl uart_putString					// String ausgeben
	
skip_char_check:

	// Alarm-Flag überprüfen: ist eine Minute vorbei?
	ldrb r1, [r7]				
	cmp r1, #0x1						// Alarm-Flag gesetzt?
	bne minute_end_not_reached			// falls nein, dann zu minute_end_not_reached springen
	
	// Alarm-Flag zurücksetzen
	mov r1, #0x0
	strb r1, [r7]
	
	// Time Counter stoppen (evtl. läuft er noch)
	ldr r3, =RTC_SR
	mov r2, #RTC_SR_SET_STOP_COUNTER
	str r2, [r3]

	// RTC Time Seconds Register: Auf "0" als Startwert zurücksetzen
	ldr r2, =RTC_TSR
	str r1, [r2]
	
	// RTC Status Register: Counter aktiviert
	mov r2, #RTC_SR_SET
	str r2, [r3]

skip_alarm_check:
	
	mov r0, #NEW_LINE					// Terminalausgabe: neue Zeile
	bl uart_putChar

	// Ausgabe der aktuellen Zeit in der Darstellung tt:hh:mm (Teit der eingegebenen bzw. gerade über DCF77 ausgegebenen Minute)
	// Tag
	ldr r1, =tag
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Doppelpunkt
	mov r0, #DOPPELPUNKT
	bl uart_putChar
	
	// Stunde
	ldr r1, =stunde
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Doppelpunkt
	mov r0, #DOPPELPUNKT
	bl uart_putChar
	
	// Minute
	ldr r1, =minuten
	ldrb r0, [r1]
	bl print_element					// Aufruf des Unterprogramms zur Element-Ausgabe
	
	// Leerzeichen
	mov r0, #LEERZEICHEN
	bl uart_putChar
	
	// Terminalausgabe "Uhr"
	ldr r0, =str_uhr
	bl uart_putString
	
	mov r0, #NEW_LINE					// Terminalausgabe: neue Zeile
	bl uart_putChar
	
	// Nun wird die aktuelle Zeit erhöht (Zet der "nächsten Sekunde")
	
	// Minuten inkrementieren
	ldr r0, =minuten					// 1. Argument: Zeiger auf das Minuten-Byte
    mov r1, #MINUTEN_MAX				// 2. Argument: Minuten-Maximum
    mov r2, #0							// 3. Argument: Startwert für Minuten nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r0, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne skip_increment_rest				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Stunde inkrementieren
    ldr r0, =stunde						// 1. Argument: Zeiger auf das Stunden-Byte
    mov r1, #STUNDEN_MAX				// 2. Argument: Stunden-Maximum
    mov r2, #0							// 3. Argument: Startwert für Stunden nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r0, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne skip_increment_rest				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Tag inkrementieren
    ldr r0, =tag						// 1. Argument: Zeiger auf das Tag-Byte
    mov r1, #TAGE_MAX					// 2. Argument: Tag-Maximum
    mov r2, #1							// 3. Argument: Startwert für Tage nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r0, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne skip_increment_rest				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Monat inkrementieren
    ldr r0, =monat						// 1. Argument: Zeiger auf das Monat-Byte
    mov r1, #MONATE_MAX					// 2. Argument: Monat-Maximum
    mov r2, #1							// 3. Argument: Startwert für Monate nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
    teq r0, #1							// Überprüfe Rückgabewert des Unterprogramms
    bne skip_increment_rest				// falls nicht 1: kein Überlauf: restliche ELemente müssen nicht erneuert werden: springe zur Terminal-Ausgabe
    
    // Jahr inkrementieren
    ldr r0, =jahr						// 1. Argument: Zeiger auf das Jahr-Byte
	mov r1, #JAHRE_MAX					// 2. Argument: Jahr-Maximum
	mov r2, #0							// 3. Argument: Startwert für Jahre nach "Überlauf"
    bl increment_element				// Aufruf des Unterprogramms
   
skip_increment_rest:

	// Bit-Counter zurücksetzen
	mov r0, #0
	strb r0, [r5]
	
	// Die über DCF77 auszugebende Zeit ist jetzt festgelegt, jetzt muss die Bitfole berechnet werden
	
	// 1. Schritt Bitfolge des zu Tag, Monat und jahr berechnen (in R10):
	// Kalendertag (6 Bit) - Wochentag (3 Bit: 111) - Monat (5 Bit) - Jahr (8 Bits) - Parität Datum (1 Bit)
	
	// Kalendertag berechnen
	ldr r2, =tag
	ldrb r0, [r2]
	bl calculate_dcf77_bits				// Unterprogramm zum berechnen der DCF77-Bits aufrufen
	mov r10, r0
	
	// Wochentag-Bits hinzufügen (Wochentag fix: Sonntag)
	mov r2, #BITS_RANDOM_WOCHENTAG_SONNTAG
	lsl r2, r2, #6						
	orr r10, r10, r2					// Wochentag-Bits um 6 nach links rotieren und mit R10 verodern
	
	// Monats-Bitfolge berechnen
	ldr r2, =monat
	ldrb r0, [r2]
	bl calculate_dcf77_bits				// Unterprogramm zum berechnen der DCF77-Bits aufrufen
	lsl r2, r0, #9
	orr r10, r10, r2					// Monats-Bits um 6 nach links rotieren und mit R10 verodern
	
	// Jahres-Bitfolge berechnen
	ldr r2, =jahr
	ldrb r0, [r2]
	bl calculate_dcf77_bits				// Unterprogramm zum berechnen der DCF77-Bits aufrufen
	lsl r2, r0, #14
	orr r10, r10, r2					// Jahres-Bits um 14 nach links rotieren und mit R10 verodern
	
	// Paritätsbit zum Datum berechnen und mit R10 an entsprechender Stelle verodern, falls gesetzt
	eor r0, r10, r10, lsr #1 			// XOR mit um 1 Bit nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #2 				// XOR mit um 2 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #4 				// XOR mit um 4 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #8 				// XOR mit um 8 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #16 			// XOR mit um 16 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #32 			// XOR mit um 32 Bits nach rechts verschobener Bitfolge
    and r0, r0, #1         				// Das Paritäts-Bit durch UND isolieren
    cmp r0, #1							// Paritätsbit zur Stunde setzen, falls Ergebnis gleich 1
    it eq
    orreq r10, r10, #BIT_PARITY_DATE_SET
	
	
	// 2. Schritt: Bitfolge des zu Stunde und Minute berechnen (in R11):
	
	// Minuten-Bitfolge berechnen
	mov r11, #BITS_ZEIT_INI
	ldr r2, =minuten
	ldrb r0, [r2]
	bl calculate_dcf77_bits				// Unterprogramm zum berechnen der DCF77-Bits aufrufen
	lsl r2, r0, #1
	orr r11, r11, r2					// Minuten-Bits um 1 nach links rotieren und mit R11 verodern
	
	// Paritätsbit Minute berechnen
	eor r0, r0, r0, lsr #1 				// XOR mit um 1 Bit nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #2 				// XOR mit um 2 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #4 				// XOR mit um 4 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #8 				// XOR mit um 8 Bits nach rechts verschobener Bitfolge
    and r0, r0, #1         				// Das Paritäts-Bit durch UND isolieren
    cmp r0, #1							// Paritätsbit zur Minute setzen, falls Ergebnis gleich 1
    it eq
    orreq r11, r11, #BIT_PARITY_MINUTE_SET
    
	// Stunden-Bitfolge berechnen
	ldr r2, =stunde
	ldrb r0, [r2]
	bl calculate_dcf77_bits				// Unterprogramm zum berechnen der DCF77-Bits aufrufen
	lsl r2, r0, #9
	orr r11, r11, r2					// Stunden-Bits um 9 nach links rotieren und mit R11 verodern
	
	// Paritätsbit Stunde berechnen
	eor r0, r0, r0, lsr #1 				// XOR mit um 1 Bit nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #2 				// XOR mit um 2 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #4 				// XOR mit um 4 Bits nach rechts verschobener Bitfolge
    eor r0, r0, r0, lsr #8 				// XOR mit um 8 Bits nach rechts verschobener Bitfolge
    and r0, r0, #1         				// Das Paritäts-Bit durch UND isolieren
    cmp r0, #1							// Paritätsbit zur Minute setzen, falls Ergebnis gleich 1
    it eq
    orreq r11, r11, #BIT_PARITY_HOUR_SET


	 // Bitfole der Anfangsbits festlegen (in R9)
	 // Prüfen, ob Monat November-März (MEZ) oder April-Oktober (MESZ) (vereinfacht)
	 ldr r1, =monat
	 ldrb r0, [r1]						// Laden des aktuellen Monat-Wertes
	 cmp r0, #3
	 itt ls								// falls Monat in Januar - März liegt
	 ldrls r9, =BITS_0_TO_19_MEZ		// MEZ
	 bls minute_end_not_reached			// dann restliche Überprüfung überspringen
	 cmp r0, #10
	 ite hi								// falls Monat in November oder Dezember
	 ldrhi r9, =BITS_0_TO_19_MEZ		// MEZ
	 ldrls r9, =BITS_0_TO_19_MESZ		// sonst: MESZ

minute_end_not_reached:

	// Überprüfen, ob das Sekunden-Flag gesetzt ist
	ldrb r1, [r6]						// Sekunden-Flag gesetzt?
	cmp r1, #0x0
	beq main_loop						// nein, also Spring zum Alarm-Flag-Check
	
	// Sekunden-Flag zurücksetzen
	mov r1, #0
	strb r1, [r6]
	
	// Festlegen des DCF77-Impulses bzw. des Bits je nach Stand des Bit-Counters: ---------------------------------
	
	// falls letzte Sekunde einer Minute (Bit-Counter bei 59), dann kein Impuls und  Zeilenumbruch im Terminal
	ldrb r1, [r5]
	cmp r1, #LAST_SEC
	it ne
	bne skip_sec_59_output				// Behandlung der Sekunde 59 überspringen, falls diese nicht aktuell
	mov r0, #NEW_LINE
	bl uart_putString
	b main_loop							// Rücksprung zum Loop-Beginn: Alarm-Check
	
skip_sec_59_output:
	
	// falls aktuelle Sekunde 0 bis 19: Anfangsbits
	ldrb r1, [r5]
	cmp r1, #NINETEEN
	ittt ls
	andls r0, r9, #1					// LSB von R9 in R0 kopieren
	lsrls r9, r9, #1					// R9 um eins nach rechts verschieben, um kopiertes Bit "zu entfernen"
	bls impulse_output
	
	
	// falls aktuelle Sekunde kleiner 36: Uhrzeit-Bits
	cmp r1, #THIRTY_FIVE
	ittt ls
	andls r0, r11, #1					// LSB von R11 in R0 kopieren
	lsrls r11, r11, #1					// R11 um eins nach rechts verschieben, um kopiertes Bit "zu entfernen"
	bls impulse_output
	
	// hier muss aktuelle Sekunde zwischen 36 und 59 sein: Datum-Bits
	and r0, r10, #1						// LSB von R10 in R0 kopieren
	lsr r10, r10, #1					// R10 um eins nach rechts verschieben, um kopiertes Bit "zu entfernen"

impulse_output:
	
	// entsprechende Impuls-Dauer nach LDVAL1 schreiben (je nachdem ob Bit in R0 gesetzt oder nicht)
	ldr r4, =PIT_LDVAL1
	cmp r0, #0					// falls R0 gleich 0
	ite eq
	ldreq r1, =PIT_100_MS		// 100ms auswählen
	ldrne r1, =PIT_200_MS		// ansonsten: 200ms auswählen
	str r1, [r4]				// Schreiben in PIT_LDVAL1
	
	mov r4, r0					// Bit nach R4 kopieren
	
	// PIT aktivieren
	ldr r3, =PIT_PIT_TCTRL1_TEN
	mov r1, #1
    strb r1, [r3]	

	// Impuls auf blauer LED und PTA6 ausgeben (-> Signal auf low)
	ldr r3, =LED_LOW
	str r1, [r3]
	ldr r3, =PTA6_LOW
	str r1, [r3]
	
	// warten, bis PIT-Flag gesetzt ist
loop_wait_for_pit:
	ldr r1, =pit1_flag			
	ldrb r0, [r1]				
	cmp r0, #0x0
	beq loop_wait_for_pit
	
	//  PIT-Flag wieder zurücksetzen und PIT ausschalten
	mov r2, #0
	strb r2, [r1]
	ldr r3, =PIT_PIT_TCTRL1_TEN
    strb r2, [r3]
	
	// PTA6 und blaue LED: Signal wieder auf high
	ldr r3, =LED_HIGH
	mov r1, #1
    str r1, [r3]         //1 nach __BBREG LED_OFF, GPIOA_PCOR,10
    ldr r3, =PTA6_HIGH
	str r1, [r3]
	
	// Bit ausgeben als Dezimalzahl
	mov r0, r4
	bl uart_putByteBase10
	
	// Bit-Counter um 1 erhöhen
	ldrb r1, [r5]
	add r1, r1, #1
	strb r1, [r5]

	b main_loop // Rücksprung zum Loop-Beginn






/*
 * Rechnet wert (z.B. Jahreszahl) in DCF-77 Bit-Darstellung um
 * Parameter: RO: Wert, der in DCF-77 Bits umgerechnet werden soll
 * Rueckgabe: R0: DCF-77 Bits
 */		
.thumb_func
calculate_dcf77_bits:
	push {r4, lr}
	
	mov r3, r0	// Sichern des Übergabeparameters in R3
	mov r0, #1	// Bit 1 zur Bitverschiebung
	mov r2, #0	// DCF-77-Wert
	
	// falls Wert durch 80 teilbar -> Bit 7 setzen
	mov r4, #DIV_EIGHTY
	udiv r1, r3, r4		// Übergabewert durch 80 teilen
	cmp r1, #0
	ittt hi				// falls teilbar durch 80
	subhi r3, r3, r4	// 80 vom Übergabewert abziehen
	lslhi r1, r0, #SHIFT_SEVEN	// Bit 7 auf 1 setzen
	orrhi r2, r2, r1
	// falls Wert durch 40 teilbar -> Bit 6 setzen
	mov r4, #DIV_FOURTY		// ...
	udiv r1, r3, r4
	cmp r1, #0
	ittt hi
	subhi r3, r3, r4
	lslhi r1, r0, #SHIFT_SIX	// Bit 6 auf 1 setzen
	orrhi r2, r2, r1
	// falls Wert durch 20 teilbar -> Bit 5 setzen
	mov r4, #DIV_TWENTY
	udiv r1, r3, r4
	cmp r1, #0
	ittt hi
	subhi r3, r3, r4
	lslhi r1, r0, #SHIFT_FIVE	// Bit 5 auf 1 setzen
	orrhi r2, r2, r1
	// falls Wert durch 10 teilbar -> Bit 4 setzen
	mov r4, #DIV_TEN
	udiv r1, r3, r4
	cmp r1, #0
	ittt hi
	subhi r3, r3, r4
	lslhi r1, r0, #SHIFT_FOUR	// Bit 4 auf 1 setzen
	orrhi r2, r2, r1
	// falls Wert durch 8 teilbar -> Bit 3 setzen
	mov r4, #DIV_EIGHT
	udiv r1, r3, r4
	cmp r1, #0
	ittt hi
	subhi r3, r3, r4
	lslhi r1, r0, #SHIFT_THREE	// Bit 3 auf 1 setzen
	orrhi r2, r2, r1
	// falls Wert durch 4 teilbar -> Bit 2 setzen
	mov r4, #SHIFT_FOUR
	udiv r1, r3, r4
	cmp r1, #0
	ittt hi
	subhi r3, r3, r4
	lslhi r1, r0, #SHIFT_TWO	// Bit 2 auf 1 setzen
	orrhi r2, r2, r1
	// falls Wert durch 2 teilbar -> Bit 1 setzen
	mov r4, #SHIFT_TWO
	udiv r1, r3, r4
	cmp r1, #0
	ittt hi
	subhi r3, r3, r4
	lslhi r1, r0, #1	// Bit 1 auf 1 setzen
	orrhi r2, r2, r1
	// falls Wert durch 1 teilbar -> Bit 0 setzen
	udiv r1, r3, r0
	cmp r1, #0
	it hi
	orrhi r2, r2, #1	// Bit 0 auf 1 setzen
	
	mov r0, r2
	pop {r4, pc}
	
/*
 * ISR fuer PIT1
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func	
isr_pit1:						// ISR fuer PIT1
	mov r0, #1					
	ldr r1, =pit1_flag			// Flag fuer PIT
	strb r0, [r1]				// setzen
	ldr r1, =PIT_TFLG1			// Interrupt-Flag
	str r0, [r1] 				// zuruecksetzen
	bx lr						// Ruecksprung
	
// Interrupt Service Routine zur Behandlung des RTC Alarm Interrupt
.thumb_func
isr_rtc_alarm:
	// TAF-Flag zurücksetzen durch schreiben von TAR
	ldr r1, =RTC_TAR
	ldr r2, =RTC_TAR_SET_MINUTE
	str r2, [r1]
    
    // Alarm-Flag setzen
    ldr r1, =alarm_flag
    mov r2, #0x1
    strb r2, [r1]
    
	bx lr

// Interrupt Service Routine zur Behandlung des RTC Seconds Interrupt
.thumb_func
isr_rtc_sec:
    
    // Seconds-Flag setzen
    ldr r1, =seconds_flag
    mov r2, #0x1
    strb r2, [r1]
    
	bx lr

.thumb_func
print_element:
	// Überprüft neben dem Ausgeben, ob auszugebender Wert eine einstellige oder zweistellige Dezimalzahl darstellt und setzt ggf. eine '0' davor

    push {lr}
    
    cmp r0, #ZEHN						// Vergleiche den Wert in R0 mit dem Wert 10 (Dezimal)
    ite hs								// größer gleich 10?
    ldrhs r1, =uart_putByteBase10		// Ausgeben des Wertes des Bytes ohne führende 0
    ldrlo r1, =uart_putByte				// Ausgeben des Wertes des Bytes mit führender 0
    blx r1								// Aufrufen des entsprechenden Unterprogramms
    
    pop {pc}

.thumb_func
increment_element:
	// Inkrementiert ein einzelnes Elemnt der Uhr und überprüft auf einen eventuellen "Überlauf"
	// Argumente: 
	// R0: Adresse des Elements
	// R1: Maximalwert des Elements
	// R2: Startwert des Elements nach "Überlauf"
	// Rückgabewerte:
	// R0: Anzeige eines eventuellen Überlaufs (Wert 1)
	
    push {lr}
    
    ldrb r3, [r0]						// Laden des Wertes des Elements
    add r3, r3, #0x1					// Erhöhen des Elements um 1
    
    // "Überlauf" überprüfen
    cmp r3, r1							// Vergleich des Erhöhten Elements mit dem zulässigen Maximum
    itte eq								// falls gleich -> Überlauf
    moveq r1, #0x1						// Überlauf durch Rückgabewert in R1 anzeigen
    moveq r3, r2						// Element auf den in R2 übergebenen Startwert zurücksetzen
    movne r1, #0x0						// falls nicht gleich: kein Überlauf durch Rückgabewert in R1 anzeigen
    
    strb r3, [r0]						// Abspeichern des Elements
    
    mov r0, r1							// Überlauf-Variable als Rückgabewert des UP in R0 bewegen
    
    pop {pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
seconds_flag: .byte 0x0
alarm_flag: .byte 0x0
pit1_flag: .byte 0x0
bit_counter: .byte 0x0
str_uhr: .asciz "Uhr\n"
str_initialisierung: .asciz "\n\nDie Initialisierung des RTC wurde erfolgreich abgeschlossen.\nDer Alarm-Interrupt ist aktiviert und das Alarmregister auf einen Tag eingestellt.\nUm das Datum oder die Uhrzeit zur Laufzeit zu aendern, geben Sie den Buchstaben 'n' in das Terminal ein.\n"
str_uhrzeit_geaendert: .asciz "\n\nUhr geaendert\n"
minuten: .byte 0x0
stunde: .byte 0x0
tag: .byte 0x0
monat: .byte 0x0
jahr: .byte 0x0
jahrhundert: .byte 0x14
str_eingabe_ini: .asciz "\nGeben Sie vor dem Start der Ausgabe des DCF-77-Signals bitte Uhrzeit und Datum an.\n"
str_eingabe_laufzeit: .asciz "\nGeben Sie nun bitte die neue Uhrzeit und das neue Datum an. Bitte beachten Sie, dass das DCF-77-Signal erst nach Ablauf der bisherigen Minute aktualisiert werden kann und die Impulse der laufenden Minute ungueltig sind (verschoben und unvollstaendig).\n"
str_stunde_eingeben: .asciz "\nStunde eingeben (hh): "
str_minuten_eingeben: .asciz "\nMinuten eingeben (mm): "
str_tag_eingeben: .asciz "\nTag eingeben (dd): "
str_monat_eingeben: .asciz "\nMonat eingeben (mm): "
str_jahr_eingeben: .asciz "\nJahr eingeben (jj): "
str_zeilenumbruch: .asciz "\n\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// Registeradressen

.equ SIM_SCGC5, 0x40048038
.equ SIM_SCGC6, 0x4004803C

.equ GPIOA_PSOR, 0x400FF004
.equ GPIOA_PCOR, 0x400FF008
.equ GPIOA_PDIR, 0x400FF010
.equ GPIOA_PDDR, 0x400FF014
.equ PORTA_PCR6, 0x40049018
.equ PORTA_PCR10, 0x40049028

.equ FTM0_CNTIN, 	0x4003804C
.equ FTM0_CNT,		0x40038004
.equ FTM0_MOD,		0x40038008
.equ FTM0_MODE, 	0x40038054
.equ FTM0_C3V, 		0x40038028
.equ FTM0_C3SC, 	0x40038024
.equ FTM0_SC, 		0x40038000
.equ FTM0_POL, 		0x40038070
.equ FTM0_SC, 		0x40038000

.equ NVIC_ISER2, 	0xE000E108
.equ NVIC_ICPR2, 	0xE000E288 
.equ SCR_VTOR, 		0xE000ED08		// Register für die Interrupt-Vektor-Tabelle (IVT)
.equ IVT_OFS_FTM0, 	0x138			// Offeset zum IVT-Vektor von FTM0 Interrupt

// Setter and Values
.equ FTM0_SC_SET, 			0x40			// FlexTimer im Systemtakt einstellen: PS: 000 (Divide by 1), CLKS: 00 (System Clock disabled), CPWMS: 0 (Up-Counting)
											// TOIE: 1 (TOF Interrupts enabled)
.equ FTM0_C3SC_SET, 		0x68			// CHIE: 1, MSB:MSA: 10, ELSB:ELSA: 10, DMA: 0
.equ FTM0_MOD_SET_1MS, 		24999  			// 1 ms für 25 MHz Systemtakt notwendig

.equ PORTA_PCR6_SET_ALT3, 	0x303			// Alternative 3 für FTM0_CH3, Pull Enable, Pull Select 
.equ PORTA_PCR10_SET_ALT1,  0x103			// Alternative 1 für GPIO, Pull Enable, Pull Select 

.equ NVIC_SET, 				0x40000000		// Bit 30 (=IRQ 62 mod 32)

// Bit-Banding Konstanten

__BBREG	SIM_PORTA, SIM_SCGC5, 9
__BBREG	SIM_FTM0, SIM_SCGC6, 24

__BBREG FTM0_SC_CLKS , FTM0_SC , 3
__BBREG FTM0_SC_TOF , FTM0_SC , 7
__BBREG FTM0_SC_POL3 , FTM0_POL , 3

__BBREG	PDDR_PTA6, GPIOA_PDDR , 6

__BBREG	PDDR_PTA10, GPIOA_PDDR, 10
__BBREG LED_LOW, GPIOA_PSOR, 10
__BBREG LED_HIGH, GPIOA_PCOR,10


// Zeichen

// Konstanten


main:	
	bl uart_init
	
	mov r4, #0
	mov r5, #1
	
	// SIM: Takt für die benutzten Module aktivieren
	ldr r0, =SIM_FTM0
	str r5, [r0]
	ldr r0, =SIM_PORTA
	str r5, [r0]
	
	// Port Konfuguration --------------------------------------------------------------------------
	
	// PCR6 Port konfiguieren
	ldr r1, =PORTA_PCR6_SET_ALT3 	// ALT3, Pull Enable, Pull Select
	ldr r0, =PORTA_PCR6
	str r1, [r0]
	
	// Datenrichtung von PTA6 als Ausgang
	ldr r0, =PDDR_PTA6
	strb r5, [r0]
	
	// LED Port konfiguieren
	ldr r1, =PORTA_PCR10_SET_ALT1 	// ALT1 (GPIO), Pull Enable, Pull Select
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	
	// Datenrichtung von PTA10 als Ausgang
	ldr r0, =PDDR_PTA10
	strb r5, [r0]
	
	// FTM0 Konfuguration ---------------------------------------------------------------------------
	
	//  Status and Control Register konfiguieren (CLSK=00 -> Counter zu Beginn deaktiviert)
	ldr r1, =FTM0_SC_SET
	ldr r0, =FTM0_SC
	str r1, [r0]
	
	// Startwert des Counters setzen
	ldr r0, =FTM0_CNTIN
	str r4, [r0]
	
	// Initialisieren des Counters (write any value sets value to CNTIN)
	ldr r0, =FTM0_CNT
	str r5, [r0]
	
	// Overflow-Wert des Counters: Grundschwingung für Grundfrequenz von 1kHz setzen
	ldr r1, =FTM0_MOD_SET_1MS
	ldr r0, =FTM0_MOD
	str r1, [r0]
	
	// Status and Control für Channel 3 setzen (High-True Pulse -> Clear Output on match)
	ldr r1, =FTM0_C3SC_SET
	ldr r0, =FTM0_C3SC
	str r1, [r0]
	
	// C3V-Register setzen : PW-Länge zu Beginn auf 100% setzen (match value) 
	ldr r0, =FTM0_C3V
	ldr r1, =FTM0_MOD_SET_1MS
	str r1, [r0]
	// aktuelle PW-Länge sichern
	ldr r0, =current_impulse_length
	str r1, [r0]
	
	// Adresse der ISRs fuer FTM0 in die IVT eintragen (Single interrupt vector for all sources))
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_ftm0
	str r0, [r1, #IVT_OFS_FTM0]
	
	// NVICISER2 und NCICICPR2: Bit 30 (FTM0) setzen
	ldr r1, =NVIC_ISER2
	ldr r3, =NVIC_ICPR2
	mov r2, #NVIC_SET
	str r2, [r1]
	str r2, [r3]
	
	// set Status and Control Register CLSK=01 (Enable Counter -> System Clock)
	ldr r0, =FTM0_SC_CLKS
	str r5, [r0]
	
	
	// Ausgabe FTM0 gestartet mit Impulsdauer von 100% (2ms) und Erläuterung zu möglichen Eingaben
	ldr r0, =str_start_description_1
	bl uart_putString
	ldr r0, =str_start_description_2
	bl uart_putString
	
	
	
	
	// Schleife -----------------------------------------------------------------------------
	
	// Vorinitialisierung verwendeter Register
	ldr r11, =LED_LOW
	ldr r12, =LED_HIGH
	
loop_main:
	
	// Überprüfung, ob ein Zeichen in das Terminal eingegeben wurde
	bl uart_charPresent						// Funktion gibt 0 in R0 zurück, falls kein char eingegeben wurde
	teq r0, #0								// Überprüfung des Rückgabewertes auf Gleichheit mit 0
	beq loop_wait_for_flag_reset			// falls gleich: kein char eingegeben -> char-Check überspringen
	
	bl uart_getChar							// Laden des Zeichens in R0
	
	// Zeichen prüfen
	// - soll die Polarity geändert werden?
	cmp r0, #'+'
	itt eq
	moveq r6, #1	
	beq setup_polarity_request
	cmp r0, #'-'
	itt eq
	moveq r6, #0	
	beq setup_polarity_request
	// - soll eine neue Impulslänge berechnet werden?
	cmp r0, #'0'
	beq setup_impulse_length_request
	cmp r0, #'1'
	beq setup_impulse_length_request
	cmp r0, #'2'
	beq setup_impulse_length_request
	cmp r0, #'3'	
	beq setup_impulse_length_request
	cmp r0, #'4'	
	beq setup_impulse_length_request
	cmp r0, #'5'	
	beq setup_impulse_length_request
	cmp r0, #'6'	
	beq setup_impulse_length_request
	cmp r0, #'7'	
	beq setup_impulse_length_request
	cmp r0, #'8'	
	beq setup_impulse_length_request
	cmp r0, #'9'	
	beq setup_impulse_length_request
	
	// sonst: es wurde kein relevantes Zeichen eigegeben -> Zeichen kann verworfen werden
	b loop_wait_for_flag_reset

setup_polarity_request:
	
	ldr r5, =polarity_switch_needed
	mov r2, #1
	// prüfen, ob eingegebene Polarität bereits aktiv ist oder geändert werden muss
	ldr r1, =current_polarity_flag
	ldrb r1, [r1]
	cmp r6, r1
	it ne
	// falls nicht gleich: polarity_switch_needed auf 1 setzen
	strbne r2, [r5]
	
	b loop_wait_for_flag_reset
	
setup_impulse_length_request:

	// neue Impulselänge berechnen R0 * 10%PWM + 5%PWM entspricht RO * PWM/10 + PWM/20
	ldr r6, =current_impulse_length
	ldr r6, [r6]
	// Char (Eingabe) in Integer umwandeln (0x30 subtrahieren)
	sub r0, r0, #0x30
	// 10%PWM berechnen
	mov r1, #10
	udiv r2, r6, r1
	// mit R0 multiplizieren
	mul r2, r2, r0
	// 5%PWM berechnen
	mov r1, #20
	udiv r3, r6, r1
	// zum Produkt addieren
	add r2, r3, r2
	
	// berechneten Wert in impulse_length sichern
	ldr r5, =impulse_length
	str r2, [r5]
	
	// Impulse Length Entered-Flag setzen
	ldrb r5, =impulse_length_entered_flag
	mov r1, #1
	strb r1, [r0]
	
loop_wait_for_flag_reset:

	// warte, bis impulse_length_entered-Flag und polarity_switch_needed-Flag von Interrupt-Routine zurückgesetzt wurde
	ldr r0, [r5]
	cmp r0, #1
	beq loop_wait_for_flag_reset
	
	ldr r1, =current_polarity_flag
	cmp r0, #1
	beq loop_wait_for_flag_reset
	
	// bereit für neue Eingabe durch Rücksprung zum Loop-Beginn
	b loop_main
	




	 
// Interrupt Service Routine zu FTM0
.thumb_func
isr_ftm0:
	
	// DEBUG
	ldr r1, =LED_LOW
	mov r2, #1
	str r2, [r1]
	
	// 1. Check, ob Overflow oder Channel Interrupt  
	// -> Timer Overflow Flag-Flag checken, um Ursprung herauszufinden
	ldr r1, =FTM0_SC_TOF
	ldrb r1, [r1]
	mov r2, #0
	cmp r1, #1									// falls gesetzt: Timer Overflow Interrupt, sonst Channel interrupt
	itt eq
	strbeq r2, [r1]								// TOF Flag kann in diesem fall gleich zurückgesetzt werden, da Register gelesen wurde
	beq jump_to_overflow_interrupt_handling		// zu OVH-Interrupt Behandlung springen
	
	// falls CHANNEL-INTERRUPTT:---------------------------------------------------------------------------
	
	// Flag prüfen, ob Zeichen eingegeben wurde
	ldr r2, =impulse_length_entered_flag
	ldrb r3, [r2]
	cmp r3, #0
	bne skip_change_impulse_length				// falls kein Zeichen eingegeben wurde -> Sprung zum Flag zurücksetzen

	// char_impulse_length_entered-Flag zurücksetzen
	mov r0, #0
	strb r0, [r2]
	
	// Counter deaktivieren: CLKS in FTM0_SC auf 0 setzen
	ldr r3, =FTM0_SC
	ldr r1, [r3]
	bic r1, r1, #0x8
	str r1, [r3]
	
	// FTMEN von 1 auf 0 setzen in FTM0_MODE
	ldr r2, =FTM0_MODE
	ldr r1, [r2]
	bic r1, r1, #1
	str r1, [r2]
	
	// neue Impulslänge laden und in C3V schreiben
	ldr r1, =impulse_length
	ldr r1, [r1]
	ldr r0, =FTM0_C3V
	str r1, [r0]
	
	// FTMEN von 0 auf 1 setzen in FTM0_MODE
	ldr r1, [r2]
	orr r1, r1, #1
	str r1, [r0]
	
	// - Counter wieder aktivieren: CLKS in FTM0_SC auf 1 setzen
	ldr r1, [r3]
	orr r1, r1, #0x8
	str r1, [r3]

skip_change_impulse_length:
	
	// Channel-Interrupt-Flag zurücksetzen
	ldr r2, =FTM0_C3SC
	ldr r1, [r2]		// Lesen des FTM0_C3SC-Registers
	bic r1, r1, #0x80
	str r1, [r2]		// CHF-Bit auf 0 zurücksetzen
	
	// Rücksprung aus ISR, da nur ein zu verarbeitender Interrupt pro ISR vorliegen kann
	bx lr

jump_to_overflow_interrupt_handling:
	
	// falls OVERFLOW-INTERRUPT: -----------------------------------------------------------------------
	
	// prüfen, ob ein Polarity-Wechsel durchgeführt werden muss
	ldr r2, =polarity_switch_needed
	ldrb r3, [r2]
	cmp r3, #0
	bne jump_to_isr_end				// falls kein Wechsel angefragt wurde -> Sprung zum ISR-Ende
	
	// Zurücksetzen des polarity_switch_needed-Flags
	mov r1, #0
	strb r1, [r2]
	
	// Manual: If POLn = 0, the channel (n) output polarity is high, so the logical one is the active
	// state and the logical zero is the inactive state.
		
	// Counter deaktivieren: CLKS in FTM0_SC auf 0 setzen
	ldr r3, =FTM0_SC
	ldr r1, [r3]
	bic r1, r1, #0x8
	str r1, [r3]
	
	// Polarity switchen
	ldr r1, =FTM0_SC_POL3
	ldrb r2, [r1]
	eor r2, r2, #1		// Bit invertieren
	strb r2, [r1]
	
	// Counter wieder aktivieren: CLKS in FTM0_SC auf 1 setzen
	ldr r1, [r3]
	orr r1, r1, #0x8
	str r1, [r3]


jump_to_isr_end:	

	bx lr					// Rücksprung




/*** Datenbereich (ab 0x20000000) ***/
.data
impulse_length_entered_flag: .byte 0x0
polarity_entered_flag: .byte 0x0

current_polarity_flag: .byte 0x0
current_impulse_length: .word 0x0

impulse_length: .word 0x0
polarity_switch_needed: .word 0x0

str_start_description_1: .asciz "\nDas FTM0-Modul wurde mit einer Impulsdauer von 100% der Grundschwingungsdauer gestartet.\n"
str_start_description_2: .asciz "Moegliche Eingaben sind:\n\n - Ziffern Z von 0 bis 9 ,um die Impulsdauer auf ungefaehr Z * 10% + 5% der Grundschwingungsdauer anzupassen.\n\n - Zeichen + und -, um die Polaritaet des PWM-Impulses festzulegen.\n\n>"
str_prompt: .asciz "\n>"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ COUNTER, 0x10				// Anzahl der Schleifendurchläufe
.equ TIMECONST, 0x0B			// Zeitkonstante Timer starten und stoppen

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:

	//***********************
	// INIT
	bl uart_init
	
	/*	INIT Pit3
	* PIT_MCR=0x0  Timer Clock enabled, Timers running in debug mode
	* PIT_LDVAL3=0xFFFFFFFF PIT1 Start Value
	* PIT_TCTRL3=0x3 Timer PIT1 aktiv, Interrupt disabled	
	*/
	bl pit3_init	
	//***********************
	
	//-----------------------
	// Bestimmung der Konstante für Timer
//	bl pit3_getval					// Timer: Anfangswert lesen
//	mov r4, r0						// Wert speichern
//	bl pit3_getval					// Timer: Endwert lesen
//	sub r0, r4, r0					// Subtrahieren der Zeit
//	mov r4, r0						// Delta sichern
//	ldr r1, =timer_const			// Zeiger auf Speicher laden
//	str r4, [r1]					// Konstante speichern
//	bl uart_putInt16				// Suchzeit ausgeben	
	//-----------------------
	
loop_program:

	// Einlesen von 16 Bytes
	ldr r0, =str_eingabe			// Startadresse von String laden
	bl uart_putString				// String ausgeben
	mov r4, #COUNTER				// Zaehler laden
	ldr r5, =bytearray				// Zeiger der zu Beginn des Speicherbereichs zeigt
	
	// Eingabeschleife
loop_eingabe:
	ldr	r0, =str_prompt				// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	bl uart_getByte					// ein Byte einlesen -> Rückgabewert in R0
	strb r0, [r5], #1				// im Array ablegen und Adresse in R5 um eins erhoehen
	bl uart_putByte					// das Byte ausgeben
	subs r4, r4, #1					// Zaehler dekrementieren; Statusregister werden gleichzeitig gesetzt --> für Ende
	bne loop_eingabe				// solange Zaehler noch nicht null

	// Maximumsbestimmung
	ldr r0, =str_startsuche			// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	mov r9, #0						// Maximum mit null initialisieren
	mov r4, #COUNTER				
	
	// Timer (Anfangszeit) - Maximumsuche
	bl pit3_getval					// Timer: Anfangswert lesen
	mov r10, r0						// Wert speichern
	
loop_maximum:
	ldrb r0, [r5, #-1]!				// Byte aus dem Array holen, vorher Adresse in R5 dekrementieren
	cmp r0, r9						// mit bisherigem Maximum vergleichen
	it hi							// Wenn es groesser ist (unsigned) -> IT-Anweisung; Ähnlich IF-THEN
	movhi r9, r0					// wird das bisherige Maximum ueberschrieben --> Maximal 4-Befehle nach dem IT-Befehl möglich!
	
	subs r4, r4, #1					// Zaehler dekrementieren
	bne loop_maximum				// solange Zaehler noch nicht null
	
	
//	mov r0, r1						// wenn diese Instruktion auskommentiert wird, dann benötigt die Suche genau einen Zyklus länger
									// --> also kann davon ausgegangen werden, dass die Taktberechnung korrekt ist
	
	// Timer (Endzeit) - Maximumsuche
	bl pit3_getval
	sub r0, r10, r0					// Subtrahieren der Zeit
	mov r1, #TIMECONST				// Zeitkonstante laden
	sub r0, r0, r1					// Subtrahieren der Zeitkonstante	
	mov r10, r0						// Wert speichern
	
	// Maximum speichern
	ldr r0, =maximum				// Adresse des Speichers fuer Maximum laden
	strb r9, [r0]					// das Maximum im Speicher ablegen

	// Ausgabe des Ergebnisses
	ldr r0, =str_endesuche			// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	mov r0, r9						// Maximum nach R0 kopieren
	bl uart_putByte					// Maximum ausgeben
	
	// Ausgabe Suchzeit für Maximum
	ldr r0, =str_time				// Zeiger auf String laden
	bl uart_putString				// String ausgeben
	mov r0, r10						// Suchzeit nach R0 kopieren
	bl uart_putInt16				// Suchzeit ausgeben
	

	// Ruecksprung zum Beginn
	mov r1, #0						// Maximum zuruecksetzen
	ldr r0, =maximum				// Adresse des Speichers fuer Maximum laden
	strb r1, [r0]					// Maximum zuruecksetzen
	b loop_program					// Erneute Programmausfuehrung


/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
	.rept COUNTER					// repeat Anweisung zum Speicherplatz reservieren
	.byte 0x00
	.endr	
maximum: .byte 0x00
//timer_const: .byte 0x00
str_prompt:	.asciz "\n>0x"
str_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben!\n"		// z = Nullterminierung wird angehängt
str_startsuche: .asciz "\nDurchsuchen gestartet\n"
str_endesuche: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_time: .asciz "\nSuchzeit fuer Maximum: 0x"




// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ BITBANDALIAS, 0x22000000	// Anfangsadresse Bit-Alias (Basisadresse)

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	//***********************
	
	
loop_program:	
	
	//--------------------------
	// Eingabe der Bit-Nummern
	
	ldr r0, =str_bitnummer0			// Zeiger laden
	bl uart_putString				// String ausgeben
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	and r0, r0, #0x1F				// beschneiden auf letzte 5-bits
	mov r5, r0						// sichern	
	bl uart_putByte					// das Byte ausgeben
	ldr r0, =str_bitnummer1			// Zeiger laden
	bl uart_putString				// String ausgeben
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	and r0, r0, #0x1F				// beschneiden auf letzte 5-bits
	mov r6, r0						// sichern	
	bl uart_putByte					// das Byte ausgeben

	//--------------------------
	
	//--------------------------
	// ohne Bit-Banding
		
	ldr r0, =str_word1InitVal			
	bl uart_putString				// String ausgeben
	ldr r0, =word1					// Startadresse von word1 laden
	ldr r0, [r0]					// Inhalt holen
	bl uart_putInt32				// word1 ausgeben
	
	// Bit zurücksetzen
	mov r0, #0x00000001				// register zuruecksetzen und erstes Bit setzen
	lsl r0, r0, r5					// shift der 1
	mvn r0, r0						// negieren der Werte
	ldr r1, =word1					// Zeiger auf word1 laden
	ldr r1, [r1]					// Inhalt holen
	and r0, r0, r1					// bit loeschen
	ldr r1, =word1					// Zeiger auf word1 laden
	str r0, [r1]					// speichern
	
	ldr r0, =str_word1DeleteVal			
	bl uart_putString				// String ausgeben
	ldr r0, =word1					// Startadresse von word1 laden
	ldr r0, [r0]					// Inhalt holen
	bl uart_putInt32				// word1 ausgeben
		
		// Bit setzen
	mov r0, #0x00000001				// register zuruecksetzen und erstes Bit setzen
	lsl r0, r0, r6					// shift der 1
	ldr r1, =word1					// Zeiger auf word1 laden
	ldr r1, [r1]					// Inhalt holen
	orr r0, r0, r1					// bit setzen
	ldr r1, =word1					// Zeiger auf word1 laden
	str r0, [r1]					// speichern

	ldr r0, =str_word1SetVal			
	bl uart_putString				// String ausgeben
	ldr r0, =word1					// Startadresse von word1 laden
	ldr r0, [r0]					// Inhalt holen
	bl uart_putInt32				// word1 ausgeben

	//--------------------------
	
	//--------------------------
	// mit Bit-Banding
	ldr r0, =str_word5InitVal			
	bl uart_putString				// String ausgeben
	ldr r0, =word5					// Startadresse von word1 laden
	ldr r0, [r0]					// Inhalt holen
	bl uart_putInt32				// word1 ausgeben
	
		// Bit zurücksetzen
	mov r0, #BITBANDALIAS			// Anfangsadresse laden
	add r0, r0, #0x200				// Startoffset des Datenworts, im Bit-Band-Alias, bei 0x20000010 addieren
	mov r1, #0x4						// Faktor 4 laden
	mul r1, r1, r5					// Bitnummer mit Faktor multiplizieren
	add r0, r0, r1					// Bit-Band-Alias-Adresse berechnen
	mov r1, #0x00000000				// register zuruecksetzen
	strb r1, [r0]					// speichern (Bit-zuruecksetzen)
	
	ldr r0, =str_word5DeleteVal			
	bl uart_putString				// String ausgeben
	ldr r0, =word5					// Startadresse von word1 laden
	ldr r0, [r0]					// Inhalt holen
	bl uart_putInt32				// word1 ausgeben
	
		// Bit setzen
	mov r0, #BITBANDALIAS			// Anfangsadresse laden
	add r0, r0, #0x200				// Startoffset des Datenworts, im Bit-Band-Alias, bei 0x20000010 addieren
	mov r1, #0x4						// Faktor 4 laden
	mul r1, r1, r6					// Bitnummer mit Faktor multiplizieren
	add r0, r0, r1					// Bit-Band-Alias-Adresse berechnen
	mov r1, #0x00000001				// register setzen
	strb r1, [r0]					// speichern (Bit-setzen)	
	
	ldr r0, =str_word5SetVal			
	bl uart_putString				// String ausgeben
	ldr r0, =word5					// Startadresse von word1 laden
	ldr r0, [r0]					// Inhalt holen
	bl uart_putInt32				// word1 ausgeben

	//--------------------------
	
	// Programm erneut ausfuehren	
		// Leerzeilen eingeben
	ldr r0, =str_nl			
	bl uart_putString	
	b loop_program					// Erneute Programmausfuehrung - keine Löschung von Registern notwendig...
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
word1: .word 0xA0A0A0A0		// Datenwort bei 0x20000000
word2: .word 0x0			// *********
word3: .word 0x0			// dieser Datenbereich wird nur allokiert,damit das Datenwort bei 0x20000010 auch allokiert werden kann!
word4: .word 0x0			// *********
word5: .word 0xB0B0B0B0		// Datenwort bei 0x20000010
str_bitnummer0:	.asciz "Nummer des 0-Bits: 0x"
str_bitnummer1:	.asciz "\nNummer des 1-Bits: 0x"
str_word1InitVal: .asciz "\nInitialwert von Datenwort 0x20000000: 0x"
str_word1DeleteVal: .asciz "\nEndwert Bit geloescht von Datenwort 0x20000000: 0x"
str_word1SetVal: .asciz "\nEndwert Bit gesetzt von Datenwort 0x20000000: 0x"
str_word5InitVal: .asciz "\nInitialwert von Datenwort 0x20000010: 0x"
str_word5DeleteVal: .asciz "\nEndwert Bit geloescht von Datenwort 0x20000010: 0x"
str_word5SetVal: .asciz "\nEndwert Bit gesetzt von Datenwort 0x20000010: 0x"
str_nl: .asciz "\n\n"



// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ TIMECONST, 0x0B				// Zeitkonstante Timer starten und stoppen - aus V1-1

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	
	/*	INIT Pit3
	* PIT_MCR=0x0  Timer Clock enabled, Timers running in debug mode
	* PIT_LDVAL3=0xFFFFFFFF PIT1 Start Value
	* PIT_TCTRL3=0x3 Timer PIT1 aktiv, Interrupt disabled	
	*/
	bl pit3_init	
	//***********************
	
loop_program:	

	//-----------------------
	// Vektoren eingeben
	bl read_vectors
	//-----------------------
	
	//-----------------------
	// (ohne DSP-Befehle)
	// Maximum und Minimum bestimmen 
	  // vektoren aus data-Bereich laden
	ldr r4, =v1				// Zeiger auf vektor1
	ldr r4, [r4]			
	ldr r5, =v2				// Zeiger auf vektor2	
	ldr r5, [r5]			
	
	  // Timer (Anfangszeit)
	bl pit3_getval			// Timer: Anfangswert lesen
	mov r10, r0				// Wert speichern
	
	mov r6, #0x0			// init für min-Wert, gehören auch zur Zeit mit rein weil dieser Algorithmus 0en voraussetzt
	mov r7, #0x0			// init für max-Wert
	  // Vergleich (IT-Befehle)
		// - Byte 0
	and r0, r4, #0x000000FF // letztes Byte ausmaskieren (Byte 0)
	and r1, r5, #0x000000FF 
	cmp r0, r1				// Wert von v1 (r0) größer als v2 (r1) - Byte 0?
	it hi					// Wenn es groesser ist (unsigned)
	orrhi r7, r7, r0		// Wert fuer max sichern
	it hi
	orrhi r6, r6, r1		// Wert fuer min sichern
	it ls					// Wert kleiner oder gleich (unsigned)
	orrls r7, r7, r1		// Wert fuer max sichern
	it ls
	orrls r6, r6, r0		// Wert fuer min sichern
	
		// - Byte 1
	and r0, r4, #0x0000FF00 // Byte ausmaskieren
	and r1, r5, #0x0000FF00 
	cmp r0, r1				// Wert von v1 (r0) größer als v2 (r1)?
	it hi					// Wenn es groesser ist (unsigned)
	orrhi r7, r7, r0		// Wert fuer max sichern
	it hi
	orrhi r6, r6, r1		// Wert fuer min sichern
	it ls					// Wert kleiner oder gleich (unsigned)
	orrls r7, r7, r1		// Wert fuer max sichern
	it ls
	orrls r6, r6, r0		// Wert fuer min sichern
	
		// - Byte 2
	and r0, r4, #0x00FF0000 // Byte ausmaskieren
	and r1, r5, #0x00FF0000 
	cmp r0, r1				// Wert von v1 (r0) größer als v2 (r1)?
	it hi					// Wenn es groesser ist (unsigned)
	orrhi r7, r7, r0		// Wert fuer max sichern
	it hi
	orrhi r6, r6, r1		// Wert fuer min sichern
	it ls					// Wert kleiner oder gleich (unsigned)
	orrls r7, r7, r1		// Wert fuer max sichern
	it ls
	orrls r6, r6, r0		// Wert fuer min sichern
	
		// - Byte 3
	and r0, r4, #0xFF000000 // Byte ausmaskieren
	and r1, r5, #0xFF000000 
	cmp r0, r1				// Wert von v1 (r0) größer als v2 (r1)?
	it hi					// Wenn es groesser ist (unsigned)
	orrhi r7, r7, r0		// Wert fuer max sichern
	it hi
	orrhi r6, r6, r1		// Wert fuer min sichern
	it ls					// Wert kleiner oder gleich (unsigned)
	orrls r7, r7, r1		// Wert fuer max sichern
	it ls
	orrls r6, r6, r0		// Wert fuer min sichern
	
	  // Timer (Endzeit)
	bl pit3_getval
	sub r0, r10, r0			// Subtrahieren der Zeit
	mov r1, #TIMECONST		// Zeitkonstante laden
	sub r0, r0, r1			// Subtrahieren der Zeitkonstante	
	mov r10, r0				// Wert speichern
	
	  // Speichern von min/max im Datenbereich
	ldr r0, =max			// Zeiger auf max
	str r7, [r0]			// Wert im Datenbereich in "max"-Speichern
	ldr r0, =min			// Zeiger auf min
	str r6, [r0]			// Wert im Datenbereich in "min"-Speichern
	
	  // Ausgabe	
	ldr r0, =str_ohneDSP	
	bl uart_putString		
	ldr r0, =str_min		// min String zur Ausgabe laden
	bl uart_putString
	mov r0, r6				// Inhalt min zur Ausgabe laden
	bl uart_putInt32		// Ausgabe	
	ldr r0, =str_max		// max String zur Ausgabe laden
	bl uart_putString
	mov r0, r7				// Inhalt min zur Ausgabe laden
	bl uart_putInt32		// Ausgabe
		// Ausgabe Timer
	ldr r0, =strTimeOhneDSP	// String zu Time ohne DSP laden
	bl uart_putString
	mov r0, r10				// Ausfuehrungszeit laden
	bl 	uart_putInt32		// Ausgabe Ausfuehrungszeit
	//-----------------------


	//-----------------------
	// (mit DSP-Befehle)
	// Maximum und Minimum bestimmen 
	  // Vektoren aus data-Bereich laden
	ldr r4, =v1				// Zeiger auf vektor1
	ldr r4, [r4]			
	ldr r5, =v2				// Zeiger auf vektor2	
	ldr r5, [r5]			
	
	  // Timer (Anfangszeit)
	bl pit3_getval			// Timer: Anfangswert lesen
	mov r10, r0				// Wert speichern
	
	  // Byteweise Min- und Max-Werte bestimmen
	usub8 r0, r5, r4		// zwangsweises ausführen eines DSP-Befehls um GE[3:0] zu setzen
	sel r6, r4, r5			// Bytes für min in r6 sichern
	sel r7, r5, r4			// Bytes für max in r7 sichern
	
	  // Timer (Endzeit)
	bl pit3_getval
	sub r0, r10, r0			// Subtrahieren der Zeit
	mov r1, #TIMECONST		// Zeitkonstante laden
	sub r0, r0, r1			// Subtrahieren der Zeitkonstante	
	mov r10, r0				// Wert speichern
	
	  // Ausgabe	
	ldr r0, =str_mitDSP	
	bl uart_putString		
	ldr r0, =str_min		// min String zur Ausgabe laden
	bl uart_putString
	mov r0, r6				// Inhalt min zur Ausgabe laden
	bl uart_putInt32		// Ausgabe	
	ldr r0, =str_max		// max String zur Ausgabe laden
	bl uart_putString
	mov r0, r7				// Inhalt min zur Ausgabe laden
	bl uart_putInt32		// Ausgabe
		// Ausgabe Timer
	ldr r0, =strTimeOhneDSP	// String zu Time ohne DSP laden
	bl uart_putString
	mov r0, r10				// Ausfuehrungszeit laden
	bl 	uart_putInt32		// Ausgabe Ausfuehrungszeit

	//-----------------------

	// Programm erneut ausfuehren	
		// Leerzeilen eingeben
	ldr r0, =str_nl			
	bl uart_putString	
	b loop_program					// Erneute Programmausfuehrung - keine Löschung von Registern notwendig...

end:
	b end
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogramm (read_vectors): 
* Hier werden die beiden Vektoren v1, v2 (je 32Bit) eingelesen
*
*/	
.thumb_func
read_vectors:
	//-----------------------
	// Inhalte sichern
	push {R4,LR}
	//-----------------------

	ldr r0, =str_readVectors		// Zeiger laden
	bl uart_putString				// String ausgeben
		// v1 eingeben
	ldr r0, =str_v1					// Zeiger laden
	bl uart_putString				// String ausgeben
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	mov r4, r0						// erste Eingabe sichern
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	lsl r4, r4, 0x08				// links schieben 1 Byte
	orr r4, r4, r0					// Bits übernehmen (zweite Eingabe sichern)
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	lsl r4, r4, 0x08				// links schieben 1 Byte
	orr r4, r4, r0					// Bits übernehmen (dritte Eingabe sichern)
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	lsl r4, r4, 0x08				// links schieben 1 Byte
	orr r4, r4, r0					// Bits übernehmen (vierte Eingabe sichern)
	mov r0, r4						// Inhalt zur Ausgabe laden
	bl uart_putInt32				// Ausgabe
	ldr r0, =v1						// Zeiger laden
	str r4, [r0]					// speichern
	
		// v2 eingeben
	ldr r0, =str_v2					// Zeiger laden
	bl uart_putString				// String ausgeben
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	mov r4, r0						// erste Eingabe sichern
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	lsl r4, r4, 0x08				// links schieben 1 Byte
	orr r4, r4, r0					// Bits übernehmen (zweite Eingabe sichern)
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	lsl r4, r4, 0x08				// links schieben 1 Byte
	orr r4, r4, r0					// Bits übernehmen (dritte Eingabe sichern)
	bl uart_getByte					// ein Byte einlesen -> Rueckgabewert in R0
	lsl r4, r4, 0x08				// links schieben 1 Byte
	orr r4, r4, r0					// Bits übernehmen (vierte Eingabe sichern)
	mov r0, r4						// Inhalt zur Ausgabe laden
	bl uart_putInt32				// Ausgabe
	ldr r0, =v2						// Zeiger laden
	str r4, [r0]					// speichern
	
	//-----------------------
	// Ruecksprung
	pop {R4,PC}
	//-----------------------

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	



/*** Datenbereich (ab 0x20000000) ***/
.data
v1: 	.word 0x0
v2: 	.word 0x0
min: 	.word 0x0
max: 	.word 0x0
str_readVectors:	.asciz "Geben Sie bitte fuer jeden Vektor 4 Bytes ein:\n"
str_v1:				.asciz "v1: 0x"
str_v2:				.asciz "\nv2: 0x"
str_ohneDSP:		.asciz "\nohne DSP-Befehle:\n"
str_mitDSP: 		.asciz "\nmit DSP-Befehlen:\n"
str_min:			.asciz "min: 0x"
str_max:			.asciz "\nmax: 0x"
strTimeOhneDSP: 	.asciz "\nAusfuehrungszeit ohne DSP-Befehle: 0x"
strTimeMitDSP: 		.asciz "\nAusfuehrungszeit mit DSP-Befehle: 0x"
str_nl: 			.asciz "\n\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ COUNTER, 			0x20				// Anzahl der Schleifendurchläufe
.equ CT_MATRIX,			0x10				// Anzahl der Schleifendurchläufe der Matrix (16 Elemente)
.equ CT_MUL,			0x08				// Anzahl durchlaeufe bei Multiplikation der Matrizen
.equ CT_MATRIX_O, 		0x40				// Anzahl der Schleifendurchlaeufe für Ausgabe der Matrix O

.equ SHIFT_16,			0x10				// Schieben um 16 Bit
.equ HALFWORD,			0x02				// Größe Half-word in Byte
.equ WORD,				0x04				// Größe Word in Byte
.equ SIX_BYTE,			0x06				// 6 Byte
.equ BITS_13,			0x0D				// 13 Bit Konstante
.equ SEC_COLUMN,		0x04				// zweite Spalte
.equ THIRD_COLUMN,		0x08				// dritte Spalte
.equ FOURTH_COLUMN,		0x0C				// vierte Spalte


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	
	//***********************
				
	
	//***********************
	// Matrixmultiplikation	+ Ausgabe
	/************************************************************
	Antwort zu V2-1 a):
	Laut meiner Lösung werden die Hälfte der Multiplikationen und Additionen benötigt.
	Bei dieser 4x4 Matrixmultiplikation müssen 16*4=64 Multiplikationen durchgeführt werden. Mit Hilfe der DSP-Befehle werden jeweils zwei Multiplikationen in einem Takt ausgeführt.
	Daraus folgt, dass nur die Hälfte der Multiplikationen benötigt werden --> 32 Multiplikationen werden eingespart!
	************************************************************/
	ldr r5, =matrix_M				// Zeiger auf Array Matrix M
	ldr r6, =matrix_N_transponed	// Zeiger auf Array Matrix N transponiert
	ldr r7, =matrix_O				// Zeiger auf Array Matrix O
loop_mul:
	mov r0, #0						// init von r0
	mov r1, #0						// init von r1
	mov r2, #0						// init von r2
		// zwei half-words von Matrix M holen -> in r0
	ldrh r0, [r5]					// half-word aus array Matrix M holen
	lsl r0, r0, #SHIFT_16
	ldrh r2, [r5, #HALFWORD]		// zweites half-word aus Matrix M holen
	orr r0, r0, r2					// beide daten in r0 speichern -> Vorbereitung für DSP-Befehl
		// zwei half-word aus transponierter Matrix N holen -> in r1
	ldrh r1, [r6]					// half-word aus transponierter Matrix N holen
	lsl r1, r1, #SHIFT_16	
	ldrh r2, [r6, #HALFWORD]		// zweites half-word aus Matrix N holen	
	orr r1, r1, r2					// beide daten in r1 speichern -> Vorbereitung für DSP-Befehl
	
		// multiplizieren und akkumulieren durchführen
	SMUAD r3, r0, r1				// DSP-Befehl: multiplizieren und akkumulieren
	
	mov r0, #0						// init von r0
	mov r1, #0						// init von r1
	mov r2, #0						// init von r2
		// zwei half-words von Matrix M holen -> in r0
	ldrh r0, [r5, #WORD]
	lsl r0, r0, #SHIFT_16
	ldrh r2, [r5, #SIX_BYTE]		// zweites half-word aus Matrix M holen
	orr r0, r0, r2					// beide daten in r0 speichern -> Vorbereitung für DSP-Befehl
		// zwei half-word aus transponierter Matrix N holen -> in r1
	ldrh r1, [r6, #WORD]			// half-word aus transponierter Matrix N holen
	lsl r1, r1, #SHIFT_16
	ldrh r2, [r6, #SIX_BYTE]		// zweites half-word aus Matrix N holen	
	orr r1, r1, r2					// beide daten in r1 speichern -> Vorbereitung für DSP-Befehl
		// multiplizieren und akkumulieren durchführen
	SMUAD r4, r0, r1				// DSP-Befehl: multiplizieren und akkumulieren
	
		// Gesamtergebnis berechnen und in Matrix_O ablegen
	add r0, r3, r4
	str r0, [r7]					// in Matrix_O speichern
	add r7, r7, #WORD				// nächster Eintrag in Matrix (word - 4 Byte)

	add r6, r6, #CT_MUL				// um zwei half-words weiter springen	
	ldr r0, =matrix_N_transponed
	sub r1, r6, r0					// Offset berechnen
		// Abfragen ob schon alle Spalten durchiteriert wurden
	cmp r1, #COUNTER				// Vergleich ob Spalten von Matrix N schon durchiteriert, dann soll es von vorne anfangen
	itt eq
	ldreq r6, =matrix_N_transponed	// Spalten neu anfangen bei Matrix N
	addeq r5, #CT_MUL				// nächste Zeile von Matrix M
	
	ldr r0, =matrix_M
	sub r1, r5, r0
		// Abfragen ob alle Zeilen von Matrix M durchiteriert wurden
	cmp r1, #COUNTER				// schon alle Zeilen von M durchiteriert?
	it ne
	bne loop_mul
	
	
		// Ausgabe Ergebnismatrix
	ldr r0, =str_MatrixO	
	bl uart_putString
	ldr r4, =matrix_O			
loop_Output_MatrixO:
	ldr r0, [r4]					// erste Spalte
	bl uart_putInt32
	ldr r0, =str_space	
	bl uart_putString
	ldr r0, [r4, #SEC_COLUMN]		// zweite Spalte
	bl uart_putInt32
	ldr r0, =str_space	
	bl uart_putString
	ldr r0, [r4, #THIRD_COLUMN]		// dritte Spalte
	bl uart_putInt32
	ldr r0, =str_space	
	bl uart_putString
	ldr r0, [r4, #FOURTH_COLUMN]	// vierte Spalte
	bl uart_putInt32
	ldr r0, =str_nl	
	bl uart_putString
	
	add r4, r4, #SHIFT_16				// Zeige auf die nächste Zeile
		// Abbruch der Schleife prüfen
	ldr r0, =matrix_O
	sub r1, r4, r0	
	cmp r1, #CT_MATRIX_O			// alle Werte durchlaufen?
	it ne
	bne loop_Output_MatrixO
		
	//***********************

	//***********************
	// Kopieren der Matrix O im Speicher
	ldr r0, =str_CopyMatrix
	bl uart_putString
		// Initialisierung
	mov r4, #COUNTER				// Anzahl zu kopierenden Elemente
	ldr r0, =matrix_O
	ldr r1, =matrix_O_copied
	
loop_copy_matrix:
	ldrh r2, [r0], #HALFWORD		// Element von Matrix O holen und danach um 2 Byte erhöhen
	strh r2, [r1], #HALFWORD		// Element in Matrix O copied speichern und um 2 Byte erhöhen
	subs r4, r4, #1
	bne	loop_copy_matrix
	
	//***********************


	//***********************
	// Berechnung der Summe S von Element-Produkten der Matrizen M und N
		// Initialisierung
	mov r4, #CT_MUL					// Anzahl zu kopierender Elemente
	mov r6, #0						// Initialisieren der Summe S
	ldr r0, =matrix_M
	ldr r1, =matrix_N_transponed
	
	
loop_product_s:
	ldr r2, [r0], #WORD				// Element von Matrix O holen und danach um 4 Byte erhöhen
	ldr r3, [r1], #WORD				// Element von Matrix O holen und danach um 4 Byte erhöhen

		// multiplizieren und akkumulieren durchführen
	SMUAD r5, r2, r3				// DSP-Befehl: multiplizieren und akkumulieren
	add r6, r6, r5					// Addieren zur Summe S
	
	subs r4, r4, #1
	bne	loop_product_s				// solange Zaehler noch nicht null
	
		// Ausgabe wenn Produkt berechnet
	ldr r0, =str_ProductSum
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	
	//***********************
	

	//***********************
	// Skalierbare Additionsbefehle
	/************************************************************
	Antwort zu V2-1 d):
	Wenn ich meine Lösung interpretiere liegt eine Sättung eines Overflows bei folgenden Berechnungen vor:
		- UQADD16(A,B) -> B4DD_FFFF - hier wird das untere half-word im maximum gesättigt, Die Summe der unteren half-words übersteigt das Maximum welches ein half-word anzeigen kann.
		- UQADD16(A,D) -> FFFF_FFFF - hier werden beide half-words gesättigt, Die Summe der unteren und oberen half-words übersteigen das Maximum welches ein half-word anzeigen kann.
		- QADD16(A,C)  -> B08B_7FFF - hier wird das untere half-word auf maximum 32767 gesättigt (signed!), Die Summe der unteren half-words übersteigt das Maximum welches ein signed short anzeigen kann. Sonst wäre es negativer Wert!
	************************************************************/
		// Werte der Operanden laden
	ldr r4, =op_A
	ldr r4, [r4]
	ldr r5, =op_B
	ldr r5, [r5]
	ldr r6, =op_C
	ldr r6, [r6]
	ldr r7, =op_D
	ldr r7, [r7]
	
		// UADD16 - unsigned arithmetic modulo 2¹⁶
	ldr r0, =str_UADD16
	bl uart_putString
	UADD16 r0, r4, r5				// Operand A und B berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	UADD16 r0, r4, r6				// Operand A und C berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	UADD16 r0, r4, r7				// Operand A und D berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	
		// SADD16 - signed arithmetic modulo 2¹⁶
	ldr r0, =str_SADD16
	bl uart_putString
	SADD16 r0, r4, r5				// Operand A und B berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	SADD16 r0, r4, r6				// Operand A und C berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	SADD16 r0, r4, r7				// Operand A und D berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	
		// UQADD16 - unsigned saturating arithmetic
	ldr r0, =str_UQADD16
	bl uart_putString
	UQADD16 r0, r4, r5				// Operand A und B berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	UQADD16 r0, r4, r6				// Operand A und C berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	UQADD16 r0, r4, r7				// Operand A und D berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	
		// QADD16 - signed saturating arithmetic
	ldr r0, =str_QADD16
	bl uart_putString
	QADD16 r0, r4, r5				// Operand A und B berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	QADD16 r0, r4, r6				// Operand A und C berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	QADD16 r0, r4, r7				// Operand A und D berechnen
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	
	
	//***********************


	//***********************
	// Saettigung auf 13-Bit Werte (signed, unsigned)
	/************************************************************
	Antwort zu V2-1 e):
	Folgend meine Interpretierung der Ergebnisse:
		SSAT16 (op_A): F000_0FFF 	-> das vordere half-word wird als negative Zahl interpretiert (somit geht es in die negative Saettigung), das hintere half-word wird als positiv interpretiert und geht in positive Saettigung
		SSAT16 (op_B): 0FFF_F000	-> vorderes half-word wird positiv interpretiert und geht in Saettigung, hinteres half-word wird negativ interpretiert und geht in negative Saettigung weil der Wert kleiner ist als negatives minimum!
		USAT16 (op_A): 0000_1FFF	-> vorderes half-word wird wieder negativ betrachtet und geht in Saettigung zu null, weil hier auf 0 und maximum von 13Bit gesaettigt wird. hinteres half-word siehe weiter oben
		USAT16 (op_B): 10A7_0000	-> vorderes half-word passt in 13Bit rein, also keine Saettigung noetig. Unteres half-word wird wieder negativ interpretiert und wird auf 0 gesaettigt!
	************************************************************/
	ldr r4, =op_A
	ldr r4, [r4]
	ldr r5, =op_B
	ldr r5, [r5]
	
		// SSAT16 - signed saturation (vorzeichenbehaftete Saettigung)
	ldr r0, =str_SSAT16
	bl uart_putString
	SSAT16 r0, #BITS_13, r4			// signed sat. op_A
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	SSAT16 r0, #BITS_13, r5			// signed sat. op_B
	bl uart_putInt32
	
		// USAT16 - unsigned saturation (nicht vorzeichenbehaftete Saettigung), instruction saturates each signed halfword to the unsigned range
	ldr r0, =str_USAT16
	bl uart_putString
	USAT16 r0, #BITS_13, r4			// unsigned sat. op_A
	bl uart_putInt32
	ldr r0, =str_space
	bl uart_putString
	USAT16 r0, #BITS_13, r5			// unsigned sat. op_B
	bl uart_putInt32



end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
matrix_M:							// array der Matrix M
	.short 	0x5f8c, 0x7f48, 0x8245, 0x6048, 0xc799, 0x9c5d, 0xd49c, 0x33d8, 0x579b, 0x8aef, 0xf2c0, 0xa3c2, 0x41fd, 0x50d4, 0x25c6, 0x4afa
matrix_N_transponed:				// array der transponierten Matrix N - sinnvoll im Speicher ablegen
	.short	0x7f41, 0x0645, 0x8c8f, 0x9065, 0x78e3, 0xf7f3, 0xd29f, 0x2961, 0x5a1e, 0xdfed, 0x4b9f, 0x1092, 0x61bf, 0x21be, 0x5ca1, 0xc6d3
matrix_O:							// array der Matrix O
	.rept CT_MATRIX	
	.word 0x0
	.endr	
matrix_O_copied:					// array der kopierten Matrix O
	.rept CT_MATRIX	
	.word 0x0
	.endr	
str_MatrixO:	.asciz "Ergebnismatrix O:\n"
str_nl:			.asciz "\n"
str_space:		.asciz " "
str_CopyMatrix:	.asciz "\nKopieren der Matrix O!\n"
str_ProductSum:	.asciz "Produkt-Summe: "
op_A:			.word 0xA4367C7B
op_B:			.word 0x10A78933
op_C:			.word 0xC5535F2
op_D:			.word 0x788E84B1
str_UADD16:		.asciz "\nUADD16:    "
str_SADD16:		.asciz "\nSADD16:    "
str_UQADD16:	.asciz "\nUQADD16: "
str_QADD16:		.asciz "\nQADD16:    "
str_SSAT16:		.asciz "\n\nSSAT16:  "
str_USAT16:		.asciz "\nUSAT16:  "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
	// Schätzung der Konstante für eine Sekunde -> Durch Verwendung von subs und bne zum runterzählen werden normalerweise 3 Takte benötigt. (subs = 1 cycle, bne = 1+P cycle)
	//											--> es werden schon 1/3 der Takte für die Zählung benötigt -> 25x10⁶/3 = 8,333x10⁶ , die anderen Instruktionen fallen so gering ins Gewicht das diese nicht berücksichtigt werden!
.equ CT_ONESEC,			0x7F2815
.equ INIT_STOP,			0x0
.equ NO_DOUBLE_DIGIT, 	0x9	// Konstante für Abfrage zur zweistelligen Darstellung der Tage, Monate etc. (führende 0 notwendig)

	// Maximalwerte für Uhrzeit und Datum
.equ MAX_MINUTE, 	0x3B				// 59
.equ MAX_HOUR,		0x17				// 23
.equ MAX_DAY,		0x1E				// 30
.equ MAX_MONTH,		0xC					// 12
.equ MAX_YEAR,		0x63				// 99 --> Überlauf für Jahrhundert soll verhindert werden
.equ PRAEFIX_YEAR,	0x14				// 20 -> Präfix 20 bei 2014.

	// ASCII-Zeichen Eingabe
.equ START_STOP,	0x73				// 's'
.equ TIME,			0x74				// 't'
.equ DATE,			0x64				// 'd'

	// Zeiger auf Datum Uhrzeit
.equ DAY,			0x0
.equ MONTH,			0x1
.equ YEAR,			0x2
.equ HOUR,			0x3
.equ MINUTE,		0x4

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	
	mov r5, #INIT_STOP
	ldr r4, =date_time		// Zeiger zur Base-Adresse von Datum und Uhrzeit

	//***********************

loop_input:
		// prüfen ob Zeichen empfangen wurde
	bl uart_charPresent
	cmp r0, #0				// Auf Ungleichheit zu 0 prüfen
	it hi
	blhi uart_getChar


		// 's' (start/stop) Uhr anhalten/starten
	cmp r0, #START_STOP
	it eq
	eoreq r5, #1			// toggle bit

		// 't' (time) Eingabe der neuen Uhrzeit
	cmp r0, #TIME
	beq time_input
	
		// 'd' (date) Eingabe eines neuen Datums
	cmp r0, #DATE
	beq date_input
	
	b check_stop			// Instruktionen für die Eingabe überspringen
	
// Eingabe der neuen Zeit	
time_input:
		// Stunde eingeben
	ldr r0, =str_newLine
	bl uart_putString
	ldr r0, =str_InHour
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #HOUR]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10
	
	ldrb r0, [r4, #HOUR]
	bl uart_putByteBase10
	ldr r0, =str_newLine
	bl uart_putString
	
		// Minuten eingeben
	ldr r0, =str_InMinute
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #MINUTE]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10

	ldrb r0, [r4, #MINUTE]
	bl uart_putByteBase10	
	ldr r0, =str_newLine	
	bl uart_putString
	
	b check_stop				// Instruktionen für die Eingabe des Datums überspringen

// Eingabe des neuen Datums
date_input:
		// Tag eingeben
	ldr r0, =str_newLine
	bl uart_putString
	ldr r0, =str_InDay
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #DAY]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10	
	
	ldrb r0, [r4, #DAY]
	bl uart_putByteBase10
	ldr r0, =str_newLine	
	bl uart_putString
	
		// Monat eingeben
	ldr r0, =str_InMonth
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #MONTH]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10
	
	ldrb r0, [r4, #MONTH]
	bl uart_putByteBase10	
	ldr r0, =str_newLine	
	bl uart_putString
	
		// Jahr eingeben
	ldr r0, =str_InYear
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #YEAR]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10
	
	ldrb r0, [r4, #YEAR]
	bl uart_putByteBase10	
	ldr r0, =str_newLine
	bl uart_putString


// Überprüfen ob die Uhr gestoppt ist oder weiterlaufen soll
check_stop:
		// prüfen ob das Stoppbit für die Clock gesetzt wurde
	cmp r5, #0
	bne loop_input			// Rücksprung zur Eingabe --> keine Ausführung der Uhrzeit
	
// Uhrzeit weiterlaufen 
clock:
	ldr r0, =date_time		// Register für die Übergabe an print_clock
	bl print_clock			// Ausgabe der Uhrzeit

	bl delay				// eine Sekunde warten
	
		// Werte für Datum und Zeit laden
	ldrb r0, [r4, #MINUTE]
	ldrb r1, [r4, #HOUR]
	ldrb r2, [r4, #DAY]
	ldrb r3, [r4, #MONTH]
	ldrb r6, [r4, #YEAR]
	 
	add r0, #1				// Minute hochzählen
	cmp r0, #MAX_MINUTE		// höchste Zahl überschritten?
	itt hi
	movhi r0, #0			// bei 0 wieder beginnen zu zählen
	addhi r1, #1			// Stunde hochzählen
	
	cmp r1, #MAX_HOUR		// Stunden voll?
	itt hi
	movhi r1, #0			// bei 0 wieder beginnen
	addhi r2, #1			// Tag hochzählen
	
	cmp r2, #MAX_DAY		// maximale Tage im Monat erreicht?
	itt hi					
	movhi r2, #1			// wieder beim ersten des Monats anfangen
	addhi r3, #1			// Monate hochzählen
	
	cmp r3, #MAX_MONTH		// ein Jahr durchlaufen?
	itt hi					
	movhi r3, #1			// wieder bei Januar anfangen		
	addhi r6, #1			// Jahr hochzählen
	
	cmp r6, #MAX_YEAR		// Jahrhundert begrenzen
	it hi					
	movhi r6, #0			// wieder im Jahrhundert anfangen
	
		// Werte für Datum und Zeit speichern
	strb r0, [r4, #MINUTE]
	strb r1, [r4, #HOUR]
	strb r2, [r4, #DAY]
	strb r3, [r4, #MONTH]
	strb r6, [r4, #YEAR]	
	
	b loop_input

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogramm (delay): 
* Programmschleife die eine Verzögerung von etwa einer Sekunde generiert
*
*/	
.thumb_func
delay:
	//-----------------------
	// Inhalte sichern
	push {LR}
	//-----------------------
	
		// Konstante für 1s laden
	ldr r0, =CT_ONESEC
	
loop_delay:
	subs r0, r0, #1				// herunterzählen
	bne loop_delay				// solange die Variable nicht null ist weiter dekrementieren	
	
	//-----------------------
	// Ruecksprung
	pop {PC}
	//-----------------------
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++


/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogramm (aktuelle Uhrzeit): 
* Ausgabe der aktuellen Uhrzeit + Datum in der Form (dd.mm.jjjj  hh:mm)
* verwendete Register:
*	r0: Zeiger auf Array der Uhrzeit + Datum
*/	
.thumb_func
print_clock:
	//-----------------------
	// Inhalte sichern
	push {r4-r5,LR}
	//-----------------------
	
		// Zeiger für Datum Uhrzeit zwischenspeichern
	mov r4, r0

		// Tage ausgeben
	ldrb r5, [r4, #DAY]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10	
	mov r0, r5	
	bl uart_putByteBase10
	ldr r0, =str_pt	
	bl uart_putString
	
		// Monate ausgeben
	ldrb r5, [r4, #MONTH]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10	
	mov r0, r5	
	bl uart_putByteBase10	
	ldr r0, =str_pt	
	bl uart_putString
	
		// Jahre ausgeben
	mov r0, #PRAEFIX_YEAR
	bl uart_putByteBase10
	ldrb r5, [r4, #YEAR]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10		
	mov r0, r5		
	bl uart_putByteBase10
	ldr r0, =str_space	
	bl uart_putString
	bl uart_putString			// Leerzeichen doppelt ausgeben
	
		// Stunden ausgeben
	ldrb r5, [r4, #HOUR]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10	
	mov r0, r5			
	bl uart_putByteBase10
	ldr r0, =str_dpt	
	bl uart_putString
	
		// Minuten ausgeben
	ldrb r5, [r4, #MINUTE]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10		
	mov r0, r5			
	bl uart_putByteBase10
	ldr r0, =str_space	
	bl uart_putString
	ldr r0, =str_clock	
	bl uart_putString

	//-----------------------
	// Ruecksprung
	pop {r4-r5,PC}
	//-----------------------
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*** Datenbereich (ab 0x20000000) ***/
.data		//		Tag		Monat	Jahr	Stunde	Minute
date_time:	.byte	0x1, 	0x1, 	0xE, 	0x0, 	0x0
str_pt:			.asciz "."
str_dpt:		.asciz ":"
str_space:		.asciz " "
str_clock:		.asciz "Uhr\n"
str_newLine: 	.asciz "\n"
str_InHour:		.asciz "Stunde eingeben (hh): "
str_InMinute:	.asciz "Minuten eingeben (mm): "
str_InDay:		.asciz "Tag eingeben (dd): "
str_InMonth:	.asciz "Monat eingeben (mm): "
str_InYear:		.asciz "Jahr eingeben (jj): "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ INIT_STOP,			0x0
.equ NO_DOUBLE_DIGIT, 	0x9	// Konstante für Abfrage zur zweistelligen Darstellung der Tage, Monate etc. (führende 0 notwendig)

	// Maximalwerte für Uhrzeit und Datum
.equ MAX_MINUTE, 	0x3B				// 59
.equ MAX_HOUR,		0x17				// 23
.equ MAX_DAY,		0x1E				// 30
.equ MAX_MONTH,		0xC					// 12
.equ MAX_YEAR,		0x63				// 99 --> Überlauf für Jahrhundert soll verhindert werden
.equ PRAEFIX_YEAR,	0x14				// 20 -> Präfix 20 bei 2014.

	// ASCII-Zeichen Eingabe
.equ START_STOP,	0x73				// 's'
.equ TIME,			0x74				// 't'
.equ DATE,			0x64				// 'd'

	// Zeiger auf Datum Uhrzeit
.equ DAY,			0x0
.equ MONTH,			0x1
.equ YEAR,			0x2
.equ HOUR,			0x3
.equ MINUTE,		0x4

	// Konstanten für PIT1-Register
.equ PIT_MCR,				0x40037000		// Adresse PIT Module Control Register (PIT_MCR)
.equ PIT_LDVAL1,			0x40037110		// Adresse Timer Load Value Register (PIT_LDVAL1)
.equ PIT_TCTRL1_TIE,		0x426E2304		// Bit-Band-Alias Adresse für Timer Interrupt Enable PIT1 (PIT_TCTRL1_TIE)
.equ PIT_TCTRL1_TEN,		0x426E2300		// Bit-Band-Alias Adresse für Timer Enable PIT1 (PIT_TCTRL1_TEN)
.equ PIT_TFLG1,				0x4003711C		// Adresse zum Timer Flag Register Timer0 (PIT_TFLG1)
.equ PIT_CLK,				0x429007DC		// Bit-Band-Alias Adresse für Clock PIT im SIM - System Integration Module - SIM_SCGC6 4004_803Ch
.equ PIT_INIT_MCR, 			0x0				// Module is enabled, Timer continues run in Debug mode
.equ PIT_INIT_LDVAL1,		0x17D783F		// Load Value für 1s -> ldval trigger = (1s/25MHz)-1
.equ PIT1_IRQHandler,		0x1FFFFF54		// Adresse in IVT (Interrupt Vector Table) im SRAM der ISR für PIT1

	// Konstanten für NVIC-Register
.equ NVIC_ICPR2,			0xE000E288		// Interrupt Clear-Pending Register
.equ NVIC_ICPR2_CLRPEND5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 hängende Interrupts löschen (Bit 5 in ICPR2)
.equ NVIC_ISER2,			0xE000E108		// Interrupt Set-Enable Register
.equ NVIC_ISER2_SETENA5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 setzen (Bit 5 in ISER2)

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	
	// init pit1
		// Takt für PIT aktivieren (System Integration Module – SIM),
	ldr r0, =PIT_CLK			// Adresse Clock PIT im SIM
	mov r1, #1
	str r1, [r0]			
		
		// Interrupt-Vektor zu PIT1 setzen,
	ldr r0, =PIT1_IRQHandler	// Adresse IVT für PIT1 laden
	ldr r1, =isr_pit1			// Startadresse von ISR laden
	str r1, [r0]
	
		// eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC),
	ldr r0, =NVIC_ICPR2	
	ldr r1, [r0]
	orr r1, r1, #NVIC_ICPR2_CLRPEND5
	str r1, [r0]
		
		// Interrupt zu PIT1 aktivieren (NVIC),
	ldr r0, =NVIC_ISER2
	ldr r1, [r0]
	orr r1, r1, #NVIC_ISER2_SETENA5
	str r1, [r0]	
		
		// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul),
	ldr r0, =PIT_MCR
	ldr r1, =PIT_INIT_MCR
	str r1, [r0]
		
		// Startwert für PIT1 auf 1 Sekunde initialisieren,
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_INIT_LDVAL1
	str r1, [r0]
		
		// Interrupt zu PIT1 aktivieren (PIT-Modul),
	ldr r0, =PIT_TCTRL1_TIE
	mov r1, #1
	str r1, [r0]
		
		// PIT1 aktivieren (PIT-Modul).
	ldr r0, =PIT_TCTRL1_TEN
	mov r1, #1
	str r1, [r0]						
	
	
	    // Init Uhr
	mov r5, #INIT_STOP
	ldr r4, =date_time		// Zeiger zur Base-Adresse von Datum und Uhrzeit

	//***********************

loop_input:
		// prüfen ob Zeichen empfangen wurde
	bl uart_charPresent
	cmp r0, #0				// Auf Ungleichheit zu 0 prüfen
	it hi
	blhi uart_getChar


		// 's' (start/stop) Uhr anhalten/starten
	cmp r0, #START_STOP
	it eq
	eoreq r5, #1			// toggle bit

		// 't' (time) Eingabe der neuen Uhrzeit
	cmp r0, #TIME
	beq time_input
	
		// 'd' (date) Eingabe eines neuen Datums
	cmp r0, #DATE
	beq date_input
	
	b check_stop			// Instruktionen für die Eingabe überspringen
	
// Eingabe der neuen Zeit	
time_input:
		// Stunde eingeben
	ldr r0, =str_newLine
	bl uart_putString
	ldr r0, =str_InHour
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #HOUR]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10
	
	ldrb r0, [r4, #HOUR]
	bl uart_putByteBase10
	ldr r0, =str_newLine
	bl uart_putString
	
		// Minuten eingeben
	ldr r0, =str_InMinute
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #MINUTE]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10

	ldrb r0, [r4, #MINUTE]
	bl uart_putByteBase10	
	ldr r0, =str_newLine	
	bl uart_putString
	
	b check_stop				// Instruktionen für die Eingabe des Datums überspringen

// Eingabe des neuen Datums
date_input:
		// Tag eingeben
	ldr r0, =str_newLine
	bl uart_putString
	ldr r0, =str_InDay
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #DAY]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10	
	
	ldrb r0, [r4, #DAY]
	bl uart_putByteBase10
	ldr r0, =str_newLine	
	bl uart_putString
	
		// Monat eingeben
	ldr r0, =str_InMonth
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #MONTH]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10
	
	ldrb r0, [r4, #MONTH]
	bl uart_putByteBase10	
	ldr r0, =str_newLine	
	bl uart_putString
	
		// Jahr eingeben
	ldr r0, =str_InYear
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #YEAR]
	cmp r0, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10
	
	ldrb r0, [r4, #YEAR]
	bl uart_putByteBase10	
	ldr r0, =str_newLine
	bl uart_putString


// Überprüfen ob die Uhr gestoppt ist oder weiterlaufen soll
check_stop:
		// prüfen ob das Stoppbit für die Clock gesetzt wurde
	cmp r5, #0
	bne loop_input			// Rücksprung zur Eingabe --> keine Ausführung der Uhrzeit
	
// Uhrzeit weiterlaufen 
clock:
		// eine Sekunde abgelaufen?
	ldr r0, =flag_oneSec
	ldr r0, [r0]
	cmp r0, #1
	bne loop_input	
	
	    // Flag Bit für eine Sekunde von pit1 löschen
	ldr r0, =flag_oneSec
	mov r1, #0
	str r1, [r0]	
	
	
	// Ausgabe Uhrzeit
	    
	ldr r0, =date_time		// Register für die Übergabe an print_clock
	bl print_clock			// Ausgabe der Uhrzeit	
	
		// Werte für Datum und Zeit laden
	ldrb r0, [r4, #MINUTE]
	ldrb r1, [r4, #HOUR]
	ldrb r2, [r4, #DAY]
	ldrb r3, [r4, #MONTH]
	ldrb r6, [r4, #YEAR]
	 
	add r0, #1				// Minute hochzählen
	cmp r0, #MAX_MINUTE		// höchste Zahl überschritten?
	itt hi
	movhi r0, #0			// bei 0 wieder beginnen zu zählen
	addhi r1, #1			// Stunde hochzählen
	
	cmp r1, #MAX_HOUR		// Stunden voll?
	itt hi
	movhi r1, #0			// bei 0 wieder beginnen
	addhi r2, #1			// Tag hochzählen
	
	cmp r2, #MAX_DAY		// maximale Tage im Monat erreicht?
	itt hi					
	movhi r2, #1			// wieder beim ersten des Monats anfangen
	addhi r3, #1			// Monate hochzählen
	
	cmp r3, #MAX_MONTH		// ein Jahr durchlaufen?
	itt hi					
	movhi r3, #1			// wieder bei Januar anfangen		
	addhi r6, #1			// Jahr hochzählen
	
	cmp r6, #MAX_YEAR		// Jahrhundert begrenzen
	it hi					
	movhi r6, #0			// wieder im Jahrhundert anfangen
	
		// Werte für Datum und Zeit speichern
	strb r0, [r4, #MINUTE]
	strb r1, [r4, #HOUR]
	strb r2, [r4, #DAY]
	strb r3, [r4, #MONTH]
	strb r6, [r4, #YEAR]	
	
	b loop_input

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogramm (aktuelle Uhrzeit): 
* Ausgabe der aktuellen Uhrzeit + Datum in der Form (dd.mm.jjjj  hh:mm)
* verwendete Register:
*	r0: Zeiger auf Array der Uhrzeit + Datum
*/	
.thumb_func
print_clock:
	//-----------------------
	// Inhalte sichern
	push {r4-r5,LR}
	//-----------------------
	
		// Zeiger für Datum Uhrzeit zwischenspeichern
	mov r4, r0

		// Tage ausgeben
	ldrb r5, [r4, #DAY]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0
	blls uart_putByteBase10	
	mov r0, r5	
	bl uart_putByteBase10
	ldr r0, =str_pt	
	bl uart_putString
	
		// Monate ausgeben
	ldrb r5, [r4, #MONTH]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10	
	mov r0, r5	
	bl uart_putByteBase10	
	ldr r0, =str_pt	
	bl uart_putString
	
		// Jahre ausgeben
	mov r0, #PRAEFIX_YEAR
	bl uart_putByteBase10
	ldrb r5, [r4, #YEAR]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10		
	mov r0, r5		
	bl uart_putByteBase10
	ldr r0, =str_space	
	bl uart_putString
	bl uart_putString			// Leerzeichen doppelt ausgeben
	
		// Stunden ausgeben
	ldrb r5, [r4, #HOUR]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10	
	mov r0, r5			
	bl uart_putByteBase10
	ldr r0, =str_dpt	
	bl uart_putString
	
		// Minuten ausgeben
	ldrb r5, [r4, #MINUTE]
	cmp r5, #NO_DOUBLE_DIGIT 	// führende 0 notwendig?
	itt ls
	movls r0, #0	
	blls uart_putByteBase10		
	mov r0, r5			
	bl uart_putByteBase10
	ldr r0, =str_space	
	bl uart_putString
	ldr r0, =str_clock	
	bl uart_putString

	//-----------------------
	// Ruecksprung
	pop {r4-r5,PC}
	//-----------------------
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR für PIT1: 
* Interrupt Service Routine für den PIT1
*
*/	
.thumb_func
isr_pit1:
		// löschen des interrupt flags
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0] 
	
	    // Flag Bit für eine Sekunde von pit1 setzen
	ldr r0, =flag_oneSec
	mov r1, #1
	str r1, [r0]	
	
	    // return from interrupt
	bx LR						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	



/*** Datenbereich (ab 0x20000000) ***/
.data		//		Tag		Monat	Jahr	Stunde	Minute
date_time:	.byte	0x1, 	0x1, 	0xE, 	0x0, 	0x0
str_pt:			.asciz "."
str_dpt:		.asciz ":"
str_space:		.asciz " "
str_clock:		.asciz "Uhr\n"
str_newLine: 	.asciz "\n"
str_InHour:		.asciz "Stunde eingeben (hh): "
str_InMinute:	.asciz "Minuten eingeben (mm): "
str_InDay:		.asciz "Tag eingeben (dd): "
str_InMonth:	.asciz "Monat eingeben (mm): "
str_InYear:		.asciz "Jahr eingeben (jj): "
flag_oneSec:	.byte 0x0	// flag welches von der isr des pit1 gesetzt wird
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

	// Konstanten für Adressen CRC-Modul
.equ CRC_CLOCK,			0x429007C8		// Alias Adresse für Clock Enable CRC
.equ CRC_CRC,			0x40032000		// CRC Data Register, beinhaltet den Wert für Seed, Data und Checksumme
.equ CRC_GPOLY,			0x40032004		// CRC Polynomial register, beinhaltet das Generatorpolynom
.equ CRC_CTRL,			0x40032008		// CRC Control Register, Einstellungen für CRC-Modul 
.equ CRC_CTRL_WAS,		0x42640164		// Alias Adresse zu "Write CRC Data Register As Seed"
.equ CRC_CTRL_TCRC,		0x42640160		// Alias Adresse zu "Width of CRC protocol"

	// Konstanten zur Initialisierung CRC-Modul
.equ GPOLY,				0x4C11DB7		// Generatorpolynom x³²+x²⁶+x²³+x²²+x¹⁶+x¹²+x¹¹+x¹⁰+x⁸+x⁷+x⁵+x⁴+x²+x+1
.equ CRC_SEED,			0x12345678		// Startwert für CRC-Generierung

	// Konstanten zum einlesen des Textes
.equ SHIFT_BYTE,		0x8				// Shift um 8 Bits
.equ WORD_SIZE,			0x4				// Groesse eines Wortes in Byte

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	
	// init CRC
	mov r2, #1
	mov r3, #0
	
		// clock von CRC aktivieren
	ldr r0, =CRC_CLOCK
	str r2, [r0]
	
		// Startinitialisierung laden	- transposed und Invertierung ausschalten
	ldr r0, =CRC_CTRL
	str r3, [r0]					// Startinitialisierung des CRC-Moduls --> alles ausgeschalten
	
		// 32-Bit Mode aktivieren
	ldr r0, =CRC_CTRL_TCRC
	strb r2, [r0]
	
	    // Generatorpolynom laden
	ldr r0, =CRC_GPOLY
	ldr r1, =GPOLY					// mov ist auf 8-Bit Konstanten begrenzt
	str r1, [r0]	
	
	    // Seed (Startwert) laden
	ldr r0, =CRC_CTRL_WAS
	str r2, [r0]
	ldr r0, =CRC_CRC
	ldr r1, =CRC_SEED
	str r1, [r0]
	
	     // CRC Umschalten auf Daten einlesen
	ldr r0, =CRC_CTRL_WAS
	str r3, [r0]	

	//***********************
	
// ---------------------------------------------------------------------------
// Schleife zum einlesen und gleichzeitigem generieren der CRC-Checksumme	
	ldr r0, =str
	ldr r4, =CRC_CRC
	mov r5, #0			// Flag das Nullterminierung erkannt wurde -> 1: Nullterminierung erkannt, 0: normales Zeichen

loop_genCRC:
	// Neues Wort einlesen
	mov r2, #0
	mov r3, #WORD_SIZE
	
	// innere Schleife zum Auslesen der einzelnen Zeichen -> dann raussprung bei Nullterminierung
loop_readWord:
	// Zeichen einlesen - es sollte hier jedes Byte betrachtet werden um die Nullterminierung zu erkennen
	ldrb r1, [r0], #1
	cmp r1, #0
	it eq
	moveq r5, #1			// Flag Nullterminierung setzen
	beq calc_CRC			
	
	// Zeichen in Wort schieben	
	lsl r2, r2, #SHIFT_BYTE		// Platz für neues Zeichen schaffen
	orr r2, r2, r1
	subs r3, r3, #1
	bne loop_readWord		// noch kein komplettes Wort eingelesen
	
	// CRC erzeugen
calc_CRC:
		// bei gültigen Zeichen im Wort -> CRC berechnen
	cmp r2, #0
	it ne
	strne r2, [r4]
	
	    // noch keine Nullterminierung gefunden -> weiter einlesen
	cmp r5, #1
	bne loop_genCRC
	
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// Ausgabe des Strings und der CRC-Checksumme	
ausgabe:
	ldr r0, =str
	bl uart_putString
	ldr r0, =str_crc
	bl uart_putString	
	ldr r1, =CRC_CRC
	ldr r0, [r1]
	bl uart_putInt32
// ---------------------------------------------------------------------------

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
str_crc: .asciz "\nCRC32-Checksumme: 0x"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

	// Konstanten für GPIO Register
.equ SIM_SCGC5_PORTA,		0x42900724		// Alias Adresse für SIM PORTA (Freischaltung Clock)
.equ SIM_SCGC5_PORTE,		0x42900734		// Alias Adresse für SIM PORTE (Freischaltung Clock)
.equ GPIOA_PDDR,			0x400FF014		// Adresse zu "Port Data Direction Register von Port A"
.equ GPIOE_PDDR,			0x400FF114		// Adresse zu "Port Data Direction Register von Port E"
.equ GPIOA_PDOR_PTA11,		0x43FE002C		// Alias Adresse zu GPIOA_PDOR PTA11 -> LED E1
.equ GPIOA_PDOR_PTA28,		0x43FE0070		// Alias Adresse zu GPIOA_PDOR PTA28 -> LED E2
.equ GPIOA_PDOR_PTA29,		0x43FE0074		// Alias Adresse zu GPIOA_PDOR PTA29 -> LED E3
.equ GPIOA_PDOR_PTA10,		0x43FE0028		// Alias Adresse zu GPIOA_PDOR PTA10 -> LED E4
.equ PORTA_PCR10,			0x40049028		// Adresse zu "Port Control Register PORTA" - Pin 10
.equ PORTA_PCR11,			0x4004902C		// Adresse zu "Port Control Register PORTA" - Pin 11
.equ PORTA_PCR19,			0x4004904C		// Adresse zu "Port Control Register PORTA" - Pin 19
.equ PORTA_PCR28,			0x40049070		// Adresse zu "Port Control Register PORTA" - Pin 28
.equ PORTA_PCR29,			0x40049074		// Adresse zu "Port Control Register PORTA" - Pin 29
.equ PORTE_PCR26,			0x4004D068		// Adresse zu "Port Control Register PORTE" - Pin 26
.equ GPIOA_PDIR_PTA19,		0x43FE024C		// Alias Adresse zu "Port Data Input Register" von PTA19
.equ GPIOE_PDIR_PTE26,		0x43FE2268		// Alias Adresse zu "Port Data Input Register" von PTE26
.equ PORTE_IRQHandler,		0x1FFFFFAC		// Adresse in IVT (Interrupt Vector Table) im SRAM der ISR für PIT1
.equ PORTE_PCR26_ISF,		0x429A0D60		// Alias Adresse zum Interrupt Service Flag

	// Konstanten Init GPIO Register 
.equ INIT_GPIOA_PDDR,		0x30000C00		// Ausgänge: E1 -> PTA11, E2 -> PTA28, E3 -> PTA29, E4 -> PTA10, Rest werden als Eingänge gesehen: SW1 (schwarz) -> PTA19
.equ INIT_GPIOE_PDDR,		0x0				// Alles Eingänge (SW2(grün) -> PTE26)
.equ INIT_GPIO_OUT,			0x100			// Initialisierung Ausgänge -> MUX = GPIO
.equ INIT_GPIO_IN,			0x103			// Initialisierung Eingang -> MUX = GPIO; PE = Pull enabled; PS = pullup-Widerstand verwenden
.equ INIT_GPIO_IN_IRQ,		0x10A0103		// Initialisierung Eingang ISR -> IRQC = 1010 (falling edge); MUX = 001 (GPIO); PE; PS

	// Konstanten für PIT1-Register
.equ PIT_MCR,				0x40037000		// Adresse PIT Module Control Register (PIT_MCR)
.equ PIT_LDVAL1,			0x40037110		// Adresse Timer Load Value Register (PIT_LDVAL1)
.equ PIT_TCTRL1_CHN,		0x426E2308		// Bit-Band-Alias Adresse für Chain Mode PIT1 (PIT_TCTRL1_CHN)
.equ PIT_TCTRL1_TIE,		0x426E2304		// Bit-Band-Alias Adresse für Timer Interrupt Enable PIT1 (PIT_TCTRL1_TIE)
.equ PIT_TCTRL1_TEN,		0x426E2300		// Bit-Band-Alias Adresse für Timer Enable PIT1 (PIT_TCTRL1_TEN)
.equ PIT_TFLG1,				0x4003711C		// Adresse zum Timer Flag Register Timer0 (PIT_TFLG1)
.equ PIT_CLK,				0x429007DC		// Bit-Band-Alias Adresse für Clock PIT im SIM - System Integration Module - SIM_SCGC6 4004_803Ch
.equ PIT_INIT_LDVAL1,		0x17D783F		// Load Value für 1s -> ldval trigger = (1s/25MHz)-1
.equ PIT1_IRQHandler,		0x1FFFFF54		// Adresse in IVT (Interrupt Vector Table) im SRAM der ISR für PIT1

	// Konstanten für NVIC-Register
.equ NVIC_ICPR2,			0xE000E288		// Interrupt Clear-Pending Register
.equ NVIC_ICPR2_CLRPEND5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 hängende Interrupts löschen (Bit 5 in ICPR2)
.equ NVIC_ISER2,			0xE000E108		// Interrupt Set-Enable Register
.equ NVIC_ISER2_SETENA5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 setzen (Bit 5 in ISER2)
.equ NVIC_ICPR2_CLRPEND27,	0x08000000		// Interrupt Nummer 91 für Pin detect (Port E) hängende Interrupts löschen (Bit 27 in ICPR2)
.equ NVIC_ISER2_SETENA27,	0x08000000		// Interrupt Nummer 91 für Pin detect (Port E)  (Bit 27 in ISER2)

	// Konstanten Dualzähler
.equ CNT_MAX,				0xFF			// 8-Bit Dualzähler Maximum
.equ CNT_MIN,				0x00			// 8-Bit Dualzähler Minimum
.equ MASK_TOGGLE,			0xFFFFFFFF		// Maske um komplettes Register zu toggeln

	// Konstante für Delay
.equ CT_DELAY5MS,			0xA2C2

	// ASCII-Zeichen Eingabe
.equ START_STOP,	0x73				// 's'
.equ PLUS,			0x2B				// '+'
.equ MINUS,			0x2D				// '-'


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	
	bl gpio_init
	
	bl pit_init		
	
	//***********************
	
loop_input:
	
	// ----------------------
	// Terminaleingabe
	// ----------------------
	bl uart_charPresent
	cmp r0, #0				// Auf Ungleichheit zu 0 prüfen
	beq check_push_buttons
	bl uart_getChar

		// 's' (start/stop) Zähler anhalten/starten
	cmp r0, #START_STOP
	beq terminal_start_stop

		// '+' (plus) Zähler soll hochzählen
	cmp r0, #PLUS
	beq terminal_count_up
	
		// '-' (minus) Zähler soll runterzählen
	cmp r0, #MINUS
	beq terminal_count_down

terminal_start_stop:
	ldr r0, =stop_count
	ldrb r1, [r0]
	eor r1, r1, #1
	strb r1, [r0]
	
	    // Ausgabe Stoppbit
	cmp r1, #0
	ite eq
	ldreq r0, =str_run
	ldrne r0, =str_stop
	bl uart_putString
		
	b check_push_buttons
	
terminal_count_up:
	ldr r0, =flag_count_direction
	mov r1, #0
	strb r1, [r0]
	
	   // Ausgabe hoch-/runterzählen
	ldr r0, =str_count_dir
	bl uart_putString
	ldr r0, =flag_count_direction
	ldrb r0, [r0]
	bl uart_putByteBase10 
	ldr r0, =str_nl
	bl uart_putString 
	
	b check_push_buttons

terminal_count_down:
	ldr r0, =flag_count_direction
	mov r1, #1
	strb r1, [r0]
	
	   // Ausgabe hoch-/runterzählen
	ldr r0, =str_count_dir
	bl uart_putString
	ldr r0, =flag_count_direction
	ldrb r0, [r0]
	bl uart_putByteBase10 
	ldr r0, =str_nl
	bl uart_putString 
		
	// ----------------------
	// HW-Taster
	// ----------------------
check_push_buttons:
	// ----------------------
	// keine Taste gedrückt
	// ----------------------
	bl sw1_sw2_not_pushed
	
	// ----------------------
	// Polling (SW1 - schwarze Taste)
	// ----------------------
	bl sw1_polling
	
	// ----------------------
	// ISR (SW2 - grüne Taste)
	// ----------------------
	ldr r0, =falling_edge_sw2
	ldrb r0, [r0]
	cmp r0, #1
	bne start_stop				// Taste nicht gedrückt
		// Taste gedrückt
	bl delay_5ms
	ldr r0, =GPIOE_PDIR_PTE26
	ldr r0, [r0]
	cmp r0, #0
	bne start_stop				// Taste nicht mehr gedrückt
		// Taste immer noch gedrückt
	mov r1, #2
	ldr r0, =mod
	str r1, [r0] 
	    // flag für fallende Flanke zurücksetzen
	ldr r0, =falling_edge_sw2
	mov r1, #0
	strb r1, [r0]
	    // Flag Bit für stoppen des Zählers toggeln
	ldr r0, =stop_count
	ldrb r1, [r0]
	eor r1, r1, #1
	strb r1, [r0]
	    // Ausgabe Stoppbit
	cmp r1, #0
	ite eq
	ldreq r0, =str_run
	ldrne r0, =str_stop
	bl uart_putString
		// Ausgabe mod
	ldr r0, =str_push
	bl uart_putString
	ldr r0, =mod
	ldr r0, [r0]
	bl uart_putByteBase10
	ldr r0, =str_nl
	bl uart_putString
	

start_stop:	
	// ----------------------
	// Zähler gestoppt/running
	// ----------------------
	ldr r0, =stop_count
	ldrb r0, [r0]
	cmp r0, #0
	bne loop_input
	

// ----------------------	
// 8-Bit Dualzähler
// ----------------------
dualcounter:
		// eine Sekunde abgelaufen?
	ldr r0, =flag_oneSec
	ldrb r0, [r0]
	cmp r0, #1
	bne loop_input	
	
	    // Flag Bit für eine Sekunde von pit1 löschen
	ldr r0, =flag_oneSec
	mov r1, #0
	strb r1, [r0]	
	
	// Hoch- oder Runterzählen
	ldr r0, =flag_count_direction		// 0: hochzählen; 1:runterzählen
	ldrb r0, [r0]
	cmp r0, #0
	bne count_down	

	// Hochzählen
count_up:
	ldr r5, =cntdual
	ldrb r0, [r5]
	add r0, r0, #1
	cmp r0, #CNT_MAX		// Maximum überschritten
	it hi
	movhi r0, #CNT_MIN		// von 0 wieder anfangen zu zählen		
	strb r0, [r5]
	b ausgabe
	
	// Runterzählen
count_down:
	ldr r5, =cntdual
	ldrb r0, [r5]
	sub r0, r0, #1
	cmp r0, #CNT_MIN		// 0 überschritten
	it mi
	movmi r0, #CNT_MAX		// von Maximum wieder anfangen zu zählen		
	strb r0, [r5]

// ----------------------	
// Ausgabe des dualen Zählwertes und LED-Ansteuerung
// ----------------------	
ausgabe:
		// Terminal Ausgabe
	ldr r5, =cntdual
	ldrb r0, [r5]
	bl uart_putByteBase10
	ldr r0, =str_nl
	bl uart_putString
	
		// GPIO LED Ausgabe
	ldrb r0, [r5]
	eor r0, r0, #MASK_TOGGLE	// alle Bits toggeln
	
	    // Bit 0 auf E1 legen
	and r1, r0, #1	// letztes Bit ausmaskieren
	ldr r2, =GPIOA_PDOR_PTA11
	str r1, [r2]
	
	    // Bit 1 auf E2 legen
	lsr r1, r0, #1
	and r1, r1, #1
	ldr r2, =GPIOA_PDOR_PTA28
	str r1, [r2]
	
	    // Bit 2 auf E3 legen
	lsr r1, r0, #2
	and r1, r1, #1
	ldr r2, =GPIOA_PDOR_PTA29
	str r1, [r2]
	
	    // Bit 3 auf E4 legen
	lsr r1, r0, #3
	and r1, r1, #1
	ldr r2, =GPIOA_PDOR_PTA10
	str r1, [r2]
	
	
	
	
	
// -----------------------------------------------------------------------------------------------------------------	
// Input wiederholen - Schleife
// -----------------------------------------------------------------------------------------------------------------	
	b loop_input
	
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* INIT GPIO: 
*/	
.thumb_func
gpio_init:

	// init gpio
	mov r2, #1
	
		// clock von GPIO PORTA aktivieren
	ldr r0, =SIM_SCGC5_PORTA
	str r2, [r0]
	
		// clock von GPIO PORTE aktivieren
	ldr r0, =SIM_SCGC5_PORTE
	str r2, [r0]
	
	    // Ausgänge und Eingänge initialisieren PORTA
	    // Ausgänge: E1 -> PTA11, E2 -> PTA28, E3 -> PTA29, E4 -> PTA10, Rest werden als Eingänge gesehen: SW1 (schwarz) -> PTA19
	ldr r0, =GPIOA_PDDR
	ldr r1, =INIT_GPIOA_PDDR
	str r1, [r0]
	
	    // Ausgänge und Eingänge initialisieren PORTE
	    // Alles Eingänge (SW2(grün) -> PTE26)
	ldr r0, =GPIOE_PDDR
	ldr r1, =INIT_GPIOE_PDDR
	str r1, [r0]
	
	    // Port control register initialisieren Ausgänge
	ldr r0, =PORTA_PCR10
	ldr r1, =INIT_GPIO_OUT
	str r1, [r0]
	ldr r0, =PORTA_PCR11
	ldr r1, =INIT_GPIO_OUT
	str r1, [r0]
	ldr r0, =PORTA_PCR28
	ldr r1, =INIT_GPIO_OUT
	str r1, [r0]
	ldr r0, =PORTA_PCR29
	ldr r1, =INIT_GPIO_OUT
	str r1, [r0]
	
	    // Port control register initialisieren Eingänge
	ldr r0, =PORTA_PCR19
	ldr r1, =INIT_GPIO_IN
	str r1, [r0]
	ldr r0, =PORTE_PCR26
	ldr r1, =INIT_GPIO_IN_IRQ
	str r1, [r0]
	
		// Interrupt-Vektor zu PORTE setzen,
	ldr r0, =PORTE_IRQHandler	// Adresse IVT für PORTE laden
	ldr r1, =sw2_isr			// Startadresse von ISR laden
	str r1, [r0]
	
		// eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC),
	ldr r0, =NVIC_ICPR2	
	mov r1, #NVIC_ICPR2_CLRPEND27
	str r1, [r0]
		
		// Interrupt zu PIT1 aktivieren (NVIC),
	ldr r0, =NVIC_ISER2
	mov r1, #NVIC_ISER2_SETENA27
	str r1, [r0]
	
	//-----------------------
	// Ruecksprung
	bx LR
	//-----------------------				
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++		

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* INIT PIT: 
*/	
.thumb_func
pit_init:
	
	//------ init PIT1	
	mov r2, #1
	mov r3, #0
	
		// Takt für PIT aktivieren (System Integration Module – SIM),
	ldr r0, =PIT_CLK			// Adresse Clock PIT im SIM
	str r2, [r0]			
		
		// Interrupt-Vektor zu PIT1 setzen,
	ldr r0, =PIT1_IRQHandler	// Adresse IVT für PIT1 laden
	ldr r1, =isr_pit1			// Startadresse von ISR laden
	str r1, [r0]
	
		// eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC),
	ldr r0, =NVIC_ICPR2	
	mov r1, #NVIC_ICPR2_CLRPEND5
	str r1, [r0]
		
		// Interrupt zu PIT1 aktivieren (NVIC),
	ldr r0, =NVIC_ISER2
	mov r1, #NVIC_ISER2_SETENA5
	str r1, [r0]	
		
		// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul),
	ldr r0, =PIT_MCR
	str r3, [r0]
		
		// Startwert für PIT1 auf 1 Sekunde initialisieren,
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_INIT_LDVAL1
	str r1, [r0]
		
	    // Chain Mode deaktivieren
	ldr r0, =PIT_TCTRL1_CHN
	str r3, [r0]
		
		// Interrupt zu PIT1 aktivieren (PIT-Modul),
	ldr r0, =PIT_TCTRL1_TIE
	str r2, [r0]
		
		// PIT1 aktivieren (PIT-Modul).
	ldr r0, =PIT_TCTRL1_TEN
	str r2, [r0]
	
	//-----------------------
	// Ruecksprung
	bx LR
	//-----------------------				
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++		

		
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR für PIT1: 
* Interrupt Service Routine für den PIT1
*
*/	
.thumb_func
isr_pit1:
		// löschen des interrupt flags
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0] 
	
	    // Flag Bit für eine Sekunde von pit1 setzen
	ldr r0, =flag_oneSec
	mov r1, #1
	strb r1, [r0]	
	
	    // return from interrupt
	bx LR						
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogram keine Taste gedrückt
*
*/	
.thumb_func
sw1_sw2_not_pushed:
	//-----------------------
	// Inhalte sichern
	push {LR}				// --> UP-Aufrufe vorhanden, deswegen push und pop notwendig
	//-----------------------
	
		// mod schon 0
	ldr r0, =mod
	ldr r0, [r0]
	cmp r0, #0
	beq sw1_sw2_skip
				
		// sw1 abfragen
	ldr r0, =GPIOA_PDIR_PTA19
	ldr r0, [r0]
	cmp r0, #1
	bne sw1_sw2_skip
	
		// sw2 abfragen
	ldr r0, =GPIOE_PDIR_PTE26
	ldr r0, [r0]
	cmp r0, #1
	bne sw1_sw2_skip
				
		// 0: keine Taste gedrückt
	ldr r1, =mod
	mov r0, #0
	str r0, [r1]
	
		// Ausgabe mod
	ldr r0, =str_push
	bl uart_putString
	ldr r0, =mod
	ldr r0, [r0]
	bl uart_putByteBase10
	ldr r0, =str_nl
	bl uart_putString
		
sw1_sw2_skip:
	
	//-----------------------
	// Ruecksprung
	pop {PC}
	//-----------------------				
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++		
			
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogram für Taster SW1(schwarz) - Polling 
*
* r3 = fallende flanke sw1 zwischenspeicher
* r4 = GPIO SW1 Taste gedrückt

*/	
.thumb_func
sw1_polling:
	//-----------------------
	// Inhalte sichern
	push {r4,LR}
	//-----------------------
		
	ldr r3, =falling_edge_sw1
	ldr r4, =GPIOA_PDIR_PTA19
		
		// fallende Flanke abfragen
	ldrb r0, [r3]
	cmp r0, #1
	beq sw1_skip			
		
		// SW1 schwarze Taste gedrückt
	ldr r0, [r4]		
	cmp r0, #0						
	bne sw1_skip					// Taste nicht gedrückt
	
	bl delay_5ms					// Entprellung
	
	ldr r0, [r4]
	cmp r0, #0
	bne sw1_skip					// Taste nicht mehr gedrückt
	ldr r1, =mod
	mov r0, #1						// Taste immer noch gedrückt - 1: SW1 (Polling) setzen
	str r0, [r1]
	mov r0, #1
	strb r0, [r3]					// Flanke zwischenspeichern
	ldr r0, =flag_count_direction
	ldrb r1, [r0]
	eor r1, r1, #1					// toggle hoch/runter
	strb r1, [r0]
	
		// Ausgabe mod
	ldr r0, =str_push
	bl uart_putString
	ldr r0, =mod
	ldr r0, [r0]
	bl uart_putByteBase10
	ldr r0, =str_nl
	bl uart_putString
	
	   // Ausgabe hoch-/runterzählen
	ldr r0, =str_count_dir
	bl uart_putString
	ldr r0, =flag_count_direction
	ldrb r0, [r0]
	bl uart_putByteBase10 
	ldr r0, =str_nl
	bl uart_putString 
	
sw1_skip:

	ldr r0, [r4] 
	cmp r0, #1
	itt eq
	moveq r0, #0
	strbeq r0, [r3]
	
	//-----------------------
	// Ruecksprung
	pop {r4,PC}
	//-----------------------				
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogram für Taster SW2(grün) - ISR
*
*/	
.thumb_func
sw2_isr:
		
		// löschen des interrupt flags
	ldr r0, =PORTE_PCR26_ISF
	mov r1, #1
	str r1, [r0] 
	
	    // Flag Bit für fallende Flanke von sw2 setzen
	ldr r0, =falling_edge_sw2
	mov r1, #1
	strb r1, [r0]	
	
	    // return from interrupt
	bx LR									
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	

	
		
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogramm (delay_5ms): 
* Programmschleife die eine Verzögerung von etwa 5ms generiert
*
*/	
.thumb_func
delay_5ms:
	
		// Konstante für 5ms laden
	ldr r0, =CT_DELAY5MS		// mov nur bei einer 8-Bit Zahl möglich
	
loop_delay:
	subs r0, r0, #1				// herunterzählen
	bne loop_delay				// solange die Variable nicht null ist weiter dekrementieren	
	
	//-----------------------
	// Ruecksprung
	bx LR
	//-----------------------
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
	
	

/*** Datenbereich (ab 0x20000000) ***/
.data
str_nl: 				.asciz "\n"
flag_oneSec:			.byte 0x0	// flag welches von der isr des pit1 gesetzt wird
cntdual:				.byte 0x0	// Zählerstand des 8-Bit Dualzählers
mod:					.word 0x0	// Variable um aktuellen Zustand "gedrückte Taste" darzustellen, 0: keine Taste ; 1: SW1 (schwarz - Polling) ; 2: SW2 (grün - ISR)
falling_edge_sw1: 		.byte 0x0	// flag für fallende Flanke von sw1
falling_edge_sw2: 		.byte 0x0 	// flag für fallende Flanke von sw2
flag_count_direction: 	.byte 0x0	// flag für Zählrichtung 0: hochzählen; 1: runterzählen
stop_count:				.byte 0x0	// flag um Zähler zu stoppen 0: running; 1: gestoppt
str_stop:				.asciz "Zaehler gestoppt!\n"
str_run:				.asciz "Zaehler gestartet!\n"
str_count_dir:			.asciz "Zaehlrichtung: 0 = hochzaehlen; 1 = runterzaehlen --> "
str_push:				.asciz "Tastendruck: 0 = keine Taste; 1 = SW1 (Polling); 2 = SW2 (ISR) --> mod = "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

	// Konstanten für Adressen des ADC1-Moduls
.equ ADC1_CLOCK,		0x4290066C		// Alias Adresse für Clock Enable ADC1
.equ ADC1_SC1A,			0x400BB000		// ADC1 Status Control Register SC1A
.equ ADC1_SC1A_COCO,	0x4376001C		// Alias Adresse ADC1 Status Control Register SC1A - Conversion Complete Flag
.equ ADC1_CFG1,			0x400BB008		// ADC1 Control Register CFG1
.equ ADC1_CFG2,			0x400BB00C		// ADC1 Control Register CFG2
.equ ADC1_RA,			0x400BB010		// ADC1 Result Register
.equ ADC1_SC2,			0x400BB020		// ADC1 Status Control Register SC2
.equ ADC1_SC2_ADACT,	0x43760418		// Alias Adresse ADC1 Status Control Register SC2 - Conversion Active
.equ ADC1_SC3,			0x400BB024		// ADC1 Status Control Register SC3

	// Konstanten für die Initialisierung des ADC1-Moduls
.equ ADC1_SC1A_INIT,		0x14			// AIEN = 0 (Interrupt abgewählt); DIFF = 0 (Single-Ended); ADCH = 10100 (AD20 als Input-channel)
.equ ADC1_CFG1_INIT,		0x6D			// ADLPC = 0 (normal mode); ADIV = 11 (input clk/8); ADLSMP = 0 (short sample time) MODE = 11 (16-Bit Resolution); ADICLK = 01 (Bus clock/2)
.equ ADC1_CFG2_INIT,		0x0				// MUXSEL = 0; ADACKEN = 0 (async. clk. disabled); ADHSC = 0 (high-speed config. -> normal); ADLSTS = 0 (Long Sample Time Sel. -> normal)
.equ ADC1_SC2_INIT,			0x0				// ADTRG = 0 (sw trigger); ACFE = 0 (no compare); ACFGT = 0 (disabled); ACREN = 0 (disabled); DMAEN = 0 (disabled); REFSEL = 00 (Vrefh, Vrefl)
.equ ADC1_SC3_INIT,			0xE				// ADCO = 1 (contin. conv. enabled); AVGE = 1 (HW Avg. Enabled); AVGS = 10 (HW Average Select -> 16 samples)
.equ ADC1_SC1A_DIS_CONV,	0x1F			// Disable Conversion if ADCH = 11111 (module disabled)
.equ ADC1_SC1A_EN_CONV,		0x74			// Enable Conversion ADCH = 10100 (AD20 als Input-channel);
.equ CV_MODE_8BIT,			0x0				// Conversion Mode 8-BIT
.equ CV_MODE_10BIT,			0x2				// Conversion Mode 10-BIT
.equ CV_MODE_12BIT,			0x1				// Conversion Mode 12-BIT
.equ CV_MODE_16BIT,			0x3				// Conversion Mode 16-BIT

	// Konstanten zum kalibrieren des ADC1-Moduls
.equ ADC1_SC3_INIT_CALIB,	0x7			// AVGE = 1 (HW Average Enable); AVGS = 11 (32 samples)
.equ ADC1_CFG1_INIT_CALIB,	0x61		// ADIV = 11 (input clk/8); MODE = 00 (8-bit); ADICLK = 01 (Bus clock/2)
.equ ADC1_CLPS,				0x400BB038	// Adresse zu ADC1_CLPS -> wird als Startadresse verwendet, die danach liegenden Register (CLP4..CLP0) werden mit einem Zeiger verwendet
.equ ADC1_CLMS,				0x400BB058	// Adresse zu ADC1_CLMS -> wird als Startadresse verwendet...
.equ ADC1_CLPMx_INC,		0x4			// Inkrement für den Zeiger auf die weiteren Kalibrierungsregister (Plus und Minus)
.equ ADC1_SC3_CAL,			0x4376049C	// Alias Adresse ADC1 Status Control Register SC3 - Calibration
.equ ADC1_SC3_CALF,			0x43760498	// Alias Adresse ADC1 Status Control Register SC3 - Calibration failed
.equ ADC1_CLPMx_NO,			0x6			// Anzahl der Register die für die Kalibrierung zusammenaddiert werden müssen
.equ ADC1_MSB,				0x8000		// MSB einer 16-Bit Zahl gesetzt
.equ ADC1_PG,				0x400BB02C	// Adresse zu ADC1_PG -> Positive Gain
.equ ADC1_MG,				0x400BB030	// Adresse zu ADC1_MG -> Minus Gain


	// Konstanten für PIT1-Register
.equ PIT_MCR,				0x40037000		// Adresse PIT Module Control Register (PIT_MCR)
.equ PIT_LDVAL1,			0x40037110		// Adresse Timer Load Value Register (PIT_LDVAL1)
.equ PIT_TCTRL1,			0x40037118		// Adresse zum Timer Control Register (PIT_TCTRL1)
.equ PIT_TCTRL1_INIT,		0x3				// Init von Timer Control Register (PIT_TCTRL1): CHN = 0; TIE = 1; TEN = 1
.equ PIT_TFLG1,				0x4003711C		// Adresse zum Timer Flag Register Timer0 (PIT_TFLG1)
.equ PIT_CLK,				0x429007DC		// Bit-Band-Alias Adresse für Clock PIT im SIM - System Integration Module - SIM_SCGC6 4004_803Ch
.equ PIT_INIT_LDVAL1,		24999999		// Load Value für 1s -> ldval trigger = (1s/25MHz)-1
.equ PIT1_IRQHandler,		0x1FFFFF54		// Adresse in IVT (Interrupt Vector Table) im SRAM der ISR für PIT1

	// Konstanten für NVIC-Register
.equ NVIC_ICPR2,			0xE000E288		// Interrupt Clear-Pending Register
.equ NVIC_ICPR2_CLRPEND5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 hängende Interrupts löschen (Bit 5 in ICPR2)
.equ NVIC_ISER2,			0xE000E108		// Interrupt Set-Enable Register
.equ NVIC_ISER2_SETENA5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 setzen (Bit 5 in ISER2)

	// Konstanten für GPIO Register
.equ SIM_SCGC5_PORTA,		0x42900724		// Alias Adresse für SIM PORTA (Freischaltung Clock)
.equ GPIOA_PDDR,			0x400FF014		// Adresse zu "Port Data Direction Register von Port A"
.equ GPIOA_PDOR_PTA11,		0x43FE002C		// Alias Adresse zu GPIOA_PDOR PTA11 -> LED E1
.equ GPIOA_PDOR_PTA28,		0x43FE0070		// Alias Adresse zu GPIOA_PDOR PTA28 -> LED E2
.equ GPIOA_PDOR_PTA29,		0x43FE0074		// Alias Adresse zu GPIOA_PDOR PTA29 -> LED E3
.equ GPIOA_PDOR_PTA10,		0x43FE0028		// Alias Adresse zu GPIOA_PDOR PTA10 -> LED E4
.equ PORTA_PCR10,			0x40049028		// Adresse zu "Port Control Register PORTA" - Pin 10
.equ PORTA_PCR11,			0x4004902C		// Adresse zu "Port Control Register PORTA" - Pin 11
.equ PORTA_PCR28,			0x40049070		// Adresse zu "Port Control Register PORTA" - Pin 28
.equ PORTA_PCR29,			0x40049074		// Adresse zu "Port Control Register PORTA" - Pin 29
.equ MASK_TOGGLE,			0xFFFFFFFF		// Maske um komplettes Register zu toggeln

	// Konstanten Init GPIO Register 
.equ INIT_GPIOA_PDDR,		0x30000C00		// Ausgänge: E1 -> PTA11, E2 -> PTA28, E3 -> PTA29, E4 -> PTA10
.equ INIT_GPIO_OUT,			0x100			// Initialisierung Ausgänge -> MUX = GPIO

	// Konstante für Stages
.equ MAX_VOLTAGE_VALUE,		3300			// 3300mV ist der maximale Spannungswert
.equ MAX_REG_VALUE,			0xFFFF			// maximaler Registerwert

	// Konstanten für Ausgabe
.equ DEC_HUNDRED,			100
.equ DEC_TEN,				10
.equ RESOLUTION_8BIT,		8
.equ RESOLUTION_10BIT,		10
.equ RESOLUTION_12BIT,		12
.equ RESOLUTION_16BIT,		16

	// ASCII-Zeichen Eingabe
.equ START_STOP,	0x73				// 's'
.equ NUMBER_0,		0x30				// '0'
.equ NUMBER_1,		0x31				// '1'
.equ NUMBER_2,		0x32				// '2'
.equ NUMBER_3,		0x33				// '3'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	//***********************
	// INIT
	bl uart_init
	
	bl ADC1_calib
	bl ADC1_init

	bl pit_init
	
	bl gpio_init	
	
	// init pointer to arrays
	ldr r0, =array_stage_pt
	ldr r1, =array_stage_16
	str r1, [r0]
	ldr r0, =array_stage_volt_pt
	ldr r1, =array_stage_16_volt
	str r1, [r0]
	
	//***********************

loop_input:
	
	// ----------------------
	// Terminaleingabe
	// ----------------------
	bl uart_charPresent
	cmp r0, #0				// Character eingegeben prüfen
	beq check_start_stop
	bl uart_getChar

		// 's' (start/stop) Zähler anhalten/starten
	cmp r0, #START_STOP
	beq input_start_stop
	
	// weitere Eingaben nur durch lassen wenn gestoppt ist
	ldr r1, =stop_adc1
	ldr r1, [r1]
	cmp r1, #1
	bne check_start_stop
		
		// '0' Conversion Mode 8-Bit
	cmp r0, #NUMBER_0
	itttt eq
	moveq r1, #RESOLUTION_8BIT
	moveq r2, #CV_MODE_8BIT
	ldreq r3, =array_stage_8
	ldreq r4, =array_stage_8_volt
	
		// '1' Conversion Mode 10-Bit
	cmp r0, #NUMBER_1
	itttt eq
	moveq r1, #RESOLUTION_10BIT
	moveq r2, #CV_MODE_10BIT
	ldreq r3, =array_stage_10
	ldreq r4, =array_stage_10_volt
	
		// '2' Conversion Mode 12-Bit
	cmp r0, #NUMBER_2
	itttt eq
	moveq r1, #RESOLUTION_12BIT
	moveq r2, #CV_MODE_12BIT
	ldreq r3, =array_stage_12
	ldreq r4, =array_stage_12_volt
	
		// '3' Conversion Mode 16-Bit
	cmp r0, #NUMBER_3
	itttt eq
	moveq r1, #RESOLUTION_16BIT
	moveq r2, #CV_MODE_16BIT
	ldreq r3, =array_stage_16
	ldreq r4, =array_stage_16_volt
	
		// überprüfen ob eine sinnvolle Eingabe erfolgt ist
	cmp r1, #1
	beq check_start_stop
	
		// stage in RAM speichern
	ldr r5, =n_stage
	str r1, [r5]
	    // conversion mode in CFG1 ändern
	ldr r5, =ADC1_CFG1
	ldr r6, [r5]
	bfi r6, r2, #2, #2
	str r6, [r5]
	    // pointer für stage und stage_volt anpassen
	ldr r5, =array_stage_pt
	str r3, [r5]
	ldr r5, =array_stage_volt_pt
	str r4, [r5]	
	
	    // Ausgabe der Auflösungsänderung
	mov r4, r1					// sichern von der stage, wegen ausgabe
	ldr r0, =str_resolution
	bl uart_putString
	mov r0, r4
	bl uart_putByteBase10
	ldr r0, =str_resolution_bit
	bl uart_putString
	ldr r0, =str_nl
	bl uart_putString	
	
	b check_start_stop

input_start_stop:
	ldr r0, =stop_adc1
	ldr r1, [r0]
	eor r1, r1, #1
	str r1, [r0]	
	
	ldr r0, =ADC1_SC1A			// Adresse für weitere Verarbeitung bereithalten
	cmp r1, #0
	bne input_stop				// es muss gestoppt werden, ansonsten wird gestartet
	
// input start	
	// ADC1 starten
	ldr r1, [r0]
	and r1, r1, #ADC1_SC1A_EN_CONV
	str r1, [r0]
	// Ausgabe starten
	ldr r0, =str_run
	bl uart_putString
	
	b check_start_stop
	
// input stop
input_stop:	
	// ADC1 stoppen
	ldr r1, [r0]
	orr r1, r1, #ADC1_SC1A_DIS_CONV
	str r1, [r0]
	// Ausgabe stoppen
	ldr r0, =str_stop
	bl uart_putString

check_start_stop:	
	// prüfen ob Anwendung gestoppt ist
	ldr r0, =stop_adc1
	ldr r0, [r0]
	cmp r0, #0
	bne loop_input

	// ----------------------
	// Berechnung und Ausgabe des ADC1-Wertes (zyklisch jede Sekunde)
	// ----------------------
		// eine Sekunde abgelaufen?
	ldr r1, =flag_oneSec
	ldr r0, [r1]
	cmp r0, #1
	bne loop_input	
	
	    // Flag Bit für eine Sekunde von pit1 löschen
	mov r0, #0
	str r0, [r1]	
	
	// Ausgabe des aktuellen ADC-Values als (4-stelliger) Hexadezimalwert
	ldr r0, =str_hex
	bl uart_putString
	ldr r0, =ADC1_RA
	ldr r0, [r0]
	bl uart_putInt16	
	
	//-----------------
	// Berechnung der Spannungswerte für die Stage + Ausgabe
	//-----------------	
	// r0 = aktueller Spannungswert (hex-Wert)
	// r1 = ausgewählte Anzahl der stages (e.g. N=16)
	// r2 = zeiger auf array von der stage
	// r5 = stage
	ldr r0, =ADC1_RA
	ldr r0, [r0]
	ldr r1, =n_stage
	ldr r1, [r1]
	ldr r2, =array_stage_pt
	ldr r2, [r2]				// Inhalt des Pointers ist die gewünschte Anfangsadresse
	add r2, r2, #4
	mov r5, #0
	
loop_select_stage:
	ldr r4, [r2], #4
	cmp r4, r0
	bhi ausgabe_stage
	beq ausgabe_stage
	
	add r5, r5, #1		// nächste stage
	
	b loop_select_stage

	//-----------------
	// Ausgabe des Spannungswertes + Stage und Range
	//-----------------
ausgabe_stage:
	ldr r0, =str_space
	bl uart_putString	
	ldr r4, =array_stage_volt_pt
	ldr r4, [r4]				// Inhalt des Pointers ist die gewünschte Anfangsadresse		
	lsl r6, r5, #2
	ldr r0, [r4, r6]
	cmp r0, #0
	it ne
	addne r0, #1
	bl uart_putDecimal
	ldr r0, =str_minus
	bl uart_putString
	add r6, r6, #4
	ldr r0, [r4, r6]
	bl uart_putDecimal
	ldr r0, =str_mV
	bl uart_putString
	ldr r0, =str_stage
	bl uart_putString
	mov r0, r5
	bl uart_putByteBase10
	ldr r0, =str_closeBraket
	bl uart_putString	
	
	// GPIO LED Ausgabe
	eor r0, r5, #MASK_TOGGLE	// alle Bits toggeln
	
	    // Bit 0 auf E1 legen
	and r1, r0, #1	// letztes Bit ausmaskieren
	ldr r2, =GPIOA_PDOR_PTA11
	str r1, [r2]
	
	    // Bit 1 auf E2 legen
	lsr r1, r0, #1
	and r1, r1, #1
	ldr r2, =GPIOA_PDOR_PTA28
	str r1, [r2]
	
	    // Bit 2 auf E3 legen
	lsr r1, r0, #2
	and r1, r1, #1
	ldr r2, =GPIOA_PDOR_PTA29
	str r1, [r2]
	
	    // Bit 3 auf E4 legen
	lsr r1, r0, #3
	and r1, r1, #1
	ldr r2, =GPIOA_PDOR_PTA10
	str r1, [r2]


	//-----------------
	// Eingabe abfragen (Loop)
	//-----------------        
	b loop_input
	
	
	// Fehlerausgabe, falls Kalibrierung fehlgeschlagen ist
failure:
	ldr r0, =str_failure_calib
	bl uart_putString	
end:
	b end
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ADC1_calib: 
* Kalibrierung des ADC1 nach Handbuch für die besten Resultate der Kalibrierung
*/	
.thumb_func
ADC1_calib:
	//-----------------------
	// Inhalte sichern - wegen Ausgabe nötig
	push {LR}
	//-----------------------
	
		// Clock für ADC1 aktivieren
	ldr r0, =ADC1_CLOCK
	mov r1, #1
	str r1, [r0]

		// Register für Kalibrierung initialisieren
	ldr r0, =ADC1_SC3
	mov r1, #ADC1_SC3_INIT_CALIB
	str r1, [r0]
	ldr r0, =ADC1_CFG1
	mov r1, #ADC1_CFG1_INIT_CALIB
	str r1, [r0]
	ldr r0, =ADC1_SC2
	mov r1, #0							
	str r1, [r0]
	ldr r0, =ADC1_CFG2
	str r1, [r0]

		// Ausgabe Kalibrierung starten
	ldr r0, =str_start_calib
	bl uart_putString
	ldr r0, =ADC1_SC3_CAL
	mov r2, #1
	str r2, [r0]		// Kalibrierung starten
	ldr r2, =ADC1_SC1A_COCO
	ldr r3, =ADC1_SC3_CALF
	
	// warten bis Kalibrierung abgeschlossen ist, oder ein Fehler aufgetreten ist
calib_active:
	ldr r0, [r3]
	cmp r0, #1
	beq failure
	ldr r0, [r2]
	cmp r0, #0
	beq calib_active
	
	// Berechnung für plus-side calibration
	mov r0, #0
	ldr r1, =ADC1_CLPS
	mov r3, #ADC1_CLPMx_NO
calib_plus:
	ldr r2, [r1], #ADC1_CLPMx_INC
	add r0, r2
	subs r3, #1
	bne calib_plus
		// alle Werte addiert
	lsr r0, r0, #1
	orr r0, r0, #ADC1_MSB
	ldr r3, =ADC1_PG
	str r0, [r3]
	
	// Berechnung für minus-side calibration
	mov r0, #0
	ldr r1, =ADC1_CLMS
	mov r3, #ADC1_CLPMx_NO	 
calib_minus:	
	ldr r2, [r1], #ADC1_CLPMx_INC
	add r0, r2
	subs r3, #1
	bne calib_minus
		// alle Werte addiert
	lsr r0, r0, #1
	orr r0, r0, #ADC1_MSB
	ldr r3, =ADC1_MG
	str r0, [r3]
	
		// Ausgabe Kalibrierung beendet
	ldr r0, =str_end_calib
	bl uart_putString
		
	//-----------------------
	// Ruecksprung
	pop {PC}
	//-----------------------				

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++		
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ADC1_init: 
* Initialisieren des ADC1
*/	
.thumb_func
ADC1_init:
		// Clock für ADC1 aktivieren
	// wurde schon bei Kalibrierung aktiviert
	
	// Register ADC1 initialisieren
	ldr r0, =ADC1_CFG1
	mov r1, #ADC1_CFG1_INIT
	str r1, [r0]
	ldr r0, =ADC1_CFG2
	mov r1, #ADC1_CFG2_INIT
	str r1, [r0]
	ldr r0, =ADC1_SC2
	mov r1, #ADC1_SC2_INIT
	str r1, [r0]
	ldr r0, =ADC1_SC3
	mov r1, #ADC1_SC3_INIT
	str r1, [r0]	
	   // muss als letztes initialisiert werden, damit wird automatisch ein dauerhaftes Konvertieren aktiviert.
	ldr r0, =ADC1_SC1A
	mov r1, #ADC1_SC1A_INIT
	str r1, [r0]

	//-----------------------
	// Ruecksprung
	bx LR	
	//-----------------------			

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++		
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* INIT PIT: 
*/	
.thumb_func
pit_init:
	
	//------ init PIT1	
	mov r2, #1
	mov r3, #0
	
		// Takt für PIT aktivieren (System Integration Module – SIM),
	ldr r0, =PIT_CLK			// Adresse Clock PIT im SIM
	str r2, [r0]			
		
		// Interrupt-Vektor zu PIT1 setzen,
	ldr r0, =PIT1_IRQHandler	// Adresse IVT für PIT1 laden
	ldr r1, =isr_pit1			// Startadresse von ISR laden
	str r1, [r0]
	
		// eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC),
	ldr r0, =NVIC_ICPR2	
	mov r1, #NVIC_ICPR2_CLRPEND5
	str r1, [r0]
		
		// Interrupt zu PIT1 aktivieren (NVIC),
	ldr r0, =NVIC_ISER2
	mov r1, #NVIC_ISER2_SETENA5
	str r1, [r0]	
		
		// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul),
	ldr r0, =PIT_MCR
	str r3, [r0]
		
		// Startwert für PIT1 auf 1 Sekunde initialisieren,
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_INIT_LDVAL1
	str r1, [r0]
		
		// Timer Control Register initialisieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_INIT
	str r1, [r0]
	
	//-----------------------
	// Ruecksprung
	bx LR
	//-----------------------				
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR für PIT1: 
* Interrupt Service Routine für den PIT1
*
*/	
.thumb_func
isr_pit1:
	// init register
	mov r1, #1

		// löschen des interrupt flags
	ldr r0, =PIT_TFLG1
	str r1, [r0] 
	
	    // Flag Bit für eine Sekunde von pit1 setzen
	ldr r0, =flag_oneSec
	str r1, [r0]	
	
	    // return from interrupt
	bx LR						
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++		

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* INIT GPIO: 
*/	
.thumb_func
gpio_init:

	// init gpio
	mov r2, #1
	
		// clock von GPIO PORTA aktivieren
	ldr r0, =SIM_SCGC5_PORTA
	str r2, [r0]
	
	    // Ausgänge und Eingänge initialisieren PORTA
	    // Ausgänge: E1 -> PTA11, E2 -> PTA28, E3 -> PTA29, E4 -> PTA10
	ldr r0, =GPIOA_PDDR
	ldr r3, [r0]
	ldr r1, =INIT_GPIOA_PDDR
	orr r3, r3, r1
	str r3, [r0]
	
	    // Port control register initialisieren Ausgänge
	ldr r0, =PORTA_PCR10
	mov r1, #INIT_GPIO_OUT
	str r1, [r0]
	ldr r0, =PORTA_PCR11
	str r1, [r0]
	ldr r0, =PORTA_PCR28
	str r1, [r0]
	ldr r0, =PORTA_PCR29
	str r1, [r0]
	
	//-----------------------
	// Ruecksprung
	bx LR
	//-----------------------				
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Ausgabe eines Dezimalwertes von 0000-9999: 
* - r0 -> Übergabe des Dezimalwertes
*
*/	
.thumb_func
uart_putDecimal:

	//-----------------------
	// Inhalte sichern
	push {r4,LR}
	//-----------------------
	// init register
		// r4 -> Übergabe des Dezimalwertes
	mov r4, r0

	mov r2, #DEC_HUNDRED
	
	udiv r0, r4, r2
	mul r1, r0, r2
	sub r4, r4, r1
	bl uart_putByteBase10
	cmp r4, #DEC_TEN
	itt ls
	movls r0, #0
	blls uart_putByteBase10		// führende 0	
	mov r0, r4
	bl uart_putByteBase10
	
	//-----------------------
	// Ruecksprung
	pop {r4,PC}
	//-----------------------						
						

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	
	

/*** Datenbereich (ab 0x20000000) ***/
.data
str_failure_calib: 		.asciz "\nFehler bei der Kalibrierung des ADC1 - muss erneut versucht werden!\n"
str_start_calib: 		.asciz "Kalibrierung beginnt...\n"
str_end_calib: 			.asciz "...Kalibrierung beendet.\n"
flag_oneSec:			.word 0x0	// flag welches von der isr des pit1 gesetzt wird
str_hex:				.asciz "0x"
str_nl:					.asciz "\n"
n_stage:				.word 0x10	// init stage ist N=16 - entspricht 16 Stufen (16-bit Auflösung)
str_space:				.asciz " "
str_minus:				.asciz " - "
str_mV:					.asciz " mV "
str_stage:				.asciz "(Stufe "
str_closeBraket:		.asciz ")\n"
array_stage_pt:			.word 0x0		// pointer auf array der aktuell ausgewählten Stage
array_stage_volt_pt:	.word 0x0		// pointer auf array_volt der aktuell ausgewählten Stage
array_stage_8:			.word 0, 32, 64, 96, 128, 160, 192, 224, 256
array_stage_8_volt:		.word 0, 412, 825, 1237, 1650, 2062, 2475, 2887, 3300
array_stage_10:			.word 0, 102, 205, 307, 410, 512, 614, 717, 819, 922, 1024
array_stage_10_volt:	.word 0, 330, 660, 990, 1320, 1650, 1980, 2310, 2640, 2970, 3300
array_stage_12:			.word 0, 341, 683, 1024, 1365, 1707, 2048, 2389, 2731, 3072, 3413, 3755, 4096
array_stage_12_volt:	.word 0, 275, 550, 825, 1100, 1375, 1650, 1925, 2200, 2475, 2750, 3025, 3300
array_stage_16:			.word 0, 4096, 8192, 12287, 16384, 20480, 24576, 28672, 32767, 36863, 40959, 45055, 49151, 53247, 57343, 61439, 65535
array_stage_16_volt:	.word 0, 206, 412, 618, 825, 1031, 1237, 1444, 1650, 1856, 2062, 2699, 2475, 2681, 2887, 3094, 3300
str_stop:				.asciz "ADC1 gestoppt!\n"
str_run:				.asciz "ADC1 gestartet!\n"
stop_adc1:				.word 0x0	// flag um Wandlung zu stoppen 0: running; 1: gestoppt
str_resolution:			.asciz "Die Aufloesung wurde auf "
