// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

	// Konstanten für PIT1-Register
.equ PIT_MCR,				0x40037000		// Adresse PIT Module Control Register (PIT_MCR)
.equ PIT_LDVAL1,			0x40037110		// Adresse Timer Load Value Register (PIT_LDVAL1)
.equ PIT_TCTRL1,			0x40037118		// Adresse zum Timer Control Register (PIT_TCTRL1)
.equ PIT_TCTRL1_INIT,		0x3				// Init von Timer Control Register (PIT_TCTRL1): CHN = 0; TIE = 1; TEN = 1
.equ PIT_TFLG1,				0x4003711C		// Adresse zum Timer Flag Register Timer0 (PIT_TFLG1)
.equ PIT_CLK,				0x429007DC		// Bit-Band-Alias Adresse für Clock PIT im SIM - System Integration Module - SIM_SCGC6 4004_803Ch
.equ PIT_INIT_LDVAL1,		24999999		// Load Value für 1s -> ldval trigger = (1s/25MHz)-1
.equ PIT1_IRQHandler,		0x1FFFFF54		// Adresse in IVT (Interrupt Vector Table) im SRAM der ISR für PIT1

	// Konstanten für NVIC-Register
.equ NVIC_ICPR2,			0xE000E288		// Interrupt Clear-Pending Register
.equ NVIC_ICPR2_CLRPEND5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 hängende Interrupts löschen (Bit 5 in ICPR2)
.equ NVIC_ISER2,			0xE000E108		// Interrupt Set-Enable Register
.equ NVIC_ISER2_SETENA5,	0x20			// Interrupt Nummer 69 für PIT Channel 1 setzen (Bit 5 in ISER2)

	// Konstanten für I2C0-Register
.equ I2C0_CLK,				0x42900698		// Bit-Band-Alias Adresse für Clock I2C0 im SIM - System Integration Module - SIM_SCGC4 4004_8034
.equ I2C0_F,				0x40066001		// Frequency Divider Register
.equ I2C0_F_INIT,			0x12			// mul = 1, scl divider 0x12 = 64 -> Datenblatt von DS75 besagt, dass max. Baudrate für fSCL = 400kHz
											//		Folgende Rechnung wird angesetzt: 25Mhz/400kHz = 62,5 -> die nächst höhere natürliche Zahl beträgt 64, welche durch den Divider eingestellt werden kann.
.equ I2C0_C1,				0x40066002		// Adresse zu Control Register 1
.equ I2C0_C1_INIT,			0xC0			// IICEN = Enabled, IICIE = Enabled, WUEN = normal operation, DMAEN = Disabled
.equ I2C0_C1_IICEN,			0x42CC005C		// Bit-Band-Alias Adresse für I2C0 Enable - Alias-Adresse von einem Byte-Register
.equ I2C0_C1_MST,			0x42CC0054		// Bit-Band-Alias Adresse für Master Mode Select - Alias-Adresse von einem Byte-Register
.equ I2C0_C1_TX,			0x42CC0050		// Bit-Band-Alias Adresse für Transmit Mode Select - Alias-Adresse von einem Byte-Register
.equ I2C0_C1_TXAK,			0x42CC004C		// Bit-Band-Alias Adresse für Transmit Acknowledge Enable - Alias-Adresse von einem Byte-Register
.equ I2C0_C1_RSTA,			0x42CC0048		// Bit-Band-Alias Adresse für Repeat Start - Alias-Adresse von einem Byte-Register
.equ I2C0_S_TCF,			0x42CC007C		// Bit-Band-Alias Adresse für Transfer Complete Flag - Alias-Adresse von einem Byte-Register
.equ I2C0_S_BUSY,			0x42CC0074		// Bit-Band-Alias Adresse für Bus Busy - Alias-Adresse von einem Byte-Register
.equ I2C0_S_ARBL,			0x42CC0070		// Bit-Band-Alias Adresse für Arbitration Lost - Alias-Adresse von einem Byte-Register
.equ I2C0_S_IICIF,			0x42CC0064		// Bit-Band-Alias Adresse für Interrupt Flag - Alias-Adresse von einem Byte-Register
.equ I2C0_S_RXAK,			0x42CC0060		// Bit-Band-Alias Adresse für Receive Acknowledge - Alias-Adresse von einem Byte-Register
.equ I2C0_D,				0x40066004		// Adresse zu Data I/O Register
.equ MASK_LS,				0x00FF			// Maske für LS Data Byte
.equ SHIFT_8BIT,			0x8				// Shift 8 Bit
.equ PT_TEMPERATURE,		0x0				// Pointer Temperature
.equ PT_CONFIGURATION,		0x1				// Pointer Configuration
.equ PT_THYST,				0x2				// Pointer T_HYST
.equ PT_TOS,				0x3				// Pointer T_OS
.equ THYST_OFFSET,			0x200			// Offset 2° bei T_HYST
.equ TOS_OFFSET,			0x300			// Offset 3° bei T_OS
.equ DEC_LS_BIT7,			5000			// Dezimal Zahl 2⁻¹ (Darstellung mit 4-Stellen)
.equ DEC_LS_BIT6,			2500			// Dezimal Zahl 2⁻² (Darstellung mit 4-Stellen)
.equ DEC_LS_BIT5,			1250			// Dezimal Zahl 2⁻³ (Darstellung mit 4-Stellen)
.equ DEC_LS_BIT4,			625				// Dezimal Zahl 2⁻⁴ (Darstellung für 4-Stellen)
.equ DEC_HUNDRED,			100
.equ DEC_TEN,				10

.equ CT_ARB_ERR,			10				// Anzahl der Fehlversuche zur Verbindung zum I2C0 Slave
.equ ADDR_SLAVE,			0x90			// Adresse des Slave (Thermometer DS75)
.equ D75_INIT_CFG,			0x60			// 12-Bit Conversion Resolution


	// Konstanten zum zurücksetzen des I2C0-Busses
.equ SIM_PORTD,		0x42900730	// Bit-Band-Alias Adresse zu Clock von PORTD - SIM_SCGC5 = 0x4004_8038
.equ PORTD_PCR8,	0x4004C020	// Adresse zu Pin Control Register von Pin 8
.equ PORTD_PCR9,	0x4004C024	// Adresse zu Pin Control Register von Pin 9
.equ GPIOD_PDDR,	0x400FF0D4	// Adresse zu Port Data Direction Register von Port D
.equ GPIOD_PDOR,	0x400FF0C0	// Adresse zu Port Data Output Register von Port D
.equ GPIOD_PDIR,	0x400FF0D0	// Adresse zu Port Data Input Register von Port D
.equ PD8_9, 		0x300 		// Maske fuer PD8 und PD9
.equ PD8, 			0x100 		// Maske fuer PD8
.equ ALT_GPIO, 		0x100 		// Alternative 1: GPIO
.equ ALT_I2C0,		0x200		// Alternative 2: I2C0
.equ WAIT_I2C0,		25			// Anzahl der Zyklen zum Warten bis ca. 2us abgelaufen

.equ CHAR_0,		'0'
.equ CHAR_X,		'x'
.equ CHAR_COMMA,	','
.equ CHAR_COLON,	':'
.equ CHAR_SPACE,	' '

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	//***********************
	// INIT	
	bl uart_init
	
	bl pit_init
	
	bl I2CBus_Reset
	bl I2CBus_Init
	bl I2CBus_Init_DS75
	
	//***********************
	
	// Pointer auf Temperatur setzen
	mov r0, #0				// schreiben
	bl I2CBus_Start
	mov r0, #0				// pointer byte = 0 -> Temperatur
	bl I2CBus_WriteByte
	bl I2CBus_Stop

mainLoop:
	// ----------------------
	// Berechnung und Ausgabe des Temperaturwertes (zyklisch jede Sekunde)
	// ----------------------
		// eine Sekunde abgelaufen?
	ldr r1, =flag_oneSec
	ldr r0, [r1]
	cmp r0, #1
	bne mainLoop
	    // Flag Bit für eine Sekunde von pit1 löschen
	mov r0, #0
	str r0, [r1]	
	
	    // Temperatur aus DS75 ermitteln und ausgeben	    
	bl putTemp

	b mainLoop
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* INIT PIT: 
*/	
.thumb_func
pit_init:
	
	//------ init PIT1	
	mov r2, #1
	mov r3, #0
	
		// Takt für PIT aktivieren (System Integration Module – SIM),
	ldr r0, =PIT_CLK			// Adresse Clock PIT im SIM
	str r2, [r0]			
		
		// Interrupt-Vektor zu PIT1 setzen,
	ldr r0, =PIT1_IRQHandler	// Adresse IVT für PIT1 laden
	ldr r1, =isr_pit1			// Startadresse von ISR laden
	str r1, [r0]
	
		// eventuell hängende (pending) Interrupts zu PIT1 löschen (NVIC),
	ldr r0, =NVIC_ICPR2	
	mov r1, #NVIC_ICPR2_CLRPEND5
	str r1, [r0]
		
		// Interrupt zu PIT1 aktivieren (NVIC),
	ldr r0, =NVIC_ISER2
	mov r1, #NVIC_ISER2_SETENA5
	str r1, [r0]	
		
		// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul),
	ldr r0, =PIT_MCR
	str r3, [r0]
		
		// Startwert für PIT1 auf 1 Sekunde initialisieren,
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_INIT_LDVAL1
	str r1, [r0]
		
		// Timer Control Register initialisieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_INIT
	str r1, [r0]
	
	bx LR							

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	
	
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR für PIT1: 
* Interrupt Service Routine für den PIT1
*
*/	
.thumb_func
isr_pit1:
	// init register
	mov r1, #1

		// löschen des interrupt flags
	ldr r0, =PIT_TFLG1
	str r1, [r0] 	
	    // Flag Bit für eine Sekunde von pit1 setzen
	ldr r0, =flag_oneSec
	str r1, [r0]	
		
	    // return from interrupt
	bx LR												

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/		


/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Ermittlung der Temperatur und Ausgabe -> Pointer muss schon auf Temperatur eingestellt sein!
*
*/	
.thumb_func
putTemp:
	push {r4,LR}	
	
	bl I2CBus_Read2Byte	
	mov r4, r0				// temperatur sichern
		
	// Ausgabe der Werte auf dem Terminal
	mov r0, #CHAR_0
	bl uart_putChar
	mov r0, #CHAR_X
	bl uart_putChar
	mov r0, r4
	bl uart_putInt16
	mov r0, #CHAR_COLON
	bl uart_putChar
	mov r0, #CHAR_SPACE
	bl uart_putChar
	mov r0, r4	
	bl uart_putTemp	

	pop {r4,PC}											

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/

	
/* **************** I2C -Bus zuruecksetzen *********** */
.thumb_func
I2CBus_Reset:
	push {lr}

	ldr r0 , =SIM_PORTD 	// Den Takt fuer Port D aktivieren
	mov r1 , #1
	str r1 , [r0]
	ldr r0 , =PORTD_PCR8 	// Portleitungen PD8 , PD9 als GPIO
	ldr r1 , =PORTD_PCR9
	mov r2 , #ALT_GPIO
	str r2 , [r0]
	str r2 , [r1]
	ldr r0 , =GPIOD_PDDR 	// PD8 , PD9 als Ausgang schalten
	ldr r2 , [r0]
	orr r2 , r2 , #PD8_9
	str r2 , [r0]
	mov r3, CT_ARB_ERR		// Zähler für Versuche initialisieren

loop:
	subs r3, r3, #1
	beq resetErr			// Zähler abgelaufen	

	ldr r0 , =GPIOD_PDOR 	// SCL deaktivieren
	ldr r2 , [r0]
	bic r2 , r2 , #PD8 		// entsprechendes Bit loeschen
	str r2 , [r0]
	bl i2c_Delay

	ldr r0 , =GPIOD_PDOR 	// SCL und SDA aktivieren
	ldr r2 , [r0]
	orr r2 , r2 , #PD8_9
	str r2 , [r0]
	bl i2c_Delay

	ldr r0 , =GPIOD_PDIR
	ldr r2 , [r0]
	and r2 , r2 , #PD8_9 	// nur Bits 9 und 10 pruefen
	cmp r2 , #PD8_9 		// Bit 9 und Bit 10 gesetzt ?
	bne loop 				// ggf. wiederholen
	b resetDone
	
resetErr:
	ldr r0, =str_nl
	bl uart_putString
	ldr r0, =str_errReset
	bl uart_putString
	
resetDone:
	pop {pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Zeitverzögerung von ca. 2us für I2C-Bus
*	- damit die Busleitungen einen definierten Zustand einrichten können 
*
*/	
.thumb_func
i2c_Delay:
	
	mov r0, #WAIT_I2C0

loop_i2c_Delay:
	subs r0, r0, #1
	bne loop_i2c_Delay		// solange zähler noch nicht 0
	
	    // return from interrupt
	bx lr					
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* INIT I2C0-Bus: 
*/	
.thumb_func
I2CBus_Init:
	push {lr}
	
	ldr r0 , =SIM_PORTD 	// Den Takt fuer Port D aktivieren
	mov r1 , #1
	str r1 , [r0]
	ldr r0 , =PORTD_PCR8 	// Portleitungen PD8 , PD9 als GPIO
	ldr r1 , =PORTD_PCR9
	mov r2 , #ALT_I2C0
	str r2 , [r0]
	str r2 , [r1]

	// clock aktivieren
	ldr r0, =I2C0_CLK
	mov r1, #1
	str r1, [r0]
	
	// Frequenz einstellen
	ldr r0, =I2C0_F
	mov r1, #I2C0_F_INIT
	strb r1, [r0]
	
	// I2C0 enable
	ldr r0, =I2C0_C1
	mov r1, #I2C0_C1_INIT
	strb r1, [r0]

	pop {pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* INIT DS75 Thermometer über I2C0-Bus: 
* Konfiguration:
*	
*/	
.thumb_func
I2CBus_Init_DS75:
	push {r4-r7,lr}
	
	mov r4, #0
	
	// Konfiguration
	mov r0, #0						// schreiben
	bl I2CBus_Start
	mov r0, #1						// pointer byte = 1 -> Configuration
	bl I2CBus_WriteByte
	mov r0, #D75_INIT_CFG
	bl I2CBus_WriteByte
	bl I2CBus_Stop
	
	// Einstellen von T_HYST und T_OS
	mov r0, #0						// schreiben
	bl I2CBus_Start
	mov r0, #0						// pointer byte = 0 -> Temperature
	bl I2CBus_WriteByte	
	bl I2CBus_Stop

		// aktuelle Temperatur lesen
	bl I2CBus_Read2Byte				// Rückgabewert in r0
	mov r7, r0
	mov r5, #TOS_OFFSET				// Offset T_OS = 3°
	add r5, r7, r5					// T_OS
	mov r6, #THYST_OFFSET			// Offset T_HYST = 2°
	add r6, r7, r6					// T_HYST
	ldr r0, =str_akt_Temperatur
	bl uart_putString
	mov r0, r7
	bl uart_putTemp
	
		// schreiben des T_OS
	mov r0, #0						// schreiben
	bl I2CBus_Start
	mov r0, #PT_TOS					// pointer byte = 3 -> T_OS
	bl I2CBus_WriteByte
	lsr r0, r5, #SHIFT_8BIT			// MS Data Byte
	bl I2CBus_WriteByte
	and r0, r5, #MASK_LS			// LS Data Byte
	bl I2CBus_WriteByte
	bl I2CBus_Stop
	ldr r0, =str_TOS
	bl uart_putString
	mov r0, r5
	bl uart_putTemp
	
	
		// schreiben des T_HYST
	mov r0, #0						// schreiben
	bl I2CBus_Start
	mov r0, #PT_THYST				// pointer byte = 2 -> T_HYST
	bl I2CBus_WriteByte
	lsr r0, r6, #SHIFT_8BIT			// MS Data Byte
	bl I2CBus_WriteByte
	and r0, r6, #MASK_LS			// LS Data Byte
	bl I2CBus_WriteByte
	bl I2CBus_Stop	
	ldr r0, =str_THYST
	bl uart_putString
	mov r0, r6
	bl uart_putTemp

	pop {r4-r7,pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	


/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Starten einer Kommunikation als Master I2C0-Bus: 
* Übergabeparameter:
*	r0: Write = 0, Read = 1
* 
*/	
.thumb_func
I2CBus_Start:
	push {r4-r9,lr}

	mov r12, #CT_ARB_ERR		// Versuchscounter vorladen	
	ldr r11, =I2C0_C1_TX
	ldr r10, =I2C0_C1_MST
	ldr r4, =I2C0_D
	mov r5, #ADDR_SLAVE
	add r5, r5, r0			// write (r0=0) or read (r0=1)
	mov r6, #1
	mov r7, #1				// write address on i2c
	ldr r8, =I2C0_S_RXAK
	ldr r9, =I2C0_S_ARBL
	
loop_Start:		
	sub r12, r12, #1				// Versuchscounter herunterzählen
	strb r7, [r11]				// transmit slave address
	strb r6, [r10]				// master mode
	strb r5, [r4]				// slave adresse -> initiiert die Übertragung		
	bl I2CBus_WaitTransFin
	
	
	ldrb r0, [r10]				// master mode?
	cmp r0, r6	
	bne loop_Start
	// prüfen ob RXAK = 0 -> Acknowledge Bit ist gesendet worden
	ldrb r0, [r8]
	cmp r0, #0
	beq ComStartEnd
	
	// slave modus wird hier nicht berücksichtigt. - ARBL wird pauschal zurückgesetzt wenn kein master modus erreicht wurde
	strb r6, [r9]				// Arbitration Lost zurücksetzen
	cmp r12, #0
	bne loop_Start				// noch einen weiteren Versuch
	
	// arbitration lost
	ldr r0, =str_nl
	bl uart_putString
	ldr r0, =str_errArbitration
	bl uart_putString

ComStartEnd:
	pop {r4-r9,pc}	

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP zur Überprüfung ob die Übertragung beendet ist I2C0-Bus - mittels Interrupt Flag: 
* 
*/	
.thumb_func
I2CBus_WaitTransFin:
	push {lr}
	
	ldr r0, =I2C0_S_IICIF
	mov r1, #1
	
waitTransFin:
	ldrb r2, [r0]
	cmp r2, r1
	bne waitTransFin

	strb r1, [r0]
	b waitTransFinEnd
	
waitTransFinError:
	ldr r0, =str_WaitIICIF_Error
	bl uart_putString

waitTransFinEnd:
	pop {pc}	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP zum Beenden der I2C0-Busübertragung - Stop-Bit setzen: 
* 
*/	
.thumb_func
I2CBus_Stop:
	push {lr}
	
	mov r0, #0
	ldr r1, =I2C0_C1_MST
	ldr r2, =I2C0_C1_TX
	strb r0, [r1]	
	strb r0, [r2]
	bl i2c_Delay		// wartezeit	
		
	pop {pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP zum schreiben eines Bytes über den I2C0-Bus: 
* Übergabeparameter:
*	r0: byte welches geschrieben werden soll		 
*
*/	
.thumb_func
I2CBus_WriteByte:
	push {lr}	
	
	// nächstes Byte auf Bus legen	
	ldr r1, =I2C0_D	
	strb r0, [r1]
	
	bl I2CBus_WaitTransFin
	
	// testen ob letztes byte erfolgreich vom slave angenommen wurde
	ldr r2, =I2C0_S_RXAK
	ldrb r2, [r2]
	cmp r2, #0
	beq WriteByteEnd		// erfolgreich übertragen	
	
	// error
	bl I2CBus_Stop
	ldr r0, =str_RXAK_Error
	bl uart_putString

WriteByteEnd:	
	pop {pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP zum lesen eines Bytes vom I2C0-Bus (in unserer Applikation ist das immer das vorletzte Byte): 
* Rückgabeparameter:
*	r0: gelesene Daten (Byte)
*
*/	
.thumb_func
I2CBus_ReadByte:
	push {r4-r6,lr}	
	
	mov r4, #1
	mov r5, #0
	ldr r6, =I2C0_D
	
	mov r0, r4				// read
	bl I2CBus_Start

	ldr r0, =I2C0_C1_TX
	ldr r1, =I2C0_C1_TXAK	
	strb r5, [r0]			// Receive mode
	strb r4, [r1]			// NACK senden
	ldrb r0, [r6]			// dummy daten lesen
	bl I2CBus_WaitTransFin	
	bl I2CBus_Stop
	
	ldrb r0, [r6]			// return value
	
	pop {r4-r6,pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP zum lesen 2 Bytes vom I2C0-Bus: 
* Rückgabeparameter:
*	r0: gelesene Daten (16Bit)
*
*/	
.thumb_func
I2CBus_Read2Byte:
	push {r4-r9,lr}		
	
	ldr r4, =I2C0_C1_TX
	ldr r5, =I2C0_D
	ldr r6, =I2C0_C1_TXAK
	mov r7, #0
	mov r8, #1

	mov r0, r8				// read
	bl I2CBus_Start	
		// dummy lesen
	strb r7, [r4]		// Receive mode
	strb r7, [r6]		// Ack senden
	ldrb r0, [r5]		// dummy daten lesen
	bl I2CBus_WaitTransFin		
		// MSB lesen
	strb r8, [r6]		// Nack senden
	ldrb r9, [r5]		// MSB lesen
	lsl r9, r9, #SHIFT_8BIT
	bl I2CBus_WaitTransFin			
		// LSB lesen
	bl I2CBus_Stop
	ldrb r0, [r5]
	orr r9, r9, r0
	
	mov r0, r9			// return value	
	
	pop {r4-r9,pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP zur Ausgabe der Temperatur: 
* Übergabeparameter:
*	r0: Temperatur
* 
*/	
.thumb_func
uart_putTemp:
	push {r4-r10, lr}
	
	mov r4, r0					// sichern temperatur
	lsr r5, r4, #SHIFT_8BIT		// MS Byte
	and r6, r4, #MASK_LS		// LS Byte
	
	mov r0, r5
	bl uart_putByteBase10
	mov r0, #CHAR_COMMA
	bl uart_putChar
	
		// Kommazahl generieren
	ldr r7, =DEC_LS_BIT7
	ldr r8, =DEC_LS_BIT6
	ldr r9, =DEC_LS_BIT5
	ldr r10, =DEC_LS_BIT4
	mov r1, #0
	and r0, r6, #0x80
	cmp r0, #0
	it ne
	addne r1, r1, r7
	and r0, r6, #0x40
	cmp r0, #0
	it ne
	addne r1, r1, r8  	
	and r0, r6, #0x20
	cmp r0, #0
	it ne
	addne r1, r1, r9 	
	and r0, r6, #0x10
	cmp r0, #0
	it ne
	addne r1, r1, r10 
	mov r0, r1
	bl uart_putDecimal
	
	mov r0, #CHAR_SPACE
	bl uart_putChar
	ldr r0, =str_temp
	bl uart_putString
	ldr r0, =str_nl
	bl uart_putString


	pop {r4-r10, pc}	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Ausgabe eines Dezimalwertes von 0000-9999: 
* - r0 -> Übergabe des Dezimalwertes
*
*/	
.thumb_func
uart_putDecimal:

	//-----------------------
	// Inhalte sichern
	push {r4,LR}
	//-----------------------
	// init register
		// r4 -> Übergabe des Dezimalwertes
	mov r1, #100
	udiv r2, r0, r1			// Dezimalwert / 100
	mls r4, r2, r1, r0		// Dezimalwert r0 - Quotient r2 * 100 r1
	
	mov r0, r2
	cmp r0, #0x9			// kleiner/gleich 9?
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1					// passendes Unterprogramm aufrufen
	
	mov r0, r4
	cmp r0, #0x9
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	
	//-----------------------
	// Ruecksprung
	pop {r4,PC}
	//-----------------------							

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/


/*** Datenbereich (ab 0x20000000) ***/
.data
flag_oneSec:			.word 0x0	// flag welches von der isr des pit1 gesetzt wird
str_nl:					.asciz "\n"
str_temp:				.asciz "Grad Celsius"
str_errArbitration:		.asciz "Arbitration ist verloren nach den voreingestellten Versuchen"
str_errReset:			.asciz "Fehler beim zurücksetzen des I2C-Busses"
str_RepeatStartNoMST:	.asciz "Kein Master-Modus bei Repeat-Start aktiv!\n"
str_RXAK_Error:			.asciz "Letztes Byte wurde nicht korrekt quittiert - RXAK = 1\n"
str_WaitIICIF_Error:	.asciz "Kein Interrupt fuer fertige Uebertragung ausgeloest...\n"
str_akt_Temperatur:		.asciz "Aktuelle Temperatur: "
str_TOS:				.asciz "Temperatur T_OS: "
str_THYST:				.asciz "Temperatur T_HYST: "




// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

	// Konstanten für GPIO Register
.equ SIM_PORTA,				0x42900724		// Alias Adresse für SIM PORTA (Freischaltung Clock)
.equ SIM_PORTE,				0x42900734		// Alias Adresse für SIM PORTE (Freischaltung Clock)
.equ PDDR_SW1_BK,			0x43FE02CC	
.equ PDDR_SW2_GR,			0x43FE22E0
.equ SW2_GR_ISF,			0x429A0D60		// Alias Adresse zum Interrupt Service Flag Pin 26 PortE
.equ SW1_BK_ISF,			0x429209CC		// Alias Adresse zum ISF Pin 19 PortA
.equ PORTE_PCR26,			0x4004D068		// Adresse zu "Port Control Register PORTE" - Pin 26 - sw2 grün
.equ PORTA_PCR19,			0x4004904C		// Adresse zu "Port Control Register PORTA" - Pin 19 - sw1 schwarz
.equ GPIO_IRQ_PE_SET, 		0xA0103			// GPIO-Modus, IRQ (fallende Flanke), Pull-Up-Widerstand
.equ SCR_VTOR,				0xE000ED08		// Interrupt Vektortabelle

// IVT-Offsets
.equ IVT_PTE, 				0x1AC
.equ IVT_PTA,				0x19C
.equ IVT_PIT1,				0x154

// Konstanten für PIT1-Register
.equ PIT_MCR,				0x40037000		// Adresse PIT Module Control Register (PIT_MCR)
.equ PIT_LDVAL1,			0x40037110		// Adresse Timer Load Value Register (PIT_LDVAL1)
.equ PIT_TCTRL1,			0x40037118		// Adresse zum Timer Control Register (PIT_TCTRL1)
.equ PIT_TFLG1,				0x4003711C		// Adresse zum Timer Flag Register Timer0 (PIT_TFLG1)
.equ SIM_PIT,				0x429007DC		// Bit-Band-Alias Adresse für Clock PIT im SIM - System Integration Module - SIM_SCGC6 4004_803Ch

// Konstanten für NVIC-Register
.equ NVIC_ICPR2,			0xE000E288		// Interrupt Clear-Pending Register
.equ NVIC_ISER2_MASK,		0x8800020		// Bit 4 PIT1, SW1, SW2
.equ NVIC_BIT5,				0x20			// Interrupt Nummer 69 für PIT Channel 1 hängende Interrupts löschen (Bit 5 in ICPR2)
.equ NVIC_ISER2,			0xE000E108		// Interrupt Set-Enable Register

// Konstanten für SPI-Schnittstelle
.equ SIM_PORTD,				0x42900730		// Clock Port D
.equ PORTD_PCR11,			0x4004C02C
.equ ALT2_SPI2,				0x200			// Alternate 2: SPI2
.equ SIM_SPI2,				0x42900630		// Clock für SPI2, Bit 12 im SIM_SCGC3 Register
.equ SPI2_MCR,				0x400AC000		// SPI2 MCR-Register
.equ SPI2_CTAR0,			0x400AC00C		// im Master-Mode verwendet
.equ SPI2_RSER,				0x400AC030
.equ SPI2_HALT,				0x43580000		// alias adress
.equ SPI2_PUSHR,			0x400AC034
.equ SPI2_POPR,				0x400AC038
.equ SPI2_TCF,				0x435805FC

.equ SPI2_MCR_INIT,			0x80003C01		// master mode, spi mode, PSCS1 inaktiv bei low signal, disable TX/RX FIFO, clear TX/RX FIFO Counter (für init) stop transfers
.equ SPI2_CTAR0_INIT,		0x7A000007		// 50/50 duty cycle, CPOL = 0, CPHA = 1, MSB first, BR = 0111 -> Baud Rate Scaler = 128 // TODO: BaudRate Scaler richtig stellen

.equ SPI2_READ_CFG,			0x20000			// PCS1, 00h (read config)
.equ SPI2_WRITE_CFG, 		0x280f1			// schreiben von cfg register mit 8-Bit Auflösung, ONE-SHOT - wird als Vorlage verwendet
.equ SPI2_READTEMP_MSB,		0x20200			
.equ SPI2_READTEMP_LSB,		0x20100	

	// Konstanten für die Ansteuerung Temperatursensor DS1722
.equ PIT_LOAD_8BIT,			1874999			// load value für pit1 bei 8-Bit Auflösung -> max conversion time = 0,075s
											// -> Da sich die Konvertierungszeit bei jedem Bit mehr an Auflösung verdoppelt, wird der Load-Value für PIT1 durch Bit-Schieben berechnet
.equ MASK_LSB,				0xFF			// Maske für LSB

.equ CHAR_COMMA,	','
.equ CHAR_SPACE,	' '
.equ CHAR_NL,		'\n'
.equ CHAR_ZERO,		'0'
.equ CHAR_X,		'x'
.equ CHAR_COLON,	':'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// für Initialisierungen genutzte Werte
	mov r10, #0
	mov r11, #1
	
	// clocks für Module aktivieren
	ldr r0, =SIM_PORTA
	str r11, [r0]
	ldr r0, =SIM_PORTE
	str r11, [r0]
	ldr r0, =SIM_PIT
	str r11, [r0]
	ldr r0, =SIM_PORTD
	str r11, [r0]
	ldr r0, =SIM_SPI2
	str r11, [r0]
	
	// gpio konfigurieren
	ldr r1, =GPIO_IRQ_PE_SET	// GPIO, Interrupt bei fallender Flanke mit Pull-up Widerstand
	ldr r0, =PORTA_PCR19		// sw1 grün
	str r1, [r0]
	ldr r0, =PORTE_PCR26		// sw2 schwarz
	str r1, [r0]
	
	// spi2 konfigurieren
	ldr r1, =ALT2_SPI2
	ldr r0, =PORTD_PCR11
	str r1, [r0], #4			// PCR11
	str r1, [r0], #4			// PCR12
	str r1, [r0], #4			// PCR13
	str r1, [r0], #4			// PCR14
	str r1, [r0], #4			// PCR15	
	ldr r0, =SPI2_MCR_INIT
	ldr r1, =SPI2_MCR
	str r0, [r1]
	str r0, [r1]				// doppeltes schreiben, weil deaktivieren der FIFO's nicht durchgehen wenn MDIS noch 1 ist.
	ldr r0, =SPI2_CTAR0_INIT
	ldr r1, =SPI2_CTAR0
	str r0, [r1]
	ldr r1, =SPI2_RSER			// Interrupts ausschalten
	str r10, [r1]

	// Eingänge festlegen
	ldr r0, =PDDR_SW1_BK
	str r10, [r0]
	ldr r0, =PDDR_SW2_GR
	str r10, [r0]
	
	// IVT - Adressen der ISR's reinschreiben
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_port_e
	str r0, [r1, #IVT_PTE]
	ldr r0, =isr_port_a
	str r0, [r1, #IVT_PTA]
	ldr r0, =isr_pit1
	str r0, [r1, #IVT_PIT1]
	
	// hängende Interrupts löschen - nur PIT1
	ldr r0, =NVIC_ICPR2	
	mov r1, #NVIC_BIT5
	str r1, [r0]
	
	// Interrupts aktivieren (PIT1, PORTE, PORTA)
	ldr r0, =NVIC_ISER2
	ldr r1, =NVIC_ISER2_MASK
	str r1, [r0]		
		
	// PIT Timers aktivieren, im Debug-Modus anhalten,
	ldr r0, =PIT_MCR
	str r11, [r0]		
	
	// pit aktivieren und startwert auf 12-Bit Auflösung schreiben
	bl reload_pit1
	
	// cfg auf DS1722 schreiben
	bl write_DS1722_cfg
		
	// oft genutzte Register in der mainloop
	ldr r5, =flag_pit1
	ldr r6, =resolution
	ldr r7, =ft_sw1_bk
	ldr r8, =ft_sw2_gr
	ldr r9, =aDigits	
	ldr r12, =flag_skip_read
		
mainloop:	
	ldr r0, [r7]
	cmp r0, r11
	beq sw1Pushed
	
	ldr r0, [r8]
	cmp r0, r11
	beq sw2Pushed
	
	ldr r0, [r5]
	cmp r0, r11
	beq readTemp	
	
	b mainloop
	
// Auflösung vergrößern
sw1Pushed:
	str r10, [r7]			// flag zurücksetzen
	ldr r1, [r6]
	cmp r1, #4
	ite eq
	moveq r1, r10
	addne r1, r1, r11	
	str r1, [r6]
	b resChanged
	
// Auflösung verringern
sw2Pushed:
	str r10, [r8]			// flag zurücksetzen
	ldr r1, [r6]
	cmp r1, r10
	ite eq
	moveq r1, #4
	subne r1, r1, r11	
	str r1, [r6]
	b resChanged

// Temperatur lesen und ausgeben
readTemp:
	str r10, [r5]			// flag zurücksetzen	
	
	ldr r0, [r12]			// skip read prüfen - da der DS1722s erst beim nächsten ONE-SHOT die neue Auflösung übernimmt.
	cmp r0, r11
	beq skip_read
	
	// ausgabe als Hex
	mov r0, #CHAR_ZERO
	bl uart_putChar
	mov r0, #CHAR_X
	bl uart_putChar
	bl read_DS1722_temp		// Temperatur auslesen
	mov r4, r0				// sichern
	bl uart_putInt16		// auch wenn es nicht explizit gefordert: Ausgabe der HEX-Zahl von der Temperatur
	mov r0, #CHAR_COLON
	bl uart_putChar
	mov r0, #CHAR_SPACE
	bl uart_putChar
	
	
	mov r0, r4
	and r4, r0, #MASK_LSB		// LSB sichern
	lsr r4, r4, #2				// als Offset für digits vorbereiten	
	lsr r0, r0, #8				// MSB
	bl uart_putByteBase10
	mov r0, #CHAR_COMMA
	bl uart_putChar	
	
	// digits von temperatur ausgeben
	ldr r0, [r9, r4]
	bl uart_putDecimal
	mov r0, #CHAR_SPACE
	bl uart_putChar
	ldr r0, =str_temp
	bl uart_putString
	mov r0, #CHAR_NL
	bl uart_putChar
	
skip_read:	
	str r10, [r12]			// skip read bit zurücksetzen
	bl write_DS1722_cfg		// neuen One-Shot anstarten	
	
	b end
	
// Auflösung hat sich geändert
resChanged:
	bl reload_pit1				// pit1 mit neuer Zeit laden	
	str r11, [r12]				// skip read setzen - da der DS1722s erst beim nächsten ONE-SHOT die neue Auflösung übernimmt. In der Aufgabenstellung steht nicht geschrieben, dass hier keine Wartezeit erfolgen darf.
	ldr r0, =str_resolution
	bl uart_putString
	ldr r0, =resolution
	ldr r0, [r0]
	bl uart_putByteBase10
	mov r0, #CHAR_NL
	bl uart_putChar

end:
	b mainloop
		
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* DS1722 CFG schreiben mit entsprechender Auflösung: 
* Inputs:	keine
* Outputs:	keine
*/	
.thumb_func
write_DS1722_cfg:	
	// cfg schreiben
	mov r1, #0
	ldr r0, =SPI2_HALT
	str r1, [r0]			// transfers zulassen
	
	ldr r0, =resolution
	ldr r0, [r0]
	ldr r1, =SPI2_WRITE_CFG
	orr r0, r1, r0, lsl #1
	
	ldr r1, =SPI2_PUSHR
	str r0, [r1]			// transfer starten 
	
	mov r2, #1
	ldr r1, =SPI2_TCF
waitTCF_cfg:
	ldr r0, [r1]
	cmp r2, r0	
	bne waitTCF_cfg
	str r2, [r1]			// clear TCF	
	
	// dummy read
	ldr r1, =SPI2_POPR
	ldr r0, [r1]			// dummy read
	
	ldr r0, =SPI2_HALT
	str r2, [r0]			// transfers blockieren
		
	bx LR	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* DS1722 Temperatur lesen (mittels LSB und MSB einzeln auslesen, weil ONE-SHOT genutzt wird): 
* Inputs:	keine
* Outputs:	r0 = Temperatur
*/	
.thumb_func
read_DS1722_temp:		
	push {r4-r5, lr}

	ldr r0, =SPI2_HALT
	mov r1, #0
	str r1, [r0]			// transfers zulassen
	
	ldr r0, =SPI2_READTEMP_MSB
	ldr r1, =SPI2_PUSHR
	str r0, [r1]			// transfer starten
	
	ldr r2, =SPI2_POPR
	ldr r3, =SPI2_TCF
	mov r4, #1
waitTMP_1:
	ldr r0, [r3]
	cmp r4, r0	
	bne waitTMP_1
	str r4, [r3]			// clear TCF
	
	ldr r0, [r2]
	and r5, r0, #MASK_LSB	// lsb sichern
	
	ldr r0, =SPI2_READTEMP_LSB
	str r0, [r1]			// transfer starten
	
waitTMP_2:
	ldr r0, [r3]
	cmp r4, r0	
	bne waitTMP_2
	str r4, [r3]			// clear TCF
	
	ldr r0, [r2]	
	and r0, r0, #MASK_LSB
	orr r0, r0, r5, lsl #8	// temperatur -> r0
	
	ldr r1, =SPI2_HALT
	str r4, [r1]			// transfers beenden
	
	pop {r4-r5, pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	

	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* PIT1 mit neuem Wert beschreiben (abhängig von Auflösung): 
* Inputs:	keine
* Outputs:	keine
*/	
.thumb_func
reload_pit1:	
	// disable PIT1 - es soll direkt der neue Wert übernommen werden
	ldr r2, =PIT_TCTRL1
	mov r1, #0
	str r1, [r2]
	
	// load value neu setzen
	ldr r0, =resolution
	ldr r0, [r0]
	ldr r1, =PIT_LOAD_8BIT		// Konstante für 8-Bit Auflösung
	lsl r0, r1, r0				// nach links schieben
	ldr r1, =PIT_LDVAL1
	str r0, [r1]				// neuen Wert speichern	
		
	// PIT1 enable, Interrupts enable
	mov r1, #3
	str r1, [r2]
	
	bx LR	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	
	

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++	
* ISR für PIT1: 
* Interrupt Service Routine für den PIT1
*
*/	
.thumb_func
isr_pit1:
	// init register
	mov r1, #1

		// löschen des interrupt flags
	ldr r0, =PIT_TFLG1
	str r1, [r0] 	
	    // Flag pit1 setzen
	ldr r0, =flag_pit1
	str r1, [r0]	
		
	    // return from interrupt
	bx LR												

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/	

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogram für Taster SW2(grün) - ISR portE
*
*/	
.thumb_func
isr_port_e:				
	// löschen des interrupt flags
	mov r1, #1
	ldr r0, =SW2_GR_ISF
	str r1, [r0] 
	
	// Flag Bit für fallende Flanke von sw2 setzen
	ldr r0, =ft_sw2_gr
	str r1, [r0]	
	
	bx LR					
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogram für Taster SW1(schwarz) - ISR portA
*
*/	
.thumb_func
isr_port_a:		
	// löschen des interrupt flags
	mov r1, #1
	ldr r0, =SW1_BK_ISF
	str r1, [r0] 
	
	// Flag Bit für fallende Flanke von sw1 setzen
	ldr r0, =ft_sw1_bk
	str r1, [r0]	
	
	bx LR									
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Ausgabe eines Dezimalwertes von 0000-9999: 
* - r0 -> Übergabe des Dezimalwertes
*
*/	
.thumb_func
uart_putDecimal:
	push {r4,LR}

	// init register
		// r4 -> Übergabe des Dezimalwertes
	mov r1, #100
	udiv r2, r0, r1			// Dezimalwert / 100
	mls r4, r2, r1, r0		// Dezimalwert r0 - Quotient r2 * 100 r1
	
	mov r0, r2
	cmp r0, #0x9			// kleiner/gleich 9?
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1					// passendes Unterprogramm aufrufen
	
	mov r0, r4
	cmp r0, #0x9
	ite ls
	ldrls r1, =uart_putByte
	ldrhi r1, =uart_putByteBase10
	blx r1
	
	pop {r4,PC}			
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/
	

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_pit1:			.word 0x0	// flag welches von der isr des pit1 gesetzt wird
resolution:			.word 0x4	// initial mit 12-Bit Auflösung
aDigits:			.word 0, 625, 1250, 1875, 2500, 3125, 3750, 4375, 5000, 5625, 6250, 6875, 7500, 8125, 8750, 9375
ft_sw2_gr:			.word 0x0	// falling trigger sw2
ft_sw1_bk:			.word 0x0	// falling trigger sw1
flag_skip_read:		.word 0x0	// skip read temperatur flag
str_resolution:		.asciz "Aufloesung veraendert (0=8Bit; 1=9Bit; 2=10Bit; 3=11Bit; 4=12Bit): " 
str_temp:			.asciz "gC"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten Interrupt
.equ SCR_VTOR,				0xE000ED08		// Interrupt Vektortabelle

// IVT-Offsets
.equ IVT_TAI,				0x148			// Alarm INT
.equ IVT_TSI,				0x14C			// Seconds INT


// Konstanten für NVIC-Register
.equ NVIC_ICPR2,			0xE000E288		// Interrupt Clear-Pending Register
.equ NVIC_RTC_IRQ_MASK,		0xC				// IRQ 66, 67 (Interrupts für RTC)
.equ NVIC_ISER2,			0xE000E108		// Interrupt Set-Enable Register

// Register RTC
.equ SIM_RTC,				0x429007F4
.equ RTC_TSR,				0x4003D000
.equ RTC_TAR,				0x4003D008
.equ RTC_CR,				0x4003D010
.equ RTC_SR_TCE,			0x427A0290
.equ RTC_SR_TAF,			0x427A0288
.equ RTC_IER,				0x4003D01C

// Konstanten für RTC
.equ RTC_IER_INIT,			0x14			// TSIE = 1, TAIE = 1
.equ RTC_CR_INIT,			0x100			// Oscillator activate
.equ RTC_24H,				86399
.equ RTC_1H,				3599
.equ RTC_PRESET_24H,		86395
.equ RTC_PRESET_1H,			3595
.equ CT_ONESEC,				0x7F2815

// Konstanten CHAR
.equ CHAR_COLON,			':'
.equ CHAR_NL,				'\n'
.equ CHAR_d,				'd'
.equ CHAR_h,				'h'
.equ CHAR_r,				'r'
.equ CHAR_s,				's'
.equ CHAR_p,				'p'

// Konstanten Time
.equ HOUR,					3600
.equ MINUTE,				60


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	// für Initialisierungen genutzte Werte
	mov r10, #0
	mov r11, #1
	
	// clocks für Module aktivieren
	ldr r0, =SIM_RTC
	str r11, [r0]	
	
	// Oscillator für RTC aktivieren
	ldr r0, =RTC_CR
	mov r1, #RTC_CR_INIT
	str r1, [r0]
	bl delay_1s				// 1s warten bis startup Time vom Oszillator definitiv vorüber ist - leider wurde nichts im Manual oder Internet gefunden, wie die Zeit abgeschätzt werden kann oder wie hoch diese überhaupt ist...
	
	// IVT - Adressen der ISR's reinschreiben
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_rtc_tsi
	str r0, [r1, #IVT_TSI]
	ldr r0, =isr_rtc_tai
	str r0, [r1, #IVT_TAI]	
	
	// hängende Interrupts löschen
	ldr r0, =NVIC_ICPR2	
	mov r1, #NVIC_RTC_IRQ_MASK
	str r1, [r0]
		
	// RTC konfigurieren
	str r1, [r0]
	ldr r0, =RTC_IER
	mov r1, #RTC_IER_INIT		// Interrupts für Seconds und Time Alarm aktivieren
	str r1, [r0]
	
	bl reset_rtc	
	ldr r0, =str_init_rtc
	bl uart_putString
	
	// Interrupts aktivieren
	ldr r0, =NVIC_ISER2
	ldr r1, =NVIC_RTC_IRQ_MASK
	str r1, [r0]	
	
	// oft genutzte Register in mainLoop
	ldr r5, =flag_OneSec
	ldr r6, =flag_TimeAlarm
	ldr r7, =mode
	ldr r8, =RTC_TSR
	ldr r9, =RTC_TAR
	ldr r12, =flag_startStop
	
	
mainLoop:	
	// Eingabe verarbeiten
	bl uart_charPresent
	cmp r0, r10
	bne inputChar	

	ldr r0, [r12]
	cmp r11, r0
	beq end

	// Sekunde
	ldr r0, [r5]
	cmp r11, r0
	beq ausgabeT
	
	// Alarm
	ldr r0, [r6]
	cmp r11, r0
	beq timeAlarm
	b end
	
	
inputChar:		
	bl uart_getChar
	cmp r0, #CHAR_d		// 'd'
	beq inDay
	
	cmp r0, #CHAR_h		// 'h'
	beq inHour
	
	cmp r0, #CHAR_r		// 'r'
	beq inReset
	
	cmp r0, #CHAR_s		// 's'
	beq inStartStop
	
	cmp r0, #CHAR_p		// 'p'
	beq inPreset

	b end

timeAlarm:
	str r10, [r6]
	ldr r0, =str_End
	bl uart_putString
	b end
	
ausgabeT:
	str r10, [r5]
	ldr r0, [r8]		// zeit in sekunden
	ldr r1, [r7]		// mode
	bl ausgabeTime
	b end

// input 'd'	
inDay:	
	str r10, [r7]
	bl reset_rtc
	ldr r0, =str_24h_mode
	bl uart_putString	
	b end
	
// input 'h'
inHour:
	str r11, [r7]
	bl reset_rtc
	ldr r0, =str_1h_mode
	bl uart_putString	
	b end
	
// input 'r'
inReset:
	bl reset_rtc
	ldr r0, =str_reset_rtc
	bl uart_putString
	b end
	
// input 's'
inStartStop:
	ldr r0, [r12]
	eors r0, r0, #1		// toggeln
	str r0, [r12]
	ite ne
	ldrne r0, =str_Display_off
	ldreq r0, =str_Display_on
	bl uart_putString	
	b end
	
// input 'p'
inPreset:
	ldr r1, =RTC_SR_TCE			// disable rtc
	str r10, [r1]
	ldr r0, [r7]
	cmp r10, r0
	ite	eq
	ldreq r0, =RTC_PRESET_24H
	ldrne r0, =RTC_PRESET_1H	
	ldr r2, =RTC_TSR			// Timer setzen
	str r0, [r2]	
	str r11, [r1]				// enable rtc
	ldr r0, =str_preset
	bl uart_putString	
	b end


end:
	b mainLoop


/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Reset RTC
*
*/	
.thumb_func
reset_rtc:		

	push {lr}

	mov r0, #0
	ldr r1, =RTC_SR_TCE			// disable rtc
	str r0, [r1]
	ldr r2, =RTC_TSR			// Timer zurücksetzen
	str r0, [r2]	
	
	ldr r0, =mode
	ldr r0, [r0]
	cmp r0, #0
	ite eq
	ldreq r0, =RTC_24H
	ldrne r0, =RTC_1H
	ldr r2, =RTC_TAR			// Alarm Register zurücksetzen
	str r0, [r2]
	
	mov r0, #1
	str r0, [r1]				// enable rtc
	
	
	pop {pc}								
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR Real Time Clock - Time Alarm Interrupt
*
*/	
.thumb_func
isr_rtc_tai:		
	
	// Flag Bit für Alarm setzen
	ldr r0, =flag_TimeAlarm
	mov r1, #1
	str r1, [r0]	
	
	// Zurücksetzen des Alarm registers, muss durchgeführt werden da sonst HW-Fault
	ldr r0, =RTC_TAR
	mov r1, #0
	str r1, [r0]
	
	bx LR									
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR Real Time Clock - Time Seconds Interrupt
*
*/	
.thumb_func
isr_rtc_tsi:		
	
	// Flag Bit für 1 Sekunde setzen
	ldr r0, =flag_OneSec
	mov r1, #1
	str r1, [r0]	
	
	bx LR									
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Ausgabe der Zeit
* Input: r0 (verstrichene Zeit in Sekunden); r1 (mode)
* Output: -
*/	
.thumb_func
ausgabeTime:		
	
	push {r4-r6, lr}
	
	mov r2, #HOUR
	mov r3, #MINUTE

	// berechnung der Stunden
	udiv r6, r0, r2		// stunden in r6
	mov r4, r0			
	
	// Berechnung der Minuten
	mul r4, r6, r2
	sub r4, r0, r4
	udiv r5, r4, r3		// minuten in r5
	
	// Berechnung der Sekunden
	mul r0, r5, r3
	sub r4, r4, r0		// sekunden in r4

	mov r0, #1
	cmp r1, r0
	beq ausgabe1h

ausgabe24h:		// ausgabe in hh:mm:ss Format
	mov r0, r6
	bl uart_putByteBase10
	mov r0, #CHAR_COLON
	bl uart_putChar

ausgabe1h:		// ausgabe in mm:ss Format
	mov r0, r5
	bl uart_putByteBase10
	mov r0, #CHAR_COLON
	bl uart_putChar
	mov r0, r4
	bl uart_putByteBase10
	mov r0, #CHAR_NL
	bl uart_putChar
	
	pop {r4-r6, pc}								
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogramm (delay): 
* Programmschleife die eine Verzögerung von etwa einer Sekunde generiert
*
*/	
.thumb_func
delay_1s:	
	ldr r0, =CT_ONESEC
	
loop_delay1s:
	subs r0, r0, #1
	bne loop_delay1s
	
	bx lr
	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++


/*** Datenbereich (ab 0x20000000) ***/
.data
flag_OneSec:	.word	0x0
flag_TimeAlarm:	.word	0x0
mode:			.word	0x0			// 0 = 24h-Mode; 1 = 1h-Mode
flag_startStop:	.word	0x0			// 0 = start; 1 = stop
str_init_rtc:	.asciz "Init RTC durchgefuehrt\n"
str_reset_rtc: 	.asciz "Uhr zurueckgesetzt\n"
str_24h_mode:	.asciz "24-Stunden-Modus\n"
str_1h_mode:	.asciz "1-Stunden-Modus\n"
str_Display_on:	.asciz "Anzeige an\n"
str_Display_off: .asciz "Anzeige aus\n"
str_preset:		.asciz "Uhr vorgestellt\n"
str_End:		.asciz "Endzeitpunkt erreicht\n"


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten Interrupt
.equ SCR_VTOR,				0xE000ED08		// Interrupt Vektortabelle

// IVT-Offsets
.equ IVT_PIT1,				0x154
.equ IVT_TSI,				0x14C			// Seconds INT

// Konstanten für NVIC-Register
.equ NVIC_ICPR2,			0xE000E288		// Interrupt Clear-Pending Register
.equ NVIC_ISER2,			0xE000E108		// Interrupt Set-Enable Register
.equ NVIC_IRQ_MASK,			0x28			// IRQ 67 (Interrupts für RTC), IRQ 69 PIT1

// Konstanten für PIT1-Register
.equ SIM_PIT,				0x429007DC		// Bit-Band-Alias Adresse für Clock PIT im SIM - System Integration Module - SIM_SCGC6 4004_803Ch
.equ PIT_MCR,				0x40037000		// Adresse PIT Module Control Register
.equ PIT_LDVAL1,			0x40037110		// Adresse Timer Load Value Register
.equ PIT_TCTRL1,			0x40037118		// Adresse zum Timer Control Register
.equ PIT_TCTRL1_TEN,		0x426E2300		// Alias-Adresse Enable PIT1 Timer	
.equ PIT_TFLG1,				0x4003711C		// Adresse zum Timer Flag Register Timer1
.equ PIT_LDVAL1_100ms,		2499999			// Load Value für 100ms
.equ PIT_LDVAL1_200ms,		4999999			// Load Value für 200ms

// Konstanten für GPIO Register
.equ SIM_PORTA,				0x42900724		// Alias Adresse für SIM PORTA (Freischaltung Clock)
.equ PDDR_LED_BLUE,			0x43FE02A8
.equ PDDR_PTA6,				0x43FE0298
.equ PORTA_PCR10,			0x40049028
.equ PORTA_PCR6,			0x40049018
.equ PDOR_LED_BLUE,			0x43FE0028
.equ PDOR_PTA6,				0x43FE0018
.equ INIT_GPIO_OUT,			0x100			// Initialisierung Ausgänge -> MUX = GPIO

// Register RTC
.equ SIM_RTC,				0x429007F4
.equ RTC_TSR,				0x4003D000
.equ RTC_CR,				0x4003D010
.equ RTC_SR_TCE,			0x427A0290
.equ RTC_IER,				0x4003D01C

// Konstanten für RTC
.equ RTC_IER_INIT,			0x14			// TSIE = 1, TAIE = 1
.equ RTC_CR_INIT,			0x100			// Oscillator activate
.equ CT_ONESEC,				0x7F2815

// Konstanten CHAR
.equ CHAR_COLON,			':'
.equ CHAR_NL,				'\n'
.equ CHAR_PT,				'.'
.equ CHAR_SPACE,			' '
.equ CHAR_COMMA,			','
.equ CHAR_t,				't'
.equ CHAR_d,				'd'	

// Zeiger Offset auf dateTime
.equ DAY,			0
.equ MONTH,			4
.equ YEAR,			8
.equ HOUR,			12
.equ MINUTE,		16
.equ WT,			20

// Konstanten Bit-Stream DCF77-Signal
.equ STREAM_BEGIN,	0x120000
.equ MASK_BYTE,		0xFF

// Maximalwerte für Uhrzeit und Datum
.equ MAX_MINUTE, 	59
.equ MAX_HOUR,		23
.equ MAX_DAY,		30
.equ MAX_MONTH,		12
.equ MAX_YEAR,		99
.equ MAX_WT,		7

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init	
	
	// für Initialisierungen genutzte Werte
	mov r10, #0
	mov r11, #1
	
	// clocks für Module aktivieren
	ldr r0, =SIM_RTC
	str r11, [r0]	
	ldr r0, =SIM_PORTA
	str r11, [r0]	
	ldr r0, =SIM_PIT
	str r11, [r0]
	
	// Oscillator für RTC aktivieren
	ldr r0, =RTC_CR
	mov r1, #RTC_CR_INIT
	str r1, [r0]
	bl delay_1s				// 1s warten bis startup Time vom Oszillator definitiv vorüber ist - leider wurde nichts im Manual oder Internet gefunden, wie die Zeit abgeschätzt werden kann oder wie hoch diese überhaupt ist...
	
	// IVT - Adressen der ISR's reinschreiben
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_rtc_tsi
	str r0, [r1, #IVT_TSI]
	ldr r0, =isr_pit1
	str r0, [r1, #IVT_PIT1]
	
	// hängende Interrupts löschen
	ldr r0, =NVIC_ICPR2	
	mov r1, #NVIC_IRQ_MASK
	str r1, [r0]
	
	// GPIO konfigurieren
	ldr r0, =PDDR_LED_BLUE
	str r11, [r0]
	ldr r0, =PDDR_PTA6
	str r11, [r0]
	ldr r0, =PORTA_PCR6
	mov r1, #INIT_GPIO_OUT
	str r1, [r0]
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	ldr r0, =PDOR_LED_BLUE		// LEDs ausschalten
	str r11, [r0]
	ldr r0, =PDOR_PTA6
	str r11, [r0]	
		
	// RTC konfigurieren
	ldr r0, =RTC_IER
	mov r1, #RTC_IER_INIT		// Interrupts für Seconds und Time Alarm aktivieren
	str r1, [r0]
	
	bl reset_rtc	
	ldr r0, =str_init_rtc
	bl uart_putString
	
	// PIT1 konfigurieren		
	ldr r0, =PIT_MCR		// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul),
	str r10, [r0]
	ldr r0, =PIT_TCTRL1
	mov r1, #2				// Interrupts enable, timer disabled
	str r1, [r0]
		
	// Interrupts aktivieren
	ldr r0, =NVIC_ISER2
	ldr r1, =NVIC_IRQ_MASK
	str r1, [r0]	
	
initDateTime:	
	bl get_time
	bl get_date	
	bl gen_dcf77_stream
	
	// oft genutzte Register in mainLoop
	ldr r4, =date_time
	ldr r5, =flag_OneSec
	mov r6, #0				// Sekundenregister (gibt die aktuelle Sekunde wieder 0..59)
	ldr r7, =dcf77_stream
	ldr r8, [r7]			// stream register initialisieren		
mainLoop:
	// Eingabe verarbeiten
	bl uart_charPresent
	cmp r0, r10
	bne inputChar	

	// Sekunde
	ldr r0, [r5]
	cmp r11, r0
	beq next_Bit
	
	b mainLoop
	
inputChar:		
	bl uart_getChar
	cmp r0, #CHAR_t		// 't'
	beq inTime
	
	cmp r0, #CHAR_d		// 'd'
	beq inDate

	b mainLoop	
	
inTime:
	mov r0, #CHAR_NL
	bl uart_putChar
	bl get_time
	b init_newStream
	
inDate:
	mov r0, #CHAR_NL
	bl uart_putChar
	bl get_date
	b init_newStream
	
next_Bit:
	str r10, [r5]			// Sekunden Flag zurücksetzen
	cmp r6, #0
	beq AusgabeDateTime		// neue Minute hat begonnen -> Ausgabe des Datum und der Uhrzeit
	cmp r6, #32
	beq init_secondStream
	cmp r6, #59
	beq inc_DateTime		// neuen Stream starten und Bit 59 nicht senden (Pause in Bit 59)	
	b put_Bit
	
AusgabeDateTime:
	bl put_DateTime
	b put_Bit	
	
init_secondStream:
	ldr r8, [r7, #4]
	
put_Bit:	
	and r0, r8, #1
	bl put_dcf77			// Bit senden
	and r0, r8, #1
	bl uart_putByteBase10	
	lsr r8, r8, #1			// nächstes Bit vorbereiten
	add r6, r6, #1			// Sekunde inkrementieren
	b mainLoop
	
inc_DateTime:
	// Werte für Datum und Zeit laden	 
	ldr r0, [r4, #MINUTE]
	ldr r1, [r4, #HOUR]
	add r0, #1				// Minute hochzählen
	cmp r0, #MAX_MINUTE		// höchste Zahl überschritten?
	itt hi
	movhi r0, #0			// bei 0 wieder beginnen zu zählen
	addhi r1, #1			// Stunde hochzählen
	str r0, [r4, #MINUTE]			
	ldr r0, [r4, #DAY]
	ldr r2, [r4, #WT]
	cmp r1, #MAX_HOUR		// Stunden voll?
	ittt hi
	movhi r1, #0			// bei 0 wieder beginnen
	addhi r0, #1			// Tag hochzählen
	addhi r2, #1			// Wochentag hochzählen
	str r1, [r4, #HOUR]	
	cmp r2, #MAX_WT			// maximale Wochentage erreicht?
	it hi
	movhi r2, #1			// bei Mo. anfangen
	str r2, [r4, #WT]	
	ldr r1, [r4, #MONTH]	
	cmp r0, #MAX_DAY		// maximale Tage im Monat erreicht?
	itt hi					
	movhi r0, #1			// wieder beim ersten des Monats anfangen
	addhi r1, #1			// Monate hochzählen
	str r0, [r4, #DAY]	
	ldr r0, [r4, #YEAR]
	cmp r1, #MAX_MONTH		// ein Jahr durchlaufen?
	itt hi					
	movhi r1, #1			// wieder bei Januar anfangen		
	addhi r0, #1			// Jahr hochzählen
	str r1, [r4, #MONTH]	
	cmp r0, #MAX_YEAR		// Jahrhundert begrenzen
	it hi					
	movhi r0, #0			// wieder im Jahrhundert anfangen
	str r0, [r4, #YEAR]	
	mov r0, #CHAR_NL
	bl uart_putChar	
	
init_newStream:
	bl gen_dcf77_stream
	mov r6, #0				// Sekunde zurücksetzen
	ldr r8, [r7]			// wieder von vorne anfangen, den stream zu senden

	b mainLoop


/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Reset RTC
*
*/	
.thumb_func
reset_rtc:		
	push {lr}

	mov r0, #0
	ldr r1, =RTC_SR_TCE			// disable rtc
	str r0, [r1]
	ldr r2, =RTC_TSR			// Timer zurücksetzen
	str r0, [r2]		
	mov r0, #1
	str r0, [r1]				// enable rtc	
	
	pop {pc}								
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR Real Time Clock - Time Seconds Interrupt
*
*/	
.thumb_func
isr_rtc_tsi:		
	// Flag Bit für 1 Sekunde setzen
	ldr r0, =flag_OneSec
	mov r1, #1
	str r1, [r0]		
	bx LR									
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* Unterprogramm (delay): 
* Programmschleife die eine Verzögerung von etwa einer Sekunde generiert
*/	
.thumb_func
delay_1s:	
	ldr r0, =CT_ONESEC
	
loop_delay1s:
	subs r0, r0, #1
	bne loop_delay1s
	
	bx lr	
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP generate dcf77 impulse:
* Input: r0 = Codierung 0 - 100ms Impuls, 1 - 200ms Impuls 
*/	
.thumb_func
put_dcf77:
	// load value schreiben
	cmp r0, #0
	ite eq
	ldreq r1, =PIT_LDVAL1_100ms
	ldrne r1, =PIT_LDVAL1_200ms
	ldr r0, =PIT_LDVAL1
	str r1, [r0]	
	// enable Timer
	mov r1, #1
	ldr r0, =PIT_TCTRL1_TEN
	str r1, [r0]	
	mov r1 , #0
	ldr r0, =PDOR_LED_BLUE		// LEDs einschalten
	str r1, [r0]
	ldr r0, =PDOR_PTA6
	str r1, [r0]		
	bx LR						
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Generierung des DCF77 Streams zur Ausgabe
*/	
.thumb_func
gen_dcf77_stream:			
	push {r4-r7, lr}

	// buffer leeren
	mov r0, #0
	ldr r5, =dcf77_stream
	str r0, [r5]
	str r0, [r5, #4]
	
	ldr r4, =date_time
	// Bit 0 - 20 (Start der Minute, Wetter, Betriebsinformation, Sommerzeit, keine Schaltsekunde, Start der Zeitinformation
	ldr r6, =STREAM_BEGIN	
	// Bit 21 - 28 (Minute + Parity)
	ldr r0, [r4, #MINUTE]
	bl calc_time_code
	mov r7, r0
	bl gen_parity
	orr r0, r7, r0, lsl #7	// parity Bit anhängen
	orr r6, r6, r0, lsl #21	// Minute an Bit-Stream hängen	
	// Bit 31 - 35 (Stunde + Parity)
	ldr r0, [r4, #HOUR]
	bl calc_time_code
	mov r7, r0
	bl gen_parity
	orr r1, r7, r0, lsl #6	// parity Bit anhängen
	and r0, r1, #7			// letzte 3 Bit filtern	
	orr r0, r6, r0, lsl #29	// erste 3 Bit der Stunde an Bit-Stream hängen
	str r0, [r5]			// stream_buffer erster Eintrag befüllen
	mov r6, #0				// nächstes Word bearbeiten
	orr r6, r6, r1, lsr #3	// restliche Bits von Stunde in Stream sichern	
	// Bit 36 - 41 (Kalendertag)
	ldr r0, [r4, #DAY]
	bl calc_time_code
	mov r7, r0
	// Bit 42 - 44 (Wochentag)
	ldr r0, [r4, #WT]
	bl calc_time_code
	orr r7, r7, r0, lsl #6
	// Bit 45 - 49 (Kalendermonat)
	ldr r0, [r4, #MONTH]
	bl calc_time_code
	orr r7, r7, r0, lsl #9
	// Bit 50 - 57 (Kalenderjahr)
	ldr r0, [r4, #YEAR]
	bl calc_time_code
	orr r7, r7, r0, lsl #14
	mov r0, r7
	bl gen_parity
	orr r7, r7, r0, lsl #22		// parity Bit anhängen
	orr r0, r6, r7, lsl #4		// mit den Bits von der Stunde verbinden
	str r0, [r5, #4]			// in Bit-Stream Buffer zweiter Array Eintrag speichern	

	pop {r4-r7, pc}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Berechnung des Codes für Zeit und Datum
* Input: r0 = Zahl die in Code umgewandelt werden soll
* Output: r0 = codierte Zahl
*/	
.thumb_func
calc_time_code:		
	mov r3, r0
	mov r0, #0
	
	mov r1, #80
	udiv r2, r3, r1		// Zahl / 80
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2, lsl #7	
	mov r1, #40
	udiv r2, r3, r1		// Zahl / 40
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2, lsl #6	
	mov r1, #20
	udiv r2, r3, r1		// Zahl / 20
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2, lsl #5	
	mov r1, #10
	udiv r2, r3, r1		// Zahl / 10
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2, lsl #4	
	mov r1, #8
	udiv r2, r3, r1		// Zahl / 8
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2, lsl #3	
	mov r1, #4
	udiv r2, r3, r1		// Zahl / 4
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2, lsl #2	
	mov r1, #2
	udiv r2, r3, r1		// Zahl / 2
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2, lsl #1	
	mov r1, #1
	udiv r2, r3, r1		// Zahl / 1
	mls r3, r2, r1, r3	// r3 = r3 - r2*r1
	orr r0, r0, r2	
	and r0, r0, #MASK_BYTE	
	bx lr
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Generierung des Paritätbits
* Input: r0 = Bit-Stream über die die Parität gebildet werden soll (es wird das Parity immer über die 32 Bit berechnet)
  Output: r0 = Parität-Bit
*/	
.thumb_func
gen_parity:		
	// Initialisierungen
	mov r2, r0
	mov r0, #0	
	mov r1, #32
loopParity:
	and r3, r2, #1
	eor r0, r0, r3
	lsr r2, r2, #1
	subs r1, r1, #1
	bne loopParity
	bx lr
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/*

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR für PIT1: 
* Interrupt Service Routine für den PIT1
*/	
.thumb_func
isr_pit1:
	// löschen des interrupt flags
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0] 
	
	// Ausgänge zurücksetzen
	ldr r0, =PDOR_LED_BLUE
	str r1, [r0]
	ldr r0, =PDOR_PTA6
	str r1, [r0]
	
	// disable Timer
	mov r1, #0
	ldr r0, =PIT_TCTRL1_TEN
	str r1, [r0]
	
	bx LR						
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++


/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP für die Eingabe der Zeit: 
*/	
.thumb_func
get_time:
	push {r4, lr}
	
	ldr r4, =date_time	
	// Stunde eingeben
	ldr r0, =str_InHour
	bl uart_putString
	bl uart_getByteBase10
	str r0, [r4, #HOUR]	
	bl put_leadingZero
	mov r0, #CHAR_NL
	bl uart_putChar	
	// Minuten eingeben
	ldr r0, =str_InMinute
	bl uart_putString
	bl uart_getByteBase10
	str r0, [r4, #MINUTE]
	bl put_leadingZero
	mov r0, #CHAR_NL
	bl uart_putChar	
	
	pop {r4, pc}						
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP für die Eingabe des Datums: 
*/	
.thumb_func
get_date:
	push {r4, lr}
	
	ldr r4, =date_time	
	// Tag eingeben
	ldr r0, =str_InDay
	bl uart_putString
	bl uart_getByteBase10
	str r0, [r4, #DAY]
	bl put_leadingZero
	mov r0, #CHAR_NL
	bl uart_putChar		
	// Monat eingeben
	ldr r0, =str_InMonth
	bl uart_putString
	bl uart_getByteBase10
	str r0, [r4, #MONTH]
	bl put_leadingZero
	mov r0, #CHAR_NL
	bl uart_putChar		
	// Jahr eingeben
	ldr r0, =str_InYear
	bl uart_putString
	bl uart_getByteBase10
	str r0, [r4, #YEAR]
	bl put_leadingZero
	mov r0, #CHAR_NL
	bl uart_putChar	
	
	pop {r4, pc}						
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Ausgabe des aktuellen Datums und der Uhrzeit
* Ausgabe der aktuellen Uhrzeit + Datum in der Form (dd.mm.jjjj  hh:mm)
*/	
.thumb_func
put_DateTime:
	push {r4,LR}
	
	ldr r4, =date_time	
	// Wochentag ausgeben
	ldr r0, [r4, #WT]
	bl put_Weekday
	mov r0, #CHAR_COMMA
	bl uart_putChar
	mov r0, #CHAR_SPACE
	bl uart_putChar
	// Tage ausgeben
	ldr r0, [r4, #DAY]
	bl put_leadingZero
	mov r0, #CHAR_PT	
	bl uart_putChar
	// Monat ausgeben
	ldr r0, [r4, #MONTH]
	bl put_leadingZero
	mov r0, #CHAR_PT	
	bl uart_putChar	
	// Jahr ausgeben
	ldr r0, [r4, #YEAR]
	bl put_leadingZero
	mov r0, #CHAR_SPACE
	bl uart_putChar	
	// Stunde ausgeben
	ldr r0, [r4, #HOUR]
	bl put_leadingZero
	mov r0, #CHAR_COLON
	bl uart_putChar	
	// Minute ausgeben
	ldr r0, [r4, #MINUTE]
	bl put_leadingZero
	mov r0, #CHAR_SPACE
	bl uart_putChar
	ldr r0, =str_Clock	
	bl uart_putString
	mov r0, #CHAR_NL
	bl uart_putChar

	pop {r4,PC}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Ausgabe der führenden 0 bei Zahlen die kleiner als 10 sind
* Input: r0 - Zahl
*/	
.thumb_func
put_leadingZero:
	push {LR}	
	cmp r0, #10	
	ite hs
	ldrhs r1, =uart_putByteBase10	// keine führende Null ausgeben
	ldrlo r1, =uart_putByte			// mit "
	blx r1
	pop {PC}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* UP: Ausgabe des aktuellen Wochentages
* Input: r0 - Wochentag als Zahl (Mo. = 1 ... So. = 7)
*/	
.thumb_func
put_Weekday:
	push {LR}
	mov r1, #4	
	sub r0, r0, #1		// Um 1 dekrementieren, um den Zeiger korrekt zu berechnen. Weil der Montag bei 1 anfängt.
	mul r0, r0, r1		// Zeiger-Offset auf Array Weekday berechnen
	ldr r1, =str_Weekday
	add r0, r1, r0
	bl uart_putString
	pop {PC}
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_OneSec:			.word	0x0
dcf77_stream:			.word	0x0, 0x0		// aktueller stream der ausgegeben wird
						//		Tag		Monat	Jahr	Stunde	Minute  Wochentag
date_time:				.word	0x0, 	0x0, 	0x0, 	0x0, 	0x0, 	0x6
str_init_rtc:	.asciz "Init RTC durchgefuehrt\n"
str_InHour:		.asciz "Stunde eingeben (hh): "
str_InMinute:	.asciz "Minuten eingeben (mm): "
str_InDay:		.asciz "Tag eingeben (dd): "
str_InMonth:	.asciz "Monat eingeben (mm): "
str_InYear:		.asciz "Jahr eingeben (jj): "
str_Weekday:	.asciz "Mo.", "Di.", "Mi.", "Do.", "Fr.", "Sa.", "So."
str_Clock:		.asciz "Uhr"


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten Interrupt
.equ SCR_VTOR,				0xE000ED08		// Interrupt Vektortabelle

// IVT-Offsets
.equ IVT_FTM0,				0x138

// Konstanten für NVIC-Register
.equ NVIC_ICPR1,			0xE000E284		// Interrupt Clear-Pending Register
.equ NVIC_ISER1,			0xE000E104		// Interrupt Set-Enable Register
.equ NVIC_IRQ_MASK,			0x40000000		// IRQ 62 FTM0

// Konstanten für FTM0-Register
.equ SIM_FTM0,				0x429007E0		// Bit-Band-Alias Adresse für Clock FTM0 im SIM
.equ FTM0_SC,				0x40038000
.equ FTM0_SC_TOF,			0x4270001C		// Alias-Adresse zu TOF Flag (Timer overflow flag)
.equ FTM0_SC_INIT,			0x48			// TOIE, system clock
.equ FTM0_CNT,				0x40038004
.equ FTM0_MOD,				0x40038008
.equ FTM0_MOD_INIT,			24999			// 1kHz PWM
.equ FTM0_CNTIN,			0x4003804C
.equ FTM0_MODE,				0x40038054

// Channel 3
.equ FTM0_C3SC,				0x40038024
.equ FTM0_C3SC_INIT,		0x68
.equ FTM0_C3SC_NEG,			0x6C
.equ FTM0_C3SC_POS,			0x68
.equ FTM0_CH3F,				0x4270049C		// channel 3 flag (interrupt)
.equ FTM0_C3V,				0x40038028
.equ FTM0_C3V_5P,			1250
.equ FTM0_C3V_10P,			2500


// Konstanten für GPIO Register
.equ SIM_PORTA,				0x42900724		// Alias Adresse für SIM PORTA (Freischaltung Clock)
.equ PDDR_PTA6,				0x43FE0298
.equ PORTA_PCR6,			0x40049018
.equ PDOR_PTA6,				0x43FE0018
.equ INIT_ALT3,				0x300			// Initialisierung Ausgang -> MUX = ALT3 (FTM0_CH3)

// Konstanten CHAR
.equ CHAR_0,				'0'
.equ CHAR_9,				'9'
.equ CHAR_PLUS,				'+'
.equ CHAR_MINUS,			'-'
.equ CHAR_PROMPT,			'>'
.equ CHAR_NL,				'\n'

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// für Initialisierungen genutzte Werte
	mov r10, #0
	mov r11, #1
	mov r12, #2
	
	// clocks für Module aktivieren
	ldr r0, =SIM_FTM0
	str r11, [r0]	
	ldr r0, =SIM_PORTA
	str r11, [r0]	
	
	// IVT - Adressen der ISR's reinschreiben
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_ftm0
	str r0, [r1, #IVT_FTM0]
	
	// hängende Interrupts löschen
	ldr r0, =NVIC_ICPR1	
	mov r1, #NVIC_IRQ_MASK
	str r1, [r0]
	
	// GPIO konfigurieren
	ldr r0, =PDDR_PTA6
	str r11, [r0]
	ldr r0, =PORTA_PCR6
	mov r1, #INIT_ALT3
	str r1, [r0]
	
	// FTM0 konfigurieren
	ldr r0, =FTM0_CNT		// counter mit 0 initialisieren
	str r10, [r0]
	ldr r0, =FTM0_C3SC
	mov r1, #FTM0_C3SC_INIT
	str r1, [r0]
	ldr r0, =FTM0_C3V
	ldr r1, =FTM0_C3V_5P
	str r1, [r0]
	ldr r0, =FTM0_MOD
	ldr r1, =FTM0_MOD_INIT
	str r1, [r0]
	ldr r0, =FTM0_CNTIN
	str r10, [r0]
	ldr r0, =FTM0_MODE
	str r10, [r0]			// keine FTM spezifische Register aktivieren!
	
	ldr r0, =FTM0_SC
	mov r1, #FTM0_SC_INIT
	str r1, [r0]
		
	// Interrupts aktivieren
	ldr r0, =NVIC_ISER1
	ldr r1, =NVIC_IRQ_MASK
	str r1, [r0]	
	
	// Ausgabe prompt
	mov r0, #CHAR_PROMPT
	bl uart_putChar
	
	// oft genutzte Register in mainLoop
	ldr r4, =requestDuty
	ldr r5, =duty
	ldr r6, =polarity
	
mainLoop:
	// Eingabe verarbeiten
	bl uart_charPresent
	cmp r0, r10
	bne inputChar	
	b mainLoop
	
inputChar:		
	bl uart_getChar
	cmp r0, #CHAR_0
	blt notADigit 
	cmp r0, #CHAR_9
	bgt notADigit
	str r11, [r4]		// request duty cycle ändern
	sub r1, r0, #CHAR_0
	str r1, [r5]		// duty cycle speichern
	bl uart_putChar
	mov r0, #CHAR_NL
	bl uart_putChar
	ldr r0, =strDutyChange
	bl uart_putString
	mov r0, #CHAR_NL
	bl uart_putChar
	mov r0, #CHAR_PROMPT
	bl uart_putChar
	b mainLoop
	
notADigit:	
	cmp r0, #CHAR_PLUS	// '+'
	bne notAPlus
	str r12, [r6]
	bl uart_putChar
	mov r0, #CHAR_NL
	bl uart_putChar
	ldr r0, =str_PolPlus
	bl uart_putString
	mov r0, #CHAR_NL
	bl uart_putChar
	mov r0, #CHAR_PROMPT
	bl uart_putChar
	b mainLoop
	
notAPlus:
	cmp r0, #CHAR_MINUS	// '-'
	bne mainLoop
	str r11, [r6]
	bl uart_putChar
	mov r0, #CHAR_NL
	bl uart_putChar
	ldr r0, =str_PolMinus
	bl uart_putString
	mov r0, #CHAR_NL
	bl uart_putChar
	mov r0, #CHAR_PROMPT
	bl uart_putChar


	b mainLoop

/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
* ISR für FTM0: 
* Interrupt Service Routine FlexTimer 0
*/	
.thumb_func
isr_ftm0:
	ldr r0, =FTM0_SC_TOF
	ldr r0, [r0]
	cmp r0, #1
	beq int_tof

	ldr r0, =FTM0_CH3F
	ldr r0, [r0]
	cmp r0, #1
	beq int_ch3
	
	b end_isr_ftm0

// Interrupt Timer Overflow
int_tof:	
	// löschen des flags	
	ldr r0, =FTM0_SC
	ldr r0, [r0]				// dummy read
	ldr r0, =FTM0_SC_TOF
	mov r1, #0
	str r1, [r0]				// TOF reset
	
	ldr r0, =polarity
	ldr r0, [r0]
	cmp r0, #0					// kein Polaritätswechsel
	beq end_isr_ftm0
	cmp r0, #1
	ite eq
	moveq r0, #FTM0_C3SC_NEG	// negative Polarität
	movne r0, #FTM0_C3SC_POS	// positive Polarität
	ldr r2, =FTM0_C3SC
	str r0, [r2]	
			
	ldr r0, =polarity		
	str r1, [r0]				// Polaritätswechsel zurücksetzen
	b end_isr_ftm0
	
	
// Interrupt Channel
int_ch3:	
	// löschen des flags	
	ldr r0, =FTM0_C3SC
	ldr r0, [r0]				// dummy read
	ldr r0, =FTM0_CH3F
	mov r1, #0
	str r1, [r0]				// CHF reset	
	
	ldr r0, =requestDuty
	ldr r0, [r0]
	cmp r0, #0
	beq end_isr_ftm0
	// duty cycle berechnen
	ldr r0, =duty
	ldr r0, [r0]
	ldr r1, =FTM0_C3V_10P
	mul r0, r0, r1
	add r0, r0, #FTM0_C3V_5P
	ldr r1, =FTM0_C3V
	str r0, [r1]
	
	ldr r0, =requestDuty
	mov r1, #0
	str r1, [r0]				// Duty request zurücksetzen	
	
end_isr_ftm0:	
	bx lr						
/*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++




/*** Datenbereich (ab 0x20000000) ***/
.data
requestDuty:		.word	0x0
duty:				.word	0x0		// duty cycle (10% Schritte), gültige Werte 0..9
polarity:			.word	0x0		// 0 = kein Polaritätswechsel, 1 = negative Polarität, 2 = positive Polarität
str_PolPlus:		.asciz	"Polaritaet auf (+) positiv gestellt"
str_PolMinus:		.asciz	"Polaritaet auf (-) negativ gestellt"
strDutyChange:		.asciz	"Duty Cycle geaendert"


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
 * Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
 * die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
 * dass die Register mit ihrem Reset-Wert vorbelegt sind.
 */


.equ NUMBER_OF_BYTES, 0x10

main:
	bl uart_init
	bl pit3_init

loop_main:
	ldr	r0, =str_begin1				// output input line
	bl	uart_putString
	mov r0, NUMBER_OF_BYTES
	bl	uart_putByteBase10
	ldr	r0, =str_begin2
	bl	uart_putString

pre_input:
	mov r4, NUMBER_OF_BYTES			// r4 holds number of remaining data inputs
	ldr r5, =ba_input				// r5 holds reference to input byte array

loop_input:
	ldr r0, =str_prompt				// output prompt
	bl	uart_putString

	bl	uart_getByte				// user input
	strb r0, [r5], #1

	bl	uart_putByte				// output of user input
	ldr r0, =str_cr
	bl	uart_putString

	subs r4, r4, #1					// decrement
bne	loop_input						// next data input

pre_calculation:
	mov r4, [NUMBER_OF_BYTES-1]		// r4 holds number of remaining comparison loops now
	ldrb r6, [r5, #-1]!				// r6 holds temporary maximum, initialized at last user input

	ldr r0, =str_start				// output search start
	bl uart_putString

// time measurement starts here
	bl pit3_getval					// timer decrements from 0xffffffff
	mov r7, r0						// r7 holds PIT3 start value

loop_calculation:
	ldrb r0, [r5, #-1]!				// -1 for decrement, ! for pre-indexing
	cmp r0, r6
	it hi
	movhi r6, r0

	subs r4, r4, #1					// decrement
bne	loop_calculation				// check max on next data input

post_calculation:
	bl	pit3_getval
// time measurement ends here
	mov r8, r0						// r8 holds PIT3 end value
	sub r9, r7, r8					// r9 holds duration of loop_calculation

	ldr r0, =b_max					// save maximum to memory
	strb r6, [r0]

output:
	mov r0, r7						// finalize output search start - placed here to avoid impact on time measurement
	bl uart_putInt32
	ldr r0, =str_cr
	bl	uart_putString

	ldr r0, =str_end				// output search end
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_cr
	bl	uart_putString
	
	ldr r0, =str_max				// output maximum
	bl uart_putString
	mov r0,r6
	bl uart_putByte
	ldr r0, =str_cr
	bl uart_putString

	ldr	r0, =str_time				// output duration
	bl uart_putString
	mov r0, r9
	bl uart_putInt16
	ldr r0, =str_cr
	bl uart_putString

end:	
	ldr	r0, =str_line				// output line between cycles
	bl uart_putString
b loop_main							// start next cycle

/*** Datenbereich (ab 0x20000000) ***/
.data
	str_cr:		.asciz "\n"
	str_prompt:	.asciz ">\0"
	str_begin1:	.asciz "Bitte \0"
	str_begin2:	.asciz " Bytes sukzessiv eingeben!\n"
	str_start:	.asciz "Durchsuchen gestartet @ \0"
	str_end:	.asciz "Durchsuchen beendet @ \0"
	str_max:	.asciz "Maximum: \0"
	str_time:	.asciz "Suchzeit in Takten (hex): \0"
	str_line:	.asciz "----------------------------------\n"

	b_max:		.byte 

	ba_input:	.rept NUMBER_OF_BYTES
				.byte 0x00
				.endr
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

.equ	ADDRESS0, 0x20000000
.equ	ADDRESS1, 0x20000010
.equ	BITBAND_BASEADDRESS1, 0x22000200	// = 0x20000000 + 0x10 x 32
.equ	BITBAND_BYTEFACTOR, 0x4
.equ	MASK_5BIT, 0b00011111

main:	
	bl uart_init

loop_main:

get_bit0:
	ldr r0, =str_input0			// output
	bl uart_putString
	
	bl uart_getByte
	mov r4, r0					// r4 holds 0-Bit

	mov r0, MASK_5BIT			// adjust r4 to 5 bits
	and r4, r4, r0
	mov r0, r4

	bl uart_putByte				// output 0-bit
	ldr r0, =str_cr
	bl uart_putString

get_bit1:
	ldr r0, =str_input1			// output
	bl uart_putString
	
	bl uart_getByte
	mov r5, r0					// r5 holds 1-Bit
	
	mov r0, MASK_5BIT			// adjust r5 to 5 bits
	and r5, r5, r0
	mov r0, r5

	bl uart_putByte				// output 1-bit
	ldr r0, =str_cr
	bl uart_putString

output_original:
	ldr r0, =ADDRESS0
	ldr r6, [r0]				// r6 holds value of address0
	ldr r0, =ADDRESS1
	ldr r7, [r0]				// r7 holds value of address1
	
	ldr r0, =ADDRESS0			// output original value address 0
	bl uart_putInt32
	ldr r0, =str_original
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

	ldr r0, =ADDRESS1			// output original value address 1
	bl uart_putInt32
	ldr r0, =str_original
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

without_bitbanding:
	mov r8, 0x1					// r8 holds 0x1 for mask generation
	
	lsl r0, r8, r4				// generate mask from 0-bit in r0
	mvn r0, r0					// bitwise not
	and r6, r6, r0				// in r0 all bits except the 0-bit are set to 1
	
	lsl r1, r8, r5				// generate mask from 1-bit in r1
	orr r6, r6, r1				// in r1 only the 1-bit is set to 1	

	ldr r0, =ADDRESS0			// write modification to memory
	str r6, [r0]
	
with_bitbanding:
	ldr r0, =BITBAND_BASEADDRESS1
	mov r1, BITBAND_BYTEFACTOR
	
	mul r2, r4, r1				// r3 = baseaddress + 0-bit * 4
	add r3, r0, r2
	mov r2, 0x0
	str r2, [r3]				// write 0 to bit band address of 0-bit

	mul r2, r5, r1				// r3 = baseaddress + 1-bit * 4
	add r3, r0, r2
	mov r2, 0x1
	str r2, [r3]				// write 1 to bit band address of 1-bit

output_modified:
	ldr r0, =ADDRESS0			// output modified value address 0
	ldr r6, [r0]
	bl uart_putInt32
	ldr r0, =str_modified
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

	ldr r0, =ADDRESS1			// output modified value address 1
	ldr r7, [r0]
	bl uart_putInt32
	ldr r0, =str_modified
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

end:
	ldr	r0, =str_line			// output line between cycles
	bl uart_putString
b loop_main

/*** Datenbereich (ab 0x20000000) ***/
.data
	str_var00:		.asciz "XXXX\0"			// to prefill memory and to avoid conflict with string variables
	str_dummy:		.asciz "        \0"
	str_var10:		.asciz "XXXX\0"
	
	str_cr:			.asciz "\n"
	str_input0: 	.asciz "Nummer des 0-Bits: 0x\0"
	str_input1: 	.asciz "Nummer des 1-Bits: 0x\0"
	str_original:	.asciz " hat einen initialen Wert von \0"
	str_modified:	.asciz " hat einen veraenderten Wert von \0"
	str_line:		.asciz "----------------------------------\n"
	
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

.equ	NUMBER_OF_BYTES, 0x4

main:	
	bl uart_init
	bl pit3_init

loop_main:

vector_input:
	ldr r4, =w_v1				// r4 holds address of v1
	bl get4bytes				// get v1
	str r0, [r4]

	ldr r5, =w_v2				// r5 holds address of v2
	bl get4bytes				// get v2
	str r0, [r5]

	ldr r0, =str_v1				// output v1
	bl uart_putString
	ldr r0, [r4] 
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

	ldr r0, =str_v2				// output v2
	bl uart_putString
	ldr r0, [r5]
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

calculation_without_DSP:
	bl pit3_getval
// time measurement starts here
	mov r6, r0					// r6 holds PIT3 start value
	
	mov r8, NUMBER_OF_BYTES		// r8 holds counter
	sub r8, r8, #1
	
	mov r10, 0x0				// r10 holds minimum vector
	mov r11, 0x0				// r11 holds maximum vector
	
loop_calculation:
	ldrb r1, [r4, r8]			// load bytes of v1 and v2 into r1 and r2
	ldrb r2, [r5, r8]
	
	cmp r1, r2
	ittt hi						// true if r1 > r2
	movhi r3, r1				// swap r1 and r2, to have min in r1 and max in r2
	movhi r1, r2
	movhi r2, r3
	
	lsl r10, r10, 0x8			// create minimum vector in r10
	orr r10, r10, r1
	
	lsl r11, r11, 0x8			// create maximum vector in r11
	orr r11, r11, r2

	subs r8, r8, #1				// decrement
bge loop_calculation			// next byte, "bge" as loop starts at 3 down to 0
	
	bl pit3_getval
// time measurement ends here
	mov r7, r0					// r7 holds PIT3 end value
	sub r9, r6, r7				// r9 holds duration of loop_calculation


	ldr r0, =str_withoutDSP		// output
	bl uart_putString

	ldr r0, =str_min			// min
	bl uart_putString
	mov r0, r10
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_max			// max
	bl uart_putString
	mov r0, r11
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_timerStart		// start
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_timerStop		// stop
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_duration		// duration
	bl uart_putString
	mov r0, r9
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

calculation_with_DSP:
	ldr r4, [r4]				// r4 and r5 hold values of v1 and v2 now
	ldr r5, [r5]

	bl pit3_getval
// time measurement starts here
	mov r6, r0					// r6 holds PIT3 start value
	
	ssub8 r12, r4, r5			// perform byte-wise subtraction, sign sets GE flags
	sel r10, r5, r4				// min: check on r4 < r5 
	sel r11, r4, r5				// max: check on r4 > r5
	
	bl pit3_getval
// time measurement ends here
	mov r7, r0					// r7 holds PIT3 end value
	sub r9, r6, r7				// r9 holds duration of loop_calculation

	ldr r0, =str_withDSP		// output
	bl uart_putString

	ldr r0, =str_min			// min
	bl uart_putString
	mov r0, r10
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_max			// max
	bl uart_putString
	mov r0, r11
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_timerStart		// start
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_timerStop		// stop
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString
	
	ldr r0, =str_duration		// duration
	bl uart_putString
	mov r0, r9
	bl uart_putInt32
	ldr r0, =str_cr
	bl uart_putString

end:
	ldr	r0, =str_line			// output line between cycles
	bl uart_putString
b loop_main

/**************************************************************************************/

// subprogram to read 4 byte vector data from terminal

.thumb_func
get4bytes:
	push {LR}					// other subprograms (uart_*) are called within get4bytes
	ldr r0, =str_prompt			// output user prompt
	bl uart_putString

	mov r1, NUMBER_OF_BYTES		// r1 is counter
	mov r9, 0x0					// r9 is temporary output register

loop_byte:
	lsl r9, r9, 0x8				// shift 1 byte left to free bits 7-0 for next input
	bl uart_getByte				// get input from terminal
	orr r9, r9, r0				// move input to bits 7-0
	
	subs r1, r1, #1				// decrement
bne loop_byte					// next byte

	mov r0, r9					// finally copy temporary output to r0
pop {PC}						// set PC to LR on stack									

	
/**************************************************************************************/

/*** Datenbereich (ab 0x20000000) ***/
.data
	str_prompt:		.asciz "Bitte Vektor eingeben (4 einzelne Bytes)!\n"
	str_withoutDSP: .asciz "ohne DSP-Befehle:\n"
	str_withDSP:	.asciz "mit DSP-Befehlen:\n"
	str_min:		.asciz "min: 0x\0"
	str_max:		.asciz "max: 0x\0"
	str_cr:			.asciz "\n"
	str_v1:			.asciz "v1: 0x\0"
	str_v2:			.asciz "v2: 0x\0"
	str_timerStart:	.asciz "Timer gestartet @ \0"
	str_timerStop:	.asciz "Timer gestoppt @ \0"
	str_duration:	.asciz "Ausfuehrungszeit (in Takten): "
	str_line:		.asciz "----------------------------------\n"

	w_v1:			.word 0x00000000
	w_v2:			.word 0x00000000
	
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

.equ	VALUE_A, 0xa4367c7b
.equ	VALUE_B, 0x10a78933
.equ	VALUE_C, 0xc5535f2c
.equ	VALUE_D, 0x788e84b1

main:	
	bl uart_init

/************************************ V 2-1 a) ***********************************

Einsparung von Multiplikationsbefehlen:

Ohne DSP-Befehle sind für jedes Feld der Matrix 4 Multiplikationen erforderlich,
jeweils Zeilenindex aus M x Spaltenindex aus N,
insgesamt also 16 x 4 = 64 Multiplikationen.

Unter Verwendung des DSP-Befehls SMLAD koennen jeweils 2 Multiplikationen parallel
durchgefuehrt werden, so dass fuer jedes Feld der Ergebnismatrix nur 2 Multiplikationen
erforderlich sind, insgesamt also 16 x 2 = 32 Multiplikationen.

Es ergibt sich eine Halbierung der erforderlichen Multiplikationsbefehle.

*********************************************************************************/

	ldr r0, =str_matrixresult				// output text "Ergebnismatrix"
	bl uart_putString

	ldr r4, =ba_m							// load M ref
	ldr r6, =ba_o							// r6 holds reference to O
	mov r11, #4								// r11 is row counter
	
loop_row:									// loop through each row of M
	mov r12, #4								// r12 is column counter
	ldr r5, =ba_n							// load N ref each row to reset pointer
	ldrd r7, r8, [r4], #8					// load row from M to r7, r8
loop_column:
	mov r0, #0								// r0 is accumulator (cleared each row)
	ldrd r9, r10, [r5], #8					// load column from N to r9, r10

	// calculation
	smlad r0, r7, r9, r0					// multiply halfword-wise (elements 1, 2) and accumulate
	smlad r0, r8, r10, r0					// same with elements 3, 4
	str r0, [r6], #4						// store accumulated result ro matrix O
	bl uart_putInt32						// output
	// calculation end
	
	mov r0, #0x09							// tab to next column for nice output
	bl uart_putChar
	bl uart_putChar
	
	subs r12, r12, #1						// decrement column counter
	bne loop_column							// next column
	
	mov r0, 0x0a							// cr to next row
	bl uart_putChar
	
	subs r11, r11, #1						// decrement row counter
	bne loop_row							// next row

	mov r0, #0x0a							// final cr
	bl uart_putChar

/************************************ V 2-1 b) ***********************************/

	ldr r0, =str_copymatrix_start			// starting to copy O
	bl uart_putString
	mov r0, #0x0a
	bl uart_putChar

	ldr r0, =ba_o							// load reference to O original
	ldr r1, =ba_o_copy						// load reference to O copy
	mov r2, #8								// 8 doublewords of data

loop_2_1b:
	ldrd r4, r5, [r0], #8					// load doubleword and post-index offset by 8 bytes
	strd r4, r5, [r1], #8					// store doubleword and post-index offset by 8 bytes
	
	subs r2, r2, #1							// decrement doubleword counter
	bne loop_2_1b							// next doubleword
	// end loop

/************************************ V 2-1 c) ***********************************/

	ldr r0, =ba_m							// load M to r0
	ldr r1, =ba_n							// load N to r1
	mov r4, #8								// r4 is counter
	mov r5, #0								// r5 is accumulator
	
loop_2_1c:
	ldr r6, [r0], #4						// r6 is word from M
	ldr r7, [r1], #4						// r7 is word from N
	smlad r5, r6, r7, r5					// multiply halfword-wise and accumulate
	subs r4, r4, #1							// decrement counter
	bne loop_2_1c
	// end loop

	ldr r0, =str_productsum					// output
	bl uart_putString
	mov r0, r5
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar
	bl uart_putChar

/************************************ V 2-1 d) ***********************************

Interpretation des UADD16 Befehls
vorzeichenlose, halbwortweise Addition, arithmetisch modulo 2^16
A+B = 0xa436 + 0x10a7 = 0xb4dd, 0x7c7b + 0x8933 = 0x105ae
bei 0x105ae werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x05ae
A+C = 0xa436 + 0xc553 = 0x16989, 0x7c7b + 0x5f2c = 0xdba7
bei 0x16989 werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x6989
A+D = 0xa436 + 0x788e = 0x11cc4, 0x7c7b + 0x84b1 = 0x1012c
bei 0x11cc4 werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x1cc4
bei 0x1012c werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x012c

Interpretation des SADD16 Befehls
vorzeichenbehaftete, halbwortweise Addition, arithmetisch modulo 2^16
A+B = 0xa436 + 0x10a7 = 0xb4dd, 0x7c7b + 0x8933 = 0x105ae
bei 0x105ae werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x05ae
A+C = 0xa436 + 0xc553 = 0x16989, 0x7c7b + 0x5f2c = 0xdba7
bei 0x16989 werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x6989
A+D = 0xa436 + 0x788e = 0x11cc4, 0x7c7b + 0x84b1 = 0x1012c
bei 0x11cc4 werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x1cc4
bei 0x1012c werden nur die letzten 16 Bits verwendet, Ergebnis somit 0x012c

Interpretation des UQADD16 Befehls
vorzeichenlose, halbwortweise Addition, gesaettigt
A+B = 0xa436 + 0x10a7 = 0xb4dd, 0x7c7b + 0x8933 = 0x105ae
0x105ae ist groesser als 0xffff, Ergebnis somit 0xffff
A+C = 0xa436 + 0xc553 = 0x16989, 0x7c7b + 0x5f2c = 0xdba7
0x16989 ist groesser als 0xffff, Ergebnis somit 0xffff
A+D = 0xa436 + 0x788e = 0x11cc4, 0x7c7b + 0x84b1 = 0x1012c
0x11cc4 ist groesser als 0xffff, Ergebnis somit 0xffff
0x1012c ist groesser als 0xffff, Ergebnis somit 0xffff

Interpretation des QADD16 Befehls
vorzeichenbehaftete, halbwortweise Addition, gesaettigt
A+B = 0xa436 + 0x10a7 = 0xb4dd, 0x7c7b + 0x8933 = 0x105ae
bei 0xb4dd liegt keine Saettigung vor, auch keine Saettigung des Overflow
bei 0x105ae (Interpretation als positive Zahl) werden nur die letzten 15 Bits verwendet,
	Ergebnis somit 0x05ae, der Overflow ist nicht gesaettigt
A+C = 0xa436 + 0xc553 = 0x16989, 0x7c7b + 0x5f2c = 0xdba7
0x16989 (Interpretation als negative Zahl) ist kleiner als 0x8000, Ergebnis somit 0x8000,
	Hier liegt Saettigung des Overflows vor, da der maximal erlaubte negative Wert ausgegeben wird.
0xdba7 (Interpretation als positive Zahl) ist groesser als 0x7fff, Ergebnis somit 0x7fff
	Hier liegt Saettigung des Overflows vor, da der maximal erlaubte positive Wert ausgegebn wird.
A+D = 0xa436 + 0x788e = 0x11cc4, 0x7c7b + 0x84b1 = 0x1012c
bei 0x11cc4 (Interpretation als positive Zahl) werden nur die letzten 15 Bits verwendet,
	Ergebnis somit 0x1cc4, der Overflow ist nicht gesaettigt, da lediglich Bit 16 gesetzt ist.
bei 0x1012c (Interpretation als positive Zahl) werden nur die letzten 15 Bits verwendet,
	Ergebnis somit 0x012c, der Overflow ist nicht gesaettigt, da lediglich Bit 16 gesetzt ist.

*********************************************************************************/
	
	ldr r4, =VALUE_A			// load values A to D into registers r4 to r7
	ldr r5, =VALUE_B
	ldr r6, =VALUE_C
	ldr r7, =VALUE_D

	// uadd
	ldr r0, =str_uadd16
	bl uart_putString
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	
	uadd16 r8, r4, r5			// results in r8, r9, r10
	uadd16 r9, r4, r6
	uadd16 r10, r4, r7
	
	mov r0, r8					// output
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r9
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r10
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar

	// sadd
	ldr r0, =str_sadd16
	bl uart_putString
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar

	sadd16 r8, r4, r5			// results in r8, r9, r10
	sadd16 r9, r4, r6
	sadd16 r10, r4, r7

	mov r0, r8					// output
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r9
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r10
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar
	
	// uqadd
	ldr r0, =str_uqadd16
	bl uart_putString
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar

	uqadd16 r8, r4, r5			// results in r8, r9, r10
	uqadd16 r9, r4, r6
	uqadd16 r10, r4, r7

	mov r0, r8					// output
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r9
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r10
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar

	// qadd
	ldr r0, =str_qadd16
	bl uart_putString
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar

	qadd16 r8, r4, r5			// results in r8, r9, r10
	qadd16 r9, r4, r6
	qadd16 r10, r4, r7

	mov r0, r8					// output
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r9
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r10
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar
	bl uart_putChar

/************************************ V 2-1 e) **********************************

Interpretation des SSAT16 Befehls:
Saettigt einen vorzeichenbehafteten Wert auf eine vorzeichenbehaftete Stellenzahl
0xa436 wird zu 0xe000 gesaettigt, da kleiner als -2^13
	0xa436 - 1 = 0xa435 ==> 1-Komplement = -0x5bca
	2^13 = 0x2000 ==> 2-Komplement = 0xdfff + 1 = 0xe000
0x7c7f wird zu 0x1fff gesaettigt, da groesser als 2^13-1
0x10a7 wird zu 0x10a7 gesaettigt, keine Aenderung, da zwischen -2^13 und +2^13-1
0x8933 wird zu 0xe000 gesaettigt, da kleiner als -2^13
	0x8933 - 1 = 0x8932 ==> 1-Komplement = -0x76cd
	2^13 = 0x2000 ==> 2-Komplement = 0xdfff + 1 = 0xe000

Interpretation des USAT16 Befehls:
Saettigt einen vorzeichenbehafteten Wert auf eine vorzeichenlose Stellenzahl
0xa436 wird zu 0x0000 gesaettigt, da 0xa436 wegen des gesetzten Bit 15 als negative
	Zahl interpretiert wird, also kleiner als Null ist.  
0x7c7b wird zu 0x1fff gesaettigt, es handelt sich um eine positive Zahl, die aber
	groesser ist als 2^13-1 = 0x1fff
0x10a7 wird zu 0x10a7 gesaettigt, keine Aenderung, da zwischen 0 und 2^13-1
0x8933 wird zu 0x0000 gesaettigt, da negativ wegen des gesetzten Bit 15

********************************************************************************/

	// values A and B are still in r4 and r5

	// ssat
	ldr r0, =str_command1
	bl uart_putString
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	
	ssat16 r8, #14, r4			// sat bit position is in the range 1 to 16
	ssat16 r9, #14, r5
	
	mov r0, r8					// output
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r9
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar
	
	// usat
	ldr r0, =str_command2
	bl uart_putString
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	
	usat16 r8, #13, r4			// sat bit position is in the range 0 to 15
	usat16 r9, #13, r5
	
	mov r0, r8					// output
	bl uart_putInt32
	mov r0, #0x09
	bl uart_putChar
	bl uart_putChar
	mov r0, r9
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar
	bl uart_putChar

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str_matrixresult:		.asciz "Ergebnismatrix O:\n"
str_copymatrix_start:	.asciz "Kopieren der Matrix O!\n"
str_copymatrix_end:		.asciz "Kopieren beendet.\n"
str_productsum:			.asciz "Produkt-Summe:\0"
str_uadd16:				.asciz "UADD16:\0"
str_sadd16:				.asciz "SADD16:\0"
str_uqadd16:			.asciz "UQADD16:\0"
str_qadd16:				.asciz "QADD16:\0"
str_command1:			.asciz "SSAT16:\0"
str_command2:			.asciz "USAT16:\0"
.align 4														// to improve access speed
ba_m:					.hword 0x5f8c, 0x7f48, 0x8245, 0x6048	// M is organized in row-major order
						.hword 0xc799, 0x9c5d, 0xd49c, 0x33d8
						.hword 0x579b, 0x8aef, 0xf2c0, 0xa3c2
						.hword 0x41fd, 0x50d4, 0x25c6, 0x4afa
ba_n:					.hword 0x7f41, 0x0645, 0x8c8f, 0x9065	// N is organized in column-major order
						.hword 0x78e3, 0xf7f3, 0xd29f, 0x2961
						.hword 0x5a1e, 0xdfed, 0x4b9f, 0x1092
						.hword 0x61bf, 0x21be, 0x5ca1, 0xc6d3
ba_o:					.rept 0x10								// O: 16 x 32-bit data
						.word 0x0
						.endr
ba_o_copy:				.rept 0x10								// O_copy: 16 x 32-bit data
						.word 0x0
						.endr
						
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/


main:	
	bl uart_init
		
loop:
	// check_input:
	bl uart_charPresent			// check terminal input
	cmp r0, #0x00
	beq update_clock			// no input: proceed with regular clock increment
	
	bl uart_getChar				// receive character from terminal

	cmp r0, #0x73				// check on "s" (start/stop), s = ascii 73
	beq toggle_active
	
	cmp r0, #0x74				// check on "t" (time), t = ascii 74
	beq set_time
	
	cmp r0, #0x64				// check on "d" (date), d = ascii 64
	beq set_date
	
	// terminal input "a" adjusts the length of the delay
	cmp r0, #0x61				// check on "a" (adjust), a = ascii 61
	beq adjust_delay
	
	b update_clock

toggle_active:					// activate/deactivate clock on s-input
	ldr r2, =b_clockActive		
	ldr r1, [r2]
	cmp r1, #0
	ite eq
	moveq r1, #0x1
	movne r1, #0x0

	str r1, [r2] 

	b update_clock				// proceed with regular clock increment
	
set_time:						// set time on t-input
	ldr r0, =str_hour			// get hour
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #1]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	ldr r0, =str_minute			// get minute
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #0]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar
	
	b update_clock				// proceed with regular clock increment

set_date:						// set date on d-input
	ldr r0, =str_day			// get day
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #2]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	ldr r0, =str_month			// get month
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #3]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	ldr r0, =str_year			// get year
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #4]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	b update_clock				// proceed with regular clock increment

adjust_delay:					// adjust delay on d-input
	ldr r0, =str_adjust			// enter real time seconds for 1 hour
	bl uart_putString
	bl uart_getByteBase10
	mov r6, r0					// r6 holds real seconds for 1 displayed hour
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar	
	
	ldr r0, =w_counterStart		// r7 holds counter start address
	ldr r8, [r0]				// r8 holds current counter start value
	
	mov r9, #60					// r9 = 60
	udiv r8, r8, r6				// r8 divided by real seconds
	mul r8, r8, r9				// and multiplied by 60
	
	str r8, [r0]				// store new delay
	ldr r0, =str_newDelay
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	mov r0, #0x0a
	bl uart_putChar
	
	
/****************** update clock ********************/

update_clock:
	ldr r0, =b_clockActive		// check if clock is set to active
	ldr r1, [r0]
	
	cmp r1, #0x00
	beq loop					// nothing to do if inactive
	
	// update starts here
	ldr r4, =ba_dateTime		// r4 holds reference to date/time array

	bl display_dateTime			// output to terminal
	bl delay					// busy wait

	// update_minute:
	ldrb r5, [r4]				// r5 holds minute
	add r5, r5, #1				// increment minute
	strb r5, [r4]				// and store
	cmp r5, #60					// if minute is below 60
	blt loop					// leave loop
	
	mov r5, #0					// set minute to 0 if it was 60
	strb r5, [r4]				// and store

	// update_hour:
	ldrb r5, [r4, #1]!			// r5 holds hour now (pre-indexed to get byte 1)
	add r5, r5, #1				// increment hour
	strb r5, [r4]				// and store

	cmp r5, #24					// if hour is below 24
	blt loop					// leave loop

	mov r5, #0					// set hour to 0 if it was 24
	strb r5, [r4]				// and store

	// update_day:	
	ldrb r5, [r4, #1]!			// r5 holds day now (byte 2)
	add r5, r5, #1				// increment day
	strb r5, [r4]				// and store

	cmp r5, #31					// if day is below 31 (simplification, every month has 30 days)
	blt loop					// leave loop
	
	mov r5, #1					// set day to 1 if it was 31
	strb r5, [r4]				// and store

	// update_month:
	ldrb r5, [r4, #1]!			// r5 holds month now (byte 3)
	add r5, r5, #1				// increment month
	strb r5, [r4]				// and store

	cmp r5, #13					// if month is below 13
	blt loop					// leave loop

	mov r5, #1					// set month to 1 if it was 13
	strb r5, [r4]				// and store

	// update_year:
	ldrb r5, [r4, #1]!			// r5 holds year now (byte 4)
	add r5, r5, #1				// increment year
	strb r5, [r4]				// and store

	cmp r5, #100				// if year is below 100
	blt loop					// leave loop
	
	mov r5, #0					// set year to 0 if it was 100
	strb r5, [r4]				// and store

	// update century:
	ldrb r5, [r4, #1]!			// r5 holds century now (byte 5)
	add r5, r5, #1				// increment century
	strb r5, [r4]				// and store
	
	cmp r5, #100				// if century is below 100
	blt loop					// leave loop	
	
	mov r5, #0x14				// set century back to 20 if it was 100 (no overflow of century required)
	strb r5, [r4]				// and store

	b loop						// and again


/*************************** SUBPROGRAMS *********************************/

.thumb_func
delay:							// subprogram to delay 1 second
	push {r4-r5, LR}
	ldr r4, =w_counterStart
	ldr r5, [r4]
delay_loop:
	subs r5, r5, #1
	bne delay_loop
	pop {r4-r5, PC}

display_dateTime:				// subprogram for terminal output of date and time
	push {r4, LR}
	ldr r4, =ba_dateTime		// r4 holds reference to date and time data

	ldrb r1, [r4, #2]			// day
	
	cmp r1, #0x0a				// put leading 0 if day < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
	mov r0, #0x2e				// .
	bl uart_putChar

	ldrb r1, [r4, #3]			// month

	cmp r1, #0x0a				// put leading 0 if month < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
		
	mov r0, #0x2e				// .
	bl uart_putChar

	ldrb r1, [r4, #5]			// century
	mov r0, r1
	bl uart_putByteBase10

	ldrb r1, [r4, #4]			// year

	cmp r1, #0x0a				// put leading 0 if year < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10

	mov r0, #0x20				// 2 spaces
	bl uart_putChar
	bl uart_putChar

	ldrb r1, [r4, #1]			// hour

	cmp r1, #0x0a				// put leading 0 if hour < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
	
	mov r0, #0x3a				// :
	bl uart_putChar

	ldrb r1, [r4, #0]			// minute

	cmp r1, #0x0a				// put leading 0 if minute < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
	
	mov r0, #0x20				// space
	bl uart_putChar
	mov r0, #0x55				// U
	bl uart_putChar
	mov r0, #0x68				// h
	bl uart_putChar
	mov r0, #0x72				// r
	bl uart_putChar
	mov r0, #0x0a				// line feed
	bl uart_putChar
	pop {r4, PC}

/*** Datenbereich (ab 0x20000000) ***/
.data
str_minute:		.asciz "Minute eingeben (mm): \0"
str_hour:		.asciz "Stunde eingeben (hh): \0"
str_day:		.asciz "Tag eingeben (dd): \0"
str_month:		.asciz "Monat eingeben (mm): \0"
str_year:		.asciz "Jahr eingeben (jj): \0"
str_adjust:		.asciz "Wie viele Sekunden vergehen real waehrend einer angezeigten Stunde? (ss): \0"
str_newDelay:	.asciz "Neue Verzoegerung: \0"
ba_dateTime:	.byte 0x00, 0x00, 0x01, 0x01, 0x0e, 0x14	// minute, hour, day, month, year, century
b_clockActive:	.byte 0x01									// clock is inactive at 0x00

.align 4

/* counter Start calculation:
delay_loop: subs command takes 1 cycle
			bne command take 1+P cycles
			=> 3 cycles in total
K60 speed = 25 MHz
25 MHz : 3 cycles = 8.333.333 loops per second
8.333.333 log2 = approx. 23
2^23 = 0x00800000 
*/
w_counterStart:	.word 0x00800000
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// see comments in code below for calculation of addresses
.equ	SIM_SCGC6_PIT,	0x429007dc
.equ	PIT1_IR_ADDR,	0xe000ee5c
.equ	SCR_VTOR,		0xe000ed08
.equ	OFFSET_IRQ69,	0x0154
.equ	BITFIELD_IRQ69, 0x0020
.equ	NVIC_ICPR2,		0xe000e288
.equ	NVIC_ISER2,		0xe000e108
.equ	NVIC_ICER2,		0xe000e188
.equ	PIT_MCR,		0x426e0000
.equ	PIT_LDVAL1,		0x40037110
.equ	PIT_TFLG1,		0x426e2380
.equ	PIT_TCTRL1_TEN,	0x426e2300
.equ	PIT_TCTRL1_TIE,	0x426e2304
.equ	CLK_CNTR,		0x017d783f 

main:	
	bl uart_init


/****************************** INIT INTERRUPT *****************************/

	// step a) - enable_PITclockGateControl:
	// see K60 sub-family ref manual, p. 308f
	// set bit 23 (0x17) of SIM_SCGC6 to 1 
	// SIM_SCGC6 has address 0x4004_803c
	// bit band alias base address is 0x4200_0000
	// bit band alias is 0x4200_0000 + 0x4_803c * 0x20 + 0x17 x 0x04 = 0x4290_07dc
	ldr r0, =SIM_SCGC6_PIT
	mov r1, #1
	str r1, [r0]				// PIT


	/************************** NVIC ***************************************************
	see K60 sub-family ref manual, p. 78f
	Vector is 85
	IRQ is 69 (vector number minus 16)
	NVIC non-IPR register number is 2 for PIT1 (integer part of IRQ div 32)
	non-IPR bitfield location is IRQ mod 32 = 5 = 0b100000
	NVIC IPR register number is 17 for PIT1 (integer part of IRQ div 4)
	IPR bitfield location is 8 x (IRQ mod 4) + 4 = 8 x 1 + 4 = 12
	IPR bitfield range is [15:12] 
	IR address is 0x0000_0154 (vector x 4)
	
	see ARM Cortex-M4 processor technical reference manual, p. 63 for NVIC registers
	NVIC_ISER2 address is 0xe000_e100 + 2 x 0x04 = 0xe000_e108
	NVIC_ICER2 address is 0xe000_e180 + 2 x 0x04 = 0xe000_e188
	NVIC_ISPR2 address is 0xe000_e200 + 2 x 0x04 = 0xe000_e208
	NVIC_ICPR2 address is 0xe000_e280 + 2 x 0x04 = 0xe000_e288
	NVIC_IABR2 address is 0xe000_e300 + 2 x 0x04 = 0xe000_e308
	NVIC_IPR17 address is 0xe000_e400 + 17 x 0x04 = 0xe000_e45c
	
	see Studientag_Folien.pdf, p. 20 for IVT
	IVT base register is 0xe000_ed08 (scr_vtor = vector table offset register)
	offset for vector 85 (0x55) is 0x55 * 0x4 = 0x154
	interrupt vector is at 0xe000_ed08 + 0x154 = 0xe000_ee5c 
	***********************************************************************************/

	// step b) - set_PIT1interruptVector:
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r2, =#OFFSET_IRQ69
	add r0, r1, r2
	ldr r1, =delay				// delay = ISR
	str r1, [r0]				// store address of ISR to IR address
	
	// step c) - set_NVIC_ClearPendingRegister:
	// see ARM Cortex-M4 processor technical reference manual, p. 63 for NVIC registers
	// NVIC_ICPR2 address is 0xe000_e280 + 5 x 0x04 = 0xe000_e294
	// no bit banding alias available
	ldr r0, =NVIC_ICPR2
	ldr r1, [r0]
	ldr r2, =#BITFIELD_IRQ69	// bitfield location is 5
	orr r1, r1, r2				// set bit 5
	str r1, [r0]				// pending reset

	// step d) - set_NVIC_SetEnableRegister:
	// see ARM Cortex-M4 processor technical reference manual, p. 63 for NVIC registers
	// NVIC_ISER2 address is 0xe000_e100 + 5 x 0x04 = 0xe000_e114
	// no bit banding alias available
	ldr r0, =NVIC_ISER2
	ldr r1, [r0]
	ldr r2, =#BITFIELD_IRQ69	// bitfield location is 5
	orr r1, r1, r2				// set bit 5
	str r1, [r0]				// enable set

	// step e) - set_PITmoduleControlRegister:
	// see K60 sub-family ref manual, p. 1078
	// PIT_MCR has address 0x4003_7000
	// bit band alias base address is 0x4200_0000
	// bit band alias is 0x4200_0000 + 0x3_7000 * 0x20 = 0x426e_0000
	ldr r0, =PIT_MCR
	mov r1, #0
	str r1, [r0], #4			// FRZ, continue to run in debug mode
	str r1, [r0]				// MDIS, clock enabled

	// step f) - set_timerLoadValueRegister:
	// see K60 sub-family ref manual, p. 1078f
	// PIT_LDVAL1 has address 0x4003_7000 + 0x100 + 0x10 = 0x4003_7110
	// bit band alias base address is 0x4200_0000
	// bit band alias is 0x4200_0000 + 0x3_7110 * 0x20 = 0x426e_2200
	// clock frequency is 25 MHz = 40 ns per cycle
	//
	// see K60 sub-family ref manual, p. 1083:
	// LDVAL trigger = (period / clock period) -1
	// period = 1000 ms, clock period = 40 ns ==> LDVAL = 25.000.000 cycles
	// 25.000.000 cycles = 0x17d7840, -1 = 0x17d783f
	ldr r0, =PIT_LDVAL1
	ldr r1, =CLK_CNTR
	str r1, [r0]

	// step g) - set_timerFlagRegister:
	// see K60 sub-family ref manual, p. 1080f
	// PIT_TFLG1 had address 0x4003_7000 + 0x10c + 0x10 = 0x4003_711c
	// bit band alias base address is 0x4200_0000
	// bit band alias is 0x4200_0000 + 0x3_711c * 0x20 = 0x426e_2380
	// to be cleared prior to TCTRL1, see p. 1080
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0]				// clear TIF

	// step h) - set_timerControlRegister:
	// see K60 sub-family ref manual, p. 1079f
	// set bit 0 of PIT_TCTRL1 to 1 (TEN, timer enabled)
	// set bit 1 of PIT_TCTRL1 to 1 (TIE, timer interrupt enabled)
	// set bit 2 of PIT_TCTRL1 to 0 (CHN, timer not chained)
	// PIT_TCTRL1 has address 0x4003_7000 + 0x108 + 0x10 = 0x4003_7118
	// bit band alias base address is 0x4200_0000
	// bit band alias is 0x4200_0000 + 0x3_7118 * 0x20 = 0x426e_2300
	mov r1, #1
	ldr r0, =PIT_TCTRL1_TIE
	str r1, [r0]				// TIE
	ldr r0, =PIT_TCTRL1_TEN
	str r1, [r0]				// TEN

loop:
	wfi							// avoid busy wait during loop
	
	ldr r0, =b_second			// check user flag to see if interrupt was from delay-isr
	ldr r1, [r0]

	cmp r1, 0x00
	beq loop					// nothing to do

	mov r1, #0
	str r1, [r0]				// user flag reset
		
/***************************** CODE FROM V2-2 *******************************/

	// check_input:
	bl uart_charPresent			// check terminal input
	cmp r0, #0x00
	beq update_clock			// no input: proceed with regular clock increment
	
	bl uart_getChar				// receive character from terminal

	cmp r0, #0x73				// check on "s" (start/stop), s = ascii 73
	beq toggle_active
	
	cmp r0, #0x74				// check on "t" (time), t = ascii 74
	beq set_time
	
	cmp r0, #0x64				// check on "d" (date), d = ascii 64
	beq set_date
	
	b update_clock
	
toggle_active:					// activate/deactivate clock on s-input
	ldr r2, =b_clockActive		
	ldr r1, [r2]
	cmp r1, #0
	ite eq
	moveq r1, #0x1
	movne r1, #0x0

	str r1, [r2] 

	b update_clock				// proceed with regular clock increment
	
set_time:						// set time on t-input
	ldr r0, =str_hour			// get hour
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #1]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	ldr r0, =str_minute			// get minute
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #0]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar
	
	b update_clock				// proceed with regular clock increment

set_date:						// set date on d-input
	ldr r0, =str_day			// get day
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #2]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	ldr r0, =str_month			// get month
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #3]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	ldr r0, =str_year			// get year
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #4]
	bl uart_putByteBase10
	mov r0, #0x0a
	bl uart_putChar

	
/****************** update clock ********************/

update_clock:
	ldr r0, =b_clockActive		// check if clock is set to active
	ldr r1, [r0]
	
	cmp r1, #0x00
	beq loop					// nothing to do if inactive
	
	// update starts here
	ldr r4, =ba_dateTime		// r4 holds reference to date/time array

	bl display_dateTime			// output to terminal
	bl delay					// busy wait

	// update_minute:
	ldrb r5, [r4]				// r5 holds minute
	add r5, r5, #1				// increment minute
	strb r5, [r4]				// and store
	cmp r5, #60					// if minute is below 60
	blt loop					// leave loop
	
	mov r5, #0					// set minute to 0 if it was 60
	strb r5, [r4]				// and store

	// update_hour:
	ldrb r5, [r4, #1]!			// r5 holds hour now (pre-indexed to get byte 1)
	add r5, r5, #1				// increment hour
	strb r5, [r4]				// and store

	cmp r5, #24					// if hour is below 24
	blt loop					// leave loop

	mov r5, #0					// set hour to 0 if it was 24
	strb r5, [r4]				// and store

	// update_day:	
	ldrb r5, [r4, #1]!			// r5 holds day now (byte 2)
	add r5, r5, #1				// increment day
	strb r5, [r4]				// and store

	cmp r5, #31					// if day is below 31 (simplification, every month has 30 days)
	blt loop					// leave loop
	
	mov r5, #1					// set day to 1 if it was 31
	strb r5, [r4]				// and store

	// update_month:
	ldrb r5, [r4, #1]!			// r5 holds month now (byte 3)
	add r5, r5, #1				// increment month
	strb r5, [r4]				// and store

	cmp r5, #13					// if month is below 13
	blt loop					// leave loop

	mov r5, #1					// set month to 1 if it was 13
	strb r5, [r4]				// and store

	// update_year:
	ldrb r5, [r4, #1]!			// r5 holds year now (byte 4)
	add r5, r5, #1				// increment year
	strb r5, [r4]				// and store

	cmp r5, #100				// if year is below 100
	blt loop					// leave loop
	
	mov r5, #0					// set year to 0 if it was 100
	strb r5, [r4]				// and store

	// update century:
	ldrb r5, [r4, #1]!			// r5 holds century now (byte 5)
	add r5, r5, #1				// increment century
	strb r5, [r4]				// and store
	
	cmp r5, #100				// if century is below 100
	blt loop					// leave loop	
	
	mov r5, #0x14				// set century back to 20 if it was 100 (no overflow of century required)
	strb r5, [r4]				// and store

	b loop						// and again

/***************************** END OF CODE FROM V2-2 ***********************/

/*************************** SUBPROGRAMS *********************/

.thumb_func
delay:
	/*set_NVIC_ClearEnableRegister:
	// see ARM Cortex-M4 processor technical reference manual, p. 63 for NVIC registers
	// NVIC_ICER2 address is 0xe000_e180 + 2 x 0x04 = 0xe000_e188
	// no bit banding alias available
	ldr r0, =NVIC_ICER2
	ldr r1, [r0]
	ldr r2, =BITFIELD_IRQ69		// bitfield location is 5
	orr r1, r1, r2				// set bit 5
	str r1, [r0]				// clear
	*/

	// clear_timerFlagRegister:
	ldr r2, =PIT_TFLG1
	mov r3, #1
	str r3, [r2]				// clear TIF

	// set_userFlag:
	ldr r2, =b_second
	mov r3, #1
	str r3, [r2]				// user flag set

	bx lr

/*************************** SUBPROGRAM FROM V2-2 *************************/

display_dateTime:				// subprogram for terminal output of date and time
	push {r4, LR}
	ldr r4, =ba_dateTime		// r4 holds reference to date and time data

	ldrb r1, [r4, #2]			// day
	
	cmp r1, #0x0a				// put leading 0 if day < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
	mov r0, #0x2e				// .
	bl uart_putChar

	ldrb r1, [r4, #3]			// month

	cmp r1, #0x0a				// put leading 0 if month < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
	
	mov r0, #0x2e				// .
	bl uart_putChar

	ldrb r1, [r4, #5]			// century
	mov r0, r1
	bl uart_putByteBase10

	ldrb r1, [r4, #4]			// year

	cmp r1, #0x0a				// put leading 0 if year < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10

	mov r0, #0x20				// 2 spaces
	bl uart_putChar
	bl uart_putChar

	ldrb r1, [r4, #1]			// hour

	cmp r1, #0x0a				// put leading 0 if hour < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
	
	mov r0, #0x3a				// :
	bl uart_putChar

	ldrb r1, [r4, #0]			// minute

	cmp r1, #0x0a				// put leading 0 if minute < 10
	itt lt
	movlt r0, #0x30
	bllt uart_putChar
	
	mov r0, r1
	bl uart_putByteBase10
	
	mov r0, #0x20				// space
	bl uart_putChar
	mov r0, #0x55				// U
	bl uart_putChar
	mov r0, #0x68				// h
	bl uart_putChar
	mov r0, #0x72				// r
	bl uart_putChar
	mov r0, #0x0a				// line feed
	bl uart_putChar
	pop {r4, PC}

/*************************** END OF SUBPROGRAM FROM V2-2 *************************/


/*** Datenbereich (ab 0x20000000) ***/
.data
str_minute:		.asciz "Minute eingeben (mm): \0"
str_hour:		.asciz "Stunde eingeben (hh): \0"
str_day:		.asciz "Tag eingeben (dd): \0"
str_month:		.asciz "Monat eingeben (mm): \0"
str_year:		.asciz "Jahr eingeben (jj): \0"
ba_dateTime:	.byte 0x00, 0x00, 0x01, 0x01, 0x0e, 0x14	// minute, hour, day, month, year, century
b_clockActive:	.byte 0x01									// clock is inactive at 0x00
b_second:		.byte 0x00									// user flag - is 1 on delay interrupt
	
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// register addresses
.equ	SIM_SCGC6,			0x4004803c			// system clock gating control register
.equ	CRC_CRC,			0x40032000			// crc data register
.equ	CRC_GPOLY,			0x40032004			// crc polynomial register
.equ	CRC_CTRL,			0x40032008			// crc control register

// bit band constants
__BBREG	BB_SIM_CRC,			SIM_SCGC6, 18		// CRC clock gate control, CRC is bit 18 in SCGC6
__BBREG	BB_CRC_WAS,			CRC_CTRL, 25		// write crc data register as seed, WAS is bit 25 in CRC_CTRL

// various constants
.equ	SEED,				0x12345678
.equ	POLYNOMIAL,			0x04c11db7			// CRC-32 (IEEE 802.3) polynomial
.equ	INIT_CRC_CTRL,		1 << 25 + 1 << 24	// WAS (bit 25) set to seed values and TCRC (bit 24) set to 32 bit
.equ	LF,					0x0a				// line feed

main:	
	bl uart_init

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/

// preload some constants
	ldr r4, =str						// r4	pointer to input string
	ldr r5, =CRC_CRC					// r5	pointer to CRC data register
	
// enable CRC Clock Gate Control
	ldr r0, =BB_SIM_CRC
	mov r1, #1
	str r1, [r0]

// set crc protocol to 32 bit and set WAS to init crc control for seed values
	ldr r0, =CRC_CTRL
	mov r1, #INIT_CRC_CTRL
	str r1, [r0]

// set polynomial
	ldr r0, =CRC_GPOLY
	ldr r1, =POLYNOMIAL
	str r1, [r0]

// write seed
	ldr r0, =SEED
	str r0, [r5]						// write seed to crc data register

// clear WAS to set crc control to data values
	ldr r0, =BB_CRC_WAS
	mov r1, #0
	str r1, [r0]						// writes to the crc data register are now considered data values

/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

loop:
	ldr r6, [r4], #4					// read word from str and post-increment by 1 word (r6)

// check byte 0 for termination
	ubfx r0, r6, #0, #8					// filter byte 0 to r0.
	cbz r0, get_result					// if byte 0 is 0x00: nothing more to do as string was completely read during last cycle

// check byte 1 for termination
	ubfx r0, r6, #8, #8					// filter byte 1 to r0
	cmp r0, #0
	itt eq								// if byte 1 is 0x00
	bfceq r6, #16, #16					// clear bytes 3 and 2
	beq final_word						// and save final word to CRC data register

// check byte 2 for termination
	ubfx r0, r6, #16, #8				// filter byte 2 to r0
	cmp r0, #0
	itt eq								// if byte 2 is 0x00
	bfceq r6, #24, #8					// clear byte 3
	beq final_word						// and save final word to CRC data register

// check byte 3 for termination
	ubfx r0, r6, #24, #8				// filter byte 3 to r0 
	cbz r0, final_word					// if byte 3 is 0x00, save final word to CRC data register

// no termination detected
	str r6, [r5]						// no termination byte detected in word, save word to CRC data register
	b loop								// and continue with next word

final_word:
// write final and cleared word to crc data
	str r6, [r5]

get_result:
// get crc result to r6
	ldr r6, [r5]

// output
	ldr r0, =str						// read again to avoid offset in r4
	bl uart_putString
	mov r0, #LF
	bl uart_putChar
	
	ldr r0, =crc32
	bl uart_putString
	mov r0, r6							// crc output in r6
	bl uart_putInt32
	mov r0, #LF
	bl uart_putChar

end:
	b end

/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/


/*** Datenbereich (ab 0x20000000) ***/
.data
str:	.asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
crc32:	.asciz "CRC-32: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/



/*******************************************************************************************************
>>> identify ports from schematic
see Schaltplan-TWR-K60N512.pdf, p. 7 for LEDs and p. 6 for switches

LED E1 		has port		PTA11
LED E2						PTA28
LED E3						PTA29
LED E4						PTA10
SW1 (black)					PTA19
SW2 (green)					PTE26 (port E !)

******************************************************************************************************/


// register addresses
.equ SIM_SCGC5,				0x40048038								// System Clock Gating 5
.equ SIM_SCGC6,				0x4004803c								// System Clock Gating 6

.equ SCR_VTOR,				0xe000ed08								// register for IVT
.equ NVIC_ISER2,			0xe000e100 + 0x2 << 2					// NVIC non-IPR register number is 2
.equ NVIC_ICPR2,			0xe000e280 + 0x2 << 2					//  (integer part of IRQ div 32)

.equ PIT_MCR,				0x40037000								// PIT Module Control Register
.equ PIT_LDVAL1,			PIT_MCR + 0x100 + 16					// PIT1 Load Value register
.equ PIT_TCTRL1,			PIT_MCR + 0x108 + 16					// PIT1 Control register
.equ PIT_TFLG1,				PIT_MCR + 0x10c + 16					// PIT1 Flag Register

.equ PORTA_GPCLR,			0x40049080								// Global Pin Control Low Register for Port A
.equ PORTA_GPCHR,			0x40049084								// Global Pin Control High Register for Port A
.equ GPIOA_PDDR,			0x400ff014								// Port Data Direction for LEDs
.equ GPIOA_PDOR,			0x400ff000								// port data output registers for LEDs
.equ GPIOA_PDIR,			0x400ff010								// port data input register for SW1

.equ PORTE_PCR26,			0x4004d068								// Pin Control Register for Port E, Pin 26
.equ GPIOE_PDDR,			0x400ff114								// Port Data Direction for SW2
.equ GPIOE_PDIR,			0x400ff110								// port data input register for SW2 (port E)

.equ LPTMR0_CSR,			0x40040000								// low power timer control status register
.equ LPTMR0_PSR,			0x40040004								// low power timer prescale register
.equ LPTMR0_CMR,			0x40040008								// low power timer compare register

// bit band constants
__BBREG BB_SIM_PORTA,		SIM_SCGC5, 9							// PORTA is bit 9 in SCGC5
__BBREG BB_SIM_PORTE,		SIM_SCGC5, 13							// PORTE is bit 13 in SCGC5
__BBREG	BB_SIM_LPTIMER,		SIM_SCGC5, 0							// LPTIMER is bit 0 in SCGC5
__BBREG	BB_SIM_PIT,			SIM_SCGC6, 23							// PIT is bit 23 in SCGC6

__BBREG	BB_GPIOA_LED1,		GPIOA_PDOR, 11							// LED E1 is bit 11 in PDOR
__BBREG	BB_GPIOA_LED2,		GPIOA_PDOR, 28							// LED E2 is bit 28 in PDOR
__BBREG	BB_GPIOA_LED3,		GPIOA_PDOR, 29							// LED E3 is bit 29 in PDOR
__BBREG	BB_GPIOA_LED4,		GPIOA_PDOR, 10							// LED E4 is bit 10 in PDOR
__BBREG	BB_GPIOA_SW1,		GPIOA_PDIR, 19							// SW1 is bit 19 in PDIR

__BBREG	BB_PORTE_ISF,		PORTE_PCR26, 24							// ISF (Interrupt Status Flag) is bit 24 in PCR
__BBREG	BB_GPIOE_SW2,		GPIOE_PDIR, 26							// SW2 is bit 26 in PDIR

__BBREG	BB_LPTMR0_TCF,		LPTMR0_CSR, 7							// TCF (Timer Compare Flag) is bit 7 in CSR

// various constants
.equ IRQ_BITFIELD,			1 << (69 % 32) + 1 << (91 % 32) 		// IRQ 69 and 91, set bits mod 32
.equ OFFSET_IRQ69,			(69 + 0x10) << 2						// add 16 base vectors to IRQ number
.equ OFFSET_IRQ91,			(91 + 0x10) << 2						//  and multiply by 4 byte per vector

.equ INIT_PIT_MCR,			0x0										// MDIS = 0, FRZ = 0
.equ INIT_PIT_TCTRL1,		0b011									// CHN = 0, TIE = 1, TEN = 1

.equ INIT_GPIOA_PDDR,		1 << 10 + 1 << 11 + 1 << 28 + 1 << 29	// set LED pins to output
.equ INIT_PORTA_GPCLR,		(1 << 10 + 1 << 11) << 16 + 1 << 8		// LED 10, 11 -> MUX = 001 = GPIO
.equ INIT_PORTA_GPCHR_LED,	1 << 28 + 1 << 29 + 1 << 8				// LED 28, 29 -> MUX = 001 = GPIO
.equ INIT_PORTA_GPCHR_SW, 	1 << 19 + 1 << 8 + 1 << 1 + 1			// SW1 MUX = 001 = GPIO, PE/PS = internal pullup resistor
.equ INIT_PORTE_PCR26,		1<<24 + 1<<19 + 1<<17 + 1<<8 + 1<<1 + 1	// reset ISF (w1c), IRQC = 1010 = falling edge, MUX = 001 = GPIO, PE/PS = internal pullup resistor

.equ INIT_LPTMR0_CSR,		1 << 7 + 1 << 6 + 1						// TCF = 1, TIE = 1 and TEN = 1
.equ INIT_LPTMR0_PSR,		1										// clock 1 selected

.equ CLK_CNTR,				25000000 - 1							/* clock runs at 25 MHz
																		see K60 sub-family ref manual, p. 1083:
																		LDVAL trigger = (period / clock period) -1 */
.equ DEBOUNCE_DELAY,		5										// 5 ms delay
.equ LF,					0x0a
.equ CHAR_S,				's'
.equ CHAR_UP,				'+'
.equ CHAR_DOWN,				'-'

main:
	bl uart_init

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/

// load some constants
	mov r7, #0					// r7	counter - initial value
	mov r8, #1					// r8	counter increment value
	ldr r9, =mod				// r9	pointer to mod variable
	mov r10, #0					// r10	fixed value of 0 to avoid multiple moves	
	mov r11, #1					// r11	fixed value of 1 to avoid multiple moves

// *************************** configure system integration module *******************************
// configure SIM prior to Interrupts !!!

// enable PIT clock
	ldr r4, =BB_SIM_PIT
	str r11, [r4]

// activate GPIO ports A and E
	ldr r4, =BB_SIM_PORTA
	str r11, [r4]
	
	ldr r4, =BB_SIM_PORTE
	str r11, [r4]

// activate LPTIMER
	ldr r4, =BB_SIM_LPTIMER
	str r11, [r4]

// ******************************* interrupt configuration ********************************************

// load reference to IVT
	ldr r4, =SCR_VTOR
	ldr r5, [r4]

// set interrupt vectors
	ldr r6, =second_isr
	str r6, [r5, #OFFSET_IRQ69]	// IRQ69 each second

	ldr r6, =sw2_isr 
	str r6, [r5, #OFFSET_IRQ91]	// IRQ91 for SW2

// load bitfield for vectors
	ldr r5, =IRQ_BITFIELD

// clear pending interrupts
	ldr r4, =NVIC_ICPR2
	str r5, [r4]

// set_NVIC_SetEnableRegister
	ldr r4, =NVIC_ISER2
	str r5, [r4]

// ************************* configure periodic interrupt timer ***********************************

// set PIT module ControlRegister
	ldr r4, =PIT_MCR
	mov r5, #INIT_PIT_MCR
	str r5, [r4]				// FRZ = 0, continue to run in debug mode - MDIS = 0, clock enabled
	
// set timer LoadValueRegister
	ldr r4, =PIT_LDVAL1
	ldr r5, =CLK_CNTR
	str r5, [r4]

// set timer FlagRegister
	ldr r4, =PIT_TFLG1
	str r11, [r4]				// clear TIF (writing 1 to the flag clears it)

// set timer ControlRegister
	ldr r4, =PIT_TCTRL1
	mov r5, #INIT_PIT_TCTRL1
	str r5, [r4]				// TIE and TEN enabled

// *************************** configure port control *******************************************

// port A low register for LEDs E1 and E4
	// LED 10, 11 = 0x0c00
	// MUX = 001
	ldr r4, =PORTA_GPCLR
	ldr r5, =INIT_PORTA_GPCLR
	str r5, [r4]

// port A high register for LEDs E2 and E3
	// LED 28, 29 =	0x3000
	// MUX = 001
	ldr r4, =PORTA_GPCHR
	ldr r5, =INIT_PORTA_GPCHR_LED
	str r5, [r4]

// according to the schematic, SW1 and SW2 do not have pull-up resistors on the board
// so their behaviour is unpredictable at start-up
// we need to setup internal pullup resistors

// port A high register for SW1
	// SW1 19 =		0x0008
	// MUX = 001
	ldr r4, =PORTA_GPCHR
	ldr r5, =INIT_PORTA_GPCHR_SW	// MUX = 001 = GPIO, PE/PS = internal pullup resistor
	str r5, [r4]

// configure PCR for SW2
	ldr r4, =PORTE_PCR26
	ldr r5, =INIT_PORTE_PCR26		// reset ISF (w1c), IRQC = 1010 = falling edge, MUX = 001 = GPIO, PE/PS = internal pullup resistor
	str r5, [r4]

// *********************************** configure GPIO ports ***********************************	

// configure data direction registers
// GPIO input is reset value of GPIOx_PDDR, no need to configure switches

	ldr r4, =GPIOA_PDDR
	ldr r5,=INIT_GPIOA_PDDR
	str r5, [r4]
	
	ldr r4, =GPIOE_PDDR
	str r10, [r4]
	
// ****************************** configure low power timer ***********************************

// set compare register to 5 ms
	ldr r4, =LPTMR0_CMR
	mov r5, #DEBOUNCE_DELAY
	str r5, [r4]

// set PSR (use LPO clock and bypass prescaler)
	// see p. 140 of K60 reference manual LPO 1 kHz clock: PCS is 01
	ldr r4, =LPTMR0_PSR
	mov r5, #INIT_LPTMR0_PSR	// PBYP (bit 2) = 1, PCS (bits 1-0) = 01
	str r5, [r4]

// enable LPTMR
	ldr r4, =LPTMR0_CSR
	mov r5, #INIT_LPTMR0_CSR
	str r11, [r4]				// sets TEN

/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

loop:
// check if one of the switches is pressed and load mod variable to r5
	bl sw1_set					// set mod for sw1
	bl sw2_set					// set mod for sw2
	ldr r5, [r9]				// load mod to r5

// toggle counter direction if mod = 1
	and r6, r5, #1				// check if mod is 1
	cmp r6, #0
	beq check_mod2				// mod is not 1, continue to check mod 2

	// mod = 1
	sub r8, r10, r8				// toggle increment/decrement
	
	cmp r8, #1					// output to terminal (up/down)
	ite eq
	ldreq r0, =str_up
	ldrne r0, =str_down
	bl uart_putString
	
	bfc r5, #0, #1				// clear mod 1
	str r5, [r9]				// and store

check_mod2:
// toggle active if mod = 2
	and r6, r5, #0x2			// check if mod is 2
	cmp r6, #0
	beq check_terminal_input	// mod is not 2, continue to check terminal input
	
	bfc r5, #1, #1				// clear mod 2
	str r5, [r9]				// and store
	
	b toggle_active				// continue with toggle_active as logic is the same as with the 's' key
	
// check for terminal input
check_terminal_input:
	bl uart_charPresent			// check terminal input
	cmp r0, #0
	beq check_active			// no input: proceed
	
	bl uart_getChar				// receive character from terminal

	cmp r0, #CHAR_S				// check on "s" (start/stop), s = ascii 73
	beq toggle_active
	
	cmp r0, #CHAR_UP			// check on "+" (up), + = ascii 2b
	beq count_up
	
	cmp r0, #CHAR_DOWN			// check on "-" (down), - = ascii 2d
	beq count_down

	b check_active				// no valid character input
	
toggle_active:
	ldr r4, =counterActive		// get status
	ldr r5, [r4]
	cmp r5, #0					// toggle status and load reference to relevant terminal output
	ittee eq
	moveq r5, #1
	ldreq r0, =str_start
	movne r5, #0
	ldrne r0, =str_stop
	
	str r5, [r4]				// store new status
	bl uart_putString			// terminal output of new status
	 
	b check_active
	
count_up:
	mov r8, #1					// set increment register to 1
	ldr r0, =str_up				// and output info to terminal
	bl uart_putString
	b check_active
	
count_down:
	mov r8, #-1					// set increment register to -1
	ldr r0, =str_down			// and output to terminal
	bl uart_putString

// check if counter is active
check_active:
	ldr r4, =counterActive
	ldr r5, [r4]	
	cmp r5, #0
	beq loop					// nothing to do if counter was stopped

// check if second is over
	ldr r4, =flagSecond			// check user flag to see if interrupt was from second-isr
	ldr r5, [r4]
	cmp r5, #0
	beq loop					// nothing to do if second not over

// another second is over
	str r10, [r4]				// user flag reset

// second is over: increment counter
	add r7, r7, r8
	bfc r7, #8, #24				// to avoid overflow to bit 8 as only 8-bit counter is required

// second is over: output counter value to LEDs (lower 4 bits only)
	ldr r4, =BB_GPIOA_LED1		// load memory address of LED E1
	ubfx r5, r7, #0, #1			// select bit 0 of counter
	sub r5, r11, r5				// negate bit
	str r5, [r4]				// store selected bit to LED E1 address
	
	ldr r4, =BB_GPIOA_LED2		// same with bit 1 of counter for LED E2
	ubfx r5, r7, #1, #1
	sub r5, r11, r5
	str r5, [r4]
	
	ldr r4, =BB_GPIOA_LED3		// same with bit 2 of counter for LED E3
	ubfx r5, r7, #2, #1
	sub r5, r11, r5
	str r5, [r4]
	
	ldr r4, =BB_GPIOA_LED4		// same with bit 3 of counter for LED E4
	ubfx r5, r7, #3, #1
	sub r5, r11, r5
	str r5, [r4]
	
// second is over: output counter value to terminal
	mov r4, #8					// counter for 8 bits
	lsl r5, r7, #24				// place relevant 8 counter bits to the left in r5
	
output: 
	lsls r5, r5, #1				// get bit (MSB first)	
	ite cs						// check carry flag after shift operation
	movcs r0, '1'				// output 1 on carry set 
	movcc r0, '0'				// coutput 0 on carry clear
	bl uart_putChar

	subs r4, r4, #1				// check if all 8 bits have been output
	bne output

	mov r0, #LF					// final line feed
	bl uart_putChar

	b loop						// and again
	
/**************************************************************************************************
***************************************************************************************************
***********************************  SUBPROGRAMS  *************************************************
***************************************************************************************************
***************************************************************************************************/

//********************************************** PIT ISR (each second) **************************

.thumb_func
second_isr:
	mov r1, #1
	
	// clear timerFlagRegister
	ldr r0, =PIT_TFLG1
	str r1, [r0]				// clear TIF

	// set userFlag
	ldr r0, =flagSecond
	str r1, [r0]				// user flag set

	bx LR

//******************************************** SW2 ISR ******************************************

.thumb_func
sw2_isr:
	mov r1, #1
	
	// clear interrupt status flag
	ldr r0, =BB_PORTE_ISF
	str r1, [r0]
	
	// set user flag
	ldr r0, =flagSW2
	str r1, [r0]				// user flag set

	bx LR

//******************************************** SW1 mod set *************************************

.thumb_func
sw1_set:
	push {LR}					// subprograms are used (uart_putString)
	
// get SW1 level
	ldr r0, =BB_GPIOA_SW1		// read SW1 logic level
	ldr r1, [r0]				// r1 is 0 if SW1 is currently pressed

// check if SW1 is not pressed (level = 1)
	cmp r1, #1
	ittt eq
	ldreq r2, =lastSW1			// store SW1 level as last level
	streq r1, [r2]
	beq sw1_end					// key not pressed: exit

// SW1 might be pressed (SW1 had level = 1 on first check): wait 5 ms
	ldr r2, =BB_LPTMR0_TCF		// writing 1 to TCF clears it and resets counter
	mov r3, #1
	str r3, [r2]

sw1_debounce:					// wait for TCF to activate
	ldr r3, [r2]
	cmp r3, #0
	beq sw1_debounce

// get SW1 level again and check if key level is still 0
	ldr r1, [r0]				// read SW1 logic level again, r0 still points to PDIR of SW1
	cbnz r1, sw1_end			// exit if key was bouncing

// check on falling edge
	ldr r2, =lastSW1
	ldr r3, [r2]				// r3 holds last SW1 level
	str r1, [r2]				// store SW1 level as last level
	
	cmp r1, r3
	bhs sw1_end					// no falling edge: exit
	
// falling edge detected
	ldr r2, =mod
	ldr r3, [r2]				// set mod to 1
	orr r3, r3, #1
	str r3, [r2]
	
	ldr r0, =str_sw1			// output info to terminal
	bl uart_putString

sw1_end:
	pop {PC}

// ********************************************* SW2 mod set ***********************************

.thumb_func
sw2_set:
	push {LR}					// subprograms are used (uart_putString)
	
	ldr r0, =flagSW2			// check user flag to see if interrupt was from SW2
	ldr r1, [r0]

	cmp r1, #0
	beq sw2_end					// nothing to do if flag is clear

	// flag was set

// SW2 might be pressed: wait 5 ms
	ldr r2, =BB_LPTMR0_TCF		// writing 1 to TCF clears it and resets counter
	mov r3, #1
	str r3, [r2]

sw2_debounce:					// wait for TCF to activate
	ldr r3, [r2]
	cmp r3, #0
	beq sw2_debounce

// get SW2 level
	ldr r2, =BB_GPIOE_SW2		// read SW2 logic level
	ldr r3, [r2]				// r3 is 0 if SW1 is currently pressed

// check if key level is still 0
	cmp r3, #0
	bne sw2_end					// exit as key was bouncing

// SW2 was in fact pressed
	mov r3, #0
	str r3, [r0]				// user flag reset, r0 still points to flagSW2
	
	ldr r2, =mod
	ldr r3, [r2]				// load mod
	orr r3, r3, #0x2			// set 2 to mod
	str r3, [r2]				// and store mod
	
	ldr r0, =str_sw2			// output info to terminal
	bl uart_putString

sw2_end:
	pop {PC}

/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/

/*** Datenbereich (ab 0x20000000) ***/
.data
mod:			.word 0x00		// switches pressed, 1 = SW1 (polling), 2 = SW2 (ISR)
counterActive:	.word 0x01		// indicates if counter is active (1) or not (0)
flagSecond:		.word 0x00		// user flag - is 1 on second interrupt
flagSW2:		.word 0x00		// user flag - is 1 on sw2 interrupt
lastSW1:		.word 0x01		// keeps last valid SW1 level, 1 = not pressed

str_sw1:		.asciz "SW1 gedrueckt. \0"
str_sw2:		.asciz "SW2 gedrueckt. \0"
str_up:			.asciz "Es wird nun hoch gezaehlt.\n"
str_down:		.asciz "Es wird nun herunter gezaehlt.\n"
str_start:		.asciz "Zaehler gestartet.\n"
str_stop:		.asciz "Zaehler gestoppt.\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/


/*******************************************************************************************************

Potentiometer is connected to ADC1_DM1 (K2) and operates on 3.3 V
ADC1_DM1 is assigned to channel AD20 for DIFF=0, see p. 123 of K60 reference manual

******************************************************************************************************/

// register addresses
.equ SIM_SCGC3,				0x40048030								// System Clock Gating 3 for ADC1
.equ SIM_SCGC5,				0x40048038								// System Clock Gating 5 for Port A
.equ SIM_SCGC6,				0x4004803c								// System Clock Gating 6 for PIT

.equ SCR_VTOR,				0xe000ed08								// register for IVT
.equ NVIC_ISER2,			0xe000e100 + 0x2 << 2					// NVIC non-IPR register number is 2
.equ NVIC_ICPR2,			0xe000e280 + 0x2 << 2					//  (integer part of IRQ div 32)

.equ PIT_MCR,				0x40037000								// PIT Module Control Register
.equ PIT_LDVAL1,			PIT_MCR + 0x100 + 16					// PIT1 Load Value register
.equ PIT_TCTRL1,			PIT_MCR + 0x108 + 16					// PIT1 Control register
.equ PIT_TFLG1,				PIT_MCR + 0x10c + 16					// PIT1 Flag Register

.equ PORTA_PCR10,			0x40049028								// Pin Control Register LED E1
.equ PORTA_PCR28,			0x40049070								// Pin Control Register LED E2
.equ PORTA_PCR29,			0x40049074								// Pin Control Register LED E3
.equ PORTA_PCR11,			0x4004902c								// Pin Control Register LED E4
.equ GPIOA_PDDR,			0x400ff014								// Port Data Direction for LEDs
.equ GPIOA_PDOR,			0x400ff000								// port data output registers for LEDs

.equ ADC1_CFG1,				0x400bb008								// ADC configuration register 1
.equ ADC1_CFG2,				0x400bb00c								// ADC configuration register 2
.equ ADC1_SC1A,				0x400bb000								// ADC Status & Control Register 1A
.equ ADC1_SC2,				0x400bb020								// ADC Status & Control Register 2
.equ ADC1_SC3,				0x400bb024								// ADC Status & Control Register 3
.equ ADC1_RA,				0x400bb010								// ADC Data Result Register A
.equ ADC1_CLPS,				0x400bb038								// ADC general calibration register
.equ ADC1_PG,				0x400bb02c								// ADC plus-side gain register
.equ ADC1_OFS,				0x400bb028								// ADC Offset Correction Register

// bit band constants
__BBREG BB_SIM_ADC1,		SIM_SCGC3, 27							// ADC1 is bit 27 in SCGC3
__BBREG BB_SIM_PORTA,		SIM_SCGC5, 9							// PORTA is bit 9 in SCGC5
__BBREG	BB_SIM_PIT,			SIM_SCGC6, 23							// PIT is bit 23 in SCGC6

__BBREG	BB_GPIOA_LED1,		GPIOA_PDOR, 11							// LED E1 is bit 11 in PDOR
__BBREG	BB_GPIOA_LED2,		GPIOA_PDOR, 28							// LED E2 is bit 28 in PDOR
__BBREG	BB_GPIOA_LED3,		GPIOA_PDOR, 29							// LED E3 is bit 29 in PDOR
__BBREG	BB_GPIOA_LED4,		GPIOA_PDOR, 10							// LED E4 is bit 10 in PDOR

__BBREG BB_ADC1_COCO,		ADC1_SC1A, 7							// COCO is set when conversion is completed
__BBREG BB_ADC1_CAL,		ADC1_SC3, 7								// CAL is bit 7 in SC3, starts calibration when set
__BBREG BB_ADC1_CALF,		ADC1_SC3, 6								// CALF is bit 6 in SC3, is clear after successful calibration
__BBREG BB_ADC1_ADCO,		ADC1_SC3, 3								// ADCO, enable/disable continous conversions

// various constants
.equ IRQ_BITFIELD,			1 << (69 % 32)					 		// IRQ 69, set bits mod 32
.equ OFFSET_IRQ69,			(69 + 0x10) << 2						// add 16 base vectors to IRQ number and multiply by 4 byte per vector

.equ INIT_PIT_MCR,			0x0										// MDIS = 0, FRZ = 0
.equ INIT_PIT_TCTRL1,		0b011									// CHN = 0, TIE = 1, TEN = 1

.equ INIT_PORTA_PCRn,		1 << 8									// MUX = 001 = GPIO
.equ INIT_GPIOA_PDDR,		1 << 10 | 1 << 11 | 1 << 28 | 1 << 29	// set LED pins to output

.equ INIT_ADC1_CFG1,		0b01101100								// ADIV=8 (25MHz:8=3.125MHz), MODE=16-bit conversion, ADICLK=Bus Clock
.equ INIT_ADC1_CFG2,		0										// Channels A, no ADACKEN, no ADHSC, default ADLSTS
.equ ENABLE_ADC1_SC1A,		0b0010100								// no interrupt, single-ended mode (DIFF=0), ADCH = AD20 selected as input
.equ DISABLE_ADC1_SC1A,		0b0011111								// no interrupt, single-ended mode (DIFF=0)
.equ INIT_ADC1_SC2,			0x0										// ADTRG = software, no compare, no DMA, REFSEL = default
.equ INIT_ADC1_SC3,			0b00001110								// ADCO = continuous, AVGE = enabled, AVGS = 16 samples
.equ ADCH_MASK,				0b11111									// to disable ADC1 module
.equ CLK_CNTR,				25000000 - 1							/* clock runs at 25 MHz
																		see K60 sub-family ref manual, p. 1083:
																		LDVAL trigger = (period / clock period) -1 */
.equ LF,					0x0a
.equ CHAR_SPACE,			' '
.equ CHAR_DASH,				'-'
.equ CHAR_BRACKET_CLOSE,	')'
.equ CHAR_S,				's'
.equ CHAR_X,				'x'
.equ CHAR_0,				'0'
.equ CHAR_1,				'1'
.equ CHAR_2,				'2'
.equ CHAR_3,				'3'
.equ VOLTAGE,				3300									// Voltage in mV

main:	

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/

	bl uart_init

// load some constants
	mov r9, #16					// r9	resolution in bits, init at 16
	mov r10, #0					// r10	fixed value of 0 to avoid multiple moves	
	mov r11, #1					// r11	fixed value of 1 to avoid multiple moves

// *************************** configure system integration module *******************************

// enable PIT clock
	ldr r0, =BB_SIM_PIT
	str r11, [r0]

// activate GPIO port A
	ldr r0, =BB_SIM_PORTA
	str r11, [r0]

// activate ADC1
	ldr r0, =BB_SIM_ADC1
	str r11, [r0]
	
// ******************************* interrupt configuration ********************************************

// load reference to IVT
	ldr r0, =SCR_VTOR
	ldr r1, [r0]

// set interrupt vector
	ldr r0, =second_isr
	str r0, [r1, #OFFSET_IRQ69]	// IRQ69 each second

// load bitfield for vectors
	ldr r0, =IRQ_BITFIELD

// clear pending interrupts
	ldr r1, =NVIC_ICPR2
	str r0, [r1]

// set_NVIC_SetEnableRegister
	ldr r1, =NVIC_ISER2
	str r0, [r1]

// ************************* configure periodic interrupt timer ***********************************

// set PIT module ControlRegister
	ldr r0, =PIT_MCR
	mov r1, #INIT_PIT_MCR
	str r1, [r0]				// FRZ = 0, continue to run in debug mode - MDIS = 0, clock enabled
	
// set timer LoadValueRegister
	ldr r0, =PIT_LDVAL1
	ldr r1, =CLK_CNTR
	str r1, [r0]

// set timer FlagRegister
	ldr r0, =PIT_TFLG1
	str r11, [r0]				// clear TIF (writing 1 to the flag clears it)

// set timer ControlRegister
	ldr r0, =PIT_TCTRL1
	mov r1, #INIT_PIT_TCTRL1
	str r1, [r0]				// TIE and TEN enabled

// *************************** configure port control *******************************************

// set MUX = 001 = GPIO for LEDs E1 to E4
	mov r0, #INIT_PORTA_PCRn

	ldr r1, =PORTA_PCR10
	str r0, [r1]
	
	ldr r1, =PORTA_PCR28
	str r0, [r1]

	ldr r1, =PORTA_PCR29
	str r0, [r1]

	ldr r1, =PORTA_PCR11
	str r0, [r1]

// *********************************** configure GPIO ports ***********************************	

// configure data direction registers
	ldr r0, =GPIOA_PDDR
	ldr r1, [r0]
	ldr r2, =INIT_GPIOA_PDDR		// PCR 10, 11, 28, 29 set
	orr r1, r1, r2
	str r1, [r0]

// ************************************ calibrate ADC ******************************************

calibrate:
	mov r0, r9						// put resolution in bits in r0 as parameter for calibrate_ADC1
	bl calibrate_ADC1				// call calibration function, returns calibration result CALF in r0 
	cmp r0, #0
	bne calibrate					// repeat calibration in case of failure

// ************************************ initialise ADC1 *****************************************

// set configuration registers CFG1 and CFG2
	ldr r0, =ADC1_CFG1
	mov r1, #INIT_ADC1_CFG1			// ADIV=8 (25MHz:8=3.125MHz), MODE=16-bit conversion, ADICLK=Bus Clock
	str r1, [r0]

	ldr r0, =ADC1_CFG2
	mov r1, #INIT_ADC1_CFG2			// Channels A, no ADACKEN, no ADHSC, default ADLSTS
	str r1, [r0]

// set status and control register SC2
	ldr r0, =ADC1_SC2
	mov r1, #INIT_ADC1_SC2			// ADTRG = software, no compare, no DMA, REFSEL = default
	str r1, [r0]

// set status and control register SC3
	ldr r0, =ADC1_SC3
	mov r1, #INIT_ADC1_SC3			// ADCO = continuous, AVGE = enabled, AVGS = 16 samples
	str r1, [r0]
 
// set status and control registers SC1n (SC1A to be used for software trigger operation)
	// (writing to SC1A also clears COCO)
	ldr r0, =ADC1_SC1A
	mov r1, #ENABLE_ADC1_SC1A			// no interrupt, single-ended mode, ADCH = AD20 selected as input
	str r1, [r0]


/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

loop:
// check for terminal input
	bl uart_charPresent			// check terminal input
	cmp r0, #0
	beq check_active			// no input: proceed
	
	bl uart_getChar				// receive character from terminal

	cmp r0, #CHAR_S				// check on "s" (start/stop)
	beq toggle_active
	
	cmp r0, #CHAR_0				// check if input is 0
	ittt eq
	moveq r4, #0b00				// MODE is '00'
	moveq r5, #8				// 8 bit resolution
	beq change_resolution		// continue
	
	cmp r0, #CHAR_1				// check if input is 1
	ittt eq
	moveq r4, #0b10				// MODE is '10'
	moveq r5, #10				// 10 bit resolution
	beq change_resolution		// continue
	
	cmp r0, #CHAR_2				// check if input is 2
	ittt eq
	moveq r4, #0b01				// MODE is '01'
	moveq r5, #12				// 12 bit resolution
	beq change_resolution		// continue
	
	cmp r0, #CHAR_3				// check if input is 3
	ittt eq
	moveq r4, #0b11				// MODE is '11'
	moveq r5, #16				// 16 bit resolution
	beq change_resolution		// continue
	
// invalid character
	ldr r0, =str_inputError		// send error message to terminal
	bl uart_putString
	
	b check_active

toggle_active:
	ldr r1, =ADC1_SC1A			// load input channel ADCH
	ldr r2, [r1]
	
	mov r3, #ADCH_MASK			// mask to get ADCH from SC1A
	and r2, r2, r3
	
	cmp r2, r3					// toggle status and load reference to relevant terminal output
	ittee eq
	ldreq r0, =str_start
	ldreq r2, =ENABLE_ADC1_SC1A	// no interrupt, single-ended mode, ADCH = AD20 selected as input
	ldrne r0, =str_stop
	ldrne r2, =DISABLE_ADC1_SC1A// no interrupt, single-ended mode, ADCH = 11111, input disabled

	str r2, [r1]
	bl uart_putString			// terminal output of new status

	b check_active

change_resolution:
	// check status
	ldr r0, =ADC1_SC1A			// load input channel ADCH
	ldr r1, [r0]
	
	mov r2, #ADCH_MASK			// mask to get ADCH
	and r1, r1, r2
	
	cmp r1, r2					// check if input channel is disabled (stop mode)
	it ne
	bne invalid_mode			// leave, if not in stop mode

	// set number of bits
	mov r9, r5					// r5 holds preliminary number of bits, now, as status is stop mode, updated to r9
	
	// update MODE in ADC1_CFG1
	ldr r0, =ADC1_CFG1
	ldr r1, [r0]
	bfi r1, r4, #2, #2			// update bits 3-2 of CFG1 with MODE from r4
	str r1, [r0]
		
	// send info to terminal
	ldr r0, =str_change
	bl uart_putString
	mov r0, r9
	bl uart_putByteBase10
	ldr r0, =str_bits
	bl uart_putString	
	
	b check_active

invalid_mode:
	ldr r0, =str_modeError		// send error message to terminal
	bl uart_putString
	
	b check_active

check_active:
	
// check if second is over
	ldr r0, =flagSecond			// check user flag to see if interrupt was from second-isr
	ldr r1, [r0]
	cmp r1, #0
	beq loop					// nothing to do if second not over

// another second is over, reset user flag
	str r10, [r0]				// user flag reset

// check if active
	ldr r0, =ADC1_SC1A			// load input channel ADCH
	ldr r1, [r0]
	
	mov r2, #ADCH_MASK			// mask to get ADCH
	and r1, r1, r2
	
	cmp r1, r2
	beq loop					// start new loop if inactive

/***** a second is over and conversion is activated => ready for measurement and output *****/

// status is active, read ADC1
	ldr r0, =ADC1_RA
	ldr r4, [r0]				// measurement in r4
	
// calculate range number and store in r7, number of ranges N = resolution in bits
	// => HEX-Value / 2^N * N
	mul r7, r4, r9				// multiply measurement by number of bits and store result to r7
	lsr r7, r7, r9				// divide r7 by 2^number of bits

// calculate voltage range floor
	// => voltage range floor = voltage x range# / N
	ldr r0, =VOLTAGE
	mul r5, r0, r7				// r5 <= range number * voltage
	udiv r5, r5, r9				// r5 <= range number * voltage / number of ranges

	cmp r7, #0					// if range number is not 0 ... 
	it ne
	addne r5, r5, #1			// ... add 1 mV to have an output floor(N) > ceiling(N-1)

// calculate voltage range ceiling
	// => voltage range ceiling = voltage x (range# + 1) / N
	add r1, r7, #1				// increment range#
	mul r6, r0, r1				// r6 <= (range number + 1) * voltage
	udiv r6, r6, r9				// r6 <= (range number + 1) * voltage / number of ranges
	
// output to LEDs
	ldr r0, =BB_GPIOA_LED1		// load memory address of LED E1
	ubfx r1, r7, #0, #1			// select bit 0 of range
	eor r1, r1, r11				// negate bit
	str r1, [r0]				// store selected bit to LED E1 address
	
	ldr r0, =BB_GPIOA_LED2		// same with bit 1 of range for LED E2
	ubfx r1, r7, #1, #1
	eor r1, r1, r11				// negate bit
	str r1, [r0]
	
	ldr r0, =BB_GPIOA_LED3		// same with bit 2 of range for LED E3
	ubfx r1, r7, #2, #1
	eor r1, r1, r11				// negate bit
	str r1, [r0]
	
	ldr r0, =BB_GPIOA_LED4		// same with bit 3 of range for LED E4
	ubfx r1, r7, #3, #1
	eor r1, r1, r11				// negate bit
	str r1, [r0]

// output to terminal
	mov r0, #CHAR_0
	bl uart_putChar				// 0
	mov r0, #CHAR_X
	bl uart_putChar				// x
	mov r0, r4
	bl uart_putInt16			// measured value

	mov r0, #CHAR_SPACE
	bl uart_putChar				// space
	mov r0, r5
	bl output_bigInt			// range floor
	mov r0, #CHAR_SPACE
	bl uart_putChar				// space
	mov r0, #CHAR_DASH
	bl uart_putChar				// -
	mov r0, #CHAR_SPACE
	bl uart_putChar				// space
	mov r0, r6
	bl output_bigInt			// range ceiling
	ldr r0, =str_mV_stufe
	bl uart_putString			// mV (Stufe
	mov r0, r7
	bl uart_putByteBase10		// range number
	mov r0, #CHAR_BRACKET_CLOSE
	bl uart_putChar				// )	
	mov r0, #LF
	bl uart_putChar

	b loop						// and again

/**************************************************************************************************
***************************************************************************************************
***********************************  SUBPROGRAMS  *************************************************
***************************************************************************************************
***************************************************************************************************/

//********************************************** PIT ISR (each second) **************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagSecond' set
second_isr:
	mov r1, #1
	
	// clear timerFlagRegister
	ldr r0, =PIT_TFLG1
	str r1, [r0]					// clear TIF

	// set userFlag
	ldr r0, =flagSecond
	str r1, [r0]					// user flag set

	bx LR

//********************************************** calibrate ADC1 **********************************

.thumb_func
	// parameter: r0 - resolution in bits
	// return: calibration result (CALF) in r0
calibrate_ADC1:
	push {r4, r5, LR}				// r4 is used to store resolution in bits, r5 holds return value temporarily
	
// ******************************* perform automatic calibration
	// store parameter 'resolution in bits' in r4
	mov r4, r0

	// output info to terminal
	ldr r0, =str_startCalib
	bl uart_putString

	// setting CAL starts calibration
	ldr r0, =BB_ADC1_CAL
	mov r1, #1
	str r1, [r0]

	// load reference to COCO (read-only), COCO will be set at completion
	// (COCO was cleared during initialisation by writing to SC1A)
	ldr r0, =BB_ADC1_COCO

	// wait for COCO to set
autoCalibration_not_completed:
	ldr r1, [r0]
	cmp r1, #0
	it eq
	beq autoCalibration_not_completed

	// automatic calibration is now completed, output info to terminal
	ldr r0, =str_autoCalib
	bl uart_putString

// ********************************** write calibration gain register

	// 1. Initialize or clear a 16-bit variable in RAM.
	// (r2 is used instead of the 16-bit variable according to the calibration procedure)
	
			/***** nothing to do in this step, r2 will be initialised in step 2 *****/
	
	// 2. Add the plus-side calibration results CLP0, CLP1, CLP2, CLP3, CLP4, and CLPS to the variable.
	// (as we use single-sided mode, we can ignore minus-side calibration)
	// (results are placed in memory starting at ADC1_CLPS address and then in 5 subsequent words)
	ldr r0, =ADC1_CLPS				// get pointer to CLPS
	ldr r2, [r0], #4				// get CLPS into r2
	
	ldr r1, [r0], #4				// get CLP4
	add r2, r2, r1					// and add to r2
	ldr r1, [r0], #4				// get CLP3
	add r2, r2, r1					// and add to r2
	ldr r1, [r0], #4				// get CLP2
	add r2, r2, r1					// and add to r2
	ldr r1, [r0], #4				// get CLP1
	add r2, r2, r1					// and add to r2
	ldr r1, [r0]					// get CLP0
	add r2, r2, r1					// and add to r2

	// 3. Divide the variable by two.
	lsr r2, r2, #1

	// 4. Set the MSB of the variable.
	// (as variable should be 16-bit, MSB is bit 15)
	mov r0, 1 << 15
	orr r2, r2, r0

	// 5. Store the value in the plus-side gain calibration register PG.
	ldr r0, =ADC1_PG
	str r2, [r0]

// ****************************** output and return

	// PG register is now written, output some info to terminal
	ldr r0, =str_PGstored
	bl uart_putString
	
	ldr r1, =ADC1_PG
	ldr r0, [r1]
	bl uart_putInt32

	mov r0, #CHAR_SPACE
	bl uart_putChar

	mov r0, #CHAR_DASH
	bl uart_putChar

	mov r0, #CHAR_SPACE
	bl uart_putChar

	ldr r0, =str_OFS
	bl uart_putString

	ldr r1, =ADC1_OFS
	ldr r0, [r1]
	bl uart_putInt32

	mov r0, #LF
	bl uart_putChar
	
	// read CALF
	ldr r1, =BB_ADC1_CALF
	ldr r5, [r1]					// put CALF to r5 as return value

	cmp r5, #0
	ite eq
	ldreq r0, =str_calibrated
	ldrne r0, =str_calibError
	bl uart_putString
		
	ldr r0, =str_init
	bl uart_putString
	
	mov r0, r4						// get resolution in bits from r4
	bl uart_putByteBase10
	
	ldr r0, =str_bits
	bl uart_putString

	// return
	mov r0, r5						// return CALF value to main program
	pop {r4, r5, PC}

//**************************************** output big integer numbers ******************************

.thumb_func
	// parameter: 32 bit word in r0
	// return: none, only output to terminal
output_bigInt:
	push {r4, LR}					// r4 used to count number of digits on stack
	
	mov r2, #100					// preload divisor	
	mov r4, #0						// count number of digits on stack in r4
	
put_digits:
	// divide input number repeatedly by #100
	// put remainder on stack for output in LIFO order
	// repeat with integer part of division until integer part becomes zero 
	mov r1, r0
	udiv r0, r0, r2					// integer part of division in r0
	mls r1, r0, r2, r1				// remainder in r1
	
	cmp r0, #0						// if there is more to come (integer part not yet 0) ...
	ittt ne
	pushne {r1}						// ... put digit to stack, last digit is not put, but kept in r1!
	addne r4, r4, #1				// increment number of digits on stack
	bne put_digits					// repeat
	
	// get digits from stack
	mov r0, r1						// take most significant output digit from r1 (not from stack)
	ldr r1, =uart_putByteBase10		// and prepare to output without leading 0 in any case
	beq write_digits				// continue with output
	
get_digits:							// only for digits after the most significant one
	pop {r0}						// get digit from stack
	sub r4, r4, #1					// decrement number of digits on stack
	
	cmp r0, #10						// add leading 0 if number < 10
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	
write_digits:
	blx r1							// output digit in specified format
	
	cmp r4, #0						// if there are more digits on stack ...
	bne get_digits					// ... continue
	
	pop {r4, PC}					// ... else return

/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/

/*** Datenbereich (ab 0x20000000) ***/
.data
flagSecond:		.word 0x00		// user flag - is 1 on second interrupt
str_startCalib:	.asciz "Kalibrierung gestartet.\n"
str_autoCalib:	.asciz "Automatische Kalibrierung durchgefuehrt (COCO = 1).\n"
str_PGstored:	.asciz "PG Register gespeichert: "
str_OFS:		.asciz "Offset (OFS) ist: "
str_calibrated:	.asciz "Kalibrierung erfolgreich durchgefuehrt (CALF = 0).\n"
str_mV_stufe:	.asciz " mV (Stufe "
str_init:		.asciz "Genauigkeit initialisiert mit "
str_change:		.asciz "Genauigkeit geaendert in "
str_bits:		.asciz " Bits.\n"
str_start:		.asciz "Wandlung und Ausgabe gestartet.\n"
str_stop:		.asciz "Wandlung und Ausgabe gestoppt.\n"
str_inputError:	.asciz "*** Fehler ***: Ungueltiges Zeichen eingegeben.\n"
str_modeError:	.asciz "*** Fehler ***: Die Genauigkeit kann nur im Stopp-Modus geaendert werden.\n"
str_calibError:	.asciz "*** Fehler ***: Die Kalibrierung war nicht erfolgreich.\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/


/******************************************************************************

Das Thermometer DS75 kann mit einer maximalen Geschwindigkeit von 400 kHz betrieben werden
(SCL Frequency fSCL = max 400 kHz, siehe S. 5 des Datenblatts).

Für das I2C-Modul ergibt sich mit den Einstellungen für das Register I2C0_F mit MUL = 1 und ICR = 0x00
ein minimaler Divisor von 20. Dies bedeutet, dass das I2C-Modul mit maximal
25 MHz / 20 = 1,25 MHz, also maximal im Fast Mode Plus, betrieben werden kann.

Verwendet wird also eine Busfrequenz von 400 kHz. Hierzu muss im Register I2C0_F ein Divisor
von >= 62,5 (25 MHz : 400 kHz) eingestellt werden.
Diesem Wert kommt man mit folgenden Einstellungen nahe: (s. Table 51-41 des Reference Manuals)
Variante 1: MUL = 1, ICR = 0x12 => SCL divider = 64
Variante 2: MUL = 2, ICR = 0x09 => SCL divider = 32
Die SCL/SDA hold values unterscheiden sich wie folgt:
Variante 1:	SDA hold time:			13 x 1 / 25 MHz =  520 ns
			SCL hold (start) time:	26 x 1 / 25 MHz = 1040 ns
			SCL hold (stop) time:	33 x 1 / 25 MHz = 1320 ns
Variante 2:	SDA hold time:			 7 x 2 / 25 MHz =  560 ns
			SCL hold (start) time:	12 x 2 / 25 MHz =  960 ns
			SCL hold (stop) time:	17 x 2 / 25 MHz = 1360 ns
Ich entscheide mich für Variante 1 (MUL = 1, SCL divider = 64), da hier die SDA hold time
etwas kuerzer ist.

-----------------

Die LED auf der Themometerplatine leuchtet bei Ueberschreiten der Temperatur TOS und erlischt
anschliessend wieder bei Unterschreiten der Temperatur THYST.

******************************************************************************/

// register addresses
.equ SIM_SCGC4,				0x40048034								// System clock gating 4 for I2C
.equ SIM_SCGC6,				0x4004803c								// System Clock Gating 6 for PIT

.equ SCR_VTOR,				0xe000ed08								// register for IVT
.equ NVIC_ISER2,			0xe000e100 + 0x2 << 2					// NVIC non-IPR register number is 2
.equ NVIC_ICPR2,			0xe000e280 + 0x2 << 2					//  (integer part of IRQ div 32)

.equ PIT_MCR,				0x40037000								// PIT Module Control Register
.equ PIT_LDVAL1,			PIT_MCR + 0x100 + 16					// PIT1 Load Value register
.equ PIT_TCTRL1,			PIT_MCR + 0x108 + 16					// PIT1 Control register
.equ PIT_TFLG1,				PIT_MCR + 0x10c + 16					// PIT1 Flag Register

/************************************************
!!! I2C registers have a width of 8 bits only !!!
************************************************/
.equ I2C0_A1,				0x40066000								// I2C address reg
.equ I2C0_F,				0x40066001								// I2C frequency divider reg
.equ I2C0_C1,				0x40066002								// I2C control reg 1
.equ I2C0_S,				0x40066003								// I2C status reg
.equ I2C0_D,				0x40066004								// I2C data i/o reg
.equ I2C0_C2,				0x40066005								// I2C control reg 2
.equ I2C0_FLT,				0x40066006								// I2C glitch filter reg
.equ I2C0_RA,				0x40066007								// I2C range address reg
.equ I2C0_SMB,				0x40066008								// I2C SMBus Control & Status reg
.equ I2C0_A2,				0x40066009								// I2C address reg 2
.equ I2C0_SLTH,				0x4006600a								// I2C low timout reg high
.equ I2C0_SLTL,				0x4006600b								// I2C low timout reg low

// bit band constants
__BBREG BB_SIM_I2C0,		SIM_SCGC4, 6							// I2C0 is bit 6 in SCGC4
__BBREG	BB_SIM_PIT,			SIM_SCGC6, 23							// PIT is bit 23 in SCGC6

__BBREG BB_I2C0_BUSY,		I2C0_S, 5								// Bus Busy, 0 = idle, 1 = busy
__BBREG BB_I2C0_IICIF,		I2C0_S, 1								// Interrupt Flag, 1 = IR pending
__BBREG BB_I2C0_MST,		I2C0_C1, 5								// Master mode Select, 1 = master mode
__BBREG BB_I2C0_TX,			I2C0_C1, 4								// Transmit mode (0 = RX, 1 = TX)
__BBREG BB_I2C0_TXAK,		I2C0_C1, 3								// TX Ackn. Enable (0 = ACK, 1 = NACK)
__BBREG BB_I2C0_RSTA,		I2C0_C1, 2								// 1 = repeat start

// various constants
.equ IRQ_BITFIELD,			1 << (69 % 32)					 		// IRQ 69, set bits mod 32
.equ OFFSET_IRQ69,			(69 + 0x10) << 2						// add 16 base vectors to IRQ number and multiply by 4 byte per vector

.equ INIT_PIT_MCR,			0x0										// MDIS = 0, FRZ = 0
.equ INIT_PIT_TCTRL1,		0x03									// CHN = 0, TIE = 1, TEN = 1

/*
	I2C0_F set to 0x12 => MULT = 1, ICR = 64
	I2C baud rate = bus speed / (MULT x ICR)
	25.000.000 / (1 x 64) => 390.625 bps
	==> bus frequency 390.625 Hz
*/

.equ INIT_I2C0_A1,			0x0
.equ INIT_I2C0_F,			0x12									// MUL = 1, ICR = 12 => divisor = 64
.equ INIT_I2C0_C1,			0x80									// IICEN = 1, slave mode on start
.equ INIT_I2C0_S,			0x92									// TCF=1, clear ARBL and IICIF
.equ INIT_I2C0_C2,			0x0
.equ INIT_I2C0_FLT,			0x0
.equ INIT_I2C0_RA,			0x0
.equ INIT_I2C0_SMB,			0x6										// clear SLTF and SHTF2
.equ INIT_I2C0_A2,			0xc2									// reset value of SMBus address
.equ INIT_I2C0_SLTH,		0x0
.equ INIT_I2C0_SLTL,		0x0

.equ DS75_W,				0x90									// DS75 address
.equ DS75_R,				0x91

.equ ONE_SECOND,			25000000 - 1							/* clock runs at 25 MHz
																		see K60 sub-family ref manual, p. 1083:
																		LDVAL trigger = (period / clock period) -1 */
.equ TWO_MICROSECONDS,		50										// 2 x 10^-6 x 25 x 10^6
.equ MAX_CONV_TIME,			30000000								// max conversion time of DS75, 1200x10^-3 x 25x10^6

.equ CHAR_SPACE,			' '
.equ CHAR_COLON,			':'
.equ CHAR_COMMA,			','

main:	

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/

	bl uart_init

// load some constants
	mov r10, #0					// r10	fixed value of 0 to avoid multiple moves	
	mov r11, #1					// r11	fixed value of 1 to avoid multiple moves

// *************************** configure system integration module *******************************

// enable PIT clock
	ldr r0, =BB_SIM_PIT
	str r11, [r0]

// enable I2C0 clock
	ldr r0, =BB_SIM_I2C0
	str r11, [r0]

// ******************************* interrupt configuration ********************************************

// load reference to IVT
	ldr r0, =SCR_VTOR
	ldr r1, [r0]

// set interrupt vector
	ldr r0, =second_isr
	str r0, [r1, #OFFSET_IRQ69]	// IRQ69 each second

// load bitfield for vectors
	ldr r0, =IRQ_BITFIELD

// clear pending interrupts
	ldr r1, =NVIC_ICPR2
	str r0, [r1]

// set_NVIC_SetEnableRegister
	ldr r1, =NVIC_ISER2
	str r0, [r1]

// ************************* configure periodic interrupt timer ***********************************

// set PIT module ControlRegister
	ldr r0, =PIT_MCR
	mov r1, #INIT_PIT_MCR
	str r1, [r0]				// FRZ = 0, continue to run in debug mode - MDIS = 0, clock enabled
	
// set timer LoadValueRegister
	ldr r0, =PIT_LDVAL1
	ldr r1, =ONE_SECOND
	str r1, [r0]

// set timer FlagRegister
	ldr r0, =PIT_TFLG1
	str r11, [r0]				// clear TIF (writing 1 to the flag clears it)

// set timer ControlRegister
	ldr r0, =PIT_TCTRL1
	mov r1, #INIT_PIT_TCTRL1
	str r1, [r0]				// TIE and TEN enabled

// *********************************** configure I2C0 ***********************************	

	ldr r0, =I2C0_A1
	mov r1, #INIT_I2C0_A1
	strb r1, [r0]
	
	ldr r0, =I2C0_F
	mov r1, #INIT_I2C0_F
	strb r1, [r0]
	
	ldr r0, =I2C0_C1
	mov r1, #INIT_I2C0_C1
	strb r1, [r0]
	
	ldr r0, =I2C0_S
	mov r1, #INIT_I2C0_S
	strb r1, [r0]
	
	ldr r0, =I2C0_C2
	mov r1, #INIT_I2C0_C2
	strb r1, [r0]
	
	ldr r0, =I2C0_FLT
	mov r1, #INIT_I2C0_FLT
	strb r1, [r0]
	
	ldr r0, =I2C0_RA
	mov r1, #INIT_I2C0_RA
	strb r1, [r0]
	
	ldr r0, =I2C0_SMB
	mov r1, #INIT_I2C0_SMB
	strb r1, [r0]
	
	ldr r0, =I2C0_A2
	mov r1, #INIT_I2C0_A2
	strb r1, [r0]
	
	ldr r0, =I2C0_SLTH
	mov r1, #INIT_I2C0_SLTH
	strb r1, [r0]
	
	ldr r0, =I2C0_SLTL
	mov r1, #INIT_I2C0_SLTL
	strb r1, [r0]

/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

// reset I2C bus
	bl I2CBus_Reset					// returns 1 in r0 on successful reset
	cmp r0, #1
	bne error						// terminate in case of unsuccessful bus reset

// set resolution of DS75 to 12 bit
	mov r0, #1						// write to configuration register (P1=0, P0=1)
	mov r1, #0x60					// 12-bit resolution, R1 and R0 of DS75 set
	bl write_1b_to_ds75

// wait 1200 ms for max conversion time of DS75 to get initial temperature value
	ldr r0, =(MAX_CONV_TIME + 2) / 3	// subs = 1 clock, bne = min 2 clocks ==> 3 clocks per loop, rounded
ds75_wait_loop:
	subs r0, r0, #1
	bne ds75_wait_loop	

// read initial temperature T0
	mov r0, #0						// read from temperature register (P1=0, P0=0)
	bl read_2b_from_ds75_new_pointer
	mov r4, r0 						// save initial temperature to r4 (format: 0x00MMLL00)

// output of T0
	ldr r0, =str_t0
	bl uart_putString
	
	mov r0, r4
	bl uart_putInt32

	mov r0, #0x0a
	bl uart_putChar

// write TOS to configuration register
	mov r0, #3						// write to TOS register (P1=1, P0=1)
	ubfx r1, r4, #16, #8			// put MSB of T0 in r1
	add r1, r1, #3					// increase MSB by 3
	ubfx r2, r4, #8, #8				// put LSB of T0 in r2
	bl write_2b_to_ds75

// output of TOS register
	ldr r0, =str_tos
	bl uart_putString
	
	bl read_2b_from_ds75_current_pointer		// read back to check
	bl uart_putInt32

	mov r0, #0x0a
	bl uart_putChar

// write THYST to configuration register
	mov r0, #2						// write to THYST register (P1=1, P0=0)
	ubfx r1, r4, #16, #8			// out MSB of T0 in r1
	add r1, r1, #2					// increase MSB by 2
	ubfx r2, r4, #8, #8				// put LSB of T0 in r2
	bl write_2b_to_ds75

// output of THYST register
	ldr r0, =str_thyst
	bl uart_putString
	
	bl read_2b_from_ds75_current_pointer		// read back to check
	bl uart_putInt32

	mov r0, #0x0a
	bl uart_putChar

// dummy read of temperature to set pointer to temperature register of DS75 for mainloop
	mov r0, #0						// read from temperature register (P1=0, P0=0)
	bl read_2b_from_ds75_new_pointer

mainloop:
	
// check if second is over
	ldr r0, =flagSecond				// check user flag to see if interrupt was from second-isr
	ldr r1, [r0]
	cmp r1, #0
	beq mainloop					// nothing to do if second not over

// another second is over, reset user flag
	str r10, [r0]					// user flag reset

	bl read_2b_from_ds75_current_pointer	// read temperature from DS75, result is in r0
	bl output_temp_to_terminal		// temperature output from r0 to terminal
		
	b mainloop						// and again
	
error:
	ldr r0, =str_error
	bl uart_putString
	
end:
	b end

/**************************************************************************************************
***************************************************************************************************
***********************************  SUBPROGRAMS  *************************************************
***************************************************************************************************
***************************************************************************************************/

//******************************** output of temperature data ************************************

.thumb_func
	// parameter: temperature in r0 (MSB and LSB) (format: 0x00MMLL00)
	// return: none, only terminal
output_temp_to_terminal:
	push {r4, LR}
	
	mov r4, r0
	ldr r0, =str_0x
	bl uart_putString			// 0x

	mov r0, r4
	bl uart_putInt32			// MSB and LSB hex

	mov r0, #CHAR_COLON
	bl uart_putChar				// :
	
	mov r0, #CHAR_SPACE
	bl uart_putChar				// space

	ubfx r0, r4, #16, #8		// get MSB from input word
	bl uart_putByteBase10		// MSB dec
	
	mov r0, #CHAR_COMMA
	bl uart_putChar				// ,
	
	ldr r0, =625				// 0,0625 seconds per bit
	ubfx r1, r4, #12, #4		// get LSB from input word - only 4 bits are significant
	mul r0, r0, r1				// multiply by 625
	mov r1, #100
	udiv r0, r0, r1				// divide by 100
	
	cmp r0, #10
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1						// LSB dec, with leading 0 if necessary

	ldr r0, =str_celsius
	bl uart_putString			// Grad Celsius

	pop {r4, PC}

//******************************** read 2 bytes from DS75 with new pointer byte ************************************

.thumb_func
	// parameter: pointer byte in r0
	// return: MSB and LSB in r0 (format: 0x00MMLL00)
read_2b_from_ds75_new_pointer:
	push {r4, LR}
	
	mov r4, r0				// save pointer byte to r4
	ldr r1, =BB_I2C0_IICIF	// reset interrupt flag
	mov r0, #1
	strb r0, [r1]

	bl set_tx_mode			// set transmit mode
	bl set_start_cond		// set master mode and send START signal

	mov r0, #DS75_W			// write slave write address to bus
	bl write_data			// write address and wait for iicif to set

	mov r0, r4				// move pointer byte to r0
	bl write_data			// write pointer byte

	bl set_rep_start		// send repeat start condition to bus

	mov r0, #DS75_R			// write slave read address to bus
	bl write_data			// write address and wait for iicif to set

	bl set_rx_mode			// set receive mode
	bl set_mst_ack			// set ACK as master response to received data

	bl read_data			// dummy read from D to r0, MSB is in D now
	bl wait_for_iicif		// wait for read to complete

	bl set_mst_nack			// set NACK as master response after LSB

	bl read_data			// MSB from D to r0, LSB is in D now
	mov r4, r0				// generate output data in r4
	lsl r4, r4, #8			// shift MSB to the left
	bl wait_for_iicif		// wait for read to complete
	
	bl set_stop_cond		// set slave mode and send STOP signal

	bl read_data			// LSB from D to r0
	
	bfi r4, r0, #0, #8		// add LSB to output register
	lsl r4, r4, #8			// shift output to the left to achieve format 0x00MMLL00
	mov r0, r4				// output

	pop {r4, PC}

//************************ read 2 bytes from DS75 from current pointer location ***************************

.thumb_func
	// parameter: none - current pointer location is used
	// return: MSB and LSB in r0 (format: 0x00MMLL00)
read_2b_from_ds75_current_pointer:
	push {r4, LR}
	
	ldr r1, =BB_I2C0_IICIF	// reset interrupt flag
	mov r0, #1
	strb r0, [r1]

	bl set_tx_mode			// set transmit mode
	bl set_start_cond		// set master mode and send START signal

	mov r0, #DS75_R			// write slave read address to bus
	bl write_data			// write address and wait for iicif to set

	bl set_rx_mode			// set receive mode
	bl set_mst_ack			// set ACK as master response to received data

	bl read_data			// dummy read from D to r0, MSB is in D now
	bl wait_for_iicif		// wait for read to complete

	bl set_mst_nack			// set NACK as master response after LSB

	bl read_data			// MSB from D to r0, LSB is in D now
	mov r4, r0				// generate output data in r4
	lsl r4, r4, #8			// shift MSB to the left
	bl wait_for_iicif		// wait for read to complete
	
	bl set_stop_cond		// set slave mode and send STOP signal

	bl read_data			// LSB from D to r0
	
	bfi r4, r0, #0, #8		// add LSB to output register
	lsl r4, r4, #8			// shift output to the left to achieve format 0x00MMLL00
	mov r0, r4				// output

	pop {r4, PC}

//************************** write single byte to DS75 register ****************************

.thumb_func
	// parameter: pointer byte in r0, data byte in r1
	// return: none
write_1b_to_ds75:
	push {r4, r5, LR}
	
	mov r4, r0				// save parameters
	mov r5, r1
	ldr r1, =BB_I2C0_IICIF	// reset interrupt flag
	mov r0, #1
	strb r0, [r1]

	bl set_tx_mode			// set transmit mode
	bl set_start_cond		// set master mode and send START signal

	mov r0, #DS75_W			// set slave write address
	bl write_data			// write slave WRITE address to bus

	mov r0, r4				// set pointer byte
	bl write_data			// write pointer byte to bus

	mov r0, r5				// set data byte
	bl write_data			// write data byte to bus

	bl set_stop_cond		// set slave mode and send STOP signal

	pop {r4, r5, PC}

//************************** write 2 bytes to DS75 register ****************************

.thumb_func
	// parameter: pointer byte in r0, MSB data byte in r1, LSB data byte in r2
	// return: none
write_2b_to_ds75:
	push {r4, r5, r6, LR}
	
	mov r4, r0				// save parameters
	mov r5, r1
	mov r6, r2
	ldr r1, =BB_I2C0_IICIF	// reset interrupt flag
	mov r0, #1
	strb r0, [r1]

	bl set_tx_mode			// set transmit mode
	bl set_start_cond		// set master mode and send START signal

	mov r0, #DS75_W			// set slave write address
	bl write_data			// write slave WRITE address to bus

	mov r0, r4				// set pointer byte
	bl write_data			// write pointer byte to bus

	mov r0, r5				// set MSB data byte
	bl write_data			// write data byte to bus

	mov r0, r6				// set MSB data byte
	bl write_data			// write data byte to bus

	bl set_stop_cond		// set slave mode and send STOP signal

	pop {r4, r5, r6, PC}

//********************************** wait for IICIF ***********************************

.thumb_func
	// parameter: none
	// return: none
wait_for_iicif:
	ldr r1, =BB_I2C0_IICIF
wait_for_iicif_loop:
	ldrb r0, [r1]
	cmp r0, #1
	bne wait_for_iicif_loop
	
	strb r0, [r1]				// clear iicif
	bx LR

//************************* set START condition and wait for busy flag to activate ****************

.thumb_func
	// parameter: none
	// return: none
set_start_cond:
	ldr r1, =BB_I2C0_MST
	mov r0, #1
	strb r0, [r1]					// setting MST initiates START condition

	ldr r1, =BB_I2C0_BUSY
	mov r2, #10						// counter for number of max trials
wait_for_busy_loop:
	ldrb r0, [r1]
	cmp r0, #1
	beq start_exit
	
	subs r2, r2, #1
	bne wait_for_busy_loop			// wait for bus to become busy

	b error
start_exit:
	bx LR

//**************************************** REPEAT START condition ****************************

.thumb_func
	// parameter: none
	// return: none
set_rep_start:
	ldr r1, =BB_I2C0_RSTA
	mov r0, #1
	strb r0, [r1]					// set RSTA bit
	bx LR

//************************** set STOP condition and delay after stop ****************************

.thumb_func
	// parameter: none
	// return: none
set_stop_cond:
	push {LR}
	
	ldr r1, =BB_I2C0_MST
	mov r0, #0
	strb r0, [r1]					// setting slave mode generates stop condition
	
	bl i2c_Delay					// delay 2 microseconds between stop and next start
	
	pop {PC}

//***************************************** set master acknowledge *******************************

.thumb_func
	// parameter: none
	// return: none
set_mst_ack:
	ldr r1, =BB_I2C0_TXAK
	mov r0, #0
	strb r0, [r1]					// clear TXAK bit
	bx LR

//***************************************** set master no acknowledge *******************************

.thumb_func
	// parameter: none
	// return: none
set_mst_nack:
	ldr r1, =BB_I2C0_TXAK
	mov r0, #1
	strb r0, [r1]					// set TXAK bit
	bx LR

//*************************************** Read Data Byte ***********************************************

.thumb_func
	// parameter: none
	// return: byte from data register in r0
read_data:
	ldr r1, =I2C0_D
	ldrb r0, [r1]					// move data register to r0 and initiate next read
	bx LR

//******************************* Write Data Byte and wait for IICIF to set ******************************

.thumb_func
	// parameter: data byte in r0
	// return: none
write_data:
	push {LR}
	
	ldr r1, =I2C0_D
	strb r0, [r1]					// save r0 to data register and initiate transfer
	bl wait_for_iicif				// wait for transfer to complete
	
	pop {PC}


//**************************************** set RX mode ************************************* 

.thumb_func
	// parameter: none
	// return: none
set_rx_mode:
	ldr r1, =BB_I2C0_TX
	mov r0, #0
	strb r0, [r1]					// clear TX bit to change to rx mode
	bx LR

//**************************************** set TX mode ************************************* 

.thumb_func
	// parameter: none
	// return: none
set_tx_mode:
	ldr r1, =BB_I2C0_TX
	mov r0, #1
	strb r0, [r1]					// set TX bit to change to tx mode
	bx LR

//********************************************** PIT ISR (each second) **************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagSecond' set
second_isr:
	mov r1, #1
	
	// clear timerFlagRegister
	ldr r0, =PIT_TFLG1
	str r1, [r0]					// clear TIF

	// set userFlag
	ldr r0, =flagSecond
	str r1, [r0]					// user flag set
	bx LR

//************************************ I2C Delay **********************************************

.thumb_func
// parameter: none
// return: none
i2c_Delay:
	ldr r0, =(TWO_MICROSECONDS + 2) / 3	// subs = 1 clock, bne = min 2 clocks ==> 3 clocks per loop, rounded
delay_loop:
	subs r0, r0, #1
	bne delay_loop	
	bx LR

//**************************************** I2CBus_Reset ********************************************

/* **************** Konstantendeklarationen ********* */
.equ SIM_SCGC5,		0x40048038
.equ PORTD_PCR8,	0x4004c020
.equ PORTD_PCR9,	0x4004c024
.equ GPIOD_PDDR,	0x400ff0d4
.equ GPIOD_PDIR,	0x400ff0d0
.equ GPIOD_PDOR,	0x400ff0c0

__BBREG SIM_PORTD, SIM_SCGC5, 12
.equ PD8_9, 0x300					// Maske fuer PD8 und PD9
.equ PD8, 0x100						// Maske fuer PD8
.equ ALT_GPIO, 0x100				// Alternative 1: GPIO

/* **************** I2C - Bus zuruecksetzen *********** */
.thumb_func
// parameter: none
// return: r0: result (1 = successfully reset, 0 = error during reset)
I2CBus_Reset:
	push {r4, lr}

	ldr r0, =SIM_PORTD				// Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR8				// Portleitungen PD8, PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR				// PD8, PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	
	mov r4, #10						// counter for max 10 trials
loop:
	ldr r0, =GPIOD_PDOR				// SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD8				// entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay

	ldr r0, =GPIOD_PDOR 			// SCL und SDA aktivieren
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	bl i2c_Delay

	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9				// nur Bits 9 und 10 pruefen
	cmp r2, #PD8_9					// Bit 9 und Bit 10 gesetzt?
	beq loop_exit

	subs r4, r4, #1
	bne loop						// ggf. wiederholen

loop_exit:
	cmp r4, #0
	itee eq
	ldreq r0, =str_i2c_error
	ldrne r0, =str_i2c_reset
	movne r4, #1
	
	bl uart_putString
	
	ldr r0, =PORTD_PCR8				// reconfigure PTD8, PTD9 as ALT2 (see p. 248 of RM)
	ldr r1, =PORTD_PCR9
	mov r2, #0x200
	str r2, [r0]
	str r2, [r1]
	
	mov r0, r4

	pop {r4, pc}

/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/

/*** Datenbereich (ab 0x20000000) ***/
.data
flagSecond:		.word 0x00		// user flag - is 1 on second interrupt
str_0x:			.asciz "0x"
str_celsius:	.asciz " Grad Celsius\n"
str_i2c_reset:	.asciz "I2C Bus zurueckgesetzt.\n"
str_i2c_error:	.asciz "*** Abbruch! Der I2C Bus konnte nicht zurueckgesetzt werden. ***\n"
str_error:		.asciz "ERROR\n"
str_tos:		.asciz "TOS: 0x"
str_thyst:		.asciz "THYST: 0x"
str_t0:			.asciz "T0: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// register addresses
.equ SIM_SCGC3,				0x40048030								// System Clock Gating 3 for SPI2
.equ SIM_SCGC5,				0x40048038								// Clock for Ports A, D, E
.equ SIM_SCGC6,				0x4004803c								// System Clock Gating 6 for PIT

.equ SCR_VTOR,				0xe000ed08								// register for IVT
.equ NVIC_ISER2,			0xe000e100 + 0x2 << 2					// NVIC non-IPR register number is 2
.equ NVIC_ICPR2,			0xe000e280 + 0x2 << 2					//  (integer part of IRQ div 32)

.equ PIT_MCR,				0x40037000								// PIT Module Control Register
.equ PIT_LDVAL1,			PIT_MCR + 0x100 + 16					// PIT1 Load Value register
.equ PIT_TCTRL1,			PIT_MCR + 0x108 + 16					// PIT1 Control register
.equ PIT_TFLG1,				PIT_MCR + 0x10c + 16					// PIT1 Flag Register

.equ PORTA_PCR19,			0x4004904c								// SW1 Pin Control Register for Port A, Pin 19
.equ PORTD_PCR12,			0x4004c030								// SPI2, PCR13, 14, 15 will be implicitly addressed
.equ PORTE_PCR26,			0x4004d068								// SW2 Pin Control Register for Port E, Pin 26

.equ GPIOA_PDIR,			0x400ff010								// port data input register for SW1
.equ GPIOD_PDIR,			0x400ff0d0								// SPI2 PDIR
.equ GPIOE_PDIR,			0x400ff110								// port data input register for SW2 (port E)
.equ GPIOA_PDDR,			0x400ff014								// Port Data Direction for SW1
.equ GPIOD_PDDR,			0x400ff0d4								// SPI2 PDDR
.equ GPIOE_PDDR,			0x400ff114								// Port Data Direction for SW2
.equ GPIOD_PDOR,			0x400ff0c0								// SPI2 PDOR

.equ SPI2_MCR,				0x400ac000								// SPI2 Module Configuration Register
.equ SPI2_CTAR0,			0x400ac00c								// SPI2 Clock and Transfer Attributes Register
.equ SPI2_SR,				0x400ac02c								// SPI2 Status Register
.equ SPI2_PUSHR,			0x400ac034								// SPI2 Push Register
.equ SPI2_POPR,				0x400ac038								// SPI2 Pop Register

// bit band constants
__BBREG	BB_PORTA_ISF,		PORTA_PCR19, 24							// ISF (Interrupt Status Flag) for Port A (SW1)
__BBREG	BB_PORTE_ISF,		PORTE_PCR26, 24							// ISF (Interrupt Status Flag) for Port E (SW2)

__BBREG	BB_SIM_SPI2,		SIM_SCGC3, 12							// SPI2 Clock Gate Control
__BBREG	BB_SIM_PIT,			SIM_SCGC6, 23							// PIT Clock Gate Control
__BBREG BB_SIM_PORTA,		SIM_SCGC5, 9							// Port A Clock Gate Control
__BBREG BB_SIM_PORTD,		SIM_SCGC5, 12							// Port D Clock Gate Control
__BBREG BB_SIM_PORTE,		SIM_SCGC5, 13							// Port E Clock Gate Control

__BBREG BB_PIT_TEN,			PIT_TCTRL1, 0							// Timer Enable

__BBREG BB_SPI2_HALT,		SPI2_MCR, 0								// start (0) and stop (1) of SPI2 module transfers
__BBREG BB_SPI2_DIS_RXF,	SPI2_MCR, 12							// Disable RX FIFO
__BBREG BB_SPI2_DIS_TXF,	SPI2_MCR, 13							// Disable TX FIFO
__BBREG BB_SPI2_TCF,		SPI2_SR, 31								// transfer complete flag


// various constants
.equ IRQ_BITFIELD,			1<<(69%32) + 1<<(87%32) + 1<<(91%32)	// PIT: IRQ 69, SW1: IRQ 87, SW2: IRQ 91
.equ OFFSET_IRQ69,			(69 + 0x10) << 2						// add 16 base vectors to IRQ number and multiply by 4 byte per vector
.equ OFFSET_IRQ87,			(87 + 0x10) << 2
.equ OFFSET_IRQ91,			(91 + 0x10) << 2

.equ INIT_PIT_MCR,			0x0										// MDIS = 0, FRZ = 0
.equ INIT_PIT_TCTRL1,		0x02									// CHN = 0, TIE = 1, TEN = 0
	/*
		when R is resolution in bits, then conversion time is 2^(R-8) x 0,075 s
		=> LDVAL = 25000000 x 0,075 x 2^(R-8) - 1 = 1875000 x 2^(R-8) - 1
		=> LDVAL at initial resolution of 12 bits is 1875000 x 16 - 1 = 29999999 = 0x01c9c37f
	*/
.equ INIT_PIT_LDVAL1,		0x01c9c37f								// conversion time at 12 bits resolution

.equ INIT_PORTA_PCR19,		1<<24 + 0xa<<16 + 1<<8 + 1<<1 + 1		// reset ISF (w1c), IRQC = 1010 = falling edge, MUX = 001 = GPIO, PE/PS = internal pullup resistor
.equ INIT_PORTE_PCR26,		1<<24 + 0xa<<16 + 1<<8 + 1<<1 + 1		// reset ISF (w1c), IRQC = 1010 = falling edge, MUX = 001 = GPIO, PE/PS = internal pullup resistor

// DIS_TXF/RXF can only be set when MDIS is clear, this will happen during configuration
.equ INIT_SPI2_MCR,			0x80000001								// MSTR = 1, MDIS = 0, HALT = 1

/*
	tCSC = tCC min 400 ns = 10 CLK ==> prescaler value 5 (0b10) ==> scaler value = 2 (0b0000)
	tASC = tCCH min 100 ns = 3 CLK ==> prescaler value 1 (0b00) ==> scaler value = 4 (0b0001)
	tDT = tCWH min 400 ns = 10 CLK ==> prescaler value 5 (0b10) ==> scaler value = 2 (0b0000)
	Baud Rate Prescaler 2 (0b00), Baud Rate Scaler 128 (0b0111) ==> 25 MHz : 2 : 128 = 97,656 kHz
*/
.equ INIT_SPI2_CTAR0,		0x7a880107								// FMSZ=16, CPHA=1, PCSSCK=5, PASC=1, PDT=5, PBR = 2, CSSCK=2, ASC=4, DT=2, BR=128
.equ BURST_READ1,			0x80020000								// CONT, PCS 2
.equ BURST_READ2,			0x00020000								// deassert CONT, PCS 2
.equ CONF_WRITE,			0x000280e8								// PCS 2, address #80, continuous mode, 12 bit resolution

.equ CHAR_COMMA,			','										// comma for terminal output

.equ ALT2_GPIO,				0x203									// Alternative 2: SPI, MUX = 002, PE = 1, PS = 1

main:	

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/

	bl uart_init				// init UART

// load some constants
	mov r10, #0					// r10	fixed value of 0 to avoid multiple moves	
	mov r11, #1					// r11	fixed value of 1 to avoid multiple moves
	mov r12, #12				// r12	holds current resolution, init at 12 bits

// *************************** configure system integration module *******************************

// enable SPI2 clock
	ldr r0, =BB_SIM_SPI2
	str r11, [r0]

// enable PIT clock
	ldr r0, =BB_SIM_PIT
	str r11, [r0]

// activate GPIO ports A, D and E
	ldr r0, =BB_SIM_PORTA
	str r11, [r0]
	
	ldr r0, =BB_SIM_PORTD
	str r11, [r0]

	ldr r0, =BB_SIM_PORTE
	str r11, [r0]

// ******************************* interrupt configuration ********************************************

// load reference to IVT
	ldr r0, =SCR_VTOR
	ldr r1, [r0]

// set interrupt vector
	ldr r0, =conversion_isr
	str r0, [r1, #OFFSET_IRQ69]	// IRQ69 for PIT

	ldr r0, =sw1_isr 
	str r0, [r1, #OFFSET_IRQ87]	// IRQ87 for SW1
	
	ldr r0, =sw2_isr 
	str r0, [r1, #OFFSET_IRQ91]	// IRQ91 for SW2

// load bitfield for vectors
	ldr r0, =IRQ_BITFIELD

// clear pending interrupts
	ldr r1, =NVIC_ICPR2
	str r0, [r1]

// set_NVIC_SetEnableRegister
	ldr r1, =NVIC_ISER2
	str r0, [r1]

// ************************* configure periodic interrupt timer ***********************************

// set PIT module ControlRegister
	ldr r0, =PIT_MCR
	mov r1, #INIT_PIT_MCR
	str r1, [r0]					// FRZ = 0, continue to run in debug mode - MDIS = 0, clock enabled
	
// set timer LoadValueRegister
	ldr r0, =PIT_LDVAL1
	ldr r1, =INIT_PIT_LDVAL1
	str r1, [r0]					// conversion time of 1,2 s at initial 12 bits resolution
	
// clear timer Flag
	ldr r0, =PIT_TFLG1
	str r11, [r0]					// clear TIF (writing 1 to the flag clears it)

// set timer ControlRegister
	ldr r0, =PIT_TCTRL1
	mov r1, #INIT_PIT_TCTRL1
	str r1, [r0]					// TIE enabled, TEN yet disabled

// ***************************** configure GPIO **************************************************

// configure SPI pins as Alternative 2
	ldr r0, =PORTD_PCR12
	ldr r1, =ALT2_GPIO				// set MUX = 010 = Alt2 for ...
	str r1, [r0], #4					// ... PORTD_PCR12
	str r1, [r0], #4					// ... PORTD_PCR13
	str r1, [r0], #4					// ... PORTD_PCR14
	str r1, [r0]						// ... PORTD_PCR15

// configure PCR for SW1
	ldr r0, =PORTA_PCR19
	ldr r1, =INIT_PORTA_PCR19		// reset ISF (w1c), IRQC = 1010 = falling edge, MUX = 001 = GPIO, PE/PS = internal pullup resistor
	str r1, [r0]

// configure PCR for SW2
	ldr r0, =PORTE_PCR26
	ldr r1, =INIT_PORTE_PCR26		// reset ISF (w1c), IRQC = 1010 = falling edge, MUX = 001 = GPIO, PE/PS = internal pullup resistor
	str r1, [r0]

// configure data direction for switches
	ldr r0, =GPIOA_PDDR
	ldr r1, [r0]
	bfc r1, #19, #1					// define SW1 as input
	str r1, [r0]

	ldr r0, =GPIOE_PDDR
	ldr r1, [r0]
	bfc r1, #26, #1					// define SW2 as input
	str r1, [r0]

// ******************************** configure SPI2 ************************************************

	ldr r0, =SPI2_MCR
	ldr r1, =INIT_SPI2_MCR
	str r1, [r0]					// this clears MDIS

	ldr r0, =SPI2_CTAR0				// init CTAR0
	ldr r1, =INIT_SPI2_CTAR0
	str r1, [r0]

	ldr r0, =BB_SPI2_DIS_TXF		// disables TX/RX FIFO
	str r11, [r0]					// this can only be done when MDIS is clear
	ldr r0, =BB_SPI2_DIS_RXF
	str r11, [r0]

/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

// preload some pointers
	ldr r6, =flagConversion			// r6: user flag from conversion ISR
	ldr r7, =BB_SPI2_HALT			// r7: HALT bit in MCR
	ldr r8, =SPI2_PUSHR				// r8: PUSH register
	ldr r9, =SPI2_POPR				// r9: POP register

// init resolution at 12 bits
	mov r0, r12
	bl set_resolution				// set initial resolution to 12 bits

mainloop:
// check if one of the switches is pressed
	mov r0, r12
	bl sw1_pressed					// sw1
	mov r12, r0						// save new resolution
	bl sw2_pressed					// sw2
	mov r12, r0						// save new resolution

// check if conversion time is over
	ldr r1, [r6]
	cmp r1, #0						// check user flag to see if interrupt was from conversion isr
	beq mainloop					// nothing to do if conversion period not over

// conversion period is over, reset user flag
	str r10, [r6]					// user flag reset

/*
	+++++++++++++++++++++++ KEY LOGIC STARTS HERE ++++++++++++++++++++++++
*/

// start SPI2
	str r10, [r7]					// SPI2: RUN (clear HALT)

// read temperature from SPI2
	ldr r1, =BURST_READ1			// CONT, CTAR0 (FMSZ 16), PCS 2, burst read
	str r1, [r8]	
	bl wait_for_tcf

	ldr r4, [r9]					// put temperature in r4 for output	
	ldr r0, [r9]					// dummy read to adjust burst pointer

	mov r1, #BURST_READ2			// deassert CONT
	str r1, [r8]
	bl wait_for_tcf
		
// stop SPI2
	str r11, [r7]					// SPI2: HALT
	
// output of temperature to terminal
	mov r0, r4
	bl temp_output					// format of parameter: L0MM, e.g. 0xC019

/*
	+++++++++++++++++++++++ KEY LOGIC ENDS HERE ++++++++++++++++++++++++
*/

	b mainloop						// and again


/**************************************************************************************************
***************************************************************************************************
***********************************  SUBPROGRAMS  *************************************************
***************************************************************************************************
***************************************************************************************************/

//********************************** wait for TCF ***********************************

.thumb_func
	// parameter: none
	// return: none
wait_for_tcf:
	ldr r1, =BB_SPI2_TCF
wait_for_tcf_loop:
	ldrb r0, [r1]
	cmp r0, #1
	bne wait_for_tcf_loop
	
	strb r0, [r1]					// clear tcf
	bx LR

//******************************* set new resolution in DS1722 and adjust PIT1 ********************************

.thumb_func
	// parameter: target resolution in bits in r0
	// return: new resolution in bits in r0
set_resolution:
	push {r4, LR}
	
	mov r4, r0						// save parameter
	
// stop PIT
	ldr r0, =BB_PIT_TEN				// disable PIT to abort current cycle
	mov r1, #0x0
	str r1, [r0]

// set new timer start value
	/*
		when R is resolution in bits, then conversion time is 2^(R-8) x 0,075 s
		=> LDVAL = 25000000 x 0,075 x 2^(R-8) - 1 = 1875000 x 2^(R-8) - 1
		(I know, I could alternatively have precalculated these values and define an array)
	*/
	ldr r0, =1875000				// 75 ms @ 25 Mhz
	sub r1, r4, #8					// reduce target resolution by 8
	lsl r0, r0, r1					// 75 ms x 2^(R-8) now in r0
	sub r0, r0, #1					// decrement by 1
	ldr r1, =PIT_LDVAL1				// set timer LoadValueRegister
	str r0, [r1]					// save conversion time to LDVAL

// start PIT again
	ldr r0, =BB_PIT_TEN
	mov r1, #0x1
	str r1, [r0]
	
// start SPI2
	ldr r0, =BB_SPI2_HALT
	mov r1, #0
	str r1, [r0]
	
// push resolution to DS1722
	ldr r1, =CONF_WRITE				// load PUSH mask, CTAR0 (FMSZ 16), PCS 2, address 0x80, continous mode 0xe8 (12 bits resolution)
	sub r2, r4, #8					// reduce target resolution by 8 to get configuration value of DS1722 R2-R0 registers
	bfi r1, r2, #1, #3				// place resolution bits in configuration value (bits 3-1)
	ldr r0, =SPI2_PUSHR				// load pointer to push register
	str r1, [r0]					// PUSH
	bl wait_for_tcf					// wait for transfer to complete

/*
	calculation of wait cycles to get first temperature with new resolution:
	when R is resolution in bits, then conversion time is 2^(R-8) x 0,075 s,
	this requires 25000000 x 0,075 x 2^(R-8) = 1875000 x 2^(R-8) clock cycles,
	given 3 cycles per loop this results in 625000 x 2^(R-8) loops
*/
	ldr r0, =625000					// base number of loops
	sub r1, r4, #8					// reduce target resolution by 8
	lsl r0, r0, r1					// shift by R-8 bits
set_res_loop:
	subs r0, r0, #1
	bne set_res_loop	

// dummy read of first result to clear old data in POPR
	ldr r0, =SPI2_PUSHR
	ldr r1, =BURST_READ1
	str r1, [r0]
	bl wait_for_tcf
	ldr r0, =SPI2_POPR
	ldr r1, [r0]

	ldr r0, =SPI2_PUSHR
	mov r1, #BURST_READ2
	str r1, [r0]
	bl wait_for_tcf
	ldr r0, =SPI2_POPR
	ldr r1, [r0]

// stop SPI2
	ldr r0, =BB_SPI2_HALT
	mov r1, #1
	str r1, [r0]
	
// output info about new resolution
	ldr r0, =str_res1
	bl uart_putString
	mov r0, r4						// new resolution
	bl uart_putByteBase10
	ldr r0, =str_res2
	bl uart_putString
	
// return
	mov r0, r4						// return resolution in r0
	pop {r4, PC}

//***************************************** temperature output *********************************

.thumb_func
 	// parameter: temperature data in format L0MM (e.g. 0xc019) in r0
	// return: none, only terminal output
temp_output:
	push {r4, LR}
	
	mov r4, r0						// save parameter
	
	bfc r0, #8, #8					// reduce r0 to contain only MSB of data
	bl uart_putByteBase10			// output MSB
	
	mov r0, #CHAR_COMMA
	bl uart_putChar					// ,
	
	lsr r1, r4, #12					// place significant 4 LSBits to the right in r1
	bfc r1, #4, #28					// use LSB as array offset
	mov r0, #5
	mul r1, r1, r0					// multiply r1 by 5 as fraction array is 4 byte + termination byte
	ldr r0, =stra_fraction16
	add r0, r0, r1					// add offset to r0
	bl uart_putString				// output LSB
	
	ldr r0, =str_gc
	bl uart_putString				// gC
	
	pop {r4, PC}

//********************************************** PIT ISR (conversion time) **************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagConversion' set
conversion_isr:
	mov r1, #1
	ldr r0, =PIT_TFLG1
	str r1, [r0]					// clear TIF

	ldr r0, =flagConversion
	str r1, [r0]					// user flag set
	bx LR

//******************************************** SW1 (black) ISR ******************************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagSW1' set
sw1_isr:
	mov r1, #1
	ldr r0, =BB_PORTA_ISF			// clear interrupt status flag
	str r1, [r0]
	
	ldr r0, =flagSW1
	str r1, [r0]					// user flag set
	bx LR

//******************************************** SW2 (green) ISR ******************************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagSW2' set
sw2_isr:
	mov r1, #1
	ldr r0, =BB_PORTE_ISF			// clear interrupt status flag
	str r1, [r0]
	
	ldr r0, =flagSW2
	str r1, [r0]					// user flag set
	bx LR

// ********************************* SW1 (black) pressed - increase resolution *************************

.thumb_func
// parameter: current resolution in r0
// return: new resolution in r0
sw1_pressed:
	push {r4, LR}
	
	mov r4, r0					// save parameter
	ldr r2, =flagSW1			// check user flag to see if interrupt was from SW1
	ldr r1, [r2]
	cmp r1, #0
	beq sw1_end					// nothing to do if flag is clear

	mov r1, #0
	str r1, [r2]				// user flag reset, r2 still points to flagSW1

	ldr r0, =str_sw1			// output info to terminal
	bl uart_putString

	cmp r4, #12					// if resolution is already 12 ...
	ite eq
	moveq r4, #8				// start again with 8 bits
	addne r4, r4, #1			// else increase by 1 bit
	
	mov r0, r4					// set new resolution as parameter
	bl set_resolution			// adjust resolution and conversion time

sw1_end:
	pop {r4, PC}

// ******************************* SW2 (green) pressed - decrease resolution***********************************

.thumb_func
// parameter: current resolution in r0
// return: new resolution in r0
sw2_pressed:
	push {r4, LR}
	
	mov r4, r0					// save parameter
	ldr r2, =flagSW2			// check user flag to see if interrupt was from SW2
	ldr r1, [r2]
	cmp r1, #0
	beq sw2_end					// nothing to do if flag is clear

	mov r1, #0
	str r1, [r2]				// user flag reset, r2 still points to flagSW2

	ldr r0, =str_sw2			// output info to terminal
	bl uart_putString

	cmp r4, #8					// if resolution is already 8 ...
	ite eq
	moveq r4, #12				// set new resolution to 12 bits
	subne r4, r4, #1			// else decrease by 1 bit

	mov r0, r4					// set new resolution as parameter	
	bl set_resolution			// adjust resolution and conversion time

sw2_end:
	pop {r4, PC}


/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/

/*** Datenbereich (ab 0x20000000) ***/
.data
flagConversion:	.word 0x00		// user flag - is 1 on conversion time interrupt
flagSW1:		.word 0x00		// user flag for SW1 (black)
flagSW2:		.word 0x00		// user flag for SW2 (green)
stra_fraction16:.asciz "0000","0625","1250","1875","2500","3125","3750","4375","5000","5625","6250","6875","7500","8125","8750","9375"			
str_gc:			.asciz " gC\n"
str_res1:		.asciz "Die Aufloesung ist auf "
str_res2:		.asciz " Bits eingestellt.\n"
str_sw1:		.asciz "SW1 gedrueckt.\n"
str_sw2:		.asciz "SW2 gedrueckt.\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/


// register addresses
.equ SCR_VTOR,				0xe000ed08								// register for IVT
.equ NVIC_ISER2,			0xe000e100 + 0x2 << 2					// NVIC non-IPR register number is 2
.equ NVIC_ICPR2,			0xe000e280 + 0x2 << 2					//  (integer part of IRQ div 32)

.equ SIM_SCGC6,				0x4004803c								// SCGC6 for RTC clock

.equ RTC_TSR,				0x4003d000								// RTC Time Seconds Register
.equ RTC_TPR,				0x4003d004								// RTC Time Prescaler Register
.equ RTC_TAR,				0x4003d008								// RTC Time Alarm Register
.equ RTC_TCR,				0x4003d00c								// RTC Time Compensation Register
.equ RTC_CR,				0x4003d010								// RTC Control Register
.equ RTC_SR,				0x4003d014								// RTC Status Register
.equ RTC_LR,				0x4003d018								// RTC Lock Register
.equ RTC_IER,				0x4003d01c								// RTC Interrup Enable Register
.equ RTC_WAR,				0x4003d800								// RTC Write Access Register
.equ RTC_RAR,				0x4003d804								// RTC Read Access Register

// bit band constants
__BBREG	BB_SIM_RTC,			SIM_SCGC6, 29							// RTC Clock Gate Control
__BBREG BB_RTC_TCE,			RTC_SR, 4								// RTC Time Counter Enable

// various constants
.equ IRQ_BITFIELD,			1<<(66%32) + 1<<(67%32)					// RTC: IRQ 66 and 67, alarm and seconds interrupt
.equ OFFSET_IRQ66,			(66 + 0x10) << 2						// add 16 base vectors to IRQ number and multiply by 4 byte per vector
.equ OFFSET_IRQ67,			(67 + 0x10) << 2

.equ INIT_RTC_CR,			0x100									// OSCE
.equ INIT_RTC_IER,			0x14									// TSIE, TAIE
.equ INIT_RTC_SR,			0x10									// TCE

.equ CHAR_COLON,			':'										// colon for terminal output
.equ CHAR_LF,				0x0a									// line feed for terminal output
.equ CHAR_D,				'd'										// day
.equ CHAR_H,				'h'										// hour
.equ CHAR_R,				'r'										// reset
.equ CHAR_S,				's'										// start/stop
.equ CHAR_P,				'p'										// preset
.equ ALARM_24H,				59 + 59*60 + 23*3600					// 23:59:59
.equ ALARM_1H,				59 + 59*60								// 59:59
.equ PRESET_24H,			55 + 59*60 + 23*3600					// 23:59:55
.equ PRESET_1H,				55 + 59*60								// 59:55

main:

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/
	
	bl uart_init

// load some constants
	mov r10, #0						// r10	fixed value of 0 to avoid multiple moves	
	mov r11, #1						// r11	fixed value of 1 to avoid multiple moves

// *************************** configure system integration module *******************************

// enable RTC clock
	ldr r0, =BB_SIM_RTC
	str r11, [r0]

// ******************************* interrupt configuration ***************************************

// load reference to IVT
	ldr r0, =SCR_VTOR
	ldr r1, [r0]

// set interrupt vector
	ldr r0, =alarm_isr 
	str r0, [r1, #OFFSET_IRQ66]		// IRQ66 for RTC alarm interrupt
	
	ldr r0, =seconds_isr
	str r0, [r1, #OFFSET_IRQ67]		// IRQ67 for RTC seconds interrupt

// load bitfield for vectors
	ldr r0, =IRQ_BITFIELD

// clear pending interrupts
	ldr r1, =NVIC_ICPR2
	str r0, [r1]

// set_NVIC_SetEnableRegister
	ldr r1, =NVIC_ISER2
	str r0, [r1]

// *************************** configure RTC module ***********************************************

// init RTC registers - TSR and TAR will be initialized later in mainloop
	ldr r0, =RTC_TPR
	str r10, [r0]					// write prescaler prior to seconds register

	ldr r0, =RTC_TCR				// no time compensation
	str r10, [r0]

	ldr r0, =RTC_CR
	ldr r1, =INIT_RTC_CR			// set OSCE
	str r1, [r0]

	ldr r0, =1500					// wait 4096 cycles for oscillator startup-time (4096 clock cycles = approx. 1500 loops)
wait_osc_startup:
	subs r0, r0, #1
	bne wait_osc_startup

	ldr r0, =RTC_SR					// TOF cannot assert, as max value 23:59:59 is below overflow limit, TIF cannot assert as TSR is regularly reset
	ldr r1, =INIT_RTC_SR			// TCE
	str r1, [r0]

	ldr r0, =RTC_IER
	ldr r1, =INIT_RTC_IER			// set TSIE and TAIE
	str r1, [r0]

	mov r1, #0xff					// reset value for LSB of LR, WAR and RAR

	ldr r0, =RTC_LR
	str r1, [r0]					// no lock

	ldr r0, =RTC_WAR
	str r1, [r0]					// normal completion on writes

	ldr r0, =RTC_RAR
	str r1, [r0]					// normal completion on reads

/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

// preload some pointers and flags
	ldr r4, =flagSeconds			// r4: pointer to seconds flag
	ldr r5, =flagAlarm				// r5: pointer to alarm flag
	ldr r6, =RTC_TAR				// r6: pointer to TAR
	ldr r7, =RTC_TSR				// r7: pointer to TSR
	ldr r8, =BB_RTC_TCE				// r8: pointer to TCE - initially on
	mov r9, #1						// r9: output flag - initially on
	mov r12, #0						// r12: mode flag (0 = 24 h, 1 = 1 h) - initially 24h
	b set_24h_mode					// activate 24h mode

mainloop:
// check alarm interrupt	
	ldr r0, [r5]					// check if alarm interrupt was set
	cmp r0, #1
	beq alarm_flag_set				// ... if so, continue to set alarm

// check seconds interrupt
	ldr r0, [r4]					// check if RTC seconds interrupt was set
	cmp r0, #1
	beq second_flag_set				// ... if so, continue to display time if not disabled

// check for terminal input
	bl uart_charPresent				// check terminal input
	cmp r0, #0
	beq mainloop					// no input: proceed
	
	bl uart_getChar					// receive character from terminal

	cmp r0, #CHAR_D					// check on "d" (day)
	beq set_24h_mode

	cmp r0, #CHAR_H					// check on "h" (hour)
	beq set_1h_mode

	cmp r0, #CHAR_R					// check on "r" (reset)
	beq reset

	cmp r0, #CHAR_S					// check on "s" (start/stop)
	beq toggle_output
	
	cmp r0, #CHAR_P					// check on "p" (preset)
	beq preset
		
	b mainloop						// if no interrupt was set and no valid key was pressed, continue mainloop

set_24h_mode:
	mov r12, #0						// set 24 h mode
	ldr r0, =ALARM_24H
	str r0, [r6]					// set 24 h alarm
	
	ldr r0, =str_mode24h			// output info on terminal
	bl uart_putString
	
	b reset							// reset clock to 0
	
set_1h_mode:
	mov r12, #1						// set 1 h mode
	ldr r0, =ALARM_1H
	str r0, [r6]					// set 1 h alarm
	
	ldr r0, =str_mode1h				// output info on terminal
	bl uart_putString
									// continue to reset clock to 0
reset:
	str r10, [r8]					// disable TCE
	str r10, [r7]					// set TSR to 0
	str r11, [r8]					// enable TCE again
	
	ldr r0, =str_reset				// output info on terminal
	bl uart_putString

// output time after reset
	cmp r9, #0
	beq mainloop					// leave if output is stopped
	mov r1, r12						// load mode as parameter for time_output
	ldr r0, [r7]					// load content of TSR as parameter for time_output
	bl time_output					// ... and display on terminal

	b mainloop
	
toggle_output:
	eor r9, r9, #1					// toggle output in r9
	
	cmp r9, #1						// output info on terminal
	ite eq
	ldreq r0, =str_output_on
	ldrne r0, =str_output_off
	bl uart_putString
	
	b mainloop
	
preset:
	str r10, [r8]					// disable TCE
	
	cmp r12, #0						// check if mode = 0 = 24 h
	ite eq							// and set respective preset value
	ldreq r2, =PRESET_24H
	ldrne r2, =PRESET_1H
	
	str r2, [r7]					// set TSR to preset value
	str r11, [r8]					// enable TCE again

	ldr r0, =str_preset				// output info on terminal
	bl uart_putString
	
// output time after preset
	cmp r9, #0
	beq mainloop					// leave if output is stopped
	
	mov r1, r12						// load mode as parameter for time_output
	ldr r0, [r7]					// load content of TSR as parameter for time_output
	bl time_output					// ... and display on terminal
	
	b mainloop	

second_flag_set:
	cmp r9, #0
	beq second_flag_exit			// leave if output is stopped

	mov r1, r12						// load mode as parameter for time_output
	ldr r0, [r7]					// load content of TSR as parameter for time_output
	bl time_output					// ... and display on terminal
second_flag_exit:
	str r10, [r4]					// reset seconds flag
	b mainloop

alarm_flag_set:
// reset time counter	
	str r10, [r8]					// disable TCE
	str r10, [r7]					// set TSR to 0
	str r11, [r8]					// enable TCE again

	ldr r0, =str_reset				// output info on terminal
	bl uart_putString

// reset alarm flag	
	str r10, [r5]

// set alarm register
	cmp r12, #0						// check if mode = 0 = 24 h
	ite eq							// and set respective alarm value
	ldreq r2, =ALARM_24H
	ldrne r2, =ALARM_1H

	str r2, [r6]					// set alarm again, writing to TAR clears TAF

	ldr r0, =str_alarm				// output info on terminal
	bl uart_putString
	
	b mainloop						// continue with mainloop

/**************************************************************************************************
***************************************************************************************************
***********************************  SUBPROGRAMS  *************************************************
***************************************************************************************************
***************************************************************************************************/

//*********************************** RTC alarm ISR **************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagAlarm' set
alarm_isr:
	ldr r0, =RTC_TAR

	mov r1, #1						// clear TAF by writing the TAR register
	str r1, [r0]					// the final TAR value will be set in the alarm handler routine

	ldr r0, =flagAlarm
	str r1, [r0]					// user flag set

	bx LR

//*********************************** RTC seconds ISR **************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagSeconds' set
seconds_isr:
	ldr r0, =flagSeconds
	mov r1, #1
	str r1, [r0]					// user flag set, no corresponding status flag to clear
	bx LR

//********************************** time output ***********************************

.thumb_func
	// parameter: number of seconds in r0, mode in r1 (0 = 24h, 1 = 1h)
	// return: none
time_output:
	push {r4, LR}

	mov r4, r0						// save seconds input
	cbnz r1, time_output_mm_ss		// skip output of hours in 1-hour-mode
	
	mov r1, #3600
	udiv r0, r4, r1					// divide seconds by 3600 to get hours
	mls r4, r0, r1, r4				// deduct hours*3600 from seconds
	
	cmp r0, #10						// output HH - check leading zeros
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1

	mov r0, #CHAR_COLON				// output colon
	bl uart_putChar

time_output_mm_ss:
	mov r1, #60
	udiv r0, r4, r1					// divide remaining seconds by 60 to get minutes
	mls r4, r0, r1, r4				// deduct minutes*60 from seconds

	cmp r0, #10						// output MM - check leading zeros
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1

	mov r0, #CHAR_COLON				// output colon
	bl uart_putChar

	mov r0, r4						// put remaining seconds into r0
	
	cmp r0, #10						// output SS - check leading zeros
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1
	
	mov r0, #CHAR_LF				// output of LF at end of line
	bl uart_putChar

	pop {r4, PC}

/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/

/*** Datenbereich (ab 0x20000000) ***/
.data
flagSeconds:	.word 0x00			// user flag - is 1 on RTC seconds interrupt
flagAlarm:		.word 0x00			// user flag - is 1 on RTC alarm interrupt

str_mode24h:	.asciz "24-Stunden-Modus\n"
str_mode1h:		.asciz "1-Stunden-Modus\n"
str_reset:		.asciz "Uhr zurueckgesetzt\n"
str_output_on:	.asciz "Anzeige an\n"
str_output_off:	.asciz "Anzeige aus\n"
str_preset:		.asciz "Uhr vorgestellt\n"
str_alarm:		.asciz "Endzeitpunkt erreicht\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/************************************************************************************

Terminal input of "s" can be used to SET date and time.

Input of "s" to terminal can be done at all time,
but the new data will only be captured in second 00 to avoid confusion with the binary output. 

************************************************************************************/

// register addresses
.equ SCR_VTOR,				0xe000ed08								// register for IVT
.equ NVIC_ISER2,			0xe000e100 + 0x2 << 2					// NVIC non-IPR register number is 2
.equ NVIC_ICPR2,			0xe000e280 + 0x2 << 2					//  (integer part of IRQ div 32)

.equ SIM_SCGC5,				0x40048038								// SCGC5 for Port A clock
.equ SIM_SCGC6,				0x4004803c								// SCGC6 for RTC clock and PIT

.equ PORTA_PCR6,			0x40049018								// PORTA 6			
.equ PORTA_PCR10,			0x40049028								// Pin Control Register LED E1

.equ GPIOA_PDDR,			0x400ff014								// Port Data Direction for LED
.equ GPIOA_PDOR,			0x400ff000								// port data output registers for LED

.equ PIT_MCR,				0x40037000								// PIT Module Control Register
.equ PIT_LDVAL1,			PIT_MCR + 0x100 + 16					// PIT1 Load Value register
.equ PIT_TCTRL1,			PIT_MCR + 0x108 + 16					// PIT1 Control register
.equ PIT_TFLG1,				PIT_MCR + 0x10c + 16					// PIT1 Flag Register

.equ RTC_TSR,				0x4003d000								// RTC Time Seconds Register
.equ RTC_TPR,				0x4003d004								// RTC Time Prescaler Register
.equ RTC_TAR,				0x4003d008								// RTC Time Alarm Register
.equ RTC_TCR,				0x4003d00c								// RTC Time Compensation Register
.equ RTC_CR,				0x4003d010								// RTC Control Register
.equ RTC_SR,				0x4003d014								// RTC Status Register
.equ RTC_LR,				0x4003d018								// RTC Lock Register
.equ RTC_IER,				0x4003d01c								// RTC Interrup Enable Register
.equ RTC_WAR,				0x4003d800								// RTC Write Access Register
.equ RTC_RAR,				0x4003d804								// RTC Read Access Register

// bit band constants
__BBREG	BB_SIM_PORTA,		SIM_SCGC5, 9							// Port A Clock Gate Control
__BBREG	BB_SIM_PIT,			SIM_SCGC6, 23							// PIT Clock Gate Control
__BBREG	BB_SIM_RTC,			SIM_SCGC6, 29							// RTC Clock Gate Control

__BBREG	BB_PIT_TEN,			PIT_TCTRL1, 0							// PIT Timer Enable

__BBREG	BB_GPIOA_DCF77,		GPIOA_PDOR, 6							// DCF77 is bit 6 in PDOR
__BBREG	BB_GPIOA_LED1,		GPIOA_PDOR, 10							// LED E1 is bit 10 in PDOR

__BBREG BB_RTC_TOF,			RTC_SR, 1								// RTC Time Overflow Flag
__BBREG BB_RTC_TCE,			RTC_SR, 4								// RTC Time Counter Enable

// various constants
.equ IRQ_BITFIELD,			1<<(67%32)+ 1<<(69%32)					// RTC: IRQ 67, seconds interrupt, PIT: IRQ 69
.equ OFFSET_IRQ67,			(67 + 0x10) << 2
.equ OFFSET_IRQ69,			(69 + 0x10) << 2

.equ INIT_PORTA_PCRn,		1 << 8									// MUX = 001 = GPIO
.equ INIT_GPIOA_PDDR,		1 << 6 | 1 << 10						// set LED pin and DCF77 to output

.equ INIT_PIT_MCR,			0x0										// MDIS = 0, FRZ = 0
.equ INIT_PIT_TCTRL1,		0x2										// CHN = 0, TIE = 1, TEN = 0

.equ INIT_RTC_CR,			0x100									// OSCE
.equ INIT_RTC_IER,			0x11									// TSIE, TOF
.equ INIT_RTC_SR,			0x10									// TCE

.equ CHAR_S,				's'										// set date and time
.equ CHAR_LF,				0x0a									// line feed for terminal output
.equ CHAR_DASH,				'-'										// dash for terminal output
.equ CHAR_DOT,				'.'										// dot for terminal output
.equ CHAR_COLON,			':'										// colon for terminal output
.equ CHAR_SPACE,			' '										// space for terminal output
.equ WAIT_100MS,			2500000 - 1								// clock runs at 25 MHz
.equ WAIT_200MS,			5000000 - 1								// clock runs at 25 MHz

main:	

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/

	bl uart_init

// load some constants
	mov r10, #0						// r10	fixed value of 0 to avoid multiple moves	
	mov r11, #1						// r11	fixed value of 1 to avoid multiple moves

// *************************** configure system integration module *******************************

// enable Port A clock
	ldr r0, =BB_SIM_PORTA
	str r11, [r0]

// enable PIT clock
	ldr r0, =BB_SIM_PIT
	str r11, [r0]

// enable RTC clock
	ldr r0, =BB_SIM_RTC
	str r11, [r0]

// ******************************* interrupt configuration ********************************************

// load reference to IVT
	ldr r0, =SCR_VTOR
	ldr r1, [r0]

// set interrupt vector
	ldr r0, =seconds_isr
	str r0, [r1, #OFFSET_IRQ67]		// IRQ67 for RTC seconds interrupt

// set interrupt vector
	ldr r0, =pit_isr
	str r0, [r1, #OFFSET_IRQ69]		// IRQ69 for PIT interrupt

// load bitfield for vectors
	ldr r0, =IRQ_BITFIELD

// clear pending interrupts
	ldr r1, =NVIC_ICPR2
	str r0, [r1]

// set_NVIC_SetEnableRegister
	ldr r1, =NVIC_ISER2
	str r0, [r1]

// ************************* configure periodic interrupt timer ***********************************

// set PIT module ControlRegister
	ldr r0, =PIT_MCR
	mov r1, #INIT_PIT_MCR
	str r1, [r0]					// FRZ = 0, continue to run in debug mode - MDIS = 0, clock enabled

// set timer ControlRegister
	ldr r0, =PIT_TCTRL1
	mov r1, #INIT_PIT_TCTRL1
	str r1, [r0]					// TIE enabled, TEN yet disabled


// *************************** configure port control *******************************************

// set MUX = 001 = GPIO for LED E1 and DCF77
	mov r0, #INIT_PORTA_PCRn

	ldr r1, =PORTA_PCR6
	str r0, [r1]

	ldr r1, =PORTA_PCR10
	str r0, [r1]

// *********************************** configure GPIO ports ***********************************	

// configure data direction registers
	ldr r0, =GPIOA_PDDR
	ldr r1, [r0]
	ldr r2, =INIT_GPIOA_PDDR		// PCR 6 and 10 set
	orr r1, r1, r2
	str r1, [r0]
	
	ldr r0, =BB_GPIOA_DCF77
	str r11, [r0]					// set PTA6 logic level to 1 at startup

	ldr r0, =BB_GPIOA_LED1
	str r11, [r0]					// set LED1 logic level to 1 (LED is clear) at startup


// *************************** configure RTC module ***********************************************

// init RTC registers
	ldr r0, =RTC_TPR
	str r10, [r0]					// write prescaler prior to seconds register

	ldr r0, =RTC_TAR
	str r10, [r0]

	ldr r0, =RTC_TCR
	str r10, [r0]

	ldr r0, =RTC_CR
	ldr r1, =INIT_RTC_CR
	str r1, [r0]

	ldr r0, =1500					// wait 4096 cycles for oscillator startup-time (4096 clock cycles = approx. 1500 loops)
wait_osc_startup:
	subs r0, r0, #1
	bne wait_osc_startup

	ldr r0, =RTC_SR
	ldr r1, =INIT_RTC_SR			// set TCE
	str r1, [r0]

	ldr r0, =RTC_IER
	ldr r1, =INIT_RTC_IER			// set TSIE and TAIE
	str r1, [r0]

	mov r1, #0xff					// reset value for LSB of LR, WAR and RAR

	ldr r0, =RTC_LR
	str r1, [r0]					// no lock

	ldr r0, =RTC_WAR
	str r1, [r0]					// normal completion on writes

	ldr r0, =RTC_RAR
	str r1, [r0]					// normal completion on reads

/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

	ldr r5, =BB_RTC_TCE				// r5: pointer to TCE flag
	mov r6, #CHAR_S					// r6: character input from terminal, to be evaluated at next second 00 - is "s" at startup to force data input 
	mov r7, #0						// r7: count seconds
	mov r8, #0						// r8: output array for DCF77 bits 31-00
	mov r9, #0						// r9: is output array for DCF77 bits 58-32 (bits 63-59 unused)
	ldr r12, =flagSeconds			// r12 is user flag for seconds interrupt

mainloop:
// check seconds interrupt
	ldr r0, [r12]					// check if RTC seconds interrupt was set
	cmp r0, #1
	beq second_over					// ... if so, continue

// check for terminal input
	bl uart_charPresent				// check terminal input
	cmp r0, #0
	beq mainloop					// no input: proceed
	
	bl uart_getChar					// receive character from terminal
	mov r6, r0						// move character input to r6 for evaluation at next second 00
		
	b mainloop						// if no interrupt was set and no key was pressed, continue mainloop

second_over:
	str r10, [r12]					// user flag reset
	
// check on overflow and reset time counter if necessary - just to be on the save side - counter will probably not reach 2^32 seconds
	ldr r0, =BB_RTC_TOF
	ldr r1, [r0]
	ldr r2, =RTC_TSR
	cmp r1, #1
	ittt eq
	streq r10, [r5]					// disable TCE
	streq r10, [r2]					// reset time counter
	streq r11, [r5]					// enable TCE
	
// get second
	cmp r7, #59						// nothing to do in second 59
	beq second_59
	
	cmp r7, #32						// if second is 32 to 58: output from r9
	bhs output_bit_from_higher_array
	
	cmp r7, #01						// is second is 00 to 31: output from r8
	bhs output_bit_from_lower_array
	
/*
	+++++++++ define DCF77 output array (r8, r9) - this code is only executed in second 00 ++++++++++++++++++++++++
	see: https://de.wikipedia.org/wiki/DCF77#Amplitudenumtastung
*/
	ldr r4, =ba_dateTime			// r4 holds reference to date and time data

// in case of terminal input request date and time data
	cmp r6, #CHAR_S					// check on "s" as terminal input
	bne build_dcf77_array			// skip date and time input in case s was not pressed

	ldr r0, =str_day				// get day
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #2]
	bl uart_putByteBase10
	mov r0, #CHAR_LF
	bl uart_putChar

	ldr r0, =str_month				// get month
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #3]
	bl uart_putByteBase10
	mov r0, #CHAR_LF
	bl uart_putChar

	ldr r0, =str_year				// get year
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #4]
	bl uart_putByteBase10
	mov r0, #CHAR_LF
	bl uart_putChar

	ldr r0, =str_hour				// get hour
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #1]
	bl uart_putByteBase10
	mov r0, #CHAR_LF
	bl uart_putChar

	ldr r0, =str_minute				// get minute
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #0]
	bl uart_putByteBase10
	mov r0, #CHAR_LF
	bl uart_putChar

	mov r6, #0						// reset terminal input flag

// ------------------------------------- build DCF77 array ------------------------------------------

build_dcf77_array:
	mov r3, #10						// divisor
	mov r8, #0						// reset lower output array
	mov r9, #0						// reset higher output array

// bits 15-0: always 0
// bits 18-16: MEZ/MESZ	- simplified calculation see below at months
// bit 19: no leap second considered
// bit 20: always 1
	bfi r8, r11, #20, #1 			// write bit 20: start of time information

// bits 24-21: minute (lower digit)
	ldrb r1, [r4], #1				// minute in r1
	udiv r2, r1, r3					// higher digit in r2
	mls r1, r2, r3, r1				// lower digit in r1
	bfi r8, r1, #21, #4				// write bits 24-21
// bits 27-25: minute (higher digit)
	bfi r8, r2, #25, #3				// write bits 27-25
// bit 28: parity minute - see below

// bits 31-29: hour (lower digit)
	ldrb r1, [r4], #1				// hour in r1
	udiv r2, r1, r3					// higher digit in r2
	mls r1, r2, r3, r1				// lower digit in r1
	bfi r8, r1, #29, #3				// write bits 31-29
// bit 32: still hour (lower digit) - remaining bit 32 in r9
	lsr r1, r1, #3
	bfi r9, r1, #0, #1				// write bit 32
// bits 34-33: hour (higher digit)
	bfi r9, r2, #1, #2				// write bits 34-33
// bit 35: parity hour - see below

// bits 39-36: day (lower digit)
	ldrb r1, [r4], #1				// day in r1
	udiv r2, r1, r3					// higher digit in r2
	mls r1, r2, r3, r1				// lower digit in r1
	bfi r9, r1, #4, #4				// write bits 39-36	
// bits 41-40: day (higher digit)
	bfi r9, r2, #8, #2				// write bits 41-40
// bits 44-42: day of week - see below
// bits 48-45: month (lower digit)
	ldrb r1, [r4], #1				// month in r1
// simplified daylight savings time calculation for months of April to October
	cmp r1, #11
	ite hs
	movhs r2, #1					// MEZ in months >= 11
	movlo r2, #2					// MESZ potentially in months < 11
	cmp r1, #4
	it lo
	movlo r2, #1					// MEZ in months < 4
	bfi r8, r2, #17, #2 			// write bits 18-17: MEZ or MESZ
	
	udiv r2, r1, r3					// higher digit in r2
	mls r1, r2, r3, r1				// lower digit in r1
	bfi r9, r1, #13, #4				// write bits 48-45
// bit 49: month (higher digit)
	bfi r9, r2, #17, #1				// write bit 49
// bits 53-50: year (lower digit)
	ldrb r1, [r4]					// year in r1
	udiv r2, r1, r3					// higher digit in r2
	mls r1, r2, r3, r1				// lower digit in r1
	bfi r9, r1, #18, #4				// write bits 53-50
// bits 57-54: year (higher digit)
	bfi r9, r2, #22, #4				// write bits 57-54
// bit 58: parity date - see below
	
// calculate day of week
	ldr r4, =ba_dateTime			// pointer to date and time array - loaded again to reset pointer
	ldrb r2, [r4, #4]				// year in r2
	ldrb r1, [r4, #3]				// month in r1
	ldrb r0, [r4, #2]				// day in r0
	bl calc_dow						// calculate day of week
	bfi r9, r0, #10, #3				// write bits 44-42: day of week	

// calculate parity bit for minute
	ubfx r0, r8, #21, #7			// get bits 27-21 from DCF output array for bits 31-00
	bl calc_even_parity				// calculate parity
	bfi r8, r0, #28, #1				// write bit 28: parity bit

// calculate parity bit for hour
	ubfx r0, r8, #29, #3			// get bits 31-29 from DCF output array for bits 31-00
	bfi r0, r9, #3, #3				// add bits 34-32 from DCF output array for bits 58-32
	bl calc_even_parity				// calculate parity
	bfi r9, r0, #3, #1				// write bit 35: parity bit

// calculate parity bit for date
	ubfx r0, r9, #4, #22			// get bits 57-36 from DCF output array for bits 58-32
	bl calc_even_parity				// calculate parity
	bfi r9, r0, #26, #1				// write bit 58: parity bit

// output to terminal
	mov r0, r9						// r9 will just be used for output of day of week
	bl output_datetime

	mov r7, #0						// reset second counter to 0 to consider waiting time for input 

// ++++++++++++++++++++++ end of second 00 code  - continue with output ++++++++++++++++++++++++++
	
output_bit_from_lower_array:	
	mov r1, r8
	b output_bit
output_bit_from_higher_array:
	mov r1, r9
output_bit:
	cmp r7, #32						// adjust register index if second >= 32 
	ite hs
	subhs r2, r7, #32				// register shift in r2
	movlo r2, r7

	lsr r1, r1, r2					// shift seconds bit to the right
	ubfx r0, r1, #0, #1				// select output bit
	bl put_pulse					// and send respective pulse

	b increment_datetime			// continue with incrementation

second_59:
	mov r0, #CHAR_LF				// output LF when minute is over
	bl uart_putChar
	
increment_datetime:
	add r7, r7, #1					// increment by 1 second

	cmp r7, #60
	ite eq
	moveq r7, #0
	bne mainloop					// second is below 60

	ldr r0, =ba_dateTime			// r0 holds reference to date/time array

	// update_minute:
	ldrb r1, [r0]					// r1 holds minute
	add r1, r1, #1					// increment minute
	strb r1, [r0]					// and store
	cmp r1, #60						// if minute is below 60
	
	itte eq
	moveq r1, #0					// set minute to 0 if it was 60
	strbeq r1, [r0]					// and store
	bne mainloop					// leave loop if minute is below 60

	// update_hour:
	ldrb r1, [r0, #1]!				// r1 holds hour now (pre-indexed to get byte 1)
	add r1, r1, #1					// increment hour
	strb r1, [r0]					// and store
	cmp r1, #24						// if hour is below 24
	
	itte eq
	moveq r1, #0					// set hour to 0 if it was 24
	strbeq r1, [r0]					// and store
	bne mainloop					// leave loop

	// update_day:	
	ldrb r1, [r0, #1]!				// r1 holds day now (byte 2)
	add r1, r1, #1					// increment day
	strb r1, [r0]					// and store
	cmp r1, #31						// if day is below 31 (simplification, every month has 30 days)

	itte eq
	moveq r1, #1					// set day to 1 if it was 31
	strbeq r1, [r0]					// and store
	bne mainloop					// leave loop

	// update_month:
	ldrb r1, [r0, #1]!				// r1 holds month now (byte 3)
	add r1, r1, #1					// increment month
	strb r1, [r0]					// and store
	cmp r1, #13						// if month is below 13

	itte eq
	moveq r1, #1					// set month to 1 if it was 13
	strbeq r1, [r0]					// and store
	bne mainloop					// leave loop

	// update_year:
	ldrb r1, [r0, #1]!				// r0 holds year now (byte 4)
	add r1, r1, #1					// increment year
	strb r1, [r0]					// and store
	cmp r1, #100					// if year is below 100

	itt eq
	moveq r1, #0					// set year to 0 if it was 100
	strbeq r1, [r0]					// and store
	
	b mainloop

/**************************************************************************************************
***************************************************************************************************
***********************************  SUBPROGRAMS  *************************************************
***************************************************************************************************
***************************************************************************************************/

//*********************************** put pulse to LED and PTA6 **************************

.thumb_func
	// parameter: pulse bit in r0
	// return: none, only output to LED, PTA6 and terminal
put_pulse:
	push {r4, LR}
	
	mov r4, r0						// save parameter

// set wait period and load to LDVAL1 register
	cmp r4, #1
	ite eq
	ldreq r1, =WAIT_200MS
	ldrne r1, =WAIT_100MS

	ldr r0, =PIT_LDVAL1
	str r1, [r0]

// clear timer FlagRegister
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0]					// clear TIF (writing 1 to the flag clears it)

// deassert PTA6
	ldr r0, =BB_GPIOA_DCF77			// load memory address of DCF77
	mov r1, #0
	str r1, [r0]					// deactivate DCF77

// output to LEDs 
	ldr r0, =BB_GPIOA_LED1			// load memory address of LED E1
	mov r1, #0
	str r1, [r0]					// activate LED E1

// output of bit to terminal
	mov r0, r4
	bl uart_putByteBase10

// enable PIT
	ldr r0, =BB_PIT_TEN
	mov r1, #1
	str r1, [r0]

// wait for PIT interrupt to set
	ldr r0, =flagPIT				// check user flag
wait_PIT:
	ldr r1, [r0]
	cmp r1, #0
	beq wait_PIT					// loop until flagPIT raises

// reset user flag
	mov r1, #0
	str r1, [r0]					// user flag reset

// disable PIT
	ldr r0, =BB_PIT_TEN
	mov r1, #0
	str r1, [r0]

// clear LED
	ldr r0, =BB_GPIOA_LED1			// load memory address of LED E1
	mov r1, #1
	str r1, [r0]					// deactivate LED E1
	
// assert PTA6
	ldr r0, =BB_GPIOA_DCF77			// load memory address of DCF77
	mov r1, #1
	str r1, [r0]					// reactivate DCF77
	
	pop {r4, PC}

//*********************************** RTC seconds ISR **************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagSeconds' set
seconds_isr:
	ldr r0, =flagSeconds
	mov r1, #1
	str r1, [r0]					// user flag set, no corresponding status flag to clear
	bx LR

//********************************************** PIT ISR **************************

.thumb_func
	// parameter: none
	// return: none, only user flag 'flagPIT' set
pit_isr:
	mov r1, #1
	
	// clear timerFlagRegister
	ldr r0, =PIT_TFLG1
	str r1, [r0]					// clear TIF

	// set userFlag
	ldr r0, =flagPIT
	str r1, [r0]					// user flag set

	bx LR

//*********************************** calculate even parity **************************

.thumb_func
	// parameter: bit sequence in r0
	// return: parity bit in r0
calc_even_parity:
	mov r2, #32						// loop counter in r2
	mov r3, #0						// parity counter in r3
	clz r1, r0						// count leading zeros in input data into r1
	subs r2, r2, r1					// number of bits to check in r2
	beq parity_exit					// leave if all bits are 0
parity_loop:
	lsrs r0, r0, #1					// shift input to the right to get carry bit					
	adc r3, r3, #0					// add carry bit
	subs r2, r2, #1					// reduce counter
	bne parity_loop					// repeat if necessary
parity_exit:	
	and r0, r3, #1					// return parity bit

	bx LR

//*********************************** time and date output **************************

.thumb_func
	// parameter: higher DCF77 array in r0 - just used for day of week to avoid recalculation
	// return: none, only output to terminal
output_datetime:
	push {r4, LR}
	
	ldr r4, =ba_dateTime
	
	// weekday
	ldr r2, =stra_dow
	ubfx r0, r0, #10, #3			// day of week now in r0
	ldr r0, [r2, r0, lsl #2]
	bl uart_putString
	
	// day
	ldrb r0, [r4, #2]
	cmp r0, #10
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1
	
	mov r0, #CHAR_DOT
	bl uart_putChar
	
	// month
	ldrb r0, [r4, #3]
	cmp r0, #10
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1

	mov r0, #CHAR_DOT
	bl uart_putChar
	
	// year
	ldrb r0, [r4, #4]
	cmp r0, #10
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1

	mov r0, #CHAR_SPACE
	bl uart_putChar
	
	// hour
	ldrb r0, [r4, #1]
	cmp r0, #10
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1

	mov r0, #CHAR_COLON
	bl uart_putChar
	
	// minute
	ldrb r0, [r4, #0]
	cmp r0, #10
	ite hs
	ldrhs r1, =uart_putByteBase10
	ldrlo r1, =uart_putByte
	blx r1

	ldr r0, =str_uhr
	bl uart_putString
	
	
	pop {r4, PC}

//********************************** day of week calculation ***********************************

/*
	I know, this was not a required - did it just for fun
	
	Formula source: https://de.wikipedia.org/wiki/Wochentagsberechnung#Programmierung
*/

.thumb_func
	// parameter: DD in r0, MM in r1, YY in r2 (century is always 20.. and will be placed in r3) 
	// return: week of day in r0 (Monday = 1 to Sunday = 7)
calc_dow:
	push {r4-r7, LR}

// calculate day of week (r4 is used for accumulation, r5 and r6 hold subtotals, r7 holds constants)
	mov r3, #20				// put century in r3

	cmp r1, #3				// reduce year by 1 if month is Jan or Febr
	it lo
	sublo r2, r2, #1
	
	cmp r2, #0				// if year falls below zero, adjust to 99 and reduce century by 1
	itt lo
	movlo r2, #99
	sublo r3, r3, #1

	mov r4, #700			// to avoid modulo 7 calculations with negative numbers
	add r4, r4, r0			// r4 = d
	
	add r5, r1, #9			// r5 = m + 9
	mov r7, #12
	udiv r6, r5, r7
	mls r5, r6, r7, r5		// r5 = (m + 9) % 12
	add r5, r5, #1			// r5 = (m + 9) % 12 + 1
	mov r7, #26
	mul r5, r5, r7
	sub r5, r5, #2
	mov r7, #10
	udiv r5, r5, r7			// floor (2,6 ((m + 9) % 12 + 1) - 0,2) in r5 now
	add r4, r4, r5			// r4 = d + floor (2,6 ((m + 9) % 12 + 1) - 0,2)
	
	add r4, r4, r2			// r4 = d + floor (2,6 ((m + 9) % 12 + 1) - 0,2) + y
	
	mov r5, r2
	lsr r5, #2				// floor (y / 4) in r5 now
	add r4, r4, r5			// r4 = d + floor (2,6 ((m + 9) % 12 + 1) - 0,2) + y + floor (y / 4)

	mov r5, r3
	lsr r5, #2				// floor (c / 4) in r5 now
	add r4, r4, r5			// r4 = d + floor (2,6 ((m + 9) % 12 + 1) - 0,2) + y + floor (y / 4) + floor (c / 4)

	mov r5, r3
	lsl r5, #1				// 2c in r5 now
	sub r4, r4, r5			// r4 = d + floor (2,6 ((m + 9) % 12 + 1) - 0,2) + y + floor (y / 4) + floor (c / 4) - 2 c
	
	sub r4, r4, #1			// r4 = d + floor (2,6 ((m + 9) % 12 + 1) - 0,2) + y + floor (y / 4) + floor (c / 4) - 2 c - 1

	mov r7, #7
	udiv r5, r4, r7
	mls r0, r5, r7, r4
	add r0, r0, #1			// now we have w in r0 = (d + floor (2,6 ((m + 9) % 12 + 1) - 0,2) + y + floor (y / 4) + floor (c / 4) - 2 c - 1) % 7 + 1

	pop {r4-r7, PC}

/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/


/*** Datenbereich (ab 0x20000000) ***/
.data
flagPIT:		.word 0x00		// user flag - is 1 on PIT interrupt
flagSeconds:	.word 0x00		// user flag - is 1 on RTC seconds interrupt
stra_dow:		.word str_dow_0, str_dow_1, str_dow_2, str_dow_3, str_dow_4, str_dow_5, str_dow_6, str_dow_7
ba_dateTime:	.byte 0x00, 0x00, 0x01, 0x01, 0x00	// minute, hour, day, month, year
str_dow_0:		.asciz "***" // day of week is not zero-based (Monday = 1)
str_dow_1:		.asciz "Mo., "
str_dow_2:		.asciz "Di., "
str_dow_3:		.asciz "Mi., "
str_dow_4:		.asciz "Do., "
str_dow_5:		.asciz "Fr., "
str_dow_6:		.asciz "Sa., "
str_dow_7:		.asciz "So., "
str_uhr:		.asciz " Uhr\n"
str_minute:		.asciz "Minute eingeben (mm): "
str_hour:		.asciz "Stunde eingeben (hh): "
str_day:		.asciz "Tag eingeben (dd): "
str_month:		.asciz "Monat eingeben (mm): "
str_year:		.asciz "Jahr eingeben (jj): "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

// register addresses
.equ SCR_VTOR,				0xe000ed08								// register for IVT
.equ NVIC_ISER1,			0xe000e100 + 0x1 << 2					// NVIC non-IPR register number is 1
.equ NVIC_ICPR1,			0xe000e280 + 0x1 << 2					//  (integer part of IRQ div 32)

.equ SIM_SCGC5,				0x40048038								// SCGC5 for Port A clock
.equ SIM_SCGC6,				0x4004803c								// SCGC6 for FTM0 clock

.equ PORTA_PCR6,			0x40049018								// PORTA 6			

.equ FTM0_SC,				0x40038000								// FTM0 Status and control
.equ FTM0_CNT,				0x40038004								// FTM0 Counter
.equ FTM0_MOD,				0x40038008								// FTM0 Modulo
.equ FTM0_C3SC,				0x40038024								// FTM0 Channel 3 Status and control
.equ FTM0_C3V,				0x40038028								// FTM0 Channel 3 Value
.equ FTM0_CNTIN,			0x4003804c								// FTM0 Counter initial value

// bit band constants
__BBREG	BB_SIM_PORTA,		SIM_SCGC5, 9							// Port A Clock Gate Control
__BBREG	BB_SIM_FTM0,		SIM_SCGC6, 24							// FTM0 Clock Gate Control

__BBREG BB_FTM0_TOF,		FTM0_SC, 7								// FTM0 Timer Overflow Flag
__BBREG BB_FTM0_CHF,		FTM0_C3SC, 7							// FTM0 Channel 3 Channel Flag
__BBREG BB_FTM0_ELS3A,		FTM0_C3SC, 2							// FTM0 Channel 3 Level Select

// various constants
.equ IRQ_BITFIELD,			1<<(62%32)								// FTM0: IRQ 62
.equ OFFSET_IRQ62,			(62 + 0x10) << 2

.equ INIT_FTM0_SC,			0x48									// TOIE, CLKS = system clock, PS = divide by 1
.equ INIT_FTM0_CNT,			0x1										// writes CNTIN
.equ INIT_FTM0_MOD,			25000 - 1								// equals 1 ms = base frequency of 1kHz
.equ INIT_FTM0_C3SC,		0x68									// CHIE, MSB, ELS3B, ELS3A = 0 (DECAPEN=0, COMBINE=0, CPWMS=0 => Edge-Aligned PWM)
.equ INIT_FTM0_C3V,			1250									// 5% duty cycle at startup 25000 x 5% = 1250
.equ INIT_FTM0_CNTIN,		0x0										// initial counter at 0

.equ CHAR_POS,				'+'										// positive polarity
.equ CHAR_NEG,				'-'										// negative polarity
.equ CHAR_PROMPT,			'>'										// prompt
.equ CHAR_0,				'0'										// to check terminal input
.equ CHAR_9,				'9'										// to check terminal input
.equ CHAR_LF,				0x0a									// line feed for terminal output

main:	

/**************************************************************************************************
***************************************************************************************************
*********************************** CONFIGURATION *************************************************
***************************************************************************************************
***************************************************************************************************/

	bl uart_init
	
// load some constants
	mov r10, #0						// r10	fixed value of 0 to avoid multiple moves	
	mov r11, #1						// r11	fixed value of 1 to avoid multiple moves

// *************************** configure system integration module *******************************

// enable Port A clock
	ldr r0, =BB_SIM_PORTA
	str r11, [r0]

// enable FTM0 clock
	ldr r0, =BB_SIM_FTM0
	str r11, [r0]

// ******************************* interrupt configuration ********************************************

// load reference to IVT
	ldr r0, =SCR_VTOR
	ldr r1, [r0]

// set interrupt vector
	ldr r0, =ftm_isr
	str r0, [r1, #OFFSET_IRQ62]		// IRQ62 for FTM0 interrupt

// load bitfield for vectors
	ldr r0, =IRQ_BITFIELD

// clear pending interrupts
	ldr r1, =NVIC_ICPR1
	str r0, [r1]

// set_NVIC_SetEnableRegister
	ldr r1, =NVIC_ISER1
	str r0, [r1]

// *************************** configure port control *******************************************

// set MUX = 011 = FTM0_CH3 for PWM
	mov r0, #0x300
	ldr r1, =PORTA_PCR6
	str r0, [r1]

// *********************************** configure FTM0 ***********************************	

	ldr r0, =FTM0_CNTIN
	ldr r1, =INIT_FTM0_CNTIN
	str r1, [r0]

	ldr r0, =FTM0_CNT				// set CNTIN first
	ldr r1, =INIT_FTM0_CNT
	str r1, [r0]

	ldr r0, =FTM0_MOD
	ldr r1, =INIT_FTM0_MOD
	str r1, [r0]

	ldr r0, =FTM0_SC				// set MOD first
	ldr r1, =INIT_FTM0_SC
	str r1, [r0]

	ldr r0, =FTM0_C3SC
	ldr r1, =INIT_FTM0_C3SC
	str r1, [r0]

	ldr r0, =FTM0_C3V
	ldr r1, =INIT_FTM0_C3V
	str r1, [r0]

/**************************************************************************************************
***************************************************************************************************
***********************************     LOGIC     *************************************************
***************************************************************************************************
***************************************************************************************************/

	mov r4, #0						// r4: buffer for polarity change to be executed at next overflow interrupt
	mov r5, #0						// r5: buffer for duty cycle change to be executed at next channel interrupt
	ldr r6, =FTM0_C3V				// r6: pointer to C3V = duty cycle
	ldr r7, =BB_FTM0_ELS3A			// r7: pointer to ElS3A = level selection
	ldr r8, =flagChannelIR			// r8: channel flag
	ldr r9, =flagOverflowIR			// r9: overflow flag

	mov r0, #CHAR_PROMPT			// show initial prompt on terminal
	bl uart_putChar
	
mainloop:
// check flags
	ldr r0, [r8]					// check channel flag
	cmp r0, #1
	beq channel_flag_set
	
	ldr r0, [r9]					// check overflow flag
	cmp r0, #1
	beq overflow_flag_set

// check_input
	bl uart_charPresent				// check terminal input
	cmp r0, #0
	beq mainloop					// no input: loop
	
// evaluate input
	bl uart_getChar					// receive character from terminal

	cmp r0, CHAR_POS				// if + entered
	itt eq
	moveq r4, #1					// put 1 in overflow buffer
	beq mainloop
	
	cmp r0, CHAR_NEG				// if - entered
	itt eq
	moveq r4, #-1					// put -1 in overflow buffer
	beq mainloop

	cmp r0, CHAR_0					// if character entered is < ascii of 0
	blo mainloop					// invalid, leave loop
	
	cmp r0, CHAR_9					// if character entered is > ascii of 9
	bhi mainloop					// invalid leave loop
	
// calculate new length of duty cycle in ticks (MOD = 25000 => 10% = 2500) and place in r5
	sub r5, r0, #0x30				// reduce ascii code of terminal input by 0x30 (asc 0 = 0x30, asc 9 = 0x39) and put in r5
	ldr r0, =2500
	mul r5, r5, r0					// multiply by 2500 (10%) per step
	add r5, r5, #1250				// add 1250 for step 0
		
	b mainloop						// input data is now in buffers r4 or r5

channel_flag_set:
	str r10, [r8]					// reset flag

// check duty cycle update
	cmp r5, #0
	beq mainloop					// check if new duty cycle was entered, if not: leave

// update duty cycle
	str r5, [r6]					// update C3V with new duty cycle

// output	
	ldr r0, =str_duty				// output info on terminal
	bl uart_putString
	
// clean up
	mov r5, r10						// clear input data

	mov r0, #CHAR_PROMPT			// show new prompt on terminal
	bl uart_putChar

	b mainloop
	
overflow_flag_set:
	str r10, [r9]					// reset flag

// check polarity update
	cmp r4, #0
	beq mainloop					// check if new polarity was entered, if not: leave

// update polarity
	cmp r4, #1						// r4 can either be 1 or -1 now
	ittee eq
	moveq r1, #0					// if r4 = 1 ==> set ELS3A to 0x0
	ldreq r0, =str_pos
	movne r1, #1					// if r4 = -1 ==> set ELS3A to 0x1
	ldrne r0, =str_neg
	
	str r1, [r7]					// update ELS3A with new level selection

// output	
	bl uart_putString				// output info to terminal

// clean up
	mov r4, r10						// clear input data

	mov r0, #CHAR_PROMPT			// show new prompt on terminal
	bl uart_putChar

	b mainloop


VIELEN_DANK:

