*/

/**************************************************************************************************
***************************************************************************************************
***********************************  SUBPROGRAMS  *************************************************
***************************************************************************************************
***************************************************************************************************/

//************************************** FTM ISR ************************************

.thumb_func
	// parameter: none
	// return: none, only user flags set
ftm_isr:
	mov r0, #0
	mov r1, #1

// channel interrupt	
	ldr r2, =BB_FTM0_CHF			// check channel interrupt
	ldr r3, [r2]
	cmp r3, r1
	ittt eq							// if CHF was set: clear CHF and set flagChannelIR
	streq r0, [r2]
	ldreq r2, =flagChannelIR
	streq r1, [r2]

// overflow interrupt	
	ldr r2, =BB_FTM0_TOF			// check overflow interrupt
	ldr r3, [r2]
	cmp r3, r1
	ittt eq							// if TOF was set: clear TOF and set flagOverflowIR
	streq r0, [r2]
	ldreq r2, =flagOverflowIR
	streq r1, [r2]
	
	bx LR

/**************************************************************************************************
***************************************************************************************************
***********************************       DATA    *************************************************
***************************************************************************************************
***************************************************************************************************/


/*** Datenbereich (ab 0x20000000) ***/
.data
flagChannelIR:		.word 0x00		// user flag - is 1 on channel interrupt
flagOverflowIR:		.word 0x00		// user flag - is 1 on overflow interrupt

str_pos:	.asciz "Positive Polaritaet gesetzt.\n"
str_neg:	.asciz "Negative Polaritaet gesetzt.\n"
str_duty:	.asciz "Duty cycle aktualisiert.\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
	Registerverwendung
	R0-R3		UP Parameter
	R0-R1		UP Rückgabe
	R4			Zählerwert; Anzahl einzugebende Bytes
	R5			Startadresse des Byte Arrays (eingegebene Werte)
	R6			Aktuelles Maximum
	R7, R8		Laufzeitmessung
	R9			Anzahl Takte zur Ermittlung des Zählerstandes
*/

// Konstanten
.equ COUNTER, 0x10 // Schleifendurchläufe; initialisiert mit Wert dec 16 (0x10)

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Taktzahl zur Ermittlung des Zählerstandes ermitteln
	// Ermittelt wird die Taktzahl eines pit3_getval Befehls + eines mov Befehls zum Ablegen des Ergebnisses in einem Register
	bl pit3_init
	bl pit3_getval
	mov r7, r0
	bl pit3_getval
	mov r8, r0
	subs r9, r7, r8
	// Einen Takt für mov Befehl abziehen
	subs r9, r9, #1
	// Taktzahl ausgeben
	ldr r0, = str_timer_takte
	bl uart_putString
	mov r0, r9
	bl uart_putByte
	
loop_program:
	// Usereingaben
	ldr r0, = str_eingabe 	// Adresse der str_eingabe variable in R0 Register laden
	bl uart_putString 		// Ausgabe UP aufrufen; Übergabe des auszugebenden Wertes über R0 Register (indirekt über Adresse)
	mov r4, #COUNTER 		// Zählerwert in Register R4 laden
	ldr r5, =bytearray		// Anfangsadresse des Bytearrays in Register R5 laden
	// Initialisierung der Register zur Laufzeitmessung
	mov r7, #0
	mov r8, #0

// Eingabeschleife
loop_eingabe:
	ldr r0, =str_prompt		// prompt string in Register R0 einlesen
	bl uart_putString		// prompt string ausgeben
	bl uart_getByte			// einzelnes byte einlesen
	strb r0, [r5], #1		// Byte aus Register R0 an Adresse aus Register R5 im Speicher ablegen und anschließend im 1 erhöhen (#1 -> Postinkrement)
	bl uart_putByte			// Zeichen aus R0 ausgeben
	subs r4, r4, #1			// Wert aus R4 um 1 reduzieren und in R4 ablegen; subs setzt Flags im Statusregister (im Gegensatz zu sub)
	bne loop_eingabe		// prüft das Zeroflag(?) im Statusregister und verzweigt falls es nicht gesetzt ist
	
	// Maximumsbestimmung
	ldr r0, =str_startsuche
	bl uart_putString
	mov r6, #0				// Register R6 initialisieren; enhält das aktuelle Maximum
	mov r4, #COUNTER		// Counter zurücksetzen
	
	// Laufzeitmessung starten 
	bl pit3_init
	bl pit3_getval
	mov r7, r0

loop_maximum:
	ldrb r0, [r5, #-1]!		// Adreesse des letzten Array Elements in R0 laden. Addresse in R5 vor dem Laden dekrementieren
	cmp r0, r6				// aktuelles Element mit aktuellem Maximum vergleichen
	it hi					// Bedingte verzweigung, ausgeführt wenn vorheriger Vergleich mit Ergebnis "größer" (hi -> higher)
		movhi r6, r0		// Wert aus R6 in R0 speichern
	subs r4, r4, #1			// Zählerwert in R4 um 1 dekrementieren
	bne loop_maximum		// Sprung, falls R4 noch nicht 0 ist
	
	// Laufzeitmessung beenden und Ergebnis in R7 ablegen
	bl pit3_getval
	mov r8, r0
	subs r7, r7, r8
	subs r7, r7, r9			// Taktzahl zur bestimmeung des Timerwertes abziehen
	
	// Maximum im Speicher ablegen
	ldr r0, =maximum		// Adresse für Zielspeicherstelle des Maximum in R0 laden
	strb r6, [r0]			// Maximum Wert im Speicher ablegen
	// Ergebnis ausgeben
	ldr r0, =str_endsuche
	bl uart_putString
	mov r0, r6				// Maximum Wert in R0 laden
	bl uart_putByte			// Maximum ausgeben
	
	// Ergebnis der Laufzeitmessung ausgeben
	ldr r0, =str_laufzeit
	bl uart_putString
	mov r0, r7
	bl uart_putByteBase10
	
	// Rücksprung zum Anfang
	mov r1, #0
	ldr r0, =maximum
	strb r1, [r0]
	ldr r0, =newline
	bl uart_putString
	b loop_program

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
// Dateneingabe
str_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben\n"
str_prompt: .asciz "\n>0x"
bytearray:
	.rept COUNTER
	.byte 0x00
	.endr
// Maximumbestimmung
str_startsuche: .asciz "\nDurchsuchen gestartet"
str_endsuche: .asciz "\nDurchsuchen beendet\nMaximum: 0x"
maximum: .byte 0x0
// Zeitmessung
str_laufzeit: .asciz "\nDie Suchzeit btraegt (in Takten): "
str_timer_takte: .asciz "Takte zur Bestimmung des Timers: 0x"
newline: .asciz "\n"

/*
	Versuch 1-1 e - Einfluss der Position des Maximums im Datensatz auf die Laufzeit
	Die hier vorliegende Implementierung durchläuft immer das gesamte Array. Die Suchzeit ist damit konstant
	und einzig von der Länge des Arrays abhängig. Die Position des Maximums im Array spielt keine Rolle.
*/
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
	Registerverwendung
	R5 = Erste Bitposition
	R6 = Zweite Bitposition
	
	R7 = Maske zum Setzen / Rücksetzen eines Bits
	R8 = Anzahl Rotationen zum Erzeugen der Maske
	R9 = Aktueller Wert des Speicherworts
	
	R10 = Bit-Banding Adresse
	R11 = Bit-Banding Adresse
	R4 = Byte-Offset der mit Bit-Banding zu manipulierenden Variable zum Start des "Daten-Bereichs"
*/

// Konstanten
// Maske zur Korrektur der eingegebenen Bitpoisition
.equ BITPOSMASK, 0x1F
// Initialwert des zu manipulierenden Speicherworts
.equ INITIALVAL, 0xAAAAAAAA
// Startadresse der "Daten-Region"
.equ DATABASE, 0x20000000
// Startadresse der Bitbanding Alias-Region
.equ BBALIASBASE, 0x22000000

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
start:		
	// erste Bitposition einlesen
	ldr r0, =strFirstBit
	bl uart_putString
	bl uart_getByte
	// höherwertige 3 Bits zurücksetzen; Bitposition auf 5-Bit Zahl reduzieren
	and r0, r0, #BITPOSMASK
	mov r5, r0
	bl uart_putByte
	
	ldr r0, =newline
	bl uart_putString		
	
	// zweite Bitposition einlesen
	ldr r0, =strSecondBit
	bl uart_putString
	bl uart_getByte
	// höherwertige 3 Bits zurücksetzen; Bitposition auf 5-Bit Zahl reduzieren
	and r0, r0, #BITPOSMASK
	mov r6, r0
	bl uart_putByte
		
	ldr r0, =newline
	bl uart_putString
	ldr r0, =newline
	bl uart_putString		
	
	// Speicherwort ohne Bitbanding manipulieren
	
	// Speicherwort initialisieren
	ldr r0, =strInitialValue
	bl uart_putString
	ldr r0, =maskWord
	mov r9, #INITIALVAL
	str r9, [r0]
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, =newline
	bl uart_putString
	
	// Bit an erster eingegebener Bitposition (R5) rücksetzen
	// Maske zum Rücksetzen eines Bits mit logischem AND erzeugen
	movs r7, #0x7FFFFFFF
	// Anazhl notwendiger Rotationen berechnen -> dec 31 - Bitposition
	mov r0, #0x1F
	sub r8, r0, r5
	// Maske rotieren
	ror r7, r7, r8
	// Speicherwort manipulieren
	and r9, r9, r7
	// Ergebnis ausgeben
	ldr r0, =strResultResetStd
	bl uart_putString
	mov r0, r9
	bl uart_putInt32
	
	ldr r0, =newline
	bl uart_putString
	
	// Bit an zweiter eingegebener Position (R6) setzen
	// Maske zum setzen eines Bits mit logischem OR erzeugen
	mov r7, #0x80000000
	// Anazhl notwendiger Rotationen berechnen -> dec 31 - Bitposition
	mov r0, #0x1F
	sub r8, r0, r6
	// Maske rotieren
	ror r7, r7, r8
	// Speicherwort manipulieren
	orr r9, r9, r7
	// Ergebnis ausgeben
	ldr r0, =strResultSetStd
	bl uart_putString
	mov r0, r9
	bl uart_putInt32
	
	// Ergebnis speichern
	ldr r0, =maskWord
	str r9, [r0]
	
	ldr r0, =newline
	bl uart_putString
	ldr r0, =newline
	bl uart_putString
	
	// Speicherwort mit Bitbanding manipulieren
	
	// Speicherwort initialisieren,
	ldr r0, =strInitialValue
	bl uart_putString
	ldr r0, =bbWord
	mov r9, #INITIALVAL
	str r9, [r0]
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, =newline
	bl uart_putString
	
	// Byte-Offset der bbWord Variable zum Begin des "Daten-Bereichs" berechnen
	ldr r0, =bbWord
	sub r4, r0, #DATABASE
	
	// BB Alias-Adresse der ersten Bitposition berechnen
	mov r0, r5
	bl divByEight
	// Offset des Speicherworts zum Byte-Offset ergänzen
	add r0, r4
	// bit_word_offset = (byte_offset x 32) + (bit_number x 4)
	// Byte-Offset * 32(dec)
	mov r2, #0x20
	mul r2, r0, r2
	// Bit-Number * 4(dec)
	mov r3, #0x04
	mul r3, r1, r3
	// Bit-Word-Offset berechnen
	add r2, r2, r3
	// bit_word_addr = bit_band_base + bit_word_offset
	add r10, r2, #BBALIASBASE
	
	// erste BB Alias-Adresse ausgeben
	ldr r0, =strBBAdrFirstBit
	bl uart_putString
	mov r0, r10
	bl uart_putInt32
	ldr r0, =newline
	bl uart_putString	
	
	// BB Alias-Adresse der zweiten Bitposition berechnen
	mov r0, r6
	bl divByEight
	// Offset des Speicherworts zum Byte-Offset ergänzen
	add r0, r4
	// bit_word_offset = (byte_offset x 32) + (bit_number x 4)
	// Byte-Offset * 32(dec)
	mov r2, #0x20
	mul r2, r0, r2
	// Bit-Number * 4(dec)
	mov r3, #0x04
	mul r3, r1, r3
	// Bit-Word-Offset berechnen
	add r2, r2, r3
	// bit_word_addr = bit_band_base + bit_word_offset
	add r11, r2, #BBALIASBASE
	
	// zweite BB Alias-Adresse ausgeben
	ldr r0, =strBBAdrSecondBit
	bl uart_putString
	mov r0, r11
	bl uart_putInt32
	
	ldr r0, =newline
	bl uart_putString	
	
	// Speicherwort mit Bit-Banding manipulieren und Ergebnis ausgeben
	// Rücksetzen der ersten Bitposition
	mov r0, #0x00
	str r0, [r10]
	ldr r0, =strResultResetBB
	bl uart_putString
	ldr r0, =bbWord
	ldr r0, [r0]
	bl uart_putInt32
	ldr r0, =newline
	bl uart_putString	
	// Setzen der zweiten Bitposition
	mov r0, #0x01
	str r0, [r11]
	ldr r0, =strResultSetBB
	bl uart_putString
	ldr r0, =bbWord
	ldr r0, [r0]
	bl uart_putInt32
	ldr r0, =newline
	bl uart_putString		
	
	ldr r0, =newline
	bl uart_putString	
	b start
	
end:
	b end

/** Subroutinen **/
/*
	Bit-Banding: Bestimmt Byte-Offset und Bit-Number für eine Bitposition
	R0 -> Bitposition
	R0 <- Byte-Offset
	R1 <- Bit-Number
*/	
.thumb_func
divByEight:
	mov r3, r0
	mov r0, 0x0
	nextByte:
	mov r1, r3
	subs r3, r3, 0x08
	it pl
		addpl r0, 0x01
		bpl nextByte
	bx lr
	
/*** Datenbereich (ab 0x20000000) ***/
.data
maskWord: 			.word 0x00000000 
dummy1: .word 0x00000000
dummy2: .word 0x00000000
dummy3: .word 0x00000000
bbWord: 			.word 0x00000000
newline: 			.asciz "\n"
strInitialValue:	.asciz "Initialwert des Speicherwortes: 0x"
strFirstBit: 		.asciz "Nummer des 0-Bits: 0x"
strSecondBit: 		.asciz "Nummer des 1-Bits: 0x"
strResultResetStd: 	.asciz "Ergebnis Ruecksetzen ohne Bitbanding: 0x"
strResultSetStd: 	.asciz "Ergebnis Setzen ohne Bitbanding: 0x"
strBBAdrFirstBit:	.asciz "BB Alias-Adresse der ersten Bitposition: 0x"
strBBAdrSecondBit:	.asciz "BB Alias-Adresse der zweiten Bitposition: 0x"
strResultResetBB: 	.asciz "Ergebnis Ruecksetzen mit Bitbanding: 0x"
strResultSetBB: 	.asciz "Ergebnis Setzen mit Bitbanding: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
	Registerverwendung
	R4 = Vektorzeiger V1
	R5 = Vektorzeiger V2
	R6 = Vektorzeiger Min
	R7 = Vektorzeiger Max
	
	R10 = Vektorwert Min
	R11 = Vektorwert Max
	
	R8 = Laufzeitmessung
*/

/* Konstanten */
.equ UNDERSCORE, 0x5F
.equ TIMERREADCYCLES, 0x11

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	/*
	Benötigte Takte zur Timerabfrage bestimmen
	bl pit3_init
	bl pit3_getval
	mov r0, r8
	bl pit3_getval
	sub r0, r8, r0
	//bl uart_putByte
	//bl uart_putByteBase10
	
	Ergebnis: 18(dec) Takte
	Korrektur um -1 Takt für mov Befehl
	=> 17(dec) bzw. 0x11
	*/
start:
	bl inputVectors
	ldr r0, =newline
	bl uart_putString
	bl outputVectors
	
	/*
		Die Laufzeitberechnung erfolgt jeweils inklusive des Ladens und Ablegens der Vektoren
		aus dem .data Speicherbereich, aber ohne der Ausgabe auf dem Terminal.
	*/
	
	// Min Max Vektorberechnung ohne DSP Befehle
	// Laufzeitmessung starten
	bl pit3_init
	bl pit3_getval
	mov r8, r0
	// Vektorzeiger initialisieren
	ldr r4, =v1
	ldr r5, =v2
	ldr r6, =minNoDsp
	ldr r7, =maxNoDsp
	// Erstes Byte vergleichen
	ldrb r0, [r4]
	ldrb r1, [r5]
	bl orderBytesAsc
	strb r0, [r6]
	strb r1, [r7]
	// Zweites Byte vergleichen
	add r4, #1
	add r5, #1
	add r6, #1
	add r7, #1
	ldrb r0, [r4]
	ldrb r1, [r5]
	bl orderBytesAsc
	strb r0, [r6]
	strb r1, [r7]	
	// Drittes Byte vergleichen
	add r4, #1
	add r5, #1
	add r6, #1
	add r7, #1
	ldrb r0, [r4]
	ldrb r1, [r5]
	bl orderBytesAsc
	strb r0, [r6]
	strb r1, [r7]
	// Viertes Byte vergleichen
	add r4, #1
	add r5, #1
	add r6, #1
	add r7, #1
	ldrb r0, [r4]
	ldrb r1, [r5]
	bl orderBytesAsc
	strb r0, [r6]
	strb r1, [r7]
	// Laufzeitmessung stoppen
	bl pit3_getval
	sub r0, r8, r0
	sub r0, r0, #TIMERREADCYCLES
	mov r8, r0
	// Min Max Vektoren ausgeben
	ldr r0, =newline
	bl uart_putString
	ldr r0, =strNoDsp
	bl uart_putString
	ldr r0, =newline
	bl uart_putString	
	
	ldr r0, =strMinOutput
	bl uart_putString
	ldr r0, =minNoDsp
	ldr r0, [r0]
	bl outputVector
	
	ldr r0, =newline
	bl uart_putString
		
	ldr r0, =strMaxOutput
	bl uart_putString
	ldr r0, =maxNoDsp
	ldr r0, [r0]
	bl outputVector	
	
	ldr r0, =newline
	bl uart_putString
	
	// Laufzeit ausgeben
	ldr r0, =strUsedCycles
	bl uart_putString
	mov r0, r8
	bl uart_putByteBase10
	ldr r0, =newline
	bl uart_putString
	
	// Min Max Vektorberechnung mit DSP Befehlen
	// R1 = Wert Vektor 1
	// R2 = Wert Vektor 2
	
	// Laufzeitmessung starten
	bl pit3_init
	bl pit3_getval
	mov r8, r0
	// Werte laden
	ldr r0, =v1
	ldr r1, [r0]
	ldr r0, =v2
	ldr r2, [r0]
	// byteweiser Vergleich
	usub8 r0, r1, r2
	// Maximum selektieren
	sel r11, r1, r2
	// Minimum selektieren
	sel r10, r2, r1
	// Werte im Speicher ablegen
	ldr r0, =minWithDsp
	str r10, [r0]
	ldr r0, =maxWithDsp
	str r11, [r0]
	// Laufzeitmessung stoppen
	bl pit3_getval
	sub r0, r8, r0
	sub r0, r0, #TIMERREADCYCLES
	mov r8, r0
	
	// Werte ausgeben
	ldr r0, =newline
	bl uart_putString
	ldr r0, =strWithDsp
	bl uart_putString
	ldr r0, =newline
	bl uart_putString
	// Minimum ausgeben
	ldr r0, =strMinOutput
	bl uart_putString
	mov r0, r10
	bl outputVector
	ldr r0, =newline
	bl uart_putString
	// Maximum ausgeben
	ldr r0, =strMaxOutput
	bl uart_putString
	mov r0, r11
	bl outputVector
	ldr r0, =newline
	bl uart_putString	
	// Laufzeit ausgeben
	ldr r0, =strUsedCycles
	bl uart_putString
	mov r0, r8
	bl uart_putByteBase10
	ldr r0, =newline
	bl uart_putString
	
	ldr r0, =newline
	bl uart_putString		
	b start	
end:
	b end

/** Subroutinen **/
/*
	Eingabe der Vektoren V1, V2 und Ablage im .data Speicherbereich
*/
.thumb_func
inputVectors:
	push {r4,lr}
	
	// Eingabeaufforderung
	ldr r0, =strVektorInput
	bl uart_putString
	ldr r0, =newline
	bl uart_putString
	
	// Eingabe V1
	ldr r0, =strV1Input
	bl uart_putString
	ldr r4, =v1
	bl uart_getByte
	strb r0, [r4], #1
	bl uart_putByte
	bl uart_getByte
	strb r0, [r4], #1
	bl uart_putByte
	bl uart_getByte
	strb r0, [r4], #1
	bl uart_putByte
	bl uart_getByte
	strb r0, [r4]
	bl uart_putByte
	
	ldr r0, =newline
	bl uart_putString
	
	// Eingabe V2
	ldr r0, =strV2Input
	bl uart_putString
	ldr r4, =v2
	bl uart_getByte
	strb r0, [r4], #1
	bl uart_putByte
	bl uart_getByte
	strb r0, [r4], #1
	bl uart_putByte
	bl uart_getByte
	strb r0, [r4], #1
	bl uart_putByte
	bl uart_getByte
	strb r0, [r4]
	bl uart_putByte	
	
	ldr r0, =newline
	bl uart_putString
	
	pop {r4,lr}
	bx lr

/*
	Gibt die Vekoren V1 und V2 aus dem .data Speicher aus
*/
.thumb_func
outputVectors:
	push {r4,lr}
	
	ldr r0, =strVektorInitial
	bl uart_putString
	ldr r0, =newline
	bl uart_putString	
	
	ldr r0, =strV1Input
	bl uart_putString
	ldr r0, =v1
	ldr r0, [r0]
	bl outputVector
	
	ldr r0, =newline
	bl uart_putString	
	
	ldr r0, =strV2Input
	bl uart_putString
	ldr r0, =v2
	ldr r0, [r0]
	bl outputVector
	
	ldr r0, =newline
	bl uart_putString	
	
	pop {r4,lr}
	bx lr
	
/*
	Gibt einen einzelnen Vektor aus
	R0 -> Vektor (Wert)
*/
.thumb_func
outputVector:
	push {r4,lr}
	mov r4, r0
	
	bl uart_putByte
	
	lsr r4, r4, #8
	mov r0, r4
	bl uart_putByte
	
	mov r0, #UNDERSCORE
	bl uart_putChar
	
	lsr r4, r4, #8
	mov r0, r4
	bl uart_putByte
	
	lsr r4, r4, #8
	mov r0, r4
	bl uart_putByte		
	
	pop {r4,lr}
	bx lr

/*
	Sortiert zwei Bytes in aufsteigender Reihenfolge
	R0 -> Byte 1
	R1 -> Byte 2
	R0 <- Kleineres Byte
	R1 <- Größeres Byte
*/
.thumb_func
orderBytesAsc:
	// Annahme: R0 <= R1
	mov r2, r0
	mov r3, r1
	
	cmp r2, r3
	itt hi
		movhi r0, r3
		movhi r1, r2
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data

newline: .asciz "\n"
v1: .word 0x00000000
v2: .word 0x00000000
minNoDsp: .word 0x00000000
maxNoDsp: .word 0x00000000
minWithDsp: .word 0x00000000
maxWithDsp: .word 0x00000000
strVektorInput: .asciz "Vektoren eingeben (einzelne Bytes)"
strVektorInitial: .asciz "Initialwerte der Vektoren:"
strV1Input: .asciz "v1: 0x"
strV2Input: .asciz "v2: 0x"
strNoDsp: .asciz "ohne DSP-Befehle:"
strWithDsp: .asciz "mit DSP-Befehlen:"
strMinOutput: .asciz "min: 0x"
strMaxOutput: .asciz "max: 0x"
strUsedCycles: .asciz "Benoetigte Takte:"

testval1: .word 0x11FF77AA
testval2: .word 0x22BB55DD

/* Beispielausgabe mit Programmlaufzeit
	Vektoren eingeben (einzelne Bytes)
	v1: 0x11FF77AA
	v2: 0x22BB55DD
	
	Initialwerte der Vektoren:
	v1: 0x11FF_77AA
	v2: 0x22BB_55DD
	
	ohne DSP-Befehle:
	min: 0x11BB_55AA
	max: 0x22FF_77DD
	Benoetigte Takte:67
	
	mit DSP-Befehlen:
	min: 0x11BB_55AA
	max: 0x22FF_77DD
	Benoetigte Takte:17
	
	Der Vergleich mittels DSP Befehlen spart in dieser Implementierung 50 Takte.
	Die Implementierung ohne DSP Befehle ließe sich ggf. durch optimierten Speicherzugriff
	und Reduktion von Unterprogrammaufrufen um einige Takte optimieren, allerdings nicht um
	mehr als 50 Takte.
*/
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/* Konstanten */
// Zeilenvorschub
.equ LINEFEED, 0x0A
// Leerzeichen
.equ SPACEC, 0x20
// Tabulator
.equ TAB, 0x09

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	/*
		V2-1 a - Matrizen M, N multiplizieren

		R0 = Produktsumme / Wert des aktuell berechneten Elements der Ergebnismatrix
		
		R1 = Element-Zähler
		R2 = Zeilen-Zähler
	
		R3 = Element-Zeiger M
		R4 = Element-Zeiger N
		R5 = Element-Zeiger O
		
		R6,R7 = M Zeile - Elemente 1,2,3,4	
		R8,R9 = N Spalte - Elemente 1,2,3,4
		
		Multiplikation + Addition mit "Dual 16-bit Signed Multiply with Addition" -> SMLAD
		O-Matrix wird zeilenweise berechnet und im Speicher abgelegt.
		
		Zur Berechnung der 4x4 Ergebnismatrix werden 32 duale Multiplikationsbefehle ausgeführt.
		Zur Berechnung der Egebnismatrix wären 64 MUL Befehle vonnöten. Der Einsatz des DSP Befehls spart hier 32 Multiplikationsbefehle,
		hinzu kommen eingesparte Additionsbefehle.
	*/
	
	// Initialisierung
	ldr r3, =M
	ldr r5, =O
	mov r2, #3
processRow:
	// Nächste M Zeile laden
	ldmia r3!, {r6,r7}
	// N Element-Zeiger nach prozessierter (O) Zeile zurücksetzen
	ldr r4, =N
	// Element-Zähler rücksetzen
	mov r1, #3
processElement:
	// Wert des Ergebnis-Elements rücksetzen
	mov r0, #0
	// Nächste N-Spalte laden
	ldmia r4!, {r8,r9}
	// Elementpaare MAC // Signed MuLtiply Add Dual
	smlad r0, r6, r8, r0	
	smlad r0, r7, r9, r0
	// Ergebniselement schreiben
	str r0, [r5], #4
	subs r1, #1
	bpl processElement
	
	subs r2, #1
	bpl processRow
	
	/*
		Matrix O ausgeben
		R0 = UP Parameter
		R4 = Element-Zeiger O
		R5 = Element-Zähler
		R6 = Zeilen-Zähler
	*/
	ldr r0, =strMatrixResult
	bl uart_putString
	ldr r4, =O
	mov r6, #3
putRow:
	mov r5, #3
putElement:
	ldr r0, [r4], #4
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	subs r5, #1
	bpl putElement
	
	mov r0, #LINEFEED
	bl uart_putChar
	subs r6, #1
	bpl putRow
	
	/*
		V2-1 b - Matrix O kopieren
		R0 = Element-Zeiger O
		R1 = Element-Zeiger P
		R4-R11 = Datenablage
	*/
	ldr r0, =strMatrixCopy
	bl uart_putString
	ldr r0, =O
	ldr r1, =P
	ldmia r0!, {r4-r11} 	// LoaD Multiple Increment After
	stmia r1!, {r4-r11}
	ldmia r0!, {r4-r11}
	stmia r1!, {r4-r11}
	
	/* 
		V2-1 c - Summe von Element-Produkten M, N
		R0 = Summe
		
		R3 = Element-Zähler
		
		R5 = Element-Zeiger M
		R6 = Element-Zeiger N
		
		R7,R8 = Elemente M
		R9,R10 = Elemente N
	*/
	ldr r0, =strElementProduct
	bl uart_putString
	
	mov r0, #0
	ldr r5, =M
	ldr r6, =N
	mov r3, #3
mulAdd:
	ldmia r5!, {r7,r8}
	ldmia r6!, {r9, r10}
	smlad r0, r7, r9, r0
	smlad r0, r8, r10, r0
	
	subs r3, #1
	bpl mulAdd
	
	bl uart_putInt32
	
	/*
		V2-1 d - Skalierbare Additionsbefehle
		R4 = A
		R5 = B
		R6 = C
		R7 = D
		
		Vozeichenlos UADD16 / UQADD16 A +
		B -> Überlauf niederwertiger Halbwort Addition. Ergebnis > 2^16.
		UQADD16 sättigt niederwertigeres Ergebnis-Halbwort auf größte darstellbare Zahl 0xFFFF.
		
		C -> Überlauf höherwertiger Halbwort Addition. Ergebnis > 2^16.
		UQADD16 sättigt höherwertigeres Ergebnis-Halbwort auf 0xFFFF.
	
		D -> Überlauf beider Halbwort-Addition. Ergebnisse sind jeweils > 2^16.
		UQADD16 sättigt beide Halbwörter auf 0xFFFF.
		
		Vorzeichenbehaftet SADD16 / QADD16 A +
		B -> kein Überlauf
		
		C -> Überlauf beider Halbwort-Additionen. 
		Niederwertigeres Ergebnis-Halbwort  < -(2^15). QADD16 sättigt auf größte (Betrag) negative darstellbare Zahl 0x8000.
		Höherwertigeres Ergebnis-Halbwort > 2^15 -1. QADD16 sättigt auf größte positive darstellbare Zahl 0x7FFF.
		
		D -> kein Überlauf
	*/
	ldr r0, =A
	ldmia r0, {r4-r7} 
	// Unsigned Add - keine Sättigung
	ldr r0, =strUadd16
	bl uart_putString
	uadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	uadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	uadd16 r0, r4, r7
	bl uart_putInt32
	// Signed Add - keine Sättigung
	ldr r0, =strSadd16
	bl uart_putString
	sadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	sadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	sadd16 r0, r4, r7
	bl uart_putInt32
	// Unsigned Add - mit Sättigung
	ldr r0, =strUqadd16
	bl uart_putString
	uqadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	uqadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	uqadd16 r0, r4, r7
	bl uart_putInt32
	// Signed Add - mit Sättigung
	ldr r0, =strQadd16
	bl uart_putString
	qadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	qadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	qadd16 r0, r4, r7
	bl uart_putInt32
	
	/*
		V2-1 3 - Sättigung auf 13 Bit
		R4 = A
		R5 = B
		
		Ergebnis:
		SSAT16:	F000_0FFF	0FFF_F000
		USAT16:	0000_1FFF	10A7_0000
		
		13 Bit Wertebereich mit Vorzeichen
		SMin -(2^12)	0xF000
		SMax (2^12)-1	0x0FFF
		
		Ergebnis Sättigung mit Vorzeichen
		A1 0xA436	< SMin	gesättigt auf SMin
		A2 0x7C7B	> SMax	gesättigt auf SMax
		B1 0x10A7	> SMax  gesättigt auf SMax
		B2 0x8933	< SMin	gesättigt auf SMin
		
		13 Bit Wertebereich ohne Vorzeichen
		UMin 0			0x0000
		UMax (2^13)-1	0x1FFF
		
		Ergebnis Sättigung ohne Vorzeichen
		A1 0xA436	< UMin	gesättigt auf 0 
		A2 0x7C7B	> UMax	gesättigt auf UMax 
		B1 0x10A7	im darstellbare Bereich -> keine Sättigung
		B2 0x8933	< UMin	gesättigt auf 0
		
	*/
	// Voreichenbehaftet
	ldr r0, =strSsat
	bl uart_putString
	ssat16 r0, #13, r4
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	ssat16 r0, #13, r5
	bl uart_putInt32
	// Vorzeichenlos
	ldr r0, =strUsat
	bl uart_putString
	usat16 r0, #13, r4
	bl uart_putInt32
	mov r0, #TAB
	bl uart_putChar
	usat16 r0, #13, r5
	bl uart_putInt32
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
// M zeilenweise ausgerollt
M: .short 0x5f8c, 0x7f48, 0x8245, 0x6048, 0xc799, 0x9c5d, 0xd49c, 0x33d8, 0x579b, 0x8aef, 0xf2c0, 0xa3c2, 0x41fd, 0x50d4, 0x25c6, 0x4afa
// N spaltenweise ausgrollt
N: .short 0x7f41, 0x0645, 0x8c8f, 0x9065, 0x78e3, 0xf7f3, 0xd29f, 0x2961, 0x5a1e, 0xdfed, 0x4b9f, 0x1092, 0x61bf, 0x21be, 0x5ca1, 0xc6d3
// O Ergebnismatrix
O:	.rept 0x10
	.word 0x00
	.endr
// P Kopie der Ergebnismatrix O
P:	.rept 0x10
	.word 0x00
	.endr
// Operanden 2-1 d/e
A: .word 0xA4367C7B
B: .word 0x10A78933
C: .word 0xC5535F2C
D: .word 0x788E84B1	
strMatrixResult: .asciz "Ergebnismatrix O:\n"
strMatrixCopy: .asciz "\nKopieren der Matrix O!\n"
strElementProduct: .asciz "\nProdukt-Summe:\t"
strUadd16: .asciz "\n\nUADD16:\t"
strSadd16: .asciz "\nSADD16:\t"
strUqadd16: .asciz "\nUQADD16:\t"
strQadd16: .asciz "\nQADD16:\t"
strSsat: .asciz "\n\nSSAT16:\t"
strUsat: .asciz "\nUSAT16:\t"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/* Konstanten */
.equ LINEFEED, 0x0A
.equ TAB, 0x09
.equ DOT, 0x2E
.equ COLON, 0x3A
.equ NULL, 0x30
.equ S, 0x73
.equ T, 0x74
.equ D, 0x64

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	/*	
		R4 = Tag
		R5 = Monat
		R7 = Jahr (Low)
		R8 = Stunde
		R9 = Minute
		
		R10 = Uhr Start/Stop Status, 0=Stop; 1=Start
		R11 = Ablage für Nutzereingaben
		
		Hinweis zu Aufgabe d:
		Die in der Aufgabenbeschreibung gezeigte Eingabeaufforderung für das Jahr "Jahr eingeben (jj):" und die Tatsache, dass 
		mit uart_getByteBase10 keine Abfrage vierstelliger Dezimalwerte möglich ist, haben mich dazu bewegt, keine komplexere
		Logik zur Eingabe vierstelliger Jahreszahlen zu implementieren. 
		Hier ist nur die Eingabe der 1er und 10er Jahreszahlen möglich. Das Überschreiten des Jahrhunderts durch den Takt wird verhindert,
		bzw. die Jahreszahl auf den Beginn des Jahrhunderts zurückgesetzt.
		"Außerdem soll ein Überlauf des Jahrhunderts ausgeschlossen werden"
		Das höherwertige Jahres-Byte wird trotzdem im Speicher abgelegt.
	*/
	// Initialisierung
	mov r10, #1
	ldr r0, =day
	ldrb r4, [r0], #1
	ldrb r5, [r0], #2
	ldrb r7, [r0], #1
	ldrb r8, [r0], #1
	ldrb r9, [r0]

checkInput:
	bl uart_charPresent
	cmp r0, #0
	beq resume
	bl uart_getChar
	mov r11, r0
	// Start / Stop
	cmp r11, #S
	it eq
	eoreq r10, r10, #1
	beq resume
	// Zeit eingeben
	cmp r11, #T
	beq inputTime
	beq resume
	// Datum eingeben
	cmp r11, #D
	beq inputDate
resume:	
	cmp r10, #0
	beq checkInput
	bl delay
	// Datum und Uhrzeit im .data Bereich ablegen
	ldr r0, =day
	strb r4, [r0], #1
	strb r5, [r0], #2
	strb r7, [r0], #1
	strb r8, [r0], #1
	strb r9, [r0]
	// Datum und Uhrzeit ausgeben
	bl putDateTime	
newMinute:	
	add r9, #1
	cmp r9, 0x3C
	blo checkInput
newHour:
	add r8, #1
	mov r9, #0
	cmp r8, 0x18
	blo checkInput
newDay:
	add r4, #1
	mov r8, #0
	cmp r4, 0x1F
	blo checkInput
newMonth:
	add r5, #1
	mov r4, #1
	cmp r5, #0x0D
	blo checkInput
newYear:
	add r7, #1
	mov r5, #1
	cmp r7, #0x64
	ittt eq
	moveq r7, #0
	ldreq r0, =strCenturyOverflow
	bleq uart_putString
	b checkInput
	
inputTime:
	// Eingabeaufforderung für neue Uhrzeit
	ldr r0, =strInputHour
	bl uart_putString
	bl uart_getByteBase10
	mov r8, r0
	bl uart_putByteBase10
	ldr r0, =strInputMinute
	bl uart_putString
	bl uart_getByteBase10
	mov r9, r0
	bl uart_putByteBase10
	mov r0, #LINEFEED
	bl uart_putChar
	b resume
	
inputDate:
	// Eingabeaufforderung für neues Datum
	ldr r0, =strInputDay
	bl uart_putString
	bl uart_getByteBase10
	mov r4, r0
	bl uart_putByteBase10
	ldr r0, =strInputMonth
	bl uart_putString
	bl uart_getByteBase10
	mov r5, r0
	bl uart_putByteBase10
	ldr r0, =strInputYear
	bl uart_putString
	bl uart_getByteBase10
	mov r7, r0
	bl uart_putByteBase10
	mov r0, #LINEFEED
	bl uart_putChar
	b resume	

/*
	Verzögert etwa seine Sekunde
*/	
.thumb_func	
delay:
	ldr r0, =cycles
	ldr r0, [r0]
wait:
	subs r0, #1
	bpl wait
	bx lr
/*
	Ausgabe Datum und Zeit auf dem Terminal.
	Lädt Daten aus .data Bereich -> keine Parameter.
*/	
.thumb_func
putDateTime:
	push {r4,lr}
	// Datum ausgeben
	ldr r4, =day
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #DOT
	bl uart_putChar
	
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #DOT
	bl uart_putChar
	
	ldrb r0, [r4], #1
	bl putByteBase10	
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #TAB
	bl uart_putChar
	
	// Zeit ausgeben
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #COLON
	bl uart_putChar
	ldrb r0, [r4]
	bl putByteBase10

	ldr r0, =strClock
	bl uart_putString
	pop {r4,pc}
	
/*
	Wrapper für uart_putByteBase10. Gibt führende 0 für Werte < 10(dec) aus.
	R0 -> Auszugebendes Byte
*/	
.thumb_func
putByteBase10:
	push {r4,lr}
	mov r4, r0
	cmp r0, #10
	itt lo
	movlo r0, #NULL
	bllo uart_putChar
	mov r0, r4
	bl uart_putByteBase10
	pop {r4,pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
cycles: .word 0x00802C80
day: .byte 0x01
month: .byte 0x01
yearH: .byte 0x14
yearL: .byte 0x0E
hour: .byte 0x00
minute: .byte 0x00
strClock: .asciz " Uhr\n"
strInputHour: .asciz "\nStunde eingeben (hh): "
strInputMinute: .asciz "\nMinuten eingeben (mm): "
strInputDay: .asciz "\nTag eingeben (dd): "
strInputMonth: .asciz "\nMonat eingeben (mm): "
strInputYear: .asciz "\nJahr eingeben (jj): "
strCenturyOverflow: .asciz "\nJahrhundert uebergelaufen\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/* Konstanten */
.equ LINEFEED, 0x0A
.equ TAB, 0x09
.equ DOT, 0x2E
.equ COLON, 0x3A
.equ NULL, 0x30
.equ S, 0x73
.equ T, 0x74
.equ D, 0x64

// Interrupt Vektor
.equ VECTOR_TABLE_OFFSET_REG, 0xE000ED08
.equ PIT1_INTERRUPT_VECTOR, 0x00000154
// SIM Register
.equ SIM_CLOCK_GATE6, 0x4004803C
__BBREG SIM_PIT_CLOCK_ENABLE 0x4004803C 23
// PIT Register
.equ PIT_MCR, 				0x40037000
.equ PIT1_LOAD_VALUE, 		0x40037110
// PIT Bit-Banding Adressen
__BBREG PIT1_CTRL_TIMER_ENABLE		0x40037118 0
__BBREG PIT1_CTRL_INTERRUPT_ENABLE	0x40037118 1
__BBREG PIT1_FLAG_INTERRUPT			0x4003711C 0
// NVIC Register
.equ NVIC_SET_ENABLE2,		0xE000E108
.equ NVIC_CLEAR_PENDING2,	0xE000E288

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// Timer und Interrupt Initialisierung
	mov r1, #1
	mov r2, #0
	// PIT Clock aktivieren, Register SIM_SCGC6
	ldr r0, =simAliasPITClockEnable
	ldr r0, [r0]	
	str r1, [r0]
	// Interrupt-Vektor für PIT1 setzen
	ldr r0, =pit1InterruptVector
	ldr r0, [r0]
	ldr r3, =vectorTableOffsetReg
	ldr r3, [r3]
	ldr r3, [r3]
	add r0, r3 // Annahme: Die Vektortabelle wird dynamisch im Speicher platziert -> statische Berechnung vermeiden
	ldr r3, =pit1End
	str r3, [r0]
	// Wartende Interrupts für PIT1 löschen; Register NVIC_ICPR2; Bit 5; PIT1 IRQ=69
	ldr r0, =nvicClearPending2
	ldr r0, [r0]
	mov r3, #32
	str r3, [r0]
	// Interrupts für PIT1 im NVIC erlauben; Register NVIC_ISER
	ldr r0, =nvicSetEnable2
	ldr r0, [r0]
	str r3, [r0]	
	// PIT Modul aktivieren; Register PIT_MCR  
	ldr r0, =pitMCR
	ldr r0, [r0]
	str r2, [r0]	        
	// PIT1 Startwert festlegen; Register PIT_LDVAL1
	ldr r0, =pit1LoadValue
	ldr r0, [r0]
	ldr r3, =pitCycles
	ldr r3, [r3]
	str r3, [r0]
	// PIT1 aktivieren und Interrupts erlauben; Register PIT_TCTRL1
	ldr r0, =pit1AliasCtrlTimerInterruptEnable
	ldr r0, [r0]
	str r1, [r0]
	ldr r0, =pit1AliasCtrlTimerEnable
	ldr r0, [r0]
	str r1, [r0]
	
	/*
		Initialisierung
		R4 = Tag
		R5 = Monat
		R7 = Jahr (Low)
		R8 = Stunde
		R9 = Minute
		
		R10 = Uhr Start/Stop Status, 0=Stop; 1=Start
		R11 = Ablage für Nutzereingaben
	*/
	mov r10, #1
	ldr r0, =day
	ldrb r4, [r0], #1
	ldrb r5, [r0], #2
	ldrb r7, [r0], #1
	ldrb r8, [r0], #1
	ldrb r9, [r0]

checkInput:
	bl uart_charPresent
	cmp r0, #0
	beq resume
	bl uart_getChar
	mov r11, r0
	// Start / Stop
	cmp r11, #S
	it eq
	eoreq r10, r10, #1
	beq resume
	// Zeit eingeben
	cmp r11, #T
	beq inputTime
	beq resume
	// Datum eingeben
	cmp r11, #D
	beq inputDate
resume:	
	// Start / Stop Status prüfen
	cmp r10, #0
	beq checkInput
	// Sekundenende-Flag prüfen
	ldr r0, =secondEnded
	ldrb r1, [r0]
	cmp r1, #0
	beq checkInput
	// ISR Flag zurücksetzen
	mov r2, #0
	strb r2, [r0]
	// Datum und Uhrzeit im .data Bereich ablegen
	ldr r0, =day
	strb r4, [r0], #1
	strb r5, [r0], #2
	strb r7, [r0], #1
	strb r8, [r0], #1
	strb r9, [r0]
	// Datum und Uhrzeit ausgeben
	bl putDateTime	
newMinute:	
	add r9, #1
	cmp r9, 0x3C
	blo checkInput
newHour:
	add r8, #1
	mov r9, #0
	cmp r8, 0x18
	blo checkInput
newDay:
	add r4, #1
	mov r8, #0
	cmp r4, 0x1F
	blo checkInput
newMonth:
	add r5, #1
	mov r4, #1
	cmp r5, #0x0D
	blo checkInput
newYear:
	add r7, #1
	mov r5, #1
	cmp r7, #0x64
	ittt eq
	moveq r7, #0
	ldreq r0, =strCenturyOverflow
	bleq uart_putString
	b checkInput
	
inputTime:
	// Eingabeaufforderung für neue Uhrzeit
	ldr r0, =strInputHour
	bl uart_putString
	bl uart_getByteBase10
	mov r8, r0
	bl uart_putByteBase10
	ldr r0, =strInputMinute
	bl uart_putString
	bl uart_getByteBase10
	mov r9, r0
	bl uart_putByteBase10
	mov r0, #LINEFEED
	bl uart_putChar
	b resume
	
inputDate:
	// Eingabeaufforderung für neues Datum
	ldr r0, =strInputDay
	bl uart_putString
	bl uart_getByteBase10
	mov r4, r0
	bl uart_putByteBase10
	ldr r0, =strInputMonth
	bl uart_putString
	bl uart_getByteBase10
	mov r5, r0
	bl uart_putByteBase10
	ldr r0, =strInputYear
	bl uart_putString
	bl uart_getByteBase10
	mov r7, r0
	bl uart_putByteBase10
	mov r0, #LINEFEED
	bl uart_putChar
	b resume	

/*
	Ausgabe Datum und Zeit auf dem Terminal.
	Lädt Daten aus .data Bereich -> keine Parameter.
*/	
.thumb_func
putDateTime:
	push {r4,lr}
	// Datum ausgeben
	ldr r4, =day
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #DOT
	bl uart_putChar
	
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #DOT
	bl uart_putChar
	
	ldrb r0, [r4], #1
	bl putByteBase10	
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #TAB
	bl uart_putChar
	
	// Zeit ausgeben
	ldrb r0, [r4], #1
	bl putByteBase10
	mov r0, #COLON
	bl uart_putChar
	ldrb r0, [r4]
	bl putByteBase10

	ldr r0, =strClock
	bl uart_putString
	pop {r4,pc}
	
/*
	Wrapper für uart_putByteBase10. Gibt führende 0 für Werte < 10(dec) aus.
	R0 -> Auszugebendes Byte
*/	
.thumb_func
putByteBase10:
	push {r4,lr}
	mov r4, r0
	cmp r0, #10
	itt lo
	movlo r0, #NULL
	bllo uart_putChar
	mov r0, r4
	bl uart_putByteBase10
	pop {r4,pc}
	
// PIT1 ISR
.thumb_func
pit1End:
	// PIT1 Interrupt Flag rücksetzen
	mov r1, #1
	ldr r0, =pit1AliasInterruptFlag
	ldr r0, [r0]
	str r1, [r0]
	// Sekundenende-Flag setzen
	ldr r0, =secondEnded
	str r1, [r0]
	
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
pitCycles: 	.word 0x017BFFFF
day: 		.byte 0x01
month: 		.byte 0x01
yearH: 		.byte 0x14
yearL: 		.byte 0x0E
hour: 		.byte 0x00
minute: 	.byte 0x00
// Sekundenende-Flag
secondEnded: .byte 0x00
.align
// SIM Register Adressen
simAliasPITClockEnable: .word SIM_PIT_CLOCK_ENABLE
// PIT Register Adressen
pitMCR: 			.word PIT_MCR
pit1LoadValue: 		.word PIT1_LOAD_VALUE
// PIT Bitbanding Alias Adressen
pit1AliasCtrlTimerEnable: 			.word PIT1_CTRL_TIMER_ENABLE
pit1AliasCtrlTimerInterruptEnable:	.word PIT1_CTRL_INTERRUPT_ENABLE
pit1AliasInterruptFlag:				.word PIT1_FLAG_INTERRUPT
// NVIC Register Adressen
nvicSetEnable2:		.word NVIC_SET_ENABLE2
nvicClearPending2:	.word NVIC_CLEAR_PENDING2
// Interrupt Vektor Adressen
vectorTableOffsetReg: 	.word VECTOR_TABLE_OFFSET_REG
pit1InterruptVector:	.word PIT1_INTERRUPT_VECTOR
// Sonstige Terminalausgaben
strClock: .asciz " Uhr\n"
strInputHour: .asciz "\nStunde eingeben (hh): "
strInputMinute: .asciz "\nMinuten eingeben (mm): "
strInputDay: .asciz "\nTag eingeben (dd): "
strInputMonth: .asciz "\nMonat eingeben (mm): "
strInputYear: .asciz "\nJahr eingeben (jj): "
strCenturyOverflow: .asciz "\nJahrhundert uebergelaufen\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert

// SIM Modul
__BBREG BBA_SIM_SCGC6_CRC 0x4004803C 18
// CRC Modul
.equ CRC_CRC, 0x40032000
.equ CRC_GPOLY, 0x40032004
.equ CRC_CTRL, 0x40032008
/*
	Vorkonfiguration CRC_CTRL
	TOT 	= 00
	TOTR 	= 00
	FXOR 	= 0
	WAS 	= 0
	TCRC 	= 1
*/
.equ CRC_CTRL_CONFIG, 0x01000000
__BBREG BBA_CRC_CTRL_WAS 0x40032008 25
.equ CRC32_POLYNOMIAL, 0x04C11DB7
.equ CRC_SEED, 0x12345678

.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	/*
		Registerverwendung
		R4 = Adresse des CRC Datenregisters CRC_CRC
		R5 = String Zeiger
		R6 = Aktuell prozessiertes Wort
		R7 = Kopie des aktuell prozessiertes Wortes
		R8 = Byte-Zähler
	*/
	// Takt für CRC Modul aktivieren
	mov r1, #1
	ldr r0, =BBA_SIM_SCGC6_CRC
	str r1, [r0]
	// CRC Konfiguration
	ldr r0, =CRC_CTRL
	ldr r1, =CRC_CTRL_CONFIG
	str r1, [r0]
	// Generator-Polynom setzen
	ldr r0, =CRC_GPOLY
	ldr r1, =CRC32_POLYNOMIAL
	str r1, [r0]
	// Startwert setzen
	ldr r0, =BBA_CRC_CTRL_WAS
	mov r1, #1
	str r1, [r0]
	ldr r4, =CRC_CRC
	ldr r2, =CRC_SEED
	str r2, [r4]
	mov r1, #0
	str r1, [r0]
	
	/*
		Prüfsumme des Strings berechnen
		Der String wird wortweise geladen und an das CRC Modul übergeben.
		Jedes Wort wird auf den String-Terminator / das Nullbyte untersucht. Is er im Wort enthalten,
		wird der nicht mehr zum String gehörende Teil des Wortes entfernt und nur die zum String gehörenden
		Zeichen an das CRC Modul übergeben.
		Das Durchsuchen der Bytes des aktuell geladenen Wortes erfolgt durch Kopie des Wortes R6 -> R7,
		Prüfen des niederwertigsten Bytes in R7 und anschließendes Rechtsschieben von R7 um ein Byte.
		Das Null-Byte wird als Teil des Strings betrachtet.
	*/
	ldr r5, =str
nextWord:
	// Wort laden, String Zeiger schieben und Hilfsregister für neues Wort initialisieren
	ldr r6, [r5], #4
	mov r7, r6
	mov r8, #0
nextByte:
	// Byte-weise Prüfung des Null-Bytes
	cmp r8, #4
	itt eq
	// Alle Bytes durchsucht aber kein Null-Byte identifiziert. Wort unverändert an das CRC Modul übergeben.
	streq r6, [r4]
	beq nextWord
	// Niederwertigstes Byte in R7 auf Nullbyte prüfen.
	and r0, r7, 0xFF
	cmp r0, 0x00
	beq terminatorFound
	// R7 um ein Byte nach rechts schieben und nächstes Byte prüfen
	lsr r7, #8
	add r8, r8, #1
	b nextByte
terminatorFound:
	// Nicht zum String gehörende Bytes durch Maskierung entfernen
	mov r0, #3
	sub r0, r0, r8
	lsl r0, r0, #3 // Anzahl Masken-Shifts aus Byte ID berechnen
	mov r1, #0xFFFFFFFF
	lsr r1, r1, r0
	and r6, r6, r1
	// Bereinigtes Wort an CRC Modul übergeben
	str r6, [r4]
	
	// Terminalausgabe
	ldr r0, =str
	bl uart_putString
	ldr r0, =result
	bl uart_putString
	ldr r0, [r4]
	bl uart_putInt32
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
result: .asciz "\nCRC Pruefsumme: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*** System Integration ***/

__BBREG SIM_SCGC6_PIT 	0x4004803C 23
__BBREG SIM_SCGC5_PORTA 0x40048038 9
__BBREG SIM_SCGC5_PORTE 0x40048038 13

/*** Interrupt / NVIC ***/

// Vector Table Offset Register
.equ SCB_VTOR, 0xE000ED08
// Set Enable Register 2
.equ NVIC_ISER2, 0xE000E108
// Clear Pending Register 2
.equ NVIC_ICPR2, 0xE000E288
/*
	NVIC Clear & Enable Wert für Interrupts dieser Anwendung im NVIC_IxxR2 Register
	PIT1 	IRQ=69 mod 32 = Bit 5
	PORTE 	IRQ=91 mod 32 = Bit 27
*/
.equ NVIC_IXXR2_VAL, 0x08000020

/*** PIT1 ***/

// PIT Zyklen für 1s Durchlauf
.equ PIT_CYCLES_1S, 0x017D7840
// PIT Zyklen für 1ms Durchlauf
.equ PIT_CYCLES_1MS, 0x0001E848
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
/*
	PIT1 Timer Control Konfiguration
	CHN	= 0 (Chain Mode)
	TIE	= 1 (Timer Interrupt Enable)
	TEN = 1 (Timer Enable)
*/
.equ PIT_TCTRL1_CONFIG, 0x00000003
// PIT1 IRQ=69
.equ PIT1_INTERRUPT_VECTOR, 0x00000154
// Timer Interrupt Flag - TIF
__BBREG PIT_TFLG1_TIF 0x4003711C 0

/*** PORT Module A und E ***/

// Pin Control Register PCR
.equ PORTA_PCR11, 0x4004902C	// LED E1
.equ PORTA_PCR28, 0x40049070	// LED E2
.equ PORTA_PCR29, 0x40049074 	// LED E3
.equ PORTA_PCR10, 0x40049028 	// LED E4
.equ PORTA_PCR19, 0x4004904C	// SW1 Schwarz
.equ PORTE_PCR26, 0x4004D068	// SW2 Grün
/*
	Standard GPIO Konfiguration
	ISF		= 0		(Interrupt Status Flag)
	IRQC	= 0 	(Interrupt Configuration)
	LK		= 0 	(Lock Register | unlocked)
	MUX		= 001 	(Pin Mux Control | GPIO)
	DSE		= 0		(Drive Strength Enable | low)
	ODE		= 0		(Open Drain Enable | disabled)
	PFE		= 0		(Passive Filter Enable | disabled)
	SRE		= 0		(Slew Rate Enable | fast)
	PE		= 0		(Pull Enable | disabled)
	PS		= 0		(Pull Select)
*/
.equ PCR_STANDARD_CONFIG, 0x00000100
/*
	Drucktaster-Pin PCR Konfiguration mit Interrupt
	Analog Standard Konfiguration, außer:
	IRQC	= 1010 	(Interrupt Configuration | Interrupt on falling edge)
*/
.equ PCR_BUTTON_IRQ_CONFIG, 0x000A0100
// PORTE_PCR26 / SW2 Button Interrupt Status Flag
__BBREG PORTE_PCR26_ISF 0x4004D068 24
// PORT E Pin Detect Interrupt Vector; IRQ=91
.equ PORTE_PIN_INTERRUPT_VECTOR, 0x000001AC 

/*** GPIO Modul ***/

// Port Data Output
.equ GPIOA_PDOR, 0x400FF000
// Port Data Direction
.equ GPIOA_PDDR, 0x400FF014
.equ GPIOE_PDDR, 0x400FF114
/*
 	 Port A I/O Konfiguration
 	 Output-Pins (1): 	PTA10, PTA11, PTA28, PTA29 
 	 Input-Pins (0):	PTA19
*/
.equ GPIOA_PDDR_CONFIG, 0x30000C00
/*
 	 Port E I/O Konfiguration 
 	 Input-Pins (0): PTE26
 	 Wird mit 0x00 konfiguriert
*/
// PIN Masken
.equ MASK_PTA10, 0x00000400
.equ MASK_PTA11, 0x00000800
.equ MASK_PTA28, 0x10000000
.equ MASK_PTA29, 0x20000000
// GPIOA Input Register - Pin 19 (SW1)
__BBREG GPIOA_PDIR_19 0x400FF010 19
// GPIOE Input Register - Pin 26 (SW2)
__BBREG GPIOE_PDIR_26 0x400FF110 26


/*** Sonstiges ***/

// Zeichen
.equ LINEFEED, 0x0A
.equ COUNT_UP, 0x2B
.equ COUNT_DOWN, 0x2D
.equ START_STOP, 0x73
// Tasterwerte / mod Variable
.equ NO_BTN, 0x00
.equ BTN_SW1, 0x01
.equ BTN_SW2, 0x02
// Steuerindikatoren
.equ UP, 0x00
.equ DOWN, 0x01
.equ START, 0x00
.equ STOP, 0x01
// Debounce Lock
.equ UNLOCKED, 0x00
.equ LOCKED, 0x01
// Zählergrenzen
.equ COUNTER_MAX, 0xFF
.equ COUNTER_MIN, 0x00

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	/*
		Registerverwendung Initialisierung
		R4	#0
		R5	#1
	*/
	mov r4, #0
	mov r5, #1
	
	/*
		Interrupt / NVIC Initialisierung
	*/
	// Interrupt-Vektor PIT1
	ldr r0, =SCB_VTOR
	ldr r0, [r0]
	ldr r1, =pit1End
	str r1, [r0, #PIT1_INTERRUPT_VECTOR]
	// Interrupt-Vektor Port E Pin Detect
	ldr r1, =portEPin
	str r1, [r0, #PORTE_PIN_INTERRUPT_VECTOR]
	// Wartende Interrupts für PIT1 & PORTE im NVIC entfernen
	ldr r1, =NVIC_IXXR2_VAL
	ldr r0, =NVIC_ICPR2
	str r1, [r0]
	// Interrupts für PIT1 & PORTE im NVIC erlauben
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	/*
		PIT1 Timer Initialisierung
	*/
	ldr r0, =SIM_SCGC6_PIT	
	str r5, [r0]
	// PIT Modul aktivieren
	// Setzt Flags FRZ (Freeze) und MDIS (Module Disable) auf 0
	ldr r0, =PIT_MCR
	str r4, [r0]	        
	// PIT1 Startwert festlegen
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_CYCLES_1S
	str r1, [r0]
	// PIT1 konfigurieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_CONFIG
	str r1, [r0]
	
	/*
		PORTA & PORTE Initialisierung
	*/
	ldr r0, =SIM_SCGC5_PORTA
	str r5, [r0]
	ldr r0, =SIM_SCGC5_PORTE
	str r5, [r0]
	// LED Pins konfigurieren
	mov r1, #PCR_STANDARD_CONFIG
	ldr r0, =PORTA_PCR11
	str r1, [r0]
	ldr r0, =PORTA_PCR28
	str r1, [r0]
	ldr r0, =PORTA_PCR29
	str r1, [r0]
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	// Polling Button konfigurieren
	ldr r0, =PORTA_PCR19
	str r1, [r0]
	// Interrup Button konfigurieren
	ldr r1, =PCR_BUTTON_IRQ_CONFIG
	ldr r0, =PORTE_PCR26
	str r1, [r0]
	
	/*
		GPIO Initialisierung
	*/
	ldr r0, =GPIOA_PDDR
	ldr r1, =GPIOA_PDDR_CONFIG
	str r1, [r0]
	ldr r0, =GPIOE_PDDR
	str r4, [r0]
	
	/*
		Die fallende Flanke an einem der beiden konfigurierten GPIO Pins wird durch Unterprogramme
		in der mod-Variable angezeigt.
		Tritt eine fallende Flanke auf, wird die Debounce-Sperre gesetzt und der aktuelle PIT3 Zählerwert
		gespeichert. Während die Sperre gesetzt ist, wird der Flankenindikator nicht verändert. 
		Der Zählerwert wird zyklisch geprüft und erst beim Ablauf der 5ms Debounce-Zeit
		wird die Debounce-Sperre aufgehoben, der Flankenindikator zurückgesetzt und der Eingangspegel validiert.
		
		Registerverwendung Anwendung
		R4	Adresse Sekundenende-Indikator
		R5	Zählerwert
		R6	PIT_CYCLES_1MS
		R7	Adresse Flankenindikator (mod)
		R8	Debounce Sperre
		R9	Debounce PIT3 Referenzzählerstand
		R10	Up/Down Indikator; 0=Up, 1=Down
		R11 Start/Stop Indikator; 0=Start; 1=Stop
		R12	Adresse GPIOA_PDOR		
	*/	
	ldr r4, =secondEnded
	mov r5, #0x00
	ldr r6, =PIT_CYCLES_1MS
	ldr r7, =mod
	mov r8, #UNLOCKED
	mov r10, #UP
	mov r11, #START
	ldr r12, =GPIOA_PDOR
	bl pit3_init
start:
	/*
		Pin Flanken und Debounce Steuerung
		R0 = PIT3 Zählerstand / Zählerstandsdifferenz
		R1 = mod Wert // Flankenindikator
		R2 = GPIO Adresse / GPIO Input-Wert
		R3 = Verschieden
	*/
	// SW1 Polling
	bl checkSW1FallingEdge
	// Aktuellen PIT3 Zählerstand laden
	bl pit3_getval
	// Flankenindikator laden
	ldrb r1, [r7]
	// Keine Flanke erkannt
	cmp r1, #NO_BTN
	beq checkInput
	// Debounce-Sperre ist inaktiv -> Neue Flanke erkannt
	cmp r8, #UNLOCKED
	itt eq
	// PIT3 Referenzzäherlstand sichern
	moveq r9, r0
	// Debounce-Sperre setzen
	moveq r8, #LOCKED
	// Debounce-Sperre ist aktiv -> PIT3 Zählerstandsdifferenz prüfen
	sub r0, r9, r0
	cmp r0, r6
	bls checkInput
	// Differenz > 5ms -> Debounce-Wartezeit abgelaufen
	// Debounce-Sperre löschen
	mov r8, #UNLOCKED
	// Flankenindikator (im Speicher) rücksetzen
	mov r3, #NO_BTN
	strb r3, [r7]
	// GPIO Eingabewert lesen
	cmp r1, #BTN_SW1
	ite eq
	ldreq r2, =GPIOA_PDIR_19
	ldrne r2, =GPIOE_PDIR_26
	ldr r2, [r2]
	// GPIO Eingabewert validieren
	cmp r2, #0x00
	it ne
	bne checkInput
	/*
		Zählersteuerung durch validen GPIO Eingabewert 
		R0 = Adressen
		R1 = mod Wert / betätigter Taster
		R2 = Valider GPIO Eingabewert
	*/
	cmp r1, #BTN_SW1
	ittee eq
	// Zählrichtung umkehren
	eoreq r10, #0x01
	ldreq r0, =strUpDownSw1
	// Start/Stop Toggle
	eorne r11, #0x01
	ldrne r0, =strStartStopSw2
	
	bl uart_putString
checkInput:
	/*
		Zählersteuerung durch Zeicheneingaben
		R0 = Eingegebenes Zeichen
		R1 = String Adresse
	*/
	bl uart_charPresent
	cmp r0, #0x00
	// Kein Zeichen eingegeben
	beq checkSecondEnd
	// Zeichen laden
	bl uart_getChar
	ldr r1, =strInvalidInput
	// +
	cmp r0, #COUNT_UP
	itt eq
	moveq r10, #UP
	ldreq r1, =strUpChar
	// -
	cmp r0, #COUNT_DOWN
	itt eq
	moveq r10, #DOWN
	ldreq r1, =strDownChar
	// s
	cmp r0, #START_STOP
	itt eq
	eoreq r11, #0x01
	ldreq r1, =strStartStopChar
	// Hinweistext ausgeben
	mov r0, r1
	bl uart_putString
	
checkSecondEnd:
	// Sekundenende-Indikator prüfen
	ldrb r0, [r4]
	cmp r0, #0
	beq start
	// Start/Stop Indikator prüfen
	cmp r11, #STOP
	beq start
	/*
		Zähler-Fortführung und Ausgabe
		R0 = UP Parameter
		R1 = 0x00
	*/
	// Zähler fortführen
	cmp r10, #UP
	ite eq
	addeq r5, r5, #1
	subne r5, r5, #1
	// Zählerunterlauf -> Zähler zurücksetzen
	cmp r5, #COUNTER_MIN
	it lt
	movlt r5, #COUNTER_MAX	
	// Zählerüberlauf -> Zähler zurücksetzen
	cmp r5, #COUNTER_MAX
	it hi
	movhi r5, #COUNTER_MIN
	// Zähler ausgeben
	mov r0, r5
	bl uart_putByte
	ldr r0, =LINEFEED
	bl uart_putChar
	// Sekundenende Flag rücksetzen
	mov r1, #0
	strb r1, [r4]	
	/*
		Unteren 4 Bit an LEDs ausgeben. Unteren 4 Bits des Zählerwertes werden durch Rechtsschieben ausgewertet
		und die Bits in GPIOA_PDOR entsprechend maskiert.
		R0 = Ablages eines einzelnen Bits
		R1 = Uhrzeit Wert (Kopie)
		R2 = Wert GPIOA_PDOR / GPIOA Data Output
	*/	
	mov r1, r5
	ldr r2, [r12]
	// LED E4 / PTA10
	and r0, r1, #0x01
	cmp r0, #0x00
	ite eq
	orreq r2, r2, #MASK_PTA10
	bicne r2, r2, #MASK_PTA10
	// LED E3 / PTA29
	lsr r1, r1, #1
	and r0, r1, #0x01
	cmp r0, #0x00
	ite eq
	orreq r2, r2, #MASK_PTA29
	bicne r2, r2, #MASK_PTA29
	// LED E2 / PTA28
	lsr r1, r1, #1
	and r0, r1, #0x01
	cmp r0, #0x00
	ite eq
	orreq r2, r2, #MASK_PTA28
	bicne r2, r2, #MASK_PTA28	
	// LED E1 / PTA11
	lsr r1, r1, #1
	and r0, r1, #0x01
	cmp r0, #0x00
	ite eq
	orreq r2, r2, #MASK_PTA11
	bicne r2, r2, #MASK_PTA11	
	// GPIOA_PDOR aktualisieren
	str r2, [r12]
	
	b start
	
/*
	Tasterabfrage SW1
	Modifiziert die mod Variable im .data Bereich im Fall, dass eine fallende
	Flanke an GPIOA_PDIR_19 aufgetreten ist und keine andere Flanke bereits gemeldet wurde. 
	R0 = Adressen
	R1 = Vorheriger GPIO Wert SW1 // Vorheriger mod Wert
	R2 = Aktueller GPIO Wert SW1
	R3 = Identifikation der Pegeländerung
*/
.thumb_func
checkSW1FallingEdge:
	// Aktuellen GPIO Wert des SW1 lesen
	ldr r0, =GPIOA_PDIR_19
	ldr r2, [r0]	
	// Vorherigen GPIO Wert des SW1 lesen
	ldr r0, =gpioa_pdir_19_old
	ldrb r1, [r0]
	// Akutellen GPIO Wert ablegen
	strb r2, [r0]		
	// Pegeländerung HIGH -> LOW erkennen
	sub r3, r1, r2
	cmp r3, #0x01
	it ne
	movne r3, #0x00
	// Prüfen, ob ein bereits ein Flankenindikator gesetzt ist.
	// Falls nicht, Indikator setzen
	ldr r0, =mod
	ldrb r1, [r0]
	cmp r1, #NO_BTN
	it eq 
	strbeq r3, [r0]
	
	bx lr
	
// PIT1 ISR
.thumb_func
pit1End:
	// PIT1 Interrupt Flag rücksetzen
	mov r1, #0x01
	ldr r0, =PIT_TFLG1_TIF
	str r1, [r0]
	// Sekundenende-Flag setzen
	ldr r0, =secondEnded
	strb r1, [r0]
	
	bx lr	
	
// PORTE Pin ISR
.thumb_func
portEPin:
	// PORTE Interrupt Flag rücksetzen
	mov r1, #0x01
	ldr r0, =PORTE_PCR26_ISF
	str r1, [r0]
	// Prüfen, ob bereits ein Flankenindikator gesetzt ist
	ldr r0, =mod
	ldrb r1, [r0]
	cmp r1, #NO_BTN
	// Fallende Flanke an SW2 in mod Variable signalisieren
	ittt eq
	moveq r1, #BTN_SW2
	ldreq r0, =mod
	strbeq r1, [r0]
	
	bx lr		

/*** Datenbereich (ab 0x20000000) ***/
.data
// Sekundenende-Flag
secondEnded: .byte 0x00
// Indikator der Tasterbetätigung
mod: .byte 0x00
// Ablage des SW1 Pegels
gpioa_pdir_19_old: .byte 0x00
// Texte
strUpDownSw1: .asciz "Richtungswechsel durch Taster SW1\n"
strStartStopSw2: .asciz "Start/Stop durch Taster SW2\n"
strUpChar: .asciz "Zaehlrichtung aufwaerts durch Zeicheneingabe\n"
strDownChar: .asciz "Zaehlrichtung abwaerts durch Zeicheneingabe\n"
strStartStopChar: .asciz "Start/Stop druch Zeicheneingabe\n"
strInvalidInput: .asciz "Ungueltiges Steuerzeichen\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*** System Integration ***/

__BBREG SIM_SCGC3_ADC1 	0x40048030 27
__BBREG SIM_SCGC6_PIT 	0x4004803C 23
__BBREG SIM_SCGC5_PORTA 0x40048038 9

/*** Interrupt / NVIC ***/

// Vector Table Offset Register
.equ SCB_VTOR, 0xE000ED08
// Set Enable Register 2
.equ NVIC_ISER2, 0xE000E108
// Clear Pending Register 2
.equ NVIC_ICPR2, 0xE000E288
/*
	NVIC Clear & Enable Wert für Interrupts dieser Anwendung im NVIC_IxxR2 Register
	PIT1 	IRQ=69 mod 32 = Bit 5
*/
.equ NVIC_IXXR2_VAL, 0x00000020

/*** PIT1 ***/

// PIT Zyklen für 1s Durchlauf
.equ PIT_CYCLES_1S, 0x017D7840
// Sonstige PIT Register
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
/*
	PIT1 Timer Control Konfiguration
	CHN	= 0 (Chain Mode)
	TIE	= 1 (Timer Interrupt Enable)
	TEN = 1 (Timer Enable)
*/
.equ PIT_TCTRL1_CONFIG, 0x00000003
// PIT1 IRQ=69
.equ PIT1_INTERRUPT_VECTOR, 0x00000154
// Timer Interrupt Flag - TIF
__BBREG PIT_TFLG1_TIF 0x4003711C 0

/*** ADC1 ***/

// Status- und Kontrollregister
/*
	COCO	= 0		(Conversion Complete)
	AIEN	= 0		(Inerrupt Enable | disabled)
	DIFF	= 0		(Differntial Mode | single ended mode)
	Input Channel Select
	ADCH	= 11111	(module disabled)	CONFIG_STOP
	ADCH	= 10100	(channel AD20)		CONFIG_RUN
*/
.equ ADC1_SC1A, 				0x400BB000
.equ ADC1_SC1A_CONFIG_STOP, 	0x0000001F
.equ ADC1_SC1A_CONFIG_RUN, 		0x00000014
__BBREG ADC1_SC1A_COCO			0x400BB000 7
/*
	ADACT	= 0		(Conversion Active)
	ADTRG	= 0		(Conversion Trigger Select | software trigger)
	ACFE	= 0		(Compare Function Enable | disabled)
	ACFGT	= 0		(Compare Function Greater Than Enable)
	ACREN	= 0		(Compare Function Range Enable)
	DMAEN	= 0		(DMA Enable | disabled)
	REFSEL	= 00	(Voltage Reference Selection | default -> V_REFH; V_REFL)
*/
.equ ADC1_SC2, 0x400BB020
/*
	CAl		= 0		(Calibration)
	CALF	= 0		(Calibration Failed)
	ADCO	= 1		(Continuous Conversion Enable | enabled)
	AVGE	= 1		(Hardware Average Enable | enabled)
	AVGS	= 10	(Hardware Average Select | 16 samples averaged)
*/
.equ ADC1_SC3, 			0x400BB024
.equ ADC1_SC3_CONFIG, 	0x0000000E
__BBREG ADC1_SC3_CAL 	0x400BB024 7
__BBREG ADC1_SC3_CALF 	0x400BB024 6
// Konfiguration
/*
	ADLPC	= 0		(Low-Power Configuration | normal power config)
	ADIV	= 11	(Clock Divide Select | ADCK = input clock / 8)
	ADLSMP	= 0		(Sample time configuration | short sample time)
	MODE	= 		(Conversion mode selection | N bit resolution; single ended; unsigned)
		N16 = 11
		N10 = 10
		N12 = 01
		N8	= 00
	ADICLK	= 00	(Input Clock Select | bus clock)
*/
.equ ADC1_CFG1, 0x400BB008
.equ ADC1_CFG1_CONFIG_N16, 	0x0000006C
.equ ADC1_CFG1_CONFIG_N12, 	0x00000064
.equ ADC1_CFG1_CONFIG_N10, 	0x00000068
.equ ADC1_CFG1_CONFIG_N8, 	0x00000060

/*
	MUXSEL	= 0		(ADC Mux Select)
	ADACKEN	= 0		(Asynchronous Clock Output Enable | disabled)
	ADHSC	= 0		(High-Speed Configuration | normal conversion sequence)
	ADLSTS	= 00	(Long Sample Time Select)
	
*/
.equ ADC1_CFG2, 0x400BB00C
// Ergebnis
.equ ADC1_RA, 0x400BB010
// Plus, Minus Verstärkung
.equ ADC1_PG, 0x400BB02C
.equ ADC1_MG, 0x400BB030
// Plus Kalibrierung
.equ ADC1_CLP0, 0x400BB04C
.equ ADC1_CLP1, 0x400BB048
.equ ADC1_CLP2, 0x400BB044
.equ ADC1_CLP3, 0x400BB040
.equ ADC1_CLP4, 0x400BB03C
.equ ADC1_CLPS, 0x400BB038
// Minus Kalibrierung
.equ ADC1_CLM0, 0x400BB06C
.equ ADC1_CLM1, 0x400BB068
.equ ADC1_CLM2, 0x400BB064
.equ ADC1_CLM3, 0x400BB060
.equ ADC1_CLM4, 0x400BB05C
.equ ADC1_CLMS, 0x400BB058

/*** PORT Modul A ***/

// Pin Control Register PCR
.equ PORTA_PCR11, 0x4004902C	// LED E1
.equ PORTA_PCR28, 0x40049070	// LED E2
.equ PORTA_PCR29, 0x40049074 	// LED E3
.equ PORTA_PCR10, 0x40049028 	// LED E4
/*
	Standard GPIO Konfiguration
	ISF		= 0		(Interrupt Status Flag)
	IRQC	= 0 	(Interrupt Configuration)
	LK		= 0 	(Lock Register | unlocked)
	MUX		= 001 	(Pin Mux Control | GPIO)
	DSE		= 0		(Drive Strength Enable | low)
	ODE		= 0		(Open Drain Enable | disabled)
	PFE		= 0		(Passive Filter Enable | disabled)
	SRE		= 0		(Slew Rate Enable | fast)
	PE		= 0		(Pull Enable | disabled)
	PS		= 0		(Pull Select)
*/
.equ PCR_STANDARD_CONFIG, 0x00000100

/*** GPIO Modul ***/

// Port Data Output
.equ GPIOA_PDOR, 0x400FF000
// Port Data Direction
.equ GPIOA_PDDR, 0x400FF014
/*
 	 Port A I/O Konfiguration
 	 Output-Pins (1): 	PTA10, PTA11, PTA28, PTA29 
 	 Input-Pins (0):	-
*/
.equ GPIOA_PDDR_CONFIG, 0x30000C00
// PIN Masken
.equ MASK_PTA10, 0x00000400
.equ MASK_PTA11, 0x00000800
.equ MASK_PTA28, 0x10000000
.equ MASK_PTA29, 0x20000000

// Zeichen
.equ START_STOP, 0x73
.equ N8, 0x30
.equ N10, 0x31
.equ N12, 0x32
.equ N16, 0x33

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	/*
		Registerverwendung Initialisierung
		R4	#0
		R5	#1
		R6	ADC1 Kalibrierungsergebnis
		R12 = Adresse ADC1_SC1A
		
		ADC1 wird mit einer Auflösung von 16 Bit initialisiert.
	*/
	mov r4, #0
	mov r5, #1
	
	/*** Interrupt / NVIC Initialisierung ***/
	// Interrupt-Vektor PIT1
	ldr r0, =SCB_VTOR
	ldr r0, [r0]
	ldr r1, =pit1End
	str r1, [r0, #PIT1_INTERRUPT_VECTOR]
	// Wartende Interrupts für PIT1 im NVIC entfernen
	ldr r1, =NVIC_IXXR2_VAL
	ldr r0, =NVIC_ICPR2
	str r1, [r0]
	// Interrupts für PIT1 im NVIC erlauben
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	/*** PIT1 Timer Initialisierung	***/
	ldr r0, =SIM_SCGC6_PIT	
	str r5, [r0]
	// PIT Modul aktivieren
	// Setzt Flags FRZ (Freeze) und MDIS (Module Disable) auf 0
	ldr r0, =PIT_MCR
	str r4, [r0]	        
	// PIT1 Startwert festlegen
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_CYCLES_1S
	str r1, [r0]
	// PIT1 konfigurieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_CONFIG
	str r1, [r0]
	
	/*** PORTA Initialisierung ***/
	ldr r0, =SIM_SCGC5_PORTA
	str r5, [r0]
	// LED Pins konfigurieren
	mov r1, #PCR_STANDARD_CONFIG
	ldr r0, =PORTA_PCR11
	str r1, [r0]
	ldr r0, =PORTA_PCR28
	str r1, [r0]
	ldr r0, =PORTA_PCR29
	str r1, [r0]
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	
	/*** GPIO Initialisierung ***/
	ldr r0, =GPIOA_PDDR
	ldr r1, =GPIOA_PDDR_CONFIG
	ldr r2, [r0]
	orr r1, r1, r2
	str r1, [r0]
	
	/*** ADC1 Initialisierung ***/
	ldr r0, =SIM_SCGC3_ADC1
	str r5, [r0]
	// Kontrollregister
	ldr r12, =ADC1_SC1A
	mov r1, #ADC1_SC1A_CONFIG_STOP
	str r1, [r12]
	ldr r0, =ADC1_SC2
	str r4, [r0]
	ldr r0, =ADC1_SC3
	mov r1, #ADC1_SC3_CONFIG
	str r1, [r0]	
	// Konfigurationsregister
	ldr r0, =ADC1_CFG1
	mov r1, #ADC1_CFG1_CONFIG_N16
	str r1, [r0]
	ldr r0, =ADC1_CFG2
	str r4, [r0]	
	bl calibrateADC1
	mov r6, r0
	// Kalibrierungsergebnis auswerten
	cmp r6, #0x00 // 0x00 -> Kalibrierung erfolgreich
	ite eq
	ldreq r0, =strADC1CalibOk
	ldrne r0, =strADC1CalibFailed
	bl uart_putString
	cmp r6, #0x00 
	bne end
	// Initiale Auflösung ausgeben
	ldr r0, =strRes16
	bl uart_putString
	
	/*
		Registerverwendung Anwendung
		R4	= Adresse secondEnded
		R5	= Adresse ADC1 Ergebnisregister
		R6	= Aktueller Wandler-Wert
		R7	= Adresse Stufen-Array
		R8	= Adresse Stufen-String-Array
		R9 	= AD Wandlung akitv=1 / inaktiv=0
		R10 = Aktuelle Spannungsstufe
		R11 = Adresse GPIOA_PDOR
		R12 = Adresse ADC1_SC1A
		
		Im Stop-Modus wird die Wandlung des ADC1 angehalten. PIT1 + Interrupt-Verarbeitung bleiben aktiv.
	*/
	ldr r4, =secondEnded
	ldr r5, =ADC1_RA
	ldr r7, =n16Levels
	ldr r8, =n16LevelStrings
	ldr r11, =GPIOA_PDOR
	
	// Kontinuierliche Wandlung starten
	mov r9, #0x01
	mov r1, #ADC1_SC1A_CONFIG_RUN
	str r1, [R12]
checkInput:
	/*
		Nutzereingaben abfragen
		R0 = Empfangenes Zeichen
		R1-R3 = Sonstiges
	*/
	bl uart_charPresent
	cmp r0, #0x00
	beq checkSecondEnd
	bl uart_getChar
	
	// Start-Stop Zeichen erkannt
	cmp r0, #START_STOP
	ite eq
	eoreq r9, r9, #0x01
	bne checkModeChangeInput
	// ADC1 Wandlung starten / stoppen
	cmp r9, #0x01
	ite eq
	ldreq r2, =ADC1_SC1A_CONFIG_RUN
	ldrne r2, =ADC1_SC1A_CONFIG_STOP
	str r2, [r12]
	b checkSecondEnd
checkModeChangeInput:
	// Auf Zeichen zur Änderung der Auflösung prüfen, falls die Wandlung nicht gerade aktiv ist
	cmp r9, 0x01
	beq checkSecondEnd
	mov r2, #0x00
	ldr r3, =strDummy
	cmp r0, #N16
	itttt eq
	ldreq r2, =ADC1_CFG1_CONFIG_N16
	ldreq r3, =strRes16
	ldreq r7, =n16Levels
	ldreq r8, =n16LevelStrings
	cmp r0, #N12
	itttt eq
	ldreq r2, =ADC1_CFG1_CONFIG_N12
	ldreq r3, =strRes12
	ldreq r7, =n12Levels
	ldreq r8, =n12LevelStrings
	cmp r0, #N10
	itttt eq
	ldreq r2, =ADC1_CFG1_CONFIG_N10
	ldreq r3, =strRes10
	ldreq r7, =n10Levels
	ldreq r8, =n10LevelStrings
	cmp r0, #N8
	itttt eq
	ldreq r2, =ADC1_CFG1_CONFIG_N8
	ldreq r3, =strRes8
	ldreq r7, =n8Levels
	ldreq r8, =n8LevelStrings	
	// Gültiges Zeichen zur Anpassung der Auflösung erkannt
	cmp r2, #0x00
	itt ne
	ldrne r1, =ADC1_CFG1
	strne r2, [r1]
	mov r0, r3
	bl uart_putString
	
checkSecondEnd:	
	// Sekundenende prüfen
	ldrb r0, [r4]
	cmp r0, #0x00
	beq checkInput
	mov r0, #0x00
	strb r0, [r4]
	
	// Prüfen ob AD Wandlung aktiv ist
	cmp r9, #0x01
	bne checkInput
	
	// Analogwert lesen und ausgeben
	ldr r0, =strHex
	bl uart_putString	
	ldr r6, [r5]
	mov r0, r6
	bl uart_putInt16	
	
	/* 
		Stufe bestimmen und String ausgeben.
		Der Stufenindex wird durch Iteration auf dem ausgewählten Stufen-Array und Vergleich des aktuellen Spannungswertes
		mit der oberen Spannungsgrenze der Stufe ermittelt.
		Aus dem Stufenindex wird anschließend ein Offset für den Zugriff auf das Stufen-Sring-Array berechnet (mul. #4) und
		der zur Stufe gehörende String ausgegeben.
		R0 = Stufen-Index
		R1 = Stufen-Array-Zeiger
		R2 = Oberer Grenzwert der aktuellen Stufe
		R3 = Stufen-String-Array-Zeiger
	*/
	mov r1, r7
	mov r0, #0
nextLevel:
	ldrh r2, [r1]
	cmp r6, r2
	ittt hi
	addhi r0, r0, #1
	addhi r1, r1, #2
	bhi nextLevel
	mov r10, r0
	// Stufen-String ausgeben
	lsl r3, r0, #2
	add r3, r3, r8
	ldr r0, [r3]
	bl uart_putString
	
	/*
		Spannungsstufe an LEDs ausgeben. Unteren 4 Bits des Wertes werden durch Rechtsschieben ausgewertet
		und die Bits in GPIOA_PDOR entsprechend maskiert.
		R0 = Ablages eines einzelnen Bits
		R1 = Stufenwert (Kopie)
		R2 = Wert GPIOA_PDOR / GPIOA Data Output
	*/	
	mov r1, r10
	ldr r2, [r12]
	// LED E4 / PTA10
	ands r0, r1, #0x01
	ite eq
	orreq r2, r2, #MASK_PTA10
	bicne r2, r2, #MASK_PTA10
	// LED E3 / PTA29
	lsr r1, r1, #1
	ands r0, r1, #0x01
	ite eq
	orreq r2, r2, #MASK_PTA29
	bicne r2, r2, #MASK_PTA29
	// LED E2 / PTA28
	lsr r1, r1, #1
	ands r0, r1, #0x01
	ite eq
	orreq r2, r2, #MASK_PTA28
	bicne r2, r2, #MASK_PTA28	
	// LED E1 / PTA11
	lsr r1, r1, #1
	ands r0, r1, #0x01
	ite eq
	orreq r2, r2, #MASK_PTA11
	bicne r2, r2, #MASK_PTA11	
	// GPIOA_PDOR aktualisieren
	str r2, [r11]	
	
	b checkInput
	
end:
	b end
/*
	Kalibriert den ADC1. Vorherige Initialisierung notwendig.
	R0 -> 0 = Kalibrierung erfolgreich; 1 = Kalibrierung fehlgeschlagen
	
	Registerverwendung
	R3 = 0x01
*/	
.thumb_func
calibrateADC1:
	mov r3, #0x01
	// Kalibrierungsfunktion starten
	ldr r0, =ADC1_SC3_CAL
	str r3, [r0]
	ldr r0, =ADC1_SC1A_COCO
awaitCalibration:
	ldr r1, [r0]
	cmp r1, #0x01
	bne awaitCalibration
	// Kalibrierung durchgeführt; Plus-Verstärkung berechnen; 16-Bit UInt
	mov r1, #0x0000
	ldr r0, =ADC1_CLP0
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLP1
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLP2
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLP3
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLP4
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLPS
	ldr r0, [r0]
	add r1, r1, r0
	// Durch 2 teilen und MSB setzen
	lsr r1, r1, #1
	mov r0, 0x00008000
	orr r1, r1, r0
	// Ergebnis sichern
	ldr r0, =ADC1_PG
	str r1, [r0]
	// Minus-Verstärkung berechnen; 16-Bit UInt
	mov r1, #0x0000
	ldr r0, =ADC1_CLM0
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLM1
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLM2
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLM3
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLM4
	ldr r0, [r0]
	add r1, r1, r0
	ldr r0, =ADC1_CLMS
	ldr r0, [r0]
	add r1, r1, r0
	// Durch 2 teilen und MSB setzen
	lsr r1, r1, #1
	mov r0, 0x00008000
	orr r1, r1, r0
	// Ergebnis sichern
	ldr r0, =ADC1_MG
	str r1, [r0]
	// Kalibrierungsfehler-Indikator laden
	ldr r0, =ADC1_SC3_CALF
	ldr r0, [r0]
	
	bx lr
	
// PIT1 ISR
.thumb_func
pit1End:
	// PIT1 Interrupt Flag rücksetzen
	mov r1, #0x01
	ldr r0, =PIT_TFLG1_TIF
	str r1, [r0]
	// Sekundenende-Flag setzen
	ldr r0, =secondEnded
	strb r1, [r0]
	
	bx lr	

/*** Datenbereich (ab 0x20000000) ***/
.data
secondEnded: .byte 0x00
/*
	Die Berechnung der Spannungs-Stufen hätte ich gerne dem Assembler überlassen. Leider kommt es bei
	12 und 10 Bit Auflösungen zu kritischen Rundungsfehlern. Eine Berechnung zur Laufzeit (ohne Gleitpunktzahlen)
	hätte den gleichen Effekt.
	Daher habe ich entschieden, die Berechnung extern durchzuführen und die Ergebnisse / Stufen im Speicher iterierbar
	abzulegen.
*/
n16Levels: .hword 0x0FFF, 0x1FFF, 0x2FFF, 0x3FFF, 0x4FFF, 0x5FFF, 0x6FFF, 0x7FFF, 0x8FFF, 0x9FFF, 0xAFFF, 0xBFFF, 0xCFFF, 0xDFFF, 0xEFFF, 0xFFFF
n12Levels: .hword 0x154, 0x2A9, 0x3FF, 0x554, 0x6A9, 0x7FF, 0x954, 0xAA9, 0xBFF, 0xD54, 0xEA9, 0xFFF
n10Levels: .hword 0x065, 0x0CB, 0x132, 0x198, 0x1FF, 0x265, 0x2CB, 0x332, 0x398, 0x3FF
n8Levels: .hword 0x1F, 0x3F, 0x5F, 0x7F, 0x9F, 0xBF, 0xDF, 0xFF
n16LevelStrings: .word strN16L0, strN16L1, strN16L2, strN16L3, strN16L4, strN16L5, strN16L6, strN16L7, strN16L8, strN16L9, strN16L10, strN16L11, strN16L12, strN16L13, strN16L14, strN16L15
n12LevelStrings: .word strN12L0, strN12L1, strN12L2, strN12L3, strN12L4, strN12L5, strN12L6, strN12L7, strN12L8, strN12L9, strN12L10, strN12L11
n10LevelStrings: .word strN10L0, strN10L1, strN10L2, strN10L3, strN10L4, strN10L5, strN10L6, strN10L7, strN10L8, strN10L9
n8LevelStrings: .word strN8L0, strN8L1, strN8L2, strN8L3, strN8L4, strN8L5, strN8L6, strN8L7
// Stufen 16 Bit Auflösung
strN16L0: .asciz "\t0 - 206 mV (Stufe 0)\n"
strN16L1: .asciz "\t207 - 412 mV (Stufe 1)\n"
strN16L2: .asciz "\t413 - 619 mV (Stufe 2)\n"
strN16L3: .asciz "\t620 - 825 mV (Stufe 3)\n"
strN16L4: .asciz "\t826 - 1031 mV (Stufe 4)\n"
strN16L5: .asciz "\t1032 - 1237 mV (Stufe 5)\n"
strN16L6: .asciz "\t1238 - 1444 mV (Stufe 6)\n"
strN16L7: .asciz "\t1445 - 1650 mV (Stufe 7)\n"
strN16L8: .asciz "\t1651 - 1856 mV (Stufe 8)\n"
strN16L9: .asciz "\t1857 - 2062 mV (Stufe 9)\n"
strN16L10: .asciz "\t2063 - 2269 mV (Stufe 10)\n"
strN16L11: .asciz "\t2270 - 2475 mV (Stufe 11)\n"
strN16L12: .asciz "\t2476 - 2681 mV (Stufe 12)\n"
strN16L13: .asciz "\t2682 - 2887 mV (Stufe 13)\n"
strN16L14: .asciz "\t2888 - 3094 mV (Stufe 14)\n"
strN16L15: .asciz "\t3095 - 3300 mV (Stufe 15)\n"
// Stufen 12 Bit Auflösung
strN12L0: .asciz "\t0 - 274 mV (Stufe 0)\n"
strN12L1: .asciz "\t275 - 549 mV (Stufe 1)\n"
strN12L2: .asciz "\t550 - 824 mV (Stufe 2)\n"
strN12L3: .asciz "\t825 - 1099 mV (Stufe 3)\n"
strN12L4: .asciz "\t1100 - 1375 mV (Stufe 4)\n"
strN12L5: .asciz "\t1376 - 1650 mV (Stufe 5)\n"
strN12L6: .asciz "\t1651 - 1925 mV (Stufe 6)\n"
strN12L7: .asciz "\t1926 - 2200 mV (Stufe 7)\n"
strN12L8: .asciz "\t2201 - 2475 mV (Stufe 8)\n"
strN12L9: .asciz "\t2476 - 2750 mV (Stufe 9)\n"
strN12L10: .asciz "\t2751 - 3025 mV (Stufe 10)\n"
strN12L11: .asciz "\t3026 - 3300 mV (Stufe 11)\n"
// Stufen 10 Bit Auflösung
strN10L0: .asciz "\t0 - 327 mV (Stufe 0)\n"
strN10L1: .asciz "\t328 - 657 mV (Stufe 1)\n"
strN10L2: .asciz "\t658 - 988 mV (Stufe 2)\n"
strN10L3: .asciz "\t989 - 1318 mV (Stufe 3)\n"
strN10L4: .asciz "\t1319 - 1648 mV (Stufe 4)\n"
strN10L5: .asciz "\t1649 - 1979 mV (Stufe 5)\n"
strN10L6: .asciz "\t1980 - 2309 mV (Stufe 6)\n"
strN10L7: .asciz "\t2310 - 2639 mV (Stufe 7)\n"
strN10L8: .asciz "\t2640 - 2970 mV (Stufe 8)\n"
strN10L9: .asciz "\t2971 - 3300 mV (Stufe 9)\n"
// Stufen 8 Bit Auflösung
strN8L0: .asciz "\t0 - 401 mV (Stufe 0)\n"
strN8L1: .asciz "\t402 - 815 mV (Stufe 1)\n"
strN8L2: .asciz "\t816 - 1229 mV (Stufe 2)\n"
strN8L3: .asciz "\t1230 - 1644 mV (Stufe 3)\n"
strN8L4: .asciz "\t1645 - 2058 mV (Stufe 4)\n"
strN8L5: .asciz "\t2059 - 2472 mV (Stufe 5)\n"
strN8L6: .asciz "\t2473 - 2886 mV (Stufe 6)\n"
strN8L7: .asciz "\t2887 - 3300 mV (Stufe 7)\n"
// Sonstige Ausgaben
strADC1CalibOk: .asciz "ADC1 Kalibrierung erfolgreich\n"
strADC1CalibFailed: .asciz "ADC1 Kalibrierung fehlgeschlagen\n"
strHex: .asciz "0x"
strRes16: .asciz "AD Wandlung mit 16 Bit Aufloesung\n"
strRes12: .asciz "AD Wandlung mit 12 Bit Aufloesung\n"
strRes10: .asciz "AD Wandlung mit 10 Bit Aufloesung\n"
strRes8: .asciz "AD Wandlung mit 8 Bit Aufloesung\n"
strStop: .asciz "AD Wandung angehalten:\n"
strDummy: .asciz ""
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*** System Integration ***/

__BBREG SIM_SCGC4_I2C0 	0x40048034 6
__BBREG SIM_SCGC5_PORTD 0x40048038 12
__BBREG SIM_SCGC6_PIT 	0x4004803C 23

/*** Interrupt / NVIC ***/

// Vector Table Offset Register
.equ SCB_VTOR, 0xE000ED08
// Set Enable Register 2
.equ NVIC_ISER2, 0xE000E108
// Clear Pending Register 2
.equ NVIC_ICPR2, 0xE000E288
/*
	NVIC Clear & Enable Wert für Interrupts dieser Anwendung im NVIC_IxxR2 Register
	PIT1 IRQ=69 mod 32 = Bit 5
*/
.equ NVIC_IXXR2_VAL, 0x00000020

/*** PIT1 ***/

// PIT Zyklen für 1s Durchlauf
.equ PIT_CYCLES_1S, 0x017D7840
// Sonstige PIT Register
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
/*
	PIT1 Timer Control Konfiguration
	CHN	= 0 (Chain Mode)
	TIE	= 1 (Timer Interrupt Enable)
	TEN = 1 (Timer Enable)
*/
.equ PIT_TCTRL1_CONFIG, 0x00000003
// PIT1 IRQ=69
.equ PIT1_INTERRUPT_VECTOR, 0x00000154
// Timer Interrupt Flag - TIF
__BBREG PIT_TFLG1_TIF 0x4003711C 0

/*** PORT D ***/
.equ PORTD_PCR8, 0x4004C020
.equ PORTD_PCR9, 0x4004C024
// Maske fuer PD8 und PD9
.equ PD8_9, 0x300
// Maske fuer PD8 
.equ PD8, 0x100
// Alternative 1: GPIO
.equ ALT_GPIO, 0x100
/*
	Alternative 2: I2C SCL/SDA
	ISF 	= 0 	(Interrupt Status Flag)
	IRQC	= 0000	(Interrupt Configuration | disabled)
	LK		= 0		(Lock | no locked)
	MUX		= 010	(Alternative 2 | PD8=SCL; PD9=SDA)
	DSE		= 0		(Drive Strength Enable | low)
	ODE		= 1		(Open Drain Enable | enabled)
	PFE		= 0		(Passive Filter Enable)
	SRE		= 0		(Slew Rate Enable)
	PE		= 0		(Pull Enable | disabled -> external pullup)
	PS		= 0		(Pull Select)
*/
.equ ALT_I2C, 0x0220

/*** GPIO D ***/

// Output Data
.equ GPIOD_PDOR, 0x400FF0C0
// Input Data
.equ GPIOD_PDIR, 0x400FF0D0
// Data Direction
.equ GPIOD_PDDR, 0x400FF0D4

/*** I2C0 ***/

/*
	Frequency Divider Register
	MULT	= 00		(Multiplier Factor | 1)
	ICR		= 001100	(Clock Rate | 12 -> SCL Divider 64)
	
	SCL Takt			= ~391kHZ < DS75 fSCL max (400kHZ)
	SDA Hold Time 		= 0,52us < DS75 tHD:DAT max (0,9us)
	SDA Start Hold Time	= 1,04us > DS75 tHD:STA min (0,6us)
	SCL Stop Hold Time	= 1,32us > DS75 tSU:STO min (0,6us)
*/
.equ I2C0_F, 0x40066001
.equ I2C0_F_CONFIG, 0x0C
/*
	Control Register 1 - Initialisierungswerte
	Änderungen an definierten Feldern im Programmverlauf
	IICEN	= 1		(I2C Enable | enabled)
	IICIE	= 0		(I2C Interrupt Enable | disabled)
	MST		= 0		(Master Mode Select | 0 = slave; 1 = master)
	TX		= 0		(Transmit Mode Select | 0 = receive; 1 = transmit)
	TXAK	= 0		(Transmit Acknoledge Enable | 0 = enabled)
	RSTA	= 0		(Repeat Start | 0 -> 1 creates RS condition)
	WUEN	= 0		(Wakeup Enable | disabled)
	DMAEN	= 0		(DMA Enable | disabled)
*/
.equ I2C0_C1, 0x40066002
.equ I2C0_C1_INIT, 0x80
/*
 	Master Mode
	0 -> 1 erzeugt START Bedingung
	1 -> 0 erzeugt STOP Bedingung
*/
__BBREG I2C0_C1_MST		I2C0_C1 5
/*
	Transmit Mode Select
	0 = receive; 1 = transmit
*/
__BBREG I2C0_C1_TX		I2C0_C1 4
/*
	Transmit Acknoledge Enable
	0 = ACK Signal für folgendes empangenes Byte
	1 = Kein ACK Signal " 
*/
__BBREG I2C0_C1_TXAK	I2C0_C1 3
/*
	Repeat SART
	1 schreiben erzeugt Repeat-Start Bedingung
*/
__BBREG I2C0_C1_RSTA	I2C0_C1 2

/* 
	Control Register 2
	GCAEN	= 0		(General Call Address Enable | disabled)
	ADEXT	= 0		(Address Extension | 7-Bit address scheme)
	HDRS	= 0		(High Drive Select | normal drive mode)
	SBRC	= 0		(Slave Baud Rate Control | slave follows master baud rate)
	RMEN	= 0		(Range Address Matching Enable | disabled)
	AD[SA]	= 000	(Slave address upper 3 Bits in 10-Bit address scheme)
*/
.equ I2C0_C2, 0x40066005
/*
	Berechnung aus Wert in Versuch 2-2 (Unterprogramm übernommen)
	0x00802C80 = 8.400.000 Zyklen für 1s Verzögerung
	0xA8 = 168 Zyklen für 2us Verzögerung
*/
.equ I2C_DELAY_CYCLES_2US, 0xA8

/*
	Status Register
*/
// Arbitration Lost
__BBREG I2C0_S_ARBL 	0x40066003 4
// Interrupt Flag
__BBREG I2C0_S_IICIF 	0x40066003 1
// Receive Acknowledge
__BBREG I2C0_S_RXAK 	0x40066003 0
/*
	Data I/O Register
*/
.equ I2C0_D, 0x40066004
/*
	Programmable Input Glitch Filter Register
	FLT = 0000 (no filter)
*/
.equ I2C0_FLT, 0x40066006
/*
	SMBus Control and Status register
	Alle Funktionen deaktiviert -> alle Felder = 0
*/
.equ I2C0_SMB, 0x40066008
/*
	SCL Low Timeout Registers
	MSB (I2C0_SLTH) und LSB (I2C0_SLTL) = 0x00 (keine Timeouts)
*/
.equ I2C0_SLTH, 0x4006600A
.equ I2C0_SLTL, 0x4006600B

// Versuche bis zum Abbruch eines Bus Übertragungsstarts
.equ I2C0_START_RETRY_COUNT, 9

/*** DS75 ***/

// Adress-Byte Schreibend
.equ DS75_ADR_WRITE, 0x90
// Adress-Byte Lesend
.equ DS75_ADR_READ, 0x91
// Zeiger Temperatur
.equ DS75_POINTER_TEMP, 0x00
// Zeiger Konfiguration
.equ DS75_POINTER_CONFIG, 0x01
// Zeiger Hysterese
.equ DS75_POINTER_HYST, 0x02
// Zeiger Übertemperatur
.equ DS75_POINTER_OS, 0x03
/*
	Configuration Register
	R1, R0	= 11 	(Resolution | 12 Bit)
	F1, F0	= 00 	(Fault Tolerance | 1 out of limit conversion)
	POL		= 0		(Thermostat Output Polarity | O.S. active low)
	TM		= 0		(Thermostat Operating Mode | Comparator Mode)
	SD		= 0		(Shutdown | active conversion) 
*/
.equ DS75_CONFIG, 0x60

/*** Zeichen ***/
.equ COMMA, 0x2C
.equ TAB, 0x09
.equ COLON, 0x3A
.equ ZERO, 0x30

// Sonstiges

// Hilfe zur Umrechnung von Nachkommastellen in dezimale Form
// 2^(-4) * 1000 = 0,0625 * 1000 (dec)
.equ FRAC_4_DEC_SCALE_1000, 0x0271 

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	/*
		Registerverwendung Initialisierung
		R4	= #0
		R5	= #1
		R6	= I2C0_C1_TX
		R7	= I2C0_C1_TXAK
		R8	= I2C0_S_RXAK
		R9	= I2C0_D
		R10 = MSB Temperatur
		R11 = LSB Temperatur
		
		Unterprogramme mit Fehlerprüfung geben selbst entsprechende Fehlermeldungen am Terminal aus. Während der Initialisierung
		auftretende Fehler führen zur Ausgabe einer Meldung und der Beendigung des Programms. Es gibt keine Wiederaufnahme der Kommunikation
		zum DS75 nach dem Auftreten eines Fehlers.
		
		Die Konfiguration des DS75 geschieht in 2 Buszugriffszyklen.
		1 - Konfigurationsregister des DS75 schreiben
		2 - Aktuellen Temperaturwert auslesen und Tos und Thyst Register schreiben
		Nach der Anpassung der Auflösung auf 12 Bit benötigt der DS75 bis zu 1200ms um einen neuen Messwert bereitzustellen. 
		Das Programm wartet nach Schritt 1 zwei volle PIT1 Zyklen (2000ms) ab. Während dieser Zeit wird der I2C0-Bus freigegeben.
		
		Der DS75 Registerzeiger wird am Ende der Konfiguration auf das Temperaturregister gesetzt.
	*/
	mov r4, #0
	mov r5, #1	
	ldr r6, =I2C0_C1_TX
	ldr r7, =I2C0_C1_TXAK
	ldr r8, =I2C0_S_RXAK
	ldr r9, =I2C0_D
	bl uart_init
	
	// I2C0-Bus zurücksetzen
	bl i2c_Reset
	cmp r0, #0x00
	bne end	
	
	/*** Interrupt / NVIC Initialisierung ***/
	// Interrupt-Vektor PIT1
	ldr r0, =SCB_VTOR
	ldr r0, [r0]
	ldr r1, =pit1End
	str r1, [r0, #PIT1_INTERRUPT_VECTOR]
	// Wartende Interrupts für PIT1 im NVIC entfernen
	mov r1, #NVIC_IXXR2_VAL
	ldr r0, =NVIC_ICPR2
	str r1, [r0]
	// Interrupts für PIT1 im NVIC erlauben
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	/*** PIT1 Timer Initialisierung	***/
	ldr r0, =SIM_SCGC6_PIT	
	str r5, [r0]
	// PIT Modul aktivieren
	// Setzt Flags FRZ (Freeze) und MDIS (Module Disable) auf 0
	ldr r0, =PIT_MCR
	str r4, [r0]	        
	// PIT1 Startwert festlegen
	ldr r0, =PIT_LDVAL1
	ldr r1, =PIT_CYCLES_1S
	str r1, [r0]
	// PIT1 konfigurieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_CONFIG
	str r1, [r0]
	
	/*** I2C0 Initialisierung ***/
	ldr r0, =SIM_SCGC4_I2C0
	str r5, [r0]
	// Baud-Rate festlegen
	ldr r0, =I2C0_F
	mov r1, #I2C0_F_CONFIG
	strb r1, [r0]
	// Input Glitch Filter deaktivieren
	ldr r0, =I2C0_FLT
	strb r4, [r0]
	// SMBus Funktionen deaktivieren
	ldr r0, =I2C0_SMB
	strb r4, [r0]
	ldr r0, =I2C0_SLTH
	strb r4, [r0]
	ldr r0, =I2C0_SLTL
	strb r4, [r0]
	// Modul aktivieren und Basis-Konfiguration herstellen
	ldr r0, =I2C0_C1
	mov r1, #I2C0_C1_INIT
	strb r1, [r0]
	ldr r0, =I2C0_C2
	strb r4, [r0]
	
	/*** DS75 Konfiguration ***/
	// Konfigurationsregister schreiben
	mov r0, #DS75_ADR_WRITE
	bl i2c_Start
	cmp r0, #0x00
	bne end
	// Pointer auf Konfigurationsregister
	mov r0, #DS75_POINTER_CONFIG
	strb r0, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Konfigurations Byte schreiben
	mov r0, #DS75_CONFIG
	strb r0, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Buszugriff beenden
	bl i2c_Stop
	
	// 12 Bit Wandlungszeit max 1200ms abwarten
	// 2 volle PIT1 Zyklen abwarten
	mov r0, #2
	ldr r1, =secondEnded
awaitDS75Conversion:
	ldrb r2, [r1]
	cmp r2, #0x01
	bne awaitDS75Conversion
	strb r4, [r1]
	subs r0, r0, #1
	bpl awaitDS75Conversion
	
	// Aktuelle Temperatur des DS75 lesen
	mov r0, #DS75_ADR_WRITE
	bl i2c_Start
	cmp r0, #0x00
	bne end	
	// Pointer auf Temperaturregister
	mov r0, #DS75_POINTER_TEMP
	strb r0, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Temperatur lesen
	mov r0, #DS75_ADR_READ
	bl i2c_RepeatStart
	cmp r0, #0x00
	bne end
	// Übertragungsmodus = Lesen
	strb r4, [r6]
	// Erstes Byte / MSB T0 lesen; ACK senden
	strb r4, [r7]
	ldrb r0, [r9]
	bl i2c_AwaitByteTransfer
	// Zweites Byte / LSB T0 lesen, NACK senden
	strb r5, [r7]
	ldrb r0, [r9]
	mov r10, r0
	bl i2c_AwaitByteTransfer
	// Übertragungsmodus = Schreiben um weitere lesende Datenübertragung zu verhindern
	strb r5, [r6]
	// Zuletzt übertragenes Byte aus Data Register lesen
	ldrb r0, [r9]
	mov r11, r0
	// Tos = T0 + 3 berechnen und übertragen
	add r10, r10, #3
	mov r0, #DS75_ADR_WRITE
	bl i2c_RepeatStart
	// Pointer auf Tos Register
	mov r0, #DS75_POINTER_OS
	strb r0, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Tos Temperaturwert übertragen - MSB
	strb r10, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Tos Temperaturwert übertragen - LSB
	strb r11, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Thyst = Tos - 1 berechnen und übertragen
	sub r10, r10, #1
	mov r0, #DS75_ADR_WRITE
	bl i2c_RepeatStart
	// Pointer auf Thyst Register
	mov r0, #DS75_POINTER_HYST
	strb r0, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Thyst Temperaturwert übertragen - MSB
	strb r10, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Thyst Temperaturwert übertragen - LSB
	strb r11, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Pointer auf Temperaturregister setzen; für weiteren Programmverlauf
	mov r0, #DS75_ADR_WRITE
	bl i2c_RepeatStart
	mov r0, #DS75_POINTER_TEMP
	strb r0, [r9]
	bl i2c_AwaitByteTransfer
	ldrb r0, [r8]
	cmp r0, #0x00
	bne DS75InitError
	// Übertragung beenden
	bl i2c_Stop
	
	/*
		Registerverwendung Anwendung
		R4	= #0
		R5	= #1
		R6	= I2C0_C1_TX
		R7	= I2C0_C1_TXAK
		R8	= Adresse secondEnded
		R9	= I2C0_D
		R10 = MSB Temperatur
		R11 = LSB Temperatur
	*/
	ldr r8, =secondEnded
start:
	// Auf Sekundenende warten
	ldrb r0, [r8]
	cmp r0, #0x00
	beq start
	strb r4, [r8]
	
	// Aktuelle Temperatur des DS75 lesen
	mov r0, #DS75_ADR_READ
	bl i2c_Start
	cmp r0, #0x00
	bne end
	// Übertragungsmodus = Lesen
	strb r4, [r6]
	// Erstes Byte / MSB T0 lesen; ACK senden
	strb r4, [r7]
	ldrb r0, [r9]
	bl i2c_AwaitByteTransfer
	// Zweites Byte / LSB T0 lesen, NACK senden
	strb r5, [r7]
	ldrb r10, [r9]
	bl i2c_AwaitByteTransfer
	// Übertragung beenden
	bl i2c_Stop	
	// Zuletzt übertragenes Byte aus Data Register lesen
	ldrb r11, [r9]	

	// Temperatur ausgeben - Hexadezimal
	ldr r0, =strHex
	bl uart_putString
	mov r0, r10
	mov r1, r11, lsl #8
	orr r0, r1, r0, lsl #16
	bl uart_putInt32
	mov r0, #COLON
	bl uart_putChar
	mov r0, #TAB
	bl uart_putChar
	// Dezimal
	mov r0, r10
	lsr r1, r11, #4
	bl put_8p4FixedPointBase10
	mov r0, #TAB
	bl uart_putChar
	// Grad Celsius String
	ldr r0, =strDegreeCelsius
	bl uart_putString
	
	b start
DS75InitError:
	ldr r0, =strDS75InitFailed	
	bl uart_putString
end:
	b end
	
/*
	Beginnt eine Datenübertragung am I2C0-Bus.
	- Erzeugt START Bedingung
	- Überträgt Slave Adresse + R/W Bit
	- Rücksprung nach Lesebestätigung (ACK) der Adresse durch den Slave
	- Übertragungsmodus (C1_TX) verbleibt auf 1 (Schreiben)
	
	Parameter
	R0 <- Slave Adresse inkl. R/W Bit
	R0 -> 0 = ok; 1 = Fehler aufgetreten
	
	Registerverwendung
	R4 = I2C0_C1_MST / I2C0_D
	R5 = Versuche bis zum Abbruch des Übertragungsstarts
	R6 = Slave Adresse inkl. R/W Bit
*/
.thumb_func
i2c_Start:
	push {r4,r5,r6,lr}
	ldr r4, =I2C0_C1_MST
	mov r5, #I2C0_START_RETRY_COUNT
	mov r6, r0
i2c_StartCheckCondition:
	// Ablauf der Startversuche prüfen
	subs r5, r5, #1
	bmi i2c_StartError
	// MST setzen und Zustand nach Verzögerung durch Lesen prüfen
	mov r2, #0x01
	strb r2, [r4]
	bl i2c_Delay
	ldrb r1, [r4]
	cmp r1, #0x01
	bne i2c_StartCheckCondition
	// Slave-Adresse übertragen; TX=1 setzen; Datenregister schreiben; I2CIF abwarten
	ldr r0, =I2C0_C1_TX
	mov r1, #0x01
	strb r1, [r0]
	ldr r4, =I2C0_D
	strb r6, [r4]
	bl i2c_AwaitByteTransfer
	// Bestätigung des Slave prüfen
	ldr r0, =I2C0_S_RXAK
	ldrb r0, [r0]
	cmp r0, 0x00
	bne i2c_StartError
	// Übertragungsstart erfolgreich
	mov r0, #0x00
	b i2c_StartEnd
i2c_StartError:
	ldr r0, =strI2CStartFailed
	bl uart_putString
	mov r0, #0x01
i2c_StartEnd:
	pop {r4,r5,r6,pc}
	
/*
	Führt einen erneuten Start der Datenübertragung am I2C0-Bus durch.
	- I2C0 muss sich bereits im Master-Mode befinden
	- Erzeugt erneute START Bedingung
	- Prüft Arbitrierungsfehler
	- Überträgt Adresse + R/W Bit
	- Rücksprung nach Lesebestätigung (ACK) der Adresse durch den Slave
	- Übertragungsmodus (C1_TX) verbleibt auf 1 (Transmit/Schreiben)	
	
	Parameter
	R0 <- Slave Adresse inkl. R/W Bit
	R0 -> 0 = ok; 1 = Fehler aufgetreten	
*/	
.thumb_func
i2c_RepeatStart:
	push {lr}
	// START Bedingung erzeugen
	mov r1, #0x01
	ldr r2, =I2C0_C1_RSTA
	strb r1, [r2]
	// Arbitrierungsfehler prüfen
	ldr r2, =I2C0_S_ARBL
	ldrb r2, [r2]
	cmp r2, #0x00
	bne i2c_RepeatStartError
	// Übertragungsmodus = Schreiben
	ldr r2, =I2C0_C1_TX
	strb r1, [r2]
	// Slave Adresse übertragen
	ldr r2, =I2C0_D
	strb r0, [r2]
	bl i2c_AwaitByteTransfer
	// Bestätigung des Slave prüfen
	ldr r2, =I2C0_S_RXAK
	ldrb r2, [r2]
	cmp r2, #0x00
	bne i2c_RepeatStartError
	// Erneuter Übertragungsstart erfolgreich
	mov r0, #0x00
	b i2c_RepeatStartEnd
i2c_RepeatStartError:
	ldr r0, =strI2CRepeatStartFailed
	bl uart_putString
	mov r0, #0x01
i2c_RepeatStartEnd:
	pop {pc}
	
/*
	Beendet eine Datenübertragung am I2C0-Bus.
	- Erzeugt STOP Bedingung
	- Wartet das i2c_delay zur Stabilisierung des Buszustands ab
*/
.thumb_func
i2c_Stop:
	push {lr}
	ldr r0, =I2C0_C1_MST
	mov r1, #0x00
	strb r1, [r0]
	bl i2c_Delay
	pop {pc}
	
/*
	Blockiert bis IICIF gesetzt ist. Setzt IICIF anschließend zurück.
*/
.thumb_func
i2c_AwaitByteTransfer:
	ldr r0, =I2C0_S_IICIF
i2c_AwaitInterrupt:
	ldrb r1, [r0]
	cmp r1, #0x01
	bne i2c_AwaitInterrupt
	strb r1, [r0]
	bx lr	
	
 /*
 	I2C-Bus zuruecksetzen
 	
 	Parameter
 	R0 -> 0 = ok; 1 = Reset fehlgeschlagen
	
	Registerverwendung
 	R4 = Zähler
 */
i2c_Reset:
	push {r4,lr}
	ldr r0, =SIM_SCGC5_PORTD // Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR8 // Portleitungen PD8, PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR // PD8, PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	mov r4, #9
i2c_ResetLoop:
	// Nach 10. Versuch abbrechen
	subs r4, r4, #1
	bmi i2c_ResetError
	ldr r0, =GPIOD_PDOR // SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD8 // entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay
	ldr r0, =GPIOD_PDOR // SCL und SDA aktivieren
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	bl i2c_Delay
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9 // nur Bits 9 und 10 pruefen
	cmp r2, #PD8_9 // Bit 9 und Bit 10 gesetzt?
	bne i2c_ResetLoop // ggf. wiederholen
	mov r0, #0
	b i2c_ResetEnd
i2c_ResetError:
	ldr r0, =strI2CResetFailed
	bl uart_putString
	mov r0, #1
i2c_ResetEnd:
	// Portleitungen PD8, PD9 für I2C Bus schalten
	ldr r1, =PORTD_PCR8
	ldr r2, =PORTD_PCR9
	mov r3, #ALT_I2C
	str r3, [r1]
	str r3, [r2]
	pop {r4,pc}
	
/*
	Blockiert für etwa 2us
*/	
.thumb_func	
i2c_Delay:
	ldr r0, =I2C_DELAY_CYCLES_2US
i2c_DelayWait:
	subs r0, r0, #1
	bpl i2c_DelayWait
	bx lr
	
/*
	Gibt eine vorzeichenlose 8.4 Fixpunktzahl in Dezimalform am Terminal aus.
	
	Parameter
	R0 -> Ganzzahliger Teil (8 Bit)
	R1 -> Fractional (4 Bit)
*/
.thumb_func
put_8p4FixedPointBase10:
	push {r4,r5,lr}
	mov r4, r1
	// Ganzzahligen Anteil ausgeben
	bl uart_putByteBase10
	mov r0, #COMMA
	bl uart_putChar
	/*
		Nachkomma-Anteil in Dezimalform skaliert mit Faktor 1000 umwandeln.
		Multipliziert jede (binäre) Nachkommastelle mit dem zugehörigen Deizmalwert und bildet eine Summe.
		R0 = Produkt / Wert der aktuellen Nachkommastelle
		R1 = Bitmaske 0x01
		R2 = Dezimal-Multiplikator der aktuellen Nachkommastelle
		R3 = Schleifenzähler
		R4 = Nachkomma-Teil der auszugebenden Zahl - Binär
		R5 = Nachkomma-Teil der auszugebenden Zahl - Dezimal
	*/
	mov r5, #0
	mov r3, #3
	ldr r2, =FRAC_4_DEC_SCALE_1000
	mov r1, #0x01
put_8p4ToDec:
	// Dezimalwert der Nachkommastelle bestimmen und summieren
	and r0, r1, r4
	mul r0, r0, r2
	add r5, r5, r0
	// Wertigkeit der nächsten Nachkommastelle berechnen
	lsl r2, r2, #1
	// Nächste Nachkommastelle wählen
	lsr r4, r4, #1
	subs r3, r3, #1
	bpl put_8p4ToDec
	/*
		Nachkomma-Anteil in Dezimalform in Zeichen umwandeln und im Stack ablegen.
		R0 = Quotient
		R1 = Rest / Zeichen
		R4 = Schleifenzähler
	*/
	mov r0, r5
	mov r4, #3
put_8p4PushChar:	
	bl divBy10WithRest
	add r1, r1, #ZERO
	push {r1}
	subs r4, r4, #1
	bpl put_8p4PushChar
	/*
		Dezimalzeichen vom Stack (in korrekter Reihenfolge) am Terminal ausgeben.
		R4 = Schleifenzähler
	*/
	mov r4, #3
put_8p4PutChar:	
	pop {r0}
	bl uart_putChar
	subs r4, r4, #1
	bpl put_8p4PutChar
	pop {r4,r5,pc}
	
/*
	Ganzzahlige Division durch Dezimal 10 mit Rest für vorzeichenlose Dividenden bis 2^30.
	
	Parameter
	R0 -> Dividend
	R0 <- Quotient
	R1 <- Rest
*/	
.thumb_func
divBy10WithRest:
	mov r3, #0
divWithRestSub:
	subs r2, r0, #10
	ittt pl
	addpl r3, r3, #1
	movpl r0, r2
	bpl divWithRestSub
	mov r1, r0
	mov r0, r3
	bx lr
		
// PIT1 ISR
.thumb_func
pit1End:
	// PIT1 Interrupt Flag rücksetzenl
	mov r1, #0x01
	ldr r0, =PIT_TFLG1_TIF
	str r1, [r0]
	// Sekundenende-Flag setzen
	ldr r0, =secondEnded
	strb r1, [r0]
	bx lr	

/*** Datenbereich (ab 0x20000000) ***/
.data
secondEnded: .byte 0x00
strI2CResetFailed: .asciz "I2C Bus Reset fehlgeschlagen\n"
strI2CStartFailed: .asciz "Initiieren der Datenuebertragung am I2C Bus fehlgeschlagen\n"
strI2CRepeatStartFailed: .asciz "Erneuter Start der Datenuebertragung am I2C Bus fehlgeschlagen\n"
strDS75InitFailed: .asciz "DS75 Initialisierung fehlgeschlagen\n"
strDegreeCelsius: .asciz "Grad Celsius\n"
strHex: .asciz "0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*** System Integration ***/

__BBREG SIM_SCGC3_SPI2	0x40048030 12
__BBREG SIM_SCGC6_PIT	0x4004803C 23
// PORT A,D,E
.equ SIM_SCGC5, 0x40048038
.equ SIM_SCGC5_PORT_MASK, 0x3200

/*** Interrupt / NVIC ***/

// Vector Table Offset Register
.equ SCB_VTOR, 0xE000ED08
// Set Enable Register 2
.equ NVIC_ISER2, 0xE000E108
// Clear Pending Register 2
.equ NVIC_ICPR2, 0xE000E288
/*
	NVIC Clear & Enable Wert für Interrupts dieser Anwendung im NVIC_IxxR2 Register
	PIT1	IRQ=69 mod 32 = Bit 5
	PORTA	IRQ=87 mod 32 = Bit 23
	PORTE 	IRQ=91 mod 32 = Bit 27
*/
.equ NVIC_IXXR2_VAL, 0x08800020

/*** PIT1 ***/

// PIT Zyklen in Abhängigkeit der Auflösung
.equ PIT_CYCLES_RES_8,	1875000		// 0,075s
.equ PIT_CYCLES_RES_9,	3750000		// 0,150s
.equ PIT_CYCLES_RES_10,	7500000		// 0,300s
.equ PIT_CYCLES_RES_11,	15000000	// 0,600s
.equ PIT_CYCLES_RES_12, 30000000	// 1,200s
// Sonstige PIT Register
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
// Timer Enable Flag
__BBREG PIT_TCTRL1_TEN 0x40037118 0
/*
	PIT1 Timer Control Konfiguration
	CHN	= 0 (Chain Mode)
	TIE	= 1 (Timer Interrupt Enable)
	TEN = 0 (Timer Enable)
*/
.equ PIT_TCTRL1_CONFIG, 0x00000002
// PIT1 IRQ=69
.equ PIT1_INTERRUPT_VECTOR, 0x00000154
// Timer Interrupt Flag - TIF
__BBREG PIT_TFLG1_TIF 0x4003711C 0

/*** PORT A und E ***/
// SW1 Schwarz
.equ PORTA_PCR19, 0x4004904C
// SW2 Grün
.equ PORTE_PCR26, 0x4004D068
/*
	Drucktaster Konfiguration mit Interrupt
	ISF		= 0		(Interrupt Status Flag)
	IRQC	= 1010 	(Interrupt Configuration | Interrupt on falling edge)
	LK		= 0 	(Lock Register | unlocked)
	MUX		= 001 	(Pin Mux Control | GPIO)
	DSE		= 0		(Drive Strength Enable | low)
	ODE		= 0		(Open Drain Enable | disabled)
	PFE		= 0		(Passive Filter Enable | disabled)
	SRE		= 0		(Slew Rate Enable | fast)
	PE		= 0		(Pull Enable | disabled)
	PS		= 0		(Pull Select)	
*/
.equ PORTAE_CONFIG, 0x000A0100
// PORTA_PCR19 / SW1 Button Interrupt Status Flag
__BBREG PORTA_PCR19_ISF 0x4004904C 24
// PORTE_PCR26 / SW2 Button Interrupt Status Flag
__BBREG PORTE_PCR26_ISF 0x4004D068 24
// PORT A Pin Detect Interrupt Vector; IRQ=87
.equ PORTA_PIN_INTERRUPT_VECTOR, 0x0000019C 
// PORT E Pin Detect Interrupt Vector; IRQ=91
.equ PORTE_PIN_INTERRUPT_VECTOR, 0x000001AC

/*** PORT D ***/
// Clock (CLK)
.equ PORTD_PCR12, 0x4004C030 
// SPI2 Master Out Slave In (MOSI)
.equ PORTD_PCR13, 0x4004C034
// SPI2 Master In Slave Out (MISO)
.equ PORTD_PCR14, 0x4004C038
// SPI2 Chip Select (CS)
.equ PORTD_PCR15, 0x4004C03C
/*
	PORT D Pin Konfiguration ALT2 - SPI2
	ISF 	= 0 	(Interrupt Status Flag)
	IRQC	= 0000	(Interrupt Configuration | disabled)
	LK		= 0		(Lock | not locked)
	MUX		= 010	(Alternative 2 | SPI2 Funktionen)
	DSE		= 0		(Drive Strength Enable | low)
	ODE		= 1		(Open Drain Enable | enabled)
	PFE		= 0		(Passive Filter Enable)
	SRE		= 0		(Slew Rate Enable)
	PE		= 0		(Pull Enable | disabled -> external pullup)
	PS		= 0		(Pull Select)
*/
.equ PORTD_CONFIG, 0x0200

/*** SPI2 ***/

/*
 	Module Configuration
	MSTR		= 1		(Master/Slave Mode Select | Master)
	CONT_SCKE	= 0		(Continuous SCK Enable | disabled)
	DCONF		= 00 	(DSPI Configuration | SPI)
	FRZ			= 0		(Freeze | no halt in Debug mode)
	MTFE		= 0		(Modified Timing Format Enable | disabled)
	ROOE		= 0		(Receive FIFO Overflow Overwrite Enable | ignore data)
	PCSIS		= 0000	(Peripheral Chip Select x Inactive State | inactive low)
	DOZE		= 0		(Doze Enable | disabled)
	MDIS		= 0		(Module Disable | module enabled)
	DIS_TXF		= 0		(Disable Transmit FIFO | enabled)
	DIS_RXF		= 0		(Disable Receive FIFO | enabled)
	CLR_TXF		= 0		(Flush the TX FIFO)
	CLR_RXF		= 0		(Flush the RX FIFO)
	SMPL_PT		= 00	(Sample Point | SPI2_CTAR1[CPHA] = 1; no effect)
	HALT		= 1		(Start / stop module transfers | stop transfers)
*/
.equ SPI2_MCR, 0x400AC000
.equ SPI2_MCR_CONFIG, 0x80000001
// Halt Flag
__BBREG SPI2_MCR_HALT 0x400AC000 0
// Queue Disable Flags
__BBREG SPI2_MCR_DIS_TXF 0x400AC000 13
__BBREG SPI2_MCR_DIS_RXF 0x400AC000 12
/*
	Clock and transfer attributes (CTAR)
	Framesize = 16 Bits
	DBR		= 0		(Double Baud Rate | not doubled)
	FMSZ	= 1111	(Frame Size | 15 + 1 = 16 Bit)
	CPOL	= 0		(Clock Polarity | inactive low)
	CPHA	= 1		(Clock Phase | data capure on leading edge)
	LSBFE	= 0		(LSB first | MSB first)
	PCSSCK	= 00	(PCS to SCK Delay Prescaler | 1)
	PASC	= 00	(After SCK Delay Prescaler | 1)
	PDT		= 00	(Delay after Transfer Prescaler | 1)
	PBR		= 00	(Baud Rate Prescaler | 1/2)
	CSSCK	= 0110	(PCS to SCK Delay Scaler | 128)
	ASC		= 0100	(After SCK Delay Scaler | 32)
	DT		= 0110	(Delay After Transfer Scaler | 128)
	BR		= 0111	(Baud Rate Scaler | 1/128)
*/
.equ SPI2_CTAR0, 0x400AC00C
.equ SPI2_CTAR0_CONFIG, 0x7A006467
/*
	Clock and transfer attributes (CTAR) - analog CTAR0
	Framesize = 8 Bits
	FMSZ	= 0111	(Frame Size | 7 + 1 = 8 Bit)
*/
.equ SPI2_CTAR1, 0x400AC010
.equ SPI2_CTAR1_CONFIG, 0x3A006467
// Transfer Complete Flag
__BBREG SPI2_SR_TCF		0x400AC02C 31
// End of Queue Flag
__BBREG SPI2_SR_EOQF	0x400AC02C 28
// DMA/Interrupt Request Select and Enable Register
.equ SPI2_RSER, 0x400AC030

// PUSH TX FIFO Register (Data)
.equ SPI2_PUSHR, 0x400AC034
// POP RX FIFO Register
.equ SPI2_POPR, 0x400AC038

/*** DS1722 ***/

/*
	SPI2 Command - Konfiguration
	Adressbyte + Konfigurationsbyte ausgeben
	CONT	= 0			(Continuous Peripheral Chip Select Enable | disabled)
	CTAS	= 000		(Clock and Transfer Attributes Select | CTAR0)
	EOQ		= 1			(End Of Queue)
	CTCNT	= 0			(Clear Transfer Counter)
	PCS		= 000010	(Chip Select | Assert PCS1)
*/
.equ DS1722_CMD_WRITE_CONFIG_RES_8,		0x080280E0
.equ DS1722_CMD_WRITE_CONFIG_RES_9,		0x080280E2
.equ DS1722_CMD_WRITE_CONFIG_RES_10,	0x080280E4
.equ DS1722_CMD_WRITE_CONFIG_RES_11,	0x080280E6
.equ DS1722_CMD_WRITE_CONFIG_RES_12,	0x080280E8
/*
	SPI2 Command - Adresse Temperatur LSB ausgeben
	CONT	= 1			(Continuous Peripheral Chip Select Enable | enabled)
	CTAS	= 001		(Clock and Transfer Attributes Select | CTAR1)
	EOQ		= 0			(End Of Queue)
	CTCNT	= 0			(Clear Transfer Counter)
	PCS		= 000010	(Chip Select | Assert PCS1)
*/
.equ DS1722_CMD_WRITE_TEMP_LSB_ADDR, 0x90020001
/*
	SPI2 Command - Lesen des Temperatur LSB + MSB
	CONT	= 0			(Continuous Peripheral Chip Select Enable | disabled)
	CTAS	= 000		(Clock and Transfer Attributes Select | CTAR0)
	EOQ		= 1			(End Of Queue)
	CTCNT	= 0			(Clear Transfer Counter)
	PCS		= 000010	(Chip Select | Assert PCS1)
*/
.equ DS1722_CMD_READ_TEMP, 0x08020000

/*** Zeichen ***/
.equ COMMA, 0x2C
.equ ZERO, 0x30

// Hilfe zur Umrechnung von Nachkommastellen in dezimale Form
// 2^(-4) * 1000 = 0,0625 * 1000 (dec)
.equ FRAC_4_DEC_SCALE_1000, 625

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	/*
		Registerverwendung Initialisierung
		R4 = #0
		R5 = #1
	*/
	bl uart_init
	mov r4, #0
	mov r5, #1
	
	/*** Interrupt / NVIC Initialisierung ***/
	// Interrupt-Vektor PIT1
	ldr r0, =SCB_VTOR
	ldr r0, [r0]
	ldr r1, =pit1End
	str r1, [r0, #PIT1_INTERRUPT_VECTOR]
	// Interrupt-Vektor Port A Pin Detect
	ldr r1, =portAPin
	str r1, [r0, #PORTA_PIN_INTERRUPT_VECTOR]
	// Interrupt-Vektor Port E Pin Detect
	ldr r1, =portEPin
	str r1, [r0, #PORTE_PIN_INTERRUPT_VECTOR]		
	// Wartende Interrupts im NVIC entfernen
	ldr r1, =NVIC_IXXR2_VAL
	ldr r0, =NVIC_ICPR2
	str r1, [r0]
	// Interrupts für PIT1, PORTA und PORTE im NVIC erlauben
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	/*** PIT1 Timer Initialisierung	***/
	ldr r0, =SIM_SCGC6_PIT	
	str r5, [r0]
	// PIT Modul aktivieren
	// Setzt Flags FRZ (Freeze) und MDIS (Module Disable) auf 0
	ldr r0, =PIT_MCR
	str r4, [r0]	        
	// PIT1 konfigurieren
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_CONFIG
	str r1, [r0]
	
	/*
		PORTA & PORTE Initialisierung
	*/
	ldr r0, =SIM_SCGC5
	ldr r1, [r0]
	ldr r2, =SIM_SCGC5_PORT_MASK
	orr r1, r1, r2
	str r1, [r0]
	ldr r1, =PORTAE_CONFIG
	ldr r0, =PORTA_PCR19
	str r1, [r0]	
	ldr r0, =PORTE_PCR26
	str r1, [r0]	
	
	/*** PORT D Initialisierung ***/
	// Pins für SPI2 Funktion konfigurieren
	// CLK
	ldr r1, =PORTD_CONFIG
	ldr r0, =PORTD_PCR12
	str r1, [r0]
	// MOSI
	ldr r0, =PORTD_PCR13
	str r1, [r0]
	// MISO
	ldr r0, =PORTD_PCR14
	str r1, [r0]
	// CS
	ldr r0, =PORTD_PCR15
	str r1, [r0]	
	
	/*** SPI2 Initialisierung ***/
	ldr r0, =SIM_SCGC3_SPI2
	str r5, [r0]
	// Modulkonfiguration
	ldr r0, =SPI2_MCR
	ldr r1, =SPI2_MCR_CONFIG
	str r1, [r0]
	// FIFO Queues deaktivieren (nach Modulaktivierung)
	ldr r0, =SPI2_MCR_DIS_TXF
	str r5, [r0]
	ldr r0, =SPI2_MCR_DIS_RXF
	str r5, [r0]
	// Konfiguration CTAR0
	ldr r0, =SPI2_CTAR0
	ldr r1, =SPI2_CTAR0_CONFIG
	str r1, [r0]
	// Konfiguration CTAR1
	ldr r0, =SPI2_CTAR1
	ldr r1, =SPI2_CTAR1_CONFIG
	str r1, [r0]
	// DMA und Interrupt Konfiguration
	ldr r0, =SPI2_RSER
	str r4, [r0]		
	
	/*
		Registervwerwendung Anwendung
		R4 = #0
		R5 = #1		
		R6	= Adresse Button Indikator
		R7	= Auflösung Indikator
			1 = 8 Bit
			2 = 9 Bit
			3 = 10 Bit
			4 = 11 Bit
			5 = 12 Bit
		R8	= SPI2_SR_TCF
		R9	= SPI2_SR_EOQF
		R10	= SPI2_MCR_HALT
		R11	= Adresse pitEnded
		R12	= SPI2_POPR
		
		Programmablauf und Initialisierung
		Nach dem Betätigen eines Tasters stopt das Programm den PIT1 Zähler, setzt einen neuen Zählerwert,
		konfiguriert den DS1722 mit der neuen Auflösung und startet den PIT1 Zähler wieder.
		Der Button Indikator ist mit "1" (Auflösung erhöhen), die Auflösungs-Indikator mit "4" (11 Bit) vorbelegt.
		Dadurch wird die Initialisierung ohne physischen Tastendruck beim ersten Schleifendurchlauf durchgeführt 
		und der DS1722 mit einer 12 Bit Wandler-Auflösung initialisiert.
		
		DS1722 Konfiguration
		Der DS1722 wandelt kontinuierlich; die Temperatur-Wandlung wird zu keinem Zeitpunkt unterbrochen.
		
		SPI2 Schnittstelle
		Es stehen zwei Transferkonfigurationen zur Verfügung, die sich ausschließlich in der Frame-Länge unterscheiden.
		1. CTAR0: 16 Bit Frame
		2. CTAR1: 8 Bit Frame
		Die Konfiguration des DS1722 geschieht mit einem 16 Bit Frame; Übertrag Adressbyte + Konfigurationsbyte.
		Das Auslesen der Temperatur geschieht mit zwei aufeinanderfolgenden Frames. PCS bleibt bis zum abgeschlossenen
		Übertrag des zweiten Frames aktiv (DS1722 Multi Byte Burst Transfer).
		1. Übertrag des LSB-Adressbytes in einem 8 Bit Frame
		2. Auslesen des LSB und MSB Bytes in einem 16 Bit Frame
	*/
	ldr r6, =button
	mov r7, #4
	ldr r8, =SPI2_SR_TCF
	ldr r9, =SPI2_SR_EOQF
	ldr r10, =SPI2_MCR_HALT
	ldr r11, =pitEnded
	ldr r12, =SPI2_POPR	
start:	
	/*
		Button Betätigung prüfen und Auflösungs-Indikator anpassen
		R0 = Button Indikator
	*/
	ldrb r0, [r6]
	cmp r0, #0
	beq awaitPitEnd
	cmp r0, #1
	ite eq
	addeq r7, r7, #1
	subne r7, r7, #1
	// Obere Grenze
	cmp r7, #5
	it hi
	movhi r7, #1
	// Untere Grenze
	cmp r7, #0
	it ls
	movls r7, #5
	// Indikator zurücksetzen
	mov r0, #0
	strb r0, [r6]	
	/*
		Auflösung umstellen
		R1 = PIT Zyklen
		R2 = SPI Command
		R3 = Adresse Info-String
	*/
	// 8 Bit
	cmp r7, #1
	ittt eq
	ldreq r1, =PIT_CYCLES_RES_8
	ldreq r2, =DS1722_CMD_WRITE_CONFIG_RES_8
	ldreq r3, =strRes8
	// 9 Bit
	cmp r7, #2
	ittt eq
	ldreq r1, =PIT_CYCLES_RES_9
	ldreq r2, =DS1722_CMD_WRITE_CONFIG_RES_9
	ldreq r3, =strRes9
	// 10 Bit
	cmp r7, #3
	ittt eq
	ldreq r1, =PIT_CYCLES_RES_10
	ldreq r2, =DS1722_CMD_WRITE_CONFIG_RES_10
	ldreq r3, =strRes10
	// 11 Bit
	cmp r7, #4
	ittt eq
	ldreq r1, =PIT_CYCLES_RES_11
	ldreq r2, =DS1722_CMD_WRITE_CONFIG_RES_11
	ldreq r3, =strRes11
	// 12 Bit
	cmp r7, #5
	ittt eq
	ldreq r1, =PIT_CYCLES_RES_12
	ldreq r2, =DS1722_CMD_WRITE_CONFIG_RES_12
	ldreq r3, =strRes12
	// Neuen PIT Zählerstartwert festlegen
	ldr r0, =PIT_TCTRL1_TEN
	str r4, [r0]
	ldr r0, =PIT_LDVAL1
	str r1, [r0]
	/*
		DS1722 Konfiguration mit gewählter Auflösung
		R1 = SPI2_PUSHR
	*/
	ldr r1, =SPI2_PUSHR
	str r2, [r1]
	// HALT lösen
	str r4, [r10]
awaitKonfigWrite:
	ldr r0, [r8]
	cmp r0, #0
	beq awaitKonfigWrite
	// HALT setzen
	str r5, [r10]
	// TCF, EOQF rücksetzen
	str r5, [r8]
	str r5, [r9]
	// Dummy Read zum löschen der RX Queue
	ldr r0, [r12]
	// PIT aktivieren
	ldr r0, =PIT_TCTRL1_TEN
	str r5, [r0]
	// Hinweis ausgeben
	mov r0, r3
	bl uart_putString
	
awaitPitEnd:	
	// Ablauf des PIT abwarten
	ldrb r0, [r11]
	cmp r0, #0
	beq awaitPitEnd
	strb r4, [r11]
	
	/*
		Temperatur abfragen und am Terminal ausgeben
		R1 = SPI2_PUSHR
	*/
	ldr r1, =SPI2_PUSHR
	// HALT lösen
	str r4, [r10]
	// Temperatur MSB Adresse schreiben
	ldr r0, =DS1722_CMD_WRITE_TEMP_LSB_ADDR
	str r0, [r1]
awaitTempMSBWrite:
	ldr r0, [r8]
	cmp r0, #0
	beq awaitTempMSBWrite
	// TCF rücksetzen
	str r5, [r8]
	// Dummy Read
	ldr r0, [r12]
	// Temperatur MSB + LSB lesen
	ldr r0, =DS1722_CMD_READ_TEMP
	str r0, [r1]
awaitTempRead:
	ldr r0, [r8]
	cmp r0, #0
	beq awaitTempRead		
	// TCF, EOQF rücksetzen
	str r5, [r8]
	str r5, [r9]	
	// HALT setzen
	str r5, [r10]	

	/*
		Ergebnis lesen und ausgeben
		R0 = MSB -> 8 Bit ganzzahliger Anteil
		R1 = LSB -> 4 Bit Nachkomma-Anteil
		R2 = LSB Maske
		R3 = Gelesenes Ergebnis
	*/
	ldr r3, [r12]	
	mov r2, #0xFF
	and r0, r3, r2
	lsr r1, r3, #12
	bl put_8p4FixedPointBase10
	ldr r0, =strDeg
	bl uart_putString	
	
	b start
	
/*
	Gibt eine vorzeichenlose 8.4 Fixpunktzahl in Dezimalform am Terminal aus.
	
	Parameter
	R0 -> Ganzzahliger Teil (8 Bit)
	R1 -> Fractional (4 Bit)
*/
.thumb_func
put_8p4FixedPointBase10:
	push {r4,r5,lr}
	mov r4, r1
	// Ganzzahligen Anteil ausgeben
	bl uart_putByteBase10
	mov r0, #COMMA
	bl uart_putChar
	/*
		Nachkomma-Anteil in Dezimalform skaliert mit Faktor 1000 umwandeln.
		Multipliziert jede (binäre) Nachkommastelle mit dem zugehörigen Deizmalwert und bildet eine Summe.
		R0 = Produkt / Wert der aktuellen Nachkommastelle
		R1 = Bitmaske 0x01
		R2 = Dezimal-Multiplikator der aktuellen Nachkommastelle
		R3 = Schleifenzähler
		R4 = Nachkomma-Teil der auszugebenden Zahl - Binär
		R5 = Nachkomma-Teil der auszugebenden Zahl - Dezimal
	*/
	mov r5, #0
	mov r3, #3
	ldr r2, =FRAC_4_DEC_SCALE_1000
	mov r1, #0x01
put_8p4ToDec:
	// Dezimalwert der Nachkommastelle bestimmen und summieren
	and r0, r1, r4
	mla r5, r0, r2, r5
	// Wertigkeit der nächsten Nachkommastelle berechnen
	lsl r2, r2, #1
	// Nächste Nachkommastelle wählen
	lsr r4, r4, #1
	subs r3, r3, #1
	bpl put_8p4ToDec
	/*
		Nachkomma-Anteil in Dezimalform in Zeichen umwandeln und in R5 ablegen.
		R0 = Quotient
		R1 = Rest / Zeichen
		R2 = Sicherung Quotient zum Rückmultiplizieren
		R3 = #10
		R4 = Schleifenzähler
		R5 = Zeichenablage
	*/
	mov r0, r5
	mov r3, #10
	mov r4, #3
	mov r5, #0
put_8p4PushChar:
	mov r2, r0
	udiv r0, r2, r3
	mls r1, r0, r3, r2
	add r1, r1, #ZERO
	orr r5, r1, r5, lsl #8
	subs r4, r4, #1
	bpl put_8p4PushChar
	/*
		Dezimalzeichen aus R5 (in korrekter Reihenfolge) am Terminal ausgeben.
		R4 = Schleifenzähler
	*/
	mov r4, #3
put_8p4PutChar:
	mov r0, r5
	bl uart_putChar
	lsr r5, r5, #8
	subs r4, r4, #1
	bpl put_8p4PutChar
	pop {r4,r5,pc}
	
// PIT1 ISR
.thumb_func
pit1End:
	// PIT1 Interrupt Flag rücksetzen
	mov r1, #0x01
	ldr r0, =PIT_TFLG1_TIF
	str r1, [r0]
	// Sekundenende-Flag setzen
	ldr r0, =pitEnded
	strb r1, [r0]
	bx lr	
	
// PORTA Pin ISR
.thumb_func
portAPin:
	// PORTA Interrupt Flag rücksetzen
	mov r1, #1
	ldr r0, =PORTA_PCR19_ISF
	str r1, [r0]
	// Button Indikator setzen
	ldr r0, =button
	strb r1, [r0]
	
	bx lr
	
// PORTE Pin ISR
.thumb_func
portEPin:
	// PORTE Interrupt Flag rücksetzen
	mov r1, #1
	ldr r0, =PORTE_PCR26_ISF
	str r1, [r0]
	// Button Indikator setzen
	ldr r0, =button
	mov r1, #2
	strb r1, [r0]
	
	bx lr			

/*** Datenbereich (ab 0x20000000) ***/
.data
pitEnded: .byte 0x00
/*
	Button Indikator
	0 = Kein Button betätigt
	1 = SW1 wurde betätigt
	2 = SW2 wurde betätigt
*/
button: .byte 0x01
strRes8: .asciz "Neue Aufloesung: 8 Bit\n"
strRes9: .asciz "Neue Aufloesung: 9 Bit\n"
strRes10: .asciz "Neue Aufloesung: 10 Bit\n"
strRes11: .asciz "Neue Aufloesung: 11 Bit\n"
strRes12: .asciz "Neue Aufloesung: 12 Bit\n"
strDeg: .asciz " gC\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*** System Integration ***/

__BBREG SIM_SCGC6_RTC	0x4004803C 29

/*** Interrupt / NVIC ***/

// Vector Table Offset Register
.equ SCB_VTOR, 0xE000ED08
// Set Enable Register 2
.equ NVIC_ISER2, 0xE000E108
// Clear Pending Register 2
.equ NVIC_ICPR2, 0xE000E288
/*
	NVIC Clear & Enable Wert für Interrupts dieser Anwendung im NVIC_IxxR2 Register
	RTC	(Seconds Interrupt) IRQ=67 mod 32 = Bit 3
*/
.equ NVIC_IXXR2_VAL, 0x08
// RTC Senconds Interrupt Vector
.equ RTC_SEC_INTERRUPT_VECTOR, 0x0000014C 

/*** Real Time Clock ***/

// Seconds
.equ RTC_TSR, 0x4003D000
// Prescaler
.equ RTC_TPR, 0x4003D004
// Alarm
.equ RTC_TAR, 0x4003D008
// Time Compensation
.equ RTC_TCR, 0x4003D00C
/*
	Control
	SCxP	= 0 (Oscillator Load Configure | standard)
	CLKO	= 1 (Clock Output | disabled)
	OSCE	= 1 (Oscillator Enable | enabled)
	UM		= 0	(Update Mode | disbaled)
	SUP		= 0 (Supervisor Access | non SV access disabled)
	WPE		= 0 (Wakeup Pin Enable | disabled)
	SWR		= 0 (Software Reset)
*/
.equ RTC_CR, 0x4003D010
.equ RTC_CR_CONFIG, 0x0300
// Status - Counter Enable
__BBREG RTC_SR_TCE 0x4003D014 4
// Status - Alarm Flag
__BBREG RTC_SR_TAF 0x4003D014 2
// Lock
.equ RTC_LR, 0x4003D018
.equ RTC_LR_CONFIG, 0xFF
/*
 	Interrupt Enable
 	WPON	= 0 (Wakeup Pin On | off)
 	TSIE	= 1 (Time Seconds Interrupt Enable | enabled)
 	TAIE	= 0 (Time Alarm Interrupt Enable | disabled)
 	TOIE	= 0 (Time Overflow Interrupt Enable | disabled)
 	TIIE	= 0 (Time Invalid Interrupt Enable | disabled)
*/
.equ RTC_IER, 0x4003D01C
.equ RTC_IER_CONFIG, 0x10
/*
	Read / Write Access - Standard
*/
.equ RTC_WAR, 0x4003D800
.equ RTC_RAR, 0x4003D804

// Sekunden für 24h Schwelle
.equ SEC_24H, 86399
.equ SEC_24H_PRESET, 86395
// Sekunden 1H Schwelle
.equ SEC_1H, 3599
.equ SEC_1H_PRESET, 3595

/* Zeichen */
.equ D, 0x64
.equ H, 0x68
.equ R, 0x72
.equ S, 0x73
.equ P, 0x70
.equ LINEFEED, 0x0A
.equ COLON, 0x3A

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	/*
		Registerverwendung Initialisierung
		R4 = #0
		R5 = #1
	*/
	bl uart_init
	mov r4, #0
	mov r5, #1
	
	/*** Interrupt / NVIC Initialisierung ***/
	// Interrupt-Vektor RTC Sekundenende
	ldr r0, =SCB_VTOR
	ldr r0, [r0]
	ldr r1, =rtcSec
	str r1, [r0, #RTC_SEC_INTERRUPT_VECTOR]		
	// Wartende Interrupts im NVIC entfernen
	ldr r1, =NVIC_IXXR2_VAL
	ldr r0, =NVIC_ICPR2
	str r1, [r0]
	// Interrupts für RTC im NVIC erlauben
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	/*** RTC Initialisierung ***/
	ldr r0, =SIM_SCGC6_RTC
	str r5, [r0]	
	// Zähler deaktivieren
	ldr r0, =RTC_SR_TCE
	str r4, [r0]
	// Startwert initialisieren
	ldr r0, =RTC_TSR
	str r4, [r0]
	// Prescaler initialisieren
	ldr r0, =RTC_TPR
	str r4, [r0]
	// Alarm Wert festlegen; Startwert für 24h Modus
	ldr r0, =RTC_TAR
	ldr r1, =SEC_24H
	str r1, [r0]
	// Time Compensation / Zählerkorrektur deaktivieren
	ldr r0, =RTC_TCR
	str r4, [r0]
	// Kontrollregister schreiben / Oszillator aktivieren
	ldr r0, =RTC_CR
	ldr r1, =RTC_CR_CONFIG
	str r1, [r0]
	// Register-Sperr-, Lese- und Schreibzugriff
	ldr r0, =RTC_LR
	mov r1, #RTC_LR_CONFIG
	str r1, [r0]
	ldr r0, =RTC_WAR
	str r1, [r0]	
	ldr r0, =RTC_RAR
	str r1, [r0]
	// Interrupts konfigurieren
	ldr r0, = RTC_IER
	mov r1, #RTC_IER_CONFIG
	str r1, [r0]
	// Zähler aktivieren
	ldr r0, =RTC_SR_TCE
	str r5, [r0]	
	
	/*
		Registerverwendung Anwendung
		R4	= RTC_TPR
		R5	= RTC_TSR
		R6	= RTC_TAR
		R7	= Start/Stop; 0=Start
		R8	= Modus; 24h=0; 1h=1
		R9	= RTC_SR_TAF
		R10	= RTC_SR_TCE
		R11	= Adresse secondEnd
		R12 = Restliche Sekunden; Zeitformatierung
		
		Die Anwendung behandelt keine RTC Überläufe. Auch beim erneuten Setzen des selben Modus (1h/24h)
		wird der Zähler zurückgesetzt. Das Erreichen des Alarm-Schwellenwertes setzt den Zähler ebenfalls zurück.
	*/
	ldr r4, =RTC_TPR
	ldr r5, =RTC_TSR
	ldr r6, =RTC_TAR
	mov r7, #0
	mov r8, #0
	ldr r9, =RTC_SR_TAF
	ldr r10, =RTC_SR_TCE
	ldr r11, =secondEnd
checkInput:	
	// Tastatureingabe prüfen
	bl uart_charPresent
	cmp r0, #0
	beq checkSecondEnd
	/*
		R0 = Eingegebenes Zeichen
	*/	
	bl uart_getChar
	cmp r0, #D
	beq set24hMode
	cmp r0, #H
	beq set1hMode
	cmp r0, #R
	beq clockReset
	cmp r0, #P
	beq clockPreset
	cmp r0, #S
	beq clockStartStop
	
	b checkSecondEnd
set24hMode:
	mov r8, #0
	// RTC anhalten und Zähler zurücksetzen
	mov r0, #0
	str r0, [r10]
	str r0, [r4]
	str r0, [r5]
	// Alarm auf 23:59:59 Sekunden setzen
	ldr r0, =SEC_24H
	str r0, [r6]
	// Terminalausgabe
	ldr r0, =str24hMode
	bl uart_putString
	// RTC starten
	mov r0, #1
	str r0, [r10]
	b checkSecondEnd

set1hMode:
	mov r8, #1
	// RTC anhalten und Zähler zurücksetzen
	mov r0, #0
	str r0, [r10]
	str r0, [r4]
	str r0, [r5]
	// Alarm auf 59:59 Sekunden setzen
	ldr r0, =SEC_1H
	str r0, [r6]
	// Terminalausgabe
	ldr r0, =str1hMode
	bl uart_putString
	// RTC starten
	mov r0, #1
	str r0, [r10]	
	b checkSecondEnd

clockReset:
	// RTC anhalten und Zähler zurücksetzen
	mov r0, #0
	str r0, [r10]
	str r0, [r4]
	str r0, [r5]
	// Terminalausgabe
	ldr r0, =strClockReset
	bl uart_putString
	// RTC starten
	mov r0, #1
	str r0, [r10]	
	b checkSecondEnd	

clockPreset:
	// RTC anhalten
	mov r0, #0
	str r0, [r10]
	// Zähler vorstellen; RTC_TPR = 0
	str r0, [r4]
	cmp r8, #0
	ite eq
	ldreq r0, =SEC_24H_PRESET
	ldrne r0, =SEC_1H_PRESET
	str r0, [r5]
	// Terminalausgabe
	ldr r0, =strClockPreset
	bl uart_putString
	// RTC starten
	mov r0, #1
	str r0, [r10]	
	b checkSecondEnd
	
clockStartStop:	
	// Start/Stop Indikator umschalten und Hinweis ausgeben
	eor r7, r7, #1
	cmp r7, #0
	ite eq
	ldreq r0, =strClockDisplayOn
	ldrne r0, =strClockDisplayOff
	bl uart_putString
	
checkSecondEnd:	
	// Ablauf einer Sekunde prüfen
	ldrb r0, [r11]
	cmp r0, #0
	beq checkInput
	// Indikator rücksetzen
	mov r0, #0
	strb r0, [r11]
	
	// Ablauf der Alarmzeit prüfen
	ldr r0, [r9]
	cmp r0, #1
	bne putTime	
	// RTC anhalten und Zähler zurücksetzen
	mov r0, #0
	str r0, [r10]
	str r0, [r4]
	str r0, [r5]
	// Alarm zurücksetzen
	cmp r8, #0
	ite eq
	ldreq r0, =SEC_24H
	ldrne r0, =SEC_1H
	// RTC_SR_TAF durch erneutes Schreiben von RTC_TAR rücksetzen
	str r0, [r6]
	// Terminalausgabe
	ldr r0, =strClockAlarm
	bl uart_putString
	// RTC starten
	mov r0, #1
	str r0, [r10]	
	b checkInput

putTime:
	// Start/Stop Indikator prüfen
	cmp r7, #1
	beq checkInput
	
	// Zeit ausgeben
	ldr r12, [r5]
	// Stunden ausgeben; falls im 24h Modus
	mov r1, #3600
	udiv r0, r12, r1
	mls r12, r0, r1, r12
	cmp r8, #1
	beq putMinutes
	bl putByteBase10
	mov r0, #COLON
	bl uart_putChar
putMinutes:	
	// Minuten
	mov r1, #60
	udiv r0, r12, r1
	mls r12, r0, r1, r12
	bl putByteBase10
	mov r0, #COLON
	bl uart_putChar	
	// Sekunden
	mov r0, r12
	bl putByteBase10
	
	ldr r0, =LINEFEED
	bl uart_putChar	
	b checkInput
	
/*
	Wrapper für uart_putByteBase10. Gibt führende 0 für Werte < 10(dec) aus.
	R0 -> Auszugebendes Byte
*/	
.thumb_func
putByteBase10:
	push {lr}
	mov r1, r0
	cmp r1, #10
	ite lo
	ldrlo r1, =uart_putByte
	ldrhs r1, =uart_putByteBase10
	blx r1
	pop {pc}	

// RTC Seconds ISR
.thumb_func
rtcSec:
	ldr r0, =secondEnd
	mov r1, #1
	strb r1, [r0]
	bx lr		

/*** Datenbereich (ab 0x20000000) ***/
.data
secondEnd: .byte 0x00
str24hMode: .asciz "24-Stunden Modus\n"
str1hMode: .asciz "1-Stunden Modus\n"
strClockReset: .asciz "Uhr zurueckgesetzt\n"
strClockDisplayOn: .asciz "Anzeige an\n"
strClockDisplayOff: .asciz "Anzeige aus\n"
strClockPreset: .asciz "Uhr vorgestellt\n"
strClockAlarm: .asciz "Endzeitpunkt erreicht\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*** System Integration ***/

__BBREG SIM_SCGC5_PORTA 0x40048038 9
__BBREG SIM_SCGC6_PIT 	0x4004803C 23
__BBREG SIM_SCGC6_RTC	0x4004803C 29

/*** Interrupt / NVIC ***/

// Vector Table Offset Register
.equ SCB_VTOR, 0xE000ED08
// Set Enable Register 2
.equ NVIC_ISER2, 0xE000E108
// Clear Pending Register 2
.equ NVIC_ICPR2, 0xE000E288
/*
	NVIC Clear & Enable Wert für Interrupts dieser Anwendung im NVIC_IxxR2 Register
	RTC	(Seconds Interrupt) IRQ=67 mod 32 = Bit 3
	PIT1 					IRQ=69 mod 32 = Bit 5
*/
.equ NVIC_IXXR2_VAL, 0x28
// Interrupt Vectors
.equ RTC_SEC_INTERRUPT_VECTOR, 0x0000014C 
.equ PIT1_INTERRUPT_VECTOR, 0x00000154

/*** PIT1 ***/

// PIT Zyklen bei 25MHZ Takt
.equ PIT_CYCLES_100MS, 0x002625A0
.equ PIT_CYCLES_200MS, 0x004C4B40
// Sonstige PIT Register
.equ PIT_MCR, 0x40037000
.equ PIT_LDVAL1, 0x40037110
.equ PIT_TCTRL1, 0x40037118
/*
	PIT1 Timer Control Konfiguration
	CHN	= 0 (Chain Mode | disabled)
	TIE	= 1 (Timer Interrupt Enable | enabled)
	TEN = 0 (Timer Enable | disabled)
*/
.equ PIT_TCTRL1_CONFIG, 0x00000002
// Timer Interrupt Flag - TIF
__BBREG PIT_TFLG1_TIF 0x4003711C 0
// Timer Enable - TEN
__BBREG PIT_TCTRL1_TEN 0x40037118 0

/*** Real Time Clock ***/

// Seconds
.equ RTC_TSR, 0x4003D000
// Prescaler
.equ RTC_TPR, 0x4003D004
// Alarm
.equ RTC_TAR, 0x4003D008
// Time Compensation
.equ RTC_TCR, 0x4003D00C
/*
	Control
	SCxP	= 0 (Oscillator Load Configure | standard)
	CLKO	= 1 (Clock Output | disabled)
	OSCE	= 1 (Oscillator Enable | enabled)
	UM		= 0	(Update Mode | disbaled)
	SUP		= 0 (Supervisor Access | non SV access disabled)
	WPE		= 0 (Wakeup Pin Enable | disabled)
	SWR		= 0 (Software Reset)
*/
.equ RTC_CR, 0x4003D010
.equ RTC_CR_CONFIG, 0x0300
// Status - Counter Enable
__BBREG RTC_SR_TCE 0x4003D014 4
// Lock
.equ RTC_LR, 0x4003D018
.equ RTC_LR_CONFIG, 0xFF
/*
 	Interrupt Enable
 	WPON	= 0 (Wakeup Pin On | off)
 	TSIE	= 1 (Time Seconds Interrupt Enable | enabled)
 	TAIE	= 0 (Time Alarm Interrupt Enable | disabled)
 	TOIE	= 0 (Time Overflow Interrupt Enable | disabled)
 	TIIE	= 0 (Time Invalid Interrupt Enable | disabled)
*/
.equ RTC_IER, 0x4003D01C
.equ RTC_IER_CONFIG, 0x10
/*
	Read / Write Access - Standard
*/
.equ RTC_WAR, 0x4003D800
.equ RTC_RAR, 0x4003D804

/*** PORT Modul A ***/

// Pin Control Register PCR
.equ PORTA_PCR6,	0x40049018
.equ PORTA_PCR10,	0x40049028 	// LED E4 - Blau
/*
	Standard GPIO Konfiguration
	ISF		= 0		(Interrupt Status Flag)
	IRQC	= 0 	(Interrupt Configuration)
	LK		= 0 	(Lock Register | unlocked)
	MUX		= 001 	(Pin Mux Control | GPIO)
	DSE		= 0		(Drive Strength Enable | low)
	ODE		= 0		(Open Drain Enable | disabled)
	PFE		= 0		(Passive Filter Enable | disabled)
	SRE		= 0		(Slew Rate Enable | fast)
	PE		= 0		(Pull Enable | disabled)
	PS		= 0		(Pull Select)
*/
.equ PCR_CONFIG, 0x00000100

/*** GPIO Modul ***/

// Port Data Output
.equ GPIOA_PDOR, 0x400FF000
// Port Data Direction
.equ GPIOA_PDDR, 0x400FF014
/*
 	 Port A I/O Konfiguration
 	 Output-Pins (1): 	PTA6, PTA10
 	 Input-Pins (0):	-
*/
.equ GPIOA_PDDR_CONFIG, 0x0440
// PIN Maske
.equ GPIO_MASK_PTA_6_10, 0x0440

/*** Zeichen ***/
.equ LINEFEED, 0x0A
.equ DOT, 0x2E
.equ COLON, 0x3A
.equ SPACE, 0x20
.equ N, 0x6E

/*
	DCF77 Signal - Übertragungsrahmen
	Bit		Wert	Bedeutung
	0 		0		Start einer neuen Minute
	1-14	0		Wetterinfos
	15		0		PTB Rufbit
	16		0		Anstehende Sommerzeit / Winterzeit Umstellung
	17-18	01		Sommerzeit
	19		0		Anstehende Schaltsekunde
	20		1		Begin Zeitinformation
	21-24	x		Minute Einer
	25-27	x		Minute Zehner
	28		x		Parität Minute (21-27)
	29-32	x		Stunde Einer
	33-34	x		Stunde Zehner
	35		x		Parität Stunde (29 -34)
	36-39	x		Monatstag Einer
	40-41	x		Monatstag Zehner
	42-44	x		Wochentag Einer
	45-48	x		Monat Einer
	49		x		Monat Zehner
	50-53	x		Jahr Einer
	54-57	x		Jahr Zehner
	58		x		Parität Datum (36-57)
	59		0		Kein Puls, Pegel bleibt stabil
	60-63	0		Füllbits - werden nicht ausgegeben
*/
// Konstanter Startteil des DCF77 Signals - Bits 0-20
.equ DCF77_STARTUP, 0x00120000

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
/*
		Registerverwendung Initialisierung
		R4 = #0
		R5 = #1
	*/
	bl uart_init
	mov r4, #0
	mov r5, #1
	
	/*** Interrupt / NVIC Initialisierung ***/
	// Interrupt-Vektor RTC Sekundenende
	ldr r0, =SCB_VTOR
	ldr r0, [r0]
	ldr r1, =rtcSec
	str r1, [r0, #RTC_SEC_INTERRUPT_VECTOR]
	// Interrupt-Vektor PIT1
	ldr r1, =pit1End
	str r1, [r0, #PIT1_INTERRUPT_VECTOR]
	// Wartende Interrupts im NVIC entfernen
	ldr r1, =NVIC_IXXR2_VAL
	ldr r0, =NVIC_ICPR2
	str r1, [r0]
	// Interrupts für RTC und PIT1 im NVIC erlauben
	ldr r0, =NVIC_ISER2
	str r1, [r0]	
	
	/*** PORTA Initialisierung ***/
	ldr r0, =SIM_SCGC5_PORTA
	str r5, [r0]
	// Pins konfigurieren
	mov r1, #PCR_CONFIG
	ldr r0, =PORTA_PCR6
	str r1, [r0]
	ldr r0, =PORTA_PCR10
	str r1, [r0]
	
	/*** GPIO Initialisierung ***/
	ldr r0, =GPIOA_PDDR
	ldr r1, =GPIOA_PDDR_CONFIG
	ldr r2, [r0]
	orr r1, r1, r2
	str r1, [r0]
	
	/*** PIT1 Timer Initialisierung	***/
	ldr r0, =SIM_SCGC6_PIT	
	str r5, [r0]
	// PIT Modul aktivieren
	// Setzt Flags FRZ (Freeze) und MDIS (Module Disable) auf 0
	ldr r0, =PIT_MCR
	str r4, [r0]	        
	// PIT1 konfigurieren; zunächst ohne Startwert
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_CONFIG
	str r1, [r0]	
	
	/*** RTC Initialisierung ***/
	ldr r0, =SIM_SCGC6_RTC
	str r5, [r0]	
	// Zähler deaktivieren
	ldr r0, =RTC_SR_TCE
	str r4, [r0]
	// Startwert initialisieren
	ldr r0, =RTC_TSR
	str r4, [r0]
	// Prescaler initialisieren
	ldr r0, =RTC_TPR
	str r4, [r0]
	// Alarm Wert festlegen; Akarm deaktivieren
	ldr r0, =RTC_TAR
	str r4, [r0]
	// Time Compensation / Zählerkorrektur deaktivieren
	ldr r0, =RTC_TCR
	str r4, [r0]
	// Kontrollregister schreiben / Oszillator aktivieren
	ldr r0, =RTC_CR
	ldr r1, =RTC_CR_CONFIG
	str r1, [r0]
	// Register-Sperr-, Lese- und Schreibzugriff
	ldr r0, =RTC_LR
	mov r1, #RTC_LR_CONFIG
	str r1, [r0]
	ldr r0, =RTC_WAR
	str r1, [r0]	
	ldr r0, =RTC_RAR
	str r1, [r0]
	// Interrupts konfigurieren
	ldr r0, = RTC_IER
	mov r1, #RTC_IER_CONFIG
	str r1, [r0]
	// Zähler aktivieren
	ldr r0, =RTC_SR_TCE
	str r5, [r0]	

	/*
		Registerverwendung Anwendung
		R4-R7	= Flexibel; siehe Abschnittbeschreibung
		R8	= Adresse PIT_LDVAL1
		R9	= Adresse PIT_TCTRL1_TEN
		R10	= Adresse GPIOA_PDOR
		R11	= Adresse pitEnd
		R12 = Adresse secondEnd
		
		Die Anwendung fragt zunächst Datum + Zeit vom Terminal ab. Ohne weitere Nutzereingaben wird nach Ablauf
		der einminütigen Übertragung unmittelbar mit der Übertragung der nächsten Minute begonnen.
		Während der Übertragung kann durch Eingabe "n" am Terminal eine neue Datum + Zeit Eingabe angefordert werden. Die
		laufende Übertragung wird jedoch nicht unterbrochen. Die Abfrage geschieht erst nach Ablauf der Übertragung.
		
		Die Übertragung beginnt mit der (lesbaren) Ausgabe des Datums und der Uhrzeit am Terminal. Anschließend wird der DCF77 
		Rahmen konstruiert und in drei Formen ausgegeben:
		- Hexadezimal am Terminal, MSb zuerst, mit Füllbits (0) gefüllt auf 64 Bit
		- Bitweise am Terminal, LSb zuerst (Signalübertragungsreihenfolge), 60 Bit
		- Bitweise an PTA6 und PTA10, siehe Abschnitt
		
		Am Terminal wird das Bit 59 des DCF77 Rahmens als 0 ausgegeben, auch wenn das echte Signal hier keinen Amplituden bzw.
		Phasen Impuls vorsieht. Bei der Ausgabe über die GPIO Pins wird dies berücksichtigt (Pegel bleibt stabil).
		
		Die Anwendung gibt das eingegebene Datum + Uhrzeit aus, nicht die Folgeminute.
	*/
	ldr r8, =PIT_LDVAL1
	ldr r9, =PIT_TCTRL1_TEN
	ldr r10, =GPIOA_PDOR 
	ldr r11, =pitEnd
	ldr r12, =secondEnd	
	
	/*
		Datum und Uhrzeit vom Terminal einlesen
		R4 = dateTime Zeiger
	*/
inputDateTime:
	ldr r4, =dateTime
	// Eingabeaufforderung für neue Uhrzeit
	ldr r0, =strInputHour
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #1]
	bl putByteBase10
	ldr r0, =strInputMinute
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4]
	bl putByteBase10
	// Eingabeaufforderung für neues Datum
	ldr r0, =strInputDay
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #3]
	bl putByteBase10
	ldr r0, =strInputMonth
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #4]
	bl putByteBase10
	ldr r0, =strInputYear
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r4, #5]
	bl putByteBase10
	mov r0, #LINEFEED
	bl uart_putChar
	// Wochentag = Montag (uff)
	mov r0, #1
	strb r0, [r4, #2]
	b putDateTime
	
incrementMinute:	
	/*
		Minute inkrementieren und Datum + Zeit neu berechnen
		R4 = dateTime Zeiger
	*/
	ldr r4, =dateTime
	/*
		Minute & Stunde
		R0 = Minute
		R1 = Stunde
	*/
	ldrb r0, [r4]
	ldrb r1, [r4, #1]
	add r0, r0, #1
	cmp r0, #60
	itt eq
	moveq r0, #0
	addeq r1, r1, #1
	strb r0, [r4]
	/*
		Stunde & Tage
		R0 = Stunde
		R1 = Wochentag
		R2 = Monatstag
	*/
	mov r0, r1
	ldrb r1, [r4, #2]
	ldrb r2, [r4, #3]
	cmp r0, #24
	ittt eq
	moveq r0, #0
	addeq r1, r1, #1
	addeq r2, r2, #1
	strb r0, [r4, #1]
	// Wochentag
	cmp r1, #8
	it eq
	moveq r1, #1
	strb r1, [r4, #2]
	/*
		Monatstag & Monat
		R2 = Monatstag
		R0 = Monat
	*/
	ldrb r0, [r4, #4]
	cmp r2, #31
	itt eq
	moveq r2, #1
	addeq r0, r0, #1
	strb r2, [r4, #3]
	/*
		Monat & Jahr
		R0 = Monat
		R1 = Jahr
	*/
	ldrb r1, [r4, #5]
	cmp r0, #13
	itt eq
	moveq r0, #1
	addeq r1, r1, #1
	strb r0, [r4, #4]
	/*
		Jahr
		R1 = Jahr
	*/
	cmp r1, #99
	it hi
	movhi r1, #0
	strb r1, [r4, #5]

putDateTime:	
	/*
		Uhrzeit + Datum ausgeben
		R4 = dateTime Zeiger
	*/
	ldr r4, =dateTime
	// Wochentag - Wochentag-Index (Mo = 1) lesen und String-Array-Index berechnen
	ldrb r0, [r4, #2]
	ldr r1, =dayOfWeek
	mov r2, #3
	mla r0, r0, r2, r1
	sub r0, r0, #3
	bl uart_putString
	ldr r0, =strDOWSeparator
	bl uart_putString
	// Monatstag	
	ldrb r0, [R4, #3]
	bl putByteBase10
	mov r0, #DOT
	bl uart_putChar
	// Monat
	ldrb r0, [R4, #4]
	bl putByteBase10
	mov r0, #DOT
	bl uart_putChar	
	// Jahr
	ldrb r0, [R4, #5]
	bl putByteBase10
	mov r0, #SPACE
	bl uart_putChar		
	// Uhrzeit - Stunden
	ldrb r0, [R4, #1]
	bl putByteBase10
	mov r0, #COLON
	bl uart_putChar
	// Minuten
	ldrb r0, [R4]
	bl putByteBase10	
	ldr r0, =strClock
	bl uart_putString
	
	/*
		Erzeugen des DCF77 Signalrahmens der aktuellen Minute
		Zunächst werden der Minutenblock, Stundenblock und Datumsblock inkl. Paritätsbit in separaten Registern 
		konstruiert und anschließend der Signalrahmen zusammengesetzt und in R5 und R6 abgelegt.
		
		R4 = dateTime
		R5 = Minutenblock
		R6 = Stundenblock
		R7 = Datumsblock
	*/
	ldr r4, =dateTime
	// Minutenblock
	ldrb r0, [r4]
	bl toBCD
	mov r5, r0
	bl isEvenParity
	cmp r0, #0
	it ne
	// Paritätsbit an Position 7 setzen
	orrne r5, r5, #0x80
	
	// Stundenblock
	ldrb r0, [r4, #1]
	bl toBCD
	mov r6, r0
	bl isEvenParity
	cmp r0, #0
	it ne
	// Paritätsbit an Position 6 setzen
	orrne r6, r6, #0x40	
	
	// Datumsblock
	// Monatstag
	ldrb r0, [r4, #3]
	bl toBCD
	mov r7, r0
	// Wochentag
	ldrb r0, [r4, #2]
	orr r7, r7, r0, lsl #6
	// Monat
	ldrb r0, [r4, #4]
	bl toBCD
	orr r7, r7, r0, lsl #9
	// Jahr
	ldrb r0, [r4, #5]
	bl toBCD
	orr r7, r7, r0, lsl #14
	// Parität bestimmen und Paritätsbit setzen
	mov r0, r7
	bl isEvenParity
	cmp r0, #0
	it ne
	// Paritätsbit an Position 22 setzen
	orrne r7, r7, #0x400000
	
	/*
		Übertragungsrahmen zusammensetzen
		R5 = DCF77 Rahmen Bits 0-31
		R6 = DCF77 Rahmen Bits 32-59 + Füllbits
	*/ 
	// Bits 31-0
	ldr r0, =DCF77_STARTUP
	orr r0, r0, r5, lsl #21
	orr r0, r0, r6, lsl #29
	mov r5, r0
	// Bits 59-32
	mov r0, r6, lsr #3
	orr r0, r0, r7, lsl #4
	mov r6, r0
	
	/*
		DCF77 Rahmen am Terminal ausgeben - Hexadezimal MSb zuerst
	*/
	ldr r0, =strDCF77Frame
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	mov r0, #SPACE
	bl uart_putChar	
	mov r0, r5
	bl uart_putInt32
	mov r0, #LINEFEED
	bl uart_putChar
	
	/*
		DCF77 Rahmen am Terminal ausgeben - Bitweise LSb zuerst
		R4 = Aktuell ausgegebener DCF77 Rahmen-Teil
		R7 = Bitzähler
	*/
	mov r4, r5
	mov r7, #59
putDCF177BitTerminal:
	and r0, r4, #1
	bl uart_putByteBase10
	lsr r4, r4, #1
	cmp r7, #28
	it eq
	moveq r4, r6
	subs r7, r7, #1
	bpl putDCF177BitTerminal
	
	/*
		DCF77 Rahmen an PTA6 und PTA10 übertragen.
		Der Abschnitt "Übertragungsverfahren" des DCF77 Wikipedia-Artikels beschreibt die Amplituden- und Phasenmodulation
		des Signals. Für die Ausgabe per GPIO Pin habe ich folgendes festgelegt:
		- Der Ruhezustand von PTA6 und PTA10 ist logisch 0
		- Für die Dauer der 100ms / 200ms Impulse werden beide Ausgänge auf logisch 1 geschaltet
		Während der Impulse ist die blaue LED damit inaktiv (PTA10 logisch 1).
		
		R2	= #0
		R3	= #1
		R4	= Aktuell ausgegebener DCF77 Rahmen-Teil
		R5, R6	= DCF77 Rahmen
		R7	= Bit-Zähler
	*/
	// Terminalausgabe Übertragungsstart
	ldr r0, =strTransferStart
	bl uart_putString
	mov r2, #0
	mov r3, #1
	mov r4, r5
	mov r7, #0
	// GPIO Ausgänge deaktivieren
	ldr r0, [r10]
	bic r0, r0, #GPIO_MASK_PTA_6_10
	str r0, [r10]
	// Sekundenende-Flag zurücksetzen
	strb r2, [r12]
putDCF177Bit:
	// Zu zweitem Rahmen-Teil wechseln
	cmp r7, #32
	it eq
	moveq r4, r6
	// PIT1 im Abhängigkeit des Bit Wertes laden
	ands r0, r4, #1
	ite eq
	ldreq r1, =PIT_CYCLES_100MS
	ldrne r1, =PIT_CYCLES_200MS
	str r1, [r8]
	// Ablauf einer Sekunde abwarten
awaitSecondEnd:	
	ldrb r0, [r12]
	cmp r0, #0
	beq awaitSecondEnd
	// Indikator rücksetzen
	strb r2, [r12]
	// PIT1 aktivieren und GPIO Signale für Laufzeit aktivieren
	str r3, [r9]
	ldr r0, [r10]
	orr r0, r0, #GPIO_MASK_PTA_6_10
	str r0, [r10]
awaitPitEnd:
	ldrb r0, [r11]
	cmp r0, #0
	beq awaitPitEnd
	// PIT1 stoppen
	str r2, [r9]
	strb r2, [r11]
	// GPIO Signal deaktivieren
	ldr r0, [r10]
	bic r0, r0, #GPIO_MASK_PTA_6_10
	str r0, [r10]
	// Abbruchbedingung prüfen
	cmp r7, #57
	ittt ls // less or same
	lsrls r4, r4, #1
	addls r7, r7, #1
	bls putDCF177Bit
	// 59. Bit - GPIO Ausgang eine weitere Sekunde inaktiv halten
awaitLastBitSecondEnd:
	ldrb r0, [r12]
	cmp r0, #0
	beq awaitLastBitSecondEnd
	// Indikator rücksetzen
	strb r2, [r12]	
	
	// Terminalausgabe Übertragungsende
	ldr r0, =strTransferEnd
	bl uart_putString	
	
	// Terminaleingabe prüfen und ggf. neues Datum + Zeit erfassen
	bl uart_charPresent
	cmp r0, #0
	beq incrementMinute
	bl uart_getChar
	cmp r0, #N
	beq inputDateTime
	b incrementMinute
	
/*
	Konvertiert eine vorzeichenlose Ganzzahl in BCD Darstellung
	Bereich 0 - 99 (dec)
	R0 -> Zu konvertierende Zahl
	R0 <- Ergebnis in BCD Form 0x000000[Zehner 4 Bit][Einer 4 Bit]
*/
.thumb_func
toBCD:
	mov r2, #10
	udiv r1, r0, r2
	mls r0, r1, r2, r0 
	orr r0, r0, r1, lsl #4
	bx lr
	
/*
	Summiert 1-Bits in R0 und gibt das LSb der Summe zurück.
	R0 -> Zu prüfender 32-Bit Wert
	R0 <- 1=Ungerade Parität; 0=Gerade Parität
*/	
.thumb_func
isEvenParity:
	mov r3, #31 // Schleifenzähler
	mov r2, #0 // Anzahl 1 Bits
isEvenParityNextBit:
	and r1, r0, #1
	cmp r1, #1
	it eq
	addeq r2, r2, #1
	lsr r0, r0, #1
	subs r3, r3, #1
	bpl isEvenParityNextBit
	and r0, r2, #1
	bx lr
	
/*
	Wrapper für uart_putByteBase10. Gibt führende 0 für Werte < 10(dec) aus.
	R0 -> Auszugebendes Byte
*/	
.thumb_func
putByteBase10:
	push {lr}
	mov r1, r0
	cmp r1, #10
	ite lo
	ldrlo r1, =uart_putByte
	ldrhs r1, =uart_putByteBase10
	blx r1
	pop {pc}	
	
// RTC Seconds ISR
.thumb_func
rtcSec:
	ldr r0, =secondEnd
	mov r1, #1
	strb r1, [r0]
	bx lr		
	
// PIT1 ISR
.thumb_func
pit1End:
	// PIT1 Interrupt Flag rücksetzen
	mov r1, #0x01
	ldr r0, =PIT_TFLG1_TIF
	str r1, [r0]
	// PIT1-Ende-Flag setzen
	ldr r0, =pitEnd
	strb r1, [r0]
	bx lr		

/*** Datenbereich (ab 0x20000000) ***/
.data
secondEnd: .byte 0x00
pitEnd: .byte 0x00
/*
	Datum und Uhrzeit
	0 [Minuten]
	1 [Stunden]
	2 [Wochentage]
	3 [Monatstage]
	4 [Monate]
	5 [Jahre]
*/
dateTime: .byte 0x00, 0x00, 0x00, 0x00, 0x00, 0x00
// Wochentage Lookup-Array
dayOfWeek: .asciz "Mo", "Di", "Mi", "Do", "Fr", "Sa", "So"
// Terminalausgaben
strDOWSeparator: .asciz "., "
strClock: .asciz " Uhr\n"
strDCF77Frame: .asciz "DCF77 Frame: "
strTransferStart: .asciz "\nUebertrage Daten\n"
strTransferEnd: .asciz "Uebertragung abgeschlossen\n"
strInputHour: .asciz "Stunde eingeben (hh): "
strInputMinute: .asciz "\nMinuten eingeben (mm): "
strInputDay: .asciz "\nTag eingeben (dd): "
strInputMonth: .asciz "\nMonat eingeben (mm): "
strInputYear: .asciz "\nJahr eingeben (jj): "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*** System Integration ***/

__BBREG SIM_SCGC5_PORTA 0x40048038 9
__BBREG SIM_SCGC6_FTM0 0x4004803C 24

/*** Interrupt / NVIC ***/

// Vector Table Offset Register
.equ SCB_VTOR, 0xE000ED08
// Set Enable Register 1
.equ NVIC_ISER1, 0xE000E104
// Clear Pending Register 1
.equ NVIC_ICPR1, 0xE000E284
/*
	NVIC Clear & Enable Wert für Interrupts dieser Anwendung im NVIC_IxxR1 Register
	FTM0 (alle Quellen)	IRQ = 62
*/
.equ NVIC_IXXR1_VAL, 0x40000000
// Interrupt Vectors
.equ FTM0_INTERRUPT_VECTOR, 0x00000138 

/*** PORT Modul A ***/

// Pin Control Register PCR
/*
	FTM_CH3 Konfiguration 
	ISF		= 0		(Interrupt Status Flag)
	IRQC	= 0 	(Interrupt Configuration)
	LK		= 0 	(Lock Register | unlocked)
	MUX		= 011 	(Pin Mux Control | FTM0_CH3)
	DSE		= 0		(Drive Strength Enable | low)
	ODE		= 0		(Open Drain Enable | disabled)
	PFE		= 0		(Passive Filter Enable | disabled)
	SRE		= 0		(Slew Rate Enable | fast)
	PE		= 0		(Pull Enable | disabled)
	PS		= 0		(Pull Select)
*/
.equ PCR_FTM0_CH3_CONFIG, 0x00000300
.equ PORTA_PCR6,	0x40049018

/*** FTM0 Modul ***/

// Status And Control
.equ FTM0_SC, 0x40038000
__BBREG FTM0_SC_TOF 0x40038000 7
/*
	Initialisierung
	TOF		= 0 (Timer Overflow Flag)
	TOIE	= 1	(Timer Overflow Interrupt Enable | enabled)
	CPWMS	= 0	(Center Aligned PWM Select | Edge Alignment - Up Counting Mode)
	CLKS	= 00 (Clock Source | clock disabled)
	PS		= 000 (Prescale Factor | Div by 1)
*/
.equ FTM0_SC_CONFIG_INIT, 0x40
/*
	Aktiver Zähler
	CLKS	= 01 (Clock Source | System Clock)
*/
.equ FTM0_SC_CONFIG_RUN, 0x48
// Counter
.equ FTM0_CNT, 0x40038004
// Modulo
.equ FTM0_MOD, 0x40038008
// Grenzwert für 1ms PWM Periode bei 25MHz Takt
.equ FTM0_MOD_1MS, 25000
// Channel 3 Status And Control
.equ FTM0_C3SC, 0x40038024
__BBREG FTM0_C3SC_CHF 0x40038024 7
/*
	CHF		= 0 (Channel Flag)
	CHIE	= 1 (Channel Interrupt Enable | enabled)
	MSB		= 1 (Channel Mode | Edge-Aligned PWM)
	MSA		= 0 "
	ELSB	= 1 (Edge or Level Select | High-True Pulses)
	ELSA	= 0 "
	DMA		= 0 (DMA Enable | disabled)
*/
.equ FTM0_C3SC_CONFIG_POL_POS, 0x68
/*
	ELSB	= 0 (Edge or Level Select | Low-True Pulses)
	ELSA	= 1 "
*/
.equ FTM0_C3SC_CONFIG_POL_NEG, 0x64
// Channel 3 Value
.equ FTM0_C3V, 0x40038028
// Channel 3 Wert für einen Duty-Cycle von 10%
.equ FTM0_C3V_PWM_10P, 2500
// Channel 3 Wert für einen Duty-Cycle von 5%
.equ FTM0_C3V_PWM_5P, 1250
// Counter Initial Vlaue
.equ FTM0_CNTIN, 0x4003804C
// Features Mode Selection - Features Enabled
__BBREG FTM0_MODE_FTMEN 0x40038054 0

/*** Zeichen ***/
.equ GREATER_THAN, 0x3E
.equ PLUS, 0x2B
.equ MINUS, 0x2D
.equ ZERO, 0x30
.equ NINE, 0x39
.equ LINEFEED, 0x0A

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	/*
		Registerverwendung Initialisierung
		R4 = #0
		R5 = #1
		
		Die Zusatzfeatures des FTM0 sind nicht aktiv. Auf Register des Registersets 2 (vgl. Dokumentation Kap. 40.3.1)
		wird mit Ausnahme von FTM0_CNTIN nicht zugegriffen. Zudem werden diese Register nicht durch die Anwendung initialisiert.
	*/
	bl uart_init
	mov r4, #0
	mov r5, #1
	
	/*** Interrupt / NVIC Initialisierung ***/
	// Interrupt-Vektor FTM0
	ldr r0, =SCB_VTOR
	ldr r0, [r0]
	ldr r1, =ftm0ISR
	str r1, [r0, #FTM0_INTERRUPT_VECTOR]
	// Wartende Interrupts im NVIC entfernen
	ldr r1, =NVIC_IXXR1_VAL
	ldr r0, =NVIC_ICPR1
	str r1, [r0]
	// Interrupts für FTM0 im NVIC erlauben
	ldr r0, =NVIC_ISER1
	str r1, [r0]		
	
	/*** PORTA Initialisierung ***/
	ldr r0, =SIM_SCGC5_PORTA
	str r5, [r0]
	// Pins konfigurieren
	mov r1, #PCR_FTM0_CH3_CONFIG
	ldr r0, =PORTA_PCR6
	str r1, [r0]

	/*** FTM0 Initialisierung ***/
	ldr r0, =SIM_SCGC6_FTM0
	str r5, [r0]
	// Grundkonfiguration mit deaktiviertem Zähler
	ldr r0, =FTM0_SC
	mov r1, #FTM0_SC_CONFIG_INIT
	str r1, [r0]
	// Zählerstartwert festlegen
	ldr r0, =FTM0_CNTIN
	str r4, [r0]
	// Zähler auf Startwert setzen
	ldr r0, =FTM0_CNT
	str r4, [r0]
	// Zählerobergrenze bestimmen
	ldr r0, =FTM0_MOD
	ldr r1, =FTM0_MOD_1MS
	str r1, [r0]
	// Channel 3 konfigurieren - positive Pulse
	ldr r0, =FTM0_C3SC
	mov r1, #FTM0_C3SC_CONFIG_POL_POS
	str r1, [r0]
	// Pulsdauer von 5% vorkonfigurieren
	ldr r0, =FTM0_C3V
	ldr r1, =FTM0_C3V_PWM_5P
	str r1, [r0]
	// FTM0 Zusatzfeatures deaktivieren
	ldr r0, =FTM0_MODE_FTMEN
	str r4, [r0]
	
	/*
		Registerverwendung Anwendung
		R4 = #0
		R5 = #1
		R6	= Ablage eingegebener Zeichen
		R7	= ftm0Channel
		R8	= ftm0Overflow
		R9	= FTM0_C3V
		R10	= FTM0_C3SC
		R11	= FTM0_CNT
		R12	= FTM0_SC
		
		Einmal gestartet, wird der Zähler des FTM0 nicht wieder angehalten. Die Änderung der Konfiguration
		(PWM Duty Cycle Länge, Polarität) erfolgt zur Laufzeit. Die Ausgabe des PWM Signals an PTA6 (FTM0_CH3)
		wird fortgesetzt während die Anwendung auf Terminaleingaben wartet.
	*/
	ldr r7, =ftm0Channel
	ldr r8, =ftm0Overflow
	ldr r9, =FTM0_C3V
	ldr r10, =FTM0_C3SC
	ldr r11, =FTM0_CNT
	ldr r12, =FTM0_SC
	
	// Zähler starten
	mov r0, #FTM0_SC_CONFIG_RUN
	str r0, [r12]
	
terminalInput:
	mov r0, #LINEFEED
	bl uart_putChar
	mov r0, #GREATER_THAN
	bl uart_putChar
awaitInput:
	bl uart_charPresent
	cmp r0, #0
	beq awaitInput
	
	bl uart_getChar
	mov r6, r0
	bl uart_putChar
	// Polaritätswechsel
	cmp r6, #PLUS
	itt eq
	moveq r0, #FTM0_C3SC_CONFIG_POL_POS
	beq updatePolarity
	cmp r6, #MINUS
	itt eq
	moveq r0, #FTM0_C3SC_CONFIG_POL_NEG
	beq updatePolarity
	// Anpassung der Impulslänge
	cmp r6, #ZERO
	blt terminalInput
	cmp r6, #NINE
	bhi terminalInput
	sub r6, r6, #0x30
	b updateDutyCycle
	
updatePolarity:
	// FTM0 Overflow abwarten
	ldr r1, [r8]
	cmp r1, #0
	beq updatePolarity
	// Channel 3 Konfiguration aktualisieren
	str r0, [r10]
	// Overflow Indikator zurücksetzen
	strb r4, [r8]
	b terminalInput

updateDutyCycle:	
	// FTM0 Channel 3 IR abwarten
	ldr r1, [r7]
	cmp r1, #0
	beq updateDutyCycle
	// Channel 3 Zählerwert berechnen
	ldr r1, =FTM0_C3V_PWM_10P
	ldr r2, =FTM0_C3V_PWM_5P
	// Eingegebener Faktor * 10% + 5%
	mla r0, r6, r1, r2
	str r0, [r9]
	// Channel 3 IR Indikator zurücksetzen
	strb r4, [r7]
	b terminalInput
	
// FTM0 ISR
.thumb_func
ftm0ISR:
	mov r1, #0
	// Channel 3 IR prüfen
	ldr r3, =FTM0_C3SC_CHF
	ldr r2, =ftm0Channel
	ldr r0, [r3]
	cmp r0, #1
	itt eq
	streq r1, [r3]
	strbeq r0, [r2]
	// Counter Overflow prüfen
	ldr r3, =FTM0_SC_TOF
	ldr r2, =ftm0Overflow
	ldr r0, [r3]
	cmp r0, #1
	itt eq
	streq r1, [r3]
	strbeq r0, [r2]	
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
ftm0Channel: .byte 0x00
ftm0Overflow: .byte 0x00
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ COUNTER, 0x10	// Anzahl der Schleifendurchläufe

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	bl uart_init
	bl pit3_init // pit zaehlt rueckwaerts
	
// Neustart des Programms
loop_programm:
	// Einlesen von 16 Bytes
	ldr r0, =str_eingabe	// Zeiger auf String laden
	bl uart_putString	// String ausgeben
	mov r4, #COUNTER	// Zaehler laden
	ldr r5, =bytearray	// Adresse laden
	
	// Eingabeschleife
loop_eingabe:
	ldr r0, =str_prompt	// Zeiger auf String laden
	bl uart_putString	// String ausgeben
	bl uart_getByte		// ein Byte einlesen
	strb r0, [r5], #1	// im Array ablegen und Adresse in R5 um eins erhoehen
	bl uart_putByte		// das Byte ausgeben
	subs r4, r4, #1		// Zaehler dekrementieren
	bne loop_eingabe	// solange Zaehler noch nicht null
	
	// Maximumbestimmung
	ldr r0, =str_startsuche	// Zeiger auf String laden
	bl uart_putString	// String ausgeben
	mov r9, #0		// Maximum mit null initialisieren
	mov r4, #COUNTER
	
	bl pit3_getval
	mov r6, r0			// timer wert in r6 schieben
	bl pit3_getval
	subs r7, r6, r0		// Taktzyklen Leermessung + mov in r7
	
	bl pit3_getval
	mov r6, r0			// timer wert in r6 schieben
	
loop_maximum:
	ldrb r0, [r5, #-1]!	// Byte aus dem Array holen, vorher Adresse in R5 dekrementieren
	cmp r0, r9		// mit bisherigem Maximum vergleichen
	it hi			// wenn es groesser ist (unsigned)
	movhi r9, r0		// wird das bisherige Maximum ueberschrieben
	// Aufgabe e:
	// Die Ausfuehrungszeit ist unabhaengig von der Reihenfolge, was dafuer spricht, dass
	// die benoetigten Taktzyklen des it Blocks nicht davon abhaengen, ob die Bedingung
	// erfuellt ist oder nicht.  
	
	
	subs r4, r4, #1		// Zaehler dekrementieren
	bne loop_maximum	// solange Zaehler noch nicht null
	
	bl pit3_getval
	subs r6, r6, r0		// Differenz Taktzyklen in r
	
	// Maximum speichern
	ldr r0, =maximum	// Adresse des Speichers fuer Maximum laden
	strb r9, [r0]		// das Maximum im Speicher ablegen
	
	// Ausgabe des Ergebnisses
	ldr r0, =str_endsuche	// Zeiger auf String laden
	bl uart_putString	// String ausgeben
	mov r0, r9		// Maximum nach R0 kopieren
	bl uart_putByte		// Maximum ausgeben
	ldr r0, =str_zeitmessung	// Zeiger auf String laden
	bl uart_putString	// String ausgeben
	mov r0, r6		// Differenz Takzyklen in r0 kopieren und Offset abziehen
	subs r0, r0, r7
	bl uart_putInt16
	
	// Rueckspringen zum Beginn
	mov r1, #0		// Maximum zuruecksetzen
	ldr r0, =maximum	// Adresse des Speichers fuer Maximum laden
	strb r1, [r0]		// Maximum zuruecksetzen
	
	// newlines für neustart
	mov r0, 0x0a
	bl uart_putChar
	mov r0, 0x0a
	bl uart_putChar
	
	b loop_programm		// Erneute Programmausfuehrung

/*** Datenbereich (ab 0x20000000) ***/
bytearray:
	.rept COUNTER
	.byte 0x00
	.endr
maximum: .byte 0x0
str_prompt: .asciz "\n>0x"
str_eingabe: .asciz "Bitte 16 Bytes sukzessiv eingeben!\n"
str_startsuche: .asciz "\nDurchsuchen gestartet\n"
str_endsuche: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_zeitmessung: .asciz "\nBenoetigte Zeit Maximumsuche: 0x"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
// Neustart des Programms
loop_programm:
	// Abfragen des Bit 0 und speichern in r5
	ldr r0, =str_eingabe_bit0
	bl uart_putString
	bl uart_getByte
	and r0, r0, #0x1f // nur erste 5 bits verwenden
	mov r5, r0
	bl uart_putByte
	// Abfragen des Bit 1 und speichern in r6
	ldr r0, =str_eingabe_bit1
	bl uart_putString
	bl uart_getByte
	and r0, r0, #0x1f // nur erste 5 bits verwenden
	mov r6, r0
	bl uart_putByte
	
	// setze r8 fuer verunden
	mov r0, #1
	lsl r8, r0, r5 // schiebe 1 um r5 bits
	mvn r8, r8
	
	// setze r9 fuer verodern
	lsl r9, r0, r6 // schiebe 1 um r6 bits
	
	// aufgabe b
	// gebe speicherinhalt aus
	ldr r0, =str_ausgabe_vorher
	bl uart_putString
	ldr r0, =word_b
	ldr r0, [r0]
	bl uart_putInt32
	
	ldr r0, =word_b // lese adresse von word_b
	ldr r7, [r0] // lese word_b in r7
	
	and r7, r7, r8 // zuruecksetzen des bit 0
	orr r7, r7, r9 // setzen des bit 1
	str r7, [r0] // zurueckschreiben in speicher
	
	// gebe speicherinhalt aus
	ldr r0, =str_ausgabe_nachher
	bl uart_putString
	ldr r0, =word_b
	ldr r0, [r0]
	bl uart_putInt32
	
	// aufgabe c
	// gebe speicherinhalt aus
	ldr r0, =str_ausgabe_vorher_bb
	bl uart_putString
	ldr r0, =word_c
	ldr r0, [r0]
	bl uart_putInt32
	
	// Basisadresse bit banding 0x20000010
	// 0x22000000 + (0x20000010 - 0x20000000) * 32 + bit * 4 = 0x22000200 + bit << 2
	mov r7, #0x0200
	movt r7, #0x2200
	lsl r5, #2
	add r8, r5, r7 // r8 ist adresse fuer zuruecksetzen
	lsl r6, #2
	add r9, r6, r7 // r9 ist adresse fuer setzen   
	
	mov r0, #0
	str r0, [r8]
	mov r0, #1
	str r0, [r9]
	
	// gebe speicherinhalt aus
	ldr r0, =str_ausgabe_nachher_bb
	bl uart_putString
	ldr r0, =word_c
	ldr r0, [r0]
	bl uart_putInt32
	
	b loop_programm
	

/*** Datenbereich (ab 0x20000000) ***/
.data
word_b: .word 0x00 // word aufgabe b
dummy: .word 0x00, 0x00, 0x00 // dummy damit naechstes word an 0x20000010 steht
word_c: .word 0x00 // word aufgabe c
str_eingabe_bit0: .asciz "\nNummer des 0-Bits: 0x"
str_eingabe_bit1: .asciz "\nNummer des 1-Bits: 0x"
str_ausgabe_vorher: .asciz "\nWert von 0x2000_0000 vor Operationen: 0x"
str_ausgabe_nachher: .asciz "\nWert von 0x2000_0000 nach Operationen: 0x"
str_ausgabe_vorher_bb: .asciz "\nWert von 0x2000_0010 vor Operationen: 0x"
str_ausgabe_nachher_bb: .asciz "\nWert von 0x2000_0010 nach Operationen: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	// r5: v1, r6: v2, r7: min, r8: max, r9: zeitoffset, r10: startzeit, dauer
	bl uart_init
	bl pit3_init // pit zaehlt rueckwaerts
    // Zeitoffset bestimmen
	bl pit3_getval
	mov r10, r0
	bl pit3_getval
	subs r9, r10, r0
	
	// Neustart des Programms
loop_programm:
	bl read2vecs
	
	// ohne dsp
	ldr r0, =str_ohneDSP
	bl uart_putString
	
	// hole v1 und v2 aus speicher und resete min und max
	ldr r5, =w_v1
	ldr r5, [r5]
	ldr r6, =w_v2
	ldr r6, [r6]
	mov r7, #0
	movt r7, #0
	mov r8, #0
	movt r8, #0
	
	// zeitmessung starten
	bl pit3_getval
	mov r10, r0
	
	mov r0, 0xff000000 // r0 ist maske und wird in schleife veraendert
loop_mask:
	// v1 und v2 byteweise maskieren und vergleichen 
	and r1, r5, r0
	and r2, r6, r0
	cmp r1, r2
	
	// wenn r1 aus r5 groesser, dann setze byte in r8 und kleineres byte in r7, sonst umgekehrt 
	ittee gt
	addgt r8, r8, r1
	addgt r7, r7, r2
	addle r8, r8, r2
	addle r7, r7, r1
	
	// schiebe maske zu naechstem byte
	lsrs r0, r0, #8 // shift mask
	
	// wenn maske gleich 0 sind wir durch
	bne loop_mask
	
	// zeitmessung stoppen
	bl pit3_getval
	subs r10, r10, r0
	subs r10, r10, r9 // leermessung abziehen
	
	// min und max ausgeben
	ldr r0, =str_min
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_max
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_tOhneDSP
	bl uart_putString
	mov r0, r10
	bl uart_putInt16
	
	// mit dsp
	ldr r0, =str_mitDSP
	bl uart_putString
	// reset min und max
	mov r7, #0
	movt r7, #0
	mov r8, #0
	movt r8, #0
	
	// zeitmessung starten
	bl pit3_getval
	mov r10, r0
	usub8 r0, r5, r6 // byteweises minus mit setzen von aspr
	sel r8, r5, r6
	sel r7, r6, r5
	// zeitmessung stoppen
	bl pit3_getval
	subs r10, r10, r0
	subs r10, r10, r9 // leermessung abziehen
	
	// Aufgabenteil d)
	// Wahrscheinlich kann man min und max noch effektiver berechnen wie oben mit mein Schleife. 
	// Jedoch wird man nicht an 3 Befehle rankommen. Die Schleife dauert fast 15 mal so lange. 
	
	// min und max ausgeben
	ldr r0, =str_min
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	ldr r0, =str_max
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_tMitDSP
	bl uart_putString
	mov r0, r10
	bl uart_putInt16
	
	b loop_programm
	
	
.thumb_func
read2vecs:
	// r5: temp fuer einlesen
	// r6: speicheradresse v1/v2
	push {r5, r6, lr}
	// nach v1 fragen
	ldr r6, =w_v1
	ldr r0, =str_v1
	bl uart_putString
	
read4bytes:
	// 4 byte einlesen, entsprechende schieben und r5 zusammenbauen
	bl uart_getByte
	lsl r0, #24 // msb
	mov r5, r0
	bl uart_getByte
	lsl r0, #16
	add r5, r5, r0
	bl uart_getByte
	lsl r0, #8
	add r5, r5, r0
	bl uart_getByte
	add r5, r5, r0 // lsb
	
	// r5 an adresse in r6 speichern und ausgeben
	str r5, [r6]
	mov r0, r5
	bl uart_putInt32

	// wenn in r6 die adress von v2 drinsteht haben wir v2 eingelesen -> return, sonst lese v2
	ldr r0, =w_v2
	cmp r6, r0 
	beq ret_read4bytes
	
	// nach v2 fragen
	ldr r6, =w_v2
	ldr r0, =str_v2
	bl uart_putString
	b read4bytes
	
ret_read4bytes:
	pop {r5, r6, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
str_v1: .asciz "\nv1: 0x"
str_v2: .asciz "\nv2: 0x"
str_ohneDSP: .asciz "\nohne DSP-Befehle:"
str_mitDSP: .asciz "\nmit DSP-Befehlen:"
str_min: .asciz "\nmin: 0x"
str_max: .asciz "\nmax: 0x"
w_v1: .word 0x0
w_v2: .word 0x0
str_tOhneDSP: .asciz "\nZeitdauer ohne DSP-Befehle: 0x"
str_tMitDSP: .asciz "\nZeitdauer mit DSP-Befehlen: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// aufgabe a
	// r0: adresse M, r1: adresse N
	// r2, r3: spaltenvektor N
	// r4, r5: reihenvektor M
	// r6: wert fuer O
	// r7: adress O
	// r8, r9: loopcounter
	ldr r1, =mat_n_cm
	ldr r7, =mat_o_cm
	mov r8, #4
	
loop_col_n: // lade spaltenvektor aus N
	cmp r8, #0
	beq ausgabe_O // schleifenabbruch
	ldrd r2, r3, [r1], #8
	mov r9, #4
	ldr r0, =mat_m_rm // laden der ersten spalte von N
loop_row_m: // lade zeilenvektor aus M und fuehre vektormultiplikation aus
	ldrd r4, r5, [r0], #8
	smuad r6, r2, r4
	smlad r6, r3, r5, r6
	str r6, [r7], #4
	subs r9, #1
	itt eq 
	subeq r8, #1
	beq loop_col_n // springe in naechste spalte von N
	
	b loop_row_m // springe in naechste zeile von M
	

	// ausgabe O
ausgabe_O:
	ldr r0, =str_mat_o
	bl uart_putString
	ldr r4, =mat_o_cm
	mov r5, #16 // zaehler
loop_disp_o:
	ldr r0, [r4]
	bl uart_putInt32
	sub r5, r5, #1
	ands r0, r5, #0x03 // schreibe 2 letzten bit von r5 in r0
	ittee eq
	moveq r0, #0x0A // neue zeile
	subeq r4, r4, #44 // springe in naechste zeile (3*16 zurueck und 4 vor)
	movne r0, #0x20 // leerzeichen
	addne r4, r4, #16 // springe in naechste spalte
	bl uart_putChar
	
	cmp r5, #0
	bne loop_disp_o // springe zum naechsten matrixwert
	
	
	// aufgabe b
	ldr r0, =str_cp_o
	bl uart_putString
	ldr r8, =mat_o_cm
	ldr r9, =mat_o_copy
	ldm r8!, {r0-r7} // lade die ersten 8 werte
	stm r9!, {r0-r7} // schreibe die ersten 8 werte
	ldm r8, {r0-r7} // lade den rest
	stm r9, {r0-r7} // schreibe den rest
	
	// aufgabe c 
	// r0, r1: adressen aus m, n
	// r2, r3, r4, r5: werte aus m, n
	// r6: summe
	// r7: zaehler
	ldr r0, =mat_m_rm
	ldr r1, =mat_n_cm
	mov r7, #4
	mov r6, #0
loop_prodsum:
	ldrd r2, r3, [r0], #8
	ldrd r4, r5, [r1], #8
	smlad r6, r2, r4, r6
	smlad r6, r3, r5, r6
	subs r7, r7, #1
	bne loop_prodsum

	ldr r0, =str_prodSum
	bl uart_putString
	mov r0, r6
	bl uart_putInt32
	
	// aufgabe d
	// r4: A, r5: B, r6: C, r7: D
	ldr r0, =word_A
	ldr r4, [r0], #4
	ldr r5, [r0], #4
	ldr r6, [r0], #4
	ldr r7, [r0], #4
	
	// uadd16
	ldr r0, =str_uadd16
	bl uart_putString
	uadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	uadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	uadd16 r0, r4, r7
	bl uart_putInt32
	
	// sadd16
	ldr r0, =str_sadd16
	bl uart_putString
	sadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	sadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	sadd16 r0, r4, r7
	bl uart_putInt32
	
	// uqadd16
	ldr r0, =str_uqadd16
	bl uart_putString
	uqadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	uqadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	uqadd16 r0, r4, r7
	bl uart_putInt32
	
	// qadd16
	ldr r0, =str_qadd16
	bl uart_putString
	qadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	qadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	qadd16 r0, r4, r7
	bl uart_putInt32
	
	// aufgabe e
	// r4, r5: adresse A, adresse B
	// r5: temp
	ldr r4, =word_A
	ldr r5, =word_B
	
	// usat
	ldr r0, =str_befehl1
	bl uart_putString
	ldr r0, [r4] // lade A
	usat16 r0, #13, r0
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	ldr r0, [r5] // lade B
	usat16 r0, #13, r0
	bl uart_putInt32
	
	// ssat
	ldr r0, =str_befehl2
	bl uart_putString
	ldr r0, [r4] // lade A
	ssat16 r0, #13, r0
	bl uart_putInt32
	mov r0, 0x20 // print space
	bl uart_putChar
	ldr r0, [r5] // lade B
	ssat16 r0, #13, r0
	bl uart_putInt32
		
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
// M in row major
mat_m_rm: .short 0x5f8c, 0x7f48, 0x8245, 0x6048
		  .short 0xc799, 0x9c5d, 0xd49c, 0x33d8
		  .short 0x579b, 0x8aef, 0xf2c0, 0xa3c2
		  .short 0x41fd, 0x50d4, 0x25c6, 0x4afa
// N in column major
mat_n_cm: .short 0x7f41, 0x0645, 0x8c8f, 0x9065
		  .short 0x78e3, 0xf7f3, 0xd29f, 0x2961
		  .short 0x5a1e, 0xdfed, 0x4b9f, 0x1092
		  .short 0x61bf, 0x21be, 0x5ca1, 0xc6d3
// O in column major
mat_o_cm:
.rept 16
.word 0x00
.endr
mat_o_copy:
.rept 16
.word 0x00
.endr
word_A: .word 0xA4367C7B
word_B: .word 0x10A78933
word_C: .word 0xC5535F2C
word_D: .word 0x788E84B1
str_mat_o: .asciz "Ergebnismatrix O:\n"
str_cp_o: .asciz "\nKopieren der Matrix O!\n"
str_prodSum: .asciz "\nProdukt-Summe: \n"
str_uadd16: .asciz "\n\nUADD16: "
str_sadd16: .asciz "\nSADD16: "
str_uqadd16: .asciz "\nUQADD16: "
str_qadd16: .asciz "\nQADD16: "
str_befehl1: .asciz "\n\nUSAT16: "
str_befehl2: .asciz "\nSSAT16: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// speicher offsets zu monat, jahr, stunde und minute
.equ OFFMONAT, 4
.equ OFFJAHR, 8
.equ OFFSTUNDE, 12
.equ OFFMINUTE, 16

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	// bl test_time // zeitstempel in CuteCom aktivieren, zwischen start und stop sollte ca 1 minute liegen
	// r4: uhr laeuft
	// r5: adresse datum und zeit
	// r6: temp
	mov r4, #1
	ldr r5, =zeit_datum 
	

run_clock:
	cmp r4, #0
	beq check_char // zeitausgabe und delay ueberspringen wenn uhr aus
	
	bl print_time // zeit ausgeben
	bl delay
	
	ldr r0, [r5, #OFFMINUTE] // minute lesen
	cmp r0, #59
	ite eq
	moveq r0, #0 // ueberlauf
	addne r0, r0, #1
	str r0, [r5, #OFFMINUTE] // neuen minutenwert zurueckschreiben
	cmp r0, #0
	bne check_char // wenn kein ueberlauf ueberspringe stunde, ...
	
	// neue stunde
	ldr r0, [r5, #OFFSTUNDE]
	cmp r0, #23
	ite eq
	moveq r0, #0
	addne r0, r0, #1
	str r0, [r5, #OFFSTUNDE]
	cmp r0, #0
	bne check_char

	// neuer tag
	ldr r0, [r5]
	cmp r0, #30
	ite eq
	moveq r0, #1 // erster des neuen monats
	addne r0, r0, #1
	str r0, [r5]
	cmp r0, #1
	bne check_char
	
	// neuer monat
	ldr r0, [r5, #OFFMONAT]
	cmp r0, #12
	ite eq
	moveq r0, #1 // januar
	addne r0, r0, #1
	str r0, [r5, #OFFMONAT]
	cmp r0, #1
	bne check_char
	
	// neues jahr
	ldr r0, [r5, #OFFJAHR]
	add r0, r0, #1
	str r0, [r5, #OFFJAHR]
	
check_char:
	bl uart_charPresent
	cmp r0, #0
	bne read_char
	b run_clock
	
start_stop:
	eor r4, r4, #1 // uhr ein, uhr aus wechseln
	b run_clock
	
input_time:
	ldr r0, =str_stunde_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese stunde und schreibe in speicher
	str r0, [r5, #OFFSTUNDE]
	bl uart_putByteBase10 // gebe stunde aus
	ldr r0, =str_minute_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese minute und schreibe in speicher
	str r0, [r5, #OFFMINUTE]
	bl uart_putByteBase10 // gebe mintute aus
	mov r0, #0x0A // neue zeile
	bl uart_putChar
	b run_clock
	
input_date:
	ldr r0, =str_tag_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese tag und schreibe in speicher
	str r0, [r5]
	bl uart_putByteBase10 // gebe tag aus
	ldr r0, =str_monat_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese monat und schreibe in speicher
	str r0, [r5, #OFFMONAT]
	bl uart_putByteBase10 // gebe monat aus
	ldr r0, =str_jahr_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese jahr und speichere in r6
	mov r6, r0
	bl uart_putByteBase10 // gebe jahr wieder aus
	add r0, r6, #2000 // addiere 2000 jahr offset und schreibe in speicher
	str r0, [r5, #OFFJAHR]
	mov r0, #0x0A // neue zeile
	bl uart_putChar
	b run_clock

read_char:
	bl uart_getChar
	cmp r0, #'s'
	beq start_stop
	cmp r0, #'t'
	beq input_time
	cmp r0, #'d'
	beq input_date
	b run_clock

.thumb_func
delay:
	push {lr} // Takte: 1 + Anzahl Register
	ldr r0, =takte_1sec // 2 Takte
	ldr r0, [r0] // 2 Takte
loop_sec:
	sub r0, #1 // 1 Takt
	cmp r0, #0 // 1 Takt
	bne	loop_sec // 1 Takt zum Schluss, sonst 1 + P
	pop {pc} // Takte: 1 + Anzahl Register + P
	
.thumb_func
print_time:
	// r5: adressen
	// r6: zehnerjahre
    push {r5, r6, lr}
    ldr r5, =zeit_datum
    ldr r0, [r5], #4 // tag
    bl uart_putByteBase10
    mov r0, 0x2E // Punkt
    bl uart_putChar
    ldr r0, [r5], #4 // monat
    bl uart_putByteBase10
    mov r0, 0x2E
    bl uart_putChar
    ldr r0, [r5], #4 // jahr
    mov r1, #100
    udiv r2, r0, r1 // jahrhundert
    mul r3, r2, r1 // volle hunderter
    sub r6, r0, r3 // zehnerjahre
    mov r0, r2
    bl uart_putByteBase10
    mov r0, r6
    bl uart_putByteBase10
    mov r0, 0x20 // leerzeichen
    bl uart_putChar
    ldr r0, [r5], #4 // stunden
    bl uart_putByteBase10
    mov r0, 0x3A
    bl uart_putChar
    ldr r0, [r5] // minuten
    bl uart_putByteBase10
    ldr r0, =str_datum
    bl uart_putString
    pop {r5, r6, pc}
    
.thumb_func
test_time:
	push {lr}
	mov r1, #60
	ldr r0, =str_start
	bl uart_putString
loop_min:
	bl delay
	subs r1, r1, #1 
	bne loop_min
	ldr r0, =str_stop
	bl uart_putString
	pop {pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
zeit_datum: .word 1, 1, 2014, 0, 0 // tag, monat, jahr, stunde, minute
//takte_1sec: .word 8333330 // (25e6 - 6 (in-out)) / (3 + P)
takte_1sec: .word 4961000
str_datum: .asciz " Uhr\n"
str_stunde_eingabe: .asciz "\nStunde eingeben (hh): "
str_minute_eingabe: .asciz "\nMinuten eingeben (mm): "
str_tag_eingabe: .asciz "\nTag eingeben (dd): "
str_monat_eingabe: .asciz "\nMonat eingeben (mm): "
str_jahr_eingabe: .asciz "\nJahr eingeben (jj): "
str_start: .asciz "\nstart\n"
str_stop: .asciz "stop\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// speicher offsets zu monat, jahr, stunde und minute
.equ OFFMONAT, 4
.equ OFFJAHR, 8
.equ OFFSTUNDE, 12
.equ OFFMINUTE, 16

// PIT1
// addresse 0x0000_0154
// vektor 85
// irq 69
.equ ISR_TABLE, 0x1FFFFE00
.equ ISR_PIT1, 0x154

.equ SIM_SCGC6_PIT, 0x429007DC // 0x42000000 + (0x4004803C - 0x40000000) * 32 + 23 * 4
.equ PIT_BASE, 0x40037000
.equ PIT_MCR, 0x0
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1, 0x11C

.equ PIT1_BIT5, 0x20 // irq69 mod 32, bit 5 als maske
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_ICPR2, 0xE000E288


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// PIT1 initialisieren
	// PIT clock aktivieren
	ldr r0, =SIM_SCGC6_PIT
	mov r1, #1
	str r1, [r0]
	
	// interrupt vektor setzen
	ldr r0, =ISR_TABLE
	ldr r1, =pit_isr
	str r1, [r0, ISR_PIT1]
	
	// pending interrupts loeschen
	ldr r0, =NVIC_ICPR2
	mov r1, #PIT1_BIT5
	str r1, [r0]
	// interrupt aktivieren
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	ldr r8, =PIT_BASE // PIT Basis in r0 setzen
	mov r1, #1 // PIT timer mit debug aktivieren
	str r1, [r8, #PIT_MCR]
	ldr r1, =24999999 // PIT Startwert 25e6 - 1
	str r1, [r8, #PIT_LDVAL1]
	mov r1, #3 // PIT1 timer und interrupt aktivieren
	str r1, [r8, #PIT_TCTRL1]

	// bl test_time // zeitstempel in CuteCom aktivieren, zwischen start und stop sollte ca 1 minute liegen
	// r4: uhr laeuft
	// r5: adresse datum und zeit
	// r6: temp
	// r7: adresse isr_flag
	// r5: adresse pit base
	mov r4, #1
	ldr r5, =zeit_datum
	ldr r7, =isr_flag
	
run_clock:
	cmp r4, #0
	beq check_char // zeitausgabe und delay ueberspringen wenn uhr aus
	
warte_auf_int:
	ldrb r6, [r7]
	cmp r6, #0
	beq warte_auf_int
	mov r6, #0
	strb r6, [r7]
	bl print_time // zeit ausgeben
	
	ldr r0, [r5, #OFFMINUTE] // minute lesen
	cmp r0, #59
	ite eq
	moveq r0, #0 // ueberlauf
	addne r0, r0, #1
	str r0, [r5, #OFFMINUTE] // neuen minutenwert zurueckschreiben
	cmp r0, #0
	bne check_char // wenn kein ueberlauf ueberspringe stunde, ...
	
	// neue stunde
	ldr r0, [r5, #OFFSTUNDE]
	cmp r0, #23
	ite eq
	moveq r0, #0
	addne r0, r0, #1
	str r0, [r5, #OFFSTUNDE]
	cmp r0, #0
	bne check_char

	// neuer tag
	ldr r0, [r5]
	cmp r0, #30
	ite eq
	moveq r0, #1 // erster des neuen monats
	addne r0, r0, #1
	str r0, [r5]
	cmp r0, #1
	bne check_char
	
	// neuer monat
	ldr r0, [r5, #OFFMONAT]
	cmp r0, #12
	ite eq
	moveq r0, #1 // januar
	addne r0, r0, #1
	str r0, [r5, #OFFMONAT]
	cmp r0, #1
	bne check_char
	
	// neues jahr
	ldr r0, [r5, #OFFJAHR]
	add r0, r0, #1
	str r0, [r5, #OFFJAHR]
	
check_char:
	bl uart_charPresent
	cmp r0, #0
	bne read_char
	b run_clock
	
start_stop:
	eor r4, r4, #1 // uhr ein, uhr aus wechseln
	cmp r4, #0
	ite eq
	moveq r0, #0 // PIT1 timer deaktivieren
	movne r0, #3 // PIT1 timer und interrupt aktivieren
	str r0, [r8, #PIT_TCTRL1]
	b run_clock
	
input_time:
	ldr r0, =str_stunde_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese stunde und schreibe in speicher
	str r0, [r5, #OFFSTUNDE]
	bl uart_putByteBase10 // gebe stunde aus
	ldr r0, =str_minute_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese minute und schreibe in speicher
	str r0, [r5, #OFFMINUTE]
	bl uart_putByteBase10 // gebe mintute aus
	mov r0, #0x0A // neue zeile
	bl uart_putChar
	b run_clock
	
input_date:
	ldr r0, =str_tag_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese tag und schreibe in speicher
	str r0, [r5]
	bl uart_putByteBase10 // gebe tag aus
	ldr r0, =str_monat_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese monat und schreibe in speicher
	str r0, [r5, #OFFMONAT]
	bl uart_putByteBase10 // gebe monat aus
	ldr r0, =str_jahr_eingabe
	bl uart_putString
	bl uart_getByteBase10 // lese jahr und speichere in r6
	mov r6, r0
	bl uart_putByteBase10 // gebe jahr wieder aus
	add r0, r6, #2000 // addiere 2000 jahr offset und schreibe in speicher
	str r0, [r5, #OFFJAHR]
	mov r0, #0x0A // neue zeile
	bl uart_putChar
	b run_clock

read_char:
	bl uart_getChar
	cmp r0, #'s'
	beq start_stop
	cmp r0, #'t'
	beq input_time
	cmp r0, #'d'
	beq input_date
	b run_clock
	
.thumb_func
print_time:
	// r5: adressen
	// r6: zehnerjahre
    push {r5, r6, lr}
    ldr r5, =zeit_datum
    ldr r0, [r5], #4 // tag
    bl uart_putByteBase10
    mov r0, 0x2E // Punkt
    bl uart_putChar
    ldr r0, [r5], #4 // monat
    bl uart_putByteBase10
    mov r0, 0x2E
    bl uart_putChar
    ldr r0, [r5], #4 // jahr
    mov r1, #100
    udiv r2, r0, r1 // jahrhundert
    mul r3, r2, r1 // volle hunderter
    sub r6, r0, r3 // zehnerjahre
    mov r0, r2
    bl uart_putByteBase10
    mov r0, r6
    bl uart_putByteBase10
    mov r0, 0x20 // leerzeichen
    bl uart_putChar
    ldr r0, [r5], #4 // stunden
    bl uart_putByteBase10
    mov r0, 0x3A
    bl uart_putChar
    ldr r0, [r5] // minuten
    bl uart_putByteBase10
    ldr r0, =str_datum
    bl uart_putString
    pop {r5, r6, pc}
	
.global pit_isr
.thumb_func
pit_isr:
	ldr r0, =PIT_BASE // PIT Basis in r0 setzen
	mov r1, #1 // clear timeout flag
	strb r1, [r0, #PIT_TFLG1]
	ldr r0, =isr_flag // lade interrupt flag und setze es auf 1
	mov r1, #1
	strb r1, [r0]
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
zeit_datum: .word 1, 1, 2014, 0, 0 // tag, monat, jahr, stunde, minuten
isr_flag: .word 0
str_datum: .asciz " Uhr\n"
str_stunde_eingabe: .asciz "\nStunde eingeben (hh): "
str_minute_eingabe: .asciz "\nMinuten eingeben (mm): "
str_tag_eingabe: .asciz "\nTag eingeben (dd): "
str_monat_eingabe: .asciz "\nMonat eingeben (mm): "
str_jahr_eingabe: .asciz "\nJahr eingeben (jj): "
str_start: .asciz "\nstart\n"
str_stop: .asciz "stop\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ CRC_BASE, 0x40032000
.equ CRC_CRC, 0x0
.equ CRC_GPOLY, 0x4
.equ CRC_CTRL, 0x8
.equ CRC_BIT_TCRC, 0x1000000 // 1<<24
.equ CRC_BIT_WAS, 0x2000000 // 1<<25
.equ CRC_SEED, 0x12345678
.equ CRC_POLY, 0x04c11db7
.equ SIM_SCGC6_CRC, 0x429007c8 // crc clock bitbanding adresse

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// r4: adresse str
	// r5: crc base addr
	ldr r4, =str_text
	ldr r5, =CRC_BASE
	
	// crc clock einschalten
	ldr r0, =SIM_SCGC6_CRC
	mov r1, #1
	str r1, [r0]
	
	// crc einheit initialisieren
	ldr r0, =CRC_BIT_TCRC
	add r1, r0, #CRC_BIT_WAS
	str r1, [r5, #CRC_CTRL] // crc32 und write seed setzen
	ldr r1, =CRC_POLY
	str r1, [r5, #CRC_GPOLY]
	ldr r1, =CRC_SEED // IEEE 802.3 polynom setzen
	str r1, [r5, #CRC_CRC] // seed setzen
	str r0, [r5, #CRC_CTRL] // crc32
	
	// crc berechnen
loop_crc:
	ldr r0, [r4], #4 // lade wort in r0
	str r0, [r5, #CRC_CRC] // berechne crc mit r0
	ldr r1, =0xff000000 // maske fuer str terminator in r1
loop_mask:
	ands r2, r1, r0 // byte in r2 maskieren
	beq crc_ready // str ende in r0
	lsrs r1, r1, #8 // maske weiterschieben
	bne loop_mask
	b loop_crc // springe zum naechsten wort

crc_ready:
	// text und crc ausgeben
	ldr r0, =str_text
	bl uart_putString
	ldr r0, =str_crc
	bl uart_putString
	ldr r0, [r5, #CRC_CRC] // crc auslesen und ausgeben
	bl uart_putInt32
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str_text: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
word_null: .word 0 // weitere 4 Nullbytes
str_crc: .asciz "\nCRC: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ SIM_SCGC5_PORTA, 0x42900724 // bitbanding PORTA
.equ SIM_SCGC5_PORTE, 0x42900734 // bitbanding PORTE 
.equ PCR_LED0, 0x4004902C
.equ PCR_LED1, 0x40049070
.equ PCR_LED2, 0x40049074
.equ PCR_LED3, 0x40049028
.equ PCR_WERT_LEDS, 0x160 // GPIO, DSE, ODE
.equ PCR_SW1, 0x4004904C
.equ PCR_SW2, 0x4004D068
.equ PCR_WERT_SW1, 0x113 // GPIO, PFE, PE, PS
.equ PCR_WERT_SW2, 0x10B0113 // ISF, IRQC, GPIO, PFE, PE, PS
.equ GPIOA_PSOR, 0x400FF004
.equ GPIOA_PCOR, 0x400FF008
.equ GPIOA_PDIR_BB, 0x43FE0200
.equ GPIOE_PDIR_BB, 0x43FE2200
.equ GPIOA_PDDR_BB, 0x43FE0280
.equ GPIOE_PDDR_BB, 0x43FE2200
.equ BB_LED0, 0x2C
.equ BB_LED1, 0x70
.equ BB_LED2, 0x74
.equ BB_LED3, 0x28
.equ BB_SW1, 0x4C
.equ BB_SW2, 0x68
.equ LED0_BIT, 0x800
.equ LED1_BIT, 0x10000000
.equ LED2_BIT, 0x20000000
.equ LED3_BIT, 0x400

// PIT1
// adresse 0x0000_0154
// vektor 85
// irq 69
.equ ISR_TABLE, 0x1FFFFE00
.equ ISR_PIT1, 0x154

.equ SIM_SCGC6_PIT, 0x429007DC
.equ PIT_BASE, 0x40037000
.equ PIT_MCR, 0x0
.equ PIT_LDVAL1, 0x110
.equ PIT_TCTRL1, 0x118
.equ PIT_TFLG1, 0x11C

.equ PIT1_BIT5, 0x20 // irq69 mod 32, bit 5 als maske
.equ NVIC_ISER2, 0xE000E108 // intr set enable
.equ NVIC_ICPR2, 0xE000E288 // intr clear pending
.equ DEBOUNCE, 0x60E0

// Switch2
// adresse 0x0000_01AC
// vektor 107
// irq 91
.equ ISR_SW2, 0x1AC
.equ SW2_BIT27, 0x8000000 // irq91 mod 32, bit 27 als maske
.equ PORTE_ISFR, 0x4004D0A0
.equ SW2_BIT26, 0x4000000 // sw2 bit in PORTE_ISFR

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init
	
	// port A und E einschalten
	ldr r0, =SIM_SCGC5_PORTA
	mov r1, #1
	str r1, [r0]
	ldr r0, =SIM_SCGC5_PORTE
	str r1, [r0]
	// PIT clock aktivieren (wird wahrscheinlich in pit3_init schon gemacht)
	ldr r0, =SIM_SCGC6_PIT
	mov r1, #1
	str r1, [r0]

	// setze led pins auf gpio
	ldr r1, =PCR_WERT_LEDS
	ldr r0, =PCR_LED0
	str r1, [r0]
	ldr r0, =PCR_LED1
	str r1, [r0]
	ldr r0, =PCR_LED2
	str r1, [r0]
	ldr r0, =PCR_LED3
	str r1, [r0]
	
	// setze switches auf gpio
	ldr r1, =PCR_WERT_SW1
	ldr r0, =PCR_SW1
	str r1, [r0]
	ldr r0, =PCR_SW2
	ldr r1, =PCR_WERT_SW2
	str r1, [r0]
	
	// setze led gpios auf ausgang
	mov r1, #1
	ldr r0, =GPIOA_PDDR_BB
	str r1, [r0, #BB_LED0]
	str r1, [r0, #BB_LED1]
	str r1, [r0, #BB_LED2]
	str r1, [r0, #BB_LED3]

	// setze switches auf eingang
	mov r1, #0
	str r1, [r0, #BB_SW1] // haengt auch an port A
	ldr r0, =GPIOE_PDDR_BB
	str r1, [r0, #BB_SW2]
	
	// leds ausschalten
	ldr r0, =GPIOA_PSOR
	mov r1, #LED0_BIT
	orr r1, r1, #LED1_BIT
	orr r1, r1, #LED2_BIT
	orr r1, r1, #LED3_BIT
	str r1, [r0]

	// interrupt vektor setzen
	ldr r0, =ISR_TABLE
	ldr r1, =pit_isr
	str r1, [r0, #ISR_PIT1] // pit interrupt
	ldr r1, =sw2_isr
	str r1, [r0, #ISR_SW2] // switch2 interrupt
	
	// pending interrupts loeschen
	ldr r0, =NVIC_ICPR2
	mov r1, #PIT1_BIT5
	orr r1, r1, #SW2_BIT27
	str r1, [r0]
	// interrupts aktivieren
	ldr r0, =NVIC_ISER2
	str r1, [r0]
	
	ldr r8, =PIT_BASE // PIT Basis in r0 setzen
	mov r1, #1 // PIT timer mit debug aktivieren
	str r1, [r8, #PIT_MCR]
	ldr r1, =24999999 // PIT Startwert 25e6 - 1
	str r1, [r8, #PIT_LDVAL1]
	mov r1, #3 // PIT1 timer und interrupt aktivieren
	str r1, [r8, #PIT_TCTRL1]
	
	// r4: adresse pit_flag
	// r5: adresse running
	// r6: zaehler wert
	// r7: timer_start
	// r8: timer_running
	// r9: debounce
	ldr r4, =pit_flag
	ldr r5, =running
	ldr r10, =forward
	mov r6, #0
	mov r8, #0
	ldr r9, =DEBOUNCE

loop_counter:
	// counter zaehlt weiter wenn er laeuft und pit flag gesetzt wurde
	ldrb r0, [r4] // pit_flag
	cmp r0, #1
	bne counter_same // pit hat nicht ausgeloest
	
	// pit hat ausgeloest
	mov r1, #0
	strb r1, [r4] // pit_flag zuruecksetzen
	
	ldr r0, [r5]
	cmp r0, #1
	bne counter_same // zaehler laeuft nicht
	
	// zaehler laeuft
	ldr r0, [r5, #4] // forward lesen
	cmp r0, #1
	ite eq
	addeq r6, r6, #1 // zaehler laueft vorwaerts
	subne r6, r6, #1 // zaehler laueft rueckwaerts
	and r6, r6, #0xFF // 8 bit zaehler 
	
	// gebe auf terminal aus
	mov r0, r6
	bl uart_putByteBase10
	mov r0, #0x0A // neue zeile
	bl uart_putChar

	// setze leds	
	mov r0, #0 // leds einschalten
	mov r1, #0 // leds ausschalten
	ands r2, r6, #0x1
	ite ne
	orrne r0, #LED0_BIT // schalte led0 ein
	orreq r1, #LED0_BIT // schalte led0 aus
	ands r2, r6, #0x2
	ite ne
	orrne r0, #LED1_BIT // schalte led1 ein
	orreq r1, #LED1_BIT // schalte led1 aus
	ands r2, r6, #0x4
	ite ne
	orrne r0, #LED2_BIT // schalte led2 ein
	orreq r1, #LED2_BIT // schalte led2 aus
	ands r2, r6, #0x8
	ite ne
	orrne r0, #LED3_BIT // schalte led3 ein
	orreq r1, #LED3_BIT // schalte led3 aus
	
	ldr r2, =GPIOA_PCOR // adresse fuer bit clear, schaltet led invers an
	str r0, [r2]
	ldr r2, =GPIOA_PSOR // adresse fuer bit set, schaltet led invers aus
	str r1, [r2]
	
counter_same:
	// poll fuer sw1
	mov r0, #1
	bl read_sw
	
	// lese mod
	ldr r0, =mod
	ldr r3, [r0] // lese mod in r3
	
	// aktionen wenn kein schalter gedrueckt ist 
	cmp r3, #0
	itt eq
	moveq r8, #0 // kein timer laeuft
	beq switch_handling_done // kein schalter
	
	// timer laeuft
	cmp r8, #3
	beq switch_handling_done // timer handling angehalten
	cmp r3, r8
	bne start_timer // timer laeuft nicht (fuer den gedrueckten schalter)
	
	// berechne laufendes zeitdelta
	bl pit3_getval
	sub r0, r7, r0 // zeitdelta
	cmp r0, r9
	blt switch_handling_done // debounce zeit noch nicht abgelaufen
	
	// debounce zeit erreicht
	mov r8, #3 // schalter funktion wird ausgefuehrt, timer handling anhalten
	cmp r3, #1
	bne handle_sw2
	
	// aendere die zaehlrichtung
	ldr r0, [r10] // lade forward
	cmp r0, #1
	ite eq
	moveq r0, #0 // zaehler rueckwaerts
	movne r0, #1 // zaehler vorwaerts
	str r0, [r10]
	b switch_handling_done
	
handle_sw2:
	// starte oder stoppe den zaehler
	ldr r0, [r5] // lade running
	cmp r0, #1
	ite eq
	moveq r0, #0 // schalte zaehler ein
	movne r0, #1 // schalte zaehler aus
	str r0, [r5]
	b switch_handling_done
	
start_timer: // speichere aktueller timerwert in r7 und setze schalter in r8
	mov r8, r3
	bl pit3_getval
	mov r7, r0
	
switch_handling_done:
	// lese terminal
	bl uart_charPresent
	cmp r0, #0
	beq loop_counter // kein terminal input
	
	// lese terminal input
	bl uart_getChar
	cmp r0, #'+'
	itt eq // setze zaehler vorwaerts
	moveq r1, #1
	streq r1, [r10] // schreibe forward
	cmp r0, #'-'
	itt eq // setze zaehler rueckwaerts
	moveq r1, #0
	streq r1, [r10] // schreibe forward
	cmp r0, #'s'
	bne loop_counter // kein gueltiges zeichen
	ldr r0, [r5] // lade running
	cmp r0, #1
	ite eq
	moveq r0, #0 // schalte zaehler ein
	movne r0, #1 // schalte zaehler aus
	str r0, [r5]
	b loop_counter
	
.thumb_func
// lese sw1 oder sw2 und schreibe mod
// r0 = 1 fuer sw1, r0 = 2 fuer sw2
read_sw:
	ldr r2, =mod
	ldr r1, [r2] // lese mod
	cmp r1, #0
	beq read_one_sw // kein schalter gesetzt
	cmp r0, r1
	bne ret_read_sw // schalter auslesen abbrechen, da der andere schalter gerade gesetzt ist
read_one_sw:
	cmp r0, #1 // ist funktionsparameter switch1 ?
	ittee eq // lese wert aus bitbanding in r1
	ldreq r1, =GPIOA_PDIR_BB
	ldreq r1, [r1, #BB_SW1]
	ldrne r1, =GPIOE_PDIR_BB
	ldrne r1, [r1, #BB_SW2]
    cmp r1, #0 // werte aus ob switch gesetzt ist
	ite eq
	moveq r1, r0 // switch ist gesetzt, schreibe r0 funktionsparameter
	movne r1, #0 // switch ist nicht gesetz
	str r1, [r2] // schreibe mod
ret_read_sw:
	bx lr

// isr sw2
.thumb_func
sw2_isr:
	ldr r0, =PORTE_ISFR
	ldr r1, =SW2_BIT26
	ldr r2, [r0]
	ands r2, r1, r2
	beq not_our_interrupt // bit26 nicht gesetzt
	str r1, [r0] // interrupt flag zuruecksetzen
	mov r0, #2
	push {lr}
	bl read_sw
	pop {lr}
not_our_interrupt:
	bx lr
	
// isr pit
.thumb_func
pit_isr:
	ldr r0, =PIT_BASE // PIT Basis in r0 setzen
	mov r1, #1 // clear timeout flag
	strb r1, [r0, #PIT_TFLG1]
	ldr r0, =pit_flag // lade interrupt flag und setze es auf 1
	strb r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
mod: .word 0
pit_flag: .byte 0
.align 4
running: .word 1 // 1: zaehler laeuft, 0: zaehler abgehalten 
forward: .word 1 // zaehler laeuft 1: vorwaerts, 0: rueckwaerts

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

__BBREG BB_SIM_SCGC3_ADC1, 0x40048030, 27
__BBREG BB_ADC1_SC3_CAL, (ADC1_BASE + ADC_SC3), 7

.equ ADC1_BASE, 0x400BB000
.equ ADC_SC1A, 0x0
.equ ADC_CFG1, 0x8
.equ ADC_CFG2, 0xC
.equ ADC_RA, 0x10
.equ ADC_SC2, 0x20
.equ ADC_SC3, 0x24
.equ ADC_PG, 0x2C
.equ ADC_CLP0, 0x4C
.equ ADC_PGA, 0x50

.equ ADC_CFG1_8BIT, 0xF1 // bus clock (50MHz/2), 8-bit, ADLSMP, div8, ADLPC
.equ ADC_CFG1_10BIT, 0xF9 // bus clock (50MHz/2), 10-bit, ADLSMP, div8, ADLPC
.equ ADC_CFG1_12BIT, 0xF5 // bus clock (50MHz/2), 12-bit, ADLSMP, div8, ADLPC
.equ ADC_CFG1_16BIT, 0xFD // bus clock (50MHz/2), 16-bit, ADLSMP, div8, ADLPC
.equ ADC_SC3_CAL, 0x7 // 32 samples, AVGE
.equ ADC_SC1A_CAL, 0x1D // V_REFSH (b11101) 
.equ ADC_SC1A_MEAS, 0x14 // Potentiometer (b10100) AD20
.equ ADC_SC3_MEAS, 0xE // 16 samples, AVGE, ADCO
.equ ADC_SC3_MEAS_STOP, 0x6 // 16 samples, AVGE

.equ BIT_SC1A_COCO, (1<<7) // Conversion Complete Mask
.equ BIT_SC3_CALF, (1<<6) // Calibration Failed

.equ VREF, 3300
.equ MAX_8BIT, 0xFF
.equ MAX_10BIT, 0x3FF
.equ MAX_12BIT, 0xFFF
.equ MAX_16BIT, 0xFFFF

.equ SIM_SCGC5_PORTA, 0x42900724 // bitbanding PORTA
.equ SIM_SCGC5_PORTE, 0x42900734 // bitbanding PORTE 
.equ PCR_LED0, 0x4004902C
.equ PCR_LED1, 0x40049070
.equ PCR_LED2, 0x40049074
.equ PCR_LED3, 0x40049028
.equ LED0_BIT, 0x800
.equ LED1_BIT, 0x10000000
.equ LED2_BIT, 0x20000000
.equ LED3_BIT, 0x400
.equ PCR_WERT_LEDS, 0x160 // GPIO, DSE, ODE
.equ GPIOA_PSOR, 0x400FF004
.equ GPIOA_PCOR, 0x400FF008
.equ GPIOA_PDDR_BB, 0x43FE0280
.equ BB_LED0, 0x2C
.equ BB_LED1, 0x70
.equ BB_LED2, 0x74
.equ BB_LED3, 0x28

.equ SIM_SCGC6,	 	0x4004803C
.equ SCR_VTOR,		0xE000ED08		// Register für die Interrupt-Vektor-Tabelle (IVT)

.equ PIT_MCR,       0x40037000
.equ PIT_LDVAL1,    0x40037110
.equ PIT_TCTRL1,    0x40037118
.equ PIT_TFLG1,     0x4003711C

.equ NVIC_ISER2, 	0xe000e108
.equ NVIC_ICPR2, 	0xe000e288

__BBREG BB_SIM_PIT, SIM_SCGC6, 23	// Bit-Band-Alias-Adresse für den PIT im SIM-Register

.equ PIT1_IRQ_OFS,	0x154			// Interrupt Request Offset für PIT1
.equ PIT1_NVIC_MASK, 1 << (69 % 32)	// Bitposition für PIT-IRQ in NVIC-Registern (IRQ mod 32)

.equ PIT_COUNT, 25000000			// 25000000	Takte bei 25 MHz => 1 Sekunde
.equ PIT_MCR_VAL, 0					// MDIS = 0, FRZ = 0
.equ PIT_TCTRL1_VAL, 3				// CHN = 0, TIE = 1, TEN = 1

.equ CHAR_S, 's'				
.equ CHAR_0, '0'
.equ CHAR_1, '1'
.equ CHAR_2, '2'
.equ CHAR_3, '3'
.equ CHAR_SPACE, ' '
.equ CHAR_BRACKET, ')'

.equ VMAX, 3300 // max 3300mV referenzspannug
.equ MVSTEP, 5 // minimale aufloesung fuer spannungsgrenzen in stufen 

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	// Initialisiere UART 
	bl uart_init

	// PIT1 initialisieren
	bl pit1_init
		
	// r12: adresse pit_flag
	// r11: adresse ADC1_BASE
	// r10: adc running
	// r9: adc wert / spannung in mV / stufe
	// r8: naechster sdc1 wert
	// r7: #ADC_SC1A_MEAS
	// r6: aufloesung in bit
	ldr r12, =pit_flag
	ldr r11, =ADC1_BASE
	mov r10, #1
	mov r9, #0
	mov r8, #ADC_CFG1_16BIT
	mov r7, #ADC_SC1A_MEAS
	mov r6, #16
	
	// port A und E einschalten
	ldr r0, =SIM_SCGC5_PORTA
	mov r1, #1
	str r1, [r0]
	ldr r0, =SIM_SCGC5_PORTE
	str r1, [r0]
	
	// setze led pins auf gpio
	ldr r1, =PCR_WERT_LEDS
	ldr r0, =PCR_LED0
	str r1, [r0]
	ldr r0, =PCR_LED1
	str r1, [r0]
	ldr r0, =PCR_LED2
	str r1, [r0]
	ldr r0, =PCR_LED3
	str r1, [r0]
	
	// setze led gpios auf ausgang
	mov r1, #1
	ldr r0, =GPIOA_PDDR_BB
	str r1, [r0, #BB_LED0]
	str r1, [r0, #BB_LED1]
	str r1, [r0, #BB_LED2]
	str r1, [r0, #BB_LED3]
	
	// leds ausschalten
	ldr r0, =GPIOA_PSOR
	mov r1, #LED0_BIT
	orr r1, r1, #LED1_BIT
	orr r1, r1, #LED2_BIT
	orr r1, r1, #LED3_BIT
	str r1, [r0]

	// adc initialisieren
	ldr r0, =BB_SIM_SCGC3_ADC1
	mov r1, #1
	str r1, [r0] // adc1 clock einschalten
	
	// clock quelle und frequenz einstellen
	mov r1, #ADC_CFG1_16BIT
	str r1, [r11, #ADC_CFG1]
	
	// adc kalibrieren
	bl cal_adc
	
	mov r0, #0
	str r0, [r11, #ADC_CFG2]
	str r0, [r11, #ADC_PGA] // kein PGA verwenden
	mov r0, #ADC_SC3_MEAS
	str r0, [r11, #ADC_SC3]
	
	// messungen starten
	mov r0, #ADC_SC1A_MEAS
	str r0, [r11, #ADC_SC1A]
loop:	
	// adc auslesen
	ldr r9, [r11, #ADC_RA]
	
	// gemessenen wert gegebenfalls auf dem terminal ausgeben
	ldr r0, [r12]
	cmp r0, #1
	bne check_char // kein pit_flag, ueberspringe ausgabe
	mov r0, #0
	str r0, [r12] // pit_flag zuruecksetzen
	cmp r10, #1
	bne check_char // adc laeuft nicht, ueberspringe ausgabe
	ldr r0, =str_start
	bl uart_putString
	mov r0, r9 // adc wert ausgeben
	bl uart_putInt16
	mov r0, #CHAR_SPACE
	bl uart_putChar
	
	mov r0, #0 // stufe
	mov r1, #1 // naechste stufe
	mov r2, #0 // unteres limit der stufe
	ldr r4, =VMAX
	mov r5, #MVSTEP
	
	// adc wert in mV umrechnen
	mul r9, r9, r4
	lsr r9, r9, r6
	
calc_step:
	// berechne oberes limit der stufe r3 (((3300*r1)/anzahlStufen + 4) / 5) * 5, gerundet auf 5mV
	mul r3, r1, r4
	udiv r3, r3, r6
	add r3, r3, #(MVSTEP - 1) // +4
	udiv r3, r3, r5
	mul r3, r3, r5
	cmp r9, r3 // vergleiche oberes limit mit spannung
	ittt gt // wenn spannung groeßer inkrementiere stufe und 
	addgt r0, r0, #1
	addgt r1, r1, #1
	movgt r2, r3
	bgt calc_step
	
	mov r9, r0 // stufe in r9 speichern
	mov r5, r3 // oberes limit in r5 speichern
	mov r4, r2 // unteres limit in r4 speichern
	mov r0, #CHAR_SPACE
	bl uart_putChar
	
	// unteres limit ausgeben
	mov r0, r4
	bl put_limit
	
	ldr r0, =str_strich
	bl uart_putString
	
	// oberes limit ausgeben
	mov r0, r5
	bl put_limit
	
	ldr r0, =str_stufe
	bl uart_putString
	mov r0, r9 // stufe ausgeben
	bl uart_putByteBase10
	mov r0, #CHAR_BRACKET
	bl uart_putChar
	
	// setze leds	
	mov r0, #0 // leds einschalten
	mov r1, #0 // leds ausschalten
	ands r2, r9, #0x1
	ite ne
	orrne r0, #LED0_BIT // schalte led0 ein
	orreq r1, #LED0_BIT // schalte led0 aus
	ands r2, r9, #0x2
	ite ne
	orrne r0, #LED1_BIT // schalte led1 ein
	orreq r1, #LED1_BIT // schalte led1 aus
	ands r2, r9, #0x4
	ite ne
	orrne r0, #LED2_BIT // schalte led2 ein
	orreq r1, #LED2_BIT // schalte led2 aus
	ands r2, r9, #0x8
	ite ne
	orrne r0, #LED3_BIT // schalte led3 ein
	orreq r1, #LED3_BIT // schalte led3 aus
	
	ldr r2, =GPIOA_PCOR // adresse fuer bit clear, schaltet led invers an
	str r0, [r2]
	ldr r2, =GPIOA_PSOR // adresse fuer bit set, schaltet led invers aus
	str r1, [r2]
	
	// terminal auswertung
check_char:
	bl	uart_charPresent			// wurde ein Zeichen eingegeben?
	cbnz r0, check_input			// ja, pruefen
	b loop
	
check_input:
	bl uart_getChar // eingegebenes Zeichen einlesen
	cmp	r0, #CHAR_S // war es ein 's'?
	bne check_0
	cmp r10, #1
	ittee eq
	moveq r10, #0
	moveq r0, #ADC_SC3_MEAS_STOP
	movne r10, #1
	movne r0, #ADC_SC3_MEAS
	str r0, [r11, #ADC_SC3]
	beq loop
	str r7, [r11, #ADC_SC1A] // adc konvertierung aktivieren
	b loop
	
check_0:
	cmp r10, #1
	beq loop // genauigkeit nur veraendern wenn in stopp modus
	cmp r0, #CHAR_0 // war es ein '0'?
	bne check_1
	mov r8, #ADC_CFG1_8BIT
	str r8, [r11, #ADC_CFG1]
	mov r6, #8 // 8 bit aufloesung
	b loop
check_1:
	cmp r0, #CHAR_1 // war es ein '1'?
	bne check_2
	mov r8, #ADC_CFG1_10BIT
	str r8, [r11, #ADC_CFG1]
	mov r6, #10 // 10 bit aufloesung
	b loop
check_2:
	cmp r0, #CHAR_2 // war es ein '2'?
	bne check_3
	mov r8, #ADC_CFG1_12BIT
	str r8, [r11, #ADC_CFG1]
	mov r6, #12 // 12 bit aufloesung
	b loop
check_3:
	cmp r0, #CHAR_3 // war es ein '3'?
	bne loop // keine gueltige Eingabe, normal weitermachen
	mov r8, #ADC_CFG1_16BIT
	str r8, [r11, #ADC_CFG1]
	mov r6, #16 // 16 bit aufloesung
	b loop
	

.thumb_func
// r0: limit
put_limit:
	push {r4, lr}
	cmp r0, #0xff
	ble disp_byte // r4 kann einfach ausgegeben werden
	mov r2, #100
	udiv r1, r0, r2 // r1: hunderter
	mul r2, r1, r2
	sub r4, r0, r2 // r0: 0-99
	// gebe hunderter aus
	mov r0, r1
	bl uart_putByteBase10
	// gebe 0-99 aus
	mov r0, r4
	cmp r0, #10
	it lt
	bllt uart_putByte
	it ge
	blge uart_putByteBase10
	b put_limit_ret
disp_byte:
	bl uart_putByteBase10
put_limit_ret:
	pop {r4, pc}
	
.thumb_func
cal_adc:
	// hardware averaging auf 32 samples stellen
	ldr r4, =ADC1_BASE
	mov r1, #ADC_SC3_CAL
	str r1, [r4, #ADC_SC3]
	
	// vrefh setzen
	mov r0, #ADC_SC1A_CAL
	str r0, [r4, #ADC_SC1A]
	
	// select software trigger
	mov r2, #0
	str r2, [r4, #ADC_SC2]
	// r2: clp summe
	
	// warten bis letzte umwandlung vorbei ist
wait_no_coco:
	ldr r0, [r4, #ADC_SC1A]
	ands r3, r0, #BIT_SC1A_COCO // ist bit conversion complete gesetzt
	bne wait_no_coco
	
	// kalibrierung starten
	ldr r3, =BB_ADC1_SC3_CAL
	mov r1, #1
	str r1, [r3]
	ldr r1, [r3] // cal bit direkt wieder lesen um zu sehen ob kalibrierung gestartet wurde
	cmp r1, #0
	beq cal_failed // kalibrierung nicht gestartet
	
	// warten bis kalibrierung fertig ist
cal_not_ready:
	ldr r0, [r4, #ADC_SC3]
	ands r3, r0, #BIT_SC3_CALF
	bne cal_failed // kalibrierung fehlgeschlagen
	ldr r0, [r4, #ADC_SC1A]
	ands r3, r0, #BIT_SC1A_COCO
	beq cal_not_ready // kalibrierung laeuft noch
	
	// kalibrierung erfolgreich
	add r3, r4, #ADC_CLP0 // r3 ist adresse von ADC_CLP0 und wird verringert bis ADC_CLPS
	mov r1, #6
loop_sum_pg:
	ldr r0, [r3], #-4
	add r2, r2, r0 // ADC_CLPx werte aufaddieren
	subs r1, r1, #1
	bne loop_sum_pg
	
	// speichere PG, r2 vorher durch 2 teilen und MSB bit16 setzen 
	lsr r2, r2, #1
	add r2, r2, #0x8000
	str r2, [r4, #ADC_PG]
	bx lr
	
cal_failed: // ausgabe fehler und endlosschleife
	ldr r0, =str_cal_failed
	bl uart_putString
loop_cal_failed:
	b loop_cal_failed
	
	
.thumb_func
pit1_init:
	ldr r0, =SCR_VTOR				// Basisadresse der IVT
	ldr r1, [r0]					// laden
	ldr r0, =isr_pit1				// ISR fuer den PIT1 
	str r0, [r1, #PIT1_IRQ_OFS]		// in die IVT eintragen
	
	ldr r0, =NVIC_ICPR2				// Pending (haengende) IRQs zu PIT1 im NVIC loeschen
	mov r1, #PIT1_NVIC_MASK			// Bit für PIT1-IRQ in den NVIC-Registern
	str r1, [r0]
	ldr r0, =NVIC_ISER2				// IRQs zu PIT1 im NVIC aktivieren
	str r1, [r0]					// R1 hat noch den Wert (PIT1_NVIC_MASK), also nicht neu laden

	ldr r0, =BB_SIM_PIT				// Bit-Band-Alias-Adresse fuer das Bit des PIT im SIM laden
	mov r1, #1						
	str r1, [r0]					// Clock fuer PIT1 aktivieren
	ldr r0, =PIT_MCR				
	mov r1, #PIT_MCR_VAL			// alle PITs einschalten, im Debug-Modus anhalten
	str r1, [r0]
	ldr r0, =PIT_LDVAL1				// initialen Zaehlwert setzen
	ldr r1, =PIT_COUNT 
	str r1, [r0]
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_VAL			// PIT1: aktivieren, IRQs aktiv 
	str r1, [r0]
 	bx lr	
	
	
.thumb_func
isr_pit1:
	mov r1, #0x1
	ldr r0, =pit_flag				// Benutzerflag setzen
	str r1, [r0]
	ldr r0, =PIT_TFLG1				// TIF (Timer Interrupt Flag) loeschen
	str r1, [r0]
	bx lr
	

/*** Datenbereich (ab 0x20000000) ***/
.data
pit_flag: .word 0
stepLimits: .word 0x00, 0x00
str_start: .asciz "\n0x"
str_cal_failed: .asciz "\nKalibrierung fehlgeschlagen"
str_strich: .asciz " - "
str_stufe: .asciz " mV (Stufe "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ SIM_SCGC4, 0x40048034
__BBREG SIM_I2C0, SIM_SCGC4, 6

.equ I2C0, 0x40066000
.equ I2C_A1, 0x0
.equ I2C_F, 0x1
.equ I2C_C1, 0x2
.equ I2C_S, 0x3
.equ I2C_D, 0x4
.equ I2C_C2, 0x5

// minimaler teiler der 25MHz ist 20, daher maximale frequenz des K60: 1250kHz
// DS75 kann aber maximal 400kHz 
.equ I2C_F_ICR, 0x12 // teiler 64 -> 390kHz
.equ I2C_C2_Reset, 0

.equ DS75_WRITE, 0x90
.equ DS75_READ, 0x91

.equ I2C_C1_ON, (1 << 7)
.equ I2C_C1_START, (1 << 7) | (1 << 5) | (1 << 4)
.equ I2C_C1_STOP, (1 << 7)
__BBREG I2C0_C1_RSTA, 0x40066002, 2
__BBREG I2C0_C1_TXAK, 0x40066002, 3
__BBREG I2C0_C1_TX, 0x40066002, 4
__BBREG I2C0_C1_MST, 0x40066002, 5

.equ DS75_12BIT, (3 << 5)
.equ DS75_PTR_TEMP, 0
.equ DS75_PTR_CFG, 1
.equ DS75_PTR_THYST, 2
.equ DS75_PTR_TOS, 3

.equ DS75_ZEROBITS, 4
.equ LSB_TIMES_10000, 625

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init // pit zaehlt rueckwaerts
	bl pit1_init // PIT1 initialisieren
	
	ldr r12, =I2C0 // basis adresse i2c0

	bl I2CBus_Reset
	
	// i2c bus initialisieren
	// i2c modul einschalten
	ldr r0, =SIM_I2C0
	mov r1, #1
	str r1, [r0]
	
	// frequenz teiler setzen
	mov r0, #I2C_F_ICR
	strb r0, [r12, #I2C_F]
	
	// i2c modul einschalten
	mov r0, #I2C_C1_ON
	strb r0, [r12, #I2C_C1]
	
	// 7bit adressen modus
	mov r0, #I2C_C2_Reset
	strb r0, [r12, #I2C_C2]
	
	// ds75 konfiguration setzen
	mov r1, #DS75_12BIT
	//orr r1, r1, #(1 << 2)
	mov r0, #DS75_PTR_CFG
	bl write_byte
	
	// dummy read um pointer zu setzen
	mov r0, DS75_PTR_TEMP
	bl read_byte
	
	// erste temperatur auslesen
	bl read_2byte
	and r11, r0, #0xFF // lsb in r11
	lsr r10, r0, #8 // msb in r10
	
	// TOS schreiben
	mov r0, DS75_PTR_TOS
	add r1, r10, #3 // TOS 3 Grad hoeher setzen
	mov r2, r11 // lsb uebernehmen
	bl write_2byte 
	
	// THYST schreiben
	mov r0, DS75_PTR_THYST
	add r1, r10, #2 // THYST 2 Grad hoeher setzen
	mov r2, r11 // lsb uebernehmen
	bl write_2byte
	
	// dummy read um pointer zu setzen
	mov r0, DS75_PTR_TEMP
	bl read_byte

	ldr r9, =pit_flag
read_temp:
	// warten auf pit_flag
	ldr r0, [r9]
	cmp r0, #1 // uberpruefe ob pit_flag gesetzt ist
	bne read_temp
	
	// pit_flag gesetzt
	mov r0, #0
	str r0, [r9] // pit_flag zuruecksetzen
	ldr r0, =str_hex
	bl uart_putString
	
	// lese temperatur aus
	bl read_2byte
	and r11, r0, #0xFF // lsb in r11
	lsr r11, r11, #DS75_ZEROBITS
	lsr r10, r0, #8 // msb in r10
	bl uart_putInt16 // gebe hexwert aus
	// gebe doppelpunkt und leerzeichen aus
	mov r0, ':'
	bl uart_putChar
	mov r0, ' '
	bl uart_putChar 
	mov r0, r10
	bl uart_putByteBase10 // gebe volle grad werte aus
	mov r0, ','
	bl uart_putChar // gebe komma aus 
	// berechne nachkommastellen
	ldr r1, =LSB_TIMES_10000
	mul r1, r11, r1
	cmp r1, #1000 // vergleiche ob lsb * 10000 < 1000 ist, da dann eine 0 eingefuegt werden muss
	blt putFirstZero // erste nachkommastelle ist 0
	mov r2, #1000
	udiv r0, r1, r2
	mul r2, r0, r2 // berechne volle tausender
	sub r4, r1, r2 // berechne rest
	bl uart_putByteBase10
	b handleDecile
putFirstZero:
	mov r4, r1
	mov r0, '0'
	bl uart_putChar
	
handleDecile:
	// restwert in r4
	cmp r4, #0
	beq putDegree // eine nachkommastelle ist ausgegeben, wenn es kein rest gibt ist die ausgabe fertig
	cmp r4, #100// vergleiche ob lsb * 10000 < 100 ist, da dann eine 0 eingefuegt werden muss
	blt putSecondZero // zweite nachkommastelle ist 0
	mov r2, #100
	udiv r0, r4, r2
	mul r2, r0, r2 // berechne volle hunderter
	sub r4, r4, r2
	bl uart_putByteBase10
	cmp r4, #0
	beq putDegree // zwei nachkommastellen sind ausgegeben, wenn es kein rest gibt ist die ausgabe fertig
	b handleThousandth
putSecondZero:
	mov r0, '0'
	bl uart_putChar
	
handleThousandth:
	cmp r4, #10// vergleiche ob lsb * 10000 < 10 ist, da dann eine 0 eingefuegt werden muss
	blt putThirdZero // dritte nachkommastelle ist 0
	mov r2, #10
	udiv r0, r4, r2
	mul r2, r0, r2 // berechne volle zehner
	sub r4, r4, r2
	bl uart_putByteBase10
	cmp r4, #0
	beq putDegree // drei nachkommastellen sind ausgegeben, wenn es kein rest gibt ist die ausgabe fertig
	b handleTenthousandth
putThirdZero:
	mov r0, '0'
	bl uart_putChar
	
handleTenthousandth:
	mov r0, r4
	bl uart_putByteBase10
	
putDegree:
	// gebe einheit aus und beginne schleife neu
	ldr r0, =str_grad
	bl uart_putString
	b read_temp


// r0: ds75 pointer location
// ausgabe byte in r0
.thumb_func
read_byte:
	push {r4, lr}
	mov r4, r0 // pointer in r4 speichern
	mov r0, #DS75_WRITE
	bl set_adress
	ldr r3, =I2C0
	strb r4, [r3, #I2C_D] // send pointer byte
	mov r4, r3 // basis adresse in r4
	bl wait_transfer_ready
	
	// setze Repeat Start
	ldr r0, =I2C0_C1_RSTA
	mov r1, #1
	strb r1, [r0]
	
	mov r1, #DS75_READ
	strb r1, [r4, #I2C_D]
	bl wait_transfer_ready
	
	mov r1, #0
	ldr r0, =I2C0_C1_TX
	strb r0, [r0] // wechsele zu rx
	mov r1, #1
	ldr r0, =I2C0_C1_TXAK // aktiviere NAK
	strb r1, [r0]
	ldrb r0, [r4, #I2C_D] // dummy read
	bl wait_transfer_ready
	bl stop_condition // beende uebertragung
	ldrb r0, [r4, #I2C_D] // lese byte aus
	pop {r4, pc}
	
	
// r0: ds75 pointer location
// r1: daten byte
.thumb_func
write_byte:
	push {r4, r5, lr}
	mov r4, r0 // pointer in r4 speichern
	mov r5, r1 // daten in r5 speichern
	mov r0, #DS75_WRITE
	bl set_adress // uebertragung fuer schreiben starten
	ldr r3, =I2C0
	strb r4, [r3, #I2C_D] // schicke pointer byte
	mov r4, r3 // basis adresse in r4
	bl wait_transfer_ready
	
	strb r5, [r4, #I2C_D] // schicke daten byte
	bl wait_transfer_ready
	bl stop_condition // beende uebertragung
	pop {r4, r5, pc}
	
	
// nutze aktuell ds75 pointer location
// ausgabe byte in r0
.thumb_func
read_2byte:
	push {r4, r5, lr}
	mov r0, #DS75_READ
	bl set_adress
	ldr r4, =I2C0 // basis adresse in r4
	mov r1, #0
	ldr r0, =I2C0_C1_TX
	strb r0, [r0] // wechsele zu rx
	ldrb r0, [r4, #I2C_D] // dummy read
	bl wait_transfer_ready
	ldrb r5, [r4, #I2C_D] // lese msb aus in r5
	bl wait_transfer_ready
	mov r1, #1
	ldr r0, =I2C0_C1_TXAK // aktiviere NAK
	strb r1, [r0]
	ldrb r4, [r4, #I2C_D] // lese lsb aus in r4
	bl wait_transfer_ready
	bl stop_condition // beende uebertragung
	orr r0, r4, r5, lsl #8
	pop {r4, r5, pc}
	
// r0: ds75 pointer location
// r1: msb
// r2: lsb
.thumb_func
write_2byte:
	push {r4, r5, r6, lr}
	mov r4, r0 // pointer in r4 speichern
	mov r5, r1 // msb in r5 speichern
	mov r6, r2 // lsb in r6 speichern
	mov r0, #DS75_WRITE
	bl set_adress // uebertragung fuer schreiben starten
	ldr r3, =I2C0
	strb r4, [r3, #I2C_D] // schicke pointer byte
	mov r4, r3 // basis adresse in r4
	bl wait_transfer_ready
	strb r5, [r4, #I2C_D] // schicke msb
	bl wait_transfer_ready
	strb r6, [r4, #I2C_D] // schicke lsb
	bl wait_transfer_ready
	bl stop_condition // beende uebertragung
	pop {r4, r5, r6, pc}


// r0: adresse mit r/w bit
.equ BIT_ACK, 1
.thumb_func
set_adress:
	push {lr}
	ldr r3, =I2C0
	mov r1, #I2C_C1_START
	// mst wiederholt setzen bis uebernommen
set_mst:
	strb r1, [r3, #I2C_C1]
	ldrb r2, [r3, #I2C_C1] // lese I2C0_C1
	cmp r1, r2
	bne set_mst
	// adresse setzen
	strb r0, [r3, #I2C_D]
	bl wait_transfer_ready // liefert I2C0_S in r0
	
	// gebe aus wenn kein ack empfangen wurde
	mov r1, #BIT_ACK
	ands r1, r0, r1
	beq ack_received
	ldr r0, =str_noack
	bl uart_putString
ack_received:
	pop {pc}

// warten bis interrupt gesetzt ist
// gibt I2C0_S in r0 zurueck
.equ BIT_IICIF, (1 << 1)
.equ BIT_ARBL, (1 << 4)
.thumb_func
wait_transfer_ready:
	push {r4, lr}
	ldr r0, =I2C0
	mov r1, #BIT_IICIF
	mov r2, #BIT_ARBL
wait_for_IICIF:
	ldrb r4, [r0, #I2C_S] // lese I2C0_S in r4
	ands r3, r4, r1 // ueberpruefe ob IICIF gesetzt ist
	beq wait_for_IICIF
	// IICIF gesetzt
	orr r3, r1, r2
	strb r3, [r0, #I2C_S] // IICIF und ARBL zuruecksetzen
	
	ands r3, r4, r2 // ueberpruefe ob arbitration lost
	beq transfer_ready
	ldr r0, =str_arbLost // gebe arbitration lost aus 
	bl uart_putString
transfer_ready:
	mov r0, r4 
	pop {r4, pc}
	

.equ BIT_BUSY, (1 << 5)
.thumb_func
stop_condition:
	push {lr}
	ldr r0, =I2C0
	mov r1, #I2C_C1_STOP
	strb r1, [r0, #I2C_C1]
	// warte bis bus busy weg ist
	mov r1, #BIT_BUSY
still_busy:
	ldrb r2, [r0, #I2C_S] // lese I2C0_S
	ands r3, r2, r1
	beq still_busy
	bl i2c_Delay
	pop {pc}

.equ WAIT_2US, 50
.thumb_func
i2c_Delay:
	push {r4, lr}
	bl pit3_getval
	ldr r2, =WAIT_2US
	sub r4, r0, r2
loop_delay:
	bl pit3_getval
	cmp r4, r0
	ble	loop_delay
	pop {r4, pc}

	
/***************** Konstantendeklarationen **********/
.equ SIM_SCGC5, 0x40048038
__BBREG SIM_PORTD, SIM_SCGC5, 12
.equ PORTD_PCR8, 0x4004C020
.equ PORTD_PCR9, 0x4004C024
.equ GPIOD_PDOR, 0x400FF0C0
.equ GPIOD_PDIR, 0x400FF0D0
.equ GPIOD_PDDR, 0x400FF0D4
.equ PD8_9, 0x300 // Maske fuer PD8 und PD9
.equ PD8, 0x100 // Maske fuer PD8
.equ ALT_GPIO, 0x100 // Alternative 1: GPIO
.equ ALT_I2C, 0x200 // Alternative 2: I2C
/***************** I2C - Bus zuruecksetzen ************/
.thumb_func
I2CBus_Reset:
	push {lr}
	
	ldr r0, =SIM_PORTD
	mov r1, #1
	str r1, [r0]
	ldr r0, =PORTD_PCR8
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	
	mov r3, #10
loop_i2c_reset:
	cmp r3, #0
	beq ret
	sub r3, r3, #1
	ldr r0, =GPIOD_PDOR
	ldr r2, [r0]
	bic r2, r2, #PD8
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDOR
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	bl i2c_Delay
	
	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9
	cmp r2, #PD8_9
	bne loop_i2c_reset
ret:
	ldr r0, =PORTD_PCR8
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_I2C
	str r2, [r0]
	str r2, [r1]
	pop {pc}


.equ SIM_SCGC6,	 	0x4004803C
.equ SCR_VTOR,		0xE000ED08		// Register für die Interrupt-Vektor-Tabelle (IVT)
.equ PIT_MCR,       0x40037000
.equ PIT_LDVAL1,    0x40037110
.equ PIT_TCTRL1,    0x40037118
.equ PIT_TFLG1,     0x4003711C
.equ NVIC_ISER2, 	0xe000e108
.equ NVIC_ICPR2, 	0xe000e288
.equ PIT1_IRQ_OFS,	0x154			// Interrupt Request Offset für PIT1
.equ PIT1_NVIC_MASK, 1 << (69 % 32)	// Bitposition für PIT-IRQ in NVIC-Registern (IRQ mod 32)
__BBREG BB_SIM_PIT, SIM_SCGC6, 23	// Bit-Band-Alias-Adresse für den PIT im SIM-Register
.equ PIT_COUNT, 25000000			// 25000000	Takte bei 25 MHz => 1 Sekunde
.equ PIT_MCR_VAL, 0					// MDIS = 0, FRZ = 0
.equ PIT_TCTRL1_VAL, 3				// CHN = 0, TIE = 1, TEN = 1
.thumb_func
pit1_init:
	ldr r0, =SCR_VTOR				// Basisadresse der IVT
	ldr r1, [r0]					// laden
	ldr r0, =isr_pit1				// ISR fuer den PIT1 
	str r0, [r1, #PIT1_IRQ_OFS]		// in die IVT eintragen
	
	ldr r0, =NVIC_ICPR2				// Pending (haengende) IRQs zu PIT1 im NVIC loeschen
	mov r1, #PIT1_NVIC_MASK			// Bit für PIT1-IRQ in den NVIC-Registern
	str r1, [r0]
	ldr r0, =NVIC_ISER2				// IRQs zu PIT1 im NVIC aktivieren
	str r1, [r0]					// R1 hat noch den Wert (PIT1_NVIC_MASK), also nicht neu laden

	ldr r0, =BB_SIM_PIT				// Bit-Band-Alias-Adresse fuer das Bit des PIT im SIM laden
	mov r1, #1						
	str r1, [r0]					// Clock fuer PIT1 aktivieren
	ldr r0, =PIT_MCR				
	mov r1, #PIT_MCR_VAL			// alle PITs einschalten, im Debug-Modus anhalten
	str r1, [r0]
	ldr r0, =PIT_LDVAL1				// initialen Zaehlwert setzen
	ldr r1, =PIT_COUNT 
	str r1, [r0]
	ldr r0, =PIT_TCTRL1
	mov r1, #PIT_TCTRL1_VAL			// PIT1: aktivieren, IRQs aktiv 
	str r1, [r0]
 	bx lr	
	
	
.thumb_func
isr_pit1:
	mov r1, #0x1
	ldr r0, =pit_flag				// Benutzerflag setzen
	str r1, [r0]
	ldr r0, =PIT_TFLG1				// TIF (Timer Interrupt Flag) loeschen
	str r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
pit_flag: .word 0
str_noack: .asciz "\nkein ACK empfangen"
str_arbLost: .asciz "\nArbitrierungsfehler"
str_hex: .asciz "\n0x"
str_grad: .asciz " Grad Celsius"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


.equ SIM_SCGC3, 0x40048030
.equ SIM_SCGC5, 0x40048038
__BBREG	SIM_SPI2, SIM_SCGC3, 12
__BBREG	SIM_PORTA, SIM_SCGC5, 9
__BBREG	SIM_PORTD, SIM_SCGC5, 12
__BBREG	SIM_PORTE, SIM_SCGC5, 13

.equ PORTA_PCR19, 0x4004904c
.equ PORTD_PCR12, 0x4004c030
.equ PORTD_PCR13, 0x4004c034
.equ PORTD_PCR14, 0x4004c038
.equ PORTD_PCR15, 0x4004c03c
.equ PORTE_PCR26, 0x4004d068

.equ GPIOA_PDDR, 0x400FF014
.equ GPIOE_PDDR, 0x400FF114
__BBREG	PDDR_SW1, GPIOA_PDDR, 19
__BBREG	PDDR_SW2, GPIOE_PDDR, 26
.equ GPIO_IRQ_PE_SET, 0xA0103 // GPIO-Modus, IRQ (fallende Flanke), Pull-Up-Widerstand

.equ PORT_ALT_SPI, 0x200 // Alternative 2: SPI

.equ NVIC_ISER2, 0xE000E108
.equ SCR_VTOR, 0xE000ED08
.equ NVIC_ISER2_MASK, 0x8800000 // Bit 27 (Port E), 23 (Port A)

// IVT-Offsets
.equ IVT_PTA, 0x19C
.equ IVT_PTE, 0x1AC

.equ RESOLUTIONINIT, 4 // 12 - offset 8
.equ RESOLUTIONMAX, 4
.equ RESOLUTIONMIN, 0 // 8 - offset 8

.equ SPI2_BASE, 0x400AC000
.equ SPIOFFSET_MCR, 0x0
.equ SPIOFFSET_TCR, 0x8
.equ SPIOFFSET_CTAR0, 0xC
.equ SPIOFFSET_CTAR1, 0x10
.equ SPIOFFSET_SR, 0x2C
.equ SPIOFFSET_PUSHR, 0x34
.equ SPIOFFSET_POPR, 0x38

.equ SPI_MCR_INIT, (1 << 0)
.equ SPI_MCR_DISABLE_FIFOS, (1 << 13) | (1 << 12) | (1 << 0)
.equ SPI_MCR_MASTER, (1 << 31) | (1 << 13) | (1 << 12) | (1 << 0)
__BBREG	MCR_HALT, (SPI2_BASE + SPIOFFSET_MCR), 0
__BBREG	SR_TCF, (SPI2_BASE + SPIOFFSET_SR), 31

.equ ADDR_WRITE_CFG, 0x8000

.equ CTAR0_16Bit, (0xf << 27) | (1 << 25) | (0x7 << 0)
.equ CTAR1_8Bit, (0x7 << 27) | (1 << 25) | (0x7 << 0)
.equ PUSHR_CFG, (1 << 17)
.equ PUSHR_TEMPADDR, (1 << 31) | (1 << 28) | (1 << 17) | 0x01
.equ PUSHR_TEMPLSB, (1 << 31) | (1 << 28) | (1 << 17)
.equ PUSHR_TEMPMSB, (1 << 28) | (1 << 17)

.equ LSB_TIMES_10000, 625
.equ BIGCOUNTERVAL, 0x70000000

.equ DS1722CFG, (0xe << 4)

__BBREG	SW1_CIF, PORTA_PCR19, 24
__BBREG	SW2_CIF, PORTE_PCR26, 24

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init // pit zaehlt rueckwaerts
	
	// Takt fuer die benutzten Module aktivieren
	mov r1, #1
	ldr r0, =SIM_SPI2
	str r1, [r0]
	ldr r0, =SIM_PORTA
	str r1, [r0]
	ldr r0, =SIM_PORTD
	str r1, [r0]
	ldr r0, =SIM_PORTE
	str r1, [r0]
	
	// GPIOA-Pin und GPIOE-Pin konfigurieren
	ldr r1, =GPIO_IRQ_PE_SET // GPIO-Modus mit IRQ (fallende Flanke) und Pull-Up-Widerstand 	
	ldr r0, =PORTA_PCR19 // fuer SW1
	str r1, [r0]	
	ldr r0, =PORTE_PCR26 // fuer SW2
	str r1, [r0]
	// SPI ausgaenge konfigurierien
	mov r1, # PORT_ALT_SPI
	ldr r0, =PORTD_PCR12
	str r1, [r0]
	ldr r0, =PORTD_PCR13
	str r1, [r0]
	ldr r0, =PORTD_PCR14
	str r1, [r0]
	ldr r0, =PORTD_PCR15
	str r1, [r0]
	
	// Datenrichtung der GPIO-Pins festlegen
	// Eingaenge (SW1 und SW2)
	mov r1, #0
	ldr r0, =PDDR_SW1
	str r1, [r0]
	ldr r0, =PDDR_SW2
	str r1, [r0]
	
	// Adressen der ISRs fuer Port A und Port E in die IVT eintragen
	ldr r0, =SCR_VTOR
	ldr r1, [r0]
	ldr r0, =isr_port_a
	str r0, [r1, #IVT_PTA]
	ldr r0, =isr_port_e
	str r0, [r1, #IVT_PTE]
	
	// NVIC-Bitmaske fuer Port A und Port E setzen
	ldr r0, =NVIC_ISER2
	ldr r1, =NVIC_ISER2_MASK
	str r1, [r0]
	
	ldr r12, =resolution_up
	ldr r11, =resolution_down
	mov r10, #RESOLUTIONINIT // neue aufloesung
	ldr r9, =SPI2_BASE
	ldr r8, =MCR_HALT
	mov r7, #0 // aktuelle aufloesung
	mov r6, #0 // temperaturwert msb
	mov r5, #0 // temperaturwert lsb
	
	// SPI modul in halt starten
	ldr r0, =SPI_MCR_INIT
	str r0, [r9, #SPIOFFSET_MCR]
	ldr r0, =SPI_MCR_DISABLE_FIFOS
	str r0, [r9, #SPIOFFSET_MCR]
	ldr r0, =SPI_MCR_MASTER
	str r0, [r9, #SPIOFFSET_MCR]
	
	ldr r0, =CTAR0_16Bit
	str r0, [r9, #SPIOFFSET_CTAR0]
	ldr r0, =CTAR1_8Bit
	str r0, [r9, #SPIOFFSET_CTAR1]
	
	mov r1, #0
	str r1, [r8] // starte transfer mode
	
loop:
	cmp r7, r10
	beq wait_for_meas
	
	// aufloesung anpassen
	mov r0, r10
	bl set_resolution
	mov r7, r10
	
	// warten bis temperaturwandlung fertig ist, erster next_timevalue wird in set_resolution gesetzt
	// 32 bit counter reicht bei 1,2s wandlung nur knapp ueber eine minute -> wrap handling
wait_for_meas:
	ldr r5, =next_timevalue
	ldr r4, [r5]
loop_wait:
	bl pit3_getval
	cmp r4, r0 // warte bis zeitpunkt in r4 groeßer aktuelle zeit in r0 ist
	blo	check_missed
	b check_valid
	
check_missed:
	// wenn r4 viel kleiner als r0 ist, haben hat pit resetet bevor wir ueberprueft haben
	sub r2, r0, r4
	cmp r2, #BIGCOUNTERVAL
	bhi wait_end // zeitpunkt wurde zwischenzeitlich erreicht
	b loop_wait // weiter warte auf zeitpunkt
	
check_valid:
	// wenn r0 viel kleiner als r4 ist, gab es einen ueberlauf beim berechnen des zeitpunkts
	sub r2, r4, r0
	cmp r2, #BIGCOUNTERVAL
	bhi loop_wait // zeitpunkt nicht wirklich erreicht
	
wait_end:
	// berechne neues next_timevalue
	ldr r0, =wait_times
	mov r1, r7 // wait_times offset ist aufloesung (0-4) * 4
	lsl r1, r1, #2
	ldr r2, [r0, r1]
	sub r4, r4, r2 // next_timevalue updaten
	str r4, [r5]
	
	// temperatur auslesen
    ldr r1, =PUSHR_TEMPADDR
	str r1, [r9, #SPIOFFSET_PUSHR]
	ldr r3, =SR_TCF
check_tcf_addr:
	ldr r1, [r3]
	cmp r1, #0
	beq check_tcf_addr
	ldr r1, [r9, #SPIOFFSET_POPR] // dummy read
	mov r1, #1
	str r1, [r3] // transfer complete flag loeschen

	ldr r1, =PUSHR_TEMPLSB
	str r1, [r9, #SPIOFFSET_PUSHR]
check_tcf_lsb:
	ldr r1, [r3]
	cmp r1, #0
	beq check_tcf_lsb
	ldr r5, [r9, #SPIOFFSET_POPR] // lsb auslesen
	mov r1, #1
	str r1, [r3] // transfer complete flag loeschen
	
	ldr r1, =PUSHR_TEMPMSB
	str r1, [r9, #SPIOFFSET_PUSHR]
check_tcf_msb:
	ldr r1, [r3]
	cmp r1, #0
	beq check_tcf_msb
	ldr r6, [r9, #SPIOFFSET_POPR] // msb auslesen
	mov r1, #1
	str r1, [r3] // transfer complete flag loeschen	

// temperatur aus r6 und r5 ausgeben
    mov r0, r6
	bl uart_putByteBase10 // gebe volle grad werte aus
	ldr r0, =str_temp // adresse template fuer nachkommastellen
	ldr r1, =LSB_TIMES_10000
	lsr r5, r5, #4
	mul r1, r1, r5
	mov r3, #1000
	udiv r2, r1, r3 // r2 sind tausender
	add r4, r2, #'0' // wandlung zum char
	strb r4, [r0, #1] // tausender in string schreiben
	mul r2, r2, r3
	sub r1, r1, r2 // hunderter rest in r1
	mov r3, #100
	udiv r2, r1, r3 // r2 sind hunderter
	add r4, r2, #'0' // wandlung zum char
	strb r4, [r0, #2] // hunderter in string schreiben
	mul r2, r2, r3
	sub r1, r1, r2 // zehner rest in r1
	mov r3, #10
	udiv r2, r1, r3 // r2 sind zehner
	add r4, r2, #'0' // wandlung zum char
	strb r4, [r0, #3] // zehner in string schreiben
	mul r2, r2, r3
	sub r1, r1, r2 // rest in r1
	add r4, r1, #'0' // wandlung zum char
	strb r4, [r0, #4] // restziffer in string schreiben
	bl uart_putString// ausgabe
	

// switch handling
	ldr r0, [r12]
	cmp r0, #1 // ueberpruefe ob sw1 isr ausgeloest hat
	bne resolutionUpHandled
	mov r0, #0
	str r0, [r12] // zuruecksetzen von resolution_up
	ldr r0, =str_res_up
	bl uart_putString
	// aufloesung erhoehen und auf 8-12 bits mappen
	add r10, r10, #1
	cmp r10, #RESOLUTIONMAX
	it gt
	movgt r10, #RESOLUTIONMIN
	add r0, r10, #8 // aufloesung wird in r10 ohne 8bit offset gespeichert
	bl uart_putByteBase10 // aufloesung ausgeben
	ldr r0, =str_bits
	bl uart_putString
resolutionUpHandled:
    ldr r0, [r11]
	cmp r0, #1 // ueberpruefe ob sw2 isr ausgeloest hat
	bne resolutionDownHandled
	mov r0, #0
	str r0, [r11] // zuruecksetzen von resolution_down
	ldr r0, =str_res_down
	bl uart_putString
	// aufloesung verringern und auf 8-12 bits mappen
	sub r10, r10, #1
	cmp r10, #RESOLUTIONMIN
	it lt
	movlt r10, #RESOLUTIONMAX
	add r0, r10, #8 // aufloesung wird in r10 ohne 8bit offset gespeichert
	bl uart_putByteBase10 // aufloesung ausgeben
	ldr r0, =str_bits
	bl uart_putString
resolutionDownHandled:
    b loop
	
	
// r0: aufloesung - 8bit
.thumb_func
set_resolution:
    push {r4, lr}
    mov r4, r0 // aufloesung in r4 sichern
	lsl r2, r0, #1 // aufloesung an richtige stelle fuer verodern schieben
	orr r0, r2, #DS1722CFG // neuer cfg wert
	ldr r2, =SPI2_BASE
	ldr r3, =SR_TCF
	mov r1, #1
	str r1, [r3] // transfer complete flag loeschen
	// schreibe PUSHR headar + addresse + cfg
	orr r1, r0, #ADDR_WRITE_CFG // 0x80 cfg write adresse setzen
	orr r1, r1, #PUSHR_CFG // PCS setzen
	str r1, [r2, #SPIOFFSET_PUSHR]
check_tcf_res:
	ldr r1, [r3]
	cmp r1, #0
	beq check_tcf_res
	ldr r0, [r2, #SPIOFFSET_POPR] // dummy read
	mov r1, #1
	str r1, [r3] // transfer complete flag loeschen	

// next_timevalue fuer wandlungszeit setzen
	bl pit3_getval
	// berechne neues next_timevalue
	ldr r3, =wait_times
	lsl r1, r4, #2
	ldr r2, [r3, r1]
	sub r4, r0, r2 // next_timevalue = aktuelle zeit - wartezeit
	ldr r0, =next_timevalue
	str r4, [r0]
	pop {r4, pc}
	
	
// ISR fuer SW1 (Port A)
// wir haben nur sw1 am port A und ein interrupt kann nur vom schalter kommen
.thumb_func 
isr_port_a:
	ldr r0, =SW1_CIF // Bit-Band-Adresse des Interrupt-Flags fuer SW1
	mov r1, #1
	str r1, [r0] // Flag loeschen
	ldr r0, =resolution_up
	str r1, [r0] // flag setzen
	bx lr
	

// ISR fuer SW2 (Port E)
// wir haben nur sw2 am port E und ein interrupt kann nur vom schalter kommen
.thumb_func
isr_port_e:
	ldr r0, =SW2_CIF // Bit-Band-Adresse des Interrupt-Flags fuer SW2
	mov r1, #1
	str r1, [r0] // Flag loeschen
	ldr r0, =resolution_down
	str r1, [r0] // flag setzen
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
resolution_up: .word 0x00
resolution_down: .word 0x00
next_timevalue: .word 0x00
wait_times: .word 1875000, 3750000, 7500000, 15000000, 30000000
str_res_up: .asciz "\nAufloesung vergroessern: "
str_res_down: .asciz "\nAufloesung verringern: "
str_bits: .asciz "bits\n"
str_grad: .asciz " gC\n"
str_temp: .asciz ",0000 gC\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

__BBREG BB_SIM_SCGC6_RTC, 0x4004803C, 29

.equ RTC_BASE, 0x4003D000
.equ RTC_TSR, 0x0
.equ RTC_TPR, 0x4
.equ RTC_TAR, 0x8
.equ RTC_CR, 0x10
.equ RTC_SR, 0x14

__BBREG SR_TAF, (RTC_BASE + RTC_SR), 2

.equ CR_OSCE, (1 << 8)
.equ SR_TCE, (1 << 4)
.equ TAR_DAY, (3600 * 24 - 1)
.equ TAR_HOUR, (3600 - 1)
.equ PRESET_DAY, (3600 * 24 - 5)
.equ PRESET_HOUR, (3600 - 5)

.equ OSC_WAIT, 0x1000000

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// RTC aktivieren
	ldr r0, =BB_SIM_SCGC6_RTC
	mov r1, #1
	str r1, [r0]
	
	ldr r12, =RTC_BASE
	mov r11, #0 // sekunden wert
	mov r10, #0 // mode: 0: 24h 1: 1h
	ldr r9, =SR_TAF
	mov r7, #1 // anzeige an
	
	// etwas warten, bis der oszillator eingeschwungen ist
	mov r0, #CR_OSCE
	str r0, [r12, #RTC_CR]
	mov r0, #OSC_WAIT
wait_osc:
	subs r0, r0, #1
	bne wait_osc
	
	// Alarmregister setzen
	ldr r0, =TAR_DAY
	str r0, [r12, #RTC_TAR]
	
	// counter auf 0 reseten 
	mov r0, #0
	bl reset
	
loop:
	ldr r0, [r9]
	cbz r0, wait_sec
	// Alarm gesetzt
	//mov r0, #0
	//str r0, [r9]
	cmp r10, #0
	ite eq
	ldreq r0, =TAR_DAY
	ldrne r0, =TAR_HOUR
	str r0, [r12, #RTC_TAR]
	ldr r0, =str_endzeitpunkt
	bl uart_putString
	
wait_sec:
	ldr r0, [r12, #RTC_TSR]
	cmp r0, r11 // aktuelle sekunde auslesen und mit letzter vergleichen
	beq check_char
	mov r11, r0 // r11 mit der neuen sekunde updaten
	
	cbz r7, check_char
	mov r1, r10 // mode setzen, sekundenwert steht noch in r0
	bl disp_time
	

	// terminal auswertung
check_char:
	bl	uart_charPresent // wurde ein Zeichen eingegeben?
	cbnz r0, check_input // ja, pruefen
	b loop

check_input:
	bl uart_getChar // eingegebenes Zeichen einlesen
	cmp	r0, #'d'
	bne check_h
	// day empfangen
	mov r0, #0
	bl reset
	ldr r0, =TAR_DAY
	str r0, [r12, #RTC_TAR]
	mov r10, #0
	ldr r0, =str_modus_24h
	bl uart_putString
	b loop
	
check_h:
	cmp	r0, #'h'
	bne check_r
	// hour empfangen
	mov r0, #0
	bl reset
	ldr r0, =TAR_HOUR
	str r0, [r12, #RTC_TAR]
	mov r10, #1
	ldr r0, =str_modus_1h
	bl uart_putString
	b loop
	
check_r:
	cmp	r0, #'r'
	bne check_s
	// reset empfangen
	mov r0, #0
	bl reset
	b loop
	
check_s:
	cmp	r0, #'s'
	bne check_p
	// start/stop empfangen
	eors r7, r7, #1 // ausgabe toggeln
	ite eq
	ldreq r0, =str_anzeige_aus
	ldrne r0, =str_anzeige_an
	bl uart_putString
	b loop
	
check_p:
	cmp	r0, #'p'
	bne loop
	// preset empfangen
	cmp r10, #0
	ite eq
	ldreq r0, =PRESET_DAY
	ldrne r0, =PRESET_HOUR
	bl reset
	b loop
	
	
.thumb_func
// r0: counter wert
reset:
	push {lr}
	ldr r3, =RTC_BASE
	mov r1, #0
	str r1, [r3, #RTC_SR] // time counter ausschalten
	str r0, [r3, #RTC_TSR] // counter reseten
	mov r1, #SR_TCE
	str r1, [r3, #RTC_SR] // time counter einschalten
	cmp r0, #0
	bne reset_end // bei preset nichts ausgeben
	ldr r0, =str_reset
	bl uart_putString
reset_end:
	pop {pc}
	
	
.thumb_func
// r0: sekundenwert
// r1: mode: 0: 24h 1: 1h
disp_time:
	push {r4, r5, lr}
	mov r4, r0
	mov r0, #'\n' // Zeilenumbruch
	bl uart_putChar
	mov r3, #3600 // lade sekunden einer stunde
	udiv r0, r4, r3 // stunde berechnen
	mul r2, r0, r3
	sub r4, r4, r2 // sekundenrest berechnen
	cbnz r1, handle_min
	// auf 23 begrenze
check_in_day:
	cmp r0, #23
	it hi
	subhi r0, r0, #24
	bhi check_in_day
	cmp r0, #10
	bhs disp_hour
	// null einfuegen
	mov r5, r0
	mov r0, #'0'
	bl uart_putChar
	mov r0, r5
disp_hour:
	bl uart_putByteBase10 // stunde ausgeben
	mov r0, #':'
	bl uart_putChar
handle_min:
	mov r1, #60 // lade sekunden einer minute
	udiv r0, r4, r1 // minute berechnen
	mul r2, r0, r1
	sub r4, r4, r2 // sekundenrest berechnen
	cmp r0, #10
	bhs disp_min
	// null einfuegen
	mov r5, r0
	mov r0, #'0'
	bl uart_putChar
	mov r0, r5
disp_min:
	bl uart_putByteBase10 // minute ausgeben
	mov r0, #':'
	bl uart_putChar
	mov r0, r4
	cmp r0, #10
	bhs disp_sec
	// null einfuegen
	mov r5, r0
	mov r0, #'0'
	bl uart_putChar
	mov r0, r5
disp_sec:
	bl uart_putByteBase10 // sekunde ausgeben

	pop {r4, r5, pc}
	

/*** Datenbereich (ab 0x20000000) ***/
.data
str_anzeige_an: .asciz "\nAnzeige an"
str_anzeige_aus: .asciz "\nAnzeige aus"
str_modus_24h: .asciz "\n24-Stunden-Modus"
str_modus_1h: .asciz "\n1-Stunden-Modus"
str_reset: .asciz "\nUhr zurueckgesetzt"
str_endzeitpunkt: .asciz "\nEndzeitpunkt erreicht"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

__BBREG	BB_SIM_PORTA, 0x40048038, 9
__BBREG BB_SIM_SCGC6_RTC, 0x4004803C, 29
__BBREG	BB_SIM_SCGC6_PIT, 0x4004803C, 23

__BBREG	BB_LED_OUT, 0x400FF000, 10
__BBREG	BB_GPIO_OUT, 0x400FF000, 6

.equ RTC_BASE, 0x4003D000
.equ RTC_TSR, 0x0
.equ RTC_CR, 0x10
.equ RTC_SR, 0x14

__BBREG SR_TAF, (RTC_BASE + RTC_SR), 2

.equ CR_OSCE, (1 << 8)
.equ SR_TCE, (1 << 4)
.equ LASTSEC, 59
.equ MIN_IN_HOUR, 60
.equ HOURS_IN_DAY, 24
.equ MONTHS_IN_YEAR, 12
.equ MAX_WEEKDAY, 7
.equ OFFSET_DAY, 5
.equ OFFSET_MONTH, 8
.equ OFFSET_YEAR, 11
.equ OFFSET_HOUR, 14
.equ OFFSET_MINUTE, 17 

.equ OSC_WAIT, 0x1000000

.equ PIT_BASE, 0x40037000
.equ PIT_MCR, 0x0
.equ PIT_LDVAL0, 0x100
.equ PIT_TCTRL0, 0x108
.equ PIT_TFLG0, 0x10C

.equ MCR_INIT, 0x1
.equ LDVAL_ZERO, (25000000 / 1000 * 100)
.equ LDVAL_ONE, (25000000 / 1000 * 200)
.equ TCTRL_ON, 0x1
.equ TCTRL_OFF, 0x0

.equ GPIOA_PDDR, 0x400FF014

.equ PDDR_MASK_OUT, (1<<6 | 1<<10)	// Maske fuer die Ausgaenge
.equ GPIO_SET, 0x120 // GPIO-Modus, Open-Drain

.equ PORTA_PCR0, 0x40049000 // Start-Adresse der Port A PCR-Register
.equ PCR6, 0x18 // GPIO
.equ PCR10, 0x28 // LED

.equ BEGIN_TIME, (1<<20)

.equ BITS_MINUTE, 7
.equ BITS_HOUR, 6
.equ BITS_DAY, 6
.equ BITS_WDAY, 3
.equ BITS_MONTH, 5
.equ BITS_YEAR, 8
.equ BITS_DATE, 22
.equ SHIFT_MINUTE, 21
.equ SHIFT_HOUR_LOW, 29
.equ SHIFT_HOUR_HIGH, 3
.equ SHIFT_DAY, 4
.equ SHIFT_WDAY, 10
.equ SHIFT_MONTH, 13
.equ SHIFT_YEAR, 18

// terminal eingabe
// erst T,M,h,m eingeben
// dann passenden wert mit 2 stellen eingeben (kein plausibilitaetstest)

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	// module aktivieren
	mov r1, #1
	ldr r0, =BB_SIM_PORTA
	str r1, [r0]
	ldr r0, =BB_SIM_SCGC6_RTC
	str r1, [r0]
	ldr r0, =BB_SIM_SCGC6_PIT
	str r1, [r0]
	
	// verwendete register	
	ldr r12, =RTC_BASE
	mov r11, #0 // rtcwert
	mov r10, #0 // ausgangswort fuer minute high
	mov r9, #0 // ausgangswort fuer minute low
	mov r8, #0 // sekundenwert
	mov r7, #0 // ausgangsbit
	ldr r6, =PIT_BASE
	
	// RTC aktivieren
	mov r0, #0
	str r0, [r12, #RTC_SR] // time counter ausschalten
	str r0, [r12, #RTC_TSR] // counter reseten
	
	// etwas warten, bis der oszillator eingeschwungen ist
	mov r0, #CR_OSCE
	str r0, [r12, #RTC_CR]
	mov r0, #OSC_WAIT
wait_osc:
	subs r0, r0, #1
	bne wait_osc
	
	// ausgaenge aktivieren
	ldr r0, =GPIOA_PDDR
	ldr r1, =PDDR_MASK_OUT
	ldr r2, [r0]
	orr	r2, r2, r1
	str r2, [r0]
	
	ldr r0, =PORTA_PCR0 // Startadresse der Port A PCR-Register
	mov r1, #GPIO_SET // GPIO-Modus festlegen
 	str r1, [r0, #PCR10] // LED
 	str r1, [r0, #PCR6] // GPIO
 	
 	// ausgang hoch setzen
	mov r0, #0
	bl set_output
	
	// PIT clock aktivieren
	mov r0, #MCR_INIT
	str r0, [r6, #PIT_MCR]
	
	// RTC einschalten
	mov r1, #SR_TCE
	str r1, [r12, #RTC_SR] // time counter einschalten
	
loop_minute:
	// berechnen des signals
	bl inc_minute
	ldr r0, =signal_low // ausgangswort fuer minute low
	ldr r1, =signal_high // ausgangswort fuer minute high	
	ldr r9, [r0]
	ldr r10, [r1]

loop_sec:
	// bestimmen des naechsten ausgangsbits
	cmp r8, #32
	ittee hs
	subhs r0, r8, #32
	movhs r1, r10 // hohes wort
	movlo r0, r8
	movlo r1, r9 // niedriges wort
	
	lsr r0, r1, r0 // ausgabewert mit sekunden verschieben
	ands r0, r0, #1 // waehle bit0
	ittee eq
	ldreq r0, =LDVAL_ZERO
	moveq r7, #0
	ldrne r0, =LDVAL_ONE
	movne r7, #1
	str r0, [r6, #PIT_LDVAL0] // pit mit entsprechender zeit laden
	mov r0, #1
	str r0, [r6, #PIT_TFLG0] // TIF zuruecksetzen
	
	// warten auf rtc
wait_sec:
	ldr r0, [r12, #RTC_TSR]
	cmp r0, r11 // aktuelle sekunde auslesen und mit letzter vergleichen
	beq wait_sec
	mov r11, r0 // r11 mit der neuen sekunde updaten
	
	// starten des pit
	mov r0, #TCTRL_ON
	str r0, [r6, #PIT_TCTRL0]
	
	// ausgang runter oder neue minute (ausgang hoch lassen)	
	cmp r8, #LASTSEC
	itet hs
	movhs r8, #0 // sekunde zuruecksetzen
	addlo r8, r8, #1 // sekunde inkrementieren
	bhs wait_pit // ausgang bleibt oben

	// ausgang runter setzen
	mov r0, #1
	bl set_output
	
	add r0, r7, #'0'
	bl uart_putChar // aktuelles bit ausgeben
	cmp r8, #LASTSEC
	bne wait_pit
	mov r0, #'\n'
	bl uart_putChar
	
	// warten auf pit
wait_pit:
	ldr r0, [r6, #PIT_TFLG0]
	cmp r0, #1
	bne wait_pit
	
	// ausgang hoch setzen
	mov r0, #0
	bl set_output
	
	// stoppen des pit
	mov r0, #TCTRL_OFF
	str r0, [r6, #PIT_TCTRL0]
	
	// terminal auswertung
	bl uart_charPresent // wurde ein Zeichen eingegeben?
	cbnz r0, check_day // ja, pruefen
	b continue_loop
check_day:
	bl uart_getChar // eingegebenes Zeichen einlesen
	cmp	r0, #'T' // monatstag lesen
	bne check_month
	bl uart_getByteBase10
	ldr r1, =tag
	str r0, [r1]
	b continue_loop
check_month:
	cmp	r0, #'M' // monat lesen
	bne check_hour
	bl uart_getByteBase10
	ldr r1, =monat
	str r0, [r1]
	b continue_loop
check_hour:
	cmp	r0, #'h' // stunde lesen
	bne check_minute
	bl uart_getByteBase10
	ldr r1, =stunde
	str r0, [r1]
	b continue_loop
check_minute:
	cmp	r0, #'m' // minute lesen
	bne continue_loop
	bl uart_getByteBase10
	ldr r1, =minute
	str r0, [r1]

continue_loop:
	cmp r8, #0
	beq loop_minute // naechste minute beginnt
	b loop_sec
	

// minute hochzaehlen
.thumb_func
inc_minute:
	push {r4, r7-r12, lr}
	ldr r12, =minute
	ldr r11, =stunde
	ldr r10, =tag
	ldr r9, =wtag
	ldr r8, =monat
	ldr r7, =jahr
	// minute inkrementieren
	ldr r0, [r12]
	add r0, r0, #1
	str r0, [r12]
	cmp r0, #MIN_IN_HOUR
	blo build_output
	// neue stunde
	mov r0, #0
	str r0, [r12] // minute auf 0
	ldr r0, [r11]
	add r0, r0, #1
	str r0, [r11]
	cmp r0, #HOURS_IN_DAY
	blo build_output
	// neuer tag
	mov r0, #0
	str r0, [r11] // stunde auf 0
	// wochentag
	ldr r0, [r9]
	add r0, r0, #1
	cmp r0, #MAX_WEEKDAY
	it hs
	movhs r0, #0 // auf montag setzen
	str r0, [r9]
	// monatstag
	ldr r0, [r10]
	add r0, r0, #1
	str r0, [r10]
	cmp r0, #31 // todo max_monatstage
	blo build_output
	// neuer monat
	mov r0, #1
	str r0, [r10] // tag auf monatsersten
	ldr r0, [r8]
	add r0, r0, #1
	str r0, [r8]
	cmp r0, #MONTHS_IN_YEAR
	blo build_output
	// neues jahr
	mov r0, #1
	str r0, [r8] // monat auf januar
	ldr r0, [r7]
	add r0, r0, #1
	str r0, [r7]	
build_output:
	// baue unteres wort in r4
	mov r4, #BEGIN_TIME
	ldr r0, [r12] // lade minuten
	mov r1, #BITS_MINUTE
	bl get_bits
	mov r1, #BITS_MINUTE
	bl set_parity
	orr r4, r4, r0, lsl #SHIFT_MINUTE
	ldr r0, [r11] // lade stunden
	mov r1, #BITS_HOUR
	bl get_bits
	mov r1, #BITS_HOUR
	bl set_parity
	orr r4, r4, r0, lsl #SHIFT_HOUR_LOW
	ldr r1, =signal_low
	str r4, [r1] // unteres wort speichern
	// baue oberes wort in r4
	lsr r4, r0, #SHIFT_HOUR_HIGH
	ldr r0, [r10] // lade tag
	mov r1, #BITS_DAY
	bl get_bits
	orr r4, r4, r0, lsl #SHIFT_DAY
	ldr r0, [r9] // lade wochentag
	mov r1, #BITS_WDAY
	bl get_bits
	orr r4, r4, r0, lsl #SHIFT_WDAY
	ldr r0, [r8] // lade monat
	mov r1, #BITS_MONTH
	bl get_bits
	orr r4, r4, r0, lsl #SHIFT_MONTH
	ldr r0, [r7] // lade jahr
	mov r1, #BITS_YEAR
	bl get_bits
	orr r4, r4, r0, lsl #SHIFT_YEAR
	// datum paritaet
	mov r0, r4, lsr #SHIFT_DAY
	mov r1, #BITS_DATE
	bl set_parity
	orr r4, r4, r0, lsl #SHIFT_DAY
	ldr r0, =signal_high
	str r4, [r0] // oberes wort speichern

print_output:
	ldr r0, =datum
	ldr r1, =str_wtag
	ldr r2, [r9]
	lsl r2, r2, #1
	ldrh r2, [r1, r2] // wochentag laden
	strh r2, [r0] // wochentag in datum schreiben
	ldr r2, [r10] // tag laden
	mov r9, r0 // addresse datum in r9 sichern
	mov r1, #OFFSET_DAY
	bl write_2byte // tag schreiben
	mov r0, r9
	mov r1, #OFFSET_MONTH
	ldr r2, [r8]
	bl write_2byte // monat schreiben
	mov r0, r9
	mov r1, #OFFSET_YEAR
	ldr r2, [r7]
	bl write_2byte // jahr schreiben
	mov r0, r9
	mov r1, #OFFSET_HOUR
	ldr r2, [r11]
	bl write_2byte // stunde schreiben
	mov r0, r9
	mov r1, #OFFSET_MINUTE
	ldr r2, [r12]
	bl write_2byte // minute schreiben
	mov r0, r9
	bl uart_putString
	pop {r4, r7-r12, pc}
	
	
.thumb_func
// r0: wert
// r1: anzahl bits
// ret: signalbits fuer wert
get_bits:
	push {r4, r5, lr}
	ldr r5, =bit_werte
	mov r4, #0 // ausgang initialisieren
next_bit:
	cmp r1, #0
	beq ret_get_bits
	sub r1, r1, #1 // anzahl bits verringern
	ldrb r2, [r5, r1] // lade vergleichswert fuer bit
	cmp r0, r2
	blo next_bit
	// setze bit
	mov r3, #1
	lsl r3, r3, r1
	orr r4, r4, r3
	sub r0, r0, r2 // ziehe wert fuer gesetztes bit ab
	b next_bit
ret_get_bits:
	mov r0, r4
	pop {r4, r5, pc}

.thumb_func
// r0: wert
// r1: anzahl bits vor paritaet
// ret: wert mit paritaetsbit davor
set_parity:
	push {r4, lr}
	mov r4, r0 // wert kopieren
	mov r3, #0 // paritaet
	mov r2, #0 // bit zaehler
shift:
	cmp r1, r2
	beq ret_parity
	eor r3, r3, r0
	lsr r0, r0, #1 // wert verschieben
	add r2, r2, #1 // naechstes bit
	b shift
ret_parity:
	ands r3, r3, #1 // betrachte bit0
	itte ne // paritaetsbit setzen
	lslne r3, r3, r1
	orrne r0, r4, r3
	moveq r0, r4
	pop {r4, pc}


.thumb_func
// r0: basis addresse
// r1: offset
// r2: daten
write_2byte:
	push {lr}
	mov r4, #100
	// jahrhunderte abziehen
	udiv r3, r2, r4
	mul r3, r3, r4 // r3 sind ganze hunderter
	sub r2, r2, r3
	cmp r2, #10
	blo write_zero // r2 ist 0-9
	mov r4, #10
	udiv r3, r2, r4 // r3 sind ganze zehner
	mul r4, r3, r4
	add r3, r3, #'0'
	strb r3, [r0, r1]
	sub r2, r2, r4 // zehner von r2 abziehen
	b write_digit
write_zero:
	mov r3, #'0'
	strb r3, [r0, r1]
write_digit:
	add r1, r1, #1 // offset anpassen
	add r3, r2, #'0'
	strb r3, [r0, r1]
	pop {pc}

.thumb_func
set_output:
	ldr r1, =BB_GPIO_OUT // Bit-Band-Alias-Adresse der GPIO laden 
	str r0, [r1] // Bit auf GPIO ausgeben
	ldr r1, =BB_LED_OUT // Bit-Band-Alias-Adresse der LED laden 
	str r0, [r1] // Bit auf LED ausgeben
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
minute: .word 0
stunde: .word 0
tag: .word 1
wtag: .word 0
monat: .word 1
jahr: .word 23
signal_low: .word 0
signal_high: .word 0
bit_werte: .byte 1, 2, 4, 8, 10, 20, 40, 80
datum: .asciz "XX., XX.XX.XX XX:XX Uhr\n"
str_wtag: .asciz "MoDiMiDoFrSaSo"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

__BBREG	BB_SIM_PORTA, 0x40048038, 9
__BBREG	BB_SIM_FTM0, 0x4004803C, 24

.equ GPIOA_PDDR, 0x400FF014
.equ PDDR_MASK_OUT, (1<<6 | 1<<10) // Maske fuer Ausgang
.equ GPIO_SET, 0x120 // GPIO-Modus, Open-Drain

.equ PORTA_PCR0, 0x40049000 // Start-Adresse der Port A PCR-Register
.equ PCROUT, 0x18 // GPIO
__BBREG	BB_GPIO_OUT, 0x400FF000, 6
//.equ PCROUT, 0x28 // LED
//__BBREG	BB_GPIO_OUT, 0x400FF000, 10

.equ FTM0_BASE, 0x40038000
.equ FTM0_SC, 0x0
.equ FTM0_CNT, 0x4
.equ FTM0_MOD, 0x8
.equ FTM0_C3SC, 0x24
.equ FTM0_C3V, 0x28

.equ SC_INIT, (1 << 6) | (1 << 3) // | 7
.equ C3SC_INIT, (1 << 6) | (2 << 4) | (2 << 2)
.equ MOD_INIT, 25000
 //.equ MOD_INIT, 0xffff
.equ SC_TOF, (1 << 7)
.equ C3SC_CHF, (1 << 7)

.equ C3V_5PERCENT, MOD_INIT / 20
.equ C3V_10PERCENT, MOD_INIT / 10

.equ ISR_TABLE, 0x1FFFFE00
.equ ISR_FTM0, 0x138 // irq62
.equ FTM0_BIT30, (1<<30)// irq62 mod 32, bit 30 als maske
.equ NVIC_ISER1, 0xE000E104 // intr set enable
.equ NVIC_ICPR1, 0xE000E284 // intr clear pending


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	bl uart_init
	
	// module aktivieren
	mov r1, #1
	ldr r0, =BB_SIM_PORTA
	str r1, [r0]
	ldr r0, =BB_SIM_FTM0
	str r1, [r0]
	
	// ausgaenge aktivieren
	ldr r0, =GPIOA_PDDR
	ldr r1, =PDDR_MASK_OUT
	ldr r2, [r0]
	orr	r2, r2, r1
	str r2, [r0]
	
	ldr r0, =PORTA_PCR0 // Startadresse der Port A PCR-Register
	mov r1, #GPIO_SET // GPIO-Modus festlegen
 	str r1, [r0, #PCROUT]
 	
 	// interrupt vektor setzen
	ldr r0, =ISR_TABLE
	ldr r1, =ftm0_isr
	str r1, [r0, #ISR_FTM0] // ftm0 interrupt
 	
 	// pending interrupt1 loeschen
	ldr r0, =NVIC_ICPR1
	mov r1, #FTM0_BIT30
	str r1, [r0]
	// interrupt aktivieren
	ldr r0, =NVIC_ISER1
	str r1, [r0]
	
	// ftm
	// ausschalten
	ldr r12, =FTM0_BASE
	mov r0, #0
	str r0, [r12, #FTM0_SC]
	str r0, [r12, #FTM0_CNT]
	
	ldr r0, =MOD_INIT
	str r0, [r12, #FTM0_MOD]
	
	mov r0, #C3SC_INIT
	str r0, [r12, #FTM0_C3SC]
	
	ldr r0, =C3V_5PERCENT
	str r0, [r12, #FTM0_C3V]
	
	// einschalten
	ldr r12, =FTM0_BASE
	mov r0, #SC_INIT
	str r0, [r12, #FTM0_SC]
	
	// gpio ausschalten
	ldr r1, =BB_GPIO_OUT // Bit-Band-Alias-Adresse der GPIO laden
	mov r0, #1
	str r0, [r1] // Bit auf GPIO ausgeben
	
	ldr r0, =prompt
	bl uart_putString
	
	
check_char:
	bl	uart_charPresent			// wurde ein Zeichen eingegeben?
	cbnz r0, check_input			// ja, pruefen
	b check_char
	
check_input:
	ldr r0, =prompt
	bl uart_putString
	bl uart_getChar // eingegebenes Zeichen einlesen
	cmp	r0, #'+' // war es ein plus?
	bne check_minus
	ldr r0, =gpio_out_new
	mov r1, #0
	str r1, [r0] // polaritaet setzen
	
check_minus:
	cmp	r0, #'-' // war es ein minus?
	bne check_number
	ldr r0, =gpio_out_new
	mov r1, #1
	str r1, [r0] // polaritaet setzen
	
check_number:
	cmp r0, #'0'
	blo check_char // keine zahl
	cmp r0, #'9'
	bhi check_char // keine zahl
	sub r0, r0, #'0' // in integer wandeln
	ldr r1, =#C3V_10PERCENT
	mul r0, r0, r1 // 10prozent schritte
	add r0, r0, #C3V_5PERCENT // 5prozent offset
	ldr r1, =c3v
	str r0, [r1]
	b check_char
	

// isr ftm0
.thumb_func
ftm0_isr:
	push {lr}
	ldr r3, =FTM0_BASE // FTM0 Basis in r0 setzen
	ldr r2, =BB_GPIO_OUT // Bit-Band-Alias-Adresse der GPIO laden
	ldr r0, [r3, #FTM0_SC]
	ands r0, r0, #SC_TOF
	cbz r0, check_ch_interrupt
	mov r0, #SC_INIT
	str r0, [r3, #FTM0_SC] // overflow interrupt zuruecksetzen
	ldr r0, =gpio_out
	ldr r0, [r0]
	str r0, [r2] // Bit auf GPIO ausgeben
	ldr r1, =gpio_out_new
	ldr r1, [r1]
	cmp r0, r1
	beq check_ch_interrupt // behalte polaritaet
	// neue polaritaet
	ldr r0, =gpio_out
	str r1, [r0]	

check_ch_interrupt:
	ldr r0, [r3, #FTM0_C3SC]
	ands r0, r0, #C3SC_CHF
	cbz r0, irq_ret
	mov r0, #C3SC_INIT
	str r0, [r3, #FTM0_C3SC] // channel interrupt zuruecksetzen
	ldr r0, =gpio_out
	ldr r0, [r0]
	eor r0, r0, #1 // gpio_out invertieren
	str r0, [r2] // Bit auf GPIO ausgeben
	ldr r1, =c3v
	ldr r0, [r1]
	cmp r0, #0
	beq irq_ret // behalte pwm
	// neue pwm
	str r0, [r3, #FTM0_C3V]
	mov r0, #0
	str r0, [r1] // wert zuruecksetzen
irq_ret:
	//bx lr
	pop {pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
gpio_out: .word 0
gpio_out_new: .word 0
c3v: .word 0
prompt: .asciz ">\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ COUNTER, 0x10 				//Schleifendurchläufe

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	bl pit3_init

//Neustart des Programms	
loop_program:

	//Einlesen von 16 Bytes
	ldr r0, =str_eingabe		// 	Zeiger auf den String laden
	bl uart_putString			// 	String augeben
	mov r4, #COUNTER			// 	Zaehler laden
	ldr r5, =bytearray			// 	Adresse laden
	
	
	//Timer-Offset bestimmen
	bl pit3_getval				
	mov r6, r0
	bl pit3_getval				
	mov r7, r0
	subs r7, r6, r7				//  Kosten für Zeitmessung in R7 speichern
	
	
	//Eingabeschleife
loop_eingabe:
	ldr r0, =str_prompt			//	Zeiger auf String laden
	bl uart_putString			//	String ausgeben
	bl uart_getByte				//	ein Byte einlesen
	strb r0, [r5], #1			// 	im Array ablegen und Adresse in R5 um eins erhoehen
	bl uart_putByte				// 	das Byte ausgeben
	subs r4, r4, #1				//  Zaehler dekrementieren 
	bne loop_eingabe			// 	solange Zaehler noch nicht null
	
	//Maximumbestimmung
	ldr r0, =str_startsuche		// Zeiger auf den String laden
	bl uart_putString			// String ausgeben
	mov r9, #0 					// Maximum mit null initaliseren
	mov r4, #COUNTER
	
	//Startzeitpunkt Maximumbestimmung aufnehmen & in R8 speichern
	bl pit3_getval				
	mov r8, r0
	
loop_maximum:
	
	ldrb r0, [r5, #-1]!			// Byte aus dem Array holen, vorher Adresse in R5 dekrementieren
	cmp r0, r9 					// mit bisherigen Maximum vergleichen
	it hi						// wenn es groesser ist (unsigend)
	movhi r9, r0				// wird das bisherige Maximum ueberschrieben
	
	subs r4, r4, #1				// Zaheler dekrementieren
	bne loop_maximum			// solange Zaehler noch nicht null
	
	ldr r0,  =maximum			// Adresse des Speichers fuer Maximum laden
	strb r9, [r0]				// das Maximum im Speicher ablegen
	
	
	//Endzeitpunkt Maximumbestimmung aufnehmen & in R10 speichern
	bl pit3_getval				
	mov r10, r0
	
	//Ausgabe des Ergebnisses
	ldr r0, =str_endsuche		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	mov r0, r9					// Maximum nach R0 kopieren
	bl uart_putByte				// Maximum ausgeben
	
	
	//Ausgabe der benötigten Zeit
	ldr r0, =str_zeitangabe		// Zeiger auf String laden
	bl uart_putString			// String ausgeben
	sub r0, r8, r10				//Differenz berechnen
	sub r0, r0, r7				// Berechnete Zeit um Kosten für Zeitmessung korrigieren 
	bl uart_putInt16			// Gemessene Zeit ausgeben
	
//Rueckspurng zum Beginn
	mov r1, #0					// Maximum zuruecksetzen
	ldr r0, =maximum 			// Adresse von Maximum laden
	strb r1, [r0]				// Wert von Maximum speichern
	b loop_program				// Erneute Programmausführung
	
	
///Bewertung der Zeitmessung///
// Die Dauer für die Bestimmung des Maximums ist unabhängig von der Eingabe und liegt bei 0x72

/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
	.rept COUNTER
	.byte 0x00
	.endr
maximum: .byte 0x0	
str_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben!\n"
str_prompt: .asciz "\n>0x"
str_startsuche: .asciz "\nDurchsuchen gestartet\n"
str_endsuche: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_zeitangabe: .asciz "\nZeit:"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


//Konstantendeklaration
.equ CORRECTION_MASK, 0x1F				//Bitmaske für Begrenzung des Eingabebereichs
.equ BITBAND_ALIAS_BASIS, 0x22000000	//Bit-Band-Alias-Basisadresse
.equ BITBAND_BASIS, 0x20000000			//Bit-Band-Basisadresse
.equ SIZE_MEMORY_BLOCK, 0x03			//Der Memory-Block, der im .data Bereich reserviert wird, dient nur dem Ziel, die in der Aufgabe geforderte 
										//Adresse 0x20000010 für die zweite Variable zu bekommen. Allerdings wird die Adresse sicherheitshalber
										//dennoch zur Laufzeit berechnet

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	mov r5, #CORRECTION_MASK   	//Bitmaske für Korrektur einlesen
	
	//Vorberechnungen - Bitbanding
	ldr r0, =variable2010			//Laden Adresse Variable
	mov r1, #BITBAND_BASIS			//Laden Bit-Band Basisadresse 
	sub r0, r0 , r1					//R0 = (Bit-Band-Adresse – Bit-Band-Basisadresse)
	mov r1, #32						//32 in Register R1 laden
	mul r1, r0, r1					//R1 = (Bit-Band-Adresse – Bit-Band-Basisadresse) x 32
	mov r2, #BITBAND_ALIAS_BASIS	//Laden Bit-Band-Alias-Basisadresse
	add r9, r1 , r2					//R8 = Bit-Band-Alias-Basisadresse + (Bit-Band-Adresse – Bit-Band-Basisadresse) × 32

loop_program:

	//Aufgabe a)
		
	//Erstes Bit einlesen & korrigieren
	ldr r0, =str_erstes_bit		 	
	bl uart_putString			
	bl uart_getByte				//	1. Byte einlesen
	and r6, r0, r5				//  1. Byte korrigieren & speichern
	bl uart_putByte				//	1. eingelesenes Byte ausgeben
	
	//Zweites Bit einlesen & korrigieren
	ldr r0, =str_zweites_bit		 	
	bl uart_putString			
	bl uart_getByte				//	2. Byte einlesen
	and r7, r0, r5				//  2. Byte korrigieren & speichern
	bl uart_putByte				//	2. eingelesenes Byte ausgeben
	
	//Korrigierte Werte ausgeben
	ldr r0, =str_korrektur
	bl uart_putString 
	
	ldr r0, =str_erstes_bit		 	
	bl uart_putString			
	mov r0, r6					// 	1. korrigiertes Byte nach R0 kopieren
	bl uart_putByte				// 	1. korrigiertes Byte ausgeben
	
	ldr r0, =str_zweites_bit		 	
	bl uart_putString			
	mov r0, r7					// 	2. korrigiertes Byte nach R0 kopieren
	bl uart_putByte				// 	2. korrigiertes Byte ausgeben
	
	//Aufgabe b)
	ldr r0, =str_schritt_0	
	bl uart_putString 		//Ausgabe vor Bitoperationen
	ldr r8, =variable2000	//Adresse von Vairable speichern
	ldr r0, [r8]			//Wert von Variable in R0 speichern
	bl uart_putInt32		//Ausgabe von Variable
	
	// 1. Bitoperation
	ldr r0, =str_schritt_1	
	bl uart_putString 		//Ausgabe vor Bitoperationen
	mov r10, #1				//Vorbereitung Bitmaske
	lsl r10, r10, r6		//Aufbau Bitmaske durch links-shift
	mvns r10, r10			//Bitmaske negieren	
	ldr r0, [r8]			//Wert von Variablen in R0 speichern
	and r0, r0, r10			//Bit mit Bitmaske über and zurücksetzen
	mov r11, r0   			//Zwischenergebnis speichern 
	bl uart_putInt32		//Zwischenergebnis ausgeben
	
	// 2. Bitoperation
	ldr r0, =str_schritt_2	
	bl uart_putString 		//Ausgabe vor Bitoperationen
	mov r0, #1				//Vorberietung Bitmaske
	lsl r0, r0, r7			//Aufbau Bitmaske durch links-shift
	orr r0, r11, r0			//Bit mit Bitmaske über orr setzen
	str r0, [r8]			//Wert von Variable in R0 speichern
	bl uart_putInt32		//Endergebnis ausgeben
	
	
	//Aufgabe c)
	
	//Ausgabe
	ldr r0, =str_bitbanding
	bl uart_putString
	ldr r0, =str_schritt_0
	bl uart_putString
	ldr r10, =variable2010			//Laden Adresse Variable
	ldr r0, [r10]					//Speichern von Wert der Variable in R0
	bl uart_putInt32	
	
	//1.Bit
	mov r2, #4
	mul r6, r2, r6					//R6 = Bitnummer x 4
	add r6, r9, r6					//R6 = Bit-Band-Alias-Basisadresse + (Bit-Band-Adresse – Bit-Band-Basisadresse) × 32 + Bitnummer x 4
	mov r3, #0						//0 in R3 schreiben
	str r3, [r6]					//0 in berechntets Stelle im Speicher schreiben
	
	//Ausgabe
	ldr r0, =str_schritt_1
	bl uart_putString
	ldr r10, =variable2010			//Laden Adresse Variable
	ldr r0, [r10]					//Speichern von Wert der Variable in R0
	bl uart_putInt32		
	
	//2.Bit
	mov r2, #4
	mul r7, r2, r7					//R7 = Bitnummer x 4
	add r7, r9, r7					//R7 = Bit-Band-Alias-Basisadresse + (Bit-Band-Adresse – Bit-Band-Basisadresse) × 32 + Bitnummer x 4
	mov r3, #1						//0 in R3 schreiben
	str r3, [r7]					//0 in berechntets Stelle im Speicher schreiben
	
	//Ausgabe
	ldr r0, =str_schritt_2
	bl uart_putString
	ldr r10, =variable2010			//Laden Adresse Variable
	ldr r0, [r10]					//Speichern von Wert der Variable in R0
	bl uart_putInt32		
	
end:
	b loop_program

/*** Datenbereich (ab 0x20000000) ***/
.data
variable2000: .long 0x0000FFFF
memory_block:
	.rept SIZE_MEMORY_BLOCK
	.long 0x00
	.endr
variable2010: .long 0x0000FFFF
str_erstes_bit: .asciz "\n\nNummer des 0-Bits: 0x"
str_zweites_bit: .asciz "\nNummer des 1-Bits: 0x"
str_korrektur: .asciz "\nArbeite mit folgenden Werten:"
str_bitbanding: .asciz "\nMit Bitbanding"
str_schritt_0: .asciz "\nWert vor Bitoperationen:"
str_schritt_1: .asciz "\nWert nach 1. Bitoperation:"
str_schritt_2: .asciz "\nWert nach 2. Bitoperaton:"

text: .asciz "Test-String\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ BITMASK, 0x000000FF 		//Bitmaske um einzelne Bytes der Vektoren zu verlgleichen
.equ COUNTER, 0x04 				//Schleifendurchläufe für byteweise Verarbeitung von Vektoren, da ein 32-Bit Wert aus 4 Bytes besteht
.equ BYTE_SIZE, 0x08			//Bytegröße

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:
	
	bl uart_init
	bl pit3_init
	
	bl pit3_getval				
	mov r4, r0
	bl pit3_getval				
	mov r5, r0
	sub r9, r4, r5	//	Kosten für Zeitmessung in R9 speichern
	
	
program:
	
	
	ldr r0, =str_start
	bl uart_putString
	
	//Zwei Vektoren einlesen
	ldr r0, =v1
	bl vektorEinlesen
	
	ldr r0, =v2
	bl vektorEinlesen
	
	
	///Berechnung ohne DSP/////////////////////////////////////////////////

	ldr r0, =v1 
	ldr r4, [r0]		//Wert von Vektor1 in R4 speichern	
	ldr r0, =v2
	ldr r5, [r0]		//Wert von Vektor2 in R5 speichern
	
	
	//Startzeitpunkt bestimmen & in R10 speichern
	bl pit3_getval				
	mov r10, r0
	
	mov r11, #0 		//Zielregister für vektorMin mit 0 initalisieren
	mov r12, #0 		//Zielregister für vektorMax mit 0 initalisieren
	mov r3, #COUNTER 	//Zaehler initaliseren
	mov r6, #BITMASK	//Bitmaske initalisieren
	

vektorVergleichen:

	and r7, r4, r6 		//Byte von Vektor1 mit Bitmaske holen
	and r8, r5, r6 		//Byte von Vektor2 mit Bitmaske holen
	
	cmp r7, r8
	ittee hi
	orrhi r11, r7, r11
	orrhi r12, r8, r12
	orrls r12, r7, r12
	orrls r11, r8, r11
	
	lsl r6, r6, #BYTE_SIZE	// Bitmaske für nächstes Byte (deshalb 8 Bit) mit links-shift vorbereiten
	subs r3, r3, #1			// Zaheler dekrementieren
	bne vektorVergleichen	// solange Zaehler noch nicht null
	
	
	//Endzeitpunkt bestimmen & in R4 speichern
	bl pit3_getval				
	mov r4, r0
	
	sub r10, r10, r4 		// Differenz Start- & Endzeitpunkt berechnen
	sub r10, r10, r9		// Zeit um Kosten für Zeitmessung korrigieren 
	
	//Ausgabe der Ergebnisse 
	ldr r0, =str_ohne_dsp
	bl uart_putString
	
	//Ausgabe vektorMin 
	ldr r0, =str_min
	bl uart_putString
	mov r0, r12
	bl uart_putInt32
	ldr r0, =vmin
	str r12, [r0]
	
	//Ausgabe vektorMax 
	ldr r0, =str_max
	bl uart_putString
	mov r0, r11
	bl uart_putInt32
	ldr r0, =vmax
	str r11, [r0]
	
	//Ausgbage Berechungszeit 
	ldr r0, =str_zeit
	bl uart_putString
	mov r0, r10
	bl uart_putInt32
	
	
	///Berechnung mit DSP///////////////////////////////////////////////////////////////////////////
	ldr r0, =v1 
	ldr r4, [r0]		//Wert von Vektor1 in R4 speichern

	ldr r0, =v2
	ldr r5, [r0]		//Wert von Vektor2 in R5 speichern
	
	
	//Startzeitpunkt bestimmen & in R8 speichern
	bl pit3_getval				
	mov r8, r0
	
	USUB8 r0, r4, r5  	//Byteweises substrahieren und setzen der GE-Bits
	SEL	r11, r4, r5		//Speichern des jeweils gößeren Bytes in R11 auf Bais der GE-Bits 
	USUB8 r0, r5, r4	//Byteweises substrahieren und setzen der GE-Bits mit umgekehrten Registern
	SEL r10, r4, r5		//Speichern des jeweils kleineren Bytes in R10 auf Bais der GE-Bits 

	//Endzeitpunkt bestimmen & in R6 speichern
	bl pit3_getval				
	mov r6, r0
	
	sub r8, r8, r6 		// Differenz Start- & Endzeitpunkt berechnen 
	sub r8, r8, r9		// Zeit um Kosten für Zeitmessung korrigieren 
	
	//Ausgabe der Ergebnisse 
	ldr r0, =str_mit_dsp
	bl uart_putString
	
	//Ausgabe vektorMin 
	ldr r0, =str_min
	bl uart_putString
	mov r0, r12
	bl uart_putInt32
	ldr r0, =vmin
	str r12, [r0]
	
	//Ausgabe vektorMax 
	ldr r0, =str_max
	bl uart_putString
	mov r0, r11
	bl uart_putInt32
	ldr r0, =vmax
	str r11, [r0]
	
	//Ausgbage Berechungszeit
	ldr r0, =str_zeit
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	
	
	///////Bewertung Messeregbnisse///////////////////////////////
	// Ohne DSP-Befehle liegt die gemessene Zeit bei 0x2F, mit DSP-Befehlen bei 0x04. 
	// Ohne DSP-Befehle wird also über 10 mal so viel Zeit benötigt wie mit DSP-Befehlen
	// Dies zeigt, wie mächtig DSP-Befehle sein können
	
	
	
end:
	b program


.thumb_func
vektorEinlesen:
	push {r4-r6,lr}
	mov r5, r0 			//Übergebene Adresse des zu speichernden Wertes in R5 sichern
	mov r6, #0 			//R6 mit 0 initalisieren: Aktueller Vektor
	mov r7, #0 			//R7 mit 0 initaliseren: Shiftindex
	mov r4, #COUNTER 	//Schleifendurchläufe für byteweise Verarbeitung von Vektoren, da ein 32-Bit Wert aus 4 Bytes besteht

	ldr r0, =str_eingabe
	bl uart_putString

byteEinlesen:
	bl uart_getByte
	lsl r0, r0, r7 		//Eingeleses Byte an korrekte Stelle des Vektors shiften
	orr r6, r0, r6			//Aktuellen Vektor mit eingelesenem Byte verodern (aktualiseren)
	add r7, r7, #BYTE_SIZE	//Shift-Index um die Größe eines Bytes erhöhen
	subs r4, r4, #1			// Zaheler dekrementieren
	bne byteEinlesen		// solange Zaehler noch nicht null	

	//Speichern endgültiger Vektor an übergebene Adresse
	str r6, [r5]	
	
	//Ausgabe Vektor	
	mov r0, r6 
	bl 	uart_putInt32
	
	pop {r4-r6, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
v1: .long 0x00000000
v2: .long 0x00000000
vmin: .long 0x00000000
vmax: .long 0x00000000

str_eingabe: .asciz "\n0x"
str_start: .asciz "\nBitte zweimal je 4 Bytes eingeben"
str_v1: .asciz "\nv1: 0x"
str_v2: .asciz "\nv2: 0x"

str_ohne_dsp: .asciz "\nohne DSP - Befehle:\n"
str_mit_dsp: .asciz "\n\nmit DSP - Befehlen:\n"
str_min: .asciz "min: "
str_max: .asciz "\nmax: "
str_zeit: .asciz "\nBenoetigte Zeit:"
// Include-Dateien
.include "k1514.inc"						// Praktikumsspezifische Definitionen
.include "lib_pit.inc"						// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"						// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text										// hier beginnt ein Code-Segment
.align	2									// Ausrichtung an eine gerade Adresse
.global	main								// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ MATRIX_SIZE, 16						//Größe Matrix
.equ MATRIX_ELEMS_PER_REIHE, 4
.equ BYTES_PER_WORD, 4
.equ BYTES_PER_REIHE, 8
.equ SAT_BIT, 13
.equ MATRIX_HALF, 8

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/


/* Kommentare zu den Aufgaben

a)
	Einsparungenen Mulitplikation: Die Zielmatrix hat 16 Einträge für deren Berechnung jeweils 4 Multiplikationen notwendig sind. Durch die DSP-Befehle werden
	jeweils 2 Mulitplikationen gleichzeitig durchgeführt. Es werden also 16 * 2 = 32 Multiplikationen gespart. 


d)
	UADD16: 
			0xA4367C7B + 0x10A78933 = 0xB4DD05AE 
			0xA436 + 0x10A7 = 0xB4DD	-> keine Sättigung & kein Überlauf
			0x7C7B + 0x8933 = 0x105AE 	-> keine Sättigung & Überlauf, Ergebnis wird auf 16 Bit abgeschnitten (05AE)
			
 	 	 	0xA4367C7B + 0xC5535F2C = 6989DBA7 
 	 	 	0xA436 + 0xC553 = 0x16989 	-> keine Sättigung & Überlauf, Ergebnis wird auf 16 Bit abgeschnitten (6989)
			0x7C7B + 0x5F2C = 0xDBA7	-> keine Sättigung & kein Überlauf
 
 	 	 	0xA4367C7B + 0x788E84B1 = 1CC4012C 
 	 	 	0xA436 + 0x788E = 0x11CC4 	-> keine Sättigung & Überlauf, Ergebnis wird auf 16 Bit abgeschnitten (1CC4)
			0x7C7B + 0x84B1 = 0x1012C	-> keine Sättigung & Überlauf, Ergebnis wird auf 16 Bit abgeschnitten (012C)
			
			
	UQADD16:	
			0xA4367C7B + 0x10A78933 = 0xB4DDFFFF 
			0xA436 + 0x10A7 = 0xB4DD	-> keine Sättigung & kein Überlauf
			0x7C7B + 0x8933 = 0x105AE 	-> Überlauf -> Sättigung auf maximal darstellbaren Wert FFFF 
			
 	 	 	0xA4367C7B + 0xC5535F2C = 0xFFFFDBA7 
 	 	 	0xA436 + 0xC553 = 0x16989 	-> Überlauf -> Sättigung auf maximal darstellbaren Wert FFFF 
			0x7C7B + 0x5F2C = 0xDBA7	-> kein Überlauf -> keine Sättigung 
 
 	 	 	0xA4367C7B + 0x788E84B1 = 0xFFFFFFFF 
 	 	 	0xA436 + 0x788E = 0x11CC4 	-> Überlauf -> Sättigung auf maximal darstellbaren Wert FFFF 
			0x7C7B + 0x84B1 = 0x1012C	-> Überlauf -> Sättigung auf maximal darstellbaren Wert FFFF 
			
			
	SADD16:	Darstellung im Zweierkomplement 
				höchste darstellbare Zahl: 7FFF 	 (führende 0, sonst 1) entspricht 32767
				niedrigste darstellbare Zahl: 0x8000 (führende 1, sonst 0) entspricht -32768
			
			0xA4367C7B + 0x10A78933 = 0xB4DD05AE
			0xA436 + 0x10A7 = 0xB4DD	-> keine Sättigung & kein Überlauf
			(-23498) + (4263) = -19235 
			0x7C7B + 0x8933 = 0x05AE -> keine Sättigung & kein Überlauf 
			(31867) + (-30413) = 1454
			
 	 	 	0xA4367C7B + 0xC5535F2C = 0x6989DBA7
			0xA436 + 0xC553 = 0x6989	
			(-23498) + (-15021) = -38519 -> Überlauf & keine Sättigung -38519 entspricht 27017 (0x6989) als UInt16  
			0x7C7B + 0x5F2C = 0xDBA7 
			(31867) + (24364) = 56231 -> Überlauf & keine Sättigung, 56231 als Int16 entspricht -9305 (0xDBA7) als UInt16
 
 	 	 	0xA4367C7B + 0x788E84B1 = 0x1CC4012C 
 	 	 	0xA436 + 0x788E = 0x1CC4	-> keine Sättigung & kein Überlauf
 	 	 	(-23498) + (30862) = 7364 
			0x7C7B + 0x84B1 = 0x012C	-> keine Sättigung & Überlauf
			(31867) + (-31567) = 300

	QADD16:	


			0xA4367C7B + 0x10A78933 = 0xB4DD05AE
			0xA436 + 0x10A7 = 0xB4DD	-> keine Sättigung & kein Überlauf
			(-23498) + (4263) = -19235 
			0x7C7B + 0x8933 = 0x05AE -> keine Sättigung & kein Überlauf 
			(31867) + (-30413) = 1454
			
 	 	 	0xA4367C7B + 0xC5535F2C = 0x80007FFF	
 	 	 	0xA436 + 0xC553 = 0x8000
			(-23498) + (-15021) = -38519 	-> Sättigung auf niedrigst darstellbare Zahl 8000
			0x7C7B + 0x5F2C = 0x7FFF
			(31867) + (24364) = 56231 		-> Sättigung auf höchste darstellbare Zahl 0x7FFF
 
 	 	 	0xA4367C7B + 0x788E84B1 = 0x1CC4012C 
 	 	 	0xA436 + 0x788E = 0x1CC4	-> keine Sättigung & kein Überlauf
 	 	 	(-23498) + (30862) = 7364 
			0x7C7B + 0x84B1 = 0x012C	-> keine Sättigung & Überlauf
			(31867) + (-31567) = 300
			
			
e)
	USAT16:
		   Sättigt vorzeichenbehaftete Zahlen zu vorzeichenlosen Zahlen
		   	   Mit 13 Bit maximal darzustellender Wert ist 0x1FFF (8191)
		   	   Mit 13 Bit minimal daruzustellender Wert ist 0x0000  
		   	   
		   0xA436 (-23498) wird auf 0x0000 gesättigt
		   0x7C7B = (31867) wird auf 0x1FFF gesättigt	   
		   Ausgabe; 0000_1FFF
		   
		   0x10A7 (4263) wird nicht gesättigt	
		   0x8933 (-30413) wird auf 0x0000 gesättigt
		   Ausgabe: 10A7_0000
		   
	SSAT16:
		   Sättigt vorzeichenbehaftete Zahlen zu vorzeichenbehafteten Zahlen
		   	   Mit 13 Bit maximal darzustellender Wert ist 0x0FFF (4095)
		   	   Mit 13 Bit minimal daruzustellender Wert ist 0xF000 (-4096) 
		   	   
		   0xA436 (-23498) wird auf 0x1000 gesättigt
		   0x7C7B = (31867) wird auf 0x0FFF gesättigt	   
		   Ausgabe; F000_0FFF
		   
		   0x10A7 (4263) wird auf 0x0FFF gesättigt
		   0x8933 (-30413) wird auf 0xF000 gesättigt
		   Ausgabe: 0FFF_F000


*/

main:	

	bl uart_init
	///////////////////////////////////////Aufgabe a////////////////////////////////////////////////////////////////
	
	//Vorbereitung Matrixmultiplikation
	mov r11, #MATRIX_SIZE					//Zähler für Iterationen der Matrixmultiplikation
	ldr r4, =matrix_m
	ldr r5, =matrix_n
	ldr r6, =matrix_O
	mov r7, #0								//Zähler für Ausgabe und Berechnung der nächsten Adressen der Matrizenmultiplikation
	ldr r0, =str_matrixausgabe				
	bl uart_putString 						//Start der Matrixausgabe
	
	//Iteration Matrixmultiplikation inklusive Ausgabe
matrix_iteration:

	//Akkumulator mit 0 initalisieren
	mov r8, #0				
	

	
	//Laden der nächsten Werte
	ldr r9, [r4], #BYTES_PER_WORD	
	ldr r10, [r5], #BYTES_PER_WORD
	//Mulitplikation & Akkumulation mit DSP
	smlad r8, r9, r10, r8 
	
	//Laden der nächsten Werte
	ldr r9, [r4], #BYTES_PER_WORD
	ldr r10, [r5], #BYTES_PER_WORD
	//Mulitplikation & Akkumulation mit DSP
	smlad r8, r9, r10, r8
	
	//Abspeichern des berechneten Wertes
	str r8, [r6], #BYTES_PER_WORD 
	
	//Ausgabe des berechneten Elements und Berechnung der nächsten Adressen 
	mov r0, r8
	bl uart_putInt32
	mov r0, ' '
	add r7, r7, #1
	cmp r7, #MATRIX_ELEMS_PER_REIHE
	ittte eq
	 ldreq r5, =matrix_n						//Matrix N wurde einmal durchlaufen, springe wieder zum ersten Tabelle 
	 moveq r0, '\n'								//4 Elemente wurden ausgegeben, Zeilenumbruch einfügen
	 moveq r7, #0								//Zurücksetzen des Zählers für Ausgabe & Berechnungen der Adressen
	 subne r4, r4, #BYTES_PER_REIHE				//Matrix N wurde noch nicht durchlaufen, springe für das nächste Element aus M an den Anfagn der momentanen Zeile 
	bl uart_putChar
			
	//Rücksprung Iteration
	subs r11,r11,#1  							//Pro Iteration wird ein Matrixwert berechnet
	bne matrix_iteration 
			
	///////////////////////////////////////Aufgabe b////////////////////////////////////////////////////////////////
	ldr r0, =str_kopiere_matrix
	bl uart_putString
	
	//Effizientes Kopieren der Matrix im Speicher durch Verwendung von 8 Registern pro Befehl
	ldr r0, =matrix_O;
	ldr r1, =kopie_matrix_O;
	ldm r0!, {r2-r9}
	stm r1!, {r2-r9}
	ldm r0, {r2-r9}
	stm r1, {r2-r9}
	
	///////////////////////////////////////Aufgabe c////////////////////////////////////////////////////////////////
	
	
	//Vorbereitung Multiplikation
	ldr r4, =matrix_m
	ldr r5, =matrix_n		
	mov r7, #0								//Akkumulator mit 0 initalisieren
	mov r9, #MATRIX_HALF					//Pro Iteration werden jeweils zwei Elemente der Matrizen verarbeitet: Insgesamt werden also 16/2 = 8 Durchläufe benötigt
	
sum_iteration:

	//Laden der nächsten Werte
	ldr r1, [r4],#BYTES_PER_WORD
	ldr r2, [r5],#BYTES_PER_WORD
		
	//Muliplikation & Akkumulation mit DSP
	smlad r7, r1, r2, r7 
	
	//Aktualisieren Schleifenvariable
	subs r9, r9, #1
	bne sum_iteration
	
	
	//Ausgabe der Produktsumme
	ldr r0, =str_produkt_summe
	bl uart_putString
	mov r0, r7
	bl uart_putInt32
	
	
	///////////////////////////////////////Aufgabe d////////////////////////////////////////////////////////////////
	
	//Laden der Werte
	ldr r4, =word_a
	ldr r5, =word_b
	ldr r6, =word_c
	ldr r7, =word_d
	ldr r8, [r4]
	ldr r9, [r5]
	ldr r10, [r6]
	ldr r11, [r7]
	
	//Ausführung der Befehle und Ausgabe
	ldr r0, =str_uadd16
	bl uart_putString 
	uadd16 r0, r8, r9
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	uadd16 r0, r8, r10
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	uadd16 r0, r8, r11
	bl uart_putInt32
	
	ldr r0, =str_sadd16
	bl uart_putString 
	sadd16 r0, r8, r9
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	sadd16 r0, r8, r10
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	sadd16 r0, r8, r11
	bl uart_putInt32
	
	ldr r0, =str_uqadd16
	bl uart_putString 
	uqadd16 r0, r8, r9
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	uqadd16 r0, r8, r10
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	uqadd16 r0, r8, r11
	bl uart_putInt32
	
	ldr r0, =str_qadd16
	bl uart_putString 
	qadd16 r0, r8, r9
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	qadd16 r0, r8, r10
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	qadd16 r0, r8, r11
	bl uart_putInt32
	
	
	///////////////////////////////////////Aufgabe e////////////////////////////////////////////////////////////////
	
	//Laden der Werte
	ldr r4, =word_a
	ldr r5, =word_b
	ldr r6, [r4]
	ldr r7, [r5]
	
	
	//Ausführen der Befehle & Ausgabe
	ldr r0, =str_ssat16
	bl uart_putString
	ssat16 r0, #SAT_BIT, r6
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	ssat16 r0, #SAT_BIT, r7
	bl uart_putInt32
	
	ldr r0, =str_usat16
	bl uart_putString
	usat16 r0, #SAT_BIT, r6
	bl uart_putInt32
	ldr r0, =str_leerzeichen
	bl uart_putString
	usat16 r0, SAT_BIT, r7
	bl uart_putInt32
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data

matrix_m: 
	.short 0x5f8c, 0x7f48, 0x8245, 0x6048, 0xc799, 0x9c5d, 0xd49c, 0x33d8, 0x579b, 0x8aef, 0xf2c0, 0xa3c2, 0x41fd, 0x50d4, 0x25c6, 0x4afa
matrix_n:
	.short 0x7f41, 0x0645, 0x8c8f, 0x9065, 0x78e3, 0xf7f3, 0xd29f, 0x2961, 0x5a1e, 0xdfed, 0x4b9f, 0x1092, 0x61bf, 0x21be, 0x5ca1, 0xc6d3
matrix_O:
	.rept MATRIX_SIZE
	.word 0x00
	.endr	
kopie_matrix_O:
	.rept MATRIX_SIZE
	.word 0x00
	.endr
word_a: .word 0xA4367C7B
word_b: .word 0x10A78933
word_c: .word 0xC5535F2C
word_d: .word 0x788E84B1
	
str_zeilenumbruch: .asciz "\n"
str_leerzeichen: .asciz "  "
str_matrixausgabe: .asciz "\nErgebnismatrix O:\n"
str_kopiere_matrix: .asciz "\nKopieren der Matrix O!\n\tBefehle:\n\tldr r0, =matrix_O\n\tldr r1, =kopie_matrix_O\n\tldm r0!, {r2-r9}\n\tstm r1!, {r2-r9}\n\tldm r0, {r2-r9}\n\tstm r1, {r2-r9}\n"
str_produkt_summe: .asciz "\nProdukt - Summe :  "
str_uadd16: .asciz "\n\nUADD16 :  "
str_sadd16: .asciz "\nSADD16 :  "
str_uqadd16: .asciz "\nUQADD16 :  "
str_qadd16: .asciz "\nQADD16 :  "
str_ssat16: .asciz "\n\nSSAT16 :  "
str_usat16: .asciz "\nUSAT16 :  "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ MINUTEN_PRO_STUNDE, 60
.equ STUNDEN_PRO_TAG, 24
.equ TAGE_PRO_MONAT, 30
.equ MONATE_PRO_JAHR, 12
.equ XOR_MASK, 0x1
.equ JAHRTAUSEND, 20
.equ AUSGABE_ZWEISTELLIG, 9
.equ COUNTER, 0x7ED8D5
.equ JAHRHUNDERT_GRENZE, 99
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*Registerbelegungen

	r4:		Adresse - Minute
	r5:		Wert - Minute
	r6:		Adresse - Stunde
	r7:		Wert - Stunde
	r8:		Adresse - Tag
	r9:		Wert - Tag
	r10:	Adresse - Monat
	r11:	Wert - Monat
	r12:	Start-Stop-Flag

*/

main:	

	bl uart_init
	//Initalisierung Registerbelegungen
	ldr r4, =uhrzeit_minute
	ldrb r5, [r4]
	ldr r6, =uhrzeit_stunde
	ldrb r7, [r6]
	ldr r8, =datum_tag
	ldrb r9, [r8]
	ldr r10,=datum_monat
	ldrb r11, [r10]
	mov r12, #1   			

program:

	//Überprüfung Eingabe
	bl delay
	bl uart_charPresent
	cmp r0,#0
	beq ausgabe
	
	//Eingabe = s?
	bl uart_getChar  
	cmp r0,'s'
	
	//Togglen Start-Stop-Flag
	it eq
	  eoreq r12, r12, #XOR_MASK
	beq ausgabe
	  
	//Eingabe = t?  
	cmp r0,'t'
	beq setze_zeit
	 
	//Eingabe = d?
	cmp r0,'d'
	beq setze_datum 
	 
setze_zeit:

	//Verarbeiten Eingabe Stunden
	ldr r0, =str_stunden
	bl uart_putString
	bl uart_getByteBase10
	mov r7, r0

	//Verabeiten Eingabe Minuten
	ldr r0, =str_minuten
	bl uart_putString
	bl uart_getByteBase10
	mov r5, r0
	b ausgabe
	
setze_datum:

	//Verarbeiten Eingabe Tage
	ldr r0, =str_tag
	bl uart_putString
	bl uart_getByteBase10
	mov r9, r0

	//Verarbeiten Eingabe Monate
	ldr r0, =str_monat
	bl uart_putString
	bl uart_getByteBase10
	mov r11, r0
	
	//Verarbeiten Eingabe Jahre
	ldr r0, =str_jahr
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =datum_jahr
	strb r0, [r1]
	

ausgabe:
	
	//Ausgabe Tag  
	cmp r9, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_tag					// Nein, springe zur Ausgabe des Tages
	mov r0, '0'
	bl uart_putChar
schreibe_tag:
	mov r0, r9
	bl uart_putByteBase10
	mov r0, '.'
	bl uart_putChar
	
	//Ausgabe Monat
	cmp r11, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_monat					// Nein, springe zur Ausgabe des Monats
	mov r0, '0'
	bl uart_putChar
schreibe_monat:
	mov r0, r11
	bl uart_putByteBase10
	mov r0, '.'
	bl uart_putChar
	
	//Ausgabe Jahr
	mov r0, #JAHRTAUSEND				// Ausgabe Prefix Jahreszahl (20) 
	bl uart_putByteBase10
	ldr r1, =datum_jahr
	ldrb r0, [r1]
	cmp r0, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_jahr					// Nein, springe zur Ausgabe des Jahres
	mov r0, '0'
	bl uart_putChar
schreibe_jahr:
	ldr r1, =datum_jahr
	ldrb r0, [r1]
	bl uart_putByteBase10
	mov r0, ' '
	bl uart_putChar

	//Ausgabe Stunden
	cmp r7, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_stunden				// Nein, springe zur Ausgabe der Stunden
	mov r0, '0'
	bl uart_putChar	
schreibe_stunden:
	mov r0, r7
	bl uart_putByteBase10
	mov r0, ':'
	bl uart_putChar

	//Ausgabe Minuten
	cmp r5, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_minuten				// Nein, springe zur Ausgabe der Minuten
	mov r0, '0'
	bl uart_putChar
schreibe_minuten:
	mov r0, r5
	bl uart_putByteBase10

	ldr r0, =str_uhr
	bl uart_putString

	//Überprüfung Start-Stop-Flag
	cmp r12, #0							 
	beq program							//Gehe nicht in den timer Block, wenn das Start-Stop = 0 ist
	
	
timer:	
	
	//Hochzählen und Abspeichern von Minuten
	add r5, r5, #1
	cmp r5, #MINUTEN_PRO_STUNDE
	it eq
	 moveq r5, #0
	strb r5, [r4]
	bne program							//Kein Überlauf der Minuten -> Stunden müssen nicht verändert werden
	
	
	//Hochzählen und Abspeichern von Stunden
	add r7, r7, #1
	cmp r7, #STUNDEN_PRO_TAG
	it eq
	 moveq r7, #0
	strb r7, [r6]
	bne program							//Kein Überlauf der Stunden -> Tage müssen nicht verändert werden					
	
		
	//Hochzählen und Abspeichern von Tagen
	add r9, r9, #1
	cmp r9, #TAGE_PRO_MONAT
	it hi
	 movhi r9, #1
	strb r9, [r8] 
	bls program							//Kein Überlauf der Tage -> Monate müssen nicht verändert werden
	    
		
	//Hochzählen und Abspeichern von Monaten
	add r11, r11, #1
	cmp r11, #MONATE_PRO_JAHR
	it hi
	 movhi r11, #1
	strb r11, [r10] 
	bls program							//Kein Überlauf der Monate -> Jahre müssen nicht verändert werden

		
	//Hochzählen und Abspeichern von Jahren
	ldr r0, =datum_jahr
	ldrb r1, [r0] 
	add r1, r1, #1
	
	//Verhindern eines Überlaufs des Jahrhunderts
	mov r2, #JAHRHUNDERT_GRENZE
	cmp r1, r2
	it hi
	 subhi r1, r1, #1
	strb r1, [r0]
	
	b program



/*	Unterprogramm delay

	- keine Übergabeparameter
	- keine Rückgabewerte
*/
	
.thumb_func
delay:
	push {lr}
	
	//Initalisierung Counter
	ldr r0, =COUNTER

iteration:
	//Counter bis 0 runterzählen
	subs r0, r0, #1
	bne iteration
	
	pop {pc}

/*** Datenbereich (ab 0x20000000) ***/
.data

start_stop: .byte 0x1
uhrzeit_stunde: .byte 0
uhrzeit_minute: .byte 0
datum_tag: .byte 1	
datum_monat: .byte 1
datum_jahr: .byte 14
str_uhr: .asciz " Uhr\n"
str_stunden: .asciz "\nStunde eingeben (hh): "
str_minuten: .asciz "\nMinuten eingeben (mm): "
str_tag: .asciz "\nTag eingeben (dd): "
str_monat: .asciz "\nMonat eingeben (mm): "
str_jahr: .asciz "\nJahr eingeben (jj): "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration - Timer
.equ MINUTEN_PRO_STUNDE, 60
.equ STUNDEN_PRO_TAG, 24
.equ TAGE_PRO_MONAT, 30
.equ MONATE_PRO_JAHR, 12
.equ XOR_MASK, 0x1
.equ JAHRTAUSEND, 20
.equ AUSGABE_ZWEISTELLIG, 9
.equ COUNTER, 0x7ED8D5
.equ JAHRHUNDERT_GRENZE, 99

//Konstantendeklaration - Interrupthandling

.equ MASK_SIM_SCGC6, 1 << 23 			  //Binäre Darstellung: 23. Bit gesetzt, alle anderen nicht
.equ NVIC_PIT1_BIT, 1 << 5				  //Berechnung IRQ (69) mod 32 = 5
.equ NVIC_ICSER2, 0xE000E108			  //Register für Setzten von Interrupts
.equ NVIC_ICPR2, 0xE000E288				  //Register zum Löschen von hängenden Interrupts
.equ SIM_SCGC6,  0x4004803C				  //Register zum Aktivieren des PIT-Taktes
.equ VEKTORTABELLE_BASIS, 0x01FFFFE00	  //Beginn Vektortabelle
.equ OFFSET_PIT1, 0x00000154			  //Offset Interrupt-Adresse PIT1
.equ PIT_CHANNEL1_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PIT1
.equ PIT_TFLG1, 0x4003711C				  //Register, das die PIT Interrupt-Flags hält
.equ PIT_TCTRL1, 0x40037118				  //Kontrollregister für Timer1
.equ PIT_MCR, 0x40037000				  //PIT Modul Kontrollregister
.equ PIT_LDVAL1, 0x40037110				  //Register für Startwert des Timers
.equ TIMER, 24999999					  //Timer Startwert						
.equ BIT_BAND_ALIAS_BASIS, 0x42000000
.equ BIT_BAND_BASIS, 0x40000000
.equ TEN, 0								  //Timer Interrupt Enable Bit im Kontrollregister PIT_TCTRL1
.equ TIE, 1								  //Timer Enable Bit im Kontrollregister PIT_TCTRL1	
.equ TIF, 0 							  //Position des Timer Interrupt Flags im Register PIT_TFLG1 

//Berechnung Bitbanding gemäß Formel Bit-Band-Alias-Basisadresse + (Bit-Band-Adresse – Bit-Band-Basisadresse) × 32 + Bitnummer x 4
.equ BIT_BAND_TIMER_ENABLE , BIT_BAND_ALIAS_BASIS + (PIT_TCTRL1 - BIT_BAND_BASIS) * 32 + TEN * 4 	
.equ BIT_BAND_INTERRUPT_ENABLE , BIT_BAND_ALIAS_BASIS + (PIT_TCTRL1 - BIT_BAND_BASIS) * 32 + TIE * 4
.equ BIT_BAND_TFLG1, BIT_BAND_ALIAS_BASIS + (PIT_TFLG1 - BIT_BAND_BASIS) * 32 + TIF * 4 	
		
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*Registerbelegungen


	r4:		Adresse - Minute
	r5:		Wert - Minute
	r6:		Adresse - Stunde
	r7:		Wert - Stunde
	r8:		Adresse - Tag
	r9:		Wert - Tag
	r10:	Adresse - Monat
	r11:	Adresse - Interrupt-Flag
	r12:	Start-Stop-Flag

*/

main:	

	bl uart_init
	//Initalisierung Registerbelegungen
	ldr r4, =uhrzeit_minute
	ldrb r5, [r4]
	ldr r6, =uhrzeit_stunde
	ldrb r7, [r6]
	ldr r8, =datum_tag
	ldrb r9, [r8]
	ldr r10,=datum_monat
	ldr r11, =interrupt_flag
	mov r12, #1   //start-stop-flag  		


	//Takt für PIT aktivieren - 23. Bit in Register SIM_SCGC6 über Maskierung setzen
	ldr r0, =SIM_SCGC6								
	ldr r1, [r0] 																			
	orr r1, r1, #MASK_SIM_SCGC6						
	str r1, [r0]									
	
	//Interrupt-Vektor zu PIT1 setzen - Speichern der Adresse der Routine in Vektortabelle  
	ldr r0, =interrupt_routine
	ldr r1, =PIT_CHANNEL1_INTERRUPT
	str r0, [r1]
	
	//eventuell hängende Interrupts zu PIT1 löschen - NVIC_ICPR2 5. Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r0, =NVIC_ICPR2
	mov r1, #NVIC_PIT1_BIT
	str r1, [r0]	
	
	//Interrupt zu PIT1 aktivieren - NVIC_ISER2 5.Bit setzen, um Interrupt zu aktivieren
	ldr r0, =NVIC_ICSER2
	mov r1, #NVIC_PIT1_BIT
	str r1, [r0]
	
	// Alle PITs aktivieren 
	ldr r0, =PIT_MCR
	mov r1,#0
	str r1, [r0]
	
	//Startwert für PIT1 auf 1 Sekunde initaliseren
	ldr r0, =PIT_LDVAL1
	ldr r1, =TIMER 		
	str r1, [r0]
	
	//Bit-Banding-Vorbereitung
	mov r1, #1	
	
	//TFLG1-Flag zurücksezten
	ldr r0, =BIT_BAND_TFLG1	
	str r1, [r0]
	
	//Interrupt zu PIT1 akitvieren
	ldr r0, =BIT_BAND_INTERRUPT_ENABLE
	str r1, [r0]
		
	//PIT1 aktivieren 
	ldr r0, =BIT_BAND_TIMER_ENABLE
	str r1, [r0]	

program:

	//Überprüfen, ob ein Interrupt aufgetreten ist
check_interrupt:
	ldrb r0, [r11]
	cmp r0, #1
	itt eq
		moveq r0, #0					
		strbeq r0, [r11]					//Interrupt-Flag zurücksetzen 
	bne check_interrupt


	//Überprüfung Eingabe
	bl uart_charPresent
	cmp r0,#0
	beq ausgabe
	
	//Eingabe = s?
	bl uart_getChar  
	cmp r0,'s'
	
	//Togglen Start-Stop-Signal
	it eq
	  eoreq r12, r12, #XOR_MASK
	beq ausgabe
	  
	//Eingabe = t?  
	cmp r0,'t'
	beq setze_zeit
	 
	//Eingabe = d?
	cmp r0,'d'
	beq setze_datum 
	 
setze_zeit:

	//Verarbeiten Eingabe Stunden
	ldr r0, =str_stunden
	bl uart_putString
	bl uart_getByteBase10
	mov r7, r0

	//Verabeiten Eingabe Minuten
	ldr r0, =str_minuten
	bl uart_putString
	bl uart_getByteBase10
	mov r5, r0
	b ausgabe
	
setze_datum:

	//Verarbeiten Eingabe Tage
	ldr r0, =str_tag
	bl uart_putString
	bl uart_getByteBase10
	mov r9, r0

	//Verarbeiten Eingabe Monate
	ldr r0, =str_monat
	bl uart_putString
	bl uart_getByteBase10
	strb r0, [r10]
	
	//Verarbeiten Eingabe Jahre
	ldr r0, =str_jahr
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =datum_jahr
	strb r0, [r1]
	

ausgabe:
	
	//Ausgabe Tag  
	cmp r9, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_tag					// Nein, springe zur Ausgabe des Tages
	mov r0, '0'
	bl uart_putChar
schreibe_tag:
	mov r0, r9
	bl uart_putByteBase10
	mov r0, '.'
	bl uart_putChar
	
	//Ausgabe Monat
	ldrb r0, [r10]
	cmp r0, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_monat					// Nein, springe zur Ausgabe des Monats
	mov r0, '0'
	bl uart_putChar
schreibe_monat:
	ldr r0, [r10]
	bl uart_putByteBase10
	mov r0, '.'
	bl uart_putChar
	
	//Ausgabe Jahr
	mov r0, #JAHRTAUSEND				// Ausgabe Prefix Jahreszahl (20) 
	bl uart_putByteBase10
	ldr r1, =datum_jahr
	ldrb r0, [r1]
	cmp r0, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_jahr					// Nein, springe zur Ausgabe des Jahres
	mov r0, '0'
	bl uart_putChar
schreibe_jahr:
	ldr r1, =datum_jahr
	ldrb r0, [r1]
	bl uart_putByteBase10
	mov r0, ' '
	bl uart_putChar

	//Ausgabe Stunden
	cmp r7, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_stunden				// Nein, springe zur Ausgabe der Stunden
	mov r0, '0'
	bl uart_putChar	
schreibe_stunden:
	mov r0, r7
	bl uart_putByteBase10
	mov r0, ':'
	bl uart_putChar

	//Ausgabe Minuten
	cmp r5, #AUSGABE_ZWEISTELLIG		// Muss zusätzlich eine führende Null augegeben werden?
	bhi schreibe_minuten				// Nein, springe zur Ausgabe der Minuten
	mov r0, '0'
	bl uart_putChar
schreibe_minuten:
	mov r0, r5
	bl uart_putByteBase10

	ldr r0, =str_uhr
	bl uart_putString

	//Überprüfung Start-Stop-Signal
	cmp r12, #0							 
	beq program							//Gehe nicht in den timer Block, wenn das Start-Stop = 0 ist
	
	
timer:	
	
	
	//Hochzählen und Abspeichern von Minuten
	add r5, r5, #1
	cmp r5, #MINUTEN_PRO_STUNDE
	it eq
	 moveq r5, #0
	strb r5, [r4]
	bne program							//Kein Überlauf der Minuten -> Stunden müssen nicht verändert werden
	
	
	//Hochzählen und Abspeichern von Stunden
	add r7, r7, #1
	cmp r7, #STUNDEN_PRO_TAG
	it eq
	 moveq r7, #0
	strb r7, [r6]
	bne program							//Kein Überlauf der Stunden -> Tage müssen nicht verändert werden					
	
		
	//Hochzählen und Abspeichern von Tagen
	add r9, r9, #1
	cmp r9, #TAGE_PRO_MONAT
	it hi
	 movhi r9, #1
	strb r9, [r8] 
	bls program							//Kein Überlauf der Tage -> Monate müssen nicht verändert werden
	    
		
	//Hochzählen und Abspeichern von Monaten
	ldr r0, [r10]
	add r0, r0, #1
	cmp r0, #MONATE_PRO_JAHR
	it hi
	 movhi r0, #1
	strb r0, [r10] 
	bls program							//Kein Überlauf der Monate -> Jahre müssen nicht verändert werden

		
	//Hochzählen und Abspeichern von Jahren
	ldr r0, =datum_jahr
	ldrb r1, [r0] 
	add r1, r1, #1
	
	//Verhindern eines Überlaufs des Jahrhunderts
	mov r2, #JAHRHUNDERT_GRENZE
	cmp r1, r2
	it hi
	 subhi r1, r1, #1
	strb r1, [r0]
	
	b program
	
	
.thumb_func
interrupt_routine:

	//Interrupt-Flag zu PIT1 löschen
	mov r0, #1
	ldr r1, =BIT_BAND_TFLG1
	str r0, [r1]
	
	//Programm-Flag setzen
	ldr r2, =interrupt_flag
	strb r0, [r2]
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
interrupt_flag: .byte 0x00
start_stop: .byte 0x1
uhrzeit_stunde: .byte 0
uhrzeit_minute: .byte 0
datum_tag: .byte 1	
datum_monat: .byte 1
datum_jahr: .byte 14
str_uhr: .asciz " Uhr\n"
str_stunden: .asciz "\nStunde eingeben (hh): "
str_minuten: .asciz "\nMinuten eingeben (mm): "
str_tag: .asciz "\nTag eingeben (dd): "
str_monat: .asciz "\nMonat eingeben (mm): "
str_jahr: .asciz "\nJahr eingeben (jj): "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ BYTES_PER_WORD, 4
.equ BITS_PER_CHAR, 8

//Register
.equ SIM_SCGC6,  0x4004803C
.equ CRC_CRC,	0x40032000			//Datenregister CRC
.equ CRC_GPOLY,	0x40032004			//Polynomregister CRC
.equ CRC_CTRL,	0x40032008			//Kontrollregister CRC

//Initalwerte
.equ CRC_POLYNOM, 0b00000100110000010001110110110111
.equ CRC_SEED, 0x12345678

//Bitmaske für finden von Nullzeichen
.equ BITMASK, 0x0000000FF

//Bitnummern CRC Control Register
.equ CTRL_WAS, 25
.equ CTRL_TCRC, 24    
.equ CTRL_TOT1, 31
.equ CTRL_TOT0, 30
.equ CTRL_TOTR1, 29
.equ CTRL_TOTR0, 28
.equ CTRL_FXFOR, 26
.equ SIM_CRC, 18

//Bitmaske Konfiguration CRC-Modul
.equ CRC_CONFIG, (0 << CTRL_TOT1) | (0 << CTRL_TOT0) | (0 << CTRL_TOTR0) | (0 << CTRL_TOTR1) | (0 << CTRL_FXFOR) | (1 << CTRL_WAS) | (1 << CTRL_TCRC) 
//	nicht transponierend Schreiben | nicht transponierend Lesen | kein Komplement bilden | WAS setzen um Seed schreiben zu können | 32-Bit-Modus

//Bitbanding CRC-WAS
__BBREG BIT_BAND_WAS, CRC_CTRL, CTRL_WAS

//Bitbanding Takt CRC-Modul
__BBREG BIT_BAND_SIM_CRC, SIM_SCGC6, SIM_CRC


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*Registerbelegungen

 r5: Register CRC_CRC

*/

main:	
 bl uart_init

 //Takt für CRC-Modul aktiveren
 ldr r0, = BIT_BAND_SIM_CRC
 mov r1, #1
 str r1, [r0]
	
 //CRC-Modul konfigurieren
 ldr r0, =CRC_CTRL
 ldr r1, =CRC_CONFIG
 str r1, [r0]	
	
 //Setzen des Polynoms
 ldr r0, =CRC_GPOLY
 ldr r1, =CRC_POLYNOM
 str r1, [r0]
 	
 //Setzen des Seeds
 ldr r5, =CRC_CRC
 ldr r0, =CRC_SEED
 str r0, [r5]
	
 // Löschen von CTRL[WAS] um Daten schreiben zu können
 ldr r0, =BIT_BAND_WAS
 mov r1, #0
 str r1, [r0]

 //Beginn Berechnung CRC
 ldr r0, =str_text

crc_word:
 //nächtes Word laden
 ldr r1, [r0], #BYTES_PER_WORD
	
 //Überprüfen, ob Stringterminator enthalten ist
 //Bitmaske und Zählvariable für Vergleich initalisieren
 ldr r2, =BITMASK
 ldr r3, =BYTES_PER_WORD
	
crc_check_null:	

 //Mit aktueller Bitmaske verunden
 and r4, r1, r2
 cmp r4, #0
 beq crc_byte					//Terminator ist enthalten CRC-Berechnung byteweise fortsetzten
 lsl r2, r2, #BITS_PER_CHAR		//Terminator ist nicht enthalten -> Bitmaske für nächstes Byte anpassen  
 subs r3, r3, #1
 bne crc_check_null				//Wurde das gesamte Word auf Nullterminator überprüft?
	
 //CRC-Berechnung fortsetzen
 str r1, [r5]
 b crc_word
	
crc_byte:

 //Berechnung der Anzahl an Bytes, die noch in Berechnung einfließen müssen
 mov r2,#BYTES_PER_WORD
 sub r3, r2,r3	
	 
bytes:	
 strb r1, [r5]
 lsr  r1, r1, #BITS_PER_CHAR
 subs r3, r3, #1
 bne bytes
	
 //Ausgabe
 ldr r0, =str_text
 bl uart_putString
 ldr r0, =str_crc
 bl uart_putString	
 ldr r0, [r5]
 bl uart_putInt32
	
end: 
 b end


/*** Datenbereich (ab 0x20000000) ***/
.data
str_text: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
str_crc: .asciz "\nBerechnete Pruefsumme: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration 
.equ XOR_MASK, 0x1
.equ MOD_LEER, 0
.equ MOD_POLLING, 1
.equ MOD_ISR, 2

//Bitnummern
.equ TEN, 0								  	//Timer Interrupt Enable Bit 
.equ TIE, 1								  	//Timer Enable Bit 	
.equ TIF, 0 							  	//Timer Interrupt Flags  
.equ CHN, 2								  	//Timer Chain Mode
.equ SIM_PIT, 23							//Bitnummer Takt PIT
.equ SIM_PORTA, 9							//Bitnummer Takt PortA
.equ SIM_PORTE, 13							//Bitnummer Takt PortE
.equ PCR_PS, 0								//Widerstandkonfiguration Pull Select
.equ PCR_PE, 1								//Widerstandkonfiguraiton Pull Enable
.equ PCR_MUX0, 8							//Pin Mux Control
.equ PCR_ISF, 24							//Interruptflag GPIO
.equ PCR_IRQ3, 19							//Interruptkonfiguration GPIO
.equ PCR_IRQ1, 17							//Interruptkonfiguration GPIO
.equ LED1, 11
.equ LED2, 28
.equ LED3, 29
.equ LED4, 10
.equ BUTTON1, 26
.equ BUTTON0, 19

//System Integraion Modul 
.equ SIM_SCGC5,  0x40048038					//Register zum Aktivieren des Taktes für PortA & PortE
.equ SIM_SCGC6,  0x4004803C				  	//Register zum Aktivieren des Taktes für das Pit-Modul

//SIM-Konfiguration Takt
__BBREG BIT_BAND_SIM_PORTA, SIM_SCGC5, SIM_PORTA
__BBREG BIT_BAND_SIM_PORTE, SIM_SCGC5, SIM_PORTE
__BBREG BIT_BAND_SIM_PIT, SIM_SCGC6, SIM_PIT


//Interrupts
.equ NVIC_ICSER2, 0xE000E108				//Register für Setzten von Interrupts
.equ NVIC_ICPR2, 0xE000E288					//Register zum Löschen von hängenden Interrupts
.equ NVIC_PIT1_BIT, 1 << 5				  	//Berechnung IRQ (69) mod 32 = 5
.equ NVIC_PIT2_BIT, 1 << 6				  	//Berechnung IRQ (70) mod 32 = 6
.equ NVIC_PORTE_BIT, 1 << 27			  	//Berechnung IRQ (91) mod 32 = 27
//Verktortabelle
.equ VEKTORTABELLE_BASIS, 0x01FFFFE00	  //Beginn Vektortabelle
.equ OFFSET_PIT1, 0x00000154			  //Offset Interrupt-Adresse PIT1
.equ OFFSET_PIT2, 0x00000158			  //Offset Interrupt-Adresse PIT2
.equ OFFSET_PORTE, 0x000001AC			  //Offset Interrupt-Adresse PortE
.equ PIT_CHANNEL1_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PIT1
.equ PIT_CHANNEL2_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PIT2
.equ PORTE_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PORTE

	
//Timerkonfiguration
.equ PIT_MCR, 0x40037000				  	//PIT Modul Kontrollregister
//Startregister 
.equ PIT_LDVAL1, 0x40037110				  	//Timer1
.equ PIT_LDVAL2, 0x40037120					//Timer2
.equ TIMER, 24999999					  	//Pit1 Startwert 
.equ TIMER_DEBOUNCE, 124999					//Pit2 Startwert 5m entsprechen 1/200 Sekunden  -> 25000000 : 200 = 125000
//Kontrollregister  
.equ PIT_TCTRL1, 0x40037118				  	//Timer1
.equ PIT_TCTRL2, 0x40037128					//Timer2
//Flagregister 
.equ PIT_TFLG1, 0x4003711C				  	//Timer1
.equ PIT_TFLG2, 0x4003712C					//Timer2
//Bitband - Pit1
__BBREG BIT_BAND_TIMER_ENABLE1, PIT_TCTRL1, TEN
__BBREG BIT_BAND_INTERRUPT_ENABLE1, PIT_TCTRL1, TIE
__BBREG BIT_BAND_CHN1, PIT_TCTRL1, CHN		
__BBREG BIT_BAND_TFLG1, PIT_TFLG1, TIF
//Bitband - Pit2
__BBREG BIT_BAND_TIMER_ENABLE2, PIT_TCTRL2, TEN
__BBREG BIT_BAND_INTERRUPT_ENABLE2, PIT_TCTRL2, TIE
__BBREG BIT_BAND_CHN2, PIT_TCTRL2, CHN		
__BBREG BIT_BAND_TFLG2, PIT_TFLG2, TIF


//Portkonfiguration

//Data Output Register
.equ GPIOA_PDOR, 0x400FF000					
//Data Input Register
.equ GPIOE_PDIR, 0x400FF110
.equ GPIOA_PDIR, 0x400FF010
//Data Toggle Register
.equ GPIOA_PTOR, 0x400FF00C
//Data Direction Register
.equ GPIOC_PDDA, 0x400FF014					
.equ GPIOC_PDDE, 0x400FF114					
//Control Register Ports
.equ PORTA_PCR11, 0x4004902C
.equ PORTA_PCR28, 0x40049070					
.equ PORTA_PCR29, 0x40049074					
.equ PORTA_PCR10, 0x40049028	
.equ PORTA_PCR19, 0x4004904C
.equ PORTE_PCR26, 0x4004D068	
//Konfiguration GPIO
.equ GPIO_MODE_LED, 1 << PCR_MUX0
.equ GPIO_MODE_BUTTON_POLL, 1 << PCR_MUX0 | 1 << PCR_PE | 1 <<PCR_PS
// GPIO | Widerstand aktiviert | Pull Down Widerstand
.equ GPIO_MODE_BUTTON_ISR, 1 << PCR_MUX0 | 1 << PCR_PE | 1 << PCR_PS | 1 << PCR_IRQ3 | 1 << PCR_IRQ1
// GPIO | Widerstand aktiviert | Pull Down Widerstand | Interrupt auf fallende Flanke

//Konfiguration Input/Output
__BBREG BIT_BAND_LED1_MODE, GPIOC_PDDA, LED1
__BBREG BIT_BAND_LED2_MODE, GPIOC_PDDA, LED2
__BBREG BIT_BAND_LED3_MODE, GPIOC_PDDA, LED3
__BBREG BIT_BAND_LED4_MODE, GPIOC_PDDA, LED4
__BBREG BIT_BAND_BUTTON0_MODE, GPIOC_PDDA, BUTTON0
__BBREG BIT_BAND_BUTTON1_MODE, GPIOC_PDDE, BUTTON1
//Bitband Input
__BBREG BIT_BAND_BUTTON0_DATA, GPIOA_PDIR, BUTTON0
__BBREG BIT_BAND_BUTTON1_DATA, GPIOE_PDIR, BUTTON1
//Bitband Output
__BBREG BIT_BAND_LED1_DATA, GPIOA_PDOR, LED1
__BBREG BIT_BAND_LED2_DATA, GPIOA_PDOR, LED2
__BBREG BIT_BAND_LED3_DATA, GPIOA_PDOR, LED3
__BBREG BIT_BAND_LED4_DATA, GPIOA_PDOR, LED4

//Bitband Interrupt Button
__BBREG BIT_BAND_BUTTON_ISR, PORTE_PCR26, PCR_ISF

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*Registerbelegungen

	r4:		0.Bit Counter
	r5:		1.Bit Counter
	r6:		2.Bit Counter
	r7:		3.Bit Counter
	r8:		4.Bit Counter
	r9:		5.Bit Counter
	r10:	6.Bit Counter
	r11.	7.Bit Counter
	r12:	Adresse - interrupt_flag_pit_1

*/

main:	

	bl pit3_init
	bl uart_init
	
	//Initalisierung Registerbelegungen
	mov r4, #0
	mov r5, #0
	mov r6, #0
	mov r7, #0
	mov r8, #0
	mov r9, #0
	mov r10, #0
	mov r11, #0
	ldr r12, =interrupt_flag_pit_1
		

	//Takt für PIT aktivieren
	ldr r0, =BIT_BAND_SIM_PIT								
	mov r1, #1 
	str r1, [r0]									
	
	//Interrupt-Vektor zu PIT1, PIT2 & PortA setzen - Speichern der Adresse der Routine in Vektortabelle
	ldr r0, =interrupt_routine_pit1
	ldr r1, =PIT_CHANNEL1_INTERRUPT
	str r0, [r1]
	ldr r0, =interrupt_debounce
	ldr r1, =PIT_CHANNEL2_INTERRUPT
	str r0, [r1]
	ldr r0, =interrupt_routine_button
	ldr r1, =PORTE_INTERRUPT
	str r0, [r1]
	
	
	//NVIC_ICPR2 5., 6., & 27. Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r0, =NVIC_ICPR2
	mov r1, #NVIC_PIT1_BIT
	str r1, [r0]	
	mov r1, #NVIC_PIT2_BIT
	str r1, [r0]
	mov r1, #NVIC_PORTE_BIT
	str r1, [r0]
	
	
	//NVIC_ISER2 5., 6. & 27. Bit setzen, um Interrupt zu aktivieren
	ldr r0, =NVIC_ICSER2
	mov r1, #NVIC_PIT1_BIT
	str r1, [r0]
	mov r1, #NVIC_PIT2_BIT
	str r1, [r0]
	mov r1, #NVIC_PORTE_BIT
	str r1, [r0]
	
	// Alle PITs aktivieren 
	ldr r0, =PIT_MCR
	mov r1,#0
	str r1, [r0]
	
	//Startwert für PIT1 auf 1 Sekunde initalisieren
	ldr r0, =PIT_LDVAL1
	ldr r1, =TIMER
	str r1, [r0]

	//Bit-Banding-Vorbereitung
	mov r1, #1	
	mov r2, #0
	
	//TFLG1-Flag zurücksezten
	ldr r0, =BIT_BAND_TFLG1	
	str r1, [r0]
	ldr r0, =BIT_BAND_TFLG2	
	str r1, [r0]
	
	//Interrupt zu PIT1 & PIT2 akitvieren
	ldr r0, =BIT_BAND_INTERRUPT_ENABLE1
	str r1, [r0]
	ldr r0, =BIT_BAND_INTERRUPT_ENABLE2
	str r1, [r0]
	
	//Chain Mode für PIT1 & PIT2 auf not chained setzen
	ldr r0, =BIT_BAND_CHN1
	str r0, [r0]
	ldr r0, =BIT_BAND_CHN2
	str r0, [r0]
	
	//PIT1 & PIT2 aktiveren
	ldr r0, =BIT_BAND_TIMER_ENABLE1
	str r1, [r0]

	//Takt für PortA & PortE aktivieren
	ldr r0, =BIT_BAND_SIM_PORTA
	str r1, [r0]
	ldr r0, =BIT_BAND_SIM_PORTE
	str r1, [r0]	

	//Ports als GPIOs konfigurieren	
	ldr r0, =PORTA_PCR19
	ldr r3, =GPIO_MODE_BUTTON_POLL
	str r3, [r0]
	ldr r0, =PORTE_PCR26
	ldr r3, =GPIO_MODE_BUTTON_ISR
	str r3, [r0]
	ldr r0, =PORTA_PCR10
	ldr r3, =GPIO_MODE_LED
	str r3, [r0]
	ldr r0, =PORTA_PCR11
	ldr r3, =GPIO_MODE_LED
	str r3, [r0]
	ldr r0, =PORTA_PCR28
	ldr r3, =GPIO_MODE_LED
	str r3, [r0]
	ldr r0, =PORTA_PCR29
	ldr r3, =GPIO_MODE_LED
	str r3, [r0]
	
	//LED GPIOs als Output konfigurieren
	ldr r0, =BIT_BAND_LED1_MODE
	str r1, [r0]
	ldr r0, =BIT_BAND_LED2_MODE
	str r1, [r0]
	ldr r0, =BIT_BAND_LED3_MODE
	str r1, [r0]
	ldr r0, =BIT_BAND_LED4_MODE
	str r1, [r0]
	
	//Button GPIOs als Input konfigurieren
	ldr r0, =BIT_BAND_BUTTON0_MODE
	str r2, [r0]
	ldr r0, =BIT_BAND_BUTTON1_MODE
	str r2, [r0]
	
	//LEDs ausschalten, da diese mit 0 initalisiert werden und über negierte Logik gesteuert werden 
	ldr r0, =BIT_BAND_LED1_DATA
	str r1, [r0]
	ldr r0, =BIT_BAND_LED2_DATA
	str r1, [r0]
	ldr r0, =BIT_BAND_LED3_DATA
	str r1, [r0]
	ldr r0, =BIT_BAND_LED4_DATA
	str r1, [r0]


program:
	//nicht blockierende Unterprogrammaufrufe Taster
	bl abfrage_taster_schwarz
	bl abfrage_taster_gruen

	ldrb r0, [r12]
	cmp r0, #1							//Ist eine Sekunde abgelaufen?	
	itt eq
	moveq r0, #0					
	strbeq r0, [r12]					//Interrupt-Flag-Pit-1 zurücksetzen 
	bne program				
	
	//Überprüfung Eingabe Buttons
	ldr r2, =mod
	ldrb r0, [r2]
	cmp r0, #MOD_LEER					//Wurde ein Taster gedrückt?
	beq check_eingabe_terminal			//Nein, überprüfe Terminaleingabe
	
	//Überprüfen Zaehlrichtung
	cmp r0, #MOD_POLLING				
	bne check_start_stop
	//Zaehlrichtung aendern 
	ldr r0, =zaehlrichtung
    ldrb r1, [r0]
    eor r1, r1, #XOR_MASK
    strb r1, [r0]
    //mod zurücksetzen
    ldr r0, =MOD_LEER
    strb r0, [r2]
    //Ausgabe Zaehlrichtung
    cmp r1, #1
	ite eq
	ldreq r0, =str_hoch
	ldrne r0, =str_runter
	bl uart_putString
	b check_eingabe_terminal
	
check_start_stop:	
	//Überprüfen Start-Stop
	ldr r2, =mod
	ldrb r0, [r2]
	cmp r0, #MOD_ISR				
	bne check_eingabe_terminal
	//Zaehlrichtung aendern 
	ldr r0, =start_stop
    ldrb r1, [r0]
    eor r1, r1, #XOR_MASK
    strb r1, [r0]
    //mod zurücksetzen
    ldr r0, =MOD_LEER
    strb r0, [r2]
	//Ausgabe Status
	cmp r1, #1
	ite eq
	ldreq r0, =str_start
	ldrne r0, =str_stop
	bl uart_putString
	
		
check_eingabe_terminal:
	bl uart_charPresent
	cmp r0,#0
	beq ausgabe 					//Kein Zeichen eingelesen, überspringe Überprüfung auf Zeichentypen
	
	//Eingabe = s?
	bl uart_getChar  
	cmp r0,'s'
	bne check_plus					//Fahre mit nächster Überprüfung fort
	//Togglen Start-Stop-Signal
	ldr r0, =start_stop
	ldrb r1, [r0]
	eor r1, r1, #XOR_MASK
	str r1, [r0]
	//Ausgabe
	cmp r1, #1
	ite eq
	ldreq r0, =str_start
	ldrne r0, =str_stop
	bl uart_putString
	beq ausgabe						//Überspringe Überprüfung auf andere mögliche Zeichen

check_plus:

	//Eingabe = +?  
	cmp r0, '+'
	bne check_minus
	ldr r0, =zaehlrichtung
	mov r1, #1
	str r1, [r0]
	//Ausgabe
	ldr r0, =str_hoch
	bl uart_putString
	beq ausgabe						//Überspringe Überprüfung auf andere mögliche Zeichen
	
check_minus:	
	//Eingabe = -?
	cmp r0,'-'
	bne ausgabe			
	ldr r0, =zaehlrichtung
	mov r1, #0
	str r1, [r0]
	//Ausgabe
	ldr r0, =str_runter
	bl uart_putString
	 
ausgabe:

	//Überprüfung Start-Stop-Signal
	ldr r0, =start_stop
	ldrb r1, [r0]
	cmp r1, #0							 
	beq program							//Keine Ausgabe, wenn das Start-Stop-Signal = 0 ist
	
	mov r0, r11
	bl uart_putByteBase10
	mov r0, '\t'
	bl uart_putChar
	
	mov r0, r10
	bl uart_putByteBase10
	mov r0, '\t'
	bl uart_putChar
	
	mov r0, r9
	bl uart_putByteBase10
	mov r0, '\t'
	bl uart_putChar
	
	mov r0, r8
	bl uart_putByteBase10
	mov r0, '\t'
	bl uart_putChar
	
	mov r0, r7
	bl uart_putByteBase10
	mov r0, '\t'
	bl uart_putChar
	ldr r0, =BIT_BAND_LED4_DATA
	mvn r1, r7
	str r1, [r0]
	
	mov r0, r6
	bl uart_putByteBase10
	mov r0, '\t'
	bl uart_putChar
	ldr r0, =BIT_BAND_LED3_DATA
	mvn r1, r6
	str r1, [r0]
	
	mov r0, r5
	bl uart_putByteBase10
	mov r0, '\t'
	bl uart_putChar
	ldr r0, =BIT_BAND_LED2_DATA
	mvn r1, r5
	str r1, [r0]

	mov r0, r4
	bl uart_putByteBase10
	mov r0, '\n'
	bl uart_putChar
	ldr r0, =BIT_BAND_LED1_DATA
	mvn r1, r4
	str r1, [r0]
	
	ldr r0, =zaehlrichtung
	ldrb r1, [r0]
		
	//0.Bit
	eor r4, r4, #XOR_MASK
	cmp r4, r1
	beq program							//Kein Überlauf des 0.Bits -> 1.Bit muss nicht angepasst werden
	
	//1.Bit
	eor r5, r5, #XOR_MASK
	cmp r5, r1
	beq program							//Kein Überlauf des 1.Bits -> 2.Bit muss nicht angepasst werden
	
	//2.Bit
	eor r6, r6, #XOR_MASK
	cmp r6, r1
	beq program							//Kein Überlauf des 2.Bits -> 3.Bit muss nicht angepasst werden

	//3.Bit
	eor r7, r7, #XOR_MASK
	cmp r7, r1
	beq program							//Kein Überlauf des 3.Bits -> 4.Bit muss nicht angepasst werden

	//4.Bit
	eor r8, r8, #XOR_MASK
	cmp r8, r1
	beq program							//Kein Überlauf des 4.Bits -> 5.Bit muss nicht angepasst werden
	
	//5.Bit
	eor r9, r9, #XOR_MASK
	cmp r9, r1
	beq program							//Kein Überlauf des 5.Bits -> 6.Bit muss nicht angepasst werden
	
	//6.Bit
	eor r10, r10, #XOR_MASK
	cmp r10, r1
	beq program							//Kein Überlauf des 6.Bits -> 7.Bit muss nicht angepasst werden
	
	//7.Bit
	eor r11, r11, #XOR_MASK
	cmp r11, r1
	b program
	
	
.thumb_func
interrupt_routine_pit1:

	//Interrupt-Flag zu PIT1 löschen
	mov r0, #1
	ldr r1, =BIT_BAND_TFLG1
	str r0, [r1]
	//Programm-Flag setzen
	ldr r2, =interrupt_flag_pit_1
	strb r0, [r2]
	bx lr
	
.thumb_func
interrupt_debounce:
	
	//Timer deaktivieren
	mov r2, #0
	ldr r1, =BIT_BAND_TIMER_ENABLE2
    str r2, [r1] 
	
	//Interrupt-Flag zu PIT2 löschen
	mov r0, #1
	ldr r1, =BIT_BAND_TFLG2
	str r0, [r1]
	
	//Ist der letze Interrupt vom Hauptprogramm bereits verarbeitet worden? 
	ldr r1, =interrupt_flag_pit_2
	ldrb r2, [r1]
	cmp r2, #1
	beq return_interrupt_debounce
	
	//Ansonten Programm-Flag setzen
	ldr r1, =interrupt_flag_pit_2
	strb r0, [r1]
	
return_interrupt_debounce:
	bx lr
	
.thumb_func
interrupt_routine_button:

	//Interrupt-Flag Button löschen
	mov r0, #1
	ldr r1, =BIT_BAND_BUTTON_ISR
	str r0, [r1]
		
	//Ist der letze Interrupt für den Button vom Hauptprogramm bereits verarbeitet worden? 
	ldr r1, =interrupt_flag_pit_2
	ldrb r2, [r1]
	cmp r2, #1
	beq return_interrupt_button

	//Ansonsten Timer2 für Entprellvorgang starten
	ldr r0, =PIT_LDVAL2
	ldr r1, =TIMER_DEBOUNCE
	str r1, [r0]
	ldr r0, =BIT_BAND_TIMER_ENABLE2
    mov r1, #1
    str r1, [r0]    	
return_interrupt_button:	
	bx lr
	

.thumb_func
abfrage_taster_schwarz:
	push {lr}
	
	ldr r3, =debounce_aktiv			//Ist ein Entprellvorgang aktiv?
	ldrb r0, [r3]
	cmp r0, #1						
	bne poll_button					//Nein, lese Button ein
	
	ldr r2, =debounce_start			//Ja, lese Startzeitpunkt des Entprellvorgangs ein
	ldr r2, [r2]
	bl pit3_getval		
    sub r0, r2, r0
    ldr r2, =TIMER_DEBOUNCE
    cmp r0, r2						//Ist der Entprellvorgang abgeschlossen?
    bls return_schwarz				//Nein -> verlasse Unterprogramm 
	
	ldr r0, =BIT_BAND_BUTTON0_DATA
	ldr r0, [r0]
	cmp r0,#1						//Ist der Pegel wieder auf dem Ausgangsniveau?
	bne return_schwarz				//Nein, verlasse Unterprogramm
	
	mov r0, #0						//Ja, setze debounce_aktiv zurück & mod=ISR_POLL	
	str r0, [r3] 					//Setze debounce_aktiv zurück
	ldr r0, =mod
	ldr r1, =MOD_POLLING
	str r1, [r0]  
	b return_schwarz				//Verlasse Unterprogramm 
	
poll_button:
	ldr r0, =BIT_BAND_BUTTON0_DATA
	ldr r0, [r0]
	cmp r0, #0						//Wurde der Button gedrückt?
	bne return_schwarz				//Nein, verlasse Unterprogramm
	
	bl pit3_getval					//Ja, erfasse Startzeitpunkt Entprellvorgang & setze debounce_aktiv
	ldr r1, =debounce_start
	str r0, [r1]
	mov r0, #1			
	strb r0, [r3]				
return_schwarz: 
	pop {pc}
	
	
.thumb_func
abfrage_taster_gruen:
	push {lr}
	
	//Überprüfen Interrupt Signal
	ldr r2, =interrupt_flag_pit_2
	ldrb r0, [r2]
	cmp r0, #1							//Ist ein Interrupt nach dem Entprellvorgang aufgetreten?
	bne return_gruen						//Nein, verlasse Unterprogramm
	
	//Pegelüberprüfung
	ldr r0, =BIT_BAND_BUTTON1_DATA		//Ja, überprüfe den Pegel
	ldr r1, [r0]
	cmp r1, #1							//Ist der Pegel immer noch aktiv?
	bne return_gruen					//Ja, verlasse Unterprogramm
		
	ldr r0, =mod						//Nein, setze mod=MOD_ISR
	mov r1, #MOD_ISR
	strb r1, [r0]
	    
	//Zurücksetzen Interrupt Signal
	mov r0, #0	
	ldr r2, =interrupt_flag_pit_2 				
	strb r0, [r2]						//Interrupt-Flag-Pit-2 zurücksetzen 
return_gruen:	
	pop {pc}


/*** Datenbereich (ab 0x20000000) ***/
.data
debounce_aktiv: .byte 0x00				// 1: aktiv | 0: inaktiv
debounce_start: .word 0x00000000

start_stop: .byte 0x01 					// 1: Start	| 0: Stop
zaehlrichtung: .byte 0x01 				// 1: Hoch	| 0: Runter
mod: .byte 0x00
counter_test: .byte 0x00
interrupt_flag_pit_1: .byte 0x00
interrupt_flag_pit_2: .byte 0x00
interrupt_flag_button: .byte 0x00
str_start: .asciz "\nCounter gestartet\n"
str_stop: .asciz "\nCounter gestoppt"
str_hoch: .asciz "\nModus: Hochzaehlen\n"
str_runter: .asciz "\nModus: Runterzaehlen\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


//Konstantendeklaration

.equ XOR_MASK, 0x1
.equ MOD_8, 0
.equ MOD_10, 1
.equ MOD_12, 2
.equ MOD_16, 3
.equ MSB_GAIN, (1 << 15)
.equ SHIFT_BITMASK_8, 5
.equ SHIFT_BITMASK_16, 12
.equ SUB_10, 102
.equ SUB_12, 12
.equ SINGLE_NULL, 100
.equ UMULL_10, 0x2800001  										// (2^32 / (1024/10)) +1
.equ UMULL_12, 0xC00001	  										// (2^32 / (4096/12)) +1
		
.equ NVIC_ICSER2, 0xE000E108									//Register für Setzten von Interrupts
.equ NVIC_ICPR2, 0xE000E288										//Register zum Löschen von hängenden Interrupts
.equ NVIC_PIT1_BIT, 1 << 5				  						//Berechnung IRQ (69) mod 32 = 5
.equ VEKTORTABELLE_BASIS, 0x01FFFFE00	  						//Beginn Vektortabelle
.equ OFFSET_PIT1, 0x00000154			  						//Offset Interrupt-Adresse PIT1
.equ PIT_CHANNEL1_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PIT1
.equ PIT_MCR, 0x40037000				  						//PIT Modul Kontrollregister
.equ WORD_PIT_MCR, 0x0											//Steuerwort PIT Modul Kontrollregister 
.equ BITMASK_TCTRL1, (1 << 0) | (1 << 1) 						//Timer enable, Interupt enable, Chained disable
.equ PIT_LDVAL1, 0x40037110				  						//Register für Startwert
.equ TIMER, 24999999					  						//Entspricht einer Sekunde
.equ PIT_TCTRL1, 0x40037118				  						//Timer Kontrollregister
.equ PIT_TFLG1, 0x4003711C				  						//Timer Flagregister
__BBREG BIT_BAND_TFLG1, PIT_TFLG1, 0

.equ SIM_SCGC3, 0x40048030
.equ WORD_SCGC3,   (1 << 27)									//Aktiviere Clock für ADC1
.equ SIM_SCGC5, 0x40048038
.equ WORD_SCGC5, (1 << 9)  										//Aktiviere Clock PortA -> LEDs 
.equ SIM_SCGC6, 0x4004803C
.equ WORD_SCGC6, (1 << 23)  									//Aktiviere Clock PIT 

.equ ADC1_SC1A, 0x400BB000 			   							//Status & Kontrollregister A
.equ DISABLE_ADC, 0x0000001F									// Channel select 11111 -> Module deaktiviert	
.equ ENABLE_ADC, (1 << 2 ) | (1 << 4)  							//Single ended Mode, Interrupt nicht aktiviert, Channel select: 10100 -> AD20 
__BBREG BIT_COCO, ADC1_SC1A, 7 									//Conversion Complete Flag

.equ ADC1_CFG1, 0x400BB008 										//ADC Konfigurationsregister 1 
.equ CFG1_MODE_8, (1 << 5) | (1 << 6)							//Normal power configuration , Clock Divide Ratio = 8, Short sample time, 8 Bit conversion mode, Input Clock: Bus clock 
.equ CFG1_MODE_10, (1 << 3) |(1 << 5) | (1 << 6) 				// "", 10 Bit conversion mode
.equ CFG1_MODE_12, (1 << 2) | (1 << 5) | (1 << 6)				// "", 12 Bit conversion mode
.equ CFG1_MODE_16, (1 << 2) | (1 << 3) |(1 << 5) | (1 << 6)		// "", 16 Bit conversion mode

.equ ADC1_CFG2, 0x400BB00C 										//ADC Konfigruationsregister 2 
.equ WORD_CFG2, 0x0												//ADxxa Kanäle , normal speed conversion , default longest cycle time

.equ ADC1_SC2, 0x400BB020 										//Status- & Kontrollregister 2 
.equ WORD_SC2, 0x0												//Software Trigger select, compare function disabled, compare range function disabled, DMA disabled, Default voltage reference

.equ ADC1_SC3, 0x400BB024										//Status- & Kontrollregister 3
.equ SC3_OPERATING, (1 << 3) | (1 << 2) | (1 << 1)  			//continious conversion enabled, hardware average enable, 16 samples average
.equ SC3_CALIBRATE, (1 << 3) | (1 << 2) | (1 << 1) | (1 << 0) 	//32 samples für genaueste Kalibirerun
__BBREG BIT_CAL, ADC1_SC3, 7 									//calibration flag
__BBREG BIT_CALF, ADC1_SC3, 6 									//calibration failed flag
	
.equ ADC1_RA, 0x400BB010   										//ADC Datenregister A	
.equ ADC1_PG, 0x400BB02C										//ADC Plus-Side Gain Register	
.equ ADC1_MG, 0x400BB030 										//ADC Minus-Side Gain Register 	
	
//ADC Plus Kalibrierungsregister
.equ ADC1_CLP0, 0x400BB04C		
.equ ADC1_CLP1, 0x400BB048		
.equ ADC1_CLP2, 0x400BB044		
.equ ADC1_CLP3, 0x400BB040		
.equ ADC1_CLP4, 0x400BB03C		
.equ ADC1_CLPS, 0x400BB038		

//ADC Minus Kalibrierungsregister
.equ ADC1_CLMS, 0x400BB058		
.equ ADC1_CLM4, 0x400BB05C		
.equ ADC1_CLM3, 0x400BB060		
.equ ADC1_CLM2, 0x400BB064		
.equ ADC1_CLM1, 0x400BB068		
.equ ADC1_CLM0, 0x400BB06C		


//Data Output Register
.equ GPIOA_PDOR, 0x400FF000					
//Data Direction Register
.equ GPIOC_PDDA, 0x400FF014							
//Control Register Ports
.equ PORTA_PCR11, 0x4004902C
.equ PORTA_PCR28, 0x40049070					
.equ PORTA_PCR29, 0x40049074					
.equ PORTA_PCR10, 0x40049028	

//Konfiguration GPIO
.equ GPIO_MODE_LED, (1 <<  8)	//Pin Mux Control

//Konfiguration Output
__BBREG BIT_BAND_LED1_MODE, GPIOC_PDDA, 11
__BBREG BIT_BAND_LED2_MODE, GPIOC_PDDA, 28
__BBREG BIT_BAND_LED3_MODE, GPIOC_PDDA, 29
__BBREG BIT_BAND_LED4_MODE, GPIOC_PDDA, 10

//Bitband Output
__BBREG BIT_BAND_LED1_DATA, GPIOA_PDOR, 11
__BBREG BIT_BAND_LED2_DATA, GPIOA_PDOR, 28
__BBREG BIT_BAND_LED3_DATA, GPIOA_PDOR, 29
__BBREG BIT_BAND_LED4_DATA, GPIOA_PDOR, 10

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.


/*
Registerbelegungen:
	r4: Adresse Interrupt_flag_pit_1
	r5: Start-Stop 								0 -> Stopp | 1 -> Start
	r6: Auflösung ADC							0 -> 8-Bit | 1 -> 10 Bit | 2 -> 12 Bit | 3 -> 16 Bit
	r7: Adresse ADC1_RA
	r8: Adresse AC1_SC1A
	r9: Adresse ADC1_CFG1
	r10: Aktueller Wert ADC
	r11: Aktuelle Stufe
	r12: Freie Verwendung
	
*/

main:
	
	bl uart_init
		
	//Initalisierung Registerbelegungen
	ldr r4, =interrupt_flag_pit_1
	mov r5, #1
	mov r6, #MOD_16
	ldr r7, =ADC1_RA
	ldr r8, =ADC1_SC1A 
	ldr r9, =ADC1_CFG1
	
	//Aktivieren Takt PIT  
	ldr r0, =SIM_SCGC6
	mov r1, #WORD_SCGC6
	str r1, [r0]
	
	//Aktivieren Takt ADC
	ldr r0, =SIM_SCGC3
	mov r1, #WORD_SCGC3
	str r1, [r0]  
	
	//Aktivieren Takt PortA
	ldr r0, =SIM_SCGC5
	mov r1, #WORD_SCGC5
	str r1, [r0]  
										
	//Interrupt-Vektor zu PIT1  Speichern der Adresse der Routine in Vektortabelle
	ldr r0, =interrupt_routine_pit1
	ldr r1, =PIT_CHANNEL1_INTERRUPT
	str r0, [r1]

	//NVIC_ICPR2 5.Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r0, =NVIC_ICPR2
	mov r1, #NVIC_PIT1_BIT
	str r1, [r0]
	
	//NVIC_ISER2 5.Bit setzen, um Interrupt zu aktivieren
	ldr r0, =NVIC_ICSER2
	str r1, [r0]
	
	// PITs aktivieren 
	ldr r0, =PIT_MCR
	mov r1, #WORD_PIT_MCR
	str r1, [r0]
	
	//Startwert für PIT1 auf 1 Sekunde initalisieren
	ldr r0, =PIT_LDVAL1
	ldr r1, =TIMER
	str r1, [r0]

	//TFLG1-Flag zurücksezten
	ldr r0, =BIT_BAND_TFLG1	
	mov r1, #1
	str r1, [r0]
	
	//Interrupt zu PIT1 akitvieren, PIT1 aktivieren, PIT1  Chainend Mode disabled
	ldr r0, =PIT_TCTRL1
	mov r1, #BITMASK_TCTRL1 
	str r1, [r0]
	
	//Kalibriere ADC
	mov r0, r9
	bl configure_and_calibrate_adc
	
	//Überprüfe Ergebnis der Kalibrierung
	cmp r0, #0
	beq enable_adc
	
	//Reagieren auf fehlerhafte Kalibrierung
	ldr r0, =str_error
	bl uart_putString
	b end
	
enable_adc:
	mov r1, #SC3_OPERATING	
	ldr r2, =ADC1_SC3	
	str r1, [r2]
		
	mov r1, #ENABLE_ADC
	str r1, [r8]
		
	//Ports als GPIOs konfigurieren	
	ldr r1, =PORTA_PCR10
	mov r2, #GPIO_MODE_LED
	str r2, [r1]
	ldr r1, =PORTA_PCR11
	str r2, [r1]
	ldr r1, =PORTA_PCR28
	str r2, [r1]
	ldr r1, =PORTA_PCR29
	str r2, [r1]		
	//LED GPIOs als Output konfigurieren
	mov r2, #1
	ldr r1, =BIT_BAND_LED1_MODE
	str r2, [r1]
	ldr r1, =BIT_BAND_LED2_MODE
	str r2, [r1]
	ldr r1, =BIT_BAND_LED3_MODE
	str r2, [r1]
	ldr r1, =BIT_BAND_LED4_MODE
	str r2, [r1]
	//LEDs ausschalten, da diese mit 0 initalisiert werden und über negierte Logik gesteuert werden 
	ldr r1, =BIT_BAND_LED1_DATA
	str r2, [r1]
	ldr r1, =BIT_BAND_LED2_DATA
	str r2, [r1]
	ldr r1, =BIT_BAND_LED3_DATA
	str r2, [r1]
	ldr r1, =BIT_BAND_LED4_DATA
	str r2, [r1]	

program:
	
	bl uart_charPresent
	cmp r0,#0
	beq print_value 							//Kein Zeichen eingelesen, überspringe Überprüfung auf Zeichentypen
	
	//Eingabe = s?
	bl uart_getChar  
	cmp r0,'s'
	bne check_accuracy							//Fahre mit Überprüfung der Genauigkeit fort
	//Togglen Start-Stop-Signal
	eors r5, r5, #XOR_MASK
	//Enable/Disable ADC & Ausgabe
	ittee ne
	ldrne r0, =str_start
	movne r1, #ENABLE_ADC
	ldreq r0, =str_stop
	moveq r1, #DISABLE_ADC
	str r1, [r8] 
	bl uart_putString
	b print_value								

check_accuracy:
	
	//Überprüfe ob Wandlung momentan gestoppt ist, andernfalls kann keine Einstellung vorgenommen werden
	cmp r5, #0
	bne print_value  
	
	cmp r0, '0'
	bne check_accuracy_10
	mov r0, #CFG1_MODE_8
	str r0, [r9]
	mov r6, #MOD_8
	ldr r0, =str_mod_8
	bl uart_putString
	b print_value

check_accuracy_10:

	cmp r0, '1'
	bne check_accuracy_12
	mov r0, #CFG1_MODE_10
	str r0, [r9]
	mov r6, #MOD_10
	ldr r0, =str_mod_10
	bl uart_putString
	b print_value

check_accuracy_12:
	
	cmp r0, '2'
	bne check_accuracy_16
	mov r0, #CFG1_MODE_12
	str r0, [r9]
	mov r6, #MOD_12
	ldr r0, =str_mod_12
	bl uart_putString
	b print_value

check_accuracy_16:

	cmp r0, '3'
	bne print_value
	mov r0, #CFG1_MODE_16
	str r0, [r9]
	mov r6, #MOD_16
	ldr r0, =str_mod_16
	bl uart_putString

	
print_value:	
	
	//Ist eine Sekunde abgelaufen?
	ldrb r0, [r4]
	cmp r0, #1													 
	bne program	
	mov r0, #0
	strb  r0, [r4]
	
	//Wenn die Wandlung gestoppt ist, gebe keine Werte aus
	cmp r5, #0
	beq program
	
	//Ausgabe des momentanen Wertes
	ldr r0, = str_hex
	bl uart_putString
	ldrh r0, [r7]
	mov r10, r0
	bl uart_putInt16
		
	//Berechnung Stufe
	cmp r6, #MOD_8
	bne calc_10
	lsr r11, r10, #SHIFT_BITMASK_8 			//Da 8 eine Zweierpotenz ist, können für die Einteilung einfach die höchstwertigsten Bits betrachtet werden
	ldr r12, =values_8_bit
	b print_voltage
	
calc_10:
	cmp r6, #MOD_10
	bne calc_12
	ldr r0, =UMULL_10						//Anstelle einer Divison durch 10, erfolgt eine Mulitplikation mit (2^32 / (1024/10)) +1
	umull r1,r0, r10, r0					//Wertebereich -> 1024 Werte, Stufen -> 10
	mov r11, r0
	ldr r12, =values_10_bit  
	b print_voltage

calc_12:	
	cmp r6, #MOD_12
	bne calc_16
	ldr r0, =UMULL_12						//Anstelle einer Divison durch 12, erfolgt eine Mulitplikation mit (2^32 / (4096/12)) +1
	umull r1,r0, r10, r0					//Wertebereich -> 4096 Werte, Stufen -> 12
	mov r11, r0  
	ldr r12, =values_12_bit
	b print_voltage
	
calc_16:	
	lsr r11, r10, #SHIFT_BITMASK_16			//Da 16 eine Zweierpotenz ist, können für die Einteilung einfach die höchstwertigsten Bits betrachtet werden
	ldr r12, =values_16_bit
	 
print_voltage:
	
	/*Ausgabe Spannungsbereich*/
	mov r0, ' '
	bl uart_putChar
	
	lsl r0, r11, #1				//Index mit zwei multiplizieren, da pro Werte zwei Bytes adressiert werden
	add r12, r12, r0
	
	/*Ausgabe 1. Zahl 1. Teil*/
	ldrb r0, [r12], #1
	bl uart_putByteBase10
	
	/*Ausgabe 1. Zahl 2. Teil*/
	ldrb r0, [r12], #1
	
	//Muss eine einzelne Null ausgegeben werden?
	cmp r0, #SINGLE_NULL
	it eq
	moveq r0, #0				//Ja, Ersetze für die Ausgabe SINGLE_NULL=100 durch eine 0
	beq print_normal_1
	
	//Müssen zwei Nullen ausgegeben werden?
	cmp r0, #0	
	bne print_normal_1 			//Nein, fahre mit einer normalen Ausgabe fort
	mov r0, '0'					 
	bl uart_putChar				//Ja, gebe eine zusätzliche Null aus 
	mov r0, 0	
	
	//Normale Ausgabe
print_normal_1:
	bl uart_putByteBase10

	ldr r0, =str_minus
	bl uart_putString

	/*Ausgabe 2. Zahl 1.Teil*/
	ldrb r0, [r12], #1
	bl uart_putByteBase10
	
	/*Ausgabe 2. Zahl 2. Teil*/
	ldrb r0, [r12]
	//Muss eine einzelne Null ausgegeben werden?
	cmp r0, #SINGLE_NULL
	it eq
	moveq r0, #0				//Ja, Ersetze für die Ausgabe SINGLE_NULL=100 durch eine 0
	beq print_normal_2 
	//Müssen zwei Nullen ausgegeben werden?
	cmp r0, #0					//Nein, fahre mit einer normalen Ausgabe fort
	bne print_normal_2
	mov r0, '0'
	bl uart_putChar			   //Ja, gebe eine zusätzliche Null aus
	mov r0, 0	
print_normal_2:
	bl uart_putByteBase10
	
	ldr r0, =str_volt
	bl uart_putString
	
	//Ausgabe Stufe Terminal
	ldr r0, =str_stufe
	bl uart_putString
	mov r0, r11
	bl uart_putByteBase10
	mov r0, ')'
	bl uart_putChar
	
	//Ausgabe Stufe LEDs
	and r1, r11, #1
	eor r1, r1, #1 
	ldr r0, =BIT_BAND_LED1_DATA
	str r1, [r0]
	lsr r11, r11, #1
	
	and r1, r11, #1
	eor r1, r1, #1
	ldr r0, =BIT_BAND_LED2_DATA
	str r1, [r0]
	lsr r11, r11, #1

	and r1, r11, #1
	eor r1, r1, #1
	ldr r0, =BIT_BAND_LED3_DATA
	str r1, [r0]
	lsr r11, r11, #1

	and r1, r11, #1
	eor r1, r1, #1
	ldr r0, =BIT_BAND_LED4_DATA
	str r1, [r0]		
	b program
	
end:
	b end

/*	Unterprogrammaufruf zur Kalibrierung und Konfiguration des ADC1 
	Überabeparameter 
		r0:	Adresse ADC1_CFG1

	Rückgabewerte
		r0: Ergebnis der Kalibirierung -> 0 erfolgreich | 1 -> fehlerhaft

*/

.thumb_func
configure_and_calibrate_adc:	

	//Konfiguration ADC	
	mov r1, #CFG1_MODE_16
	str r1, [r0]

	ldr r0, =ADC1_CFG2
	mov r1, #WORD_CFG2
	str r1, [r0]

	ldr r0, =ADC1_SC2
	mov r1, #WORD_SC2
	str r1, [r0]

	ldr r0, =ADC1_SC3
	mov r1, #SC3_CALIBRATE
	str r1, [r0]
	
	//Initalisiere Kalibierung
	ldr r0, =BIT_CAL
	mov r1, #1
	str r1, [r0]
	
	//Überprüfe, ob Initalisierung abgeschlossen wurde
	ldr r0, =BIT_COCO
check_coco:
	ldr r1, [r0]
	cmp r1, #0
	beq check_coco
	 
	//Sichere Ergebnis der Kalibrierung in r0  
	ldr r0, =BIT_CALF 
	ldr r0, [r0] 
	
	//Berechnen des Plus Gain Wertes
	mov r1, #0
	ldr r2, =ADC1_CLP0
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLP1
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLP2
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLP3
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLP4
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLPS
	ldr r2, [r2]
	add r1, r1, r2
	
	//Modifiziern des Plus Gain Wertes nach Handbuch & Speichern im Register 
	lsr r1,r1, #1 					//Durch zwei teilen
	orr r1, r1, #MSB_GAIN			//Setzen des höchsen Bits
	ldr r2, =ADC1_PG
	str r1, [r2]
	
	//Berechnen des Minus Gain Wertes
	mov r1, #0	
	ldr r2, =ADC1_CLM0
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLM1
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLM2
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLM3
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLM4
	ldr r2, [r2]
	add r1, r1, r2
	ldr r2, =ADC1_CLMS
	ldr r2, [r2]
	add r1, r1, r2
	
	//Modifiziern des Minus Gain Wertes nach Handbuch & Speichern im Register
	lsr r1,r1, #1 					//Durch zwei teilen
	orr r1, r1, #MSB_GAIN			//Setzen des höchsten Bits
	ldr r2, =ADC1_MG
	str r1, [r2]	
	bx lr
	
	
/* ISR-Routinte für Timer 1

*/	
	
.thumb_func
interrupt_routine_pit1:

	//Interrupt-Flag zu PIT1 löschen
	mov r0, #1
	ldr r1, =BIT_BAND_TFLG1
	str r0, [r1]
	//Programm-Flag setzen
	ldr r2, =interrupt_flag_pit_1
	strb r0, [r2]
	bx lr
	


/*** Datenbereich (ab 0x20000000) ***/
.data

/*
	Die Ausgabewerte werden in jeweils zwei Bytes aufgeteilt, um direkt die Funktion uart_putByteBase10 nutzen zu können
	Um für die Ausgabe eine Differenzierung zwischen 0 und 00 vornehmen zu können, wird eine 0 im zweiten Teil einer Zahl durch 100 (SINGLE_NULL) ersetzt
*/
values_16_bit: .byte 0, 0, 20,6, 41,3, 61,9, 82,5, 10,31, 12,37, 14,44, 16,50, 18,56, 20,63, 22,69, 24,75, 26,81, 28,88, 30,94, 33,00
values_12_bit: .byte 0, 0, 27,5, 55,SINGLE_NULL , 82,5, 11,00, 13,75, 16,50, 19,25, 22,00, 24,75, 27,50, 30,25, 33,00
values_10_bit: .byte 0, 0, 33,SINGLE_NULL, 66,SINGLE_NULL, 99,SINGLE_NULL, 13,20, 16,50, 19,80, 23,10, 26,40, 29,70, 33,00
values_8_bit: .byte  0, 0, 41,3, 82,5, 12,38, 16,50, 20,63, 24,75, 28,88, 33,00

str_volt: .asciz " mV"
str_error: .asciz "\nKalibrierung fehlerhaft\n"
str_hex: .asciz "\n0x"
str_mod_8: .asciz "\nGenaugikeit 8 Bit"
str_mod_10: .asciz "\nGenaugikeit 10 Bit"
str_mod_12: .asciz "\nGenaugikeit 12 Bit"
str_mod_16: .asciz "\nGenaugikeit 16 Bit"
str_start: .asciz "\nWandlung gestartet\n"
str_stop: .asciz "\nWandlung gestoppt\n"
str_stufe: .asciz " (Stufe "
str_minus: .asciz " - "
interrupt_flag_pit_1: .byte 0x00
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/* Timerkonfiguration */
.equ NVIC_ICSER2, 0xE000E108									//Register für Setzten von Interrupts
.equ NVIC_ICPR2, 0xE000E288										//Register zum Löschen von hängenden Interrupts
.equ NVIC_PIT1_BIT, 1 << 5				  						//Berechnung IRQ (69) mod 32 = 5
.equ VEKTORTABELLE_BASIS, 0x01FFFFE00	  						//Beginn Vektortabelle
.equ OFFSET_PIT1, 0x00000154			  						//Offset Interrupt-Adresse PIT1
.equ PIT_CHANNEL1_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PIT1
.equ PIT_MCR, 0x40037000				  						//PIT Modul Kontrollregister
.equ WORD_PIT_MCR, 0x0											//Steuerwort PIT Modul Kontrollregister 
.equ BITMASK_TCTRL1, (1 << 0) | (1 << 1) 						//Timer enable, Interupt enable, Chained disable
.equ PIT_LDVAL1, 0x40037110				  						//Register für Startwert
.equ TIMER, 24999999					  						//Entspricht einer Sekunde
.equ PIT_TCTRL1, 0x40037118				  						//Timer Kontrollregister
.equ PIT_TFLG1, 0x4003711C				  						//Timer Flagregister
__BBREG BIT_BAND_TFLG1, PIT_TFLG1, 0
.equ SIM_SCGC6, 0x4004803C
.equ WORD_SCGC6, (1 << 23)  									//Aktiviere Clock PIT 



/* IIC Konfiguration */
.equ SIM_SCGC4, 0x40048034
.equ WORD_SIM_SCGC4, (1 << 6) 				//Aktiviere Clock IIC0-Modul

.equ I2C0_A1, 0x40066000        			//I2C Address Register 1 
.equ I2C0_F, 0x40066001         			//I2C Frequency Divider register 
.equ I2C0_F_WORD,  0xA3						//MUL FACTOR = 4 | ICR = 0x23 -> entspricht gemäß Berechnung circa 400kHz 

.equ I2C0_C1, 0x40066002        			//I2C Control Register 1 
.equ I2C0_C1_ENABLE_I2C, (1 << 7)  			//I2C Enable 
.equ TRANSMIT, 1
.equ RECEIVE, 0
.equ NACK, 1
.equ ACK, 0
.equ MAX_TRY_RESET, 10 + 1

__BBREG MASTER_MODE, I2C0_C1, 4				//Transmit/Receive Bit 
__BBREG TRANSMIT_ACKNOLEDGE, I2C0_C1, 3		//Transmit Acknowledge Bit
__BBREG REPEAT_START, I2C0_C1, 2			//Repeat Start	
__BBREG START_STOP_SIGNAL, I2C0_C1, 5 		//Master Mode Select

.equ I2C0_S, 0x40066003         			//I2C Status register 
__BBREG IICIF, I2C0_S, 1					//Interrupt Flag
__BBREG TRANSFER_COMPLETE_FLAG, I2C0_S, 6	//Transfer Complete Flag
__BBREG BUS_BUSY_FLAG, I2C0_S, 5			//Bus Busy Flag
__BBREG ARBITRATION_LOST, I2C0_S, 4  		//Arbitration-Flag-Lost
__BBREG RXAK, I2C0_S, 0  					//Receive Acknowledge Bit

.equ I2C0_D, 0x40066004        				//I2C Data I/O register 
.equ I2C0_C2, 0x40066005        			//I2C Control Register 2 
.equ IC20_RESET_BYTE, 0x00					//Disable general call address | 7 Bit Adresse | normal drive mode | slave baud rate follows master | range mode disabled | slave adress not relevant
.equ I2C0_FLT, 0x40066006       			//I2C Programmable Input Glitch Filter register 
.equ I2C0_RA, 0x40066007        			//I2C Range Address register 
.equ I2C0_SMB, 0x40066008       			//I2C SMBus Control and Status register 
.equ I2C0_A2, 0x40066009        			//I2C Address Register 2 
.equ I2C0_SLTH, 0x4006600A      			//I2C SCL Low Timeout Register High 
.equ I2C0_SLTL, 0x4006600B      			//I2C SCL Low Timeout Register Low 
 

.equ SIM_SCGC5, 0x40048038
__BBREG SIM_PORTD, SIM_SCGC5, 12
.equ PORTD_PCR8, 0x4004C020 				//Pin Control Register 8
.equ PORTD_PCR9, 0x4004C024 				//Pin Control Register 9
.equ PD8_9, 0x300 							//Maske fuer PD8 und PD9
.equ PD8, 0x100 							//Maske fuer PD8
.equ ALT_GPIO, 0x100 						//Alternative 1: GPIO
.equ GPIO_IIC, 0x200						//Mode chip-specific 2
.equ GPIOD_PDOR, 0x400FF0C0 				//Port Data Output Register 
.equ GPIOD_PDIR, 0x400FF0D0 				//Port Data Input Register 
.equ GPIOD_PDDR, 0x400FF0D4 				//Port Data Direction Register 
.equ COUNTER, 50							//25 MHz entsprechen 0.04 us -> 50 x 0.04us = 2us


/* DS75 Konfiguration */
.equ DS75_READ_ADRESS, 0x91
.equ DS75_WRITE_ADRESS, 0x90
.equ DS75_POINTER_TEMP, 0b00
.equ DS75_POINTER_CONFIG, 0b01
.equ DS75_POINTER_TOS, 0b10
.equ DS75_POINTER_THYST, 0b11
.equ DS75_CONFIGURATION_REGISTER, (1 << 6) | (1 << 5)  //12 Bit Auflösung, Comperator Mode

/* Konstanten Berechnung Temperatur */
.equ HAELFTE, 50
.equ VIERTEL, 25
.equ ACHTEL, 13
.equ SECHZEHNTEL, 6 
.equ BITMASK_HAELFTE, (1 << 7)
.equ BITMASK_VIERTEL, (1 << 6)
.equ BITMASK_ACHTEL, (1 << 5)
.equ BITMASK_SECHZEHNTEL, (1 << 4)

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	

	bl uart_init
	
	/* Timer konfigurieren */
	
	//Aktivieren Takt PIT  
	ldr r0, =SIM_SCGC6
	mov r1, #WORD_SCGC6
	str r1, [r0]
										
	//Interrupt-Vektor zu PIT1  Speichern der Adresse der Routine in Vektortabelle
	ldr r0, =interrupt_routine_pit1
	ldr r1, =PIT_CHANNEL1_INTERRUPT
	str r0, [r1]

	//NVIC_ICPR2 5.Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r0, =NVIC_ICPR2
	mov r1, #NVIC_PIT1_BIT
	str r1, [r0]
	
	//NVIC_ISER2 5.Bit setzen, um Interrupt zu aktivieren
	ldr r0, =NVIC_ICSER2
	str r1, [r0]
	
	// PITs aktivieren 
	ldr r0, =PIT_MCR
	mov r1, #WORD_PIT_MCR
	str r1, [r0]
	
	//Startwert für PIT1 auf 1 Sekunde initalisieren
	ldr r0, =PIT_LDVAL1
	ldr r1, =TIMER
	str r1, [r0]

	//TFLG1-Flag zurücksezten
	ldr r0, =BIT_BAND_TFLG1	
	mov r1, #1
	str r1, [r0]
	
	//Interrupt zu PIT1 akitvieren, PIT1 aktivieren, PIT1  Chainend Mode disabled
	ldr r0, =PIT_TCTRL1
	mov r1, #BITMASK_TCTRL1 
	str r1, [r0]
	
	/* IIC Modul  konfigurieren */
	bl I2CBus_Reset
	bl I2CBus_Initalize


	/* Schreiben des DS75 Konfigurationsregisters */
	mov r4, #DS75_POINTER_CONFIG
	//12-Bit Auflösung & Komparator-Modus einstellen
	mov r5, #DS75_CONFIGURATION_REGISTER

retry_configuration:	
	//Send Start Signal
	mov r0, #DS75_WRITE_ADRESS
	bl start
	
	//Überprüfe, ob Slave 1. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_configuration
	
	//Write Pointer Byte 
	mov r0, r4
	bl data_write
	
	//Überprüfe, ob Slave 2. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_configuration
	
	//Write Data Byte
	mov r0, r5
	bl data_write
	
	//Überprüfe, ob Slave 3. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_configuration
	//Send stop signal
	bl stop 
	
	
	/* T0 bestimmen */
	mov r0, #DS75_POINTER_TEMP
	bl read_single_byte_new_pointer
	bl read_2_bytes_current_pointer
	//Ergebnis zwischenspeichern
	mov r4, r0
	mov r5, r1
	
	/* Grenzwert T0 +3 in TOS eintragen*/
	mov r0, #DS75_POINTER_TOS
	add r1, r4, #3
	mov r2, r5
	bl write_tos_thyst
	
	/* Grenzwert T0 +2 in THYST eintragen*/
	mov r0, #DS75_POINTER_THYST
	add r1, r4, #2
	mov r2, r5
	bl write_tos_thyst
	
	/* Konfiguration auf Temperatur umstellen */
	mov r0, #DS75_POINTER_TEMP
	bl read_single_byte_new_pointer


	/* Registerbelegung für Hauptprogramm 	
		r4: Adresse Interrupt_flag_pit_1
	*/
	//Initalisierung Register
	ldr r4, =interrupt_flag_pit_1

program:

	/* Verarbeitung Interrupt */
	ldrb r0, [r4]
	cmp r0, #1													 
	bne program	
	mov r0, #0
	strb  r0, [r4]
	
	/*Temperaturwert lesen & ausgeben*/
	ldr r0, =hex
	bl uart_putString
	bl read_2_bytes_current_pointer
	//Zwischenspeichern Ergebnis
	mov r5, r0
	mov r6, r1
	
	/* Ausgabe Terminal */
	bl uart_putInt16
	mov r0, '_'
	bl uart_putChar
	mov r0, r6
	bl uart_putInt16

	ldr r0, =trennzeichen
	bl uart_putString
	mov r0, r5
	bl uart_putByteBase10
	mov r0, ','
	bl uart_putChar
	
	//Nachkommastellen berechnen
	mov r0, #0
	ands r1, r6, #BITMASK_HAELFTE
	it ne
	addne r0, #HAELFTE
	ands r1, r6, #BITMASK_VIERTEL
	it ne
	addne r0, #VIERTEL
	ands r1, r6, #BITMASK_ACHTEL
	it ne
	addne r0, #ACHTEL
	ands r1, r6, #BITMASK_SECHZEHNTEL
	it ne
	addne r0, #SECHZEHNTEL
	
	//Muss eine führende Null ausgegeben werden?
	cmp r0, #SECHZEHNTEL
	bne ausgabe_normal
	//Ergebnis zwischenspeichern, um führende Null auszugeben
	mov r6, r0
	mov r0, '0'
	bl uart_putChar
	mov r0, r6
	
ausgabe_normal:	
	bl uart_putByteBase10
	ldr r0, =celsius
	bl uart_putString
	
	b program

error:
	ldr r0, =error_init
	bl uart_putString
	
end:	
	b end



/* Funktion zum Schreiben des Tos- & Thyst-Registers des DS75

	Übergabeparameter
		r0: Pointerbyte
		r1: Datenbyte MS
		r2: Datenbyte LS
		
	Rückgabewerte:
		- 
*/
.thumb_func 
write_tos_thyst:
	push {r4-r6, lr}
	
	//Übergabeparameter sichern
	mov r4, r0
	mov r5, r1 
	mov r6, r2
	
retry_tos_thyst:	
	
	//Send Start Signal
	mov r0, #DS75_WRITE_ADRESS
	bl start
	
	//Überprüfe, ob Slave 1. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_tos_thyst
	
	//Write Pointer Byte 
	mov r0, r4
	bl data_write
	
	//Überprüfe, ob Slave 2. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_tos_thyst
	
	//Write Data Byte MS
	mov r0, r5
	bl data_write
	
	//Überprüfe, ob Slave 3. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_tos_thyst
	
	//Write Data Byte LS
	mov r0, r6
	bl data_write
	
	//Überprüfe, ob Slave 4. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_tos_thyst

	//Send stop signal
	bl stop 
	pop {r4-r6, pc}



/* Funktion zum Lesen eines Bytes, von einer neuen Adresse DS75 

	Übergabeparameter
		r0: Pointerbyte
	Rückgabewerte:
		r0: Gelesenses Byte 
*/
.thumb_func 
read_single_byte_new_pointer:
	push {r4, lr}
	
	//Übergabeparameter sichern
	mov r4, r0 
	
retry_single_byte_new_pointer:	
	
	//Send Start Signal
	mov r0, #DS75_WRITE_ADRESS
	bl start
	
	//Überprüfe, ob Slave 1. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_single_byte_new_pointer
	
	//Write Pointer Byte 
	mov r0, r4
	bl data_write
	
	//Überprüfe, ob Slave 2. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry_single_byte_new_pointer
	
	//Send Repeat-Start-Signal
	ldr r0, =REPEAT_START
	mov r1, #1
	strb r1, [r0]
	
	//Write: Data register with the address of the target slave 
	mov r0, #DS75_READ_ADRESS
	bl data_write
	
	//Überprüfe, ob Slave 3. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry
	
	//Change mode to receive
	mov r0,  #RECEIVE
	bl set_mode
	
	//Configure NACK
	mov r0, #NACK
	bl configure_ack
	
	//Dummy read
	bl data_read
	bl check_and_clear_iicif
	
	//Send stop signal
	bl stop 
	//Lesen MS Byte
	bl data_read
	pop {r4, pc}


/* Funktion zum Lesen von 2 Bytes vom DS75 

	Übergabeparameter:
		- 
	Rückgabewerte
		r0: MS Data Byte
		r1: LS Data Byte		
*/
.thumb_func
read_2_bytes_current_pointer:
	push {r4, lr}

retry:	
	//Send Start Signal
	mov r0, #DS75_READ_ADRESS
	bl start
	
	//Überprüfe, ob Slave 1. ACK gesendet hat
	bl check_rxak 
	cmp r0, #0
	bne retry
	
	//Change mode to receive
	mov r0,  #RECEIVE
	bl set_mode
	
	//Configure ACK
	mov r0, #ACK
	bl configure_ack
	
	//Dummy read
	bl data_read
	bl check_and_clear_iicif
	
	//Configure NACK
	mov r0, #NACK
	bl configure_ack

	//Lesen MS Byte
	bl data_read
	
	//Zwischenspeichern Ergebnis
	mov r4, r0
	bl check_and_clear_iicif

	//Send stop signal
	bl stop 	
	//Lesen LS Byte
	bl data_read
	
	//Reihenfolge tauschen: MS Byte: R0 - LS Byte: R1
	mov r1, r0
	mov r0, r4
	pop {r4, pc}


/* Funktion zum Zurücksetzen des I2CBus 
	Übergabeparameter:
		-
	Rückgabewerte:
		-
*/
.thumb_func
I2CBus_Reset:
	push {lr}
	ldr r0 , =SIM_PORTD // Den Takt fuer Port D aktivieren
	mov r1 , #1
	str r1 , [r0]
	
	ldr r0 , =PORTD_PCR8 // Portleitungen PD8 , PD9 als GPIO
	ldr r1 , =PORTD_PCR9
	mov r2 , #ALT_GPIO
	str r2 , [r0]
	str r2 , [r1]
	ldr r0 , =GPIOD_PDDR // PD8 , PD9 als Ausgang schalten
	ldr r2 , [r0]
	orr r2 , r2 , #PD8_9
	str r2 , [r0]

	mov r3, #MAX_TRY_RESET

loop:
	//Abfangen wiederholter Fehlschläge
	subs r3, r3, #1
	beq error
	
	ldr r0 , =GPIOD_PDOR 			//SCL deaktivieren
	ldr r2 , [r0]
	bic r2 , r2 , #PD8 				//Entsprechendes Bit loeschen
	str r2 , [r0]
	bl i2c_Delay

	ldr r0 , =GPIOD_PDOR 			//SCL und SDA aktivieren
	ldr r2 , [r0]
	orr r2 , r2 , #PD8_9
	str r2 , [r0]
	bl i2c_Delay

	ldr r0 , = GPIOD_PDIR
	ldr r2 , [r0]
	and r2 , r2 , #PD8_9 		// nur Bits 9 und 10 pruefen
	cmp r2 , #PD8_9 			// Bit 9 und Bit 10 gesetzt ?
	bne loop 					// ggf. wiederholen
	pop {pc}


/* Funktion zum Initalisieren des I2CBus 
	Übergabeparameter:
		-
	Rückgabewerte:
		-
*/
.thumb_func
I2CBus_Initalize:
	//Module Initialization Master
	
	// Portleitungen PD8 , PD9 als IIC2	
	ldr r0 , =PORTD_PCR8 
	ldr r1 , =PORTD_PCR9
	mov r2 , #GPIO_IIC
	str r2 , [r0]
	str r2 , [r1]
	
	//Takt für IIC0 aktivieren
	ldr r0, =SIM_SCGC4
	mov r1, #WORD_SIM_SCGC4
	str r1, [r0]
	
	//1. Write: Frequency Divider register to set the I2C baud rate
	ldr r0, =I2C0_F
	mov r1, #I2C0_F_WORD
	strb r1, [r0]   
			
	//2. Write: Control Register 1 to enable the I2C module 
	ldr r0, =I2C0_C1
	mov r1, #I2C0_C1_ENABLE_I2C
	strb r1, [r0]  
	
	//Restlichen Register konfigurieren
	ldr r0, =I2C0_C2        			
	mov r1, #IC20_RESET_BYTE
	strb r1, [r0]	
	ldr r0, =I2C0_FLT
	strb r1, [r0]	
	ldr r0, =I2C0_RA
	strb r1, [r0]	
	ldr r0, =I2C0_SMB
	strb r1, [r0]	
	ldr r0, =I2C0_A2
	strb r1, [r0]	
	ldr r0, =I2C0_SLTH
	strb r1, [r0]	
	ldr r0, =I2C0_SLTL
	strb r1, [r0]	
	
	bx lr

/* Funktion zum Starten einer Datenübertragung 
	Übergabeparameter:
		r0: Slave Adresse
	Rückgabewerte:
		- 
*/
.thumb_func
start:
	push {r4,lr}	
	//Übergabeparameter sichern
	mov r4, r0
	
	//Write Control Register 1 to enable TX  	
	mov r0, #TRANSMIT
	bl set_mode
	
	ldr r0 , =BUS_BUSY_FLAG
check_busy_flag:	
	ldrb r1, [r0]
	cmp r1, #0
	bne check_busy_flag 
	
	ldr r0, =START_STOP_SIGNAL
send_start_signal:
	mov r1, #1
	strb r1, [r0]
	ldrb r0, [r0]
	cmp r0, #1
	bne send_start_signal
	
	//Slave Adresse schreiben
	mov r0, r4
	bl data_write
	pop {r4, pc}


/* Funktion zum Schreiben eines Bytes 
	Übergabeparameter:
		r0: Zu schreibendes Byte
	Rückgabewerte:
		- 
*/
.thumb_func 
data_write:
	push {lr}
	ldr r1, =I2C0_D
	strb r0, [r1]
	bl check_and_clear_iicif
	pop {pc}


/* Funktion zum Lesen eines Bytes 
	Übergabeparameter:
		-
	Rückgabewerte:
		r0: Gelesenes Byte 
*/
.thumb_func
data_read:
	ldr r0, =I2C0_D
	ldrb r0, [r0]
	bx lr

/* Funktion zum Stoppen eines Datentransfers 
	Übergabeparameter:
		-
	Rückgabewerte:
		- 
*/
.thumb_func
stop:
	push {lr}
	ldr r0, =START_STOP_SIGNAL
	mov r1, #0
	strb r1, [r0]
	bl i2c_Delay
	pop {pc}


/* Funktion um zu überprüfen ob der Slave ein ACK gesendet hat 
	Übergabeparameter:
		-
	Rückgabewerte:
		r0:  0 -> ACK gesendet | 1 -> ACK nicht gesendet 
*/
.thumb_func
check_rxak:
	ldr r0, =RXAK
	ldrb r0, [r0]
	bx lr

/* Funktion zum Setzen des RX bzw. TX Modus 
	Übergabeparameter:
		r0: Modus
	Rückgabewerte:
		- 
*/
.thumb_func
set_mode:
	ldr r1, =MASTER_MODE
	strb r0, [r1] 
	bx lr


/* Funktion zum Konfigurieren von ACK & NACK 
	Übergabeparameter:
		r0: Zu konfiguriender Wert
	Rückgabewerte:
		- 
*/
.thumb_func
configure_ack:
	ldr r1, =TRANSMIT_ACKNOLEDGE
	strb r0, [r1]
	bx lr

/* Funktion zum Überprüfen und Löschen des IICI-Flags 
	Übergabeparameter:
		-
	Rückgabewerte:
		- 
*/		
.thumb_func
check_and_clear_iicif:
	ldr r0, =IICIF
read_iicif:
	ldrb r1, [r0]
	cmp r1, #1
	bne read_iicif
	strb r1, [r0]
	bx lr


/* Funktion zur Erzeugung einer Verzögerung von circa 50 us 
	Übergabeparameter:
		-
	Rückgabewerte:
		-
*/
.thumb_func
i2c_Delay:

	//Initalisierung Counter
	ldr r0, =COUNTER
iteration:
	//Counter bis 0 runterzählen
	subs r0, r0, #1
	bne iteration
	bx lr


/* ISR für Timer Interrupt 
	Übergabeparameter:
		-
	Rückgabewerte:
		- 
*/
.thumb_func
interrupt_routine_pit1:
	//Interrupt-Flag zu PIT1 löschen
	mov r0, #1
	ldr r1, =BIT_BAND_TFLG1
	str r0, [r1]
	//Programm-Flag setzen
	ldr r2, =interrupt_flag_pit_1
	strb r0, [r2]
	bx lr
	

/*** Datenbereich (ab 0x20000000) ***/
.data
error_init: .asciz "Fehler bei der Initialisierung.\n"
hex: .asciz "0x"
trennzeichen: .asciz ": "
celsius: .asciz "  Grad Celsius\n"
interrupt_flag_pit_1: .byte 0x00
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified


/* Timer Konstantendeklaration */
.equ NVIC_ICSER2, 0xE000E108									//Register für Setzten von Interrupts
.equ NVIC_ICPR2, 0xE000E288										//Register zum Löschen von hängenden Interrupts
.equ NVIC_PIT1_BIT, 1 << 5				  						//Berechnung IRQ (69) mod 32 = 5
.equ VEKTORTABELLE_BASIS, 0x01FFFFE00	  						//Beginn Vektortabelle
.equ OFFSET_PIT1, 0x00000154			  						//Offset Interrupt-Adresse PIT1
.equ PIT_CHANNEL1_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PIT1
.equ PIT_MCR, 0x40037000				  						//PIT Modul Kontrollregister
.equ WORD_PIT_MCR, 0x0											//Steuerwort PIT Modul Kontrollregister 
.equ BITMASK_TCTRL, (1 << 0) | (1 << 1) 						//Timer enable, Interupt enable, Chained disable
__BBREG TIMER_ENABLE, PIT_TCTRL, 0
.equ PIT_LDVAL, 0x40037110				  						//Register für Startwert
.equ TIMER, 24999999					  						//Entspricht einer Sekunde
.equ PIT_TCTRL, 0x40037118				  						//Timer Kontrollregister
.equ PIT_TFLG, 0x4003711C				  						//Timer Flagregister
__BBREG TFLG, PIT_TFLG, 0


/* SPI Konstantendeklaration */
.equ SPI2_CTAR0, 0x400AC00C 						//DSPI Clock and Transfer Attributes Register
.equ CTAR0_WORD, (0xf << 27) | (1 << 25) | (0x7)  	// Frame Size 15 | Clock Phase = 1 | Baud Rate Prescaler 2 | Baud Rate Scaler 128
.equ SPI2_CTAR1, 0x400AC010
.equ CTAR1_WORD, (0x7 << 27) | (1 << 25) | (0x7)  	// Frame Size 8, ansonsten identisch zu CTAR0

.equ SPI2_MCR, 0x400AC000 //Module Configuration Register  
.equ MCR_WORD, (1 << 31) |  (1 << 13) | (1 << 12) | (1 << 0)	//Master Mode Select | Disable Tramist FIFO | Disable Receive FIFO | Stop transfer
__BBREG HALT, SPI2_MCR, 0

.equ SPI2_RSER, 0x400AC030		//DMA/Interrupt Request Select and Enable Register
.equ SPI2_TCR, 0x400AC008		//Transfer Count Register
   
.equ SPI2_SR, 0x400AC02C 		//DSPI Status Register 
__BBREG TCF, SPI2_SR, 31
.equ TIMEOUT_TCF, 500
 
.equ SPI2_PUSHR, 0x400AC034 	//PUSH TX FIFO Register   
.equ SPI2_POPR, 0x400AC038 		//POP RX FIFO Register 


/* SIM Konstantendeklaration */
.equ SIM_SCGC6, 0x4004803C
__BBREG CLOCK_PIT, SIM_SCGC6, 23

.equ SIM_SCGC5, 0x40048038
__BBREG CLOCK_PORTA, SIM_SCGC5, 9
__BBREG CLOCK_PORTD, SIM_SCGC5, 12
__BBREG CLOCK_PORTE, SIM_SCGC5, 13

.equ SIM_SCGC3, 0x40048030
__BBREG CLOCK_SPI2, SIM_SCGC3, 12

/* GPIOS & PORTS Konstantendkeklaration */

//Pin Control Register
.equ PORTD_PCR12, 0x4004C030  
.equ PORTD_PCR13, 0x4004C034 
.equ PORTD_PCR14, 0x4004C038 
.equ PORTD_PCR15, 0x4004C03C 
.equ PORTE_PCR26, 0x4004D068
__BBREG ISR_SW2, PORTE_PCR26, 24
.equ PORTA_PCR19, 0x4004904C
__BBREG ISR_SW1, PORTA_PCR19, 24
.equ GPIO_SPI, 0x200					  											//Mode chip-specific 2
.equ GPIO_MODE_BUTTON_ISR, (1 << 8) | (1 << 1) | (1 << 0) | (1 << 19) | (1 << 17) 	// GPIO | Widerstand aktiviert | Pull Down Widerstand | Interrupt auf fallende Flanke

.equ OFFSET_PORTA, 0x0000019C			  											//Offset Interrupt-Adresse PortA
.equ OFFSET_PORTE, 0x000001AC			 											//Offset Interrupt-Adresse PortE
.equ NVIC_SW2_BIT, 1 << 27			  												//Berechnung IRQ (91) mod 32 = 27
.equ NVIC_SW1_BIT, 1 << 23				  											//Berechnung IRQ (87) mod 32 = 23
.equ SW1_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PORTA
.equ SW2_INTERRUPT, VEKTORTABELLE_BASIS + OFFSET_PORTE

//Data Direction Register
.equ GPIOC_PDDA, 0x400FF014	
__BBREG BIT_BAND_SW1_MODE, GPIOC_PDDA, 19				
.equ GPIOC_PDDE, 0x400FF114	
__BBREG BIT_BAND_SW2_MODE, GPIOC_PDDE, 26


/* Konstantendeklaration DS1722*/
.equ CONFIGURATION_WRITE, 0x80
.equ TEMP_READ,	(1 << 31) |  (1 << 17) | (0x1 << 8) 								//CONT enabled | no EOQF-Flag |verwende CTAR1 | Adresse LSB
.equ TEMP_READ_RESET_CONT,	(1 << 28)  |(1 << 27) | (1 << 17) | (0x1 << 8) 			//CONT disabled | EOFQ-Flag | verwende CTAR0 | Adresse LSB 
.equ DS1722_RESOLUTION, (1 << 17) | (CONFIGURATION_WRITE << 8) | (0xE0)				//Kontiniuierliche Wandlung | Shutdown Bit = 0
.equ DS1722_12_BIT, DS1722_RESOLUTION | (0x8)  										//12 Bit Auflösung 

.equ BIT_POSITION_RESOLUTION, 1
.equ RESOLUTION_8, 8
.equ RESOLUTION_9, 9
.equ RESOLUTION_10, 10
.equ RESOLUTION_11, 11
.equ RESOLUTION_12, 12
.equ TIMER_8,  1874999		// 0.075s
.equ TIMER_9,  3749999		// 0.15s
.equ TIMER_10, 7499999		// 0.3s
.equ TIMER_11, 14999999		// 0.6s
.equ TIMER_12, 29999999		// 1.2s
.equ BITMASK_BYTE, 0xFF		


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init


	/* Konifuration Clock & Pins */

	//Aktiviere Clock für Port D
	mov r0, #1
	ldr r1, =CLOCK_PORTD
	str r0, [r1]

	//Konfiguriere Pins für SPI
	mov r2, #GPIO_SPI
	ldr r1, =PORTD_PCR12
	str r2, [r1]
	ldr r1, =PORTD_PCR13
	str r2, [r1]	
	ldr r1, =PORTD_PCR14
	str r2, [r1]
	ldr r1, =PORTD_PCR15
	str r2, [r1]
	
	//Aktiviere Clock für SPI2
	ldr r1, =CLOCK_SPI2
	str r0, [r1]
	//Aktiviere Clock für PIT
	ldr r1, =CLOCK_PIT
	str r0, [r1]
	//Aktiviere Clock für Port A & E 
	ldr r1, =CLOCK_PORTA
	str r0, [r1]
	ldr r1, =CLOCK_PORTE
	str r0, [r1]	
	
	//Konfiguriere Pins für ISR
	ldr r2, =GPIO_MODE_BUTTON_ISR
	ldr r1, =PORTE_PCR26
	str r2, [r1]
	ldr r1, =PORTA_PCR19
	str r2, [r1]
	
	//GPIOs als Input konfigurieren
	ldr r1, =BIT_BAND_SW1_MODE
	str r3, [r1]
	ldr r1, =BIT_BAND_SW2_MODE
	str r3, [r1]
	
	
	/*Initalisierung SPI2 */
	
	
	
	//MCR konfigurieren
	ldr r2, =SPI2_MCR
	ldr r1, =MCR_WORD
	//Schreibe Konfigurationsword zweimal, da DIS_RXF & DIS_TXF nur gesetzt werden können, wenn MDIS nicht gesetzt ist
	str r1, [r2]
	str r1, [r2]

	//Transfer Count Register mit 0 initalisieren
	mov r3, #0
	ldr r1, =SPI2_TCR
	str r3, [r1]
	
	
	//Konifguriere CTARx Register 
	ldr r2, =SPI2_CTAR0 
	ldr r1, =CTAR0_WORD
	str r1, [r2]
	
	ldr r2, =SPI2_CTAR1
	ldr r1, =CTAR1_WORD
	str r1, [r2]
	
	
	//Deaktiviere alle DMA & Interrupts Requests 
	ldr r2, =SPI2_RSER
	str r3, [r2]
	
	
	/*Interruptkonfiguration*/	
	
	
	//Eintragen der Routinen in Vektortabelle
	ldr r2, =interrupt_routine_pit1
	ldr r1, =PIT_CHANNEL1_INTERRUPT
	str r2, [r1]
	ldr r2, =interrupt_routine_sw1
	ldr r1, =SW1_INTERRUPT
	str r2, [r1]
	ldr r2, =interrupt_routine_sw2
	ldr r1, =SW2_INTERRUPT
	str r2, [r1]
	
	//NVIC_ICPR2 5. 23. & 27. Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r2, =NVIC_ICPR2
	ldr r1, =(NVIC_PIT1_BIT | NVIC_SW2_BIT | NVIC_SW1_BIT) 
	str r1, [r2]
	//NVIC_ISER2 5. 23. & 27. Bit setzen, um Interrupts zu aktivieren
	ldr r2, =NVIC_ICSER2
	str r1, [r2]
	// PITs aktivieren 
	ldr r2, =PIT_MCR
	mov r1, #WORD_PIT_MCR
	str r1, [r2]
	//Startwert für PIT1 auf 1.2 Sekunden initalisieren
	ldr r2, =PIT_LDVAL
	ldr r1, =TIMER_12
	str r1, [r2]
	//TFLG1-Flag zurücksezten
	ldr r2, =TFLG	
	str r0, [r2]
	//Interrupt zu PIT1 akitvieren, PIT1 aktivieren, PIT1  Chainend Mode disabled
	ldr r2, =PIT_TCTRL
	mov r1, #BITMASK_TCTRL 
	str r1, [r2]
	

/*Registerbelegungen Hauptprogramm
	r4 : PUSHR
	r5 : HALT
	r6 : Aktuelle Auflösung
	r7 : MSB Temperatur
	r8 : LSB Temperatur
	r9 : Adresse Program Flag Timer
	r10 : Adresse Program Flag SW1
	r11 : Adresse Program Flag SW2
*/
	         
	/* Initalisierung Registerbelegung */
	ldr r4, =SPI2_PUSHR
	ldr r5, =HALT
	mov r6, #RESOLUTION_12
	ldr r9, =interrupt_flag_pit_1
	ldr r10, =interrupt_flag_sw_1
	ldr r11, =interrupt_flag_sw_2

	/* Schreibe Konfigurationsregister */
	ldr r0, =DS1722_12_BIT
	bl spi_write
	


	/* Beginn Hauptprogramm */
	
	/* Ggfs. Anpassung der Auflösung */

increase_resolution:
	ldrb r0, [r10]
	cmp r0, #1													 
	bne decrease_resolution	
	mov r0, #0
	strb  r0, [r10]
	
	cmp r6, #RESOLUTION_12 
	it eq
	//Abfangen Überlauf
	moveq r6, #RESOLUTION_8-1
	
	add r6, r6, #1
	b write_configuration
	
decrease_resolution:
	ldrb r0, [r11]
	cmp r0, #1													 
	bne read_value	
	mov r0, #0
	strb  r0, [r11]
	
	cmp r6, #RESOLUTION_8 
	it eq
	//Abfangen Überlauf
	moveq r6, #RESOLUTION_12+1
	
	sub r6, r6, #1
	
	
	/* Schreibe neue Konfiguraiton */
	
write_configuration:

	//Ausgabe Terminal
	ldr r0, =str_resolution
	bl uart_putString
	mov r0, r6
	bl uart_putByteBase10
	ldr r0, =str_bit
	bl uart_putString
	
	//Stoppe Timer 
	mov r0, #0
	ldr r1, =TIMER_ENABLE
    str r0, [r1] 
	
	//Lade Basiskonfiguraion
	ldr r0, =DS1722_RESOLUTION
	
	//Vorbereiten Maskierung
	sub r1, r6, #RESOLUTION_8
	lsl r1, r1, #BIT_POSITION_RESOLUTION
	
	orr r0, r0, r1
	bl spi_write

	
	/* Passe Timer an neue Wandlungszeit an */
	cmp r6, #RESOLUTION_8
	it eq
	ldreq r1, =TIMER_8
	cmp r6, #RESOLUTION_9
	it eq
	ldreq r1, =TIMER_9
	cmp r6, #RESOLUTION_10
	it eq
	ldreq r1, =TIMER_10
	cmp r6, #RESOLUTION_11
	it eq
	ldreq r1, =TIMER_11
	cmp r6, #RESOLUTION_12
	it eq
	ldreq r1, =TIMER_12
	
	// Starte Timer erneut
	ldr r0, =PIT_LDVAL
	str r1, [r0]
	ldr r0, =TIMER_ENABLE
    mov r1, #1
    str r1, [r0]  	

read_value:
	/* Überprüfen, ob nächster Wert ausgelesen werden kann */ 
	ldrb r0, [r9]
	cmp r0, #1													 
	bne increase_resolution	
	mov r0, #0
	strb  r0, [r9]

	/*Lese momentanen Temperaturwert aus */
	// clear HALT
	mov r0, #0
	str r0, [r5]	
	
	ldr r3, =TEMP_READ
	str r3, [r4]
	
	bl spi_read
	and r0, r0, #BITMASK_BYTE
	mov r8, r0
	
	ldr r3, =TEMP_READ_RESET_CONT
	str r3, [r4]

	// MSB auslesen
	bl spi_read
	and r0, r0, #BITMASK_BYTE
	mov r7, r0

	//set HALT
	mov r0, #1
	str r0, [r5]
	

	/*Ausgabe Terminal*/
	mov r0, r7
	bl uart_putByteBase10
	
	
	//Lase Basisadresse String Array
	ldr r0, =str_array_lsb
	
	//Berechne Offset 
	lsr r8, #2
	add r0, r0, r8
	
	//Lade String für Nachkommastelle
	ldr r0, [r0]
	bl uart_putString
	ldr r0, =celsius
	bl uart_putString
	
	b increase_resolution

error: 
	ldr r0, =error_tcf
	bl uart_putString
		
end:
	b end



.thumb_func
interrupt_routine_pit1:
	//Interrupt-Flag zu PIT1 löschen
	mov r0, #1
	ldr r1, =TFLG
	str r0, [r1]
	//Programm-Flag setzen
	ldr r2, =interrupt_flag_pit_1
	strb r0, [r2]
	bx lr


.thumb_func
interrupt_routine_sw1:

	//Interrupt-Flag Button löschen
	mov r0, #1
	ldr r1, =ISR_SW1
	str r0, [r1]
	
	ldr r1, =interrupt_flag_sw_1	
	strb r0, [r1]
	bx lr


.thumb_func
interrupt_routine_sw2:

	//Interrupt-Flag Button löschen
	mov r0, #1
	ldr r1, =ISR_SW2
	str r0, [r1]
	
	ldr r1, =interrupt_flag_sw_2	
	strb r0, [r1]
	bx lr

/* Funktion zum Überprüfen und Löschen des TCF-Flags 
	Übergabeparameter:
		-
	Rückgabewerte:
		- 
*/		
.thumb_func
spi_read:
	ldr r0, =TCF
	mov r2, #TIMEOUT_TCF
read_tcf:
	subs r2, r2, #1
	beq error
	ldr r1, [r0]
	cmp r1, #1
	bne read_tcf
	str r1, [r0]
	
	ldr r1, =SPI2_POPR
	ldr r0, [r1]
	bx lr


/*	Unterprogramm zum Schreiben des Konfigurationsregisters des DS1722
	
	Übergabewerte:
		r0: Zu schreibendes Byte

	Rükgabewerte: 
		-
*/
.thumb_func
spi_write:
	push {lr}
	
	//1. clear Halt
	mov r1, #0
	ldr r2, =HALT
	str r1, [r2]

	//2. write PUSR
	ldr r2, =SPI2_PUSHR
	str r0, [r2]

	//3. dummy read
	bl spi_read

	//4. set Halt
	mov r1, #1
	ldr r2, =HALT
	str r1, [r2]
	pop {pc}


/*** Datenbereich (ab 0x20000000) ***/
.data
str_0000: .asciz ".0"
str_0001: .asciz ".0625"
str_0010: .asciz ".125"
str_0011: .asciz ".1875"
str_0100: .asciz ".25"
str_0101: .asciz ".3125"
str_0110: .asciz ".375"
str_0111: .asciz ".4375"
str_1000: .asciz ".5"
str_1001: .asciz ".5625"
str_1010: .asciz ".625"
str_1011: .asciz ".6875"
str_1100: .asciz ".75"
str_1101: .asciz ".8125"
str_1110: .asciz ".875"
str_1111: .asciz ".9375"
str_array_lsb: .word str_0000, str_0001, str_0010, str_0011, str_0100, str_0101, str_0110, str_0111, str_1000, str_1001, str_1010, str_1011, str_1100, str_1101, str_1110, str_1111  
error_tcf: .asciz "TCF ist wider Erwarten nicht gesetzt, beende Programm\n"
interrupt_flag_pit_1: .byte 0x00
interrupt_flag_sw_1: .byte 0x00
interrupt_flag_sw_2: .byte 0x00
str_resolution: .asciz "\nAufloesung: "
str_bit: .asciz " Bit\n"
celsius: .asciz " gC\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ XOR_MASK, 0x1
.equ SIM_SCGC6, 0x4004803C 
__BBREG RTC_SIM, SIM_SCGC6, 29 


/* Interrupt-Konstanten*/
.equ NVIC_ICSER2, 0xE000E108									//Register für Setzten von Interrupts
.equ NVIC_ICPR2, 0xE000E288										//Register zum Löschen von hängenden Interrupts
.equ VEKTORTABELLE_BASIS, 0x01FFFFE00
.equ OFFSET_RTC_TAIE, 0x00000148
.equ OFFSET_RTC_TSIE, 0x0000014C
.equ INTERRUPT_TAIE,  VEKTORTABELLE_BASIS + OFFSET_RTC_TAIE
.equ INTERRUPT_TSIE,  VEKTORTABELLE_BASIS + OFFSET_RTC_TSIE
.equ NVIC_TSIE_BIT, 1 << 3				  						//Berechnung IRQ (67) mod 32 = 3
.equ NVIC_TAIE_BIT, 1 << 2				  						//Berechnung IRQ (66) mod 32 = 2


/* RTC-Konstanten */
.equ RTC_TSR, 0x4003D000    									//RTC Time Seconds Register  
.equ RTC_TPR, 0x4003D004    									//RTC Time Prescaler Register  
.equ RTC_TAR, 0x4003D008    									//RTC Time Alarm Register  
.equ RTC_TCR, 0x4003D00C    									//RTC Time Compensation Register  
.equ RTC_CR, 0x4003D010     									//RTC Control Register  
__BBREG UM, RTC_CR, 3
__BBREG SUP, RTC_CR, 2
__BBREG OSCE, RTC_CR, 8
__BBREG SWR, RTC_CR, 0
.equ OSCE_WAIT, 12500000										//Oszillator Initalisierungszeit
.equ RTC_SR, 0x4003D014     									//RTC Status Register  
__BBREG TCE, RTC_SR, 4											//Timer Counter Enable
.equ RTC_LR, 0x4003D018     									//RTC Lock Register  
.equ RTC_IER, 0x4003D01C    									//RTC Interrupt Enable Register  
__BBREG TSIE, RTC_IER, 4 										//Time Seconds Interrupt Enable
__BBREG TAIE, RTC_IER, 2 										//Time Seconds Interrupt Enable
		
/*Zeit-Konstanten*/
.equ TAR_HOUR, CMP_HOUR -1
.equ TAR_HOUR_PR, TAR_HOUR - 5									//Preset-Wert Stunde
.equ TAR_DAY, 0x15180 - 1
.equ TAR_DAY_PR, TAR_DAY - 5 									//Preset-Wert Tag

.equ CMP_HOUR, 3600				
.equ CMP_MIN, 60
.equ STUNDEN_PRO_TAG, 24
.equ MINUTEN_PRO_STUNDE, 60


/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

	/* Initalisierung RTC-Modul */
	mov r0, #0
	mov r1, #1
	
	//Aktiviere Takt für RTC Modul
	ldr r2, =RTC_SIM
	str r1, [r2] 
	
	//Software Reset Timer um Register in definierten Zustand zu bringen
	ldr r2, =SWR
	str r1, [r2]	
	str r0, [r2]
	
	//Aktiviere den Non-Supervisor-mode write acess
	ldr r2, =SUP
	str r1, [r2]
		
	//Update Mode
	ldr r2, =UM
	str r1, [r2]
	
	//Aktiviere den Oszillator
	ldr r2, =OSCE
	str r1, [r2] 
	
	//Einschwingen des Oszillators abwarten
	ldr r2, =OSCE_WAIT
osce_delay:
	subs r2, r2, #1
	bne osce_delay
	
	//Setze initalen Zielwert
	ldr r2, =RTC_TAR
	ldr r3, =TAR_DAY
	str r3, [r2] 
	
	//Setze Startwert
	ldr r2, =RTC_TSR
	str r0, [r2]
	
	//RTC Timer aktivieren
	ldr r2, =TCE
	str r1, [r2]
	
	/*Konfiguriere Interrupts*/
	ldr r2, =INTERRUPT_TAIE
	ldr r3, =isr_ta
	str r3, [r2]

	ldr r2, =INTERRUPT_TSIE
	ldr r3, =isr_ts
	str r3, [r2]
	
	//NVIC_ICPR2  2. & 3. Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r2, =NVIC_ICPR2
	ldr r3, =(NVIC_TAIE_BIT | NVIC_TSIE_BIT) 
	str r3, [r2]
	//NVIC_ISER2 2. & 3. Bit setzen, um Interrupts zu aktivieren
	ldr r2, =NVIC_ICSER2
	str r3, [r2]
	
	
	//RTC Interrupts aktivieren
	ldr r2, =TAIE		
	str r1, [r2]
	ldr r2, =TSIE 
	str r1, [r2]
	
/* Registerbelegungen Hauptprogramm	
		
		r4: Adresse isr_flag_ts
		r5: Adresse isr_flag_ta
		r6: Adresse TCR_TSR
		r7: Adresse TCR_TAR
		r8: Start-Stop: 0 -> Anzeige aus & 1 -> Anzeige an
		r9: Modus: 0 -> Modus Stunde & 1 -> Modus Tag
		r10: Register für Zeitberechnungen
		r11: Preset Wert für Modus Stunde
		r12: Preset Wert für Modus Tag
*/	
	
	/* Initalisierung Registerbelegung*/
	ldr r4, =isr_flag_ts
	ldr r5, =isr_flag_ta
	ldr r6, =RTC_TSR
	ldr r7, =RTC_TAR
	mov r8, #1
	mov r9, #1
	ldr r11, =TAR_HOUR_PR
	ldr r12, =TAR_DAY_PR

program:

	/*Abfrage Terminal & Verarbeitung Eingabe*/
	bl uart_charPresent
	cmp r0,#0
	beq timer_second 				//Kein Zeichen eingelesen, überspringe Überprüfung auf Zeichentypen
	
	//Eingabe = d?
	bl uart_getChar  
	cmp r0,'d'
	bne check_hour					//Fahre mit nächster Überprüfung fort
	
	//Setze Modus
	mov r9, #1
	
	//Stoppe Timer
	mov r0, #0
	mov r1, #1
	ldr r2, =TCE
	str r0, [r2]
	//Setze Startwert zurück
	str r0, [r6]
	//Setze Zielwert auf einen Tag 
	ldr r0, =TAR_DAY
	str r0, [r7] 
	ldr r3, =value_rtc_tar
	str r0, [r3]
	
	//Reaktiviere Timer
	str r1, [r2]
	
	ldr r0, =str_24h
	bl uart_putString
	b timer_second


check_hour:

	//Eingabe = h?
	cmp r0,'h'
	bne check_reset							//Fahre mit nächster Überprüfung fort

	//Setze Modus
	mov r9, #0

	//Stoppe Timer
	mov r1, #1
	ldr r2, =TCE
	str r9, [r2]
	//Setze Startwert zurück
	str r9, [r6]
	//Setze Zielwert auf eine Stunde 
	ldr r0, =TAR_HOUR
	str r0, [r7] 	
	ldr r3, =value_rtc_tar
	str r0, [r3]
	
	//Reaktiviere Timer
	str r1, [r2]
	
	ldr r0, =str_1h
	bl uart_putString
	b timer_second
	
check_reset:	

	//Eingabe = r?
	cmp r0,'r'
	bne check_start_stop					//Fahre mit nächster Überprüfung fort

	//Stoppe Timer
	mov r0, #0
	mov r1, #1
	ldr r2, =TCE
	str r0, [r2]
	//Setze Startwert zurück
	str r0, [r6]
	//Reaktiviere Timer
	str r1, [r2]
	
	ldr r0, =str_reset
	bl uart_putString
	b timer_second
	
check_start_stop:

	//Eingabe = s? 
	cmp r0,'s'
	bne check_preset
    eors r8, r8, #XOR_MASK
    ite ne
	ldrne r0, =str_start
	ldreq r0, =str_stop
	bl uart_putString
	b timer_second
	
check_preset:

	//Eingabe = p?
	cmp r0,'p'
	bne timer_second
	
	//Stoppe Timer
	mov r0, #0
	mov r1, #1
	ldr r2, =TCE
	str r0, [r2]

	//Prüfe Modus & setze ensprechenden Startwert
	cmp r9, #0
	ite eq	
	streq r11, [r6]
	strne r12, [r6]
	
	//Reaktiviere Timer
	str r1, [r2]
	ldr r0, =str_preset
	bl uart_putString
	
	
timer_second:
	/* Verarbeitung Interrupt TS*/
	ldrb r0, [r4]
	cmp r0, #1
	bne timer_end
	mov r0, #0
	strb r0, [r4] 
		
	/*Ausgabe Uhr */
	cmp r8, #1
	bne timer_end
	
	//Lade aktuellen Sekundenwert
	ldr r10, [r6]

	//Überprüfen des Modus
	cmp r9, #1
	bne calc_min
	
	//Iterativ Stundenwert abziehen
calc_hour:
	cmp r10, #CMP_HOUR
	itt hs
	subhs r10, r10, #CMP_HOUR
	addhs r0, #1
	bhs calc_hour
	
	//Handeln Überlauf für Tagmodus
	cmp r0, #STUNDEN_PRO_TAG
	it eq
	moveq r0, #0
	
	//Ausgabe Stunden
	bl ausgabe_zweistellig	
	mov r0, ':'
	bl uart_putChar
	mov r0, #0
	
	
	//Iterativ Minutenwert abziehen
calc_min:
	cmp r10, #CMP_MIN
	itt hs
	subhs r10, r10, #CMP_MIN
	addhs r0, #1
	bhs calc_min

	//Handeln Überlauf für Stundenmodus
	cmp r0, #MINUTEN_PRO_STUNDE
	it eq
	moveq r0, #0

	//Ausgabe Minuten
	bl ausgabe_zweistellig	
	mov r0, ':'
	bl uart_putChar
	
	mov r0, r10
	bl ausgabe_zweistellig
	
	mov r0, '\n'
	bl uart_putChar
	
timer_end:	
	/* Verarbeitung Interrupt TA*/
	ldrb r0, [r5]
	cmp r0, #1
	bne program
	mov r0, #0
	strb r0, [r5] 
	
	//Ausgabe Endzeitpunkt
	ldr r0, =str_end
	bl uart_putString
	b program
	
	
/*
 * isr-routine ta
 */	
	
.thumb_func
isr_ta:
	mov r0, #1
	//Programm-Flag setzen
	ldr r1, =isr_flag_ta
	strb r0, [r1]
	
	//Interupt clearen
	ldr r0, =RTC_TAR
	ldr r1, =value_rtc_tar
	ldr r1, [r1]
	str r1, [r0]
	bx lr


/*
 * isr-routine ts
 */

.thumb_func
isr_ts:	
	mov r0, #1
	//Programm-Flag setzen
	ldr r2, =isr_flag_ts
	strb r0, [r2]
	bx lr
	
/* Unterprogramm für zweistellige Ausgabe
 * Gibt bei Zahlen < 10 eine fuehrende Null aus
 * Parameter: 8-bit-Zahl in R0
 * Rueckgabe: keine
 */		
.thumb_func
ausgabe_zweistellig:
	push {lr}
	cmp r0, #10						// >= 10? 
	ite hs
	ldrhs r1, =uart_putByteBase10	// ohne fuehrende Null
	ldrlo r1, =uart_putByte			// mit fuehrender Null
	blx r1							// entsprechendes UP aufrufen
	pop {pc}
	

/*** Datenbereich (ab 0x20000000) ***/
.data
str_24h: .asciz "24-Stunden-Modus\n"
str_1h: .asciz "1-Stunden-Modus\n"
str_reset: .asciz "Uhr zurueckgesetzt\n"
str_start: .asciz "Anzeige an\n"
str_stop: .asciz "Anzeige aus\n"
str_preset: .asciz "Uhr vorgestellt\n"
str_end: .asciz "Endzeitpunkt erreicht\n"
isr_flag_ta: .byte 0x00
isr_flag_ts: .byte 0x00
value_rtc_tar: .word TAR_DAY
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration

.equ SIM_SCGC5,  0x40048038										
.equ SIM_SCGC6, 0x4004803C 
__BBREG RTC_SIM, SIM_SCGC6, 29 
__BBREG PIT_SIM, SIM_SCGC6, 23
__BBREG PORTA_SIM, SIM_SCGC5, 9 


/*Timer-Konstanten*/
.equ PIT_MCR, 0x40037000				  						//PIT Modul Kontrollregister
.equ WORD_PIT_MCR, 0x0											//Steuerwort PIT Modul Kontrollregister 
.equ BITMASK_TCTRL1,  (1 << 1) 									//Timer disable, Interupt enable, Chained disable
.equ PIT_LDVAL1, 0x40037110				  						//Register für Startwert
.equ PIT_TCTRL1, 0x40037118				  						//Timer Kontrollregister
__BBREG TIMER_ENABLE, PIT_TCTRL1, 0
.equ PIT_TFLG1, 0x4003711C				  						//Timer Flagregister
__BBREG BIT_BAND_TFLG1, PIT_TFLG1, 0
.equ TIMER_100_MS, 2499999
.equ TIMER_200_MS, 4999999

/*Interrupt-Konstanten*/
.equ NVIC_ISER2, 0xE000E108										//Register für Setzten von Interrupts
.equ NVIC_ICPR2, 0xE000E288										//Register zum Löschen von hängenden Interrupts
.equ VEKTORTABELLE_BASIS, 0x01FFFFE00
.equ OFFSET_PIT1, 0x00000154			  						//Offset Interrupt-Adresse PIT1
.equ OFFSET_RTC_TSIE, 0x0000014C								//Offset Interrupt-Adresse TS	
.equ INTERRUPT_PIT1,  VEKTORTABELLE_BASIS + OFFSET_PIT1
.equ INTERRUPT_TSIE,  VEKTORTABELLE_BASIS + OFFSET_RTC_TSIE
.equ NVIC_PIT1_BIT, 1 << 5				  						//Berechnung IRQ (69) mod 32 = 5
.equ NVIC_TSIE_BIT, 1 << 3				  						//Berechnung IRQ (67) mod 32 = 3


/*RTC-Konstanten*/
.equ RTC_TSR, 0x4003D000    									//RTC Time Seconds Register 
.equ RTC_TAR, 0x4003D008    									//RTC Time Alarm Register  
.equ RTC_CR, 0x4003D010     									//RTC Control Register  
__BBREG UM, RTC_CR, 3
__BBREG SUP, RTC_CR, 2
__BBREG OSCE, RTC_CR, 8
__BBREG SWR, RTC_CR, 0
.equ OSCE_WAIT, 12500000										//Oszillator Initalisierungszeit
.equ RTC_SR, 0x4003D014     									//RTC Status Register  
__BBREG TCE, RTC_SR, 4											//Timer Counter Enable
.equ RTC_LR, 0x4003D018     									//RTC Lock Register  
.equ RTC_IER, 0x4003D01C    									//RTC Interrupt Enable Register  
__BBREG TSIE, RTC_IER, 4 										//Time Seconds Interrupt Enable
__BBREG TAIE, RTC_IER, 2 										//Time Seconds Interrupt Enable


/*Zeit-Konstanten*/	
.equ TAR_DAY, 0x15180 - 1
.equ TAGE_PRO_WOCHE, 7
.equ SEKUNDEN_PRO_MINUTE, 60
.equ MINUTEN_PRO_STUNDE, 60
.equ STUNDEN_PRO_TAG, 24
.equ TAGE_PRO_MONAT, 30
.equ MONATE_PRO_JAHR, 12
.equ XOR_MASK, 0x1
.equ JAHRHUNDERT_GRENZE, 99

/*BCD-Konstanten*/
.equ BCD_1, 1
.equ BCD_2, 2
.equ BCD_4, 4
.equ BCD_8, 8
.equ BCD_10, 10
.equ BCD_20, 20
.equ BCD_40, 40
.equ BCD_80, 80

/*DCF77-Konstanten*/
.equ DCF77_BITS, 59
.equ DCF_MINUTE, 27
.equ DCF_STUNDE, 34
.equ DCF_JAHR, 57
.equ DCF_PAR_DATUM, 58 
.equ DCF_PAR_STUNDE, 35
.equ DCF_PAR_MINUTE, 28


/*GPIO-Konstanten*/
.equ GPIOA_PDOR, 0x400FF000					//Data Output Register
.equ GPIOA_PDDR, 0x400FF014					//Data Direction Register
.equ PORTA_PCR6, 0x40049018
.equ PORTA_PCR10, 0x40049028
.equ PCR_MUX0, 8
.equ GPIO_MODE, 1 << PCR_MUX0
__BBREG MODE_PCR10, GPIOA_PDDR, 10
__BBREG MODE_PCR6, GPIOA_PDDR, 6
__BBREG LED_BLUE_DATA, GPIOA_PDOR, 10
__BBREG DCF77_PIN_DATA, GPIOA_PDOR, 6




/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*Registerbelegungen

	r4: 	Index DCF77-Signal Ausgabe
	r5: 	Adresse dcf77_array
	r6: 	Zwischenspeicher Ausgabe
	r7: 	Wert aktuell auzugebenden Bits
	r8: 	Aktueller Startwert Timer
	r9:	Zwischenspeicher Berechnungen
	r10:	Adresse isr_flag_ts

*/

main:	

	bl uart_init
		
	
	mov r0, #0
	mov r1, #1
	/* Initalisierung RTC-Modul */
	
	//Aktiviere Takt für RTC Modul, PIT & PORTA
	ldr r2, =RTC_SIM
	str r1, [r2] 
	ldr r2, =PIT_SIM
	str r1, [r2] 
	ldr r2, =PORTA_SIM
	str r1, [r2] 
	
	//Software Reset Timer
	ldr r2, =SWR
	str r1, [r2]
	
	str r0, [r2]
	
	//Aktiviere den Non-Supervisor-mode write acess
	ldr r2, =SUP
	str r1, [r2]
		
	//Update Mode
	ldr r2, =UM
	str r1, [r2]
	
	//Aktiviere den Oszillator
	ldr r2, =OSCE
	str r1, [r2] 
	
	
	//Einschwingen des Oszillators abwarten
	ldr r2, =OSCE_WAIT
osce_delay:
	subs r2, r2, #1
	bne osce_delay

	
	//Setze initalen Zielwert
	ldr r2, =RTC_TAR
	ldr r3, =TAR_DAY
	str r3, [r2] 
	
	//Setze Startwert
	ldr r2, =RTC_TSR
	str r0, [r2]
	
	//RTC Timer aktivieren
	ldr r2, =TCE
	str r1, [r2]
	
	/*Konfiguriere Interrupts*/
	ldr r2, =INTERRUPT_PIT1
	ldr r3, =isr_pit1
	str r3, [r2]

	ldr r2, =INTERRUPT_TSIE
	ldr r3, =isr_ts
	str r3, [r2]
	
	//NVIC_ICPR2  2. & 3. Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r2, =NVIC_ICPR2
	ldr r3, =(NVIC_TSIE_BIT | NVIC_PIT1_BIT) 
	str r3, [r2]
	//NVIC_ISER2 2. & 3. Bit setzen, um Interrupts zu aktivieren
	ldr r2, =NVIC_ISER2
	str r3, [r2]
	
	//RTC Interrupts aktivieren
	ldr r2, =TSIE 
	str r1, [r2]
	

	// PITs aktivieren 
	ldr r2, =PIT_MCR
	mov r3, #WORD_PIT_MCR
	str r3, [r2]
	

	//TFLG1-Flag zurücksezten
	ldr r2, =BIT_BAND_TFLG1	
	mov r3, #1
	str r3, [r2]
	
	//Interrupt zu PIT1 akitvieren, Time nicht aktivieren, PIT1  Chainend Mode disabled
	ldr r2, =PIT_TCTRL1
	mov r3, #BITMASK_TCTRL1 
	str r3, [r2]
	
	//Ports als GPIOs konfigurieren
	ldr r2, =PORTA_PCR10
	ldr r3, =GPIO_MODE
	str r3, [r2]
	ldr r2, =PORTA_PCR6
	str r3, [r2]
	
	//GPIOs als Output konfigurieren
	ldr r2, =MODE_PCR10
	str r1, [r2]
	ldr r2, =MODE_PCR6
	str r1, [r2]
	
	//Initalisierung Registerbelegungen
	mov r4, #0
	ldr r5, =dcf77_array
	ldr r10, =isr_flag_ts
	
	
	/* Initiale Berechnung DCF77-Signal & Konsolenausgabe Datum*/
	bl berechne_dcf77
	bl terminal_dcf77
	
program:

	//Überprüfung Eingabe
	bl uart_charPresent
	cmp r0,#0
	beq check_interrupt
	 
	//Eingabe = t?  
	bl uart_getChar
	cmp r0,'t'
	beq setze_zeit
	 
	//Eingabe = d?
	cmp r0,'d'
	beq setze_datum 
	
	//Ungültige Eingabe -> ingorieren
	b check_interrupt
	 
setze_zeit:

	//Verarbeiten Eingabe Stunden
	ldr r0, =str_stunden
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =uhrzeit_stunde
	strb r0, [r1]

	//Verabeiten Eingabe Minuten
	ldr r0, =str_minuten
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =uhrzeit_minute
	strb r0, [r1]
	
	bl berechne_dcf77
	b check_interrupt
	
setze_datum:

	//Verarbeiten Eingabe Tage
	ldr r0, =str_tag
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =datum_tag
	strb r0, [r1]

	//Verarbeiten Eingabe Monate
	ldr r0, =str_monat
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =datum_monat
	strb r0, [r1]
	
	//Verarbeiten Eingabe Jahre
	ldr r0, =str_jahr
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =datum_jahr
	strb r0, [r1]
	
	bl berechne_dcf77
	
check_interrupt:	
	
	/* Verarbeitung Interrupt TS*/
	ldrb r0, [r10]
	cmp r0, #1
	bne program
	mov r0, #0
	strb r0, [r10] 
		
	/*Ausgabe DCF77*/
	
	//Überprüfe ob DCF77-Übertragung abgeschlossen ist
	cmp r4, #DCF77_BITS
	bne ausgabe_led
	mov r0, '\n'
	bl uart_putChar
	b timer
	
ausgabe_led:
	//Lade Bit aus Speicher
	add r1, r5, r4
	ldrb r6, [r1]
	//Inkrementiere Index	
	add r4,#1
	
	cmp r6, #1
	ittee eq
	moveq r7, '1'
	ldreq r8, =TIMER_100_MS
	movne r7, '0'
	ldrne r8, =TIMER_200_MS
	
	/*Ausgabe Bit Terminal*/
	mov r0, r7
	bl uart_putChar          

	/*Setze GPIO*/
	ldr r0, =LED_BLUE_DATA
	mov r1, #1
	str r1, [r0]
	ldr r0, =DCF77_PIN_DATA
	str r1, [r0]
	
	/*Starte Timer mit variablen Startwert*/
	ldr r0, =PIT_LDVAL1
	str r8, [r0]
	ldr r0, =TIMER_ENABLE
    mov r1, #1
    str r1, [r0]  
	

timer:	
	
	//Hochzählen und Abspeichern von Sekunden
	ldr r0, =uhrzeit_sekunde
	ldrb r1, [r0]
	add r1, r1, #1
	cmp r1, #SEKUNDEN_PRO_MINUTE
	it eq
	moveq r1, #0
	strb r1, [r0]
	bne program							//Kein Überlauf der Sekunden -> Minuten müssen nicht verändert werden
	
	
	//Hochzählen und Abspeichern von Minuten
	ldr r0, =uhrzeit_minute
	ldrb r1, [r0]
	add r1, r1, #1
	mov r9, r1
	cmp r1, #MINUTEN_PRO_STUNDE
	it eq
	moveq r1, #0
	strb r1, [r0]
	
	//Zurücksetzen Index DCF77-Signal
	mov r4, #0
	
	//Überprüfung Überlauf Minuten
	cmp r9, #MINUTEN_PRO_STUNDE
	bne ausgabe							//Kein Überlauf der Minuten -> Stunden müssen nicht verändert werden
	
	//Hochzählen und Abspeichern von Stunden
	ldr r0, =uhrzeit_stunde
	ldrb r1, [r0]
	add r1, r1, #1
	cmp r1, #STUNDEN_PRO_TAG
	it eq
	moveq r1, #0
	strb r1, [r0]
	bne ausgabe							//Kein Überlauf der Stunden -> Tage müssen nicht verändert werden					
	
	//Hochzählen und Abspeichern von Tagen
	ldr r0, =datum_wochentag
	ldrb r1, [r0]
	add r1, #1
	cmp r1, #TAGE_PRO_WOCHE
	it eq
	moveq r1, #0
	strb r1, [r0] 

	ldr r0, =datum_tag
	ldrb r1, [r0]
	add r1, r1, #1
	cmp r1, #TAGE_PRO_MONAT
	it hi
	movhi r1, #1
	strb r1, [r0] 
	bls ausgabe							//Kein Überlauf der Tage -> Monate müssen nicht verändert werden
	    
	//Hochzählen und Abspeichern von Monaten
	ldr r0, =datum_monat
	ldrb r1, [r0]
	add r1, r1, #1
	cmp r1, #MONATE_PRO_JAHR
	it hi
	movhi r1, #1
	strb r1, [r0] 
	bls ausgabe							//Kein Überlauf der Monate -> Jahre müssen nicht verändert werden

	//Hochzählen und Abspeichern von Jahren
	ldr r0, =datum_jahr
	ldrb r1, [r0] 
	add r1, r1, #1
	
	//Verhindern eines Überlaufs des Jahrhunderts
	mov r2, #JAHRHUNDERT_GRENZE
	cmp r1, r2
	it hi
	subhi r1, r1, #1
	strb r1, [r0]
	
ausgabe:

	//Berechnung neues DCF77-Signal
	bl berechne_dcf77
	// Konsolenausgabe Datum
	bl terminal_dcf77		
	b program

/*
 * isr-routine ts
 */
.thumb_func
isr_ts:	
	mov r0, #1
	//Programm-Flag setzen
	ldr r2, =isr_flag_ts
	strb r0, [r2]
	bx lr


/*
 * isr-routine pit1
 */

.thumb_func
isr_pit1:

	//Interrupt-Flag zu PIT1 löschen
	mov r0, #1
	ldr r1, =BIT_BAND_TFLG1
	str r0, [r1]
	
	//Setze GPIO
	ldr r0, =LED_BLUE_DATA
	mov r1, #0
	str r1, [r0]
	ldr r0, =DCF77_PIN_DATA
	str r1, [r0]
	
	//Stoppe Timer 
	mov r0, #0
	ldr r1, =TIMER_ENABLE
    str r0, [r1] 
	bx lr


/* Unterprogramm zur Ausgabe des DCF77-Signals auf dem Terminal
 * Parameter: keine
 * Rueckgabe: keine
 */

.thumb_func
terminal_dcf77:
	push {lr}
	
	//Ausgabe Wochentag
	//Lese Basisadresse String Array
	ldr r0, =wochentag_array
	ldr r1, =datum_wochentag
	ldrb r1, [r1]
	//Berechne Offset 
	lsl r1, #2
	add r0, r0, r1
	//Lade String für Wochentag
	ldr r0, [r0]
	bl uart_putString	
	
	//Ausgabe Tag  
	ldr r0, =datum_tag
	ldrb r0, [r0]
	bl ausgabe_zweistellig
	mov r0, '.'
	bl uart_putChar
	
	//Ausgabe Monat
	ldr r0, =datum_monat
	ldrb r0, [r0]
	bl ausgabe_zweistellig
	mov r0, '.'
	bl uart_putChar
	
	//Ausgabe Jahr

	ldr r0, =datum_jahr
	ldrb r0, [r0]
	bl ausgabe_zweistellig
	mov r0, ' '
	bl uart_putChar

	//Ausgabe Stunden
	ldr r0, =uhrzeit_stunde
	ldrb r0, [r0]
	bl ausgabe_zweistellig
	mov r0, ':'
	bl uart_putChar

	//Ausgabe Minuten
	ldr r0, =uhrzeit_minute
	ldrb r0, [r0]
	bl ausgabe_zweistellig

	ldr r0, =str_uhr
	bl uart_putString
	pop {pc}
	
	
/* Unterprogramm zur Berechnung des DCF77-Signals
 * Parameter: keine
 * Rueckgabe: keine
 */		
.thumb_func	
berechne_dcf77:
	push {r4, lr}
	
	/*Anmerkung zur Berechnung
	
		Da in der Aufabe nicht explizit gefordert, werden lediglich Uhrzeit und Datum inklusikve Parität berechnet.
		Bit 0-19 werden als 0 ausgegeben.
		
	*/
	
	
	
	
	//Vorbereitung Parität & Index DCF77-Signal
	ldr r4, =dcf77_array
	add r1, r4, #DCF_MINUTE
	mov r3, #0
	
	/*Minutenbits berechnen*/
	ldr r0, =uhrzeit_stunde
	ldrb r0, [r0]
	cmp r0, #BCD_40
	ittte hs
	subhs r0, r0, #BCD_40
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_20
	ittte hs
	subhs r0, r0, #BCD_20
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_10
	ittte hs
	subhs r0, r0, #BCD_10
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_8
	ittte hs
	subhs r0, r0, #BCD_8
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_4
	ittte hs
	subhs r0, r0, #BCD_4
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_2
	ittte hs
	subhs r0, r0, #BCD_2
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_1
	ittte hs
	subhs r0, r0, #BCD_1
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	//Paritätsbit speichern
	add r1, r4, #DCF_PAR_MINUTE	
	strb r3, [r1]
	
	/*Stundenbits berechnen*/
	ldr r0, =uhrzeit_stunde
	ldrb r0, [r0]
	add r1, r4, #DCF_STUNDE
	//Vorbereitung Parität
	mov r3, #0
	
	cmp r0, #BCD_20
	ittte hs
	subhs r0, r0, #BCD_20
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_10
	ittte hs
	subhs r0, r0, #BCD_10
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_8
	ittte hs
	subhs r0, r0, #BCD_8
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_4
	ittte hs
	subhs r0, r0, #BCD_4
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_2
	ittte hs
	subhs r0, r0, #BCD_2
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_1
	ittte hs
	subhs r0, r0, #BCD_1
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	//Paritätsbit speichern
	add r1, r4, #DCF_PAR_STUNDE	
	strb r3, [r1]
	
	/*Jahresbits berechnen*/
	ldr r0, =datum_jahr
	ldrb r0, [r0]
	add r1, r4, #DCF_JAHR
	//Vorbereitung Parität
	mov r3, #0
	
	cmp r0, #BCD_80
	ittte hs
	subhs r0, r0, #BCD_40
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
		
	cmp r0, #BCD_40
	ittte hs
	subhs r0, r0, #BCD_40
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_20
	ittte hs
	subhs r0, r0, #BCD_20
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_10
	ittte hs
	subhs r0, r0, #BCD_10
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_8
	ittte hs
	subhs r0, r0, #BCD_8
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_4
	ittte hs
	subhs r0, r0, #BCD_4
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_2
	ittte hs
	subhs r0, r0, #BCD_2
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_1
	ittte hs
	subhs r0, r0, #BCD_1
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	/*Monatsbits berechnen*/
	ldr r0, =datum_monat
	ldrb r0, [r0]

	cmp r0, #BCD_10
	ittte hs
	subhs r0, r0, #BCD_10
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
