	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_2
	ittte hs
	subhs r0, r0, #BCD_2
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_1
	ittte hs
	subhs r0, r0, #BCD_1
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	/* Wochentagbits berechnen */
	ldr r0, =datum_wochentag
	ldrb r0, [r0]
	
	cmp r0, #BCD_4
	ittte hs
	subhs r0, r0, #BCD_4
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_2
	ittte hs
	subhs r0, r0, #BCD_2
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_1
	ittte hs
	subhs r0, r0, #BCD_1
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	/* Tagesbits berechnen */
	ldr r0, =datum_tag
	ldrb r0, [r0]
	
	cmp r0, #BCD_20
	ittte hs
	subhs r0, r0, #BCD_20
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_10
	ittte hs
	subhs r0, r0, #BCD_10
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_8
	ittte hs
	subhs r0, r0, #BCD_8
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_4
	ittte hs
	subhs r0, r0, #BCD_4
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	cmp r0, #BCD_2
	ittte hs
	subhs r0, r0, #BCD_2
	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
