	movhs r2, #1
	eorhs r3, r3, #XOR_MASK
	movlo r2, #0
	strb r2, [r1], #-1
	
	//Paritätsbit speichern
	add r1, r4, #DCF_PAR_DATUM	
	strb r3, [r1]
	pop {r4, pc}


/* Unterprogramm für zweistellige Ausgabe
 * Gibt bei Zahlen < 10 eine fuehrende Null aus
 * Parameter: 8-bit-Zahl in R0
 * Rueckgabe: keine
 */		
.thumb_func
ausgabe_zweistellig:
	push {lr}
	cmp r0, #10						// >= 10? 
	ite hs
	ldrhs r1, =uart_putByteBase10	// ohne fuehrende Null
	ldrlo r1, =uart_putByte			// mit fuehrender Null
	blx r1							// entsprechendes UP aufrufen
	pop {pc}


/*** Datenbereich (ab 0x20000000) ***/
.data
str_montag: .asciz "Mo., "
str_dienstag: .asciz "Di., "
str_mittwoch: .asciz "Mi., "
str_donnerstag: .asciz "Do., "
str_freitag: .asciz "Fr., "
str_samstag: .asciz "Sa., "
str_sonntag: .asciz "So., "
.align 4
wochentag_array: .word str_montag, str_dienstag, str_mittwoch, str_donnerstag, str_freitag, str_samstag, str_sonntag
start_stop: .byte 0x1
uhrzeit_stunde: .byte 0
uhrzeit_minute: .byte 0
uhrzeit_sekunde: .byte 0
datum_wochentag: .byte 5
datum_tag: .byte 1	
datum_monat: .byte 1
datum_jahr: .byte 14
str_uhr: .asciz " Uhr "
str_stunden: .asciz "\nStunde eingeben (hh): "
str_minuten: .asciz "\nMinuten eingeben (mm): "
str_tag: .asciz "\nTag eingeben (dd): "
str_monat: .asciz "\nMonat eingeben (mm): "
str_jahr: .asciz "\nJahr eingeben (jj): "
isr_flag_ts: .byte 0x00
dcf77_array: 
			.rept DCF77_BITS
			.byte 0x00
			.endr
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

//Konstantendeklaration
.equ FTM0_SC, 0x40038000    									//Status And Control Channel Global
__BBREG TOIE, FTM0_SC, 6
__BBREG TOF, FTM0_SC, 7
__BBREG CLKS0, FTM0_SC, 3

.equ FTM0_CNTIN, 0x4003804C 

.equ FTM0_CNT, 0x40038004   									//Counter Register 
.equ FTM0_MOD, 0x40038008   									//Modulo  Register
.equ FTM0_C3V, 0x40038028
.equ MOD_KHZ, 2500	
.equ FTM0_C3SC, 0x40038024  									//Status And Control Channel3
.equ FTM0_C3SC_CONFIG, (1 << 6) | (1 << 5) | (1 << 3)			// Channel-Interrupts aktiviert, Edge Aligned PWM Modus ,positive Polaritaet
__BBREG CHF, FTM0_C3SC, 7
__BBREG ELSA, FTM0_C3SC, 2


.equ PORTA_PCR6, 0x40049018
.equ PORTA_PCR6_CONFIG, (0x3 << 8)								// Alternative 3: FTM0_CH3 (MUX = 0x3)

.equ VEKTORTABELLE_BASIS, 0x01FFFFE00
.equ OFFSET_FTM0, 0x00000138  									//FTM0Single interrupt vector for all sources
.equ INTERRUPT_FTM0,  VEKTORTABELLE_BASIS + OFFSET_FTM0
.equ NVIC_ICSER1, 0xE000E104									//Register für Setzten von Interrupts
.equ NVIC_ICPR1, 0xE000E284	
.equ NVIC_FTM0_BIT, 1 << 30				  						//Berechnung IRQ (62) mod 32 = 30


.equ SIM_SCGC5,  0x40048038										
__BBREG PORTA_SIM, SIM_SCGC5, 9 
.equ SIM_SCGC6, 0x4004803C 
__BBREG FTM0_SIM, SIM_SCGC6, 24 

.equ INIT_IMPULSDAUER, 125

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	

	bl uart_init
	
	
	/*Initalisierung*/
	mov r0, #0
	mov r1, #1

	//Aktiviere Takt FTC
	ldr r2, =FTM0_SIM
	str r1, [r2]
	ldr r2, =PORTA_SIM
	str r1, [r2]
	
	//Setze Port Modus
	ldr r2, =PORTA_PCR6
	mov r3, #PORTA_PCR6_CONFIG
	str r3, [r2]
	
	/*Konfiguriere Interrupts*/
	ldr r2, =INTERRUPT_FTM0
	ldr r3, =isr_ftm0
	str r3, [r2]

	
	//NVIC_ICPR1  30. Bit setzen, um ggfs. hängenden Interrupt zu löschen
	ldr r2, =NVIC_ICPR1
	ldr r3, =NVIC_FTM0_BIT  
	str r3, [r2]
	//NVIC_ISER1 30. Bit setzen, um Interrupts zu aktivieren
	ldr r2, =NVIC_ICSER1
	str r3, [r2]
	
	/*Aktiviere FTM0 Interupts*/
	//Overflow Interrupt
	ldr r2, =TOIE
	str r1, [r2]

	
	//Schreibe FTM0_CNTIN
	ldr r2, =FTM0_CNTIN
	str r0, [r2]
	
	//Schreibe CNT
	ldr r2, =FTM0_CNT
	str r0, [r2]
	//Schreibe MOD
	ldr r2, =FTM0_MOD
	ldr r3, =MOD_KHZ
	str r3, [r2]
	
	ldr r2, =FTM0_C3SC
	ldr r3, =FTM0_C3SC_CONFIG
	str r3, [r2]
	
	
	ldr r2, =FTM0_C3V
	mov r3, #INIT_IMPULSDAUER
	str r3, [r2]
	
	//Setze Clock auf Systemzeit
	ldr r2, =CLKS0
	str r1, [r2]
	
	
	/* Registerbelegungen 
	
		r4:	Adresse neue_dauer
		r5: Adresse neue_polaritaet
		r6: Polarität   0 -> Normal | 1 -> Invertiert
		r7: Index Impulsdauer 
		r8: Adresse array_time
		r9: Adresse Impulsdauer
		r10: Adresse Polaritaet
	*/
	
	
	//Initalisiere Registerbelegungen
	ldr r4, =neue_dauer
	ldr r5, =neue_polaritaet
	mov r6, #0
	mov r7, #0
	ldr r8, =array_time 
	ldr r9, =dauer
	ldr r10, =polaritaet
	

program:


	/*Eingabe Terminal */
	bl uart_charPresent
	cmp r0, #0
	bne program
	
	ldr r0, =str_eingabe
	bl uart_putString
	bl uart_getChar
	
	cmp r0, '+'
	it eq
	moveq r6, #0
	beq verarbeite_polaritaet
	cmp r0, '-'
	it eq
	moveq r6, #1
	beq verarbeite_polaritaet	
	
	cmp r0, '0'
	it eq
	moveq r7, #0
	beq verarbeite_dauer
	
	cmp r0, '1'
	it eq
	moveq r7, #1
	beq verarbeite_dauer
	
	cmp r0, '2'
	it eq
	moveq r7, #2
	beq verarbeite_dauer
	
	cmp r0, '3'
	it eq
	moveq r7, #3
	beq verarbeite_dauer
	
	cmp r0, '4'
	it eq
	moveq r7, #4
	beq verarbeite_dauer
	
	cmp r0, '5'
	it eq
	moveq r7, #4
	beq verarbeite_dauer
	
	cmp r0, '6'
	it eq
	moveq r7, #6
	beq verarbeite_dauer
	
	cmp r0, '7'
	it eq
	moveq r7, #7
	beq verarbeite_dauer
	
	cmp r0, '8'
	it eq
	moveq r7, #8
	beq verarbeite_dauer
	
	cmp r0, '9'
	it eq
	moveq r7, #9
	beq verarbeite_dauer
	
	//Alle anderen Eingaben werden ignoriert
	b program

verarbeite_dauer:
	
	//Setze neue Impulsdauer
	lsl r0, r7, #2
	add r0, r8 ,r0
	ldr r0, [r0]
	str r0, [r9]
	
	//Setze Merker neue Impulsdauer
	mov r0, #1
	strb r0, [r4]
	b program
	         

verarbeite_polaritaet:

	//Setze neue Polaritaet
	strb r6, [r10]
	
	//Setze Merker neue polaritaet
	mov r0, #1
	strb r0, [r5]
	b program
	         
end:
	b end


.thumb_func
isr_ftm0:	
	
	
	//Überprüfe und Lösche Interrupt
	ldr r0, =CHF
	ldr r1, [r0]
	cmp r1, #1
	bne check_overflow_isr
	
	
	//Cleare Interrupt
	ldr r2, =FTM0_C3SC
	ldr r3, [r2]
	mov r2, #0
	ldr r0, =CHF
	str r2, [r0]

	//Wurde eine neue dauer eingeben?
	ldr r0, =neue_dauer
	ldrb r1, [r0]
	cmp r1, #1
	bne return
	mov r1, #0
	strb r1, [r0]
	
	//Deaktiviere FTM0
	ldr r0, =CLKS0
	mov r1, #0
	str r1, [r0]
	
	ldr r3, =FTM0_C3V
	ldr r2, =dauer
	ldr r2, [r2]
	str r2, [r3]
	
	//Reaktiviere FTM0
	mov r1, #1
	str r1, [r0]         
	
	
check_overflow_isr:	
	
	ldr r0, =TOF
	ldr r1, [r0]
	cmp r1, #1
	bne return
	
	ldr r2, =FTM0_SC
	ldr r3, [r2]
	mov r2, #0
	ldr r0, =TOF
	str r2, [r0]
	
	
	//Wurde eine neue polaritaet eingeben?
	ldr r0, =neue_polaritaet
	ldrb r1, [r0]
	cmp r1, #1
	bne return
	mov r1, #0
	strb r1, [r0]
	
	//Passe Polarität an
	ldr r2, =ELSA
	ldr r3, =polaritaet
	ldrb r3, [r3]
	strb r3, [r2]
	
return:
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
neue_dauer: .byte 0x00
neue_polaritaet: .byte 0x00
polaritaet: .byte 0x00
dauer: .byte 0x00
array_time: .word 125, 375, 625, 875, 1125, 1375, 1625, 1875, 2125, 2375
str_eingabe: .asciz ">\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ ascii_lf, 0x0a
.equ ascii_gt, 0x3e
.equ n_array_items, 16
.equ pit3_getval_offset_with_mov, 11

/*
* Suchzeit:
* Die Suchzeit hängt nicht von der Lage des Maximums im Array
* ab. Das liegt daran, dass die "it hi" und movhi Anweisung
* für den Vergleich immer "spekulativ ausgeführt" werden, auch wenn
* das Maximum gar nicht verändert werden muss.
*/
main:	
	bl uart_init
	
/***************************************************************************\
*                                                                           *
* Bestimmung der Taktzahl des Aufrufs von pit3_getval selbst                *
*                                                                           *
* Der Wert ist 10, addiert um 1 um den Wert in einem Register zu speichern. *
* Ich gehe daher zukünftig von der Konstante 11 aus, welche bei             *
* Messungen abgezogen wird.                                                 *
*                                                                           *
\***************************************************************************/
	bl	pit3_init
	bl	pit3_getval  	// Startwert (läuft runter!)
	mov	r4, r0			// -1
	bl	pit3_getval		// -
	sub	r0, r4, r0  	// x = Startwert - zweiter Zeitpunkt - 1
	// HIER BREAKPOINT SETZEN UM WERT AUSZULESEN

	ldr r4, =str_start
	ldr r5, =str_search_start
	ldr r6, =str_search_end
	ldr r7, =str_cycles
	ldr r8, =array

loop_start:	
	// Alle Zähler zurücksetzen
	mov r9,  0						// Maximum
	mov r10, 0						// nächster Wert für Vergleich
	mov r11, 0						// Taktzähler

	// Eingabeaufforderung ausgeben
	mov	r0, r4
	bl uart_putString

	// Als Schleife jeweils...
	.set counter, 0
	.rept n_array_items
		mov r0, ascii_lf			// eine neue Zeile,
		bl uart_putChar
		mov r0, ascii_gt			// ein > ausgeben,
		bl uart_putChar
		bl uart_getByte				// ein Byte einlesen und
		strb r0, [r8, counter]		// das gelesene Byte im Array speichern
		bl uart_putByte
		.set counter, counter + 1
	.endr
	
	mov r0, r5
	bl uart_putString
	
	
	// Taktzähler starten
	bl pit3_init					// pit3 "zurücksetzen"
	bl pit3_getval					// aktuellen Zähler holen
	mov r11, r0						// und in r12 sichern

	.set counter, 0
	.rept n_array_items
		ldrb r10, [r8, counter]		// ein Byte laden
		cmp r10, r9					// mit aktuellen Maximum vergleichen
		it hi
			movhi r9, r10			// ggfs. Maximum ersetzen		
		.set counter, counter + 1
	.endr
	
	// Taktanzahl berechnen und dabei den "Offset" berücksichtigen
	bl pit3_getval
	sub r0, r11, r0
	sub r11, r0, pit3_getval_offset_with_mov
	
	// Resultate ausgeben
	mov r0, r6
	bl uart_putString
	mov r0, r9
	bl uart_putByteBase10
	mov r0, r7
	bl uart_putString
	mov r0, r11
	bl uart_putInt16
	.rept 2
		mov r0, ascii_lf
		bl uart_putChar
	.endr
	
	b loop_start

/*** Datenbereich (ab 0x20000000) ***/
.data
str_start: 			.asciz "Bitte 16 Bytes sukzessiv eingeben!"
str_search_start:	.asciz "\nDurchsuchen gestartet"
str_search_end: 	.asciz "\nDurchsuchen beendet\nMaximum (dezimal): "
str_cycles:			.asciz "\nAnzahl der Takte: 0x"
.align 4
array:
	.rept n_array_items
		.byte 0x0
	.endr
.align 4

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ ascii_lf,		0x0a
.equ mask_lower_5,  0b00000000000000000000000000011111
.equ mask_lower_31, 0b01111111111111111111111111111111
.equ mask_bit_31,   0b10000000000000000000000000000000
.equ highest_bit, 	31
.equ base_addr,		0x20000000
.equ alias_addr,	0x22000000

main:	
	bl uart_init

	ldr r4, =str_get_bit0
	ldr r5, =str_get_bit1
	mov r6, base_addr		// entspricht 0x20000000 - auf welche Art sollte diese fixe Adresse festgelegt werden?
	add r7, r6, #0x10		// entspricht 0x20000010
	// r8	0-Bit
	// r9	1-Bit
	
start:
	// Eingabeaufforderung ausgeben, dann "0"-Bit einlesen,
	// zusätzliche Bits verwerfen und speichern
	mov r0, r4
	bl	uart_putString
	bl	uart_getByte
	and	r8, r0, mask_lower_5
	
	// eingelesenes Bit ausgeben
	mov	r0, r8
	bl	uart_putByte
	mov	r0, ascii_lf
	bl	uart_putChar
	
	// Analog "1"-Bit einlesen und...
	mov	r0, r5
	bl	uart_putString
	bl	uart_getByte
	and r9, r0, mask_lower_5
	
	// ...ausgeben
	mov	r0, r9
	bl	uart_putByte
	mov	r0, ascii_lf
	bl	uart_putChar

/************************************\
*                                    *
* Anfang Algorithmus ohne BitBanding *
*                                    *
\************************************/

	// Wert aus 0x20000000 laden
	ldr r10, [r6]

	// Ausgabe vor Veränderung 
	mov r0, r10
	bl	uart_putInt32
	mov r0, ascii_lf
	bl	uart_putChar
	
	mov r0, mask_lower_31	// Wird in einen anderen Befehl übersetzt, aber die Intention lässt sich so besser einfangen
	mov r1, highest_bit
	sub r1, r1, r8
	ror r0, r0, r1			// Maske um 31 - n rotieren
	and r10, r10, r0		// Die Maske ist für alle Bits, außer das zu nullende Bit, gesetzt
	
	mov r0, mask_bit_31
	mov r1, highest_bit
	sub r1, r1, r9
	ror r0, r0, r1			// Maske um 31 - n rotieren
	orr r10, r10, r0		// Alle Bits bleiben gesetzt und zusätzlich wird das n Bit auf 1 gesetzt
	
	// Wert in 0x20000000 speichern
	str r10, [r6]
	
	// Ausgabe nach Veränderung 
	mov r0, r10
	bl	uart_putInt32
	mov r0, ascii_lf
	bl	uart_putChar
	
/***********************************\
*                                   *
* Anfang Algorithmus mit BitBanding *
*                                   *
\***********************************/

	// Ausgabe vor Veränderung in Bitband
	
	ldr r0, [r7]			// Wert aus 0x20000010 laden
	bl	uart_putInt32
	mov r0, ascii_lf
	bl	uart_putChar
	
	// "Basis" Adresse des Alias für das Byte bestimmen
	uxth r0, r7				// Obwohl die oberen Bits bei den Adressen in diesem Programm durch das Verschieben automatisch verfallen,
							// scheint das vorherige Verwerfen eventuell vorhandener Bits über Bit 15 trotzdem sinnvoll.
							// Gibt es eine bessere Methode?
	lsl r0, r0, #5			// Multiplikation mit 64 = 2^6
	add	r0, r0, alias_addr	// Alias Offset addieren
	
	// 0-Bit
	lsl r1, r8, #2			// "Offset" für das richtige Bit bestimmen
	mov r2, #0				// Es soll auf 0 gesetzt werden
	str r2, [r0, r1]		// 0 in alias + byte_addr + bit_offset_addr schreiben
	
	// 1-Bit analog zu 0-Bit
	lsl r1, r9, #2			
	mov r2, #1			
	str r2, [r0, r1]
	
	// Ausgabe nach Veränderung in Bitband
	ldr r0, [r7]			// Wert aus 0x20000010 erneut (!) laden, weil er nicht direkt verändert wurde
	bl	uart_putInt32
	mov r0, ascii_lf
	bl	uart_putChar
	
	b start

/*** Datenbereich (ab 0x20000000) ***/
.data
array:			// Eigentlich soll nach den Vorgaben im Datenbereich 
.rept 8			// kein Speicherplatz reserviert werden, aber wie soll
	.word 0x0	// es sonst in diesem Fall funktionieren?
.endr
str_get_bit0:	.asciz "Nummer des 0-Bits: 0x"
str_get_bit1:	.asciz "Nummer des 1-Bits: 0x"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ ascii_lf, 0x0a
.equ pit3_getval_offset_with_mov, 11	// gilt für einen Aufruf + ein mov zum Speichern des Zählers. Wurde in 1-1 bestimmt und gilt weiterhin

/*
* Ergebnisvergleich:
* Ohne DSP Befehle benötigt das Programm 28 Takte zur Bestimmung
* von min und max. Das liegt insbesondere daran, dass jeder Zugriff
* auf die "einzelnen" Bytes der 32 Bit Variable in irgendeiner Form (in diesem
* Fall über eine Bitmaske) einzeln geschehen muss. Anschließend muss über
* einen Vergleich und nachfolgende, bedingte Befehle das jeweils höhere und niedrigere Byte
* ausgewählt werden.
* Mit DSP Befehlen wird die gleiche Aufgabe in nur 3 Takten erledigt.
* Hilfreich dabei sind insbesondere die GE Bits im ASPR Register in
* Kombination mit der sel Operation.
*/
main:	
	bl	uart_init

loop_start:
	bl  read_bytes
	bl  calculate_min_max
	bl  calculate_min_max_DSP
	b	loop_start
	
.thumb_func
read_bytes:
	push {r4-r10, lr}
	
	// r4	=str_enter_vx
	// r5	=str_value_v1
	// r6	=str_value_v2
	// r7	=v1
	// r8	=v2
	// r9	.word v1
	// r10 	.word v2
	
	ldr r4, =str_enter_vx
	ldr r5, =str_value_v1
	ldr r6, =str_value_v2
	ldr r7, =v1
	ldr r8, =v2
	
	// Eingabeaufforderung ausgeben
	mov r0, r4
	bl	uart_putString
	
	// v1 einlesen und speichern
	bl  get_word
	mov r9, r0
	str r9, [r7]
	
	// v2 einlesen und speichern
	bl	get_word
	mov r10, r0
	str r10, [r8]
	
	// Eingelesene Werte ausgeben
	mov r0, r5
	bl  uart_putString
	mov r0, r9
	bl  uart_putInt32
	mov r0, r6
	bl  uart_putString
	mov r0, r10
	bl  uart_putInt32
	.rept 2
		mov r0, ascii_lf
		bl	uart_putChar
	.endr
	
	pop {r4-r10, pc}

.thumb_func
get_word:
	push {lr}
	
	mov r0, #0x0	// Zurücksetzen wegen orr!
	mov r1, #0x0
	
	bl	uart_getByte
	orr r1, r1, r0
	.rept 3
		lsl r1, #8	// Verschieben um genau ein Byte
		bl	uart_getByte
		orr r1, r1, r0
	.endr
	
	mov r0, r1		// Rückgabe von nur einem Wert, daher auf r0 schieben
	
	pop {pc}		// UP wurde benutzt, Rücksprung über Stack

.thumb_func
calculate_min_max:
	push {r4-r11, lr}
	
	// r4	=str_min
	// r5	=str_max
	// r6	=str_cycles
	// r7	.word v1 | =v1
	// r8 	.word v2 | =v2
	// r9	.word min
	// r10	.word max
	// r11	.word cycles_start
	
	ldr r4, =str_min
	ldr r5, =str_max
	ldr r6, =str_cycles
	ldr r7, =v1
	ldr r7, [r7]
	ldr r8, =v2
	ldr r8, [r8]
	mov r9, #0x0	// r9 und r10 werden mit orr bearbeitet,
	mov r10, #0x0	// sie müssen deshalb zwingend vorher zurückgesetzt werden!
	
	// Timer zurücksetzen und starten, siehe auch
	// calculate_min_max_DSP
	bl  pit3_init
	bl  pit3_getval
	mov r11, r0
	
	// Es werden jeweils nur 8 Bit aus v1 und v2
	// veglichen und dann jeweils in min oder max gesetzt
	.set mask, 0xff000000
	.rept 4
		and r0, r7, mask
		and r1, r8, mask
		cmp r0, r1
		ittee hi
			orrhi r9, r9, r1
			orrhi r10, r10, r0
			orrls r9, r9, r0
			orrls r10, r10, r1
		.set mask, mask >> 8	// Die Maske wird um genau ein Byte nach rechts verschoben
	.endr
	
	// Takte bestimmen
	bl  pit3_getval
	sub r0, r11, r0
	sub r11, r0, pit3_getval_offset_with_mov
	
	// Ausgabe der Ergebnisse
	mov r0, r4
	bl  uart_putString
	mov r0, r9
	bl  uart_putInt32
	mov r0, r5
	bl  uart_putString
	mov r0, r10
	bl  uart_putInt32
	mov r0, r6
	bl  uart_putString
	mov r0, r11
	bl  uart_putInt32
	.rept 2
		mov r0, ascii_lf
		bl	uart_putChar
	.endr
	
	pop {r4-r11, pc}

.thumb_func
calculate_min_max_DSP:
	push {r4-r11, lr}
	
	// r4	=str_min_DSP
	// r5	=str_max
	// r6	=str_cycles
	// r7	.word v1 | =v1
	// r8 	.word v2 | =v2
	// r9	.word min
	// r10	.word max
	// r11	.word cycles_start
	
	ldr r4, =str_min_DSP
	ldr r5, =str_max
	ldr r6, =str_cycles
	ldr r7, =v1
	ldr r7, [r7]
	ldr r8, =v2
	ldr r8, [r8]
	// Bei dieser Variante müssen r9 und r10 nicht
	// zurückgesetzt werden

	// Timer zurücksetzen und, weil pit3_getval
	// als UP immer schreibend auf r0 zugreift, Wert speichern.
	// Später muss ein "Offset" abgezogen werden,
	// dabei handelt es sich um die Anzahl der Takte für den
	// UP Aufruf + mov == #11 (bestimmt in V1-1)
	bl  pit3_init
	bl  pit3_getval
	mov r11, r0

	// usub8 setzt im APSR die GE Bits 0-3 wenn die
	// Teilsumme >= 0 ist und *kein Underflow* stattfindet. (Ist das richtig?)
	// Der Befehl selbst teilt eine 32 Bit Variable in 4
	// Bytes auf und subtrahiert diese Bytes jeweils zu einer zweiten
	// 32 Bit Variable auf die entsprechenden Bytes.
	// Das Ergebnis in r0 wird für die gewünschte Bestimmung 
	// von min und max jedoch gar nicht benötigt.
	usub8 r0, r7, r8
	sel r9, r8, r7
	sel r10, r7, r8
	
	// Takte := Starttakt - Endtakt - Offset
	bl  pit3_getval
	sub r0, r11, r0
	sub r11, r0, pit3_getval_offset_with_mov

	// Ausgabe analog zu calculate_min_max
	mov r0, r4
	bl  uart_putString
	mov r0, r9
	bl  uart_putInt32
	mov r0, r5
	bl  uart_putString
	mov r0, r10
	bl  uart_putInt32
	mov r0, r6
	bl  uart_putString
	mov r0, r11
	bl  uart_putInt32
	.rept 2
		mov r0, ascii_lf
		bl	uart_putChar
	.endr
	
	pop {r4-r11, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
v1: .word 0x0
v2: .word 0x0
str_enter_vx: 	.asciz "Bitte v1 und v2 jeweils als Folge von vier Bytes eingeben: "
str_value_v1: 	.asciz "\nv1: 0x"
str_value_v2: 	.asciz "\nv2: 0x"
str_min: 		.asciz "ohne DSP-Befehle:\nmin: 0x"
str_min_DSP: 	.asciz "mit DSP-Befehlen:\nmin: 0x"
str_max:		.asciz "\nmax: 0x"
str_cycles:		.asciz "\nAnzahl der Takte: 0x"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ ASCII_LF,		0x0a
.equ ASCII_SPACE,	0x20

/*
* 1a:
* Es werden nur halb so viele Multiplikationen tatsächlich
* benötigt. Die Einsparung von Befehlen ist durch die Anordnung
* der Matrix im Speicher, komibiniert mit den smuad Befehlen jedoch
* noch größer, weil weniger häufig Daten geladen und gespeichert, oder
* Register addiert werden müssen.
*
* 1d:
* In tabellarischer Form wird schnell deutlich, bei welchen Operationen Over- und
* Underflow, sowie Sättigung eine Rolle spielen. Wichtig dabei ist die Interpretation
* der 32 Bit Worte als zwei 16 Bit Werte, die jeweils entweder unsigned oder signed addiert werden.
* Während beispielsweise die Addition von 31867 (0x7C7B) und 35123 (0x8933) einen Overflow erzeugt und daher mit uqadd gesättigt wird,
* findet bei der Addition als signed Werte (31867, -30413) kein Overflow und dementsprechend auch keine Sättigung statt.
* Die signed Addition von -23498 (0xA436) und -15021 (0xC553) erzeugt einen Wert der zwar überläuft, aber eigentlich richtig interpretiert sogar viel zu klein ist. 
*
*					A1			A2					A1			A2					A1			A2
*					B1			B2					C1			C2					D1			D2
*
*	unsigned		42038		31867				42038		31867				42038		31867
*					 4263		35123				50515		24364				30862		33969
*	uadd16			46301		 1454				27017		56231				 7364		  300
*	uqadd16			46301		65535				65535		56231				65535		65535
*								OVERFLOW			OVERFLOW						OVERFLOW	OVERFLOW
*
*	signed			-23498		 31867				-23498		 31867				-23498		 31867
*					  4263		-30413				-15021		 24364				 30862		-31567
*	sadd16			-19235		 1454				27017		-9305				 7364		   300
*	qadd			-19235		 1454				-32768		 32767				 7364		   300
*													OVERFLOW	OVERFLOW
*
*
* 1e:
*
* Die USAT16 und SSAT16 Befehle sättigen zwei Halbwörter in einem Wort
* auf die jeweils angegebene Anzahl an Bits. Die Halbwörter werden dabei als
* signed interpretiert.
* 
* Bei einer Sättigung auf 13 Bits sind Werte zwischen 0 bis 8191 bzw. -4096 bis 4095
* möglich. Die Ergebnistabelle verdeutlich dies:
* 
* Eingabe:		A436	7C7B	10A7	8933
* USAT16:		0000	1FFF	10A7	0000
* SSAT16:		F000	0FFF	10A7	0000
* 
* 0xA436 ist als signed Halbwort kleiner als -4096. Gesättigt auf 13 Bits ergibt sich dadurch
* unsigned 0x0 bzw. signed 0xf000. 0x7C7B ist größer als 8191 und wird daher jeweils auf den
* höchstmöglichen Wert gesättigt. 0x10A7 liegt jeweils im gültigen Bereich und wird daher nicht gesättigt.
* 0x8933 ist erneut kleiner als 0 und wird deshalb unsigned auf 0 und signed auf -4096 gesetzt.
* 
* 
*/
main:
	bl	uart_init

	/***********\
	* Anfang 1a *
	\***********/

	// Ergebnismatrix berechnen

	ldr		r0, =matrixO
	ldr		r1, =matrixM
	add		r2, r1, #32		// Die äußere Schleife endet, wenn alle Werte von MatrixM durchlaufen wurden.
loop_row:					// Da in jedem Zelle tatsächlich 2 Werte gespeichert sind, müssen nur 16 * 2 durchlaufen werden. 
	ldr		r3, [r1], #4
	ldr		r4, [r1], #4
	ldr		r5, =matrixN
	add		r6, r5, #32		// Die innere Schleife endet, wenn alle Werte von MatrixN durchlaufen wurden
loop_col:
	ldr		r7, [r5], #4
	ldr		r8, [r5], #4
	smuad	r9, r3, r7
	smuad	r10, r4, r8
	add		r9, r9, r10
	str		r9, [r0], #4
	cmp		r5, r6
	bne		loop_col
	cmp		r1, r2
	bne		loop_row

	ldr r0, =str_result
	bl uart_putString

	// Ausgabe der Ergebnismatrix
	
	ldr		r4, =matrixO
	add		r5, r4, #64			// Ende bei Wert 32 * 2
loop_print_matrixO:
	ldm		r4!, {r6 - r9}		// 4 Zellen (8 Werte) laden und ausgeben
	mov		r0, r6
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, r7
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, r8
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, r9
	bl		uart_putInt32
	mov		r0, #ASCII_LF		// neue Zeilen beginnen
	bl		uart_putChar

	cmp		r5, r4				// Schleife abbrechen
	bne		loop_print_matrixO

	/***********\
	* Anfang 1b *
	\***********/
	
	ldr		r0, =str_copy
	bl		uart_putString

	ldr		r0, =matrixO
	ldr		r1, =copyMatrixO

	ldm		r0!, {r2 - r9}		// An dieser Stelle können 8 Register genutzt werden
	stm		r1!, {r2 - r9}		// Dadurch lässt die Matrix sich selbst ohne Schleife
	ldm		r0!, {r2 - r9}		// mit nur 4 Befehlen kopieren
	stm		r1!, {r2 - r9}

	/***********\
	* Anfang 1c *
	\***********/

	ldr		r0, =str_sum
	bl		uart_putString

	mov		r0, #0				// Das Ergebnisregister vorher auf 0 setzen
	ldr		r1, =matrixM
	ldr		r2, =matrixN
	add		r3, r1, #32
loop_product:
	ldr		r4, [r1], #4
	ldr		r5, [r2], #4		// Weil N invertiert abgelegt wurde, kann an dieser Stelle
	smuad	r4, r4, r5			// ein einzelner DSP Multiplikationsbefehl bereits zwei Werte bestimmen
	add		r0, r4
	cmp		r1, r3				// Abbruch am Ende von MatrixM...
	bne		loop_product

	bl		uart_putInt32		// Das Ergebnis liegt bereits in r0

	mov		r0, #ASCII_LF
	bl		uart_putChar
	mov		r0, #ASCII_LF
	bl		uart_putChar

	/***********\
	* Anfang 1d *
	\***********/

	ldr		r4, =A
	ldr		r4, [r4]
	ldr		r5, =B
	ldr		r5, [r5]
	ldr		r6, =C
	ldr		r6, [r6]
	ldr		r7, =D
	ldr		r7, [r7]

	ldr		r0, =str_uadd16
	bl		uart_putString
	uadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	uadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	uadd16	r0, r4, r7
	bl		uart_putInt32
	mov		r0, #ASCII_LF
	bl		uart_putChar

	ldr		r0, =str_sadd16
	bl		uart_putString
	sadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	sadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	sadd16	r0, r4, r7
	bl		uart_putInt32
	mov		r0, #ASCII_LF
	bl		uart_putChar

	ldr		r0, =str_uqadd16
	bl		uart_putString
	uqadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	uqadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	uqadd16	r0, r4, r7
	bl		uart_putInt32
	mov		r0, #ASCII_LF
	bl		uart_putChar

	ldr		r0, =str_qadd16
	bl		uart_putString
	qadd16	r0, r4, r5
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	qadd16	r0, r4, r6
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	qadd16	r0, r4, r7
	bl		uart_putInt32
	mov		r0, #ASCII_LF
	bl		uart_putChar

	mov		r0, #ASCII_LF
	bl		uart_putChar

	/***********\
	* Anfang 1e *
	\***********/

	ldr		r4, =A
	ldr		r4, [r4]
	ldr		r5, =B
	ldr		r5, [r5]

	ldr		r0, =str_ssat16
	bl		uart_putString
	ssat16	r0, #13, r4
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	ssat16	r0, #13, r5
	bl		uart_putInt32
	mov		r0, #ASCII_LF
	bl		uart_putChar
	
	ldr		r0, =str_usat16
	bl		uart_putString
	usat16	r0, #13, r4
	bl		uart_putInt32
	mov		r0, #ASCII_SPACE
	bl		uart_putChar
	usat16	r0, #13, r5
	bl		uart_putInt32
	mov		r0, #ASCII_LF
	bl		uart_putChar

end:
	b end
	
/*** Datenbereich (ab 0x20000000) ***/
.data
matrixM:		.word	0x5f8c7f48, 0x82456048,	0xc7999c5d, 0xd49c33d8,	0x579b8aef, 0xf2c0a3c2,	0x41fd50d4, 0x25c64afa
// N wird gespiegelt im Speicher abgelegt
matrixN:		.word	0x7f410645, 0x8c8f9065,	0x78e3f7f3, 0xd29f2961,	0x5a1edfed, 0x4b9f1092,	0x61bf21be, 0x5ca1c6d3
.align 
str_result:		.asciz "Ergebnismatrix O:\n"
str_copy:		.asciz "\nKopieren der Matrix O!\n"
str_sum:		.asciz "\nProdukt-Summe: "
str_uadd16:		.asciz "UADD16:  "
str_sadd16:		.asciz "SADD16:  "
str_uqadd16:	.asciz "UQADD16: "
str_qadd16:		.asciz "QADD16:  "
str_ssat16:		.asciz "SSAT16:  "
str_usat16:		.asciz "USAT16:  "
.align
A:				.word 0xA4367C7B
B:				.word 0x10A78933
C:				.word 0xC5535F2C
D:				.word 0x788E84B1
matrixO:
	.rept 16
				.word 0x0
	.endr
copyMatrixO:
	.rept 16
				.word 0x0
	.endr
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirekdtiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ	M25,						25000000	// entspricht 25 MHz Taktfrequenz

.equ	ASCII_PERIOD,				0x2e
.equ	ASCII_COLON,				0x3a
.equ	ASCII_SPACE,				0x20
.equ	ASCII_LF,					0x0a
.equ	ASCII_ZERO,					0x30
.equ	ASCII_S,					0x73
.equ	ASCII_T,					0x74
.equ	ASCII_D,					0x64

.equ	MAX_SECOND,					59
.equ	MAX_MINUTE,					59
.equ	MAX_HOUR,					23
.equ	MAX_DAY,					30
.equ	MAX_MONTH,					12
.equ	MAX_YEAR,					99

.equ	MIN_SECOND,					0
.equ	MIN_MINUTE,					0
.equ	MIN_HOUR,					0
.equ	MIN_DAY,					1
.equ	MIN_MONTH,					1
.equ	MIN_YEAR,					0

.equ	PADDING_THRESHOLD,			9

.equ	PIT3_GETVAL_OFFSET,			11

main:
	bl		uart_init

	// Falls das Programm einfach 25000000 Takte
	// wartet, ist es sehr ungenau, da die zusätzlichen
	// Takte durch die Ein-/Ausgabe des Datums und das hHchzählen
	// der Sekunden dazu addiert werden. Außerdem ist die
	// Anzahl variabel, da nicht immer der gesamte Code durchlaufen wird.
	//
	// Um dieses Problem etwas abzumildern, kann man die insgesamt
	// benötigten Takte mit dem PIT3 zählen und dann von 25 Millionen abziehen.
	// Die Uhr scheint dadurch auch nach mehreren Stunden im Test noch
	// relativ genau zu sein.

	bl		pit3_init
	bl		pit3_getval
	mov		r10, r0

main_loop:
	bl		pit3_getval
	sub		r0,	r10, r0					// Differenz Start - Ende - Offset bestimmen
	sub		r0, r0, #PIT3_GETVAL_OFFSET	// und in r0 weiterreichen.
	bl		delay

	bl		pit3_getval
	mov		r10, r0						// Eine neue Startzeit sichern

	// Datum nicht ausgeben, falls die Uhr gestoppt wurde.
	// Ich interpretiere die Aufgabenstellung dabei so, dass die Uhrzeit nicht ausgegeben
	// und *auch nicht* erhöht wird. Daher erfolgt bei gestoppter Uhr der Sprung
	// direkt zur Überprüfung, ob eine Eingabe vorliegt.
	// Falls die Uhr im Hintergrund weiterlaufen sollte, müsste stattdessen
	// nur die print_date Funktion übersprungen werden.
	ldr		r0, =running_flag
	ldr		r0, [r0]
	cmp		r0, #0
	bne		check_input

	// Datum durch UP ausgeben lassen

	bl		print_date

	// Datum um eine Sekunde erhöhen und dabei auch "Überläufe" berücksichtigen

	ldr		r0, =seconds		// bei den Sekunden anfangen
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_SECOND		// Falls kein Sekunden "Überlauf" 
	itt ls						// stattfindet, muss der Rest
	strls	r1, [r0]			// des Datums auch nicht erhöht werden,
	bls		check_input			// daher den Rest überspringen...
	mov		r1, #MIN_SECOND
	str		r1, [r0]

	ldr		r0, =minutes		// Immer wenn die nächst größe
	ldr		r1, [r0]			// Einheit jedoch ihr Maximum erreicht,
	add		r1, r1, #1			// muss dann auch der nächste Wert erhöht werden.
	cmp		r1, #MAX_MINUTE
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_MINUTE
	str		r1, [r0]

	ldr		r0, =hours
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_HOUR 
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_HOUR
	str		r1, [r0]

	ldr		r0, =day
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_DAY
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_DAY
	str		r1, [r0]

	ldr		r0, =month
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_MONTH
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_MONTH
	str		r1, [r0]

	ldr		r0, =year
	ldr		r1, [r0, #4]
	add		r1, r1, #1
	cmp		r1, #MAX_YEAR 
	itt ls
	strls	r1, [r0, #4]
	bls		check_input
	mov		r1, #MIN_YEAR
	str		r1, [r0, #4]

	// Auf eingegebenes Zeichen prüfen

check_input:						// Falls ein Zeichen empfangen wurde
	bl		uart_charPresent		// muss es genauer überprüft werden,
	cmp		r0, #0					// alternativ wird wieder gewartet.
	beq		main_loop

	bl		uart_getChar			// Zeichen holen

	cmp 	r0, #ASCII_S			// Falls ein "s" eingegeben wurde
	bne 	check_ascii_t			// starten/stoppen, sonst nächster Vergleich

	ldr		r0, =running_flag		// Das Flag wird negiert und wieder gespeichert
	ldr		r1, [r0]
	mvn		r1, r1
	str		r1, [r0]

	b		main_loop				// s wurde empfangen, daher wieder warten

check_ascii_t:
	cmp 	r0, #ASCII_T			// Falls ein "t" empfangen wurde
	bne 	check_ascii_d			// Zeit eingeben, sonst weiter
	
	ldr		r0, =str_enter_hh
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0					// Wert sichern wegen bedingtem UP Aufrufe, siehe oben
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls 	uart_putChar
	ldr		r0, =hours
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10
	
	ldr		r0, =str_enter_mm
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls 	uart_putChar
	ldr		r0, =minutes
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_LF
	bl		uart_putChar
	
	bl		pit3_getval				// An dieser Stelle sollte der Taktzähler
	mov		r10, r0					// neu gesetzt werden, da der Benutzer gegebenenfalls
									// eine sehr lange Zeit für seine Eingabe benötigt hat.
									
	b		main_loop				// Zeit wurde eingegeben, wieder warten
	
check_ascii_d:
	cmp 	r0, #ASCII_D			// Falls "d" eingegeben wurde
	bne		main_loop				// das Datum setzen, sonst weiter warten und Eingabe ignorieren

	ldr		r0, =str_enter_day		// Der gesamte Abschnitt funktioniert
	bl		uart_putString			// analog zur Eingabe einer neuen Zeit.
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls 	uart_putChar
	ldr		r0, =day
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10

	ldr		r0, =str_enter_month
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	ldr		r0, =month
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10

	ldr		r0, =str_enter_year
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	ldr		r0, =year
	str		r4, [r0, #4]
	mov		r0, r4
	bl		uart_putByteBase10
	mov		r0, #ASCII_LF
	bl		uart_putChar
	
	bl		pit3_getval
	mov		r10, r0

	b		main_loop

.thumb_func
print_date:
	push {r4-r5, lr}

	ldr		r4, =day				// Da eventuell links per UP eine 0 angefügt wird, muss der Wert gesichert werden
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD	// Falls der Tag <= 9 ist,
	itt ls							// gibt uart_putByteBase10 die Zahl nicht im "dd"
	movls	r0, #ASCII_ZERO			// Format aus. Der Wert muss daher links um eine 0 ergänzt werden.
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_PERIOD
	bl		uart_putChar

	ldr		r4, =month				// Nachfolgende Werte analog zum Tag ausgeben
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_PERIOD
	bl		uart_putChar

	ldr		r4, =year				// Die Jahreszahl besteht aus zwei Werten,
	ldr		r0, [r4, #0]			// dadurch ist es theoretisch auch sehr einfach möglich
	bl		uart_putByteBase10		// den Jahrhundertüberlauf zu berücksichtigen
	ldr		r5, [r4, #4]			// Derzeit erlaubt das Programm jedoch ausschließlich 
	cmp		r5, #PADDING_THRESHOLD	// die Jahre 2000 bis 2099, das Jahrhundert kann nicht während der Ausführung verändert werden.
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r5
	bl		uart_putByteBase10

	mov		r0, #ASCII_SPACE
	bl		uart_putChar

	ldr		r4, =hours
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_COLON
	bl		uart_putChar

	ldr		r4, =minutes
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	// Der auskommentierte Code erlaubt es auch die Sekunden anzuzeigen.

/*
	mov		r0, #ASCII_COLON
	bl		uart_putChar

	ldr		r4, =seconds
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10
*/

	ldr		r0, =str_date_end
	bl		uart_putString

	pop {r4-r5,pc}

.thumb_func
delay:						// Die Funktion erwartet in
	ldr		r1, =M25		// r0 einen Wert < 25000000.
delay_loop:					// Dieser Wert wird dann schrittweise (add:1+cmp:1+b:2 Takte)
	add		r0, r0, #4		// erhöht, bis der Wert >= 25000000 ist.
	cmp		r0, r1			//
	blt		delay_loop		// Auf diese Weise kann das Programm ca. 1 Sekunde
							// sinnvoll "abschätzen". Die Abweichung ist auch
	bx		lr				// nach mehreren Stunden nur gering.

/*** Datenbereich (ab 0x20000000) ***/
.data
running_flag:		.word	0
str_is_stopped:		.asciz	"\n\nUhr gestoppt\n\n"
str_enter_hh: 		.asciz	"Stunde eingeben (hh): "
str_enter_mm: 		.asciz	"\nMinuten eingeben (mm): "
str_enter_day: 		.asciz	"Tag eingeben (dd): "
str_enter_month: 	.asciz	"\nMonat eingeben (mm): "
str_enter_year:		.asciz	"\nJahr eingeben (jj): "
str_date_end:		.asciz	" Uhr\n"
.align
year:				.word	20,14
month:				.word	01
day:				.word	01
hours:				.word	00
minutes:			.word	00
seconds:			.word	00

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirekdtiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ	M25,						25000000					// entspricht 25 MHz Taktfrequenz

		// Bit Band Aliase der Steuerregister
.equ	BB_BASE,					0x40000000
.equ	BB_ALIAS_BASE,				0x42000000

		// Clock Gate für PIT schalten
.equ	SIM_SCGC6,					0x4004803c					// Quelle: S.308 Handbuch
.equ	SIM_SCGC6_BIT_PIT,			23							// Quelle: S.308 Handbuch
.equ	SIM_SCGC6_BB_BIT_PIT,		BB_ALIAS_BASE + (SIM_SCGC6  - BB_BASE) << 5 + SIM_SCGC6_BIT_PIT << 2

.equ	NVIC_ISER_BASE,				0xe000e100					// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ISER2,					NVIC_ISER_BASE + 0x8
.equ	NVCI_ICPR_BASE,				0xe000e280
.equ	NVCI_ICPR2,					NVCI_ICPR_BASE + 0x8

		// PIT_TCTRL Register Felder
.equ	PIT_TIE,					1							// Quelle: S.1080 Handbuch
.equ	PIT_TEN,					0							// Quelle: S.1080 Handbuch

.equ	PIT_MCR,					0x40037000					// Quelle: S.1077 Handbuch

.equ	PIT1_BASE,					0x40037110					// Quelle: S.1077 Handbuch
.equ	PIT_LDVAL1,					PIT1_BASE + 0x0
.equ	PIT_CVAL1,					PIT1_BASE + 0x4
.equ	PIT_TCTRL1,					PIT1_BASE + 0x8
.equ	PIT_TFLG1,					PIT1_BASE + 0xc

.equ	PIT1_IRQ,					69							// Quelle: S.78 Handbuch
.equ	PIT1_IRQ_OFFSET,			0x00000154					// Quelle: S.78 Handbuch

.equ	PIT1_INTERRUPT_BB,			BB_ALIAS_BASE + (PIT_TCTRL1 - BB_BASE) << 5 + PIT_TIE  << 2
.equ	PIT1_TIMER_BB,				BB_ALIAS_BASE + (PIT_TCTRL1 - BB_BASE) << 5 + PIT_TEN  << 2

		// Offset des Bits für PIT1 im NVCI Register
.equ	NVCI_PIT1_BIT,				PIT1_IRQ | 32				// entspricht modulo 32

.equ	IRQ_VECTOR_TABLE_BASE,		0x1ffffe00					// Quelle: Skript
.equ	IRQ_VECTOR_PIT1,			IRQ_VECTOR_TABLE_BASE + PIT1_IRQ_OFFSET

.equ	ASCII_PERIOD,				0x2e
.equ	ASCII_COLON,				0x3a
.equ	ASCII_SPACE,				0x20
.equ	ASCII_LF,					0x0a
.equ	ASCII_ZERO,					0x30
.equ	ASCII_S,					0x73
.equ	ASCII_T,					0x74
.equ	ASCII_D,					0x64

.equ	MAX_SECOND,					59
.equ	MAX_MINUTE,					59
.equ	MAX_HOUR,					23
.equ	MAX_DAY,					30
.equ	MAX_MONTH,					12
.equ	MAX_YEAR,					99

.equ	MIN_SECOND,					0
.equ	MIN_MINUTE,					0
.equ	MIN_HOUR,					0
.equ	MIN_DAY,					1
.equ	MIN_MONTH,					1
.equ	MIN_YEAR,					0

.equ	PADDING_THRESHOLD,			9

main:
	bl		uart_init

	// Takt für PIT aktivieren (SIM) (Hinweis a)
	ldr		r0, =SIM_SCGC6_BB_BIT_PIT
	mov		r1, #1
	str		r1, [r0]

	// Interrupthandler in Tabelle schreiben (Hinweis b)
	ldr		r0, =interrupt_handler
	ldr		r1, =IRQ_VECTOR_PIT1
	str		r0, [r1]

	// Pending Interrupt löschen (Hinweis c)
	ldr		r0, =NVCI_ICPR2
	ldr		r1, [r0]
	orr		r1, r1, #NVCI_PIT1_BIT
	str		r1, [r0]

	// Interrupt aktivieren (Hinweis d)
	// analog zu Pending löschen
	ldr		r0, =NVIC_ISER2
	ldr		r1, [r0]
	orr		r1, r1, #NVCI_PIT1_BIT
	str		r1, [r0]

	// Im Handbuch steht auf S.1078, dass das 
	// Modul erst deaktiviert werden muss (Bit 1 setzen).
	// In den Hinweisen zu V2-3 ist davon bei der Initialisierung
	// jedoch keine Rede. Da das Programm, nach mehrfachem Testen, auch ohne das 
	// Setzen von Bit 1 und nach direktem Schreiben von 0x1 funktioniert,
	// gehe ich davon aus, dass es so richtig ist.

	// PIT im Debug-Modus laufen lassen (Hinweis e)
	ldr		r0, =PIT_MCR
	mov		r1, #1					// An dieser Stelle kein Bit Banding
	str		r1, [r0]

	// 25000000 Takte eintragen (Hinweis f)
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =M25
	str		r1, [r0]

	// Interrupt zu PIT1 aktivieren (Hinweis h) und PIT1 starten (Hinweis g)
	mov		r0, #1
	ldr		r1, =PIT1_TIMER_BB
	str		r0, [r1]
	ldr		r1, =PIT1_INTERRUPT_BB
	str		r0, [r1]

	// Alle Interrupts aktivieren
	cpsie	i

	// In einer Schleife "warten"
main_loop:
	ldr		r1, =second_flag
wait_loop:
	ldr		r0, [r1]
	cmp		r0, #0					// Falls das Flag gesetzt wurde, ist der Wert != 0
	beq		wait_loop

	// Benutzer-Flag zurücksetzen
	mov		r0, #0
	str		r0, [r1]

	// Der folgende Code ist bis zur Definition der Interrupt Routine identisch zu V2-2

	// Datum nicht ausgeben, falls die Uhr gestoppt wurde.
	// Ich interpretiere die Aufgabenstellung dabei so, dass die Uhrzeit nicht ausgegeben
	// und *auch nicht* erhöht wird. Daher erfolgt bei gestoppter Uhr der Sprung
	// direkt zur Überprüfung, ob eine Eingabe vorliegt.
	// Falls die Uhr im Hintergrund weiterlaufen sollte, müsste stattdessen
	// nur die print_date Funktion übersprungen werden.
	ldr		r0, =running_flag
	ldr		r0, [r0]
	cmp		r0, #0
	bne		check_input

	// Datum durch UP ausgeben lassen

	bl		print_date

	// Datum um eine Sekunde erhöhen und dabei auch "Überläufe" berücksichtigen

	ldr		r0, =seconds		// bei den Sekunden anfangen
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_SECOND		// Falls kein Sekunden "Überlauf" 
	itt ls						// stattfindet, muss der Rest
	strls	r1, [r0]			// des Datums auch nicht erhöht werden,
	bls		check_input			// daher den Rest überspringen...
	mov		r1, #MIN_SECOND
	str		r1, [r0]

	ldr		r0, =minutes		// Immer wenn die nächst größe
	ldr		r1, [r0]			// Einheit jedoch ihr Maximum erreicht,
	add		r1, r1, #1			// muss dann auch der nächste Wert erhöht werden.
	cmp		r1, #MAX_MINUTE
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_MINUTE
	str		r1, [r0]

	ldr		r0, =hours
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_HOUR 
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_HOUR
	str		r1, [r0]

	ldr		r0, =day
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_DAY
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_DAY
	str		r1, [r0]

	ldr		r0, =month
	ldr		r1, [r0]
	add		r1, r1, #1
	cmp		r1, #MAX_MONTH
	itt ls
	strls	r1, [r0]
	bls		check_input
	mov		r1, #MIN_MONTH
	str		r1, [r0]

	ldr		r0, =year
	ldr		r1, [r0, #4]
	add		r1, r1, #1
	cmp		r1, #MAX_YEAR 
	itt ls
	strls	r1, [r0, #4]
	bls		check_input
	mov		r1, #MIN_YEAR
	str		r1, [r0, #4]

	// Auf eingegebenes Zeichen prüfen

check_input:						// Falls ein Zeichen empfangen wurde
	bl		uart_charPresent		// muss es genauer überprüft werden,
	cmp		r0, #0					// alternativ wird wieder gewartet.
	beq		main_loop

	bl		uart_getChar			// Zeichen holen

	cmp 	r0, #ASCII_S			// Falls ein "s" eingegeben wurde
	bne 	check_ascii_t			// starten/stoppen, sonst nächster Vergleich

	ldr		r0, =running_flag		// Das Flag wird negiert und wieder gespeichert
	ldr		r1, [r0]
	mvn		r1, r1
	str		r1, [r0]

	b		main_loop				// s wurde empfangen, daher wieder warten

check_ascii_t:
	cmp 	r0, #ASCII_T			// Falls ein "t" empfangen wurde
	bne 	check_ascii_d			// Zeit eingeben, sonst weiter
	
	ldr		r0, =str_enter_hh
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0					// Wert sichern wegen bedingtem UP Aufrufe, siehe oben
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls 	uart_putChar
	ldr		r0, =hours
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10
	
	ldr		r0, =str_enter_mm
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls 	uart_putChar
	ldr		r0, =minutes
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_LF
	bl		uart_putChar
	
	bl		pit3_getval				// An dieser Stelle sollte der Taktzähler
	mov		r10, r0					// neu gesetzt werden, da der Benutzer gegebenenfalls
									// eine sehr lange Zeit für seine Eingabe benötigt hat.
									
	b		main_loop				// Zeit wurde eingegeben, wieder warten
	
check_ascii_d:
	cmp 	r0, #ASCII_D			// Falls "d" eingegeben wurde
	bne		main_loop				// das Datum setzen, sonst weiter warten und Eingabe ignorieren

	ldr		r0, =str_enter_day		// Der gesamte Abschnitt funktioniert
	bl		uart_putString			// analog zur Eingabe einer neuen Zeit.
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls 	uart_putChar
	ldr		r0, =day
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10

	ldr		r0, =str_enter_month
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	ldr		r0, =month
	str		r4, [r0]
	mov		r0, r4
	bl		uart_putByteBase10

	ldr		r0, =str_enter_year
	bl		uart_putString
	bl		uart_getByteBase10
	mov		r4, r0
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	ldr		r0, =year
	str		r4, [r0, #4]
	mov		r0, r4
	bl		uart_putByteBase10
	mov		r0, #ASCII_LF
	bl		uart_putChar
	
	bl		pit3_getval
	mov		r10, r0

	b		main_loop

.thumb_func
print_date:
	push {r4-r5, lr}

	ldr		r4, =day				// Da eventuell links per UP eine 0 angefügt wird, muss der Wert gesichert werden
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD	// Falls der Tag <= 9 ist,
	itt ls							// gibt uart_putByteBase10 die Zahl nicht im "dd"
	movls	r0, #ASCII_ZERO			// Format aus. Der Wert muss daher links um eine 0 ergänzt werden.
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_PERIOD
	bl		uart_putChar

	ldr		r4, =month				// Nachfolgende Werte analog zum Tag ausgeben
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_PERIOD
	bl		uart_putChar

	ldr		r4, =year				// Die Jahreszahl besteht aus zwei Werten,
	ldr		r0, [r4, #0]			// dadurch ist es theoretisch auch sehr einfach möglich
	bl		uart_putByteBase10		// den Jahrhundertüberlauf zu berücksichtigen
	ldr		r5, [r4, #4]			// Derzeit erlaubt das Programm jedoch ausschließlich 
	cmp		r5, #PADDING_THRESHOLD	// die Jahre 2000 bis 2099, das Jahrhundert kann nicht während der Ausführung verändert werden.
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r5
	bl		uart_putByteBase10

	mov		r0, #ASCII_SPACE
	bl		uart_putChar

	ldr		r4, =hours
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	mov		r0, #ASCII_COLON
	bl		uart_putChar

	ldr		r4, =minutes
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10

	// Der auskommentierte Code erlaubt es auch die Sekunden anzuzeigen.

/*
	mov		r0, #ASCII_COLON
	bl		uart_putChar

	ldr		r4, =seconds
	ldr		r4, [r4]
	cmp		r4, #PADDING_THRESHOLD
	itt ls
	movls	r0, #ASCII_ZERO
	blls	uart_putChar
	mov		r0,	r4
	bl		uart_putByteBase10
*/

	ldr		r0, =str_date_end
	bl		uart_putString

	pop {r4-r5,pc}

.thumb_func
interrupt_handler:
	// Interrupt-Flag löschen und
	// Benutzer-Flag setzen
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	ldr		r1, =second_flag
	str		r0, [r1]

	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
second_flag:		.word	0
running_flag:		.word	0
str_is_stopped:		.asciz	"\n\nUhr gestoppt\n\n"
str_enter_hh: 		.asciz	"Stunde eingeben (hh): "
str_enter_mm: 		.asciz	"\nMinuten eingeben (mm): "
str_enter_day: 		.asciz	"Tag eingeben (dd): "
str_enter_month: 	.asciz	"\nMonat eingeben (mm): "
str_enter_year:		.asciz	"\nJahr eingeben (jj): "
str_date_end:		.asciz	" Uhr\n"
.align
year:				.word	20,14
month:				.word	01
day:				.word	01
hours:				.word	00
minutes:			.word	00
seconds:			.word	00

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified



.equ	SIM_SCGC6,				0x4004803c						// Quelle: S.308 Handbuch
.equ	SIM_SCGC6_BIT_CRC,		18								// Quelle: S.308 Handbuch
__BBREG	SIM_SCGC6_BB_BIT_CRC,	SIM_SCGC6, SIM_SCGC6_BIT_CRC

.equ	CRC_CRC,				0x40032000						// Quelle: S.780ff Handbuch
.equ	CRC_GPOLY,				0x40032004						// Quelle: S.780ff Handbuch
.equ	CRC_CTRL,				0x40032008						// Quelle: S.780ff Handbuch

.equ	CRC_BIT_TOT1,			31								// Quelle: S.780ff Handbuch
.equ	CRC_BIT_TOT0,			30								// Quelle: S.780ff Handbuch
.equ	CRC_BIT_TOTR1,			29								// Quelle: S.780ff Handbuch
.equ	CRC_BIT_TOTR0,			28								// Quelle: S.780ff Handbuch
.equ	CRC_BIT_FXOR,			26								// Quelle: S.780ff Handbuch
.equ	CRC_BIT_WAS,			25								// Quelle: S.780ff Handbuch
.equ	CRC_BIT_TCRC,			24								// Quelle: S.780ff Handbuch

__BBREG CRC_BIT_TOT1_BB,		CRC_CTRL, CRC_BIT_TOT1
__BBREG CRC_BIT_TOT0_BB,		CRC_CTRL, CRC_BIT_TOT0
__BBREG CRC_BIT_TOTR1_BB,		CRC_CTRL, CRC_BIT_TOTR1
__BBREG CRC_BIT_TOTR0_BB,		CRC_CTRL, CRC_BIT_TOTR0
__BBREG CRC_BIT_FXOR_BB,		CRC_CTRL, CRC_BIT_FXOR
__BBREG	CRC_BIT_WAS_BB,			CRC_CTRL, CRC_BIT_WAS
__BBREG	CRC_BIT_TCRC_BB,		CRC_CTRL, CRC_BIT_TCRC

.equ	ASCII_LF,				0x0a
.equ	ASCII_SPACE,			0x20

.equ	CRC_STD_32,				0x04C11DB7						// Standard CRC-32 Polynom 
.equ	SEED,					0x12345678

.equ	WORD_OF_ONES,			0x01010101						// notwendig für Abbruchbedingung der Schleife

main:
	bl	uart_init

	// Takt für CRC aktivieren
	ldr		r0, =SIM_SCGC6_BB_BIT_CRC
	mov		r1, #1
	str		r1, [r0]

	// Konfiguration entsprechend (b):
	// * kein Transpose
	// * kein finales XOR
	// * 32 Bit Breite
	mov		r1, #0
	ldr		r0, =CRC_BIT_TOT1_BB
	str		r1, [r0]
	ldr		r0, =CRC_BIT_TOT0_BB
	str		r1, [r0]
	ldr		r0, =CRC_BIT_TOTR1_BB
	str		r1, [r0]
	ldr		r0, =CRC_BIT_TOTR0_BB
	str		r1, [r0]
	ldr		r0, =CRC_BIT_FXOR_BB
	str		r1, [r0]
	ldr		r0, =CRC_BIT_TCRC_BB
	mov		r1, #1
	str		r1, [r0]

	// Standard Polynom eintragen (c)
	ldr		r0, =CRC_GPOLY
	ldr		r1, =CRC_STD_32
	str		r1, [r0]

	// Zuletzt (Handbuch S.784) Seed in Register 
	// schreiben (d), dafür WAS Bit setzen...
	ldr		r0, =CRC_BIT_WAS_BB
	mov		r1, #1
	str		r1, [r0]

	ldr		r0, =CRC_CRC
	ldr		r1, =SEED
	str		r1, [r0]

	// ...und wieder zurücksetzen.
	ldr		r0, =CRC_BIT_WAS_BB
	mov		r1, #0
	str		r1, [r0]



	ldr		r4, =CRC_CRC
	ldr		r5, =str
	ldr		r6, =WORD_OF_ONES
crc_loop:
	// Wort laden und um 4 Bytes weiterrücken
	ldr		r7, [r5], #4

	// Die Prüfsumme des Strings soll wortweise
	// berechnet werden. Da die Grenzen von Strings jedoch
	// nicht zwangsläufig in einem neuen Wort liegen, muss
	// der Nullterminator auch innerhalb eines Wortes ermittelt werden. 
	// Falls dieser im geladenen Wort liegt, bricht die Schleife also ab.
	// Dabei wird das den Terminator enthaltenden Wort NICHT
	// mehr in das CRC Register geschrieben. Effektiv heißt das,
	// dass die Prüfsumme nicht über den gesamten String berechnet wird.
	//
	// Ich verstehe diese Einschränkung als so durch die
	// Aufgabenstellung gegeben. Alternativ könnte man auch
	// erst das geladene Wort in das Register schreiben und 
	// danach die Schleife beenden. Denkbar wäre aber auch,
	// den Index des Terminatorbytes im Wort zu finden und
	// den, im Byte "links" stehenden, Rest mit 0 aufzufüllen,
	// um so die Prüfsumme für den vollständigen String zu bestimmen.
	//
	// Die Abbruchbedingung nutzt die aus V1-1 bekannte Bestimmung
	// der kleinsten Bytes eines Wortes, um ein mögliches
	// 0x00 Byte zu erkennen. Dafür wird das geladene Wort 
	// mit 0x01010101 verglichen und die jeweils kleinsten Bytes
	// werden ausgewählt. Falls ein Terminator (0x00) vorliegt,
	// ist das "neue" Wort, interpretiert als UInt32, kleiner als 0x01010101.
	// Es handelt sich hierbei nicht um eine allgemeine Lösung,
	// da für sehr kurze Strings auf diese Art eventuell keine Prüfsumme
	// berechnet werden kann UND weil ein String der nicht an einer
	// Wortgrenze beginnt direkt zum Schleifenabbruch führt.
	// Bedingt durch die vorliegenden Einschränkung bezüglich der Berechnung,
	// scheint mir dies in diesem Fall akzeptabel.
	usub8	r0, r7, r6
	sel		r0, r6, r7
	cmp		r0, r6
	bne		print_result

	str		r7, [r4]

	b		crc_loop

print_result:

	ldr		r0, =str
	bl		uart_putString

	ldr		r0, =str_result
	bl		uart_putString

	ldr		r0, =CRC_CRC
	ldr		r0, [r0]
	bl		uart_putInt32

end:
	b		end

/*** Datenbereich (ab 0x20000000) ***/
.data
str:		.asciz	"Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
str_result:	.asciz	"\nPruefsumme: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ	SIM_SCGC5,					0x40048038					// Quelle: S.306 Handbuch
.equ	SIM_SCGC5_BIT_PORTA,		9							// Quelle: S.306 Handbuch
.equ	SIM_SCGC5_BIT_PORTE,		13							// Quelle: S.306 Handbuch

.equ	SIM_SCGC6,					0x4004803c					// Quelle: S.308 Handbuch
.equ	SIM_SCGC6_BIT_PIT,			23							// Quelle: S.308 Handbuch

.equ	NVIC_ISER_BASE,				0xe000e100					// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ISER2,					NVIC_ISER_BASE + 0x8		// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ICPR_BASE,				0xe000e280					// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ICPR2,					NVIC_ICPR_BASE + 0x8		// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual

.equ	PIT_MCR,					0x40037000					// Quelle: S.1077 Handbuch

.equ	PIT1_BASE,					0x40037110					// Quelle: S.1077 Handbuch
.equ	PIT_LDVAL1,					PIT1_BASE + 0x0				// Quelle: S.1077 Handbuch
.equ	PIT_CVAL1,					PIT1_BASE + 0x4				// Quelle: S.1077 Handbuch
.equ	PIT_TCTRL1,					PIT1_BASE + 0x8				// Quelle: S.1077 Handbuch
.equ	PIT_TFLG1,					PIT1_BASE + 0xc				// Quelle: S.1077 Handbuch

		// PIT_TCTRL Register Felder
.equ	PIT_CHN,					2							// Quelle: S.1080 Handbuch
.equ	PIT_TIE,					1							// Quelle: S.1080 Handbuch
.equ	PIT_TEN,					0							// Quelle: S.1080 Handbuch

__BBREG	PIT1_CHAIN_BB,				PIT_TCTRL1, PIT_CHN
__BBREG	PIT1_INTERRUPT_BB,			PIT_TCTRL1, PIT_TIE
__BBREG	PIT1_TIMER_BB,				PIT_TCTRL1, PIT_TEN

.equ	PIT1_IRQ,					69							// Quelle: S.78 Handbuch
.equ	PIT1_IRQ_OFFSET,			0x00000154					// Quelle: S.78 Handbuch

.equ	SW2_IRQ,					91							// Quelle: S.78 Handbuch
.equ	SW2_IRQ_OFFSET,				0x000001AC					// Quelle: S.78 Handbuch

		// Offset der Bits im NVIC Register
.equ	NVIC_PIT1_BIT,				PIT1_IRQ % 32
.equ	NVIC_SW2_BIT,				SW2_IRQ % 32

.equ	IRQ_VECTOR_TABLE_BASE,		0x1ffffe00					// Quelle: Skript
.equ	IRQ_VECTOR_PIT1,			IRQ_VECTOR_TABLE_BASE + PIT1_IRQ_OFFSET
.equ	IRQ_VECTOR_SW2,				IRQ_VECTOR_TABLE_BASE + SW2_IRQ_OFFSET

.equ	GPIOA_PDOR,					0x400FF000					// Quelle: S.1743 Handbuch
.equ	GPIOA_PDIR,					0x400FF010					// Quelle: S.1743 Handbuch
.equ	GPIOA_PDDR,					0x400FF014					// Quelle: S.1743 Handbuch

.equ	GPIOE_PDDR,					0x400FF114					// Quelle: S.1745 Handbuch

.equ	PORTA_PCR10,				0x40049028					// Quelle: S.272 Handbuch
.equ	PORTA_PCR11,				0x4004902C					// Quelle: S.272 Handbuch
.equ	PORTA_PCR19,				0x4004904C					// Quelle: S.272 Handbuch
.equ	PORTA_PCR28,				0x40049070					// Quelle: S.272 Handbuch
.equ	PORTA_PCR29,				0x40049074					// Quelle: S.272 Handbuch

.equ	PORTE_PCR26,				0x4004D068					// Quelle: S.276 Handbuch

.equ	PORT_BIT_ISF,				24							// Quelle: S.277 Handbuch

// Konfiguration jeweils als GPIO (Pin Mux Control Alternative 1),
// für SW2 zusätzlich ISF zurück- und Interrupt
// auf "0101" ("Interrupt on falling edge") setzen
.equ	PORTA_LED_CFG,				0x00000103					// Quelle: S.277ff Handbuch
.equ	PORTA_PCR19_CFG,			0x00000103					// Quelle: S.277ff Handbuch
.equ	PORTE_PCR26_CFG,			0x010a0103					// Quelle: S.277ff Handbuch

.equ	E1_PIN,						11							// Quelle: Schaltplan
.equ	E2_PIN,						28							// Quelle: Schaltplan
.equ	E3_PIN,						29							// Quelle: Schaltplan
.equ	E4_PIN,						10							// Quelle: Schaltplan
.equ	SW1_PIN,					19							// Quelle: Schaltplan
.equ	SW2_PIN,					26							// Quelle: Schaltplan

.equ	M25,						25000000					// Anzahl der Takte bei 25 MHz pro Sekunde
.equ	MS5,						M25 *5 / 1000				// Anzahl der Takte bei 25 MHz pro 5ms

.equ	MASK_BYTE_0,				0xff

.equ	ASCII_LF,					0x0a
.equ	ASCII_PLUS,					0x2b
.equ	ASCII_MINUS,				0x2d
.equ	ASCII_S,					0x73

.equ	MOD_NORMAL,					0
.equ	MOD_SW1,					1
.equ	MOD_SW2,					2

main:	
	bl		uart_init

/***************\
*               *
* Konfiguration *
*               *
\***************/

	// Takt für PORTA und PORTA aktivieren
	ldr		r0, =SIM_SCGC5
	ldr		r1, [r0]
	orr		r1, r1, #(1 << SIM_SCGC5_BIT_PORTA)
	orr		r1, r1, #(1 << SIM_SCGC5_BIT_PORTE)
	str		r1, [r0]
	
	// Takt für PIT aktivieren
	ldr		r0, =SIM_SCGC6
	ldr		r1, [r0]
	orr		r1, r1, #(1 << SIM_SCGC6_BIT_PIT)
	str		r1, [r0]

	// SW2 Interrupt Handler eintragen
	ldr		r0, =IRQ_VECTOR_SW2
	ldr		r1, =sw2_handler
	str		r1, [r0]

	// PIT1 Interrupt Handler eintragen
	ldr		r0, =pit1_handler
	ldr		r1, =IRQ_VECTOR_PIT1
	str		r0, [r1]

	// GPIO Data Direction konfigurieren
	// orr setzt das Bit auf Output
	// bic löscht es und konfiguriert damit für Input
	ldr		r1, =GPIOA_PDDR
	ldr		r0, [r1]
	orr		r0, r0, #(1 << E1_PIN)
	orr		r0, r0, #(1 << E2_PIN)
	orr		r0, r0, #(1 << E3_PIN)
	orr		r0, r0, #(1 << E4_PIN)
	bic		r0, r0, #(1 << SW1_PIN)
	str		r0, [r1]

	ldr		r1, =GPIOE_PDDR
	ldr		r0, [r1]
	bic		r0, r0, #(1 << SW2_PIN)
	str		r0, [r1]

	// GPIO Output löschen (notwendig um Aufleuchten zu vermeiden)
	ldr		r0, =GPIOA_PDOR
	ldr		r1, [r0]
	orr		r1, r1, #(1 << E1_PIN)
	orr		r1, r1, #(1 << E2_PIN)
	orr		r1, r1, #(1 << E3_PIN)
	orr		r1, r1, #(1 << E4_PIN)
	str		r1, [r0]

	// LEDs konfigurieren
	ldr		r1, =PORTA_LED_CFG
	ldr		r0, =PORTA_PCR10
	str		r1, [r0]
	ldr		r0, =PORTA_PCR11
	str		r1, [r0]
	ldr		r0, =PORTA_PCR28
	str		r1, [r0]
	ldr		r0, =PORTA_PCR29
	str		r1, [r0]

	// SW1 konfigurieren
	ldr		r0, =PORTA_PCR19
	ldr		r1, =PORTA_PCR19_CFG
	str		r1, [r0]

	// SW2 konfigurieren
	ldr		r0, =PORTE_PCR26
	ldr		r1, =PORTE_PCR26_CFG
	str		r1, [r0]

	// Pending Interrupt löschen und Interrupt aktivieren
	ldr		r0, =NVIC_ICPR2
	ldr		r1, =NVIC_ISER2
	mov		r2, #(1 << NVIC_SW2_BIT)
	str		r2, [r0]
	str		r2, [r1]
	mov		r2, #(1 << NVIC_PIT1_BIT)
	str		r2, [r0]
	str		r2, [r1]

	// PIT im Debug-Modus laufen lassen
	ldr		r0, =PIT_MCR
	mov		r1, #1					// An dieser Stelle kein Bit Banding
	str		r1, [r0]

	// 25000000 Takte === 1s eintragen
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =M25
	str		r1, [r0]

	// PIT1 Chain Mode deaktivieren, Interrupt aktivieren und starten
	mov		r0, #0
	ldr		r1, =PIT1_CHAIN_BB
	str		r0, [r1]
	mov		r0, #1
	ldr		r1, =PIT1_TIMER_BB
	str		r0, [r1]
	ldr		r1, =PIT1_INTERRUPT_BB
	str		r0, [r1]

	// Alle Interrupts aktivieren
	cpsie	i

/*************************************************\
*                                                 *
* Hauptschleife                                   *
*                                                 *
* ----------------------------------------------- *
* Funktionalität zusätzlich für Übersichtlichkeit *
* in Unterprogramme ausgelagert                   *
\*************************************************/

main_loop:
	// Da das UP für SW1 mit Polling arbeiten soll, muss
	// der Code möglichst oft laufen, dabei soll er jedoch
	// trotzdem nicht blockieren. Daher wird der Schalter am Anfang
	// jeder Hauptschleifen abgefragt.
	bl		check_sw1

	// Flags abfragen und abarbeiten
	bl		handle_sw1_pressed_flag
	bl		handle_sw2_pressed_flag

	// Abhängig vom gesetzten Modus Änderung vornehmen.
	// SW2 "überschreibt" dabei einen gültigen SW1 Knopfdruck.
	bl		handle_mod

	// Falls eine Sekunde vergangen ist Zaehler ausgeben
	ldr		r1, =second_flag
	ldr		r0, [r1]
	cmp		r0, #0
	beq		main_loop

	// Flag zurücksetzen
	mov		r0, #0
	str		r0, [r1]

	// Das Terminal "weiß", dass ein Zeichen gelesen wurde,
	// daher muss dieses nicht so oft abgefragt werden, wie die Knöpfe
	bl		check_terminal

	// Falls der Zähler nicht läuft wird der Rest übersprungen
	ldr		r0, =running_flag
	ldr		r0, [r0]
	cmp		r0, #0
	bne		main_loop

	// Ausgabe auf Terminal, der LEDs und Zähler auf nächsten Wert setzen
	bl		set_leds
	bl		print_counter
	bl		update_counter

	b		main_loop
	
/****************\
*                *
* Unterprogramme *
*                *
\****************/

.thumb_func
handle_mod:
	ldr		r0,	=mod
	ldr		r1, [r0]
	cmp 	r1, #MOD_NORMAL
	beq 	handle_mod__return

	cmp 	r1, #MOD_SW1
	bne		handle_mod__sw2

	// Zählerrichtung umkehren
	ldr		r2, =step
	ldr		r1, [r2]
	rsb		r1, r1, #0
	str		r1, [r2]

	b		handle_mod__reset

handle_mod__sw2:
	// Zähler starten/stoppen
	ldr		r2, =running_flag		// Das Flag wird negiert und wieder gespeichert
	ldr		r1, [r2]
	mvn		r1, r1
	str		r1, [r2]

handle_mod__reset:
	mov 	r1, #MOD_NORMAL
	str		r1, [r0]
handle_mod__return:
	bx		lr


.thumb_func
check_terminal:
	push	{lr}
	
	// Falls ein Zeichen empfangen wurde
	// muss es genauer überprüft werden
	bl		uart_charPresent
	cmp		r0, #0
	beq		check_terminal__return
	
	ldr		r0, =str_terminal_input
	bl		uart_putString
	
	// Zeichen holen
	bl		uart_getChar

	// Falls ein "s" eingegeben wurde
	// starten/stoppen, sonst nächster Vergleich
	cmp 	r0, #ASCII_S
	bne 	check_terminal__ascii_plus

	// Das Flag wird negiert und wieder gespeichert
	ldr		r2, =running_flag
	ldr		r1, [r2]
	mvn		r1, r1
	str		r1, [r2]

	b		check_terminal__output

check_terminal__ascii_plus:
	cmp		r0, #ASCII_PLUS
	bne		check_terminal__ascii_minus

	ldr		r2, =step
	mov		r1, #1
	str		r1, [r2]
	
	b		check_terminal__output

check_terminal__ascii_minus:
	cmp		r0, #ASCII_MINUS
	bne		check_terminal__output

	ldr		r2, =step
	mov		r1, #-1
	str		r1, [r2]

check_terminal__output:
	bl		uart_putChar
	mov		r0, #ASCII_LF
	bl		uart_putChar
check_terminal__return:
	pop		{pc}


.thumb_func
set_leds:
	ldr		r0, =count
	ldr		r0, [r0]
	ldr		r3, =GPIOA_PDOR
	ldr		r1, [r3]

	// Alle LEDs ausschalten
	orr		r1, r1, #(1 << E1_PIN)
	orr		r1, r1, #(1 << E2_PIN)
	orr		r1, r1, #(1 << E3_PIN)
	orr		r1, r1, #(1 << E4_PIN)

	// Zählerbits extrahieren und entsprechend LED anschalten
	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E1_PIN
	bic		r1, r1, r2

	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E2_PIN
	bic		r1, r1, r2

	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E3_PIN
	bic		r1, r1, r2

	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E4_PIN
	bic		r1, r1, r2

	str		r1, [r3]

	bx		lr


.thumb_func
print_counter:
	push	{lr}

	ldr		r0, =count
	ldr		r0, [r0]
	bl		uart_putByte
	mov		r0, #ASCII_LF
	bl		uart_putChar

	pop		{pc}


.thumb_func
update_counter:
	ldr		r0, =count
	ldr		r1, =step
	ldr		r1, [r1]
	ldr		r2, [r0]
	add		r1, r2, r1
	and		r1, r1, #MASK_BYTE_0		// Der Zähler soll nur 8 Bit haben,
	str		r1, [r0]					// daher "Überlauf" verhindern

	bx		lr


.thumb_func
handle_sw2_pressed_flag:
	push	{lr}

	// SW2 überprüfen, falls Flag nicht gesetzt, weiter
	ldr		r1, =sw2_pressed_flag
	ldr		r0, [r1]
	cmp		r0, #0
	beq		handle_sw2_pressed_flag__return

	// Ich bin mir an dieser Stelle nicht ganz sicher, wie 5ms "sicher"
	// bzw. exakt zu überprüfen sind. Dafür müsste eigentlich
	// ein weiterer Interrupt durch einen weiteren PIT genutzt werden.
	// Da die Abweichung von 5ms bei 25MHz durch diesen "einfachen"
	// Ansatz jedoch auch nur wenige Nanosekunden* beträgt,
	// bleibe ich für die Abfrage, ob 5ms vergangen sind, für beide Schalter beim Polling.

	// * Insgesamt werden überschaubar viele Zyklen für alle Vergleiche und Sprünge benötigt:
	// Das Programm hat insgesamt ca. 600 Zeilen.
	// Wenn jede Zeile einen Befehl enthalten würde, welcher jeweils 3 Zyklen
	// benötigt, so wäre die maximale Abweichung von 5ms, falls ein komplette
	// Schleife durchlaufen würde, nur knapp 72ns. Durch uart UP Aufrufe
	// wird diese eventuell noch länger.
	// Dabei handelt es sich jedoch um den schlechtesten Fall, tatsächlich sollte
	// die Abweichung eher geringer sein.

	// Aktuellen Zähler holen und mit Ziel vergleichen, dabei gilt:
	// falls Ziel >= Zähler (der Zähler läuft runter!),
	// dann sind mindestens 5ms vergangen sonst weiter
	ldr		r0, =PIT_CVAL1
	ldr		r0, [r0]
	ldr		r2, =sw2_pressed_time
	ldr		r2, [r2]
	subs	r0, r0, r2
	bhi		handle_sw2_pressed_flag__return

	// Ausgabe auf Terminal
	ldr		r0, =str_sw2_pressed
	bl		uart_putString

	// Modus speichern
	ldr		r1, =mod
	mov		r0, #MOD_SW2
	str		r0, [r1]

	// Button Flag zurücksetzen
	ldr		r1, =sw2_pressed_flag
	mov		r0, #0
	str		r0, [r1]

handle_sw2_pressed_flag__return:
	pop		{pc}


.thumb_func
handle_sw1_pressed_flag:
	push	{lr}
	// Funktion analog zu sw2

	// SW1 überprüfen, falls Flag nicht gesetzt, weiter
	ldr		r0, =sw1_pressed_flag
	ldr		r0, [r0]
	cmp		r0, #0
	beq		handle_sw2_pressed_flag__return

	// Aktuellen Zähler holen und mit Ziel vergleichen
	ldr		r0, =PIT_CVAL1
	ldr		r0, [r0]
	ldr		r1, =sw1_pressed_time
	ldr		r1, [r1]
	subs	r0, r0, r1
	bhi		handle_sw2_pressed_flag__return

	// Ausgabe auf Terminal
	ldr		r0, =str_sw1_pressed
	bl		uart_putString

	// Modus speichern
	ldr		r0, =mod
	mov		r1, #MOD_SW1
	str		r1, [r0]

	// Flag zurücksetzen
	ldr		r0, =sw1_pressed_flag
	mov		r1, #0
	str		r1, [r0]
	
	// Da der Status mit Polling abgefragt wird,
	// muss irgendwie unterschieden werden, ob ein gedrückter
	// Schalter bereits abgearbeitet wurde. Dafür wird hier ein
	// weiters Flag gesetzt, welches wiederum in der Abfrage UP 
	// für einen Abbruch sorgt, falls der Schalter weiter aktiv ist.
	// An dieser Stelle wird deutlich, dass die Abfrage über einen
	// Interrupt viel besser geeignet ist, um den Knopfdruck zu registrieren.
	// Falls nach 5ms kein neuer Interrupt vorliegt und das Signal weiter anliegt,
	// ist der Knopfdruck gültig.
	ldr		r0, =sw1_handled_flag
	mov		r1, #1
	str		r1, [r0]

handle_sw1_pressed_flag__return:
	pop		{pc}


.thumb_func
check_sw1:
	// Überprüfen, ob der Knopf bereits als gedrückt markiert wurde
	ldr		r0, =sw1_pressed_flag
	ldr		r0, [r0]
	cmp		r0, #0
	bne		check_sw1__return

	// Falls der Knopf immernoch gedrückt ist,
	// sollte kein neuer Knopfdruck registriert werden.
	// Daher muss überprüft werden, ob zuvor ein Knopfdruck abgearbeitet
	// wurde.
	ldr		r0, =sw1_handled_flag
	ldr		r0, [r0]
	cmp		r0, #0
	beq		check_sw1__not_handled_before

	// Zuvor wurde ein Knopfdruck abgearbeitet,
	// jetzt nachsehen, wie der derzeitige Pegel ist.
	// Falls weiter ein Signal anliegt, darf kein neues button_flag gesetzt werden.
	ldr		r0, =GPIOA_PDIR
	ldr		r0, [r0]
	mvn		r0, r0
	and		r0, r0, #(1 << SW1_PIN)
	cmp		r0, #0
	bne		check_sw1__return

	// Falls aktuell nicht gedrückt, aber bereits abgearbeitet,
	// daher zurücksetzen und in der nächsten Schleife wieder prüfen
	ldr		r0, =sw1_handled_flag
	mov		r1, #0
	str		r1, [r0]
	b		check_sw1__return

check_sw1__not_handled_before:
	// Pin Wert auslesen
	ldr		r0, =GPIOA_PDIR
	ldr		r0, [r0]
	mvn		r0, r0
	and		r0, r0, #(1 << SW1_PIN)
	cmp		r0, #0
	beq		check_sw1__return

	// Flag setzen
	ldr		r0, =sw1_pressed_flag
	mov		r1, #1
	str		r1, [r0]

	// Zielzeitpunkt (also +5ms) für Vergleich im Hauptprogramm eintragen.
	ldr		r0, =PIT_CVAL1
	ldr		r1, [r0]
	ldr		r0, =#MS5
	sub		r1, r1, r0
	ldr		r0, =sw1_pressed_time
	str		r1, [r0]
	
check_sw1__return:
	bx		lr


.thumb_func
pit1_handler:
	// Interrupt-Flag löschen und
	// Benutzer-Flag setzen
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	ldr		r1, =second_flag
	str		r0, [r1]

	bx		lr


.thumb_func
sw2_handler:
	// Interrupt Flag löschen
	ldr		r0, =PORTE_PCR26
	ldr		r1, [r0]
	orr		r1, r1, #(1 << PORT_BIT_ISF)
	str		r1, [r0]
	
	// Button Flag setzen
	ldr		r0, =sw2_pressed_flag
	mov		r1, #1
	str		r1, [r0]
	
	// Zielzeitpunkt eintragen
	ldr		r0, =PIT_CVAL1
	ldr		r1, [r0]
	ldr		r0, =#MS5
	sub		r1, r1, r0
	ldr		r0, =sw2_pressed_time
	str		r1, [r0]
	
	bx		lr


/*** Datenbereich (ab 0x20000000) ***/
.data
second_flag:		.word	0
running_flag:		.word	0
sw1_pressed_flag:	.word	0
sw1_handled_flag:	.word	0
sw1_pressed_time:	.word	0
sw2_pressed_flag:	.word	0
sw2_pressed_time:	.word	0
count:				.word	0
step:				.word	1
mod:				.word	0
str_sw1_pressed:	.asciz	"SW1 gedrueckt!\n"
str_sw2_pressed:	.asciz	"SW2 gedrueckt!\n"
str_terminal_input:	.asciz	"Eingabe auf Terminal: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Die Quellenangaben und Beschreibungen helfen mir dabei, um bei eventuellenen Problemen die
// entsprechenden Stellen im Handbuch oder im Skript schnell finden zu können.
// Die Beschreibung der Konstanten erfolgt soweit sinnvoll möglich und notwendig über der Konstanten.
//
// Teilweise sind einzelne Konstanten auskommentiert. Diese wurden dann nicht benutzt und sind nur
// für die vollständige Übersicht über die Themenbereiche weiter enthalten. Zusätzlich kann
// davon ausgegangen werden, dass auskommentierte Bit-Konstanten während der Konfiguration implizit,
// z.B. durch das Laden einer Makse, auf "0" gesetzt werden.

.equ	SIM_SCGC3,					0x40048030					// Quelle: S.302 Handbuch
.equ	SIM_SCGC3_BIT_ADC1,			27							// Quelle: S.302 Handbuch
.equ	SIM_SCGC5,					0x40048038					// Quelle: S.306 Handbuch
.equ	SIM_SCGC5_BIT_PORTA,		9							// Quelle: S.306 Handbuch
.equ	SIM_SCGC6,					0x4004803c					// Quelle: S.308 Handbuch
.equ	SIM_SCGC6_BIT_PIT,			23							// Quelle: S.308 Handbuch

__BBREG	SIM3_ADC1,	SIM_SCGC3, SIM_SCGC3_BIT_ADC1
__BBREG	SIM5_PORTA,	SIM_SCGC5, SIM_SCGC5_BIT_PORTA
__BBREG	SIM6_PIT,	SIM_SCGC6, SIM_SCGC6_BIT_PIT

.equ	NVIC_ISER_BASE,				0xe000e100					// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ISER2,					NVIC_ISER_BASE + 0x8		// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ICPR_BASE,				0xe000e280					// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ICPR2,					NVIC_ICPR_BASE + 0x8		// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual

.equ	PIT_MCR,					0x40037000					// Quelle: S.1077 Handbuch

.equ	PIT1_BASE,					0x40037110					// Quelle: S.1077 Handbuch
.equ	PIT_LDVAL1,					PIT1_BASE + 0x0				// Quelle: S.1077 Handbuch
.equ	PIT_CVAL1,					PIT1_BASE + 0x4				// Quelle: S.1077 Handbuch
.equ	PIT_TCTRL1,					PIT1_BASE + 0x8				// Quelle: S.1077 Handbuch
.equ	PIT_TFLG1,					PIT1_BASE + 0xc				// Quelle: S.1077 Handbuch

// PIT_TCTRL Register Felder
.equ	PIT_CHN,					2							// Quelle: S.1080 Handbuch
.equ	PIT_TIE,					1							// Quelle: S.1080 Handbuch
.equ	PIT_TEN,					0							// Quelle: S.1080 Handbuch

.equ	PIT1_IRQ,					69							// Quelle: S.78 Handbuch
.equ	PIT1_IRQ_OFFSET,			0x00000154					// Quelle: S.78 Handbuch

.equ	NVIC_PIT1_BIT,				PIT1_IRQ % 32

.equ	IRQ_VECTOR_TABLE_BASE,		0x1ffffe00					// Quelle: Skript
.equ	IRQ_VECTOR_PIT1,			IRQ_VECTOR_TABLE_BASE + PIT1_IRQ_OFFSET

// Anzahl der Takte bei 25 MHz pro Sekunde
.equ	M25,						25000000

.equ	GPIOA_PDOR,					0x400FF000					// Quelle: S.1743 Handbuch
.equ	GPIOA_PDDR,					0x400FF014					// Quelle: S.1743 Handbuch

.equ	PORTA_PCR10,				0x40049028					// Quelle: S.272 Handbuch
.equ	PORTA_PCR11,				0x4004902C					// Quelle: S.272 Handbuch
.equ	PORTA_PCR28,				0x40049070					// Quelle: S.272 Handbuch
.equ	PORTA_PCR29,				0x40049074					// Quelle: S.272 Handbuch

// Konfiguration jeweils als GPIO
// (Pin Mux Control Alternative 1), Open-Drain
.equ	PORTA_LED_CFG,				0x00000120					// Quelle: S.277ff Handbuch

.equ	E1_PIN,						11							// Quelle: Schaltplan
.equ	E2_PIN,						28							// Quelle: Schaltplan
.equ	E3_PIN,						29							// Quelle: Schaltplan
.equ	E4_PIN,						10							// Quelle: Schaltplan

.equ	ADC1_SC1A,					0x400BB000					// ADC Status and Control
//.equ	ADC1_SC1B,					0x400BB004					// ADC Status and Control
.equ	ADC1_CFG1,					0x400BB008					// ADC Configuration
.equ	ADC1_CFG2,					0x400BB00C					// ADC Configuration
.equ	ADC1_RA,					0x400BB010					// ADC Data
//.equ	ADC1_RB,					0x400BB014					// ADC Data
//.equ	ADC1_CV1,					0x400BB018					// Compare Value
//.equ	ADC1_CV2,					0x400BB01C					// Compare Value
.equ	ADC1_SC2,					0x400BB020					// Status and Control
.equ	ADC1_SC3,					0x400BB024					// Status and Control
//.equ	ADC1_OFS,					0x400BB028					// ADC Offset Correction
.equ	ADC1_PG,					0x400BB02C					// ADC Plus-Side Gain
.equ	ADC1_MG,					0x400BB030					// ADC Minus-Side Gain
//.equ	ADC1_CLPD,					0x400BB034					// ADC Plus-Side General Calibration Value
.equ	ADC1_CLPS,					0x400BB038					// ADC Plus-Side General Calibration Value
.equ	ADC1_CLP4,					0x400BB03C					// ADC Plus-Side General Calibration Value
.equ	ADC1_CLP3,					0x400BB040					// ADC Plus-Side General Calibration Value
.equ	ADC1_CLP2,					0x400BB044					// ADC Plus-Side General Calibration Value
.equ	ADC1_CLP1,					0x400BB048					// ADC Plus-Side General Calibration Value
.equ	ADC1_CLP0,					0x400BB04C					// ADC Plus-Side General Calibration Value
//.equ	ADC1_PGA,					0x400BB050					// ADC PGA
//.equ	ADC1_CLMD,					0x400BB054					// ADC Minus-Side General Calibration Value
.equ	ADC1_CLMS,					0x400BB058					// ADC Minus-Side General Calibration Value
.equ	ADC1_CLM4,					0x400BB05C					// ADC Minus-Side General Calibration Value
.equ	ADC1_CLM3,					0x400BB060					// ADC Minus-Side General Calibration Value
.equ	ADC1_CLM2,					0x400BB064					// ADC Minus-Side General Calibration Value
.equ	ADC1_CLM1,					0x400BB068					// ADC Minus-Side General Calibration Value
.equ	ADC1_CLM0,					0x400BB06C					// ADC Minus-Side General Calibration Value

//.equ	ADCx_SC1n_BIT_COCO,			7							// Conversion Complete Flag
//.equ	ADCx_SC1n_BIT_AIEN,			6							// Interrupt Enable
//.equ	ADCx_SC1n_BIT_DIFF,			5							// Differential Mode 0 = single, 1 = diff
.equ	ADCx_SC1n_BIT_ADCH4,		4							// Input Channel select S.828
.equ	ADCx_SC1n_BIT_ADCH3,		3							// 11111 = disabled
.equ	ADCx_SC1n_BIT_ADCH2,		2
.equ	ADCx_SC1n_BIT_ADCH1,		1
.equ	ADCx_SC1n_BIT_ADCH0,		0

//.equ	ADCx_CFG1_BIT_ADLPC,		7							// Low Power 0 = normal
.equ	ADCx_CFG1_BIT_ADIV1,		6							// Clock Devide 
.equ	ADCx_CFG1_BIT_ADIV0,		5							// 00 = 1, 01 = 2, 10 = 4, 11 = 8
//.equ	ADCx_CFG1_BIT_ADLSMP,		4							// Sample Time 0 = short, 1 = long
.equ	ADCx_CFG1_BIT_MODE1,		3							// Conversion Mode
.equ	ADCx_CFG1_BIT_MODE0,		2							// 00 (d = 0) single ended 8, 9 bit 2's, 01 12/13, 10 10/11, 11 16/16
//.equ	ADCx_CFG1_BIT_ADICLK1,		1							// Input Clock Select
//.equ	ADCx_CFG1_BIT_ADICLK0,		0							// 00 Bus, 01 Bus/2, 10 ATLCLK, 11 ADACK

//.equ	ADCx_CFG2_BIT_MUXSEL,		4							// ADC Mux Select 0 = ADxxa, 1 = ADxxb
//.equ	ADCx_CFG2_BIT_ADACKEN,		3							// Asynchronous Clock Output Enable 0 = disabled
//.equ	ADCx_CFG2_BIT_ADHSC,		2							// High-Speed Configuration 0 = normal
//.equ	ADCx_CFG2_BIT_ADLSTS1,		1							// Long Sample Time Select
//.equ	ADCx_CFG2_BIT_ADLSTS0,		0							// 00 = default

//.equ	ADCx_SC2_BIT_ADACT,			7							// Conversion Active
//.equ	ADCx_SC2_BIT_ADTRG,			6							// Conversion Trigger Select 0 = software, 1 = hardware
//.equ	ADCx_SC2_BIT_ACFE,			5							// Compare Function Enable 0 = disabled
//.equ	ADCx_SC2_BIT_ACFGT,			4							// CF Greater Than Enable
//.equ	ADCx_SC2_BIT_ACREN,			3							// CF		range Enable
//.equ	ADCx_SC2_BIT_DMAEN,			2							// DMA Enable
//.equ	ADCx_SC2_BIT_REFSEL1,		1							// Voltage		reference
//.equ	ADCx_SC2_BIT_REFSEL0,		0							// 00 = default, 01 = alternate

.equ	ADCx_SC3_BIT_CAL,			7							// Calibration - stays set, gets cleared!
//.equ	ADCx_SC3_BIT_CALF,			6							// READ_ONLY Calibration Failed Flag
.equ	ADCx_SC3_BIT_ADCO,			3							// Continuous Conversion Enable
.equ	ADCx_SC3_BIT_AVGE,			2							// Hardware Average Enable
.equ	ADCx_SC3_BIT_AVGS1,			1							// Average Select
.equ	ADCx_SC3_BIT_AVGS0,			0							// 00 = 4, 01 = 8, 10 = 16, 11 = 32

// Für Konfiguration nicht benötigte PGA Bits
/*
.equ	ADCx_PGA_BIT_PGAEN,			23
.equ	ADCx_PGA_BIT_PGALPb,		20
.equ	ADCx_PGA_BIT_PGAG3,			19
.equ	ADCx_PGA_BIT_PGAG2,			18
.equ	ADCx_PGA_BIT_PGAG1,			17
.equ	ADCx_PGA_BIT_PGAG0,			16
*/

.equ	ASCII_LF,					0x0a
.equ	ASCII_S,					0x73
.equ	ASCII_X,					0x78
.equ	ASCII_0,					0x30
.equ	ASCII_1,					0x31
.equ	ASCII_2,					0x32
.equ	ASCII_3,					0x33

// Interne Mode Nummerierung, entspricht der Nummerierung im ADCx_SC3 Register
.equ	MODE_16,					0x3
.equ	MODE_12,					0x1
.equ	MODE_10,					0x2
.equ	MODE_08,					0x0

// Konfigurationsmasken
.equ	MASK_LED_ALL,				(1 << E1_PIN | 1 << E2_PIN | 1 << E3_PIN | 1 << E4_PIN)
.equ	MASK_ADCH_INACTIVE,			(1 << ADCx_SC1n_BIT_ADCH4 | 1 << ADCx_SC1n_BIT_ADCH3 | 1 << ADCx_SC1n_BIT_ADCH2 | 1 << ADCx_SC1n_BIT_ADCH1 | 1 << ADCx_SC1n_BIT_ADCH0)
.equ	MASK_ADCH_ACTIVE,			(1 << ADCx_SC1n_BIT_ADCH4 | 1 << ADCx_SC1n_BIT_ADCH2)
.equ	MASK_ADC_CFG1_MODE16,		(1 << ADCx_CFG1_BIT_ADIV1 | 1 << ADCx_CFG1_BIT_ADIV0 | 1 << ADCx_CFG1_BIT_MODE1 | 1 << ADCx_CFG1_BIT_MODE0)
.equ	MASK_ADC_CFG1_MODE12,		(1 << ADCx_CFG1_BIT_ADIV1 | 1 << ADCx_CFG1_BIT_ADIV0 | 1 << ADCx_CFG1_BIT_MODE0)
.equ	MASK_ADC_CFG1_MODE10,		(1 << ADCx_CFG1_BIT_ADIV1 | 1 << ADCx_CFG1_BIT_ADIV0 | 1 << ADCx_CFG1_BIT_MODE1)
.equ	MASK_ADC_CFG1_MODE08,		(1 << ADCx_CFG1_BIT_ADIV1 | 1 << ADCx_CFG1_BIT_ADIV0)
.equ	MASK_ADC_SC3,				(1 << ADCx_SC3_BIT_ADCO | 1 << ADCx_SC3_BIT_AVGE | 1 << ADCx_SC3_BIT_AVGS1 | 1 << ADCx_SC3_BIT_CAL)
.equ	MASK_PIT1,					(1 << PIT_TIE | 1 << PIT_TEN)

main:
	bl uart_init

/***************\
*               *
* Konfiguration *
*               *
\***************/

	// Initialisier ein Array der verschiedenen Ausgabestrings. Diese
	// müssen sich an Modus und Stufe anpassen. Beim Starten des Programms
	// werden die Adressen der Strings eingelesen und in einer "Matrix" gespeichert,
	// sodass ihre Startadressen zur Ausgabe "einfach"
	// über string_array[($MODE << 6) + ($LEVEL << 2)] ausgelesen werden können
	bl		index_strings

	mov r1, #1 

	// Takt fuer die benutzten Module aktivieren
	ldr r0, =SIM3_ADC1
	str r1, [r0]
	ldr r0, =SIM5_PORTA
	str r1, [r0]
	ldr r0, =SIM6_PIT
	str r1, [r0]

	// PIT1 Interrupt Handler eintragen
	ldr		r0, =pit1_handler
	ldr		r1, =IRQ_VECTOR_PIT1
	str		r0, [r1]

	// Pending Interrupt löschen und Interrupt aktivieren
	ldr		r0, =NVIC_ICPR2
	ldr		r1, =NVIC_ISER2
	mov		r2, #(1 << NVIC_PIT1_BIT)
	str		r2, [r0]
	str		r2, [r1]

	// PIT im Debug-Modus laufen lassen
	ldr		r0, =PIT_MCR
	mov		r1, #1
	str		r1, [r0]

	// 25000000 Takte === 1s eintragen
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =M25
	str		r1, [r0]

	// GPIO Data Direction konfigurieren
	ldr		r1, =GPIOA_PDDR
	ldr		r0, =MASK_LED_ALL
	str		r0, [r1]

	// zusätzlich GPIO Output löschen (notwendig um Aufleuchten zu vermeiden)
	// Obwohl in diesem Programm andere GPIO nicht benutzt werden, scheint es mir
	// an dieser Stelle "richtiger", nur die tatsächlich benutzten anzusprechen,
	ldr		r2, =GPIOA_PDOR
	ldr		r1, [r2]
	orr		r1, r1, r0
	str		r1, [r2]

	// LEDs konfigurieren
	ldr		r1, =PORTA_LED_CFG
	ldr		r0, =PORTA_PCR10
	str		r1, [r0]
	ldr		r0, =PORTA_PCR11
	str		r1, [r0]
	ldr		r0, =PORTA_PCR28
	str		r1, [r0]
	ldr		r0, =PORTA_PCR29
	str		r1, [r0]

	// Nun zunächst ADC1 deaktiviert konfigurieren und kalibrieren

	// Zurücksetzen und Deaktivieren des ADC1
	// Konfiguration nach Aufgabenstellung:
	// * Kein Interrupt (AIEN=0)
	// * Single-Ended (DIFF=0)
	// * deakiviert (ADCH)
	ldr		r0, =ADC1_SC1A
	ldr		r1, =MASK_ADCH_INACTIVE
	str		r1, [r0]

	// * Normal Power
	// * Clock Divide 1/8 (25 MHz / 8 = 3,125 MHz)
	// * Short Sample Time (ADLSMP)
	// * 16 Bit Mode
	// * Bus Clock
	ldr		r0, =ADC1_CFG1
	ldr		r1, =MASK_ADC_CFG1_MODE16
	str		r1, [r0]

	mov		r1, #0

	// * ADxxa selected
	// * ADACKEN, ADHSC, ADLSTS default
	ldr		r0, =ADC1_CFG2
	str		r1, [r0]

	// * Software Triggger
	// * keine Compare Function
	// * kein DMA
	// * default Voltage reference
	ldr		r0, =ADC1_SC2
	str		r1, [r0]

	// * Continuous Conversion Enabled
	// * Hardware Average Enabled
	// * Hardware Average Select = 16
	// * Kalibrierung sofort starten (im Handbuch steht nicht, dass dieser
	//   Schritt einzeln ausgeführt werden muss. Da das CALF Bit auch nicht
	//   gesetzt wird, scheint dieses Vorgehen so auch richtig zu funktionieren.)
	ldr		r0, =ADC1_SC3
	ldr		r1, =MASK_ADC_SC3
	str		r1, [r0]

	// Kalibrierungsbit lesen und auswerten bis Kalibrierung abgeschlossen
	// Laut Handbuch wird das Cal Bit zurückgesetzt, wenn die Kalibrierung beendet wurde.
	// Alternativ könnte auch COCO gelesen werden. Gibt es einen funktionalen Unterschied?
	mov		r2, #0
check_cal_bit:
	add		r2, r2, #1
	ldr		r1, [r0]
	tst		r1, #(1 << ADCx_SC3_BIT_CAL)
	beq		check_cal_bit

	// Laut Handbuch müsste an dieser Stelle
	// das CALF Bit überprüft werden. Da die Aufgabe
	// jedoch keine Anweisungen bezüglich eines möglichen
	// Fehlers enthält, wird dieser Schritt übersprungen...
	//
	// Eine manuelle Überprüfung per Breakpoint zeigt, dass das Bit nicht
	// gesetzt wird.

	// "gain calibration values" nach Prozedur im Handbuch bestimmen.
	// Zunächst plus-side gain...
	mov		r1, #0
	ldr		r0, =ADC1_CLP0
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLP1
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLP2
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLP3
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLP4
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLPS
	ldr		r0, [r0]
	add		r1, r1, r0
	lsr		r1, r1, #1
	orr		r1, r1, #0x8000	// "Set the MSB of the variable." == Most Significant Bit?
	ldr		r0, =ADC1_PG	// Da der zu schreibende Wert 16 Bit hat, ist damit Bit 15  gemeint.
	str		r1, [r0]

	// ...dann minus-side gain
	mov		r1, #0
	ldr		r0, =ADC1_CLM0
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLM1
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLM2
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLM3
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLM4
	ldr		r0, [r0]
	add		r1, r1, r0
	ldr		r0, =ADC1_CLMS
	ldr		r0, [r0]
	add		r1, r1, r0
	lsr		r1, r1, #1
	orr		r1, r1, #0x8000	// MSB wie oben
	ldr		r0, =ADC1_MG
	str		r1, [r0]

	// ADC1 starten, dafür entsprechend ADC1_DM1 (Schaltplan) bzw.
	// AD20 (S.123 Handbuch) konfigurieren
	ldr		r0, =ADC1_SC1A
	ldr		r1, =MASK_ADCH_ACTIVE
	str		r1, [r0]

	// PIT1 Chain Mode deaktivieren, Interrupt aktivieren und starten
	ldr		r1, =PIT_TCTRL1
	ldr		r0, =MASK_PIT1
	str		r0, [r1]

/*************************************************\
*                                                 *
* Hauptschleife                                   *
*                                                 *
\*************************************************/

	ldr		r4, =ADC1_RA
	ldr		r6, =second_flag
	ldr		r7, =compare_16bit_values

main_loop:
	// Falls eine Sekunde vergangen ist, Terminal prüfen
	ldr		r0, [r6]
	cmp		r0, #0
	beq		main_loop

	// Flag zurücksetzen
	mov		r0, #0
	str		r0, [r6]

	// Falls gestoppt, LEDs nicht setzen
	// und stattdessen direkt zur Eingabeprüfung springen
	ldr		r0, =running_flag
	ldr		r0, [r0]
	cmp		r0, #0
	bne		main_loop__check_terminal

	bl		get_compare_array_address
	ldr		r5, [r4]
	mov		r1, r5
	bl		compare_bits // r0 enthält Arrayadresse, r1 den Samplewert
	ldr		r1, =level
	str		r0, [r1]
	bl		set_leds

	// Terminalausgabe
	mov		r0, #ASCII_0
	bl		uart_putChar
	mov		r0, #ASCII_X
	bl		uart_putChar
	mov		r0, r5
	bl		uart_putInt16
	bl		get_output_string_address
	bl		uart_putString

main_loop__check_terminal:
	// Eingabe überprüfen und gegebenenenfalls Konfiguration anpassen
	bl		check_terminal

	b		main_loop

/****************\
*                *
* Unterprogramme *
*                *
\****************/

.thumb_func
pit1_handler:
	// Interrupt-Flag löschen und
	// Benutzer-Flag setzen
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	ldr		r1, =second_flag
	str		r0, [r1]

	bx		lr

.thumb_func
check_terminal:
	push	{lr}

	// Falls ein Zeichen empfangen wurde
	// muss es genauer überprüft werden
	bl		uart_charPresent
	cmp		r0, #0
	beq		check_terminal__return

	// Zeichen holen
	bl		uart_getChar

	// Falls ein "s" eingegeben wurde
	// starten/stoppen, sonst nächster Vergleich
	cmp 	r0, #ASCII_S
	bne 	check_terminal__precision_ASCII_0

	// Das Flag wird negiert und wieder gespeichert
	ldr		r2, =running_flag
	ldr		r1, [r2]
	mvn		r1, r1
	str		r1, [r2]

	// Ausgabe auf dem Terminal entsprechend start/stop
	cmp		r1, #0
	ite eq
	ldreq	r0, =str_start
	ldrne	r0, =str_stop
	bl		uart_putString

	// Konvertierung starten/stoppen
	ldr		r0, =ADC1_SC1A
	ldr		r1, [r0]
	ldr		r2, =MASK_ADCH_ACTIVE
	eor		r1, r1, r2
	str		r1, [r0]

	b		check_terminal__return

check_terminal__precision_ASCII_0:
	// Falls nicht gestoppt, wird 0, 1, 2, 3 ebenfalls ignoriert!
	ldr		r1, =running_flag
	ldr		r1, [r1]
	cmp		r1, #0
	beq		check_terminal__return

	// Auf Modus 8 Bit setzen falls gestoppt und 0 eingegeben wurde,
	// sonst weiter
	cmp		r0, #ASCII_0
	bne		check_terminal__precision_ASCII_1
	ldr		r0, =current_mode
	mov		r1, #MODE_08
	str		r1, [r0]
	ldr		r0, =ADC1_CFG1
	ldr		r1, =MASK_ADC_CFG1_MODE08
	str		r1, [r0]

	// Ausgabe auf Terminal
	ldr		r0, =str_changed_mode_08
	bl		uart_putString

	b		check_terminal__return

check_terminal__precision_ASCII_1:

	// Auf Modus 10 Bit setzen falls gestoppt und 1 eingegeben wurde,
	// sonst weiter
	cmp		r0, #ASCII_1
	bne		check_terminal__precision_ASCII_2
	ldr		r0, =current_mode
	mov		r1, #MODE_10
	str		r1, [r0]
	ldr		r0, =ADC1_CFG1
	ldr		r1, =MASK_ADC_CFG1_MODE10
	str		r1, [r0]

	// Ausgabe auf Terminal
	ldr		r0, =str_changed_mode_10
	bl		uart_putString

	b		check_terminal__return

check_terminal__precision_ASCII_2:

	// Auf Modus 12 Bit setzen falls gestoppt und 2 eingegeben wurde
	// sonst weiter
	cmp		r0, #ASCII_2
	bne		check_terminal__precision_ASCII_3
	ldr		r0, =current_mode
	mov		r1, #MODE_12
	str		r1, [r0]
	ldr		r0, =ADC1_CFG1
	mov		r1, #0
	ldr		r1, =MASK_ADC_CFG1_MODE12
	str		r1, [r0]

	// Ausgabe auf Terminal
	ldr		r0, =str_changed_mode_12
	bl		uart_putString

	b		check_terminal__return

check_terminal__precision_ASCII_3:

	// Auf Modus 16 Bit setzen falls gestoppt und 3 eingegeben wurde,
	// sonst weiter
	cmp		r0, #ASCII_3
	bne		check_terminal__return

	ldr		r0, =current_mode
	mov		r1, #MODE_16
	str		r1, [r0]
	ldr		r0, =ADC1_CFG1
	ldr		r1, =MASK_ADC_CFG1_MODE16
	str		r1, [r0]

	// Ausgabe auf Terminal
	ldr		r0, =str_changed_mode_16
	bl		uart_putString

check_terminal__return:
	pop		{pc}

.thumb_func
get_compare_array_address:
	ldr		r0, =current_mode
	ldr		r0, [r0]

	cmp		r0, #MODE_08
	itt eq
	ldreq	r0, =compare_8bit_values
	beq		get_compare_array_address__return

	cmp		r0, #MODE_10
	itt eq
	ldreq	r0, =compare_10bit_values
	beq		get_compare_array_address__return

	cmp		r0, #MODE_12
	itt eq
	ldreq	r0, =compare_12bit_values
	beq		get_compare_array_address__return

	ldr		r0, =compare_16bit_values

get_compare_array_address__return:
	bx		lr

// Berechnet anhand von Modus und Stufe einen Offset,
// welcher im string_addresses Array nach Indizierung am Anfang des Programms
// die Adresse des richtigen, auszugebenden Strings enthält.
// Da meine einzige alternativ Implementierung eine lange Liste von Vergleichen
// enthielt, habe ich diesen "übersichtlicheren" Weg gewählt. 
.thumb_func
get_output_string_address:
	ldr		r0, =current_mode
	ldr		r0, [r0]
	ldr		r1, =level
	ldr		r1, [r1]
	ldr		r2, =string_addresses

	lsl		r0, r0, #6 // Multiplikation 64, entspricht Zugriff auf Zeile der Matrix
	lsl		r1, r1, #2 // Multiplikation 4, entspricht Zugriff auf Reihe der Matrix

	// Startaddresse und die beiden Offsets addieren
	add		r0, r0, r1
	add		r0, r0, r2

	// Adresse des Strings aus dem Array laden und zurückgeben.
	ldr		r0, [r0]

	bx		lr

// IN	r0: Adresse des Vergleichsarrays, r1: Samplewert
// OUT	r0: Stufe
.thumb_func
compare_bits:

	mov		r2, #0
	// Solange durch das Vergleichsarraylaufen, bis der "Nullterminator" des Arrays erreicht wird
compare_bits__loop:
	ldr		r3, [r0], #4
	cmp		r3, #0
	beq		compare_bits__return

	// Falls der aktuelle Samplewert kleiner als der Vergleichswert ist,
	// wurde die richtige Stufe gefunden
	cmp		r1, r3
	blo		compare_bits__return
	add		r2, r2, #1
	b		compare_bits__loop

compare_bits__return:
	//
	mov		r0, r2
	bx		lr

// IN	r0: 4-Bit Zählerwert
.thumb_func
set_leds:
	ldr		r3, =GPIOA_PDOR
	ldr		r1, [r3]

	// Alle LEDs ausschalten
	ldr		r2, =MASK_LED_ALL
	orr		r1, r1, r2

	// Zählerbits extrahieren und entsprechend LED anschalten
	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E1_PIN
	bic		r1, r1, r2

	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E2_PIN
	bic		r1, r1, r2

	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E3_PIN
	bic		r1, r1, r2

	and		r2, r0, #1
	lsr		r0, r0, #1
	lsl		r2, r2, #E4_PIN
	bic		r1, r1, r2

	str		r1, [r3]

	bx		lr

// Hilfsfunktion um die verschiedenen Strings über eine Matrix adressierbar
// zu machen. Gibt es eine bessere Möglichkeit? Ist das auch mit einer Schleife möglich?
// Gibt es andere Wege, um auf die Adressen der Strings indiziert zugreifen zu können?
.thumb_func
index_strings:
	ldr		r1, =string_addresses
	ldr		r0, =str_mode_08_00
	str		r0, [r1], #4
	ldr		r0, =str_mode_08_01
	str		r0, [r1], #4
	ldr		r0, =str_mode_08_02
	str		r0, [r1], #4
	ldr		r0, =str_mode_08_03
	str		r0, [r1], #4
	ldr		r0, =str_mode_08_04
	str		r0, [r1], #4
	ldr		r0, =str_mode_08_05
	str		r0, [r1], #4
	ldr		r0, =str_mode_08_06
	str		r0, [r1], #4
	ldr		r0, =str_mode_08_07
	str		r0, [r1], #4

	ldr		r1, =string_addresses
	add		r1, r1, #128
	ldr		r0, =str_mode_10_00
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_01
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_02
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_03
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_04
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_05
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_06
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_07
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_08
	str		r0, [r1], #4
	ldr		r0, =str_mode_10_09
	str		r0, [r1], #4

	ldr		r1, =string_addresses
	add		r1, r1, #64
	ldr		r0, =str_mode_12_00
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_01
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_02
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_03
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_04
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_05
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_06
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_07
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_08
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_09
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_10
	str		r0, [r1], #4
	ldr		r0, =str_mode_12_11
	str		r0, [r1], #4

	ldr		r1, =string_addresses
	add		r1, r1, #192
	ldr		r0, =str_mode_16_00
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_01
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_02
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_03
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_04
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_05
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_06
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_07
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_08
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_09
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_10
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_11
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_12
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_13
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_14
	str		r0, [r1], #4
	ldr		r0, =str_mode_16_15
	str		r0, [r1], #4

	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
running_flag:			.word	0
second_flag:			.word	0
level:					.word	0
current_mode:			.word	0x3 // entspricht Startwert 16 Bit
// Die Werte der Vergleichsarrays, sowie der Ausgabelevel Strings, wurden
// händisch bestimmt und dabei teilweise gerundet. Dadurch entstehen geringe 
// Fehler und Abweichungen von der idealen Verteilung.
// Laut Schaltplan liegt am Poti eine Sollspannung von 3,3 V an, auf Grundlage
// dieser wurden die Werte gewählt.
//
// Die Vergleichsarrays enden jeweils mit einem 0-Wort als Terminator, dadurch
// kann leicht über sie iteriert werden, ohne dass die genaue Länge bekannt ist.
compare_8bit_values:	.word	0x20, 0x40, 0x60, 0x80, 0xa0, 0xc0, 0xe0, 0x00
compare_10bit_values:	.word	0x066, 0x0cc, 0x133, 0x199, 0x200, 0x266, 0x2cc, 0x333, 0x399, 0x000
compare_12bit_values:	.word	0x155, 0x2aa, 0x400, 0x555, 0x6aa, 0x800, 0x955, 0xaaa, 0xc00, 0xd55, 0xeaa, 0x000
compare_16bit_values:	.word	0x1000, 0x2000, 0x3000, 0x4000, 0x5000, 0x6000, 0x7000, 0x8000, 0x9000, 0xa000, 0xb000, 0xc000, 0xd000, 0xe000, 0xf000, 0x0000
str_stop:				.asciz	"Konvertierung gestoppt\n"
str_start:				.asciz	"Konvertierung gestartet\n"
str_changed_mode_08:	.asciz	"8 Bit Genauigkeit eingestellt\n"
str_changed_mode_10:	.asciz	"10 Bit Genauigkeit eingestellt\n"
str_changed_mode_12:	.asciz	"12 Bit Genauigkeit eingestellt\n"
str_changed_mode_16:	.asciz	"16 Bit Genauigkeit eingestellt\n"
str_mode_08_00:			.asciz	" 0 -  412 mV (Stufe 0)\n"
str_mode_08_01:			.asciz	" 413 -  825 mV (Stufe 1)\n"
str_mode_08_02:			.asciz	" 826 - 1237 mV (Stufe 2)\n"
str_mode_08_03:			.asciz	" 1238 - 1650 mV (Stufe 3)\n"
str_mode_08_04:			.asciz	" 1651 - 2062 mV (Stufe 4)\n"
str_mode_08_05:			.asciz	" 2063 - 2475 mV (Stufe 5)\n"
str_mode_08_06:			.asciz	" 2476 - 2887 mV (Stufe 6)\n"
str_mode_08_07:			.asciz	" 2888 - 3300 mV (Stufe 7)\n"
str_mode_10_00:			.asciz	" 0 -  330 mV (Stufe 0)\n"
str_mode_10_01:			.asciz	" 331 -  660 mV (Stufe 1)\n"
str_mode_10_02:			.asciz	" 661 -  990 mV (Stufe 2)\n"
str_mode_10_03:			.asciz	" 991 - 1320 mV (Stufe 3)\n"
str_mode_10_04:			.asciz	" 1321 - 1650 mV (Stufe 4)\n"
str_mode_10_05:			.asciz	" 1651 - 1980 mV (Stufe 5)\n"
str_mode_10_06:			.asciz	" 1981 - 2310 mV (Stufe 6)\n"
str_mode_10_07:			.asciz	" 2311 - 2640 mV (Stufe 7)\n"
str_mode_10_08:			.asciz	" 2641 - 2970 mV (Stufe 8)\n"
str_mode_10_09:			.asciz	" 2971 - 3300 mV (Stufe 9)\n"
str_mode_12_00:			.asciz	" 0 - 275 mV (Stufe  0)\n"
str_mode_12_01:			.asciz	" 275 - 550 mV (Stufe  1)\n"
str_mode_12_02:			.asciz	" 550 - 825 mV (Stufe  2)\n"
str_mode_12_03:			.asciz	" 825 - 1100 mV (Stufe  3)\n"
str_mode_12_04:			.asciz	" 1100 - 1375 mV (Stufe  4)\n"
str_mode_12_05:			.asciz	" 1375 - 1650 mV (Stufe  5)\n"
str_mode_12_06:			.asciz	" 1650 - 1925 mV (Stufe  6)\n"
str_mode_12_07:			.asciz	" 1925 - 2200 mV (Stufe  7)\n"
str_mode_12_08:			.asciz	" 2200 - 2475 mV (Stufe  8)\n"
str_mode_12_09:			.asciz	" 2475 - 2750 mV (Stufe 9)\n"
str_mode_12_10:			.asciz	" 2750 - 3025 mV (Stufe 10)\n"
str_mode_12_11:			.asciz	" 3025 - 3300 mV (Stufe 11)\n"
str_mode_16_00:			.asciz	" 0 - 206 mV (Stufe 0)\n"
str_mode_16_01:			.asciz	" 207 - 412 mV (Stufe 1)\n"
str_mode_16_02:			.asciz	" 413 - 618 mV (Stufe 2)\n"
str_mode_16_03:			.asciz	" 619 - 825 mV (Stufe 3)\n"
str_mode_16_04:			.asciz	" 826 - 1031 mV (Stufe 4)\n"
