str_mode_16_15:			.asciz	" 3094 - 3300 mV (Stufe 15)\n"
// Platzhalterarray für die Bestimmung der Stringadressen im UP "index_strings"
string_addresses:
.rept 64
	.word 0x0
.endr
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ	SIM_SCGC4			,	0x40048034		// S.304
.equ	SIM_SCGC4_BIT_I2C0	,	6				// S.305
.equ	SIM_SCGC5			,	0x40048038		// Quelle: S.306 Handbuch
.equ	SIM_SCGC5_BIT_PORTD	,	12				// Quelle: S.306 Handbuch
.equ	SIM_SCGC6			,	0x4004803c		// Quelle: S.308 Handbuch
.equ	SIM_SCGC6_BIT_PIT	,	23				// Quelle: S.308 Handbuch

__BBREG	SIM_I2C				,	SIM_SCGC4	,	SIM_SCGC4_BIT_I2C0
__BBREG	SIM_PORTD			,	SIM_SCGC5	,	SIM_SCGC5_BIT_PORTD
__BBREG	SIM_PIT				,	SIM_SCGC6	,	SIM_SCGC6_BIT_PIT

.equ	PORTD_PCR8			,	0x4004C020		// S.275
.equ	PORTD_PCR9			,	0x4004C024		// S.275

.equ	GPIOD_PDOR			,	0x400FF0C0		// S.1744
.equ	GPIOD_PDIR			,	0x400FF0D0		// S.1744
.equ	GPIOD_PDDR			,	0x400FF0D4		// S.1744

.equ	I2C0_F				,	0x40066001		// I2C Frequency Divider register					1457
.equ	I2C0_C1				,	0x40066002		// I2C Control Register 1							1458
.equ	I2C0_S				,	0x40066003		// I2C Status register								1460
.equ	I2C0_D				,	0x40066004		// I2C Data I/O register							1461
.equ	I2C0_C2				,	0x40066005		// I2C Control Register 2							1462
.equ	I2C0_FLT			,	0x40066006		// I2C Programmable Input Glitch Filter register	1463

__BBREG	I2C0_C1_IICEN		,	I2C0_C1	,	7	// 1 enable module
__BBREG	I2C0_C1_IICIE		,	I2C0_C1	,	6	// 1 interrupt enable
__BBREG	I2C0_C1_MST			,	I2C0_C1	,	5	// 1 master mode
__BBREG	I2C0_C1_TX			,	I2C0_C1	,	4	// 0 recieve, 1 transmit
__BBREG	I2C0_C1_TXAK		,	I2C0_C1	,	3	// 0 is send, 1 is not send
__BBREG	I2C0_C1_RSTA		, 	I2C0_C1	,	2	// write 1 == repeat start, reads 0, wrong time == loss of arbitration
__BBREG	I2C0_C1_WUEN		,	I2C0_C1	,	1	// wakeup, 0 = normal, 1 = enabled
__BBREG	I2C0_C1_DMAEN		,	I2C0_C1	,	0	// 0 disabled

__BBREG	I2C0_S_TCF			,	I2C0_S	,	7	// 0 = progress, 1 complete, cleared by reading/writing I2Cx_D
__BBREG	I2C0_S_IAAS			,	I2C0_S	,	6
__BBREG	I2C0_S_BUSY			,	I2C0_S	,	5	// 0 idle, 1 busy
__BBREG	I2C0_S_ARBL			,	I2C0_S	,	4	// 0 standard, 1 loss
__BBREG	I2C0_S_RAM			,	I2C0_S	,	3	// 0 not, 1 as slave
__BBREG	I2C0_S_SRW			,	I2C0_S	,	2	// 0 slave recieve, master write, 1 slave transmit, master reading
__BBREG	I2C0_S_IICIF		,	I2C0_S	,	1	// 0 no pending, 1 pending, write 1 to clear
__BBREG	I2C0_S_RXAK			,	I2C0_S	,	0	// 0 ack detected, 1 no ack

.equ	DS75_WRITE			,	0x90
.equ	DS75_READ			,	0x91
.equ	DS75_CONFIG			,	0x60
.equ	DS75_POINTER_TEMP	,	0
.equ	DS75_POINTER_CFG	,	1
.equ	DS75_POINTER_THYST	,	2
.equ	DS75_POINTER_TOS	,	3

.equ	NVIC_ISER_BASE		,	0xe000e100					// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ISER2			,	NVIC_ISER_BASE + 0x8		// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ICPR_BASE		,	0xe000e280					// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual
.equ	NVIC_ICPR2			,	NVIC_ICPR_BASE + 0x8		// Quelle: Sektion B3.4.3 Armv7-M Architecture Reference Manual

.equ	PIT_MCR				,	0x40037000					// Quelle: S.1077 Handbuch

.equ	PIT1_BASE			,	0x40037110					// Quelle: S.1077 Handbuch
.equ	PIT_LDVAL1			,	PIT1_BASE + 0x0				// Quelle: S.1077 Handbuch
.equ	PIT_CVAL1			,	PIT1_BASE + 0x4				// Quelle: S.1077 Handbuch
.equ	PIT_TCTRL1			,	PIT1_BASE + 0x8				// Quelle: S.1077 Handbuch
.equ	PIT_TFLG1			,	PIT1_BASE + 0xc				// Quelle: S.1077 Handbuch

// PIT_TCTRL Register Felder
.equ	PIT_CHN				,	2							// Quelle: S.1080 Handbuch
.equ	PIT_TIE				,	1							// Quelle: S.1080 Handbuch
.equ	PIT_TEN				,	0							// Quelle: S.1080 Handbuch

.equ	PIT1_IRQ			,	69							// Quelle: S.78 Handbuch
.equ	PIT1_IRQ_OFFSET		,	0x00000154					// Quelle: S.78 Handbuch

.equ	NVIC_PIT1_BIT		,	PIT1_IRQ % 32

.equ	IRQ_VECTOR_TABLE	,	0x1ffffe00					// Quelle: Skript
.equ	IRQ_VECTOR_PIT1		,	IRQ_VECTOR_TABLE + PIT1_IRQ_OFFSET

.equ	MASK_PIT1_CONFIG	,	(1 << PIT_TIE | 1 << PIT_TEN)
.equ	MASK_PD8_9			,	0x300			// Maske fuer PD8 und PD9
.equ	MASK_PD8			,	0x100			// Maske fuer PD8
.equ	MASK_ALT_GPIO 		,	0x100			// Alternative 1: GPIO
.equ	MASK_ALT_I2C		,	0x200			// Alternative 2: in diesem Fall i2c
.equ	MASK_I2C0_C1_CONFIG	,	0x80
.equ	MASK_I2C_F_CONFIG	,	0x12
.equ	MASK_BIT_7_4		,	0xf0

.equ	I2C_BUS_RETRIES		,	1000		// Anzahl der Wiederholungen bei Buszugriff, danach Ausgabe einer Fehlermeldung.

.equ	BYTE_LENGTH			,	8

.equ	TWO_MICRO_SECONDS	, 	50			// wegen Taktfrequenz 25 MHz ist 1 Takt == 40ns, daher 2µs == 50 Takte
.equ	ONE_SECOND			,	25000000	// Anzahl der Takte bei 25 MHz pro Sekunde

main:
	bl		uart_init

	// Bus zurücksetzen und initialisieren
	bl		i2c_bus_reset
	bl		i2c_init

	// Konfiguration schreiben
	bl		ds75_write_config

	// Basistemperatur lesen und Schwellenwerte schreiben
	bl		ds75_read_first_temp
	
	bl		pit1_init

	ldr		r4, =second_flag
main_loop:
	// Schleife immer nach einer Sekunde unterbrechen
	ldr		r0, [r4]
	cmp		r0, #0
	beq		main_loop

	// Flag zurücksetzen
	mov		r0, #0
	str		r0, [r4]

	// Temperatur lesen und ausgeben
	bl		ds75_read_temp
	bl		print_temp
	b		main_loop
	
.thumb_func
pit1_init:
	// Takt für PIT aktivieren
	mov		r1, #1 
	ldr		r0, =SIM_PIT
	str		r1, [r0]
	
	// PIT1 Interrupt Handler eintragen
	ldr		r0, =pit1_handler
	ldr		r1, =IRQ_VECTOR_PIT1
	str		r0, [r1]

	// Pending Interrupt löschen und Interrupt aktivieren
	ldr		r0, =NVIC_ICPR2
	ldr		r1, =NVIC_ISER2
	mov		r2, #(1 << NVIC_PIT1_BIT)
	str		r2, [r0]
	str		r2, [r1]

	// PIT im Debug-Modus laufen lassen
	ldr		r0, =PIT_MCR
	mov		r1, #1
	str		r1, [r0]

	// 25000000 Takte === 1s eintragen
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =ONE_SECOND
	str		r1, [r0]

	// PIT1 Chain Mode deaktivieren, Interrupt aktivieren und starten
	ldr		r1, =PIT_TCTRL1
	ldr		r0, =MASK_PIT1_CONFIG
	str		r0, [r1]

	bx		lr

.thumb_func
i2c_enable:
	ldr		r0, =I2C0_C1_IICEN
	mov		r1, #1
	strb	r1, [r0]
	bx		lr

.thumb_func
i2c_set_write:
	ldr		r0, =I2C0_C1_TX
	mov		r1, #1
	strb	r1, [r0]
	bx		lr

.thumb_func
i2c_set_read:
	ldr		r0, =I2C0_C1_TX
	mov		r1, #0
	strb	r1, [r0]
	bx		lr

.thumb_func
i2c_set_start:
	push	{lr}
	ldr		r0, =I2C0_C1_MST
	ldr		r1, =I2C_BUS_RETRIES
	// Versuche die Startbedingung zu erreichen.
	// Der Bus ist erst dann für einen
	// Schreibvorgang bereit, wenn das MST Bit auch
	// tatsächlich im Register steht. Daher muss
	// dieses auch immer wieder erneut gelesen werden.
i2c_set_start__loop:
	mov		r2, #1
	strb	r2, [r0]
	ldrb	r2, [r0]
	cmp		r2, #1
	beq		i2c_set_start__end
	subs	r1, r1, #1
	bne		i2c_set_start__loop
	ldr		r0, =str_set_start_error
	bl		uart_putString
i2c_set_start__end:
	pop		{pc}

.thumb_func
i2c_set_stop:
	ldr		r0, =I2C0_C1_MST
	mov		r1, #0
	strb	r1, [r0]
	bx		lr

.thumb_func
i2c_set_repeat_start:
	ldr		r0, =I2C0_C1_RSTA
	mov		r1, #1
	strb	r1, [r0]
	bx		lr

.thumb_func
i2c_set_nack:
	ldr		r0, =I2C0_C1_TXAK
	mov		r1, #1
	strb	r1, [r0]
	bx		lr
	
.thumb_func
i2c_set_ack:
	ldr		r0, =I2C0_C1_TXAK
	mov		r1, #0
	strb	r1, [r0]
	bx		lr

.thumb_func
i2c_write:
	push	{lr}
	ldr		r1, =I2C0_D
	ldr		r2, =I2C_BUS_RETRIES
	ldr		r3, =I2C0_S_IICIF
	// Schreibe Byte und prüfe dann IICIF,
	// um sicherzustellen, dass die Übertragung
	// funktioniert und um die nächste Übertragung
	// soweit zu verzögern, dass keine Kollisionen auftreten.
	strb	r0, [r1]
i2c_write__loop:
	ldrb	r0, [r3]
	cmp		r0, #1
	beq		i2c_write__clear_iicif
	subs	r2, r2, #1
	bne		i2c_write__loop
	ldr		r0, =str_write_error
	bl		uart_putString
i2c_write__clear_iicif:
	ldr		r0, =I2C0_S_IICIF
	mov		r1, #1
	strb	r1, [r0]
i2c_write__end:
	pop		{pc}

.thumb_func
i2c_read:
	// Liest ein Byte aus dem Datenregister
	// und prüft dann solange das IICIF Bit,
	// bis der *nächste* Vorgang abgeschlossen ist
	// (oder die Anzahl der Wiederholungen überschritten wurde)
	//
	// Um einen Lesevorgang anzustoßen, muss zunächst
	// ein "Dummy Read" erfolgen, das dabei gelesene
	// Byte wird verworfen. Das eigentlich zu lesende
	// Byte wird "während" der Überprüfung von IICIF
	// übertragen und steht beim nächsten Aufruf
	// des UP zur Verfügung.
	push	{r4, lr}
	ldr		r1, =I2C0_D
	ldr		r2, =I2C_BUS_RETRIES
	ldr		r3, =I2C0_S_IICIF
	ldrb	r4, [r1]
i2c_read__loop:
	ldrb	r0, [r3]
	cmp		r0, #1
	beq		i2c_read__clear_iicif
	subs	r2, r2, #1
	bne		i2c_read__loop
	ldr		r0, =str_read_error
	bl		uart_putString
i2c_read__clear_iicif:
	mov		r1, #1
	strb	r1, [r3]
i2c_read__end:
	mov		r0, r4
	pop		{r4, pc}

.thumb_func
i2c_init:

	// Takt für Port D und I2C aktivieren
	mov		r1, #1
	ldr		r0, =SIM_PORTD
	str		r1, [r0]
	ldr		r0,	=SIM_I2C		
	str		r1, [r0]

	// Port D konfigurieren und als I2C schalten
	ldr		r0, =PORTD_PCR8		
	ldr		r1, =PORTD_PCR9
	mov		r2, #MASK_ALT_I2C
	str		r2, [r0]
	str		r2, [r1]

	// Auf höchstmögliche Geschwindigkeit setzen.
	// Laut Handbuch des DS75 ist f_SCL = 400KHz
	// Es gilt 25MHz / 400KHz = 62,5
	// Aus der Tabelle 51-41 im Handbuch des K60
	// geht als nächstkleinerer Divider 0x12 == 64
	// hevor. MULT bleibt bei 1.
	ldr		r1, =MASK_I2C_F_CONFIG
	ldr		r0, =I2C0_F
	strb	r1, [r0]
	
	// C2 auf Standardwerte setzen und FLT deaktivieren
	// außer C1 werden keine anderen Register benötigt.
	// Insbesondere SMB wird nicht benutzt
	mov		r1, #0
	ldr		r0, =I2C0_C2
	strb	r1, [r0]
	ldr		r0, =I2C0_FLT
	strb	r1, [r0]

	// Das Modul wird nur aktiviert,
	// alle anderen Bits werden auf 0 gesetzt.
	ldr		r1, =MASK_I2C0_C1_CONFIG
	ldr		r0, =I2C0_C1
	strb	r1, [r0]

	bx		lr

// Funktion basierend auf Vorschlag aus Aufgabenstellung
.thumb_func
i2c_bus_reset:
	push	{lr}

	// Takt für Port D
	ldr		r0, =SIM_PORTD
	mov		r1, #1
	str		r1, [r0]

	// Portleitungen PD8, PD9 als GPIO
	ldr		r0, =PORTD_PCR8
	ldr		r1, =PORTD_PCR9
	mov		r2, #MASK_ALT_GPIO
	str		r2, [r0]
	str		r2, [r1]

	// PD8, PD9 als Ausgang
	ldr		r0, =GPIOD_PDDR		
	ldr		r2, [r0]
	orr		r2, r2, #MASK_PD8_9
	str		r2, [r0]

i2c_bus_reset__loop:
	// SCL deaktivieren
	ldr		r0, =GPIOD_PDOR
	ldr		r2, [r0]
	// Bit löschen
	bic		r2, r2, #MASK_PD8
	str		r2, [r0]
	bl		i2c_delay

	// SCL und SDA deaktivieren
	ldr		r0, =GPIOD_PDOR
	ldr		r2, [r0]
	orr		r2, r2, #MASK_PD8_9
	str		r2, [r0]
	bl		i2c_delay

	ldr		r0, =GPIOD_PDIR
	ldr		r2, [r0]
	// Bits 9 und 10 prüfen
	and		r2, r2, #MASK_PD8_9
	cmp		r2, #MASK_PD8_9
	bne		i2c_bus_reset__loop

	pop		{pc}

.thumb_func
i2c_delay:
	// Vorgehen analog zur Abfrage des sw2 in ML V3-2
	// Die Schleife läuft daher mindestens 2µs
	ldr		r0, =(TWO_MICRO_SECONDS + 2) / 3
i2c_delay__loop:
	subs	r0, r0, #1
	bne 	i2c_delay__loop
	bx		lr
	
.thumb_func
ds75_read_first_temp:
	push	{r4-r5, lr}

	// Temperatur lesen und zwischenspeichern
	bl		ds75_read_temp
	mov		r4, r0
	mov		r5, r1
	// In THyst und TOS schreiben und...
	bl		ds75_write_thyst_add2
	mov		r0, r4
	mov		r1, r5
	bl		ds75_write_tos_add3
	mov		r0, r4
	mov		r1, r5
	// ...ausgeben
	bl		print_temp
	
	pop		{r4-r5, pc}

.thumb_func
ds75_write_config:
	push	{lr}

	bl		i2c_set_write
	bl		i2c_set_start
	ldr		r0, =DS75_WRITE
	bl		i2c_write
	ldr		r0, =DS75_POINTER_CFG
	bl		i2c_write
	// Einstellungen setzen auf:
	// * Resolution: 12 Bit
	// * Fault: 0
	// * POL: active low
	// * TM: comparator
	// * SD: active
	ldr		r0, =DS75_CONFIG
	bl		i2c_write
	bl		i2c_set_stop
	bl		i2c_delay

	pop		{pc}

.thumb_func
ds75_write_thyst_add2:
	push	{r4-r5, lr}

	// Der Wert soll um 2 erhöht werden,
	// damit die LED nach dem Einschalten
	// beim Unterschreiten von TOS um 1 Grad
	// wieder ausgeschaltet wird.
	add		r4, r0, #2
	mov		r5, r1

	bl		i2c_set_write
	bl		i2c_set_start
	ldr		r0, =DS75_WRITE
	bl		i2c_write
	ldr		r0, =DS75_POINTER_THYST
	bl		i2c_write
	mov		r0, r4
	bl		i2c_write
	mov		r0, r5
	bl		i2c_write
	bl		i2c_set_stop
	bl		i2c_delay

	pop		{r4-r5, pc}

.thumb_func
ds75_write_tos_add3:
	push	{r4-r5, lr}

	// Eingabe um 3 erhöhen und als
	// Schwellwert speichern
	add		r4, r0, #3
	mov		r5, r1

	bl		i2c_set_write
	bl		i2c_set_start
	ldr		r0, =DS75_WRITE
	bl		i2c_write
	ldr		r0, =DS75_POINTER_TOS
	bl		i2c_write
	mov		r0, r4
	bl		i2c_write
	mov		r0, r5
	bl		i2c_write
	bl		i2c_set_stop
	bl		i2c_delay

	pop		{r4-r5, pc}

// OUT r0 MSB
// OUT r1 LSB
.thumb_func
ds75_read_temp:
	push	{r4-r5, lr}

	bl		i2c_set_write
	bl		i2c_set_start
	ldr		r0, =DS75_WRITE
	bl		i2c_write
	// Beim wiederholten Lesen der Temperatur
	// in der Hautpschleife, muss der Zeiger
	// nicht erneut gesetzt werden. Da das
	// Datenblatt des DS75 das erneute Setzen
	// aber auch nicht verbietet, kann die Funktion
	// unverändert benutzt werden.
	ldr		r0, =DS75_POINTER_TEMP
	bl		i2c_write
	bl		i2c_set_repeat_start
	ldr		r0, =DS75_READ
	bl		i2c_write
	bl		i2c_set_read
	// Dummy Read startet Lesevorgang
	bl		i2c_read
	// MSB lesen und zwischenspeichern
	bl		i2c_read
	mov		r4, r0
	// Da das letzte Byte dieses Lesevorgangs gelesen
	// wird, muss der Master mit NACK das Ende der 
	// Leseabsicht ankündigen. 
	bl		i2c_set_nack
	// LSB lesen und zwischenspeichern
	bl		i2c_read
	mov		r5,	r0
	bl		i2c_set_stop
	bl		i2c_delay
	// NACK zurücksetzen, damit der nächste Vorgang
	// wieder mit Standardeinstellungen startet
	bl		i2c_set_ack

	// MSB und LSB zurückgeben
	mov		r0, r4
	mov		r1, r5

	pop		{r4-r5, pc}

.thumb_func
// IN r0 enthält MSB == 8 Bits des Fixed Point
// IN r1 enthält LSB == 7:4 sind 8 Bits vom 8.4 Format
print_temp:
	push	{r4, lr}
	// In ein Byte zusammenfassen
	lsl		r0, r0, #BYTE_LENGTH
	orr		r0, r0, r1
	mov		r4, r0

	ldr		r0, =str_hex
	bl		uart_putString

	mov		r0, r4
	lsl		r0, r0, #BYTE_LENGTH
	bl		uart_putInt32

	ldr		r0, =str_divider
	bl		uart_putString

	mov		r0, r4
	lsr		r0, r0, #BYTE_LENGTH
	bl		uart_putByteBase10

	mov		r1, r4
	and		r1, r1, #MASK_BIT_7_4
	// Hole Bits 7-4 und schiebe sie auf 3-0,
	// damit über sie auf das String Array zugegriffen werden kann.
	// Der Wert muss zusätzlich mit 4 (Wortlänge) multipliziert werden
	// zusammen ergibt das die Notwendigkeit für
	// 2-faches rechtsschieben
	lsr		r1, r1, #2
	ldr		r0, =str_addresses_fixed4
	ldr		r0, [r0, r1]
	bl		uart_putString

	ldr		r0, =str_celsius
	bl		uart_putString

	pop		{r4, pc}

.thumb_func
pit1_handler:
	// Interrupt-Flag löschen und
	// Benutzer-Flag setzen
	mov		r0, #1
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	ldr		r1, =second_flag
	str		r0, [r1]

	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
second_flag:			.word	0
str_set_start_error:	.asciz	"Busfehler: Konnte Start nicht setzen\n"
str_write_error:		.asciz	"Busfehler: Konnte nicht schreiben\n"
str_read_error:			.asciz	"Busfehler: Konnte nicht lesen\n"
str_hex:				.asciz	"0x"
str_divider:			.asciz	": "
str_celsius:			.asciz	" Grad Celsius\n"
str_fixed4_00:			.asciz	",0000"
str_fixed4_01:			.asciz	",0625"
str_fixed4_02:			.asciz	",1250"
str_fixed4_03:			.asciz	",1875"
str_fixed4_04:			.asciz	",2500"
str_fixed4_05:			.asciz	",3125"
str_fixed4_06:			.asciz	",3750"
str_fixed4_07:			.asciz	",4375"
str_fixed4_08:			.asciz	",5000"
str_fixed4_09:			.asciz	",5625"
str_fixed4_10:			.asciz	",6250"
str_fixed4_11:			.asciz	",6875"
str_fixed4_12:			.asciz	",7500"
str_fixed4_13:			.asciz	",8125"
str_fixed4_14:			.asciz	",8750"
str_fixed4_15:			.asciz	",9375"
str_addresses_fixed4:	.word	str_fixed4_00,	str_fixed4_01,	str_fixed4_02,	str_fixed4_03,	str_fixed4_04,	str_fixed4_05,	str_fixed4_06,	str_fixed4_07,	str_fixed4_08,	str_fixed4_09,	str_fixed4_10,	str_fixed4_11,	str_fixed4_12,	str_fixed4_13,	str_fixed4_14,	str_fixed4_15

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// SIM
.equ	SIM_SCGC3					,	0x40048030
.equ	SIM_SCGC3_SPI2				,	12
__BBREG	SIM_SCGC3_SPI2_BB			,	SIM_SCGC3	,	SIM_SCGC3_SPI2

.equ	SIM_SCGC5					,	0x40048038
.equ	SIM_SCGC5_PORTA				,	9
.equ	SIM_SCGC5_PORTD				,	12
.equ	SIM_SCGC5_PORTE				,	13
__BBREG	SIM_PORTA					,	SIM_SCGC5	,	SIM_SCGC5_PORTA
__BBREG	SIM_PORTD					,	SIM_SCGC5	,	SIM_SCGC5_PORTD
__BBREG	SIM_PORTE					,	SIM_SCGC5	,	SIM_SCGC5_PORTE

.equ	SIM_SCGC6					,	0x4004803C
.equ	SIM_SCGC6_PIT				,	23
__BBREG	SIM_PIT						,	SIM_SCGC6	,	SIM_SCGC6_PIT

// PORT

.equ	PORTA_PCR_BASE				,	0x40049000
.equ	PORTD_PCR_BASE				,	0x4004C000
.equ	PORTE_PCR_BASE				,	0x4004D000

.equ	PORTA_PCR19					,	PORTA_PCR_BASE + (4 * 19)

.equ	PORTD_PCR11					,	PORTD_PCR_BASE + (4 * 11)
.equ	PORTD_PCR12					,	PORTD_PCR_BASE + (4 * 12)
.equ	PORTD_PCR13					,	PORTD_PCR_BASE + (4 * 13)
.equ	PORTD_PCR14					,	PORTD_PCR_BASE + (4 * 14)
.equ	PORTD_PCR15					,	PORTD_PCR_BASE + (4 * 15)

.equ	PORTE_PCR26					,	PORTE_PCR_BASE + (4 * 26)

.equ	PORTx_PCRn_ISF_BIT			,	24
.equ	PORTx_PCRn_MUX1_BIT			,	9

.equ	PORTD_PCR_CONFIG_SPI		,	( 1 << PORTx_PCRn_MUX1_BIT )

// SPI

.equ	SPI_MCR_OFFSET				,	0x00
.equ	SPI_CTAR0_OFFSET			,	0x0C
.equ	SPI_SR_OFFSET				,	0x2C
.equ	SPI_RSER_OFFSET				,	0x30
.equ	SPI_PUSHR_OFFSET			,	0x34
.equ	SPI_POPR_OFFSET				,	0x38

.equ	SPI_MCR_MSTR				,	31
.equ	SPI_MCR_DIS_TXF				,	13
.equ	SPI_MCR_DIS_RXF				,	12
.equ	SPI_MCR_CLR_TXF				,	11
.equ	SPI_MCR_CLR_RXF				,	10
.equ	SPI_MCR_HALT				,	0

.equ	SPI_CTAR_DBR				,	31
.equ	SPI_CTAR_FMSZ3				,	30
.equ	SPI_CTAR_FMSZ2				,	29
.equ	SPI_CTAR_FMSZ1				,	28
.equ	SPI_CTAR_FMSZ0				,	27
.equ	SPI_CTAR_CPHA				,	25
.equ	SPI_CTAR_PCSSCK1			,	23
.equ	SPI_CTAR_PASC1				,	21
.equ	SPI_CTAR_PDT1				,	19
.equ	SPI_CTAR_PBR1				,	17

.equ	SPI_PUSHR_CONT				,	31
.equ	SPI_PUSHR_PCS1				,	17

.equ	SPI_SR_TCF					,	31
.equ	SPI_SR_RFDF					,	17

.equ	SPI_MCR_MSTR_MASK			,	(1 << SPI_MCR_MSTR)
.equ	SPI_MCR_HALT_MASK			,	(1 << SPI_MCR_HALT)

.equ	SPI_CTAR_DBR_MASK			,	(1 << SPI_CTAR_DBR)
.equ	SPI_CTAR_FMSZ3_MASK			,	(1 << SPI_CTAR_FMSZ3)
.equ	SPI_CTAR_FMSZ2_MASK			,	(1 << SPI_CTAR_FMSZ2)
.equ	SPI_CTAR_FMSZ1_MASK			,	(1 << SPI_CTAR_FMSZ1)
.equ	SPI_CTAR_FMSZ0_MASK			,	(1 << SPI_CTAR_FMSZ0)
.equ	SPI_CTAR_CPHA_MASK			,	(1 << SPI_CTAR_CPHA)
.equ	SPI_CTAR_PCSSCK1_MASK		,	(1 << SPI_CTAR_PCSSCK1)
.equ	SPI_CTAR_PASC1_MASK			,	(1 << SPI_CTAR_PASC1)
.equ	SPI_CTAR_PDT1_MASK			,	(1 << SPI_CTAR_PDT1)
.equ	SPI_CTAR_PBR1_MASK			,	(1 << SPI_CTAR_PBR1)

.equ	SPI_PUSHR_CONT_MASK			,	(1 << SPI_PUSHR_CONT)
.equ	SPI_PUSHR_PCS1_MASK			,	(1 << SPI_PUSHR_PCS1)

// SPI2

.equ	SPI2_ADDR					,	0x400AC000

.equ	SPI2_MCR					,	SPI2_ADDR + SPI_MCR_OFFSET
.equ	SPI2_CTAR0					,	SPI2_ADDR + SPI_CTAR0_OFFSET
.equ	SPI2_SR						,	SPI2_ADDR + SPI_SR_OFFSET
.equ	SPI2_RSER					,	SPI2_ADDR + SPI_RSER_OFFSET
.equ	SPI2_PUSHR					,	SPI2_ADDR + SPI_PUSHR_OFFSET
.equ	SPI2_POPR					,	SPI2_ADDR + SPI_POPR_OFFSET

__BBREG	SPI2_MCR_HALT_BB			,	SPI2_MCR	,	SPI_MCR_HALT
__BBREG	SPI2_MCR_DIS_TXF_BB			,	SPI2_MCR	,	SPI_MCR_DIS_TXF
__BBREG	SPI2_MCR_DIS_RXF_BB			,	SPI2_MCR	,	SPI_MCR_DIS_RXF
__BBREG	SPI2_MCR_CLR_TXF_BB			,	SPI2_MCR	,	SPI_MCR_CLR_TXF
__BBREG	SPI2_MCR_CLR_RXF_BB			,	SPI2_MCR	,	SPI_MCR_CLR_RXF

__BBREG	SPI2_SR_TCF_BB				,	SPI2_SR		,	SPI_SR_TCF
__BBREG	SPI2_SR_RFDF_BB				,	SPI2_SR		,	SPI_SR_RFDF

.equ	SPI2_MCR_INITIAL_CONFIG		,	( SPI_MCR_MSTR_MASK | SPI_MCR_HALT_MASK )

// Nach den Hinweisen würde auch 100KHz BR reichen, mit diesen Einstellungen
// sind 5MHz (max laut Datenblatt) jedoch möglich. Die Verzögerungen werden auf 
// 400ns (min laut Datenblatt) gesetzt.
// DBR		1
// FMSZ		7 (+1)
// CPO		0
// CPHA		1
// LSBFE	0
// PCSCK	5
// PASC		5
// PDT		5
// PBR		5
// CSSCK	2	0,0000004	1 / 25000000 * PCSCK * CSSCK
// ASC		2	0,0000004	1 / 25000000 * PASC * ASC
// DT		2	0,0000004	1 / 25000000 * PDT * DT
// BR		2	5000000		25000000 / PBR * [(1+DRB) / BR]
.equ	SPI2_CTAR_INITIAL_CONFIG	,	( SPI_CTAR_DBR_MASK | SPI_CTAR_FMSZ3_MASK | SPI_CTAR_FMSZ2_MASK | SPI_CTAR_FMSZ1_MASK | SPI_CTAR_FMSZ0_MASK | SPI_CTAR_CPHA_MASK | SPI_CTAR_PCSSCK1_MASK | SPI_CTAR_PASC1_MASK | SPI_CTAR_PDT1_MASK | SPI_CTAR_PBR1_MASK )

// PIT

.equ	PIT_MCR						,	0x40037000
.equ	PIT_LDVAL1					,	0x40037110
.equ	PIT_TCTRL1					,	0x40037118
.equ	PIT_TFLG1					,	0x4003711C

.equ	PIT1_INIT					,	3	// TEN und TIE gesetzt

// GPIO, SW1, SW2

.equ	SW1_PIN						,	19
.equ	SW2_PIN						,	26

.equ	GPIOA_PDDR					,	0x400FF014
.equ	GPIOE_PDDR					,	0x400FF114

.equ	GPIO_IRQ_PE_SET				,	0xA0103		// GPIO, IRQ (fallende Flanke), Pull-Up

__BBREG	GPIOA_PDDR_SW1				,	GPIOA_PDDR	,	SW1_PIN
__BBREG	GPIOA_PDDR_SW2				,	GPIOE_PDDR	,	SW2_PIN

__BBREG	SW1_CIF						,	PORTA_PCR19	,	PORTx_PCRn_ISF_BIT
__BBREG	SW2_CIF						,	PORTE_PCR26	,	PORTx_PCRn_ISF_BIT

// Interrupt

.equ	NVIC_ISER2					,	0xE000E108
.equ	SCR_VTOR					,	0xE000ED08

.equ	IVT_PIT1					,	0x154
.equ	IVT_PTA						,	0x19C
.equ	IVT_PTE						,	0x1AC

.equ	IRQ_PIT1					,	69
.equ	IRQ_PTA						,	87
.equ	IRQ_PTE						,	91

.equ	NVIC_ISER2_PIT1_MASK		,	1 << (IRQ_PIT1 % 32)
.equ	NVIC_ISER2_PTA_MASK			,	1 << (IRQ_PTA  % 32)
.equ	NVIC_ISER2_PTE_MASK			,	1 << (IRQ_PTE  % 32)



.equ	DS1722_CFG_WRITE			,	0x80
.equ	DS1722_TEMP_MSB_READ		,	0x02

.equ	MIN_LEVEL					,	0
.equ	MAX_LEVEL					,	4

.equ	MASK_BYTE_0					,	0xff
.equ	MASK_BYTE_1					,	0xff00
.equ	MASK_BIT_7_4				,	0xf0
.equ	BYTE_LENGTH					,	8


// Funktionalität zwecks besserer Übersicht in
// Unterprogramme ausgelagert.
main:
	bl		uart_init
	bl		portd_init
	bl		spi2_init
	bl		sw_init
	bl		pit1_init

	bl		ds1722_write_cfg
	bl		pit1_start_with_level

	ldr		r9, =pit1_flag
	mov		r10, #0

main_loop:
	ldr		r0, [r9]
	cmp		r0, #0
	// Falls der PIT ausgelöst hat fortfahren.
	// Sonst weiter in der Schleife warten.
	beq		main_loop

	// Flag löschen
	str		r10, [r9]

	// Durch den Aufbau der read Funktion kann
	// hier mit einem Breakpoint auch das
	// Konfigurationsregister gelesen werden.
	// Siehe Beschreibung der Funktion.
	bl		ds1722_read
	bl		print_temp

	// An dieser Stelle wurde eine "unfreiwillige"
	// Designentscheidung getroffen:
	// Während einer Schleife wird in jedem Fall
	// auf die Temperatur des DS1722 gewartet und
	// erst dann wird die Auflösung angepasst
	// und zwar pro Schleife nur um +/-1.
	// Der Grund dafür liegt daran, dass, zumindest
	// bei meinem Versuchsgerät, die Knöpfe ohne
	// Debouncing so sensibel reagieren, dass ein
	// "Hoch-" oder "Runter-"schalten nicht gezielt
	// möglich war.
	// Ich hatte zunächst einen Zähler implementiert,
	// welcher die hoch-/runter Interrupts saldiert
	// und die Auflösung dementsprechend am Ende der
	// Schleife anpasst. Da jedoch bei einem
	// Knopfdruck teilweise 3 oder mehr Interrupts
	// ausgelöst wurden, konnte ich das Level nicht
	// sauber auswählen und habe mich deswegen dazu
	// entschieden, immer nur eine Stufe weiterzuschalten.
	// Der Code ähnelt daher nun stark V3-2.
	bl		adjust_level

	// Ǹeue Konfiguration schreiben
	// und PIT1 erneut starten:
	// Die aktuelle Auflösung wird
	// bei jedem Durchgang neu bestimmt und erneut
	// in den DS1722 geschrieben. Der PIT wird dann ebenfalls,
	// mit angepasster Dauer bis zum Interrupt, 
	// erneut gestartet.
	bl		ds1722_write_cfg
	bl		pit1_start_with_level

	b		main_loop

.thumb_func
adjust_level:
	push	{lr}
	// Gibt es hier einen kurzen Moment, an dem eine ISR 
	// adjust_flag verändern könnte, obwohl der Wert bereits
	// geladen wurde? Dann würde das Schreiben von #0
	// die neue "Absicht" den Wert zu verändern
	// auch überschreiben! Wie kann man das verhindern?
	ldr		r0, =adjust_flag
	ldr		r2, [r0]
	mov		r1, #0
	str		r1, [r0]

	cmp		r2, #0 // Normalfall
	beq		adjust_level__complete
	cmp		r2, #1
	beq		adjust_level__up
	cmp		r2, #2
	beq		adjust_level__down

	// Sollte niemals eintreten!
	b		adjust_level__complete

adjust_level__up:

	ldr		r0, =str_new_resolution
	bl		uart_putString

	ldr		r0, =level
	ldr		r1, [r0]
	cmp		r1, #MAX_LEVEL
	ite eq
	moveq	r1, #MIN_LEVEL
	addne	r1, r1, #1
	str		r1, [r0]
	b		adjust_level__continue

adjust_level__down:

	ldr		r0, =str_new_resolution
	bl		uart_putString
	
	ldr		r0, =level
	ldr		r1, [r0]
	cmp		r1, #MIN_LEVEL
	ite eq
	moveq	r1, #MAX_LEVEL
	subne	r1, r1, #1
	str		r1, [r0]

adjust_level__continue:
	lsl		r1, r1, #2
	ldr		r0, =str_resolution
	ldr		r0, [r0, r1]
	bl		uart_putString

adjust_level__complete:
	pop		{pc}


.thumb_func
sw_init:
	// Takt einschalten
	mov		r1, #1
	ldr		r0, =SIM_PORTA
	str		r1, [r0]
	ldr		r0, =SIM_PORTE
	str		r1, [r0]
	// GPIO konfigurieren
	ldr		r1, =GPIO_IRQ_PE_SET
	ldr		r0, =PORTA_PCR19
	str		r1, [r0]
	ldr		r0, =PORTE_PCR26
	str		r1, [r0]
	// Datenrichtung setzen
	mov		r1, #0
	ldr		r0, =GPIOA_PDDR_SW1
	str		r1, [r0]
	ldr		r0, =GPIOA_PDDR_SW2
	str		r1, [r0]
	// ISRs eintragen
	ldr		r0, =SCR_VTOR
	ldr		r1, [r0]
	ldr		r0, =isr_port_a
	str		r0, [r1, #IVT_PTA]
	ldr		r0, =isr_port_e
	str		r0, [r1, #IVT_PTE]
	// Bitmaske setzen
	ldr		r0, =NVIC_ISER2
	ldr		r1, [r0]
	orr		r1, r1, #( NVIC_ISER2_PTA_MASK | NVIC_ISER2_PTE_MASK )
	str		r1, [r0]

	bx		lr

.thumb_func
pit1_init:
	mov		r2, #0
	mov		r3, #1 
	// Takt schalten
	ldr		r0, =SIM_PIT
	str		r3, [r0]
	// ISR eintragen
	ldr		r0, =SCR_VTOR
	ldr		r1, [r0]
	ldr		r0, =isr_pit1
	str		r0, [r1, #IVT_PIT1]
	// MCR
	ldr		r0, =PIT_MCR
	str		r3, [r0]
	// Bitmaske setzen
	ldr		r0, =NVIC_ISER2
	ldr		r1, [r0]
	orr		r1, r1, #NVIC_ISER2_PIT1_MASK
	str		r1, [r0]

	bx		lr

.thumb_func
pit1_start_with_level:
	ldr		r0, =PIT_LDVAL1
	ldr		r1, =pit_cycles
	ldr		r2, =level
	ldr		r2, [r2]
	lsl		r2, r2, #2
	ldr		r1, [r1, r2]
	ldr		r1, [r1]
	str		r1, [r0]
	// PIT1 starten
	mov		r1, #PIT1_INIT
	ldr		r0, =PIT_TCTRL1
	str		r1, [r0]

	bx		lr

// Für diese Funktion (und PTA entsprechend) gilt
// der Hinweis aus ML3-1: Es handelt sich um ISRs des Ports,
// nicht der einzelnen Pins. Trotzdem gehen wir davon aus,
// dass ein Interrupt nur von den eingestellten Pins stammen kann.
.thumb_func
isr_port_a:
	// Interrupt loeschen
	ldr		r0, =SW1_CIF
	mov		r1, #1
	str		r1, [r0]
	// User Flag setzen
	mov		r0, #1
	ldr		r1, =adjust_flag
	str		r0, [r1]
	
	bx		lr

.thumb_func
isr_port_e:
	// Interrupt löschen
	ldr		r0, =SW2_CIF
	mov		r1, #1
	str		r1, [r0]
	// User Flag setzen
	mov		r0, #2
	ldr		r1, =adjust_flag
	str		r0, [r1]

	bx		lr

.thumb_func
isr_pit1:
	// User Flag setzen
	mov		r0, #1
	ldr		r1, =pit1_flag
	str		r0, [r1]
	// Interrupt löschen
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]
	// PIT1 ausschalten (!)
	mov		r0, #0
	ldr		r1, =PIT_TCTRL1
	str		r0, [r1]

	bx		lr

// IN r0:
// 31:8		0x000000
// 7:0		enthält eine DS1722 Konfiguration
.thumb_func
ds1722_write_cfg:
	push	{lr}

	bl		spi2_enable_transfers
	
	// Die zu schreibende Aufloesung auslesen
	// und auf die richtige Bit-Position schieben
	ldr		r2, =level
	ldr		r2, [r2]
	lsl		r2, r2, #1

	// PCS1 entspricht dem DS1722
	ldr		r0, =SPI2_PUSHR
	ldr		r1, =( SPI_PUSHR_PCS1_MASK | DS1722_CFG_WRITE << BYTE_LENGTH )
	orr		r1, r1, r2
	str		r1, [r0]

	bl		spi2_check_tcf

	bl		spi2_flush_fifos
	bl		spi2_disable_transfers
	
	pop		{pc}

// OUT r0:
// 31:24	Configuration
// 23:16	0x00
// 15: 8	Temperature MSB
//   7:0	Temperature LSB
.thumb_func
ds1722_read:
	push	{r4, lr}

	bl		spi2_enable_transfers

	// Mit CONT ist es durch der Burst-Mode
	// leicht möglich, den gesamten DS1722 zu lesen.
	ldr		r0, =SPI2_PUSHR
	ldr		r1, =(SPI_PUSHR_PCS1_MASK | SPI_PUSHR_CONT_MASK | DS1722_TEMP_MSB_READ << BYTE_LENGTH)
	str		r1, [r0]

	bl		spi2_check_tcf

	// Da das Programm nicht mit der FIFO
	// Funktionalität arbeitet, muss
	// der gelesene Frame jetzt schon
	// zwischengespeichert werden.
	ldr		r0,	=SPI2_POPR
	ldrh	r4, [r0]

	// Beim erneuten Schreiben wird auch CONT zurückgesetzt.
	ldr		r0, =SPI2_PUSHR
	ldr		r1, =(SPI_PUSHR_PCS1_MASK)
	str		r1, [r0]
	
	bl		spi2_check_tcf

	ldr 	r0, =SPI2_POPR
	ldrh	r0, [r0]

	// Bytes extrahieren und zwischenspeichern,
	// sodass sie bereits in der Ausgabereihenfolge
	// vorliegen.

	and		r2, r0, #MASK_BYTE_0
	and		r0, r0, #MASK_BYTE_1
	orr		r2, r2, r4, LSL #BYTE_LENGTH
	orr		r4, r2, r0, LSL #(BYTE_LENGTH * 2)

	bl		spi2_flush_fifos
	bl		spi2_disable_transfers

	mov		r0, r4

	pop		{r4, pc}

.thumb_func
spi2_enable_transfers:
	ldr		r0, =SPI2_MCR_HALT_BB
	mov		r1, #0
	str		r1, [r0]

	bx		lr

.thumb_func
spi2_disable_transfers:
	ldr		r0, =SPI2_MCR_HALT_BB
	mov		r1, #1
	str		r1, [r0]

	bx		lr

.thumb_func
spi2_check_tcf:
	ldr		r0, =SPI2_SR_TCF_BB
spi2_check_tcf__loop:
	ldr		r1, [r0]
	cmp		r1, #0
	beq		spi2_check_tcf__loop
	mov		r1, #1
	str		r1, [r0]

	bx		lr

.thumb_func
spi2_flush_fifos:
	mov		r1, #1
	ldr		r0, =SPI2_MCR_CLR_TXF_BB
	str		r1, [r0]
	ldr		r0, =SPI2_MCR_CLR_RXF_BB
	str		r1, [r0]
	// RFDF wird nicht zurückgesetzt, obwohl
	// nach CLR_RXF oben die Anzahl der Einträge
	// in der FIFO in SR mit 0 angezeigt wird!
	// DAher ebenfalls manuell zurücksetzen
	// Da das Bit in in diesem Programm nicht
	// gelesen wird, ist das jedoch nicht
	// zwingend notwendig, da es keine
	// negative Nebeneffekte zu geben scheint,
	// wenn es nicht zurückgesetzt wird
	ldr		r0, =SPI2_SR_RFDF_BB
	str		r1, [r0]

	bx		lr

.thumb_func
spi2_init:
	mov		r1, #1
	// Takt einschalten
	ldr		r0, =SIM_SCGC3_SPI2_BB
	str		r1, [r0]
	// SPI zuerst anhalten
	ldr		r0, =SPI2_MCR_HALT_BB
	str		r1, [r0]
	// MCR konfigurieren
	ldr		r0, =SPI2_MCR_INITIAL_CONFIG
	ldr		r1, =SPI2_MCR
	str		r0, [r1]
	// FIFOS entsprechend den Hinweisen ausschalten. MDIS wurde zuvor als
	// Teil der Konfiguration auf 0 gesetzt.
	// Das Programm funktioniert jedoch auch mit aktivierten FIFOS.
	// Obwohl diese nun im MCR ausgeschaltet sind, müssen
	// sie nach dem Transfer manuell "geleert" werden.
	// Dafür wird jeweils die flush Funktion aufgerufen.
	ldr		r0, =SPI2_MCR_DIS_TXF_BB
	str		r1, [r0]
	ldr		r0, =SPI2_MCR_DIS_RXF_BB
	str		r1, [r0]
	// TCR wird nicht benötigt

	// CTAR konfigurieren
	ldr		r0, =SPI2_CTAR_INITIAL_CONFIG 
	ldr		r1, =SPI2_CTAR0
	str		r0, [r1]
	// Flags zurücksetzen
	mov		r1, #0xffffffff
	ldr		r0, =SPI2_SR
	str		r1, [r0]
	// Interrupts ausschalten
	mov		r1, #0
	ldr		r0, =SPI2_RSER
	str		r1, [r0]

	bx		lr
	
.thumb_func
portd_init:
	// Takt einschalten
	ldr		r1, =SIM_PORTD
	mov		r0, #1
	str		r0, [r1]
	// Ports konfigurieren
	mov		r0, #PORTD_PCR_CONFIG_SPI
	ldr		r1, =PORTD_PCR11
	str		r0, [r1]
	ldr		r1, =PORTD_PCR12
	str		r0, [r1]
	ldr		r1, =PORTD_PCR13
	str		r0, [r1]
	ldr		r1, =PORTD_PCR14
	str		r0, [r1]
	ldr		r1, =PORTD_PCR15
	str		r0, [r1]

	bx		lr

// IN r0 mit
// 31:16 0x0000
// 15: 8 MSB mit 8 Bits vom 8.4 Format
//  7: 4 LSB mit 4 Bits vom 8.4 Format
.thumb_func
print_temp:
	push	{r4, lr}

	mov		r4, r0

	lsr		r0, r4, #BYTE_LENGTH
	bl		uart_putByteBase10

	// Hole Bits 7:4 und schiebe sie auf 3:0,
	// damit über sie auf das String Array zugegriffen werden kann.
	// Der Wert muss zusätzlich mit 4 (Wortlänge) multipliziert werden
	// zusammen ergibt das die Notwendigkeit für
	// 2-faches Rechtsschieben
	and		r1, r4, #MASK_BIT_7_4
	lsr		r1, r1, #2
	ldr		r0, =str_addresses_fixed4
	ldr		r0, [r0, r1]
	bl		uart_putString

	ldr		r0, =str_celsius
	bl		uart_putString

	pop		{r4, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
level:					.word	4
adjust_flag:			.word	0
pit1_flag:				.word	0
pit_cycles:				.word	pit_cycles_0, pit_cycles_1, pit_cycles_2, pit_cycles_3, pit_cycles_4
pit_cycles_0:			.word	1875000
pit_cycles_1:			.word	3750000
pit_cycles_2:			.word	7500000
pit_cycles_3:			.word	15000000
pit_cycles_4:			.word	30000000
str_resolution:			.word	str_resolution_8, str_resolution_9, str_resolution_10, str_resolution_11, str_resolution_12
str_addresses_fixed4:	.word	str_fixed4_00, str_fixed4_01, str_fixed4_02, str_fixed4_03, str_fixed4_04, str_fixed4_05, str_fixed4_06, str_fixed4_07, str_fixed4_08, str_fixed4_09, str_fixed4_10, str_fixed4_11, str_fixed4_12, str_fixed4_13, str_fixed4_14, str_fixed4_15
str_new_resolution:		.asciz	"Die Aufloesung wurde angepasst auf "
str_resolution_8:		.asciz	"8-Bit\n"
str_resolution_9:		.asciz	"9-Bit\n"
str_resolution_10:		.asciz	"10-Bit\n"
str_resolution_11:		.asciz	"11-Bit\n"
str_resolution_12:		.asciz	"12-Bit\n"
str_celsius:			.asciz	" gC\n"
str_fixed4_00:			.asciz	",0000"
str_fixed4_01:			.asciz	",0625"
str_fixed4_02:			.asciz	",1250"
str_fixed4_03:			.asciz	",1875"
str_fixed4_04:			.asciz	",2500"
str_fixed4_05:			.asciz	",3125"
str_fixed4_06:			.asciz	",3750"
str_fixed4_07:			.asciz	",4375"
str_fixed4_08:			.asciz	",5000"
str_fixed4_09:			.asciz	",5625"
str_fixed4_10:			.asciz	",6250"
str_fixed4_11:			.asciz	",6875"
str_fixed4_12:			.asciz	",7500"
str_fixed4_13:			.asciz	",8125"
str_fixed4_14:			.asciz	",8750"
str_fixed4_15:			.asciz	",9375"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ	RTC_TSR					,	0x4003D000
.equ	RTC_TAR					,	0x4003D008
.equ	RTC_CR					,	0x4003D010
.equ	RTC_SR					,	0x4003D014
.equ	RTC_LR					,	0x4003D018
.equ	RTC_IER					,	0x4003D01C

.equ	RTC_CR_OSCE_BIT			,	8	// Oscilator Enable
.equ	RTC_CR_SUP_BIT			,	2	// Supervisor
.equ	RTC_CR_SWR_BIT			,	0	// Software Reset

.equ	RTC_SR_TCE_BIT			,	4	// Time Counter Enable

.equ	RTC_IER_TSIE_BIT		,	4	// Time Seconds Interrupt
.equ	RTC_IER_TAIE_BIT		,	2	// Time Alarm Interrupt

__BBREG	RTC_CR_OSCE_BB			,	RTC_CR		,	RTC_CR_OSCE_BIT
__BBREG	RTC_CR_SUP_BB			,	RTC_CR		,	RTC_CR_SUP_BIT
__BBREG	RTC_CR_SWR_BB			,	RTC_CR		,	RTC_CR_SWR_BIT
__BBREG RTC_SR_TCE_BB			,	RTC_SR		,	RTC_SR_TCE_BIT
__BBREG RTC_IER_TSIE_BB			,	RTC_IER		,	RTC_IER_TSIE_BIT
__BBREG RTC_IER_TAIE_BB			,	RTC_IER		,	RTC_IER_TAIE_BIT

.equ	SIM_SCGC6				,	0x4004803C
.equ	SIM_SCGC6_RTC			,	29
__BBREG	SIM_RTC					,	SIM_SCGC6	,	SIM_SCGC6_RTC

.equ	NVIC_ISER2				,	0xE000E108
.equ	SCR_VTOR				,	0xE000ED08

.equ	IRQ_RTC_TAI				,	66
.equ	IRQ_RTC_TSI				,	67

.equ	IVT_RTC_TAI				,	0x148
.equ	IVT_RTC_TSI				,	0x14C

.equ	NVIC_ISR2_RTC_TAI_MASK	,	1 << (IRQ_RTC_TAI % 32)
.equ	NVIC_ISR2_RTC_TSI_MASK	,	1 << (IRQ_RTC_TSI % 32)

.equ	VALUE_235959			,	(24 * 60 * 60 - 1)
.equ	VALUE_5959				,	(60 * 60 - 1)
.equ	VALUE_235955			,	(24 * 60 * 60 - 5)
.equ	VALUE_5955				,	(60 * 60 - 5)

.equ	ASCII_D					,	0x64
.equ	ASCII_H					,	0x68
.equ	ASCII_R					,	0x72
.equ	ASCII_S					,	0x73
.equ	ASCII_P					,	0x70
.equ	ASCII_COLON				,	0x3A
.equ	ASCII_LF				,	0x0A
.equ	ASCII_0					,	0x30

main:
	bl		uart_init
	bl		rtc_init

	ldr		r7, =print_flag
	ldr		r8, =configure_flag
	ldr		r9, =rtc_flag
	mov		r10, #0

	// Direkt mit Ausgabe beginnen und erst
	// dann mit Schleife forsetzen
	b		main_loop__print_date

main_loop:
	ldr		r0, [r9]
	cmp		r0, #0
	// Falls der RTC ausgelöst hat fortfahren.
	// Sonst weiter in der Schleife warten.
	// Als Konsequenz daraus folgt, dass Eingaben immer nur nach "vollen"
	// Sekunden verarbeitet werden.
	beq		main_loop

	// Flag löschen
	str		r10, [r9]
	
main_loop__print_date:
	// Uhrzeit nicht ausgeben, falls gestoppt.
	ldr		r0, [r7]
	cmp		r0, #0
	bne		main_loop__check_input

	// Konfiguration / Format laden
	ldr		r0, [r8]
	cmp		r0, #0

	bne		main_loop__print_1h
	bl		print_date_full

	b		main_loop__check_input
main_loop__print_1h:
	bl		print_date_hour

main_loop__check_input:

	// Eingabe überprüfen
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop

	bl		uart_getChar

	cmp		r0, #ASCII_D
	bne		main_loop__check_1h_mode

	// Modus auf 24-h / HH:MM:SS setzen
	mov		r0, #0
	str		r0, [r8]
	ldr		r0, =str_mode_24
	bl		uart_putString
	
	// RTC wie in Aufgabenstellung gefordert zurücksetzen
	bl		rtc_reset
	b		main_loop__print_date
	
main_loop__check_1h_mode:
	cmp		r0, #ASCII_H
	bne		main_loop__check_reset
	
	// Modus auf 1-h HH:SS, der eigentliche Wert ist ein Offset,
	// damit über ein Array auf verschiedene Werte zugegriffen werden kann
	mov		r0, #4
	str		r0, [r8]
	ldr		r0, =str_mode_1
	bl		uart_putString
	
	// RTC wie in Aufgabenstellung gefordert zurücksetzen
	bl		rtc_reset
	b		main_loop__print_date

main_loop__check_reset:

	cmp		r0, #ASCII_R
	bne		main_loop__check_start_or_stop

	// RTC zurücksetzen und String ausgeben
	bl		rtc_reset
	ldr		r0, =str_reset
	bl		uart_putString
	b		main_loop__print_date

main_loop__check_start_or_stop:

	cmp		r0, #ASCII_S
	bne		main_loop__check_preset

	// Es wird nur die Ausgabe angehalten oder gestartet,
	// der RTC läuft im Hintergrund weiter
	ldr		r0, [r7]
	cmp		r0, #0
	beq		main_loop__stop
	mov		r0, #0
	str		r0, [r7]
	ldr		r0, =str_start
	bl		uart_putString
	b		main_loop__print_date

main_loop__stop:
	mov		r0, #1
	str		r0, [r7]
	ldr		r0, =str_stop
	bl		uart_putString
	b		main_loop

main_loop__check_preset:
	cmp		r0, #ASCII_P
	bne		main_loop

	// RTC anhalten, damit TSR beschrieben werden kann
	ldr		r3, =RTC_SR_TCE_BB
	mov		r0, #0
	str		r0, [r3]
	ldr		r0, =configure_flag
	ldr		r0, [r0]
	ldr		r2, =preset_values
	ldr		r0, [r2, r0]
	ldr		r1, =RTC_TSR
	str		r0, [r1]
	mov		r0, #1
	str		r0, [r3]
	ldr		r0, =str_preset
	bl		uart_putString

	b		main_loop__print_date

.thumb_func
print_date_hour:
	push	{r4-r5, lr}
	// aktuellen Zeitstempel laden
	ldr		r0, =RTC_TSR
	ldr		r1, [r0]

	// Minuten, Sekunden extrahieren
	mov		r0, #60
	sdiv	r4, r1, r0	// r4 == minuten
	mul		r5, r4, r0
	sub		r5, r1, r5	// r5 =0 sekunden

	// Ausgabe der Uhrzeit
	cmp		r4, #10
	itt lt
	movlt	r0, #ASCII_0
	bllt	uart_putChar
	mov		r0, r4
	bl		uart_putByteBase10
	mov		r0, #ASCII_COLON
	bl		uart_putChar
	cmp		r5, #10
	itt lt
	movlt	r0, #ASCII_0
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	mov		r0, #ASCII_LF
	bl		uart_putChar

	pop		{r4-r5, pc}

.thumb_func
print_date_full:
	push	{r4-r6, lr}
	// aktuellen Zeitstempel laden
	ldr		r0, =RTC_TSR
	ldr		r1, [r0]

	// Stunden, Minuten, Sekunden extrahieren
	mov		r0, #3600
	sdiv	r4, r1, r0	// r4 == stunden
	mul		r5, r4, r0
	sub		r1, r1, r5
	mov		r0, #60
	sdiv	r5, r1, r0	// r5 == minuten
	mul		r6, r5, r0
	sub		r6, r1, r6	// r6 =0 sekunden

	// Ausgabe der Uhrzeit
	cmp		r4, #10
	itt lt
	movlt	r0, #ASCII_0
	bllt	uart_putChar
	mov		r0, r4
	bl		uart_putByteBase10
	mov		r0, #ASCII_COLON
	bl		uart_putChar
	cmp		r5, #10
	itt lt
	movlt	r0, #ASCII_0
	bllt	uart_putChar
	mov		r0, r5
	bl		uart_putByteBase10
	mov		r0, #ASCII_COLON
	bl		uart_putChar
	cmp		r6, #10
	itt lt
	movlt	r0, #ASCII_0
	bllt	uart_putChar
	mov		r0, r6
	bl		uart_putByteBase10
	mov		r0, #ASCII_LF
	bl		uart_putChar
	
	pop		{r4-r6, pc}
	
.thumb_func
rtc_reset:
	// RTC anhalten
	ldr		r3, =RTC_SR_TCE_BB
	mov		r0, #0
	str		r0, [r3]
	// Auf 0 setzen
	ldr		r1, =RTC_TSR
	str		r0, [r1]
	// Endwert abhängig von Konfiguration setzen
	ldr		r0, =configure_flag
	ldr		r0, [r0]
	ldr		r2, =end_values
	ldr		r0, [r2, r0]
	ldr		r1, =RTC_TAR
	str		r0, [r1]
	// Wieder starten
	mov		r0, #1
	str		r0, [r3]
	bx		lr

.thumb_func
rtc_tsi_isr:
	ldr		r0, =rtc_flag
	mov		r1, #1
	str		r1, [r0]
	bx		lr

.thumb_func
rtc_tai_isr:
	push	{lr}
	ldr		r0, =str_end
	bl		uart_putString
	// RTC anhalten, damit TSR schreibbar ist
	ldr		r3, =RTC_SR_TCE_BB
	mov		r0, #0
	str		r0, [r3]
	mov		r0, #0
	ldr		r1, =RTC_TSR
	str		r0, [r1]
	ldr		r0, =configure_flag
	ldr		r0, [r0]
	ldr		r2, =end_values
	ldr		r0, [r2, r0]
	ldr		r1, =RTC_TAR
	str		r0, [r1]
	// RTC wieder starten
	mov		r0, #1
	str		r0, [r3]

	pop		{pc}

.thumb_func
rtc_init:
	mov		r2, 0
	mov		r3, 1

	// Takt einschalten
	ldr		r1, =SIM_RTC
	str		r3, [r1]

	// RTC zurücksetzen
	ldr		r0, =RTC_CR_SWR_BB
	str		r3, [r0]
	str		r2, [r0]

	// Schreiben ermöglichen
	ldr		r0, =RTC_CR_SUP_BB
	str		r3, [r0]

	// Oszillator einschalten
	ldr		r0, =RTC_CR_OSCE_BB
	str		r3, [r0]

	// Alarmwert schreiben
	ldr		r0, =RTC_TAR
	ldr		r1, =VALUE_235959
	str		r1, [r0]

	// Startwert schreiben, dadurch werden Flags zurückgesetzt.
	// Allerdings wird trotzdem SR[TAF] gesetzt wodurch
	// dann nach dem Eintragen der ISR diese ausgeführt
	// wird.
	// Dieses Verhalten kann ich trotz mehrfachem Suchem
	// im Handbuch nicht nachvollziehen. Nach Handbuch sollte
	// TAF nur gesetzt werden, wenn TAR == TSR und TSR wird erhöht.
	// Es gilt zwar zwischenzeitlich kurz TAR == TSR == 0,
	// aber TSR wird erst erhöht wenn TSIE == 1 *und* TAR ist bereits
	// auf einen anderen Wert gesetzt.
	// Als Konsequenz daraus trage ich die ISR erst nach dem Starten
	// des RTC ein. Dadurch wird dann allerdings der erste
	// Wert gar nicht ausgeben, weshalb das Datum vor dem
	// Start der Hauptschleife bereits einmal ausgegeben
	// muss.
	ldr		r0, =RTC_TSR
	str		r2, [r0]
	
	// Alarmwert schreiben
	ldr		r0, =RTC_TAR
	ldr		r1, =VALUE_235959
	str		r1, [r0]

	// Bitmaske setzen
	ldr		r0, =NVIC_ISER2
	ldr		r1, [r0]
	orr		r1, r1, #NVIC_ISR2_RTC_TSI_MASK
	orr		r1, r1, #NVIC_ISR2_RTC_TAI_MASK
	str		r1, [r0]

	// Timer einschalten
	ldr		r0, =RTC_SR_TCE_BB
	str		r3, [r0]
	
	// ISR eintragen
	ldr		r0, =SCR_VTOR
	ldr		r1, [r0]
	ldr		r0, =rtc_tsi_isr
	str		r0, [r1, #IVT_RTC_TSI]
	ldr		r0, =rtc_tai_isr
	str		r0, [r1, #IVT_RTC_TAI]

	// Interrupt konfigurieren und einschalten
	ldr		r0, =RTC_IER
	str		r2, [r0]
	ldr		r0, =RTC_IER_TSIE_BB
	str		r3, [r0]
	ldr		r0, =RTC_IER_TAIE_BB
	str		r3, [r0]

	bx		lr

/*** Datenbereich (ab 0x20000000) ***/
.data
print_flag:			.word	0
configure_flag:		.word	0
rtc_flag:			.word	0
preset_values:		.word	VALUE_235955, VALUE_5955
end_values:			.word	VALUE_235959, VALUE_5959
str_mode_24:		.asciz	"24-Stunden-Modus\n"
str_mode_1:			.asciz	"1-Stunden-Modus\n"
str_reset:			.asciz	"Uhr zurueckgesetzt\n"
str_start:			.asciz	"Anzeige an\n"
str_stop:			.asciz	"Anzeige aus\n"
str_end:			.asciz	"Endzeitpunkt erreicht\n"
str_preset:			.asciz	"Uhr vorgestellt\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/*******************************************************************************
*
* RTC
*
*******************************************************************************/

.equ	RTC_TSR						,	0x4003D000
.equ	RTC_TPR						,	0x4003D004
.equ	RTC_TAR						,	0x4003D008
.equ	RTC_CR						,	0x4003D010
.equ	RTC_SR						,	0x4003D014
.equ	RTC_IER						,	0x4003D01C

.equ	RTC_CR_OSCE_BIT				,	8	// Oscilator Enable
.equ	RTC_CR_SUP_BIT				,	2	// Supervisor
.equ	RTC_CR_SWR_BIT				,	0	// Software Reset
.equ	RTC_SR_TCE_BIT				,	4	// Time Counter Enable
.equ	RTC_IER_TSIE_BIT			,	4	// Time Seconds Interrupt
.equ	RTC_IER_TAIE_BIT			,	2	// Time Alarm Interrupt

__BBREG	RTC_CR_OSCE_BB				,	RTC_CR		,	RTC_CR_OSCE_BIT
__BBREG	RTC_CR_SUP_BB				,	RTC_CR		,	RTC_CR_SUP_BIT
__BBREG	RTC_CR_SWR_BB				,	RTC_CR		,	RTC_CR_SWR_BIT
__BBREG RTC_SR_TCE_BB				,	RTC_SR		,	RTC_SR_TCE_BIT
__BBREG RTC_IER_TSIE_BB				,	RTC_IER		,	RTC_IER_TSIE_BIT
__BBREG RTC_IER_TAIE_BB				,	RTC_IER		,	RTC_IER_TAIE_BIT

/*******************************************************************************
*
* PIT
*
*******************************************************************************/

.equ	PIT_MCR						,	0x40037000
.equ	PIT_LDVAL1					,	0x40037110
.equ	PIT_TCTRL1					,	0x40037118
.equ	PIT_TFLG1					,	0x4003711C

.equ	PIT1_INIT					,	3	// TEN und TIE gesetzt


/*******************************************************************************
*
* LED und PTA6
*
*******************************************************************************/

.equ	GPIOA_PDOR					,	0x400FF000
.equ	GPIOA_PDDR					,	0x400FF014

.equ	PORTA_PCR6					,	0x40049018
.equ	PORTA_PCR10					,	0x40049028
.equ	GPIO_MODE					,	0x00000100

.equ	E4_PIN						,	10

/*******************************************************************************
*
* Interrupts
*
*******************************************************************************/
.equ	NVIC_ISER2					,	0xE000E108
.equ	SCR_VTOR					,	0xE000ED08

.equ	IRQ_RTC_TAI					,	66
.equ	IRQ_RTC_TSI					,	67
.equ	IRQ_PIT1					,	69

.equ	IVT_RTC_TAI					,	0x148
.equ	IVT_RTC_TSI					,	0x14C
.equ	IVT_PIT1					,	0x154

.equ	NVIC_ISR2_RTC_TAI_MASK		,	1 << (IRQ_RTC_TAI % 32)
.equ	NVIC_ISR2_RTC_TSI_MASK		,	1 << (IRQ_RTC_TSI % 32)
.equ	NVIC_ISER2_PIT1_MASK		,	1 << (IRQ_PIT1 % 32)

/*******************************************************************************
*
* SIM
*
*******************************************************************************/

.equ	SIM_SCGC5					,	0x40048038
.equ	SIM_SCGC5_PORTA				,	9
__BBREG	SIM_PORTA					,	SIM_SCGC5	,	SIM_SCGC5_PORTA

.equ	SIM_SCGC6					,	0x4004803C
.equ	SIM_SCGC6_RTC				,	29
.equ	SIM_SCGC6_PIT				,	23
__BBREG	SIM_RTC						,	SIM_SCGC6	,	SIM_SCGC6_RTC
__BBREG	SIM_PIT						,	SIM_SCGC6	,	SIM_SCGC6_PIT

/*******************************************************************************
*
* ASCII
*
*******************************************************************************/

.equ	ASCII_LF					,	0x0A
.equ	ASCII_SPACE					,	0x20
.equ	ASCII_PERIOD				,	0x2E
.equ	ASCII_0						,	0x30
.equ	ASCII_COLON					,	0x3A
.equ	ASCII_D						,	0x64
.equ	ASCII_T						,	0x74


// Dieses Wort enthält Bit 0 bis 20 des DCF77 Signals, welche
// vom Programm zu keinem Zeitpunkt verändert werden.
// Abgesehen von den Wetterinformationen, wird auch das
// Umschalten von Sommer- auf Winterzeit, sowie 
// das Einfügen von Schaltsekunden nicht berechnet.
.equ	DCF77_FIXED					,	0x00120000

main:
	bl		uart_init
	bl		pit_init
	bl		gpio_init
	bl		led_init
	bl		rtc_init

	ldr		r0, =str_start
	bl		uart_putString

	bl		create_bit_sequence
	bl		print_date

	// Register vorbelegen
	mov		r6, #0
	ldr		r7, =GPIOA_PDOR
	ldr		r8, =isr_tsr_flag
	ldr		r9, =isr_pit_flag
	mov		r10, #10

	// RTC jetzt starten
	ldr		r0, =RTC_SR_TCE_BB
	mov		r1, #1
	str		r1, [r0]

	// Pro Sekunde wird in der Hauptschleife ein Bit ausgegeben.
	// Um die ganze Sequenz für eine Minute einzusehen, kann man
	// mit dem Debugger auf bit_sequence0 und bit_sequence1 zugreifen und
	// dort die Werte auslesen.

	// Die Schleife wurde so aufgebaut, dass RTC und PIT
	// Vorrang vor Eingaben haben, damit diese möglichst ohne
	// Verzögerung die Ausgabe an LED und GPIO verändern.
	// Dabei wird, selbst wenn in einer Runde der RTC abgearbeitet wurde,
	// im nächsten Schritt trotzdem auch PIT und Eingabe überprüft.
	//
	// Trotzdem entsteht gegebenfalls durch das Abrufen
	// der verschiedenen Flags eine gewisse Verzögerung bei der Ausgabe der
	// Bits. Da im Normalfall PIT, RTC und Input nicht gleichzeitig auftreten,
	// kann man den entstehenden Fehler abschätzen:
	// Die ldr und bXX Aufrufe benötigen zwischen 2 und 5 Takten, dazu kommt
	// jeweils der Vergleich. Wenn man insgesamt von 20 Takten ausgeht beträgt
	// die Abweichung dennoch weniger als 1µs 
main__loop:
	ldr		r0, [r8]
	cmp		r0, #1
	bne		main_loop__handle_pit

	str		r6, [r8]
	bl		handle_second

main_loop__handle_pit:
	ldr		r0, [r9]
	cmp		r0, #1
	bne		main_loop__check_input

	str		r6, [r9]

	// LED und Pin wieder einschalten!
	// An dieser Stelle könnten zusätzlich Takte eingespart werden, wenn man
	// davon ausgeht, dass keine anderen Programm GPIOA_PDOR verändern.
	ldr		r1, [r7]
	bic		r1, r1, #((1 << 6) | (1 << E4_PIN))
	str		r1, [r7]

main_loop__check_input:
	bl		uart_charPresent
	cmp		r0, #0
	
	beq		main__loop

	// Falls eine Eingabe vorliegt, werden
	// RTC und PIT angehalten, damit Überschneidungen
	// bei der Ein- und Ausgabe verhindert werden.
	ldr		r0, =RTC_SR_TCE_BB
	ldr		r2, =PIT_TCTRL1
	str		r6, [r0]
	str		r6, [r2]

	bl		uart_getChar
	cmp		r0, #ASCII_D
	bne		main_loop__check_t

	ldr		r0, =str_prompt_weekday
	bl		uart_putString
main_loop__wait_for_weekday:
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop__wait_for_weekday
	bl		uart_getByteBase10
	ldr		r1, =weekday
	str		r0, [r1]

	ldr		r0, =str_prompt_day
	bl		uart_putString
main_loop__wait_for_day:
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop__wait_for_day
	bl		uart_getByteBase10

	// Die nachfolgenden drei OPs kommen in dieser Form
	// in der Hauptschleife immer wieder vor. Hierbei wird jeweils
	// die Zehnerstelle eines eingegebenen Bytes extrahiert.
	sdiv	r2, r0, r10
	mul		r3, r2, r10
	sub		r0, r0, r3

	ldr		r1, =day
	str		r2, [r1, #0]
	str		r0, [r1, #4]

	ldr		r0, =str_prompt_month
	bl		uart_putString
main_loop__wait_for_month:
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop__wait_for_month
	bl		uart_getByteBase10

	sdiv	r2, r0, r10
	mul		r3, r2, r10
	sub		r0, r0, r3

	ldr		r1, =month
	str		r2, [r1, #0]
	str		r0, [r1, #4]

	ldr		r0, =str_prompt_year
	bl		uart_putString
main_loop__wait_for_year:
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop__wait_for_year
	bl		uart_getByteBase10

	sdiv	r2, r0, r10
	mul		r3, r2, r10
	sub		r0, r0, r3

	ldr		r1, =year
	str		r2, [r1, #0]
	str		r0, [r1, #4]

	ldr		r0, =str_prompt_date_end
	bl		uart_putString

	b		main_loop__input_end

main_loop__check_t:
	cmp		r0, #ASCII_T
	bne		main_loop__input_end

	ldr		r0, =str_prompt_hour
	bl		uart_putString
main_loop__wait_for_hour:
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop__wait_for_hour
	bl		uart_getByteBase10

	sdiv	r2, r0, r10
	mul		r3, r2, r10
	sub		r0, r0, r3

	ldr		r1, =hour
	str		r2, [r1, #0]
	str		r0, [r1, #4]

	ldr		r0, =str_prompt_minute
	bl		uart_putString
main_loop__wait_for_minute:
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop__wait_for_minute
	bl		uart_getByteBase10

	sdiv	r2, r0, r10
	mul		r3, r2, r10
	sub		r0, r0, r3

	ldr		r1, =minute
	str		r2, [r1, #0]
	str		r0, [r1, #4]

	ldr		r0, =second
	str		r6, [r0]
	bl		create_bit_sequence
	bl		print_date

	ldr		r0, =str_prompt_time_end
	bl		uart_putString

	ldr		r0, =RTC_TSR
	str		r6, [r0]

main_loop__input_end:
	// RTC wieder starten
	ldr		r0, =RTC_SR_TCE_BB
	mov		r1, #1
	str		r1, [r0]

	b		main__loop

.thumb_func
pit_init:
	mov		r2, #0
	mov		r3, #1
	// Takt schalten
	ldr		r0, =SIM_PIT
	str		r3, [r0]
	// ISR eintragen
	ldr		r0, =SCR_VTOR
	ldr		r1, [r0]
	ldr		r0, =pit_isr
	str		r0, [r1, #IVT_PIT1]
	// MCR
	ldr		r0, =PIT_MCR
	str		r3, [r0]
	// Bitmaske setzen
	ldr		r0, =NVIC_ISER2
	ldr		r1, [r0]
	orr		r1, r1, #NVIC_ISER2_PIT1_MASK
	str		r1, [r0]

	bx		lr

.thumb_func
led_init:
	// Takt schalten
	mov		r1, #1
	ldr		r0, =SIM_PORTA
	str		r1, [r0]

	// GPIO Data Direction konfigurieren
	// orr setzt das Bit auf Output
	// bic löscht es und konfiguriert damit für Input
	ldr		r1, =GPIOA_PDDR
	ldr		r0, [r1]
	orr		r0, r0, #(1 << E4_PIN)
	str		r0, [r1]

	// GPIO Output löschen (notwendig um Aufleuchten zu vermeiden)
	ldr		r0, =GPIOA_PDOR
	ldr		r1, [r0]
	orr		r1, r1, #(1 << E4_PIN)
	str		r1, [r0]

	// LEDs konfigurieren
	ldr		r1, =GPIO_MODE
	ldr		r0, =PORTA_PCR10
	str		r1, [r0]

	bx		lr

.thumb_func
gpio_init:
	// Takt schalten
	mov		r1, #1
	ldr		r0, =SIM_PORTA
	str		r1, [r0]

	// GPIO Data Direction konfigurieren
	ldr		r1, =GPIOA_PDDR
	ldr		r0, [r1]
	orr		r0, r0, #(1 << 6)
	str		r0, [r1]

	// Konfigurieren
	ldr		r1, =GPIO_MODE
	ldr		r0, =PORTA_PCR6
	str		r1, [r0]

	bx		lr

.thumb_func
rtc_init:

	mov		r2, 0
	mov		r3, 1

	// Takt einschalten
	ldr		r1, =SIM_RTC
	str		r3, [r1]

	// RTC zurücksetzen
	ldr		r0, =RTC_CR_SWR_BB
	str		r3, [r0]
	str		r2, [r0]

	// Schreiben ermöglichen
	ldr		r0, =RTC_CR_SUP_BB
	str		r3, [r0]

	// Oszillator einschalten
	ldr		r0, =RTC_CR_OSCE_BB
	str		r3, [r0]

	// Interrupt konfigurieren und einschalten
	ldr		r0, =RTC_IER
	str		r2, [r0]
	ldr		r0, =RTC_IER_TSIE_BB
	str		r3, [r0]
	ldr		r0, =RTC_IER_TAIE_BB
	str		r3, [r0]

	// Startwert schreiben, dadurch
	// werden Flags zurückgesetzt
	ldr		r0, =RTC_TSR
	str		r2, [r0]

	// Alarmwert schreiben
	ldr		r0, =RTC_TAR
	ldr		r1, =(24 * 60 * 60 - 1) // 235959
	str		r1, [r0]

		// ISR eintragen
	ldr		r0, =SCR_VTOR
	ldr		r1, [r0]
	ldr		r0, =rtc_tsi_isr
	str		r0, [r1, #IVT_RTC_TSI]
	ldr		r0, =rtc_tai_isr
	str		r0, [r1, #IVT_RTC_TAI]

	// Bitmaske setzen
	ldr		r0, =NVIC_ISER2
	ldr		r1, [r0]
	orr		r1, r1, #NVIC_ISR2_RTC_TSI_MASK
	orr		r1, r1, #NVIC_ISR2_RTC_TAI_MASK
	str		r1, [r0]

	bx		lr

.thumb_func
rtc_tsi_isr:
	ldr		r0, =isr_tsr_flag
	mov		r1, #1
	str		r1, [r0]

	bx		lr

.thumb_func
handle_second:
	push	{r4, lr}

	ldr		r1, =second
	ldr		r0, [r1]
	cmp		r0, #59
	beq		handle_second__59

	// Nun muss ein Bit aus der Sequenz geholt werden.
	// Dafür wird diese um eine Stelle nach rechts geschoben!
	ldr		r1, =bit_sequence1
	ldr		r2, [r1]
	and		r3, r2, #1
	lsl		r3, r3, #31
	lsr		r2, r2, #1
	str		r2, [r1]
	ldr		r1, =bit_sequence0
	ldr		r2, [r1]
	// Der Verschiebevorgang läuft noch,
	// aber das Bit wird schon in r0 extrahiert
	and		r0, r2, #1
	lsr		r2, r2, #1
	orr		r2, r2, r3
	str		r2, [r1]

	mov		r4, r0

	// Anzahl der Takte für Verzögerung Abhängig vom Bit bestimmen
	ldr		r3, =PIT_LDVAL1
	ldr		r1, =pit_cycles
	lsl		r2, r0, #2
	ldr		r1, [r1, r2]
	ldr		r1, [r1]
	str		r1, [r3]
	// PIT1 starten
	mov		r1, #PIT1_INIT
	ldr		r2, =PIT_TCTRL1
	str		r1, [r2]

	// LED und PTA6 für Start von Bit ausschalten
	ldr		r3, =GPIOA_PDOR
	ldr		r1, [r3]
	orr		r1, r1, #((1 << 6) | (1 << E4_PIN))
	str		r1, [r3]

	// Ausgabe des Zeichens auf Terminal,
	// es gilt ASCII_0 + (0|1) == ASCII_0|ASCII_1
	add		r0, r0, #ASCII_0
	bl		uart_putChar
	mov		r0, #ASCII_LF
	bl		uart_putChar

	ldr		r1, =second
	ldr		r0, [r1]
	add		r0, r0, #1
	str		r0, [r1]

	b		handle_second__end

handle_second__59:
	mov		r0, #0
	str		r0, [r1]

	bl		bump_minute
	bl		create_bit_sequence
	bl		print_date

handle_second__end:
	pop		{r4, pc}

// Aufgrund von diversen Problemen bei
// der Realisierung dieses Programms habe ich mich
// dazu entschlossen, den RTC möglichst ohne
// Unterbrechung laufen zu lassen. Nach dem Umschreiben des
// Programms aufgrund der vorhandenen Fehler, war eine Auswertung
// von TSR jedoch gar nicht mehr notwendig, sodass auch TAR gar nicht mehr
// benutzt wird. Das RTC wird nur dafür benutzt, pro Sekunde jeweils einmal
// die ISR aufzurufen. Leider konnte ich den Code aus V7-1 nicht
// sinnvoll integrieren. Da keine echte Zeit aus dem TSR gelesen wird, kann
// dort eigentlich der Maximalwert erreicht werden, sodass TAI erst nach
// ca. 47000 Tagen auslösen würde!
// Trotzdem bleibt die Konfiguration an dieser Stelle erhalten.
.thumb_func
rtc_tai_isr:
	mov		r0, #0
	ldr		r3, =RTC_SR_TCE_BB
	str		r0, [r3]
	ldr		r1, =RTC_TSR
	str		r0, [r1]
	ldr		r0, =RTC_TAR
	ldr		r1, =(24 * 60 * 60 - 1)	// 235959
	str		r1, [r0]
	mov		r0, #1
	str		r0, [r3]
	bx		lr

.thumb_func
pit_isr:
	mov		r0, #1
	// Interrupt löschen
	ldr		r1, =PIT_TFLG1
	str		r0, [r1]

	// PIT1 ausschalten (!)
	mov		r2, #0
	ldr		r1, =PIT_TCTRL1
	str		r2, [r1]

	ldr		r1, =isr_pit_flag
	str		r0, [r1]

	bx		lr


// Die Funktion erhöht nur die Minuten und, 
// nur wenn diese auch "voll" sind, auch die Stunden.
// Wochen- und Kalendertage, Monate und Jahre
// werden aufgrund der Komplexität bei der Bestimmung
// des richtigen Datums nicht weitergesetzt.
// In der Aufgabenstellung heißt es, dass der Wochentag
// frei zu bestimmen ist. Ich gehe daher, aufgrund
// des Kontextes davon aus, dass dies auch für das Datum gilt.
//
// In V2-2 und V2-3 habe ich bereits eine "funktionierende" Uhr geschrieben,
// welche auch das Datum einigermaßen richtig beachtet. Schaltsekunden, 
// Schaltjahre, Sommerzeit, Wochentage in Kombination mit der Anforderung 
// der Ausgabe als BCD statt als normale Binärzahl überfordert mich jedoch
// schlicht, weshalb ich auf einen Versuch der Implementierung verzichte.
//
// Grundsätzlich wäre es wahrscheinlich möglich, wenn auch
// unübersicthlich, das nachfolengende Schema auf zu erweitern.
.thumb_func
bump_minute:
	ldr		r0, =minute
	ldr		r1, [r0, #0]	// zehner
	ldr		r2, [r0, #4]	// einer

	cmp		r2, #9
	beq		bump_minute__next_tens
	add		r2, r2, #1
	str		r2, [r0, #4]

	b		bump_minute_end
bump_minute__next_tens:
	mov		r2, #0
	str		r2, [r0, #4]
	cmp		r1, #5
	beq		bump_minute__next_hour
	add		r1, r1, #1
	str		r1, [r0, #0]

	b		bump_minute_end

bump_minute__next_hour:
	mov		r1, #0
	str		r1, [r0, #0]

	ldr		r0, =hour
	ldr		r1, [r0, #0]	// zehner
	ldr		r2, [r0, #4]	// einer

	cmp		r1, #2
	beq		bump_minute__maybe_next_day
	cmp		r2, #9
	beq		bump_minute__next_tens_hour

	add		r2, r2, #1
	str		r2, [r0, #4]

	b		bump_minute_end

bump_minute__maybe_next_day:
	cmp		r2, #3
	beq		bump_minute__next_day
	add		r2, r2, #1
	str		r2, [r0, #4]

	b		bump_minute_end

bump_minute__next_day:
	mov		r1, #0

	str		r1, [r0, #0]
	str		r1, [r0, #4]

	b		bump_minute_end

bump_minute__next_tens_hour:
	mov		r2, #0
	add		r1, r1, #1

	str		r1, [r0, #0]
	str		r2, [r0, #4]

bump_minute_end:
	bx		lr

// Da ich große Probleme beim Erstellen
// dieser Funktion hatte, enthält sie nun sehr viele
// Wiederholungen. Die Idee besteht darin, immer einen
// Wert in einen Teil der Sequenz einzutragen und dann
// weiterzuschieben. Die Sequenz wird dadurch verteilt
// auf zwei Worte nach folgendem Schema erstellt:
//                             JJJJ
//                         JJJJjjjj
//                        JJJJjjjjM
//                    JJJJjjjjMmmmm
//                 JJJJjjjjMmmmmWWW
//               JJJJjjjjMmmmmWWWDD
//           JJJJjjjjMmmmmWWWDDdddd
//          PJJJJjjjjMmmmmWWWDDdddd
//         PJJJJjjjjMmmmmWWWDDdddd
//       PJJJJjjjjMmmmmWWWDDdddd HH
//   PJJJJjjjjMmmmmWWWDDdddd HHhhhh
//   PJJJJjjjjMmmmmWWWDDddddPHHhhhh
//      PJJJJjjjjMmmmmWWWDDddddPHHh seq1 fertig
//                              hhh ist Übertrag aus lsr vorher
//                          hhh    
//                          hhh MMM
//                      hhh MMMmmmm
//                      hhhPMMMmmmm
// hhhPMMMmmmm                     
// hhhPMMMmmmm100100000000000000000 seq0 fertig
//
// Eine folge dieses Designs liegt darin, dass
// die Werte jeweils als eigener Teil im Speicher
// vorliegen müssen. Ich hätte gerne die Funktionalität
// aus 7-1 benutzt, um jeweils aus einem Zeitstempel
// alle Daten zu berechnen, da ich jedoch beim Realisieren
// immer wieder verschiedene Probleme hatte, habe ich mich
// dazu entschieden einen einfachen, wenn auch sich häufig
// wiederholenden Ansatz zu wählen.
.thumb_func
create_bit_sequence:
	mov		r2, #0
	mov		r3, #0

	ldr		r0, =year
	ldr		r1, [r0]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #4
	ldr		r0, =year
	ldr		r1, [r0, #4]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #1
	ldr		r0, =month
	ldr		r1, [r0, #0]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #4
	ldr		r0, =month
	ldr		r1, [r0, #4]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #3
	ldr		r0, =weekday
	ldr		r1, [r0, #0]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #2
	ldr		r0, =day
	ldr		r1, [r0, #0]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #4
	ldr		r0, =day
	ldr		r1, [r0, #4]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	// datum Parität schreiben
	and		r3, r3, #1
	lsl		r3, r3, #22
	orr		r2, r2, r3

	// Parität zurücksetzen
	mov		r3, #0
	// Platz für Parität lassen!
	lsl		r2, r2, #3
	ldr		r0, =hour
	ldr		r1, [r0, #0]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #4
	ldr		r0, =hour
	ldr		r1, [r0, #4]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	// Stunde Parität schreiben
	and		r3, r3, #1
	lsl		r3, r3, #6
	orr		r2, r2, r3

	and		r1, r2, #7
	lsr		r2, r2, #3
	ldr		r0, =bit_sequence1
	str		r2, [r0]

	mov		r2, r1
	mov		r3, #0

	// Platz für Parität lassen!
	lsl		r2, r2, #4
	ldr		r0, =minute
	ldr		r1, [r0, #0]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	lsl		r2, r2, #4
	ldr		r0, =minute
	ldr		r1, [r0, #4]
	orr		r2, r2, r1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0
	lsr		r1, r1, #1

	and		r0, r1, #1
	add		r3, r3, r0

	// Minute Parität schreiben
	and		r3, r3, #1
	lsl		r3, r3, #7
	orr		r2, r2, r3

	lsl		r2, r2, #21
	mov		r3, #DCF77_FIXED
	orr		r2, r2, r3
	ldr		r0, =bit_sequence0
	str		r2, [r0]

	bx		lr

.thumb_func
print_date:
	push	{r4, lr}
	ldr		r0, =weekday
	ldr		r0, [r0]
	lsl		r0, r0, #2
	ldr		r1, =weekdays
	ldr		r0, [r1, r0]
	bl		uart_putString

	ldr		r4, =day
	ldr		r0, [r4, #0]
	bl		uart_putByteBase10
	ldr		r0, [r4, #4]
	bl		uart_putByteBase10
	mov		r0, #ASCII_PERIOD
	bl		uart_putChar
	ldr		r4, =month
	ldr		r0, [r4, #0]
	bl		uart_putByteBase10
	ldr		r0, [r4, #4]
	bl		uart_putByteBase10
	mov		r0, #ASCII_PERIOD
	bl		uart_putChar
	ldr		r4, =year
	ldr		r0, [r4, #0]
	bl		uart_putByteBase10
	ldr		r0, [r4, #4]
	bl		uart_putByteBase10

	mov		r0, #ASCII_SPACE
	bl		uart_putChar

	ldr		r4, =hour
	ldr		r0, [r4, #0]
	bl		uart_putByteBase10
	ldr		r0, [r4, #4]
	bl		uart_putByteBase10
	mov		r0, #ASCII_COLON
	bl		uart_putChar
	ldr		r4, =minute
	ldr		r0, [r4, #0]
	bl		uart_putByteBase10
	ldr		r0, [r4, #4]
	bl		uart_putByteBase10

	ldr		r0, =str_date_end
	bl		uart_putString

	pop		{r4, pc}

.data
isr_pit_flag:			.word	0
isr_tsr_flag:			.word	0
weekdays:				.word	0, weekday_mo, weekday_di, weekday_mi, weekday_do, weekday_fr, weekday_sa, weekday_so
second:					.word	0
minute:					.word	5, 9
hour:					.word	2, 3
day:					.word	2, 0
month:					.word	1, 1
year:					.word	2, 3
weekday:				.word	1
bit_sequence0:			.word	0x0
bit_sequence1:			.word	0x0
pit_cycles:				.word	pit_cycles_0, pit_cycles_1
pit_cycles_0:			.word	2500000
pit_cycles_1:			.word	5000000
weekday_mo:				.asciz	"Mo., "
weekday_di:				.asciz	"Di., "
weekday_mi:				.asciz	"Mi., "
weekday_do:				.asciz	"Do., "
weekday_fr:				.asciz	"Fr., "
weekday_sa:				.asciz	"Sa., "
weekday_so:				.asciz	"So., "
str_date_end:			.asciz	" Uhr\n"
str_start:				.asciz	"Die Uhr wird gestartet\nd eingeben um das Datum zu aendern\nt eingeben um die Uhr zu stellen\n\nACHTUNG: Eingaben werden nicht auf Plausibilitaet ueberprueft!\n\n"
str_prompt_weekday:		.asciz	"Bitte den Wochentag als Zahl im Format XX (01 - 07) eingeben: \n"
str_prompt_day:			.asciz	"Bitte den Kalendertag als Zahl im Format XX (01 - 31) eingeben: \n"
str_prompt_month:		.asciz	"Bitte den Monat als Zahl im Format XX (01 - 12) eingeben: \n"
str_prompt_year:		.asciz	"Bitte das Jahr als Zahl im Format XX (00 - 99) eingeben: \n"
str_prompt_date_end:	.asciz	"Das Datum wurde geaendert und wird nach dem Ablauf der aktuellen Sequenz benutzt\n"
str_prompt_hour:		.asciz	"Bitte die Stunde als Zahl im Format XX (00 - 23) eingeben: \n"
str_prompt_minute:		.asciz	"Bitte die Minute als Zahl im Format XX (00 - 59) eingeben: \n"
str_prompt_time_end:	.asciz	"Die Zeit wurde geaendert, die Sequenz wird neugestartet\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// SIM

.equ	SIM_SCGC6				,	0x4004803C
.equ	SIM_SCGC6_FTM0			,	24
__BBREG	SIM_FTM0				,	SIM_SCGC6		,	SIM_SCGC6_FTM0

// Interrupts

.equ	NVIC_ISER1				,	0xe000e104
.equ	SCR_VTOR				,	0xE000ED08

.equ	IRQ_FTM0				,	62

.equ	IVT_FTM0				,	0x00000138

.equ	NVIC_ISER1_FTM0_MASK	,	1 << (IRQ_FTM0 % 32)

// FTM0

.equ	FTM0_SC					,	0x40038000
.equ	FTM0_CNT				,	0x40038004	// 15:0
.equ	FTM0_MOD				,	0x40038008	// 15:0
.equ	FTM0_C3SC				,	0x40038024
.equ	FTM0_C3V				,	0x40038028	// 15:0
.equ	FTM0_CNTIN				,	0x4003804C	// 15:0
// Handbuch zum Starten des FTM:
// When the FTM clock is initially selected, by writing a non-zero value to the CLKS bits,
// the FTM counter starts with the value 0x0000. To avoid this behavior, before the first
// write to select the FTM clock, write the new value to the the CNTIN register and then
// initialize the FTM counter by writing any value to the CNT register.
.equ	FTM0_STATUS				,	0x40038050	// ONLY IN COMBINE
.equ	FTM0_MODE				,	0x40038054
.equ	FTM0_SYNC				,	0x40038058	// 0
.equ	FTM0_OUTINIT			,	0x4003805C	// 0
.equ	FTM0_OUTMASK			,	0x40038060	// 0
.equ	FTM0_COMBINE			,	0x40038064	// 0
.equ	FTM0_DEADTIME			,	0x40038068	// 0
.equ	FTM0_EXTTRIG			,	0x4003806C	// 0
.equ	FTM0_POL				,	0x40038070	// 0
.equ	FTM0_FMS				,	0x40038074	// 0
.equ	FTM0_FILTER				,	0x40038078	// 0
.equ	FTM0_FLTCTRL			,	0x4003807C	// 0
.equ	FTM0_QDCTRL				,	0x40038080	// 0
.equ	FTM0_CONF				,	0x40038084	// 0
.equ	FTM0_FLTPOL				,	0x40038088	// 0
.equ	FTM0_SYNCONF			,	0x4003808C	// 0
.equ	FTM0_INVCTRL			,	0x40038090	// 0
.equ	FTM0_SWOCTRL			,	0x40038094	// 0	ldr
.equ	FTM0_PWMLOAD			,	0x40038098	// 0

.equ	FTM0_SC_BIT_TOF			,	7
.equ	FTM0_SC_BIT_TOIE		,	6
.equ	FTM0_SC_BIT_CLKS0		,	3
.equ	FTM0_C3SC_BIT_CHF		,	7	// CLEAR!
.equ	FTM0_C3SC_BIT_CHIE		,	6	// 1
.equ	FTM0_C3SC_BIT_MSB		,	5
.equ	FTM0_C3SC_BIT_ELSB		,	3
.equ	FTM0_C3SC_BIT_ELSA		,	2
.equ	FTM0_MODE_BIT_WPDIS		,	2	// 1
.equ	FTM0_MODE_BIT_INIT		,	1	// W1 R0

__BBREG	FTM0_WPDIS				,	FTM0_MODE		,	FTM0_MODE_BIT_WPDIS
__BBREG	FTM0_INIT				,	FTM0_MODE		,	FTM0_MODE_BIT_INIT

// PTA6

.equ	SIM_SCGC5				,	0x40048038
.equ	SIM_SCGC5_PORTA			,	9
__BBREG	SIM_PORTA				,	SIM_SCGC5		,	SIM_SCGC5_PORTA

.equ	GPIOA_PDOR				,	0x400FF000
.equ	GPIOA_PDDR				,	0x400FF014

.equ	PORTA_PCR6				,	0x40049018
.equ	FTM_MODE				,	0x00000300		// FTM0_CH3 ALT_3 S.245

// ASCII

.equ	ASCII_LF				,	0x0A
.equ	ASCII_PLUS				,	0x2B
.equ	ASCII_MINUS				,	0x2D
.equ	ASCII_0					,	0x30
.equ	ASCII_9					,	0x39

// "The FTM period when using up counting is (MOD – CNTIN + 0x0001) × period of the
// FTM counter clock."
// Gesucht also:
// (MOD - 0 + 1) * 1/25000000s = 1/1000s
// <> MOD + 1 = 25000000 / 1000 = 25000
// <> MOD = 24999
.equ	FTM0_PERIOD				,	25000
.equ	FTM0_MOD_VALUE			,	FTM0_PERIOD - 1
.equ	FTM0_5_PERCENT			,	FTM0_PERIOD / 20
.equ	FTM0_10_PERCENT			,	FTM0_PERIOD / 10

.equ	FTM0_SC_INIT_CONFIG		,	(1 << FTM0_SC_BIT_TOIE | 1 << FTM0_SC_BIT_CLKS0)

// Zunächst Channel Interrupt aktivieren, Modus auf EPWM Hi-true setzen
.equ	FTM0_C3SC_INIT_CONFIG	,	(1 << FTM0_C3SC_BIT_CHIE | 1 << FTM0_C3SC_BIT_MSB | 1 << FTM0_C3SC_BIT_ELSB )

main:
	bl		uart_init
	bl		gpio_init
	bl		ftm_init

	ldr		r4, =polarity
	ldr		r5, =level
	ldr		r6, =polarity_flag
	ldr		r7, =level_flag
	ldr		r8, =str_prompt

	mov		r0, r8
	bl		uart_putString
main_loop:
	bl		uart_charPresent
	cmp		r0, #0
	beq		main_loop

	bl		uart_getChar

	// Eingabe echo
	mov		r9, r0
	bl		uart_putChar
	mov		r0, #ASCII_LF
	bl		uart_putChar
	mov		r0, r9

	// Falls r0 < ASCII_0 oder > ASCII_9, kann keine Leveleingabe vorliegen
	cmp		r0, #ASCII_0
	blt		main_loop_PLUS
	cmp		r0, #ASCII_9
	bgt		main_loop_PLUS

	// Wert holen und zwischenspeichern, durch das Setzen des User Flags
	// wird dann in der ISR der Wechsel ausgelöst.
	sub		r0, r0, #ASCII_0
	str		r0, [r5]
	mov		r0, #1
	str		r0, [r7]
	b		main_loop_end

main_loop_PLUS:
	cmp		r0, #ASCII_PLUS
	bne		main_loop_MINUS

	mov		r0, #0
	str		r0, [r4]
	mov		r0, #1
	str		r0, [r6]
	b		main_loop_end

main_loop_MINUS:
	cmp		r0, #ASCII_MINUS
	bne		main_loop_end

	mov		r0, #1
	str		r0, [r4]
	mov		r0, #1
	str		r0, [r6]
main_loop_end:
	mov		r0, r8
	bl		uart_putString
	b		main_loop

.thumb_func
gpio_init:
	// Takt schalten
	mov		r1, #1
	ldr		r0, =SIM_PORTA
	str		r1, [r0]

	// GPIO Data Direction konfigurieren
	ldr		r1, =GPIOA_PDDR
	ldr		r0, [r1]
	orr		r0, r0, #(1 << 6)
	str		r0, [r1]

	// Konfigurieren
	ldr		r1, =FTM_MODE // Alt 3 laut Handbuch
	ldr		r0, =PORTA_PCR6
	str		r1, [r0]

	bx		lr

.thumb_func
ftm_init:
	mov		r2, #0
	mov		r3, #1
	// Takt schalten
	ldr		r0, =SIM_FTM0
	str		r3, [r0]
	
	// ISR eintragen
	ldr		r0, =SCR_VTOR
	ldr		r1, [r0]
	ldr		r0, =ftm_isr
	str		r0, [r1, #IVT_FTM0]
	// Bitmaske setzen
	ldr		r0, =NVIC_ISER1
	ldr		r1, [r0]
	orr		r1, r1, #NVIC_ISER1_FTM0_MASK
	str		r1, [r0]

	// Bearbeiten erlauben
	ldr		r0, =FTM0_WPDIS
	str		r3, [r0]

	// nun zunächst ausschalten
	ldr		r0, =FTM0_SC
	str		r2, [r0]

	// Alle Startwerte schreiben
	ldr		r0, =FTM0_CNTIN
	str		r2, [r0]
	// Schreiben irgendeines Wertes setzt CNT au CNTIN beim Update
	ldr		r0, =FTM0_CNT
	str		r2, [r0]
	ldr		r0, =FTM0_MOD
	ldr		r1, =FTM0_MOD_VALUE
	str		r1, [r0]
	ldr		r0, =FTM0_C3V
	ldr		r1, =FTM0_5_PERCENT
	str		r1, [r0]

	// Mode konfigurieren, insbesondere FTMEN == 0 schreiben!
	ldr		r0, =FTM0_MODE
	str		r2, [r0]

	// Sync vollständig ausschalten
	ldr		r0, =FTM0_SYNC
	str		r2, [r0]

	// Outinit resetten
	ldr		r0, =FTM0_OUTINIT
	str		r2, [r0]

	// Trigger, Faults, Filter, Deadtime, erweiterte Funktionalität, etc.
	// abstellen! - Trotz intensiver Lektüre bin ich mir nicht ganz sicher,
	// welche Register wann aktiv sind. Aufgrund der Tatsache, dass die ISR
	// mit dieser Konfiguration jedoch zu funktionieren scheint, übernehme ich
	// sie in die Abgabe.
	ldr		r0, =FTM0_OUTMASK
	str		r2, [r0]
	ldr		r0, =FTM0_COMBINE
	str		r2, [r0]
	ldr		r0, =FTM0_DEADTIME
	str		r2, [r0]
	ldr		r0, =FTM0_EXTTRIG
	str		r2, [r0]
	ldr		r0, =FTM0_POL
	str		r2, [r0]
	ldr		r0, =FTM0_FMS
	ldr		r1, [r0]	// einmal lesen, damit hängende Interrupts gelöscht werden
	str		r2, [r0]
	ldr		r0, =FTM0_FILTER
	str		r2, [r0]
	ldr		r0, =FTM0_FLTCTRL
	str		r2, [r0]
	ldr		r0, =FTM0_QDCTRL
	str		r2, [r0]
	ldr		r0, =FTM0_CONF
	str		r2, [r0]
	ldr		r0, =FTM0_FLTPOL
	str		r2, [r0]
	ldr		r0, =FTM0_SYNCONF
	str		r2, [r0]
	ldr		r0, =FTM0_INVCTRL
	str		r2, [r0]
	ldr		r0, =FTM0_SWOCTRL
	str		r2, [r0]
	ldr		r0, =FTM0_PWMLOAD
	str		r2, [r0]

	// Lesen und dann erst schreiben, damit eventuell hänge Interrupts
	// gelöscht werden.
	ldr		r0, =FTM0_C3SC
	ldr		r1, [r0]
	// Startkonfiguration mit Channel Interrupt und Modus EPWM Hi-true
	mov		r1, #FTM0_C3SC_INIT_CONFIG
	str		r1, [r0]

	// Channel Output starten!
	ldr		r0, =FTM0_INIT
	str		r3, [r0]

	// Jetzt SC lesen und finale Konfiguration mit CLKS setzen,
	// wodurch FTM gestartet wird
	ldr		r0, =FTM0_SC
	ldr		r1, [r0]
	mov		r1, #FTM0_SC_INIT_CONFIG
	str		r1, [r0]

	bx		lr

.thumb_func
ftm_isr:

	// Leider scheint die ISR etwas instabil zu laufen, zumindest wenn man
	// den Debugger einsetzt. Die Ursache dafür liegt meiner Meinung nach darin,
	// dass das Modul sich die noch hängenden Interrupts merkt. Bei der "hohen"
	// Frequenz der Interrupts entsteht so schnell eine sehr lange Schlange,
	// die wahrscheinlich begrenzt ist.
	// Eigentlich muss nach der Beschreibung im Handbuch
	// nur überprüft werden, welcher Interrupt vorliegt,
	// damit dieses abgearbeitet werden kann.
	// Stattdessen setze ich jedoch bei jedem Interrupt jedes Flag
	// zurück und prüfe dann zusätzlich die User Flags.
	// Um trotzdem den Debugger ausführen zu können wurden die
	// markierten Stellen ausgeklammertn und einige hinzugefügt.
	// Dann kann festgestellt werden, dass die ISR grundsätzlich funktioniert:
	// Setzt man Breakpoints jeweils nach dem Lesen der User Flags, so werden
	// diese nur dann ausgeführt, wenn auch tatsächlich Eingaben vorliegen.

	// Die ISR selbst wird in jedem Fall auch dann ausgeführt, wenn keine Eingabe erfolgt ist.

	// SC lesen und dann schreiben, damit TOF zurückgesetzt wird!
	ldr		r0, =FTM0_SC
	ldr		r1, [r0]

//	and		r2, r1, #(1 << FTM0_SC_BIT_TOF)
//	cmp		r2, #0
//	beq		ftm_isr_check_channel

	bic		r1, r1, #(1 << FTM0_SC_BIT_TOF)
	str		r1, [r0]

	ldr		r0, =polarity_flag
	ldr		r1, [r0]
	cmp		r1, #0
// hinzugefügt
	beq		ftm_isr_check_channel
//	beq		ftm_isr_end

	mov		r1, #0
	str		r1, [r0]

	ldr		r0, =polarity
	ldr		r1, [r0]
	ldr		r0, =FTM0_C3SC
	ldr		r2, [r0]
	// Bit löschen und durch die Verschiebung von 0 oder 1
	// abhängig von Wert aus =polarity den neuen, zu schreibenden Wert bestimmen.
	bic		r2, r2, #(1 << FTM0_C3SC_BIT_ELSA)
	lsl		r1, r1, #FTM0_C3SC_BIT_ELSA
	orr		r2, r2, r1	
	str		r2, [r0]

//	b		ftm_isr_end

ftm_isr_check_channel:

	// Auch hier lesen und dann schreiben, damit Bit zurückgesetzt wird!
	ldr		r0, =FTM0_C3SC
	ldr		r1, [r0]

//	and		r2, r1, #(1 << FTM0_C3SC_BIT_CHF)
//	cmp		r2, #0
//	beq		ftm_isr_end

	bic		r1, r1, #(1 << FTM0_C3SC_BIT_CHF)
	str		r1, [r0]

	ldr		r0, =level_flag
	ldr		r1, [r0]
	cmp		r1, #0

	beq		ftm_isr_end

	mov		r1, #0
	str		r1, [r0]

	// Eingabewert * 10% + 5% berechnen und schreiben
	ldr		r0, =level
	ldr		r1, [r0]
	ldr		r2, =FTM0_10_PERCENT
	ldr		r3, =FTM0_C3V
	// Anmerkung ldr oben:
	// Ist es richtig, dass ldr nur einen Takt benötigt, falls
	// auf das Register in welches der Wert geladen wird nicht in der direkt
	// darauf folgenden OP zurückgegriffen wird?
	
	mul		r1, r1, r2
	ldr		r2, =FTM0_5_PERCENT
	add		r1, r1, r2
	str		r1, [r3]

ftm_isr_end:
	bx		lr

.data
polarity:		.word	0
level:			.word	0
polarity_flag:	.word	0
level_flag:		.word	0
str_prompt:		.asciz	"> "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklaration
.equ COUNTER, 0x10 // Anzahl der Schleifendurchläufe

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/* 
* ---Registerbelegungen --- 
* r5: Zeiger auf aktuelle Speicherstelle im Array
* r6: Kosten fuer Zeitmessung in Taktzyklen
* r7: Timer Startwert
* r8: Timer Endwert
* r9: (aktuelles) Maximum
*/

main:	
	// serielle Schnittstelle und Timer initialisieren
	bl uart_init
	bl pit3_init
	
	// Kosten fuer Zeitmessung bestimmen
	bl pit3_getval
	mov r6, r0
	bl pit3_getval
	sub r6, r6, r0
		
loop_program:

	// Einlesen von 16 Bytes
	ldr r0, =str_eingabe 	// Zeiger auf String laden
	bl uart_putString 		// String ausgeben
	
	mov r4, #COUNTER 		// Zähler laden
	ldr r5, =bytearray 		// Adresse laden
	
	// Eingabeschleife
loop_eingabe:
	ldr r0, =str_prompt
	bl uart_putString		// Ausgabe für Werteabfrage
	
	bl uart_getByte 		// ein Byte einlesen
	strb r0, [r5], #1 		// im Array ablegen und Adresse in R5 um eins erhöhen
	bl uart_putByte			// das Byte ausgeben
	subs r4, r4, #1			// Zähler um 1 dekrementieren
	bne loop_eingabe		// zu Anfang springen solange Zero-Flag nicht gesetzt ist 
	
	// Maximumsbestimmung
	ldr r0, =str_startsuche
	bl uart_putString
	
	mov r9, #0				// Maximum mit null initialisieren
	
	bl pit3_getval			// Timer Startwert auslesen
	mov r7, r0				// Timer Startwert sichern
	
	mov r4, #COUNTER		// Schleifenvariable zurücksetzen
	
loop_maximum:
	ldrb r0, [r5, #-1]!	
	cmp r0, r9				// mit bisherigem Maximum vergleichen
	it hi
	movhi r9, r0			// wenn groesser als aktuelles Maximum (gespeichert in r9), dann kopiere r0 in r9
	subs r4, r4, #1			// Zählervariable dekrementieren
	bne loop_maximum
	
	
	bl pit3_getval			// Timerwert auslesen
	mov r8, r0
	// Maximum speichern
	ldr r0, =maximum		// Adresse für Maximum laden
	strb r9, [r0]			// Maximum im Speicher ablegen	
	
	// Ausgabe des Ergebnisses
	ldr r0, =str_endsuche
	bl uart_putString
	mov r0, r9				// Maximum nach r0 kopieren
	bl uart_putByte
	
	ldr r0, =str_zeitmessung
	bl uart_putString
	sub r0, r7, r8			// Zeit bestimmen
	sub r0, r0, r6			// Zeit für Zeitmessung subtrahieren
	bl uart_putInt16		// timerwert ausgeben
	
	/*
	* Aufg. 1-1e): Zeitmessung liefert unabhängig von der Lage des Maximums im Datensatz
	* 	immer den Wert 0x70
	*/
	
	
	// Maximum zurücksetzen
	mov r1, #0
	ldr r0, =maximum
	strb r1, [r0]
	
	// Ruecksprung zum Beginn
	b loop_program
	
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
	.rept COUNTER // repeat COUNTER mal
	.byte 0x00
	.endr
maximum: .byte 0x00
str_prompt: .asciz "\n> 0x"
str_eingabe: .asciz "\nBitte 16 Bytes sukzessiv eingeben!" // .asci = Ascii-String, .asciz = null-terminiert
str_startsuche: .asciz "\nDurchsuchen gestartet\n"
str_endsuche: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_zeitmessung: .asciz "\nZeit: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)3980588

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ BITMASKE_5_BIT, 0x1F
.equ BITBAND_BASISADRESSE, 0x20000000
.equ BITBAND_ALIAS_BASISADRESSE, 0x22000000
.equ RESERVED_MEM_SIZE, 0x0B			// Groesse des "reservierten" Speichers zwischen var0 und var1 in byte

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
* --- Registerbelegungen ---
* r5: bit 0
* r6: bit 1
* r7: Adresse var0/var1
* r8: Wert var0
* r9: Bit Banding Startadresse von var1
*/

main:	
	bl uart_init
	
	/* Bit Banding Startadresse von var1 berechnen */
	mov r0, BITBAND_ALIAS_BASISADRESSE
	mov r1, BITBAND_BASISADRESSE
	ldr r2, =var1
	sub r1, r2, r1	// r1 = Bit-Band-Adresse - Bit-Band-Basisadresse
	mov r2, #32
	mul r1, r1, r2	// r1 = (Bit-Band-Adresse - Bit-Band-Basisadresse)*32
	add r9, r0, r1	// r9 = Bit-Band-Alias-Basisadresse + (Bit-Band-Adresse - Bit-Band-Basisadresse)*32
	
loop_program:
	ldr r0, =str_eingabe
	bl uart_putString
	
	/* Eingabe der Werte */ 
	ldr r0, =str_prompt0
	bl uart_putString
	bl uart_getByte
	and r0, r0, BITMASKE_5_BIT
	mov r5, r0
	bl uart_putByte
	
	ldr r0, =str_prompt1
	bl uart_putString
	bl uart_getByte
	and r0, r0, BITMASKE_5_BIT
	mov r6, r0
	bl uart_putByte
	
	/* Aenderung Variable 0 */
	ldr r0, =str_nobitbanding
	bl uart_putString
	
	ldr r7, =var0
	ldr r8, [r7]		// Wert von var0 laden
	
	// Wert vorher ausgeben
	ldr r0, =str_wertvorher
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	
	mov r1, #1			// Zusammenbau Bitmaske: 1 laden
	lsl r1, r1, r5		// Zusammenbau Bitmaske: 1 an das richtige Bit schieben
	mvn r1, r1			// Zusammenbau Bitmaske: Invertierung der Bitmaske, da Bit zurueckgesetzt werden soll
	and r8, r8, r1		// Bitmaske anwenden
	
	// Bitmaske zweites Bit zusammenbauen und anwenden
	mov r1, #1
	lsl r1, r1, r6
	orr r8, r8, r1
	
	// Wert nachher ausgeben
	ldr r0, =str_wertnachher
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	
	str r8, [r7]		// neuen Wert speichern
	
	/* Aenderung Variable 1 */
	ldr r0, =str_bitbanding
	bl uart_putString
	
	// Wert vorher ausgeben
	ldr r0, =str_wertvorher
	bl uart_putString
	ldr r7, =var1
	ldr r0, [r7]		// Wert von var1 laden
	bl uart_putInt32
	
	// Berechnung Bit-Banding Adresse Bit0 in var1
	mov r0, #4	
	mul r0, r0, r5		// r0 = Bit 0 * 4 (4 Byte pro Bit im Bit-Banding Bereich) = Offset
	add r0, r0, r9		// r0 = Bit-Banding Adresse von Bit 0 in var1 (Basisadresse + Offset)
	
	// Zuruecksetzen Bit0 in var1
	mov r1, #0
	str r1, [r0]
	
	// Berechnung Bit-Banding Adresse Bit1 in var1
	mov r0, #4	
	mul r0, r0, r6
	add r0, r0, r9
	
	// Setzen Bit1 in var1
	mov r1, #1
	str r1, [r0]
	
	// Wert nachher ausgeben
	ldr r0, =str_wertnachher
	bl uart_putString
	ldr r0, [r7]		// Wert von var1 laden
	bl uart_putInt32
	
	
	b loop_program
	
/*** Datenbereich (ab 0x20000000) ***/
.data
var0: .long 0xffff0000
reserved:				// belegt Adressen 0x20000004 bis 0x2000000F, damit var1 die Adresse 0x20000010 bekommt
	.rept RESERVED_MEM_SIZE
	.byte 0x00
	.endr
var1: .long 0xffff0000
str_eingabe: .asciz "\nHexadezimalwerte eingeben:"
str_prompt0: .asciz "\nNummer des 0-Bits: "
str_prompt1: .asciz "\nNummer des 1-Bits: "
str_wertvorher: .asciz "\nWert vorher: "
str_wertnachher: .asciz "\nWert nachher: "
str_nobitbanding: .asciz "\n--- Ohne Bitbanding ---"
str_bitbanding: .asciz "\n--- Mit Bitbanding ---"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ BYTES_PER_VECTOR, 4
.equ BITS_PER_BYTE, 8
.equ BITMASK_FIRST_BYTE, 0x000000FF

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*
* Registerbelegungen:
* r5: Schleifenvariable
* r6: Vektor 1
* r7: Vektor 2
* r8: Vektor Minima
* r9: Vektor Maxima
* r10: Bitmaske fuer aktuelles Byte
* r11: Kosten fuer Zeitmessung in Taktzyklen
* r12: Zeitmessung
*/
main:	
	// serielle Schnittstelle und Timer initialisieren
	bl uart_init
	bl pit3_init
	
	// Kosten fuer Zeitmessung bestimmen
	bl pit3_getval
	mov r11, r0
	bl pit3_getval
	sub r11, r11, r0
	
loop_program:	
	ldr r0, =str_readvectors
	bl uart_putString
	
	// Vektor 1 einlesen
	ldr r0, =str_vector1
	bl uart_putString
	bl read_vector
	mov r6, r0
	bl uart_putInt32
	
	// Vektor 2 einlesen
	ldr r0, =str_vector2
	bl uart_putString
	bl read_vector
	mov r7, r0
	bl uart_putInt32
	
	// Minima und Maxima bestimmen ohne DSP
	bl pit3_getval
	mov r12, r0
	mov r5, #BYTES_PER_VECTOR	// Schleifenvariable initialisieren
	mov r8, #0					// Minimum-Vektor initialisieren
	mov r9, #0					// Maximum-Vektor initialisieren
	mov r10, #BITMASK_FIRST_BYTE	// Bitmaske initialisieren
loop_getminmax:
	and r1, r6, r10			// aktuelles Byte aus v1 in r1 speichern
	and r2, r7, r10 		// aktuelles Byte aus v2 in r2 speichern
	cmp r1, r2				// da Werte unsigned sind können sie hier direkt verglichen werden, obwohl die Bitwertungen bei byte2-4 nicht passen
	ittee ls				// wenn b1.x < b2.x: b1.x in Minima und b2.x in Maxima speichern, sonst anders herum
	orrls r8, r8, r1
	orrls r9, r9, r2
	orrhi r8, r8, r2
	orrhi r9, r9, r1
	lsl r10, r10, #BITS_PER_BYTE	// Bitmaske fuer naechstes Byte vorbereiten
	subs r5, r5, #1
	bne loop_getminmax
	
	bl pit3_getval
	sub r12, r12, r0			// Ausfuehrungszeit bestimmen
	sub r12, r12, r11			// Kosten fuer Zeitmessung subtrahieren
	
	// Ergebnisse ausgeben
	ldr r0, =str_nodsp
	bl uart_putString
	ldr r0, =str_minvector
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_maxvector
	bl uart_putString
	mov r0, r9
	bl uart_putInt32
	// Ergebnis der Zeitmessung ausgeben
	ldr r0, =str_time
	bl uart_putString
	mov r0, r12
	bl uart_putInt16
	
	
	// Minima und Maxima bestimmen mit DSP
	bl pit3_getval
	mov r12, r0
	// min
	usub8 r0, r6, r7
	sel r8, r7, r6
	// max
	usub8 r0, r6, r7
	sel r9, r6, r7
	
	bl pit3_getval
	sub r12, r12, r0			// Ausfuehrungszeit bestimmen
	sub r12, r12, r11			// Kosten fuer Zeitmessung subtrahieren
	
	// Ergebnisse ausgeben
	ldr r0, =str_withdsp
	bl uart_putString
	ldr r0, =str_minvector
	bl uart_putString
	mov r0, r8
	bl uart_putInt32
	ldr r0, =str_maxvector
	bl uart_putString
	mov r0, r9
	bl uart_putInt32
	// Ergebnis der Zeitmessung ausgeben
	ldr r0, =str_time
	bl uart_putString
	mov r0, r12
	bl uart_putInt16
	
	/*
	* Aufg. 1-3d):
	* 	ohne DSP: 0x32
	* 	mit DSP: 0x04
	* 	Es ist erkennbar, dass sich die Ausführungszeit mit den DSP-Befehlen signifikant verbessern lässt.
	*/
	
	b loop_program
	
/*
* Unterprogramm zum Einlesen eines Vektors bestehend aus 4 Bytes, Vektoraufteilung: 0xb4b3_b2b1
*
* Rückgabewerte:
* r0: eingelesener Vektor
*
* Registerbelegungen:
* r4: Menge einzulesender Bytes (Schleifenvariable)
* r5: shift-offset
* r6: vektor
*/	
.thumb_func
read_vector:
	push {r4-r6, lr}
	
	mov r4, #BYTES_PER_VECTOR	// Schleifenvariable initialisieren
	mov r5, #0			// Offset initialisieren
	mov r6, #0			// Vektorwert initialisieren
	
loop_getvector:
	bl uart_getByte		// Byte einlesen
	lsl r0, r0, r5		// shift an richtige Stelle im Vektor
	orr r6, r6, r0		// Byte zu Vektor hinzufügen 
	add r5, r5, #BITS_PER_BYTE		// offset um 1 Byte erhoehen
	subs r4, r4, #1
	bne loop_getvector
	
	mov r0, r6			// Rueckgabewert in r0 kopieren
	pop {r4-r6, pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
str_readvectors: .asciz "\nEingabe Vektoren"
str_vector1: .asciz "\nv1: 0x"
str_vector2: .asciz "\nv2: 0x"
str_nodsp: .asciz "\nohne DSP-Befehle:"
str_withdsp: .asciz "\nmit DSP-Befehlen:"
str_minvector: .asciz "\nmin: 0x"
str_maxvector: .asciz "\nmax: 0x"
str_time: .asciz "\nZeit: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ MATRIX_ROWS_COLS, 4 		// Anzahl Zeilen/Spalten pro Matrix
.equ MATRIX_NUM_ELEMENTS, MATRIX_ROWS_COLS * MATRIX_ROWS_COLS	// Anzahl Elemente in einer der Matrizen
.equ BYTES_IN_WORD, 4			// Bytes pro Datenwort
.equ SATURATION_BIT, 13			// Bit auf das gesaettigt werden soll (Aufg. e)
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
* zu a):	Ein DSP-Befehl fuehrt zwei Multiplikationen gleichzeitig aus, es laesst sich also die Anzahl
*			der Multiplikationsbefehle halbieren. Insgesamt sind 4 Multiplikationen pro Zelle der 
* 			Ergebnismatrix notwendig, also 64 Multiplikationen insgesamt. Diese lassen sich mithilfe der
*			DSP-Befehle in 32 Multiplikationsbefehlen (statt 64) durchfuehren, es werden also 32
*			Multiplikationsbefehle eingespart.
*
* zu d):	Es werden immer die jeweils hoeheren und tieferen Halbwoerter miteinander addiert. Werden die 
*			Werte als unsigned interpretiert ergeben sich damit folgende Ergebnisse, alle Werte größer 0xFFFF
*			können in 16 Bit nicht mehr dargestellt werden und führen zu einem Overflow:
*			A + B (oberes Halbwort) = 	0xA436 + 0x10A7 = 0xB4DD
*			A + B (unteres Halbwort) = 	0x7C7B + 0x8933 = 0x105AE (Overflow!)
*			A + C (oberes Halbwort) = 	0xA436 + 0xC553 = 0x16989 (Overflow!)
*			A + C (unteres Halbwort) = 	0x7C7B + 0x5f2C = 0xDBA7
*			A + D (oberes Halbwort) = 	0xA436 + 0x788E = 0x11CC4 (Overflow!)
*			A + D (unteres Halbwort) =	0x7C7B + 0x84B1 = 0x1012C (Overflow!)
*			
*			UADD16: Unsigned Addition ohne Saettigung. Hier werden jeweils nur die unteren 16 Bit des Ergebnisses
*					abgebildet (also die unteren 4 Ziffern in hexadezimaler Darstellung). Aus den Overflow-Werten
*					wird also:
*						0x105AE -> 0x05AE
*						0x16989 -> 0x6989
*						0x11CC4 -> 0x1CC4
*						0x1012C -> 0x012C
*					was dann insgesamt zu folgender Ausgabe fuehrt: B4DD_05AE 6989_DBA7 1CC4_012C
*
*			UQADD16: Unsigned Addition mit Saettigung. Hier wird ein Wert der zu groß ist, um in den 16 Bit abge-
*					bildet zu werden, durch den groesstmoeglichen Wert ersetzt, der noch abbildbar ist. Bei einem
*					unsigned-16-Bit-Wert ist das 0xFFFF.
*					Dies fuehrt zu der Ausgabe B4DD_FFFF FFFF_DBA7 FFFF_FFFF
*			
*			Der hoechste Wert, der im 2er Komplement in 16 Bit abgebildet werden kann, ist 0x7FFF (32767), der
*			niedrigste 0x8000 (-32768). bei den Berechnungen ergeben sich folgende Ergebnisse:
*			A + B (oberes Halbwort) = 	0xA436 + 0x10A7 = -23498 + 4263 	= -19262 	= 0xB4DD
*			A + B (unteres Halbwort) = 	0x7C7B + 0x8933 = 31867 + (-30413) 	= 1454 		= 0x05AE
*			A + C (oberes Halbwort) = 	0xA436 + 0xC553 = -23498 + (-15021)	= −38519 (Overflow!)
*			A + C (unteres Halbwort) = 	0x7C7B + 0x5f2C = 31867 + 24364		= 56231 (Overflow!)
*			A + D (oberes Halbwort) = 	0xA436 + 0x788E = -23498 + 30862	= 7364		= 0x1CC4
*			A + D (unteres Halbwort) =	0x7C7B + 0x84B1 = 31867 + (-31567)	= 300		= 0x012C
*
*			SADD16: Signed Addition ohne Saettigung. Hier wird bei einem Ueberlauf mit dem jeweils hoechsten
*					bzw. niedrigsten Wert fortgefahren: 32768 wird zu -32768 (0x8000), 32769 zu -32767 (0x8001),
*					32770 zu -32766 (0x8002) usw. Anders herum wird -32769 zu 32767 (0x7FFF), -32770 zu 32766 
*					(0x7FFE) usw.
*					Aus -38519 wird also 27017 (0x6989) und aus 56231 wird -9305 (0xDBA7)
*					Dies fuehrt zu der Ausgabe B4DD_05AE 6989_DBA7 1CC4_012C
*
*			QADD16: Signed Addition mit Saettigung. Hier wird bei einem Ueberlauf der hoechstmoegliche (bzw.
*					niedrigstmoegliche) abbildbare Wert angenommen.
*					Aus -38519 wird also -32768 (0x8000) und aus 56231 wird 32767 (0x7FFF)
*					Dies fuehrt zu der Ausgabe B4DD_05AE 8000_7FFF 1CC4_012C
*
* zu e):	SSAT16: Der Befehl saettigt einen 16 Bit vorzeichenbehafteten Wert auf den Wertebereich von x Bit
*					vorzeichenbehaftet. In diesem Fall (13 Bit) ist das -4096 (0xF000) bis 4095 (0x0FFF). Die Werte
*					werden also folgendermassen gesaettigt:
*					0xA436 = -23498 wird zu -4096 = 0xF000
*					0x7C7B = 31867 wird zu 4095 = 0x0FFF
*					0x10A7 = 4263 wird zu 4095 = 0x0FFF
*					0x8933 = -30413 wird zu -4096 = 0xF000
*
*			USAT16: Der Befehl saettigt einen 16 Bit vorzeichenbehafteten Wert auf den Wertebereich von x Bit
*					nicht vorzeichenbehaftet. In diesem Fall (13 Bit) ist das 0 (0x0000) bis 8191 (0x1FFF). Die
*					Werte werden also folgendermassen gesaettigt:
*					0xA436 = -23498 wird zu 0 = 0x0000
*					0x7C7B = 31867 wird zu 8191 = 0x1FFF
*					0x10A7 = 4263 fuehrt zu keiner Saettigung
*					0x8933 = -30413 wird zu 0 = 0x0000
*/

main:	
	bl uart_init

// a) Matrizenmultiplikation

/*
* Registerbelegungen:
*	r4,r5: Aktuelle Zeile aus M
*	r6,r7: Aktuelle Spalte aus N
*	r8: Adresse aktuelle Zelle in O
*	r9: Verbleibende zu berechnende Zeilen
*	r10: Verbleibende zu berechnende Werte in aktueller Zeile
* 	r11: Aktuelle Adresse aus NT
* 	r12: Aktuelle Adresse aus M
*/

	ldr r0, =str_ergebnis
	bl uart_putString
	
	ldr r12, =m
	ldr r8, =o						// Initialisiere Adresse mit erstem Element in O
	

	mov r9, #MATRIX_ROWS_COLS		// Initialisiere verbleibende Zeilen mit Gesamtzahl zu berechnender Zeilen
loop_multiplikation:
	// lade naechste Zeile aus M
	ldr r4, [r12], #BYTES_IN_WORD	// Element 1+2
	ldr r5, [r12], #BYTES_IN_WORD	// Element 3+4
	// Vorbereitung fuer Zeilenberechnung
	ldr r11, =nT	
	mov r10, #MATRIX_ROWS_COLS		// Initialisiere verbleibende Werte mit Gesamtzahl zu berechnender Werte pro Zeile
loop_zeile:
	// lade naechste Spalte aus N
	ldr r6, [r11], #BYTES_IN_WORD	// Element 1+2
	ldr r7, [r11], #BYTES_IN_WORD	// Element 1+2
	// berechne Zelle r9, r10 in O
	mov r0, #0
	smlad r0, r4, r6, r0
	smlad r0, r5, r7, r0
	str r0, [r8], #BYTES_IN_WORD	// Speichere berechneten Wert, setze Adresse auf naechste Zelle in O
	bl uart_putInt32				// gebe berechneten Wert aus
	mov r0, ' '
	bl uart_putChar
	
	subs r10, r10, #1
	bne loop_zeile
	
	mov r0, '\n'
	bl uart_putChar
	subs r9, r9, #1
	bne loop_multiplikation
	
	
// b) Kopieren der Ergebnismatrix

/*	
* Registerbelegungen:
*	r4-r11: Zwischenspeicher
*/
	
	ldr r0, =str_kopieren
	bl uart_putString
	ldr r0, =o
	ldr r1, =o_copy
	ldm r0!, {r4-r11}
	stm r1!, {r4-r11}
	ldm r0!, {r4-r11}
	stm r1!, {r4-r11}
	
	
// c) Berechnung der Summe S der Element-Produkte

/*
* Registerbelegungen:
*   r4: verbleibende Elemente
*   r5: Produktsumme
* 	r11: Startadresse NT
* 	r12: Startadresse M
*/
	
	ldr r11, =nT
	ldr r12, =m
	
	mov r4, #MATRIX_NUM_ELEMENTS 	// verbleibende Elemente mit Gesamtzahl der Elemente pro Matrix initialisieren
	mov r5, #0						// Produktsumme initialisieren
	
loop_produktsumme:
	ldr r6, [r11], #4
	ldr r7, [r12], #4
	smlad r5, r6, r7, r5
	subs r4, #2						// zwei Elemente gleichzeitig bearbeitet -> Anzahl verbleibender Elemente um zwei verringern
	bne loop_produktsumme
	
	ldr r0, =str_produktsumme
	bl uart_putString
	
	mov r0, r5
	bl uart_putInt32
	
// d) skalierbare Additionsbefehle
	
/*
* Registerbelegungen:
*   r4: A
*   r5: B
* 	r6: C
* 	r7: D
*/

	// Werte A-D in Register r4-r7 laden
	ldr r4, =val_abcd
	ldm r4, {r4-r7}
	
	// UADD16
	ldr r0, =str_uadd16
	bl uart_putString
	
	uadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	uadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	uadd16 r0, r4, r7
	bl uart_putInt32
	
	// SADD16
	ldr r0, =str_sadd16
	bl uart_putString
	
	sadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	sadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	sadd16 r0, r4, r7
	bl uart_putInt32
	
	// UQADD16
	ldr r0, =str_uqadd16
	bl uart_putString
	
	uqadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	uqadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	uqadd16 r0, r4, r7
	bl uart_putInt32
	
	// QADD16
	ldr r0, =str_qadd16
	bl uart_putString
	
	qadd16 r0, r4, r5
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	qadd16 r0, r4, r6
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	qadd16 r0, r4, r7
	bl uart_putInt32
	
// e) Saettigung auf 13 Bit
	
/*
* Registerbelegungen:
*   r4: A
*   r5: B
*/

	ldr r4, =val_abcd
	ldm r4, {r4-r5}
	
	// vorzeichenbehaftete Saettigung
	ldr r0, =str_ssat16
	bl uart_putString
	ssat16 r0, #SATURATION_BIT, r4
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	ssat16 r0, #SATURATION_BIT, r5
	bl uart_putInt32
	
	// vorzeichenlose Saettigung
	ldr r0, =str_usat16
	bl uart_putString
	usat16 r0, #SATURATION_BIT, r4
	bl uart_putInt32
	mov r0, ' '
	bl uart_putChar
	usat16 r0, #SATURATION_BIT, r5
	bl uart_putInt32

end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
m: 	// Matrix M
	.short 0x5f8c, 0x7f48, 0x8245, 0x6048
	.short 0xc799, 0x9c5d, 0xd49c, 0x33d8
	.short 0x579b, 0x8aef, 0xf2c0, 0xa3c2
	.short 0x41fd, 0x50d4, 0x25c6, 0x4afa
nT: // transponierte Matrix N
	.short 0x7f41, 0x0645, 0x8c8f, 0x9065
	.short 0x78e3, 0xf7f3, 0xd29f, 0x2961
	.short 0x5a1e, 0xdfed, 0x4b9f, 0x1092
	.short 0x61bf, 0x21be, 0x5ca1, 0xc6d3
o:	// Ergebnismatrix O
	.rept MATRIX_NUM_ELEMENTS
	.word 0x00
	.endr
o_copy:	// Kopie der Ergebnismatrix O
	.rept MATRIX_NUM_ELEMENTS
	.word 0x00
	.endr
val_abcd: .word 0xa4367c7b, 0x10a78933, 0xc5535f2c, 0x788e84b1
str_ergebnis: .asciz "\nErgebnismatrix O:\n"
str_kopieren: .asciz "Kopieren der Matrix O!\n"
str_produktsumme: .asciz "Produkt-Summe: "
str_uadd16: .asciz "\nUADD16: "
str_sadd16: .asciz "\nSADD16: "
str_uqadd16: .asciz "\nUQADD16: "
str_qadd16: .asciz "\nQADD16: "
str_ssat16: .asciz "\nSSAT16: "
str_usat16: .asciz "\nUSAT16: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ DELAY_CORRECTION, -10000	// Delay-Korrektur
// Initialwerte
.equ INIT_MIN, 0
.equ INIT_HOUR, 0
.equ INIT_DAY, 1
.equ INIT_MONTH, 1
.equ INIT_YEAR, 14

.equ MINS_PER_HOUR, 60
.equ HOURS_PER_DAY, 24
.equ DAYS_PER_MONTH, 30
.equ MONTHS_PER_YEAR, 12
.equ MAX_YEAR, 99
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
* Registerbelegungen:
* r4: aktuelle Minute
* r5: aktuelle Stunde
* r6: aktueller Tag
* r7: aktueller Monat
* r8: aktuelles Jahr
* r9: Uhr gestartet (1) oder gestoppt (0)
*/
main:	
	bl uart_init
	
	ldr r4, =minuten
	ldrb r4, [r4]
	ldr r5, =stunden
	ldrb r5, [r5]
	ldr r6, =tage
	ldrb r6, [r6]
	ldr r7, =monate
	ldrb r7, [r7]
	ldr r8, =jahre
	ldrb r8, [r8]
	mov r9, #1
	
loop_program:
	bl delay
	
	// Abfrage Steuerzeichen, falls keine Eingabe erfolgt ist, springe direkt zu uhrzeit_aktualisieren
	bl uart_charPresent
	cmp r0, #0
	beq uhrzeit_aktualisieren
	
	bl uart_getChar
	cmp r0, 's'
	beq start_stop
	cmp r0, 't'
	beq neue_zeit
	cmp r0, 'd'
	beq neues_datum
	
	b default
	
start_stop:
	eor r9, r9, #1			// Wert in r9 umschalten
	b uhrzeit_aktualisieren
neue_zeit:
	// Abfrage Stunde
	ldr r0, =str_eingabe_h
	bl uart_putString
	bl uart_getByteBase10
	mov r5, r0
	bl uart_putByteBase10TwoDigits
	// Abfrage Minute
	ldr r0, =str_eingabe_min
	bl uart_putString
	bl uart_getByteBase10
	mov r4, r0
	bl uart_putByteBase10TwoDigits
	// Zeilenumbruch
	mov r0, '\n'
	bl uart_putChar
	b uhrzeit_aktualisieren
neues_datum:
	// Abfrage Tag
	ldr r0, =str_eingabe_t
	bl uart_putString
	bl uart_getByteBase10
	mov r6, r0
	bl uart_putByteBase10TwoDigits
	// Abfrage Monat
	ldr r0, =str_eingabe_m
	bl uart_putString
	bl uart_getByteBase10
	mov r7, r0
	bl uart_putByteBase10TwoDigits
	// Abfrage Jahr
	ldr r0, =str_eingabe_j
	bl uart_putString
	bl uart_getByteBase10
	mov r8, r0
	bl uart_putByteBase10TwoDigits
	// Zeilenumbruch
	mov r0, '\n'
	bl uart_putChar
	b uhrzeit_aktualisieren
default:
	ldr r0, =str_eingabe_unbek
	bl uart_putString

uhrzeit_aktualisieren:
	// wenn Uhr auf Stopp, dann gebe nur die Uhrzeit aus
	cmp r9, #0				
	beq ausgabe_uhrzeit
	// aktualisiere Minuten
	add r4, r4, #1
	cmp r4, #MINS_PER_HOUR		// Pruefung ob Stunde voll
	itt eq
		moveq r4, #0			// wenn volle Stunde, dann setze Minuten zurueck und inkrementiere Stunden
		addeq r5, #1
	cmp r5, #HOURS_PER_DAY		// Pruefung ob Tag voll
	itt eq
		moveq r5, #0			// wenn voller Tag, dann setze Stunden zurueck und inkrementiere Tag
		addeq r6, #1
	cmp r6, #(DAYS_PER_MONTH + 1)	//Pruefung ob Monat voll
	itt eq
		moveq r6, #1			// wenn voller Monat, dann setze Tage zurueck und inkrementiere Monat
		addeq r7, #1
	cmp r7, #(MONTHS_PER_YEAR + 1)	//Pruefung ob Jahr voll
	itt eq
		moveq r7, #1			// wenn volles Jahr, dann setze Monat zurueck und inkrementiere Jahr
		addeq r8, #1
	cmp r8, #(MAX_YEAR + 1)		// Pruefung ob Jahrhundertgrenze erreicht
	it eq
		moveq r8, #MAX_YEAR		// Setze Jahr wieder auf 99 zurueck

ausgabe_uhrzeit:
	mov r0, r6
	bl uart_putByteBase10TwoDigits
	mov r0, '.'
	bl uart_putChar
	mov r0, r7
	bl uart_putByteBase10TwoDigits
	mov r0, '.'
	bl uart_putChar
	ldr r0, =str_padding_year
	bl uart_putString
	mov r0, r8
	bl uart_putByteBase10TwoDigits
	mov r0, ' '
	bl uart_putChar
	mov r0, r5
	bl uart_putByteBase10TwoDigits
	mov r0, ':'
	bl uart_putChar
	mov r0, r4
	bl uart_putByteBase10TwoDigits
	ldr r0, =str_uhr
	bl uart_putString

uhrzeit_speichern:
	// aktuelle Uhrzeit und Datum speichern
	ldr r0, =minuten
	strb r4, [r0]
	ldr r0, =stunden
	strb r5, [r0]
	ldr r0, =tage
	strb r6, [r0]
	ldr r0, =monate
	strb r7, [r0]
	ldr r0, =jahre
	strb r8, [r0]

	b loop_program

/*
*	Wrapper fuer uart_putByteBase10 mit Padding auf 2 Zeichen
*
*	Uebergabewerte:
*	r0: 	Base10-Byte das ausgegeben werden soll
*
*	Rueckgabewerte:
*	-
*
*	Registerbelegungen:
*	r4: Sicherung Uebergabewert
*/
.thumb_func
uart_putByteBase10TwoDigits:
	push {r4, lr}
	subs r1, r0, #10
	bpl putbyte	// Wert ist zweistellig, Padding nicht notwendig 
	mov r4, r0
	mov r0, '0'
	bl uart_putChar
	mov r0, r4
putbyte:
	bl uart_putByteBase10
	pop {r4, pc}

/* 
* Unterprogramm fuer 1s Verzoegerung 
*
* Rückgabewerte: -
*
* Registerbelegungen: -
*
*/
.thumb_func
delay:
	push {lr}
	ldr r0, =delay_reps
	ldr r0, [r0]
loop_delay:
	subs r0, r0, #1
	bne loop_delay
	
	pop {pc}

/*** Datenbereich (ab 0x20000000) ***/
.data
delay_reps: .word (25000000/3) + DELAY_CORRECTION
minuten: .byte INIT_MIN
stunden: .byte INIT_HOUR
tage: .byte INIT_DAY
monate: .byte INIT_MONTH
jahre: .byte INIT_YEAR
str_uhr: .asciz " Uhr\n"
str_eingabe_unbek: .asciz "Unbekanntes Eingabezeichen!\n"
str_eingabe_min: .asciz "\nMinuten eingeben (mm): "
str_eingabe_h: .asciz "\nStunde eingeben (hh): "
str_eingabe_t: .asciz "\nTag eingeben (tt): "
str_eingabe_m: .asciz "\nMonat eingeben (mm): "
str_eingabe_j: .asciz "\nJahr eingeben (jj): "
str_padding_year: .asciz "20"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Initialwerte
.equ INIT_MIN, 0
.equ INIT_HOUR, 0
.equ INIT_DAY, 1
.equ INIT_MONTH, 1
.equ INIT_YEAR, 14

.equ MINS_PER_HOUR, 60
.equ HOURS_PER_DAY, 24
.equ DAYS_PER_MONTH, 30
.equ MONTHS_PER_YEAR, 12
.equ MAX_YEAR, 99

.equ BITBAND_ALIAS_STATUS_REG_BASE, 0x42000000	// Startadresse Bitband-Alias-Region Statusregister
.equ BITBAND_STATUS_REG_BASE, 0x40000000		// Startadresse Bitband-Region Statusregister

.equ SIM_SCGC6, 0x4004803C				// Register mit Bit zum Anschalten der PIT-Clock
.equ PIT_CLOCK_BIT_IN_REG, 23			// Position des Bits in diesem Register
.equ PIT_CLOCK_BIT, BITBAND_ALIAS_STATUS_REG_BASE + (SIM_SCGC6 - BITBAND_STATUS_REG_BASE) * 32 + PIT_CLOCK_BIT_IN_REG * 4 // Bitband-Alias-Adresse des Bits

.equ NVIC_ISER2, 0xE000E108				// Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR2, 0xE000E288				// Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_PIT1, 0x1 << (69 - 64)		// Bitmask fuer PIT1 in NVIC_ISER2 und NVIC_ICPR2

.equ PIT_MCR, 0x40037000				// Adresse fuer Konfiguration PIT-Modul
.equ PIT_MDIS_BIT_IN_MCR, 1				// Module-Disable-Bit Position in MCR
.equ PIT_MDIS, BITBAND_ALIAS_STATUS_REG_BASE + (PIT_MCR - BITBAND_STATUS_REG_BASE) * 32 + PIT_MDIS_BIT_IN_MCR * 4	// Bitband Adresse PIT MDIS

.equ PIT_LDVAL1, 0x40037110				// Adresse fuer Startwert PIT1
.equ PIT_TCTRL1, 0x40037118				// Adresse fuer Konfigurationsbits PIT1
.equ PIT_TEN, 0							// Timer enable bit in PIT_TCTRL*
.equ PIT_TIE, 1							// Timer interrupt enable bit in PIT_TCTRL*
.equ PIT_TFLG1, 0x4003711C				// Adresse fuer Timer0 Flag Register
.equ PIT_TIF, 0							// Timer Interrupt Flag Position in PIT_TFLG*
.equ PIT_TEN1, BITBAND_ALIAS_STATUS_REG_BASE + (PIT_TCTRL1 - BITBAND_STATUS_REG_BASE) * 32 + PIT_TEN * 4	// Bitband Adresse PIT1 TEN	(Timer Enable)
.equ PIT_TIE1, BITBAND_ALIAS_STATUS_REG_BASE + (PIT_TCTRL1 - BITBAND_STATUS_REG_BASE) * 32 + PIT_TIE * 4	// Bitband Adresse PIT1 TIE	(Timer Interrupt Enable)
.equ PIT_TIF1, BITBAND_ALIAS_STATUS_REG_BASE + (PIT_TFLG1 - BITBAND_STATUS_REG_BASE) * 32 + PIT_TIF * 4		// Bitband Adresse PIT1 TIF (Timer Interrupt Flag)

.equ START_VTABLE, 0x1FFFFE00			// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ OFFSET_IRQ_PIT1, 0x154				// Offset Vektortabelleneintrag IRQ69 (PIT1)

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
* Registerbelegungen:
* r4: aktuelle Minute
* r5: aktuelle Stunde
* r6: aktueller Tag
* r7: aktueller Monat
* r8: aktuelles Jahr
* r9: Uhr gestartet (1) oder gestoppt (0)
*/
main:	
	bl uart_init
	
	ldr r4, =minuten
	ldrb r4, [r4]
	ldr r5, =stunden
	ldrb r5, [r5]
	ldr r6, =tage
	ldrb r6, [r6]
	ldr r7, =monate
	ldrb r7, [r7]
	ldr r8, =jahre
	ldrb r8, [r8]
	mov r9, #1
	
	
	// Takt für PIT1 aktivieren (SIM)	
	mov r0, #1
	ldr r1, =PIT_CLOCK_BIT
	str r0, [r1]
	
	// Interrupt-Vektor zu PIT1 setzen
	ldr r0, =isr_timer
	ldr r1, =START_VTABLE
	add r1, r1, #OFFSET_IRQ_PIT1
	str r0, [r1]
	
	// pending Interrupts zu PIT1 loeschen (NVIC)
	// NVIC_ICPR0 -> Interrupt Clear-Pending Register
	mov r0, #NVIC_BITMASK_PIT1
	ldr r1, =NVIC_ICPR2
	str r0, [r1]
	
	// Interrupt zu PIT1 aktivieren (NVIC)
	// NVIC_ISER0 -> Interrupt Set-enable Register
	ldr r1, =NVIC_ISER2
	str r0, [r1]
	
	// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	mov r0, #0
	ldr r1, =PIT_MDIS
	str r0, [r1]
	
	// Startwert fuer PIT1 auf 1 Sekunde initialisieren
	ldr r0, =timer_val
	ldr r0, [r0]
	ldr r1, =PIT_LDVAL1
	str r0, [r1]
	
	// Interrupt fuer PIT1 aktivieren
	mov r0, #1
	ldr r1, =PIT_TIE1
	str r0, [r1]		
	
	// PIT1 aktivieren	
	ldr r1, =PIT_TEN1
	str r0, [r1]
	
loop_program:
	// Abfrage Steuerzeichen, falls keine Eingabe erfolgt ist, springe direkt zu uhrzeit_aktualisieren
	bl uart_charPresent
	cmp r0, #0
	beq uhrzeit_aktualisieren
	
	bl uart_getChar
	cmp r0, 's'
	beq start_stop
	cmp r0, 't'
	beq neue_zeit
	cmp r0, 'd'
	beq neues_datum
	
	b default
	
start_stop:
	eor r9, r9, #1			// Wert in r9 umschalten
	b uhrzeit_aktualisieren
neue_zeit:
	// Abfrage Stunde
	ldr r0, =str_eingabe_h
	bl uart_putString
	bl uart_getByteBase10
	mov r5, r0
	bl uart_putByteBase10TwoDigits
	// Abfrage Minute
	ldr r0, =str_eingabe_min
	bl uart_putString
	bl uart_getByteBase10
	mov r4, r0
	bl uart_putByteBase10TwoDigits
	// Zeilenumbruch
	mov r0, '\n'
	bl uart_putChar
	b uhrzeit_aktualisieren
neues_datum:
	// Abfrage Tag
	ldr r0, =str_eingabe_t
	bl uart_putString
	bl uart_getByteBase10
	mov r6, r0
	bl uart_putByteBase10TwoDigits
	// Abfrage Monat
	ldr r0, =str_eingabe_m
	bl uart_putString
	bl uart_getByteBase10
	mov r7, r0
	bl uart_putByteBase10TwoDigits
	// Abfrage Jahr
	ldr r0, =str_eingabe_j
	bl uart_putString
	bl uart_getByteBase10
	mov r8, r0
	bl uart_putByteBase10TwoDigits
	// Zeilenumbruch
	mov r0, '\n'
	bl uart_putChar
	b uhrzeit_aktualisieren
default:
	ldr r0, =str_eingabe_unbek
	bl uart_putString

uhrzeit_aktualisieren:
	// wenn Sekunde noch nicht abgelaufen, dann springe direkt wieder an den Anfang
	ldr r0, =flag_sek_abgelaufen
	ldrb r1, [r0]
	cmp r1, #0
	beq loop_program
	// setze Flag zurueck
	mov r1, #0
	strb r1, [r0]  
	
	// wenn Uhr auf Stopp, dann gebe nur die Uhrzeit aus
	cmp r9, #0				
	beq ausgabe_uhrzeit
	// aktualisiere Minuten
	add r4, r4, #1
	cmp r4, #MINS_PER_HOUR		// Pruefung ob Stunde voll
	itt eq
		moveq r4, #0			// wenn volle Stunde, dann setze Minuten zurueck und inkrementiere Stunden
		addeq r5, #1
	cmp r5, #HOURS_PER_DAY		// Pruefung ob Tag voll
	itt eq
		moveq r5, #0			// wenn voller Tag, dann setze Stunden zurueck und inkrementiere Tag
		addeq r6, #1
	cmp r6, #(DAYS_PER_MONTH + 1)	//Pruefung ob Monat voll
	itt eq
		moveq r6, #1			// wenn voller Monat, dann setze Tage zurueck und inkrementiere Monat
		addeq r7, #1
	cmp r7, #(MONTHS_PER_YEAR + 1)	//Pruefung ob Jahr voll
	itt eq
		moveq r7, #1			// wenn volles Jahr, dann setze Monat zurueck und inkrementiere Jahr
		addeq r8, #1
	cmp r8, #(MAX_YEAR + 1)		// Pruefung ob Jahrhundertgrenze erreicht
	it eq
		moveq r8, #MAX_YEAR		// Setze Jahr wieder auf 99 zurueck

ausgabe_uhrzeit:
	// Ausgabe Uhrzeit
	mov r0, r6
	bl uart_putByteBase10TwoDigits
	mov r0, '.'
	bl uart_putChar
	mov r0, r7
	bl uart_putByteBase10TwoDigits
	mov r0, '.'
	bl uart_putChar
	ldr r0, =str_padding_year
	bl uart_putString
	mov r0, r8
	bl uart_putByteBase10TwoDigits
	mov r0, ' '
	bl uart_putChar
	mov r0, r5
	bl uart_putByteBase10TwoDigits
	mov r0, ':'
	bl uart_putChar
	mov r0, r4
	bl uart_putByteBase10TwoDigits
	ldr r0, =str_uhr
	bl uart_putString
	
uhrzeit_speichern:
	// aktuelle Uhrzeit und Datum speichern
	ldr r0, =minuten
	strb r4, [r0]
	ldr r0, =stunden
	strb r5, [r0]
	ldr r0, =tage
	strb r6, [r0]
	ldr r0, =monate
	strb r7, [r0]
	ldr r0, =jahre
	strb r8, [r0]
	
	b loop_program

/*
*	Wrapper fuer uart_putByteBase10TwoDigits mit Padding auf 2 Zeichen
*
*	Uebergabewerte:
*	r0: 	Base10-Byte das ausgegeben werden soll
*
*	Rueckgabewerte:
*	-
*
*	Registerbelegungen:
*	r4: Sicherung Uebergabewert
*/
.thumb_func
uart_putByteBase10TwoDigits:
	push {r4, lr}
	subs r1, r0, #10
	bpl putbyte	// Wert ist zweistellig, Padding nicht notwendig 
	mov r4, r0
	mov r0, '0'
	bl uart_putChar
	mov r0, r4
putbyte:
	bl uart_putByteBase10
	pop {r4, pc}

/*
* Interrupt Service Routine zur Behandlung eines Ablaufs des PIT1
*/
.thumb_func
isr_timer:
	// PIT interrupt flag zuruecksetzen
	ldr r0, =PIT_TIF1
	mov r1, #1
	str r1, [r0]
	// User-Flag setzen
	ldr r0, =flag_sek_abgelaufen
	mov r1, #1
	strb r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
timer_val: .word (25000000-1) // Timerwert für PIT, PIT-clock hat 25MHz, daher entspricht 25 Millionen exakt 1s, -1 da Counterwert bei 0 startet
flag_sek_abgelaufen: .byte 0x0
minuten: .byte INIT_MIN
stunden: .byte INIT_HOUR
tage: .byte INIT_DAY
monate: .byte INIT_MONTH
jahre: .byte INIT_YEAR
str_uhr: .asciz " Uhr\n"
str_eingabe_unbek: .asciz "Unbekanntes Eingabezeichen!\n"
str_eingabe_min: .asciz "\nMinuten eingeben (mm): "
str_eingabe_h: .asciz "\nStunde eingeben (hh): "
str_eingabe_t: .asciz "\nTag eingeben (tt): "
str_eingabe_m: .asciz "\nMonat eingeben (mm): "
str_eingabe_j: .asciz "\nJahr eingeben (jj): "
str_padding_year: .asciz "20"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ SIM_SCGC6, 0x4004803C
__BBREG SIM_SCGC6_CRC, SIM_SCGC6, 18		// Clock Gate Control fuer CRC-Modul

.equ CRC_CTRL, 0x40032008					// CRC Control Register
.equ CRC_CTRL_CFG, (1 << 24) | (1 << 25)	// no transposition, no XOR, 32-bit Protokoll (TCRC=1), Write Data Register as Seed (WAS=1)
__BBREG CRC_CTRL_WAS, CRC_CTRL, 25			// CRC_CTRL WAS (Write CRC Data Register as Seed)

.equ CRC_GPOLY, 0x40032004					// CRC Polynom Register
.equ CRC_GPOLY_CFG, (1 << 26) | (1 << 23) | (1 << 22) | (1 << 16) | (1 << 12) | (1 << 11) | (1 << 10) | (1 << 8) | (1 << 7) | (1 << 5) | (1 << 4) | (1 << 2) | (1 << 1) | (1 << 0) // CRC-Polynom

.equ CRC_CRC, 0x40032000					// CRC Data/Seed/Result Register
.equ CRC_SEED, 0x12345678					// CRC Seed

.equ BYTES_IN_WORD, 4						// Anzahl Bytes pro Datenwort
.equ BITMASK_BYTE, 0x000000ff				// Bitmaske zur Maskierung des ersten Bytes eines Datenwortes 
.equ BITS_IN_BYTE, 8						// Anzahl Bits pro Byte
.equ BITS_IN_HALFWORD, 16					// Anzahl Bits pro Halbwort

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
/*
* --- Registerbelegungen ---
* r5:	aktuelle Adresse in str
* r6:	Adresse Register CRC_CRC (CRC Data/Checksum)
*/
main:	
	bl uart_init
	
	ldr r0, =str_input
	bl uart_putString

	ldr r0, =str
	bl uart_putString
	
	ldr r0, =str_crc
	bl uart_putString
	
	// CRC Clock aktivieren
	ldr r0, =SIM_SCGC6_CRC
	mov r1, #1
	str r1, [r0]
	
	// CRC-Modul initialisieren
	ldr r0, =CRC_CTRL
	mov r1, #CRC_CTRL_CFG
	str r1, [r0]
	
	// CRC-Polynom setzen
	ldr r0, =CRC_GPOLY
	ldr r1, =CRC_GPOLY_CFG
	str r1, [r0]
	
	// Seed setzen (und WAS zuruecksetzen)        
	ldr r6, =CRC_CRC
	ldr r1, =CRC_SEED
	str r1, [r6]
	ldr r0, =CRC_CTRL_WAS
	mov r1, #0
	str r1, [r0]
	
/* CRC-Berechnung */
	ldr r5, =str
loop_crc:
	ldr r0, [r5], #BYTES_IN_WORD	// hole naechstes Wort aus dem Speicher
	
	mov r1, #BITMASK_BYTE
	ands r2, r0, r1					// Pruefe ob Byte 1 null (String Terminator)
	beq get_result					// falls ja, springe direkt zur Ausgabe des Ergebnisses
	
	lsl r1, #BITS_IN_BYTE			// schiebe Bitmaske auf naechstes Byte			
	ands r2, r0, r1
	it eq
	strbeq r0, [r6]					// wenn 2. Byte null, dann schreibe 1. Byte noch in CRC-Modul
	beq get_result
	
	lsl r1, #BITS_IN_BYTE			
	ands r2, r0, r1
	it eq
	strheq r0, [r6]					// wenn 3. Byte null, dann schreibe 1. und 2. Byte noch in CRC-Modul
	beq get_result
	
	lsl r1, #BITS_IN_BYTE			
	ands r2, r0, r1
	ittt eq
	strheq r0, [r6]					// wenn 4. Byte null, dann schreibe 1., 2. und 3. Byte noch in CRC-Modul
	lsleq r0, #BITS_IN_HALFWORD
	strbeq r0, [r6]
	beq get_result
	
	str r0, [r6]					// wenn kein Byte null, dann schreibe komplettes Wort in CRC und springe zurueck zum Schleifenanfang
	b loop_crc

get_result:
	ldr r0, [r6]					// lade Ergebnis
	bl uart_putInt32
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str: .asciz "Praktikum und Werkstatt Technische Informatik, FernUniversitaet Hagen"
str_input: .asciz "\nString: "
str_crc: .asciz "\nCRC: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_PIT1, START_VTABLE + 0x154		// Register fuer Adresse der PIT1-ISR
.equ VTABLE_IRQ_PIT2, START_VTABLE + 0x158		// Register fuer Adresse der PIT2-ISR
.equ VTABLE_IRQ_PORTE, START_VTABLE + 0x1AC 	// Register fuer Adresse der PORT-E-ISR

.equ SIM_SCGC5, 0x40048038
__BBREG CLOCK_GATE_CTRL_PORTA, SIM_SCGC5, 9		// Adresse Bit zur Aktivierung der Clock fuer das Modul PORT A
__BBREG CLOCK_GATE_CTRL_PORTE, SIM_SCGC5, 13	// Adresse Bit zur Aktivierung der Clock fuer das Modul PORT E
.equ SIM_SCGC6, 0x4004803C
__BBREG PIT_CLOCK_BIT, SIM_SCGC6, 23			// Adresse Bit zur Aktivierung der PIT-Clock

.equ PORTA_PCR10, 0x40049028					// Adresse Pin Control Register PTA10 (LED 4)
.equ PORTA_PCR11, 0x4004902C					// Adresse Pin Control Register PTA11 (LED 1)
.equ PORTA_PCR19, 0x4004904C					// Adresse Pin Control Register PTA19 (SW1)
.equ PORTA_PCR28, 0x40049070					// Adresse Pin Control Register PTA28 (LED 2)
.equ PORTA_PCR29, 0x40049074					// Adresse Pin Control Register PTA29 (LED 3)
.equ PORTE_PCR26, 0x4004D068					// Adresse Pin Control Register PTE26 (SW2)
__BBREG PORTE_PCR26_ISF, PORTE_PCR26, 24		// Adresse Interrupt Status Flag fuer SW2
.equ LED_PORT_MASK, (1 << 8)					// GPIO Mode (MUX = 001), kein Interrupt
.equ SW1_PORT_MASK, (1 << 8) | (1 << 1) | (1 << 0)	// GPIO Mode (MUX = 001), kein Interrupt, Pullup Widerstand (PE = 1, PS = 1)
.equ SW2_PORT_MASK, (0b1010 << 16) | (0b001 << 8) | (1 << 1) | (1 << 0)	// GPIO Mode (MUX = 001), Interrupt bei fallender Flanke (IRQC = 1010), Pullup Widerstand (PE = 1, PS = 1)

.equ GPIOA_PDDR, 0x400FF014						// Adresse GPIOA Port Data Direction Register
__BBREG GPIOA_PDDR_PDO10, GPIOA_PDDR, 10		// Adresse LED 4 Direction Bit
__BBREG GPIOA_PDDR_PDO11, GPIOA_PDDR, 11		// Adresse LED 1 Direction Bit
__BBREG GPIOA_PDDR_PDO19, GPIOA_PDDR, 19		// Adresse SW1 Direction Bit
__BBREG GPIOA_PDDR_PDO28, GPIOA_PDDR, 28		// Adresse LED 2 Direction Bit
__BBREG GPIOA_PDDR_PDO29, GPIOA_PDDR, 29		// Adresse LED 3 Direction Bit
.equ GPIOE_PDDR, 0x400FF114
__BBREG GPIOE_PDDR_PDO26, GPIOE_PDDR, 26		// Adresse SW2 Direction Bit

.equ GPIOA_PSOR, 0x400FF004						// Adresse GPIOA Port Set Output Register
__BBREG GPIOA_PSOR_PDO10, GPIOA_PSOR, 10		// Adresse LED 4 Set Bit
__BBREG GPIOA_PSOR_PDO11, GPIOA_PSOR, 11		// Adresse LED 1 Set Bit
__BBREG GPIOA_PSOR_PDO28, GPIOA_PSOR, 28		// Adresse LED 2 Set Bit
__BBREG GPIOA_PSOR_PDO29, GPIOA_PSOR, 29		// Adresse LED 3 Set Bit

.equ GPIOA_PCOR, 0x400FF008
__BBREG GPIOA_PCOR_PDO10, GPIOA_PCOR, 10		// Adresse LED 4 Reset Bit
__BBREG GPIOA_PCOR_PDO11, GPIOA_PCOR, 11		// Adresse LED 1 Reset Bit
__BBREG GPIOA_PCOR_PDO28, GPIOA_PCOR, 28		// Adresse LED 2 Reset Bit
__BBREG GPIOA_PCOR_PDO29, GPIOA_PCOR, 29		// Adresse LED 3 Reset Bit

.equ GPIOA_PDIR, 0x400FF010
__BBREG GPIOA_PDIR_PDO19, GPIOA_PDIR, 19		// Adresse SW1 Input Bit
.equ GPIOE_PDIR, 0x400FF110
__BBREG GPIOE_PDIR_PDO26, GPIOE_PDIR, 26		// Adresse SW2 Input Bit

.equ NVIC_ISER2, 0xE000E108						// Adresse Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR2, 0xE000E288						// Adresse Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_PIT1, 1 << (69 - 64)			// Bitmask fuer PIT1, PIT2 und SW2 (PORTE) in NVIC_ISER2 und NVIC_ICPR2
.equ NVIC_BITMASK_PIT2, 1 << (70 - 64)			// Bitmask fuer PIT1, PIT2 und SW2 (PORTE) in NVIC_ISER2 und NVIC_ICPR2
.equ NVIC_BITMASK_PORTE, 1 << (91 - 64)			// Bitmask fuer PIT1, PIT2 und SW2 (PORTE) in NVIC_ISER2 und NVIC_ICPR2

.equ PIT_MCR, 0x40037000						// Adresse fuer Konfiguration PIT-Modul
__BBREG PIT_MDIS, PIT_MCR, 1					// Adresse PIT MDIS

.equ PIT_LDVAL1, 0x40037110						// Adresse fuer Startwert PIT1
.equ PIT_LDVAL2, 0x40037120						// Adresse fuer Startwert PIT2
.equ PIT_TCTRL1, 0x40037118
__BBREG PIT_TCTRL1_TEN, PIT_TCTRL1, 0			// Adresse PIT1 Timer Enable Bit
__BBREG PIT_TCTRL1_TIE, PIT_TCTRL1, 1			// Adresse PIT1 Timer Interrupt Enable Bit
.equ PIT_TCTRL2, 0x40037128
__BBREG PIT_TCTRL2_TEN, PIT_TCTRL2, 0			// Adresse PIT2 Timer Enable Bit
__BBREG PIT_TCTRL2_TIE, PIT_TCTRL2, 1			// Adresse PIT2 Timer Interrupt Enable Bit
.equ PIT_TFLG1, 0x4003711C
__BBREG PIT_TFLG1_TIF, PIT_TFLG1, 0				// Adresse PIT1 Timer Interrupt Flag
.equ PIT_TFLG2, 0x4003712C
__BBREG PIT_TFLG2_TIF, PIT_TFLG2, 0				// Adresse PIT2 Timer Interrupt Flag

.equ BITMASK_LED_1, (1 << 0)					// Bitmaske fuer Bit in Zaehler, dass ueber LED 1 ausgegeben wird
.equ BITMASK_LED_2, (1 << 1)					// Bitmaske fuer Bit in Zaehler, dass ueber LED 2 ausgegeben wird
.equ BITMASK_LED_3, (1 << 2)					// Bitmaske fuer Bit in Zaehler, dass ueber LED 3 ausgegeben wird
.equ BITMASK_LED_4, (1 << 3)					// Bitmaske fuer Bit in Zaehler, dass ueber LED 4 ausgegeben wird

.equ COUNT_UP, 0								// Wert fuer Variable count_direction um Zaehler auf Hochzaehlen zu konfigurieren
.equ COUNT_DOWN, 1								// Wert fuer Variable count_direction um Zaehler auf Runterzaehlen zu konfigurieren
.equ COUNTER_STARTED, 1							// Wert fuer Variable counter_start um Zaehler zu starten
.equ COUNTER_STOPPED, 0							// Wert fuer Variable counter_start um Zaehler zu stoppen

.equ CYCLES_5MS, (25000000 / 1000) * 5			// CPU-Zyklen pro 5 ms

.equ BITMASK_FIRST_BYTE, 0xff					// Bitmaske zum Maskieren des ersten Bytes eines Datenworts

.equ BITMASK_MSB, (1 << 7)						// Bitmaske hoechstwertiges Bit

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
*	Registerbelegungen:
*		r4: buffer fuer eingelesenen char vom Terminal
*		r5: Counterwert
*		r6: Counter Start/Stop
*		r7: Zaehlrichtung
*		r8: Bitmaske fuer Terminalausgabe
*/
main:	
	bl uart_init
	
/* Initialisierung PITs */
	bl pit3_init
	// Takt für PIT Modul aktivieren (SIM)	
	mov r0, #1
	ldr r1, =PIT_CLOCK_BIT
	str r0, [r1]
	
	// Interrupt-Vektor zu PIT1 und PIT2 setzen
	ldr r0, =isr_timer
	ldr r1, =VTABLE_IRQ_PIT1
	str r0, [r1]
	ldr r0, =isr_timer_sw2_debounce
	ldr r1, =VTABLE_IRQ_PIT2
	str r0, [r1]
	
	// Interrupt-Vektor zu SW2 setzen
	ldr r0, =isr_sw2
	ldr r1, =VTABLE_IRQ_PORTE
	str r0, [r1]
	
	// pending Interrupts zu PIT1 und PIT2 loeschen (NVIC)
	// NVIC_ICPRx -> Interrupt Clear-Pending Register
	mov r0, #(NVIC_BITMASK_PIT1 | NVIC_BITMASK_PIT2)
	ldr r1, =NVIC_ICPR2
	str r0, [r1]
	
	// Interrupt zu PIT1 und PIT2 aktivieren (NVIC)
	// NVIC_ISERx -> Interrupt Set-enable Register
	ldr r1, =NVIC_ISER2
	str r0, [r1]
	
	// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	mov r0, #0
	ldr r1, =PIT_MDIS
	str r0, [r1]
	
	// Startwert fuer PIT1 auf 1 Sekunde initialisieren
	ldr r0, =timer_val
	ldr r0, [r0]
	ldr r1, =PIT_LDVAL1
	str r0, [r1]
	
	// Interrupt fuer PIT1 und PIT2 aktivieren
	mov r0, #1
	ldr r1, =PIT_TCTRL1_TIE
	str r0, [r1]
	ldr r1, =PIT_TCTRL2_TIE
	str r0, [r1]
	
	// PIT1 aktivieren	
	ldr r1, =PIT_TCTRL1_TEN
	str r0, [r1]
	
/* GPIOs fuer LEDs initialisieren */
	
	// aktiviere Clock fuer Port A (LED1-4, SW1) und E (SW2)
	mov r0, #1
	ldr r1, =CLOCK_GATE_CTRL_PORTA
	str r0, [r1]
	ldr r1, =CLOCK_GATE_CTRL_PORTE
	str r0, [r1]

	
	// konfiguriere GPIO mode fuer Pins PTA10, PTA11, PTA28, PTA29 (LEDs) und PTA19 (SW1) 
	mov r0, #LED_PORT_MASK
	ldr r1, =PORTA_PCR10
	str r0, [r1]
	ldr r1, =PORTA_PCR11
	str r0, [r1]
	ldr r1, =PORTA_PCR28
	str r0, [r1]
	ldr r1, =PORTA_PCR29
	str r0, [r1]
	ldr r0, =SW1_PORT_MASK
	ldr r1, =PORTA_PCR19
	str r0, [r1]
	// konfiguriere GPIO mode + Interrupt fuer PTE26 (SW2)
	ldr r0, =SW2_PORT_MASK
	ldr r1, =PORTE_PCR26
	str r0, [r1]
	
	// setze Direction der LED-Pins auf Output
	mov r0, #1
	ldr r1, =GPIOA_PDDR_PDO10
	str r0, [r1]
	ldr r1, =GPIOA_PDDR_PDO11
	str r0, [r1]
	ldr r1, =GPIOA_PDDR_PDO28
	str r0, [r1]
	ldr r1, =GPIOA_PDDR_PDO29
	str r0, [r1]
	
	// setze Direction des SW1-Pins und SW2-Pins auf Input
	mov r0, #0
	ldr r1, =GPIOA_PDDR_PDO19
	str r0, [r1]
	ldr r1, =GPIOE_PDDR_PDO26
	str r0, [r1]
	
	// pending Interrupts zu SW2 loeschen (NVIC)
	// NVIC_ICPRx -> Interrupt Clear-Pending Register
	mov r0, #NVIC_BITMASK_PORTE
	ldr r1, =NVIC_ICPR2
	str r0, [r1]
	
	// Interrupt zu SW2 aktivieren (NVIC)
	// NVIC_ISERx -> Interrupt Set-enable Register
	ldr r1, =NVIC_ISER2
	str r0, [r1]
	
	mov r5, #0
	
loop_program:
	// lese SW1
	bl poll_sw1
	
	// pruefe ob Taster gedrueckt wurde
	ldr r0, =mod
	ldrb r1, [r0]
	mov r2, #0		// flag zuruecksetzen
	strb r2, [r0]
	cmp r1, #1
	beq zaehler_richtung_aendern
	cmp r1, #2
	beq zaehler_start_stop

	// pruefe Terminal-Eingaben
	bl uart_charPresent
	cmp r0, #0
	beq update_zaehler
	
	bl uart_getChar
	cmp r0, '+'
	beq zaehler_hochzaehlen
	cmp r0, '-'
	beq zaehler_runterzaehlen
	cmp r0, 's'
	beq zaehler_start_stop
	
	mov r4, r0
	ldr r0, =str_unknown_char
	bl uart_putString
	mov r0, r4
	bl uart_putChar
	
	b update_zaehler
	
zaehler_hochzaehlen:
	// Aendere Zaehlrichtung zu Hochzaehlen 
	mov r0, #COUNT_UP
	ldr r1, =count_direction
	strb r0, [r1]
	ldr r0, =str_count_up
	bl uart_putString
	b update_zaehler

zaehler_runterzaehlen:
	// Aendere Zaehlrichtung zu Runterzaehlen
	mov r0, #COUNT_DOWN
	ldr r1, =count_direction
	strb r0, [r1]
	ldr r0, =str_count_down
	bl uart_putString
	b update_zaehler
	
zaehler_richtung_aendern:
	// invertiere Zaehlrichtung
	ldr r1, =count_direction
	ldrb r0, [r1]
	eor r0, r0, #1
	strb r0, [r1]
	cmp r0, #COUNT_DOWN
	ite eq
	ldreq r0, =str_count_down
	ldrne r0, =str_count_up
	bl uart_putString
	b update_zaehler

zaehler_start_stop:
	// Starte/Stoppe Zaehler
	ldr r1, =counter_start
	ldrb r0, [r1]
	eor r0, r0, #1
	strb r0, [r1]
	cmp r0, #COUNTER_STOPPED
	ite eq
	ldreq r0, =str_count_stop
	ldrne r0, =str_count_start
	bl uart_putString
	
		
update_zaehler:	
	// wenn Sekunde noch nicht abgelaufen, dann springe direkt wieder an den Anfang
	ldr r0, =flag_sek_abgelaufen
	ldrb r1, [r0]
	cmp r1, #0
	beq loop_program
	
	// setze Flag fuer Ablauf einer Sekunde zurueck
	mov r1, #0
	strb r1, [r0]  
	
	// wenn Zaehler gestoppt, dann springe direkt wieder an den Anfang
	ldr r1, =counter_start
	ldrb r0, [r1]
	cmp r0, #COUNTER_STOPPED
	beq loop_program
	
	// inkrementiere/dekrementiere Zaehlerwert abhängig von der Zaehlrichtung	
	ldr r0, =count_direction
	ldrb r1, [r0]
	cmp r1, #COUNT_UP
	ite eq
	addeq r5, r5, #1
	subne r5, r5, #1
	and r5, r5, #BITMASK_FIRST_BYTE
	
	/* aktualisiere LEDs */
	mov r2, #1
	
	mov r0, #BITMASK_LED_1
	ands r0, r5, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO11
	ldrne r1, =GPIOA_PCOR_PDO11
	// aktualisiere LED1
	str r2, [r1]
	
	mov r0, #BITMASK_LED_2
	ands r0, r5, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO28
	ldrne r1, =GPIOA_PCOR_PDO28
	// aktualisiere LED2
	str r2, [r1]
	
	mov r0, #BITMASK_LED_3
	ands r0, r5, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO29
	ldrne r1, =GPIOA_PCOR_PDO29
	// aktualisiere LED3
	str r2, [r1]
	
	mov r0, #BITMASK_LED_4
	ands r0, r5, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO10
	ldrne r1, =GPIOA_PCOR_PDO10
	// aktualisiere LED4
	str r2, [r1]
	
	/* Ausgabe auf dem Terminal */
	ldr r0, =str_count_val
	bl uart_putString
	
	mov r8, #BITMASK_MSB
	
loop_terminalausgabe:
	ands r0, r5, r8
	ite eq
	moveq r0, '0'
	movne r0, '1'
	bl uart_putChar
	lsrs r8, r8, #1
	bne loop_terminalausgabe
	
	b loop_program
	
end:
	b end
	

/*
*	Unterprogramm zum Pollen von SW1 mit ~5ms Entprellung
*
*	Ablauf:
*	
*	        │
*	        │
*	        │
*	        │
*	 ┌──────▼────────────────────────────┐
*	 │pruefe ob Entprellungsvorgang aktiv├───────────────────────────────────┐
*	 └──────┬────────────────────────────┘                                   │
*	        │                                                                │
*	        │ nicht aktiv                                                    │
*	        │                                                                │
*	 ┌──────▼──┐                                                     ┌───────▼─────────────────────────┐
*	 │lese GPIO├──────────────────────┐                        ┌─────┤pruefe ob PIT3 5ms nach Startwert│
*	 └──────┬──┘                      │                        │     └───────┬─────────────────────────┘
*	        │                         │                        │             │
*	        │ 1                       │ 0                      │ nein        │ ja
*	        │                         │                        │             │
*	 ┌──────▼────────┐           ┌────▼──────────┐             │     ┌───────▼───────────────┐
*	 │pruefe last_val├───┐       │pruefe last_val│             │     │reset Flag zur Signali-│
*	 └──────┬────────┘   │       └────┬──────────┘             │     │sierung eines Entprell-│
*	        │            │            │                        │     │vorgangs               ├──────────┐
*	        │ 0          │ 1          │ 1                      │     │                       │          │
*	        │            │            │                        │     │lese GPIO              │          │
*	 ┌──────▼──────┐     │       ┌────▼──────────────────┐     │     └───────┬───────────────┘          │
*	 │schreibe 1 in│     │       │speichere aktuellen    │     │             │                          │
*	 │last_val     │     │       │Wert von PIT3          │     │             │ 1                        │ 0
*	 └──────┬──────┘     │       │                       │     │             │                          │
*	        │            │       │setze Flag zur signali-│     │     ┌───────▼─────┐             ┌──────▼──────────┐
*	        │            │       │sierung eines Entprell-│     │     │schreibe 1 in│             │schreibe 1 in mod│
*	        │            │       │vorgangs               │     │     │last_val     │             └──────┬──────────┘
*	        │            │       │                       │     │     └───────┬─────┘                    │
*	        │            │       │schreibe 0 in last_val │     │             │                          │
*	        │            │       └────┬──────────────────┘     │             │                          │
*	        │            │            │                        │             │                          │
*	        │            │            │                        │             │                          │
*	        │            │            │                        │             │                          │
*	    ┌───▼──┐         │            │                        │             │                          │
*	    │return◄─────────┴────────────┴────────────────────────┴─────────────┴──────────────────────────┘
*	    └──────┘
*
*	Registerbelegung:
*		r5:	Adresse Flag Debounce-Vorgang aktiv
*		r6: Adresse letzter GPIO-Wert
*		r7: Adresse GPIO
*		r8: Adresse Timer-Startwert
*
*	Uebergabewerte: -
*
*	Rueckgabewerte: -
*/
.thumb_func
poll_sw1:
	push {r5-r8, lr}
	// pruefe ob Debounce-Vorgang laeuft
	ldr r5, =sw1_debounce_aktiv
	ldrb r0, [r5]
	cmp r0, #0
	bne debounce
	
	// kein aktiver Debounce-Vorgang. lese GPIO
	ldr r7, =GPIOA_PDIR_PDO19
	ldr r0, [r7]
	ldr r6, =sw1_last_val
	ldrb r1, [r6]
	
	// aktualisiere last_val im Speicher
	strb r0, [r6]
	
	// wenn GPIO == 1, dann springe direkt zurueck (Taster nicht gedrueckt)
	cmp r0, #0
	bne poll_sw1_return
	
	// GPIO == 0, pruefe ob last_val == 0. Falls ja, dann wurde Tastendruck schon behandelt, falls nein liegt fallende Flanke vor
	cmp r1, #0
	beq poll_sw1_return

	// speichere aktuellen Timerwert 
	bl pit3_getval
	ldr r8, =sw1_last_val
	str r0, [r8]
	
	// setze Debounce-Flag
	mov r0, #1
	strb r0, [r5]
	
	b poll_sw1_return

debounce:
	// pruefe ob Timer abgelaufen (Zeit fuer Messung von PIT3 sollte fuer die Entprellung vernachlaessigbar sein)
	bl pit3_getval
	ldr r8, =sw1_last_val
	ldr r1, [r8]
	subs r1, r1, r0
	ldr r0, =CYCLES_5MS
	cmp r0, r1
	bhi poll_sw1_return	// Timer noch nicht abgelaufen
	
	// setze Debounce-Flag zurueck
	mov r0, #0
	str r0, [r5]

	// pruefe ob Taster weiterhin gedrueckt (und aktualisiere last_val)
	ldr r7, =GPIOA_PDIR_PDO19
	ldr r0, [r7]
	ldr r6, =sw1_last_val
	str r0, [r6]
	cmp r0, #0
	bne poll_sw1_return	// Taster nicht mehr gedrueckt
	
	// schreibe 1 in mod
	mov r0, #1
	ldr r1, =mod
	str r0, [r1]

poll_sw1_return:
	pop {r5-r8, pc}
	
	
/*
* Interrupt Service Routine zur Behandlung einer fallenden Flanke an SW2
*/
.thumb_func
isr_sw2:	
	// pruefen ob Timer schon aktiviert
	ldr r2, =PIT_TCTRL2_TEN
	cmp r2, #1
	beq sw2_interrupt_flag_reset

	// Startwert fuer PIT2 auf 5ms initialisieren
	ldr r0, =CYCLES_5MS
	ldr r1, =PIT_LDVAL2
	str r0, [r1]
		
	// PIT1 aktivieren	
	mov r0, #1
	str r0, [r2]
	
sw2_interrupt_flag_reset:
	// interrupt flag von SW1 zuruecksetzen
	ldr r1, =PORTE_PCR26_ISF
	mov r0, #1
	str r0, [r1]
	
	bx lr

/*
* Interrupt Service Routine zur Behandlung eines Ablaufs des PIT1 (genutzt fuer 8bit Binaerzaehler) 
*/
.thumb_func
isr_timer:
	// PIT interrupt flag zuruecksetzen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	// User-Flag setzen
	ldr r0, =flag_sek_abgelaufen
	mov r1, #1
	strb r1, [r0]
	bx lr

/*
* Interrupt Service Routine zur Behandlung eines Ablaufs des PIT2 (genutzt fuer Entprellung des SW2)
*/
.thumb_func
isr_timer_sw2_debounce:
	// PIT2 deaktivieren	
	mov r0, #0
	ldr r1, =PIT_TCTRL2_TEN
	str r0, [r1]
	
	// PIT2 interrupt flag zuruecksetzen
	mov r0, #1
	ldr r1, =PIT_TFLG2_TIF
	str r0, [r1]
	
	// Wert GPIO pruefen, falls immer noch 0: setze mod=2
	ldr r1, =GPIOE_PDIR_PDO26
	ldr r0, [r1]
	cmp r0, #0
	ittt eq
	ldreq r1, =mod
	moveq r2, #2
	streq r2, [r1]
	
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
mod: .byte 0x0						// Variable zur Signalisierung eines Tastendrucks (SW1/SW2)
sw1_last_val: .byte 0x1				// zuletzt gelesener Wert des SW1-GPIO-Pins
sw1_debounce_aktiv: .byte 0x0		// Flag zur Signalisierung eines aktiven Entprellungsvorgangs fuer SW1 
timer_val: .word (25000000-1) 		// Timerwert für PIT, PIT-clock hat 25MHz, daher entspricht 25 Millionen exakt 1s, -1 da Counterwert bei 0 startet
count_direction: .byte 0x0			// Zaehlrichtung: 0 = hochzaehlen, 1 = runterzaehlen
counter_start: .byte 0x1			// 0 = Zaehler gestoppt, 1 = Zaehler gestartet
flag_sek_abgelaufen: .byte 0x0		// Flag zur Signalisierung des Ablaufs einer Sekunde fuer die Weiterschaltung des Binaerzaehlers
str_count_up: .asciz "\nneuer Zaehler-Modus: Inkrement"
str_count_down: .asciz "\nneuer Zaehler-Modus: Dekrement"
str_count_stop: .asciz "\nZaehler gestoppt"
str_count_start: .asciz "\nZaehler gestartet"
str_unknown_char: .asciz "\nUnbekanntes Zeichen: "
str_count_val: .asciz "\nZaehlerwert: "


// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/* Konstanten */
.equ SIM_SCGC3, 0x40048030
__BBREG SIM_SCGC3_ADC1, SIM_SCGC3, 27	// ADC1 Clock Gate Control

.equ ADC1_CFG1, 0x400BB008
.equ ADC1_CFG1_CONFIG_8BIT,  (0b11 << 5) | (0b00 << 2)	// Clock Divide 8 (ADIV=0b11), Conversion Mode 8 bit (MODE=0b11), Bus Clock (ADICLK=0b00)
.equ ADC1_CFG1_CONFIG_10BIT, (0b11 << 5) | (0b10 << 2)	// Clock Divide 8 (ADIV=0b11), Conversion Mode 10 bit (MODE=0b11), Bus Clock (ADICLK=0b00)
.equ ADC1_CFG1_CONFIG_12BIT, (0b11 << 5) | (0b01 << 2)	// Clock Divide 8 (ADIV=0b11), Conversion Mode 12 bit (MODE=0b11), Bus Clock (ADICLK=0b00)
.equ ADC1_CFG1_CONFIG_16BIT, (0b11 << 5) | (0b11 << 2)	// Clock Divide 8 (ADIV=0b11), Conversion Mode 16 bit (MODE=0b11), Bus Clock (ADICLK=0b00)
.equ ADC1_CFG2, 0x400BB00C
.equ ADC1_CFG2_CONFIG, 0x0								// Channel A, Default sample time
.equ ADC1_SC1A, 0x400BB000
.equ ADC1_SC1A_CONFIG_START, (0b10100 << 0)				// Kanal AD20 (ADCH=0b10100)
.equ ADC1_SC1A_CONFIG_STOP, (0b11111 << 0)				// Module Disabled (ADCH=0b11111)
__BBREG ADC1_SC1A_COCO, ADC1_SC1A, 7					// Conversion Complete Statusbit
.equ ADC1_SC2, 0x400BB020
.equ ADC1_SC2_CONFIG, 0x0								// Default Reference Voltage, DMA & Compare-Funktionen deaktiviert
.equ ADC1_SC3, 0x400BB024
.equ ADC1_SC3_CONFIG_CAL, (0b1 << 3) | (0b1 << 2) | (0b11 << 0) // Konfiguration fuer Kalibrierung: Continuous Conversion (ADCO=0b1), Hardware Average enabled (AVGE=0b1), 32 samples (AVGS=0b11)
.equ ADC1_SC3_CONFIG, (0b1 << 3) | (0b1 << 2) | (0b10 << 0) // Konfiguration: Continuous Conversion (ADCO=0b1), Hardware Average enabled (AVGE=0b1), 16 samples (AVGS=0b10)
__BBREG ADC1_SC3_CAL, ADC1_SC3, 7						// Bit zum Starten der Kalibrierung
__BBREG ADC1_SC3_CALF, ADC1_SC3, 6						// Kalibrierung Fehler-Flag

.equ ADC1_PG, 0x400BB02C
.equ ADC1_MG, 0x400BB030

.equ ADC1_CLP0, 0x400BB04C
.equ ADC1_CLM0, 0x400BB06C

.equ ADC1_CLxx_MSB_MASK, 0x8000
.equ ADC1_RA, 0x400BB010

.equ BYTES_IN_WORD, 4

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_PIT1, START_VTABLE + 0x154		// Register fuer Adresse der PIT1-ISR

.equ NVIC_ISER2, 0xE000E108						// Adresse Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR2, 0xE000E288						// Adresse Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_PIT1, 1 << (69 - 64)			// Bitmask fuer PIT1 in NVIC_ISER2 und NVIC_ICPR2

.equ SIM_SCGC5, 0x40048038
__BBREG SIM_SCGC5_PORTA, SIM_SCGC5, 9			// Adresse Bit zur Aktivierung der Clock fuer das Modul PORT A
.equ SIM_SCGC6, 0x4004803C
__BBREG SIM_SCGC6_PIT, SIM_SCGC6, 23			// Adresse Bit zur Aktivierung der PIT-Clock

.equ PIT_MCR, 0x40037000						// Adresse fuer Konfiguration PIT-Modul
__BBREG PIT_MDIS, PIT_MCR, 1					// Adresse PIT MDIS

.equ PIT_LDVAL1, 0x40037110						// Adresse fuer Startwert PIT1
.equ PIT1_INIT_VAL, 24999999					// Startwert PIT1 (1s)

.equ PIT_TCTRL1, 0x40037118
__BBREG PIT_TCTRL1_TEN, PIT_TCTRL1, 0			// Adresse PIT1 Timer Enable Bit
__BBREG PIT_TCTRL1_TIE, PIT_TCTRL1, 1			// Adresse PIT1 Timer Interrupt Enable Bit
.equ PIT_TFLG1, 0x4003711C
__BBREG PIT_TFLG1_TIF, PIT_TFLG1, 0				// Adresse PIT1 Timer Interrupt Flag

.equ PORTA_PCR10, 0x40049028					// Adresse Pin Control Register PTA10 (LED 4)
.equ PORTA_PCR11, 0x4004902C					// Adresse Pin Control Register PTA11 (LED 1)
.equ PORTA_PCR28, 0x40049070					// Adresse Pin Control Register PTA28 (LED 2)
.equ PORTA_PCR29, 0x40049074					// Adresse Pin Control Register PTA29 (LED 3)
.equ LED_PORT_MASK, (1 << 8)					// GPIO Mode (MUX = 001), kein Interrupt

.equ BITMASK_LED_1, (1 << 0)					// Bitmaske fuer Bit in Stufe das ueber LED 1 ausgegeben wird
.equ BITMASK_LED_2, (1 << 1)					// Bitmaske fuer Bit in Stufe das ueber LED 2 ausgegeben wird
.equ BITMASK_LED_3, (1 << 2)					// Bitmaske fuer Bit in Stufe das ueber LED 3 ausgegeben wird
.equ BITMASK_LED_4, (1 << 3)					// Bitmaske fuer Bit in Stufe das ueber LED 4 ausgegeben wird

.equ GPIOA_PDDR, 0x400FF014						// Adresse GPIOA Port Data Direction Register
__BBREG GPIOA_PDDR_PDO10, GPIOA_PDDR, 10		// Adresse LED 4 Direction Bit
__BBREG GPIOA_PDDR_PDO11, GPIOA_PDDR, 11		// Adresse LED 1 Direction Bit
__BBREG GPIOA_PDDR_PDO28, GPIOA_PDDR, 28		// Adresse LED 2 Direction Bit
__BBREG GPIOA_PDDR_PDO29, GPIOA_PDDR, 29		// Adresse LED 3 Direction Bit

.equ GPIOA_PSOR, 0x400FF004						// Adresse GPIOA Port Set Output Register
__BBREG GPIOA_PSOR_PDO10, GPIOA_PSOR, 10		// Adresse LED 4 Set Bit
__BBREG GPIOA_PSOR_PDO11, GPIOA_PSOR, 11		// Adresse LED 1 Set Bit
__BBREG GPIOA_PSOR_PDO28, GPIOA_PSOR, 28		// Adresse LED 2 Set Bit
__BBREG GPIOA_PSOR_PDO29, GPIOA_PSOR, 29		// Adresse LED 3 Set Bit

.equ GPIOA_PCOR, 0x400FF008						// Adresse GPIOA Port Clear Output Register
__BBREG GPIOA_PCOR_PDO10, GPIOA_PCOR, 10		// Adresse LED 4 Reset Bit
__BBREG GPIOA_PCOR_PDO11, GPIOA_PCOR, 11		// Adresse LED 1 Reset Bit
__BBREG GPIOA_PCOR_PDO28, GPIOA_PCOR, 28		// Adresse LED 2 Reset Bit
__BBREG GPIOA_PCOR_PDO29, GPIOA_PCOR, 29		// Adresse LED 3 Reset Bit

.equ STEP_SIZE_8BIT, 2^8/8
.equ STEP_SIZE_10BIT, 2^10/10
.equ STEP_SIZE_12BIT, 2^12/12
.equ STEP_SIZE_16BIT, 2^16/16

.equ PRECISION_8BIT, 8
.equ PRECISION_10BIT, 10
.equ PRECISION_12BIT, 12
.equ PRECISION_16BIT, 16

.equ LEVEL_SHIFT_8BIT, (8-3)					// Anzahl an Bits, die der 8bit-Wert nach rechts geschoben werden muss, um die Stufe zu erhalten
.equ LEVEL_SHIFT_16BIT, (16-4)					// Anzahl an Bits, die der 16bit-Wert nach rechts geschoben werden muss, um die Stufe zu erhalten

.equ SHIFT_MUL_4, 2								// Anzahl Bits fuer Linksshift um mit 4 zu multiplizieren

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
*	Registerbelegungen:
*		r4: start/stop (1=start)
*		r5: precision (8,10,12,16)
*		r6: ADC-Wert
*		r7: Stufe
*/
main:	
	bl uart_init

	/* Kalibrierung ADC1 (a) */
	bl adc_calibration

	cmp r0, #0
	beq configuration

	// Kalibrierung fehlgeschlagen, gebe Fehlermeldung auf dem Terminal aus und stoppe weitere Programmausfuehrung

	mov r4, r0
	ldr r0, =str_calibration_failed
	bl uart_putString
	mov r0, r4
	bl uart_putInt32
	b end

configuration:
	mov r0, #0
	mov r1, #1
	/* Konfiguration ADC1 (b) */
	ldr r2, =ADC1_CFG2
	mov r3, #ADC1_CFG2_CONFIG
	str r3, [r2]

	ldr r2, =ADC1_SC2
	mov r3, #ADC1_SC2_CONFIG
	str r3, [r2]

	// Umschalten auf 16 Samples
	ldr r2, =ADC1_SC3
	ldr r3, =ADC1_SC3_CONFIG
	str r3, [r2]

	// Kanal auswaehlen
	ldr r2, =ADC1_SC1A
	ldr r3, =ADC1_SC1A_CONFIG_START
	str r3, [r2]

	/* Konfiguration PIT1 (c) */
	// Takt für PIT Modul aktivieren (SIM)
	ldr r2, =SIM_SCGC6_PIT
	str r1, [r2]

	// Interrupt-Vektor zu PIT1 setzen
	ldr r2, =VTABLE_IRQ_PIT1
	ldr r3, =isr_timer
	str r3, [r2]

	// pending Interrupts zu PIT1 loeschen (NVIC)
	ldr r2, =NVIC_ICPR2
	mov r3, #NVIC_BITMASK_PIT1
	str r3, [r2]

	// Interrupt zu PIT1 aktivieren (NVIC)
	ldr r2, =NVIC_ISER2
	str r3, [r2]

	// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	ldr r2, =PIT_MDIS
	str r0, [r2]

	// Startwert fuer PIT1 auf 1 Sekunde initialisieren
	ldr r2, =PIT_LDVAL1
	ldr r3, =PIT1_INIT_VAL
	str r3, [r2]

	// Interrupt fuer PIT1 aktivieren
	ldr r2, =PIT_TCTRL1_TIE
	str r1, [r2]

	// PIT1 aktivieren	
	ldr r2, =PIT_TCTRL1_TEN
	str r1, [r2]

	/* Konfiguration LEDs (d) */
	// aktiviere Clock fuer Port A
	ldr r2, =SIM_SCGC5_PORTA
	str r1, [r2]

	// konfiguriere GPIO mode fuer Pins PTA10, PTA11, PTA28, PTA29 (LEDs)
	mov r3, #LED_PORT_MASK
	ldr r2, =PORTA_PCR10
	str r3, [r2]
	ldr r2, =PORTA_PCR11
	str r3, [r2]
	ldr r2, =PORTA_PCR28
	str r3, [r2]
	ldr r2, =PORTA_PCR29
	str r3, [r2]

	// setze Direction der LED-Pins auf Output
	ldr r2, =GPIOA_PDDR_PDO10
	str r1, [r2]
	ldr r2, =GPIOA_PDDR_PDO11
	str r1, [r2]
	ldr r2, =GPIOA_PDDR_PDO28
	str r1, [r2]
	ldr r2, =GPIOA_PDDR_PDO29
	str r1, [r2]

	// Programm auf "start" setzen
	mov r4, #1
	mov r5, #PRECISION_16BIT

loop_program:

	// Abfrage Terminaleingaben
	bl uart_charPresent
	cmp r0, #0
	beq output 							// keine Eingabe ueber das Terminal

	bl uart_getChar
	cmp r0, 's'
	beq start_stop
	cmp r4, #1
	beq output
	cmp r0, '0'
	beq set_precision_8bit
	cmp r0, '1'
	beq set_precision_10bit
	cmp r0, '2'
	beq set_precision_12bit
	cmp r0, '3'
	beq set_precision_16bit
	b output

start_stop:
	eor r4, r4, #1
	cmp r4, #1
	ite eq
	ldreq r0, =ADC1_SC1A_CONFIG_START
	ldrne r0, =ADC1_SC1A_CONFIG_STOP
	ldr r1, =ADC1_SC1A
	str r0, [r1]
	b output

set_precision_8bit:
	mov r5, #PRECISION_8BIT
	ldr r0, =ADC1_CFG1_CONFIG_8BIT
	ldr r1, =ADC1_CFG1
	str r0, [r1]
	b output

set_precision_10bit:
	mov r5, #PRECISION_10BIT
	ldr r0, =ADC1_CFG1_CONFIG_10BIT
	ldr r1, =ADC1_CFG1
	str r0, [r1]
	b output

set_precision_12bit:
	mov r5, #PRECISION_12BIT
	ldr r0, =ADC1_CFG1_CONFIG_12BIT
	ldr r1, =ADC1_CFG1
	str r0, [r1]
	b output

set_precision_16bit:
	mov r5, #PRECISION_16BIT
	ldr r0, =ADC1_CFG1_CONFIG_16BIT
	ldr r1, =ADC1_CFG1
	str r0, [r1]

output:
	// pruefe Timer-Flag
	ldr r0, =flag_sek_abgelaufen
	ldrb r1, [r0]
	cmp r1, #1
	bne loop_program				// springe zurueck, wenn Sekunde noch nicht abgelaufen

	// Flag zuruecksetzen
	mov r1, #0
	strb r1, [r0]

	// pruefe start/stop
	cmp r4, #1
	bne loop_program

	// Ausgabe des ADC-Wertes auf dem Terminal
	ldr r0, =str_hex
	bl uart_putString
	ldr r1, =ADC1_RA
	ldr r6, [r1]
	mov r0, r6
	bl uart_putInt16

	// Berechnung der Stufe
	cmp r5, #PRECISION_8BIT
	it eq
	lsreq r7, r6, #LEVEL_SHIFT_8BIT 		// da 8 eine Zweierpotenz ist, geben die oberen 3 Bits bereits die Stufe an
	beq output_voltage_level
	cmp r5, #PRECISION_16BIT
	it eq
	lsreq r7, r6, #LEVEL_SHIFT_16BIT		// da 16 eine Zweierpotenz ist, geben die oberen 4 Bits bereits die Stufe an
	beq output_voltage_level
	cmp r5, #PRECISION_10BIT
	ite eq
	ldreq r0, =lut_levels_10bit
	ldrne r0, =lut_levels_12bit
	mov r7, #0
loop_calc_level:
	ldr r1, [r0], #BYTES_IN_WORD
	cmp r6, r1
	bls output_voltage_level
	add r7, r7, #1
	b loop_calc_level

output_voltage_level:
	cmp r5, #PRECISION_8BIT
	it eq
	ldreq r0, =levels_8bit
	cmp r5, #PRECISION_10BIT
	it eq
	ldreq r0, =levels_10bit
	cmp r5, #PRECISION_12BIT
	it eq
	ldreq r0, =levels_12bit
	cmp r5, #PRECISION_16BIT
	it eq
	ldreq r0, =levels_16bit
	// 8 bit
	lsl r1, r7, #SHIFT_MUL_4
	add r0, r1								// verschiebe den Index des Arrays zu dem Eintrag mit der Adresse fuer den korrekten String
	ldr r0, [r0]							// lade die Adresse fuer den korrekten String in r0
	bl uart_putString
	ldr r0, =str_level
	bl uart_putString
	mov r0, r7
	bl uart_putByteBase10
	mov r0, ')'
	bl uart_putChar

	/* Ausgabe LEDs */
	mov r2, #1
	
	mov r0, #BITMASK_LED_1
	ands r0, r7, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO11
	ldrne r1, =GPIOA_PCOR_PDO11
	// aktualisiere LED1
	str r2, [r1]
	
	mov r0, #BITMASK_LED_2
	ands r0, r7, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO28
	ldrne r1, =GPIOA_PCOR_PDO28
	// aktualisiere LED2
	str r2, [r1]
	
	mov r0, #BITMASK_LED_3
	ands r0, r7, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO29
	ldrne r1, =GPIOA_PCOR_PDO29
	// aktualisiere LED3
	str r2, [r1]
	
	mov r0, #BITMASK_LED_4
	ands r0, r7, r0
	ite eq
	ldreq r1, =GPIOA_PSOR_PDO10
	ldrne r1, =GPIOA_PCOR_PDO10
	// aktualisiere LED4
	str r2, [r1]

	b loop_program

end:
	b end
	
/*
*	Unterprogramm zur Konfiguration & Kalibrierung des ADC
*
*	Uebergabeparameter: -
*
*	Registerbelegungen: -
*
* 	Rueckgabewert:
*		r0:	0 wenn Kalibrierung erfolgreich, ADC1_SC3[CALF] sonst
*/
.thumb_func
adc_calibration:
	/* Konfiguration */
	// ADC Clock aktivieren (SIM): SIM_SCGC3[ADC1]
	mov r0, #1
	ldr r3, =SIM_SCGC3_ADC1
	str r0, [r3]

	// ADC Clock Source, Divide, Low-Power-Configuration, sample time
	ldr r3, =ADC1_CFG1
	ldr r2, =ADC1_CFG1_CONFIG_16BIT
	str r2, [r3]

	// hardware averaging auf Maximum: SC3[AVGE]=1 und SC3[AVGS]=11
	ldr r3, =ADC1_SC3
	ldr r2, =ADC1_SC3_CONFIG_CAL
	str r2, [r3]
	
	/* Kalibrierung starten */
	ldr r3, =ADC1_SC3_CAL
	str r0, [r3]

	// warte auf Abschluss der Kalibrierung
	ldr r3, =ADC1_SC1A_COCO
wait_for_calibration:
	ldr r2, [r3]
	cmp r2, #1
	bne wait_for_calibration

	// pruefe, ob Kalibrierung erfolgreich war
	ldr r3, =ADC1_SC3_CALF
	ldr r2, [r3]
	cmp r2, #0
	it ne
	movne r0, r2
	bne adc_calibration_return

	/* Post-Kalibrierung */
	mov r0, #0
	ldr r1, =ADC1_CLP0
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLP0
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLP1
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLP2
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLP3
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLP4
	ldr r2, [r1]
	add r0, r2	// CLPS

	lsr r0, #1	// durch 2 teilen
	orr r0, #ADC1_CLxx_MSB_MASK	// MSB setzen
	ldr r2, =ADC1_PG
	strh r0, [r2]


	mov r0, #0
	ldr r1, =ADC1_CLM0
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLM0
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLM1
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLM2
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLM3
	ldr r2, [r1], #-BYTES_IN_WORD
	add r0, r2	// CLM4
	ldr r2, [r1]
	add r0, r2	// CLMS

	lsr r0, #1	// durch 2 teilen
	orr r0, #ADC1_CLxx_MSB_MASK	// MSB setzen
	ldr r2, =ADC1_MG
	strh r0, [r2]

	mov r0, #0
adc_calibration_return:
	bx lr

/*
* Interrupt Service Routine zur Behandlung eines Ablaufs des PIT1 (genutzt fuer 8bit Binaerzaehler) 
*/
.thumb_func
isr_timer:
	// PIT interrupt flag zuruecksetzen
	ldr r0, =PIT_TFLG1_TIF
	mov r1, #1
	str r1, [r0]
	// User-Flag setzen
	ldr r0, =flag_sek_abgelaufen
	mov r1, #1
	strb r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
