// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/***************** Konstantendeklarationen **********/
.equ SIM_SCGC4, 0x40048034
__BBREG SIM_I2C0, SIM_SCGC4, 6

.equ SIM_SCGC5, 0x40048038
__BBREG SIM_PORTD, SIM_SCGC5, 12

.equ SIM_SCGC6, 0x4004803C
__BBREG SIM_PIT, SIM_SCGC6, 23			// Adresse Bit zur Aktivierung der PIT-Clock

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_PIT1, START_VTABLE + 0x154		// Register fuer Adresse der PIT1-ISR

.equ NVIC_ISER2, 0xE000E108						// Adresse Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR2, 0xE000E288						// Adresse Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_PIT1, 1 << (69 - 64)			// Bitmask fuer PIT1 in NVIC_ISER2 und NVIC_ICPR2

.equ PIT_MCR, 0x40037000						// Adresse fuer Konfiguration PIT-Modul
__BBREG PIT_MDIS, PIT_MCR, 1					// Adresse PIT MDIS

.equ PIT_LDVAL1, 0x40037110						// Adresse fuer Startwert PIT1
.equ PIT1_INIT_VAL, 24999999					// Startwert PIT1 (1s)

.equ PIT_TCTRL1, 0x40037118
__BBREG PIT_TCTRL1_TEN, PIT_TCTRL1, 0			// Adresse PIT1 Timer Enable Bit
__BBREG PIT_TCTRL1_TIE, PIT_TCTRL1, 1			// Adresse PIT1 Timer Interrupt Enable Bit
.equ PIT_TFLG1, 0x4003711C
__BBREG PIT_TFLG1_TIF, PIT_TFLG1, 0				// Adresse PIT1 Timer Interrupt Flag

.equ PD8_9, 0x300				// Maske fuer PD8 und PD9
.equ PD8, 0x100					// Maske fuer PD8
.equ ALT_GPIO , 0x100			// Alternative 1: GPIO

.equ PORTD_PCR8, 0x4004C020
.equ PORTD_PCR9, 0x4004C024

.equ PORTD_PCRx_CONFIG, (1<<9) | (1<<5)			// Alternative 2, Open Drain Enable

.equ GPIOD_PDDR, 0x400FF0D4
.equ GPIOD_PDOR, 0x400FF0C0
.equ GPIOD_PDIR, 0x400FF0D0

.equ I2C0_A1, 0x40066000
.equ I2C0_A1_CONFIG, 0x0						// Wird nur im Master-Modus betrieben. Slave-Adresse irrelevant
.equ I2C0_F, 0x40066001
.equ I2C0_F_CONFIG, 0x12						// Multiplizierungsfaktor 1 (MULT=0), Clock Divider 64 (ICR=0x12), entspricht ca. 390kHz (max. Baudrate wird durch den DS75 bestimmt und betraegt 400kHz)
.equ I2C0_C1, 0x40066002
.equ I2C0_C1_CONFIG, (1 << 7)					// I2C0 Enable (IICEN=1), Interrupt Disable (IICIE=0), Slave Mode (MST=0), Receive Mode (TX=0)
.equ I2C0_C1_DISABLE, 0x0						// I2C0-Modul deaktivieren
__BBREG I2C0_MST, I2C0_C1, 5					// Adresse I2C0 MST (Master/Slave Mode)
__BBREG I2C0_TX, I2C0_C1, 4						// Adresse I2C0 TX (Receive/Transmit Mode)
__BBREG I2C0_TXAK, I2C0_C1, 3
__BBREG I2C0_RSTA, I2C0_C1, 2
.equ I2C0_S, 0x40066003
__BBREG I2C0_BUSY, I2C0_S, 5					// I2C0 Bus Busy Flag
__BBREG I2C0_ARBL, I2C0_S, 4					// I2C0 Arbitration Lost Flag
__BBREG I2C0_IICIF, I2C0_S, 1					// I2C0 Interrupt Flag
__BBREG I2C0_RXAK, I2C0_S, 0					// ACK received (0 = ack received)
.equ I2C0_D, 0x40066004
.equ I2C0_C2, 0x40066005
.equ I2C0_C2_CONFIG, 0x0						// 7-bit Adressen (ADEXT=0)
.equ I2C0_FLT, 0x40066006
.equ I2C0_FLT_CONFIG, 0x0						// kein Input Filter
.equ I2C0_RA, 0x40066007
.equ I2C0_RA_CONFIG, 0x0						// Wird nur im Master-Modus betrieben. Slave-Address-Range irrelevant
.equ I2C0_SMB,  0x40066008
.equ I2C0_SMB_CONFIG, 0x0						// SMB wird nicht verwendet
.equ I2C0_A2, 0x40066009
.equ I2C0_A2_CONFIG, 0x0						// Wird nur im Master-Modus betrieben. Slave-Adresse irrelevant
.equ I2C0_SLTH, 0x4006600A
.equ I2C0_SLTH_CONFIG, 0x0
.equ I2C0_SLTL, 0x4006600B
.equ I2C0_SLTL_CONFIG, 0x0

.equ DS75_I2C_ADDR_W, 0x90						// Slave Addresse zum Schreiben
.equ DS75_I2C_ADDR_R, 0x91						// Slave Address zum Lesen
.equ DS75_TEMP, 0x0								// Adresse DS75 Temperature Register
.equ DS75_CFG, 0x1								// Adresse DS75 Configuration Register
.equ DS75_CFG_CONFIG, 0x60						// Comparator Mode (TM=0), 12bit (R0=1, R1=1)
.equ DS75_THYST, 0x2							// Adresse DS75 T_HYST
.equ DS75_TOS, 0x3								// Adresse DS75 T_OS

.equ T_L_SHIFT, 0x4 - 0x2						// Wert fuer Rechtsshift von T_L fuer die Ausgabe auf dem Terminal: 4 bit nach Rechts um Index im String Array zu erhalten, 2 bit nach links (= Multiplikation mit 4), da jedes Speicherwort eine Groesse von 4 Byte hat
.equ DIFF_THYST_T0, 0x2							// Wert, der auf T0 aufaddiert wird, um T_HYST zu berechnen
.equ DIFF_TOS_T0, 0x3							// Wert, der auf T0 aufaddiert wird, um T_OS zu berechnen

.equ BITS_IN_BYTE, 0x8
.equ DELAY_LOOPS_2us, 0x19						// Anzahl Schleifendurchlaeufe in i2c_Delay fuer 2us Verzoegerung

.equ I2C_RESET_RETRIES, 0xA						// Maximale Anzahl I2C-Reset-Versuche
.equ I2C_START_RETRIES, 0x1						// Maximale Anzahl I2C-Start-Versuche

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
*	Registerbelegungen:
*		r4: Adresse I2C0_D
*		r5: read low byte
*		r6: read high byte
* 		r7: flag, das ersten lesezugriff signalisiert (fuer das Setzen von T_OS und T_HYST)
*		r8: Wert fuer T_OS
*		r9: Wert fuer T_HYST
*		r10: #0
*		r11: #1
*		r12: Adresse I2C0_TXAK 
*/
main:	
	bl uart_init

	bl I2CBus_Reset

	ldr r4, =I2C0_D
	mov r7, #1
	mov r10, #0
	mov r11, #1
	ldr r12, =I2C0_TXAK

	/* Konfiguration I2C */
	// PINs konfigurieren
	ldr r2, =PORTD_PCR8
	mov r3, #PORTD_PCRx_CONFIG
	str r3, [r2]
	ldr r2, =PORTD_PCR9
	str r3, [r2]

	// Takt für I2C0 Modul aktivieren
	ldr r2, =SIM_I2C0
	str r11, [r2]

	// I2C0 Konfigurieren
	ldr r1, =I2C0_C1
	mov r3, #I2C0_C1_DISABLE
	strb r3, [r1]

	ldr r2, =I2C0_F
	mov r3, #I2C0_F_CONFIG
	strb r3, [r2]

	ldr r2, =I2C0_C2
	mov r3, #I2C0_C2_CONFIG
	strb r3, [r2]

	ldr r2, =I2C0_FLT
	mov r3, #I2C0_FLT_CONFIG
	strb r3, [r2]

	ldr r2, =I2C0_RA
	mov r3, #I2C0_RA_CONFIG
	strb r3, [r2]

	ldr r2, =I2C0_SMB
	mov r3, #I2C0_SMB_CONFIG
	strb r3, [r2]

	ldr r2, =I2C0_A2
	mov r3, #I2C0_A2_CONFIG
	strb r3, [r2]
	
	ldr r2, =I2C0_SLTH
	mov r3, #I2C0_SLTH_CONFIG
	strb r3, [r2]
	
	ldr r2, =I2C0_SLTL
	mov r3, #I2C0_SLTL_CONFIG
	strb r3, [r2]

	mov r3, #I2C0_C1_CONFIG
	strb r3, [r1]

	/* Konfiguration PIT1 */
	// Takt für PIT Modul aktivieren (SIM)
	ldr r2, =SIM_PIT
	str r11, [r2]

	// Interrupt-Vektor zu PIT1 setzen
	ldr r2, =VTABLE_IRQ_PIT1
	ldr r3, =isr_timer
	str r3, [r2]

	// pending Interrupts zu PIT1 loeschen (NVIC)
	mov r3, #NVIC_BITMASK_PIT1
	ldr r2, =NVIC_ICPR2
	str r3, [r2]

	// Interrupt zu PIT1 aktivieren (NVIC)
	ldr r2, =NVIC_ISER2
	str r3, [r2]

	// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	ldr r2, =PIT_MDIS
	str r10, [r2]

	// Startwert fuer PIT1 auf 1 Sekunde initialisieren
	ldr r2, =PIT_LDVAL1
	ldr r3, =PIT1_INIT_VAL
	str r3, [r2]

	// Interrupt fuer PIT1 aktivieren
	ldr r2, =PIT_TCTRL1_TIE
	str r11, [r2]

	// PIT1 aktivieren	
	ldr r2, =PIT_TCTRL1_TEN
	str r11, [r2]

	/* Auflösung 12 bit und Thermostat Comparator-Mode einstellen */
	mov r0, #DS75_I2C_ADDR_W
	bl i2c_Start

	// select configuration register
	mov r0, #DS75_CFG						// Pointer auf Konfigurationsbyte setzen
	strb r0, [r4]
	bl i2c_Wait

	strb r11, [r12]							// letztes Byte wird uebertragen: NAK-Signal ausgeben

	mov r0, #DS75_CFG_CONFIG
	strb r0, [r4]							// Konfigurationsbyte schreiben
	bl i2c_Wait

	bl i2c_Stop

loop_program:
	ldr r2, =flag_sek_abgelaufen
	ldrb r1, [r2]
	cmp r1, #1
	bne loop_program
	strb r10, [r2]

	/* Temperatur auslesen */
	mov r0, #DS75_I2C_ADDR_W
	bl i2c_Start

	mov r1, #DS75_TEMP
	strb r1, [r4]							// Pointer auf Temperatur setzen
	bl i2c_Wait

	// TX abgeschlossen, Wechsel auf RX um Temperatur auszulesen
	mov r0, #DS75_I2C_ADDR_R
	bl i2c_RepeatStart

	ldr r2, =I2C0_TX
	strb r10, [r2]							// Modul in RX-Modus schalten

	strb r10, [r12]							// TXACK fuer Bestaetigung nach Lesen des ersten Bytes setzen

	ldrb r3, [r4]							// dummy read
	bl i2c_Wait

	strb r11, [r12]							// vorletztes Byte wurde gelesen: TXNACK fuer Ende des Lesevorgangs nach letztem Byte setzen

	ldrb r5, [r4]							// MS Byte lesen
	bl i2c_Wait

	bl i2c_Stop
	
	ldrb r6, [r4]							// LS Byte lesen

	/* Temperatur in lesbares Format konvertieren und auf Terminal ausgeben */
	ldr r0, =str_hex
	bl uart_putString
	
	// Ausgabe Hexadezimalwert
	mov r0, r5
	lsl r0, r0, #BITS_IN_BYTE
	orr r0, r0, r6
	lsl r0, r0, #BITS_IN_BYTE
	bl uart_putInt32

	ldr r0, =str_sep
	bl uart_putString
	
	// Ausgabe Dezimalwert
	mov r0, r5
	mov r1, r6
	bl print_temperature

	/* T_OS und T_HYST setzen falls erster Durchlauf */
	cmp r7, #1
	bne loop_program
	mov r7, #0

	// Es wird mit einem ganzzahligen Offset gearbeitet, daher ist das LS Byte, das die Nachkommastellen angibt, bei T_OS und T_HYST gleich dem von T0
	add r8, r5, #DIFF_TOS_T0				// MS Byte von T_OS berechnen
	add r9, r5, #DIFF_THYST_T0				// MS Byte von T_HYST berechnen

	// T_OS schreiben
	mov r0, #DS75_I2C_ADDR_W
	bl i2c_Start

	mov r0, #DS75_TOS
	strb r0, [r4]							// Pointer auf T_OS setzen
	bl i2c_Wait

	strb r8, [r4]							// MS Datenbyte schreiben
	bl i2c_Wait

	strb r6, [r4]							// LS Datenbyte schreiben
	bl i2c_Wait

	// T_HYST schreiben
	mov r0, #DS75_I2C_ADDR_W
	bl i2c_RepeatStart

	mov r0, #DS75_THYST
	strb r0, [r4]							// Pointer auf T_HYST setzen
	bl i2c_Wait

	strb r9, [r4]							// MS Datenbyte schreiben
	bl i2c_Wait

	strb r11, [r12]							// letztes Byte wird uebertragen: NAK-Signal ausgeben

	strb r6, [r4]							// LS Datenbyte schreiben
	bl i2c_Wait

	bl i2c_Stop

	// DS75-Konfiguration auf dem Terminal ausgeben
	ldr r0, =str_configuration_complete
	bl uart_putString
	mov r0, r8
	mov r1, r6
	bl print_temperature
	ldr r0, =str_THYST
	bl uart_putString
	mov r0, r9
	mov r1, r6
	bl print_temperature

	b loop_program


	/* Behandlung von Fehlern, die nicht kompensiert werden koennen/sollen */
error_reset:
	ldr r0, =str_err_i2c_reset
	b print_error_message
	
error_arbl:
	ldr r0, =str_err_i2c_arbl

print_error_message:
	bl uart_putString						// Fehlermeldung auf dem Terminal ausgeben				

	ldr r2, =I2C0_C1
	mov r3, #I2C0_C1_DISABLE
	strb r3, [r2]							// I2C0-Modul deaktivieren

end:
	b end

/*
*	Unterprogramm zur Ausgabe eines DS75-Temperaturwertes als Dezimalzahl in Grad Celsius
*	
*	Uebergabewerte:
*		r0: MS Byte
*		r1: LS Byte
*
*	Rueckgabewerte: -
*
*	Registerbelegungen: 
*		r4: Buffer fuer LS Byte
*/
.thumb_func
print_temperature:
	push {r4, lr}
	mov r4, r1

	// Ausgabe ganzzahliger Teil
	bl uart_putByteBase10

	// Ausgabe Nachkommastellen
	lsr r0, r4, #T_L_SHIFT					// Index in String-Array berechnen
	ldr r1, =str_decimals
	add r1, r1, r0							// an berechneten Index springen
	ldr r0, [r1]							// String-Adresse laden
	bl uart_putString

	ldr r0, =str_celsius
	bl uart_putString
	pop {r4, pc}

/*
*	Unterprogramm zur Generierung eines 2us Delay nach Abschluss einer I2C-Uebertragung
*	
*	Uebergabewerte: -
*
*	Rueckgabewerte: -
*
*	Registerbelegungen: -
*/
.thumb_func
i2c_Delay:
	mov r0, #DELAY_LOOPS_2us
loop_i2c_Delay:
	subs r0, r0, #1
	bne loop_i2c_Delay
	bx lr

/*
*	Unterprogramm zum Starten einer I2C-Kommunikation
*	
*	Uebergabewerte: 
*		r0:	Slave-Adresse
*
*	Rueckgabewerte: -
*
*	Registerbelegungen:
*		r4: Buffer fuer Slave-Adresse
*		r5: Verbleibende Start-Versuche
*/
.thumb_func
i2c_Start:
	push {r4-r5, lr}
	mov r4, r0
	mov r1, #1

	// Modul in TX-Modus setzen
	ldr r2, =I2C0_TX
	strb r1, [r2]

	mov r5, #I2C_START_RETRIES

	ldr r2, =I2C0_MST
	ldr r3, =I2C0_ARBL
loop_i2c_start_signal:
	// START-Signal
	strb r1, [r2]
	ldrb r0, [r3]							// ARBL-Flag pruefen und ggf. Startbedingung wiederholen
	cmp r0, #0
	beq start_wait_busy						// Startbedingung erfolgreich ausgefuehrt
	mov r1, #0
	strb r1, [r2]
	subs r5, r5, #1
	bne loop_i2c_start_signal

	b error_arbl							// max. Anzahl Wiederholungen ueberschritten -> in Fehlerzustand uebergehen

start_wait_busy:
	ldr r2, =I2C0_BUSY
loop_start_wait_busy:
	ldrb r3, [r2]
	cmp r3, #1
	bne loop_start_wait_busy
	
	ldr r2, =I2C0_D
	strb r4, [r2]							// sende Slave-Adresse

	bl i2c_Wait

	pop {r4-r5, pc}

/*
*	Unterprogramm zur Generierung eines wiederholten Startsignals auf dem I2C-Bus
*	
*	Uebergabewerte: 
*		r0:	Slave-Adresse
*
*	Rueckgabewerte: -
*
*	Registerbelegungen: -
*/
.thumb_func
i2c_RepeatStart:
	push {lr}
	mov r1, #1
	ldr r2, =I2C0_RSTA
	strb r1, [r2]
	bl i2c_Start
	pop {pc}

/*
*	Unterprogramm zum Warten auf das Ende einer Uebertragung (Interrupt Flag)
*	
*	Uebergabewerte: -
*
*	Rueckgabewerte: -
*
*	Registerbelegungen: -
*/
.thumb_func
i2c_Wait:
	ldr r0, =I2C0_IICIF

wait_for_interrupt_flag:
	ldrb r1, [r0]
	cmp r1, #1
	bne wait_for_interrupt_flag

	strb r1, [r0]							// Interrupt-Flag zuruecksetzen
	bx lr

/*
*	Unterprogramm zum Beenden einer I2C-Kommunikation
*	
*	Uebergabewerte: -
*
*	Rueckgabewerte: -
*
*	Registerbelegungen: -
*/
.thumb_func
i2c_Stop:
	push {lr}
	mov r0, #0

	ldr r1, =I2C0_TX
	strb r0, [r1]							// Modul in RX-Modus schalten
	
	ldr r2, =I2C0_MST
	strb r0, [r2]							// STOP-Signal generieren

	// warten, bis Bus wieder freigegeben ist
	ldr r2, =I2C0_BUSY
stop_wait_notbusy:
	ldrb r0, [r2]
	cmp r0, #0
	bne stop_wait_notbusy

	bl i2c_Delay
	pop {pc}


/*
*	Unterprogramm zum Zuruecksetzen des I2C-Bus
*	
*	Uebergabewerte: -
*
*	Rueckgabewerte:
*		r0: 0 falls erfolgreich, Fehlercode falls Fehler
*
*	Registerbelegungen: -
*/
.thumb_func
I2CBus_Reset:
	push {lr}

	ldr r0, =SIM_PORTD			// Den Takt fuer Port D aktivieren
	mov r1, #1
	str r1, [r0]
	ldr	r0, =PORTD_PCR8			// Portleitungen PD8 , PD9 als GPIO
	ldr r1, =PORTD_PCR9
	mov r2, #ALT_GPIO
	str r2, [r0]
	str r2, [r1]
	ldr r0, =GPIOD_PDDR			// PD8, PD9 als Ausgang schalten
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]

	mov r3, #(I2C_RESET_RETRIES + 1)

loop:
	subs r3, r3, #1
	it eq
	beq error_reset

	ldr r0, =GPIOD_PDOR 		// SCL deaktivieren
	ldr r2, [r0]
	bic r2, r2, #PD8			// entsprechendes Bit loeschen
	str r2, [r0]
	bl i2c_Delay

	ldr r0, =GPIOD_PDOR			// SCL und SDA aktivieren
	ldr r2, [r0]
	orr r2, r2, #PD8_9
	str r2, [r0]
	bl i2c_Delay

	ldr r0, =GPIOD_PDIR
	ldr r2, [r0]
	and r2, r2, #PD8_9			// nur Bits 9 und 10 pruefen
	cmp r2, #PD8_9				// Bit 9 und Bit 10 gesetzt ?
	bne loop

	pop {pc}

/*
* Interrupt Service Routine zur Behandlung eines Ablaufs des PIT1 (genutzt fuer 8bit Binaerzaehler) 
*/
.thumb_func
isr_timer:
	mov r1, #1

	ldr r0, =PIT_TFLG1_TIF
	str r1, [r0]				// PIT interrupt flag zuruecksetzen

	ldr r0, =flag_sek_abgelaufen
	strb r1, [r0]				// User-Flag setzen

	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
flag_sek_abgelaufen: .byte 0x0

str_0_16th: .asciz ",0"
str_1_16th: .asciz ",0625"
str_2_16th: .asciz ",125"
str_3_16th: .asciz ",1875"
str_4_16th: .asciz ",25"
str_5_16th: .asciz ",3125"
str_6_16th: .asciz ",375"
str_7_16th: .asciz ",4375"
str_8_16th: .asciz ",5"
str_9_16th: .asciz ",5625"
str_10_16th: .asciz ",625"
str_11_16th: .asciz ",6875"
str_12_16th: .asciz ",75"
str_13_16th: .asciz ",8125"
str_14_16th: .asciz ",875"
str_15_16th: .asciz ",9375"

.align 4
str_decimals: .word str_0_16th, str_1_16th, str_2_16th, str_3_16th, str_4_16th, str_5_16th, str_6_16th, str_7_16th, str_8_16th, str_9_16th, str_10_16th, str_11_16th, str_12_16th, str_13_16th, str_14_16th, str_15_16th	// Array mit Strings fuer die Nachkommastellen

str_hex: .asciz "0x"
str_sep: .asciz ": "
str_celsius: .asciz " Grad Celsius\n"
str_err_i2c_reset: .asciz "ERROR: Maximale Anzahl I2C-Reset-Versuche erreicht. Programm wird beendet.\n"
str_err_i2c_arbl: .asciz "ERROR: Zu viele fehlgeschlagene Uebertragungsstart-Versuche. Programm wird beendet.\n"
str_THYST: .asciz "T_HYST: "
str_configuration_complete: .asciz "Konfiguration und Initialisierung des DS75 abgeschlossen.\nAufloesung: 12bit\nThermostat-Modus: Comparator\nTOS: "
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstantendeklarationen
/* SPI */
.equ SIM_SCGC3, 0x40048030
__BBREG SIM_SPI2, SIM_SCGC3, 12					// Adresse Bit zur Aktivierung des SPI2-Moduls
.equ SIM_SCGC5, 0x40048038
__BBREG SIM_PORTD, SIM_SCGC5, 12				// Adresse Bit zur Aktivierung von PORTD

.equ PORTD_PCR12, 0x4004C030					// PIN SPI2_CLK
.equ PORTD_PCR13, 0x4004C034					// PIN SPI2_SDO
.equ PORTD_PCR14, 0x4004C038					// PIN SPI2_SDI
.equ PORTD_PCR15, 0x4004C03C					// PIN SPI2_PCS1

.equ PORTx_PCR_SPI_CONFIG, (0x2 << 8)			// MUX Alternative 2 (SPI)

.equ SPI2_MCR, 0x400AC000
__BBREG SPI2_MCR_HALT, SPI2_MCR, 0				// HALT bit
.equ SPI2_MCR_CONFIG, (1 << 31) | (1 << 13) | (1 << 12) | (1 << 0) // Master Mode (MSTR=1), FIFOs disabled (DIS_TXF = 1, DIS_RXF = 1), stop module transfers (HALT = 1)
.equ SPI2_TCR, 0x400AC008
.equ SPI2_CTARx_CONFIG_COMMON, (1 << 25) | (0x7 << 0) // Clock Polarity egal, CPHA = 1 (wie in DS1722-Manual vorgegeben), Baud Rate Prescaler 2 (PBR = 0b00), Baud Rate Scaler 128 (BR = 0x7)
.equ SPI2_CTAR0, 0x400AC00C
.equ SPI2_CTAR0_CONFIG, (0xF << 27) | SPI2_CTARx_CONFIG_COMMON // Frame Size 16 bit (FMSZ = 15)
.equ SPI2_CTAR1, 0x400AC010
.equ SPI2_CTAR1_CONFIG, (0x7 << 27) | SPI2_CTARx_CONFIG_COMMON // Frame Size 8 bit (FMSZ = 7)
.equ SPI2_SR, 0x400AC02C
__BBREG SPI2_SR_RFDF, SPI2_SR, 17				// Receive FIFO Drain Flag
.equ SPI2_RSER, 0x400AC030
.equ SPI2_PUSHR, 0x400AC034
.equ SPI2_PUSHR_CONFIG_TX_16BIT, (1 << 31) | (0x2 << 16)	// Chip Select aktiviert halten (CONT = 1), CTAR0 nutzen (CTAS = 0x0), Chip Select PCS1 (PCS = 0x2)
.equ SPI2_PUSHR_CONFIG_TX_16BIT_LASTFRAME,  (1 << 27) | (0x2 << 16) // PCS nach Ende Uebertragung abschalten (CONT = 0), End of Queue Flag setzen (EOQ = 1), CTAR0 nutzen (CTAS = 0x0), Chip Select PCS1 (PCS = 0x2)
.equ SPI2_PUSHR_CONFIG_TX_8BIT_LASTFRAME, SPI2_PUSHR_CONFIG_TX_16BIT_LASTFRAME | (1 << 28) // CTAR1 nutzen (CTAS = 0x1), sonst wie bei 16 bit
.equ SPI2_POPR, 0x400AC038

/* DS1722 */
.equ DS1722_TEMP_LSB_R, 0x01					// Adresse fuer Lesezugriff auf das LSB des Temperaturwertes
.equ DS1722_CONFIG_W, 0x80						// Adresse fuer Schreibzugriff auf das Konfigurationsbyte
.equ DS1722_CONFIG_BASIC, 0xE0					// Allgemeine Konfiguration DS1722 ohne Aufloesungsbits
.equ DS1722_CONFIG_BITS_RES, 0x1				// Bitposition der Aufloesungsbits
.equ DS1722_MIN_RES, 0x0						// Wert Aufloesungsbits/r4 bei minimaler Aufloesung (8 bit)
.equ DS1722_MIN_RES_VALUE, 0x8					// minimale Aufloesung in bit
.equ DS1722_MAX_RES, 0x4						// Wert Aufloesungsbits/r4 bei maximaler Aufloesung (12 bit)
.equ DS1722_CONFIG_12BIT, DS1722_CONFIG_BASIC | (DS1722_MAX_RES << 1)	// Wert des Konfigurationsbytes bei 12 bit Aufloesung (gewuenschter Initialwert)

.equ MIN_CONVERSION_TIME_MS, 75					// minimale Konvertierungszeit in ms (= bei 8 bit Aufloesung)

/* Buttons */
__BBREG SIM_PORTE, SIM_SCGC5, 13				// Adresse Bit zur Aktivierung von PORTE
__BBREG SIM_PORTA, SIM_SCGC5, 9					// Adresse Bit zur Aktivierung von PORTA

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_PORTA, START_VTABLE + 0x19C 	// Register fuer Adresse der PORT-A-ISR
.equ VTABLE_IRQ_PORTE, START_VTABLE + 0x1AC 	// Register fuer Adresse der PORT-E-ISR

.equ PORTA_PCR19, 0x4004904C					// Adresse Pin Control Register PTA19 (SW1)
__BBREG PORTA_PCR19_ISF, PORTA_PCR19, 24		// Adresse Interrupt Status Flag fuer SW1
.equ PORTE_PCR26, 0x4004D068					// Adresse Pin Control Register PTE26 (SW2)
__BBREG PORTE_PCR26_ISF, PORTE_PCR26, 24		// Adresse Interrupt Status Flag fuer SW2
.equ SW_PORT_MASK, (0b1010 << 16) | (0b001 << 8) | (1 << 1) | (1 << 0)	// GPIO Mode (MUX = 001), Interrupt bei fallender Flanke (IRQC = 1010), Pullup Widerstand (PE = 1, PS = 1)

.equ NVIC_BITMASK_PORTA_PORTE, (1 << (87 - 64)) | (1 << (91 - 64))	// Bitmask fuer PIT1, PIT2 und SW2 (PORTE) in NVIC_ISER2 und NVIC_ICPR2

.equ GPIOA_PDDR, 0x400FF014
__BBREG GPIOA_PDDR_PDO19, GPIOA_PDDR, 19		// Adresse SW1 Direction Bit
.equ GPIOE_PDDR, 0x400FF114
__BBREG GPIOE_PDDR_PDO26, GPIOE_PDDR, 26		// Adresse SW2 Direction Bit

/* PIT */
.equ SIM_SCGC6, 0x4004803C
__BBREG SIM_PIT, SIM_SCGC6, 23					// Adresse Bit zur Aktivierung der PIT-Clock

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_PIT1, START_VTABLE + 0x154		// Register fuer Adresse der PIT1-ISR

.equ NVIC_ISER2, 0xE000E108						// Adresse Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR2, 0xE000E288						// Adresse Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_PIT1, 1 << (69 - 64)			// Bitmask fuer PIT1 in NVIC_ISER2 und NVIC_ICPR2

.equ PIT_MCR, 0x40037000						// Adresse fuer Konfiguration PIT-Modul
__BBREG PIT_MDIS, PIT_MCR, 1					// Adresse PIT MDIS

.equ PIT_LDVAL1, 0x40037110						// Adresse fuer Startwert PIT1

.equ PIT_TCTRL1, 0x40037118
__BBREG PIT_TCTRL1_TEN, PIT_TCTRL1, 0			// Adresse PIT1 Timer Enable Bit
__BBREG PIT_TCTRL1_TIE, PIT_TCTRL1, 1			// Adresse PIT1 Timer Interrupt Enable Bit
.equ PIT_TFLG1, 0x4003711C
__BBREG PIT_TFLG1_TIF, PIT_TFLG1, 0				// Adresse PIT1 Timer Interrupt Flag

.equ MIN_CONVERSION_TIME_TIMER_VAL, (25000 * MIN_CONVERSION_TIME_MS)	// Timerwert fuer minimale Konvertierungszeit
.equ TIMER_INIT_VAL, (MIN_CONVERSION_TIME_TIMER_VAL << DS1722_MAX_RES)	// Initialisierungswert fuer Timer: Konvertierungszeit bei 12 bit Aufloesung

/* Flags */
.equ FLAG_RES_INC, 0x1							// Flag-Wert SW1 gedrueckt (inkrementiere Aufloesung)
.equ FLAG_RES_DEC, 0x2							// Flag-Wert SW2 gedrueckt (dekrementiere Aufloesung)

/* Sonstige Konstanten */
.equ BITMASK_BYTE, 0xFF							// Bitmaske fuer niederwertigstes Byte
.equ SHIFT_LSB_TO_IDX, 0x2						// Anzahl Bits, die das LSB der Temperatur geschoben werden muss um den Index im String-Array zu erhalten
.equ SPI_TIMEOUT, 0x1000						// Timeout fuer SPI-Uebertragung

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
*	Registerbelegungen:
*		r4: aktuelle Aufloesung
*		r5: Temp LSB
*		r6: Temp MSB
*		r7: Adresse SPI2_MCR_HALT
*		r8: Adresse flag_inc_dec
*		r9: Adresse SPI2_PUSHR
*		r10: #0
*		r11: #1
*		r12: Adresse flag_timer_abgelaufen
*/
main:	
	bl uart_init

	mov r4, #DS1722_MAX_RES					// initiale Aufloesung: 12 bit
	ldr r7, =SPI2_MCR_HALT
	ldr r8, =flag_inc_dec
	ldr r9, =SPI2_PUSHR
	mov r10, #0
	mov r11, #1
	ldr r12, =flag_timer_abgelaufen

	/* Konfiguration SPI2 */
	// PORTD Modul aktivieren
	ldr r2, =SIM_PORTD
	str r11, [r2]

	// PINs konfigurieren
	mov r3, #PORTx_PCR_SPI_CONFIG
	ldr r2, =PORTD_PCR12
	str r3, [r2]
	ldr r2, =PORTD_PCR13
	str r3, [r2]
	ldr r2, =PORTD_PCR14
	str r3, [r2]
	ldr r2, =PORTD_PCR15
	str r3, [r2]

	// Takt fuer SPI2 Modul aktivieren
	ldr r2, =SIM_SPI2
	str r11, [r2]

	// Konfiguration fuer SPI2-Modul schreiben
	ldr r2, =SPI2_MCR
	ldr r3, =SPI2_MCR_CONFIG
	str r3, [r2]
	str r3, [r2]								// erneut schreiben, da DIS_TXF und DIS_RXF erst bei MDIS=0 geschrieben werden koennen

	// Init Transmission Counter mit 0
	ldr r2, =SPI2_TCR
	str r10, [r2]								

	// Kommunikationsparameter konfigurieren
	ldr r2, =SPI2_CTAR0
	ldr r3, =SPI2_CTAR0_CONFIG
	str r3, [r2]
	ldr r2, =SPI2_CTAR1
	ldr r3, =SPI2_CTAR1_CONFIG
	str r3, [r2]

	// Interrupt Requests deaktivieren
	ldr r2, =SPI2_RSER
	str r10, [r2]

	/* Konfiguration Buttons */
	// Interrupt-Vektor zu SW1 und SW2 setzen
	ldr r3, =isr_sw1
	ldr r2, =VTABLE_IRQ_PORTA
	str r3, [r2]
	ldr r3, =isr_sw2
	ldr r2, =VTABLE_IRQ_PORTE
	str r3, [r2]

	// PORTA und PORTE Module aktivieren
	ldr r2, =SIM_PORTA
	str r11, [r2]
	ldr r2, =SIM_PORTE
	str r11, [r2]

	// konfiguriere GPIO mode + Interrupt fuer PTA19 (SW1) und PTE26 (SW2)
	ldr r0, =SW_PORT_MASK
	ldr r1, =PORTA_PCR19
	str r0, [r1]
	ldr r1, =PORTE_PCR26
	str r0, [r1]
	
	// setze Direction des SW1-Pins und SW2-Pins auf Input
	mov r0, #0
	ldr r1, =GPIOA_PDDR_PDO19
	str r0, [r1]
	ldr r1, =GPIOE_PDDR_PDO26
	str r0, [r1]

	/* Konfiguration PIT1 */
	// Takt fuer PIT Modul aktivieren (SIM)
	ldr r2, =SIM_PIT
	str r11, [r2]

	// Interrupt-Vektor zu PIT1 setzen
	ldr r2, =VTABLE_IRQ_PIT1
	ldr r3, =isr_timer
	str r3, [r2]

	// pending Interrupts zu PIT1, SW1 und SW2 loeschen (NVIC)
	ldr r3, =(NVIC_BITMASK_PIT1 | NVIC_BITMASK_PORTA_PORTE)
	ldr r2, =NVIC_ICPR2
	str r3, [r2]

	// Interrupt zu PIT1, SW1 und SW2 aktivieren (NVIC)
	ldr r2, =NVIC_ISER2
	str r3, [r2]

	// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	ldr r2, =PIT_MDIS
	str r10, [r2]

	// Startwert fuer PIT1 auf Wandlungszeit bei 12 bit (1.2s) initialisieren
	ldr r2, =PIT_LDVAL1
	ldr r3, =TIMER_INIT_VAL
	str r3, [r2]

	// Interrupt fuer PIT1 aktivieren
	ldr r2, =PIT_TCTRL1_TIE
	str r11, [r2]

	// PIT1 aktivieren	
	ldr r2, =PIT_TCTRL1_TEN
	str r11, [r2]

	/* initiale Konfiguration DS1722 */
	mov r0, #DS1722_CONFIG_12BIT
	bl spi_write_config

loop_program:
	/* pruefe, ob ein Taster gedrueckt wurde */
	ldrb r0, [r8]
	strb r10, [r8]
	cmp r0, #FLAG_RES_INC
	beq increase_resolution
	cmp r0, #FLAG_RES_DEC
	beq decrease_resolution
	b check_flag_timer

increase_resolution:
	/* inkrementiere Aufloesung oder setze auf Minimum, falls bereits bei Maximum */
	cmp r4, #DS1722_MAX_RES
	ite eq
	moveq r4, #DS1722_MIN_RES
	addne r4, r4, #1
	ldr r0, =str_res_inc
	b write_new_config

decrease_resolution:
	/* dekrementiere Aufloesung oder setze auf Maximum, falls bereits bei Minimum */
	cmp r4, #DS1722_MIN_RES
	ite eq
	moveq r4, #DS1722_MAX_RES
	subne r4, r4, #1
	ldr r0, =str_res_dec
	b write_new_config

write_new_config:
	bl uart_putString
	/* Sende Konfiguration fuer neue Auflosung an DS1722*/
	mov r0, r4
	lsl r0, r0, #DS1722_CONFIG_BITS_RES
	orr r0, r0, #DS1722_CONFIG_BASIC
	bl spi_write_config

	// PIT1 deaktivieren
	ldr r2, =PIT_TCTRL1_TEN
	str r10, [r2]

	// neuen Wert fuer PIT1 berechnen (= Wert fuer 8 bit multipliziert mit 2^Aufloesungsstufe)
	ldr r0, =MIN_CONVERSION_TIME_TIMER_VAL
	lsl r0, r0, r4
	ldr r1, =PIT_LDVAL1
	str r0, [r1]

	// PIT1 aktivieren
	str r11, [r2]

	// evtl. in der Zwischenzeit gesetztes Timer abgelaufen flag zuruecksetzen
	strb r10, [r12]

	ldr r0, =str_new_res
	bl uart_putString
	add r0, r4, #DS1722_MIN_RES_VALUE
	bl uart_putByteBase10

check_flag_timer:
	ldrb r0, [r12]
	cmp r0, #1
	bne loop_program

	// Timer abgelaufen Flag zuruecksetzen
	strb r10, [r12]

	/* Temperatur auslesen */
	// SPI aktivieren
	str r10, [r7]

	// Registeradresse uebertragen
	ldr r3, =(SPI2_PUSHR_CONFIG_TX_16BIT | (DS1722_TEMP_LSB_R << 8) | 0)
	str r3, [r9]

	// LSB auslesen
	bl spi2_read
	and r0, r0, #BITMASK_BYTE
	mov r5, r0

	// dummy write
	ldr r3, =SPI2_PUSHR_CONFIG_TX_8BIT_LASTFRAME
	str r3, [r9]

	// MSB auslesen
	bl spi2_read
	and r0, r0, #BITMASK_BYTE
	mov r6, r0

	// SPI deaktivieren
	str r10, [r7]

	/* Temperatur auf dem Terminal ausgeben */
	mov r0, '\n'
	bl uart_putChar
	mov r0, r6
	bl uart_putByteBase10

	// shifte LSB-Bits nach rechts, sodass die jeweils relevanten Bits als Index fuer das String-Array genutzt werden koennen
	lsr r0, r5, #SHIFT_LSB_TO_IDX

	// passenden String ermitteln
	ldr r1, =str_arr_decimals
	ldr r0, [r1, r0]
	bl uart_putString

	ldr r0, =str_celsius
	bl uart_putString

	b loop_program

error_timeout:
	ldr r0, =str_error_timeout
	bl uart_putString
end:
	b end

/*
*	Unterprogramm zum Lesen eines Wertes aus der SPI-Schnittstelle
*	
*	Uebergabewerte: -
*
*	Rueckgabewerte:
*		r0: gelesener Wert
*
*	Registerbelegungen: -
*/
.thumb_func
spi2_read:
	ldr r2, =SPI2_SR_RFDF
	mov r3, #SPI_TIMEOUT
loop_wait_rx:
	subs r3, r3, #1
	beq error_timeout
	ldr r0, [r2]
	cmp r0, #1
	bne loop_wait_rx

	ldr r2, =SPI2_POPR
	ldr r0, [r2]

	mov r1, #1
	ldr r2, =SPI2_SR_RFDF
	str r1, [r2]
	
	bx lr

/*
*	Unterprogramm zum Schreiben des Konfigurationsregisters des DS1722
*	
*	Uebergabewerte:
*		r0: Konfigurationsbyte
*
*	Rueckgabewerte: -
*
*	Registerbelegungen: -
*/
.thumb_func
spi_write_config:
	push {lr}
	// SPI aktivieren
	mov r1, #0
	ldr r2, =SPI2_MCR_HALT
	str r1, [r2]

	// Adresse Konfigurationsregister und Konfigurationswert schreiben
	ldr r2, =SPI2_PUSHR
	ldr r3, =(SPI2_PUSHR_CONFIG_TX_16BIT_LASTFRAME | (DS1722_CONFIG_W << 8))
	orr r3, r3, r0
	str r3, [r2]

	// Dummy-Read um Lesebuffer zu leeren
	bl spi2_read

	// SPI deaktivieren
	mov r1, #1
	ldr r2, =SPI2_MCR_HALT
	str r1, [r2]
	pop {pc}

/*
* Interrupt Service Routine zur Behandlung einer fallenden Flanke an SW1
*/
.thumb_func
isr_sw1:
	// User-Flag setzen
	ldr r1, =flag_inc_dec
	mov r0, #FLAG_RES_INC
	strb r0, [r1]
	
	// interrupt flag von SW1 zuruecksetzen
	ldr r1, =PORTA_PCR19_ISF
	mov r0, #1
	str r0, [r1]
	
	bx lr

/*
* Interrupt Service Routine zur Behandlung einer fallenden Flanke an SW2
*/
.thumb_func
isr_sw2:
	// User-Flag setzen
	ldr r1, =flag_inc_dec
	mov r0, #FLAG_RES_DEC
	strb r0, [r1]
	
	// interrupt flag von SW2 zuruecksetzen
	ldr r1, =PORTE_PCR26_ISF
	mov r0, #1
	str r0, [r1]
	
	bx lr

/*
* Interrupt Service Routine zur Behandlung eines Ablaufs des PIT1
*/
.thumb_func
isr_timer:
	mov r1, #1

	ldr r0, =PIT_TFLG1_TIF
	str r1, [r0]				// PIT interrupt flag zuruecksetzen

	ldr r0, =flag_timer_abgelaufen
	strb r1, [r0]				// User-Flag setzen

	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_timer_abgelaufen: .byte 0x0
flag_inc_dec: .byte 0x0

str_0_16th: .asciz ",0"
str_1_16th: .asciz ",0625"
str_2_16th: .asciz ",125"
str_3_16th: .asciz ",1875"
str_4_16th: .asciz ",25"
str_5_16th: .asciz ",3125"
str_6_16th: .asciz ",375"
str_7_16th: .asciz ",4375"
str_8_16th: .asciz ",5"
str_9_16th: .asciz ",5625"
str_10_16th: .asciz ",625"
str_11_16th: .asciz ",6875"
str_12_16th: .asciz ",75"
str_13_16th: .asciz ",8125"
str_14_16th: .asciz ",875"
str_15_16th: .asciz ",9375"

.align 4
str_arr_decimals: .word str_0_16th, str_1_16th, str_2_16th, str_3_16th, str_4_16th, str_5_16th, str_6_16th, str_7_16th, str_8_16th, str_9_16th, str_10_16th, str_11_16th, str_12_16th, str_13_16th, str_14_16th, str_15_16th	// Array mit Strings fuer die Nachkommastellen

str_res_inc: .asciz "\nAufloesung inkrementiert"
str_res_dec: .asciz "\nAufloesung dekrementiert"
str_new_res: .asciz ", neuer Wert: "
str_celsius: .asciz " gC"
str_error_timeout: .asciz "\nERR: Timeout bei der Datenuebertragung"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC6, 0x4004803C
__BBREG SIM_SCGC6_RTC, SIM_SCGC6, 29

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_RTC_TA, START_VTABLE + 0x148	// Register fuer Adresse der RTC-TA-ISR
.equ VTABLE_IRQ_RTC_TS, START_VTABLE + 0x14C	// Register fuer Adresse der RTC-TS-ISR

.equ NVIC_ISER2, 0xE000E108						// Adresse Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR2, 0xE000E288						// Adresse Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_RTC, (1 << (66 - 64)) | (1 << (67 - 64))	// Bitmask fuer RTC TS und RTC TA in NVIC_ISER2 und NVIC_ICPR2

.equ RTC_TSR, 0x4003D000
.equ RTC_TPR, 0x4003D004
.equ RTC_TAR, 0x4003D008
.equ RTC_TAR_TEST, 0xA
.equ RTC_TAR_1H, 0xE0F
.equ RTC_TAR_24H, 0x1517F
.equ RTC_TSR_PRESET_1H, RTC_TAR_1H - 4
.equ RTC_TSR_PRESET_24H, RTC_TAR_24H - 4
.equ RTC_CR, 0x4003D010
.equ RTC_CR_CONFIG, (1 << 8)					// Oszillator aktivieren (OSCE = 1)
.equ RTC_SR, 0x4003D014
.equ RTC_IER, 0x4003D01C
.equ RTC_IER_CONFIG, (1 << 4) | (1 << 2)		// Interrupts fuer Ablauf einer Sekunde (TSIE = 1) und erreichen des Alarmwertes (TAIE = 1) aktivieren

__BBREG RTC_SR_TCE, RTC_SR, 4

.equ SLEEP_VAL, 12500000

.equ MODE_1H, 0
.equ MODE_24H, 1

.equ TIME_DIV, 60								// Minuten pro Stunde / Sekunden pro Minute

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
*	Registerbelegungen:
*		r4: Adresse RTC_TSR
*		r5: Adresse flag_sek
*		r6: Adresse flag_alarm
*		r7: buffer
*		r8: TIME_DIV
*		r9: Output aktiviert
*		r10: #0 (= MODE_1H)
*		r11: #1 (= MODE_24H)
*		r12: Adresse mode
*/
main:	
	bl uart_init

	ldr r4, =RTC_TSR
	ldr r5, =flag_sek
	ldr r6, =flag_alarm
	mov r8, #TIME_DIV
	mov r9, #1
	mov r10, #0
	mov r11, #1
	ldr r12, =mode

	// RTC-Modul aktivieren (SIM)
	ldr r2, =SIM_SCGC6_RTC
	str r11, [r2]

	// RTC stoppen
	ldr r2, =RTC_SR_TCE
	str r10, [r2]

	// Interrupt-Vektoren setzen
	ldr r2, =VTABLE_IRQ_RTC_TS
	ldr r3, =rtc_ts_isr
	str r3, [r2]
	ldr r2, =VTABLE_IRQ_RTC_TA
	ldr r3, =rtc_ta_isr
	str r3, [r2]

	// Zeit-Register initialisieren
	ldr r2, =RTC_TPR
	str r10, [r2]
	str r10, [r4]

	// Alarm-Wert initialisieren
	ldr r2, =RTC_TAR
	ldr r3, =RTC_TAR_24H
	str r3, [r2]

	// Interrupts aktivieren
	ldr r2, =RTC_IER
	mov r3, #RTC_IER_CONFIG
	str r3, [r2]

	// Oszillator aktivieren
	ldr r2, =RTC_CR
	mov r3, #RTC_CR_CONFIG
	str r3, [r2]

	// Stabilisierung des Oszillator-Signals abwarten
	ldr r0, =SLEEP_VAL
loop_wait_oscillator_startup:
	subs r0, r0, #1
	bne loop_wait_oscillator_startup

	// pending Interrupts loeschen und Interrupts aktivieren
	ldr r3, =NVIC_BITMASK_RTC
	ldr r2, =NVIC_ICPR2
	str r3, [r2]
	ldr r2, =NVIC_ISER2
	str r3, [r2]

	// RTC starten
	ldr r2, =RTC_SR_TCE
	str r11, [r2]

	ldr r0, =str_reset_clock
	bl uart_putString

loop_program:
	bl uart_charPresent
	cmp r0, #0
	beq check_alarm
	bl uart_getChar
	cmp r0, 'd'
	beq set_day_mode
	cmp r0, 'h'
	beq set_hour_mode
	cmp r0, 'r'
	beq reset_clock
	cmp r0, 's'
	beq start_stop
	cmp r0, 'p'
	beq preset

set_day_mode:
	strb r11, [r12]
	bl rtc_set_alarm
	ldr r0, =str_24h
	bl uart_putString
	ldr r0, =str_reset_clock
	bl uart_putString
	b check_alarm

set_hour_mode:
	strb r10, [r12]
	bl rtc_set_alarm
	ldr r0, =str_1h
	bl uart_putString
	ldr r0, =str_reset_clock
	bl uart_putString
	b check_alarm

start_stop:
	eor r9, r9, #1
	cmp r9, #1
	ite eq
	ldreq r0, =str_print_on
	ldrne r0, =str_print_off
	bl uart_putString
	b check_alarm

reset_clock:
	mov r0, #0
	bl rtc_set_clock

	ldr r0, =str_reset_clock
	bl uart_putString
	b check_alarm

preset:
	ldrb r1, [r12]
	cmp r1, #MODE_1H
	ite eq
	ldreq r0, =RTC_TSR_PRESET_1H
	ldrne r0, =RTC_TSR_PRESET_24H
	bl rtc_set_clock
	ldr r0, =str_set_clock
	bl uart_putString

check_alarm:
	ldrb r0, [r6]
	cmp r0, #1
	bne check_flag_sek

	strb r10, [r6]
	ldr r0, =str_end
	bl uart_putString

	// Ausgabe deaktivieren
	mov r9, r10

check_flag_sek:
	ldrb r0, [r5]
	cmp r0, #1
	bne loop_program
	strb r10, [r5]

	cmp r9, #1
	bne loop_program

	ldr r0, [r4]
	mov r7, r0

	mov r0, '\n'
	bl uart_putChar

	/* Zeit in Sekunden zu hh:mm:ss konvertieren */
	mov r0, r7
	udiv r1, r0, r8
	udiv r2, r1, r8
	ldr r3, =time_h
	strb r2, [r3]
	mul r2, r2, r8
	sub r1, r1, r2
	ldr r3, =time_m
	strb r1, [r3]
	mul r2, r2, r8
	mul r1, r1, r8
	sub r0, r0, r2
	sub r0, r0, r1
	ldr r3, =time_s
	strb r0, [r3]

	/* Zeit ausgeben */
	ldrb r2, [r12]
	cmp r2, #MODE_1H
	beq print_1h_mode

	ldr r2, =time_h
	ldrb r0, [r2]
	bl uart_putByteBase10TwoDigits

	mov r0, ':'
	bl uart_putChar

print_1h_mode:
	ldr r2, =time_m
	ldrb r0, [r2]
	bl uart_putByteBase10TwoDigits

	mov r0, ':'
	bl uart_putChar

	ldr r2, =time_s
	ldrb r0, [r2]
	bl uart_putByteBase10TwoDigits

	b loop_program

/*
*	Unterprogramm um den RTC Timer auf einen bestimmten Wert zu setzen
*
*	Registerbelegung: -
*
*	Uebergabewerte: 
*		r0: neuer Wert fuer RTC_TSR
*
*	Rueckgabewerte: -
*/
.thumb_func
rtc_set_clock:
	mov r1, #0
	// RTC stoppen
	ldr r3, =RTC_SR_TCE
	str r1, [r3]

	// Counter auf uebergebenen Wert setzen
	ldr r2, =RTC_TPR
	str r1, [r2]
	ldr r2, =RTC_TSR
	str r0, [r2]

	// RTC starten
	mov r1, #1
	str r1, [r3]
	bx lr

/*
*	Unterprogramm zum Setzen des Wertes im RTC Alarm-Register (RTC_TAR)
*
*	Registerbelegung: -
*
*	Uebergabewerte: -
*
*	Rueckgabewerte: -
*/
.thumb_func
rtc_set_alarm:
	mov r0, #0
	// RTC stoppen
	ldr r1, =RTC_SR_TCE
	str r0, [r1]

	// Counter zuruecksetzen
	ldr r2, =RTC_TSR
	str r0, [r2]
	ldr r2, =RTC_TPR
	str r0, [r2]

	// neuen Wert in Alarmregister schreiben
	ldr r2, =mode
	ldrb r3, [r2]
	cmp r3, #MODE_1H
	ite eq
	ldreq r0, =RTC_TAR_1H
	ldrne r0, =RTC_TAR_24H

	ldr r2, =RTC_TAR
	str r0, [r2]

	// RTC starten
	mov r0, #1
	str r0, [r1]
	bx lr

/*
*	Unterprogramm zur zweistelligen Ausgabe einer Dezimalzahl auf dem Terminal
*	Fuegt ggf. eine fuehrende Null ein 
*
*	Registerbelegung: -
*
*	Uebergabewerte: 
*		r0: Dezimalzahl, die auf dem Terminal ausgegeben werden soll
*
*	Rueckgabewerte: -
*/
.thumb_func
uart_putByteBase10TwoDigits:
	push {r4, lr}
	cmp r0, #9
	bhi no_leading_zero
	mov r4, r0
	mov r0, '0'
	bl uart_putChar
	mov r0, r4
no_leading_zero:
	bl uart_putByteBase10
	pop {r4, pc}

/*
*	Interrupt Service Routine zur Behandlung des Sekunden-Interrupts der RTC
*/
.thumb_func
rtc_ts_isr:
	ldr r0, =flag_sek
	mov r1, #1
	strb r1, [r0]
	bx lr

/*
*	Interrupt Service Routine zur Behandlung des Alarm-Interrupts der RTC
*/
.thumb_func
rtc_ta_isr:
	// schreibe in RTC_TAR um Alarm-Flag zurueckzusetzen
	ldr r2, =RTC_TAR
	ldr r0, [r2]
	str r0, [r2]

	// setze User-Flag
	mov r0, #1
	ldr r2, =flag_alarm
	strb r0, [r2]
	bx lr


/*** Datenbereich (ab 0x20000000) ***/
.data
time_h: .byte 0x0
time_m: .byte 0x0
time_s: .byte 0x0
flag_sek: .byte 0x0
flag_alarm: .byte 0x0
mode: .byte 0x1
str_end: .asciz "\nEndzeitpunkt erreicht"
str_24h: .asciz "\n24-Stunden-Modus"
str_1h: .asciz "\n1-Stunden-Modus"
str_reset_clock: .asciz "\nUhr zurueckgesetzt"
str_set_clock: .asciz "\nUhr vorgestellt"
str_print_on: .asciz "\nAnzeige an"
str_print_off: .asciz "\nAnzeige aus"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
/* LED & GPIO */
.equ SIM_SCGC5, 0x40048038
__BBREG CLOCK_GATE_CTRL_PORTA, SIM_SCGC5, 9		// Adresse Bit zur Aktivierung der Clock fuer das Modul PORT A

.equ PORTA_PCR6, 0x40049018						// Adresse Pin Control Register PTA6
.equ PORTA_PCR10, 0x40049028					// Adresse Pin Control Register PTA10 (LED 4)
.equ GPIO_PORT_MASK, (1 << 8)					// GPIO Mode (MUX = 001), kein Interrupt

.equ GPIOA_PDDR, 0x400FF014						// Adresse GPIOA Port Data Direction Register
__BBREG GPIOA_PDDR_PDO6, GPIOA_PDDR, 6 			// Adresse PTA6 Direction Bit
__BBREG GPIOA_PDDR_PDO10, GPIOA_PDDR, 10		// Adresse LED 4 Direction Bit

.equ GPIOA_PSOR, 0x400FF004						// Adresse GPIOA Port Set Output Register
__BBREG GPIOA_PSOR_PDO10, GPIOA_PSOR, 10		// Adresse LED 4 Set Bit
__BBREG GPIOA_PSOR_PDO6, GPIOA_PSOR, 6			// Adresse PTA6 Set Bit

.equ GPIOA_PCOR, 0x400FF008
__BBREG GPIOA_PCOR_PDO10, GPIOA_PCOR, 10		// Adresse LED 4 Reset Bit
__BBREG GPIOA_PCOR_PDO6, GPIOA_PCOR, 6			// Adresse PTA6 Reset Bit

/* PIT */
.equ PIT_MCR, 0x40037000						// Adresse fuer Konfiguration PIT-Modul
__BBREG PIT_MDIS, PIT_MCR, 1					// Adresse PIT MDIS

.equ PIT_LDVAL1, 0x40037110						// Adresse fuer Startwert PIT1
.equ PIT_LDVAL2, 0x40037120						// Adresse fuer Startwert PIT2
.equ PIT_TCTRL1, 0x40037118
__BBREG PIT_TCTRL1_TEN, PIT_TCTRL1, 0			// Adresse PIT1 Timer Enable Bit
__BBREG PIT_TCTRL1_TIE, PIT_TCTRL1, 1			// Adresse PIT1 Timer Interrupt Enable Bit
.equ PIT_TCTRL2, 0x40037128
__BBREG PIT_TCTRL2_TEN, PIT_TCTRL2, 0			// Adresse PIT2 Timer Enable Bit
__BBREG PIT_TCTRL2_TIE, PIT_TCTRL2, 1			// Adresse PIT2 Timer Interrupt Enable Bit
.equ PIT_TFLG1, 0x4003711C
__BBREG PIT_TFLG1_TIF, PIT_TFLG1, 0				// Adresse PIT1 Timer Interrupt Flag
.equ PIT_TFLG2, 0x4003712C
__BBREG PIT_TFLG2_TIF, PIT_TFLG2, 0				// Adresse PIT2 Timer Interrupt Flag

.equ TIMER_VAL_100MS, 2500000-1
.equ TIMER_VAL_200MS, 5000000-1

/* RTC */
.equ SIM_SCGC6, 0x4004803C
__BBREG SIM_SCGC6_RTC, SIM_SCGC6, 29
__BBREG PIT_CLOCK_BIT, SIM_SCGC6, 23			// Adresse Bit zur Aktivierung der PIT-Clock

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_RTC_TS, START_VTABLE + 0x14C	// Register fuer Adresse der RTC-TS-ISR
.equ VTABLE_IRQ_PIT1, START_VTABLE + 0x154		// Register fuer Adresse der PIT1-ISR
.equ VTABLE_IRQ_PIT2, START_VTABLE + 0x158		// Register fuer Adresse der PIT2-ISR

.equ NVIC_ISER2, 0xE000E108						// Adresse Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR2, 0xE000E288						// Adresse Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_RTC, (1 << (67 - 64))			// Bitmask fuer RTC TS in NVIC_ISER2 und NVIC_ICPR2
.equ NVIC_BITMASK_PIT1, 1 << (69 - 64)			// Bitmask fuer PIT1, PIT2 und SW2 (PORTE) in NVIC_ISER2 und NVIC_ICPR2
.equ NVIC_BITMASK_PIT2, 1 << (70 - 64)			// Bitmask fuer PIT1, PIT2 und SW2 (PORTE) in NVIC_ISER2 und NVIC_ICPR2

.equ RTC_TSR, 0x4003D000
.equ RTC_TPR, 0x4003D004
.equ RTC_TAR, 0x4003D008
.equ RTC_TAR_1H, 0xE0F
.equ RTC_TAR_24H, 0x1517F
.equ RTC_TSR_PRESET_1H, RTC_TAR_1H - 4
.equ RTC_TSR_PRESET_24H, RTC_TAR_24H - 4
.equ RTC_CR, 0x4003D010
.equ RTC_CR_CONFIG, (1 << 8)					// Oszillator aktivieren (OSCE = 1)
.equ RTC_SR, 0x4003D014
.equ RTC_IER, 0x4003D01C
.equ RTC_IER_CONFIG, (1 << 4)					// Interrupt fuer Ablauf einer Sekunde (TSIE = 1) aktivieren

__BBREG RTC_SR_TCE, RTC_SR, 4

.equ SLEEP_VAL, 12500000

/* CUSTOM */

// DCF77 Bits und Offsets
.equ BIT_CALL, 15
.equ BIT_MEZ_MESZ_SWITCH, 16
.equ OFFSET_MEZ_MESZ, 16
.equ LAST_BIT_MEZ_MESZ, 18

.equ BIT_LEAP_SECOND, 19

.equ BIT_START_TIME, 20

.equ OFFSET_MINUTE_ONES, 20
.equ LAST_BIT_MINUTE_ONES, 24
.equ OFFSET_MINUTE_TENS, 24
.equ LAST_BIT_MINUTE, 27
.equ BIT_PARITY_MINUTE, 28

.equ OFFSET_HOUR_ONES, 28
.equ LAST_BIT_HOUR_ONES, 32
.equ OFFSET_HOUR_TENS, 32
.equ LAST_BIT_HOUR, 34
.equ BIT_PARITY_HOUR, 35

.equ OFFSET_DAY_ONES, 35
.equ LAST_BIT_DAY_ONES, 39
.equ OFFSET_DAY_TENS, 39
.equ LAST_BIT_DAY, 41
.equ OFFSET_DAYOFWEEK, 41
.equ LAST_BIT_DAYOFWEEK, 44
.equ OFFSET_MONTH_ONES, 44
.equ LAST_BIT_MONTH_ONES, 48
.equ OFFSET_MONTH_TENS, 48
.equ LAST_BIT_MONTH, 49
.equ OFFSET_YEAR_ONES, 49
.equ LAST_BIT_YEAR_ONES, 53
.equ OFFSET_YEAR_TENS, 53
.equ LAST_BIT_YEAR, 57
.equ BIT_PARITY_DATE, 58
.equ BIT_SYNC, 59

// Zeitumrechnungen
.equ DAYS_IN_YEAR, 365							// Tage im (nicht Schalt-)Jahr
.equ HOURS_IN_DAY, 24							// Stunden pro Tag
.equ SECMIN_IN_MINHOUR, 60						// Sekunden pro Minute / Minuten pro Stunde
.equ SECONDS_IN_HOUR, 3600						// Sekunden pro Stunde
.equ SECONDS_IN_DAY, 24 * 60 * 60				// Sekunden pro Tag
.equ LEAPYEAR_INTERVAL, 4						// Schaltjahres-Intervall
.equ LUT_ENTRY_ADDRESS_DIFFERENCE, 8			// Abstand der Eintraege im Monat -> Tage seit Jahresbeginn Lookup-Table in Bytes (2 Words, da jeder zweite Eintrag fuer Schaltjahre gilt)

// Flag-Werte
.equ NEXT_BIT_NONE, 2							// Wert fuer next_bit, falls kein Bit gesendet werden soll (Bit 59)

// Werte zur Fehlerbehandlung bei der Eingabe
.equ MAX_DAYS_IN_MONTH, 31
.equ MAX_MONTHS_IN_YEAR, 12
.equ MAX_YEARS, 99
.equ MAX_HOUR_IN_DAY, 23
.equ MAX_MINUTE_IN_HOUR, 59

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
*	Registerbelegungen:
*		r4: Jahr
*		r5: Monat
*		r6: Tag des Monats
*		r7: Stunde
*		r8: Minute
*		r9: Wochentag
*		r10: #0
*		r11: #1
*		r12: Paritaet / Buffer
*/
main:	
	bl uart_init

	mov r10, #0
	mov r11, #1

/* Initialisierung PITs */
	// Takt für PIT Modul aktivieren (SIM)	
	ldr r2, =PIT_CLOCK_BIT
	str r11, [r2]
	
	// Interrupt-Vektor zu PIT1 und PIT2 setzen
	ldr r3, =pit1_isr
	ldr r2, =VTABLE_IRQ_PIT1
	str r3, [r2]
	ldr r3, =pit2_isr
	ldr r2, =VTABLE_IRQ_PIT2
	str r3, [r2]
	
	// pending Interrupts zu PIT1 und PIT2 loeschen (NVIC)
	// NVIC_ICPRx -> Interrupt Clear-Pending Register
	mov r3, #(NVIC_BITMASK_PIT1 | NVIC_BITMASK_PIT2)
	ldr r2, =NVIC_ICPR2
	str r3, [r2]
	
	// Interrupt zu PIT1 und PIT2 aktivieren (NVIC)
	// NVIC_ISERx -> Interrupt Set-enable Register
	ldr r2, =NVIC_ISER2
	str r3, [r2]
	
	// alle PITs aktivieren, im Debug-Modus laufen lassen (PIT-Modul)
	ldr r2, =PIT_MDIS
	str r10, [r2]
	
	// Timerwerte fuer PITs konfigurieren
	ldr r3, =TIMER_VAL_100MS
	ldr r2, =PIT_LDVAL1
	str r3, [r2]
	ldr r3, =TIMER_VAL_200MS
	ldr r2, =PIT_LDVAL2
	str r3, [r2]

	// Interrupt fuer PIT1 und PIT2 aktivieren
	ldr r2, =PIT_TCTRL1_TIE
	str r11, [r2]
	ldr r2, =PIT_TCTRL2_TIE
	str r11, [r2]

/* GPIOs fuer LEDs initialisieren */
	
	// aktiviere Clock fuer Port A
	ldr r2, =CLOCK_GATE_CTRL_PORTA
	str r11, [r2]
	
	// konfiguriere GPIO mode fuer PTA6 und PTA10(LED)
	mov r3, #GPIO_PORT_MASK
	ldr r2, =PORTA_PCR10
	str r3, [r2]
	ldr r2, =PORTA_PCR6
	str r3, [r2]
	
	// setze Direction der Pins auf Output
	ldr r2, =GPIOA_PDDR_PDO10
	str r11, [r2]

	// Pegel setzen (DCF77 standard high, LED standard low)
	ldr r2, =GPIOA_PSOR_PDO10
	str r11, [r2]
	ldr r2, =GPIOA_PCOR_PDO6
	str r11, [r2]

/* RTC */

	// RTC-Modul aktivieren (SIM)
	ldr r2, =SIM_SCGC6_RTC
	str r11, [r2]

	// RTC stoppen
	ldr r2, =RTC_SR_TCE
	str r10, [r2]

	// Interrupt-Vektoren setzen
	ldr r2, =VTABLE_IRQ_RTC_TS
	ldr r3, =rtc_ts_isr
	str r3, [r2]

	// Zeit-Register initialisieren
	ldr r2, =RTC_TPR
	str r10, [r2]
	bl get_time
	/* DEBUG: set time to 20.08.23 20:43:58 */
	//ldr r0, =745879438
	ldr r2, =RTC_TSR
	str r0, [r2]

	// Alarm-Wert initialisieren
	ldr r2, =RTC_TAR
	str r10, [r2]

	// Interrupts aktivieren
	ldr r2, =RTC_IER
	mov r3, #RTC_IER_CONFIG
	str r3, [r2]

	// Oszillator aktivieren
	ldr r2, =RTC_CR
	mov r3, #RTC_CR_CONFIG
	str r3, [r2]

	// Stabilisierung des Oszillator-Signals abwarten
	ldr r0, =SLEEP_VAL
loop_wait_oscillator_startup:
	subs r0, r0, #1
	bne loop_wait_oscillator_startup

	// pending Interrupts loeschen und Interrupts aktivieren
	ldr r3, =NVIC_BITMASK_RTC
	ldr r2, =NVIC_ICPR2
	str r3, [r2]
	ldr r2, =NVIC_ISER2
	str r3, [r2]

	// RTC starten
	ldr r2, =RTC_SR_TCE
	str r11, [r2]

loop_program:
	bl uart_charPresent
	cmp r0, #0
	beq check_flag_sek

	bl uart_getChar
	cmp r0, 's'
	bne check_flag_sek

	// Neue Zeit einlesen
	// RTC stoppen
	ldr r2, =RTC_SR_TCE
	str r10, [r2]

	bl get_time

	ldr r2, =RTC_TSR
	str r0, [r2]

	// RTC starten
	ldr r2, =RTC_SR_TCE
	str r11, [r2]

	b loop_program

check_flag_sek:
	ldr r2, =flag_sek
	ldrb r0, [r2]
	cmp r0, #1
	bne loop_program
	strb r10, [r2]
	
	// lese aktuelle Sekunde ein
	bl rtc_get_second

/* naechstes bit = 1? (aktuelles Bit = 0) */
	ldr r2, =next_bit
	ldr r3, =flag_bit_ready
	cmp r0, #0
	beq print_time

/* 2 <= naechstes bit <= 15? (Wetterinformation und Rufbit) */
	cmp r0, #BIT_CALL
	it lo
	movlo r0, #0
	blo set_and_print_bit

/* naechstes bit = 16? (MEZ/MESZ wird am Ende der Stunde umgestellt) */
	cmp r0, #BIT_MEZ_MESZ_SWITCH
	blo check_mez_mesz_switch

/* 17 <= naechstes bit <= 18? (MEZ/MESZ) */
	cmp r0, #LAST_BIT_MEZ_MESZ
	blo mez_mesz

/* naechstes bit = 19? (Schaltsekunde wird am Ende dieser Stunde eingefuegt) */
	cmp r0, #BIT_LEAP_SECOND
	blo leap_second

/* naechstes bit = 20? (Beginn der Zeitinformation) */
	cmp r0, #BIT_START_TIME
	it lo
	movlo r0, #1
	blo set_and_print_bit

/* 21 <= naechstes bit <= 28? (Minute + Paritaet) */
	cmp r0, #BIT_PARITY_MINUTE
	blo minute

/* 29 <= naechstes bit <= 35? (Stunde + Paritaet) */
	cmp r0, #BIT_PARITY_HOUR
	blo hour

/* 36 <= naechstes bit <= 58? (Datum + Paritaet) */
	cmp r0, #BIT_PARITY_DATE
	blo date

/* naechstes bit = 59? (kein bit senden) */
	ldr r2, =next_bit
	ldr r3, =flag_bit_ready
	cmp r0, #BIT_SYNC
	it lo
	movlo r0, #NEXT_BIT_NONE
	blo set_and_print_bit

/* naechstes bit = 0 (Start einer neuen Minute) */
	// setze Wert fuer naechstes Bit auf 0
	ldr r2, =next_bit
	ldr r3, =flag_bit_ready
	strb r10, [r2]
	strb r11, [r3]

	// Wenn Schaltsekunde, dann stoppe RTC fuer eine Sekunde
	ldr r2, =flag_leap_second
	ldrb r0, [r2]
	cmp r0, #0
	beq get_time_from_timestamp
	strb r10, [r2]								// Flag zuruecksetzen

	ldr r2, =RTC_SR_TCE
	ldr r1, =SLEEP_VAL
	str r10, [r2]								// RTC stoppen

	// 1s warten
loop_leap_second:
	subs r1, r1, #1
	bne loop_leap_second

	str r11, [r2]								// RTC starten

get_time_from_timestamp:
	/* Berechne aktuelle Zeit aus Zeitstempel */

	// lese Zeitstempel aus
	ldr r2, =RTC_TSR
	ldr r0, [r2]

	// addiere 1h falls Sommerzeit
	ldr r2, =flag_mesz
	ldrb r2, [r2]
	ldr r1, =SECONDS_IN_HOUR
	mul r2, r2, r1
	add r0, r2

	mov r1, #SECMIN_IN_MINHOUR
	// r2: Timestamp in Minuten
	udiv r2, r0, r1
	add r2, r2, #2	// berechne Wert fuer uebernaechste Minute: Wert soll in der naechsten Minute ausgegeben werden und die uebernachste Minute liefern -> +2
	// r3: Timestamp in Stunden
	udiv r3, r2, r1
	// r0: Timestamp in Tagen
	mov r1, #HOURS_IN_DAY
	udiv r0, r3, r1
	// r4: Jahr
	ldr r1, =(DAYS_IN_YEAR*LEAPYEAR_INTERVAL+1)
	udiv r4, r0, r1	// Anzahl 4xJahr in Gesamtanzahl Tagen
	mul r12, r4, r1	// Anzahl Tagen in allen vollen 4xJahr-Bloecken zusammen
	sub r12, r0, r12	// Verbleibende Tage ohne volle 4xJahr-Bloecke
	cmp r12, #0
	it ne
	subne r12, r12, #1	// -1, da erstes Jahr ein Schaltjahr ist
	ldr r1, =DAYS_IN_YEAR
	udiv r12, r12, r1
	mov r5, #LEAPYEAR_INTERVAL
	mul r4, r4, r5
	add r4, r4, r12
	// r12: Tag im Jahr
	mul r12, r4, r1
	add r5, r4, #3	// Schalttage berechnen
	mov r1, #LEAPYEAR_INTERVAL
	udiv r5, r5, r1
	add r12, r12, r5	// Schalttage auf restliche Tage aufaddieren
	sub r12, r0, r12	// Tage in vollen Jahren von Timestamp in Tagen abziehen
	// r5: Monat

	// pruefe ob aktuelles Jahr ein Schaltjahr ist
	mov r1, #LEAPYEAR_INTERVAL
	udiv r7, r4, r1		// Jahr % 4
	mul r7, r7, r1		// Jahr % 4
	subs r7, r4, r7		// Jahr % 4
	ite eq
	moveq r7, #1	// Schaltjahr
	movne r7, #0	// kein Schaltjahr
	mov r6, #2
	add r6, r7		// Startindex in LUT
	mul r6, r6, r1	// word-Zugriff
	mov r5, #1
	ldr r8, =lut_month_dayofyear
	add r8, r8, r6
loop_calc_month:
	ldr r9, [r8]
	cmp r12, r9
	itt hs
	addhs r5, r5, #1
	addhs r8, r8, #LUT_ENTRY_ADDRESS_DIFFERENCE
	bhs loop_calc_month

	// r6: Tag des Monats
	sub r8, r8, #LUT_ENTRY_ADDRESS_DIFFERENCE
	ldr r6, [r8]
	sub r6, r12, r6
	add r6, r6, #1

	// r7: Stunden
	mov r1, #HOURS_IN_DAY
	mul r7, r0, r1
	sub r7, r3, r7	// Stunden = Gesamtstunden - Gesamttage*24

	// r8: Minuten
	mov r1, #SECMIN_IN_MINHOUR
	mul r8, r3, r1
	sub r8, r2, r8 // Minuten = Gesamtminuten - Gesamtstunden*60

	// r9: Wochentag
	mov r1, #7
	add r0, r0, #5
	udiv r9, r0, r1
	mul r9, r9, r1
	sub r9, r0, r9
	add r9, r9, #1

	b loop_program


check_mez_mesz_switch:
	// pruefe, ob eingegebene Zeit Sommer- oder Winterzeit ist
	cmp r5, #3
	beq check_mez_mesz_switch_march
	cmp r5, #10
	beq check_mez_mesz_switch_october

check_mez_mesz_switch_march:
	// Sonntag? wenn nein, dann kein Wechsel in <1h
	cmp r9, #7
	bne check_mez_mesz_switch_no
	// weniger als 7 tage verbleibend?
	mov r2, #31
	sub r2, r2, r6
	cmp r2, #7
	bhs check_mez_mesz_switch_no
	// zwischen 1 und 2 uhr?
	cmp r7, #1
	bne check_mez_mesz_switch_no
	beq check_mez_mesz_switch_yes

check_mez_mesz_switch_october:
	// Sonntag? wenn nein, dann kein Wechsel in <1h
	cmp r9, #7
	bne check_mez_mesz_switch_no
	// weniger als 7 tage verbleibend?
	mov r2, #31
	sub r2, r2, r6
	cmp r2, #7
	bhs check_mez_mesz_switch_no
	// zwischen 2 und 3 uhr?
	cmp r7, #2
	bne check_mez_mesz_switch_no
	// aktuell noch Sommerzeit?
	ldr r2, =flag_mesz
	cmp r2, #1
	bne check_mez_mesz_switch_no
	beq check_mez_mesz_switch_yes

check_mez_mesz_switch_no:
	mov r0, #0
	ldr r2, =flag_mez_mesz_switch
	ldrb r1, [r2]
	strb r0, [r2]
	// war flag vorher noch gesetzt? wenn ja -> Wechsel von MEZ auf MESZ bzw. MESZ auf MEZ
	cmp r1, #1
	bne set_and_print_bit
	ldr r2, =flag_mesz
	ldrb r1, [r2]
	eor r1, r1, #1
	strb r1, [r2]
	b set_and_print_bit
check_mez_mesz_switch_yes:
	mov r0, #1
	ldr r2, =flag_mesz
	strb r0, [r2]
	b set_and_print_bit

mez_mesz:
	sub r0, r0, #OFFSET_MEZ_MESZ
	ldr r2, =flag_mesz
	ldr r1, [r2]
	eor r0, r0, r1
	b set_and_print_bit

leap_second:
	ldr r2, =leap_seconds_pointer
	ldr r2, [r2]
	ldr r1, [r2]
	ldr r3, =RTC_TSR
	ldr r3, [r3]
	cmp r1, r3
	// Differenz zwischen aktueller Zeit und naechster Schaltsekunde
	subs r1, r1, r3
	cmp r1, #SECMIN_IN_MINHOUR
	blo leap_second_now							// weniger als 60s zur Schaltsekunde: Flag setzen
	cmp r1, #SECONDS_IN_HOUR
	ite lo
	movlo r0, #1	// naechste Schaltsekunde in unter einer Stunde
	movhs r0, #0
	b set_and_print_bit

leap_second_now:
	// Aktuelle Sekunde ist eine Schaltsekunde: setze Pointer auf naechsten Wert
	ldr r3, =leap_seconds_pointer
	add r2, r2, #4
	str r2, [r3]
	// setze Flag
	ldr r2, =flag_leap_second
	strb r11, [r2]
	mov r0, #1
	b set_and_print_bit

minute:
	cmp r0, #OFFSET_MINUTE_ONES
	it eq
	moveq r12, #0
	cmp r0, #LAST_BIT_MINUTE_ONES
	blo minute_ones
	cmp r0, #LAST_BIT_MINUTE
	blo minute_tens

	// Paritaetsbit
	mov r0, r12
	b set_and_print_bit

minute_ones:
	sub r0, r0, #OFFSET_MINUTE_ONES

	mov r1, r8
	bl get_ones_offset
	eor r12, r12, r0

	b set_and_print_bit

minute_tens:
	sub r0, r0, #OFFSET_MINUTE_TENS

	mov r1, r8
	bl get_tens_offset
	eor r12, r12, r0

	b set_and_print_bit

hour:
	cmp r0, #OFFSET_HOUR_ONES
	it eq
	moveq r12, #0
	cmp r0, #LAST_BIT_HOUR_ONES
	blo hour_ones
	cmp r0, #LAST_BIT_HOUR
	blo hour_tens

	// Paritaetsbit
	mov r0, r12
	b set_and_print_bit

hour_ones:
	sub r0, r0, #OFFSET_HOUR_ONES

	mov r1, r7
	bl get_ones_offset
	eor r12, r12, r0

	b set_and_print_bit

hour_tens:
	sub r0, r0, #OFFSET_HOUR_TENS

	mov r1, r7
	bl get_tens_offset
	eor r12, r12, r0

	b set_and_print_bit

date:
	cmp r0, #OFFSET_DAY_ONES
	it eq
	moveq r12, #0
	cmp r0, #LAST_BIT_DAY_ONES
	blo day_ones
	cmp r0, #LAST_BIT_DAY
	blo day_tens
	cmp r0, #LAST_BIT_DAYOFWEEK
	blo day_of_week
	cmp r0, #LAST_BIT_MONTH_ONES
	blo month_ones
	cmp r0, #LAST_BIT_MONTH
	blo month_tens
	cmp r0, #LAST_BIT_YEAR_ONES
	blo year_ones
	cmp r0, #LAST_BIT_YEAR
	blo year_tens

	mov r0, r12
	b set_and_print_bit

day_ones:
	sub r0, r0, #OFFSET_DAY_ONES

	mov r1, r6
	bl get_ones_offset
	eor r12, r12, r0

	b set_and_print_bit

day_tens:
	sub r0, r0, #OFFSET_DAY_TENS

	mov r1, r6
	bl get_tens_offset
	eor r12, r12, r0

	b set_and_print_bit

day_of_week:
	sub r0, r0, #OFFSET_DAYOFWEEK
	// maskiere aktuelles bit aus
	lsr r0, r9, r0
	and r0, r0, #1
	eor r12, r12, r0
	b set_and_print_bit

month_ones:
	sub r0, r0, #OFFSET_MONTH_ONES

	mov r1, r5
	bl get_ones_offset
	eor r12, r12, r0

	b set_and_print_bit

month_tens:
	sub r0, r0, #OFFSET_MONTH_TENS

	mov r1, r5
	bl get_tens_offset
	eor r12, r12, r0

	b set_and_print_bit

year_ones:
	sub r0, r0, #OFFSET_YEAR_ONES

	mov r1, r4
	bl get_ones_offset
	eor r12, r12, r0

	b set_and_print_bit

year_tens:
	sub r0, r0, #OFFSET_YEAR_TENS

	mov r1, r4
	bl get_tens_offset
	eor r12, r12, r0

	b set_and_print_bit

print_time:
	// naechstes Bit vorbereiten
	strb r10, [r2]
	strb r11, [r3]

	/* Zeit der kommenden Minute auf dem Terminal ausgeben */
	mov r0, '\n'
	bl uart_putChar

	// Wochentag
	mov r0, r9
	sub r0, r0, #1
	lsl r0, r0, #2
	ldr r1, =lut_dayofweek
	add r1, r1, r0
	ldr r0, [r1]
	bl uart_putString

	// Datum
	mov r0, r6
	bl uart_putByteBase10TwoDigits
	mov r0, '.'
	bl uart_putChar
	mov r0, r5
	bl uart_putByteBase10TwoDigits
	mov r0, '.'
	bl uart_putChar
	mov r0, r4
	bl uart_putByteBase10TwoDigits

	// Uhrzeit
	mov r0, ' '
	bl uart_putChar
	mov r0, r7
	bl uart_putByteBase10TwoDigits
	mov r0, ':'
	bl uart_putChar
	mov r0, r8
	bl uart_putByteBase10TwoDigits
	ldr r0, =str_time
	bl uart_putString

	mov r0, '0'
	bl uart_putChar
	mov r0, #0
	b set_and_print_bit

set_and_print_bit:
	// Naechstes Bit vorbereiten
	ldr r2, =next_bit
	ldr r3, =flag_bit_ready
	strb r0, [r2]
	strb r11, [r3]
	// Naechstes Bit auf dem Terminal ausgeben
	cmp r0, #NEXT_BIT_NONE
	itee eq
	moveq r0, '_'
	movne r1, '0'
	addne r0, r1, r0
	bl uart_putChar
	b loop_program

error:
	ldr r0, =str_error
	bl uart_putString
end:
	b end


/*
*	Unterprogramm zur Berechnung des Bits an Offset [r0] in den Einerstellen von Wert [r1]
*	Beispiel: Wert 13, Offset 1: Einerstellen von 12 = 2, Bit 1 in Wert 2 (= 0b10) = 1	
*
*	Registerbelegung: -
*
*	Uebergabewerte: 
*		r0: Offset innerhalb der Einerstellen
*		r1: Wert
*
*	Rueckgabewerte: 
*		r0: Bit an Offset [r0] in Einerstellen des Wertes [r1]
*/
.thumb_func
get_ones_offset:
	// berechne Einerstellen (= Wert % 10)
	mov r2, #10
	udiv r3, r1, r2
	mul r3, r3, r2
	sub r3, r1, r3

	// maskiere Bit an offset [r0] aus
	lsr r0, r3, r0
	and r0, r0, #1
	bx lr

/*
*	Unterprogramm zur Berechnung des Bits an Offset [r0] in den Zehnerstellen von Wert [r1]
*	Wie get_ones_offset nur mit Zehner- statt Einerstelle
*
*	Registerbelegung: -
*
*	Uebergabewerte: 
*		r0: Offset innerhalb der Zehnerstellen
*		r1: Wert
*
*	Rueckgabewerte: 
*		r0: Bit an Offset [r0] in Zehnerstellen des Wertes [r1]
*/
.thumb_func
get_tens_offset:
	// berechne Zehnerstellen (= Wert / 10)
	mov r2, #10
	udiv r3, r1, r2

	// maskiere Bit an offset [r0] aus
	lsr r0, r3, r0
	and r0, r0, #1
	bx lr

/*
*	Unterprogramm zur Berechnung des Sekundenwertes (in [0..59]) im Zeitstempel
*
*	Registerbelegung: -
*
*	Uebergabewerte: -
*
*	Rueckgabewerte: 
*		r0: aktueller Sekundenwert
*/
.thumb_func
rtc_get_second:
	ldr r2, =RTC_TSR
	ldr r0, [r2]
	mov r1, #SECMIN_IN_MINHOUR
	udiv r2, r0, r1
	mul r2, r2, r1
	sub r0, r0, r2
	bx lr

/*
*	Unterprogramm zum Auslesen eines neuen Datums und einer neuen Zeit vom Terminal
*	Berechnet aus den eingegebenen Werten einen Zeitstempel und bestimmt, ob es
*	sich um Sommer- oder Winterzeit handelt
*
*	Registerbelegung: 
*		r4: Jahr
*		r5: Monat
*		r6: Tag des Monats
*		r7: Stunde
*		r8: Minute
*
*	Uebergabewerte: -
*
*	Rueckgabewerte: 
*		r0: Zeitstempel in Sekunden seit 01.01.2000 00:00 Uhr
*/
.thumb_func
get_time:
	push {r4-r8, lr}
	ldr r0, =str_day
	bl uart_putString
get_time_day:
	bl uart_getByteBase10
	cmp r0, #0
	beq get_time_day
	cmp r0, #MAX_DAYS_IN_MONTH
	bhi get_time_day							// Wenn der eingegebene Tag nicht im Bereich 1 <= x <= 31 liegt, frage erneut ab
	mov r6, r0
	bl uart_putByteBase10TwoDigits
	ldr r0, =str_month
	bl uart_putString
get_time_month:
	bl uart_getByteBase10
	cmp r0, #0
	beq get_time_month
	cmp r0, #MAX_MONTHS_IN_YEAR
	bhi get_time_month
	mov r5, r0
	bl uart_putByteBase10TwoDigits
	ldr r0, =str_year
	bl uart_putString
get_time_year:
	bl uart_getByteBase10
	cmp r0, #MAX_YEARS
	bhi get_time_year
	mov r4, r0
	bl uart_putByteBase10TwoDigits
	ldr r0, =str_hour
	bl uart_putString
get_time_hour:
	bl uart_getByteBase10
	cmp r0, #MAX_HOUR_IN_DAY
	bhi get_time_hour
	mov r7, r0
	bl uart_putByteBase10TwoDigits
	ldr r0, =str_minute
	bl uart_putString
get_time_minute:
	bl uart_getByteBase10
	cmp r0, #MAX_MINUTE_IN_HOUR
	bhi get_time_minute
	mov r8, r0
	bl uart_putByteBase10TwoDigits

	// Berechne Zeitstempel
	mov r0, #0
	mov r1, #SECMIN_IN_MINHOUR
	mul r2, r8, r1	
	add r0, r0, r2	// addiere Sekunden in Minuten
	ldr r1, =SECONDS_IN_HOUR
	mul r2, r7, r1
	add r0, r0, r2	// addiere Sekunden in Stunden
	ldr r1, =SECONDS_IN_DAY
	sub r2, r6, #1
	mul r2, r2, r1
	add r0, r0, r2	// addiere Sekunden in Tagen

	// pruefe ob aktuelles Jahr ein Schaltjahr ist
	mov r1, #4
	udiv r2, r4, r1		// Jahr % 4
	mul r2, r2, r1		// Jahr % 4
	subs r2, r4, r2		// Jahr % 4
	ite eq
	moveq r3, #1	// Schaltjahr
	movne r3, #0	// kein Schaltjahr

	// bestimme Tage in bereits abgeschlossenen Monaten
	sub r1, r5, #1
	mov r2, #2
	mul r1, r1, r2
	add r1, r1, r3
	mov r2, #4
	mul r1, r1, r2
	ldr r2, =lut_month_dayofyear
	add r2, r2, r1
	ldr r3, [r2]	// r3: Tage in Monaten

	// berechne Tage in bereits abgeschlossenen Jahren
	ldr r1, =365
	mul r2, r4, r1
	add r3, r3, r2	// addiere Tage in Jahren (ohne Schalttage)

	// berechne Schalttage
	mov r1, #LEAPYEAR_INTERVAL
	add r2, r4, #3								// 2000 ist bereits ein Schaltjahr, daher Offset von 3
	udiv r2, r2, r1
	add r3, r3, r2	// addiere Schalttage

	ldr r1, =(3600*24)
	mul r3, r3, r1
	add r0, r0, r3
	sub r0, r0, #2	// subtrahiere 2 Sekunden um die eingegebene Uhrzeit noch mit auszugeben

	// pruefe, ob eingegebene Zeit Sommer- oder Winterzeit ist
	mov r4, r0
	cmp r5, #3
	blo get_time_mez
	beq get_time_mez_mesz_switch_march
	cmp r5, #10
	bhi get_time_mez
	blo get_time_mesz
	beq get_time_mez_mesz_switch_october

get_time_mez_mesz_switch_march:
	bl get_day_of_week
	cmp r0, #7
	beq get_time_mez_mesz_switch_march_sunday
	// Eingegebene Zeit liegt im Maerz und ist kein Sonntag -> pruefe ob es in diesem Monat noch einen Sonntag gibt
	mov r1, #6
	sub r0, r1, r0
	mov r2, #31
	sub r2, r2, r6
	cmp r1, r0
	bhi get_time_mez
	bls get_time_mesz
get_time_mez_mesz_switch_march_sunday:
	// Eingegebene Zeit liegt im Maerz und ist ein Sonntag -> pruefe ob verbleibende Tage im Monat <= 6 (letzter Sonntag im Monat)
	cmp r6, #31
	bne get_time_mez
	cmp r7, #3
	bhs get_time_mesz
	blo get_time_mez

get_time_mez_mesz_switch_october:
	bl get_day_of_week
	cmp r0, #7
	beq get_time_mez_mesz_switch_october_sunday
	// Eingegebene Zeit liegt im Oktober und ist kein Sonntag -> pruefe ob es in diesem Monat noch einen Sonntag gibt
	mov r1, #6
	sub r0, r1, r0
	mov r2, #31
	sub r2, r2, r6
	cmp r1, r0
	bhi get_time_mesz
	bls get_time_mez
get_time_mez_mesz_switch_october_sunday:
	// Eingegebene Zeit liegt im Oktober und ist ein Sonntag -> pruefe ob verbleibende Tage im Monat <= 6 (letzter Sonntag im Monat)
	cmp r6, #31
	bne get_time_mesz
	cmp r7, #3
	bhs get_time_mez
	blo get_time_mesz

get_time_mez:
	// Eingegebene Zeit liegt in der Winterzeit
	ldr r2, =flag_mesz
	mov r1, #0
	strb r1, [r2]
	mov r0, r4
	b get_time_get_next_leap_sec
get_time_mesz:
	// Eingegebene Zeit liegt in der Sommerzeit
	ldr r2, =flag_mesz
	mov r1, #1
	strb r1, [r2]
	mov r0, r4
	// Wenn Sommerzeit, dann subtrahiere eine Stunde (Zeitstempel immer in MEZ)
	ldr r1, =SECONDS_IN_HOUR
	sub r0, r0, r1

	// bestimme naechste Schaltsekunde
get_time_get_next_leap_sec:
	ldr r1, =leap_seconds
loop_get_next_leap_sec:
	ldr r2, [r1]
	cmp r0, r2
	it hs
	addhs r1, r1, #4
	bhs loop_get_next_leap_sec
	ldr r2, =leap_seconds_pointer
	str r1, [r2]
	pop {r4-r8, pc}

/*
*	Unterprogramm zur zweistelligen Ausgabe einer Dezimalzahl auf dem Terminal
*	Fuegt ggf. eine fuehrende Null ein 
*
*	Registerbelegung: -
*
*	Uebergabewerte: 
*		r0: Dezimalzahl, die auf dem Terminal ausgegeben werden soll
*
*	Rueckgabewerte: -
*/
.thumb_func
uart_putByteBase10TwoDigits:
	push {r4, lr}
	cmp r0, #9
	bhi no_leading_zero
	mov r4, r0
	mov r0, '0'
	bl uart_putChar
	mov r0, r4
no_leading_zero:
	bl uart_putByteBase10
	pop {r4, pc}
	
/*
*	Unterprogramm, das zu einem Timestamp den Wochentag ausgibt
*
*	Registerbelegung: -
*
*	Uebergabewerte:
*		r0: Zeitstempel in Sekunden seit 01.01.2000 00:00 Uhr
*
*	Rueckgabewerte: 
*		r0: Wochentag (1 = Montag, 7 = Sonntag)
*/
.thumb_func
get_day_of_week:
	ldr r1, =SECONDS_IN_DAY
	udiv r0, r0, r1
	// r9: Wochentag
	mov r1, #7
	add r2, r0, #5
	udiv r0, r2, r1
	mul r0, r0, r1
	sub r0, r2, r0
	add r0, r0, #1
	bx lr

/*
*	Interrupt Service Routine zur Behandlung des Sekunden Interrupts der RTC
*/
.thumb_func
rtc_ts_isr:
	mov r0, #0
	mov r1, #1

	// flag_sek setzen
	ldr r2, =flag_sek
	strb r1, [r2]

	ldr r2, =flag_bit_ready
	ldrb r3, [r2]
	cmp r3, #0
	beq rtc_ts_isr_return
	
	// flag_bit_ready zuruecksetzen
	strb r0, [r2]

	// GPIO Wert setzen
	ldr r2, =next_bit
	ldrb r3, [r2]
	cmp r3, #2
	beq rtc_ts_isr_return
	// setze GPIOs
	ldr r2, =GPIOA_PCOR_PDO10
	str r1, [r2]
	ldr r2, =GPIOA_PSOR_PDO6
	str r1, [r2]
	// starte passenden Timer
	cmp r3, #1
	ite eq
	ldreq r2, =PIT_TCTRL2_TEN
	ldrne r2, =PIT_TCTRL1_TEN
	str r1, [r2]

rtc_ts_isr_return:
	bx lr

/*
*	Interrupt Service Routine zur Behandlung des Ablaufs von PIT1 (100ms)
*/
.thumb_func
pit1_isr:
	mov r0, #0
	mov r1, #1
	ldr r2, =GPIOA_PSOR_PDO10
	str r1, [r2]
	ldr r3, =GPIOA_PCOR_PDO6
	str r1, [r3]

	// Timer deaktivieren und Flag zuruecksetzen
	ldr r2, =PIT_TCTRL1_TEN
	str r0, [r2]
	ldr r2, =PIT_TFLG1_TIF
	str r1, [r2]
	bx lr

/*
*	Interrupt Service Routine zur Behandlung des Ablaufs von PIT2 (200ms)
*/
.thumb_func
pit2_isr:
	mov r0, #0
	mov r1, #1
	ldr r2, =GPIOA_PSOR_PDO10
	str r1, [r2]
	ldr r3, =GPIOA_PCOR_PDO6
	str r1, [r3]

	// Timer deaktivieren und Flag zuruecksetzen
	ldr r2, =PIT_TCTRL2_TEN
	str r0, [r2]
	ldr r2, =PIT_TFLG2_TIF
	str r1, [r2]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
flag_error: .byte 0x0
flag_sek: .byte 0x0
flag_bit_ready: .byte 0x0
next_bit: .byte 0x0
flag_mesz: .byte 0x0
flag_mez_mesz_switch: .byte 0x0
flag_leap_second: .byte 0x0

str_monday: .asciz "Mo., "
str_tuesday: .asciz "Di., "
str_wednesday: .asciz "Mi., "
str_thursday: .asciz "Do., "
str_friday: .asciz "Fr., "
str_saturday: .asciz "Sa., "
str_sunday: .asciz "So., "

.align 4
lut_dayofweek: .word str_monday, str_tuesday, str_wednesday, str_thursday, str_friday, str_saturday, str_sunday
lut_month_dayofyear: .word 0, 0, 31, 31, 59, 60, 90, 91, 120, 121, 151, 152, 181, 182, 212, 213, 243, 244, 273, 274, 304, 305, 334, 335, 365, 366
leap_seconds: .word 0xb49d7ff, 0x10eec3ff, 0x17824f7f, 0x1d25e9ff, 0x1ffb02ff, 0xffffffff
leap_seconds_pointer: .word 0x0

str_time: .asciz " Uhr "
str_day: .asciz "\nTag: "
str_month: .asciz "\nMonat: "
str_year: .asciz "\nJahr: "
str_hour: .asciz "\nStunde: "
str_minute: .asciz "\nMinute: "
str_error: .asciz "\nFEHLER: Das naechste Bit wurde nicht rechtzeitig bereitgestellt!"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SIM_SCGC5, 0x40048038
__BBREG SIM_SCGC5_PORTA, SIM_SCGC5, 9			// Adresse Bit zur Aktivierung der Clock fuer das Modul PORT A

.equ SIM_SCGC6, 0x4004803C
__BBREG SIM_SCGC6_FTM0, SIM_SCGC6, 24			// Adresse Bit zur Aktivierung der Clock fuer das Modul FTM0

.equ START_VTABLE, 0x1FFFFE00					// Startadresse Vektortabellen-Kopie im Programmspeicher
.equ VTABLE_IRQ_FTM0, START_VTABLE + 0x138		// Register fuer Adresse der FTM0-isr

.equ NVIC_ISER1, 0xE000E104						// Adresse Register zum Einschalten der IRQs 64-95
.equ NVIC_ICPR1, 0xE000E284						// Adresse Register zum Loeschen der Pending Interrupts zu ISR 64-95
.equ NVIC_BITMASK_FTM0, (1 << (62 - 32))		// Bitmask fuer FTM0 in NVIC_ISER2 und NVIC_ICPR2

/* FTM */
.equ FTM0_SC, 0x40038000
.equ FTM0_SC_CONFIG, (1 << 6)					// aktiviere timer overflow interrupts (TOIE = 1), keine Clock auswaehlen (CLKS = 00), Prescaler-Wert 1 (PS = 000)
__BBREG FTM0_ENABLE, FTM0_SC, 3					// Bit 1 von Clock Select (stellt um von clock disabled auf Systemclock)
__BBREG FTM0_SC_TOF, FTM0_SC, 7
.equ FTM0_CNT, 0x40038004
.equ FTM0_MOD, 0x40038008
.equ FTM0_MOD_VAL, 24999						// 25MHz / 25000 = 1kHz
.equ FTM0_C3SC, 0x40038024
.equ FTM0_C3SC_CONFIG, (1 << 6) | (1 << 5) | (1 << 3)	// Channel-Interrupts aktiviert (CHIE = 1), Edge Aligned PWM Modus (MSB = 1, MSA = 0), positive Polaritaet (ELSB = 1, ELSA = 0)
__BBREG FTM0_C3SC_ELSA, FTM0_C3SC, 2
__BBREG FTM0_C3SC_CHF, FTM0_C3SC, 7
.equ FTM0_C3V, 0x40038028
//.equ FTM0_C3V_CONFIG_INIT, (25000 / 20) 		// Initiale PWM: 5% duty-cycle
.equ FTM0_C3V_CONFIG_INIT, (25000 / 20) * 19	// Initiale PWM: 95% duty-cycle
.equ FTM0_CNTIN, 0x4003804C
.equ FTM0_MODE, 0x40038054
.equ FTM0_MODE_CONFIG, (1 << 2)					// Schreibschutz deaktivieren (WPDIS = 1), FTM-spezifische Register deaktivieren (FTMEN = 0)

.equ PORTA_PCR6, 0x40049018
.equ PORTA_PCR6_CONFIG, (0x3 << 8)				// Alternative 3: FTM0_CH3 (MUX = 0x3)

.equ DUTY_CYCLE_10_PERCENT, 2500
.equ DUTY_CYCLE_5_PERCENT, 1250

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

/*
*	Registerbelegungen:
*		r4: buffer
*		r5: Adresse new_c3v_value
*		r6: Adresse new_polarity
*		r7: DUTY_CYCLE_5_PERCENT
*		r8: DUTY_CYCLE_10_PERCENT
*		r10: #0
*		r11: #1 (= positive Polaritaet in new_polarity)
*		r12: #2 (= negative Polaritaet in new_polarity)
*/
main:	
	bl uart_init

	ldr r5, =new_c3v_value
	ldr r6, =new_polarity
	ldr r7, =DUTY_CYCLE_5_PERCENT
	ldr r8, =DUTY_CYCLE_10_PERCENT
	mov r10, #0
	mov r11, #1
	mov r12, #2

	/* FTM */
	ldr r2, =SIM_SCGC5_PORTA
	str r11, [r2]

	ldr r2, =PORTA_PCR6
	mov r3, #PORTA_PCR6_CONFIG
	str r3, [r2]

	ldr r2, =SIM_SCGC6_FTM0
	str r11, [r2]

	ldr r2, =FTM0_MODE
	mov r3, #FTM0_MODE_CONFIG
	str r3, [r2]

	ldr r2, =FTM0_SC
	ldr r3, =FTM0_SC_CONFIG
	str r3, [r2]

	ldr r2, =FTM0_CNTIN
	str r10, [r2]

	ldr r2, =FTM0_MOD
	ldr r3, =FTM0_MOD_VAL
	str r3, [r2]

	ldr r2, =FTM0_C3SC
	ldr r3, =FTM0_C3SC_CONFIG
	str r3, [r2]

	ldr r2, =FTM0_C3V
	ldr r3, =FTM0_C3V_CONFIG_INIT
	str r3, [r2]

	ldr r2, =FTM0_CNT
	str r10, [r2]

	ldr r2, =VTABLE_IRQ_FTM0
	ldr r3, =ftm0_isr
	str r3, [r2]

	// pending Interrupts loeschen und Interrupts aktivieren
	ldr r3, =NVIC_BITMASK_FTM0
	ldr r2, =NVIC_ICPR1
	str r3, [r2]
	ldr r2, =NVIC_ISER1
	str r3, [r2]

	ldr r2, =FTM0_ENABLE
	str r11, [r2]


loop_program:
	mov r0, '>'
	bl uart_putChar

loop_wait_for_input:
	bl uart_charPresent
	cmp r0, #0
	beq loop_wait_for_input

	bl uart_getChar
	mov r4, r0
	bl uart_putChar
	mov r0, r4
	cmp r0, '+'
	beq positive_polarity
	cmp r0, '-'
	beq negative_polarity
	cmp r0, '9'
	bgt unknown_char
	subs r0, r0, '0'							// char zu Integer konvertieren
	bmi unknown_char

	mov r4, r0

	// neuen Wert fuer FTM0_C3V berechnen
	mul r0, r0, r8
	add r0, r0, r7
	
	strh r0, [r5]

	ldr r0, =str_new_pulse_width
	bl uart_putString

	mov r1, #10
	mul r0, r4, r1
	add r0, r0, #5
	bl uart_putByteBase10
	mov r0, '%'
	bl uart_putChar
	mov r0, '\n'
	bl uart_putChar

	b loop_program

positive_polarity:
	strb r11, [r6]
	ldr r0, =str_positive_polarity
	bl uart_putString
	b loop_program

negative_polarity:
	strb r12, [r6]
	ldr r0, =str_negative_polarity
	bl uart_putString
	b loop_program

unknown_char:
	ldr r0, =str_unknown_char
	bl uart_putString

	b loop_program

/*
*	Interrupt Service Routine zur Behandlung eines Timer oder Channel Interrupt des FTM0
*/
.thumb_func
ftm0_isr:
	mov r0, #0
	ldr r2, =FTM0_SC_TOF
	ldr r1, [r2]
	str r0, [r2]
	cmp r1, #1
	bne channel_interrupt
	
	ldr r2, =new_polarity
	ldrb r1, [r2]
	cmp r1, #0
	beq ftm0_isr_return
	sub r1, r1, #1
	ldr r3, =FTM0_C3SC_ELSA
	str r1, [r3]
	strb r0, [r2]

	b ftm0_isr_return

channel_interrupt:
	ldr r2, =FTM0_C3SC_CHF
	ldr r1, [r2]
	str r0, [r2]
	
	ldr r2, =new_c3v_value
	ldrb r1, [r2]
	cmp r1, #0
	beq ftm0_isr_return

	strb r0, [r2]
	ldr r2, =FTM0_C3V
	ldr r3, =new_c3v_value
	ldrh r1, [r3]
	str r1, [r2]
	strh r0, [r3]

ftm0_isr_return:
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
new_c3v_value: .short 0x0
new_polarity: .byte 0x0

str_unknown_char: .asciz "\nUngueltige Eingabe!\n"
str_positive_polarity: .asciz "\nPolaritaet: positiv.\n"
str_negative_polarity: .asciz "\nPolaritaet: negativ.\n"
str_new_pulse_width: .asciz "\nPulsweite geaendert. Neue Pulsweite: "

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ COUNTER, 0x10				// Anzahl der Schleifendurchläufe
.equ REFERENCE_PIT, 0xb					// Referenzwert für PIT

main:	
	bl uart_init
	bl pit3_init
	
	ldr r6, =start_time_search	// r6 zeigt auf Adresse von start_time_search
	ldr r7, =end_time_search	// r7 zeigt auf Adresse von end_time_search
	
loop_program:
	/**
	 Einlesen von 16 Bytes
	 **/
	ldr r0, =str_prompt
	bl uart_putString	
	mov r4, #COUNTER			// Zähler laden (max. 16 Bit mit mov, sonst ldr)
	ldr r5, =bytearray			// Adresse des bytearray einlesen
	
	// Eingabeschleife
loop_prompt:
	ldr r0, =str_input_prompt	
	bl uart_putString			
	bl uart_getByte
	strb r0, [r5], #1			// im Array ablegen und Adresse in R5 um eins erhöhen
	bl uart_putByte				// das Byte ausgeben
	subs r4, r4, #1				// Quelle, Ziel, Anzahl (subs setzt ZERO-Flag, wenn auf 0)
	bne loop_prompt				// solange Zähler noch nicht null, springe zu loop_prompt
	
	// Maximumsbestimmung
	ldr r0, =str_search_start	// String für Beginn der Suche in r0 laden
	bl uart_putString			// String für Beginn der Suche ausgeben
	
	mov r9, #0					// Maximum mit null initialisieren
	mov r4, #COUNTER			// Schleifenanzahl mit #COUNTER initialisieren
		
	// PIT Startmessung für Suchzeit
	bl pit3_getval				// UP-Aufruf für Zeitmessung
	mov r6, r0					// Rückgabewert aus r0 in r6 speichern
	
loop_maximum:
	ldrb r0, [r5, #-1]!			// Byte aus Array holen, vorhrer Adresse in r5 predekrementieren
	cmp r0, r9					// Vergleich von bisherigem Maximum mit aktuellem Wert
	it hi						// wenn größer ist (unsigned)
	movhi r9, r0 				// Quellregister, Zielregister (move when high)
	
	subs r4, r4, #1
	bne loop_maximum
	
	// PIT Endmessung für Suchzeit
	bl pit3_getval				// UP-Aufruf für Zeitmessung
	mov r7, r0					// Rückgabewert aus r0 in r7 speichern
	
	// Maximum speichern
	ldr r0, =maximum			// Adresse des Speichers für Maximum laden
	strb r9, [r0]				// das Maximum im Speicher ablegen
	
	// Maximum ausgeben
	ldr r0, =str_search_stop	// String für Beendigung der Suche in r0 laden
	bl uart_putString			// String für Beendigung der Suche ausgeben
	mov r0, r9					// nach r0 kopieren
	bl uart_putByte				// Maximum ausgeben
	ldr r0, =str_needed_time	// String für benötigte Zeit in r0 laden
	bl uart_putString			// String für benötigte Zeit ausgeben
	
	// Suchzeit berechnen und ausgeben
	mov r11, #REFERENCE_PIT
	subs r7, r6, r7 			// Subtrahiert r7 (Ende) von r6 (Anfang) und speichert das wieder in r7 -> da Counter von 0xFFFFFFFF auf 0x00000000 herunterzählt
	subs r7, r7, r11			// Subtrahiert r11 (Referenz für Zeitmessung) von r7 (vorherige Differenz) und speichert das wieder in r7
	mov r0, r7					//holt Ergebnis der Subtraktion aus r7 und kopiert das in r0
	bl uart_putInt16			// gibt das Ergebnis in 0x0000 aus
	
	// Ruecksprung zum Beginn
	b loop_program				// Sprung zum Programmstart
	
/**
BEANTWORTUNG AUFGABE e):

Es ist kein Unterschied erkennbar abhängig davon, an welcher Stelle das Maximum eingegeben wird. Das hängt daran, dass die IT-Anweisung in dem Fall, dass der Vergleich nicht stimmt NOP ausführt (benötigt ebenfalls 1 Takt, wie die Anweisung falls Vergleich stimmt).
	
	
/*** Datenbereich (ab 0x20000000) ***/
.data
bytearray:
	.rept COUNTER
	.byte 0x00
	.endr
maximum: .byte 0x0
start_time_reference: .byte 0x0
end_time_reference: .byte 0x0
start_time_search: .byte 0x0
end_time_search: .byte 0x0
str_prompt: .asciz "\nBitte 16 Bytes sukzessiv eingeben !\n"
str_input_prompt: .asciz "\n>0x"
str_search_start: .asciz "\nDurchsuchen gestartet\n"
str_search_stop: .asciz "Durchsuchen beendet\nMaximum: 0x"
str_needed_time: .asciz "\nBenoetigte Zeit zur Maximumsuche: 0x"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ SHIFT, 27				// Anzahl der Verschiebung (32 Bit - x = 5 Bit) --> Ausgabe der 5 niedrigsten Bits
.equ BYTES, 4				// Anzahl der Bytes für Aufgabe b) (32 Bit)
.equ ADDRESS_B, 0x20000000
.equ ADDRESS_C, 0x20000010
.equ BASISADDR_BITBAND_ALIAS, 0x22000000

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init

loop_program:
	// lese erstes Byte ein und gebe eine entsprechende Ausgabe an UART
	ldr r0, =str_input_prompt_first	// lade Adresse von str_input_prompt_first in r0
	bl uart_putString // gebe String an r0 aus
	ldr r5, =firstBit	// lade Adresse des firstByte in r5
	bl uart_getByte // lasse Byte eingeben und speichert in r0
	mov r5, r0 // speichere Byte in r5
	lsls r5, r5, #SHIFT // verschiebe den Inhalt von r5 um SHIFT (27) Stellen nach links (nicht gewollte Bits (alle außer die fünf niedrigwertigsten) entfallen)
	rors r5, r5, #SHIFT // rotiert den Inhalt von r5 um SHIFT (27) STellen nach rechts -> damit stehen die fünf niedrigwertigsten Bits korrekt und der Rest enthält den Wert 0
	mov r0, r5 // lade Adresse von r5 in r0
	bl uart_putByte // gebe Byte in r0 aus
	
	// lese zweites Byte ein und gebe eine entsprechende Ausgabe an UART
	ldr r0, =str_input_prompt_second // lade Adresse von str_input_prompt_second in r0
	bl uart_putString
	ldr r6, =secondBit	// lade Adresse des secondByte in r6
	bl uart_getByte
	mov r6, r0
	lsls r6, r6, #SHIFT // verschiebe den Inhalt von r6 um SHIFT (27) Stellen nach links (nicht gewollte Bits (alle außer die fünf niedrigwertigsten) entfallen)
	rors r6, r6, #SHIFT // rotiert den Inhalt von r6 um SHIFT (27) STellen nach rechts -> damit stehen die fünf niedrigwertigsten Bits korrekt und der Rest enthält den Wert 0
	mov r0, r6
	bl uart_putByte
	
	
	/**
	HIER BEGINNT AUFGABE B) OHNE BIT-BANDING
	**/
	
	// Ausgabe des initialen Werts aus dem Speicher
	ldr r0, =str_value_before_manipulation
	bl uart_putString
	ldr r4, =ADDRESS_B
	ldr r0, [r4]
	bl uart_putInt32
	
	// setzen des ersten Bits
	ldr r0, [r4]
	mov r1, #0 // 0 in r1 schreiben
	lsls r1, r1, r5 // die 0 um r5-Stellen nach Links verschieben (r5 ist das erste Byte)
	ands r0, r0, r1 // AND Vergleich zwischen initialem Wert und r1 --> 1 AND 0 wird 0; 0 AND 0 wird 0 (r1 ist IMMER 0 an der eingegebenen Stelle)
	str r0, [r4] // Ergebnis aus r0 an Speicherstelle in r4 zurückschreiben
	
	// setzen des zweiten Bits
	ldr r0, [r4]
	mov r1, #1 // 1 in r1 schreiben
	lsls r1, r1, r6 // die 1 um r6-Stellen nach Links verschieben (r6 ist das zweite Byte)
	orrs r0, r0, r1  // OR Vergleich zwischen initialem Wert und r1 --> 1 OR 1 wird 1; 0 OR 1 wird 1 (r1 ist IMMER 1 an der eingegebenen Stelle)
	str r0, [r4]
	
	// Ausgabe des veränderten Wertes aus dem Speicher
	ldr r0, =str_value_after_manipulation
	bl uart_putString
	ldr r4, =ADDRESS_B
	ldr r0, [r4]
	bl uart_putInt32
	
	/**
	HIER BEGINNT AUFGABE C) MIT BIT-BANDING
	**/
	
	// Ausgabe des initialen Werts aus dem Speicher
	ldr r0, =str_value_before_manipulation_bit
	bl uart_putString
	ldr r1, =ADDRESS_C
	ldr r0, [r1]
	bl uart_putInt32
	
	/* 
	BERECHNUNG der Bit-Alias-Adressen für erstes und zweites Bit
	
		Erstes Bit: r9 = r8 + (0x20000010 - 0x20000000) << 5 + r5 << 2 
		Zweites Bit: r10 = r8 + (0x20000010 - 0x20000000) << 5 + r6 << 2 
	
	*/
	lsls r6, r6, #2  // multipliziere zweites Bit mit 4
	lsls r5, r5, #2  // multipliziere erstes Bit mit 4
	ldr r8, =BASISADDR_BITBAND_ALIAS
	adds r8, r8, #(0x10 << 5)// #0x10 = 0x20000010 - 0x20000000 << 5
	adds r9, r8, r5 // Addiere r8 und r5
	adds r10, r8, r6 // addiere r8 und r6
	
	// setzen des ersten und zweiten Bits
	mov r0, #0x01 // schreibe 1 in r0
	str r0, [r10] // zweites Bit wird gesetzt (auf 1)
	mov r0, #0x00 // schreibe 0 in r0
	str r0, [r9] // erstes Bit wird zurückgesetzt (auf 0)
	
	// Ausgabe des veränderten Wertes aus dem Speicher
	ldr r0, =str_value_after_manipulation_bit
	bl uart_putString
	ldr r1, =ADDRESS_C
	ldr r0, [r1]
	bl uart_putInt32
	
	ldr r0, =str_line_break
	bl uart_putString
	
	// Ruecksprung zum Beginn
	b loop_program				// Sprung zum Programmstart

/*** Datenbereich (ab 0x20000000) ***/
.data
reserved_arrays: 
	.rept 20
	.byte 0x0
	.endr
firstBit: .byte 0x0
secondBit: .byte 0x0
str_input_prompt_first: .asciz "\nNummer des 0-Bits: 0x"
str_input_prompt_second: .asciz "\nNummer des 1-Bits: 0x"
str_value_before_manipulation_bit: .asciz "\nWert vor Manipulierung mit Bit-Banding: 0x"
str_value_after_manipulation_bit: .asciz "\nWert nach Manipulierung mit Bit-Banding: 0x"
str_value_before_manipulation: .asciz "\nWert vor Manipulierung ohne Bit-Banding: 0x"
str_value_after_manipulation: .asciz "\nWert nach Manipulierung ohne Bit-Banding: 0x"
str_line_break: .asciz "\n\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ COUNTER_READ_BYTE, 0x4				// Anzahl der Schleifendurchläufe
.equ REFERENCE_PIT, 0xb					// Referenzwert für PIT

/*
* Beantwortung von Aufgabe d) Die benötigte Zeit mit DSP ist etwas geringer. Je mehr IT-Befehlsblöcke man durch DSP-Befehle ersetzt, desto größer wird die Ersparnis
*/
main:	
	bl uart_init
	bl pit3_init
	
loop_program:	
	// Eingabe v1
	ldr r5, =v1
	ldr r0, =input_prompt_v1
	bl uart_putString
	bl readInByteVector
	
	// Eingabe v2
	ldr r5, =v2
	ldr r0, =input_prompt_v2
	bl uart_putString
	bl readInByteVector
	
	// Initialisierung für Loop
	mov r4, #COUNTER_READ_BYTE 
	ldr r6, =v1 // r6 zeigt auf byte array v1
	ldr r7, =v2 // r7 zeigt auf byte array v2
	ldr r8, =min // r8 zeigt auf byte array min
	ldr r9, =max // r9 zeigt auf byte array max
	ldr r0, =text_without_dsp
	bl uart_putString
	
	
	// PIT Startmessung für OHNE DSP
	ldr r10, =start_time_without_dsp
	bl pit3_getval				// UP-Aufruf für Zeitmessung
	mov r10, r0			// Rückgabewert aus r0 in r10 speichern
	
loop_sort_without_dsp:
	ldrb r0, [r6], #1 // lade erstes Byte aus r6 (v1) in r0 und inkrementiere danach
	ldrb r1, [r7], #1 // lade erstes Byte aus r7 (v2) in r1 und inkrementiere danach
	
	cmp r0, r1	// vergleiche r0 und r1
	ittee hi	
	movhi r2, r0	// wenn r0 > r1 dann Wert aus r0 nach r2 kopieren
	movhi r3, r1	// wenn r0 > r1 dann Wert aus r1 nach r3 kopieren
	movls r3, r0	// wenn r0 < r1 dann Wert aus r0 nach r3 kopieren
	movls r2, r1	// wenn r0 < r1 dann Wert aus r1 nach r2 kopieren
	
	strb r3, [r8], #1	// speicher den Wert aus r3 in min-Array und inkrementiere danach
	strb r2, [r9], #1	// speicher den Wert aus r2 in max-Array und inkrementiere danach
	
	subs r4, r4, #1			// dekrementiere counter (r4)
	bne loop_sort_without_dsp
	
	// PIT Endmessung für OHNE DSP
	ldr r11, =end_time_without_dsp
	bl pit3_getval				// UP-Aufruf für Zeitmessung
	mov r11, r0				// Rückgabewert aus r0 in r11 speichern
	
	// Ausgabe des minimalen und maximalen Vektors
	ldr r8, =min
	ldr r9, =max
	bl printVectors
	
	ldr r0, =str_needed_time_without_dsp	// String für benötigte Zeit in r0 laden
	bl uart_putString			// String für benötigte Zeit ausgeben
	
	// Suchzeit berechnen und ausgeben
	mov r9, #REFERENCE_PIT
	subs r11, r10, r11 			// Subtrahiert r11 (Ende) von r10 (Anfang) und speichert das wieder in r7 -> da Counter von 0xFFFFFFFF auf 0x00000000 herunterzählt
	subs r11, r11, r9			// Subtrahiert r9 (Referenz für Zeitmessung) von r11 (vorherige Differenz) und speichert das wieder in r11
	mov r0, r11					//holt Ergebnis der Subtraktion aus r11 und kopiert das in r0
	bl uart_putInt32			// gibt das Ergebnis aus
	
	ldr r0, =text_with_dsp
	bl uart_putString

	// Initialisierung für Loop (sh. oben)
	ldr r6, =v1
	ldr r7, =v2
	ldr r8, =min_dsp
	ldr r9, =max_dsp
	mov r4, #COUNTER_READ_BYTE
	
	// PIT Startmessung für MIT DSP
	ldr r10, =start_time_with_dsp
	bl pit3_getval				// UP-Aufruf für Zeitmessung
	mov r10, r0				// Rückgabewert aus r0 in r10 speichern
loop_sort_with_dsp:
	ldrb r0, [r6], #1 // lade erstes Byte aus r6 (v1) in r0 und inkrementiere danach
	ldrb r1, [r7], #1 // lade erstes Byte aus r7 (v2) in r1 und inkrementiere danach
	usub8 r2, r0, r1 // subtrahiere r1 von r0 und speichere Ergebnis in r2
	sel r3, r0, r1  // selektiert GE-Flags und gibt den größeren Wert zurück 
	sel r2, r1, r0  // selektiert GE-Flags und gibt den kleineren Wert zurück 
	 
	strb r2, [r8], #1 // speicher den Wert aus r2 in min-Array und inkrementiere danach
	strb r3, [r9], #1 // speicher den Wert aus r3 in max-Array und inkrementiere danach
	
	subs r4, r4, #1  // dekrementiere counter (r4)
	bne loop_sort_with_dsp
	
	// PIT Endmessung für OHNE DSP
	ldr r11, =end_time_with_dsp
	bl pit3_getval				// UP-Aufruf für Zeitmessung			
	mov r11, r0				// Rückgabewert aus r0 in r10 speichern
	
	// Ausgabe des minimalen und maximalen Vektors
	ldr r8, =min_dsp
	ldr r9, =max_dsp
	bl printVectors
	
	ldr r0, =str_needed_time_with_dsp	// String für benötigte Zeit in r0 laden
	bl uart_putString			// String für benötigte Zeit ausgeben
	
	// Suchzeit berechnen und ausgeben
	mov r9, #REFERENCE_PIT
	subs r11, r10, r11 			// Subtrahiert r11 (Ende) von r10 (Anfang) und speichert das wieder in r7 -> da Counter von 0xFFFFFFFF auf 0x00000000 herunterzählt
	subs r11, r11, r9			// Subtrahiert r9 (Referenz für Zeitmessung) von r11 (vorherige Differenz) und speichert das wieder in r11
	mov r0, r11					//holt Ergebnis der Subtraktion aus r11 und kopiert das in r0
	bl uart_putInt32			// gibt das Ergebnis in 0x0000 aus
	
	b loop_program

.thumb_func
readInByteVector:	
PUSH {r5, LR}
	mov r4, #COUNTER_READ_BYTE // initialisiere counter
	mov r1, r5 // kopiere r5 nach r1, um originale Adresse zu behalten 
	adds r5, r5, #(COUNTER_READ_BYTE - 1) // gehe ans Ende des Byte-Arrays
	loop_readByte:
		bl uart_getByte
		strb r0, [r5], #-1	// speichere Wert aus r0 an Adresse in r5 und dekrementiere um 1
		subs r4, r4, #1		// dekrementiere Counter um 1
		bne loop_readByte
	
	ldr r0, [r1]	// lade kompletten Vektor aus r1 in r0 
	bl uart_putInt32 // gebe Vektor aus
POP {r5, PC}

.thumb_func
printVectors:
PUSH {r8-r9, LR}
	// Ausgabe des min-Vektors
	ldr r0, =text_min
	bl uart_putString	
	ldr r0, [r8]
	bl uart_putInt32	
		
	// Ausgabe des max-Vektors
	ldr r0, =text_max
	bl uart_putString
	ldr r0, [r9]
	bl uart_putInt32
POP {r8-r9, PC}
	
/*** Datenbereich (ab 0x20000000) ***/
.data
input_prompt_v1: .asciz "\nGeben Sie den ersten Vektor in vier Bytes nacheinander ein: 0x"
input_prompt_v2: .asciz "\nGeben Sie den zweiten Vektor in vier Bytes nacheinander ein: 0x"
text_without_dsp: .asciz "\nohne DSP-Befehle:"
text_with_dsp: .asciz "\nmit DSP-Befehlen:"
text_min: .asciz "\nmin: 0x"
text_max: .asciz "\nmax: 0x"
str_needed_time_with_dsp: .asciz "\nBenoetigte Zeit mit DSP-Befehlen: 0x"
str_needed_time_without_dsp: .asciz "\nBenoetigte Zeit ohne DSP-Befehle: 0x"
start_time_with_dsp: .byte 0x0
end_time_with_dsp: .byte 0x0
start_time_without_dsp: .byte 0x0
end_time_without_dsp: .byte 0x0
v1: 
	.rept 4
	.byte 0x0
	.endr
v2: 
	.rept 4
	.byte 0x0
	.endr
min:
	.rept 4
	.byte 0x0
	.endr
max:
	.rept 4
	.byte 0x0
	.endr
min_dsp:
	.rept 4
	.byte 0x0
	.endr
max_dsp:
	.rept 4
	.byte 0x0
	.endr
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// Konstanten
.equ COUNTER, 3	
.equ SHORT_SIZE, 2		
.equ WORD_SIZE, 4
.equ COPY_COUNTER, 16

/*
* Es können durch die Nutzung von DSP die Hälfte der Multiplikationen gespart werden, da bei MUL 32-bit x 32-bit multipliziert werden müssen um am Ende auch nur ein 32-bit Ergebnis zu erhalten, wie z.B. bei SMUL
*/
main:	
	bl uart_init
	
	/**
	
	Aufgabe 2-1a)
	**/
	ldr r0, =str_matrix_o
	bl uart_putString
	
	mov r8, #COUNTER // inner Counter
	mov r9, #COUNTER // outer Counter
	
	ldr r5, =o
	ldr r10, =m_1
	ldr r11, =n_1
loop_matrix_multiplication_outer:
/* BEGINN Inner-Loop */
loop_matrix_multiplication_inner:	
	// Werte aus r10 und r11 an UP calculateSum übergeben
	mov r0, r10
	mov r1, r11
	bl calculateSum
	
	// Rückgabe aus calculateSum in r5 speichern und danach r5 um die Größe eines Wortes weiterzeigen lasen
	str r0, [r5]
	add r5, #WORD_SIZE
	bl uart_putInt32
	ldr r0, =empty
	bl uart_putString
	
	// nächste Spalte der Matrix N in r11 ablegen
	add r11, #SHORT_SIZE << 2
	subs r8, r8, #1
	bpl loop_matrix_multiplication_inner
/* ENDE Inner-Loop */
	
	ldr r0, =new_line
	bl uart_putString
	// nächste Zeile der Matrix M in r10 ablegen
	add r10, #SHORT_SIZE << 2
	// r11 wieder auf erste Spalte von Matrix N setzen
	ldr r11, =n_1
	mov r8, #COUNTER
	subs r9, r9, #1
	bpl loop_matrix_multiplication_outer

	/**
	Aufgabe 2-1b)
	
	Kopiere Matrix O nach Matrix O'
	 **/
	ldr r5, =o
	ldr r6, =o2
	mov r4, #COPY_COUNTER
	/*
	Lade immer Zeilen und Spalten und kopiere diese in die neue Matrix und inkrementiere danach um Länge eines Wortes
	*/
loop_copy:
	ldr r7, [r5], #WORD_SIZE
	str r7, [r6], #WORD_SIZE
	subs r4, r4, #1
	bne loop_copy

	ldr r0, =str_copy_matrix
	bl uart_putString

	/**
	
	Aufgabe 2-1c)
	**/
	ldr r10, =m_1
	ldr r11, =n_1
	mov r5, #0
	mov r8, #COUNTER
loop_matrix_multiplication_sum:
	// Werte aus r10 und r11 an UP calculateSum übergeben	
	mov r0, r10
	mov r1, r11
	bl calculateSum
	add r5, r5, r0 // Rückgabe aus calculateSum in r5 speichern
	
	// nächste Spalte der Matrix N in r11 ablegen
	add r11, #SHORT_SIZE << 2
	// nächste Teile der Matrix M in r10 ablegen
	add r10, #SHORT_SIZE << 2
	subs r8, r8, #1
	bpl loop_matrix_multiplication_sum
	
	ldr r0, =str_product_sum
	bl uart_putString
	
	// r5 ausgeben
	mov r0, r5
	bl uart_putInt32


	/**
	
	Aufgabe 2-1d)
	
	Hier wird ersichtlich, dass die Befehle UADD16 und SADD16 keine Sättigung vornehmen, die Befehle UQADD16 und QADD16 jedoch schon, da erkennbar ist, dass die Ausgaben der beiden ersten Befehle identisch sind, jedoch die anderen 
	beiden sich unterscheiden, obwohl in beiden Varianten (UADD16 und UQADD16 bzw. SADD16 und QADD16) zwei 16-Bit Integer miteinander addiert werden
	**/
	ldr r0, =task_d_a
	ldr r4, [r0]
	ldr r0, =task_d_b
	ldr r5, [r0]
	ldr r0, =task_d_c
	ldr r6, [r0]
	ldr r0, =task_d_d
	ldr r7, [r0]
	
	// UADD16
	ldr r0, =str_uadd16
	bl uart_putString
	
	// a mit b
	uadd16 r0, r4, r5
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit c
	uadd16 r0, r4, r6
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit d
	uadd16 r0, r4, r7
	bl uart_putInt32
	
	// SADD16
	ldr r0, =str_sadd16
	bl uart_putString
	
	// a mit b
	sadd16 r0, r4, r5
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit c
	sadd16 r0, r4, r6
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit d
	sadd16 r0, r4, r7
	bl uart_putInt32
	
	// UQADD16
	ldr r0, =str_uqadd16
	bl uart_putString
	
	// a mit b
	uqadd16 r0, r4, r5
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit c
	uqadd16 r0, r4, r6
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit d
	uqadd16 r0, r4, r7
	bl uart_putInt32
	
	// QADD16
	ldr r0, =str_qadd16
	bl uart_putString
	
	// a mit b
	qadd16 r0, r4, r5
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit c
	qadd16 r0, r4, r6
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	// a mit d
	qadd16 r0, r4, r7
	bl uart_putInt32
	
	/**
	
	Aufgabe 2-1e)
	
	Aus dem Generic User Guide für Cortex-M4 Devices ist ersichtlich, dass je nach dem ob eine signed oder unsigned n-Bit Sättigung stattfindet unterschiedliche Sättigungsregeln gelten.
	
	bei Signed:
	- wenn Wert kleiner als -2^{n-1} ist, dann gib -2^{n-1} zurück
	- wenn Wert größer ist, wird -2^{n-1}-1 zurückgegeben
	- sonst wird der Ursprungswert zurückgegeben
	
	bei Unsigned:
	- wenn Wert kleiner 0 ist, gib 0 zurück
	- wenn Wert größer als 2^{n-1] ist, dann gib 2^{n-1} zurück
	- sonst wird der Ursprungswert zurückgegeben
	
	Damit lassen sich Werte auf bestimmte Wertebereiche beschränken und mann kan z.B. negative Werte verhindern -> aus einem negativen Wert wird einfach eine 0
	**/
	ldr r0, =str_ssat16
	bl uart_putString
	
	// lade die beiden Halfwords aus r0 in r6 und r7
	ldr r0, =task_d_a
	ldrh r6, [r0], #SHORT_SIZE
	ldrh r7, [r0]
	
	// sättige r6 auf 13 Bit und speichere nach r1
	ldr r1, =ssat16_e
	ssat16 r0, #13, r6
	strh r0, [r1], #SHORT_SIZE

	// sättige r7 auf 13 Bit und speichere nach r1
	ssat16 r0, #13, r7
	strh r0, [r1], #SHORT_SIZE
	
	// gebe r1 aus
	ldr r1, =ssat16_e
	ldr r0, [r1]
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	ldr r0, =task_d_b
	ldrh r6, [r0], #SHORT_SIZE
	ldrh r7, [r0]
	
	ldr r1, =ssat16_e
	ssat16 r0, #13, r6
	strh r0, [r1], #SHORT_SIZE

	ssat16 r0, #13, r7
	strh r0, [r1], #SHORT_SIZE
	
	ldr r1, =ssat16_e
	ldr r0, [r1]
	bl uart_putInt32
	
	/* USAT16 */
	ldr r0, =str_usat16
	bl uart_putString
	
	ldr r0, =task_d_a
	ldrh r6, [r0], #SHORT_SIZE
	ldrh r7, [r0]
	
	ldr r1, =usat16_e
	usat16 r0, #13, r6
	strh r0, [r1], #SHORT_SIZE

	usat16 r0, #13, r7
	strh r0, [r1], #SHORT_SIZE
	
	ldr r1, =usat16_e
	ldr r0, [r1]
	bl uart_putInt32
	
	ldr r0, =empty
	bl uart_putString
	
	ldr r0, =task_d_b
	ldrh r6, [r0], #SHORT_SIZE
	ldrh r7, [r0]
	
	ldr r1, =usat16_e
	usat16 r0, #13, r6
	strh r0, [r1], #SHORT_SIZE

	usat16 r0, #13, r7
	strh r0, [r1], #SHORT_SIZE
	
	ldr r1, =usat16_e
	ldr r0, [r1]
	bl uart_putInt32
end:
	b end

/**
	multipliziert immer die Zeile mit der Spalte und gibt das in r0 zurück
**/	
.thumb_func
calculateSum:	
PUSH {r4-r7, LR}
	mov r4, #0
	mov r5, #WORD_SIZE
loop_sum:	
	ldrh r6, [r0], #SHORT_SIZE
	ldrh r7, [r1], #SHORT_SIZE
	smlabb r4, r6, r7, r4	
	subs r5, r5, #1			// dekrementiere counter
	bne loop_sum
	
	mov r0, r4
POP {r4-r7, PC}

/*** Datenbereich (ab 0x20000000) ***/
.data
m_1: .short 0x5F8C, 0x7F48, 0x8245, 0x6048 // erste Zeile Vektor M
m_2: .short 0xC799, 0x9C5D, 0xD49C, 0x33D8 // zweite Zeile Vektor M
m_3: .short 0x579B, 0x8AEF, 0xF2C0, 0xA3C2 // dritte Zeile Vektor M
m_4: .short 0x41FD, 0x50D4, 0x25C6, 0x4AFA // vierte Zeile Vektor M

n_1: .short 0x7F41, 0x0645, 0x8C8F, 0x9065 // erste Spalte Vektor N
n_2: .short 0x78E3, 0xF7F3, 0xD29F, 0x2961 // zweite Spalte Vektor N
n_3: .short 0x5A1E, 0xDFED, 0x4B9F, 0x1092 // dritte Spalte Vektor N
n_4: .short 0x61BF, 0x21BE, 0x5CA1, 0xC6D3 // vierte Spalte Vektor N

o:
	.rept 4
	.word 0x0, 0x0, 0x0, 0x0 
	.endr
	
o2:
	.rept 4
	.word 0x0, 0x0, 0x0, 0x0 
	.endr
	
task_d_a: .word 0xA4367C7B	
task_d_b: .word 0x10A78933	
task_d_c: .word 0xC5535F2C	
task_d_d: .word 0x788E84B1	

ssat16_e: .word 0x0
usat16_e: .word 0x0

str_matrix_o: .asciz "\nErgebnismatrix O:\n"
str_copy_matrix: .asciz "Kopieren der Matrix O!"
str_product_sum: .asciz "\nProdukt-Summe: "
str_uadd16: .asciz "\nUADD16: "
str_sadd16: .asciz "\nSADD16: "
str_uqadd16: .asciz "\nUQADD16: "
str_qadd16: .asciz "\nQADD16: "
str_ssat16: .asciz "\nSSAT16: "
str_usat16: .asciz "\nUSAT16: "
empty: .asciz " "
new_line: .asciz "\n"
// Include-Dateien
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/**

(25.000.000 Takte - 4 Takte) / 4 Takte 
(Startwert - Initialisierung) / Schleifendauer

**/
.equ START_VALUE_DELAY, 0x5F5E0F

/*
Grenzwerte für einzelne Zeitelemente
*/ 
.equ MAX_MINUTES, 60
.equ MAX_HOURS, 24
.equ MAX_DAYS, 31
.equ MAX_MONTHS, 12
.equ MAX_YEAR, 99

/*
ASCII Hex-Repräsentation für d, s & t
*/
.equ CHAR_D, 0x64
.equ CHAR_S, 0x73
.equ CHAR_T, 0x74

main:	
	bl uart_init

loop_time:
	// rufe UP für Delay auf
	bl delay
	// rufe UP für Ausgabe der aktuellen Zeit auf
	bl currentTime
	
	// prüfe ob Zeichen vorhanden und rufe wenn das UP zur Überprüfung des Zeichens auf
	bl uart_charPresent
	cmp r0, #0
	it ne
	blne checkSendedCharacter
	
	// inkrementiere die aktuelle Minute -> passiert kein Überlauf der MAX_MINUTES, dann springe zu loop_time
	ldr r0, =minute
	mov r1, #MAX_MINUTES
	mov r2, #0
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere die aktuelle Stunde -> passiert kein Überlauf der MAX_HOURS, dann springe zu loop_time
	ldr r0, =hour
	mov r1, #MAX_HOURS
	mov r2, #0
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere den aktuellen Tag -> passiert kein Überlauf der MAX_DAYS, dann springe zu loop_time
	ldr r0, =day
	mov r1, #MAX_DAYS
	mov r2, #1
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere den aktuellen Monat -> passiert kein Überlauf der MAX_MONTHS, dann springe zu loop_time
	ldr r0, =month
	mov r1, #MAX_MONTHS
	mov r2, #1
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere das aktuelle Jahr (2014 -> 2015) -> passiert kein Überlauf der MAX_YEAR, dann springe zu loop_time -> Überlauf wäre bei > 99 und würde zufolge haben, dass aus 2099 dann 2100 wird
	ldr r0, =year
	add r0, r0, #1
	mov r1, #MAX_YEAR
	mov r2, #0
	bl incrementDateSegment
	bne loop_time
	
	// Falls größer > 2099 dann inkrementiere die ersten beiden Stellen des Jahres -> z.B. aus 20 wird 21 usw.
	ldr r0, =year
	mov r1, #MAX_YEAR
	mov r2, #0
	bl incrementDateSegment
end:
	b loop_time

/*
Holt sich das eingegebene Zeichen und ruft je nach eingegebenem Zeichen eine der drei spezifizierten Funktionen auf
*/
.thumb_func
checkSendedCharacter:
PUSH {r4, LR}
	bl uart_getChar
	mov r4, r0
	
	cmp r4, #CHAR_S
	it eq
	bleq startStop
	
	cmp r4, #CHAR_T
	it eq
	bleq setTime
	
	cmp r4, #CHAR_D
	it eq
	bleq setDate
POP {r4, PC}

/**
Zeit wird vom Nutzer einzeln in Stunde und Minute eingegeben und im Speicher abgelegt 

Danach wird UP verlassen und die Uhr läuft mit der neu gesetzten Zeit weiter
**/
.thumb_func
setTime:
PUSH {LR}
	ldr r0, =str_input_hour
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =hour
	strb r0, [r1]
	bl uart_putByteBase10
	
	ldr r0, =str_input_minute
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =minute
	strb r0, [r1]
	bl uart_putByteBase10
	
	ldr r0, =str_new_line
	bl uart_putString
POP {PC}

/**
Datum wird vom Nutzer einzeln in Tag, Monat und Jahr eingegeben und im Speicher abgelegt 

Danach wird UP verlassen und die Uhr läuft mit dem neu gesetzten Datum weiter
**/
.thumb_func
setDate:
PUSH {LR}
	ldr r0, =str_input_day
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =day
	strb r0, [r1]
	bl uart_putByteBase10
	
	ldr r0, =str_input_month
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =month
	strb r0, [r1]
	bl uart_putByteBase10
	
	ldr r0, =str_input_year
	bl uart_putString
	bl uart_getByteBase10
	ldr r1, =year
	add r1, r1, #1
	strb r0, [r1]
	bl uart_putByteBase10
	
	ldr r0, =str_new_line
	bl uart_putString
POP {PC}

/**
Wartet bis wieder das Zeichen s eingegeben wurde -> wird was anderes eingegeben wird das UP in einer Schleife aufgerufen
**/
.thumb_func
startStop:
PUSH {r4, LR}
	bl uart_getChar
	cmp r0, #CHAR_S
	it ne
	bne startStop
POP {r4, PC}

/*
Looped solange, bis Delay-Counter abgelaufen ist
*/
.thumb_func
delay:	
PUSH {LR}
	ldr r1, =#START_VALUE_DELAY
loop_delay:
	nop
	subs r1, r1, #1
	bpl loop_delay
POP {PC}

/**
Erwartet verschiedene Eingabewerte
r0: das aktuelle Elemente (z.B. Tag, Stunde, Jahr etc.)
r1: das Maximum des entsprechenden Elements
r2: den Standardwert bei Überlauf (z.B. Erste Stunde des nächsten Tags ist 0)

Es lädt den aktuellen Wert des Elements, inkrementiert dieses, prüft ob ein Überlauf stattfindet (= Maximum), wenn ja wird Standardwert gespeichert und sonst der inkrementierte Wert in r0 zurückgespeichert
**/
.thumb_func
incrementDateSegment:
    push {r4, LR}
    
    ldrb r4, [r0]          
    add r4, r4, #1             
    cmp r4, r1                 
    it eq
    moveq r4, r2               
    strb r4, [r0]
    
    pop {r4, PC}
	
/**
GIbt das aktuelle Datum und die aktuelle Zeit aus
**/	
.thumb_func
currentTime:
PUSH {r4, LR}
	ldr r1, =day
	ldrb r0, [r1]
	bl printNumberWithLeadingZero // das UP prüft ob die aktuelle Zahl < 10 ist und gibt in dem Fall eine führende Null mit aus
	ldr r0, =str_dot
	bl uart_putString
	
	ldr r1, =month
	ldrb r0, [r1]
	bl printNumberWithLeadingZero
	ldr r0, =str_dot
	bl uart_putString
	
	ldr r4, =year
	ldrb r0, [r4]
	add r4, r4, #1
	bl uart_putByteBase10
	ldrb r0, [r4]
	bl printNumberWithLeadingZero
	ldr r0, =str_empty
	bl uart_putString
	
	ldr r1, =hour
	ldrb r0, [r1]
	bl printNumberWithLeadingZero
	ldr r0, =str_colon
	bl uart_putString
	
	ldr r1, =minute
	ldrb r0, [r1]
	bl printNumberWithLeadingZero
	ldr r0, =str_empty
	bl uart_putString
	
	ldr r0, =str_time
	bl uart_putString
POP {r4, PC}	

/**
prüft ob Zahl kleiner 10, wenn nicht gebe führende 0 mit aus und sonst gebe nur die Zahl aus
**/
.thumb_func
printNumberWithLeadingZero:
PUSH {r4, LR}
	mov r4, r0
	cmp r4, #10
	it ge
	bge skipLeadingZero
	
	mov r0, #'0'
	bl uart_putChar
skipLeadingZero:
	mov r0, r4
	bl uart_putByteBase10
POP {r4, PC}
	
/*** Datenbereich (ab 0x20000000) ***/
.data
str_input_hour: .asciz "\nStunde eingeben (hh): "
str_input_minute: .asciz "\nMinuten eingeben (mm): "
str_input_day: .asciz "\nTag eingeben (dd): "
str_input_month: .asciz "\nMonat eingeben (mm): "
str_input_year: .asciz "\nJahr eingeben (jj): "
str_start: .asciz "Start\n"
str_end: .asciz "Ende\n"
str_dot: .asciz "."
str_colon: .asciz ":"
str_empty: .asciz " "
str_new_line: .asciz "\n"
str_time: .asciz "Uhr\n"
day: .byte 0x1
month: .byte 0x1
year: .byte 0x14, 0xE
hour: .byte 0x0
minute: .byte 0x0

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/**
40 ns ergeben sich bei Takt von 25 MHz

1 Sekunde / 40 ns = 25000000 Takte => 0x17D7840

**/
.equ PIT1_START_VALUE, 0x17D7840

/*
Grenzwerte für einzelne Zeitelemente
*/
.equ MAX_MINUTES, 60
.equ MAX_HOURS, 24
.equ MAX_DAYS, 31
.equ MAX_MONTHS, 12
.equ MAX_YEAR, 99

/*
ASCII Hex-Repräsentation für d, s & t
*/
.equ CHAR_D, 0x64
.equ CHAR_S, 0x73
.equ CHAR_T, 0x74

// SIM Module Adressen
__BBREG SIM_SCGC6_PIT_ADR, 0x4004803C, 23

// PIT Module Adressen
.equ PIT_LDVAL1, 0x40037110	
.equ PIT_TFLG1, 0x4003711c
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ PIT1_OFFSET, 0x154

// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E280
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BIT_MSK, 1 << 5


main:	
	bl uart_init
	
	/*
	 Aktiviere PIT Clock Gate Control
	*/
	ldr r0, =SIM_SCGC6_PIT_ADR
    mov r1, #1
    str r1, [r0]
    
    // Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
    
    // Addiere Offset für PIT1 (0x154) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r1, r1, #PIT1_OFFSET
    ldr r0, =pit_isr
    str r0, [r1]
    
    // Aktiviere Clock for PIT Timers
    ldr r0, =PIT_MCR
    mov r1, #0
    str r1, [r0]	
    
    // Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE
    str r1, [r0]
    
    // Aktiviere Interrupt für PIT1
    ldr r0, =NVIC_ISER2
    mov r1, #NVIC_BIT_MSK
    str r1, [r0]
    
    // Lösche Pending Interrupts für PIT1
    ldr r0, =NVIC_ICPR2
    mov r1, #NVIC_BIT_MSK
    str r1, [r0]
   
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #3
    str r1, [r0]

loop_time:
	// werte Benutzer-Flag des Interrupts für PIT1 aus -> wenn nicht gesetzt loope
	ldr r7, =isr_flag
	ldrb r6, [r7]
	cmp r6, #0
	beq loop_time
	
	// setze Benutzer-Flag zurück
	mov r6, #0
	strb r6, [r7]

	// rufe UP für Ausgabe der aktuellen Zeit auf
	bl currentTime
	
	// prüfe ob Zeichen vorhanden und rufe wenn das UP zur Überprüfung des Zeichens auf
	bl uart_charPresent
	cmp r0, #0
	it ne
	blne checkSendedCharacter
	
	// inkrementiere die aktuelle Minute -> passiert kein Überlauf der MAX_MINUTES, dann springe zu loop_time
	ldr r0, =minute
	mov r1, #MAX_MINUTES
	mov r2, #0
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere die aktuelle Stunde -> passiert kein Überlauf der MAX_HOURS, dann springe zu loop_time
	ldr r0, =hour
	mov r1, #MAX_HOURS
	mov r2, #0
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere den aktuellen Tag -> passiert kein Überlauf der MAX_DAYS, dann springe zu loop_time
	ldr r0, =day
	mov r1, #MAX_DAYS
	mov r2, #1
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere den aktuellen Monat -> passiert kein Überlauf der MAX_MONTHS, dann springe zu loop_time
	ldr r0, =month
	mov r1, #MAX_MONTHS
	mov r2, #1
	bl incrementDateSegment
	bne loop_time
	
	// inkrementiere das aktuelle Jahr (2014 -> 2015) -> passiert kein Überlauf der MAX_YEAR, dann springe zu loop_time -> Überlauf wäre bei > 99 und würde zufolge haben, dass aus 2099 dann 2100 wird
	ldr r0, =year
	add r0, r0, #1
	mov r1, #MAX_YEAR
	mov r2, #0
	bl incrementDateSegment
	bne loop_time
	
	// Falls größer > 2099 dann inkrementiere die ersten beiden Stellen des Jahres -> z.B. aus 20 wird 21 usw.
	ldr r0, =year
	mov r1, #MAX_YEAR
	mov r2, #0
	bl incrementDateSegment
end:
	b loop_time

