	ldr r0, =str_dot
	bl uart_putString
	
	ldr r4, =year
	ldrb r0, [r4]
	add r4, r4, #1
	bl uart_putByteBase10
	ldrb r0, [r4]
	bl printNumberWithLeadingZero
	ldr r0, =str_empty
	bl uart_putString
	
	ldr r1, =hour
	ldrb r0, [r1]
	bl printNumberWithLeadingZero
	ldr r0, =str_colon
	bl uart_putString
	
	ldr r1, =minute
	ldrb r0, [r1]
	bl printNumberWithLeadingZero
	ldr r0, =str_empty
	bl uart_putString
	
	ldr r0, =str_time
	bl uart_putString
POP {r4, PC}	

/**
prüft ob Zahl kleiner 10, wenn nicht gebe führende 0 mit aus und sonst gebe nur die Zahl aus
**/
.thumb_func
printNumberWithLeadingZero:
PUSH {r4, LR}
	mov r4, r0
	cmp r4, #10
	it ge
	bge skipLeadingZero
	
	mov r0, #'0'
	bl uart_putChar
skipLeadingZero:
	mov r0, r4
	bl uart_putByteBase10
POP {r4, PC}

/**
ISR setzt Benutzer-Flag auf 1 und resettet das Timer Interrupt Flag
**/
.global pit_isr
.thumb_func
pit_isr:
	ldr r0, =isr_flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0]
	bx lr
	
/*** Datenbereich (ab 0x20000000) ***/
.data
str_input_hour: .asciz "\nStunde eingeben (hh): "
str_input_minute: .asciz "\nMinuten eingeben (mm): "
str_input_day: .asciz "\nTag eingeben (dd): "
str_input_month: .asciz "\nMonat eingeben (mm): "
str_input_year: .asciz "\nJahr eingeben (jj): "
str_start: .asciz "Start\n"
str_end: .asciz "Ende\n"
str_dot: .asciz "."
str_colon: .asciz ":"
str_empty: .asciz " "
str_new_line: .asciz "\n"
str_time: .asciz "Uhr\n"
day: .byte 0x1
month: .byte 0x1
year: .byte 0x14, 0xE
hour: .byte 0x0
minute: .byte 0x0
isr_flag: .byte 0x0
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

// SIM Module Adressen
__BBREG SIM_SCGC6_CRC_ADR, 0x4004803C, 18

// CRC Module Adressen
.equ CRC_CRC, 0x40032000
.equ CRC_CTRL, 0x40032008
// Wert zur Aktivierung von CRC-32
.equ CRC_CTRL_VAL, 0x1000000
.equ CRC_GPOLY, 0x40032004
// CRC-32 Polynom
.equ CRC_GPOLY_VAL, 0x82608EDB
__BBREG CRC_CTRL_WAS, 0x40032008, 25

.equ CRC_SEED, 0x12345678
.equ BYTE_COUNTER, 0x3

main:	
	bl uart_init

	/*
	 Aktiviere CRC Clock Gate Control
	*/
	ldr r0, =SIM_SCGC6_CRC_ADR
    mov r1, #1
    str r1, [r0]

	/*
	 Aktiviere CRC 32-Bit
	*/
	ldr r0, =CRC_CTRL
    mov r1, #CRC_CTRL_VAL
    str r1, [r0]
    
    /*
	 Setze CRC Polynom
	*/
	ldr r0, =CRC_GPOLY
    ldr r1, =#CRC_GPOLY_VAL
    str r1, [r0]
    
    /*
     Setze CRC CRTL WAS auf HIGH
    */
    ldr r0, =CRC_CTRL_WAS
    mov r1, #1
    str r1, [r0]
    
    /*
    Setze CRC Seed
    */
    ldr r0, =CRC_CRC
    ldr r1, =#CRC_SEED
    str r1, [r0]
    
    /*
     Setze CRC CRTL WAS auf LOW
    */
    ldr r0, =CRC_CTRL_WAS
    mov r1, #0
    str r1, [r0]
    
    ldr r5, =CRC_CRC
    ldr r4, =str
loop_crc:    
    ldr r1, [r4]
    
    /*
    Prüfe ob ein Byte des Wortes 0x0 ist => Ende des Strings, wenn ja dann Springe zur Ausgabe-Marke
    */
    mov r6, #BYTE_COUNTER
loop_str_end:    
    ldrb r2, [r4]
    cmp r2, #0x0
    beq print_result
    add r4, r4, #1
    
    subs r6, r6, #1
    bpl loop_str_end 
    
    //  Schreibe Wert in r1 (aktueller r4 Wort) in deas Register CRC_CRC (r5)
    str r1, [r5]
    b loop_crc
    
print_result:
	ldr r0, =str
	bl uart_putString
	ldr r0, =new_line
	bl uart_putString
	ldr r0, [r5]
	bl uart_putInt32
	
end:
	b end

/*** Datenbereich (ab 0x20000000) ***/
.data
str: .asciz "Praktikum und Werkstatt Technische Informatik, \nFernuniversitaet Hagen"
new_line: .asciz "\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/**
40 ns ergeben sich bei Takt von 25 MHz

1 Sekunde / 40 ns = 25000000 Takte => 0x17D7840

**/
.equ PIT1_START_VALUE, 0x17D7840

// SIM Module Adressen
__BBREG SIM_SCGC5_PORTA_ADR, 0x40048038, 9
__BBREG SIM_SCGC5_PORTE_ADR, 0x40048038, 13
__BBREG SIM_SCGC6_PIT_ADR, 0x4004803C, 23
__BBREG PORTE_PCR26_ISF_ADR, 0x4004D068, 24

// PIT Module Adressen
.equ PIT_LDVAL1, 0x40037110	
.equ PIT_TFLG1, 0x4003711c
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ PIT1_OFFSET, 0x154
.equ PORT_E_OFFSET, 0x1AC

// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E288
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_IABR2, 0xE000E300
.equ NVIC_BIT_MSK, 0x8000020
.equ NVIC_BIT_PORT_E_MSK, 1 << 27

.equ GPIOA_PDDR_ADR, 0x400FF014
.equ GPIOA_PDDR_VALUE, 0x30000C00
.equ GPIOA_PDOR_ADR, 0x400FF000
.equ GPIOA_PDOR_VALUE, 0x30000C00

__BBREG GPIOA_PDOR_LED_D7, 0x400FF000, 11
__BBREG GPIOA_PDOR_LED_D8, 0x400FF000, 28
__BBREG GPIOA_PDOR_LED_D9, 0x400FF000, 29
__BBREG GPIOA_PDOR_LED_D11, 0x400FF000, 10

.equ GPIOA_PDIR, 0x400ff010	
.equ GPIOA_PDIR_SW1_MASK, 0xFFF7FFFF
.equ GPIOE_PDIR_SW2_MASK, 0xFBFFFFFF 
.equ GPIOE_PDIR, 0x400ff110	


.equ PORTA_PCR11, 0x4004902C // LED D7
.equ PORTA_PCR28, 0x40049070 // LED D8
.equ PORTA_PCR29, 0x40049074 // LED D9
.equ PORTA_PCR10, 0x40049028 // LED D11
.equ PORTA_PCR_LED_VALUE, 0x100

.equ PORTA_PCR19, 0x4004904C // SW1
.equ PORTA_PCR19_VALUE, 0x20100
.equ PORTE_PCR26, 0x4004D068 // SW2
.equ PORTE_PCR26_VALUE, 0x10a0103
.equ PORTE_ISFR, 0x4004d0a0

.equ LINE_FEED, 0x0A
.equ COUNTER_LED, 3
.equ FIRST_BIT, 0xFE
.equ SECOND_BIT, 0xFD
.equ THIRD_BIT, 0xFB
.equ FOURTH_BIT, 0xF7
.equ FULL, 0xFF

/*
ASCII Hex-Repräsentation für d, + & .
*/
.equ CHAR_PLUS, 0x2B
.equ CHAR_S, 0x73
.equ CHAR_MINUS, 0x2D

/**

(25.000.000 Takte - 4 Takte) / 4 Takte 
t = (Startwert - Initialisierung) / Schleifendauer = 1s 

5ms = 1s / 200 -> t/200 _> 0x7A12

**/

.equ DEBOUNCE_DELAY_START_VALUEE, 0x7A12

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
	
	/*
	 Aktiviere Port A Clock Gate Control
	*/
	ldr r0, =SIM_SCGC5_PORTA_ADR
    mov r1, #1
    str r1, [r0]
    
    /*
	 Aktiviere Port E Clock Gate Control
	*/
	ldr r0, =SIM_SCGC5_PORTE_ADR
    mov r1, #1
    str r1, [r0]
    
	/*
	 Aktiviere PIT Clock Gate Control
	*/
	ldr r0, =SIM_SCGC6_PIT_ADR
    mov r1, #1
    str r1, [r0]
    
    // Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r4, [r0]
    
    // Addiere Offset für PIT1 (0x154) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r1, r4, #PIT1_OFFSET
    ldr r0, =pit_isr
    str r0, [r1]
   
    // Addiere Offset für Port E (0x1AC) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r1, r4, #PORT_E_OFFSET
    ldr r0, =button_isr
    str r0, [r1]
    
    // Aktiviere Clock for PIT Timers
    ldr r0, =PIT_MCR
    mov r1, #0
    str r1, [r0]	
    
    // Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE
    str r1, [r0]
    
    // Aktiviere Interrupt für PIT1 & Port E
    ldr r0, =NVIC_ISER2
    ldr r1, =#NVIC_BIT_MSK
    str r1, [r0]
    
    // Lösche Pending Interrupts für PIT1 & Port E
    ldr r0, =NVIC_ICPR2
    ldr r1, =#NVIC_BIT_MSK
    str r1, [r0]
    
    /*
    Setze LEDs auf Output
    */
    ldr r0, =GPIOA_PDDR_ADR
    ldr r1, =#GPIOA_PDDR_VALUE
    str r1, [r0]
    
    /*
    Setze GPIO von LED D7 aktiv
    */
    ldr r0, =PORTA_PCR11
    ldr r1, =#PORTA_PCR_LED_VALUE
    str r1, [r0]
    
    /*
    Setze GPIO von LED D8 aktiv
    */
    ldr r0, =PORTA_PCR28
    ldr r1, =#PORTA_PCR_LED_VALUE
    str r1, [r0]
    
    /*
    Setze GPIO von LED D9 aktiv
    */
    ldr r0, =PORTA_PCR29
    ldr r1, =#PORTA_PCR_LED_VALUE
    str r1, [r0]
    
    /*
    Setze GPIO von LED D11 aktiv
    */
    ldr r0, =PORTA_PCR10
    ldr r1, =#PORTA_PCR_LED_VALUE
    str r1, [r0]
    
    /*
    Setze GPIO von SW1 aktiv
    */
    ldr r0, =PORTA_PCR19
    ldr r1,  =#PORTA_PCR19_VALUE
    str r1, [r0]
    
    /*
    Setze GPIO von SW2 aktiv
    */
    ldr r0, =PORTE_PCR26
    ldr r1, =#PORTE_PCR26_VALUE
    str r1, [r0]
    
    /*
    Schalte LEDs aus (Default ist an)
    */
    ldr r0, =GPIOA_PDOR_ADR
    ldr r1, =#GPIOA_PDOR_VALUE
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #3
    str r1, [r0]
    
loop_program:
	// werte Benutzer-Flag des Interrupts für PIT1 aus -> wenn nicht gesetzt loope
	ldr r7, =isr_flag
	ldrb r6, [r7]
	cmp r6, #0
	beq loop_program   
	
	// setze Benutzer-Flag zurück
	mov r6, #0
	strb r6, [r7]
	
running_loop:	
	ldr r0, =running
	ldrb r4, [r0]
	
	/*
	Prüfe auf gesendeten Charakter (s, +, -)
	*/
	bl uart_charPresent
	cmp r0, #0
	it ne
	blne checkSendedCharacter
	
	cmp r4, #0
	it eq
	// springe zurück, solange running = 0
	beq running_loop
		
	/*
	Gebe den aktuellen Counter-Wert aus
	*/	
	ldr r4, =counter
	ldrb r0, [r4]
	bl uart_putByteBase10
	
	ldrb r5, [r4]


	          
	bic r0, r5, #FIRST_BIT // lösche alle Bits außer an der Stelle 2⁰
	eor r0, r0, #FULL // invertieren (0-> 1 & 1->0), da LED high bei logic low
	ldr r1, =GPIOA_PDOR_LED_D7
	cmp r0, #FIRST_BIT
	ite eq
	moveq r2, #0
	movne r2, #1
	str r2, [r1]
	
	bic r0, r5, #SECOND_BIT // lösche alle Bits außer an der Stelle 2¹
	eor r0, r0, #FULL // invertieren (0-> 1 & 1->0), da LED high bei logic low
	ldr r1, =GPIOA_PDOR_LED_D8
	cmp r0, #SECOND_BIT
	ite eq
	moveq r2, #0
	movne r2, #1
	str r2, [r1]
	
	bic r0, r5, #THIRD_BIT // lösche alle Bits außer an der Stelle 2²
	eor r0, r0, #FULL // invertieren (0-> 1 & 1->0), da LED high bei logic low
	ldr r1, =GPIOA_PDOR_LED_D9
	str r0, [r1]
	cmp r0, #THIRD_BIT
	ite eq
	moveq r2, #0
	movne r2, #1
	str r2, [r1]
	
	bic r0, r5, #FOURTH_BIT // lösche alle Bits außer an der Stelle 2³
	eor r0, r0, #FULL // invertieren (0-> 1 & 1->0), da LED high bei logic low
	ldr r1, =GPIOA_PDOR_LED_D11
	cmp r0, #FOURTH_BIT
	ite eq
	moveq r2, #0
	movne r2, #1
	str r2, [r1]
	
	/*
	Abhängig vom Status von direction eine Zahl zum Counter addieren oder subtrahieren
	*/
	ldr r0, =direction
	ldrb r1, [r0]
	cmp r1, #0
	ite eq
	addeq r5, r5, #1
	subne r5, r5, #1
	strb r5, [r4]
	
	mov r0, #LINE_FEED
	bl uart_putChar

	// Button-Status prüfen
	bl button_request_sw1
   
	b loop_program


/*
UP für SW1
*/
.thumb_func
button_request_sw1:
PUSH {r4, LR}
	ldr r2, =mod
	ldrb r3, [r2]
	
	/*
	Prüfen ob GPIOA_PDIR an der Stelle von SW1 (Bit 20) passt -> Button gedrückt
	*/
	ldr r4, =GPIOA_PDIR
	ldr r0, [r4]
	bic r0, r0, #GPIOA_PDIR_SW1_MASK
	cmp r0, #0x0
	ite eq 
	moveq r3, #1
	bne button_request_end
	
	/*
	Delay von 5ms
	*/
	ldr r1, =#DEBOUNCE_DELAY_START_VALUEE
loop_delay:
	nop
	subs r1, r1, #1
	bpl loop_delay
	
	/*
	Prüfen ob GPIOA_PDIR an der Stelle von SW1 (Bit 20) immernoch passt -> Button gedrückt
	*/
	ldr r0, [r4]
	bic r0, r0, #GPIOA_PDIR_SW1_MASK
	cmp r0, #0x0
	itee eq 
	moveq r3, #1
	movne r3, #0
	bne button_request_end
	
	/*
	Setze Richtung invers zur vorher gesetzten
	*/
	ldr r0, =direction
	ldrb r1, [r0]
	cmp r1, #0
	ite eq
	moveq r1, #1
	movne r1, #0
	
	strb r1, [r0]
	
button_request_end:	
	strb r3, [r2]
	
POP {r4, PC}


/*
Prüfe darauf, welcher Char gesendet wurde und  springe in daas entsprechende UP
*/
.thumb_func
checkSendedCharacter:
	PUSH {r4, LR}
	bl uart_getChar
	mov r4, r0
	
	cmp r4, #CHAR_S
	it eq
	bleq startStop
	
	cmp r4, #CHAR_PLUS
	it eq
	bleq setDirectionUp
	
	cmp r4, #CHAR_MINUS
	it eq
	bleq setDirectionDown
	POP {r4, PC}

/**
Setzt direction auf 0 (aufwärts)
**/
.thumb_func
setDirectionUp:
	ldr r2, =direction
	ldrb r3, [r2]
	
	mov r3, #0
	strb r3, [r2]
	
	bx lr

/**
Setzt direction auf 1 (abwärts)
**/
.thumb_func
setDirectionDown:
	ldr r2, =direction
	ldrb r3, [r2]
	
	mov r3, #1
	strb r3, [r2]
	
	bx lr

/**
Setzt running auf 1 (Timer läuft) wenn Wert bisher 0 (Timer gestoppt) war und umgekehrt
**/
.thumb_func
startStop:
	PUSH {LR}
	ldr r2, =running
	ldrb r3, [r2]
	
	cmp r3, #1
	ite eq
	moveq r3, #0
	movne r3, #1
	
	strb r3, [r2]
	POP {PC}

/*
UP für SW2 ISR
*/
.global button_isr
.thumb_func
button_isr:
	/*
	Delay von 5ms für Debounce
	*/
	ldr r1, =#DEBOUNCE_DELAY_START_VALUEE
	ldr r4, =GPIOE_PDIR
loop_delay_isr:
	nop
	subs r1, r1, #1
	bpl loop_delay_isr
	
	/*
	Prüfen ob GPIOE_PDIR an der Stelle von SW2 (Bit 27) passt -> Button immernoch gedrückt
	*/
	ldr r0, [r4]
	bic r0, r0, #GPIOE_PDIR_SW2_MASK
	cmp r0, #0x0
	bne button_isr_end

	/*
	Setze mod auf 2
	*/
	ldr r0, =mod
	mov r1, #0x2
	strb r1, [r0]
	
	/*
	Setze interrupt zurück
	*/
	ldr r0, =PORTE_PCR26_ISF_ADR
    mov r1, #1
    str r1, [r0]
    
    /*
    Invertiere aktuelles running
    */
    ldr r2, =running
	ldrb r3, [r2]
	cmp r3, #1
	ite eq
	moveq r3, #0
	movne r3, #1
	
	strb r3, [r2]

button_isr_end:
	bx lr
/**
ISR setzt Benutzer-Flag auf 1 und resettet das Timer Interrupt Flag
**/
.global pit_isr
.thumb_func
pit_isr:
	ldr r0, =isr_flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0]
	bx lr
	

/*** Datenbereich (ab 0x20000000) ***/
.data
text: .asciz "Bla\n"
isr_flag: .byte 0x0
counter: .byte 0x0
mod: .word 0x0
running: .word 0x1
direction: .word 0x0
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/**
40 ns ergeben sich bei Takt von 25 MHz

1 Sekunde / 40 ns = 25000000 Takte

**/
.equ PIT1_START_VALUE, 25000000
.equ OPERATION_VOLTAGE, 3300 //3300 mV

// SIM Module Adressen
__BBREG SIM_SCGC5_PORTA_ADR, 0x40048038, 9
__BBREG SIM_SCGC6_PIT_ADR, 0x4004803C, 23
__BBREG SIM_SCGC3_ADC1_ADR, 0x40048030, 27

// PIT Module Adressen
.equ PIT_LDVAL1, 0x40037110	
.equ PIT_TFLG1, 0x4003711c
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118

// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E280
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BIT_MSK, 1 << 5

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ PIT1_OFFSET, 0x154

__BBREG GPIOA_PDOR_LED_D7, 0x400FF000, 11
__BBREG GPIOA_PDOR_LED_D8, 0x400FF000, 28
__BBREG GPIOA_PDOR_LED_D9, 0x400FF000, 29
__BBREG GPIOA_PDOR_LED_D11, 0x400FF000, 10

__BBREG GPIOA_PDDR_LED_D7, 0x400FF014, 11
__BBREG GPIOA_PDDR_LED_D8, 0x400FF014, 28
__BBREG GPIOA_PDDR_LED_D9, 0x400FF014, 29
__BBREG GPIOA_PDDR_LED_D11, 0x400FF014, 10

.equ GPIOA_PDOR, 0x400FF000
.equ GPIOA_PDOR_VALUE, 0x30000C00

.equ PORTA_PCR11, 0x4004902C // LED D7
.equ PORTA_PCR28, 0x40049070 // LED D8
.equ PORTA_PCR29, 0x40049074 // LED D9
.equ PORTA_PCR10, 0x40049028 // LED D11
.equ PORTA_PCR_LED_VALUE, 0x100

// ADC Adressen
.equ ADC1_SC3, 0x400bb024
.equ ADC1_SC3_VALUE, 0xE // activate continues mode, 16 bit samples and activate hardware average functiion
__BBREG ADC1_SC3_CAL, 0x400bb024, 7

.equ ADC1_CFG1,	0x400bb008
.equ ADC1_CFG1_VALUE_16, 0x6C // setze MODE auf 11 und ADIV 11 (3,125 MHz -> 25 MHz / 8 = 3,125 MHz)
.equ ADC1_CFG1_VALUE_12, 0x64 // setze MODE auf 01 und ADIV 11 (3,125 MHz -> 25 MHz / 8 = 3,125 MHz)
.equ ADC1_CFG1_VALUE_10, 0x68 // setze MODE auf 10 und ADIV 11 (3,125 MHz -> 25 MHz / 8 = 3,125 MHz)
.equ ADC1_CFG1_VALUE_8, 0x60 // setze MODE auf 00 und ADIV 11 (3,125 MHz -> 25 MHz / 8 = 3,125 MHz)


.equ ADC1_SC1A, 0x400bb000
.equ ADC1_SC1A_VALUE_STARTED, 0x14 // setze ADCH auf 10100 (AD20 als Input-Quelle)
.equ ADC1_SC1A_VALUE_STOPPED, 0x1F // setze ADCH auf 11111 (auf Module is disabled)

.equ ADC1_CLP0, 0x400bb04c
.equ ADC1_CLP1, 0x400bb048
.equ ADC1_CLP2, 0x400bb044
.equ ADC1_CLP3, 0x400bb040
.equ ADC1_CLP4, 0x400bb03c
.equ ADC1_CLPS, 0x400bb038
.equ ADC1_PG, 0x400bb02c

.equ ADC1_CLM0, 0x400bb06c
.equ ADC1_CLM1, 0x400bb068
.equ ADC1_CLM2, 0x400bb064
.equ ADC1_CLM3, 0x400bb060
.equ ADC1_CLM4, 0x400bb05c
.equ ADC1_CLMS, 0x400bb058
.equ ADC1_MG, 0x400bb030

.equ ADC1_RA, 0x400bb010

.equ LINE_FEED, 0x0A
.equ CHAR_MINUS, 0x2D
.equ CHAR_OPENING_BRACKET, 0x28
.equ CHAR_CLOSING_BRACKET, 0x29
.equ CHAR_SPACE, 0x20
.equ CHAR_S, 0x73
.equ CHAR_0, 0x30
.equ CHAR_1, 0x31
.equ CHAR_2, 0x32
.equ CHAR_3, 0x33

.equ FIRST_BIT, 0x1
.equ SECOND_BIT, 0x2
.equ THIRD_BIT, 0x4
.equ FOURTH_BIT, 0x8
.equ CLEAR_FIRST_HALFWORD, 0xF000
.equ MSB_16_BIT, 0x8000
.equ POTENCE_BASE, 0x2
.equ RESOLUTION_16_BIT, 16
.equ RESOLUTION_12_BIT, 12
.equ RESOLUTION_10_BIT, 10
.equ RESOLUTION_8_BIT, 8 


main:	
	bl uart_init

	/*
	 Aktiviere Port A Clock Gate Control
	*/
	ldr r0, =SIM_SCGC5_PORTA_ADR
    mov r1, #1
    str r1, [r0]
    
    /*
	 Aktiviere PIT Clock Gate Control
	*/
	ldr r0, =SIM_SCGC6_PIT_ADR
    str r1, [r0]
    
    /*
     Aktiviere ADC1 Clock Gate Control
    */
    ldr r0, =SIM_SCGC3_ADC1_ADR
    str r1, [r0]
    
    // Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
    
    // Addiere Offset für PIT1 (0x154) auf die Adresse der IVT und speichere die ISR an diese Stelle
    ldr r0, =pit_isr
    str r0, [r1, #PIT1_OFFSET]
    
    // Aktiviere Clock for PIT Timers
    ldr r0, =PIT_MCR
    mov r1, #0
    str r1, [r0]	
    
    // Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =PIT1_START_VALUE
    str r1, [r0]
    
    // Aktiviere Interrupt für PIT1
    ldr r0, =NVIC_ISER2
    ldr r1, =NVIC_BIT_MSK
    str r1, [r0]
    
    // Lösche Pending Interrupts für PIT1
    ldr r0, =NVIC_ICPR2
    ldr r1, =NVIC_BIT_MSK
    str r1, [r0]
    
    /*
    Setze LED D7 auf Output
    */
    ldr r0, =GPIOA_PDDR_LED_D7
    mov r1, #1
    str r1, [r0]
    
    /*
    Setze LED D8 auf Output
    */
    ldr r0, =GPIOA_PDDR_LED_D8
    str r1, [r0]
    
    /*
    Setze LED D9 auf Output
    */
    ldr r0, =GPIOA_PDDR_LED_D9
    str r1, [r0]
    
    /*
    Setze LED D11 auf Output
    */
    ldr r0, =GPIOA_PDDR_LED_D11
    str r1, [r0]
    
    /*
    Setze GPIO von LED D7 aktiv
    */
    ldr r0, =PORTA_PCR11
    ldr r1, =PORTA_PCR_LED_VALUE
    str r1, [r0]
    
    /*
    Setze GPIO von LED D8 aktiv
    */
    ldr r0, =PORTA_PCR28
    str r1, [r0]
    
    /*
    Setze GPIO von LED D9 aktiv
    */
    ldr r0, =PORTA_PCR29
    str r1, [r0]
    
    /*
    Setze GPIO von LED D11 aktiv
    */
    ldr r0, =PORTA_PCR10
    str r1, [r0]
    
    /*
    Schalte LEDs aus (Default ist an)
    */
    ldr r0, =GPIOA_PDOR
    ldr r1, =GPIOA_PDOR_VALUE
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #3
    str r1, [r0]
    
     // Activate Conversion Enable
    ldr r0, =ADC1_SC3
    ldr r1, =ADC1_SC3_VALUE
    str r1, [r0]
    
    // Aktiviere 16-Bit Auflösung
    ldr r0, =ADC1_CFG1
    ldr r1, =ADC1_CFG1_VALUE_16
    str r1, [r0]
    
    bl calibrate_adc   
     
    //  Starte ADC
    ldr r0, =ADC1_SC1A
    ldr r1, =ADC1_SC1A_VALUE_STARTED
    str r1, [r0]
    
    // Standardgenauigkeit ist 16 Bit
	mov r8, #RESOLUTION_16_BIT

loop_program:
	// werte Benutzer-Flag des Interrupts für PIT1 aus -> wenn nicht gesetzt loope
	ldr r7, =isr_flag
	ldrb r6, [r7]
	cmp r6, #0
	beq loop_program   
	
	// setze Benutzer-Flag zurück
	mov r6, #0
	strb r6, [r7]
	
	// prüfe auf vorhandene Nutzereingabe
	bl uart_charPresent
	cmp r0, #0
	beq endCheckSendedCharacter
	
	bl uart_getChar
	mov r4, r0
	ldr r1, =ADC1_CFG1
	
	// wenn s gesendet
	cmp r4, #CHAR_S
	bne skipStartTop
	
	// prüfe aktuellen Status von running und setze Gegenteil für running und stoppe ADC via ADC1_SC1A
	ldr r2, =running
	ldrb r5, [r2]
	cmp r5, #0
	ittee eq
	moveq r3, #1
	ldreq r6, =ADC1_SC1A_VALUE_STARTED
	movne r3, #0
	ldrne r6, =ADC1_SC1A_VALUE_STOPPED
	
	cmp r5, #0
	ite eq
	ldreq r0, =str_start
	ldrne r0, =str_stop
	
	strb r3, [r2]
	ldr r2, =ADC1_SC1A
    str r6, [r2]
    
    bl uart_putString
	
skipStartTop:
	// wenn 0 gesendet
	cmp r4, #CHAR_0
	bne skipResolution8

	// setze 8 Bit Auflösung
	mov r8, #RESOLUTION_8_BIT
	ldr r2, =ADC1_CFG1_VALUE_8
	str r2, [r1]
	
	// setze ADC1_SC1A je nach dem ob ADC läuft oder nicht
	ldr r2, =running
	ldrb r3, [r2]
	cmp r3, #1
	ite eq
	ldreq r3, =ADC1_SC1A_VALUE_STARTED
	ldrne r3, =ADC1_SC1A_VALUE_STOPPED
	ldr r2, =ADC1_SC1A
    str r3, [r2]
	
	ldr r0, =str_8bit
	bl uart_putString
	
skipResolution8:
	// wenn 1 gesendet
	cmp r4, #CHAR_1
	bne skipResolution10

	// setze 10 Bit Auflösung
	mov r8, #RESOLUTION_10_BIT
	ldr r2, =ADC1_CFG1_VALUE_10
	str r2, [r1]
	
	// setze ADC1_SC1A je nach dem ob ADC läuft oder nicht
	ldr r2, =running
	ldrb r3, [r2]
	cmp r3, #1
	ite eq
	ldreq r3, =ADC1_SC1A_VALUE_STARTED
	ldrne r3, =ADC1_SC1A_VALUE_STOPPED
	ldr r2, =ADC1_SC1A
    str r3, [r2]
    
    ldr r0, =str_10bit
	bl uart_putString

skipResolution10:
	// wenn 2 gesendet
	cmp r4, #CHAR_2
	bne skipResolution12
	
	// setze 12 Bit Auflösung
	mov r8, #RESOLUTION_12_BIT
	ldr r2, =ADC1_CFG1_VALUE_12
	str r2, [r1]
	
	// setze ADC1_SC1A je nach dem ob ADC läuft oder nicht
	ldr r2, =running
	ldrb r3, [r2]
	cmp r3, #1
	ite eq
	ldreq r3, =ADC1_SC1A_VALUE_STARTED
	ldrne r3, =ADC1_SC1A_VALUE_STOPPED
	ldr r2, =ADC1_SC1A
    str r3, [r2]
    
    ldr r0, =str_12bit
	bl uart_putString	
skipResolution12:	
	// wenn 3 gesendet
	cmp r4, #CHAR_3
	bne endCheckSendedCharacter
	
	// setze 16 Bit Auflösung
	mov r8, #RESOLUTION_16_BIT
	ldr r2, =ADC1_CFG1_VALUE_16
	str r2, [r1]
	
	// setze ADC1_SC1A je nach dem ob ADC läuft oder nicht
	ldr r2, =running
	ldrb r3, [r2]
	cmp r3, #1
	ite eq
	ldreq r3, =ADC1_SC1A_VALUE_STARTED
	ldrne r3, =ADC1_SC1A_VALUE_STOPPED
	ldr r2, =ADC1_SC1A
    str r3, [r2]
    
    ldr r0, =str_16bit
	bl uart_putString
	
endCheckSendedCharacter:	
	// werte Running-Status aus
	ldr r0, =running
	ldrb r1, [r0]
	cmp r1, #0
	beq loop_program  


	ldr r0, =str_hex
	bl uart_putString
	
	// gebe aktuellen ADC Wert aus
	ldr r1, =ADC1_RA
	ldr r4, [r1]
	mov r0, r4
	bl uart_putInt16
	
	ldr r0, =CHAR_SPACE
	bl uart_putChar
	
	/**
	Berechnung der aktuellen Stufe:
	
	Messwert / 2^Genauigkeit * Genauigkeit
	
	
	*/
	sub r1, r8, #1 // Counter
	mov r2, #POTENCE_BASE
	mov r0, #POTENCE_BASE
	// Loope für 2^x (x-1) mal
loop_potence:
	mul r0, r0, r2
	sub r1, r1, #1
	cmp r1, #0
	bgt loop_potence
	
	mul r4, r4, r8
	sdiv r4, r4, r0
	
	/*
	Setze LEDs für das jeweilige Bit aus der aktuellen Stufe
	*/
	ldr r1, =GPIOA_PDOR_LED_D7
	ands r0, r4, #FIRST_BIT // lösche alle Bits außer an der Stelle 2⁰
	ite ne
	movne r2, #0
	moveq r2, #1
	str r2, [r1]
	
	ldr r1, =GPIOA_PDOR_LED_D8
	ands r0, r4, #SECOND_BIT // lösche alle Bits außer an der Stelle 2¹
	ite ne
	movne r2, #0
	moveq r2, #1
	str r2, [r1]
	
	ldr r1, =GPIOA_PDOR_LED_D9
	ands r0, r4, #THIRD_BIT // lösche alle Bits außer an der Stelle 2²
	ite ne
	movne r2, #0
	moveq r2, #1
	str r2, [r1]
	
	ldr r1, =GPIOA_PDOR_LED_D11
	ands r0, r4, #FOURTH_BIT // lösche alle Bits außer an der Stelle 2³
	ite ne
	movne r2, #0
	moveq r2, #1
	str r2, [r1]
	
	/*
	Berechnung Untere Grenze:
	
	3300 mV / Genauigkeit * Stufe (0-15 bei 16 Bit usw.)
	*/
	ldr r5, =OPERATION_VOLTAGE
	mul r6, r5, r4
	sdiv r6, r6, r8
	
	mov r0, r6
	mov r1, #CLEAR_FIRST_HALFWORD 
	bic r0, r0, r1 // ignoriere das erste halbe Wort (setze Bits auf 0 -> Leading Zeros)
	bl uart_putInt16
	
	ldr r0, =CHAR_SPACE
	bl uart_putChar
	
	ldr r0, =CHAR_MINUS
	bl uart_putChar
	
	ldr r0, =CHAR_SPACE
	bl uart_putChar
	
	/*
	Berechnung Obere Grenze:
	
	3300 mv / Genauigkeit * (Stufe + 1)
	*/
	add r0, r4, #1 // aktuelle Stufe +1
	mul r6, r5, r0
	sdiv r6, r6, r8
	
	mov r0, r6
	mov r1, #CLEAR_FIRST_HALFWORD 
	bic r0, r0, r1 // ignoriere das erste halbe Wort (setze Bits auf 0 -> Leading Zeros)
	bl uart_putInt16
	
	ldr r0, =CHAR_SPACE
	bl uart_putChar
	
	ldr r0, =str_mv
	bl uart_putString
	
		
	ldr r0, =CHAR_OPENING_BRACKET
	bl uart_putChar
	
	ldr r0, =str_level
	bl uart_putString
	
	// Ausgabe der aktuellen Stufe
	mov r0, r4
	bl uart_putByteBase10
	
	ldr r0, =CHAR_CLOSING_BRACKET
	bl uart_putChar
	
	mov r0, #LINE_FEED
	bl uart_putChar
	
	b loop_program
	
.thumb_func
calibrate_adc:
	// ADC Kalibrierung starten
    ldr r0, =ADC1_SC3_CAL
    mov r1, #1
    str r1, [r0]
	
	// warten bis Kalibrierung abgeschlossen (CAL wieder auf 0)
loop_cal:	
	ldr r1, [r0]
	cmp r1, #0
	bne loop_cal
	
	/*
	Kalibrierungsregister der Plus-Seite summieren
	*/
	mov r1, #0
	
	ldr r2, =ADC1_CLP0
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLP1
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLP2
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLP3
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLP4
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLPS
	ldr r3, [r2]
	add r1, r1, r3
	
	// Ergebnis durch zwei teilen
	lsr r1, r1, #1
	
	// MSB setzen
	add r1, r1, #MSB_16_BIT
	
	// Ergebnis in Ergebnisregister der Plusseitigen Kalibrierung schreiben
	ldr r2, =ADC1_PG
	str r1, [r2]
	
	/*
	Kalibrierungsregister der Minus-Seite summieren
	*/
	mov r1, #0
	
	ldr r2, =ADC1_CLM0
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLM1
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLM2
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLM3
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLM4
	ldr r3, [r2]
	add r1, r1, r3
	
	ldr r2, =ADC1_CLMS
	ldr r3, [r2]
	add r1, r1, r3
	
	// Ergebnis durch zwei teilen
	lsr r1, r1, #1
	
	// MSB setzen
	add r1, r1, #MSB_16_BIT
	
	// Ergebnis in Ergebnisregister der Minusseitigen Kalibrierung schreiben
	ldr r2, =ADC1_MG
	str r1, [r2]
	
	bx lr
	
/**
ISR setzt Benutzer-Flag auf 1 und resettet das Timer Interrupt Flag
**/
.thumb_func
pit_isr:
	ldr r0, =isr_flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
isr_flag: .byte 0x0
running: .byte 0x1
str_level: .asciz "Stufe "
str_mv: .asciz "mV "
str_hex: .asciz "0x"
str_start: .asciz "Start\n"
str_stop: .asciz "Stop\n"
str_16bit: .asciz "16-Bit Aufloesung\n"
str_12bit: .asciz "12-Bit Aufloesung\n"
str_10bit: .asciz "10-Bit Aufloesung\n"
str_8bit: .asciz "8-Bit Aufloesung\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert

/**
40 ns ergeben sich bei Takt von 25 MHz

1 Sekunde / 40 ns = 25000000 Takte
**/
.equ PIT1_START_VALUE, 25000000

/**
Für 2 Mikrosekunden Delay:
(50 Takte - 4 Takte) / 4 Takte 
(Startwert - Initialisierung) / Schleifendauer

**/
.equ START_VALUE_DELAY, 0xC
.equ IICIF_COUNTER, 0x64

__BBREG SIM_PORTD, 0x40048038, 12
__BBREG SIM_ISC0, 0x40048034, 6
__BBREG SIM_SCGC6_PIT, 0x4004803C, 23

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ PIT1_OFFSET, 0x154

// PIT Module Adressen
.equ PIT_LDVAL1, 0x40037110	
.equ PIT_TFLG1, 0x4003711c
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118

// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E280
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BIT_MSK, 1 << 5

__BBREG I2C0_C1_MST, 0x40066002, 5
__BBREG I2C0_C1_TX, 0x40066002, 4
__BBREG I2C0_C1_RSTA, 0x40066002, 2
__BBREG I2C0_S_IICIF, 0x40066003, 1
__BBREG I2C0_S_ARBL, 0x40066003, 4
__BBREG I2C0_C1_TXAK, 0x40066002, 3

.equ PD8_9, 0x300 // Maske fuer PD8 und PD9
.equ PD8, 0x100 // Maske fuer PD8
.equ ALT_GPIO, 0x100 // Alternative 1: GPIO
.equ ALT_I2C0, 0x220 // Alternative 2: I2C0
.equ PORTD_PCR8, 0x4004c020
.equ PORTD_PCR9, 0x4004c024
.equ GPIOD_PDDR, 0x400ff0d4
.equ GPIOD_PDOR, 0x400ff0c0
.equ GPIOD_PDIR, 0x400ff0d0
.equ I2C0_C2, 0x40066005
.equ I2C0_C1, 0x40066002
.equ I2C0_F, 0x40066001
.equ I2C0_D, 0x40066004

.equ I2C0_C2_VALUE, 0x0
.equ I2C0_C1_VALUE, 0xD0 // IICEN, IICIE & TX auf 1
.equ I2C0_F_VALUE, 0x12 // 400kHz maximale Frequenz des Thermometers
.equ DS75_WRITE, 0x90
.equ DS75_READ, 0x91
.equ DS75_CONFIGURATION, 0x60 // Resolution auf 12-Bit & Operation Mode auf Komparator (Rest auf Standard = 0)
.equ DS75_POINTER_CONFIGURATION, 0x1
.equ DS75_POINTER_TEMPERATURE, 0x0
.equ DS75_POINTER_TOS, 0x3
.equ DS75_POINTER_THYST, 0x2
.equ THYST_OFFSET, 0x2
.equ TOS_OFFSET, 0x3


.equ CHAR_UNDERSCORE, 0x5F
.equ CHAR_COMMA, 0x2C
.equ CHAR_0, 0x30
.equ LOWER_100, 0x64
.equ RESET_COUNTER, 0xa
.equ SHIFT_MSB, 0x8
.equ MASK_LSB, 0xFF
.equ MASK_MSB, 0xFF00

.equ ERROR_CODE, 0xFFFFFF

.syntax unified


main:	
	bl uart_init
	bl I2CBus_Reset
	
	// Prüfe auf Fehler in I2CBus_Reset
	mov r1, #ERROR_CODE
	cmp r0, r1
	bne skip_error
	
	ldr r0, =str_error
	bl uart_putString
	
	b error

skip_error:
	ldr r0 , =SIM_ISC0 // Den Takt fuer Port D aktivieren
	mov r1 , #1
	str r1 , [r0]
	
	/*
	 Aktiviere PIT Clock Gate Control
	*/
	ldr r0, =SIM_SCGC6_PIT
    str r1, [r0]
    
    // Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
	
	// Addiere Offset für PIT1 (0x154) auf die Adresse der IVT und speichere die ISR an diese Stelle
    ldr r0, =pit_isr
    str r0, [r1, #PIT1_OFFSET]
    
    // Aktiviere Clock for PIT Timers
    ldr r0, =PIT_MCR
    mov r1, #0
    str r1, [r0]	
    
    // Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =PIT1_START_VALUE
    str r1, [r0]
    
    // Aktiviere Interrupt für PIT1
    ldr r0, =NVIC_ISER2
    mov r1, #NVIC_BIT_MSK
    str r1, [r0]
    
    // Lösche Pending Interrupts für PIT1
    ldr r0, =NVIC_ICPR2
    str r1, [r0]
	
	// Setze Frequenz (400 kHz) des I2C-Busses
	ldr r0, =I2C0_F
	mov r1, #I2C0_F_VALUE
	strb r1, [r0]

	// Konfigure Config Register 2
	ldr r0, =I2C0_C2
	mov r1, #I2C0_C2_VALUE
	strb r1, [r0]
	
	// Konfigure Config Register 1
	ldr r0, =I2C0_C1
	mov r1, #I2C0_C1_VALUE
	strb r1, [r0]
	
	// Sende Start
	bl start
	
	// Sende Schreibmodus (0x90)
	ldr r4, =I2C0_D
	mov r1, #DS75_WRITE
	strb r1, [r4]
	
	bl check_iicif
	
	// Sende Zugriff auf Konfigurationsregister
	mov r1, #DS75_POINTER_CONFIGURATION // Zeige auf Konfigurationsregister
	strb r1, [r4]
	
	bl check_iicif
	
	// Sende Konfiguration
	mov r1, #DS75_CONFIGURATION
	strb r1, [r4]
	
	bl check_iicif
	
	// Sende Stopp-Bedingung
	bl stop
	
	// Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #3
    str r1, [r0]
    
    // Initialisiere Run-only-once Variable
    mov r9, #0x1 // Variable um zu erkennen, ob bereits gelesen wurde
	
program:	
	// werte Benutzer-Flag des Interrupts für PIT1 aus -> wenn nicht gesetzt loope
	ldr r4, =isr_flag
	ldrb r5, [r4]
	cmp r5, #0
	beq program
	
	// setze Benutzer-Flag zurück
	mov r5, #0
	strb r5, [r4]

	// lese Temperaturwert
	bl read
	
	// Trenne r0 in LSB und MSB
	and r4, r0, #MASK_LSB // LSB
	and r5, r0, #MASK_MSB 
	lsr r5, r5, #SHIFT_MSB // MSB
	
	ldr r0, =hex
	bl uart_putString
	
	
	// gebe MSB hexadezimal aus
	mov r0, r5
	bl uart_putInt16
	
	ldr r0, =CHAR_UNDERSCORE
	bl uart_putChar
	
	// gebe LSB hexadezimal aus
	mov r0, r4
	bl uart_putInt16
	
	ldr r0, =dot
	bl uart_putString
	
	// gebe MSB dezimal aus
	mov r0, r5
	bl uart_putByteBase10
	
	ldr r0, =CHAR_COMMA
	bl uart_putChar
	
	// wenn LSB < 100 -> führende null
	cmp r4, #LOWER_100
	bgt skip_leading_zero
	
	ldr r0, =CHAR_0
	bl uart_putChar
	
skip_leading_zero:	
	// gebe LSB dezimal aus
	mov r0, r4
	bl uart_putByteBase10
	
	ldr r0, =celsius
	bl uart_putString
	
	// schreibe nur beim ersten Lesen THYST und TOS
	cmp r9, #0x1
	bne skip_tos_thyst
	
	/* Schreibe in THYST */
	add r6, r5, #THYST_OFFSET // Addiere Offset auf MSB
	bl start
	
	ldr r8, =I2C0_D
	mov r1, #DS75_WRITE
	strb r1, [r8]
	
	bl check_iicif
	
	mov r1, #DS75_POINTER_THYST
	strb r1, [r8]
	
	bl check_iicif
	
	// Sende MSB
	strb r6, [r8]

	bl check_iicif
	
	// Sende LSB
	strb r4, [r8]
	
	bl check_iicif
	
	bl stop
	
	/* Schreibe in TOS */
	add r6, r5, #TOS_OFFSET // Addiere Offset auf MSB
	bl start
	
	mov r1, #DS75_WRITE
	strb r1, [r8]
	
	bl check_iicif
	
	mov r1, #DS75_POINTER_TOS
	strb r1, [r8]
	
	bl check_iicif
	
	// Sende MSB
	strb r6, [r8]
	
	bl check_iicif
	
	// Sende LSB
	strb r4, [r8]
	
	bl check_iicif
	
	bl stop
	
	// Setze First Read auf 0
	mov r9, 0x0
	
skip_tos_thyst:
	b program
	
error:
	b error
	
/*
UP um Start auszuführen (TX auf 1; TXAK auf 0 und MST auf 1)
*/
.thumb_func
start:
	PUSH {LR}
	
	ldr r0, =I2C0_C1_TX
	mov r1, #0x1
	strb r1, [r0]
	
	ldr r0, =I2C0_C1_TXAK
	mov r1, #0x0
	strb r1, [r0]
	
	ldr r0, =I2C0_C1_MST
	mov r1, #0x1
	strb r1, [r0]
	
	pop { pc }
	
.thumb_func
stop:
	PUSH {LR}
	
	// Sende Stopp-Bedingung und führe danach Delay aus für Ruhezeit
	ldr r0, =I2C0_C1_MST
	mov r1, #0x0
	strb r1, [r0]
	
	bl i2c_Delay
	
	pop { pc }

.thumb_func
restart:
	PUSH {LR}

	// Sende Repeated Start
	ldr r0, =I2C0_C1_RSTA
	mov r1, #0x1
	strb r1, [r0]
	
	pop { pc }

/*
UP zur Überprüfung eines gesetzten IICIF-Flags 
*/
.thumb_func
check_iicif:
	PUSH {LR}
	mov r2, #IICIF_COUNTER
iicif_loop:
	ldr r0, =I2C0_S_IICIF
	ldrb r1, [r0]
	cmp r1, #0 // prüfe ob IICIIF 0 ist, wenn ja loope
	bne skip_iicif_loop
	
	subs r2, r2, #1
	bpl iicif_loop
	
	// Ausführung wenn Loop mehr als 100 mal nicht erfolgreich war -> IICIF ist nie gesetzt worden -> Fehlerausgabe und Programm abbrechen
	ldr r0, =str_error
	bl uart_putString
iicif_error:
	b iicif_error
	
skip_iicif_loop:
	// IICIF zurücksetzen
	mov r1, #1
	strb r1, [r0]

	pop { pc }

/*
UP für Delayloop von 2 Mikrosekunden -> benötigte Entspannungszeit
*/
.thumb_func
i2c_Delay:
	push { lr }
	ldr r1, =#START_VALUE_DELAY
loop_delay:
	nop
	subs r1, r1, #1
	bpl loop_delay
	pop { pc }

.thumb_func
I2CBus_Reset:
	push { r4, lr }

	ldr r0 , =SIM_PORTD // Den Takt fuer Port D aktivieren
	mov r1 , #1
	str r1 , [ r0 ]
	ldr r0 , =PORTD_PCR8 // Portleitungen PD8 , PD9 als GPIO
	ldr r1 , =PORTD_PCR9
	mov r2 , #ALT_GPIO
	str r2 , [ r0 ]
	str r2 , [ r1 ]
	ldr r0 , =GPIOD_PDDR // PD8 , PD9 als Ausgang schalten
	ldr r2 , [ r0 ]
	orr r2 , r2 , #PD8_9
	str r2 , [ r0 ]
	
	mov r4, #RESET_COUNTER
loop:
	// nach 10 Loops setze Fehlercode und verlasse das UP
	subs r4, r4, #1
	itt mi
	movmi r0, #ERROR_CODE
	bmi skip_loop
	
	ldr r0 , =GPIOD_PDOR // SCL deaktivieren
	ldr r2 , [ r0 ]
	bic r2 , r2 , #PD8 // entsprechendes Bit loeschen
	str r2 , [ r0 ]
	bl i2c_Delay
	
	ldr r0 , =GPIOD_PDOR // SCL und SDA aktivieren
	ldr r2 , [ r0 ]
	orr r2 , r2 , #PD8_9
	str r2 , [ r0 ]
	bl i2c_Delay

	ldr r0 , =GPIOD_PDIR
	ldr r2 , [ r0 ]
	and r2 , r2 , #PD8_9 // nur Bits 9 und 10 pruefen
	cmp r2 , #PD8_9 // Bit 9 und Bit 10 gesetzt ?
	bne loop // ggf . wiederholen
	
	// Setze Portleitungen schlussendlich für I2C auf Alternative 2
	ldr r0 , =PORTD_PCR8 // Portleitungen PD8 , PD9 als I2C
	ldr r1 , =PORTD_PCR9
	mov r2 , #ALT_I2C0
	str r2 , [ r0 ]
	str r2 , [ r1 ]

skip_loop:
	pop { r4, pc }

.thumb_func
read:
	push { r4-r6, lr }
	// Sende Start-Bedingung
	bl start
	
	// Schreibe Adresse (0x90) für Schreiben
	ldr r4, =I2C0_D
	mov r1, #DS75_WRITE
	strb r1, [r4]
	
	bl check_iicif
	
	// Schreibe Pointer (0x0) für Temperatur
	mov r1, #DS75_POINTER_TEMPERATURE
	strb r1, [r4]
	
	bl check_iicif
	
	// Sende Repeated Start
	bl restart
	
	// Schreibe Adresse (0x91) für Lesen
	mov r1, #DS75_READ
	strb r1, [r4]
	
	bl check_iicif
	
	// Setze Schreiben auf I2C-Bus auf 0 -> Lesen
	ldr r0, =I2C0_C1_TX
	mov r1, #0x0
	strb r1, [r0]
	
	// Führe Dummy Read aus (Ergebnis nicht benötigt)
	ldrb r0, [r4]
	
	bl check_iicif
	
	// Lese erstes Bit (Most significant bit)
	ldrb r5, [r4]
	
	// Setze Senden des Acknowledgments auf 1
	ldr r0, =I2C0_C1_TXAK
	mov r1, #0x1
	strb r1, [r0]
	
	bl check_iicif
	
	// Lese zweites Bit (Least significant bit)
	ldrb r6, [r4]
	bl check_iicif
	
	// Sende Sotpp-Bedingung
	bl stop
	
	// Fasse MSB und LSB in einem Ergebnis (r0) zusammen, da weniger als 32 Bit
	mov r0, r5
	lsl r0, r0, #SHIFT_MSB
	orr r0, r0, r6
	
	pop { r4-r6, pc }

/**
ISR setzt Benutzer-Flag auf 1 und resettet das Timer Interrupt Flag
**/
.thumb_func
pit_isr:
	ldr r0, =isr_flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =PIT_TFLG1
	str r1, [r0]
	bx lr

/*** Datenbereich (ab 0x20000000) ***/
.data
isr_flag: .byte 0x0
hex: .asciz "0x"
dot: .asciz ": "
celsius: .asciz " Grad Celsius\n"
str_error: .asciz "Es ist ein Fehler aufgetreten. Das Programm wird abgebrochen.\n"

// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

/**
Für 2 Mikrosekunden Delay:
(50 Takte - 4 Takte) / 4 Takte 
(Startwert - Initialisierung) / Schleifendauer

**/
.equ START_VALUE_DELAY, 0xC

__BBREG SIM_SCGC5_PORTD, 0x40048038, 12
__BBREG SIM_SCGC3_SPI2, 0x40048030, 12
__BBREG SIM_SCGC6_PIT_ADR, 0x4004803C, 23
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG SIM_SCGC5_PORTE, 0x40048038, 13

__BBREG SPI2_MCR_DIS_TXF, 0x400ac000, 13
__BBREG SPI2_MCR_DIS_RXF, 0x400ac000, 12
__BBREG SPI2_MCR_FRZ, 0x400ac000, 27
__BBREG SPI2_MCR_HALT, 0x400ac000, 0
__BBREG SPI2_SR_EOQF, 0x400AC02C, 28
__BBREG SPI2_SR_TCF, 0x400AC02C, 31

__BBREG PDDR_SW1, 0x400FF014, 19
__BBREG PDDR_SW2, 0x400FF114, 26

.equ GPIOD_PDDR, 0x400ff0d4
.equ GPIOD_PDOR, 0x400ff0c0

.equ SPI2_MCR, 0x400ac000
.equ SPI2_MCR_VALUE, 0x80000001 // MSTR und HALT auf 1
.equ SPI2_CTAR0, 0x400ac00c
.equ SPI2_CTAR0_VALUE, (0xf << 27) | (1 << 25) | (0x7) // 16 Bit Frame Size, Clock Phase = 1, Baud Rate Scaler = 128 -> ca. 100 kHz
.equ SPI2_RSER, 0x400ac030
.equ SPI2_POPR, 0x400AC038
.equ SPI2_PUSHR, 0x400AC034

.equ PORTD_PCR12, 0x4004c030
.equ PORTD_PCR13, 0x4004c034
.equ PORTD_PCR14, 0x4004c038
.equ PORTD_PCR15, 0x4004c03C
.equ PORTE_PCR26, 0x4004d068
.equ PORTA_PCR19, 0x4004904C

__BBREG	SW2_CIF, PORTE_PCR26, 24
__BBREG	SW1_CIF, PORTA_PCR19, 24

.equ ALT_GPIO, 0x100 // Alternative 1: GPIO
.equ ALT_SPI, 0x200 // Alternative 2: SPI2
.equ PD12_13_14_15, 0xF000 // Maske fuer PD12, PD13, PD14 und PD15

.equ ERROR_CODE, 0xFFFFFF
.equ RESET_COUNTER, 0xa

.equ CHAR_COMMA, 0x2c

// PIT Module Adressen
.equ PIT_LDVAL1, 0x40037110	
.equ PIT_TFLG1, 0x4003711c
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118

.equ PIT_TCTRL1_VALUE, 0x3

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ PIT1_OFFSET, 0x154 // Offset für IVT PIT1
.equ PORTE_OFFSET, 0x1AC // Offset für IVT Port E
.equ PORTA_OFFSET, 0x19C // Offset für IVT Port A

.equ GPIO_IRQ_PE_SET, 0xA0103	// GPIO-Modus, IRQ (fallende Flanke), Pull-Up-Widerstand

// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E280
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BIT_MSK, (1 << 5) | (1 << 27) | (1 << 23) // Vector-Index für PIT1, PORTE, PORTA

/**
30.000.000 Takte = 1,2 Sekunden
**/
.equ PIT1_START_VALUE_12BIT, 30000000
// 0,6s
.equ PIT1_START_VALUE_11BIT, 15000000
// 0,3s
.equ PIT1_START_VALUE_10BIT, 7500000
// 0,15s
.equ PIT1_START_VALUE_9BIT, 3750000
// 0,075s
.equ PIT1_START_VALUE_8BIT, 1875000

.equ DS1722_WRITE_BASE_ADDRESS, 0x28000
.equ DS1722_READ_MSB_ADDRESS, 0x80020200 // CONT-Bit gesetzt
.equ DS1722_READ_LSB_ADDRESS, 0x20100

.equ LSB_MAX_VALUE_8BIT, 0x0
.equ LSB_MAX_VALUE_9BIT, 0x8
.equ LSB_MAX_VALUE_10BIT, 0xc
.equ LSB_MAX_VALUE_11BIT, 0xe
.equ LSB_MAX_VALUE_12BIT, 0xf

.equ DS1722_CONFIG_8BIT, 0xe0
.equ DS1722_CONFIG_9BIT, 0xe2
.equ DS1722_CONFIG_10BIT, 0xe4
.equ DS1722_CONFIG_11BIT, 0xe6
.equ DS1722_CONFIG_12BIT, 0xe8

.equ RESOLUTION_12BIT, 0x0
.equ RESOLUTION_11BIT, 0x1
.equ RESOLUTION_10BIT, 0x2
.equ RESOLUTION_9BIT, 0x3
.equ RESOLUTION_8BIT, 0x4

.equ LSB_BIT_MSK, 0x00FF
.equ MSB_BIT_MSK, 0xFF00
/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/

main:		
	bl uart_init
	ldr r0 , =SIM_SCGC3_SPI2 // Den Takt fuer SPI2 aktivieren
	mov r1 , #1
	str r1 , [r0]

	// Aktiviere Takt für Port A (SW1)
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]
	
	// Aktiviere Takt für Port E (SW2)
	ldr r0, =SIM_SCGC5_PORTE
	str r1, [r0]

	ldr r1, =GPIO_IRQ_PE_SET 	// GPIO-Modus mit IRQ (fallende Flanke) und Pull-Up-Widerstand 	
	ldr r0, =PORTE_PCR26 		// fuer SW2
	str r1, [r0]				// festlegen
	
	ldr r0, =PORTA_PCR19 		// GPIO-Modus mit IRQ (fallende Flanke) und Pull-Up-Widerstand fuer SW1
	str r1, [r0]				// festlegen
	
	// Datenrichtung der GPIO-Pins festlegen
	// Eingaenge (SW1 und SW2)
	mov r1, #0
	ldr r0, =PDDR_SW1
	str r1, [r0]
	ldr r0, =PDDR_SW2
	str r1, [r0]

	/*
	 Aktiviere PIT Clock Gate Control
	*/
	mov r1 , #1
	ldr r0, =SIM_SCGC6_PIT_ADR
    str r1, [r0]
    
    // Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
    
    // Addiere Offset für PIT1 (0x154) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #PIT1_OFFSET
    ldr r0, =pit_isr
    str r0, [r2]
    
    // Addiere Offset für PORTE auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #PORTE_OFFSET
    ldr r0, =sw2_isr
    str r0, [r2]
    
    // Addiere Offset für PORTA auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #PORTA_OFFSET
    ldr r0, =sw1_isr
    str r0, [r2]
    
    // Aktiviere Clock for PIT Timers
    ldr r0, =PIT_MCR
    mov r1, #0
    str r1, [r0]	
    
    // Lade Startwert (für 12-Bit Wandlung) in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_12BIT
    str r1, [r0]
    
    // Aktiviere Interrupt für PIT1, PORTE & PORTA
    ldr r0, =NVIC_ISER2
    ldr r1, =NVIC_BIT_MSK
    str r1, [r0]
    
    // Lösche Pending Interrupts für PIT1, PORTE & PORTA
    ldr r0, =NVIC_ICPR2
    ldr r1, =NVIC_BIT_MSK
    str r1, [r0]

    // setze SPI-Bus zurück um Fehler zu vermeiden
	bl SPIBus_Reset
	
	// Konfiguriere SPI MCR als Master und in Halt
	ldr r0, =SPI2_MCR
	ldr r1, =SPI2_MCR_VALUE
	str r1, [r0]
	
	// Deaktiviere TX FIFO (nicht direkt möglich, da nur in MDIS=0, aber MDIS=1 ist Reset-Wert
	ldr r0, =SPI2_MCR_DIS_TXF
	mov r1, #1
	strb r1, [r0]
	
	// Deaktiviere RX FIFO (nicht direkt möglich, da nur in MDIS=0, aber MDIS=1 ist Reset-Wert
	ldr r0, =SPI2_MCR_DIS_RXF
	strb r1, [r0]
	
	ldr r0, =SPI2_CTAR0
	ldr r1, =SPI2_CTAR0_VALUE
	str r1, [r0]
	
	ldr r0, =SPI2_RSER
	mov r1, #0
	str r1, [r0]
	
	// Schreibe Default-Konfiguration (12-Bit Wandlung) in DS1722
	mov r0, #DS1722_CONFIG_12BIT
	bl write_config
	
	// Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
	
main_loop:	
	// Werte Button-Flag für verkleinern aus
	ldr r7, =down_button_pressed
    ldrb r6, [r7]
    cmp r6, #1
    bne skip_down_button_pressed // überspringe, wenn nicht gedrückt
    
    // Deaktiviere Timer und Timer Interrupt für PIT1, um diesen je nach Auflösung neu zusetzen
    ldr r0, =PIT_TCTRL1
    mov r1, #0
    str r1, [r0]
    
    // Setze möglichen Interrupt zurück
    ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0]
    
    // setze Down-Button-Pressed-Flag zurück
	mov r6, #0
	strb r6, [r7]

	// lade bisherige Auflösung
    ldr r0, =current_resolution
    ldrb r1, [r0]
    
    // wenn bisher 12-Bit-Auflösung, dann setze 11 Bit Auflösung
    cmp r1, #RESOLUTION_12BIT
    bne skip_down_0
    
    mov r2, #RESOLUTION_11BIT
    strb r2, [r0]
    
    // schreibe Konfiguration für 11-Bit in DS1722
    mov r0, #DS1722_CONFIG_11BIT
	bl write_config
	
	// gebe neue Auflösung auf Terminal aus
	ldr r0, =str_11bit
	bl uart_putString
    
    // speichere maximalen Wert, der vom DS1722 für das LSB kommen darf (größere Fehler sind eventuell Fehler und können beim Speicherzugriff zu Fehlern führen)
    ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_11BIT
	strb r1, [r0]
	
	// Lade Wert in den PIT1 für 11-Bit Auflösung
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_11BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_down_0:

	// wenn 11-Bit bisher, dann 12 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_11BIT
	bne skip_down_1
	
	mov r2, #RESOLUTION_10BIT
	strb r2, [r0]
	
	// write config e4
	mov r0, #DS1722_CONFIG_10BIT
	bl write_config
	
	ldr r0, =str_10bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_10BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_10BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_down_1:    

	// wenn 10-Bit bisher, dann 11 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_10BIT
	bne skip_down_2
	
	mov r2, #RESOLUTION_9BIT
	strb r2, [r0]
	
	// write config e2
	mov r0, #DS1722_CONFIG_9BIT
	bl write_config
	
	ldr r0, =str_9bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_9BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_9BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_down_2:

	// wenn 9-Bit bisher, dann 8 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_9BIT
	bne skip_down_3
	
	mov r2, #RESOLUTION_8BIT
	strb r2, [r0]
	
	// write config e0
	mov r0, #DS1722_CONFIG_8BIT
	bl write_config
	
	ldr r0, =str_8bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_8BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_8BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_down_3:	

	// wenn 8-Bit bisher, dann 12 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_8BIT
	bne skip_down_button_pressed
	
	mov r2, #RESOLUTION_12BIT
	strb r2, [r0]
	
	// write config e8
	mov r0, #DS1722_CONFIG_12BIT
	bl write_config
	
	ldr r0, =str_12bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_12BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_12BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
    
skip_down_button_pressed:

	// prüfen ob vergrößern Button gedrückt
	ldr r7, =up_button_pressed
    ldrb r6, [r7]
    cmp r6, #1
    bne skip_up_button_pressed
    
    // Deaktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #0
    str r1, [r0]
    
    // Setze möglichen Interrupt zurück
    ldr r0, =PIT_TFLG1
	mov r1, #1
	str r1, [r0]
    
    // setze Up-Button-Pressed-Flag zurück
	mov r6, #0
	strb r6, [r7]

	// lade aktuelle Auflösung
    ldr r0, =current_resolution
    ldrb r1, [r0]
    
    // wenn 12-Bit bisher, dann 8 Bit -> Rest analog zu vorher
    cmp r1, #RESOLUTION_12BIT
    bne skip_up_0
    
    mov r2, #RESOLUTION_8BIT
    strb r2, [r0]
    
    // write config e0
    mov r0, #DS1722_CONFIG_8BIT
	bl write_config
	
	ldr r0, =str_8bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_8BIT
	strb r1, [r0]
    
    // Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_8BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_up_0:

	// wenn 11-Bit bisher, dann 12 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_11BIT
	bne skip_up_1
	
	mov r2, #RESOLUTION_12BIT
	strb r2, [r0]
	
	// write config e8
	mov r0, #DS1722_CONFIG_12BIT
	bl write_config
	
	ldr r0, =str_12bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_12BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_12BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_up_1:    

	// wenn 10-Bit bisher, dann 11 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_10BIT
	bne skip_up_2
	
	mov r2, #RESOLUTION_11BIT
	strb r2, [r0]
	
	// write config e6
	mov r0, #DS1722_CONFIG_10BIT
	bl write_config
	
	ldr r0, =str_11bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_11BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_11BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_up_2:

	// wenn 9-Bit bisher, dann 10 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_9BIT
	bne skip_up_3
	
	mov r2, #RESOLUTION_10BIT
	strb r2, [r0]
	
	// write config e4
	mov r0, #DS1722_CONFIG_10BIT
	bl write_config
	
	ldr r0, =str_10bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_10BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_10BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
skip_up_3:	

	// wenn 8-Bit bisher, dann 9 Bit -> Rest analog zu vorher
	cmp r1, #RESOLUTION_8BIT
	bne skip_up_button_pressed
	
	mov r2, #RESOLUTION_9BIT
	strb r2, [r0]
	
	// write config e2
	mov r0, #DS1722_CONFIG_9BIT
	bl write_config
	
	ldr r0, =str_9bit
	bl uart_putString
	
	ldr r0, =current_resolution_max_value
	mov r1, #LSB_MAX_VALUE_9BIT
	strb r1, [r0]
	
	// Lade Startwert in den PIT1
    ldr r0, =PIT_LDVAL1
    ldr r1, =#PIT1_START_VALUE_9BIT
    str r1, [r0]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r0, =PIT_TCTRL1
    mov r1, #PIT_TCTRL1_VALUE
    str r1, [r0]
    
    b main_loop // springe nach erfolgreichem Ändern der Auflösung zur main_loop zurück, um Wandlungszeit einzuhalten (warten auf PIT Interrupt)
    

skip_up_button_pressed:
	// werte Benutzer-Flag des Interrupts für PIT1 aus -> wenn nicht gesetzt loope
	ldr r7, =isr_flag
	ldrb r6, [r7]
	cmp r6, #0
	beq main_loop
	
	// setze PIT-Benutzer-Flag zurück
	mov r6, #0
	strb r6, [r7]

	// rufe Lesen auf
	bl read
	
	and r4, r0, #MSB_BIT_MSK // extrahiere MSB
	lsr r4, r4, #8 // schiebe MSB nach rechts um LSB Nullen loszuwerden
	and r5, r0, #LSB_BIT_MSK // extrahiere LSB
	
	// gebe MSB aus
	mov r0, r4
	bl uart_putByteBase10
	
	// prüfe ob LSB gegen maximalen Wert verstößt, wenn ja loope, um Fehler beim Speicherzugriff zu vermeiden
	ldr r0, =current_resolution_max_value
	ldrb r1, [r0]
	cmp r5, r1
	bgt main_loop
	

	// Mapping von LSB-Value (0b0000 bis 0b1111, je nach Auflösung) auf dezimale Werte
	ldr r1, =current_resolution_array			// Startadresse der Stringtabelle
	ldr r0, [r1, r5, lsl #2]	// Stringadresse mit Index laden 
	bl uart_putString			// und ausgeben
	
	ldr r0, =str_gc
	bl uart_putString
	
	b main_loop
	

.thumb_func
read:
	push {r4-r5, lr}
	bl start // starte SPI-Bus
	
	// schreibe Lese-Adresse von MSB
	ldr r0, =DS1722_READ_MSB_ADDRESS 
	ldr r1, =SPI2_PUSHR
	str r0, [r1]
	
	// warte Transfer Complete ab
	bl wait_tcf
	
	// lade LSB und MSB
	ldr r2, =SPI2_POPR
	ldr r4, [r2] // load LSB (including CFG)
	ldr r5, [r2] // load MSB
	
	//schreibe Lese-Adresse von LSB (danach ist Pointer wieder an richtiger Stelle)
	ldr r0, =DS1722_READ_LSB_ADDRESS
	ldr r1, =SPI2_PUSHR
	str r0, [r1]
	
	// warte Transfer Complete ab
	bl wait_tcf
	
	bl stop // stoppe SPI-Bus
	
	// packe LSB und MSB zusammen
	and r4, r4, #LSB_BIT_MSK
	lsr r4, r4, #4 // schiebe LSB nach rechts um statische Nullen (sh. DS1722 Datenblatt) des LSB loszuwerden
	lsl r5, r5, #8 // schiebe MSB nach links
	orr r0, r4, r5 // verordere MSB und LSB
	
	pop {r4-r5, pc}

/*
Wartet bis TCF-Flag gesetzt ist
*/
.thumb_func
wait_tcf:	
wait_tcf_loop:	
	ldr r1, =SPI2_SR_TCF
	ldr r0, [r1]
	cmp r0, #1
	bne wait_tcf_loop
	
	mov r2, #1
	str r2, [r1]
	
	bx lr
	
/*

Startet SPI-Bus (FRZ, EOQF und HALT auf 0)
*/	
.thumb_func
start:
	mov r1, #0
	ldr r0, =SPI2_MCR_FRZ
	str r1, [r0]
	
	ldr r0, =SPI2_SR_EOQF
	str r1, [r0]
	
	ldr r0, =SPI2_MCR_HALT
	str r1, [r0]
	
	bx lr
	
/*

Stoppt SPI-Bus (FRZ, EOQF und HALT auf 1)
*/		
.thumb_func
stop:	
	mov r1, #1
	ldr r0, =SPI2_SR_EOQF
	str r1, [r0]
	
	ldr r0, =SPI2_MCR_FRZ
	str r1, [r0]
	
	ldr r0, =SPI2_MCR_HALT
	str r1, [r0]
	
	bx lr
	
/*
Schreibt Config in DS1722
*/	
.thumb_func
write_config:
	push { r4, lr }
	
	// Verordere Basis-Adresse mit den Daten (Auflösung)
	mov r4, r0 // sichere Übergabe-Parameter
	bl start
	ldr r1, =DS1722_WRITE_BASE_ADDRESS
	orr r0, r4, r1
	
	ldr r1, =SPI2_PUSHR
	str r0, [r1]
	
	// warte Transfer-Complete ab
	bl wait_tcf
	
	bl stop
	
	pop { r4, pc }
	
/*
UP für Delayloop von 2 Mikrosekunden -> benötigte Entspannungszeit
*/
.thumb_func
spi_Delay:
	ldr r1, =#START_VALUE_DELAY
loop_delay:
	nop
	subs r1, r1, #1
	bpl loop_delay
	bx lr
	

.thumb_func
SPIBus_Reset:
	push { lr }

	ldr r0 , =SIM_SCGC5_PORTD // Den Takt fuer Port D aktivieren
	mov r1 , #1
	str r1 , [ r0 ]
	ldr r0 , =PORTD_PCR12 // Portleitungen PD12, PD13, PD14, PD15 als GPIO
	ldr r1 , =PORTD_PCR13
	ldr r3 , =PORTD_PCR14
	mov r2 , #ALT_GPIO
	str r2 , [ r0 ]
	str r2 , [ r1 ]
	str r2 , [ r3 ]
	ldr r3 , =PORTD_PCR15
	str r2 , [ r3 ]
	ldr r0 , =GPIOD_PDDR // PD12, PD13, PD14, PD15 als Ausgang schalten
	ldr r2 , [ r0 ]
	orr r2 , r2 , #PD12_13_14_15
	str r2 , [ r0 ]
	
	ldr r0 , =GPIOD_PDOR // Ports deaktivieren
	ldr r2 , [ r0 ]
	bic r2 , r2 , #PD12_13_14_15 // entsprechendes Bit loeschen
	str r2 , [ r0 ]
	bl spi_Delay

	ldr r0 , =GPIOD_PDOR // Ports aktivieren
	ldr r2 , [ r0 ]
	orr r2 , r2 , #PD12_13_14_15
	str r2 , [ r0 ]
	bl spi_Delay
	
	// Setze Portleitungen schlussendlich für SPI auf Alternative 2
	ldr r0 , =PORTD_PCR12
	ldr r1 , =PORTD_PCR13
	ldr r3 , =PORTD_PCR14
	mov r2 , #ALT_SPI
	str r2 , [ r0 ]
	str r2 , [ r1 ]
	str r2 , [ r3 ]
	ldr r3 , =PORTD_PCR15
	str r2 , [ r3 ]

skip_loop:
	pop { pc }
	
.thumb_func
pit_isr:
	ldr r0, =isr_flag  // Setze PIT Benutzer-Flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =PIT_TFLG1 // Setze PIT-Interrupt-Flag zurück
	mov r1, #1
	str r1, [r0]
	bx lr
	
	
.thumb_func
# schwarzer Taster
sw1_isr:
	push {lr}
	
	ldr r0, =up_button_pressed	// Setze SW1-Flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =SW1_CIF			// Bit-Band-Adresse des Interrupt-Flags fuer SW1
	mov r1, #1
	str r1, [r0]				// Flag loeschen
	
	pop {pc}
	
.thumb_func
# grüner Taster
sw2_isr:
	push {lr}
	
	ldr r0, =down_button_pressed // Setze SW2-Flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =SW2_CIF			// Bit-Band-Adresse des Interrupt-Flags fuer SW1
	mov r1, #1
	str r1, [r0]				// Flag loeschen
	
	pop {pc}
/*** Datenbereich (ab 0x20000000) ***/
.data
str_8bit: .asciz "8-Bit Aufloesung gesetzt\n"
str_9bit: .asciz "9-Bit Aufloesung gesetzt\n"
str_10bit: .asciz "10-Bit Aufloesung gesetzt\n"
str_11bit: .asciz "11-Bit Aufloesung gesetzt\n"
str_12bit: .asciz "12-Bit Aufloesung gesetzt\n"
str_gc: .asciz " gC\n"
isr_flag: .byte 0x0

up_button_pressed: .byte 0x0
down_button_pressed: .byte 0x0

current_resolution_array: .word str_0, str_1, str_2, str_3, str_4, str_5, str_6, str_7, str_8, str_9, str_a, str_b, str_c, str_d, str_e, str_f

/*
0x0 -> 12-Bit
0x1 -> 11-Bit
0x2 -> 10-Bit
0x3 -> 9-Bit
0x4 -> 8-Bit
*/
current_resolution: .byte 0x0
current_resolution_max_value: .byte 0xf

str_0: .asciz ",0"  //0000
str_1: .asciz ",0625" //0001
str_2: .asciz ",125"  //0010
str_3: .asciz ",1875" // 0011
str_4: .asciz ",25"  //0100
str_5: .asciz ",315" //0101
str_6: .asciz ",375" //0110
str_7: .asciz ",4375" //0111
str_8: .asciz ",5" //1000
str_9: .asciz ",5625" // 1001
str_a: .asciz ",625"  // 1010
str_b: .asciz ",6875" // 1011
str_c: .asciz ",75" // 1100
str_d: .asciz ",8125" // 1101
str_e: .asciz ",875"  // 1110
str_f: .asciz ",9375" // 1111
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

__BBREG SIM_SCG6_RTC, 0x4004803C, 29
.equ RTC_IER, 0x4003D01C 
.equ RTC_IER_VALUE, 0x14 // Alarm and second interrupt enabled
.equ RTC_TAR, 0x4003D008
.equ RTC_TAR_START_VALUE, 0x1517F // 23:59:59
.equ RTC_TAR_MODE_1_VALUE, 0xE0F  // 59:59
.equ RTC_TSR, 0x4003D000
.equ RTC_SR, 0x4003D014
.equ RTC_SR_VALUE, 0x10 // TCE = 1
.equ RTC_CR, 0x4003d010
.equ RTC_CR_VALUE, 0x100 // OSCE = 1
.equ RTC_TCR, 0x4003d00c
.equ RTC_TPR, 0x4003d004

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ RTC_ALARM_OFFSET, 0x148
.equ RTC_SECONDS_OFFSET, 0x14C

// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E280
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BIT_MSK_ALARM, 1 << 2
.equ NVIC_BIT_MSK_SECONDS, 1 << 3

.equ DIV_VALUE_MINUTES, 0x3c // 60 Seconds
.equ DIV_VALUE_HOURS,  0xE10 // 60 Seconds * 60 Minutes

.equ CHAR_0, 0x30
.equ CHAR_COLON, 0x3A
.equ CHAR_LINE_FEED, 0x0A 
.equ CHAR_D, 0x64
.equ CHAR_H, 0x68
.equ CHAR_P, 0x70
.equ CHAR_R, 0x72
.equ CHAR_S, 0x73

.equ PRESET_VALUE_HOUR, 0xE0B // 59:55
.equ PRESET_VALUE_DAY, 0x1517B // 23:59:55

/**
(25.000.000 Takte - 4 Takte) / 4 Takte 
(Startwert - Initialisierung) / Schleifendauer

**/
.equ RTC_DELAY, 0x3B9AC96 // ca. 10 Sekunden

main:	
	bl uart_init
	
	// Aktiviere RTC Clock
	ldr r0, =SIM_SCG6_RTC
	mov r1, #1
	str r1, [r0]
	
	// Setze SR auf 0
	ldr r12, =RTC_SR
	mov r1, #0
	str r1, [r12]
	
	// Setze TCR auf Standard
	ldr r0, =RTC_TCR
	str r1, [r0]
	
	// Setze TPR auf Standard
	ldr r0, =RTC_TPR
	str r1, [r0]
	
	// Setze TSR auf Standard
	ldr r10, =RTC_TSR
	str r1, [r10]
	
	// Aktivierer Oszilator
	ldr r0, =RTC_CR
	mov r1, #RTC_CR_VALUE
	str r1, [r0]
	
	// gebe Anfangsstring aus
	ldr r0, =str_swingin
	bl uart_putString
	
	// rufe Delay auf, damit Oszilator sich einschwingen kann
	bl swing_in_delay
	
	// Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
    
    // Addiere Offset für RTC_ALARM Interrupt (0x148) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #RTC_ALARM_OFFSET
    ldr r0, =alarm_isr
    str r0, [r2]
    
    // Addiere Offset für RTC_SECONDS Interrupt (0x14C) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #RTC_SECONDS_OFFSET
    ldr r0, =seconds_isr
    str r0, [r2]
	
	// setze Alarm Interrupt-Zeit auf 23:59:59
	ldr r11, =RTC_TAR
	ldr r1, =RTC_TAR_START_VALUE
	str r1, [r11]
	
	// aktiviere Alarm und Second-Interrupt
	ldr r0, =RTC_IER
	mov r1, #RTC_IER_VALUE
	str r1, [r0]
	
	// Aktiviere RTC Alarm Interrupt
    ldr r0, =NVIC_ISER2
    mov r1, #NVIC_BIT_MSK_ALARM
    str r1, [r0]
    
    // Lösche Pending Interrupts für RTC Alarm Interrupt
    ldr r0, =NVIC_ICPR2
    mov r1, #NVIC_BIT_MSK_ALARM
    str r1, [r0]
    
    // Aktiviere RTC Alarm Interrupt
    ldr r0, =NVIC_ISER2
    mov r1, #NVIC_BIT_MSK_SECONDS
    str r1, [r0]
    
    // Lösche Pending Interrupts für RTC Alarm Interrupt
    ldr r0, =NVIC_ICPR2
    mov r1, #NVIC_BIT_MSK_SECONDS
    str r1, [r0]

    // aktiviere Time Counter
    mov r1, #RTC_SR_VALUE
    str r1, [r12]
    
    mov r4, #0 // seconds
    mov r5, #0 // minutes
    mov r6, #0 // hours
    
    mov r7, #1 // running auf Läuft
    ldr r8, =mode
  
  /**
  r7 Running: Läuft (1) / Steht (0)
  r8 Modus: 24 Stunden (1) / 1 STunde (0) 
  */
loop:   
	// prüfe ob Zeichen gesendet, wenn nicht überspringe
	bl uart_charPresent
	cmp r0, #0
	beq endCheckSendedCharacter
	
	// lade Zeichen in r9
	bl uart_getChar
	mov r9, r0
	
	/*
	Schalte Anzeige aus bzw. an
	*/
	cmp r9, #CHAR_S
	bne skipStartStop
	
	// setze Running auf "steht (0)" oder "läuft (1)"
	cmp r7, #0
	ittee eq
	moveq  r7, #1
	ldreq r0, =str_display_on
	movne r7, #0
	ldrne r0, =str_display_off
	
	bl uart_putString
skipStartStop:	

	/*
	Setzte Zeit auf 0 zurück
	*/
	cmp r9, #CHAR_R
	bne skipReset
	
	mov r0, #0
	str r0, [r12] //deaktiviere Timer Counter
	
	str r0, [r10] // schreibe 0 ins Seconds Register
	
	mov r0, #RTC_SR_VALUE
	str r0, [r12] // aktiviere Timer Counter
	
	ldr r0, =str_reset
	bl uart_putString
	
skipReset:

	/*
	Setzte Modus auf 1 Stunde
	*/
	cmp r9, #CHAR_H
	bne skipMode0
	
	mov r0, #0
	str r0, [r12] // deaktiviere Timer Counter
	
	str r0, [r10] // schreibe 0 ins Seconds Register
	
	ldr r0, =RTC_TAR_MODE_1_VALUE
	str r0, [r11] // setze Alarm-Register auf 59:59
	
	mov r0, #0 
	strb r0, [r8] // setze Modus auf 1 Stunde
	
	mov r0, #RTC_SR_VALUE
	str r0, [r12] // aktiviere Timer Counter
	
	ldr r0, =str_mode_0
	bl uart_putString
	
skipMode0:	
	
	/*
	Setzte Modus auf 24 Stunden
	*/
	cmp r9, #CHAR_D
	bne skipMode1
	
	mov r0, #0
	str r0, [r12] // deaktiviere Timer Counter
	
	str r0, [r10] // schreibe 0 ins Seconds Register
	
	ldr r0, =RTC_TAR_START_VALUE
	str r0, [r11] // setze Alarm-Register auf 23:59:59
	
	mov r0, #1 
	strb r0, [r8]// setze Modus auf 24 Stunden
	
	mov r0, #RTC_SR_VALUE
	str r0, [r12] // aktiviere Timer Counter
	
	ldr r0, =str_mode_1
	bl uart_putString

skipMode1:
	
	cmp r9, #CHAR_P
	bne endCheckSendedCharacter
	
	mov r0, #0
	str r0, [r12] // deaktiviere Timer Counter
	
	// lade aktuellen Modus und setze je nach dem den richtigen Preset-Wert
	ldrb r0, [r8]
	cmp r0, #1 // Tages-Modus
	ite eq
	ldreq r0, =PRESET_VALUE_DAY
	ldrne r0, =PRESET_VALUE_HOUR
	
	str r0, [r10] // schreibe Preset-Wert in Sekunden-Register
	
	mov r0, #RTC_SR_VALUE
	str r0, [r12] // aktiviere Timer Counter
	
	ldr r0, =str_preset
	bl uart_putString
endCheckSendedCharacter:	
	// wenn Alarm dann gebe Alarm-String aus
	ldr r1, =alarm_isr_flag
	ldrb r0, [r1]
	cmp r0, #1
	bne skipAlarm
	
	ldr r0, =alarm
	bl uart_putString
	
	// setze Alarm-ISR-Flag zurück
	ldr r1, =alarm_isr_flag
	mov r0, #0
	strb r0, [r1]
	
	b loop
	
skipAlarm:	

	// werte Benutzer-Flag des Interrupts für RTC Seconds aus -> wenn nicht gesetzt loope
	ldr r0, =seconds_isr_flag
	ldrb r1, [r0]
	cmp r1, #0
	beq loop
	
	// Setze Benutzer-Flag zurück
	mov r1, #0
	strb r1, [r0]
	      
	// wenn Ausgabe gestoppt, überspringe diese          
	cmp r7, #0
	beq skipOutput

	// lade aktuelle Sekunden
	ldr r1, =RTC_TSR
	ldr r0, [r1]
	

	// Berechne Stunden aus den bereits abgelaufenen Sekunden
    mov r1, #DIV_VALUE_HOURS
    udiv r6, r0, r1 // Aktueller Sekundenwert / 3600 Sekunden = Anzahl Stunden
    mul r3, r6, r1 // Anzahl Stunden * 3600 Sekunden 
    
    // Berechne Minuten aus den bereits abgelaufenen Sekunden (beachtet auch die vollen Stunden)
    mov r1, #DIV_VALUE_MINUTES
    sub r5, r0, r3 // Aktueller Sekunden Wert - (Anzahl Stunden * 3600 Sekunden)
    udiv r5, r5, r1 // Restliche Sekunden aus r5 / 60 Sekunden = Anzahl Minuten
    mul r2, r1, r5 // Anzahl Minuten * 60 Sekunden
    
    // Berechne Sekunden aus den bereits abgelaufenen Sekunden (beachtet auch die vollen Stunden & Minuten)
    sub r4, r0, r3 // Aktueller Sekundenwert - (Anzahl Stunden * 3600 Sekunden)
    sub r4, r4, r2 // Restliche Sekunden aus r4 - (Anzahl Minuten * 60 Sekunden)
     
     // Wenn 1-Stunden Modus, dann überspringe die Stundenausgabe
    ldrb r0, [r8]
    cmp r0, #0
    beq skipHour  
      
    // Stunden >= 10 -> überspringe führende Null  
    cmp r6, #10
    bge skipHourLeadingZero
    
    mov r0, #CHAR_0
    bl uart_putChar
    
skipHourLeadingZero:    
	mov r0, r6
	bl uart_putByteBase10
	
	mov r0, #CHAR_COLON
    bl uart_putChar
	
skipHour:	
	// Minuten >= 10 -> überspringe führende Null  
	cmp r5, #10
	bge skipMinuteLeadingZero
	
	mov r0, #CHAR_0
    bl uart_putChar
   
skipMinuteLeadingZero:  
	mov r0, r5
	bl uart_putByteBase10 

	mov r0, #CHAR_COLON
    bl uart_putChar

    // Sekunden >= 10 -> überspringe führende Null  
    cmp r4, #10
	bge skipSecondLeadingZero
	
	mov r0, #CHAR_0
    bl uart_putChar

skipSecondLeadingZero:
	mov r0, r4
	bl uart_putByteBase10 
	
	mov r0, #CHAR_LINE_FEED
	bl uart_putChar
	
skipOutput:	
	b loop

.global alarm_isr
.thumb_func
alarm_isr:
	// setze ALARM-ISR-FLag
	ldr r0, =alarm_isr_flag
    mov r1, #1
    strb r1, [r0]
    
    
	ldr r0, =RTC_SR
	mov r1, #0
	str r1, [r0] // deaktiviere Timer Counter
	
	ldr r2, =RTC_TSR
	str r1, [r2] // setze Sekunden auf 0 zurück
	
	mov r1, #RTC_SR_VALUE
	str r1, [r0] // aktiviere Timer Counter
	
	// setze Alarm-Interrupt_Wert je nach Modus
	ldr r0, =mode
	ldrb r1, [r0]
	cmp r1, #0 // 1 Stunde Modus
	ite eq
	ldreq r1, =RTC_TAR_MODE_1_VALUE
	ldrne r1, =RTC_TAR_START_VALUE
	
	ldr r2, =RTC_TAR
	str r1, [r2] // setze Alarm Zeit
	
	bx lr
	
.global seconds_isr
.thumb_func
seconds_isr:
	// setze Seconds-ISR-Flag
	ldr r0, =seconds_isr_flag
    mov r1, #1
    strb r1, [r0]
	
	bx lr
	
/*
Looped solange, bis Delay-Counter abgelaufen ist
*/
.thumb_func
swing_in_delay:	
	ldr r1, =#RTC_DELAY
loop_delay:
	nop
	subs r1, r1, #1
	bpl loop_delay
	BX LR	

/*** Datenbereich (ab 0x20000000) ***/
.data
mode: .byte 0x1
alarm_isr_flag: .byte 0x0
seconds_isr_flag: .byte 0x0
alarm: .asciz "Endzeitpunkt erreicht\n"
str_mode_1: .asciz "24-Stunden-Modus\n"
str_mode_0: .asciz "1-Stunden-Modus\n"
str_reset: .asciz "Uhr zurueckgesetzt\n"
str_display_on: .asciz "Anzeige an\n"
str_display_off: .asciz "Anzeige aus\n"
str_preset: .asciz "Uhr vorgestellt\n"
str_swingin: .asciz "Uhr gestartet (Achtung: Es folgt eine Einschwingzeit fuer den Oszilator)\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

.equ LF, 0x0a
.equ CHAR_DOT, 0x2E
.equ CHAR_COLON, 0x3A
.equ SP, 0x20

/*
OUTPUT
*/
.equ PORTA_PCR6, 0x40049018
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
.equ ALT_GPIO, 0x100 // Alternative 1: GPIO
.equ GPIOA_PDDR, 0x400ff014
.equ GPIOA_PDOR, 0x400ff000
.equ GPIOA_PCOR, 0x400FF008
.equ GPIOA_PSOR, 0x400FF004

/**
(25.000.000 Takte - 4 Takte) / 4 Takte 
(Startwert - Initialisierung) / Schleifendauer

**/
.equ RTC_DELAY, 0x773592C // ca. 20 Sekunden

/*
LED
*/
.equ PORTA_PCR10, 0x40049028 // LED D11
.equ GPIOA_LED_OUTPUT_VALUE, 0x440

.equ CHAR_E, 0x65
.equ CHAR_0, 0x30


__BBREG SIM_SCGC6_PIT, 0x4004803C, 23
// PIT Module Adressen
.equ PIT_LDVAL1, 0x40037110	
.equ PIT_TFLG1, 0x4003711c
.equ PIT_MCR, 0x40037000
.equ PIT_TCTRL1, 0x40037118
.equ PIT_TCTRL1_VALUE, 0x3 // TEN & TIE = 1
// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ PIT1_OFFSET, 0x154 // Offset für IVT PIT1
// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E280
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BIT_MSK, (1 << 5) // Vector-Index für PIT1


__BBREG SIM_SCG6_RTC, 0x4004803C, 29
.equ RTC_TSR, 0x4003D000
.equ RTC_SR, 0x4003D014
.equ RTC_SR_VALUE, 0x10 // TCE = 1
.equ RTC_TCR, 0x4003d00c
.equ RTC_TPR, 0x4003d004
.equ RTC_CR, 0x4003d010
.equ RTC_CR_VALUE, 0x100 // OSCE = 1
.equ RTC_TAR, 0x4003D008
.equ RTC_TAR_START_VALUE, 0x3b // 59 seconds
.equ RTC_IER, 0x4003D01C 
.equ RTC_IER_VALUE, 0x14 // Alarm and second interrupt enabled

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ RTC_ALARM_OFFSET, 0x148
.equ RTC_SECONDS_OFFSET, 0x14C

// NVIC Module Adressen
.equ NVIC_ICPR2, 0xE000E280
.equ NVIC_ISER2, 0xE000E108
.equ NVIC_BIT_MSK_ALARM, 1 << 2
.equ NVIC_BIT_MSK_SECONDS, 1 << 3

.equ DCF77_BITS_0_20, 0x120000
.equ DCF77_WEEKDAY_WEDNESDAY, 0b011 << 6

.equ INCREMENT_MINUTE_BOUNDARY, 0x3b // 59 Sekunden
.equ INCREMENT_HOUR_BOUNDARY, 0x17 // 23 Stunden
.equ INCREMENT_DAY_BOUNDARY, 0x1E // 30 Tage
.equ INCREMENT_MONTH_BOUNDARY, 0xC // 12 Monate
.equ INCREMENT_YEAR_BOUNDARY, 0x63 // 99 Jahre
.equ COUNTER_DIVIDER, 0xA

.equ SHIFT_PARITY_HOUR, 0xE
.equ SHIFT_HOUR, 0x8
.equ SHIFT_PARITY_MINUTE, 0x7
.equ SHIFT_MONTH, 0x9
.equ SHIFT_YEAR, 0xE
.equ SHIFT_PARITY_MONTH_DAY_YEAR, 0x16
.equ SHIFT_ONE_COUNTER, 0x4 // Zähler und einer schieben

.equ COUNTER_LAST, 0x3B // 59
.equ COUNTER_STATIC, 0x14 // 20
.equ COUNTER_HOUR_MINUTE, 0x23 // 35

.equ PIT_100_MS, 0x2625A0
.equ PIT_200_MS, 0x4C4B40
/*
	r4: Tag
  	r5: Monat
  	r6: Jahr
  	r7: Stunde
  	r8: Minute
  	r9: Bits 21 - 35
  	r10: Bits 36-58
  	r11: Bitzähler
  	r12: Bits 0-20
*/
main:	
	bl uart_init

	// aktiviere RTC Clock
	ldr r0, =SIM_SCG6_RTC
	mov r1, #1
	str r1, [r0]
	
	// aktiviere PORTA Clock
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]
	
	// aktiviere PIT Clock
	ldr r0, =SIM_SCGC6_PIT
    str r1, [r0]
	
	// setze LED und Port A6 als Output
	ldr r0, =GPIOA_PDDR
	ldr r1, [r0]
	orr r1, r1, #GPIOA_LED_OUTPUT_VALUE
	str r1, [r0]
	
	// setze LED und Port A6 als Output
	ldr r0, =GPIOA_PDOR
	ldr r1, [r0]
	orr r1, r1, #GPIOA_LED_OUTPUT_VALUE
	str r1, [r0]
	
	ldr r0 , =PORTA_PCR6 // Portleitungen PA6 als GPIO
	mov r1, #ALT_GPIO
	str r1 , [ r0 ]
	
	ldr r0 , =PORTA_PCR10 // Portleitungen PA10 als GPIO
	str r1 , [ r0 ]
	
	// Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
    
    // Addiere Offset für PIT1 (0x154) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #PIT1_OFFSET
    ldr r0, =pit_isr
    str r0, [r2]
    
    // Aktiviere Interrupt für PIT1
    ldr r0, =NVIC_ISER2
    ldr r1, =NVIC_BIT_MSK
    str r1, [r0]
    
    // Lösche Pending Interrupts für PIT1
    ldr r0, =NVIC_ICPR2
    ldr r1, =NVIC_BIT_MSK
    str r1, [r0]
    
    // Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
    
    // Addiere Offset für RTC_ALARM Interrupt (0x148) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #RTC_ALARM_OFFSET
    ldr r0, =alarm_isr
    str r0, [r2]
    
    // Addiere Offset für RTC_SECONDS Interrupt (0x14C) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r2, r1, #RTC_SECONDS_OFFSET
    ldr r0, =seconds_isr
    str r0, [r2]
    
    // Aktiviere RTC Alarm Interrupt
    ldr r0, =NVIC_ISER2
    mov r1, #NVIC_BIT_MSK_ALARM
    str r1, [r0]
    
    // Lösche Pending Interrupts für RTC Alarm Interrupt
    ldr r0, =NVIC_ICPR2
    mov r1, #NVIC_BIT_MSK_ALARM
    str r1, [r0]
    
    // Aktiviere RTC Alarm Interrupt
    ldr r0, =NVIC_ISER2
    mov r1, #NVIC_BIT_MSK_SECONDS
    str r1, [r0]
    
    // Lösche Pending Interrupts für RTC Alarm Interrupt
    ldr r0, =NVIC_ICPR2
    mov r1, #NVIC_BIT_MSK_SECONDS
    str r1, [r0]
    
    // Aktiviere Clock for PIT Timers
    ldr r0, =PIT_MCR
    str r1, [r0]
    
edit:    
	// Deaktiviere RTC
	ldr r12, =RTC_SR
	mov r1, #0
	str r1, [r12]

	ldr r0, =str_day
	bl echo_input
	mov r4, r0
	
	ldr r0, =str_month
	bl echo_input
	mov r5, r0
	
	ldr r0, =str_year
	bl echo_input
	mov r6, r0
	
	ldr r0, =str_hour
	bl echo_input
	mov r7, r0	
	
	ldr r0, =str_minute
	bl echo_input
	mov r8, r0
	
	// Setze Standard-Werte
	ldr r0, =RTC_TCR
	mov r1, #0
	str r1, [r0]
	
	ldr r0, =RTC_TPR
	str r1, [r0]
	
	ldr r10, =RTC_TSR
	str r1, [r10]
	
	// aktiviere Oszilator
	ldr r0, =RTC_CR
	mov r1, #RTC_CR_VALUE
	str r1, [r0]
	
	// aktiviere  Alarm und Sekunden-Interrupt
	ldr r0, =RTC_IER
	mov r1, #0
	str r1, [r0]
	
	 // gebe Anfangsstring aus
	ldr r0, =str_swingin
	bl uart_putString
	
	// rufe Delay auf, damit Oszilator sich einschwingen kann
	bl swing_in_delay
	
	// setze Wert für Alarm Interrupt
	ldr r11, =RTC_TAR
	ldr r1, =RTC_TAR_START_VALUE
	str r1, [r11]
    
    // aktiviere RTC
    mov r1, #RTC_SR_VALUE
    str r1, [r12]
	
	// aktiviere  Alarm und Sekunden-Interrupt
	ldr r0, =RTC_IER
	mov r1, #RTC_IER_VALUE
	str r1, [r0]
    
main_loop:
	// prüfe ob Zeichen gesendet, wenn nicht überspringe
	bl uart_charPresent
	cmp r0, #0
	beq endCheckSendedCharacter
	
	// lade Zeichen
	bl uart_getChar
	
	// wenn Zeichen "e" dann springe in "edit"-Modus
	cmp r0, #CHAR_E
	beq edit
	
endCheckSendedCharacter:	
	// wenn erste Minute, dann führe einmalig Ausgabe und Berechnungen aus (ohne Minute zu inkrementieren)
	mov r2, #0
	ldr r0, =first_minute
	ldrb r1, [r0]
	cmp r1, #1
	itt eq
	strbeq r2, [r0]
	beq skipIncrement
	
	// wenn Minuten-Flag gesetzt, dann berechne neue Minute
	ldr r0, =minute_flag
	ldrb r1, [r0]
	
	cmp r1, #1
	bne no_minute

    mov r1, #0
    strb r1, [r0]
		
	// Setze nächste Minute
	add r8, r8, #1
	cmp r8, #INCREMENT_MINUTE_BOUNDARY
	ite gt
	movgt r8, #0
	ble skipIncrement
	
	// Setze nächste Stunde
	add r7, r7, #1
	cmp r7, #INCREMENT_HOUR_BOUNDARY
	ite gt
	movgt r7, #0
	ble skipIncrement
	
	// Setze nächsten Tag
	add r4, r4, #1 
	cmp r4, #INCREMENT_DAY_BOUNDARY // gehen von 30 Tagen aus
	ite gt
	movgt r4, #1
	ble skipIncrement
	
	// Setze nächsten Monat
	add r5, r5, #1 
	cmp r5, #INCREMENT_MONTH_BOUNDARY
	ite gt
	movgt r5, #1
	ble skipIncrement
	
	// Setze nächstes Jahr
	add r6, r6, #1 
	cmp r6, #INCREMENT_YEAR_BOUNDARY
	ite gt
	movgt r6, #0
	ble skipIncrement	

skipIncrement:	
	/** gebe aktuelles Datum + Uhrzeit in dd.mm.yy hh:mm aus **/

	ldr r0, =str_weekday
	bl uart_putString
	
	cmp r4, #10
	bge skipLeadingZeroDay
	
	mov r0, #CHAR_0
	bl uart_putChar
	
skipLeadingZeroDay:	
	mov r0, r4
	bl uart_putByteBase10
	
	mov r0, #CHAR_DOT
	bl uart_putChar
	
	cmp r5, #10
	bge skipLeadingZeroMonth
	
	mov r0, #CHAR_0
	bl uart_putChar
	
skipLeadingZeroMonth:	
	mov r0, r5
	bl uart_putByteBase10
	
	mov r0, #CHAR_DOT
	bl uart_putChar
	
	cmp r6, #10
	bge skipLeadingZeroYear
	
	mov r0, #CHAR_0
	bl uart_putChar
	
skipLeadingZeroYear:
	mov r0, r6
	bl uart_putByteBase10
	
	mov r0, #SP
	bl uart_putChar
		
	cmp r7, #10
	bge skipLeadingZeroHour
	
	mov r0, #CHAR_0
	bl uart_putChar
	
skipLeadingZeroHour:	
	mov r0, r7
	bl uart_putByteBase10
	
	mov r0, #CHAR_COLON
	bl uart_putChar
	
	cmp r8, #10
	bge skipLeadingZeroMinute
	
	mov r0, #CHAR_0
	bl uart_putChar
	
skipLeadingZeroMinute:
	mov r0, r8
	bl uart_putByteBase10
	
	ldr r0, =str_hour_output
	bl uart_putString
	
	// r9 Uhrzeit
	mov r9, #0x0
	
	// Stunde
	mov r0, #0x0
	mov r2, #COUNTER_DIVIDER
	
	// wenn Stunde < 10, dann setze in r0 (Zehner) eine 0 und in r1 (Einer) den Wert aus Eingabe -> ansonsten setze Zehner durch Division mit 10 und Einer durch: Eingabe - (Zehner * 10)
	cmp r7, #COUNTER_DIVIDER
	ittee ge
	udivge r0, r7, r2
	mlsge r1, r0, r2, r7
	movlt r0, #0
	movlt r1, r7
	
	
	lsl r0, r0, #SHIFT_ONE_COUNTER // schiebe Zehner 4 Bits nach Links und verordere die Einer
	orr r0, r0, r1
	lsl r9, r0, #SHIFT_HOUR // schiebe Stunde um 8 bits nach Links (sh. DCF77)
	
	// Berechnung Parität Stunde
	mov r0, r9
	bl getParityBit
	lsl r0, r0, #SHIFT_PARITY_HOUR // schiebe Parität an die richtige Stelle (14 Bits nach Links) und verordere mit r9
	orr r9, r9, r0
	
	// Minute
	mov r0, #0x0
	mov r2, #COUNTER_DIVIDER
		
	// wenn Minute < 10, dann setze in r0 (Zehner) eine 0 und in r1 (Einer) den Wert aus Eingabe -> ansonsten setze Zehner durch Division mit 10 und Einer durch: Eingabe - (Zehner * 10)	
	cmp r8, #COUNTER_DIVIDER
	ittee ge
	udivge r0, r8, r2
	mlsge r1, r0, r2, r8
	movlt r0, #0
	movlt r1, r8
	
	lsl r0, r0, #SHIFT_ONE_COUNTER  // schiebe Zehner 4 Bits nach Links und verordere die Einer
	orr r0, r0, r1
	mov r10, r0
	
	// Berechnung Parität Minute
	bl getParityBit
	lsl r0, r0, #SHIFT_PARITY_MINUTE // schiebe Parität an die richtige Stelle (7 Bits nach Links) und verordere mit r10
	orr r10, r10, r0 
	orr r9, r9, r10 // verordere r9 und r10 (Stunde und Minute) miteinander  --> r9
	
	// Datum
	mov r10, #0x0
	
	// Kalendertag (aus r4)
	mov r0, #0x0
	mov r2, #COUNTER_DIVIDER
	
	// wenn Kalendertag < 10, dann setze in r0 (Zehner) eine 0 und in r1 (Einer) den Wert aus Eingabe -> ansonsten setze Zehner durch Division mit 10 und Einer durch: Eingabe - (Zehner * 10)
	cmp r4, #COUNTER_DIVIDER
	ittee ge
	udivge r0, r4, r2
	mlsge r1, r0, r2, r4
	movlt r0, #0 
	movlt r1, r4
	
	lsl r0, r0, #SHIFT_ONE_COUNTER // schiebe Zehner 4 Bits nach Links und verordere die Einer
	orr r0, r0, r1
	orr r10, r10, r0
	
	// Wochentag (aus Konstante für Mittwoch)
	mov r0, #DCF77_WEEKDAY_WEDNESDAY
	orr r10, r10, r0
	
	// wenn Monatstag < 10, dann setze in r0 (Zehner) eine 0 und in r1 (Einer) den Wert aus Eingabe -> ansonsten setze Zehner durch Division mit 10 und Einer durch: Eingabe - (Zehner * 10)
	cmp r5, #COUNTER_DIVIDER
	ittee ge
	udivge r0, r5, r2
	mlsge r1, r0, r2, r5
	movlt r0, #0
	movlt r1, r5
	
	lsl r0, r0, #SHIFT_ONE_COUNTER // schiebe Zehner 4 Bits nach Links und verordere die Einer
	orr r0, r0, r1
	lsl r0, r0, #SHIFT_MONTH // schiebe Monat um 9 bits nach Links (sh. DCF77)
	orr r10, r10, r0
	
	// wenn Jahr < 10, dann setze in r0 (Zehner) eine 0 und in r1 (Einer) den Wert aus Eingabe -> ansonsten setze Zehner durch Division mit 10 und Einer durch: Eingabe - (Zehner * 10)
	cmp r6, #COUNTER_DIVIDER
	ittee ge
	udivge r0, r6, r2
	mlsge r1, r0, r2, r6
	movlt r0, #0 
	movlt r1, r6 
	
	lsl r0, r0, #SHIFT_ONE_COUNTER // schiebe Zehner 4 Bits nach Links und verordere die Einer
	orr r0, r0, r1
	lsl r0, r0, #SHIFT_YEAR // schiebe Jahr um 14 bits nach Links (sh. DCF77)
	orr r10, r10, r0
	
	// Berechnung Parität Kalendertag, Wochentag, Monat Jahr
	mov r0, r10
	bl getParityBit
	lsl  r0, r0, #SHIFT_PARITY_MONTH_DAY_YEAR // schiebe Parität an die richtige Stelle (22 Bits nach Links) und verordere mit r10
	orr r10, r10, r0
	
	mov r11, #0 // Definiere Counter-Variable mit 0
	mov r12, #DCF77_BITS_0_20 //  setze die Standardbits
	
no_minute:	
	// wenn keine Sekunde vorbei, loop
	ldr r0, =second_flag
	ldrb r1, [r0]
	
	cmp r1, #1
	bne main_loop
	
	// kein Absenken beim 60. Durchlauf
	cmp r11, #COUNTER_LAST
	beq output_end
	
	// wenn Durchlauf <= 20 nutze r12: verANDe das aktuell erste Bit mit 1 -> (1 & 1 = 1) und schiebe r12 um 1 Bit nach rechts -> springe zum Output 
	cmp r11, #COUNTER_STATIC
	ittt le
	andle r0, r12, #1
	lsrle r12, r12, #1
	ble output
	
	// wenn Durchlauf <= 35 nutze r9: verANDe das aktuell erste Bit mit 1 -> (1 & 1 = 1) und schiebe r9 um 1 Bit nach rechts -> springe zum Output 
	cmp r11, #COUNTER_HOUR_MINUTE
	ittt le
	andle r0, r9, #1
	lsrle r9, r9, #1
	ble output
	
	// wenn Durchlauf > 35 nutze r10: verANDe das aktuell erste Bit mit 1 -> (1 & 1 = 1) und schiebe r10 um 1 Bit nach rechts -> springe zum Output 
	and r0, r10, #1
	lsr r10, r10, #1

output:
	// wenn r0 (aktuelles Bit) = 0 -> 100ms PIT ansonsten 200ms
	cmp r0, #0
	ite eq
	ldreq r1, =PIT_100_MS // 100ms
	ldrne r1, =PIT_200_MS // 200ms
	
	// Lade Startwert in den PIT1
    ldr r2, =PIT_LDVAL1
    str r1, [r2]
    
    // Aktiviere Timer und Timer Interrupt für PIT1
    ldr r2, =PIT_TCTRL1
    mov r3, #PIT_TCTRL1_VALUE
    str r3, [r2]
    
    // Ziehe LED & PIN auf LOW
    ldr r2, =GPIOA_PCOR
    mov r3, #GPIOA_LED_OUTPUT_VALUE
    str r3, [r2]
    
wait_for_pit:
	//  Warte bis PIT ISR Flag gesetzt
    ldr r2, =pit_flag
    ldrb r3, [r2]
    
    cmp r3, #0
    beq wait_for_pit
    
    // PIT Flag zurücksetzen
    mov r3, #0
    strb r3, [r2]
    
    // Deaktiviere Timer und Timer Interrupt für PIT1
    ldr r2, =PIT_TCTRL1
    str r3, [r2]
    
    // Ziehe LED & PIN auf HIGH
    ldr r2, =GPIOA_PSOR
    mov r3, #GPIOA_LED_OUTPUT_VALUE
    str r3, [r2]

    // gebe aktuelles BIT aus und erhöhe Counter (r11)
	bl uart_putByteBase10
	add r11, r11, #1
	
	b loop_end

output_end:
	mov	r0, #LF						// neue Zeile
	bl uart_putChar				// ausgeben
	
loop_end:
	// setze Sekunden-Flag zurück
	ldr r0, =second_flag
	mov r1, #0
    strb r1, [r0]

	b main_loop
	
.thumb_func
echo_input:
	push {r4,lr}
	bl	uart_putString				// Uebergebenen String ausgeben
	bl	uart_getByteBase10			// einen zweistelligen Dezimalwert einlesen
	mov r4, r0						// sichern
	bl	uart_putByteBase10			// zur Kontrolle ausgeben
	mov	r0, #LF						// neue Zeile
	bl	uart_putChar				// ausgeben
	mov r0, r4						// gesicherten Wert zurueckgeben
	pop {r4,pc}
	
.thumb_func
getParityBit:
	// Verknüpfe XOR mit jeweils um 2^x geschobenem Wert (siehe hier: https://www.freecodecamp.org/news/algorithmic-problem-solving-efficiently-computing-the-parity-of-a-stream-of-numbers-cd652af14643/ (Approach 4 - Using XOR & Shifting operations)
	eor r1, r0, r0, lsr #1
	eor r1, r1, r1, lsr #2
	eor r1, r1, r1, lsr #4
	eor r1, r1, r1, lsr #8
	eor r1, r1, r1, lsr #16
	
	and r0, r1, #1
	
	bx lr
	
.global alarm_isr
.thumb_func
alarm_isr:
	// setze Minuten-Flag
	ldr r0, =minute_flag
    mov r1, #1
    strb r1, [r0]
    
    ldr r0, =RTC_SR
	mov r1, #0
	str r1, [r0] // deaktiviere Timer Counter
	
	ldr r2, =RTC_TSR
	str r1, [r2] // setze Sekunden auf 0 zurück
	
	mov r1, #RTC_SR_VALUE
	str r1, [r0] // aktiviere Timer Counter

	// setze Alarm-Interrupt-Wert
	ldr r0, =RTC_TAR
	ldr r1, =RTC_TAR_START_VALUE
	str r1, [r0]
	bx lr
	
.global seconds_isr
.thumb_func
seconds_isr:
	// setze Sekunden-Flag
	ldr r0, =second_flag
    mov r1, #1
    strb r1, [r0]
	
	bx lr	
	
.thumb_func
pit_isr:
	ldr r0, =pit_flag  // Setze PIT Benutzer-Flag
    mov r1, #1
    strb r1, [r0]
	
	ldr r0, =PIT_TFLG1 // Setze PIT-Interrupt-Flag zurück
	mov r1, #1
	str r1, [r0]
	bx lr	
	
/*
Looped solange, bis Delay-Counter abgelaufen ist
*/
.thumb_func
swing_in_delay:	
	ldr r1, =#RTC_DELAY
loop_delay:
	nop
	subs r1, r1, #1
	bpl loop_delay
	BX LR		

/*** Datenbereich (ab 0x20000000) ***/
.data
pit_flag: .byte 0x0
minute_flag: .byte 0x0
second_flag: .byte 0x0
first_minute: .byte 0x1
str_hour: .asciz "Stunde eingeben (hh): "
str_minute: .asciz "Minute eingeben (mm): "
str_day: .asciz "Tag eingeben (dd): "
str_month: .asciz "Monat eingeben (mm): "
str_year: .asciz "Jahr eingeben (jj): "
str_weekday: .asciz "Mi., "
str_hour_output: .asciz "Uhr\n"
str_swingin: .asciz "Uhr gestartet (Achtung: Es folgt eine Einschwingzeit fuer den Oszilator)\n"
// Include-Dateien
.include "k1514.inc"			// Praktikumsspezifische Definitionen
.include "lib_pit.inc"			// Einfache Unterprogramme zur Zeitmessung
.include "lib_uart.inc"			// Unterprogramme zur Ein-/Ausgabe vom/zum Terminal (CuteCom)

// Assemblerdirektiven
.text							// hier beginnt ein Code-Segment
.align	2						// Ausrichtung an eine gerade Adresse
.global	main					// "main" wird als globales Symbol deklariert
.syntax unified

__BBREG SIM_SCGC6_FMT0, 0x4004803C, 24
__BBREG SIM_SCGC5_PORTA, 0x40048038, 9
__BBREG GPIOA_PDDR_6, GPIOA_PDDR, 6
__BBREG GPIOA_PDOR_6, GPIOA_PDOR, 6
.equ PORTA_PCR6, 0x40049018
.equ ALT_FTM, 0x300 // Alternative 3: FTM
__BBREG FTM0_MODE_WPDIS, FTM0_MODE, 2
__BBREG FTM0_MODE_FTMEN, FTM0_MODE, 0
.equ FTM0_MODE, 0x40038054
.equ FTM0_MODE_VALUE, 0x5 // WPDIS = 1; FTMEN = 1
.equ FTM0_SC, 0x40038000
.equ FTM0_SC_VALUE, 0x48 // TOIE = 1; CPWMS = 0; CLKS = 01 (System clock); PS = 000
.equ FTM0_SC_VALUE_DISABLE, 0x40 // TOIE = 1; CPWMS = 0; CLKS = 00; PS = 000
.equ FTM0_MOD, 0x40038008
.equ FTM0_MOD_VALUE, 0x61A7 // 24.999 (25 MHz / 100 kHz) - 1 Takt (wird mit nächstem Takt overflowed)
.equ FTM0_C3SC, 0x40038024
.equ FTM0_C3SC_VALUE_PLUS, 0x68 // CHIE=1, MSB=1, MSA=0, ELSB=1, ELSA=0
.equ FTM0_C3SC_VALUE_MINUS, 0x64 // CHIE=1, MSB=1, MSA=0, ELSB=0, ELSA=1
.equ FTM0_C3V, 0x40038028
.equ FTM0_QDCTRL, 0x40038080
.equ FTM0_COMBINE, 0x40038064
.equ FTM0_CNTIN, 0x4003804C
.equ FTM0_CNT, 0x40038004	

// IVT Adressen
.equ SCR_VTOR, 0xE000ED08
.equ FTM0_OFFSET, 0x138 // Offset für IVT FTM0
// NVIC Module Adressen
.equ NVIC_ISER1, 0xE000E104
.equ NVIC_BIT_MSK, (1 << 30) // Vector-Index für FTM0

.equ GPIOA_PDDR, 0x400ff014
.equ GPIOA_PDOR, 0x400ff000

.equ CHAR_PLUS, 0x2B
.equ CHAR_MINUS, 0x2D
.equ CHAR_0, 0x30
.equ CHAR_9, 0x39

.equ MOD_10_PERCENT, 0x9C4 // C3V = Eingabe * (MOD * 10%) + (MOD * 5%) -> MOD_10_PERCENT = 25.000 * 10% = 2500
.equ MOD_5_PERCENT, 0x4E2 // 25.000 * 5% = 1250

/*
* Hauptprogramm (main): Wird nicht direkt nach dem Reset, sondern von einer Routine aufgerufen, 
* die nach einem Reset die grundlegende Systeminitialisierung durchfuehrt. Man darf also nicht davon ausgehen,
* dass die Register mit ihrem Reset-Wert vorbelegt sind.
*/
main:	
	bl uart_init
 
	/* Aktiviere FTM0 Clock */
	ldr r0, =SIM_SCGC6_FMT0
	mov r1, #1
	str r1, [r0]

	/* Aktiviere PORTA Clock */
	ldr r0, =SIM_SCGC5_PORTA
	str r1, [r0]

	// Setze GPIOA 6 Output
	ldr r0, =GPIOA_PDDR_6
	str r1, [r0]
 
	// Setze GPIOA 6 Output
	ldr r0, =GPIOA_PDOR_6
	str r1, [r0]
	
	// Deaktiviere Write-Protection (theoretisch Default-Wert, aber sicher ist sicher)
	ldr r0, =FTM0_MODE_WPDIS
	str r1, [r0]
	
	// Lade Adresse der IVT von Basisadresse
    ldr r0, =SCR_VTOR
    ldr r1, [r0]
	
	// Addiere Offset für FTM0 (0x138) auf die Adresse der IVT und speichere die ISR an diese Stelle
    add r1, r1, #FTM0_OFFSET
    ldr r0, =ftm_isr
    str r0, [r1]
    
    // Aktiviere Interrupt für FTM0
    ldr r0, =NVIC_ISER1
    ldr r1, =NVIC_BIT_MSK
    str r1, [r0]
	
	// PORTA 6 auf Alternative 3 (FTM)
	ldr r0 , =PORTA_PCR6 // Portleitungen PA6 als FTM
	mov r1, #ALT_FTM
	str r1 , [ r0 ]

    // Setze Modulo für FTM-Counter
	ldr r0, =FTM0_MOD
	ldr r1, =FTM0_MOD_VALUE
	str r1, [r0]
	
	// Setze Default-Werte (sicher ist sicher)
	ldr r0, =FTM0_QDCTRL
	mov r1, #0
	str r1, [r0]
	
	// Setze Default-Werte (sicher ist sicher)
	ldr r0, =FTM0_COMBINE
	str r1, [r0]
	
	// Setze Default-Werte (sicher ist sicher)
	ldr r0, =FTM0_CNTIN
	str r1, [r0]
	
	// Setze Polarität für Channel 3
	ldr r0, =FTM0_C3SC
	mov r1,  #FTM0_C3SC_VALUE_PLUS
	str r1, [r0]
	
	// speichere aktuellen Channel Status (vorrangig zwecks Polarität) ab
	ldr r0, =currentC3SCValueAddress
	strb r1, [r0]
	
	// setze Standard-C3V Wert (Annahme Eingabe 0)
	ldr r0, =FTM0_C3V
	ldr r1, =MOD_5_PERCENT
    str r1, [r0]
    
    // Setze Status Control (aktiviere FTM)
    ldr r0, =FTM0_SC
	mov r1, #FTM0_SC_VALUE
	str r1, [r0]
	
	// aktiviere FTM (FTMEN = 1)
	ldr r0, =FTM0_MODE
	mov r1, #FTM0_MODE_VALUE
	str r1, [r0]
	
	// gebe ">" aus, um Eingabe zu erwarten
	ldr r0, =input_string
	bl uart_putString
 
loop:  
	// prüfe ob Eingabe vorhanden
	bl uart_charPresent
	cmp r0, #0
	beq loop
	
	// wenn ja, speichere erhaltene Eingabe in Speicher (um in ISR drauf zuzugreifen)
	bl uart_getChar
	ldr r1, =receivedChar
	strb r0, [r1]
	
	// gebe eingegebenes Zeichen aus
	bl uart_putChar
	
	// gebe ">" aus, um wieder eine Eingabe zu erwarten
	ldr r0, =input_string
	bl uart_putString
	
	// setze Flag, dass Zeichen empfangen wurde
	ldr r1, =charReceived
	mov r0, #1
	strb r0, [r1]
    
	b loop
	
.thumb_func
ftm_isr:
	// Setze FTMEN = 0 
	ldr r0, =FTM0_MODE_FTMEN
	mov r1, #0
	str r1, [r0]
	
	// lade Flag ob Zeichen erhalten
	ldr r0, =charReceived
	ldrb r1, [r0]

	// lese Statusregister um Timer Overflow zu erkennen
	ldr r0, =FTM0_SC
    ldr r2, [r0]                           //Liest 0xC8
    cmp r2, #FTM0_SC_VALUE
    beq skipTimerOverflow
    
    // wenn Zeichen nicht erhalten, überspringen
    cmp r1, #0
    beq skipTimerOverflow
    
    // lade erhaltenes Zeichen
    ldr r1, =receivedChar
    ldrb r1, [r1]
    
    // überprüfe ob Plus gesendet
    cmp r1, #CHAR_PLUS
    bne skipPlus
    
    // speichere aktuellen Channel Status für Polarität "Plus" ab
    ldr r0, =currentC3SCValueAddress
    mov r2, #FTM0_C3SC_VALUE_PLUS
	strb r2, [r0]
    
    // setze Zeichen erhalten-Flag zurück
    ldr r0, =charReceived
    mov r2, #0
    strb r2, [r0]
    
skipPlus:    
	// überprüfe ob Minus gesendet
    cmp r1, #CHAR_MINUS
    bne skipTimerOverflow
    
    // speichere aktuellen Channel Status für Polarität "Minus" ab
    ldr r0, =currentC3SCValueAddress
    mov r2, #FTM0_C3SC_VALUE_MINUS
	strb r2, [r0]
	
	// setze Zeichen erhalten-Flag zurück
	ldr r0, =charReceived
    mov r2, #0
    strb r2, [r0]
	 
skipTimerOverflow:   
	// überprüfe Channel Status ob Channel-Overflow vorliegt
    ldr r0, =FTM0_C3SC
    ldr r2, [r0]
    ldr r3, =currentC3SCValueAddress
    ldrb r3, [r3]
    cmp r2, r3
    beq skipChannelOverflow
    
    // Deaktiviere FTM (CLKS = 00) um C3V setzen zu können
    ldr r0, =FTM0_SC
	ldr r2, =FTM0_SC_VALUE_DISABLE
	str r2, [r0]
	
	// lade Flag ob Zeichen erhalten
	ldr r0, =charReceived
	ldrb r1, [r0]
    
    // wenn kein Zeichen erhalten, überspringen
    cmp r1, #0
    beq skipCharacterChannelOverflow
    
     // lade erhaltenes Zeichen
    ldr r1, =receivedChar
    ldrb r1, [r1]
    
    // wenn Zeichen größer 9, dann überspringe
    cmp r1, #CHAR_9
    bgt skipCharacterChannelOverflow
    
    // wenn Zeichen größer 0, dann überspringe
    cmp r1, #CHAR_0
    blt skipCharacterChannelOverflow
    
    // subtrahiere vom ASCII-Zeichenwert 30 ab (39-30 = 9 usw.)
    sub r1, r1, #CHAR_0
    // lade Wert für 10 Prozent vom MOD-Wert
    ldr r0, =MOD_10_PERCENT
    // Multipliziere Eingabe * MOD 10 Prozent
    mul r1, r1, r0
    // Addiere Ergebnis + MOD 5 Prozent
    add r1, r1, #MOD_5_PERCENT
    
    // speichere berechneten Wert in C3V
    ldr r0, =FTM0_C3V
    str r1, [r0]
    
    // setze Zeichen erhalten-Flag zurück
    ldr r0, =charReceived
    mov r2, #0
    strb r2, [r0]
    
skipCharacterChannelOverflow:
	ldr r0, =FTM0_C3SC
	str r3, [r0]
    
skipChannelOverflow:    
	
	// aktiviere FTM (CLKS = 01)
	ldr r0, =FTM0_SC
    ldr r2, =FTM0_SC_VALUE
    str r2, [r0]      

    // setze FTMEN=1
    ldr r0, =FTM0_MODE_FTMEN
	mov r1, #1
	str r1, [r0]
    
	bx lr		

/*** Datenbereich (ab 0x20000000) ***/
.data
charReceived: .byte 0x0
receivedChar: .byte 0x0
currentC3SCValueAddress: .byte 0x0
input_string: .asciz "\n> "

